// German V2 B1 Units (13-24)
// Split from units-german-v2.js for maintainability

const GERMAN_V2_B1 = [
{n:13,lang:"de",srcLang:"en",track:"v2",title:"Die Bewerbung",sub:"Job application, formal German, mock interview, Konjunktiv II",icon:"📝",level:"B1.1",color:"#7B5EE8",lessons:[

// ==================== LESSON 1: Der rote Stift ====================
{id:"deu_r13l1",title:"Der rote Stift",icon:"🖊️",xp:15,board:true,steps:[
{type:"intro",title:"Der rote Stift",desc:"Verumius sits in Dr. Yilmaz's office. His CV is covered in red corrections. Time to discover the world of German job applications.",goals:["Learn key vocabulary for applications and job interviews","Understand what makes a German application unique","Follow Verumius through his first application"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-vhs-office",trg:"Dr. Yilmaz' Büro in der Volkshochschule. Nachmittagslicht fällt durch die Jalousien. Bücher überall. Eine kleine Goethe-Büste beobachtet vom Regal. Verumius sitzt Dr. Yilmaz gegenüber, sein Lebenslauf-Entwurf liegt zwischen ihnen. Rote Markierungen bedecken fast jede Zeile.",src:"Dr. Yilmaz's office at the adult education center. Afternoon light falls through the blinds. Books everywhere. A small Goethe bust watches from the shelf. Verumius sits across from Dr. Yilmaz, his CV draft lies between them. Red marks cover nearly every line."},
{type:"story",speaker:"yilmaz",mood:"patient",trg:"Verumius, deine Bewerbung ist... kreativ. Aber in Deutschland ist eine Bewerbung ein offizielles Dokument. Sie muss perfekt sein.",src:"Verumius, your application is... creative. But in Germany, an application is an official document. It must be perfect."},
{type:"story",speaker:"verumius",mood:"nervous",trg:"Aber ich habe alles geschrieben. Meinen Namen, meine Arbeit...",src:"But I wrote everything. My name, my work..."},
{type:"story",speaker:"yilmaz",mood:"firm",trg:"Ein deutscher Lebenslauf braucht Struktur. Foto, Personaldaten, Ausbildung, Berufserfahrung. Alles korrekt, alles vollständig.",src:"A German CV needs structure. Photo, personal data, education, work experience. Everything correct, everything complete."},
{type:"teach",trg:"die Bewerbung",src:"the application",pos:"noun",gender:"f",note:"Feminine noun. From 'bewerben' (to apply).\nBe- + werben (to advertise/recruit).",example:"A: Ich schreibe eine Bewerbung.\nB: Für welche Firma?\nA: Für Siemens in Berlin.\nB: Viel Erfolg!",exampleSrc:"A: I am writing an application.\nB: For which company?\nA: For Siemens in Berlin.\nB: Good luck!",funFact:"A German Bewerbung always includes a cover letter (Anschreiben), CV (Lebenslauf), and certificates (Zeugnisse). It is a three-part package. You are literally 'advertising yourself.'"},
{type:"teach",trg:"der Lebenslauf",src:"the CV, the resume",pos:"noun",gender:"m",note:"Masculine noun. Literally 'life-run' (Leben + Lauf).\nThe story of your life on paper.",example:"A: Haben Sie Ihren Lebenslauf mitgebracht?\nB: Ja, hier ist er. Zwei Seiten.\nA: Sehr gut. Mit Foto?\nB: Natürlich. Wie in Deutschland üblich.",exampleSrc:"A: Did you bring your CV?\nB: Yes, here it is. Two pages.\nA: Very good. With a photo?\nB: Of course. As is customary in Germany.",funFact:"Germans traditionally include a photo, date of birth, and marital status on their CV. This surprises many non-Germans. The Lebenslauf is literally the 'run of your life' on paper."},
{type:"teach",trg:"der Erfolg",src:"the success",pos:"noun",gender:"m",note:"Masculine noun. From 'erfolgen' (to result).\n'Viel Erfolg!' = Good luck!",example:"A: Morgen habe ich mein Vorstellungsgespräch.\nB: Viel Erfolg! Du schaffst das.\nA: Danke. Ich bin so nervös.\nB: Erfolg kommt mit Vorbereitung.",exampleSrc:"A: Tomorrow I have my job interview.\nB: Good luck! You can do it.\nA: Thanks. I am so nervous.\nB: Success comes with preparation.",funFact:"'Viel Erfolg!' (Much success!) is how Germans wish you good luck before an interview. Success is literally 'what follows' from your effort."},
{type:"teach",trg:"die Karriere",src:"the career",pos:"noun",gender:"f",note:"Feminine noun. Borrowed from French 'carriere'.\nSame root as English 'career.'",example:"A: Was ist Ihr Karriereziel?\nB: Ich möchte Teamleiterin werden.\nA: Gute Karriereplanung ist wichtig.\nB: Ja, ich habe einen klaren Plan.",exampleSrc:"A: What is your career goal?\nB: I want to become a team leader.\nA: Good career planning is important.\nB: Yes, I have a clear plan.",funFact:"Germans distinguish between Karriere (ambitious upward path) and Beruf (your profession). Not every Beruf is a Karriere. The French origin 'carriere' originally meant 'racecourse.'"},
{type:"teach",trg:"der Eindruck",src:"the impression",pos:"noun",gender:"m",note:"Masculine noun. Ein (in) + Druck (pressure/print).\n'Der erste Eindruck zählt.'",example:"A: Wie war dein Eindruck vom Gespräch?\nB: Gut. Der Chef war freundlich.\nA: Der erste Eindruck zählt.\nB: Ja, ich habe mich gut vorbereitet.",exampleSrc:"A: What was your impression of the meeting?\nB: Good. The boss was friendly.\nA: The first impression counts.\nB: Yes, I prepared well.",funFact:"'Der erste Eindruck zählt' (The first impression counts) is a universal German saying. An impression is literally something 'pressed into' you."},
{type:"teach",trg:"die Vorbereitung",src:"the preparation",pos:"noun",gender:"f",note:"Feminine noun. Vor (before) + Bereitung (preparation).\nPreparing before the event.",example:"A: Hast du dich vorbereitet?\nB: Ja, die Vorbereitung hat drei Tage gedauert.\nA: Gut. Ohne Vorbereitung kein Erfolg.\nB: Das stimmt. Ich bin jetzt bereit.",exampleSrc:"A: Did you prepare?\nB: Yes, the preparation took three days.\nA: Good. Without preparation, no success.\nB: That's right. I am ready now.",funFact:"Germans are famous for Vorbereitung. A job interview without preparation is unthinkable. The compound tells you: do it BEFORE."},
{type:"teach",trg:"die Vorstellung",src:"the introduction, the idea",pos:"noun",gender:"f",note:"Feminine noun. Vor + Stellung (position).\nMeans both 'introduction' and 'imagination.'",example:"A: Haben Sie eine Vorstellung vom Gehalt?\nB: Ja, ich habe eine klare Vorstellung.\nA: Gut. Dann lassen Sie uns darüber sprechen.\nB: Gern.",exampleSrc:"A: Do you have an idea about the salary?\nB: Yes, I have a clear idea.\nA: Good. Then let us talk about it.\nB: Gladly.",funFact:"'Hast du eine Vorstellung?' can mean 'Do you have an idea?' or 'Do you have an appointment?' Literally 'placing yourself before someone.'"},
{type:"teach",trg:"das Vorstellungsgespräch",src:"the job interview",pos:"noun",gender:"n",note:"Neuter noun. Vorstellung + Gespräch (conversation).\nThe formal German word for job interview.",example:"A: Wann ist Ihr Vorstellungsgespräch?\nB: Am Dienstag um zehn Uhr.\nA: Sind Sie nervös?\nB: Ein bisschen. Aber ich bin gut vorbereitet.",exampleSrc:"A: When is your job interview?\nB: On Tuesday at ten o'clock.\nA: Are you nervous?\nB: A little. But I am well prepared.",funFact:"A 'getting-to-know-you conversation.' Das Vorstellungsgespräch is always neuter because Gespräch is the last element. The gender of the last word in a compound always wins."},
{type:"teach",trg:"bereit",src:"ready",pos:"adj",gender:null,note:"Adjective. 'Bist du bereit?' = Are you ready?\nRelated to 'bereiten' (to prepare).",example:"A: Bist du bereit für das Gespräch?\nB: Ja, ich bin bereit.\nA: Hast du alle Unterlagen?\nB: Ja. Lebenslauf, Zeugnisse, alles.",exampleSrc:"A: Are you ready for the interview?\nB: Yes, I am ready.\nA: Do you have all the documents?\nB: Yes. CV, certificates, everything.",funFact:"'Bist du bereit?' is what coaches, teachers, and mentors ask before the big moment. Ready means you have prepared. Being 'bereit' is a state you earned."},
{type:"teach",trg:"korrekt",src:"correct, fair",pos:"adj",gender:null,note:"Same as English 'correct.' From Latin 'correctus.'\nAlso means 'fair/decent' in slang.",example:"A: Sind alle Angaben korrekt?\nB: Ja, alles ist korrekt.\nA: Gut. Dann schicken wir die Bewerbung ab.\nB: Perfekt. Vielen Dank für Ihre Hilfe.",exampleSrc:"A: Is all the information correct?\nB: Yes, everything is correct.\nA: Good. Then we will send off the application.\nB: Perfect. Thank you very much for your help.",funFact:"In German, korrekt also means 'fair/decent' in slang: 'Er ist ein korrekter Typ' (He is a decent guy). Double meaning: accurate AND upstanding."},
{type:"teach",trg:"persönlich",src:"personal",pos:"adj",gender:null,note:"From Person + -lich.\n'Persönliche Daten' = personal data.",example:"A: Bitte tragen Sie Ihre persönlichen Daten ein.\nB: Name, Adresse, Geburtsdatum?\nA: Ja, und Familienstand.\nB: Verstanden.",exampleSrc:"A: Please enter your personal data.\nB: Name, address, date of birth?\nA: Yes, and marital status.\nB: Understood.",funFact:"Your persönliche Daten go on every German form. In job interviews, persönliche Fragen about family or religion are actually illegal to ask."},
{type:"teach",trg:"höflich",src:"polite",pos:"adj",gender:null,note:"From 'Hof' (court). Being höflich originally meant\nbehaving like someone at a royal court.",example:"A: War der Interviewer nett?\nB: Ja, sehr höflich und professionell.\nA: Das ist wichtig. Sei auch du höflich.\nB: Natürlich. Immer höflich und freundlich.",exampleSrc:"A: Was the interviewer nice?\nB: Yes, very polite and professional.\nA: That is important. Be polite too.\nB: Of course. Always polite and friendly.",funFact:"From 'Hof' (court). Being höflich originally meant behaving like someone at a royal court. Courtly manners became 'polite.' Same etymology as English 'courteous' from 'court.'"},
{type:"teach",trg:"erstellen",src:"to create, to produce",pos:"verb",gender:null,note:"Not separable. Er- + stellen (to place).\nMore formal than 'machen.' The professional word.",example:"A: Können Sie einen Bericht erstellen?\nB: Ja, ich erstelle ihn bis Freitag.\nA: Gut. Bitte erstellen Sie auch eine Übersicht.\nB: Kein Problem.",exampleSrc:"A: Can you create a report?\nB: Yes, I will create it by Friday.\nA: Good. Please also create an overview.\nB: No problem.",funFact:"You 'erstellen' a document, report, or CV. More formal than 'machen.' The professional word for creation. Er- + stellen: to make something stand."},
{type:"teach",trg:"erwarten",src:"to expect",pos:"verb",gender:null,note:"Not separable. Er- + warten (to wait).\nTo expect is to 'wait out' for something.",example:"A: Was erwarten Sie von diesem Job?\nB: Ich erwarte gute Arbeitsbedingungen.\nA: Und was können wir von Ihnen erwarten?\nB: Engagement und Zuverlässigkeit.",exampleSrc:"A: What do you expect from this job?\nB: I expect good working conditions.\nA: And what can we expect from you?\nB: Commitment and reliability.",funFact:"'Was erwarten Sie von diesem Job?' is a classic interview question. To expect is literally to 'wait out' for something."},
{type:"teach",trg:"reagieren",src:"to react",pos:"verb",gender:null,note:"Not separable. From Latin 're-agere' (to act back).\nSame word in English, French, and German.",example:"A: Wie reagieren Sie auf Kritik?\nB: Ich nehme Kritik ernst und lerne daraus.\nA: Gut. Und wie reagieren Sie unter Stress?\nB: Ich bleibe ruhig und fokussiert.",exampleSrc:"A: How do you react to criticism?\nB: I take criticism seriously and learn from it.\nA: Good. And how do you react under stress?\nB: I stay calm and focused.",funFact:"'Wie reagieren Sie auf Kritik?' (How do you react to criticism?) is another classic interview question. From Latin 're-agere' (to act back)."},
{type:"teach",trg:"beachten",src:"to observe, to pay attention to",pos:"verb",gender:null,note:"Not separable. Be- + achten (to regard).\n'Bitte beachten Sie die Regeln.'",example:"A: Bitte beachten Sie die Frist.\nB: Wann ist die Frist?\nA: Am fünfzehnten März.\nB: Gut, ich beachte das. Vielen Dank.",exampleSrc:"A: Please observe the deadline.\nB: When is the deadline?\nA: On the fifteenth of March.\nB: Good, I will note that. Thank you.",funFact:"Achtung + be- prefix = active attention. 'Bitte beachten Sie die Regeln' (Please observe the rules). To beachten is to actively pay attention, not just to notice passively."},
{type:"teach",trg:"anfangs",src:"at first, initially",pos:"adv",gender:null,note:"From Anfang (beginning). The -s ending turns\nit into an adverb.",example:"A: Wie war der erste Tag?\nB: Anfangs war ich sehr nervös.\nA: Und jetzt?\nB: Jetzt fühle ich mich sicher.",exampleSrc:"A: How was the first day?\nB: At first I was very nervous.\nA: And now?\nB: Now I feel confident.",funFact:"'Anfangs war ich nervös' (At first I was nervous). Perfect for telling the story of how you started somewhere. The -s ending turns the noun Anfang into an adverb."},
{type:"teach",trg:"per",src:"by, via",pos:"prep",gender:null,note:"From Latin 'per' (through/by means of).\n'Per E-Mail,' 'per Post.' Formal usage.",example:"A: Wie schicke ich die Bewerbung?\nB: Per E-Mail oder per Post.\nA: Was ist besser?\nB: Die meisten Firmen bevorzugen per E-Mail.",exampleSrc:"A: How do I send the application?\nB: By email or by mail.\nA: What is better?\nB: Most companies prefer by email.",funFact:"'Per E-Mail' (by email), 'per Post' (by mail). Short, efficient, and used in formal writing. German borrowed it directly from Latin and never let go."},
{type:"mc",q:"Verumius muss ein Dokument über seine Ausbildung und Berufserfahrung schreiben. Wie heißt dieses Dokument?",opts:["Vorstellung","Bewerbung","Eindruck","Lebenslauf"],ans:"Lebenslauf",hint:"Dieses Dokument erzählt die Geschichte deines Lebens auf Papier."},
{type:"mc",q:"Dr. Yilmaz sagt: 'Der erste Eindruck zählt.' Was bedeutet Eindruck?",opts:["application","preparation","impression","success"],ans:"impression",hint:"Something that gets 'pressed into' someone's mind."},
{type:"fb",s:"Verumius muss seine {1} gut vorbereiten.",a:["Bewerbung"],opts:["Bewerbung","Karriere","Erfolg","Eindruck"],hint:"The three-part package you send when applying for a job in Germany.",sSrc:"Verumius must prepare his application well."},
{type:"match",pairs:[{trg:"Bewerbung",src:"application"},{trg:"Lebenslauf",src:"CV/resume"},{trg:"Erfolg",src:"success"},{trg:"Karriere",src:"career"},{trg:"Eindruck",src:"impression"},{trg:"Vorbereitung",src:"preparation"}]},
{type:"mc",q:"Was braucht ein deutscher Lebenslauf laut Dr. Yilmaz?",opts:["Nur den Namen und die Adresse","Ein kurzes Video","Nur die Berufserfahrung","Foto, Personaldaten, Ausbildung, Berufserfahrung"],ans:"Foto, Personaldaten, Ausbildung, Berufserfahrung",hint:"Yilmaz nennt vier Elemente, die einen deutschen Lebenslauf vollständig machen."}
]},

// ==================== LESSON 2: Berufe und Qualifikationen ====================
{id:"deu_r13l2",title:"Berufe und Qualifikationen",icon:"🎓",xp:15,board:true,steps:[
{type:"intro",title:"Berufe und Qualifikationen",desc:"Learn vocabulary for professions and qualifications. Understand the German training system. Master masculine/feminine job title pairs.",goals:["Name professions and qualifications","Understand the German training system","Master masculine/feminine job title pairs"]},
{type:"teach",trg:"die Qualifikation",src:"the qualification",pos:"noun",gender:"f",note:"Feminine noun. Same Latin root as English.\nGerman job ads list Qualifikationen precisely.",example:"A: Welche Qualifikationen haben Sie?\nB: Ich habe einen Master in Informatik.\nA: Und welche praktischen Qualifikationen?\nB: Drei Jahre Erfahrung als Entwickler.",exampleSrc:"A: What qualifications do you have?\nB: I have a Master's in computer science.\nA: And what practical qualifications?\nB: Three years of experience as a developer.",funFact:"German job ads list Qualifikationen more precisely than most countries. They expect you to prove every single one with a certificate or reference."},
{type:"teach",trg:"die Fähigkeit",src:"the ability, the skill",pos:"noun",gender:"f",note:"Feminine noun. From 'fähig' (capable) + '-keit.'\n'Soziale Fähigkeiten' = social skills.",example:"A: Welche Fähigkeiten bringen Sie mit?\nB: Ich bin gut im Teamwork.\nA: Haben Sie technische Fähigkeiten?\nB: Ja, ich kann programmieren.",exampleSrc:"A: What skills do you bring?\nB: I am good at teamwork.\nA: Do you have technical skills?\nB: Yes, I can program.",funFact:"'Soziale Fähigkeiten' (social skills) appear on every German job listing. The -keit ending always makes feminine nouns. Fähig (capable) becomes Fähigkeit (capability)."},
{type:"teach",trg:"die Fortbildung",src:"the continuing education",pos:"noun",gender:"f",note:"Feminine noun. Fort (further) + Bildung (education).\nProfessional development.",example:"A: Waren Sie auf einer Fortbildung?\nB: Ja, letzte Woche. Projektmanagement.\nA: Gut. Fortbildung ist uns wichtig.\nB: Mir auch. Ich lerne gern Neues.",exampleSrc:"A: Did you attend continuing education?\nB: Yes, last week. Project management.\nA: Good. Continuing education is important to us.\nB: To me too. I like learning new things.",funFact:"Germans take Fortbildung seriously. Many employers pay for it. It shows you never stop learning. Fort (further/onward) + Bildung (education)."},
{type:"teach",trg:"die Weiterbildung",src:"the further education",pos:"noun",gender:"f",note:"Feminine noun. Weiter (further) + Bildung (education).\nBroader than Fortbildung.",example:"A: Planen Sie eine Weiterbildung?\nB: Ja, ich möchte Spanisch lernen.\nA: Beruflich oder privat?\nB: Beides. Weiterbildung ist immer gut.",exampleSrc:"A: Are you planning further education?\nB: Yes, I would like to learn Spanish.\nA: Professionally or privately?\nB: Both. Further education is always good.",funFact:"Nearly synonymous with Fortbildung but broader. Weiterbildung can be personal growth too, not just professional. Both are feminine because of Bildung."},
{type:"teach",trg:"das Zertifikat",src:"the certificate",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'certificare' (to make certain).\nGermans love certificates.",example:"A: Haben Sie ein Zertifikat?\nB: Ja, ein B2-Zertifikat in Deutsch.\nA: Sehr gut. Das brauchen wir.\nB: Hier ist die Kopie.",exampleSrc:"A: Do you have a certificate?\nB: Yes, a B2 certificate in German.\nA: Very good. We need that.\nB: Here is the copy.",funFact:"Germans love certificates. You can get a Zertifikat for almost anything: language level, first aid, fire safety, even coffee brewing. Das Zertifikat is always neuter."},
{type:"teach",trg:"das Diplom",src:"the diploma",pos:"noun",gender:"n",note:"Neuter noun. From Greek 'diploma' (folded paper).\nThe traditional German university degree.",example:"A: Haben Sie ein Diplom?\nB: Ja, ein Diplom in Maschinenbau.\nA: Von welcher Universität?\nB: Von der TU München.",exampleSrc:"A: Do you have a diploma?\nB: Yes, a diploma in mechanical engineering.\nA: From which university?\nB: From the TU Munich.",funFact:"Das Diplom was the traditional German university degree before the Bologna reform. Some older Germans still proudly use 'Diplom-Ingenieur' as a title."},
{type:"teach",trg:"das Abitur",src:"the high school leaving exam",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'abire' (to go away).\nWithout it, university is nearly impossible.",example:"A: Hast du Abitur?\nB: Ja, mit der Note 1,8.\nA: Sehr gut! Was hast du dann studiert?\nB: Informatik in Berlin.",exampleSrc:"A: Do you have the Abitur?\nB: Yes, with a grade of 1.8.\nA: Very good! What did you study then?\nB: Computer science in Berlin.",funFact:"Das Abitur is the German high school leaving exam. It takes 12 to 13 years of schooling to reach. The equivalent of A-levels or SATs but considerably harder."},
{type:"teach",trg:"der Abschluss",src:"the degree, the completion",pos:"noun",gender:"m",note:"Masculine noun. Ab (off) + Schluss (closing).\n'Welchen Abschluss haben Sie?'",example:"A: Welchen Abschluss haben Sie?\nB: Einen Bachelor in Wirtschaft.\nA: Und planen Sie einen weiteren Abschluss?\nB: Ja, einen Master.",exampleSrc:"A: What degree do you have?\nB: A Bachelor's in economics.\nA: And are you planning another degree?\nB: Yes, a Master's.",funFact:"'Welchen Abschluss haben Sie?' is a standard interview question. The word implies you closed a chapter of your education. Ab (off) + Schluss (closing)."},
{type:"teach",trg:"die Lehre",src:"the apprenticeship",pos:"noun",gender:"f",note:"Feminine noun. From 'lehren' (to teach).\nGermany's famous dual education system.",example:"A: Hast du eine Lehre gemacht?\nB: Ja, als Elektriker. Drei Jahre.\nA: Wo war die Lehre?\nB: Bei Bosch in Stuttgart.",exampleSrc:"A: Did you do an apprenticeship?\nB: Yes, as an electrician. Three years.\nA: Where was the apprenticeship?\nB: At Bosch in Stuttgart.",funFact:"Die Lehre is Germany's famous dual education system: you work at a company AND attend school. Fifty percent of Germans do a Lehre instead of university."},
{type:"teach",trg:"der Lehrling",src:"the apprentice",pos:"noun",gender:"m",note:"Masculine noun. Lehre + -ling (person suffix).\nThe -ling suffix has a junior quality.",example:"A: Wie viele Lehrlinge habt ihr?\nB: Dieses Jahr fünf neue Lehrlinge.\nA: In welchem Bereich?\nB: Drei in der IT, zwei im Marketing.",exampleSrc:"A: How many apprentices do you have?\nB: This year five new apprentices.\nA: In which field?\nB: Three in IT, two in marketing.",funFact:"The -ling suffix often has a diminutive or junior quality: Lehrling (apprentice), Frühling (spring, the 'young' season). Always masculine grammatically."},
{type:"teach",trg:"die Lehrstelle",src:"the apprenticeship position",pos:"noun",gender:"f",note:"Feminine noun. Lehre + Stelle (position).\nFinding one is a big deal for teenagers.",example:"A: Hast du schon eine Lehrstelle gefunden?\nB: Nein, ich suche noch.\nA: Bewirb dich bei Siemens.\nB: Gute Idee. Die haben viele Lehrstellen.",exampleSrc:"A: Have you found an apprenticeship position yet?\nB: No, I am still looking.\nA: Apply at Siemens.\nB: Good idea. They have many positions.",funFact:"Finding a Lehrstelle is a big deal for German teenagers. Companies compete for good Lehrlinge, and Lehrlinge compete for good Lehrstellen."},
{type:"teach",trg:"der Praktikant",src:"the intern (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'Praktikum' + '-ant.'\nThe -ant ending signals a person doing something.",example:"A: Der neue Praktikant fängt morgen an.\nB: Wie lange bleibt er?\nA: Drei Monate.\nB: Gut. Ich zeige ihm alles.",exampleSrc:"A: The new intern starts tomorrow.\nB: How long will he stay?\nA: Three months.\nB: Good. I will show him everything.",funFact:"The -ant ending comes from Latin and always signals a person doing something. Always masculine. From Praktikum (internship)."},
{type:"teach",trg:"die Praktikantin",src:"the intern (female)",pos:"noun",gender:"f",note:"Feminine noun. Praktikant + '-in.'\nThe -in suffix is the universal feminine marker.",example:"A: Unsere Praktikantin ist sehr fleißig.\nB: Ja, sie arbeitet hervorragend.\nA: Vielleicht stellen wir sie ein.\nB: Das wäre toll für sie.",exampleSrc:"A: Our intern is very diligent.\nB: Yes, she works excellently.\nA: Maybe we will hire her.\nB: That would be great for her.",funFact:"German always has masculine/feminine pairs for professions. The -in suffix is the universal feminine marker. Always die."},
{type:"teach",trg:"der Ingenieur",src:"the engineer",pos:"noun",gender:"m",note:"Masculine noun. From French 'ingénieur.'\nA title of respect in Germany.",example:"A: Was ist Ihr Beruf?\nB: Ich bin Ingenieur.\nA: In welchem Bereich?\nB: Maschinenbau. Seit zehn Jahren.",exampleSrc:"A: What is your profession?\nB: I am an engineer.\nA: In which field?\nB: Mechanical engineering. For ten years.",funFact:"Germany is famous for engineering. 'Made in Germany' was originally a British warning label. Germans turned it into a badge of pride. Der Ingenieur is a title of respect."},
{type:"teach",trg:"der Architekt",src:"the architect (male)",pos:"noun",gender:"m",note:"Masculine noun. From Greek 'architekton' (master builder).\nRequires university degree and state registration.",example:"A: Wer hat dieses Gebäude entworfen?\nB: Ein bekannter Architekt aus Berlin.\nA: Es ist wunderschön.\nB: Ja, der Architekt hat viele Preise gewonnen.",exampleSrc:"A: Who designed this building?\nB: A well-known architect from Berlin.\nA: It is beautiful.\nB: Yes, the architect has won many awards.",funFact:"Germany's Bauhaus movement revolutionized architecture worldwide. German architects are required to have a university degree and state registration."},
{type:"teach",trg:"die Architektin",src:"the architect (female)",pos:"noun",gender:"f",note:"Feminine noun. Architekt + '-in.'\nThe -in suffix works on every profession.",example:"A: Die Architektin hat den Plan geändert.\nB: Warum?\nA: Das Dach war zu flach.\nB: Sie hat recht. Sicherheit geht vor.",exampleSrc:"A: The architect changed the plan.\nB: Why?\nA: The roof was too flat.\nB: She is right. Safety comes first.",funFact:"The -in suffix works on every profession: Lehrer/Lehrerin, Arzt/Ärztin, Architekt/Architektin. Once you know the pattern, you can feminize any profession."},
{type:"teach",trg:"der Mechaniker",src:"the mechanic (male)",pos:"noun",gender:"m",note:"Masculine noun. From Greek 'mechanikos.'\nRequires a 3.5-year apprenticeship in Germany.",example:"A: Mein Auto ist kaputt.\nB: Bring es zum Mechaniker.\nA: Kennst du einen guten Mechaniker?\nB: Ja, in der Hauptstraße. Sehr zuverlässig.",exampleSrc:"A: My car is broken.\nB: Take it to the mechanic.\nA: Do you know a good mechanic?\nB: Yes, on the main street. Very reliable.",funFact:"In Germany, a Mechaniker must complete a 3.5-year apprenticeship. German car mechanics are among the best trained in the world because of this system."},
{type:"teach",trg:"die Mechanikerin",src:"the mechanic (female)",pos:"noun",gender:"f",note:"Feminine noun. Mechaniker + '-in.'\nMore women enter traditionally male professions.",example:"A: Die Mechanikerin hat mein Auto repariert.\nB: War sie gut?\nA: Ausgezeichnet. Schnell und professionell.\nB: Gut zu wissen.",exampleSrc:"A: The mechanic repaired my car.\nB: Was she good?\nA: Excellent. Fast and professional.\nB: Good to know.",funFact:"More and more women enter traditionally male professions in Germany. The language always had the feminine form ready."},
{type:"teach",trg:"beruflich",src:"professional, work-related",pos:"adj",gender:null,note:"Beruf (profession) + -lich.\n'Beruflich läuft es gut' = Professionally, things are going well.",example:"A: Wie läuft es beruflich?\nB: Gut. Ich habe eine Beförderung bekommen.\nA: Glückwunsch! Und privat?\nB: Auch gut. Alles in Balance.",exampleSrc:"A: How are things going professionally?\nB: Good. I got a promotion.\nA: Congratulations! And personally?\nB: Also good. Everything in balance.",funFact:"The -lich suffix turns nouns into adjectives, like English '-ly.' Beruf (profession) becomes beruflich (professional). Freund becomes freundlich (friendly)."},
{type:"teach",trg:"berufstätig",src:"employed, working",pos:"adj",gender:null,note:"Beruf + tätig (active/engaged).\n'Sind Sie berufstätig?' = Are you employed?",example:"A: Sind Sie berufstätig?\nB: Ja, ich arbeite als Lehrerin.\nA: Vollzeit oder Teilzeit?\nB: Vollzeit. Vierzig Stunden pro Woche.",exampleSrc:"A: Are you employed?\nB: Yes, I work as a teacher.\nA: Full-time or part-time?\nB: Full-time. Forty hours per week.",funFact:"'Sind Sie berufstätig?' (Are you employed?) is a standard form question. Being berufstätig is a core part of German identity."},
{type:"teach",trg:"die Ingenieurin",src:"the engineer (female)",pos:"noun",gender:"f",note:"Feminine of Ingenieur. Ingenieur + '-in.'\nThe -in suffix works on every profession.",example:"A: Die Ingenieurin hat den Plan erstellt.\nB: Welche Ingenieurin?\nA: Frau Dr. Braun. Sie arbeitet bei Siemens.\nB: Eine erfahrene Ingenieurin.",exampleSrc:"A: The engineer created the plan.\nB: Which engineer?\nA: Dr. Braun. She works at Siemens.\nB: An experienced engineer.",funFact:"Germany has seen a steady increase in female engineers. The -in suffix applies to every profession: Ingenieur/Ingenieurin, just like Lehrer/Lehrerin."},
{type:"tip",title:"Das deutsche -in-Muster",text:"Every masculine profession has a feminine form: add -in.\n\nLehrer / Lehrerin (teacher)\nIngenieur / Ingenieurin (engineer)\nArchitekt / Architektin (architect)\nMechaniker / Mechanikerin (mechanic)\n\nThe plural feminizes too:\nLehrerinnen, Architektinnen\n\nModern German increasingly uses gender-neutral forms:\nArchitekt*innen or Ingenieur:innen\n\nYou will see all variants in job listings and official documents.",deepDive:{title:"N-Deklination bei Berufen",text:"Some masculine profession nouns follow the n-Deklination. They add -n or -en in all cases except nominative singular.\n\nder Architekt, den Architekten, dem Architekten\nder Kandidat, den Kandidaten, dem Kandidaten\nder Praktikant, den Praktikanten, dem Praktikanten\n\nClues: masculine nouns ending in -ent, -ant, -ist, -at, or -e often follow this pattern."}},
{type:"mc",q:"A female engineer in German is...",opts:["Ingenieur","Architektin","Ingenieurin","Mechanikerin"],ans:"Ingenieurin",hint:"Take the masculine profession word for engineer and add the feminine suffix."},
{type:"match",pairs:[{trg:"Abitur",src:"high school exam"},{trg:"Lehre",src:"apprenticeship"},{trg:"Diplom",src:"university degree"},{trg:"Zertifikat",src:"certificate"},{trg:"Abschluss",src:"degree/completion"},{trg:"Fortbildung",src:"continuing education"}]},
{type:"fb",s:"Nach dem Studium hat sie einen {1} in Informatik.",a:["Abschluss"],opts:["Abschluss","Anfang","Lehrling","Praktikant"],hint:"The word for completing your education, literally a 'closing off.'",sSrc:"After her studies she has a degree in computer science."},
{type:"mc",q:"Weiterbildung means...",opts:["university degree","apprenticeship","job interview","continuing education"],ans:"continuing education",hint:"Weiter means further. Bildung means education. Put them together."}
]},

// ==================== LESSON 3: Ich studierte in Istanbul ====================
{id:"deu_r13l3",title:"Ich studierte in Istanbul",icon:"📜",xp:15,board:true,steps:[
{type:"intro",title:"Ich studierte in Istanbul",desc:"Learn the Präteritum (narrative past tense). Write your work experience in formal German. Master professional documentation vocabulary.",goals:["Learn the Präteritum (narrative past tense)","Write work experience in formal German","Master professional documentation vocabulary"]},
{type:"story",speaker:"yilmaz",mood:"encouraging",art:"de-vhs-office-desk",trg:"Für den Lebenslauf brauchst du das Präteritum. Nicht 'Ich habe studiert,' sondern 'Ich studierte.' Das klingt professioneller.",src:"For the CV you need the Präteritum. Not 'I have studied,' but 'I studied.' That sounds more professional."},
{type:"story",speaker:"verumius",mood:"thinking",trg:"Also: 'Ich studierte Linguistik in Istanbul. Ich arbeitete drei Jahre als Übersetzer.' So?",src:"So: 'I studied linguistics in Istanbul. I worked three years as a translator.' Like that?"},
{type:"story",speaker:"yilmaz",mood:"pleased",trg:"Genau! Und bei starken Verben ändert sich der Vokal: 'Ich schrieb,' nicht 'Ich schreibte.' Das musst du lernen.",src:"Exactly! And with strong verbs the vowel changes: 'Ich schrieb,' not 'Ich schreibte.' You need to learn that."},
{type:"teach",trg:"die Angabe",src:"the information, the detail",pos:"noun",gender:"f",note:"Feminine noun. An (at) + Gabe (giving).\n'Persönliche Angaben' = personal details on a CV.",example:"A: Sind alle Angaben korrekt?\nB: Ja, ich habe alles überprüft.\nA: Gut. Falsche Angaben können Probleme verursachen.\nB: Ich weiß. Alles ist korrekt.",exampleSrc:"A: Is all the information correct?\nB: Yes, I checked everything.\nA: Good. False information can cause problems.\nB: I know. Everything is correct.",funFact:"'Persönliche Angaben' is the first section on every German CV. Die Angabe is always feminine because of the -e ending from Gabe."},
{type:"teach",trg:"die Personalie",src:"the personal detail",pos:"noun",gender:"f",note:"Feminine noun. Usually plural: Personalien.\n'Personalien aufnehmen' = to take down details.",example:"A: Bitte geben Sie Ihre Personalien an.\nB: Name, Adresse, Geburtsdatum?\nA: Ja, und Ihren Familienstand.\nB: Ledig. Hier sind meine Personalien.",exampleSrc:"A: Please state your personal details.\nB: Name, address, date of birth?\nA: Yes, and your marital status.\nB: Single. Here are my details.",funFact:"'Personalien aufnehmen' is what police do when they take down your details. On a CV, your Personalien include name, address, and date of birth."},
{type:"teach",trg:"der Personenstand",src:"the marital status",pos:"noun",gender:"m",note:"Masculine noun. Personen + Stand (status).\nLedig (single), verheiratet (married).",example:"A: Wie ist Ihr Personenstand?\nB: Ich bin ledig.\nA: Das gehört auf den Lebenslauf?\nB: Traditionell ja, aber es ist freiwillig.",exampleSrc:"A: What is your marital status?\nB: I am single.\nA: Does that go on the CV?\nB: Traditionally yes, but it is voluntary.",funFact:"German CVs traditionally include marital status. Many modern career advisors now recommend leaving it out. Ledig (single), verheiratet (married)."},
{type:"teach",trg:"das Personal",src:"the staff, the personnel",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'personalis.'\n'Die Personalabteilung' = HR department.",example:"A: Haben Sie genug Personal?\nB: Nein, wir brauchen mehr Personal.\nA: In welcher Abteilung?\nB: Im Kundenservice. Fünf neue Stellen.",exampleSrc:"A: Do you have enough staff?\nB: No, we need more staff.\nA: In which department?\nB: In customer service. Five new positions.",funFact:"'Die Personalabteilung' (HR department) handles your Bewerbung. Das Personal is neuter and collective. One word for all the people who work somewhere."},
{type:"teach",trg:"die Empfehlung",src:"the recommendation",pos:"noun",gender:"f",note:"Feminine noun. From 'empfehlen' (to recommend).\n'Empfehlungsschreiben' = letter of recommendation.",example:"A: Haben Sie eine Empfehlung?\nB: Ja, von meinem früheren Chef.\nA: Gut. Eine gute Empfehlung hilft sehr.\nB: Hier ist das Schreiben.",exampleSrc:"A: Do you have a recommendation?\nB: Yes, from my former boss.\nA: Good. A good recommendation helps a lot.\nB: Here is the letter.",funFact:"'Empfehlungsschreiben' (letter of recommendation) is a standard part of German job applications. Germans value written Empfehlungen highly."},
{type:"teach",trg:"der Bericht",src:"the report",pos:"noun",gender:"m",note:"Masculine noun. From 'berichten' (to report).\nArbeitsbericht, Jahresbericht.",example:"A: Der Bericht ist fertig.\nB: Gut. Wie lang ist er?\nA: Zehn Seiten. Mit Grafiken.\nB: Perfekt. Schicken Sie ihn per E-Mail.",exampleSrc:"A: The report is finished.\nB: Good. How long is it?\nA: Ten pages. With graphics.\nB: Perfect. Send it by email.",funFact:"'Arbeitsbericht' (work report), 'Jahresbericht' (annual report). Der Bericht is always masculine. Germans document everything in writing."},
{type:"teach",trg:"der Bereich",src:"the field, the area",pos:"noun",gender:"m",note:"Masculine noun. Be- + Reich (realm/area).\n'In welchem Bereich arbeiten Sie?'",example:"A: In welchem Bereich arbeiten Sie?\nB: Im IT-Bereich.\nA: Und in welchem Fachbereich genau?\nB: Softwareentwicklung.",exampleSrc:"A: In which field do you work?\nB: In the IT field.\nA: And in which specialty exactly?\nB: Software development.",funFact:"'In welchem Bereich arbeiten Sie?' (In which field do you work?) is a networking question. Der Bereich covers everything from 'Fachbereich' (department) to 'Lebensbereich' (area of life)."},
{type:"teach",trg:"der Beitrag",src:"the contribution",pos:"noun",gender:"m",note:"Masculine noun. Bei- (alongside) + Trag (carrying).\nAlso means 'fee' in some contexts.",example:"A: Jeder Mitarbeiter leistet einen Beitrag.\nB: Was ist mein Beitrag?\nA: Ihre Sprachkenntnisse. Das ist sehr wertvoll.\nB: Danke. Ich gebe mein Bestes.",exampleSrc:"A: Every employee makes a contribution.\nB: What is my contribution?\nA: Your language skills. That is very valuable.\nB: Thank you. I will do my best.",funFact:"'Einen Beitrag leisten' (to make a contribution) is formal language for doing your part. Also means 'fee' in contexts like 'Mitgliedsbeitrag' (membership fee)."},
{type:"teach",trg:"die Beschäftigung",src:"the employment, the occupation",pos:"noun",gender:"f",note:"Feminine noun. From 'beschäftigen' (to employ).\nThe -ung ending always makes feminine nouns.",example:"A: Was ist Ihre aktuelle Beschäftigung?\nB: Ich bin als Übersetzer beschäftigt.\nA: Vollzeit?\nB: Ja, seit zwei Jahren.",exampleSrc:"A: What is your current occupation?\nB: I am employed as a translator.\nA: Full-time?\nB: Yes, for two years.",funFact:"'Beschäftigungsverhältnis' (employment relationship) is a word that only German bureaucracy could produce. Die Beschäftigung is feminine because of the -ung ending."},
{type:"teach",trg:"die Bedingung",src:"the condition, the requirement",pos:"noun",gender:"f",note:"Feminine noun. From 'bedingen' (to require).\n'Arbeitsbedingungen' = working conditions.",example:"A: Wie sind die Arbeitsbedingungen?\nB: Gut. Flexible Zeiten und Homeoffice.\nA: Unter welchen Bedingungen arbeiten Sie?\nB: Ich brauche mindestens 30 Urlaubstage.",exampleSrc:"A: How are the working conditions?\nB: Good. Flexible hours and home office.\nA: Under what conditions do you work?\nB: I need at least 30 vacation days.",funFact:"'Arbeitsbedingungen' (working conditions) matter in every job. The -ung ending always makes feminine nouns. German workers are protected by strict labor laws."},
{type:"teach",trg:"der Bedarf",src:"the need, the demand",pos:"noun",gender:"m",note:"Masculine noun. From 'bedürfen' (to require).\n'Bei Bedarf' = if needed/on demand.",example:"A: Gibt es Bedarf an Übersetzern?\nB: Ja, der Bedarf ist groß.\nA: In welchen Sprachen?\nB: Besonders Türkisch und Arabisch.",exampleSrc:"A: Is there a need for translators?\nB: Yes, the demand is great.\nA: In which languages?\nB: Especially Turkish and Arabic.",funFact:"'Bei Bedarf' (if needed/on demand) appears in contracts and job ads. Der Bedarf is always masculine. The professional way to say 'if you need it.'"},
{type:"teach",trg:"der Anspruch",src:"the claim, the entitlement",pos:"noun",gender:"m",note:"Masculine noun. An + Spruch (saying/claim).\n'Anspruch auf Urlaub' = entitlement to vacation.",example:"A: Habe ich Anspruch auf Urlaub?\nB: Ja, mindestens zwanzig Tage.\nA: Und Anspruch auf Weiterbildung?\nB: Ja, fünf Tage pro Jahr.",exampleSrc:"A: Do I have a right to vacation?\nB: Yes, at least twenty days.\nA: And a right to continuing education?\nB: Yes, five days per year.",funFact:"German workers have strong Ansprüche by law: minimum 20 vacation days, health insurance, parental leave. 'Anspruch auf Urlaub' is a legal entitlement."},
{type:"teach",trg:"das Werk",src:"the work, the factory",pos:"noun",gender:"n",note:"Neuter noun. Cognate with English 'work.'\nDas Werk von Goethe, Automobilwerk.",example:"A: In welchem Werk arbeiten Sie?\nB: Im Volkswagen-Werk in Wolfsburg.\nA: Wie groß ist das Werk?\nB: Über 60.000 Mitarbeiter.",exampleSrc:"A: In which factory do you work?\nB: In the Volkswagen factory in Wolfsburg.\nA: How big is the factory?\nB: Over 60,000 employees.",funFact:"'Das Werk von Goethe' (the works of Goethe), 'Automobilwerk' (car factory). Cognate with English 'work.' Different from 'Arbeit' (labor). Das Werk is neuter."},
{type:"teach",trg:"erfolgreich",src:"successful",pos:"adj",gender:null,note:"Erfolg (success) + reich (rich).\n'Eine erfolgreiche Bewerbung' = a successful application.",example:"A: War die Bewerbung erfolgreich?\nB: Ja! Ich habe die Stelle bekommen.\nA: Herzlichen Glückwunsch! Du bist erfolgreich.\nB: Danke. Die Vorbereitung hat geholfen.",exampleSrc:"A: Was the application successful?\nB: Yes! I got the job.\nA: Congratulations! You are successful.\nB: Thanks. The preparation helped.",funFact:"Literally 'rich in success.' The -reich suffix means 'rich in' or 'full of.' 'Eine erfolgreiche Bewerbung' is what everyone hopes for."},
{type:"teach",trg:"erforderlich",src:"required, necessary",pos:"adj",gender:null,note:"From 'erfordern' (to require).\nMore formal than 'nötig' (needed).",example:"A: Welche Dokumente sind erforderlich?\nB: Lebenslauf, Anschreiben und Zeugnisse.\nA: Ist ein Foto erforderlich?\nB: Nicht mehr, aber es wird empfohlen.",exampleSrc:"A: Which documents are required?\nB: CV, cover letter, and certificates.\nA: Is a photo required?\nB: Not anymore, but it is recommended.",funFact:"'Erforderliche Qualifikationen' appears in every job listing. More formal than 'nötig' (needed). The official language of job ads."},
{type:"teach",trg:"bestimmt",src:"certain, specific, definitely",pos:"adj",gender:null,note:"From 'bestimmen' (to determine).\nAlso an adverb: 'Das klappt bestimmt!'",example:"A: Suchen Sie eine bestimmte Stelle?\nB: Ja, im Bereich Übersetzung.\nA: Das klappt bestimmt!\nB: Danke. Ich bin optimistisch.",exampleSrc:"A: Are you looking for a specific position?\nB: Yes, in the translation field.\nA: That will definitely work!\nB: Thanks. I am optimistic.",funFact:"Double function: 'Ein bestimmter Bereich' (a specific area) as adjective. 'Das klappt bestimmt!' (That will definitely work!) as adverb. Context decides."},
{type:"teach",trg:"komplett",src:"complete, entire",pos:"adj",gender:null,note:"From French 'complet,' from Latin 'completus.'\n'Ihre Bewerbung ist komplett.'",example:"A: Ist meine Bewerbung komplett?\nB: Fast. Es fehlt noch ein Zeugnis.\nA: Welches?\nB: Das Arbeitszeugnis von Ihrer letzten Stelle.",exampleSrc:"A: Is my application complete?\nB: Almost. A certificate is still missing.\nA: Which one?\nB: The work reference from your last position.",funFact:"'Ihre Bewerbung ist komplett' (Your application is complete) is what you want to hear from HR. From French 'complet,' from Latin 'completus.'"},
{type:"teach",trg:"offiziell",src:"official",pos:"adj",gender:null,note:"From French 'officiel,' from Latin 'officium.'\nStress on the last syllable: off-ih-tsee-ELL.",example:"A: Ist das ein offizielles Dokument?\nB: Ja, mit Stempel und Unterschrift.\nA: Gut. Wir brauchen offizielle Unterlagen.\nB: Hier sind alle offiziellen Papiere.",exampleSrc:"A: Is this an official document?\nB: Yes, with stamp and signature.\nA: Good. We need official documents.\nB: Here are all the official papers.",funFact:"Pronounced 'off-ih-tsee-ELL' with stress on the last syllable. German borrowed it with French pronunciation. 'Ein offizielles Dokument' (an official document)."},
{type:"teach",trg:"angeben",src:"to state, to specify",pos:"verb",gender:null,note:"Separable verb. An + geben (to give).\n'Bitte geben Sie Ihre Adresse an.'",example:"A: Bitte geben Sie Ihre Adresse an.\nB: Hauptstraße 12, 10115 Berlin.\nA: Und Ihre Telefonnummer?\nB: Gebe ich auch an. 030-12345.",exampleSrc:"A: Please state your address.\nB: Main Street 12, 10115 Berlin.\nA: And your phone number?\nB: I will state that too. 030-12345.",funFact:"Separable verb: 'Ich gebe meine Daten an.' Also colloquially means 'to show off.' 'Gib nicht so an!' (Don't show off!). Context matters."},
{type:"teach",trg:"beschäftigen",src:"to employ, to occupy",pos:"verb",gender:null,note:"Not separable. Reflexive: 'sich beschäftigen mit...'\n'Die Firma beschäftigt 200 Mitarbeiter.'",example:"A: Wie viele Leute beschäftigt die Firma?\nB: Etwa 500 Mitarbeiter.\nA: Und womit beschäftigen Sie sich?\nB: Ich beschäftige mich mit Softwareentwicklung.",exampleSrc:"A: How many people does the company employ?\nB: About 500 employees.\nA: And what do you occupy yourself with?\nB: I occupy myself with software development.",funFact:"Two uses: 'Die Firma beschäftigt 200 Mitarbeiter' (The company employs 200 workers). Reflexive: 'Ich beschäftige mich mit...' (I occupy myself with...)."},
{type:"tip",title:"Präteritum: The Narrative Past",text:"Spoken German mostly uses the Perfekt:\nIch habe geschrieben.\n\nBut written German, especially in CVs, uses the Präteritum:\nIch schrieb.\n\nStrong verbs change the vowel:\nschreiben / schrieb, gehen / ging, kommen / kam\n\nWeak verbs add -te:\narbeiten / arbeitete, studieren / studierte\n\nFor sein, haben, and modal verbs, even spoken German uses Präteritum:\nwar, hatte, konnte, musste.",deepDive:{title:"When Präteritum, when Perfekt?",text:"Rule of thumb:\n\nPräteritum in:\n1. CVs and formal texts\n2. Narratives and reports\n3. With sein, haben, modal verbs (always)\n\nPerfekt in:\n1. Everyday conversations\n2. Oral reports\n3. Informal emails\n\n'Ich studierte in Istanbul' sounds more professional than 'Ich habe in Istanbul studiert.' Both are correct, but the CV demands Präteritum."}},
{type:"verb_table",title:"Präteritum: Starke Verben",groups:[{label:"Häufige starke Verben",rows:[{pronoun:"gehen",form:"ging",src:"went"},{pronoun:"kommen",form:"kam",src:"came"},{pronoun:"schreiben",form:"schrieb",src:"wrote"},{pronoun:"sprechen",form:"sprach",src:"spoke"},{pronoun:"geben",form:"gab",src:"gave"},{pronoun:"nehmen",form:"nahm",src:"took"},{pronoun:"finden",form:"fand",src:"found"},{pronoun:"stehen",form:"stand",src:"stood"},{pronoun:"lesen",form:"las",src:"read"}]},{label:"Konjugation: schreiben",rows:[{pronoun:"ich",form:"schrieb",src:"I wrote"},{pronoun:"du",form:"schriebst",src:"you wrote"},{pronoun:"er/sie/es",form:"schrieb",src:"he/she/it wrote"},{pronoun:"wir",form:"schrieben",src:"we wrote"},{pronoun:"ihr",form:"schriebt",src:"you all wrote"},{pronoun:"sie/Sie",form:"schrieben",src:"they/you wrote"}]}],note:"Strong verbs change their stem vowel in the Präteritum. The ich and er/sie/es forms are identical: ich schrieb, er schrieb."},

{type:"verb_table",title:"Präteritum: sein (war)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"war",src:"I was"},{pronoun:"du",form:"warst",src:"you were"},{pronoun:"er/sie/es",form:"war",src:"he/she/it was"}]},{label:"Plural",rows:[{pronoun:"wir",form:"waren",src:"we were"},{pronoun:"ihr",form:"wart",src:"you all were"},{pronoun:"sie/Sie",form:"waren",src:"they/you (formal) were"}]}],note:"Only 4 forms: war, warst, wart, waren. ich and er/sie/es share: war. Sein and haben ALWAYS use Präteritum, even in conversation."},
{type:"verb_table",title:"Präteritum: haben (hatte)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"hatte",src:"I had"},{pronoun:"du",form:"hattest",src:"you had"},{pronoun:"er/sie/es",form:"hatte",src:"he/she/it had"}]},{label:"Plural",rows:[{pronoun:"wir",form:"hatten",src:"we had"},{pronoun:"ihr",form:"hattet",src:"you all had"},{pronoun:"sie/Sie",form:"hatten",src:"they/you (formal) had"}]}],note:"Only 4 forms: hatte, hattest, hattet, hatten. ich and er/sie/es share: hatte."},
{type:"verb_table",title:"Präteritum: Schwache Verben (machen)",groups:[{label:"Konjugation",rows:[{pronoun:"ich",form:"machte",src:"I did/made"},{pronoun:"du",form:"machtest",src:"you did/made"},{pronoun:"er/sie/es",form:"machte",src:"he/she/it did/made"},{pronoun:"wir",form:"machten",src:"we did/made"},{pronoun:"ihr",form:"machtet",src:"you all did/made"},{pronoun:"sie/Sie",form:"machten",src:"they/you did/made"}]}],note:"ich = er/sie/es (both -te). wir = sie/Sie (both -ten). Same pattern for ALL weak verbs.",deepDive:{title:"The -ete Exception",text:"Verbs with stems ending in -t/-d add an extra -e:\narbeiten: arbeitete (not arbeitte)\nwarten: wartete\nreden: redete\n\nWhy? Arbeitte is impossible to pronounce. The extra -e is a pronunciation aid."}},
{type:"verb_table",title:"Präteritum: gehen und kommen",groups:[{label:"gehen (ging)",rows:[{pronoun:"ich",form:"ging",src:"I went"},{pronoun:"du",form:"gingst",src:"you went"},{pronoun:"er/sie/es",form:"ging",src:"he/she/it went"},{pronoun:"wir",form:"gingen",src:"we went"},{pronoun:"ihr",form:"gingt",src:"you all went"},{pronoun:"sie/Sie",form:"gingen",src:"they/you went"}]},{label:"kommen (kam)",rows:[{pronoun:"ich",form:"kam",src:"I came"},{pronoun:"du",form:"kamst",src:"you came"},{pronoun:"er/sie/es",form:"kam",src:"he/she/it came"},{pronoun:"wir",form:"kamen",src:"we came"},{pronoun:"ihr",form:"kamt",src:"you all came"},{pronoun:"sie/Sie",form:"kamen",src:"they/you came"}]}],note:"ich = er/sie/es (no ending). du adds -st. ihr adds -t. wir/sie/Sie add -en."},
{type:"tip",title:"Vowel Change Groups: Strong Verbs",text:"Strong verbs follow patterns:\ne to a (largest group): nahm, sprach, las, gab, kam, sah, fand\nei to ie: schrieb (schreiben), blieb (bleiben), stieg (steigen)\na to u: trug (tragen), fuhr (fahren), wuchs (wachsen)\ne to i: ging (gehen)\n\nThe e-to-a group is by far the largest.\nOnce you know the vowel change, you can predict new forms.",deepDive:{title:"The war/hatte Exception",text:"Most Präteritum forms sound stiff in conversation.\nBut war and hatte are EXCEPTIONS:\n\n'Ich war müde' sounds natural.\n'Ich bin müde gewesen' sounds clunky.\n\nRule: Use war/hatte ALWAYS, in speech AND writing.\nSame applies to modal verbs: konnte, musste, wollte, sollte, durfte."}},
{type:"verb_table",title:"Präteritum: Gemischte Verben",groups:[{label:"bringen (brachte)",rows:[{pronoun:"ich",form:"brachte",src:"I brought"},{pronoun:"du",form:"brachtest",src:"you brought"},{pronoun:"er/sie/es",form:"brachte",src:"he/she/it brought"}]},{label:"denken (dachte)",rows:[{pronoun:"ich",form:"dachte",src:"I thought"},{pronoun:"du",form:"dachtest",src:"you thought"},{pronoun:"er/sie/es",form:"dachte",src:"he/she/it thought"}]},{label:"wissen (wusste)",rows:[{pronoun:"ich",form:"wusste",src:"I knew"},{pronoun:"du",form:"wusstest",src:"you knew"},{pronoun:"er/sie/es",form:"wusste",src:"he/she/it knew"}]}],note:"Mixed verbs: vowel change AND -te ending. Three types:\n1. Weak (regular): stem + -te (machte)\n2. Strong (irregular): vowel change, no -te (ging)\n3. Mixed: vowel change + -te (brachte, dachte, wusste)"},
{type:"teach",trg:"wissen",src:"to know (a fact)",pos:"verb",gender:null,note:"Irregular: weiß/wusste/gewusst.\n'Ich weiß es nicht' = I don't know.",example:"A: Weißt du, wo das Büro ist?\nB: Ja, ich weiß es. Zweiter Stock.\nA: Wusste Verumius das?\nB: Nein, er wusste es nicht.",exampleSrc:"A: Do you know where the office is?\nB: Yes, I know. Second floor.\nA: Did Verumius know that?\nB: No, he didn't know.",funFact:"Wissen vs. kennen: wissen = to know a FACT, kennen = to know a PERSON or PLACE. 'Ich weiß die Antwort' but 'Ich kenne diesen Mann.' This is one of the most common mistakes for German learners.",deepDive:{title:"wissen vs. kennen",text:"wissen = Fakten kennen:\nIch weiß, wo er wohnt.\nIch weiß die Antwort.\nIch wusste das nicht.\n\nkennen = vertraut sein mit Personen, Orten, Dingen:\nIch kenne diesen Mann.\nKennst du Berlin?\nIch kannte das Lied nicht.\n\nkennen braucht immer ein OBJEKT.\nwissen kann mit dass-Sätzen stehen."}},
{type:"teach",trg:"kennen",src:"to know (a person/place)",pos:"verb",gender:null,note:"Mixed verb: kennen/kannte/gekannt.\n'Ich kenne ihn' = I know him (personally).",example:"A: Kennen Sie Herrn Müller?\nB: Ja, ich kenne ihn seit Jahren.\nA: Und kennen Sie Hamburg?\nB: Nein, ich kannte nur Berlin, bis ich hierherkam.",exampleSrc:"A: Do you know Mr. Müller?\nB: Yes, I have known him for years.\nA: And do you know Hamburg?\nB: No, I only knew Berlin until I came here.",funFact:"Kennen is a mixed verb: the stem vowel changes (kennen/kannte) AND it takes the -te ending. Part of the kennen/kannte/gekannt family with nennen/nannte and rennen/rannte."},

{type:"mc",q:"Yilmaz schreibt auf Verumius' Lebenslauf: 'Er studierte drei Jahre in Istanbul.' Welche Zeitform ist 'studierte'?",opts:["Präsens (Gegenwart)","Futur (Zukunft)","Perfekt (gesprochene Vergangenheit)","Präteritum (erzählende Vergangenheit)"],ans:"Präteritum (erzählende Vergangenheit)",hint:"The -te ending on a regular verb signals the formal written past tense."},
{type:"fb",s:"Er {1} nach Deutschland und fand eine neue Heimat.",a:["kam"],opts:["kam","kommt","gekommen","kommen"],hint:"Kommen in the Präteritum changes its vowel completely. Think of English 'came.'",sSrc:"He came to Germany and found a new home."},
{type:"mc",q:"Welches Wort bedeutet 'recommendation' in a professional context?",opts:["Bedingung","Beschäftigung","Empfehlung","Angabe"],ans:"Empfehlung",hint:"From 'empfehlen' (to recommend). A letter from your former boss."},
{type:"match",pairs:[{trg:"Angabe",src:"information/detail"},{trg:"Bericht",src:"report"},{trg:"Bereich",src:"field/area"},{trg:"Beschäftigung",src:"employment"},{trg:"Bedarf",src:"need/demand"},{trg:"Empfehlung",src:"recommendation"}]}
]},

// ==================== LESSON 4: Ich würde mich freuen ====================
{id:"deu_r13l4",title:"Ich würde mich freuen",icon:"🤝",xp:15,board:true,steps:[
{type:"intro",title:"Ich würde mich freuen",desc:"Master the Konjunktiv II with würde + infinitive. Express polite wishes and requests. Write formal application sentences.",goals:["Master Konjunktiv II with würde + infinitive","Express polite wishes and requests","Write formal application sentences"]},
{type:"teach",trg:"die Aushilfe",src:"the temporary worker",pos:"noun",gender:"f",note:"Feminine noun. Aus (out) + Hilfe (help).\nA casual or temporary worker.",example:"A: Wir suchen eine Aushilfe für den Sommer.\nB: Für wie viele Stunden?\nA: Zwanzig Stunden pro Woche.\nB: Das passt. Ich bewerbe mich.",exampleSrc:"A: We are looking for temporary help for the summer.\nB: For how many hours?\nA: Twenty hours per week.\nB: That fits. I will apply.",funFact:"Many students work as Aushilfe alongside their studies. 'Aushilfsjob' is a part-time or temporary job. Die Aushilfe is feminine."},
{type:"teach",trg:"die Teilzeit",src:"part-time",pos:"noun",gender:"f",note:"Feminine noun. Teil (part) + Zeit (time).\n'Teilzeitarbeit' = part-time work.",example:"A: Arbeiten Sie Vollzeit oder Teilzeit?\nB: Teilzeit. Dreißig Stunden.\nA: Warum Teilzeit?\nB: Ich studiere noch nebenbei.",exampleSrc:"A: Do you work full-time or part-time?\nB: Part-time. Thirty hours.\nA: Why part-time?\nB: I am still studying on the side.",funFact:"In Germany, parents have a legal right to switch to Teilzeit after having children. Teil (part) + Zeit (time)."},
{type:"teach",trg:"die Vollzeit",src:"full-time",pos:"noun",gender:"f",note:"Feminine noun. Voll (full) + Zeit (time).\nTypically 38-40 hours per week in Germany.",example:"A: Suchen Sie eine Vollzeitstelle?\nB: Ja, vierzig Stunden pro Woche.\nA: Wir bieten flexible Vollzeit.\nB: Das klingt gut.",exampleSrc:"A: Are you looking for a full-time position?\nB: Yes, forty hours per week.\nA: We offer flexible full-time.\nB: That sounds good.",funFact:"Typically 38 to 40 hours per week in Germany. 'Vollzeitstelle' (full-time position). The contrast pair: Teilzeit vs. Vollzeit appears in every job listing."},
{type:"teach",trg:"das Einkommen",src:"the income",pos:"noun",gender:"n",note:"Neuter noun. Ein (in) + kommen (to come).\nIncome, literally what 'comes in.'",example:"A: Wie hoch ist Ihr Einkommen?\nB: Das möchte ich nicht sagen.\nA: Verstehe. In Deutschland spricht man nicht gern darüber.\nB: Genau. Das ist privat.",exampleSrc:"A: How high is your income?\nB: I would rather not say.\nA: I understand. In Germany people don't like to talk about it.\nB: Exactly. That is private.",funFact:"Germans rarely discuss their Einkommen openly. Talking about salary is considered impolite in many social situations. What 'comes in' stays private."},
{type:"teach",trg:"der Angestellte",src:"the employee (white-collar)",pos:"noun",gender:"m",note:"Masculine noun (changes with article: der/die Angestellte).\nFrom 'anstellen' (to employ). Declines like an adjective.",example:"A: Wie viele Angestellte hat die Firma?\nB: Etwa zweihundert Angestellte.\nA: Und Arbeiter?\nB: Noch einmal dreihundert.",exampleSrc:"A: How many employees does the company have?\nB: About two hundred employees.\nA: And workers?\nB: Another three hundred.",funFact:"Der/die Angestellte changes gender with the article. Like 'Deutsche,' it declines as an adjective. The distinction between Arbeiter and Angestellte was legally important until 2005."},
{type:"teach",trg:"der Arbeiter",src:"the worker (blue-collar)",pos:"noun",gender:"m",note:"Masculine noun. Arbeit (work) + -er (person).\nTraditionally blue-collar.",example:"A: Die Arbeiter in der Fabrik streiken.\nB: Warum?\nA: Sie wollen bessere Arbeitsbedingungen.\nB: Das ist ihr Recht.",exampleSrc:"A: The workers in the factory are striking.\nB: Why?\nA: They want better working conditions.\nB: That is their right.",funFact:"The distinction between Arbeiter and Angestellte was legally important in Germany until 2005 for insurance purposes. Traditionally, Arbeiter did manual labor."},
{type:"teach",trg:"die Arbeiterin",src:"the worker (female)",pos:"noun",gender:"f",note:"Feminine noun. Arbeiter + '-in.'\nSame pattern: masculine + -in = feminine.",example:"A: Die Arbeiterin hat zehn Jahre Erfahrung.\nB: In welchem Bereich?\nA: In der Produktion.\nB: Das ist beeindruckend.",exampleSrc:"A: The worker has ten years of experience.\nB: In which field?\nA: In production.\nB: That is impressive.",funFact:"Same pattern as always: masculine profession + -in = feminine. The German language never leaves you without a feminine form."},
{type:"teach",trg:"die Arbeitsstelle",src:"the job, the position",pos:"noun",gender:"f",note:"Feminine noun. Arbeit + Stelle (position).\nMore formal than 'Job.'",example:"A: Ich suche eine neue Arbeitsstelle.\nB: In welchem Bereich?\nA: Im Marketing.\nB: Ich kenne eine offene Arbeitsstelle bei Bosch.",exampleSrc:"A: I am looking for a new job.\nB: In which field?\nA: In marketing.\nB: I know an open position at Bosch.",funFact:"'Ich suche eine Arbeitsstelle' (I am looking for a job). More formal than 'Job.' Die Arbeitsstelle is feminine because Stelle is feminine."},
{type:"teach",trg:"die Arbeitserlaubnis",src:"the work permit",pos:"noun",gender:"f",note:"Feminine noun. Arbeit + Erlaubnis (permission).\nEssential for non-EU citizens.",example:"A: Haben Sie eine Arbeitserlaubnis?\nB: Ja, seit letztem Jahr.\nA: Gut. Ohne Arbeitserlaubnis geht es nicht.\nB: Ich weiß. Es war ein langer Prozess.",exampleSrc:"A: Do you have a work permit?\nB: Yes, since last year.\nA: Good. Without a work permit it is not possible.\nB: I know. It was a long process.",funFact:"Die Arbeitserlaubnis is essential for non-EU citizens in Germany. Without it, you cannot legally work. The feminine gender comes from Erlaubnis."},
{type:"teach",trg:"die Arbeitslosigkeit",src:"the unemployment",pos:"noun",gender:"f",note:"Feminine noun. Arbeitslos (jobless) + -igkeit.\nThe -keit/-igkeit suffix always creates feminine nouns.",example:"A: Die Arbeitslosigkeit sinkt.\nB: Das sind gute Nachrichten.\nA: Ja, es gibt mehr Arbeitsstellen.\nB: Besonders im IT-Bereich.",exampleSrc:"A: Unemployment is falling.\nB: That is good news.\nA: Yes, there are more jobs.\nB: Especially in the IT field.",funFact:"The German social safety net includes 'Arbeitslosengeld' (unemployment benefits). The -keit/-igkeit suffix always creates feminine nouns."},
{type:"teach",trg:"die Lehrerin",src:"the teacher (female)",pos:"noun",gender:"f",note:"Feminine noun. Lehrer (teacher) + '-in.'\nTeaching is highly respected in Germany.",example:"A: Meine Lehrerin ist sehr streng.\nB: Streng aber fair?\nA: Ja, genau. Ich lerne viel.\nB: Das ist eine gute Lehrerin.",exampleSrc:"A: My teacher is very strict.\nB: Strict but fair?\nA: Yes, exactly. I learn a lot.\nB: That is a good teacher.",funFact:"Teaching is one of the most respected professions in Germany. Lehrer/Lehrerin are civil servants (Beamte) in most German states, with excellent benefits."},
{type:"teach",trg:"der Meister",src:"the master craftsman",pos:"noun",gender:"m",note:"Masculine noun. From Latin 'magister.'\nA protected title requiring years of training.",example:"A: Sind Sie Meister?\nB: Ja, Meister im Elektrohandwerk.\nA: Wie lange hat das gedauert?\nB: Drei Jahre Ausbildung plus Meisterprüfung.",exampleSrc:"A: Are you a master craftsman?\nB: Yes, master in electrical trade.\nA: How long did that take?\nB: Three years of training plus the master exam.",funFact:"Der Meister title requires years of training plus a demanding exam. 'Meister' is a protected title in Germany. You cannot call yourself one without the certificate."},
{type:"teach",trg:"der Profi",src:"the pro, the professional",pos:"noun",gender:"m",note:"Masculine noun. Short for 'Professional.'\nBorrowed from English. Informal but common.",example:"A: Er ist ein echter Profi.\nB: Ja, er arbeitet sehr genau.\nA: Profis machen keine Fehler.\nB: Na ja, weniger Fehler als andere.",exampleSrc:"A: He is a real pro.\nB: Yes, he works very precisely.\nA: Pros don't make mistakes.\nB: Well, fewer mistakes than others.",funFact:"Short for 'Professional.' Borrowed from English. 'Er ist ein echter Profi' (He is a real pro). Colloquial but understood everywhere."},
{type:"teach",trg:"der Fachmann",src:"the expert, the specialist (male)",pos:"noun",gender:"m",note:"Masculine noun. Fach (field) + Mann (man).\n'Fragen Sie einen Fachmann.'",example:"A: Wir brauchen einen Fachmann.\nB: Für welchen Bereich?\nA: Für IT-Sicherheit.\nB: Ich kenne einen guten Fachmann.",exampleSrc:"A: We need an expert.\nB: For which field?\nA: For IT security.\nB: I know a good expert.",funFact:"'Fragen Sie einen Fachmann' (Ask an expert) is common advice in Germany. Der Fachmann is the go-to person when you need specialized knowledge."},
{type:"teach",trg:"die Fachfrau",src:"the expert, the specialist (female)",pos:"noun",gender:"f",note:"Feminine noun. Fach + Frau.\nThe modern feminine form of Fachmann.",example:"A: Die Fachfrau hat das Problem gelöst.\nB: In nur einer Stunde?\nA: Ja, sie ist wirklich kompetent.\nB: Wir sollten sie öfter fragen.",exampleSrc:"A: The expert solved the problem.\nB: In only one hour?\nA: Yes, she is really competent.\nB: We should ask her more often.",funFact:"The modern feminine form. Some companies now use 'Fachkraft' (skilled worker) as a gender-neutral alternative instead of Fachmann/Fachfrau."},
{type:"teach",trg:"die Fachleute",src:"the experts (plural)",pos:"noun",gender:"pl",note:"Plural of Fachmann/Fachfrau.\nOne of the few words where the plural changes entirely.",example:"A: Wir brauchen Fachleute für das Projekt.\nB: Wie viele?\nA: Mindestens drei Fachleute.\nB: Ich suche sofort.",exampleSrc:"A: We need experts for the project.\nB: How many?\nA: At least three experts.\nB: I will search immediately.",funFact:"Not 'Fachmänner' or 'Fachfrauen' but 'Fachleute' (professional people). One of the few German words where the plural changes the second element entirely."},
{type:"teach",trg:"absolut",src:"absolute, absolutely",pos:"adj",gender:null,note:"From Latin 'absolutus' (completed/perfect).\nStress on the last syllable: ab-so-LOOT.",example:"A: Sind Sie sicher?\nB: Absolut. Hundert Prozent.\nA: Das ist absolut richtig.\nB: Danke für die Bestätigung.",exampleSrc:"A: Are you sure?\nB: Absolutely. One hundred percent.\nA: That is absolutely right.\nB: Thank you for the confirmation.",funFact:"Same word in English, French, and German. 'Absolut richtig!' (Absolutely right!). Stress on the last syllable: ab-so-LOOT."},
{type:"teach",trg:"flexibel",src:"flexible",pos:"adj",gender:null,note:"From Latin 'flexibilis.'\n'Flexible Arbeitszeiten' = flexible working hours.",example:"A: Sind Sie zeitlich flexibel?\nB: Ja, sehr flexibel.\nA: Auch am Wochenende?\nB: Wenn nötig, ja.",exampleSrc:"A: Are you flexible with your time?\nB: Yes, very flexible.\nA: Also on weekends?\nB: If necessary, yes.",funFact:"'Flexible Arbeitszeiten' (flexible working hours) is the most desired benefit in German job surveys. Stress on the second syllable: flek-SEE-bel."},
{type:"teach",trg:"ideal",src:"ideal, perfect",pos:"adj",gender:null,note:"From Greek 'idea.'\n'Der ideale Kandidat' = the ideal candidate.",example:"A: Das ist die ideale Stelle für Sie.\nB: Warum?\nA: Sie passt perfekt zu Ihren Qualifikationen.\nB: Das klingt ideal!",exampleSrc:"A: This is the ideal position for you.\nB: Why?\nA: It fits your qualifications perfectly.\nB: That sounds ideal!",funFact:"'Der ideale Kandidat' (the ideal candidate) is what every job listing describes. Same word internationally. Stress on the last syllable: ee-de-AHL."},
{type:"teach",trg:"individuell",src:"individual, personal",pos:"adj",gender:null,note:"From Latin 'individualis.'\n'Individuelle Lösungen' = individual solutions.",example:"A: Jede Bewerbung muss individuell sein.\nB: Nicht einfach kopieren?\nA: Nein! Individuell anpassen.\nB: Okay, ich schreibe jede einzeln.",exampleSrc:"A: Every application must be individual.\nB: Not just copy?\nA: No! Adapt individually.\nB: Okay, I will write each one separately.",funFact:"'Individuelle Lösungen' (individual solutions) is a phrase from every consulting brochure. Stress on the last syllable: in-di-vi-du-ELL."},
{type:"tip",title:"Konjunktiv II: The Polite Mode",text:"German has a special verb form for wishes, polite requests, and hypotheticals.\n\nThe simplest version: würde + infinitive\n\n'Ich würde mich freuen' (I would be pleased)\n'Würden Sie mir bitte helfen?' (Would you please help me?)\n\nIn applications:\n'Ich würde gern in Ihrem Unternehmen arbeiten.'\n\nThis is softer and more polite than the indicative.\n\nWish sentences:\n'Wenn ich doch nur mehr Erfahrung hätte!'\n(If only I had more experience!)",deepDive:{title:"Würde vs. True Konjunktiv II Forms",text:"Würde + infinitive is the modern, simple form.\n\nBut some verbs have their own Konjunktiv II forms:\nsein: wäre (would be)\nhaben: hätte (would have)\nwerden: würde (would become)\n\nThese 'true' forms sound more elegant.\n'Ich wäre froh' instead of 'Ich würde froh sein'\n'Ich hätte gern' instead of 'Ich würde gern haben'\n\nFor most other verbs, Germans use würde + infinitive."}},
{type:"verb_table",title:"Konjunktiv II: würde + Infinitiv",groups:[{label:"Konjugation",rows:[{pronoun:"ich",form:"würde ... arbeiten",src:"I would work"},{pronoun:"du",form:"würdest ... arbeiten",src:"you would work"},{pronoun:"er/sie/es",form:"würde ... arbeiten",src:"he/she/it would work"},{pronoun:"wir",form:"würden ... arbeiten",src:"we would work"},{pronoun:"ihr",form:"würdet ... arbeiten",src:"you all would work"},{pronoun:"sie/Sie",form:"würden ... arbeiten",src:"they/you would work"}]},{label:"Wichtige eigene Formen",rows:[{pronoun:"sein",form:"wäre",src:"would be"},{pronoun:"haben",form:"hätte",src:"would have"},{pronoun:"werden",form:"würde",src:"would become"}]}],note:"Würde + infinitive is the standard form for polite requests and wishes in German. Sein and haben use their own forms: wäre, hätte."},
{type:"mc",q:"Verumius schreibt im Anschreiben: 'Ich würde mich über ein Gespräch freuen.' Welcher Modus ist das?",opts:["Indikativ (Tatsache)","Präteritum (Vergangenheit)","Konjunktiv II (höflich/hypothetisch)","Imperativ (Befehl)"],ans:"Konjunktiv II (höflich/hypothetisch)",hint:"The word 'würde' signals a softer, more polite form than a direct statement."},
{type:"fb",s:"Ich {1} gern in Ihrem Unternehmen arbeiten.",a:["würde"],opts:["würde","will","muss","kann"],hint:"The polite way to say you would like to do something in a formal application.",sSrc:"I would gladly work in your company."},
{type:"mc",q:"Lebenslauf: 'Ich arbeitete bei Siemens.' Anschreiben: 'Ich würde gern wieder im Ingenieurbereich arbeiten.' Welche Zeitformen?",opts:["Präteritum, dann Konjunktiv II","Beides Konjunktiv II","Beides Präteritum","Präsens, dann Präteritum"],ans:"Präteritum, dann Konjunktiv II",hint:"The CV describes the past. The letter expresses a polite wish for the future."},
{type:"drag_fill",s:"Ich {1} mich sehr {2}, von Ihnen zu hören.",blanks:{"1":"würde","2":"freuen"},pool:["würde","freuen","wurde","gefreut","habe","arbeiten"],hint:"A polite closing line in a cover letter. 'Would' + 'be pleased.'",sSrc:"I would be very pleased to hear from you."},
{type:"match",pairs:[{trg:"Vollzeit",src:"full-time"},{trg:"Teilzeit",src:"part-time"},{trg:"Aushilfe",src:"temporary worker"},{trg:"Praktikant",src:"intern"},{trg:"Angestellte",src:"employee"},{trg:"Meister",src:"master craftsman"}]}
]},

// ==================== LESSON 5: Könnten Sie das wiederholen? ====================
{id:"deu_r13l5",title:"Könnten Sie das wiederholen?",icon:"🎤",xp:15,board:true,steps:[
{type:"intro",title:"Könnten Sie das wiederholen?",desc:"Master Konjunktiv II of modal verbs. Survive a simulated job interview. Practice polite professional German.",goals:["Master Konjunktiv II of modal verbs","Survive a simulated job interview","Practice polite professional German"]},
{type:"story",speaker:"narrator",mood:"tense",art:"de-vhs-classroom-interview",trg:"Der VHS-Klassenraum wurde umgebaut. Zwei Stühle stehen sich gegenüber. Yilmaz sitzt mit perfekter Haltung, Klemmbrett in der Hand. Verumius zupft an seinem Kragen.",src:"The VHS classroom has been rearranged. Two chairs face each other. Yilmaz sits with perfect posture, clipboard in hand. Verumius tugs at his collar."},
{type:"story",speaker:"yilmaz",mood:"professional",trg:"Guten Tag, Herr Verumius. Nehmen Sie bitte Platz. Könnten Sie sich kurz vorstellen?",src:"Good day, Mr. Verumius. Please take a seat. Could you briefly introduce yourself?"},
{type:"story",speaker:"verumius",mood:"nervous",trg:"Guten Tag. Ich... ähm... Ich studierte Linguistik in Istanbul und arbeitete als Übersetzer. Ich würde gern in Ihrem Unternehmen arbeiten.",src:"Good day. I... um... I studied linguistics in Istanbul and worked as a translator. I would like to work in your company."},
{type:"story",speaker:"yilmaz",mood:"evaluating",trg:"Gut. Sie sollten auch Ihre Stärken nennen. Was könnten Sie unserem Team bieten?",src:"Good. You should also mention your strengths. What could you offer our team?"},
{type:"story",speaker:"verumius",mood:"concentrating",trg:"Ich spreche fließend drei Sprachen. Ich könnte Ihre internationale Kommunikation verbessern.",src:"I speak three languages fluently. I could improve your international communication."},
{type:"story",speaker:"yilmaz",mood:"pleased",trg:"Gut. Du bist bereit.",src:"Good. You are ready."},
{type:"teach",trg:"der Experte",src:"the expert",pos:"noun",gender:"m",note:"Masculine noun. From French 'expert.'\nN-Deklination: Experte, Experten, Experten.",example:"A: Wir brauchen einen Experten.\nB: Für welches Thema?\nA: Für Datenschutz.\nB: Ich kenne einen Experten in Berlin.",exampleSrc:"A: We need an expert.\nB: For which topic?\nA: For data protection.\nB: I know an expert in Berlin.",funFact:"Der Experte belongs to the 'n-Deklination': Experte, Experten, Experten. The -e ending on a masculine noun is a clue for this special declension."},
{type:"teach",trg:"der Spezialist",src:"the specialist",pos:"noun",gender:"m",note:"Masculine noun. From Latin 'specialis.'\nThe -ist ending always makes masculine nouns.",example:"A: Sie ist Spezialistin für Marketing.\nB: Und er ist Spezialist für Finanzen.\nA: Zusammen sind sie ein gutes Team.\nB: Genau. Jeder hat seine Stärke.",exampleSrc:"A: She is a specialist in marketing.\nB: And he is a specialist in finance.\nA: Together they are a good team.\nB: Exactly. Everyone has their strength.",funFact:"The -ist ending comes from Latin/French and always makes masculine nouns: Journalist, Tourist, Spezialist. Same pattern across European languages."},
{type:"teach",trg:"die Spezialistin",src:"the specialist (female)",pos:"noun",gender:"f",note:"Feminine noun. Spezialist + '-in.'\nThe pattern: -ist (masculine) + -in = -istin.",example:"A: Die Spezialistin hat das Problem gelöst.\nB: Welche Spezialistin?\nA: Frau Dr. Müller. IT-Sicherheit.\nB: Ah ja. Sie ist wirklich gut.",exampleSrc:"A: The specialist solved the problem.\nB: Which specialist?\nA: Dr. Müller. IT security.\nB: Ah yes. She is really good.",funFact:"The pattern holds: -ist (masculine) + -in = -istin (feminine). Spezialist becomes Spezialistin."},
{type:"teach",trg:"der Unternehmer",src:"the entrepreneur",pos:"noun",gender:"m",note:"Masculine noun. Unter (under) + nehmen (to take).\nSomeone who 'undertakes' business.",example:"A: Er ist ein erfolgreicher Unternehmer.\nB: Was für ein Unternehmen hat er?\nA: Eine Softwarefirma.\nB: Seit wann ist er Unternehmer?",exampleSrc:"A: He is a successful entrepreneur.\nB: What kind of company does he have?\nA: A software company.\nB: Since when has he been an entrepreneur?",funFact:"Germany has 3.5 million Unternehmer. The Mittelstand (medium-sized businesses) are the backbone of the economy. Literally 'someone who undertakes.'"},
{type:"teach",trg:"die Unternehmerin",src:"the entrepreneur (female)",pos:"noun",gender:"f",note:"Feminine noun. Unternehmer + '-in.'\n'Gründerinnen' is a buzzword in the startup scene.",example:"A: Die Unternehmerin hat drei Firmen gegründet.\nB: Beeindruckend. In welchen Bereichen?\nA: Technologie und Bildung.\nB: Eine echte Vorreiterin.",exampleSrc:"A: The entrepreneur has founded three companies.\nB: Impressive. In which fields?\nA: Technology and education.\nB: A true pioneer.",funFact:"Female entrepreneurs are growing fast in Germany. 'Gründerinnen' (female founders) is a buzzword in the German startup scene."},
{type:"teach",trg:"der Kandidat",src:"the candidate",pos:"noun",gender:"m",note:"Masculine noun. From Latin 'candidatus' (clothed in white).\nN-Deklination: Kandidat, Kandidaten.",example:"A: Wie viele Kandidaten gibt es?\nB: Fünfzig Kandidaten für drei Stellen.\nA: Das ist viel Konkurrenz.\nB: Ja, aber unser Kandidat ist stark.",exampleSrc:"A: How many candidates are there?\nB: Fifty candidates for three positions.\nA: That is a lot of competition.\nB: Yes, but our candidate is strong.",funFact:"White togas were worn by Romans seeking office. Der Kandidat also belongs to the n-Deklination: Kandidat, Kandidaten. From Latin 'candidatus.'"},
{type:"teach",trg:"das Mitglied",src:"the member",pos:"noun",gender:"n",note:"Neuter noun. Mit (with) + Glied (limb/member).\nThere are 600,000 registered Vereine in Germany.",example:"A: Sind Sie Mitglied in einem Verein?\nB: Ja, im Sportverein.\nA: Wie viele Mitglieder hat der Verein?\nB: Etwa dreihundert.",exampleSrc:"A: Are you a member of a club?\nB: Yes, in a sports club.\nA: How many members does the club have?\nB: About three hundred.",funFact:"Germans love club membership: 'Vereinsmitglied' (club member). There are 600,000 registered Vereine in Germany. Das Mitglied is neuter."},
{type:"teach",trg:"die Visitenkarte",src:"the business card",pos:"noun",gender:"f",note:"Feminine noun. Visite (visit) + Karte (card).\nStill standard practice at networking events.",example:"A: Haben Sie eine Visitenkarte?\nB: Ja, hier bitte.\nA: Danke. Ich melde mich bei Ihnen.\nB: Gern. Meine E-Mail steht auf der Karte.",exampleSrc:"A: Do you have a business card?\nB: Yes, here you go.\nA: Thank you. I will get in touch.\nB: Gladly. My email is on the card.",funFact:"In German business culture, exchanging Visitenkarten is still standard practice at meetings and networking events. Digital alternatives are growing but paper persists."},
{type:"teach",trg:"die Wirtschaft",src:"the economy",pos:"noun",gender:"f",note:"Feminine noun. From 'Wirt' (host/innkeeper).\n'Wirtschaftswunder' = the economic miracle.",example:"A: Wie steht die deutsche Wirtschaft?\nB: Gut. Die Wirtschaft wächst.\nA: In welchem Bereich?\nB: Besonders in der Technologie.",exampleSrc:"A: How is the German economy?\nB: Good. The economy is growing.\nA: In which sector?\nB: Especially in technology.",funFact:"Originally meant 'hosting/hospitality' and expanded to mean all economic activity. 'Wirtschaftswunder' (economic miracle) describes Germany's post-war recovery."},
{type:"teach",trg:"die Verantwortung",src:"the responsibility",pos:"noun",gender:"f",note:"Feminine noun. Ver- + Antwortung (answering).\nLiterally 'answering for' something.",example:"A: Diese Stelle hat viel Verantwortung.\nB: Das ist mir bewusst.\nA: Sind Sie bereit für die Verantwortung?\nB: Ja, absolut.",exampleSrc:"A: This position has a lot of responsibility.\nB: I am aware of that.\nA: Are you ready for the responsibility?\nB: Yes, absolutely.",funFact:"'Verantwortung übernehmen' (to take responsibility) is a phrase German managers use constantly. Responsibility is literally 'answering for' something."},
{type:"teach",trg:"die Voraussetzung",src:"the prerequisite, the requirement",pos:"noun",gender:"f",note:"Feminine noun. Voraus (ahead) + Setzung (setting).\nSomething set ahead of you.",example:"A: Was sind die Voraussetzungen für die Stelle?\nB: Ein Abschluss und drei Jahre Erfahrung.\nA: Erfülle ich die Voraussetzungen?\nB: Ja, alle.",exampleSrc:"A: What are the requirements for the position?\nB: A degree and three years of experience.\nA: Do I meet the requirements?\nB: Yes, all of them.",funFact:"'Voraussetzungen für die Stelle' (requirements for the position) is standard in job ads. Always feminine because of the -ung ending."},
{type:"teach",trg:"ausgezeichnet",src:"excellent",pos:"adj",gender:null,note:"Past participle of 'auszeichnen' (to distinguish).\nLiterally 'marked out' as special.",example:"A: Wie sind Ihre Deutschkenntnisse?\nB: Ausgezeichnet. Ich habe ein C1-Zertifikat.\nA: Ausgezeichnet! Das freut uns.\nB: Danke.",exampleSrc:"A: How is your German?\nB: Excellent. I have a C1 certificate.\nA: Excellent! We are pleased.\nB: Thank you.",funFact:"'Ausgezeichnete Deutschkenntnisse' (excellent German skills) is the highest level on job listings. Past participle used as adjective: 'marked out' as special."},
{type:"teach",trg:"geeignet",src:"suitable, qualified",pos:"adj",gender:null,note:"Past participle of 'eignen' (to be suitable).\n'Für diese Stelle geeignet.'",example:"A: Ist er für die Stelle geeignet?\nB: Ja, er ist sehr gut geeignet.\nA: Warum?\nB: Er hat alle erforderlichen Qualifikationen.",exampleSrc:"A: Is he suitable for the position?\nB: Yes, he is very well suited.\nA: Why?\nB: He has all the required qualifications.",funFact:"The ge- prefix marks it as a past participle turned adjective. 'Für diese Stelle geeignet' (suitable for this position)."},
{type:"teach",trg:"fließend",src:"fluent",pos:"adj",gender:null,note:"Present participle of 'fließen' (to flow).\nLanguage that flows without stopping.",example:"A: Sprechen Sie fließend Deutsch?\nB: Ja, fließend. Und auch Englisch.\nA: Und Türkisch?\nB: Das ist meine Muttersprache.",exampleSrc:"A: Do you speak fluent German?\nB: Yes, fluently. And also English.\nA: And Turkish?\nB: That is my mother tongue.",funFact:"'Fließend Deutsch sprechen' (to speak fluent German) means your German flows without stopping. Language proficiency that moves like water."},
{type:"teach",trg:"eindeutig",src:"unambiguous, clear",pos:"adj",gender:null,note:"Ein (one) + deutig (meaning/interpretation).\nHaving only one possible meaning.",example:"A: Das Ergebnis ist eindeutig.\nB: Ja, da gibt es keinen Zweifel.\nA: Eindeutig der beste Kandidat.\nB: Einverstanden.",exampleSrc:"A: The result is clear.\nB: Yes, there is no doubt.\nA: Clearly the best candidate.\nB: Agreed.",funFact:"Having only one possible meaning. 'Das Ergebnis ist eindeutig' (The result is clear). The opposite: 'mehrdeutig' (ambiguous, having multiple meanings)."},
{type:"teach",trg:"eignen",src:"to be suitable",pos:"verb",gender:null,note:"Reflexive: 'sich eignen für.'\nRelated to 'eigen' (own).",example:"A: Eignen Sie sich für Teamarbeit?\nB: Ja, ich eigne mich gut für Teams.\nA: Und für Einzelarbeit?\nB: Auch. Ich bin flexibel.",exampleSrc:"A: Are you suited for teamwork?\nB: Yes, I am well suited for teams.\nA: And for working alone?\nB: Also. I am flexible.",funFact:"'Sich eignen für' (to be suited for). Reflexive in this meaning. Related to 'eigen' (own). What is 'eigenartig' (peculiar) is uniquely its own."},
{type:"teach",trg:"einstellen",src:"to hire, to employ",pos:"verb",gender:null,note:"Separable verb. Ein + stellen (to place).\n'Wir stellen Sie ein' = We are hiring you.",example:"A: Wann stellen Sie neue Mitarbeiter ein?\nB: Ab nächstem Monat.\nA: Wie viele stellen Sie ein?\nB: Drei neue Mitarbeiter.",exampleSrc:"A: When do you hire new employees?\nB: Starting next month.\nA: How many will you hire?\nB: Three new employees.",funFact:"Separable verb: 'Wir stellen Sie ein' (We are hiring you). Also means 'to adjust' (ein Gerät einstellen) or 'to stop' (die Produktion einstellen). Context decides."},
{type:"teach",trg:"bieten",src:"to offer",pos:"verb",gender:null,note:"Strong verb: bieten/bot/geboten.\n'Was können Sie uns bieten?'",example:"A: Was können Sie uns bieten?\nB: Erfahrung, Sprachkenntnisse und Motivation.\nA: Und was bieten wir Ihnen?\nB: Eine interessante Arbeitsstelle.",exampleSrc:"A: What can you offer us?\nB: Experience, language skills, and motivation.\nA: And what do we offer you?\nB: An interesting job.",funFact:"'Was können Sie uns bieten?' (What can you offer us?) is the classic interview question. Strong verb: bieten/bot/geboten. Related to English 'bid.'"},
{type:"teach",trg:"bemühen",src:"to make an effort",pos:"verb",gender:null,note:"Reflexive: 'sich bemühen.'\nFormal: 'Ich bemühe mich um eine Stelle.'",example:"A: Ich bemühe mich sehr um diese Stelle.\nB: Das sehe ich. Ihr Lebenslauf ist beeindruckend.\nA: Danke. Ich bemühe mich immer um Qualität.\nB: Das ist eine gute Eigenschaft.",exampleSrc:"A: I am making a great effort for this position.\nB: I can see that. Your CV is impressive.\nA: Thank you. I always strive for quality.\nB: That is a good quality.",funFact:"In formal letters: 'Ich bemühe mich um eine Stelle' (I am applying for a position). Old-fashioned but still used in very formal applications. Be- + mühen (to toil)."},
{type:"teach",trg:"beteiligen",src:"to participate, to involve",pos:"verb",gender:null,note:"Reflexive: 'sich beteiligen an.'\nMaking yourself part of something.",example:"A: Möchten Sie sich am Projekt beteiligen?\nB: Ja, gern. Wie kann ich mich beteiligen?\nA: Sie könnten die Übersetzungen übernehmen.\nB: Das mache ich gern.",exampleSrc:"A: Would you like to participate in the project?\nB: Yes, gladly. How can I participate?\nA: You could take over the translations.\nB: I would gladly do that.",funFact:"'An einem Projekt beteiligt sein' (to be involved in a project). Reflexive: 'Ich beteilige mich an der Diskussion.' Making yourself part of something."},
{type:"tip",title:"Konjunktiv II of Modal Verbs: The Polite Tools",text:"Modal verbs have their own Konjunktiv II forms. No 'würde' needed.\n\nkönnen: könnte (could)\nmüssen: müsste (would have to)\ndürfen: dürfte (might/may I)\nsollen: sollte (should)\nwollen: wollte (would want)\n\nThese are MORE POLITE than würde:\n'Könnten Sie mir helfen?' is softer than\n'Würden Sie mir helfen?'\n\nUse modal Konjunktiv II forms in job interviews, emails, and with strangers.",deepDive:{title:"Könnten vs. konnten: One Letter, Big Difference",text:"Könnten (Konjunktiv II) = could (polite/hypothetical)\nKonnten (Präteritum) = could (past: were able to)\n\nThe umlaut makes the difference:\n'Sie könnten mir helfen' = You could help me (polite request)\n'Sie konnten mir helfen' = You were able to help me (past fact)\n\nSame rule for all modal verbs:\nmüsste (should) vs. musste (had to)\ndürfte (might) vs. durfte (was allowed to)"}},
{type:"verb_table",title:"Konjunktiv II: Modalverben",groups:[{label:"Modale Konjunktiv-II-Formen",rows:[{pronoun:"können",form:"könnte",src:"could"},{pronoun:"müssen",form:"müsste",src:"would have to"},{pronoun:"dürfen",form:"dürfte",src:"might/would be allowed to"},{pronoun:"sollen",form:"sollte",src:"should"},{pronoun:"wollen",form:"wollte",src:"would want"}]},{label:"Konjugation: könnte",rows:[{pronoun:"ich",form:"könnte",src:"I could"},{pronoun:"du",form:"könntest",src:"you could"},{pronoun:"er/sie/es",form:"könnte",src:"he/she/it could"},{pronoun:"wir",form:"könnten",src:"we could"},{pronoun:"ihr",form:"könntet",src:"you all could"},{pronoun:"sie/Sie",form:"könnten",src:"they/you could"}]}],note:"Modal Konjunktiv II forms are more polite than würde + infinitive. ich and er/sie/es have identical forms: ich könnte, er könnte."},
{type:"mc",q:"Yilmaz fragt: 'Könnten Sie sich kurz vorstellen?' Warum benutzt sie 'könnten' statt 'können'?",opts:["Es ist Vergangenheit","Es ist ein Befehl","Es ist höflicher und formeller","Es bedeutet etwas anderes"],ans:"Es ist höflicher und formeller",hint:"The Konjunktiv II of modals softens the request. Could you vs. Can you."},
{type:"fb",s:"Sie {1} auch Ihre Stärken nennen.",a:["sollten"],opts:["sollten","sollen","müssen","wollen"],hint:"A gentle suggestion from Yilmaz. The Konjunktiv II of sollen makes it advisory, not commanding.",sSrc:"You should also mention your strengths."},
{type:"mc",q:"Verumius sagt: 'Ich studierte in Istanbul und könnte Ihre Kommunikation verbessern.' Welche Zeitformen?",opts:["Beides Konjunktiv II","Beides Präteritum","Präsens + Konjunktiv II","Präteritum + Konjunktiv II"],ans:"Präteritum + Konjunktiv II",hint:"The first verb describes the past. The second expresses a polite possibility."},
{type:"drag_fill",s:"{1} Sie mir bitte {2}, was genau die Stelle beinhaltet?",blanks:{"1":"Könnten","2":"sagen"},pool:["Könnten","sagen","Können","gesagt","Sollten","erklären"],hint:"A polite interview question: 'Could you please tell me...' Modal Konjunktiv II + Infinitiv.",sSrc:"Could you please tell me what exactly the position involves?"},
{type:"match",pairs:[{trg:"Voraussetzung",src:"prerequisite"},{trg:"Verantwortung",src:"responsibility"},{trg:"Wirtschaft",src:"economy"},{trg:"Visitenkarte",src:"business card"},{trg:"Experte",src:"expert"},{trg:"Kandidat",src:"candidate"}]}
]},

// ==================== LESSON 6: Der perfekte Lebenslauf ====================
{id:"deu_r13l6",title:"Der perfekte Lebenslauf",icon:"✍️",xp:15,board:true,steps:[
{type:"intro",title:"Der perfekte Lebenslauf",desc:"Master job search vocabulary. Practice all three grammar constructs in professional context. Write application-level sentences.",goals:["Master job search vocabulary","Practice all three grammar constructs in context","Write application-level sentences"]},
{type:"story",speaker:"yilmaz",mood:"coaching",art:"de-vhs-office-desk",trg:"So, Verumius. Dein Lebenslauf ist jetzt komplett. Aber du musst auch auf Annoncen reagieren können. Lass uns üben.",src:"So, Verumius. Your CV is now complete. But you also need to be able to respond to job ads. Let us practice."},
{type:"story",speaker:"verumius",mood:"determined",trg:"Ich bin bereit. Ich habe die ganze Nacht geübt.",src:"I am ready. I practiced all night."},
{type:"teach",trg:"die Annonce",src:"the classified ad",pos:"noun",gender:"f",note:"Feminine noun. From French 'annonce' (announcement).\nThe traditional word for a job advertisement.",example:"A: Hast du die Annonce gelesen?\nB: Ja, die klingt interessant.\nA: Bewirb dich schnell.\nB: Ich schreibe heute noch die Bewerbung.",exampleSrc:"A: Did you read the classified ad?\nB: Yes, it sounds interesting.\nA: Apply quickly.\nB: I will write the application today.",funFact:"Die Annonce is the traditional word for a job ad. Modern German also uses 'Stellenanzeige' (position announcement). The French origin gives it elegance."},
{type:"teach",trg:"das Inserat",src:"the advertisement",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'inserere' (to insert).\nParticularly in newspapers.",example:"A: Ich habe ein Inserat in der Zeitung gesehen.\nB: Für welche Stelle?\nA: Übersetzer. Genau mein Bereich.\nB: Schick deine Bewerbung sofort ab.",exampleSrc:"A: I saw an ad in the newspaper.\nB: For which position?\nA: Translator. Exactly my field.\nB: Send your application right away.",funFact:"The Swiss and Austrians prefer Inserat. Germans often say Anzeige or Annonce. All three mean the same thing. From Latin 'inserere' (to insert)."},
{type:"teach",trg:"die Nachfrage",src:"the demand, the inquiry",pos:"noun",gender:"f",note:"Feminine noun. Nach (after) + Frage (question).\nDemand or a follow-up question.",example:"A: Die Nachfrage nach IT-Experten ist hoch.\nB: Ja, der Markt sucht Fachleute.\nA: Haben Sie eine Nachfrage?\nB: Ja, wie hoch ist das Gehalt?",exampleSrc:"A: The demand for IT experts is high.\nB: Yes, the market is looking for specialists.\nA: Do you have a question?\nB: Yes, how high is the salary?",funFact:"'Die Nachfrage nach Fachkräften ist hoch' (The demand for skilled workers is high). Also: 'Bei Nachfrage kontaktieren Sie uns' (For inquiries, contact us)."},
{type:"teach",trg:"die Auswahl",src:"the selection, the choice",pos:"noun",gender:"f",note:"Feminine noun. Aus (out) + Wahl (choice).\n'Eine große Auswahl' = a large selection.",example:"A: Die Auswahl der Kandidaten war schwer.\nB: Wie viele waren es?\nA: Dreißig für fünf Stellen.\nB: Eine große Auswahl also.",exampleSrc:"A: The selection of candidates was difficult.\nB: How many were there?\nA: Thirty for five positions.\nB: A large selection then.",funFact:"The hiring process involves an 'Auswahlverfahren' (selection procedure). Choosing FROM a group. Aus (out) + Wahl (choice)."},
{type:"teach",trg:"die Konkurrenz",src:"the competition",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'concurrere' (to run together).\n'Die Konkurrenz ist stark.'",example:"A: Gibt es viel Konkurrenz?\nB: Ja, die Konkurrenz ist stark.\nA: Wie kann ich mich abheben?\nB: Mit einem perfekten Lebenslauf.",exampleSrc:"A: Is there a lot of competition?\nB: Yes, the competition is strong.\nA: How can I stand out?\nB: With a perfect CV.",funFact:"Used for business competition and personal rivalry. The German job market can be very 'konkurrenzfähig' (competitive). From Latin 'concurrere' (to run together)."},
{type:"teach",trg:"der Empfang",src:"the reception",pos:"noun",gender:"m",note:"Masculine noun. From 'empfangen' (to receive).\nAlso means receiving a signal.",example:"A: Bitte melden Sie sich am Empfang.\nB: Wo ist der Empfang?\nA: Im Erdgeschoss, gleich links.\nB: Danke. Bis gleich.",exampleSrc:"A: Please report to reception.\nB: Where is the reception?\nA: On the ground floor, just to the left.\nB: Thank you. See you shortly.",funFact:"'Bitte melden Sie sich am Empfang' (Please report to reception). Also means receiving a signal: 'Kein Empfang' (no reception/signal)."},
{type:"teach",trg:"die Kündigung",src:"the termination, the resignation",pos:"noun",gender:"f",note:"Feminine noun. From 'kündigen' (to terminate).\nNotice periods: often 1-3 months.",example:"A: Ich habe meine Kündigung eingereicht.\nB: Warum?\nA: Ich habe eine bessere Stelle gefunden.\nB: Die Kündigungsfrist beträgt drei Monate.",exampleSrc:"A: I submitted my resignation.\nB: Why?\nA: I found a better position.\nB: The notice period is three months.",funFact:"In Germany, notice periods are strictly regulated: often 1 to 3 months. 'Ich habe meine Kündigung eingereicht' (I submitted my resignation). From 'kündigen.'"},
{type:"teach",trg:"die Entlassung",src:"the dismissal, being let go",pos:"noun",gender:"f",note:"Feminine noun. Ent- (away) + Lassung (letting).\nWhen the employer ends the contract.",example:"A: Er hat eine Entlassung bekommen.\nB: Warum wurde er entlassen?\nA: Die Firma baut Stellen ab.\nB: Das ist traurig.",exampleSrc:"A: He received a dismissal.\nB: Why was he let go?\nA: The company is cutting positions.\nB: That is sad.",funFact:"Kündigung can go either way (employee or employer). Entlassung is when the employer ends it. 'Massenentlassungen' (mass layoffs) make headlines."},
{type:"teach",trg:"die Aktion",src:"the action, the campaign",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'actio.'\nAlso used for promotional campaigns.",example:"A: Wir starten eine neue Aktion.\nB: Was für eine Aktion?\nA: Eine Werbeaktion für unsere Produkte.\nB: Gute Idee. Wann geht es los?",exampleSrc:"A: We are starting a new campaign.\nB: What kind of campaign?\nA: A promotional campaign for our products.\nB: Good idea. When does it start?",funFact:"Same root as English 'action.' 'Eine Werbeaktion' (a promotional campaign). Also used for activist campaigns: 'Aktion gegen Armut' (Action against poverty)."},
{type:"teach",trg:"die Aktivität",src:"the activity",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'activitas.'\n'Freizeitaktivitäten' sometimes appear on German CVs.",example:"A: Welche Aktivitäten machen Sie in der Freizeit?\nB: Sport und Lesen.\nA: Schreiben Sie das in den Lebenslauf?\nB: Ja, in Deutschland ist das üblich.",exampleSrc:"A: What activities do you do in your free time?\nB: Sports and reading.\nA: Do you write that on the CV?\nB: Yes, in Germany that is customary.",funFact:"Yes, Germans sometimes list hobbies and 'Freizeitaktivitäten' on their CV. It is considered normal and can make a good impression."},
{type:"teach",trg:"die Aufforderung",src:"the request, the call to action",pos:"noun",gender:"f",note:"Feminine noun. Auf (up) + Forderung (demand).\nStronger than a 'Bitte' (request).",example:"A: Das ist eine Aufforderung zur Bewerbung.\nB: Von welcher Firma?\nA: Von TechBerlin GmbH.\nB: Ich bewerbe mich sofort.",exampleSrc:"A: That is a call for applications.\nB: From which company?\nA: From TechBerlin GmbH.\nB: I will apply immediately.",funFact:"'Eine Aufforderung zur Bewerbung' (a call for applications). The Auf- prefix adds urgency. Stronger than 'bitten' (to ask politely)."},
{type:"teach",trg:"der Vortrag",src:"the presentation, the lecture",pos:"noun",gender:"m",note:"Masculine noun. Vor (before) + Trag (carrying).\nYou 'carry' ideas before an audience.",example:"A: Können Sie einen Vortrag halten?\nB: Ja, ich halte gern Vorträge.\nA: Über welches Thema?\nB: Über interkulturelle Kommunikation.",exampleSrc:"A: Can you give a presentation?\nB: Yes, I like giving presentations.\nA: On which topic?\nB: On intercultural communication.",funFact:"'Einen Vortrag halten' (to give a presentation) is a standard professional skill. You 'carry' your ideas before an audience."},
{type:"teach",trg:"der Beweis",src:"the proof, the evidence",pos:"noun",gender:"m",note:"Masculine noun. From 'beweisen' (to prove).\n'Zeugnisse sind der Beweis.'",example:"A: Haben Sie einen Beweis für Ihre Erfahrung?\nB: Ja, hier sind meine Arbeitszeugnisse.\nA: Das ist der beste Beweis.\nB: Ich habe auch Referenzen.",exampleSrc:"A: Do you have proof of your experience?\nB: Yes, here are my work references.\nA: That is the best proof.\nB: I also have references.",funFact:"'Zeugnisse sind der Beweis für Ihre Qualifikation' (Certificates are proof of your qualification). In court: 'Beweismittel' (evidence/means of proof)."},
{type:"teach",trg:"ablehnen",src:"to reject, to decline",pos:"verb",gender:null,note:"Separable verb. Ab (off) + lehnen (to lean).\nLeaning away from something.",example:"A: Die Firma hat meine Bewerbung abgelehnt.\nB: Das tut mir leid. Warum?\nA: Sie sagten, mir fehlt Erfahrung.\nB: Versuch es bei einer anderen Firma.",exampleSrc:"A: The company rejected my application.\nB: I am sorry. Why?\nA: They said I lack experience.\nB: Try another company.",funFact:"'Die Bewerbung wurde abgelehnt' (The application was rejected). Leaning away from something. Separable: 'Ich lehne das Angebot ab.'"},
{type:"teach",trg:"absagen",src:"to cancel, to turn down",pos:"verb",gender:null,note:"Separable verb. Ab + sagen (to say).\nMore personal than ablehnen.",example:"A: Ich muss leider absagen.\nB: Schade. Warum?\nA: Ich habe schon eine andere Stelle angenommen.\nB: Verstehe. Viel Erfolg dort!",exampleSrc:"A: I unfortunately have to cancel.\nB: Too bad. Why?\nA: I already accepted another position.\nB: I understand. Good luck there!",funFact:"More personal than ablehnen. You 'absagen' to people, you 'ablehnen' offers or proposals. 'Ich muss leider absagen' is a polite refusal."},
{type:"teach",trg:"akzeptieren",src:"to accept",pos:"verb",gender:null,note:"Not separable. From Latin 'acceptare.'\nMore formal than 'annehmen.'",example:"A: Akzeptieren Sie das Angebot?\nB: Ja, ich akzeptiere es.\nA: Wunderbar! Willkommen im Team.\nB: Vielen Dank. Ich freue mich.",exampleSrc:"A: Do you accept the offer?\nB: Yes, I accept it.\nA: Wonderful! Welcome to the team.\nB: Thank you very much. I am pleased.",funFact:"Same word internationally. 'Das Angebot akzeptieren' (to accept the offer). Not separable. More formal than 'annehmen.'"},
{type:"teach",trg:"annehmen",src:"to accept, to assume",pos:"verb",gender:null,note:"Separable verb. An + nehmen (to take).\nAlso means 'to assume': 'Ich nehme an, dass...'",example:"A: Nehmen Sie das Angebot an?\nB: Ja, ich nehme es gern an.\nA: Sehr gut.\nB: Wann kann ich anfangen?",exampleSrc:"A: Do you accept the offer?\nB: Yes, I gladly accept it.\nA: Very good.\nB: When can I start?",funFact:"Separable: 'Ich nehme das Angebot an.' Also means 'to assume': 'Ich nehme an, dass...' (I assume that...). Double meaning depending on context."},
{type:"teach",trg:"ausbilden",src:"to train, to educate",pos:"verb",gender:null,note:"Separable verb. Aus + bilden (to form).\n'Wir bilden Lehrlinge aus.'",example:"A: Bilden Sie Lehrlinge aus?\nB: Ja, jedes Jahr fünf neue.\nA: In welchem Beruf?\nB: Als Mechatroniker.",exampleSrc:"A: Do you train apprentices?\nB: Yes, five new ones every year.\nA: In which profession?\nB: As mechatronics engineers.",funFact:"The Ausbildung (training) is the cornerstone of the German economy. Separable: 'Wir bilden Lehrlinge aus' (We train apprentices)."},
{type:"teach",trg:"auswählen",src:"to select, to pick",pos:"verb",gender:null,note:"Separable verb. Aus + wählen (to choose).\nChoosing one OUT of many.",example:"A: Wen haben Sie ausgewählt?\nB: Den Kandidaten aus Berlin.\nA: Warum ihn?\nB: Er hatte die besten Qualifikationen.",exampleSrc:"A: Whom did you select?\nB: The candidate from Berlin.\nA: Why him?\nB: He had the best qualifications.",funFact:"'Wir haben den besten Kandidaten ausgewählt' (We selected the best candidate). Separable. Choosing one OUT of many."},
{type:"teach",trg:"auffordern",src:"to request, to call upon",pos:"verb",gender:null,note:"Separable verb. Auf + fordern (to demand).\nStronger than 'bitten.'",example:"A: Wir fordern Sie auf, sich zu bewerben.\nB: Vielen Dank für die Einladung.\nA: Bitte senden Sie Ihre Unterlagen.\nB: Gern. Bis wann?",exampleSrc:"A: We invite you to apply.\nB: Thank you very much for the invitation.\nA: Please send your documents.\nB: Gladly. By when?",funFact:"'Wir fordern Sie auf, sich zu bewerben' (We invite you to apply). Separable and formal. Note: kündigen alone means 'to resign/fire.' The auf- prefix changes it completely."},
{type:"mc",q:"Der Personalchef schrieb die Annonce und wählte drei Kandidaten aus. Welche Verben stehen im Präteritum?",opts:["Nur wählte","Nur schrieb","Beide sind Präsens","schrieb und wählte"],ans:"schrieb und wählte",hint:"Both verbs describe completed past actions in a narrative. One is strong (vowel change), one is weak (-te)."},
{type:"fb",s:"Ich {1} mich sehr freuen, wenn Sie mich zum Gespräch einladen.",a:["würde"],opts:["würde","will","habe","bin"],hint:"A polite expression of a wish in a cover letter. 'I would be very pleased if...'",sSrc:"I would be very pleased if you invite me to the interview."},
{type:"mc",q:"Verumius fragt: 'Dürfte ich noch eine Frage stellen?' und Yilmaz antwortet: 'Sie könnten auch nach dem Gehalt fragen.' Beide Sätze benutzen...",opts:["Imperativ (Befehle)","Präteritum der Modalverben (Vergangenheit)","Konjunktiv II der Modalverben (höfliche Bitten)","Indikativ der Modalverben (Gegenwart)"],ans:"Konjunktiv II der Modalverben (höfliche Bitten)",hint:"Dürfte and könnten are both Konjunktiv II forms. They soften the request."},
{type:"drag_fill",s:"Ich {1} mich auf die Stelle und {2} gern mehr erfahren.",blanks:{"1":"bewerbe","2":"würde"},pool:["bewerbe","würde","bewarb","will","könnte","muss"],hint:"Present tense for what you are doing now, Konjunktiv II for the polite wish.",sSrc:"I am applying for the position and would like to learn more."},
{type:"match",pairs:[{trg:"ablehnen",src:"to reject"},{trg:"annehmen",src:"to accept"},{trg:"absagen",src:"to cancel"},{trg:"auswählen",src:"to select"},{trg:"auffordern",src:"to request"},{trg:"ausbilden",src:"to train"}]},
{type:"mc",q:"Lebenslauf: 'Ich arbeitete bei BMW.' Anschreiben: 'Ich könnte Ihre Kommunikation verbessern.' Gespräch: 'Ich würde mich über die Stelle freuen.' Welche Konstrukte erscheinen der Reihe nach?",opts:["Alles Konjunktiv II","Präteritum, dann Präteritum, dann Konjunktiv II","Alles Präteritum","Präteritum, dann Modaler Konj. II, dann würde + Inf."],ans:"Präteritum, dann Modaler Konj. II, dann würde + Inf.",hint:"The CV uses narrative past. The letter uses a polite modal. The interview uses würde + Infinitiv."}
]},

// ==================== LESSON 7: Alles auf dem Prüfstand ====================
{id:"deu_r13l7",title:"Alles auf dem Prüfstand",icon:"📋",xp:15,board:true,steps:[
{type:"intro",title:"Alles auf dem Prüfstand",desc:"Test everything from Unit 13. Prove you can write a CV, hold a conversation, and use Präteritum and Konjunktiv II correctly.",goals:["Test everything from Unit 13","Master CV writing and conversation","Apply Präteritum and Konjunktiv II correctly"]},
{type:"teach",trg:"der Anbieter",src:"the provider, the supplier",pos:"noun",gender:"m",note:"Masculine noun. An + Bieter (bidder/offerer).\n'Internetanbieter' = internet provider.",example:"A: Wer ist Ihr Internetanbieter?\nB: Telekom. Und Ihrer?\nA: Vodafone. Die sind günstig.\nB: Ja, es gibt viele Anbieter in Deutschland.",exampleSrc:"A: Who is your internet provider?\nB: Telekom. And yours?\nA: Vodafone. They are affordable.\nB: Yes, there are many providers in Germany.",funFact:"'Internetanbieter' (internet provider), 'Dienstleistungsanbieter' (service provider). The -er ending makes it the person or company doing the offering."},
{type:"teach",trg:"die Beratung",src:"the consulting, the advice",pos:"noun",gender:"f",note:"Feminine noun. From 'beraten' (to advise).\n'Berufsberatung' = career counseling.",example:"A: Brauchen Sie eine Beratung?\nB: Ja, eine Berufsberatung.\nA: Die Agentur für Arbeit bietet kostenlose Beratung.\nB: Gut zu wissen. Danke.",exampleSrc:"A: Do you need counseling?\nB: Yes, career counseling.\nA: The employment agency offers free counseling.\nB: Good to know. Thanks.",funFact:"'Berufsberatung' (career counseling) is free at the Agentur für Arbeit (employment agency). Germany offers professional Beratung for almost everything."},
{type:"teach",trg:"die Fremdsprache",src:"the foreign language",pos:"noun",gender:"f",note:"Feminine noun. Fremd (foreign) + Sprache (language).\nStandard on German CVs.",example:"A: Welche Fremdsprachen sprechen Sie?\nB: Englisch und Französisch.\nA: Auf welchem Niveau?\nB: Englisch fließend, Französisch B1.",exampleSrc:"A: Which foreign languages do you speak?\nB: English and French.\nA: At what level?\nB: English fluently, French B1.",funFact:"'Fremdsprachenkenntnisse' (foreign language skills) are standard on German CVs. English is the most common first Fremdsprache in Germany."},
{type:"teach",trg:"die Muttersprache",src:"the mother tongue",pos:"noun",gender:"f",note:"Feminine noun. Mutter + Sprache.\nSame concept as English 'mother tongue.'",example:"A: Was ist Ihre Muttersprache?\nB: Türkisch.\nA: Und Ihre Fremdsprachen?\nB: Deutsch, Englisch und Arabisch.",exampleSrc:"A: What is your mother tongue?\nB: Turkish.\nA: And your foreign languages?\nB: German, English, and Arabic.",funFact:"Germans put this on their CV to distinguish from learned languages. 'Muttersprache: Deutsch' is how native speakers label it."},
{type:"teach",trg:"die Zweitsprache",src:"the second language",pos:"noun",gender:"f",note:"Feminine noun. Zweit (second) + Sprache.\nLearned early, feels almost native.",example:"A: Deutsch ist meine Zweitsprache.\nB: Wirklich? Sie sprechen perfekt!\nA: Danke. Ich lebe seit 15 Jahren hier.\nB: Das hört man.",exampleSrc:"A: German is my second language.\nB: Really? You speak perfectly!\nA: Thanks. I have been living here for 15 years.\nB: One can tell.",funFact:"Different from Fremdsprache: a Zweitsprache is learned so early it feels almost native. Fremdsprache is learned later and feels foreign."},
{type:"teach",trg:"das Kennzeichen",src:"the characteristic, the license plate",pos:"noun",gender:"n",note:"Neuter noun. Kenn (know) + Zeichen (sign).\nAlso means 'license plate.'",example:"A: Was sind die Kennzeichen eines guten Lebenslaufs?\nB: Struktur, Klarheit und Vollständigkeit.\nA: Und besondere Kennzeichen?\nB: Ihre individuellen Stärken.",exampleSrc:"A: What are the characteristics of a good CV?\nB: Structure, clarity, and completeness.\nA: And special characteristics?\nB: Your individual strengths.",funFact:"Also means 'license plate': your car's Kennzeichen identifies it. On forms: 'Besondere Kennzeichen' (special characteristics)."},
{type:"teach",trg:"die Matura",src:"the Matura (Austrian/Swiss school exam)",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'maturus' (ripe/mature).\nAustrian and Swiss equivalent of Abitur.",example:"A: Haben Sie Matura oder Abitur?\nB: Matura. Ich komme aus Österreich.\nA: Das ist gleichwertig.\nB: Ja, Matura und Abitur sind dasselbe.",exampleSrc:"A: Do you have the Matura or Abitur?\nB: Matura. I come from Austria.\nA: That is equivalent.\nB: Yes, Matura and Abitur are the same.",funFact:"Die Matura is the Austrian and Swiss equivalent of the German Abitur. Same exam, different name. You will encounter both terms when applying across German-speaking countries."},
{type:"teach",trg:"der Führerausweis",src:"the driver's license (Swiss)",pos:"noun",gender:"m",note:"Masculine noun. Führer (driver) + Ausweis (ID).\nSwiss German term. Germans say 'Führerschein.'",example:"A: Haben Sie einen Führerschein?\nB: In der Schweiz heißt das Führerausweis.\nA: Stimmt. Haben Sie einen?\nB: Ja, seit zehn Jahren.",exampleSrc:"A: Do you have a driver's license?\nB: In Switzerland it is called Führerausweis.\nA: Right. Do you have one?\nB: Yes, for ten years.",funFact:"Germans say 'Führerschein,' Swiss say 'Führerausweis.' Same document, regional vocabulary. This shows how German varies across countries."},
{type:"teach",trg:"die Mehrwertsteuer",src:"the value-added tax (VAT)",pos:"noun",gender:"f",note:"Feminine noun. Mehr (more) + Wert (value) + Steuer (tax).\nCurrently 19% in Germany. Abbreviation: MwSt.",example:"A: Ist die Mehrwertsteuer inklusive?\nB: Ja, 19 Prozent MwSt.\nA: In der Schweiz ist sie niedriger.\nB: Stimmt. Dort sind es nur 8,1 Prozent.",exampleSrc:"A: Is the VAT included?\nB: Yes, 19 percent VAT.\nA: In Switzerland it is lower.\nB: Right. There it is only 8.1 percent.",funFact:"Die Mehrwertsteuer is currently 19% in Germany. Everyone knows the abbreviation: MwSt. The longest everyday compound in German tax vocabulary."},
{type:"teach",trg:"der Profisportler",src:"the professional athlete (male)",pos:"noun",gender:"m",note:"Masculine noun. Profi + Sportler (athlete).\nGermany produces many world-class athletes.",example:"A: Er ist Profisportler.\nB: In welcher Sportart?\nA: Fußball. Er spielt in der Bundesliga.\nB: Beeindruckend.",exampleSrc:"A: He is a professional athlete.\nB: In which sport?\nA: Football. He plays in the Bundesliga.\nB: Impressive.",funFact:"Germany's Bundesliga (football), Handball-Bundesliga, and Formula 1 produce many Profisportler. Sports vocabulary meets professional vocabulary."},
{type:"teach",trg:"die Profisportlerin",src:"the professional athlete (female)",pos:"noun",gender:"f",note:"Feminine noun. Profisportler + '-in.'\nGerman women's sports are growing enormously.",example:"A: Sie ist Profisportlerin.\nB: Wirklich? In welcher Sportart?\nA: Handball. Nationalmannschaft.\nB: Toll!",exampleSrc:"A: She is a professional athlete.\nB: Really? In which sport?\nA: Handball. National team.\nB: Great!",funFact:"German women's football has grown enormously. The national team has won multiple European Championships. Die Profisportlerin follows the standard -in pattern."},
{type:"teach",trg:"abhängig",src:"dependent",pos:"adj",gender:null,note:"Ab (off) + hängig (hanging).\nLiterally 'hanging from.' Also used for addiction.",example:"A: Ist das Ergebnis von mir abhängig?\nB: Ja, es hängt von Ihnen ab.\nA: Dann strenge ich mich an.\nB: Das ist die richtige Einstellung.",exampleSrc:"A: Does the result depend on me?\nB: Yes, it depends on you.\nA: Then I will make an effort.\nB: That is the right attitude.",funFact:"'Finanziell abhängig' (financially dependent). Also used for addiction: 'abhängig von Kaffee' (dependent on coffee). The opposite: 'unabhängig' (independent)."},
{type:"teach",trg:"abwesend",src:"absent",pos:"adj",gender:null,note:"Ab (away) + wesend (being).\nThe opposite of anwesend.",example:"A: Herr Müller ist heute abwesend.\nB: Ist er krank?\nA: Ja, er hat sich krankgemeldet.\nB: Gute Besserung.",exampleSrc:"A: Mr. Müller is absent today.\nB: Is he sick?\nA: Yes, he called in sick.\nB: Get well soon.",funFact:"Ab- (away from) vs. an- (at/present). Perfect contrast pair: abwesend (absent) and anwesend (present)."},
{type:"teach",trg:"anwesend",src:"present, in attendance",pos:"adj",gender:null,note:"An (at) + wesend (being).\nRoll call vocabulary.",example:"A: Sind alle Mitarbeiter anwesend?\nB: Fast alle. Drei sind abwesend.\nA: Wer ist nicht anwesend?\nB: Frau Schulz, Herr Weber und Frau Klein.",exampleSrc:"A: Are all employees present?\nB: Almost all. Three are absent.\nA: Who is not present?\nB: Mrs. Schulz, Mr. Weber, and Mrs. Klein.",funFact:"'Alle Mitarbeiter sind anwesend' (All employees are present). Roll call vocabulary. Perfect contrast pair with abwesend."},
{type:"teach",trg:"angenehm",src:"pleasant, agreeable",pos:"adj",gender:null,note:"From 'annehmen.' Pleasant.\n'Angenehm!' = Pleased to meet you!",example:"A: Angenehm! Mein Name ist Verumius.\nB: Freut mich! Ich bin Frau Schmidt.\nA: Die Arbeitsatmosphäre ist sehr angenehm.\nB: Ja, wir legen Wert darauf.",exampleSrc:"A: Pleased to meet you! My name is Verumius.\nB: Nice to meet you! I am Mrs. Schmidt.\nA: The work atmosphere is very pleasant.\nB: Yes, we value that.",funFact:"'Angenehm!' is what Germans say when introduced. Short for 'Es ist mir angenehm, Sie kennenzulernen' (It is pleasant to meet you)."},
{type:"teach",trg:"achten",src:"to pay attention to, to respect",pos:"verb",gender:null,note:"Related to 'Achtung' (attention).\nNot to be confused with acht (eight).",example:"A: Achten Sie auf die Details.\nB: Ja, ich achte immer auf Details.\nA: Sehr gut. Das ist wichtig.\nB: Besonders bei Bewerbungen.",exampleSrc:"A: Pay attention to the details.\nB: Yes, I always pay attention to details.\nA: Very good. That is important.\nB: Especially with applications.",funFact:"Related to 'Achtung' (attention). 'Ich achte darauf' (I pay attention to that). Not to be confused with the number acht (eight)."},
{type:"teach",trg:"ankündigen",src:"to announce",pos:"verb",gender:null,note:"Separable verb. An + kündigen (to announce).\nNote: kündigen alone means 'to resign/fire.'",example:"A: Die Firma kündigt Veränderungen an.\nB: Welche Veränderungen?\nA: Neue Arbeitszeiten.\nB: Das wurde letzte Woche angekündigt.",exampleSrc:"A: The company announces changes.\nB: What changes?\nA: New working hours.\nB: That was announced last week.",funFact:"Separable: 'Die Firma kündigt Veränderungen an.' Note: kündigen alone means 'to resign/fire.' The an- prefix changes the meaning entirely."},
{type:"teach",trg:"anschaffen",src:"to purchase, to acquire",pos:"verb",gender:null,note:"Separable verb. An + schaffen (to create).\nMore formal than 'kaufen.'",example:"A: Wir müssen neue Computer anschaffen.\nB: Wie viele?\nA: Zehn Stück. Für die neue Abteilung.\nB: Das kostet viel Geld.",exampleSrc:"A: We need to purchase new computers.\nB: How many?\nA: Ten units. For the new department.\nB: That costs a lot of money.",funFact:"Used for business purchases. More formal than 'kaufen' (to buy). Separable: 'Wir schaffen neue Geräte an.'"},
{type:"teach",trg:"anstellen",src:"to hire, to employ",pos:"verb",gender:null,note:"Separable verb. An + stellen (to place).\nSame meaning as 'einstellen.'",example:"A: Wir stellen neue Mitarbeiter an.\nB: Wie viele?\nA: Fünf für die IT-Abteilung.\nB: Wann fangen sie an?",exampleSrc:"A: We are hiring new employees.\nB: How many?\nA: Five for the IT department.\nB: When do they start?",funFact:"Same meaning as 'einstellen.' Separable. Also colloquial: 'Was stellst du an?' (What are you up to/doing?)."},
{type:"teach",trg:"anstrengen",src:"to exhaust, to make an effort",pos:"verb",gender:null,note:"Separable verb. An + strengen (to tighten).\nReflexive: 'Ich strenge mich an.'",example:"A: Die Arbeit strengt mich an.\nB: Ist es zu viel?\nA: Nein, ich strenge mich gern an.\nB: Das sieht man. Gute Arbeit!",exampleSrc:"A: The work exhausts me.\nB: Is it too much?\nA: No, I like making an effort.\nB: One can tell. Good work!",funFact:"Reflexive: 'Ich strenge mich an' (I make an effort). The more you tighten yourself, the harder you work. The noun: Anstrengung (effort)."},
{type:"mc",q:"Im Lebenslauf: 'Ich ging zur Universität und studierte Architektur.' Was beschreibt dieser Satz?",opts:["Vergangene Ausbildung im Präteritum","Einen aktuellen Plan im Präsens","Einen Zukunftsplan im Futur I","Einen Wunsch im Konjunktiv II"],ans:"Vergangene Ausbildung im Präteritum",hint:"Ging and studierte are both Präteritum forms. CVs use this tense for work and education history."},
{type:"fb",s:"Ich {1} mich über eine Einladung zum Gespräch freuen.",a:["würde"],opts:["würde","will","habe","wurde"],hint:"A polite wish in a cover letter. Be careful: würde (would) is not the same as wurde (became).",sSrc:"I would be pleased about an invitation to the interview."},
{type:"mc",q:"'Dürfte ich Sie etwas fragen?' Welches Modalverb steht im Konjunktiv II?",opts:["sollen (sollte)","dürfen (dürfte = darf ich/könnte ich)","müssen (müsste)","können (könnte)"],ans:"dürfen (dürfte = darf ich/könnte ich)",hint:"Dürfte is the Konjunktiv II of dürfen. It makes the permission request very polite."},
{type:"drag_fill",s:"Ich {1} bei Siemens und {2} gern wieder dort {3}.",blanks:{"1":"arbeitete","2":"würde","3":"arbeiten"},pool:["arbeitete","würde","arbeiten","arbeite","wurde","gearbeitet"],hint:"First: past tense for CV history. Then: würde + Infinitiv for a polite wish about the future.",sSrc:"I worked at Siemens and would gladly work there again."},
{type:"match",pairs:[{trg:"Muttersprache",src:"mother tongue"},{trg:"Fremdsprache",src:"foreign language"},{trg:"Zweitsprache",src:"second language"},{trg:"fließend",src:"fluent"},{trg:"Anbieter",src:"provider"},{trg:"Beratung",src:"consulting"}]},
{type:"mc",q:"Ein Anschreiben enthält: 'Ich könnte Ihr Team verstärken, da ich drei Sprachen fließend spreche.' Was macht diesen Satz fortgeschritten?",opts:["Nur der Wortschatz ist fortgeschritten","Es enthält einen Relativsatz","Es benutzt Präteritum","Modaler Konjunktiv II + Kausalsatz + Wortschatzbreite"],ans:"Modaler Konjunktiv II + Kausalsatz + Wortschatzbreite",hint:"Multiple advanced constructs in one sentence: polite modal, cause-and-effect with 'da,' and professional vocabulary."},
{type:"fb",s:"Könnten Sie mir bitte {1}, wann das Gespräch stattfindet?",a:["sagen"],opts:["sagen","gesagt","sage","sagte"],hint:"Könnten Sie + Infinitiv at the end. A polite request for information.",sSrc:"Could you please tell me when the interview takes place?"}
]},

// ==================== LESSON 8: Die gute Nachricht ====================
{id:"deu_r13l8",title:"Die gute Nachricht",icon:"🎉",xp:15,board:true,steps:[
{type:"intro",title:"Die gute Nachricht",desc:"Read a formal acceptance email. Compare formal and informal German. Celebrate with friends. Review all constructs from Unit 13.",goals:["Read a formal acceptance email","Compare formal and informal German","Review all constructs from Unit 13"]},
{type:"story",speaker:"narrator",mood:"excited",art:"de-verumius-apartment-laptop",trg:"Verumius' Wohnung. Später Abend. Er sitzt an seinem Laptop, die Kaffeetasse leer. Eine E-Mail-Benachrichtigung erscheint. Der Absender: Personalabteilung, TechBerlin GmbH.",src:"Verumius's apartment. Late evening. He sits at his laptop, the coffee cup empty. An email notification appears. The sender: HR Department, TechBerlin GmbH."},
{type:"story",speaker:"narrator",mood:"suspenseful",art:"de-verumius-apartment-laptop",trg:"Die E-Mail beginnt: 'Sehr geehrter Herr Verumius, wir freuen uns, Ihnen mitzuteilen, dass wir Sie für die Stelle ausgewählt haben...'",src:"The email begins: 'Dear Mr. Verumius, we are pleased to inform you that we have selected you for the position...'"},
{type:"story",speaker:"verumius",mood:"ecstatic",trg:"JA! Ich habe die Stelle! Dr. Yilmaz hatte recht, die Vorbereitung hat sich gelohnt!",src:"YES! I got the job! Dr. Yilmaz was right, the preparation paid off!"},
{type:"story",speaker:"verumius",mood:"happy",trg:"Verumius tippt eine Nachricht an Lukas: 'Lukas! Ich habe den Job bekommen!'",src:"Verumius types a message to Lukas: 'Lukas! I got the job!'"},
{type:"story",speaker:"lukas",mood:"excited",trg:"Alter! Krass! Das müssen wir feiern. Freitag Kneipe?",src:"Dude! Awesome! We have to celebrate. Friday at the bar?"},
{type:"story",speaker:"verumius",mood:"happy",trg:"Ja!",src:"Yes!"},
{type:"story",speaker:"lukas",mood:"casual",trg:"Ich bring meine Gitarre mit.",src:"I'll bring my guitar."},
{type:"teach",trg:"die Mühe",src:"the effort, the trouble",pos:"noun",gender:"f",note:"Feminine noun. 'Die Mühe lohnt sich' = The effort is worth it.\nRelated to English 'moil' (to toil).",example:"A: Vielen Dank für Ihre Mühe.\nB: Gern geschehen. Es war keine Mühe.\nA: Doch, Sie haben sich viel Mühe gegeben.\nB: Es hat sich gelohnt.",exampleSrc:"A: Thank you very much for your effort.\nB: You're welcome. It was no trouble.\nA: Yes it was, you put in a lot of effort.\nB: It was worth it.",funFact:"'Vielen Dank für Ihre Mühe' is a formal closing line that thanks someone for their effort. 'Die Mühe lohnt sich' (The effort is worth it)."},
{type:"teach",trg:"anhaben",src:"to wear, to have on",pos:"verb",gender:null,note:"Separable verb. An + haben.\n'Was hast du an?' = What are you wearing?",example:"A: Was hast du morgen an?\nB: Meinen besten Anzug.\nA: Gute Idee. Der erste Eindruck zählt.\nB: Ja, ich will professionell aussehen.",exampleSrc:"A: What will you wear tomorrow?\nB: My best suit.\nA: Good idea. The first impression counts.\nB: Yes, I want to look professional.",funFact:"'Was hast du an?' (What are you wearing?). Separable. More casual than 'tragen' (to wear/carry). Perfect for informal conversation."},
{type:"teach",trg:"ansprechen",src:"to address, to bring up",pos:"verb",gender:null,note:"Separable verb. An + sprechen.\nTwo meanings: talking TO and talking ABOUT.",example:"A: Darf ich Sie ansprechen?\nB: Natürlich.\nA: Ich möchte das Thema Gehalt ansprechen.\nB: Gern. Was stellen Sie sich vor?",exampleSrc:"A: May I address you?\nB: Of course.\nA: I would like to bring up the topic of salary.\nB: Gladly. What do you have in mind?",funFact:"Two meanings: 'Darf ich Sie ansprechen?' (May I address you?) and 'Das Thema ansprechen' (to bring up the topic). Talking TO and talking ABOUT."},
{type:"teach",trg:"anwenden",src:"to apply, to use",pos:"verb",gender:null,note:"Separable verb. An + wenden (to turn).\nApplying knowledge in practice.",example:"A: Können Sie Ihre Kenntnisse anwenden?\nB: Ja, ich wende mein Wissen täglich an.\nA: Die Anwendung ist wichtiger als die Theorie.\nB: Da stimme ich zu.",exampleSrc:"A: Can you apply your knowledge?\nB: Yes, I apply my knowledge daily.\nA: Application is more important than theory.\nB: I agree.",funFact:"What you learned in theory, you 'anwenden' in practice. 'Anwendung' (application) is the noun form. Separable verb."},
{type:"teach",trg:"anzeigen",src:"to display, to report, to advertise",pos:"verb",gender:null,note:"Separable verb. An + zeigen (to show).\nAlso: 'jemanden anzeigen' = to report to police.",example:"A: Die Firma zeigt die Stelle online an.\nB: Auf welcher Webseite?\nA: Auf Indeed und LinkedIn.\nB: Gut. Ich schaue sofort nach.",exampleSrc:"A: The company advertises the position online.\nB: On which website?\nA: On Indeed and LinkedIn.\nB: Good. I will check right away.",funFact:"'Eine Stelle anzeigen' (to advertise a position). Also: 'Jemanden anzeigen' (to report someone to police). 'Anzeige' is both an ad and a police report."},
{type:"teach",trg:"begleiten",src:"to accompany",pos:"verb",gender:null,note:"Not separable. Be- + gleiten (to glide).\nTo glide alongside someone.",example:"A: Darf ich Sie zum Büro begleiten?\nB: Ja, gern. Ich kenne den Weg noch nicht.\nA: Kommen Sie. Ich begleite Sie.\nB: Vielen Dank.",exampleSrc:"A: May I accompany you to the office?\nB: Yes, gladly. I don't know the way yet.\nA: Come along. I will accompany you.\nB: Thank you very much.",funFact:"The be- prefix makes it transitive. Gleiten alone means to glide. Together: to glide alongside someone. 'Darf ich Sie begleiten?' is polite and formal."},
{type:"teach",trg:"bekanntgeben",src:"to announce, to make known",pos:"verb",gender:null,note:"Separable verb. Bekannt (known) + geben (to give).\nMaking something known to everyone.",example:"A: Wann geben Sie die Ergebnisse bekannt?\nB: Morgen Nachmittag.\nA: Per E-Mail?\nB: Ja, wir geben alles per E-Mail bekannt.",exampleSrc:"A: When will you announce the results?\nB: Tomorrow afternoon.\nA: By email?\nB: Yes, we announce everything by email.",funFact:"'Die Firma gibt die Ergebnisse bekannt' (The company announces the results). Separable. Making something known to everyone."},
{type:"teach",trg:"benötigen",src:"to require, to need",pos:"verb",gender:null,note:"Not separable. More formal than 'brauchen.'\nStandard in business correspondence.",example:"A: Welche Unterlagen benötigen Sie?\nB: Lebenslauf und Zeugnisse.\nA: Benötigen Sie auch ein Foto?\nB: Ja, bitte.",exampleSrc:"A: Which documents do you need?\nB: CV and certificates.\nA: Do you also need a photo?\nB: Yes, please.",funFact:"'Wir benötigen Ihre Unterlagen' (We require your documents). Standard in business correspondence. More formal than 'brauchen.'"},
{type:"teach",trg:"besorgen",src:"to obtain, to get",pos:"verb",gender:null,note:"Not separable. Be- + sorgen (to care).\nAlso: 'besorgt sein' = to be worried.",example:"A: Können Sie mir die Unterlagen besorgen?\nB: Ja, ich besorge sie bis morgen.\nA: Danke. Das ist sehr hilfreich.\nB: Kein Problem.",exampleSrc:"A: Can you get me the documents?\nB: Yes, I will get them by tomorrow.\nA: Thanks. That is very helpful.\nB: No problem.",funFact:"Two meanings depending on context: 'besorgen' (to obtain/get) and 'besorgt sein' (to be worried). The meaning changes with reflexive use."},
{type:"teach",trg:"beweisen",src:"to prove",pos:"verb",gender:null,note:"Not separable. Strong verb: beweisen/bewies/bewiesen.\nIn job contexts: proving your worth.",example:"A: Können Sie Ihre Qualifikation beweisen?\nB: Ja, hier sind meine Zeugnisse.\nA: Das beweist Ihre Erfahrung.\nB: Ich habe auch Referenzen.",exampleSrc:"A: Can you prove your qualification?\nB: Yes, here are my certificates.\nA: That proves your experience.\nB: I also have references.",funFact:"Strong verb: beweisen/bewies/bewiesen. 'Das beweist seine Qualifikation' (That proves his qualification). Be- + weisen (to show/point)."},
{type:"teach",trg:"erfordern",src:"to require, to demand",pos:"verb",gender:null,note:"Not separable. Er- + fordern (to demand).\nMore formal than 'brauchen.'",example:"A: Die Stelle erfordert Erfahrung.\nB: Wie viel Erfahrung?\nA: Mindestens drei Jahre.\nB: Das erfülle ich.",exampleSrc:"A: The position requires experience.\nB: How much experience?\nA: At least three years.\nB: I meet that requirement.",funFact:"'Die Stelle erfordert Erfahrung' (The position requires experience). Not separable. The official word in job listings. More formal than 'brauchen.'"},
{type:"teach",trg:"erkundigen",src:"to inquire",pos:"verb",gender:null,note:"Always reflexive: 'sich erkundigen nach.'\nFormal and polite.",example:"A: Ich erkundige mich nach der Stelle.\nB: Gern. Was möchten Sie wissen?\nA: Wann beginnt die Stelle?\nB: Am ersten April.",exampleSrc:"A: I am inquiring about the position.\nB: Gladly. What would you like to know?\nA: When does the position start?\nB: On the first of April.",funFact:"Always reflexive: 'Ich erkundige mich nach der Stelle' (I inquire about the position). Formal and polite. What you do before applying."},
{type:"teach",trg:"funktionieren",src:"to function, to work",pos:"verb",gender:null,note:"Not separable. From French 'fonctionner.'\n'Das funktioniert!' = That works!",example:"A: Funktioniert der Drucker?\nB: Nein, er funktioniert nicht.\nA: Seit wann funktioniert er nicht?\nB: Seit gestern.",exampleSrc:"A: Does the printer work?\nB: No, it doesn't work.\nA: Since when doesn't it work?\nB: Since yesterday.",funFact:"One of the most-used words in everyday German. Pronounced 'funk-tsio-NEE-ren.' 'Das funktioniert!' (That works!) is said constantly."},
{type:"teach",trg:"handeln",src:"to act, to trade, to negotiate",pos:"verb",gender:null,note:"'Es handelt sich um...' = It concerns...\nDer Handel = trade. Die Handlung = plot/action.",example:"A: Worum handelt es sich?\nB: Es handelt sich um eine neue Stelle.\nA: Wie sollen wir handeln?\nB: Schnell. Die Frist endet bald.",exampleSrc:"A: What is it about?\nB: It is about a new position.\nA: How should we act?\nB: Quickly. The deadline ends soon.",funFact:"'Es handelt sich um...' (It concerns...) is formal German for introducing a topic. Covers action, commerce, and negotiation. Der Handel = trade."},
{type:"teach",trg:"melden",src:"to report, to register",pos:"verb",gender:null,note:"'Sich melden' = to get in touch.\n'Bitte melden Sie sich am Empfang.'",example:"A: Bitte melden Sie sich am Empfang.\nB: Gut. Wo ist der Empfang?\nA: Im Erdgeschoss.\nB: Ich melde mich sofort.",exampleSrc:"A: Please report to reception.\nB: Good. Where is reception?\nA: On the ground floor.\nB: I will report right away.",funFact:"'Sich melden' (to get in touch, to report). 'Bitte melden Sie sich am Empfang.' Essential for German bureaucracy. Also used for raising your hand in class."},
{type:"teach",trg:"die Absenderin",src:"the sender (female)",pos:"noun",gender:"f",note:"Feminine noun. Ab (from) + Senderin.\nThe person who sends a letter or email.",example:"A: Wer ist die Absenderin?\nB: Die Personalabteilung.\nA: Die Absenderin schreibt sehr höflich.\nB: Ja, formelle E-Mails sind immer höflich.",exampleSrc:"A: Who is the sender?\nB: The HR department.\nA: The sender writes very politely.\nB: Yes, formal emails are always polite.",funFact:"'Absender/Absenderin' appears on every German letter and official email. The female sender. Ab (from) + Senderin."},
{type:"teach",trg:"meinetwegen",src:"for my sake, as far as I'm concerned",pos:"adv",gender:null,note:"Meinet (my) + wegen (because of).\nCan be generous or dismissive depending on tone.",example:"A: Soll ich Freitag kommen?\nB: Meinetwegen. Freitag passt.\nA: Bist du sicher?\nB: Ja, meinetwegen gern.",exampleSrc:"A: Should I come on Friday?\nB: Fine by me. Friday works.\nA: Are you sure?\nB: Yes, fine by me.",funFact:"'Meinetwegen kannst du gehen' (For all I care, you can go). Can be generous or dismissive depending on tone. Combines 'my' with 'because of.'"},
{type:"teach",trg:"halbtags",src:"half-day, mornings/afternoons only",pos:"adv",gender:null,note:"Halb (half) + tags (during the day).\nDifferent from Teilzeit: specifically half a day.",example:"A: Arbeiten Sie halbtags?\nB: Ja, nur vormittags.\nA: Von wann bis wann?\nB: Von acht bis zwölf.",exampleSrc:"A: Do you work half-days?\nB: Yes, only mornings.\nA: From when to when?\nB: From eight to twelve.",funFact:"Different from Teilzeit: halbtags is specifically half a day, Teilzeit can be any reduced hours. 'Halbtags arbeiten' (to work half-days)."},
{type:"teach",trg:"perfekt",src:"perfect",pos:"adj",gender:null,note:"From Latin 'perfectus' (completed).\nAlso the name of a German past tense.",example:"A: Dein Lebenslauf ist perfekt!\nB: Wirklich?\nA: Ja, perfekt strukturiert.\nB: Danke! Das freut mich.",exampleSrc:"A: Your CV is perfect!\nB: Really?\nA: Yes, perfectly structured.\nB: Thanks! That makes me happy.",funFact:"Same word in English and German. 'Dein Lebenslauf ist perfekt!' Also the name of the German past tense 'Perfekt' (Ich habe gemacht). Double meaning: the grammar tense and the adjective."},
{type:"tip",title:"Formal vs. Informal: Two Worlds",text:"The acceptance email:\n'Sehr geehrter Herr Verumius, wir freuen uns, Ihnen mitzuteilen...'\n\nLukas' message:\n'Alter! Krass!'\n\nSame language, two worlds.\n\nFormal German: Konjunktiv II, complete sentences, Sie, long words.\nInformal German: du, slang, abbreviations, voice messages.\n\nBoth are correct. The art is knowing when to use which.",deepDive:{title:"Switching Registers: A Key Skill",text:"In a job interview:\n'Ich würde mich freuen, von Ihnen zu hören.'\n\nIn the WhatsApp group:\n'Yo, hab den Job! Party?'\n\nGerman has more register levels than English.\nThe same person might use:\n1. Formal (applications, government offices)\n2. Standard (work, teachers)\n3. Informal (friends, family)\n4. Colloquial (slang, youth language)\n\nVerumius needs to understand all four.\n\nPhone etiquette: Always answer the phone with your name:\n'Müller, guten Tag.' Never just say 'Hallo?'\n\nLabor law basics:\nAfter probation: notice period = 4 weeks to the 15th or month end.\nWorks council must be consulted before termination.\nSick note: 6 weeks full salary."}},

{type:"tip",title:"The Application Process: Eight Steps",text:"The typical application process in Germany:\n\n1. Find a job listing (Stellenanzeige)\n2. Write the application (Anschreiben + Lebenslauf + Zeugnisse)\n3. Send the application (by email or portal)\n4. Receive an interview invitation\n5. Job interview (Vorstellungsgespräch)\n6. Acceptance or rejection (Zusage/Absage)\n7. Sign the contract\n8. Probation period begins (usually 6 months)",deepDive:{title:"Patience Required",text:"The process takes weeks to months.\nLarge companies: phone interview + in-person interview + assessment center.\nAcceptance: 1-2 weeks to decide.\nRejection: usually by email or letter.\n\nIt is completely normal to write 20-50 applications before getting an offer. Do not give up!"}},
{type:"tip",title:"The Cover Letter: Structure",text:"A German Anschreiben has 10 parts:\n\n1. Sender (your address, top right)\n2. Recipient (company, left)\n3. Place and date: Berlin, den 15. März 2026\n4. Subject line (bold, without 'Betreff:')\n5. Greeting: Sehr geehrte Damen und Herren,\n6. Introduction\n7. Main body\n8. Closing\n9. Sign-off: Mit freundlichen Grüßen\n10. Signature\n\nMaximum ONE page. After the greeting: comma, then new line.",deepDive:{title:"Formal Letters: The Sie Rule",text:"In formal letters and emails, Sie is ALWAYS capitalized:\nIhnen, Ihrer, Ihrem, Ihre\n\nThis also applies to emails.\n'Ich freue mich, von Ihnen zu hören.'\n'Könnten Sie mir Ihre Unterlagen zusenden?'\n\nDate format: Day. Month Year\nBerlin, den 15. März 2026 (not: März 15, 2026)"}},
{type:"tip",title:"The Sie Form in Job Interviews",text:"Job interviews in Germany ALWAYS use Sie.\nNever switch to du unless the interviewer explicitly offers it.\nEven then, some candidates stay with Sie.",deepDive:{title:"Offering the Du",text:"The transition from Sie to du is called 'das Duzen anbieten.'\nTraditionally, the higher-ranking person offers the Du.\n\nIn startups, du is often used from the start.\nWhen in doubt: always use Sie.\n\n'Sollen wir uns duzen?' = Shall we use du?\n'Gern! Ich bin Thomas.' = The switch happens."}},
{type:"mc",q:"Welcher Satz gehört in eine formelle Zusage-E-Mail?",opts:["Hey, du hast den Job! Komm Montag.","Ja cool, bis Montag dann.","Wir würden uns freuen, Sie in unserem Team zu begrüßen.","Alter, krass! Willkommen!"],ans:"Wir würden uns freuen, Sie in unserem Team zu begrüßen.",hint:"Formal emails use Konjunktiv II, Sie, and complete sentences."},
{type:"fb",s:"Er {1} drei Jahre in Istanbul und kam dann nach Berlin.",a:["studierte"],opts:["studierte","studiert","studieren","studiere"],hint:"Narrative past in a CV context. A regular verb in the Präteritum takes -te.",sSrc:"He studied three years in Istanbul and then came to Berlin."},
{type:"mc",q:"Verumius schreibt an die Firma: 'Könnten Sie mir bitte den Vertrag zusenden?' Warum könnten und nicht können?",opts:["Es gibt keinen Unterschied","Können wäre grammatisch falsch","Könnten bedeutet etwas anderes","Könnten ist höflicher und formeller"],ans:"Könnten ist höflicher und formeller",hint:"The Konjunktiv II of modals softens requests. Professional correspondence always prefers the polite form."},
{type:"drag_fill",s:"Ich {1} mir, Ihnen {2}, dass ich die Stelle gern {3} möchte.",blanks:{"1":"erlaube","2":"mitzuteilen","3":"annehmen"},pool:["erlaube","mitzuteilen","annehmen","erlaubte","mitteilen","angenommen"],hint:"A formal response: 'I allow myself to inform you that I would like to accept the position.'",sSrc:"I allow myself to inform you that I would like to accept the position."},
{type:"match",pairs:[{trg:"Bewerbung",src:"application"},{trg:"Lebenslauf",src:"CV/resume"},{trg:"Vorstellungsgespräch",src:"job interview"},{trg:"Kündigung",src:"termination"},{trg:"Mühe",src:"effort"},{trg:"Erfolg",src:"success"}]},
{type:"mc",q:"Lukas schreibt: 'Alter! Krass!' Die Firma schreibt: 'Sehr geehrter Herr Verumius.' Was zeigt dieser Kontrast?",opts:["Formelles und informelles Register in derselben Sprache","Lukas spricht kein gutes Deutsch","Die Firma ist unhöflich","Verumius versteht Lukas nicht"],ans:"Formelles und informelles Register in derselben Sprache",hint:"German has formal and informal registers. The skill is knowing when to use which one."},
{type:"fb",s:"Wir {1} uns, Ihnen mitzuteilen, dass wir Sie ausgewählt haben.",a:["freuen"],opts:["freuen","würden","können","haben"],hint:"The standard opening of a positive reply from an employer. 'We are pleased to inform you...'",sSrc:"We are pleased to inform you that we have selected you."}
]}

]},

{n:14,lang:"de",srcLang:"en",track:"v2",title:"Erster Arbeitstag",sub:"First day at work, office culture, passive voice, relative clauses",icon:"💼",level:"B1.1",color:"#7B5EE8",lessons:[

// ─── Lesson 1: Der erste Morgen ───
{id:"deu_r14l1",title:"Der erste Morgen",icon:"🌅",xp:15,board:true,steps:[
{type:"intro",title:"Der erste Morgen",desc:"Verumius stands in front of his new workplace in Berlin-Mitte. He is wearing a suit. Everyone else is wearing jeans. Time to discover the German office world.",goals:["Learn 20 key workplace vocabulary words","Understand the structure of a German office","Follow Verumius through his first workday with Mia as guide"]},
{type:"story",speaker:"narrator",mood:"excited",art:"de-ber-office-exterior",trg:"Es ist Montagmorgen in Berlin-Mitte. Verumius steht vor einem modernen Bürogebäude aus Glas und Stahl. Er trägt einen Anzug. Alle anderen tragen Jeans.",src:"It is Monday morning in Berlin-Mitte. Verumius stands in front of a modern office building of glass and steel. He is wearing a suit. Everyone else is wearing jeans."},
{type:"story",speaker:"mia",mood:"amused",art:"de-ber-office-entrance",trg:"Willkommen im Betrieb! Du bist etwas overdressed. Aber keine Sorge, das passiert jedem am ersten Tag.",src:"Welcome to the company! You are a bit overdressed. But no worries, that happens to everyone on the first day."},
{type:"teach",trg:"der Betrieb",src:"the company, the operation",pos:"noun",gender:"m",note:"From 'betreiben' (to operate). A Betrieb is any active business.\n'Im Betrieb' means at work or in operation.",example:"A: Wie lange gibt es diesen Betrieb schon?\nB: Seit zwanzig Jahren. Er wurde 2006 gegründet.\nA: Und wie viele Leute arbeiten hier?\nB: Ungefähr zweihundert im ganzen Betrieb.",exampleSrc:"A: How long has this company existed?\nB: For twenty years. It was founded in 2006.\nA: And how many people work here?\nB: About two hundred in the whole company.",funFact:"Germans distinguish Firma (legal company name), Betrieb (active operation), and Unternehmen (enterprise). A Betrieb can be a factory, an office, or a bakery. If it operates, it is a Betrieb."},
{type:"teach",trg:"die Abteilung",src:"the department",pos:"noun",gender:"f",note:"Ab- (off) + teilen (to divide). A department is a 'division.'\nEvery German company is organized into Abteilungen.",example:"A: In welcher Abteilung arbeitest du?\nB: In der Marketing-Abteilung.\nA: Und wie viele Leute sind in deiner Abteilung?\nB: Wir sind zu zwölft.",exampleSrc:"A: Which department do you work in?\nB: In the marketing department.\nA: And how many people are in your department?\nB: There are twelve of us.",funFact:"Your Abteilung defines your identity at work. Germans introduce themselves by department: 'Ich bin aus der IT-Abteilung.' It is your workplace tribe."},
{type:"teach",trg:"die Etage",src:"the floor, the level",pos:"noun",gender:"f",note:"Borrowed from French. 'Erste Etage' = first floor ABOVE ground.\nGround floor is 'Erdgeschoss.'",example:"A: Auf welcher Etage ist die Kantine?\nB: Im dritten Stock, also dritte Etage.\nA: Gibt es einen Aufzug?\nB: Ja, am Ende vom Flur.",exampleSrc:"A: Which floor is the canteen on?\nB: On the third floor, so third level.\nA: Is there an elevator?\nB: Yes, at the end of the hallway.",funFact:"Germans say 'erste Etage' for the first floor ABOVE ground. Ground floor is 'Erdgeschoss.' So 'dritte Etage' equals the British third floor or the American fourth floor. Confusion guaranteed for visitors."},
{type:"teach",trg:"der Flur",src:"the hallway, the corridor",pos:"noun",gender:"m",note:"Where you overhear gossip and bump into the boss.\nAlso means 'open field' in old German.",example:"A: Wo ist das Büro von Frau Müller?\nB: Am Ende vom Flur, die letzte Tür links.\nA: Danke! Der Flur ist aber lang.\nB: Ja, wir haben eine große Etage.",exampleSrc:"A: Where is Frau Müller's office?\nB: At the end of the hallway, the last door on the left.\nA: Thanks! The hallway is quite long.\nB: Yes, we have a large floor.",funFact:"The Flur is where German office culture happens: chance encounters with the boss, overheard phone calls, and the eternal walk to the coffee kitchen. Many important decisions are made 'auf dem Flur.'"},
{type:"teach",trg:"der Gang",src:"the corridor, the aisle",pos:"noun",gender:"m",note:"Both a corridor AND a course of a meal.\n'Der Gang zum Kopierer' uses the same word as 'der erste Gang' (first course).",example:"A: Der Konferenzraum ist am Ende des Gangs.\nB: Welcher Gang? Es gibt hier so viele!\nA: Der Gang rechts neben der Kaffeküche.\nB: Ah, jetzt sehe ich ihn.",exampleSrc:"A: The conference room is at the end of the corridor.\nB: Which corridor? There are so many here!\nA: The corridor to the right of the coffee kitchen.\nB: Ah, now I see it.",funFact:"Gang has many meanings: corridor, aisle (in a plane), course (of a meal), gear (in a car), and gait (how you walk). Context is everything in German."},
{type:"teach",trg:"die Kantine",src:"the canteen, the cafeteria",pos:"noun",gender:"f",note:"From Latin 'cantina.' The company cafeteria.\nSubsidized meals, salad bars, Currywurst on Fridays.",example:"A: Wo essen die meisten zu Mittag?\nB: In der Kantine. Das Essen ist gut und günstig.\nA: Was kostet ein Mittagessen?\nB: Ungefähr vier Euro. Der Betrieb zahlt den Rest.",exampleSrc:"A: Where do most people eat lunch?\nB: In the canteen. The food is good and affordable.\nA: How much does a lunch cost?\nB: About four euros. The company pays the rest.",funFact:"German office canteens are legendary: subsidized hot meals, salad bars, and the social epicenter of every workplace. Currywurst on Fridays is a tradition in many Kantinen across the country."},
{type:"teach",trg:"die Garderobe",src:"the cloakroom, the wardrobe",pos:"noun",gender:"f",note:"From French 'garder' (to keep) + 'robe' (clothing).\nEveryone hangs their coat here before starting work.",example:"A: Wo kann ich meine Jacke aufhängen?\nB: In der Garderobe, gleich am Eingang.\nA: Gibt es einen Haken für mich?\nB: Ja, nimm einfach einen freien Platz.",exampleSrc:"A: Where can I hang my jacket?\nB: In the cloakroom, right at the entrance.\nA: Is there a hook for me?\nB: Yes, just take any free spot.",funFact:"In German offices, everyone hangs their coat in the Garderobe before starting work. Some companies have a strict 'no jackets at desks' policy. The Garderobe is the transition zone between outside world and office world."},
{type:"teach",trg:"die Besprechung",src:"the meeting, the discussion",pos:"noun",gender:"f",note:"Be- + sprechen (to speak). A meeting.\nGermans take Besprechungen seriously: agenda, start time, end time.",example:"A: Wann ist die Besprechung?\nB: Um zehn Uhr im Konferenzraum.\nA: Wie lange dauert sie?\nB: Ungefähr eine Stunde. Danach ist Mittagspause.",exampleSrc:"A: When is the meeting?\nB: At ten o'clock in the conference room.\nA: How long does it last?\nB: About one hour. After that is lunch break.",funFact:"Germans take Besprechungen seriously: there is an agenda, a start time, and usually an end time. Being late to a Besprechung is a serious faux pas. Five minutes early is the German on time."},
{type:"teach",trg:"die Konferenz",src:"the conference",pos:"noun",gender:"f",note:"From Latin 'conferre' (to bring together).\nMore formal than a Besprechung. Konferenzräume are on every floor.",example:"A: Nächste Woche haben wir eine große Konferenz.\nB: Wie viele Teilnehmer kommen?\nA: Ungefähr fünfzig. Aus drei Abteilungen.\nB: Dann brauchen wir den großen Konferenzraum.",exampleSrc:"A: Next week we have a big conference.\nB: How many participants are coming?\nA: About fifty. From three departments.\nB: Then we need the large conference room.",funFact:"A Konferenz is more formal than a Besprechung. Conference rooms are Konferenzräume. The -enz ending in German (like Konferenz, Konkurrenz, Existenz) always comes from Latin and is always feminine."},
{type:"teach",trg:"der Tagesablauf",src:"the daily routine, the daily schedule",pos:"noun",gender:"m",note:"Tag (day) + Ablauf (sequence). Your daily routine.\nOn your first day, someone always explains the Tagesablauf.",example:"A: Wie ist der Tagesablauf hier?\nB: Wir fangen um acht an, Mittagspause um zwölf.\nA: Und wann ist Feierabend?\nB: Um siebzehn Uhr. Pünktlich.",exampleSrc:"A: What is the daily routine here?\nB: We start at eight, lunch break at twelve.\nA: And when is end of work?\nB: At five o'clock. Punctually.",funFact:"Germans love structure. The Tagesablauf is almost sacred: 8:00 start, 12:00 lunch, 17:00 Feierabend. Deviating from the Tagesablauf without good reason raises eyebrows."},
{type:"teach",trg:"die Zusammenarbeit",src:"the collaboration, the teamwork",pos:"noun",gender:"f",note:"Zusammen (together) + Arbeit (work). Collaboration.\n'Gute Zusammenarbeit' is the highest workplace praise.",example:"A: Wie ist die Zusammenarbeit in deinem Team?\nB: Sehr gut. Wir besprechen alles gemeinsam.\nA: Das klingt ideal.\nB: Ja, gute Zusammenarbeit ist hier sehr wichtig.",exampleSrc:"A: How is the collaboration in your team?\nB: Very good. We discuss everything together.\nA: That sounds ideal.\nB: Yes, good collaboration is very important here.",funFact:"Germans value Zusammenarbeit so much they put it in job descriptions, performance reviews, and company values. 'Gute Zusammenarbeit' is the highest workplace praise you can receive."},
{type:"teach",trg:"begrüßen",src:"to welcome, to greet",pos:"verb",gender:null,note:"Be- + grüßen (to greet). More thorough than casual grüßen.\n'Ich begrüße Sie herzlich' starts formal meetings.",example:"A: Guten Morgen! Ich begrüße Sie herzlich im Team.\nB: Vielen Dank! Ich freue mich sehr.\nA: Wir begrüßen jeden neuen Kollegen persönlich.\nB: Das finde ich sehr nett.",exampleSrc:"A: Good morning! I warmly welcome you to the team.\nB: Thank you very much! I am very happy.\nA: We welcome every new colleague personally.\nB: I think that is very nice.",funFact:"The be- prefix makes begrüßen more thorough than casual grüßen. 'Ich begrüße Sie herzlich' is how department heads start meetings. It signals official, warm recognition."},
{type:"teach",trg:"einrichten",src:"to set up, to furnish",pos:"verb",gender:null,note:"Ein- (in) + richten (to arrange). To set up or furnish.\n'Seinen Arbeitsplatz einrichten' = setting up your workspace.",example:"A: Hast du deinen Arbeitsplatz schon eingerichtet?\nB: Noch nicht. Ich brauche noch einen Monitor.\nA: Der wird heute Nachmittag geliefert.\nB: Super, dann richte ich alles morgen ein.",exampleSrc:"A: Have you set up your workspace yet?\nB: Not yet. I still need a monitor.\nA: It will be delivered this afternoon.\nB: Great, then I will set everything up tomorrow.",funFact:"Einrichten means to set up or furnish. Germans take both very seriously: setting up a workspace AND furnishing an apartment. 'Sich häuslich einrichten' means to make yourself comfortable, to settle in."},
{type:"teach",trg:"ordnen",src:"to organize, to sort",pos:"verb",gender:null,note:"'Dateien ordnen' = organize files.\nRelated to 'Ordnung' (order). 'Ordnung muss sein!'",example:"A: Kannst du bitte die Unterlagen ordnen?\nB: Natürlich. Nach Datum oder nach Name?\nA: Nach Datum, bitte. Die neuesten zuerst.\nB: Ist erledigt. Alles ist jetzt geordnet.",exampleSrc:"A: Can you please organize the documents?\nB: Of course. By date or by name?\nA: By date, please. The newest first.\nB: Done. Everything is organized now.",funFact:"Related to 'Ordnung' (order). The saying 'Ordnung muss sein' (there must be order) is practically the German national motto. Filing, sorting, and labeling bring Germans genuine satisfaction."},
{type:"teach",trg:"gemeinsam",src:"together, jointly, shared",pos:"adj",gender:null,note:"Stronger than 'zusammen.' Implies unity of purpose.\n'Gemeinsam sind wir stark' (together we are strong).",example:"A: Machen wir das Projekt gemeinsam?\nB: Ja, gemeinsam geht es schneller.\nA: Gut, dann teilen wir die Aufgaben auf.\nB: Einverstanden. Gemeinsame Arbeit ist besser.",exampleSrc:"A: Shall we do the project together?\nB: Yes, together it goes faster.\nA: Good, then we divide up the tasks.\nB: Agreed. Joint work is better.",funFact:"Gemeinsam is stronger than zusammen because it implies unity of purpose, not just physical togetherness. 'Gemeinsam einsam' (together alone) is a famous German phrase for being lonely in a crowd."},
{type:"teach",trg:"aufmerksam",src:"attentive, observant",pos:"adj",gender:null,note:"Auf- (up) + merksam (noticing). Attentive.\n'Aufmerksam zuhören' = to listen attentively.",example:"A: Bitte sei aufmerksam in der Besprechung.\nB: Natürlich. Ich höre immer aufmerksam zu.\nA: Gut, denn es geht um wichtige Änderungen.\nB: Ich mache mir Notizen.",exampleSrc:"A: Please be attentive in the meeting.\nB: Of course. I always listen attentively.\nA: Good, because it is about important changes.\nB: I will take notes.",funFact:"'Aufmerksam zuhören' (to listen attentively) is what your new boss hopes you will do on day one. 'Eine Aufmerksamkeit' (a small attention) also means a small gift or gesture of kindness."},
{type:"teach",trg:"ordentlich",src:"tidy, proper, decent",pos:"adj",gender:null,note:"From 'Ordnung.' A tidy desk, a proper report.\n'Ordentlich arbeiten' = to work properly.",example:"A: Dein Schreibtisch ist sehr ordentlich!\nB: Danke, Ordnung muss sein.\nA: Bei mir sieht es nicht so ordentlich aus.\nB: Das kommt mit der Zeit.",exampleSrc:"A: Your desk is very tidy!\nB: Thanks, there must be order.\nA: Mine does not look so tidy.\nB: That comes with time.",funFact:"Ordentlich comes from Ordnung (order). An 'ordentlicher Professor' is a full professor (not just a tidy one). In everyday German, 'ordentlich' can also mean 'quite a lot': 'Das war ordentlich teuer!'"},
{type:"teach",trg:"fest",src:"firm, fixed, solid",pos:"adj",gender:null,note:"Opposite of 'locker' (loose). 'Ein fester Termin' = a fixed appointment.\n'Fest angestellt' = permanently employed.",example:"A: Hast du einen festen Vertrag?\nB: Ja, seit letztem Monat. Unbefristet.\nA: Glückwunsch! Ein fester Arbeitsplatz ist toll.\nB: Danke, ich bin sehr froh darüber.",exampleSrc:"A: Do you have a permanent contract?\nB: Yes, since last month. Unlimited.\nA: Congratulations! A permanent job is great.\nB: Thanks, I am very happy about it.",funFact:"Fest has many uses: ein Fest (a celebration), fest angestellt (permanently employed), festhalten (to hold on tight), feststehen (to be certain). The concept of firmness and reliability runs deep in German culture."},
{type:"teach",trg:"innen",src:"inside, indoors",pos:"adv",gender:null,note:"Opposite of 'außen' (outside).\n'Von innen' = from the inside. 'Nach innen' = inward.",example:"A: Ist es warm hier innen?\nB: Ja, die Heizung funktioniert gut.\nA: Von innen sieht das Büro sehr modern aus.\nB: Ja, es wurde letztes Jahr renoviert.",exampleSrc:"A: Is it warm in here?\nB: Yes, the heating works well.\nA: From inside, the office looks very modern.\nB: Yes, it was renovated last year.",funFact:"Innen and außen are the German inside/outside pair. 'Innenstadt' (inner city) is the city center. 'Innenminister' (interior minister) handles domestic affairs. 'Innere Ruhe' (inner peace) is what every German seeks."},
{type:"teach",trg:"miteinander",src:"with each other, together",pos:"adv",gender:null,note:"Mit (with) + einander (each other).\n'Miteinander reden' = to talk with each other.",example:"A: Wie arbeitet ihr miteinander?\nB: Sehr gut. Wir reden viel miteinander.\nA: Das ist wichtig für die Zusammenarbeit.\nB: Ja, ohne Kommunikation geht es nicht.",exampleSrc:"A: How do you work with each other?\nB: Very well. We talk a lot with each other.\nA: That is important for collaboration.\nB: Yes, without communication it does not work.",funFact:"German has many einander-compounds: miteinander (with each other), füreinander (for each other), nebeneinander (next to each other), nacheinander (one after another). Each one is its own word."},
{type:"story",speaker:"mia",mood:"helpful",art:"de-ber-office-floor",trg:"Hier ist unsere Etage. Der Flur führt zur Kantine, und am Ende vom Gang ist der Konferenzraum. Die Besprechung beginnt um zehn.",src:"Here is our floor. The hallway leads to the canteen, and at the end of the corridor is the conference room. The meeting starts at ten."},
{type:"mc",q:"Mia sagt, die Besprechung ist im Konferenzraum. Was ist ein Konferenzraum?",opts:["Ein Raum für Besprechungen und Konferenzen","Der Flur","Die Garderobe","Die Kantine"],ans:"Ein Raum für Besprechungen und Konferenzen",hint:"Konferenz means conference, Raum means room. Put them together."},
{type:"fb",s:"Die {1} beginnt um zehn Uhr im Konferenzraum.",a:["Besprechung"],opts:["Besprechung","Kantine","Garderobe","Etage"],hint:"Which word means a meeting or formal discussion?",sSrc:"The meeting starts at ten o'clock in the conference room."}
]},

// ─── Lesson 2: Das Büro ───
{id:"deu_r14l2",title:"Das Büro",icon:"🖥️",xp:15,board:true,steps:[
{type:"intro",title:"Das Büro",desc:"Verumius sets up his workstation. Monitor, keyboard, copier. Learn the German names for everything in an office.",goals:["Learn 20 words for office equipment","Understand compound word patterns for office items","Master technical vocabulary for the German workplace"]},
{type:"teach",trg:"der Bildschirm",src:"the screen, the monitor",pos:"noun",gender:"m",note:"Bild (picture) + Schirm (screen/umbrella). Literally 'picture-screen.'\nUsed for any display: computer, TV, phone.",example:"A: Mein Bildschirm ist zu klein.\nB: Wir können einen größeren bestellen.\nA: Das wäre toll. Ich brauche zwei Bildschirme.\nB: Kein Problem, frag den IT-Leiter.",exampleSrc:"A: My screen is too small.\nB: We can order a bigger one.\nA: That would be great. I need two screens.\nB: No problem, ask the IT manager.",funFact:"Bild (picture) + Schirm (screen/umbrella) creates 'picture-screen.' Germans use this for any display. Das Bild is neuter but der Schirm wins the gender battle, making it masculine."},
{type:"teach",trg:"der Monitor",src:"the monitor",pos:"noun",gender:"m",note:"From Latin 'monere' (to warn/watch).\nInterchangeable with Bildschirm in tech contexts.",example:"A: Ist das ein neuer Monitor?\nB: Ja, er wurde letzte Woche geliefert.\nA: Er ist sehr groß.\nB: Siebenundzwanzig Zoll. Perfekt für die Arbeit.",exampleSrc:"A: Is that a new monitor?\nB: Yes, it was delivered last week.\nA: It is very big.\nB: Twenty-seven inches. Perfect for work.",funFact:"Monitor sounds more international, Bildschirm more traditionally German. Both are used daily. In everyday conversation, many Germans now also say 'Screen' with German pronunciation."},
{type:"teach",trg:"der Rechner",src:"the computer, the calculator",pos:"noun",gender:"m",note:"From 'rechnen' (to calculate). A computer is literally a 'calculator.'\nTaschenrechner = pocket calculator.",example:"A: Mein Rechner ist sehr langsam heute.\nB: Hast du ihn schon neu gestartet?\nA: Nein, das probiere ich mal.\nB: Das löst meistens das Problem.",exampleSrc:"A: My computer is very slow today.\nB: Have you restarted it yet?\nA: No, I will try that.\nB: That usually solves the problem.",funFact:"Before English 'Computer' took over, Rechner was the standard word. A Taschenrechner (pocket calculator) keeps the old meaning alive. Germany even had 'Großrechner' (mainframes), literally 'big calculators.'"},
{type:"teach",trg:"die Tastatur",src:"the keyboard",pos:"noun",gender:"f",note:"From 'Taste' (key/button). German keyboards have QWERTZ layout.\nY and Z are swapped. Also has keys for ä, ö, ü, ß.",example:"A: Wo ist das ß auf der Tastatur?\nB: Rechts neben der Null.\nA: Und die Umlaute?\nB: Rechts neben dem P und dem L.",exampleSrc:"A: Where is the ß on the keyboard?\nB: To the right of the zero.\nA: And the umlauts?\nB: To the right of the P and the L.",funFact:"German keyboards have QWERTZ layout, not QWERTY. The Y and Z are swapped. Also, there are dedicated keys for ä, ö, ü, and ß. Switching between keyboard layouts is a daily struggle for multilingual workers."},
{type:"teach",trg:"die Taste",src:"the key, the button",pos:"noun",gender:"f",note:"From French 'taster' (to touch/feel).\nEvery button on keyboard, remote, or elevator is a Taste.",example:"A: Welche Taste muss ich drücken?\nB: Die große Taste unten. Das ist die Leertaste.\nA: Und diese kleine Taste hier?\nB: Das ist die Escape-Taste.",exampleSrc:"A: Which key do I have to press?\nB: The big key at the bottom. That is the space bar.\nA: And this little key here?\nB: That is the escape key.",funFact:"Leertaste (space bar) literally means 'empty key.' Löschtaste (delete key) means 'erase key.' German names for keyboard keys always describe what the key does."},
{type:"teach",trg:"die Festplatte",src:"the hard drive",pos:"noun",gender:"f",note:"Fest (solid/fixed) + Platte (plate/disk). Literally 'fixed disk.'\n'Die Festplatte ist voll' is every office worker's nightmare.",example:"A: Meine Festplatte ist fast voll.\nB: Lösch doch alte Dateien.\nA: Oder ich brauche eine neue Festplatte.\nB: Frag die IT-Abteilung.",exampleSrc:"A: My hard drive is almost full.\nB: Delete some old files then.\nA: Or I need a new hard drive.\nB: Ask the IT department.",funFact:"'Die Festplatte ist voll' is the IT nightmare sentence every office worker dreads. Festplatte is being replaced by SSD (Solid State Drive), but Germans still call any internal storage 'Festplatte' out of habit."},
{type:"teach",trg:"das Kabel",src:"the cable, the cord",pos:"noun",gender:"n",note:"From Latin 'capulum' (rope). Any cable or cord.\n'Kabelsalat' (cable salad) = tangled cables under your desk.",example:"A: Wo ist das Kabel für den Monitor?\nB: Unter dem Schreibtisch. Im Kabelsalat.\nA: Da sind so viele Kabel!\nB: Ja, das ist normaler Büro-Kabelsalat.",exampleSrc:"A: Where is the cable for the monitor?\nB: Under the desk. In the cable mess.\nA: There are so many cables!\nB: Yes, that is normal office cable spaghetti.",funFact:"'Kabelsalat' (cable salad) is the beautiful German word for tangled cables under your desk. Every office has Kabelsalat. Some companies hire professionals to tame the Kabelsalat."},
{type:"teach",trg:"die Steckdose",src:"the power outlet, the socket",pos:"noun",gender:"f",note:"Stecken (to plug in) + Dose (socket/tin). A power outlet.\nGerman outlets are round (Schuko type).",example:"A: Gibt es hier eine Steckdose?\nB: Ja, unter dem Tisch.\nA: Ich brauche eine für meinen Laptop.\nB: Da drüben ist auch eine freie Steckdose.",exampleSrc:"A: Is there a power outlet here?\nB: Yes, under the table.\nA: I need one for my laptop.\nB: Over there is also a free outlet.",funFact:"German outlets are round (Schuko type). Visitors from the UK or US always need an adapter. The Schuko system was invented in 1926 by Albert Büttner and is now standard in most of Europe."},
{type:"teach",trg:"der Stecker",src:"the plug",pos:"noun",gender:"m",note:"From 'stecken' (to plug). Der Stecker goes into die Steckdose.\nSimple, logical compound naming.",example:"A: Der Stecker passt nicht in die Steckdose.\nB: Das ist ein britischer Stecker. Du brauchst einen Adapter.\nA: Wo bekomme ich einen?\nB: Frag den Hausmeister.",exampleSrc:"A: The plug does not fit in the outlet.\nB: That is a British plug. You need an adapter.\nA: Where do I get one?\nB: Ask the caretaker.",funFact:"Der Stecker goes into die Steckdose. Stecker, Steckdose, stecken: all from the same root. German makes hardware vocabulary self-explanatory through compound words."},
{type:"teach",trg:"der Kopierer",src:"the copier, the copy machine",pos:"noun",gender:"m",note:"From 'kopieren' (to copy) + -er (machine suffix).\n'Der Kopierer ist kaputt' is the most common office complaint.",example:"A: Wo steht der Kopierer?\nB: Im Flur, neben der Kaffeküche.\nA: Funktioniert er?\nB: Meistens. Aber er ist oft kaputt.",exampleSrc:"A: Where is the copier?\nB: In the hallway, next to the coffee kitchen.\nA: Does it work?\nB: Usually. But it is often broken.",funFact:"'Der Kopierer ist kaputt' (the copier is broken) might be the most common office complaint in Germany. Every new employee has to learn the copier's quirks. Each office copier has its own personality."},
{type:"teach",trg:"die Kopie",src:"the copy",pos:"noun",gender:"f",note:"From Latin 'copia' (abundance). 'Eine Kopie machen' = to make a copy.\nGerman bureaucracy runs on Kopien of everything.",example:"A: Ich brauche drei Kopien von diesem Dokument.\nB: Kein Problem. Farbe oder schwarz-weiß?\nA: Schwarz-weiß reicht.\nB: Hier sind die Kopien.",exampleSrc:"A: I need three copies of this document.\nB: No problem. Color or black-and-white?\nA: Black-and-white is enough.\nB: Here are the copies.",funFact:"The bureaucratic soul of Germany runs on Kopien of everything. Insurance claims need Kopien, tax returns need Kopien, apartment applications need Kopien. A good German always has Kopien ready."},
{type:"teach",trg:"der Ordner",src:"the binder, the folder",pos:"noun",gender:"m",note:"From 'ordnen' (to organize). Both physical ring binders AND computer folders.\nGermans keep Ordner for everything.",example:"A: In welchem Ordner ist der Vertrag?\nB: Im blauen Ordner auf dem Regal.\nA: Und die digitale Version?\nB: Im Ordner 'Verträge' auf dem Server.",exampleSrc:"A: In which folder is the contract?\nB: In the blue binder on the shelf.\nA: And the digital version?\nB: In the 'Contracts' folder on the server.",funFact:"Germans keep physical Ordner for everything: taxes, insurance, contracts, warranties. The Ordner culture is legendary. IKEA's bestselling storage item in Germany is the Billy bookcase to hold Ordner."},
{type:"teach",trg:"das Regal",src:"the shelf, the bookcase",pos:"noun",gender:"n",note:"From Latin 'regalis' (royal).\nBücherregal (bookshelf), Aktenregal (file shelf).",example:"A: Wo stelle ich die Ordner hin?\nB: Ins Regal, dritte Reihe von oben.\nA: Das Regal ist schon ziemlich voll.\nB: Dann bestellen wir ein neues.",exampleSrc:"A: Where do I put the binders?\nB: On the shelf, third row from the top.\nA: The shelf is already quite full.\nB: Then we will order a new one.",funFact:"IKEA's Billy Regal is Germany's favorite bookcase. Every German household owns at least one. Bücherregal (bookshelf) and Aktenregal (file shelf) are in every German office."},
{type:"teach",trg:"die Mappe",src:"the folder, the portfolio",pos:"noun",gender:"f",note:"Thinner than an Ordner. For meetings and presentations.\nAktenmappe = document folder. Schulmappe = school bag.",example:"A: Hast du die Unterlagen in der Mappe?\nB: Ja, alles ist drin. Berichte, Listen, Kopien.\nA: Perfekt, wir brauchen die Mappe für die Besprechung.\nB: Ich bringe sie gleich mit.",exampleSrc:"A: Do you have the documents in the folder?\nB: Yes, everything is in there. Reports, lists, copies.\nA: Perfect, we need the folder for the meeting.\nB: I will bring it right away.",funFact:"A Mappe is thinner than an Ordner. Students carry a Schulmappe, professionals carry a Mappe to meetings. An Aktenmappe holds important documents. In art, a Mappe is a portfolio."},
{type:"teach",trg:"der Kuli",src:"the ballpoint pen",pos:"noun",gender:"m",note:"Short for 'Kugelschreiber' (ball-point writer).\nOne of Germany's greatest word shortcuts: 16 letters to 4.",example:"A: Hast du einen Kuli?\nB: Ja, hier. Blau oder schwarz?\nA: Schwarz, bitte.\nB: Bitte. Aber gib ihn mir zurück!",exampleSrc:"A: Do you have a pen?\nB: Yes, here. Blue or black?\nA: Black, please.\nB: Here you go. But give it back to me!",funFact:"Kuli is short for Kugelschreiber (ball-point writer). One of Germany's greatest word shortcuts: 16 letters to just 4. The full compound has Kugel (ball) + Schreiber (writer). Invented in 1938 by Hungarian inventor László Bíró."},
{type:"teach",trg:"die Tabelle",src:"the table, the spreadsheet",pos:"noun",gender:"f",note:"From Latin 'tabella' (small board).\nExcel-Tabellen rule German office life.",example:"A: Kannst du eine Tabelle mit den Zahlen machen?\nB: Klar, in Excel oder auf Papier?\nA: In Excel, bitte. Mit allen Abteilungen.\nB: Wird gemacht. Bis morgen?",exampleSrc:"A: Can you make a table with the numbers?\nB: Sure, in Excel or on paper?\nA: In Excel, please. With all departments.\nB: Will be done. By tomorrow?",funFact:"Excel-Tabellen rule German office life. 'Ich mache eine Tabelle' means someone is about to organize everything into neat rows and columns. Germany's love of data and order meets perfectly in the Tabelle."},
{type:"teach",trg:"ausdrucken",src:"to print out",pos:"verb",gender:null,note:"Aus- (out) + drucken (to print/press). Separable verb.\n'Können Sie das ausdrucken?' is heard constantly in German offices.",example:"A: Können Sie den Bericht ausdrucken?\nB: Natürlich. Wie viele Kopien?\nA: Drei, bitte. Und in Farbe.\nB: Wird sofort ausgedruckt.",exampleSrc:"A: Can you print out the report?\nB: Of course. How many copies?\nA: Three, please. And in color.\nB: Will be printed out right away.",funFact:"Despite digitalization, Germans still print a lot. 'Können Sie das ausdrucken?' is heard dozens of times a day. Germany has been slower than other countries to adopt a fully digital office. Paper feels more official."},
{type:"teach",trg:"kopieren",src:"to copy",pos:"verb",gender:null,note:"Regular -ieren verb from Latin/French.\n-ieren verbs always conjugate regularly, and the past participle has no ge-.",example:"A: Bitte kopieren Sie diese Unterlagen.\nB: Wie viele Kopien brauchen Sie?\nA: Fünf Stück. Doppelseitig.\nB: Wird sofort kopiert.",exampleSrc:"A: Please copy these documents.\nB: How many copies do you need?\nA: Five. Double-sided.\nB: Will be copied right away.",funFact:"The -ieren verbs are easy: they always conjugate regularly, and the past participle has no ge-. Kopiert, not gekopiert. This rule works for telefonieren, installieren, organisieren, and hundreds more."},
{type:"teach",trg:"klicken",src:"to click",pos:"verb",gender:null,note:"Onomatopoeia borrowed from English.\n'Klicken Sie auf den Link' (click on the link).",example:"A: Wo muss ich klicken?\nB: Auf den grünen Knopf oben rechts.\nA: Diesen hier?\nB: Genau. Einmal klicken reicht.",exampleSrc:"A: Where do I have to click?\nB: On the green button in the upper right.\nA: This one here?\nB: Exactly. One click is enough.",funFact:"German tech vocabulary freely borrows English words and adds German grammar. Klicken, downloaden, liken, chatten. The words are English, but they conjugate German: ich klicke, du klickst, er klickt."},
{type:"teach",trg:"tippen",src:"to type, to tap",pos:"verb",gender:null,note:"From English 'to tip/tap.' 'Tippen Sie Ihr Passwort ein.'\nAlso means to guess/bet: 'Ich tippe auf Bayern.'",example:"A: Kannst du schnell tippen?\nB: Ja, ungefähr siebzig Wörter pro Minute.\nA: Das ist beeindruckend!\nB: Übung macht den Meister.",exampleSrc:"A: Can you type fast?\nB: Yes, about seventy words per minute.\nA: That is impressive!\nB: Practice makes perfect.",funFact:"Tippen means to type AND to bet/guess. 'Ich tippe auf Bayern' means 'I bet on Bayern Munich.' Tipps (tips/advice) come from the same root. In the office, 'tippen' is always about typing."},
{type:"mc",q:"Du musst ein Dokument drucken. Welches Gerät brauchst du?",opts:["Den Kopierer","Die Tastatur","Den Ordner","Das Regal"],ans:"Den Kopierer",hint:"Which machine produces physical paper copies of documents?"},
{type:"fb",s:"Bitte {1} Sie die Datei aus.",a:["drucken"],opts:["drucken","klicken","tippen","kopieren"],hint:"Which verb means to print something on paper?",sSrc:"Please print out the file."},
{type:"match",pairs:[{trg:"der Bildschirm",src:"screen/monitor"},{trg:"die Tastatur",src:"keyboard"},{trg:"die Festplatte",src:"hard drive"},{trg:"die Steckdose",src:"power outlet"},{trg:"der Kuli",src:"ballpoint pen"}]}
]},

// ─── Lesson 3: Die Kaffeküche ───
{id:"deu_r14l3",title:"Die Kaffeküche",icon:"☕",xp:15,board:true,steps:[
{type:"intro",title:"Die Kaffeküche",desc:"Mia shows Verumius the office kitchen. Special rules apply here: notes on the wall, passive-aggressive signs, and the coffee is freshly made every morning.",goals:["Learn vocabulary for colleagues and job titles","Discover the unwritten rules of the Kaffeküche","Understand the passive construction: werden + Partizip II"]},
{type:"story",speaker:"mia",mood:"direct",art:"de-ber-kaffeekueche",trg:"So, das hier ist die Kaffeküche. Hier gelten besondere Regeln. Siehst du die Zettel an der Wand?",src:"So, this is the coffee kitchen. Special rules apply here. Do you see the notes on the wall?"},
{type:"story",speaker:"narrator",mood:"amused",art:"de-ber-kaffeekueche-notes",trg:"An der Wand hängen bunte Zettel: 'Bitte Spülmaschine ausräumen!' 'Milch mit NAMEN beschriften!' 'Der Kaffee wird jeden Morgen frisch gemacht!'",src:"On the wall hang colorful notes: 'Please empty the dishwasher!' 'Label milk with your NAME!' 'The coffee is made fresh every morning!'"},
{type:"teach",trg:"der Leiter",src:"the leader, the manager (male)",pos:"noun",gender:"m",note:"From 'leiten' (to lead). Also means 'ladder' when feminine (die Leiter).\nSame word, different gender, different meaning.",example:"A: Wer ist der Leiter dieser Abteilung?\nB: Herr Schmidt. Er leitet das Team seit fünf Jahren.\nA: Ist er nett?\nB: Ja, sehr. Er begrüßt jeden persönlich.",exampleSrc:"A: Who is the manager of this department?\nB: Herr Schmidt. He has managed the team for five years.\nA: Is he nice?\nB: Yes, very. He greets everyone personally.",funFact:"Der Leiter (masculine) = leader/manager. Die Leiter (feminine) = ladder. Same word, different gender, completely different meaning. Classic German trap that even native speakers joke about."},
{type:"teach",trg:"die Leiterin",src:"the leader, the manager (female)",pos:"noun",gender:"f",note:"Leiter + -in. German requires gendered job titles.\nCompanies often write 'Teamleiter/in' to include both.",example:"A: Frau Müller ist die Leiterin unserer Abteilung.\nB: Seit wann?\nA: Seit drei Jahren. Sie macht einen tollen Job.\nB: Das habe ich gehört.",exampleSrc:"A: Frau Müller is the manager of our department.\nB: Since when?\nA: For three years. She does a great job.\nB: I have heard that.",funFact:"Germany requires gendered job titles: der Leiter/die Leiterin. Companies increasingly write 'Teamleiter:in' with a gender colon to include everyone. The debate over gender-neutral language is ongoing in Germany."},
{type:"teach",trg:"die Leitung",src:"the leadership, the management, the line",pos:"noun",gender:"f",note:"'Unter der Leitung von...' = under the leadership of.\nAlso: Telefonleitung (phone line), Wasserleitung (water pipe).",example:"A: Wer hat die Leitung des Projekts?\nB: Frau Müller. Sie leitet alles.\nA: Unter ihrer Leitung läuft es gut.\nB: Ja, sie ist eine gute Leiterin.",exampleSrc:"A: Who has the leadership of the project?\nB: Frau Müller. She manages everything.\nA: Under her leadership things run well.\nB: Yes, she is a good manager.",funFact:"Leitung means leadership, management, or line/pipe. One word, many pipes: Telefonleitung (phone line), Wasserleitung (water pipe), Gasleitung (gas line). Context is always king in German."},
{type:"teach",trg:"die Mitarbeiterin",src:"the colleague, the employee (female)",pos:"noun",gender:"f",note:"Mit- (with) + Arbeiterin (worker). Female colleague.\nGermans increasingly use 'Mitarbeitende' (gender-neutral).",example:"A: Wie viele Mitarbeiterinnen gibt es in deinem Team?\nB: Sieben Mitarbeiterinnen und fünf Mitarbeiter.\nA: Und ihr arbeitet alle auf dieser Etage?\nB: Ja, wir sitzen alle zusammen.",exampleSrc:"A: How many female employees are in your team?\nB: Seven female and five male employees.\nA: And you all work on this floor?\nB: Yes, we all sit together.",funFact:"Germans increasingly use 'Mitarbeitende' (gender-neutral) in official contexts. Your Mitarbeiter and Mitarbeiterinnen are your coworkers. In job ads, you will often see 'Mitarbeiter (m/w/d)' meaning male/female/diverse."},
{type:"teach",trg:"der Hausmeister",src:"the caretaker, the janitor",pos:"noun",gender:"m",note:"Haus (house) + Meister (master). The building caretaker.\nFixes everything, knows everything, has all the keys.",example:"A: Die Heizung funktioniert nicht.\nB: Ruf den Hausmeister an. Er repariert alles.\nA: Wo finde ich ihn?\nB: Im Keller. Er hat sein Büro dort.",exampleSrc:"A: The heating does not work.\nB: Call the caretaker. He repairs everything.\nA: Where do I find him?\nB: In the basement. He has his office there.",funFact:"In German offices and apartment buildings, the Hausmeister is the person who fixes everything, knows everything, and has all the keys. A good Hausmeister is treated like gold."},
{type:"teach",trg:"die Sekretärin",src:"the secretary, the administrative assistant (female)",pos:"noun",gender:"f",note:"From Latin 'secretarius' (confidant).\nModern offices use 'Assistenz' or 'Office-Management.'",example:"A: Wer organisiert die Termine hier?\nB: Die Sekretärin, Frau Weber.\nA: Sitzt sie am Empfang?\nB: Ja, gleich am Eingang. Sie hilft dir bei allem.",exampleSrc:"A: Who organizes the appointments here?\nB: The secretary, Frau Weber.\nA: Does she sit at the reception?\nB: Yes, right at the entrance. She helps you with everything.",funFact:"Modern German offices increasingly use 'Assistenz' or 'Office-Management' instead of Sekretärin. But the word remains widely understood. The role has evolved from typing pools to managing entire departments."},
{type:"teach",trg:"der Dienst",src:"the service, the duty",pos:"noun",gender:"m",note:"'Im Dienst' = on duty. 'Kundendienst' = customer service.\n'Dienst ist Dienst und Schnaps ist Schnaps' = work and pleasure do not mix.",example:"A: Bist du heute im Dienst?\nB: Ja, ich habe Dienst bis achtzehn Uhr.\nA: Und morgen?\nB: Morgen habe ich frei. Kein Dienst.",exampleSrc:"A: Are you on duty today?\nB: Yes, I am on duty until six PM.\nA: And tomorrow?\nB: Tomorrow I am off. No duty.",funFact:"'Dienst ist Dienst und Schnaps ist Schnaps' means work and pleasure do not mix. It is a very German saying. Dienstleistung (service provision) is the backbone of the German service economy."},
{type:"teach",trg:"die Überstunde",src:"the overtime hour",pos:"noun",gender:"f",note:"Über- (over) + Stunde (hour). Germans track Überstunden meticulously.\nWorking too many is seen negatively, not as dedication.",example:"A: Wie viele Überstunden hast du diese Woche?\nB: Nur zwei. Mehr will ich nicht.\nA: In meiner alten Firma waren es oft zehn.\nB: Das ist zu viel. Hier werden Überstunden genau gezählt.",exampleSrc:"A: How many overtime hours do you have this week?\nB: Only two. I do not want more.\nA: At my old company it was often ten.\nB: That is too much. Here overtime is counted precisely.",funFact:"Germans track Überstunden meticulously. Many contracts cap them. Working too many Überstunden is seen as poor time management, not dedication. The Betriebsrat (works council) watches overtime closely."},
{type:"teach",trg:"der Terminkalender",src:"the schedule, the planner",pos:"noun",gender:"m",note:"Termin (appointment) + Kalender (calendar). Your daily planner.\nIf it is not in the Kalender, it does not exist.",example:"A: Hast du morgen Zeit für eine Besprechung?\nB: Moment, ich schaue in meinen Terminkalender.\nA: Geht es um zehn Uhr?\nB: Ja, zehn Uhr ist frei. Ich trage es ein.",exampleSrc:"A: Do you have time for a meeting tomorrow?\nB: One moment, I will check my schedule.\nA: Is ten o'clock okay?\nB: Yes, ten o'clock is free. I will write it in.",funFact:"Germans live by their Terminkalender. If it is not in the Kalender, it does not exist. Spontaneous meetings are rare. Everything gets a Termin. 'Ich habe keinen Termin frei' is the polite German no."},
{type:"teach",trg:"die Wand",src:"the wall (interior)",pos:"noun",gender:"f",note:"Interior wall. Not to be confused with Mauer (exterior/freestanding wall).\nDie Berliner Mauer was THE wall. Die Wand is for hanging pictures.",example:"A: Siehst du die Zettel an der Wand?\nB: Ja, da hängen viele Regeln.\nA: Jeder klebt seine eigenen Zettel an die Wand.\nB: Die Kaffeküche hat die meisten Zettel.",exampleSrc:"A: Do you see the notes on the wall?\nB: Yes, there are many rules hanging there.\nA: Everyone sticks their own notes on the wall.\nB: The coffee kitchen has the most notes.",funFact:"Die Wand (interior wall) versus die Mauer (exterior/freestanding wall). Die Berliner Mauer was THE Wall. In offices, die Wand is where passive-aggressive notes, calendars, and motivational posters live."},
{type:"teach",trg:"der Teppich",src:"the carpet, the rug",pos:"noun",gender:"m",note:"'Teppichboden' = wall-to-wall carpet. Very common in German offices.\n'Unter den Teppich kehren' = to sweep under the rug.",example:"A: Warum liegt hier überall Teppich?\nB: Teppichboden ist in deutschen Büros normal.\nA: In meinem Land haben Büros Fliesen.\nB: Hier nicht. Der Teppich dämpft den Lärm.",exampleSrc:"A: Why is there carpet everywhere here?\nB: Wall-to-wall carpet is normal in German offices.\nA: In my country offices have tiles.\nB: Not here. The carpet dampens the noise.",funFact:"Teppichboden (wall-to-wall carpet) is standard in German offices. 'Unter den Teppich kehren' (to sweep under the rug) means to hide a problem. 'Jemanden auf dem Teppich halten' means to keep someone grounded."},
{type:"teach",trg:"der Spiegel",src:"the mirror",pos:"noun",gender:"m",note:"Also the name of Germany's most famous news magazine.\n'Spiegelbild' (mirror image) = reflection.",example:"A: Gibt es einen Spiegel im Büro?\nB: Ja, in der Garderobe hängt einer.\nA: Gut, ich will schauen, ob mein Anzug gut sitzt.\nB: Du siehst gut aus, keine Sorge.",exampleSrc:"A: Is there a mirror in the office?\nB: Yes, there is one in the cloakroom.\nA: Good, I want to check if my suit fits well.\nB: You look good, no worries.",funFact:"Der Spiegel is also the name of Germany's most famous news magazine, founded in 1947. 'Spiegel' literally means mirror, reflecting the magazine's mission to hold a mirror to society."},
{type:"teach",trg:"leiten",src:"to lead, to manage",pos:"verb",gender:null,note:"'Eine Abteilung leiten' = to manage a department.\nAlso: to conduct (electricity, water).",example:"A: Wer leitet die Besprechung heute?\nB: Frau Müller. Sie leitet immer die Montagsbesprechung.\nA: Leitet sie auch das Projekt?\nB: Ja, das ganze Projekt wird von ihr geleitet.",exampleSrc:"A: Who leads the meeting today?\nB: Frau Müller. She always leads the Monday meeting.\nA: Does she also lead the project?\nB: Yes, the entire project is led by her.",funFact:"Leiten means to lead, manage, or conduct. A Leiter leitet. Electricity is geleitet through Leitungen (lines). Water is geleitet through Wasserleitungen. Everything in German gets leitet somewhere."},
{type:"teach",trg:"reinigen",src:"to clean",pos:"verb",gender:null,note:"More formal than 'putzen.' 'Chemisch reinigen' = dry cleaning.\nReinigungsplan (cleaning schedule) is on every office kitchen wall.",example:"A: Wer reinigt die Kaffeküche?\nB: Wir alle. Es gibt einen Reinigungsplan.\nA: An welchem Tag bin ich dran?\nB: Am Mittwoch. Dann wird die Küche von dir gereinigt.",exampleSrc:"A: Who cleans the coffee kitchen?\nB: All of us. There is a cleaning schedule.\nA: Which day is my turn?\nB: Wednesday. Then the kitchen is cleaned by you.",funFact:"Office kitchens always have a Reinigungsplan (cleaning schedule) on the wall. Germans take collective cleanliness seriously. 'Chemisch reinigen' means dry cleaning. A Reinigung is a dry cleaner's shop."},
{type:"teach",trg:"erledigen",src:"to complete, to take care of",pos:"verb",gender:null,note:"'Das ist erledigt' = that is done. One of the most satisfying German sentences.\nMeans you finished a task completely.",example:"A: Hast du die Aufgabe erledigt?\nB: Ja, alles erledigt. Fertig.\nA: Perfekt. Dann können wir weitermachen.\nB: Was muss als Nächstes erledigt werden?",exampleSrc:"A: Have you completed the task?\nB: Yes, all done. Finished.\nA: Perfect. Then we can continue.\nB: What needs to be completed next?",funFact:"'Das ist erledigt!' (That is done!) is one of the most satisfying German sentences. In office culture, erledigen means you finished a task completely. No loose ends, no follow-up needed."},
{type:"teach",trg:"besprechen",src:"to discuss",pos:"verb",gender:null,note:"Be- + sprechen (to speak). More structured than 'reden' (to talk).\n'Wir müssen das besprechen' = we need to discuss this.",example:"A: Können wir das Projekt heute besprechen?\nB: Ja, um vierzehn Uhr. In der Besprechung.\nA: Gut. Ich bereite die Unterlagen vor.\nB: Perfekt. Das müssen wir gründlich besprechen.",exampleSrc:"A: Can we discuss the project today?\nB: Yes, at two o'clock. In the meeting.\nA: Good. I will prepare the documents.\nB: Perfect. We need to discuss this thoroughly.",funFact:"Besprechen is more structured than reden (to talk). 'Wir müssen das besprechen' is the calm German way of saying 'we need to talk.' A Besprechung is a besprechen-event."},
{type:"teach",trg:"anstrengend",src:"exhausting, strenuous, tiring",pos:"adj",gender:null,note:"From 'anstrengen' (to exert). 'Ein anstrengender Tag.'\n'Das war anstrengend!' after a long meeting.",example:"A: Wie war dein erster Tag?\nB: Anstrengend! So viele neue Namen und Regeln.\nA: Der erste Tag ist immer anstrengend.\nB: Morgen wird es bestimmt besser.",exampleSrc:"A: How was your first day?\nB: Exhausting! So many new names and rules.\nA: The first day is always exhausting.\nB: Tomorrow it will certainly be better.",funFact:"'Anstrengend' is the go-to German word for anything tiring. A long meeting? Anstrengend. A difficult colleague? Anstrengend. Monday morning? Anstrengend. It covers physical and mental exhaustion equally."},
{type:"teach",trg:"einheitlich",src:"uniform, consistent, standardized",pos:"adj",gender:null,note:"From 'Einheit' (unity). 'Einheitliche Regeln' = uniform rules.\nGermans love einheitliche Systeme.",example:"A: Gibt es einheitliche Regeln für alle Abteilungen?\nB: Ja, die Regeln gelten einheitlich im ganzen Betrieb.\nA: Das ist gut. So weiß jeder, was gilt.\nB: Genau. Einheitlichkeit ist hier wichtig.",exampleSrc:"A: Are there uniform rules for all departments?\nB: Yes, the rules apply uniformly throughout the whole company.\nA: That is good. So everyone knows what applies.\nB: Exactly. Uniformity is important here.",funFact:"Germans love einheitliche systems. The DIN (Deutsches Institut für Normung) creates standardized norms for everything from paper sizes (DIN A4) to beer glass shapes. Einheitlichkeit runs deep in German culture."},
{type:"teach",trg:"technisch",src:"technical",pos:"adj",gender:null,note:"From 'Technik' (technology/technique).\n'Technische Probleme' are every IT department's daily bread.",example:"A: Wir haben ein technisches Problem mit dem Rechner.\nB: Welche Art von technischem Problem?\nA: Der Bildschirm bleibt schwarz.\nB: Das klingt nach einem Kabel-Problem.",exampleSrc:"A: We have a technical problem with the computer.\nB: What kind of technical problem?\nA: The screen stays black.\nB: That sounds like a cable problem.",funFact:"'Technisch gesehen' (technically speaking) is a common German phrase used to be precise. Germans value technical precision in language as much as in engineering."},
{type:"teach",trg:"digital",src:"digital",pos:"adj",gender:null,note:"Same as English. 'Digitale Transformation' is the big topic.\n'Digitaler Wandel' (digital change) is reshaping German offices.",example:"A: Ist euer Büro schon komplett digital?\nB: Fast. Wir haben noch viele Ordner aus Papier.\nA: Die digitale Transformation braucht Zeit.\nB: Ja, aber wir arbeiten daran.",exampleSrc:"A: Is your office already completely digital?\nB: Almost. We still have many paper binders.\nA: Digital transformation takes time.\nB: Yes, but we are working on it.",funFact:"Germany's 'Digitalisierung' (digitalization) has been slower than in many countries. The famous German Fax machine still exists in many offices. 'Digital first' is the goal, but paper still rules in many Betriebe."},
{type:"teach",trg:"aktualisieren",src:"to update",pos:"verb",gender:null,note:"From 'aktuell' (current) + -isieren. Not separable.\n'Die Software aktualisieren' = to update the software.",example:"A: Hast du den Terminkalender aktualisiert?\nB: Ja, ich habe ihn gerade aktualisiert.\nA: Gut. Er muss immer aktuell sein.\nB: Ich aktualisiere ihn jeden Montag.",exampleSrc:"A: Did you update the schedule?\nB: Yes, I just updated it.\nA: Good. It always needs to be up to date.\nB: I update it every Monday.",funFact:"The -isieren ending makes Latin/Greek roots into regular German verbs. Aktuell (current) becomes aktualisieren (to make current). Same pattern: digital/digitalisieren, optimal/optimieren."},
{type:"verb_table",title:"werden: Vollständige Konjugation (Präsens)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"werde",src:"I become"},{pronoun:"du",form:"wirst",src:"you become"},{pronoun:"er/sie/es",form:"wird",src:"he/she/it becomes"}]},{label:"Plural",rows:[{pronoun:"wir",form:"werden",src:"we become"},{pronoun:"ihr",form:"werdet",src:"you all become"},{pronoun:"sie/Sie",form:"werden",src:"they/you (formal) become"}]}],note:"Werden is irregular: e to i in du/er. Note the vowel changes: werde, wirst, wird.",deepDive:{title:"Werden: Three Roles",text:"Werden has three different functions:\n\n1. Full verb 'werden' (to become):\nEr wird Arzt. (He is becoming a doctor.)\n\n2. Passive auxiliary:\nDer Kaffee wird gemacht. (Coffee is being made.)\n\n3. Future auxiliary:\nIch werde kommen. (I will come.)\n\nSame form, three meanings. Context decides."}},
{type:"verb_table",title:"werden: Präteritum (wurde)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"wurde",src:"I became"},{pronoun:"du",form:"wurdest",src:"you became"},{pronoun:"er/sie/es",form:"wurde",src:"he/she/it became"}]},{label:"Plural",rows:[{pronoun:"wir",form:"wurden",src:"we became"},{pronoun:"ihr",form:"wurdet",src:"you all became"},{pronoun:"sie/Sie",form:"wurden",src:"they/you (formal) became"}]}],note:"Wurde is the Präteritum of werden. Used for passive Präteritum: 'Es wurde gebaut.' Very common in news and written German.",deepDive:{title:"Spoken vs. Written Passive",text:"In spoken German, Perfekt passive is sometimes preferred:\n'Es ist gemacht worden.'\n\nBut Präteritum passive dominates in news and texts:\n'Es wurde bekannt gegeben, dass...'"}},
{type:"tip",title:"Passiv Präsens: werden + Partizip II",text:"In English: 'Coffee is made.' In German: 'Kaffee wird gemacht.'\n\nStructure: Subject + werden (konjugiert) + Partizip II (am Ende)\n\nWerden is the helper verb for ALL passive sentences:\nich werde, du wirst, er/sie/es wird, wir werden, sie/Sie werden\n\nThe person doing the action often disappears:\n'Der Kaffee wird gemacht.' By whom? Nobody knows.\n\nThe passive loves hiding responsibility.\nOffice signs love the passive because rules apply to everyone.",deepDive:{title:"Warum Passiv im Büro?",text:"German offices use the passive voice constantly:\n'Hier wird nicht geraucht.' (Smoking is not done here.)\n'Die Tür wird um 18 Uhr geschlossen.' (The door is closed at 6.)\n\nThe passive removes the 'who' and focuses on the 'what.'\nIt makes rules feel universal, not personal.\n'Du sollst nicht rauchen' (you should not smoke) feels like an order.\n'Hier wird nicht geraucht' feels like a law of nature.\n\nThis is why every Kaffeküche note uses passive voice."}},
{type:"verb_table",title:"Passiv Präsens: werden + Partizip II",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"werde gemacht",src:"I am being made"},{pronoun:"du",form:"wirst gemacht",src:"you are being made"},{pronoun:"er/sie/es",form:"wird gemacht",src:"he/she/it is being made"}]},{label:"Plural",rows:[{pronoun:"wir",form:"werden gemacht",src:"we are being made"},{pronoun:"ihr",form:"werdet gemacht",src:"you (pl.) are being made"},{pronoun:"sie/Sie",form:"werden gemacht",src:"they/you (formal) are being made"}]}],note:"The past participle always goes to the END of the clause."},
{type:"story",speaker:"mia",mood:"matter-of-fact",art:"de-ber-kaffeekueche",trg:"Der Kaffee wird jeden Morgen um acht gemacht. Die Spülmaschine wird nach dem Mittagessen ausgeräumt. Das sind die Regeln.",src:"The coffee is made every morning at eight. The dishwasher is emptied after lunch. Those are the rules."},
{type:"mc",q:"'Der Kaffee wird um 8 gemacht.' Was bedeutet dieser Satz?",opts:["Jemand hat den Kaffee gestern um 8 gemacht","Es gibt keinen Kaffee um 8 Uhr","Der Kaffee wird morgen um 8 gemacht","Der Kaffee wird jeden Morgen um 8 Uhr zubereitet"],ans:"Der Kaffee wird jeden Morgen um 8 Uhr zubereitet",hint:"Wird + Partizip II = Passiv Präsens. Something IS being done regularly."},
{type:"fb",s:"Die Spülmaschine {1} nach dem Essen ausgeräumt.",a:["wird"],opts:["wird","werden","wurde","wirst"],hint:"The dishwasher (singular, she/it) IS emptied. Third person singular of werden.",sSrc:"The dishwasher is emptied after the meal."},
{type:"mc",q:"Mia sagt: 'Frau Schneider leitet unsere Abteilung.' Was ist Frau Schneiders Rolle?",opts:["Sie ist die Hausmeisterin","Sie ist eine neue Mitarbeiterin","Sie ist die Abteilungsleiterin","Sie ist die Sekretärin"],ans:"Sie ist die Abteilungsleiterin",hint:"Leiten means to lead or manage. Someone who leitet is a Leiter/in."},
{type:"drag_fill",s:"Der Terminkalender {1} jeden Montag {2}.",blanks:{"1":"wird","2":"aktualisiert"},pool:["wird","wurde","aktualisiert","gemacht","werden"],hint:"The schedule IS (present) updated. Werden in third person singular + past participle at end.",sSrc:"The schedule is updated every Monday."}
]},

// ─── Lesson 4: Grammatik im Büro ───
{id:"deu_r14l4",title:"Grammatik im Büro",icon:"📝",xp:15,board:true,steps:[
{type:"intro",title:"Grammatik im Büro",desc:"Passive Präteritum, relative clauses, and how to talk about the past in a German office. Three grammar structures you will need every day.",goals:["Master the passive Präteritum: wurde + Partizip II","Learn relative clauses with der/die/das (nominative, accusative, dative)","Combine both structures in office situations"]},
{type:"teach",trg:"der Auftrag",src:"the order, the task, the assignment",pos:"noun",gender:"m",note:"'Im Auftrag von' (on behalf of) appears on every official letter.\nFrom 'auftragen' (to assign). Your boss gives you Aufträge.",example:"A: Hast du den Auftrag von Frau Müller bekommen?\nB: Ja, ich soll den Bericht bis Freitag schreiben.\nA: Das ist ein wichtiger Auftrag.\nB: Ich weiß. Er wird rechtzeitig erledigt.",exampleSrc:"A: Did you get the assignment from Frau Müller?\nB: Yes, I am supposed to write the report by Friday.\nA: That is an important assignment.\nB: I know. It will be completed on time.",funFact:"'Im Auftrag von' (on behalf of) appears on every official German letter. In business emails, 'i.A.' (im Auftrag) before your name means you are signing on someone else's behalf."},
{type:"teach",trg:"der Direktor",src:"the director",pos:"noun",gender:"m",note:"From Latin 'dirigere' (to direct). The top boss.\nIn German schools, the principal is also 'der Direktor.'",example:"A: Der Direktor möchte dich sprechen.\nB: Oh. Was will er?\nA: Keine Sorge. Er begrüßt alle neuen Mitarbeiter.\nB: Ah, gut. Dann gehe ich gleich hin.",exampleSrc:"A: The director wants to speak with you.\nB: Oh. What does he want?\nA: No worries. He welcomes all new employees.\nB: Ah, good. Then I will go right away.",funFact:"Direktor is more formal than Leiter. In German schools, the principal is 'der Direktor.' In companies, the Direktor sits at the top. 'Direktorsebene' (director level) is where the big decisions happen."},
{type:"teach",trg:"die Direktorin",src:"the director (female)",pos:"noun",gender:"f",note:"Germany has been increasing the number of Direktorinnen in leadership.\nThe -in suffix is mandatory when referring to a specific woman.",example:"A: Die Direktorin kommt um elf Uhr.\nB: Die neue Direktorin? Ich habe sie noch nicht kennengelernt.\nA: Sie wurde letzten Monat eingestellt.\nB: Ich bin gespannt auf die Besprechung.",exampleSrc:"A: The director is coming at eleven o'clock.\nB: The new director? I have not met her yet.\nA: She was hired last month.\nB: I am curious about the meeting.",funFact:"Germany has been steadily increasing the number of Direktorinnen in leadership positions. Since 2015, a Frauenquote (women's quota) requires large companies to have at least 30% women on their supervisory boards."},
{type:"teach",trg:"die Leiter",src:"the ladder",pos:"noun",gender:"f",note:"Feminine. Der Leiter = male leader, die Leiter = ladder.\nGender changes meaning completely.",example:"A: Wo ist die Leiter? Ich muss an die Decke.\nB: Im Lager. Der Hausmeister hat sie.\nA: Danke. Die Leiter wird oft gebraucht.\nB: Ja, besonders wenn Lampen gewechselt werden.",exampleSrc:"A: Where is the ladder? I need to reach the ceiling.\nB: In the storage room. The caretaker has it.\nA: Thanks. The ladder is often needed.\nB: Yes, especially when lamps are changed.",funFact:"Der Leiter (masculine) = leader. Die Leiter (feminine) = ladder. 'Die Karriereleiter' (career ladder) combines both meanings beautifully: you climb the Leiter to become a Leiter."},
{type:"teach",trg:"die Liste",src:"the list",pos:"noun",gender:"f",note:"Same word in many European languages.\nGermans make Listen for everything: Einkaufsliste, Aufgabenliste, Wunschliste.",example:"A: Steht das auf der Liste?\nB: Ja, Punkt sieben auf der Liste.\nA: Gut. Wir arbeiten die Liste ab.\nB: Bis Freitag muss alles auf der Liste erledigt sein.",exampleSrc:"A: Is that on the list?\nB: Yes, point seven on the list.\nA: Good. We will work through the list.\nB: By Friday everything on the list must be completed.",funFact:"Germans make Listen for everything: Einkaufsliste (shopping list), Aufgabenliste (task list), Wunschliste (wish list), Packliste (packing list). If it can be organized, it gets a Liste."},
{type:"teach",trg:"die Organisation",src:"the organization",pos:"noun",gender:"f",note:"The -tion ending is always feminine in German.\nAlways stressed on the last syllable: Organisa-TION.",example:"A: Die Organisation der Konferenz war perfekt.\nB: Danke! Es wurde alles im Voraus geplant.\nA: Gute Organisation ist der Schlüssel zum Erfolg.\nB: Ja, ohne Organisation funktioniert nichts.",exampleSrc:"A: The organization of the conference was perfect.\nB: Thanks! Everything was planned in advance.\nA: Good organization is the key to success.\nB: Yes, without organization nothing works.",funFact:"The -tion ending is always feminine in German and always stressed on the last syllable: Organisa-TION. This rule works for Kommunikation, Information, Situation, and hundreds more. Free gender rule for all Latin loanwords."},
{type:"teach",trg:"der Stil",src:"the style",pos:"noun",gender:"m",note:"Same word in English. 'Führungsstil' = management style.\n'Arbeitsstil' = work style. 'Im großen Stil' = on a grand scale.",example:"A: Wie ist der Führungsstil hier?\nB: Ziemlich locker. Wir arbeiten selbstständig.\nA: Das passt zu meinem Arbeitsstil.\nB: Gut. Jeder hat seinen eigenen Stil.",exampleSrc:"A: What is the management style here?\nB: Pretty relaxed. We work independently.\nA: That suits my work style.\nB: Good. Everyone has their own style.",funFact:"Führungsstil (management style) is a key concept in German business culture. German companies are known for 'Mitbestimmung' (co-determination), where employees have a say in management decisions."},
{type:"teach",trg:"das Loch",src:"the hole",pos:"noun",gender:"n",note:"Plural: die Löcher. 'Ein Loch in der Wand.'\n'Budgetloch' = budget hole (deficit). 'Schwarzes Loch' = black hole.",example:"A: Da ist ein Loch in der Wand!\nB: Ja, dort hing vorher ein Regal.\nA: Das Loch muss repariert werden.\nB: Der Hausmeister wurde schon informiert.",exampleSrc:"A: There is a hole in the wall!\nB: Yes, a shelf used to hang there.\nA: The hole needs to be repaired.\nB: The caretaker was already informed.",funFact:"'Budgetloch' (budget hole) is what Germans call a deficit. 'Schwarzes Loch' is a black hole. 'Ein Loch im Socken' (a hole in the sock) is the morning nightmare. German uses Loch for any gap, literal or figurative."},
{type:"teach",trg:"die Decke",src:"the ceiling, the blanket",pos:"noun",gender:"f",note:"Two meanings: ceiling and blanket. Context decides.\n'An die Decke gehen' = to hit the ceiling (to get very angry).",example:"A: Die Decke im Büro ist sehr hoch.\nB: Ja, dreieinhalb Meter. Ein alter Bau.\nA: Und die Lampe an der Decke?\nB: Die wurde letzte Woche ausgetauscht.",exampleSrc:"A: The ceiling in the office is very high.\nB: Yes, three and a half meters. An old building.\nA: And the lamp on the ceiling?\nB: It was replaced last week.",funFact:"Decke means both ceiling and blanket. 'An die Decke gehen' (to go to the ceiling) means to get very angry. 'Unter einer Decke stecken' (to be under one blanket) means to be in cahoots."},
{type:"teach",trg:"die Kerze",src:"the candle",pos:"noun",gender:"f",note:"'Kerzen anzünden' = to light candles. Very German.\nBirthday tradition: one candle per year on the cake.",example:"A: Warum stehen Kerzen auf dem Tisch?\nB: Thomas hat Geburtstag. Eine Kerze für jedes Jahr.\nA: Das sind viele Kerzen!\nB: Ja, er wird fünfzig. Die Kerzen wurden alle angezündet.",exampleSrc:"A: Why are there candles on the table?\nB: Thomas has his birthday. One candle for each year.\nA: That is a lot of candles!\nB: Yes, he is turning fifty. The candles were all lit.",funFact:"Germans love candles. Germany is Europe's largest candle market. In winter, Adventskränze (Advent wreaths) have four candles. Birthday cakes have one candle per year of life. Candle-lit evenings are called 'gemütlich.'"},
{type:"teach",trg:"bedienen",src:"to operate, to serve",pos:"verb",gender:null,note:"Be- + dienen (to serve). 'Eine Maschine bedienen' = to operate a machine.\n'Kunden bedienen' = to serve customers.",example:"A: Kannst du den Kopierer bedienen?\nB: Ja, er ist einfach zu bedienen.\nA: Zeig mir bitte, wie er bedient wird.\nB: Klar, drück diesen Knopf und warte.",exampleSrc:"A: Can you operate the copier?\nB: Yes, it is easy to operate.\nA: Please show me how it is operated.\nB: Sure, press this button and wait.",funFact:"Bedienen has two meanings: to operate a machine and to serve a customer. 'Selbstbedienung' (self-service) is everywhere in Germany. 'Wird hier bedient?' (Is there table service here?) is the first question in any restaurant."},
{type:"teach",trg:"klären",src:"to clarify, to settle",pos:"verb",gender:null,note:"From 'klar' (clear). 'Das müssen wir klären.'\nThe calm German way of saying 'we have a problem.'",example:"A: Es gibt ein Missverständnis. Das muss geklärt werden.\nB: Okay, was muss geklärt werden?\nA: Wer ist für das Projekt verantwortlich?\nB: Das wurde in der letzten Besprechung geklärt.",exampleSrc:"A: There is a misunderstanding. That needs to be clarified.\nB: Okay, what needs to be clarified?\nA: Who is responsible for the project?\nB: That was clarified in the last meeting.",funFact:"'Das müssen wir klären' (we need to clarify that) is the calm German way of saying 'we have a problem.' Klären comes from klar (clear). A Kläranlage is a water treatment plant that 'clarifies' dirty water."},
{type:"teach",trg:"festlegen",src:"to determine, to establish, to set",pos:"verb",gender:null,note:"Fest (firm) + legen (to lay). 'Einen Termin festlegen.'\nThe fest- prefix family: festhalten, festsetzen, feststehen, festlegen.",example:"A: Wann legen wir den Termin fest?\nB: Am besten heute. Der Termin wurde noch nicht festgelegt.\nA: Wie wäre es mit nächstem Dienstag?\nB: Gut. Dann legen wir Dienstag fest.",exampleSrc:"A: When do we set the date?\nB: Best today. The date has not been set yet.\nA: How about next Tuesday?\nB: Good. Then we will set Tuesday.",funFact:"The fest- prefix family all mean making something firm or fixed: festlegen (to establish), festhalten (to hold on to), festsetzen (to fix/determine), feststehen (to be certain). All built from fest (firm)."},
{type:"teach",trg:"festsetzen",src:"to fix, to set, to determine",pos:"verb",gender:null,note:"Fest (firm) + setzen (to set). More official than festlegen.\n'Der Preis wurde festgesetzt' = the price was fixed.",example:"A: Der Termin wurde auf Freitag festgesetzt.\nB: Von wem?\nA: Von der Direktorin. Das steht fest.\nB: Okay, dann muss ich meinen Terminkalender ändern.",exampleSrc:"A: The date was set for Friday.\nB: By whom?\nA: By the director. That is certain.\nB: Okay, then I need to change my schedule.",funFact:"Festsetzen is more official than festlegen. Prices are festgesetzt, court dates are festgesetzt, rules are festgesetzt. It implies authority made the decision."},
{type:"teach",trg:"feststehen",src:"to be certain, to be definite",pos:"verb",gender:null,note:"Fest + stehen (to stand). 'Das steht fest' = that is certain.\nSomething that festststeht cannot be changed.",example:"A: Steht der Termin fest?\nB: Ja, das steht fest. Nächsten Mittwoch.\nA: Gut. Das steht also fest.\nB: Ja, es wurde von der Leitung festgelegt.",exampleSrc:"A: Is the date definite?\nB: Yes, that is certain. Next Wednesday.\nA: Good. So that is definite.\nB: Yes, it was determined by management.",funFact:"'Das steht fest' is one of the most decisive phrases in German. When something festststeht, discussion is over. It combines fest (firm) with stehen (to stand): it stands firm. No arguments."},
{type:"teach",trg:"festhalten",src:"to hold on to, to record, to note",pos:"verb",gender:null,note:"Fest + halten (to hold). Physical: 'Halt dich fest!'\nAbstract: 'Wir halten das im Protokoll fest' (record in minutes).",example:"A: Halte bitte fest, was in der Besprechung besprochen wird.\nB: Natürlich. Ich schreibe alles auf.\nA: Gut. Das muss im Protokoll festgehalten werden.\nB: Wird gemacht.",exampleSrc:"A: Please record what is discussed in the meeting.\nB: Of course. I will write everything down.\nA: Good. That must be recorded in the minutes.\nB: Will be done.",funFact:"Festhalten means both physical holding (Halt dich fest! = Hold on tight!) and recording (im Protokoll festhalten = record in the minutes). German meetings always produce a Protokoll where everything is festgehalten."},
{type:"teach",trg:"inner",src:"inner, internal",pos:"adj",gender:null,note:"'Die innere Stimme' = the inner voice.\n'Innerbetrieblich' = within the company.",example:"A: Die innere Organisation muss verbessert werden.\nB: Ja, die inneren Abläufe sind zu langsam.\nA: Das wurde auch in der Besprechung besprochen.\nB: Wir klären das nächste Woche.",exampleSrc:"A: The internal organization must be improved.\nB: Yes, the internal processes are too slow.\nA: That was also discussed in the meeting.\nB: We will clarify that next week.",funFact:"Inner describes anything inside: innere Stimme (inner voice), innere Ruhe (inner peace), Innenminister (interior minister). 'Innere Werte' (inner values) is what Germans say matters more than appearances."},
{type:"tip",title:"Passiv Präteritum: wurde + Partizip II",text:"Past passive: something WAS done.\nEnglish: 'The office was built in 2010.'\nGerman: 'Das Büro wurde 2010 gebaut.'\n\nStructure: Subject + wurde (konjugiert) + Partizip II (am Ende)\n\nWurde is the Präteritum of werden:\nich wurde, du wurdest, er/sie/es wurde\nwir wurden, ihr wurdet, sie/Sie wurden\n\nVergleich:\nwird gemacht (IS being made, Präsens)\nwurde gemacht (WAS made, Präteritum)\n\nPassiv Präteritum is standard in written German for reporting past events.",deepDive:{title:"Passiv mit 'von' und 'durch'",text:"Who did the action? Two prepositions help:\n\n'von + Dativ' identifies a person:\nDer Bericht wurde von der Leiterin geschrieben.\n(The report was written by the manager.)\n\n'durch + Akkusativ' identifies a means:\nDie Nachricht wurde durch eine E-Mail gesendet.\n(The message was sent by means of an email.)\n\nVon = who did it (agent)\nDurch = how it was done (means)"}},
{type:"verb_table",title:"Passiv Präteritum: wurde + Partizip II",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"wurde eingeladen",src:"I was invited"},{pronoun:"du",form:"wurdest eingeladen",src:"you were invited"},{pronoun:"er/sie/es",form:"wurde eingeladen",src:"he/she/it was invited"}]},{label:"Plural",rows:[{pronoun:"wir",form:"wurden eingeladen",src:"we were invited"},{pronoun:"ihr",form:"wurdet eingeladen",src:"you (pl.) were invited"},{pronoun:"sie/Sie",form:"wurden eingeladen",src:"they/you (formal) were invited"}]}],note:"Wurde replaces wird. Past participle stays at the end."},
{type:"tip",title:"ge- or no ge-? Partizip II Rules",text:"Regular: ge- + stem + -t\ngemacht, gekauft, gelernt\n\nIrregular: ge- + changed stem + -en\ngeschrieben, gesprochen, gelesen\n\nInseparable prefixes (be-, ver-, er-, ent-, emp-, zer-): NO ge-\nbezahlt, verkauft, erklärt, entdeckt\n\nVerbs ending in -ieren: NO ge-\nrepariert, studiert, organisiert",deepDive:{title:"Separable Prefixes and ge-",text:"With separable verbs, ge- goes BETWEEN prefix and stem:\naufgemacht, zugemacht, eingeladen, angefangen\n\naufmachen: aufgemacht\neinladen: eingeladen\nmitbringen: mitgebracht\n\nSeparable prefixes: auf, an, ein, mit, aus, ab, zu, vor\nInseparable prefixes: be-, ge-, er-, ver-, zer-, ent-, emp-, miss-"}},
{type:"tip",title:"worden vs. geworden",text:"Passive Perfekt: ist gemacht WORDEN (NOT geworden!)\n\ngeworden = became (full verb 'werden'):\nEr ist Arzt geworden. (He became a doctor.)\n\nworden = passive auxiliary:\nEs ist gebaut worden. (It has been built.)\n\nRule: In passive Perfekt, 'geworden' is shortened to 'worden.'",deepDive:{title:"Process Passive vs. State Passive",text:"Process passive (werden + PP) = ACTION:\nDas Fenster wird geöffnet.\n(Someone is opening it right now.)\n\nState passive (sein + PP) = RESULT:\nDas Fenster ist geöffnet.\n(It is in an open state.)\n\nThe difference:\nwird geöffnet = process\nist geöffnet = result\n\nThis distinction is tested on the Goethe B1 exam."}},
{type:"mc",q:"'Das Büro wurde 2010 gebaut.' Wann wurde das Büro gebaut?",opts:["Es wird nächstes Jahr gebaut","Im Jahr 2010","Es wird jetzt gebaut","Es hat schon immer existiert"],ans:"Im Jahr 2010",hint:"Wurde + Partizip = Passiv Vergangenheit. The action is finished."},
{type:"fb",s:"Die Konferenz {1} gestern organisiert.",a:["wurde"],opts:["wurde","wird","werden","wurden"],hint:"The conference (singular) WAS organized yesterday. Past passive singular.",sSrc:"The conference was organized yesterday."},
{type:"mc",q:"Welcher Satz beschreibt etwas, das JETZT passiert?",opts:["Die Datei wurde kopiert.","Die Datei war kopiert worden.","Die Datei wird kopiert.","Die Datei ist kopiert worden."],ans:"Die Datei wird kopiert.",hint:"Present passive uses wird, not wurde. Wird = now, wurde = past."},
{type:"tip",title:"Relative Clauses: der/die/das as Relative Pronouns",text:"Relative clauses describe a noun.\n'The colleague WHO sits next to me' = 'Der Kollege, DER neben mir sitzt.'\n\nThe relative pronoun agrees with:\nGENDER and NUMBER of the reference word\nbut the CASE depends on its role in the relative clause.\n\nNominative (subject): der/die/das/die\nAccusative (object): den/die/das/die\nDative (indirect object): dem/der/dem/denen\n\nThe verb goes to the END of the relative clause.\nComma before the relative pronoun is mandatory.",deepDive:{title:"Relative Clauses in the Office",text:"Relative clauses are perfect for descriptions:\n\nDer Kollege, der neben mir sitzt, heißt Thomas.\n(Nominative: he sits)\n\nDie Datei, die ich gestern kopiert habe, ist weg.\n(Accusative: I copied IT)\n\nDer Kollege, dem ich das Dokument gegeben habe, ist krank.\n(Dative: I gave it TO HIM)\n\nTip: Gender from the reference word. Case from the role in the subclause. Verb at end. Comma before.\n\nIMPORTANT: Relative clauses in German ALWAYS need commas (not optional like in English).\n\nNominative or accusative? The test:\nWho performs the action in the relative clause?\nDer Mann, der singt = HE sings (nominative).\nDer Mann, den ich sehe = I see HIM (accusative).\nOnly MASCULINE changes: der to den.\n\nCommon dative verbs in relative clauses:\nhelfen, danken, gefallen, gehören, vertrauen, folgen\nAll require dem/der/dem/denen.\n\n'was' as relative pronoun:\nAfter alles, etwas, nichts, vieles, einiges: Alles, was er sagt...\nAfter neuter superlatives: Das Beste, was ich je gegessen habe...\nAfter whole sentences: Er lacht, was mich freut."}},
{type:"verb_table",title:"Relativpronomen: der/die/das",groups:[{label:"Nominativ (Subjekt)",rows:[{pronoun:"maskulin",form:"der",src:"who/that (m)"},{pronoun:"feminin",form:"die",src:"who/that (f)"},{pronoun:"neutrum",form:"das",src:"who/that (n)"},{pronoun:"Plural",form:"die",src:"who/that (pl)"}]},{label:"Akkusativ (direktes Objekt)",rows:[{pronoun:"maskulin",form:"den",src:"whom/that (m)"},{pronoun:"feminin",form:"die",src:"whom/that (f)"},{pronoun:"neutrum",form:"das",src:"whom/that (n)"},{pronoun:"Plural",form:"die",src:"whom/that (pl)"}]},{label:"Dativ (indirektes Objekt)",rows:[{pronoun:"maskulin",form:"dem",src:"to whom (m)"},{pronoun:"feminin",form:"der",src:"to whom (f)"},{pronoun:"neutrum",form:"dem",src:"to whom (n)"},{pronoun:"Plural",form:"denen",src:"to whom (pl)"}]}],note:"Gender from the reference word. Case from the role in the relative clause. Verb at end."},
{type:"mc",q:"'Der Kollege, ___ neben mir sitzt, heißt Thomas.' Welches Relativpronomen passt?",opts:["die","dem","den","der"],ans:"der",hint:"Kollege is masculine. In the relative clause, he IS SITTING (subject = Nominativ)."},
{type:"fb",s:"Die Datei, {1} ich gestern kopiert habe, ist weg.",a:["die"],opts:["die","der","das","den"],hint:"Datei is feminine. In the relative clause, I copied IT (direct object = Akkusativ).",sSrc:"The file that I copied yesterday is gone."},
{type:"mc",q:"'Der Kollege, ___ ich das Dokument gegeben habe, ist im Urlaub.' Welches Pronomen?",opts:["den","die","dem","der"],ans:"dem",hint:"Kollege is masculine. I gave the document TO HIM (indirect object = Dativ)."},
{type:"mc",q:"Welcher Satz kombiniert Passiv UND Relativsatz?",opts:["Der Tisch, der neu ist, steht hier.","Das Dokument liegt auf dem Tisch.","Das Dokument, das gestern gedruckt wurde, liegt auf dem Tisch.","Gestern wurde das Dokument gedruckt."],ans:"Das Dokument, das gestern gedruckt wurde, liegt auf dem Tisch.",hint:"Look for wurde + Partizip INSIDE a relative clause (between commas)."},
{type:"fb",s:"Die Büros {1} letztes Jahr renoviert.",a:["wurden"],opts:["wurden","wurde","wird","werden"],hint:"Multiple offices (plural) WERE renovated. Plural past passive.",sSrc:"The offices were renovated last year."},
{type:"drag_fill",s:"Die Kollegin, {1} gestern {2} wurde, heißt Anna.",blanks:{"1":"die","2":"eingeladen"},pool:["die","der","eingeladen","einladen","dem","wurde"],hint:"Kollegin is feminine. She WAS invited (accusative passive). Feminine accusative relative pronoun = die.",sSrc:"The colleague who was invited yesterday is called Anna."},
{type:"mc",q:"'Das Kind, ___ wir geholfen haben, war dankbar.' Welches Pronomen?",opts:["dem","das","den","die"],ans:"dem",hint:"Kind is neuter. Helfen takes dative: we helped IT. Neuter dative = dem."},
{type:"drag_fill",s:"Der Auftrag, {1} letzte Woche {2} wurde, ist jetzt {3}.",blanks:{"1":"der","2":"erledigt","3":"fertig"},pool:["der","den","erledigt","erledigen","fertig","wurde"],hint:"Auftrag is masculine, subject of the relative clause (Nominativ). It WAS completed.",sSrc:"The assignment that was completed last week is now finished."}
]},

// ─── Lesson 5: Du oder Sie? ───
{id:"deu_r14l5",title:"Du oder Sie?",icon:"🤝",xp:15,board:true,steps:[
{type:"intro",title:"Du oder Sie?",desc:"Verumius accidentally says 'du' to the department head in a meeting. Silence. Then a smile. Learn to navigate the Du/Sie minefield.",goals:["Navigate the Du/Sie minefield in a German office","Practice passive and relative clauses in real work situations","Survive your first Besprechung (meeting)"]},
{type:"story",speaker:"narrator",mood:"tense",art:"de-ber-meeting-room",trg:"Es ist zehn Uhr. Verumius sitzt im Besprechungsraum. Die Abteilungsleiterin, die alle nur 'Frau Müller' nennen, betritt den Raum.",src:"It is ten o'clock. Verumius sits in the meeting room. The department head, whom everyone only calls 'Frau Müller,' enters the room."},
{type:"story",speaker:"verumius",mood:"nervous",art:"de-ber-meeting-room",trg:"Guten Morgen! Ah... du hast... ich meine... Sie haben... die Präsentation schon vorbereitet?",src:"Good morning! Ah... you have (informal)... I mean... you have (formal)... already prepared the presentation?"},
{type:"story",speaker:"narrator",mood:"dramatic",art:"de-ber-meeting-room",trg:"Stille. Mias Augen werden groß. Die Kollegen schauen auf ihre Laptops. Dann lächelt Frau Müller.",src:"Silence. Mia's eyes go wide. The colleagues look at their laptops. Then Frau Müller smiles."},
{type:"story",speaker:"mia",mood:"relieved",art:"de-ber-meeting-room",trg:"'Sie können ruhig du sagen,' sagt Frau Müller. 'Wir duzen uns hier alle.' Verumius atmet aus.",src:"'You can go ahead and say du,' says Frau Müller. 'We all use du with each other here.' Verumius exhales."},
{type:"teach",trg:"duzen",src:"to use 'du' (informal) with someone",pos:"verb",gender:null,note:"'Wir duzen uns' = we address each other informally.\nThe older or higher-ranking person always offers first.",example:"A: Darf ich Sie duzen?\nB: Natürlich! Wir duzen uns hier alle.\nA: Gut. Dann sage ich ab jetzt du.\nB: Perfekt. Ich bin Thomas.",exampleSrc:"A: May I use 'du' with you?\nB: Of course! We all use 'du' with each other here.\nA: Good. Then I will say 'du' from now on.\nB: Perfect. I am Thomas.",funFact:"Offering the 'du' is a social milestone in Germany. The older or higher-ranking person always offers first. 'Wollen wir uns duzen?' (Shall we use du?) is a significant moment in any relationship."},
{type:"teach",trg:"siezen",src:"to use 'Sie' (formal) with someone",pos:"verb",gender:null,note:"Default with strangers, officials, and in business.\nBreaking through to 'du' can take years.",example:"A: Siezen Sie mich bitte.\nB: Natürlich, kein Problem.\nA: Wir siezen uns im Büro mit allen Kunden.\nB: Verstehe. Hier wird gesiezt, nicht geduzt.",exampleSrc:"A: Please use 'Sie' with me.\nB: Of course, no problem.\nA: We use 'Sie' with all clients in the office.\nB: I understand. Here we use formal address, not informal.",funFact:"The default with strangers, officials, and in business is Sie. Breaking through to 'du' can take years in some relationships. Some neighbors siezen each other for decades. It is not unfriendly, it is respectful."},
{type:"teach",trg:"klopfen",src:"to knock",pos:"verb",gender:null,note:"Onomatopoeia. Germans ALWAYS knock before entering an office.\n'Bitte klopfen' is on many office doors. Three knocks is standard.",example:"A: Klopf bitte an, bevor du reinkommst.\nB: Natürlich. Ich klopfe immer an.\nA: Gut. In diesem Büro wird angeklopft.\nB: Verstanden. Drei Mal klopfen?",exampleSrc:"A: Please knock before you come in.\nB: Of course. I always knock.\nA: Good. In this office, knocking is expected.\nB: Understood. Three knocks?",funFact:"Germans ALWAYS knock before entering an office. 'Bitte klopfen' (please knock) is on many office doors. Three knocks is the standard. Entering without knocking is considered extremely rude."},
{type:"teach",trg:"klingeln",src:"to ring",pos:"verb",gender:null,note:"Onomatopoeia. 'Es klingelt' = the bell/phone is ringing.\nYour phone klingelt, your doorbell klingelt.",example:"A: Es klingelt! Wer ist da?\nB: Wahrscheinlich der Postbote. Er klingelt jeden Tag.\nA: Soll ich aufmachen?\nB: Ja, bitte. Er hat ein Paket.",exampleSrc:"A: The bell is ringing! Who is there?\nB: Probably the mailman. He rings every day.\nA: Should I open up?\nB: Yes, please. He has a package.",funFact:"German has many sound-words: klingeln (to ring), klopfen (to knock), klirren (to clink), knacken (to crack). German onomatopoeia is surprisingly precise."},
{type:"teach",trg:"die Klingel",src:"the bell, the doorbell",pos:"noun",gender:"f",note:"Every German apartment building has a row of Klingeln with name tags.\nFinding the right Klingel is the first challenge for visitors.",example:"A: Wo ist die Klingel für die dritte Etage?\nB: Die dritte von oben. Steht 'Schmidt' drauf.\nA: Ah, ich sehe sie. Die Klingel ist sehr klein.\nB: Ja, aber sie funktioniert.",exampleSrc:"A: Where is the doorbell for the third floor?\nB: The third from the top. It says 'Schmidt' on it.\nA: Ah, I see it. The bell is very small.\nB: Yes, but it works.",funFact:"Every German apartment building has a row of Klingeln with name tags. If your name is not on the Klingel, the Postbote will not deliver your packages. First rule after moving in: put your name on the Klingel."},
{type:"teach",trg:"einschalten",src:"to turn on, to switch on",pos:"verb",gender:null,note:"Ein- (on) + schalten (to switch). Separable verb.\nOpposite: ausschalten (to turn off).",example:"A: Kannst du den Computer einschalten?\nB: Natürlich. Er wird gerade eingeschaltet.\nA: Dauert das immer so lange?\nB: Ja, der Rechner ist alt. Er wurde nie ausgetauscht.",exampleSrc:"A: Can you turn on the computer?\nB: Of course. It is being turned on right now.\nA: Does it always take this long?\nB: Yes, the computer is old. It was never replaced.",funFact:"Einschalten and ausschalten (on/off) are the most basic German tech verbs. 'Haben Sie versucht, ihn aus- und wieder einzuschalten?' (Have you tried turning it off and on again?) is the universal IT helpdesk answer."},
{type:"teach",trg:"schalten",src:"to switch, to shift",pos:"verb",gender:null,note:"The base verb. 'Den Gang schalten' = to shift gears.\n'Schalter' = switch. 'Schaltjahr' = leap year (a switched year).",example:"A: Wie schalte ich den Drucker ein?\nB: Da ist ein Schalter auf der Seite.\nA: Dieser kleine Knopf hier?\nB: Genau. Einmal schalten und warten.",exampleSrc:"A: How do I switch on the printer?\nB: There is a switch on the side.\nA: This little button here?\nB: Exactly. Switch once and wait.",funFact:"Schalten gives us Schalter (switch), Schaltjahr (leap year, literally 'switch year'), and Schaltfläche (digital button). Gang schalten means to shift gears in a car. Most German cars still have manual Schaltgetriebe."},
{type:"teach",trg:"drehen",src:"to turn, to rotate",pos:"verb",gender:null,note:"Physical rotation. 'Einen Film drehen' = to shoot a film.\n'Sich drehen' = to turn around.",example:"A: Dreh den Knopf nach rechts.\nB: So? Passiert nichts.\nA: Noch etwas weiter drehen.\nB: Ah, jetzt funktioniert es!",exampleSrc:"A: Turn the knob to the right.\nB: Like this? Nothing is happening.\nA: Turn a bit more.\nB: Ah, now it works!",funFact:"'Einen Film drehen' (to turn a film) means to shoot a movie. It comes from physically turning the film reel in old cameras. 'Mir dreht sich alles' (everything is turning for me) means being dizzy."},
{type:"teach",trg:"heizen",src:"to heat",pos:"verb",gender:null,note:"'Die Heizung' = the heating system. 'Heizkosten' = heating costs.\nGermans are very conscious of Heizkosten.",example:"A: Wird das Büro im Winter geheizt?\nB: Natürlich. Die Heizung wird im Oktober eingeschaltet.\nA: Und die Heizkosten?\nB: Die werden vom Betrieb bezahlt.",exampleSrc:"A: Is the office heated in winter?\nB: Of course. The heating is turned on in October.\nA: And the heating costs?\nB: They are paid by the company.",funFact:"Germans are very conscious of Heizkosten (heating costs). 'Heiz nicht so viel!' (Do not heat so much!) is a common household complaint. The Heizkostenabrechnung (heating cost bill) arrives once a year and causes stress."},
{type:"teach",trg:"senden",src:"to send, to broadcast",pos:"verb",gender:null,note:"More formal than 'schicken.' 'Eine E-Mail senden.'\nAlso: 'Der Sender sendet ein Signal' (broadcast).",example:"A: Wurde die E-Mail schon gesendet?\nB: Ja, sie wurde heute Morgen gesendet.\nA: Gut. Dann warten wir auf die Antwort.\nB: Die wird sicher bald kommen.",exampleSrc:"A: Has the email been sent yet?\nB: Yes, it was sent this morning.\nA: Good. Then we wait for the reply.\nB: It will surely come soon.",funFact:"Senden has two past participles: 'gesendet' (for sending messages) and 'gesandt' (more literary, for sending people). In the office, 'gesendet' is standard. 'Die E-Mail wurde gesendet' is the confirmation you want to see."},
{type:"teach",trg:"der Knopf",src:"the button (physical), the knob",pos:"noun",gender:"m",note:"'Auf den Knopf drücken' = to press the button.\nAlso means a button on clothing. Not for digital screen buttons.",example:"A: Wo ist der Knopf für den Aufzug?\nB: Der große runde Knopf an der Wand.\nA: Dieser hier? Er leuchtet nicht.\nB: Drück fester. Der Knopf ist etwas alt.",exampleSrc:"A: Where is the button for the elevator?\nB: The big round button on the wall.\nA: This one? It does not light up.\nB: Press harder. The button is a bit old.",funFact:"Knopf means both a mechanical button and a button on clothing. 'Knopfdruck' (button press) is used metaphorically: 'auf Knopfdruck' means at the push of a button, instantly."},
{type:"teach",trg:"der Klick",src:"the click",pos:"noun",gender:"m",note:"From English. 'Ein Klick genügt' = one click is enough.\n'Doppelklick' = double click.",example:"A: Wie öffne ich die Datei?\nB: Mit einem Doppelklick.\nA: Ein Klick reicht nicht?\nB: Nein, für Dateien brauchst du zwei Klicks.",exampleSrc:"A: How do I open the file?\nB: With a double click.\nA: One click is not enough?\nB: No, for files you need two clicks.",funFact:"Klick is borrowed from English. 'Ein-Klick-Kauf' (one-click purchase) changed online shopping. In German, Klick can also mean a sudden understanding: 'Es hat Klick gemacht' (it clicked, I understood)."},
{type:"teach",trg:"der Stempel",src:"the stamp, the seal",pos:"noun",gender:"m",note:"Germany runs on Stempel. Official documents need an official stamp.\n'Abgestempelt' = stamped, but also 'labeled/stigmatized.'",example:"A: Braucht dieses Dokument einen Stempel?\nB: Ja, ohne Stempel ist es nicht gültig.\nA: Wo bekomme ich den Stempel?\nB: Bei der Sekretärin. Sie hat den Firmenstempel.",exampleSrc:"A: Does this document need a stamp?\nB: Yes, without a stamp it is not valid.\nA: Where do I get the stamp?\nB: From the secretary. She has the company stamp.",funFact:"Germany runs on Stempel (stamps). Official documents, contracts, certifications all need a Stempel to be valid. 'Abgestempelt werden' also means to be labeled or stigmatized, to have a metaphorical stamp put on you."},
{type:"teach",trg:"der Sekretär",src:"the secretary (male), the writing desk",pos:"noun",gender:"m",note:"Two meanings: male secretary AND a type of writing desk.\nThe furniture Sekretär is an antique desk with a fold-down front.",example:"A: Herr Weber ist der Sekretär der Geschäftsleitung.\nB: Seit wann?\nA: Seit zwei Jahren. Vorher war er in der IT.\nB: Ein interessanter Karrierewechsel.",exampleSrc:"A: Herr Weber is the secretary of the executive board.\nB: Since when?\nA: For two years. Before that he was in IT.\nB: An interesting career change.",funFact:"Sekretär has two meanings: male secretary AND a type of antique writing desk with a fold-down front. The furniture meaning comes from French and refers to a desk where secrets (sekret) were kept."},
{type:"teach",trg:"der Sitz",src:"the seat, the headquarters",pos:"noun",gender:"m",note:"'Firmensitz' = company headquarters. 'Sitzplatz' = seating place.\n'Seinen Sitz haben' = to be headquartered.",example:"A: Wo hat die Firma ihren Sitz?\nB: In Berlin-Mitte. Das ist der Hauptsitz.\nA: Und andere Standorte?\nB: Ja, einen Sitz in Hamburg und einen in München.",exampleSrc:"A: Where is the company headquartered?\nB: In Berlin-Mitte. That is the headquarters.\nA: And other locations?\nB: Yes, one office in Hamburg and one in Munich.",funFact:"Sitz means both a physical seat and a headquarters. 'Firmensitz' is where the company is officially registered. 'Regierungssitz' (government seat) is Berlin for Germany. The Bundestag has its Sitz in the Reichstag building."},
{type:"teach",trg:"der Sessel",src:"the armchair",pos:"noun",gender:"m",note:"A comfortable chair with armrests. More cozy than 'Stuhl' (chair).\nThe Büro-Sessel is the office desk chair.",example:"A: Der Sessel im Konferenzraum ist sehr bequem.\nB: Ja, die Sessel wurden neu gekauft.\nA: Viel besser als die alten Stühle.\nB: Die alten Stühle wurden letzten Monat entsorgt.",exampleSrc:"A: The armchair in the conference room is very comfortable.\nB: Yes, the armchairs were newly purchased.\nA: Much better than the old chairs.\nB: The old chairs were disposed of last month.",funFact:"In Austria, Sessel means any chair, not just armchairs. In Germany, a Sessel is specifically a comfortable armchair. The word comes from Latin 'sessio' (sitting). A Chefsessel is the boss's chair."},
{type:"teach",trg:"das Kissen",src:"the cushion, the pillow",pos:"noun",gender:"n",note:"'Kopfkissen' = pillow. 'Sofakissen' = couch cushion.\nSome German offices have Kissen on chairs for comfort.",example:"A: Möchtest du ein Kissen für den Stuhl?\nB: Ja, gerne. Der Stuhl ist etwas hart.\nA: Hier, dieses Kissen ist weich.\nB: Danke, das ist viel besser.",exampleSrc:"A: Would you like a cushion for the chair?\nB: Yes, please. The chair is a bit hard.\nA: Here, this cushion is soft.\nB: Thanks, that is much better.",funFact:"Kopfkissen (head cushion) is a pillow. Sofakissen (sofa cushion) is a throw pillow. Germans have specific compound nouns for each type of Kissen. 'Kissenschlacht' (pillow fight) is one of the most fun German compounds."},
{type:"teach",trg:"mobil",src:"mobile",pos:"adj",gender:null,note:"'Mobiles Arbeiten' = mobile working/remote work.\n'Mobiltelefon' is the formal word for cell phone, but everyone says 'Handy.'",example:"A: Arbeitest du mobil oder im Büro?\nB: Meistens mobil. Ich brauche nur meinen Laptop.\nA: Mobiles Arbeiten wird hier unterstützt.\nB: Ja, dreimal pro Woche ist mobiles Arbeiten erlaubt.",exampleSrc:"A: Do you work mobile or in the office?\nB: Mostly mobile. I only need my laptop.\nA: Mobile working is supported here.\nB: Yes, three times per week mobile working is allowed.",funFact:"'Mobiles Arbeiten' (mobile working/remote work) became standard in Germany after 2020. 'Mobiltelefon' is the formal word for cell phone, but everyone just says 'Handy,' a word that does not exist in English with this meaning."},
{type:"teach",trg:"möbliert",src:"furnished",pos:"adj",gender:null,note:"From 'Möbel' (furniture). 'Möblierte Wohnung' = furnished apartment.\n'Möbliertes Zimmer' is common in German housing ads.",example:"A: Ist das Büro schon möbliert?\nB: Teilweise. Die Schreibtische sind da.\nA: Und die Regale?\nB: Die werden nächste Woche geliefert. Dann ist es voll möbliert.",exampleSrc:"A: Is the office already furnished?\nB: Partially. The desks are there.\nA: And the shelves?\nB: They will be delivered next week. Then it will be fully furnished.",funFact:"'Möbliertes Zimmer' (furnished room) is the most searched housing term for newcomers in Germany. Unmöbliert (unfurnished) in Germany means truly empty: no kitchen, no light fixtures, sometimes not even a kitchen sink."},
{type:"teach",trg:"elektrisch",src:"electric, electrical",pos:"adj",gender:null,note:"'Elektrischer Strom' = electric current.\n'Elektroauto' = electric car. A big topic in Germany.",example:"A: Ist die Heizung elektrisch?\nB: Nein, wir heizen mit Gas.\nA: Und der Firmenwagen?\nB: Der ist elektrisch. Ein Elektroauto.",exampleSrc:"A: Is the heating electric?\nB: No, we heat with gas.\nA: And the company car?\nB: It is electric. An electric car.",funFact:"Germany's Energiewende (energy transition) is pushing everything to become elektrisch. Elektroautos, elektrische Busse, elektrische Roller. The word 'elektrisch' comes from Greek 'elektron' (amber), which produces static electricity when rubbed."},
{type:"mc",q:"Verumius sagt versehentlich 'du' zur Chefin. Wer bietet in der deutschen Bürokultur das 'du' zuerst an?",opts:["Jeder kann zuerst anbieten","Die ranghöhere oder ältere Person","Es passiert automatisch","Der neue Mitarbeiter"],ans:"Die ranghöhere oder ältere Person",hint:"Hierarchy and age determine who breaks the formal barrier in Germany."},
{type:"fb",s:"In unserem Büro {1} jeden Morgen eine Besprechung gehalten.",a:["wird"],opts:["wird","wurde","werden","worden"],hint:"A meeting IS held every morning. Present passive, singular.",sSrc:"In our office a meeting is held every morning."},
{type:"mc",q:"'Die Kollegin, ___ neben Verumius sitzt, heißt Mia.' Welches Pronomen?",opts:["die","den","dem","der"],ans:"die",hint:"Kollegin is feminine. She IS SITTING (subject = Nominativ). Feminine Nominativ = die."},
{type:"fb",s:"Der Rechner, {1} ich bediene, ist neu.",a:["den"],opts:["den","der","dem","das"],hint:"Rechner is masculine. I operate IT (direct object = Akkusativ). Masculine Akkusativ = den.",sSrc:"The computer that I operate is new."},
{type:"mc",q:"'Die Besprechung wurde um zehn Uhr begonnen.' Was ist passiert?",opts:["Die Besprechung wurde um zehn gestartet","Die Besprechung beginnt um zehn","Die Besprechung wird um zehn beginnen","Die Besprechung findet nicht statt"],ans:"Die Besprechung wurde um zehn gestartet",hint:"Wurde + Partizip = something WAS done in the past."},
{type:"drag_fill",s:"Die E-Mail, {1} gestern {2} wurde, ist wichtig.",blanks:{"1":"die","2":"gesendet"},pool:["die","der","gesendet","senden","wurde","wird"],hint:"E-Mail is feminine (direct object inside passive relative clause = Akkusativ). She WAS sent.",sSrc:"The email that was sent yesterday is important."},
{type:"mc",q:"Verumius klopft an die Tür, bevor er das Büro betritt. Warum klopft er?",opts:["Die Tür ist abgeschlossen","Jemand hat ihm gesagt, er soll klopfen","Es ist höfliche Büro-Etikette in Deutschland","Er hat seinen Schlüssel vergessen"],ans:"Es ist höfliche Büro-Etikette in Deutschland",hint:"Knocking before entering is standard German office behavior everywhere."},
{type:"fb",s:"Der Computer muss zuerst {1} werden.",a:["eingeschaltet"],opts:["eingeschaltet","einschalten","schalten","geschaltet"],hint:"The computer must be turned on. Modal passive: muss + Partizip II + werden.",sSrc:"The computer must first be turned on."},
{type:"match",pairs:[{trg:"duzen",src:"to use 'du' (informal)"},{trg:"siezen",src:"to use 'Sie' (formal)"},{trg:"klopfen",src:"to knock"},{trg:"einschalten",src:"to turn on"}]},
{type:"drag_fill",s:"Der Kollege, {1} mich {2} hat, {3} gestern eingestellt.",blanks:{"1":"der","2":"begrüßt","3":"wurde"},pool:["der","den","begrüßt","begrüßen","wurde","wird"],hint:"Masculine colleague WHO (Nominativ) greeted me. He WAS hired yesterday (Passiv Präteritum).",sSrc:"The colleague who greeted me was hired yesterday."}
]},

// ─── Lesson 6: Geburtstagskuchen und Regeln ───
{id:"deu_r14l6",title:"Geburtstagskuchen und Regeln",icon:"🎂",xp:15,board:true,steps:[
{type:"intro",title:"Geburtstagskuchen und Regeln",desc:"Thomas has a birthday. And he brought his OWN cake! Welcome to the German birthday tradition. Passive and relative clauses in action.",goals:["Discover the German birthday cake tradition","Master passive in both tenses","Use relative clauses to describe colleagues and situations"]},
{type:"story",speaker:"mia",mood:"cheerful",art:"de-ber-kaffeekueche-cake",trg:"Oh, Thomas hat heute Geburtstag! Schau, er hat einen Kuchen mitgebracht.",src:"Oh, Thomas has his birthday today! Look, he brought a cake."},
{type:"story",speaker:"verumius",mood:"confused",art:"de-ber-kaffeekueche-cake",trg:"Moment... ER hat den Kuchen mitgebracht? Für seinen EIGENEN Geburtstag?",src:"Wait... HE brought the cake? For his OWN birthday?"},
{type:"story",speaker:"mia",mood:"amused",art:"de-ber-kaffeekueche-cake",trg:"Natürlich! In Deutschland bringt das Geburtstagskind den Kuchen mit. Der Kuchen wird vom Geburtstagskind selbst gemacht oder gekauft.",src:"Of course! In Germany, the birthday person brings the cake. The cake is made or bought by the birthday person themselves."},
{type:"teach",trg:"die Schachtel",src:"the box, the packet",pos:"noun",gender:"f",note:"Smaller than a Kiste. 'Eine Schachtel Pralinen' = a box of chocolates.\nOften used for packaging.",example:"A: Ist das eine Schachtel Pralinen?\nB: Ja, für Thomas. Zum Geburtstag.\nA: Die Schachtel sieht schön aus.\nB: Sie wurde extra verpackt.",exampleSrc:"A: Is that a box of chocolates?\nB: Yes, for Thomas. For his birthday.\nA: The box looks nice.\nB: It was specially wrapped.",funFact:"'Eine Schachtel Pralinen' (a box of chocolates) is a classic German gift. Schachtel is also used as mild slang for an older woman (unflattering), so be careful with context."},
{type:"teach",trg:"die Kiste",src:"the crate, the chest",pos:"noun",gender:"f",note:"Bigger than a Schachtel. 'Eine Kiste Bier' = a crate of beer.\nYou bring the empty Kiste back for deposit.",example:"A: Kannst du eine Kiste aus dem Lager holen?\nB: Welche Kiste? Es gibt viele dort.\nA: Die große Holzkiste mit den Werkzeugen.\nB: Klar, die Kiste wird sofort geholt.",exampleSrc:"A: Can you get a crate from the storage room?\nB: Which crate? There are many there.\nA: The big wooden crate with the tools.\nB: Sure, the crate will be fetched right away.",funFact:"'Eine Kiste Bier' (a crate of beer) is the standard beer purchase unit in Germany. You bring the empty Kiste back to the store for a deposit (Pfand). A 20-bottle Kiste is the German standard."},
{type:"teach",trg:"der Kasten",src:"the box, the case, the crate",pos:"noun",gender:"m",note:"Regional: in Bavaria and Austria, 'Kasten' also means wardrobe.\n'Bierkasten' = beer crate.",example:"A: Stell den Kasten bitte in die Ecke.\nB: Welchen Kasten?\nA: Den mit den Getränken.\nB: Ah, der Bierkasten. Wird gemacht.",exampleSrc:"A: Please put the crate in the corner.\nB: Which crate?\nA: The one with the drinks.\nB: Ah, the beer crate. Will be done.",funFact:"In Bavaria and Austria, Kasten also means wardrobe or closet. 'Mein Kasten ist voll' could mean your beer crate is full OR your closet is full, depending on where you are."},
{type:"teach",trg:"das Werkzeug",src:"the tool(s)",pos:"noun",gender:"n",note:"Werk (work) + Zeug (stuff). Literally 'work-stuff.'\nCollective: all tools together. Individual tools have specific names.",example:"A: Hast du das richtige Werkzeug?\nB: Ja, Hammer, Schraubenzieher und Zange.\nA: Perfekt. Das Regal muss repariert werden.\nB: Das Werkzeug wurde gerade aus dem Keller geholt.",exampleSrc:"A: Do you have the right tools?\nB: Yes, hammer, screwdriver, and pliers.\nA: Perfect. The shelf needs to be repaired.\nB: The tools were just fetched from the basement.",funFact:"Das Werkzeug is collective: all your tools together. Zeug literally means 'stuff.' German loves Zeug-compounds: Spielzeug (play-stuff = toys), Fahrzeug (drive-stuff = vehicle), Flugzeug (fly-stuff = airplane)."},
{type:"teach",trg:"der Hammer",src:"the hammer",pos:"noun",gender:"m",note:"Same word in English and German. From Proto-Germanic.\n'Das ist der Hammer!' = slang for 'That is amazing/unbelievable!'",example:"A: Wo ist der Hammer?\nB: Im Werkzeugkasten. Wozu brauchst du ihn?\nA: Ein Nagel muss in die Wand.\nB: Hier ist der Hammer. Aber klopf nicht zu laut!",exampleSrc:"A: Where is the hammer?\nB: In the toolbox. What do you need it for?\nA: A nail needs to go into the wall.\nB: Here is the hammer. But do not bang too loudly!",funFact:"'Das ist der Hammer!' is German slang for 'That is amazing/unbelievable!' Used both positively and negatively. Hammerhart (hammer-hard) means extremely tough. Hammermäßig means awesome."},
{type:"teach",trg:"der Handwerker",src:"the craftsperson, the tradesperson",pos:"noun",gender:"m",note:"Hand + Werk (work) + -er (person). Germany's Handwerker tradition goes back to medieval guilds.",example:"A: Wir brauchen einen Handwerker für das Dach.\nB: Einen Handwerker zu finden ist schwer.\nA: Der letzte Handwerker wurde vor drei Monaten bestellt.\nB: Ja, man muss lange warten.",exampleSrc:"A: We need a tradesperson for the roof.\nB: Finding a tradesperson is difficult.\nA: The last tradesperson was booked three months ago.\nB: Yes, you have to wait a long time.",funFact:"Germany's Handwerker tradition goes back to medieval guilds (Zünfte). Finding a good Handwerker today can take months. The Handwerkskammer (Chamber of Crafts) regulates quality. 'Handwerk hat goldenen Boden' (craftsmanship has a golden foundation)."},
{type:"teach",trg:"kleben",src:"to glue, to stick",pos:"verb",gender:null,note:"'Der Zettel klebt an der Wand' = the note sticks to the wall.\nThose passive-aggressive Kaffeküche notes? They are geklebt everywhere.",example:"A: Wer hat den Zettel an die Wand geklebt?\nB: Keine Ahnung. Er wurde gestern Nacht geklebt.\nA: 'Bitte Küche sauber halten!' steht drauf.\nB: Das wird jede Woche neu geklebt.",exampleSrc:"A: Who stuck the note on the wall?\nB: No idea. It was stuck there last night.\nA: 'Please keep the kitchen clean!' is written on it.\nB: That gets re-stuck every week.",funFact:"Those passive-aggressive Kaffeküche notes are geklebt to every surface in German offices. 'Kleben bleiben' means to stick around. 'Klebstoff' (glue) literally means 'sticky substance.'"},
{type:"teach",trg:"stecken",src:"to put in, to insert, to be stuck",pos:"verb",gender:null,note:"'Den Stecker in die Steckdose stecken.'\nStecker and Steckdose come from stecken. German vocabulary is a family tree.",example:"A: Steck bitte den Stecker in die Steckdose.\nB: Welchen Stecker?\nA: Den vom Kopierer.\nB: Ah, der steckt schon drin.",exampleSrc:"A: Please put the plug into the outlet.\nB: Which plug?\nA: The one from the copier.\nB: Ah, it is already plugged in.",funFact:"Stecken, Stecker, Steckdose, Steckbrief (wanted poster, literally 'plug letter'), Stecknadel (pin). German vocabulary is a family tree. One root gives birth to entire word families."},
{type:"teach",trg:"aufheben",src:"to pick up, to keep, to save",pos:"verb",gender:null,note:"Two meanings: pick up AND keep/save.\n'Heb das auf!' means both 'Pick that up!' and 'Save that!'",example:"A: Heb bitte das Papier vom Boden auf.\nB: Natürlich. Soll ich es aufheben?\nA: Ja, bitte aufheben. Es ist ein wichtiges Dokument.\nB: Okay, das wird sicher aufgehoben.",exampleSrc:"A: Please pick up the paper from the floor.\nB: Of course. Should I keep it?\nA: Yes, please save it. It is an important document.\nB: Okay, it will be safely kept.",funFact:"Aufheben has two meanings: to pick up AND to keep/save. 'Das Gesetz wurde aufgehoben' means the law was abolished (literally 'picked up and removed'). Context decides which meaning applies."},
{type:"teach",trg:"aufnehmen",src:"to record, to absorb, to take in",pos:"verb",gender:null,note:"Auf- (up) + nehmen (to take). 'Ein Gespräch aufnehmen' = to record a conversation.\n'Neue Mitarbeiter aufnehmen' = to take on new employees.",example:"A: Wird die Besprechung aufgenommen?\nB: Ja, alles wird aufgenommen und protokolliert.\nA: Gut. Dann kann ich nachher alles nachhören.\nB: Die Aufnahme wurde gestern getestet.",exampleSrc:"A: Is the meeting being recorded?\nB: Yes, everything is being recorded and documented.\nA: Good. Then I can listen to it later.\nB: The recording was tested yesterday.",funFact:"Aufnehmen means to record, absorb, or take in. 'Etwas in sich aufnehmen' means to absorb something. 'In einen Verein aufgenommen werden' means to be accepted into a club. Multi-talented verb."},
{type:"teach",trg:"gebrauchen",src:"to use",pos:"verb",gender:null,note:"Ge- + brauchen (to need). 'Gebrauchsanweisung' = instructions for use.\n'Gebraucht' also means secondhand.",example:"A: Wie gebraucht man diesen Kopierer?\nB: Lesen Sie die Gebrauchsanweisung.\nA: Wo ist die?\nB: Sie wurde neben dem Kopierer aufgehängt.",exampleSrc:"A: How do you use this copier?\nB: Read the instructions for use.\nA: Where are they?\nB: They were hung up next to the copier.",funFact:"'Gebraucht' means both used (as in 'I used it') and secondhand. 'Gebrauchtwagen' is a used car. A 'Gebrauchsanweisung' (instructions for use) is on every German product. Reading them is practically a national pastime."},
{type:"teach",trg:"einsetzen",src:"to deploy, to use, to insert",pos:"verb",gender:null,note:"Ein- (in) + setzen (to place). 'Mitarbeiter einsetzen' = to deploy employees.\n'Sich einsetzen für' = to advocate for.",example:"A: Wo wirst du im Betrieb eingesetzt?\nB: In der IT-Abteilung. Ich wurde dort eingesetzt.\nA: Und die neuen Rechner?\nB: Die werden nächste Woche eingesetzt.",exampleSrc:"A: Where will you be deployed in the company?\nB: In the IT department. I was placed there.\nA: And the new computers?\nB: They will be deployed next week.",funFact:"'Sich für etwas einsetzen' (to advocate for something) is a key German phrase. The Betriebsrat setzt sich für die Mitarbeiter ein (advocates for the employees). A word that combines placing and caring."},
{type:"teach",trg:"eckig",src:"angular, square, cornered",pos:"adj",gender:null,note:"From 'Ecke' (corner). 'Ein eckiger Tisch' = a square table.\n'Ecken und Kanten haben' = to have rough edges (personality).",example:"A: Soll der Tisch rund oder eckig sein?\nB: Eckig. Ein eckiger Tisch passt besser.\nA: Und die Regale?\nB: Auch eckig. Alles hier ist eckig und ordentlich.",exampleSrc:"A: Should the table be round or square?\nB: Square. A square table fits better.\nA: And the shelves?\nB: Also square. Everything here is angular and tidy.",funFact:"'Ecken und Kanten haben' (to have corners and edges) means to have a strong, unpolished personality. Germans appreciate people with Ecken und Kanten over smooth, flawless facades."},
{type:"teach",trg:"senkrecht",src:"vertical, perpendicular",pos:"adj",gender:null,note:"Senk- (to lower/sink) + recht (right/straight).\nOpposite: waagerecht (horizontal).",example:"A: Hängt das Bild senkrecht?\nB: Nein, es hängt etwas schief.\nA: Soll ich es senkrecht ausrichten?\nB: Ja bitte. Es muss senkrecht hängen.",exampleSrc:"A: Is the picture hanging vertically?\nB: No, it is hanging a bit crooked.\nA: Should I straighten it vertically?\nB: Yes please. It must hang vertically.",funFact:"Senkrecht and waagerecht (vertical and horizontal) are the German pair for crossword puzzles: 'senkrecht' = down, 'waagerecht' = across. Precision in direction is very German."},
{type:"mc",q:"In Deutschland bringt zum Geburtstag im Büro traditionell wer den Kuchen mit?",opts:["Die Kollegen","Der Chef","Das Geburtstagskind selbst","Die Sekretärin"],ans:"Das Geburtstagskind selbst",hint:"German birthday tradition reverses what many cultures expect. The birthday person treats."},
{type:"fb",s:"Der Kuchen {1} vom Geburtstagskind mitgebracht.",a:["wird"],opts:["wird","wurde","werden","worden"],hint:"The cake IS brought. Present passive, third person singular.",sSrc:"The cake is brought by the birthday person."},
{type:"mc",q:"'Die Kaffeküche wurde letzte Woche renoviert.' Was bedeutet das?",opts:["Die Küche wird gerade renoviert","Die Küche muss noch renoviert werden","Die Küche braucht keine Renovierung","Die Küche wurde letzte Woche erneuert"],ans:"Die Küche wurde letzte Woche erneuert",hint:"Wurde + Partizip = past passive. Letzte Woche = last week."},
{type:"fb",s:"Thomas, {1} heute Geburtstag hat, bringt den Kuchen mit.",a:["der"],opts:["der","den","dem","die"],hint:"Thomas is masculine. He HAS his birthday (subject = Nominativ). Masculine Nominativ = der.",sSrc:"Thomas, who has his birthday today, brings the cake."},
{type:"drag_fill",s:"Der Kuchen, {1} von Thomas {2} wurde, schmeckt gut.",blanks:{"1":"der","2":"gebacken"},pool:["der","den","gebacken","backen","wurde","wird"],hint:"Kuchen is masculine, subject of passive relative clause (Nominativ). It WAS baked.",sSrc:"The cake that was baked by Thomas tastes good."},
{type:"mc",q:"'Die E-Mail wurde von der Sekretärin gesendet.' Wer hat die E-Mail gesendet?",opts:["Der Direktor","Die Sekretärin","Die E-Mail selbst","Es ist unbekannt"],ans:"Die Sekretärin",hint:"Von + Dativ identifies who performed the action in a passive sentence."},
{type:"drag_fill",s:"Die Regeln, {1} in der Kaffeküche gelten, {2} ernst genommen.",blanks:{"1":"die","2":"werden"},pool:["die","der","werden","wurde","wird","den"],hint:"Rules (feminine plural, Nominativ in relative clause). They ARE taken seriously (plural passive present).",sSrc:"The rules that apply in the coffee kitchen are taken seriously."},
{type:"mc",q:"Welcher Satz benutzt Passiv Präteritum IN einem Relativsatz?",opts:["Das Werkzeug, das repariert wurde, funktioniert wieder.","Das Werkzeug, das auf dem Tisch liegt, ist alt.","Das Werkzeug wird repariert.","Der Handwerker repariert das Werkzeug."],ans:"Das Werkzeug, das repariert wurde, funktioniert wieder.",hint:"Look for wurde + Partizip within commas (relative clause markers)."},
{type:"match",pairs:[{trg:"die Schachtel",src:"small box/packet"},{trg:"die Kiste",src:"crate/chest"},{trg:"das Werkzeug",src:"tools"},{trg:"der Hammer",src:"hammer"},{trg:"der Handwerker",src:"craftsperson"}]},
{type:"drag_fill",s:"Der Handwerker, {1} gerufen {2}, hat das Regal {3}.",blanks:{"1":"der","2":"wurde","3":"repariert"},pool:["der","den","wurde","wird","repariert","reparieren"],hint:"Masculine Handwerker WHO was called (Nominativ relative + passive). He repaired the shelf.",sSrc:"The craftsperson who was called repaired the shelf."}
]},

// ─── Lesson 7: Alles zusammen ───
{id:"deu_r14l7",title:"Alles zusammen",icon:"🧪",xp:15,board:true,steps:[
{type:"intro",title:"Alles zusammen",desc:"Test everything you have learned about passive and relative clauses. Prove you can describe workplace events, technology, and people in German.",goals:["Test passive Präsens and Präteritum in combination","Master relative clauses in all three cases","Combine all three constructions in office contexts"]},
{type:"teach",trg:"der Fernseher",src:"the television set",pos:"noun",gender:"m",note:"Fern (far) + Seher (viewer). Literally 'far-viewer.'\nUsually means the TV set, not the activity.",example:"A: Haben wir einen Fernseher im Konferenzraum?\nB: Ja, ein großer Fernseher hängt an der Wand.\nA: Der Fernseher wurde letzte Woche installiert.\nB: Perfekt für Präsentationen.",exampleSrc:"A: Do we have a television in the conference room?\nB: Yes, a large TV hangs on the wall.\nA: The TV was installed last week.\nB: Perfect for presentations.",funFact:"Fern (far) + Seher (viewer) creates 'far-viewer.' The German word describes exactly what TV does. 'Glotze' (starer) is the slang word for TV, from 'glotzen' (to stare)."},
{type:"teach",trg:"das Fernsehen",src:"the television (medium)",pos:"noun",gender:"n",note:"Fern (far) + sehen (to see). The medium, not the device.\n'Fernsehen gucken' = to watch TV.",example:"A: Wie oft schaust du Fernsehen?\nB: Jeden Abend. Nachrichten und Serien.\nA: Im Fernsehen wird viel über Politik berichtet.\nB: Ja, besonders in den Nachrichten.",exampleSrc:"A: How often do you watch television?\nB: Every evening. News and series.\nA: On television a lot is reported about politics.\nB: Yes, especially in the news.",funFact:"Fernsehen (the medium) versus Fernseher (the device). 'Im Fernsehen' means on TV. Germans love their Tatort (crime scene) on Sunday evenings. It is practically a national ritual."},
{type:"teach",trg:"die Fernbedienung",src:"the remote control",pos:"noun",gender:"f",note:"Fern (far) + Bedienung (operation). Literally 'far-operation.'\nA perfect German compound that describes exactly what it does.",example:"A: Wo ist die Fernbedienung?\nB: Unter dem Kissen auf der Couch.\nA: Da liegt sie immer! Warum wird sie nie zurückgelegt?\nB: Das ist eines der großen Büro-Mysterien.",exampleSrc:"A: Where is the remote control?\nB: Under the cushion on the couch.\nA: It is always there! Why is it never put back?\nB: That is one of the great office mysteries.",funFact:"Fernbedienung is one of those perfect German compounds: Fern (far) + Bedienung (operation/service). It describes exactly what the thing does. English 'remote control' does the same, but the German version is one elegant word."},
{type:"teach",trg:"der Lautsprecher",src:"the loudspeaker, the speaker",pos:"noun",gender:"m",note:"Laut (loud) + Sprecher (speaker). Same compound logic as English.\nUsed for speakers on computers, phones, PA systems.",example:"A: Der Lautsprecher funktioniert nicht.\nB: Welcher Lautsprecher? Der am Rechner?\nA: Ja. Es wird kein Ton wiedergegeben.\nB: Das Kabel wurde wahrscheinlich nicht richtig angeschlossen.",exampleSrc:"A: The speaker is not working.\nB: Which speaker? The one on the computer?\nA: Yes. No sound is being played.\nB: The cable was probably not connected properly.",funFact:"Laut (loud) + Sprecher (speaker) mirrors English for once. German and English share this compound logic because both descend from Proto-Germanic. Not all borrowing goes one direction."},
{type:"teach",trg:"der Sender",src:"the transmitter, the TV/radio station",pos:"noun",gender:"m",note:"From 'senden' (to send). A transmitter or broadcasting station.\nARD and ZDF are Germany's biggest Sender.",example:"A: Auf welchem Sender läuft das?\nB: Auf dem Ersten. Das ist der größte Sender.\nA: Und der Sender wird staatlich finanziert?\nB: Ja, durch den Rundfunkbeitrag. Jeder zahlt.",exampleSrc:"A: On which channel is that on?\nB: On Das Erste. That is the biggest station.\nA: And the station is state-funded?\nB: Yes, through the broadcasting fee. Everyone pays.",funFact:"ARD and ZDF are Germany's public broadcasters, funded by the Rundfunkbeitrag (broadcasting fee) of 18.36 euros per month per household. Every household must pay, whether they watch TV or not."},
{type:"teach",trg:"der Kanal",src:"the channel, the canal",pos:"noun",gender:"m",note:"'Auf welchem Kanal?' = On which channel?\nFrom Latin 'canalis.' Also a waterway.",example:"A: Auf welchem Kanal kommt die Sendung?\nB: Kanal drei. Um zwanzig Uhr.\nA: Und die Wiederholung?\nB: Die wird auf einem anderen Kanal gesendet.",exampleSrc:"A: On which channel is the show on?\nB: Channel three. At eight PM.\nA: And the rerun?\nB: It will be broadcast on a different channel.",funFact:"Germany has dozens of TV Kanäle. The public ones (ARD, ZDF) coexist with private ones (RTL, ProSieben). The 'Kanalwechsel' (channel switching) between public and private is a daily German ritual."},
{type:"teach",trg:"die Kassette",src:"the cassette",pos:"noun",gender:"f",note:"From French. Audio and video cassettes.\nAlmost extinct but still understood by all Germans.",example:"A: Was ist das? Eine Kassette?\nB: Ja, eine alte Videokassette. Die wurde im Keller gefunden.\nA: Haben wir noch einen Kassettenrekorder?\nB: Nein, der wurde vor Jahren weggeworfen.",exampleSrc:"A: What is that? A cassette?\nB: Yes, an old video cassette. It was found in the basement.\nA: Do we still have a cassette recorder?\nB: No, it was thrown away years ago.",funFact:"The Kassette is almost extinct in Germany, replaced by digital media. But 'Hörspielkassetten' (audio play cassettes) were a huge part of German childhood. The detective series 'Die drei Fragezeichen' sold millions of Kassetten."},
{type:"teach",trg:"das Laufwerk",src:"the drive (computer)",pos:"noun",gender:"n",note:"Lauf (run) + Werk (work). A disc drive or storage drive.\n'CD-Laufwerk,' 'DVD-Laufwerk.' Being phased out.",example:"A: Mein Rechner hat kein CD-Laufwerk mehr.\nB: Die neuen Rechner werden ohne Laufwerk gebaut.\nA: Wie installiere ich dann Software?\nB: Alles wird online heruntergeladen.",exampleSrc:"A: My computer does not have a CD drive anymore.\nB: The new computers are built without drives.\nA: How do I install software then?\nB: Everything is downloaded online.",funFact:"Laufwerk (run-work) refers to any disk drive. CD-Laufwerke and DVD-Laufwerke are vanishing from modern computers. The word persists in IT jargon though: Netzlaufwerk (network drive) is still common."},
{type:"teach",trg:"abonnieren",src:"to subscribe",pos:"verb",gender:null,note:"From French 'abonner.' Regular -ieren verb.\n'Einen Kanal abonnieren' = to subscribe to a channel.",example:"A: Hast du den Newsletter abonniert?\nB: Ja, er wurde letzte Woche abonniert.\nA: Und die Zeitung?\nB: Die wird ab nächstem Monat abonniert.",exampleSrc:"A: Did you subscribe to the newsletter?\nB: Yes, it was subscribed to last week.\nA: And the newspaper?\nB: It will be subscribed to starting next month.",funFact:"Germans love their Abos (abbreviation of Abonnement). Streaming, gym, magazine, newspaper: everything runs on Abonnements. 'Abo-Falle' (subscription trap) is the German term for sneaky auto-renewing subscriptions."},
{type:"teach",trg:"hochladen",src:"to upload",pos:"verb",gender:null,note:"Hoch (up) + laden (to load). Separable verb.\nOpposite: herunterladen (to download).",example:"A: Kannst du die Datei hochladen?\nB: Ja, sie wird gerade hochgeladen.\nA: Wie lange dauert das?\nB: Nur eine Minute. Die Datei wurde schon komprimiert.",exampleSrc:"A: Can you upload the file?\nB: Yes, it is being uploaded right now.\nA: How long does it take?\nB: Only a minute. The file was already compressed.",funFact:"Hochladen (upload) and herunterladen (download) are literal translations: hoch (up) + laden (load) and herunter (down) + laden (load). German tech vocabulary loves to create transparent compounds."},
{type:"teach",trg:"herunterfahren",src:"to shut down (a computer)",pos:"verb",gender:null,note:"Herunter- (down) + fahren (to drive). Proper shutdown.\nDifferent from ausschalten (just turning off).",example:"A: Bitte fahren Sie den Computer herunter.\nB: Wird sofort heruntergefahren.\nA: Nicht einfach ausschalten!\nB: Nein, nein. Er wird ordentlich heruntergefahren.",exampleSrc:"A: Please shut down the computer.\nB: It will be shut down right away.\nA: Do not just turn it off!\nB: No, no. It will be properly shut down.",funFact:"Germans distinguish between herunterfahren (proper shutdown process) and ausschalten (just turning off). 'Fahr den Rechner runter!' is the proper way. Just pressing the power button is considered barbarisch."},
{type:"teach",trg:"installieren",src:"to install",pos:"verb",gender:null,note:"From Latin 'installare.' Regular -ieren verb.\n'Software installieren' = universal tech language.",example:"A: Wurde die neue Software schon installiert?\nB: Ja, sie wurde gestern installiert.\nA: Und funktioniert sie?\nB: Ja, alles wird gerade getestet.",exampleSrc:"A: Has the new software been installed yet?\nB: Yes, it was installed yesterday.\nA: And does it work?\nB: Yes, everything is being tested right now.",funFact:"German IT vocabulary is heavily English-influenced but grammar stays German. Installieren follows German conjugation: ich installiere, du installierst, es wurde installiert. The -ieren ending always means regular conjugation."},
{type:"teach",trg:"löschen",src:"to delete, to extinguish",pos:"verb",gender:null,note:"'Eine Datei löschen' = delete a file.\n'Ein Feuer löschen' = extinguish a fire. Same verb for both.",example:"A: Soll ich die alten Dateien löschen?\nB: Ja, die können gelöscht werden.\nA: Alle?\nB: Nein, nur die, die älter als ein Jahr sind.",exampleSrc:"A: Should I delete the old files?\nB: Yes, they can be deleted.\nA: All of them?\nB: No, only those that are older than one year.",funFact:"Löschen means both delete and extinguish. 'Feuerlöscher' (fire extinguisher) and 'Datei löschen' (delete file) use the same verb. In both cases, something is completely removed."},
{type:"teach",trg:"aufladen",src:"to charge, to load up",pos:"verb",gender:null,note:"Auf- (up) + laden (to load). 'Das Handy aufladen' = to charge the phone.\nAlso: 'eine Karte aufladen' = to top up a card.",example:"A: Mein Laptop muss aufgeladen werden.\nB: Hier ist eine freie Steckdose.\nA: Danke. Wie lange wird der Laptop aufgeladen?\nB: Eine Stunde reicht meistens.",exampleSrc:"A: My laptop needs to be charged.\nB: Here is a free outlet.\nA: Thanks. How long will the laptop be charged?\nB: One hour is usually enough.",funFact:"Aufladen means to charge (a device) or to load up (a truck). 'Emotional aufgeladen' means emotionally charged. The word works for batteries, vehicles, and feelings."},
{type:"teach",trg:"kaputtgehen",src:"to break down, to stop working",pos:"verb",gender:null,note:"Kaputt (broken) + gehen (to go). Separable verb.\nKaputt comes from French 'capot' (a losing hand in cards).",example:"A: Der Drucker ist kaputtgegangen.\nB: Schon wieder? Er geht ständig kaputt.\nA: Wann wird er repariert?\nB: Der Handwerker wurde schon gerufen.",exampleSrc:"A: The printer has broken down.\nB: Again? It breaks down constantly.\nA: When will it be repaired?\nB: The tradesperson has already been called.",funFact:"Kaputt comes from French 'capot' (a losing hand in cards). When something is kaputt, it is game over. 'Kaputtlachen' means to laugh so hard you break. 'Kaputt sein' also means to be exhausted."},
{type:"teach",trg:"kaputtmachen",src:"to break, to destroy",pos:"verb",gender:null,note:"Active version of kaputtgehen. 'Wer hat das kaputtgemacht?'\nKaputtgehen = it breaks itself. Kaputtmachen = someone breaks it.",example:"A: Wer hat den Kopierer kaputtgemacht?\nB: Niemand weiß es.\nA: Er wurde wahrscheinlich falsch bedient.\nB: Ja, die Bedienungsanleitung wird nie gelesen.",exampleSrc:"A: Who broke the copier?\nB: Nobody knows.\nA: It was probably operated incorrectly.\nB: Yes, the user manual is never read.",funFact:"Kaputtgehen = it breaks by itself. Kaputtmachen = someone breaks it. The distinction matters in German offices where blame is a serious matter. 'Das war schon kaputt!' (That was already broken!) is the universal defense."},
{type:"teach",trg:"virtuell",src:"virtual",pos:"adj",gender:null,note:"From Latin 'virtualis.' 'Virtuelles Meeting' = virtual meeting.\nBecame everyday vocabulary after 2020.",example:"A: Die Konferenz findet virtuell statt.\nB: Wieder ein virtuelles Meeting?\nA: Ja, alle Teilnehmer werden virtuell zugeschaltet.\nB: Ich bevorzuge persönliche Besprechungen.",exampleSrc:"A: The conference is taking place virtually.\nB: Another virtual meeting?\nA: Yes, all participants will be connected virtually.\nB: I prefer in-person meetings.",funFact:"'Virtuelles Meeting' became everyday vocabulary in Germany after 2020. Before that, the word virtuell was mainly used for 'virtuelle Realität' (virtual reality). Now every German office worker knows 'virtuelle Besprechung.'"},
{type:"mc",q:"'Die Software wird heute installiert.' Was passiert?",opts:["Die Software wurde gestern installiert","Die Software wird heute eingerichtet","Die Software wird morgen installiert","Die Software muss noch bestellt werden"],ans:"Die Software wird heute eingerichtet",hint:"Wird + Partizip = Passiv Präsens. Something IS being done today."},
{type:"fb",s:"Der alte Fernseher {1} letzte Woche ersetzt.",a:["wurde"],opts:["wurde","wird","werden","worden"],hint:"The old TV WAS replaced last week. Past passive, singular.",sSrc:"The old television was replaced last week."},
{type:"mc",q:"'Der Lautsprecher, ___ nicht funktioniert, muss repariert werden.' Welches Pronomen?",opts:["das","den","dem","der"],ans:"der",hint:"Lautsprecher is masculine. It does NOT function (subject = Nominativ). Masculine Nominativ = der."},
{type:"fb",s:"Die Fernbedienung, {1} ich gesucht habe, lag unter dem Kissen.",a:["die"],opts:["die","der","den","dem"],hint:"Fernbedienung is feminine. I searched for IT (direct object = Akkusativ). Feminine Akkusativ = die.",sSrc:"The remote control that I was looking for was under the cushion."},
{type:"mc",q:"'Der Rechner, der gestern repariert wurde, funktioniert wieder.' Was ist passiert?",opts:["Er wird morgen repariert","Er wird gerade repariert","Er wurde gestern repariert und geht wieder","Er ist gestern kaputtgegangen"],ans:"Er wurde gestern repariert und geht wieder",hint:"Wurde repariert = was repaired. Funktioniert wieder = works again."},
{type:"drag_fill",s:"Die Datei {1} auf den Server {2}.",blanks:{"1":"wird","2":"hochgeladen"},pool:["wird","wurde","hochgeladen","hochladen","geladen","werden"],hint:"The file IS being uploaded (present passive). Wird + Partizip II.",sSrc:"The file is being uploaded to the server."},
{type:"fb",s:"Der Kollege, {1} ich geholfen habe, ist sehr dankbar.",a:["dem"],opts:["dem","den","der","die"],hint:"Kollege is masculine. Helfen takes Dativ. I helped TO HIM. Masculine Dativ = dem.",sSrc:"The colleague whom I helped is very grateful."},
{type:"mc",q:"'Die Festplatte wurde vom Techniker ausgetauscht.' Wer hat die Festplatte ersetzt?",opts:["Der Leiter","Die Festplatte selbst","Der Techniker","Unbekannt"],ans:"Der Techniker",hint:"Vom (von + dem) Dativ tells you who performed the passive action."},
{type:"drag_fill",s:"Das Programm, {1} gestern {2} wurde, funktioniert nicht.",blanks:{"1":"das","2":"installiert"},pool:["das","der","installiert","installieren","wurde","wird"],hint:"Programm is neuter, subject in relative clause (Nominativ). It WAS installed (Passiv Präteritum).",sSrc:"The program that was installed yesterday does not work."},
{type:"drag_fill",s:"Heute {1} die Software aktualisiert. Gestern {2} der Drucker repariert.",blanks:{"1":"wird","2":"wurde"},pool:["wird","wurde","werden","wurden"],hint:"Today = present passive (wird). Yesterday = past passive (wurde).",sSrc:"Today the software is being updated. Yesterday the printer was repaired."},
{type:"mc",q:"Welcher Satz kombiniert Relativsatz + Passiv Präteritum + Dativ korrekt?",opts:["Der Kollege, die geholfen wurde, ist zufrieden.","Der Kollege, der geholfen wurde, ist zufrieden.","Der Kollege, den geholfen wurde, ist zufrieden.","Der Kollege, dem geholfen wurde, ist jetzt zufrieden."],ans:"Der Kollege, dem geholfen wurde, ist jetzt zufrieden.",hint:"Helfen takes Dativ. The colleague TO WHOM help was given. Masculine Dativ = dem."},
{type:"match",pairs:[{trg:"hochladen",src:"to upload"},{trg:"herunterfahren",src:"to shut down"},{trg:"löschen",src:"to delete"},{trg:"installieren",src:"to install"},{trg:"kaputtgehen",src:"to break down"}]},
{type:"drag_fill",s:"Die Dateien, {1} gelöscht {2}, {3} wichtig.",blanks:{"1":"die","2":"wurden","3":"waren"},pool:["die","der","wurden","wurde","waren","war"],hint:"Files (feminine plural, Nominativ). They WERE deleted (plural passive past). They WERE important.",sSrc:"The files that were deleted were important."},
{type:"mc",q:"'Der Sender, ___ wir gestern empfangen haben, wurde abgeschaltet.' Welches Pronomen und warum?",opts:["die: Plural","den: maskulin Akkusativ (wir haben IHN empfangen)","dem: maskulin Dativ","der: maskulin Nominativ"],ans:"den: maskulin Akkusativ (wir haben IHN empfangen)",hint:"Sender is masculine. We received IT (direct object in the relative clause = Akkusativ). Masculine Akkusativ = den."}
]},

// ─── Lesson 8: Feierabend ───
{id:"deu_r14l8",title:"Feierabend",icon:"🌅",xp:15,board:true,steps:[
{type:"intro",title:"Feierabend",desc:"It is 16:58. Computers are being shut down. Jackets are being put on. Feierabend is sacred. Learn the holy concept of the German Feierabend.",goals:["Discover the sacred concept of Feierabend","Review all office vocabulary","Master passive and relative clauses in natural storytelling"]},
{type:"story",speaker:"narrator",mood:"observant",art:"de-ber-office-evening",trg:"Es ist 16:58 Uhr. Etwas Seltsames passiert. Überall im Büro werden Computer heruntergefahren. Jacken werden angezogen. Taschen werden gepackt.",src:"It is 4:58 PM. Something strange is happening. All around the office, computers are being shut down. Jackets are being put on. Bags are being packed."},
{type:"story",speaker:"mia",mood:"matter-of-fact",art:"de-ber-office-evening",trg:"Feierabend! Kommst du? Um 17 Uhr ist Schluss. Die Arbeit, die nicht erledigt wurde, wird morgen gemacht.",src:"End of work! Are you coming? At 5 PM it is over. The work that was not finished will be done tomorrow."},
{type:"story",speaker:"verumius",mood:"surprised",art:"de-ber-office-evening",trg:"Aber... ich bin noch nicht fertig mit dem Bericht, der geschrieben werden muss!",src:"But... I am not yet finished with the report that needs to be written!"},
{type:"story",speaker:"mia",mood:"wise",art:"de-ber-office-exit",trg:"Der Bericht wird morgen geschrieben. Feierabend ist heilig. Die Überstunden, die hier gemacht werden, werden genau gezählt.",src:"The report will be written tomorrow. Feierabend is sacred. The overtime that is worked here is counted precisely."},
{type:"teach",trg:"das Abonnement",src:"the subscription",pos:"noun",gender:"n",note:"From French 'abonner.' Germans love their Abos (abbreviation).\nStreaming, gym, magazines: everything runs on Abonnements.",example:"A: Hast du ein Abonnement für die Zeitung?\nB: Ja, ein digitales Abonnement. Wird monatlich bezahlt.\nA: Und das Fitnessstudio?\nB: Auch ein Abonnement. Zwölf Monate.",exampleSrc:"A: Do you have a subscription for the newspaper?\nB: Yes, a digital subscription. It is paid monthly.\nA: And the gym?\nB: Also a subscription. Twelve months.",funFact:"Germans love their Abos. A typical German household has Abonnements for: newspaper, streaming, phone, public transit, gym, and magazine. 'Abo kündigen' (cancel subscription) is a common internet search."},
{type:"teach",trg:"die Anleitung",src:"the instructions, the guide",pos:"noun",gender:"f",note:"An- (to) + Leitung (guidance). 'Schritt-für-Schritt-Anleitung.'\nEvery IKEA furniture comes with a wordless Anleitung.",example:"A: Wo ist die Anleitung für den Drucker?\nB: Die Anleitung wurde online hochgeladen.\nA: Gut. Ich lese sie mir durch.\nB: Die Anleitung ist auf Deutsch und Englisch.",exampleSrc:"A: Where are the instructions for the printer?\nB: The instructions were uploaded online.\nA: Good. I will read through them.\nB: The instructions are in German and English.",funFact:"Every IKEA furniture comes with a wordless Anleitung. Germans actually read their Anleitungen before assembling anything. 'Ohne Anleitung aufbauen' (to assemble without instructions) is considered reckless."},
{type:"teach",trg:"die Bedienungsanleitung",src:"the user manual, the operating instructions",pos:"noun",gender:"f",note:"Bedienung (operation) + Anleitung (instructions).\nGermans actually READ their Bedienungsanleitungen.",example:"A: Wo ist die Bedienungsanleitung für den Kopierer?\nB: Im Ordner neben dem Regal.\nA: Die Bedienungsanleitung hat dreißig Seiten!\nB: Ja, aber sie wurde übersichtlich geschrieben.",exampleSrc:"A: Where is the user manual for the copier?\nB: In the binder next to the shelf.\nA: The user manual has thirty pages!\nB: Yes, but it was written clearly.",funFact:"Bedienungsanleitung is one of the longest common compound words in German office life. Germans actually read their Bedienungsanleitungen. In other countries, they are famously ignored."},
{type:"teach",trg:"die Gebrauchsanweisung",src:"the instructions for use",pos:"noun",gender:"f",note:"Gebrauch (use) + Anweisung (instruction). More formal.\nFound on medicine, cleaning products, and technical equipment.",example:"A: Steht in der Gebrauchsanweisung, wie man das reinigt?\nB: Ja, auf Seite drei. Es wurde genau beschrieben.\nA: Gut, dann lese ich die Gebrauchsanweisung.\nB: Die Gebrauchsanweisung ist auch online verfügbar.",exampleSrc:"A: Does the instructions for use say how to clean it?\nB: Yes, on page three. It was described exactly.\nA: Good, then I will read the instructions.\nB: The instructions for use are also available online.",funFact:"Gebrauchsanweisung is the formal version of Bedienungsanleitung. Medicine always has a Gebrauchsanweisung (also called Beipackzettel). Reading the Gebrauchsanweisung before using medication is a German habit."},
{type:"teach",trg:"der Betriebsrat",src:"the works council",pos:"noun",gender:"m",note:"Betrieb (company) + Rat (council). A legally mandated employee body.\nHas real power: hiring, firing, working conditions.",example:"A: Was macht der Betriebsrat?\nB: Er vertritt die Interessen der Mitarbeiter.\nA: Und er wird von den Mitarbeitern gewählt?\nB: Ja, alle vier Jahre. Die Wahl wird geheim durchgeführt.",exampleSrc:"A: What does the works council do?\nB: It represents the interests of the employees.\nA: And it is elected by the employees?\nB: Yes, every four years. The election is conducted secretly.",funFact:"The Betriebsrat is a legally mandated employee representation body in German companies with 5+ employees. It has real power over hiring, firing, and working conditions. It is a uniquely German form of workplace democracy."},
{type:"teach",trg:"das Treppenhaus",src:"the stairwell, the staircase",pos:"noun",gender:"n",note:"Treppe (stairs) + Haus (house). The architectural soul of German buildings.\nMany Treppenhäuser have strict Hausordnung rules.",example:"A: Nehmen wir den Aufzug oder das Treppenhaus?\nB: Das Treppenhaus. Nur zwei Etagen.\nA: Gut. Das Treppenhaus wurde gerade geputzt.\nB: Der Hausmeister reinigt es jeden Montag.",exampleSrc:"A: Shall we take the elevator or the stairwell?\nB: The stairwell. Only two floors.\nA: Good. The stairwell was just cleaned.\nB: The caretaker cleans it every Monday.",funFact:"The Treppenhaus is the architectural soul of German apartment buildings. Many have strict Hausordnung rules about noise and cleaning. 'Kehrwoche' (sweeping week) is a rotating schedule where residents clean the Treppenhaus."},
{type:"teach",trg:"das Dach",src:"the roof",pos:"noun",gender:"n",note:"Same root as English 'thatch.' 'Unter einem Dach' = under one roof.\n'Dachgeschoss' (roof floor) = attic apartment.",example:"A: Das Dach des Bürogebäudes wurde letztes Jahr renoviert.\nB: War es kaputt?\nA: Ja, es gab ein Loch im Dach.\nB: Das Loch wurde vom Handwerker repariert.",exampleSrc:"A: The roof of the office building was renovated last year.\nB: Was it broken?\nA: Yes, there was a hole in the roof.\nB: The hole was repaired by the tradesperson.",funFact:"'Unter einem Dach' (under one roof) means living or working together. 'Dachgeschoss' (roof floor) is the attic apartment, very popular in Berlin. 'Ein Dach über dem Kopf haben' means to have shelter."},
{type:"teach",trg:"der Wecker",src:"the alarm clock",pos:"noun",gender:"m",note:"From 'wecken' (to wake). The enemy of every Monday morning.\n'Der Wecker klingelt um sechs' is the most dreaded German sentence.",example:"A: Um wie viel Uhr klingelt dein Wecker?\nB: Um sechs. Jeden Morgen.\nA: Das ist früh. Mein Wecker wird auf sieben gestellt.\nB: Du hast es gut. Um sechs wird bei mir aufgestanden.",exampleSrc:"A: What time does your alarm clock ring?\nB: At six. Every morning.\nA: That is early. My alarm clock is set to seven.\nB: You are lucky. I get up at six.",funFact:"Der Wecker is the enemy of every Monday morning. 'Wecker überhören' (to sleep through the alarm) is every German's nightmare. Some people have multiple Wecker. The word Wecker also means someone who wakes you up."},
{type:"teach",trg:"der Schlaf",src:"the sleep",pos:"noun",gender:"m",note:"Same root as English 'sleep.' 'Guten Schlaf!' = Sleep well.\nSchlafzimmer (bedroom), Mittagsschlaf (afternoon nap).",example:"A: Wie war dein Schlaf letzte Nacht?\nB: Schlecht. Ich habe nur vier Stunden geschlafen.\nA: Das ist zu wenig. Schlaf ist wichtig.\nB: Ja, heute Abend wird früh ins Bett gegangen.",exampleSrc:"A: How was your sleep last night?\nB: Bad. I only slept four hours.\nA: That is too little. Sleep is important.\nB: Yes, tonight I will go to bed early.",funFact:"Germans value their Schlaf. 'Mittagsschlaf' (afternoon nap) is a tradition, especially on Sundays. 'Schlaf gut!' (sleep well) is the standard German goodnight. A Schlafmütze (sleeping cap) is a sleepyhead."},
{type:"teach",trg:"die Couch",src:"the couch, the sofa",pos:"noun",gender:"f",note:"Borrowed from English/French. Die Couch is feminine.\nAfter Feierabend, the Couch is the destination.",example:"A: Nach dem Feierabend liege ich auf der Couch.\nB: Ich auch. Die Couch ist mein bester Freund.\nA: Unsere Couch wurde letzten Monat neu gekauft.\nB: Eine gute Investition.",exampleSrc:"A: After work I lie on the couch.\nB: Me too. The couch is my best friend.\nA: Our couch was bought new last month.\nB: A good investment.",funFact:"After Feierabend, die Couch is the destination for many Germans. 'Couchpotato' has been adopted into German. The German equivalent is 'Couchkartoffel' (couch potato), a literal translation that sounds even funnier."},
{type:"teach",trg:"der Lift",src:"the elevator, the lift",pos:"noun",gender:"m",note:"From English 'lift.' More common in Austria and Switzerland.\nIn Germany, 'Aufzug' or 'Fahrstuhl' are more standard.",example:"A: Nehmen wir den Lift oder die Treppe?\nB: Den Lift. Meine Beine sind müde.\nA: Der Lift wurde gestern repariert.\nB: Gut, dann funktioniert er wieder.",exampleSrc:"A: Shall we take the elevator or the stairs?\nB: The elevator. My legs are tired.\nA: The elevator was repaired yesterday.\nB: Good, then it works again.",funFact:"Lift is more common in Austria and Switzerland. Germany prefers Aufzug or Fahrstuhl (drive-chair). All three mean elevator. Regional vocabulary differences within German-speaking countries are enormous."},
{type:"teach",trg:"abwaschen",src:"to wash dishes, to wash off",pos:"verb",gender:null,note:"Ab- (off) + waschen (to wash). 'Den Abwasch machen' = to do the dishes.\nIn the Kaffeküche: the eternal question, who does the Abwasch?",example:"A: Wer wäscht heute in der Kaffeküche ab?\nB: Du bist dran. Es steht auf dem Reinigungsplan.\nA: Aber gestern wurde auch schon von mir abgewaschen!\nB: Das stimmt nicht. Gestern wurde von Thomas abgewaschen.",exampleSrc:"A: Who does the dishes in the coffee kitchen today?\nB: You are up. It is on the cleaning schedule.\nA: But yesterday I also did the dishes!\nB: That is not true. Yesterday Thomas did the dishes.",funFact:"In the Kaffeküche, the eternal question is: who does the Abwasch? The Reinigungsplan (cleaning schedule) is supposed to solve this, but passive-aggressive notes suggest it does not always work."},
{type:"teach",trg:"anschließen",src:"to connect, to plug in",pos:"verb",gender:null,note:"An- (to/on) + schließen (to close/connect).\n'Den Monitor anschließen' = to connect the monitor.",example:"A: Wie schließe ich den Monitor an?\nB: Das Kabel wird hinten angeschlossen.\nA: Welches Kabel?\nB: Das HDMI-Kabel. Es wurde gestern bestellt.",exampleSrc:"A: How do I connect the monitor?\nB: The cable is connected in the back.\nA: Which cable?\nB: The HDMI cable. It was ordered yesterday.",funFact:"Anschließen means to connect or join. 'Sich jemandem anschließen' means to join someone. 'Im Anschluss an' means following/after. One verb, many connections."},
{type:"teach",trg:"ausfallen",src:"to fail, to be cancelled, to break down",pos:"verb",gender:null,note:"Aus- (out) + fallen (to fall). 'Der Strom fällt aus' = power outage.\n'Die Besprechung fällt aus' = the meeting is cancelled.",example:"A: Die Besprechung fällt heute aus.\nB: Warum? Was ist ausgefallen?\nA: Der Strom ist ausgefallen.\nB: Wann wird der Strom wieder eingeschaltet?",exampleSrc:"A: The meeting is cancelled today.\nB: Why? What failed?\nA: The power went out.\nB: When will the power be turned back on?",funFact:"Ausfallen is a versatile word for things going wrong. Stromausfall (power failure), Haarausfall (hair loss), Unterrichtsausfall (class cancellation). When something ausfällt, it literally falls out of existence."},
{type:"teach",trg:"auflösen",src:"to dissolve, to resolve, to disband",pos:"verb",gender:null,note:"Auf- (up/open) + lösen (to solve/loosen). 'Ein Rätsel auflösen.'\nAlso: 'Einen Vertrag auflösen' = to terminate a contract.",example:"A: Das Problem wurde endlich aufgelöst.\nB: Wie?\nA: Der Fehler wurde im System gefunden und behoben.\nB: Gut. Dann kann die Abteilung normal weiterarbeiten.",exampleSrc:"A: The problem was finally resolved.\nB: How?\nA: The error was found in the system and fixed.\nB: Good. Then the department can continue working normally.",funFact:"Auflösen works for physical (dissolving sugar), organizational (disbanding a team), and intellectual (solving a riddle) dissolution. 'Die Auflösung' at the end of a mystery is the reveal."},
{type:"teach",trg:"einfügen",src:"to insert, to paste",pos:"verb",gender:null,note:"Ein- (in) + fügen (to fit). 'Text einfügen' = to paste text.\nCtrl+V in German is 'Einfügen.'",example:"A: Kannst du den Text hier einfügen?\nB: Ja, er wird sofort eingefügt.\nA: Der Text wurde von der Leiterin geschrieben.\nB: Gut, ich füge ihn in das Dokument ein.",exampleSrc:"A: Can you insert the text here?\nB: Yes, it will be inserted right away.\nA: The text was written by the manager.\nB: Good, I will insert it into the document.",funFact:"In German computer menus, 'Einfügen' is the paste command (Ctrl+V). 'Sich einfügen' means to fit in, to integrate. New employees must 'sich ins Team einfügen' (fit into the team)."},
{type:"teach",trg:"herausfinden",src:"to find out, to discover",pos:"verb",gender:null,note:"Heraus- (out) + finden (to find). Separable verb.\n'Ich muss herausfinden, wann Feierabend ist.'",example:"A: Hast du herausgefunden, wann die Konferenz ist?\nB: Ja, nächsten Dienstag. Es wurde gestern festgelegt.\nA: Gut. Ich muss noch herausfinden, wer teilnimmt.\nB: Das wird von der Sekretärin organisiert.",exampleSrc:"A: Did you find out when the conference is?\nB: Yes, next Tuesday. It was determined yesterday.\nA: Good. I still need to find out who is participating.\nB: That is being organized by the secretary.",funFact:"Herausfinden is the detective verb of German. You find things out, you discover them. 'Es stellte sich heraus' (it turned out) is used when discoveries are made. Every good Krimi (crime novel) is about herausfinden."},
{type:"teach",trg:"der Bau",src:"the construction, the building",pos:"noun",gender:"m",note:"'Der Bau' = construction or a building under construction.\nPlural: die Bauten (buildings) or die Baue (animal burrows).",example:"A: Neben unserem Büro ist ein Bau.\nB: Ja, da wird ein neues Gebäude gebaut.\nA: Der Bau wurde letztes Jahr begonnen.\nB: Er soll nächstes Jahr fertig sein.",exampleSrc:"A: Next to our office is a construction site.\nB: Yes, a new building is being built there.\nA: The construction was started last year.\nB: It should be finished next year.",funFact:"Bau has many meanings: construction, building, structure, den (animal). 'Baufirma' (construction company), 'Bauarbeiter' (construction worker), 'Baustelle' (construction site). Germany is always in a state of Bau."},
{type:"teach",trg:"der Ofen",src:"the oven, the stove, the heater",pos:"noun",gender:"m",note:"'Backofen' = baking oven. 'Kachelofen' = tiled stove.\n'Jetzt ist der Ofen aus!' = Now the show is over! (idiom).",example:"A: Gibt es einen Ofen in der Kaffeküche?\nB: Ja, einen kleinen Backofen. Für Kuchen.\nA: Der wurde von Thomas benutzt.\nB: Natürlich. Er hat seinen Geburtstagskuchen gebacken.",exampleSrc:"A: Is there an oven in the coffee kitchen?\nB: Yes, a small baking oven. For cakes.\nA: It was used by Thomas.\nB: Of course. He baked his birthday cake.",funFact:"'Jetzt ist der Ofen aus!' (now the oven is off) means the game is over, no more chances. A Kachelofen (tiled stove) is a traditional German heating stove, beautifully decorated with ceramic tiles."},
{type:"teach",trg:"die Vase",src:"the vase",pos:"noun",gender:"f",note:"Pronounced 'VAH-zeh' in German, not like English.\nEvery German office has at least one Vase with flowers.",example:"A: Wo kommt diese Vase hin?\nB: Auf den Tisch in der Kaffeküche.\nA: Die Vase wurde von der Leiterin mitgebracht.\nB: Schön, mit frischen Blumen.",exampleSrc:"A: Where does this vase go?\nB: On the table in the coffee kitchen.\nA: The vase was brought by the manager.\nB: Nice, with fresh flowers.",funFact:"Germans pronounce Vase as 'VAH-zeh,' very different from the English 'vayz.' Flowers on the office table are common in German workplaces. A Blumenvase (flower vase) brings life to the Büroalltag (office routine)."},
{type:"teach",trg:"staubsaugen",src:"to vacuum",pos:"verb",gender:null,note:"Staub (dust) + saugen (to suck). 'Dust-sucking.'\nAlso written as two words: 'Staub saugen.'",example:"A: Wer saugt heute Staub im Büro?\nB: Der Hausmeister. Es wird jeden Freitag gestaubsaugt.\nA: Gut. Der Teppich muss dringend gesaugt werden.\nB: Ja, es wurde schon lange nicht mehr gestaubsaugt.",exampleSrc:"A: Who is vacuuming in the office today?\nB: The caretaker. It is vacuumed every Friday.\nA: Good. The carpet urgently needs to be vacuumed.\nB: Yes, it has not been vacuumed in a long time.",funFact:"Staubsauger (vacuum cleaner) literally means 'dust sucker.' Germans debate whether the past participle is 'gestaubsaugt' or 'staubgesaugt.' Both exist. It is one of German's great grammar controversies."},
{type:"teach",trg:"twittern",src:"to tweet, to post on social media",pos:"verb",gender:null,note:"From English 'Twitter.' Adapted with German verb ending.\nUsed broadly for short social media posts.",example:"A: Hat der Betrieb einen Social-Media-Account?\nB: Ja, es wird jeden Tag getwittert.\nA: Wer twittert für den Betrieb?\nB: Die Marketing-Abteilung. Alles wird vorher geprüft.",exampleSrc:"A: Does the company have a social media account?\nB: Yes, tweets are posted every day.\nA: Who tweets for the company?\nB: The marketing department. Everything is checked beforehand.",funFact:"German happily adopts English tech verbs and adds German grammar: twittern, googeln, liken, chatten, bloggen. They conjugate fully: ich twittere, du twitterst, er twittert, wir haben getwittert."},
{type:"teach",trg:"die Mobilbox",src:"the voicemail box",pos:"noun",gender:"f",note:"Mobil (mobile) + Box. Your mobile phone voicemail.\nAlso called 'Mailbox' in German.",example:"A: Ich habe dich angerufen, aber du warst nicht da.\nB: Hast du auf die Mobilbox gesprochen?\nA: Ja, eine Nachricht wurde hinterlassen.\nB: Ich höre sie gleich ab.",exampleSrc:"A: I called you, but you were not there.\nB: Did you speak on the voicemail?\nA: Yes, a message was left.\nB: I will listen to it right away.",funFact:"Germans call voicemail 'Mobilbox' or 'Mailbox.' 'Bitte hinterlassen Sie eine Nachricht nach dem Signalton' (please leave a message after the beep) is the standard German voicemail greeting."},
{type:"teach",trg:"die Mobilität",src:"the mobility",pos:"noun",gender:"f",note:"'Elektromobilität' is a huge topic in Germany.\nThe -ität ending is always feminine.",example:"A: Mobilität ist wichtig für den Job.\nB: Ja, flexible Mobilität wird erwartet.\nA: Wird ein Firmenwagen zur Verfügung gestellt?\nB: Nein, aber ein Jobticket für den Nahverkehr.",exampleSrc:"A: Mobility is important for the job.\nB: Yes, flexible mobility is expected.\nA: Is a company car provided?\nB: No, but a job ticket for public transport.",funFact:"The -ität ending is always feminine and matches English -ity: Mobilität, Qualität, Aktivität, Universität. A free gender rule for hundreds of German nouns."},
{type:"teach",trg:"die Hausmeisterin",src:"the caretaker (female)",pos:"noun",gender:"f",note:"Feminine form of Hausmeister. Hausmeister + -in.\nIncreasingly common in German buildings.",example:"A: Die Hausmeisterin hat den Schlüssel.\nB: Wo finde ich die Hausmeisterin?\nA: Im Erdgeschoss. Sie wurde letzte Woche eingestellt.\nB: Gut, ich gehe zu ihr.",exampleSrc:"A: The caretaker has the key.\nB: Where do I find the caretaker?\nA: On the ground floor. She was hired last week.\nB: Good, I will go to her.",funFact:"More and more German buildings have a Hausmeisterin instead of a Hausmeister. The job has become increasingly professionalized. A Hausverwaltung (building management company) often employs the Hausmeister/in."},
{type:"teach",trg:"das Eck",src:"the corner",pos:"noun",gender:"n",note:"Short for 'die Ecke.' More common in southern German.\n'Am Eck' = at the corner.",example:"A: Stell den Kasten bitte in das Eck.\nB: Welches Eck?\nA: Das Eck neben dem Regal.\nB: Okay, der Kasten wird ins Eck gestellt.",exampleSrc:"A: Please put the crate in the corner.\nB: Which corner?\nA: The corner next to the shelf.\nB: Okay, the crate will be put in the corner.",funFact:"Eck is the southern German/Austrian variant of Ecke (corner). 'Dreieck' (triangle) = three corners. 'Viereck' (rectangle/square) = four corners. German geometry is built on Ecken."},
{type:"teach",trg:"der Fauteuil",src:"the armchair (Austrian)",pos:"noun",gender:"m",note:"From French 'fauteuil.' Used in Austria and Switzerland.\nIn Germany, people say 'Sessel' instead.",example:"A: Was für ein schöner Fauteuil!\nB: Danke, der ist aus Wien.\nA: In Deutschland sagt man Sessel.\nB: Ja, Fauteuil ist österreichisch.",exampleSrc:"A: What a beautiful armchair!\nB: Thanks, it is from Vienna.\nA: In Germany they say Sessel.\nB: Yes, Fauteuil is Austrian.",funFact:"Fauteuil is the Austrian and Swiss word for a comfortable armchair. It comes directly from French. German, Austrian, and Swiss German have many such vocabulary differences, making the language wonderfully diverse."},
{type:"teach",trg:"das Schaufenster",src:"the shop window, the display window",pos:"noun",gender:"n",note:"Schau (look/show) + Fenster (window). Literally 'look-window.'\n'Schaufensterbummel' = window shopping.",example:"A: Hast du das Schaufenster gesehen?\nB: Ja, es wurde neu dekoriert.\nA: Die Produkte im Schaufenster sehen toll aus.\nB: Schaufensterbummel machen wir am Wochenende.",exampleSrc:"A: Did you see the display window?\nB: Yes, it was newly decorated.\nA: The products in the window look great.\nB: We will go window shopping on the weekend.",funFact:"'Schaufensterbummel' (window shopping stroll) is a beloved German pastime. 'Schaufensterpuppe' (display window doll) is a mannequin. The Schaufenster is the boundary between looking and buying."},
{type:"teach",trg:"der Korridor",src:"the corridor",pos:"noun",gender:"m",note:"From French/Latin. More formal than Flur or Gang.\nUsed in official buildings and large office complexes.",example:"A: Der Korridor zum Konferenzraum ist lang.\nB: Ja, das Gebäude ist groß.\nA: Der Korridor wurde gerade renoviert.\nB: Deshalb sieht er so neu aus.",exampleSrc:"A: The corridor to the conference room is long.\nB: Yes, the building is large.\nA: The corridor was just renovated.\nB: That is why it looks so new.",funFact:"Korridor is more formal than Flur or Gang. In hospitals, government buildings, and large offices, you walk through Korridore. In apartments and small offices, you walk through Flure."},
{type:"teach",trg:"die Stiege",src:"the staircase (Austrian)",pos:"noun",gender:"f",note:"Austrian and southern German for 'Treppe' (stairs).\nStiegenhaus = Treppenhaus = stairwell.",example:"A: Nehmen wir die Stiege oder den Lift?\nB: Die Stiege. Ist gesünder.\nA: In Deutschland sagt man Treppe.\nB: Ja, Stiege ist österreichisch.",exampleSrc:"A: Shall we take the stairs or the elevator?\nB: The stairs. It is healthier.\nA: In Germany they say Treppe.\nB: Yes, Stiege is Austrian.",funFact:"Stiege is the Austrian word for stairs (Treppe). Stiegenhaus = Treppenhaus = stairwell. Austrian German has hundreds of unique words. Learning them is part of mastering German for the whole DACH region."},
{type:"teach",trg:"das Stiegenhaus",src:"the stairwell (Austrian)",pos:"noun",gender:"n",note:"Austrian variant of Treppenhaus. Stiege + Haus.\nUsed throughout Austria and parts of southern Germany.",example:"A: Das Stiegenhaus in diesem Gebäude ist schön.\nB: Ja, es wurde im Jugendstil gebaut.\nA: In Deutschland sagt man Treppenhaus.\nB: Richtig. Stiegenhaus ist typisch österreichisch.",exampleSrc:"A: The stairwell in this building is beautiful.\nB: Yes, it was built in Art Nouveau style.\nA: In Germany they say Treppenhaus.\nB: Right. Stiegenhaus is typically Austrian.",funFact:"The DACH region (Deutschland, Austria, Swiss) shares a language but has distinct vocabulary. Stiegenhaus (AT), Treppenhaus (DE), Stiegenhaus (CH-partly). The Goethe exam tests all variants."},
{type:"teach",trg:"der Fleck",src:"the spot, the stain",pos:"noun",gender:"m",note:"'Ein Fleck auf dem Hemd' = a stain on the shirt.\n'Blinder Fleck' = blind spot.",example:"A: Da ist ein Fleck auf dem Teppich!\nB: Oh nein. Kaffee? Der wurde wahrscheinlich verschüttet.\nA: Der Fleck muss gereinigt werden.\nB: Der Hausmeister wird informiert.",exampleSrc:"A: There is a stain on the carpet!\nB: Oh no. Coffee? It was probably spilled.\nA: The stain needs to be cleaned.\nB: The caretaker will be informed.",funFact:"'Am rechten Fleck' (in the right spot) means in the right place. 'Das Herz auf dem rechten Fleck haben' means to have your heart in the right place, to be a good person."},
{type:"teach",trg:"die Nadel",src:"the needle, the pin",pos:"noun",gender:"f",note:"'Die Nadel im Heuhaufen suchen' = looking for a needle in a haystack.\nNähnadel (sewing needle), Stecknadel (pin).",example:"A: Hast du eine Nadel? Der Knopf ist abgefallen.\nB: Ja, eine Nadel und Faden.\nA: Danke. Der Knopf wird schnell wieder angenäht.\nB: Wie praktisch!",exampleSrc:"A: Do you have a needle? The button fell off.\nB: Yes, a needle and thread.\nA: Thanks. The button will be quickly sewn back on.\nB: How practical!",funFact:"'Die Nadel im Heuhaufen suchen' (looking for a needle in a haystack) exists in German too. Nadelwald (needle forest) is a coniferous forest. Tannennadeln (fir needles) cover the forest floor."},
{type:"teach",trg:"der Nagel",src:"the nail",pos:"noun",gender:"m",note:"Both the hardware nail and fingernail.\n'Den Nagel auf den Kopf treffen' = to hit the nail on the head.",example:"A: Ich brauche einen Nagel für das Bild.\nB: Der Hammer liegt im Werkzeugkasten.\nA: Danke. Der Nagel wird jetzt in die Wand geschlagen.\nB: Aber nicht zu laut! Es wird noch gearbeitet.",exampleSrc:"A: I need a nail for the picture.\nB: The hammer is in the toolbox.\nA: Thanks. The nail will now be hammered into the wall.\nB: But not too loud! People are still working.",funFact:"'Den Nagel auf den Kopf treffen' (to hit the nail on the head) means to be exactly right. 'Nägel mit Köpfen machen' (to make nails with heads) means to do things properly, thoroughly."},
{type:"teach",trg:"die Kabine",src:"the cabin, the booth",pos:"noun",gender:"f",note:"Umkleidekabine (changing room), Telefonkabine (phone booth).\nFrom French 'cabine.'",example:"A: Wo ist die Umkleidekabine?\nB: Am Ende des Korridors.\nA: Gibt es auch eine Duschkabine?\nB: Ja, die wurde letztes Jahr eingebaut.",exampleSrc:"A: Where is the changing room?\nB: At the end of the corridor.\nA: Is there also a shower cabin?\nB: Yes, it was installed last year.",funFact:"Kabine appears in many compounds: Umkleidekabine (changing room), Telefonkabine (phone booth), Flugzeugkabine (airplane cabin), Duschkabine (shower stall). The phone Kabine is nearly extinct."},
{type:"teach",trg:"das Kuvert",src:"the envelope",pos:"noun",gender:"n",note:"From French 'couvert.' More common in Austria and Switzerland.\nIn Germany, 'Umschlag' or 'Briefumschlag' is more common.",example:"A: Hast du ein Kuvert für diesen Brief?\nB: Ja, hier. Das Kuvert wurde schon beschriftet.\nA: In Deutschland sagt man Umschlag.\nB: Stimmt. Kuvert ist eher österreichisch.",exampleSrc:"A: Do you have an envelope for this letter?\nB: Yes, here. The envelope was already labeled.\nA: In Germany they say Umschlag.\nB: True. Kuvert is more Austrian.",funFact:"Kuvert is the Austrian/Swiss word for envelope. In Germany, Briefumschlag (letter envelope) is standard. These DACH vocabulary differences appear on the Goethe exam, so learning all variants matters."},
{type:"teach",trg:"elektronisch",src:"electronic",pos:"adj",gender:null,note:"'Elektronische Post' = email (formal term).\n'Elektronische Geräte' = electronic devices.",example:"A: Ist das Formular elektronisch oder auf Papier?\nB: Elektronisch. Es wird digital ausgefüllt.\nA: Gut. Elektronische Dokumente werden schneller bearbeitet.\nB: Ja, die Digitalisierung hilft.",exampleSrc:"A: Is the form electronic or on paper?\nB: Electronic. It is filled out digitally.\nA: Good. Electronic documents are processed faster.\nB: Yes, digitalization helps.",funFact:"'Elektronische Post' is the formal German term for email. Nobody uses it in conversation (everyone says E-Mail), but it appears on government forms. German bureaucracy loves formal terms for modern technology."},
{type:"teach",trg:"waagerecht",src:"horizontal",pos:"adj",gender:null,note:"Waage (scale/balance) + recht (right/straight).\nOpposite: senkrecht (vertical). Used in crossword puzzles.",example:"A: Hängt das Regal waagerecht?\nB: Nein, es hängt etwas schief.\nA: Es muss waagerecht ausgerichtet werden.\nB: Ich brauche eine Wasserwaage.",exampleSrc:"A: Is the shelf hanging horizontally?\nB: No, it is hanging a bit crooked.\nA: It needs to be aligned horizontally.\nB: I need a spirit level.",funFact:"Waagerecht and senkrecht are the German crossword puzzle words: waagerecht = across, senkrecht = down. A Wasserwaage (water scale = spirit level) checks if something is perfectly waagerecht."},
{type:"teach",trg:"waagrecht",src:"horizontal (variant)",pos:"adj",gender:null,note:"Shorter variant of waagerecht. Both are correct.\nMore common in Austrian and Swiss German.",example:"A: Ist die Linie waagrecht?\nB: Ja, perfekt waagrecht.\nA: Waagrecht und waagerecht sind beide richtig?\nB: Ja, waagrecht ist die kürzere Form.",exampleSrc:"A: Is the line horizontal?\nB: Yes, perfectly horizontal.\nA: Waagrecht and waagerecht are both correct?\nB: Yes, waagrecht is the shorter form.",funFact:"Waagrecht is the shorter variant of waagerecht. Both are correct. Austrian German prefers waagrecht. The Goethe exam accepts both spellings."},
{type:"teach",trg:"innerhalb",src:"within, inside of",pos:"prep",gender:null,note:"Inner (inside) + halb (half/side). Takes Genitiv.\n'Innerhalb einer Woche' = within a week.",example:"A: Innerhalb des Betriebs gelten besondere Regeln.\nB: Welche Regeln?\nA: Zum Beispiel: Überstunden werden innerhalb eines Monats ausgeglichen.\nB: Das ist eine gute Regelung.",exampleSrc:"A: Within the company, special rules apply.\nB: Which rules?\nA: For example: overtime is compensated within a month.\nB: That is a good regulation.",funFact:"Innerhalb takes Genitiv: innerhalb des Gebäudes (within the building), innerhalb einer Woche (within a week). Its opposite is außerhalb (outside of). Both are essential for describing rules and boundaries."},
{type:"tip",title:"Feierabend: die heilige Grenze",text:"Feierabend heißt wörtlich 'Feier-Abend' (celebration evening).\nEs markiert das Ende der Arbeit und den Beginn der Freizeit.\n\nDeutsche nehmen diese Grenze ernst:\n- Arbeits-E-Mails nach Feierabend sind verpönt\n- Manche Firmen sperren E-Mail-Server nach 18 Uhr\n- Der Betriebsrat achtet auf die Einhaltung\n- Überstunden werden dokumentiert und kompensiert\n\nWork-Life-Balance ist kein Modewort in Deutschland.\nEs ist ein kultureller Wert, der gesetzlich geschützt wird.",deepDive:{title:"Das Arbeitszeitgesetz",text:"Das deutsche Arbeitszeitgesetz regelt:\n- Maximal 8 Stunden pro Tag (10 in Ausnahmen)\n- Mindestens 11 Stunden Ruhezeit zwischen Arbeitstagen\n- Sonntags- und Feiertagsruhe\n- Überstundenausgleich innerhalb von 6 Monaten\n\nDer Betriebsrat überwacht die Einhaltung.\nVerstöße können mit Bußgeldern bestraft werden.\n\nFeierabend ist nicht nur Tradition. Es ist Gesetz."}},
{type:"mc",q:"Warum besteht Mia darauf, dass Verumius um 17 Uhr geht?",opts:["Das Büro wird für Reparaturen geschlossen","Feierabend ist eine heilige Grenze zwischen Arbeit und Freizeit","Der Chef hat allen gesagt, sie sollen gehen","Sie will zum Abendessen gehen"],ans:"Feierabend ist eine heilige Grenze zwischen Arbeit und Freizeit",hint:"German work culture has strict boundaries between work and personal time."},
{type:"fb",s:"Überstunden {1} in Deutschland genau gezählt.",a:["werden"],opts:["werden","wurde","wird","worden"],hint:"Overtime hours (plural) ARE counted. Plural present passive.",sSrc:"Overtime hours are counted precisely in Germany."},
{type:"mc",q:"'Die Arbeit, ___ nicht erledigt wurde, wird morgen gemacht.' Welches Pronomen?",opts:["das","die","den","der"],ans:"die",hint:"Arbeit is feminine. It was NOT completed (subject of passive = Nominativ). Feminine Nominativ = die."},
{type:"fb",s:"Das neue Bürogebäude {1} letztes Jahr gebaut.",a:["wurde"],opts:["wurde","wird","werden","worden"],hint:"The building (singular) WAS built. Past passive.",sSrc:"The new office building was built last year."},
{type:"mc",q:"Welcher Satz kombiniert Relativsatz + Passiv Präsens korrekt?",opts:["Die Dokumente liegen im Ordner.","Die Dokumente werden jeden Tag kopiert.","Die Dokumente, die im Ordner liegen, sind alt.","Die Dokumente, die jeden Tag kopiert werden, liegen im Ordner."],ans:"Die Dokumente, die jeden Tag kopiert werden, liegen im Ordner.",hint:"Relative clause (die...) with present passive (kopiert werden) inside."},
{type:"drag_fill",s:"Der Bericht {1} morgen {2}. Heute ist {3}.",blanks:{"1":"wird","2":"geschrieben","3":"Feierabend"},pool:["wird","wurde","geschrieben","schreiben","Feierabend","Überstunde"],hint:"The report WILL BE written tomorrow (present passive). Today is end-of-work.",sSrc:"The report will be written tomorrow. Today is end of work."},
{type:"match",pairs:[{trg:"Feierabend",src:"end of workday"},{trg:"die Überstunde",src:"overtime hour"},{trg:"der Betriebsrat",src:"works council"},{trg:"der Tagesablauf",src:"daily routine"},{trg:"die Zusammenarbeit",src:"collaboration"}]},
{type:"mc",q:"'Der Computer wurde vom Hausmeister repariert.' Was verrät 'vom Hausmeister'?",opts:["Wo die Reparatur stattfand","Wann repariert wurde","Wer die Reparatur durchgeführt hat","Warum repariert wurde"],ans:"Wer die Reparatur durchgeführt hat",hint:"Von + Dativ in passive sentences reveals the agent: the person who did it."},
{type:"fb",s:"Die Kollegin, {1} wir zum Geburtstag gratuliert haben, war gerührt.",a:["der"],opts:["der","die","dem","den"],hint:"Kollegin is feminine. Gratulieren takes Dativ. Feminine Dativ = der.",sSrc:"The colleague whom we congratulated on her birthday was moved."},
{type:"mc",q:"'Der Hausmeister, dem das Werkzeug gehört, wurde gestern angerufen.' Wie viele Grammatik-Konstruktionen kommen vor?",opts:["Vier oder mehr","Drei: Relativsatz + Dativ + Passiv Präteritum","Zwei: Relativsatz + Passiv","Eine: nur Passiv"],ans:"Drei: Relativsatz + Dativ + Passiv Präteritum",hint:"Dem = datives Relativpronomen. Wurde angerufen = Passiv Präteritum. Alles in einem Satz."},
{type:"teach",trg:"befördern",src:"to promote, to transport",pos:"verb",gender:null,note:"Not separable. Be- + fördern (to support/advance).\n'Befördert werden' = to be promoted.",example:"A: Sie wurde zur Teamleiterin befördert.\nB: Das hat sie verdient!\nA: Wann wirst du befördert?\nB: Hoffentlich nächstes Jahr.",exampleSrc:"A: She was promoted to team leader.\nB: She deserved it!\nA: When will you be promoted?\nB: Hopefully next year.",funFact:"Befördern has two meanings: to promote (a person) and to transport (goods). Die Post befördert Briefe (the post transports letters). Der Chef befördert Mitarbeiter (the boss promotes employees)."},
{type:"drag_fill",s:"Die Mitarbeiterin, {1} die E-Mail {2} hat, {3} gestern {4}.",blanks:{"1":"die","2":"geschrieben","3":"wurde","4":"befördert"},pool:["die","der","geschrieben","schreiben","wurde","wird","befördert","befördern"],hint:"Feminine colleague WHO wrote the email (Nominativ). She WAS promoted (Passiv Präteritum).",sSrc:"The colleague who wrote the email was promoted yesterday."},
{type:"story",speaker:"narrator",mood:"warm",art:"de-ber-office-exit-sunset",trg:"Verumius verlässt das Büro. Die Sonne steht tief über Berlin. Sein erster Arbeitstag wurde gemeistert. Morgen wird er wissen, wo der Kopierer steht und wann Feierabend ist.",src:"Verumius leaves the office. The sun hangs low over Berlin. His first workday has been mastered. Tomorrow he will know where the copier is and when the workday ends."},
{type:"story",speaker:"mia",mood:"friendly",art:"de-ber-street-evening",trg:"Übrigens, nächste Woche fahren wir nach Hamburg. Eine Geschäftsreise. Du brauchst einen Anzug, der passt, und einen Koffer, der nicht zu groß ist.",src:"By the way, next week we are going to Hamburg. A business trip. You need a suit that fits and a suitcase that is not too big."},
{type:"mc",q:"Mia sagt 'einen Koffer, der nicht zu groß ist.' Welche Grammatik ist das?",opts:["Ein Passivsatz","Eine indirekte Frage","Ein Konditionalsatz","Ein Relativsatz, der den Koffer beschreibt"],ans:"Ein Relativsatz, der den Koffer beschreibt",hint:"'Der' refers back to Koffer and introduces a clause that describes it."},
{type:"fb",s:"Der erste Arbeitstag {1} erfolgreich gemeistert.",a:["wurde"],opts:["wurde","wird","werden","worden"],hint:"The first workday WAS successfully mastered. Past passive, singular.",sSrc:"The first workday was successfully mastered."},
{type:"match",pairs:[{trg:"die Abteilung",src:"department"},{trg:"die Besprechung",src:"meeting"},{trg:"der Kopierer",src:"copier"},{trg:"die Tastatur",src:"keyboard"},{trg:"Feierabend",src:"end of workday"}]},
{type:"drag_fill",s:"Morgen {1} der Bericht, {2} heute nicht fertig {3}, endlich geschrieben.",blanks:{"1":"wird","2":"der","3":"wurde"},pool:["wird","wurde","der","den","wurde","werden"],hint:"Tomorrow the report (wird, present passive) THAT today was not finished (der, masculine Nominativ relative; wurde, past passive) will finally be written.",sSrc:"Tomorrow the report that was not finished today will finally be written."}
]}

]},

{n:15,lang:"de",srcLang:"en",track:"v2",title:"Reise nach Hamburg",sub:"Business trip, genitive case, N-Deklination, regional differences",icon:"\uD83D\uDE84",level:"B1.1",color:"#7B5EE8",lessons:[

// ─── Lesson 1: "Moin, Hamburg!" ───────────────────────────────────────
{id:"deu_r15l1",title:"Moin, Hamburg!",icon:"\uD83C\uDF27\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Moin, Hamburg!",desc:"Verumius arrives in Hamburg for a business trip. Rain, red brick, and a greeting he has never heard before.",goals:["Learn travel and geography vocabulary","Hear your first genitive construction","Experience northern German culture","Understand regional greetings"]},
{type:"story",speaker:"narrator",mood:"descriptive",art:"de-ham-hauptbahnhof",trg:"Hamburg Hauptbahnhof. Regen, roter Backstein, der Geruch der Nordsee in der Luft. Alles hier ist anders als in Berlin.",src:"Hamburg Central Station. Rain, red brick, the smell of the North Sea in the air. Everything here is different from Berlin."},
{type:"story",speaker:"colleague",mood:"friendly",art:"de-ham-hauptbahnhof",trg:"Moin! Sie m\u00fcssen Herr Verumius sein. Willkommen in Hamburg!",src:"Moin! You must be Herr Verumius. Welcome to Hamburg!"},
{type:"story",speaker:"verumius",mood:"happy",art:"de-ham-hauptbahnhof",trg:"Hallo! Danke, dass Sie mich abholen. Was bedeutet 'Moin'?",src:"Hello! Thanks for picking me up. What does 'Moin' mean?"},
{type:"story",speaker:"colleague",mood:"amused",art:"de-ham-hauptbahnhof",trg:"Moin ist unser Hallo hier im Norden. Morgens, abends, immer: Moin!",src:"Moin is our Hello here in the north. Morning, evening, always: Moin!"},
{type:"teach",trg:"der Hauptbahnhof",src:"the main train station",pos:"noun",gender:"m",note:"Haupt (main) + Bahnhof (train station). Every major German city has one.",example:"A: Entschuldigung, wo ist der Hauptbahnhof?\nB: Geradeaus, dann links.\nA: Wie weit ist es?\nB: Etwa zehn Minuten zu Fu\u00df.",exampleSrc:"A: Excuse me, where is the main train station?\nB: Straight ahead, then left.\nA: How far is it?\nB: About ten minutes on foot.",funFact:"Hamburg Hauptbahnhof sees 550,000 travelers daily, making it one of Europe's busiest stations. It opened in 1906 and has been the heart of the city ever since."},
{type:"teach",trg:"der Hafen",src:"the harbor / port",pos:"noun",gender:"m",note:"Hamburg has the third-largest port in Europe. Related to English 'haven.'",example:"A: Wollen wir zum Hafen gehen?\nB: Ja, gern! Ich liebe den Hamburger Hafen.\nA: Kann man dort Schiffe sehen?\nB: Ja, riesige Containerschiffe!",exampleSrc:"A: Shall we go to the harbor?\nB: Yes, gladly! I love Hamburg's harbor.\nA: Can you see ships there?\nB: Yes, enormous container ships!",funFact:"Der Hafen shaped Hamburg's identity for over 800 years. The city is officially called 'Freie und Hansestadt Hamburg' (Free and Hanseatic City of Hamburg) because of its trading history."},
{type:"teach",trg:"die Region",src:"the region",pos:"noun",gender:"f",note:"Borrowed from Latin 'regio.' Germany has strong regional identities.",example:"A: Aus welcher Region kommen Sie?\nB: Ich komme aus der Region Hamburg.\nA: Das ist eine sch\u00f6ne Region.\nB: Ja, wir haben das Meer und die Stadt.",exampleSrc:"A: Which region are you from?\nB: I come from the Hamburg region.\nA: That is a beautiful region.\nB: Yes, we have the sea and the city.",funFact:"Germany has 16 Bundesl\u00e4nder (federal states), each with distinct dialects, food, and culture. A Hamburger and a M\u00fcnchner might as well be from different countries."},
{type:"teach",trg:"die Gegend",src:"the area / vicinity",pos:"noun",gender:"f",note:"From 'gegen' (against/toward). Less formal than Region.",example:"A: Kennen Sie die Gegend?\nB: Ja, ich wohne in dieser Gegend.\nA: Gibt es hier gute Restaurants?\nB: Ja, viele! Besonders am Hafen.",exampleSrc:"A: Do you know the area?\nB: Yes, I live in this area.\nA: Are there good restaurants here?\nB: Yes, many! Especially by the harbor.",funFact:"'In dieser Gegend' (in this area) is one of the most useful phrases for navigating a new city. It is more casual and conversational than 'Region.'"},
{type:"teach",trg:"das Gebiet",src:"the territory / area",pos:"noun",gender:"n",note:"More formal and official than Gegend. Used on signs and in official contexts.",example:"A: Dieses Gebiet ist ein Naturschutzgebiet.\nB: Darf man hier wandern?\nA: Ja, aber bleiben Sie auf den Wegen.\nB: Nat\u00fcrlich!",exampleSrc:"A: This area is a nature reserve.\nB: Can you hike here?\nA: Yes, but stay on the paths.\nB: Of course!",funFact:"Compound words with Gebiet are very common: Wohngebiet (residential area), Industriegebiet (industrial area), Stadtgebiet (city area). You see them on official signs everywhere."},
{type:"teach",trg:"der Nebel",src:"the fog",pos:"noun",gender:"m",note:"Same root as Latin 'nebula.' Hamburg is famous for fog and rain.",example:"A: Ich sehe nichts! Alles ist wei\u00df.\nB: Das ist der Nebel. Typisch Hamburg.\nA: Wie lange bleibt der Nebel?\nB: Manchmal den ganzen Tag.",exampleSrc:"A: I cannot see anything! Everything is white.\nB: That is the fog. Typical Hamburg.\nA: How long does the fog stay?\nB: Sometimes all day.",funFact:"'Nebel \u00fcber der Elbe' (fog over the Elbe) is practically Hamburg's motto. The city averages 52 foggy days per year."},
{type:"teach",trg:"die Richtung",src:"the direction",pos:"noun",gender:"f",note:"From 'richten' (to direct/align). You see it on every road sign.",example:"A: In welche Richtung muss ich gehen?\nB: In Richtung Hafen.\nA: Links oder rechts?\nB: Geradeaus, dann rechts.",exampleSrc:"A: In which direction do I need to go?\nB: In the direction of the harbor.\nA: Left or right?\nB: Straight, then right.",funFact:"'In Richtung' followed by a destination is how Germans give directions on highways and road signs. 'A7 in Richtung Hamburg' means the A7 toward Hamburg."},
{type:"teach",trg:"die Strecke",src:"the route / stretch",pos:"noun",gender:"f",note:"A defined path from A to B. Very common in train travel.",example:"A: Die Strecke Hamburg-Berlin ist sehr beliebt.\nB: Wie lange dauert die Fahrt?\nA: Etwa 1 Stunde 45 Minuten mit dem ICE.\nB: Das ist schnell!",exampleSrc:"A: The Hamburg-Berlin route is very popular.\nB: How long does the journey take?\nA: About 1 hour 45 minutes by ICE.\nB: That is fast!",funFact:"The Hamburg-Berlin Strecke was one of the first high-speed rail routes in Germany. ICE trains cover the 290 km in under two hours."},
{type:"teach",trg:"die Verbindung",src:"the connection",pos:"noun",gender:"f",note:"Ver- + Bindung (bond). On Deutsche Bahn, your specific train connection.",example:"A: Gibt es eine direkte Verbindung nach Hamburg?\nB: Ja, der ICE f\u00e4hrt direkt.\nA: Muss ich umsteigen?\nB: Nein, die Verbindung ist direkt.",exampleSrc:"A: Is there a direct connection to Hamburg?\nB: Yes, the ICE goes directly.\nA: Do I have to change trains?\nB: No, the connection is direct.",funFact:"On the Deutsche Bahn app, 'Verbindung suchen' (search for a connection) is the first button you press. Germans check Verbindungen obsessively when traveling."},
{type:"teach",trg:"die Station",src:"the station / stop",pos:"noun",gender:"f",note:"From Latin 'statio.' Used for subway stops and smaller stops.",example:"A: Wie viele Stationen sind es bis zum Hafen?\nB: Drei Stationen mit der U-Bahn.\nA: Welche Station muss ich nehmen?\nB: Station Landungsbr\u00fccken.",exampleSrc:"A: How many stations is it to the harbor?\nB: Three stations by subway.\nA: Which station do I need?\nB: Station Landungsbr\u00fccken.",funFact:"Hamburg's Landungsbr\u00fccken station is the gateway to the harbor. From there you can take ferry boats across the Elbe using a regular transit ticket."},
{type:"teach",trg:"die Linie",src:"the line",pos:"noun",gender:"f",note:"From Latin 'linea.' Used for transit routes.",example:"A: Welche Linie f\u00e4hrt zum Hauptbahnhof?\nB: Nehmen Sie die Linie U3.\nA: Wie oft f\u00e4hrt die Linie?\nB: Alle f\u00fcnf Minuten.",exampleSrc:"A: Which line goes to the main station?\nB: Take Line U3.\nA: How often does the line run?\nB: Every five minutes.",funFact:"Germans are precise: not just 'take the subway' but 'take Linie 3.' Hamburg's U3 is famous for its above-ground section with harbor views."},
{type:"teach",trg:"die Metropole",src:"the metropolis",pos:"noun",gender:"f",note:"From Greek 'metropolis' (mother city). Hamburg is Germany's second-largest.",example:"A: Hamburg ist eine echte Metropole.\nB: Ja, fast zwei Millionen Einwohner.\nA: Gr\u00f6\u00dfer als M\u00fcnchen?\nB: Ja, die zweitgr\u00f6\u00dfte Stadt Deutschlands.",exampleSrc:"A: Hamburg is a real metropolis.\nB: Yes, almost two million inhabitants.\nA: Bigger than Munich?\nB: Yes, Germany's second-largest city.",funFact:"With 1.9 million people, Hamburg is Germany's second city after Berlin. It has more bridges than Venice, Amsterdam, and London combined: over 2,500."},
{type:"teach",trg:"die Nordsee",src:"the North Sea",pos:"noun",gender:"f",note:"Nord + See (sea). Bordered by Germany, the Netherlands, Denmark, Norway, and the UK.",example:"A: Kann man von Hamburg die Nordsee sehen?\nB: Nicht direkt. Hamburg liegt an der Elbe.\nA: Wie weit ist die Nordsee?\nB: Etwa 100 Kilometer.",exampleSrc:"A: Can you see the North Sea from Hamburg?\nB: Not directly. Hamburg is on the Elbe.\nA: How far is the North Sea?\nB: About 100 kilometers.",funFact:"Hamburg sits on the Elbe river, 100 km from the Nordsee. But you can smell the salt in the air on windy days. The Nordsee shaped the city's trading identity."},
{type:"teach",trg:"die Ostsee",src:"the Baltic Sea",pos:"noun",gender:"f",note:"Ost (east) + See (sea). Germans call it 'East Sea' while most languages call it 'Baltic.'",example:"A: Warst du schon an der Ostsee?\nB: Ja, letzten Sommer.\nA: Ist das Wasser kalt?\nB: K\u00e4lter als die Nordsee!",exampleSrc:"A: Have you been to the Baltic Sea?\nB: Yes, last summer.\nA: Is the water cold?\nB: Colder than the North Sea!",funFact:"Germans call it the 'Ostsee' (East Sea) while English and most languages use 'Baltic.' Same sea, different perspective. Popular vacation destination for northern Germans."},
{type:"teach",trg:"die Nacht",src:"the night",pos:"noun",gender:"f",note:"Same root as English 'night' and Latin 'nox.'",example:"A: Gute Nacht!\nB: Gute Nacht! Schlaf gut.\nA: Bis morgen.\nB: Bis morgen!",exampleSrc:"A: Good night!\nB: Good night! Sleep well.\nA: See you tomorrow.\nB: See you tomorrow!",funFact:"Hamburg's Reeperbahn is famous for its Nachtleben (nightlife). The street in the St. Pauli district has been called 'the most sinful mile' since the 1960s."},
{type:"teach",trg:"feucht",src:"damp / humid",pos:"adj",gender:null,note:"Hamburg in one word. Not 'nass' (wet), not 'trocken' (dry), but in-between.",example:"A: Warum ist alles so feucht hier?\nB: Das ist Hamburg! Immer feucht.\nA: Brauche ich einen Regenschirm?\nB: Immer. Jeden Tag.",exampleSrc:"A: Why is everything so damp here?\nB: That is Hamburg! Always damp.\nA: Do I need an umbrella?\nB: Always. Every day.",funFact:"Related to English 'damp' via Proto-Germanic. Hamburg's maritime climate means feuchte Luft (humid air) year-round. Locals just accept it."},
{type:"teach",trg:"nah",src:"near / close",pos:"adj",gender:null,note:"Comparative: n\u00e4her (nearer). Superlative: am n\u00e4chsten (nearest).",example:"A: Ist der Hafen nah?\nB: Ja, sehr nah. Nur zehn Minuten.\nA: Kann man zu Fu\u00df gehen?\nB: Ja, das ist die n\u00e4chste Stra\u00dfe.",exampleSrc:"A: Is the harbor near?\nB: Yes, very near. Only ten minutes.\nA: Can you walk there?\nB: Yes, it is the next street.",funFact:"'Nah' and 'nahe' are both used, but in different grammatical slots. 'Der Hafen ist nah' (predicative) vs. 'nahe dem Hafen' (prepositional)."},
{type:"teach",trg:"nahe",src:"near (preposition/adverb form)",pos:"prep",gender:null,note:"Slightly more literary than 'nah.' Takes dative: 'nahe dem Hafen.'",example:"A: Das Hotel liegt nahe dem Hauptbahnhof.\nB: Sehr praktisch!\nA: Ja, alles ist nahe.\nB: Perfekt f\u00fcr eine kurze Gesch\u00e4ftsreise.",exampleSrc:"A: The hotel is near the main train station.\nB: Very practical!\nA: Yes, everything is nearby.\nB: Perfect for a short business trip.",funFact:"'Nahe' as a preposition takes dative: 'nahe dem Hafen.' As an adverb, it works like 'nah.' Both forms trace back to the same Proto-Germanic root."},
{type:"mc",q:"A colleague greets Verumius in Hamburg. What does 'Moin' mean?",opts:["Thank you","Good morning only","Goodbye","Hello (northern German greeting)"],ans:"Hello (northern German greeting)",hint:"This greeting works at any time of day in northern Germany."},
{type:"mc",q:"Hamburg liegt an der Elbe, nahe der ...",opts:["Ostsee","Alpen","Donau","Nordsee"],ans:"Nordsee",hint:"Hamburg faces northwest, toward the sea between Germany and England."},
{type:"fb",s:"Die {1} Hamburg-Berlin dauert etwa zwei Stunden.",a:["Strecke"],opts:["Strecke","Station","Linie","Richtung"],hint:"Which word describes a defined route between two cities?",sSrc:"The Hamburg-Berlin route takes about two hours."}
]},

// ─── Lesson 2: "Unterwegs in der Stadt" ───────────────────────────────
{id:"deu_r15l2",title:"Unterwegs in der Stadt",icon:"\uD83D\uDE8B",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs in der Stadt",desc:"Master urban transport vocabulary. Learn road and traffic terms. Navigate a German city like a local.",goals:["Learn 20 transport and urban vocabulary words","Understand compound noun gender rules","Navigate Hamburg's streets and transit"]},
{type:"teach",trg:"die U-Bahn",src:"the subway",pos:"noun",gender:"f",note:"Untergrund (underground) + Bahn (railway). The yellow U sign is iconic.",example:"A: Wie komme ich zum Hafen?\nB: Nehmen Sie die U-Bahn.\nA: Welche Linie?\nB: Die U3 bis Landungsbr\u00fccken.",exampleSrc:"A: How do I get to the harbor?\nB: Take the subway.\nA: Which line?\nB: The U3 to Landungsbr\u00fccken.",funFact:"Hamburg's U-Bahn opened in 1912. Berlin, Munich, Hamburg, and Nuremberg all have U-Bahn systems. The yellow U sign marks every entrance."},
{type:"teach",trg:"die Tram",src:"the streetcar / tram",pos:"noun",gender:"f",note:"Short for 'Trambahn.' Most German cities have tram networks.",example:"A: F\u00e4hrt hier eine Tram?\nB: Nein, Hamburg hat keine Tram mehr.\nA: Wirklich? Warum nicht?\nB: Die Stadt hat sie 1978 abgeschafft.",exampleSrc:"A: Does a tram run here?\nB: No, Hamburg no longer has a tram.\nA: Really? Why not?\nB: The city removed them in 1978.",funFact:"Hamburg actually removed its trams in 1978, but most German cities kept theirs. Berlin has one of Europe's largest tram networks with over 190 km of track."},
{type:"teach",trg:"die F\u00e4hre",src:"the ferry",pos:"noun",gender:"f",note:"From 'fahren' (to travel). Hamburg's harbor ferries are part of public transport.",example:"A: Kann man mit der F\u00e4hre fahren?\nB: Ja! Die F\u00e4hre geh\u00f6rt zum HVV.\nA: Brauche ich ein extra Ticket?\nB: Nein, Ihr normales Ticket reicht.",exampleSrc:"A: Can you take the ferry?\nB: Yes! The ferry is part of the HVV.\nA: Do I need an extra ticket?\nB: No, your normal ticket is enough.",funFact:"Hamburg's harbor ferries are part of the public transport system (HVV). You can ride them with a normal transit ticket, making them the cheapest harbor tour in the city."},
{type:"teach",trg:"die Eisenbahn",src:"the railway",pos:"noun",gender:"f",note:"Eisen (iron) + Bahn (track). Literally 'iron track.'",example:"A: Die Eisenbahn ist in Deutschland sehr wichtig.\nB: Ja, viele Menschen fahren mit der Bahn.\nA: Seit wann gibt es die Eisenbahn?\nB: Seit 1835 in Deutschland.",exampleSrc:"A: The railway is very important in Germany.\nB: Yes, many people travel by train.\nA: Since when has the railway existed?\nB: Since 1835 in Germany.",funFact:"The first German Eisenbahn ran in 1835 between N\u00fcrnberg and F\u00fcrth, just 6 km. Today Germany has over 33,000 km of track."},
{type:"teach",trg:"das Fahrzeug",src:"the vehicle",pos:"noun",gender:"n",note:"Fahr (drive) + Zeug (stuff/thing). Literally 'driving-thing.'",example:"A: Was f\u00fcr ein Fahrzeug haben Sie?\nB: Ich habe ein kleines Auto.\nA: In Hamburg braucht man kein Fahrzeug.\nB: Stimmt, die U-Bahn reicht.",exampleSrc:"A: What kind of vehicle do you have?\nB: I have a small car.\nA: In Hamburg you do not need a vehicle.\nB: True, the subway is enough.",funFact:"The Zeug pattern is productive: Fahrzeug (vehicle), Flugzeug (airplane = flying-thing), Werkzeug (tool = work-thing), Spielzeug (toy = play-thing). Gender always comes from the last element."},
{type:"teach",trg:"das Motorrad",src:"the motorcycle",pos:"noun",gender:"n",note:"Motor + Rad (wheel). Germany is the birthplace of the motorcycle.",example:"A: F\u00e4hrst du Motorrad?\nB: Ja, im Sommer. Im Winter ist es zu kalt.\nA: Ist es gef\u00e4hrlich?\nB: Nur wenn man nicht aufpasst.",exampleSrc:"A: Do you ride a motorcycle?\nB: Yes, in summer. In winter it is too cold.\nA: Is it dangerous?\nB: Only if you do not pay attention.",funFact:"Gottlieb Daimler built the first motorcycle in 1885 in Bad Cannstatt, Germany. Today Germany has over 4 million registered motorcycles."},
{type:"teach",trg:"das Kraftfahrzeug",src:"the motor vehicle",pos:"noun",gender:"n",note:"Kraft (power) + Fahrzeug (vehicle). Abbreviated KFZ. On every vehicle registration.",example:"A: Was ist ein Kraftfahrzeug?\nB: Jedes Fahrzeug mit Motor.\nA: Also Auto, Motorrad, LKW?\nB: Genau. Alles mit Motor ist ein KFZ.",exampleSrc:"A: What is a Kraftfahrzeug?\nB: Any vehicle with an engine.\nA: So car, motorcycle, truck?\nB: Exactly. Everything with an engine is a KFZ.",funFact:"KFZ is one of Germany's most common abbreviations. 'KFZ-Versicherung' (vehicle insurance) and 'KFZ-Zulassungsstelle' (vehicle registration office) are words every German driver knows."},
{type:"teach",trg:"die Fahrbahn",src:"the roadway / carriageway",pos:"noun",gender:"f",note:"Fahr (drive) + Bahn (track). The actual surface where vehicles drive.",example:"A: Bleiben Sie auf der Fahrbahn!\nB: Ich bin Radfahrer. Wo soll ich fahren?\nA: Auf dem Radweg, nicht auf der Fahrbahn.\nB: Oh, Entschuldigung!",exampleSrc:"A: Stay on the roadway!\nB: I am a cyclist. Where should I ride?\nA: On the bike path, not on the roadway.\nB: Oh, sorry!",funFact:"In Germany, the Fahrbahn is strictly for motor vehicles. Cyclists use the Radweg (bike path) and pedestrians use the Gehsteig (sidewalk). Mixing them up is frowned upon."},
{type:"teach",trg:"die Einbahnstra\u00dfe",src:"the one-way street",pos:"noun",gender:"f",note:"Ein (one) + Bahn (track) + Stra\u00dfe (street). Common in old town centers.",example:"A: Kann ich hier rechts fahren?\nB: Nein, das ist eine Einbahnstra\u00dfe!\nA: In welche Richtung?\nB: Nur nach links.",exampleSrc:"A: Can I turn right here?\nB: No, that is a one-way street!\nA: In which direction?\nB: Only to the left.",funFact:"German old town centers are full of Einbahnstra\u00dfen. The blue sign with a white arrow marks them. Tourists often learn this word the hard way."},
{type:"teach",trg:"die Einfahrt",src:"the entry / entrance (for vehicles)",pos:"noun",gender:"f",note:"Ein (in) + Fahrt (drive). On garage doors: 'Einfahrt freihalten!'",example:"A: Wo ist die Einfahrt zum Parkhaus?\nB: Die n\u00e4chste Stra\u00dfe rechts.\nA: Ist die Einfahrt breit genug?\nB: Ja, kein Problem.",exampleSrc:"A: Where is the entrance to the parking garage?\nB: The next street on the right.\nA: Is the entrance wide enough?\nB: Yes, no problem.",funFact:"'Einfahrt freihalten!' (Keep entrance clear!) is one of the most common signs on German garage doors. Germans take this very seriously."},
{type:"teach",trg:"die Ausfahrt",src:"the exit (for vehicles)",pos:"noun",gender:"f",note:"Aus (out) + Fahrt (drive). On the Autobahn, every exit has a number.",example:"A: Welche Ausfahrt m\u00fcssen wir nehmen?\nB: Ausfahrt 23: Hamburg-Harburg.\nA: Wie weit ist das noch?\nB: Noch zehn Kilometer.",exampleSrc:"A: Which exit do we need to take?\nB: Exit 23: Hamburg-Harburg.\nA: How far is that?\nB: Ten more kilometers.",funFact:"Every tourist giggles at how often they see 'Ausfahrt' on the Autobahn. It just means 'exit,' but it sounds exotic when you cannot read German yet."},
{type:"teach",trg:"der Fu\u00dfg\u00e4nger",src:"the pedestrian (male)",pos:"noun",gender:"m",note:"Fu\u00df (foot) + G\u00e4nger (goer). Germany has strict pedestrian rules.",example:"A: Hier d\u00fcrfen nur Fu\u00dfg\u00e4nger gehen.\nB: Keine Autos?\nA: Nein, das ist eine Fu\u00dfg\u00e4ngerzone.\nB: Sehr angenehm!",exampleSrc:"A: Only pedestrians may walk here.\nB: No cars?\nA: No, this is a pedestrian zone.\nB: Very pleasant!",funFact:"Jaywalking is frowned upon in Germany. Crossing on red earns you disapproving looks, especially from parents with children. In Switzerland, the sidewalk is called 'Trottoir' (from French)."},
{type:"teach",trg:"die Fu\u00dfg\u00e4ngerin",src:"the pedestrian (female)",pos:"noun",gender:"f",note:"Feminine form of Fu\u00dfg\u00e4nger. The -in suffix for feminine persons.",example:"A: Die Fu\u00dfg\u00e4ngerin wartet an der Ampel.\nB: Sehr vorbildlich!\nA: In Hamburg warten alle bei Rot.\nB: Das ist typisch norddeutsch.",exampleSrc:"A: The pedestrian is waiting at the traffic light.\nB: Very exemplary!\nA: In Hamburg everyone waits at red.\nB: That is typically northern German.",funFact:"The -in suffix for feminine persons is consistent: Lehrer/Lehrerin, Fahrer/Fahrerin, Fu\u00dfg\u00e4nger/Fu\u00dfg\u00e4ngerin. It is one of German's most productive patterns."},
{type:"teach",trg:"die Fu\u00dfg\u00e4ngerzone",src:"the pedestrian zone",pos:"noun",gender:"f",note:"Fu\u00dfg\u00e4nger + Zone. No cars, only people, shops, and cafes.",example:"A: Gibt es in Hamburg eine Fu\u00dfg\u00e4ngerzone?\nB: Ja, die M\u00f6nckebergstra\u00dfe.\nA: Kann man dort einkaufen?\nB: Ja, viele Gesch\u00e4fte und Kaufh\u00e4user.",exampleSrc:"A: Is there a pedestrian zone in Hamburg?\nB: Yes, M\u00f6nckebergstra\u00dfe.\nA: Can you shop there?\nB: Yes, many shops and department stores.",funFact:"Every German city center has a Fu\u00dfg\u00e4ngerzone. Hamburg's M\u00f6nckebergstra\u00dfe is one of the city's main shopping streets."},
{type:"teach",trg:"der Radfahrer",src:"the cyclist (male)",pos:"noun",gender:"m",note:"Rad (wheel/bicycle) + Fahrer (driver). Germany has excellent cycling infrastructure.",example:"A: Vorsicht, ein Radfahrer!\nB: Wo? Ich sehe ihn nicht.\nA: Auf dem Radweg links.\nB: Oh ja, danke!",exampleSrc:"A: Watch out, a cyclist!\nB: Where? I do not see him.\nA: On the bike path to the left.\nB: Oh yes, thanks!",funFact:"Germany has excellent cycling infrastructure. In Switzerland, a bicycle is called 'Velo' (from French v\u00e9locip\u00e8de), not 'Fahrrad.'"},
{type:"teach",trg:"die Radfahrerin",src:"the cyclist (female)",pos:"noun",gender:"f",note:"Feminine cyclist. Same -in pattern.",example:"A: Die Radfahrerin f\u00e4hrt sehr schnell.\nB: Ja, in Hamburg sind viele Radfahrerinnen unterwegs.\nA: Gibt es gute Radwege?\nB: Ja, die Stadt investiert viel in Radwege.",exampleSrc:"A: The cyclist is riding very fast.\nB: Yes, many cyclists are out and about in Hamburg.\nA: Are there good bike paths?\nB: Yes, the city invests a lot in bike paths.",funFact:"Hamburg is investing heavily in cycling infrastructure with the 'Velorouten' network, connecting the city's neighborhoods with dedicated bike highways."},
{type:"teach",trg:"die Zone",src:"the zone",pos:"noun",gender:"f",note:"From Greek 'zone' (belt/girdle). Very versatile word in German.",example:"A: Wir fahren in Zone A.\nB: Brauchen wir ein anderes Ticket f\u00fcr Zone B?\nA: Ja, ein Erweiterungsticket.\nB: Das ist kompliziert!",exampleSrc:"A: We are traveling in Zone A.\nB: Do we need a different ticket for Zone B?\nA: Yes, an extension ticket.\nB: That is complicated!",funFact:"'Umweltzone' (low-emission zone) covers most German city centers. Only vehicles with a green sticker may enter. 'Zeitzone' = time zone. A versatile word."},
{type:"teach",trg:"die Spur",src:"the lane / track / trace",pos:"noun",gender:"f",note:"Also means 'trace' or 'clue' in detective stories.",example:"A: Bleiben Sie auf der rechten Spur.\nB: Warum?\nA: Die linke Spur ist nur zum \u00dcberholen.\nB: Ah, wie auf der Autobahn.",exampleSrc:"A: Stay in the right lane.\nB: Why?\nA: The left lane is only for passing.\nB: Ah, like on the Autobahn.",funFact:"On the Autobahn, 'die rechte Spur' (right lane) is for normal driving, 'die linke Spur' (left lane) is for overtaking only. Germans take this rule very seriously."},
{type:"teach",trg:"die Kurve",src:"the curve / bend",pos:"noun",gender:"f",note:"Related to English 'curve' via Latin 'curvus.'",example:"A: Vorsicht, scharfe Kurve!\nB: Ich fahre langsam.\nA: Diese Kurven sind gef\u00e4hrlich bei Regen.\nB: Ja, die Stra\u00dfe ist glatt.",exampleSrc:"A: Caution, sharp curve!\nB: I am driving slowly.\nA: These curves are dangerous in the rain.\nB: Yes, the road is slippery.",funFact:"On mountain roads, you see 'Vorsicht, scharfe Kurve!' (Caution, sharp curve!) constantly. The word also works figuratively: 'die Kurve kriegen' = to get it together."},
{type:"teach",trg:"die Lage",src:"the location / situation",pos:"noun",gender:"f",note:"Context determines meaning: 'location' or 'situation.'",example:"A: Die Lage des Hotels ist perfekt.\nB: Ja, direkt am Hafen.\nA: Und die politische Lage?\nB: Das ist eine andere Frage!",exampleSrc:"A: The location of the hotel is perfect.\nB: Yes, right on the harbor.\nA: And the political situation?\nB: That is a different question!",funFact:"'Die Lage des Hotels' (the location of the hotel) sneaks in a genitive construction. You will learn this case formally in the next lesson."},
{type:"mc",q:"Kraftfahrzeug is made of Kraft + Fahrzeug. What does Kraft mean?",opts:["Power","New","Big","Fast"],ans:"Power",hint:"KFZ is a ___-vehicle. What does that first element contribute?"},
{type:"fb",s:"In der Hamburger Innenstadt gibt es eine gro\u00dfe {1}.",a:["Fu\u00dfg\u00e4ngerzone"],opts:["Fu\u00dfg\u00e4ngerzone","Einbahnstra\u00dfe","Ausfahrt","Fahrbahn"],hint:"A zone where only pedestrians walk, no cars allowed.",sSrc:"In Hamburg's city center there is a large pedestrian zone."},
{type:"match",pairs:[{trg:"U-Bahn",src:"subway"},{trg:"F\u00e4hre",src:"ferry"},{trg:"Eisenbahn",src:"railway"},{trg:"Motorrad",src:"motorcycle"},{trg:"Tram",src:"streetcar"}]},
{type:"mc",q:"Das Kraft-FAHRZEUG. Why is it 'das'?",opts:["The last element (Zeug/Fahrzeug) is neuter","Kraft is neuter","Long words are always neuter","All transport words are neuter"],ans:"The last element (Zeug/Fahrzeug) is neuter",hint:"In German compounds, the last element determines the article."},
{type:"drag_fill",s:"Nehmen Sie die n\u00e4chste {1} auf der rechten {2}.",blanks:{"1":"Ausfahrt","2":"Spur"},pool:["Ausfahrt","Spur","Einfahrt","Kurve","Linie","Zone"],hint:"Take the next exit on the right lane. Two road/highway terms.",sSrc:"Take the next exit on the right lane."}
]},

// ─── Lesson 3: "Herr Professor Doktor Schmidt" ───────────────────────
{id:"deu_r15l3",title:"Herr Professor Doktor Schmidt",icon:"\uD83D\uDC54",xp:15,board:true,steps:[
{type:"intro",title:"Herr Professor Doktor Schmidt",desc:"Navigate a formal German meeting. Learn the genitive case: 'des Mannes, der Frau.' Understand German title culture.",goals:["Master building and location vocabulary","Learn the genitive case","Navigate professional introductions","Understand German title culture"]},
{type:"story",speaker:"narrator",mood:"formal",art:"de-ham-office",trg:"Das B\u00fcro des Unternehmens liegt direkt am Hafen. Durch die Fenster sieht Verumius die Kr\u00e4ne der Hafenstadt.",src:"The company's office is right on the harbor. Through the windows, Verumius sees the cranes of the harbor city."},
{type:"story",speaker:"colleague",mood:"formal",art:"de-ham-office",trg:"Darf ich vorstellen? Das ist Herr Professor Doktor Schmidt, der Leiter der Abteilung.",src:"May I introduce? This is Herr Professor Doktor Schmidt, the head of the department."},
{type:"story",speaker:"verumius",mood:"nervous",art:"de-ham-office",trg:"Guten Tag, Herr Professor Doktor Schmidt. Es ist mir eine Ehre.",src:"Good day, Herr Professor Doktor Schmidt. It is an honor."},
{type:"story",speaker:"colleague",mood:"amused",art:"de-ham-office",trg:"In Hamburg sagen wir alle Titel. Der Name des Kollegen ist wichtig, aber die Titel sind heilig!",src:"In Hamburg we say all titles. The colleague's name is important, but the titles are sacred!"},
{type:"teach",trg:"das Geb\u00e4ude",src:"the building",pos:"noun",gender:"n",note:"From 'bauen' (to build). The Ge- prefix creates a collective noun.",example:"A: Was f\u00fcr ein Geb\u00e4ude ist das?\nB: Das ist die Elbphilharmonie.\nA: Ein beeindruckendes Geb\u00e4ude!\nB: Ja, das ber\u00fchmteste Geb\u00e4ude Hamburgs.",exampleSrc:"A: What kind of building is that?\nB: That is the Elbphilharmonie.\nA: An impressive building!\nB: Yes, Hamburg's most famous building.",funFact:"The Ge- prefix creates collective nouns: Geb\u00e4ude (building), Gep\u00e4ck (luggage), Gebirge (mountain range). The Elbphilharmonie is Hamburg's most famous Geb\u00e4ude."},
{type:"teach",trg:"der Turm",src:"the tower",pos:"noun",gender:"m",note:"From Latin 'turris.' Hamburg's Michel (St. Michaelis) is the city's landmark.",example:"A: Sehen Sie den Turm dort?\nB: Ja, das ist der Michel.\nA: Wie hoch ist er?\nB: 132 Meter. Man kann hinaufsteigen.",exampleSrc:"A: Do you see the tower there?\nB: Yes, that is the Michel.\nA: How tall is it?\nB: 132 meters. You can climb up.",funFact:"Hamburg's Michel (St. Michaelis church tower) is the city's landmark. Berlin's Fernsehturm (TV tower) is 368 m tall. The word Turm is related to English 'tower.'"},
{type:"teach",trg:"der Hof",src:"the courtyard / yard / farm",pos:"noun",gender:"m",note:"One of German's most productive compound elements.",example:"A: Der Hof des Geb\u00e4udes ist wundersch\u00f6n.\nB: Ja, mit B\u00e4umen und einer Bank.\nA: Haben alle Geb\u00e4ude einen Hof?\nB: Viele Altbauten, ja.",exampleSrc:"A: The courtyard of the building is beautiful.\nB: Yes, with trees and a bench.\nA: Do all buildings have a courtyard?\nB: Many old buildings, yes.",funFact:"'Hof' appears in many compounds: Bahnhof (train yard), Bauernhof (farm), Innenhof (inner courtyard), Friedhof (peace-yard = cemetery). One root, endless compounds."},
{type:"teach",trg:"der Vorort",src:"the suburb",pos:"noun",gender:"m",note:"Vor (before/in front of) + Ort (place). Literally 'fore-place.'",example:"A: Wohnen Sie in Hamburg?\nB: Nein, in einem Vorort.\nA: Ist es weit zur Arbeit?\nB: Nein, nur 20 Minuten mit der S-Bahn.",exampleSrc:"A: Do you live in Hamburg?\nB: No, in a suburb.\nA: Is it far to work?\nB: No, only 20 minutes by commuter rail.",funFact:"Hamburg's Vororte stretch far along the Elbe. German suburbs feel different from American ones: denser, with better public transport and local bakeries."},
{type:"teach",trg:"das Ufer",src:"the bank / shore (of a river)",pos:"noun",gender:"n",note:"Related to English 'over' via Proto-Germanic.",example:"A: Gehen wir am Ufer der Elbe spazieren?\nB: Gute Idee! Das Ufer ist hier sehr sch\u00f6n.\nA: Kann man dort sitzen?\nB: Ja, es gibt B\u00e4nke am Ufer.",exampleSrc:"A: Shall we walk along the bank of the Elbe?\nB: Good idea! The shore is very beautiful here.\nA: Can you sit there?\nB: Yes, there are benches on the bank.",funFact:"Hamburg's HafenCity neighborhood sits on the Ufer der Elbe. 'Am Ufer' (on the bank) is one of the most scenic phrases in Hamburg's vocabulary."},
{type:"teach",trg:"die K\u00fcste",src:"the coast",pos:"noun",gender:"f",note:"From Latin 'costa' (rib/side). Famous for Wattwanderung (mudflat hiking).",example:"A: Waren Sie schon an der K\u00fcste?\nB: Ja, an der Nordseek\u00fcste.\nA: Wie ist es dort?\nB: Windig und wundersch\u00f6n!",exampleSrc:"A: Have you been to the coast?\nB: Yes, to the North Sea coast.\nA: What is it like there?\nB: Windy and beautiful!",funFact:"The German North Sea coast is famous for Wattwanderung (mudflat hiking). At low tide, you can walk kilometers into the sea. UNESCO World Heritage since 2009."},
{type:"teach",trg:"der Ozean",src:"the ocean",pos:"noun",gender:"m",note:"From Greek 'Okeanos.' Hamburg's connection to the Atlantic made it great.",example:"A: Der Atlantische Ozean ist nicht weit von Hamburg.\nB: Naja, die Nordsee ist n\u00e4her.\nA: Die Nordsee ist Teil des Ozeans.\nB: Stimmt!",exampleSrc:"A: The Atlantic Ocean is not far from Hamburg.\nB: Well, the North Sea is closer.\nA: The North Sea is part of the ocean.\nB: True!",funFact:"Hamburg's connection to the Atlantic via the Elbe made it one of Europe's greatest trading cities. The word '\u00dcbersee' (overseas) is deeply woven into Hamburg's identity."},
{type:"teach",trg:"die Distanz",src:"the distance (formal)",pos:"noun",gender:"f",note:"From Latin 'distantia.' More formal than 'Entfernung.'",example:"A: Die Distanz zwischen Hamburg und Berlin betr\u00e4gt 290 km.\nB: Das ist nicht weit.\nA: Mit dem ICE nur 1:45.\nB: Sehr praktisch.",exampleSrc:"A: The distance between Hamburg and Berlin is 290 km.\nB: That is not far.\nA: By ICE only 1:45.\nB: Very practical.",funFact:"Distanz is used in professional and scientific contexts. For everyday speech, Germans prefer Entfernung."},
{type:"teach",trg:"die Entfernung",src:"the distance (everyday)",pos:"noun",gender:"f",note:"From 'entfernen' (to remove/move away). More everyday than Distanz.",example:"A: Wie gro\u00df ist die Entfernung zum Hafen?\nB: Etwa zwei Kilometer.\nA: Kann man zu Fu\u00df gehen?\nB: Ja, ein sch\u00f6ner Spaziergang.",exampleSrc:"A: What is the distance to the harbor?\nB: About two kilometers.\nA: Can you walk?\nB: Yes, a nice walk.",funFact:"Entfernung comes from ent- (away) + fernen (from fern = far). 'In kurzer Entfernung' = at a short distance. More common in daily speech than Distanz."},
{type:"teach",trg:"st\u00e4dtisch",src:"urban / municipal",pos:"adj",gender:null,note:"From 'Stadt' (city). The adjective form of Stadt.",example:"A: Gibt es st\u00e4dtische Busse?\nB: Ja, der st\u00e4dtische Nahverkehr ist gut.\nA: Wie hei\u00dft das Unternehmen?\nB: HVV, der Hamburger Verkehrsverbund.",exampleSrc:"A: Are there municipal buses?\nB: Yes, the municipal public transport is good.\nA: What is the company called?\nB: HVV, the Hamburg Transport Association.",funFact:"Hamburg's st\u00e4dtische character differs sharply from rural Schleswig-Holstein just north of the city. The urban-rural contrast is one of Germany's defining features."},
{type:"teach",trg:"regional",src:"regional",pos:"adj",gender:null,note:"Same as English. Pronounced 'ray-gee-oh-NAHL.'",example:"A: Gibt es regionale Unterschiede?\nB: Ja, viele! Sprache, Essen, Kultur.\nA: Zum Beispiel?\nB: In Hamburg sagt man 'Moin', in Bayern 'Gr\u00fc\u00df Gott.'",exampleSrc:"A: Are there regional differences?\nB: Yes, many! Language, food, culture.\nA: For example?\nB: In Hamburg they say 'Moin', in Bavaria 'Gr\u00fc\u00df Gott.'",funFact:"Germany's regional diversity is one of its defining features. From greetings to bread rolls to humor: every Region has its own flavor."},
{type:"teach",trg:"der Passagier",src:"the passenger (male)",pos:"noun",gender:"m",note:"From French 'passager.' Used for ship, plane, and train passengers.",example:"A: Wie viele Passagiere hat das Schiff?\nB: \u00dcber 3.000 Passagiere.\nA: Das ist ein riesiges Schiff!\nB: Ja, ein Kreuzfahrtschiff.",exampleSrc:"A: How many passengers does the ship have?\nB: Over 3,000 passengers.\nA: That is an enormous ship!\nB: Yes, a cruise ship.",funFact:"In Switzerland, the train platform is called 'Perron' (from French), not 'Bahnsteig.' Swiss German has many French loanwords."},
{type:"teach",trg:"die Passagierin",src:"the passenger (female)",pos:"noun",gender:"f",note:"Feminine form. The -in suffix applies to all person-nouns.",example:"A: Die Passagierin hat ihr Gep\u00e4ck vergessen.\nB: Im Zug?\nA: Ja, im Speisewagen.\nB: Sie sollte das Fundb\u00fcro anrufen.",exampleSrc:"A: The passenger forgot her luggage.\nB: On the train?\nA: Yes, in the dining car.\nB: She should call the lost and found.",funFact:"The Passagier/Passagierin pair follows the same -in pattern as Fahrer/Fahrerin. Consistent and productive."},
{type:"teach",trg:"der Steward",src:"the steward (male)",pos:"noun",gender:"m",note:"Borrowed from English. Used for male flight attendants and ship stewards.",example:"A: Der Steward bringt das Essen.\nB: Auf dem Schiff?\nA: Ja, auf dem Kreuzfahrtschiff.\nB: Wie nett!",exampleSrc:"A: The steward is bringing the food.\nB: On the ship?\nA: Yes, on the cruise ship.\nB: How nice!",funFact:"Borrowed from English but pronounced with a German R. Used on ships and planes. Increasingly replaced by gender-neutral alternatives in modern German."},
{type:"teach",trg:"die Stewardess",src:"the stewardess / flight attendant (female)",pos:"noun",gender:"f",note:"From English. Increasingly replaced by 'Flugbegleiterin.'",example:"A: Die Stewardess erkl\u00e4rt die Sicherheitsregeln.\nB: Wie sagt man das modern?\nA: Flugbegleiterin.\nB: Das klingt professioneller.",exampleSrc:"A: The stewardess is explaining the safety rules.\nB: What is the modern term?\nA: Flugbegleiterin (flight companion).\nB: That sounds more professional.",funFact:"'Flugbegleiterin' (flight companion, feminine) is the modern replacement for Stewardess. The shift reflects German's ongoing effort to modernize gendered job titles."},
{type:"teach",trg:"der Laster",src:"the truck",pos:"noun",gender:"m",note:"Short for 'Lastkraftwagen' (LKW). Everyday word for truck.",example:"A: Ein gro\u00dfer Laster blockiert die Stra\u00dfe.\nB: Das passiert oft in Hamburg.\nA: Wegen des Hafens?\nB: Ja, viele Laster fahren zum Hafen.",exampleSrc:"A: A large truck is blocking the street.\nB: That happens often in Hamburg.\nA: Because of the harbor?\nB: Yes, many trucks drive to the harbor.",funFact:"The formal term is LKW (Lastkraftwagen), but everyone says Laster in everyday speech. On the Autobahn, Laster have a speed limit of 80 km/h."},
{type:"teach",trg:"der Transport",src:"the transport",pos:"noun",gender:"m",note:"From Latin 'transportare.' Hamburg handles 130 million tons of cargo annually.",example:"A: Der Transport der Waren dauert drei Tage.\nB: Von wo?\nA: Vom Hamburger Hafen nach Berlin.\nB: Das ist schnell.",exampleSrc:"A: The transport of the goods takes three days.\nB: From where?\nA: From Hamburg's harbor to Berlin.\nB: That is fast.",funFact:"Hamburg's port handles 130 million tons of cargo annually. '\u00d6ffentlicher Nahverkehr' (public transit) is more common than '\u00f6ffentlicher Transport' in everyday German."},
{type:"teach",trg:"transportieren",src:"to transport",pos:"verb",gender:null,note:"Regular verb with the -ieren ending from French/Latin.",example:"A: Die Schiffe transportieren Waren aus aller Welt.\nB: Was f\u00fcr Waren?\nA: Alles: Autos, Elektronik, Lebensmittel.\nB: Der Hamburger Hafen ist riesig.",exampleSrc:"A: The ships transport goods from around the world.\nB: What kind of goods?\nA: Everything: cars, electronics, food.\nB: Hamburg's harbor is enormous.",funFact:"Verbs ending in -ieren (transportieren, organisieren, telefonieren) are always regular and never get ge- in the past participle: transportiert, not getransportiert."},
{type:"teach",trg:"dicht",src:"dense / thick / tight",pos:"adj",gender:null,note:"'Dichter Nebel' = thick fog. Also slang for 'drunk' (informal).",example:"A: Der Nebel ist heute sehr dicht.\nB: Ja, man kann kaum etwas sehen.\nA: Typisch Hamburg!\nB: Dichter Nebel, feuchte Luft.",exampleSrc:"A: The fog is very thick today.\nB: Yes, you can barely see anything.\nA: Typical Hamburg!\nB: Thick fog, damp air.",funFact:"'Dicht besiedelt' (densely populated) describes Hamburg's inner city. The word also means 'tight' (a container is dicht) and, in slang, 'drunk.'"},
{type:"teach",trg:"der Tourismus",src:"the tourism",pos:"noun",gender:"m",note:"From French/English. The -ismus suffix marks abstract concepts, always masculine.",example:"A: Der Tourismus ist wichtig f\u00fcr Hamburg.\nB: Wie viele Touristen kommen pro Jahr?\nA: \u00dcber 15 Millionen \u00dcbernachtungen.\nB: Beeindruckend!",exampleSrc:"A: Tourism is important for Hamburg.\nB: How many tourists come per year?\nA: Over 15 million overnight stays.\nB: Impressive!",funFact:"The -ismus suffix is always masculine: Tourismus, Kapitalismus, Optimismus. It marks abstract concepts borrowed through Latin/French/English."},
{type:"tip",title:"The genitive case: showing possession",text:"In English, you say 'the man's book' or 'the book of the man.' German uses the genitive case.\n\nMasculine/neuter: change the article to 'des' and add -(e)s to the noun.\nFeminine/plural: change the article to 'der,' noun stays the same.\n\nMaskulin: der Mann becomes des Mannes (of the man)\nFeminin: die Frau becomes der Frau (of the woman)\nNeutral: das Kind becomes des Kindes (of the child)\nPlural: die Kinder becomes der Kinder (of the children)\n\nExamples from the story:\n'der Leiter der Abteilung' = the head of the department\n'der Name des Kollegen' = the colleague's name\n'die Atmosph\u00e4re des Hafens' = the atmosphere of the harbor",deepDive:{title:"Genitive in everyday speech",text:"In casual speech, many Germans avoid genitive and use 'von + dative' instead:\n'das Buch von dem Mann' instead of 'das Buch des Mannes.'\nBut in writing, professional contexts, and with prepositions like 'w\u00e4hrend,' genitive is essential. Northern Germany (Hamburg!) uses genitive more than southern Germany.\n\nOne-syllable nouns get -es: des Mannes, des Kindes.\nMulti-syllable nouns get just -s: des Hafens, des Geb\u00e4udes."}},
{type:"verb_table",title:"Der Genitiv: Artikel und Endungen",groups:[{label:"Bestimmter Artikel (definite)",rows:[{pronoun:"maskulin",form:"des Mannes",src:"of the man"},{pronoun:"feminin",form:"der Frau",src:"of the woman"},{pronoun:"neutral",form:"des Kindes",src:"of the child"},{pronoun:"Plural",form:"der Kinder",src:"of the children"}]},{label:"Unbestimmter Artikel (indefinite)",rows:[{pronoun:"maskulin",form:"eines Mannes",src:"of a man"},{pronoun:"feminin",form:"einer Frau",src:"of a woman"},{pronoun:"neutral",form:"eines Kindes",src:"of a child"}]}],note:"Masculine and neuter: des/eines + noun + -(e)s. Feminine and plural: der + noun unchanged.",deepDive:{title:"Eigennamen im Genitiv: Peters Auto",text:"Zwei Wege, Besitz auszudrücken:\n\n1. Name + s: Peters Auto = Peter's car. KEIN Apostroph!\n2. Artikel-Genitiv: das Auto des Mannes.\n\nNie mischen: Des Peters Auto (falsch). Peters Auto (richtig).\n\nDer 'Deppenapostroph': Peter's Auto ist grammatisch falsch.\nDeutscher Genitiv-s kommt OHNE Apostroph.\n\nAusnahme: Namen auf -s, -x, -z nutzen Apostroph:\nMax' Auto, Hans' Buch (oder: das Auto von Max)\n\nDas gilt auch für Ortsnamen: Berlins Museen, Hamburgs Hafen."}},
{type:"mc",q:"'Der Leiter DER Abteilung.' What does 'der' signal here?",opts:["Accusative: the department","Genitive: of the department (feminine)","Dative: to the department","Nominative: the department"],ans:"Genitive: of the department (feminine)",hint:"Abteilung is feminine. In genitive, feminine 'die' becomes 'der.'"},
{type:"mc",q:"How do you say 'the atmosphere of the harbor'?",opts:["die Atmosph\u00e4re des Hafens","die Atmosph\u00e4re den Hafen","die Atmosph\u00e4re der Hafen","die Atmosph\u00e4re dem Hafen"],ans:"die Atmosph\u00e4re des Hafens",hint:"Hafen is masculine. Masculine genitive: des + noun + -(e)s."},
{type:"fb",s:"Der Name {1} Kollegen ist Schmidt.",a:["des"],opts:["des","der","dem","den"],hint:"Kollege is masculine. Which genitive article goes with masculine nouns?",sSrc:"The colleague's name is Schmidt."}
]},

// ─── Lesson 4: "Der Genitiv und die N-Deklination" ──────────────────
{id:"deu_r15l4",title:"Der Genitiv und die N-Deklination",icon:"\uD83D\uDCDD",xp:15,board:true,steps:[
{type:"intro",title:"Der Genitiv und die N-Deklination",desc:"Master genitive case formation. Learn N-Deklination nouns (der Herr, der Kollege, der Junge). Understand German traffic and driving vocabulary.",goals:["Practice genitive case formation","Learn N-Deklination noun patterns","Master traffic and driving vocabulary","Combine genitive with N-Deklination"]},
{type:"teach",trg:"der Gegenstand",src:"the object / item",pos:"noun",gender:"m",note:"Gegen (against) + Stand (standing). Something you encounter.",example:"A: Haben Sie pers\u00f6nliche Gegenst\u00e4nde dabei?\nB: Ja, meinen Laptop und mein Handy.\nA: Bitte lassen Sie keine Gegenst\u00e4nde im Zug.\nB: Nat\u00fcrlich.",exampleSrc:"A: Do you have personal belongings with you?\nB: Yes, my laptop and my phone.\nA: Please do not leave any items on the train.\nB: Of course.",funFact:"'Pers\u00f6nliche Gegenst\u00e4nde' (personal belongings) is an announcement you hear on every German train. The word literally means 'against-standing' thing."},
{type:"teach",trg:"der Geschmack",src:"the taste / flavor",pos:"noun",gender:"m",note:"From 'schmecken' (to taste). Also means aesthetic sense.",example:"A: Wie ist der Geschmack?\nB: Sehr gut! Salzig und frisch.\nA: Hamburg hat guten Geschmack beim Essen.\nB: Besonders beim Fisch!",exampleSrc:"A: How is the taste?\nB: Very good! Salty and fresh.\nA: Hamburg has good taste in food.\nB: Especially with fish!",funFact:"'Guter Geschmack' means both good taste in food AND good aesthetic sense. 'Geschmacklos' (tasteless) works the same way: bad-tasting or tacky."},
{type:"teach",trg:"die Geschwindigkeit",src:"the speed",pos:"noun",gender:"f",note:"From 'geschwind' (swift). A famously long word at 17 letters.",example:"A: Wie hoch ist die Geschwindigkeit des ICE?\nB: Bis zu 300 km/h.\nA: Das ist schnell!\nB: Ja, die schnellste Verbindung.",exampleSrc:"A: How fast is the ICE?\nB: Up to 300 km/h.\nA: That is fast!\nB: Yes, the fastest connection.",funFact:"On the Autobahn, sections without speed limit are marked 'Keine Geschwindigkeitsbegrenzung.' This word alone is 30 characters of German compound mastery."},
{type:"teach",trg:"die Geschwindigkeitsbeschr\u00e4nkung",src:"the speed limit",pos:"noun",gender:"f",note:"Geschwindigkeit + Beschr\u00e4nkung (restriction). 30 characters long.",example:"A: Gibt es hier eine Geschwindigkeitsbeschr\u00e4nkung?\nB: Ja, Tempo 50.\nA: Und auf der Autobahn?\nB: Manchmal keine!",exampleSrc:"A: Is there a speed limit here?\nB: Yes, 50 km/h.\nA: And on the Autobahn?\nB: Sometimes none!",funFact:"This is the word that makes German famous for long compounds. Posted as road signs: '50' in a red circle. Most Germans just say 'Tempolimit' in conversation."},
{type:"teach",trg:"die Reservierung",src:"the reservation",pos:"noun",gender:"f",note:"From 'reservieren.' The -ung suffix is always feminine.",example:"A: Haben Sie eine Reservierung?\nB: Ja, auf den Namen Verumius.\nA: F\u00fcr zwei Personen?\nB: Ja, genau.",exampleSrc:"A: Do you have a reservation?\nB: Yes, under the name Verumius.\nA: For two people?\nB: Yes, exactly.",funFact:"'Haben Sie eine Reservierung?' is what every hotel and restaurant asks. For trains, you pay extra for a 'Sitzplatzreservierung' (seat reservation)."},
{type:"teach",trg:"die R\u00fcckfahrt",src:"the return trip",pos:"noun",gender:"f",note:"R\u00fcck (back) + Fahrt (journey). 'Hin- und R\u00fcckfahrt' = round trip.",example:"A: Wann ist die R\u00fcckfahrt?\nB: Morgen Abend.\nA: Haben Sie ein Ticket f\u00fcr die R\u00fcckfahrt?\nB: Ja, eine Hin- und R\u00fcckfahrt.",exampleSrc:"A: When is the return trip?\nB: Tomorrow evening.\nA: Do you have a ticket for the return?\nB: Yes, a round trip.",funFact:"On train tickets, 'einfach' means one way and 'hin und zur\u00fcck' means round trip. The R\u00fcckfahrt is always the homeward leg."},
{type:"teach",trg:"die Rundfahrt",src:"the tour / sightseeing trip",pos:"noun",gender:"f",note:"Rund (round) + Fahrt (journey). Hamburg's Hafenrundfahrt is iconic.",example:"A: Machen wir eine Rundfahrt?\nB: Ja, eine Hafenrundfahrt!\nA: Wie lange dauert die Rundfahrt?\nB: Etwa eine Stunde.",exampleSrc:"A: Shall we do a tour?\nB: Yes, a harbor tour!\nA: How long does the tour take?\nB: About one hour.",funFact:"Hamburg's Hafenrundfahrt (harbor tour) is the city's most popular tourist activity. Small boats navigate between enormous container ships."},
{type:"teach",trg:"die Umleitung",src:"the detour",pos:"noun",gender:"f",note:"Um (around) + Leitung (leading). Yellow signs guide you around construction.",example:"A: Die Stra\u00dfe ist gesperrt!\nB: Es gibt eine Umleitung.\nA: Wohin f\u00fchrt die Umleitung?\nB: Folgen Sie den gelben Schildern.",exampleSrc:"A: The road is closed!\nB: There is a detour.\nA: Where does the detour lead?\nB: Follow the yellow signs.",funFact:"On German roads, the yellow 'Umleitung' signs guide you around construction. Germans trust these signs completely, even when the detour seems absurdly long."},
{type:"teach",trg:"der Umtausch",src:"the exchange / return (of goods)",pos:"noun",gender:"m",note:"Um (exchange) + Tausch (swap). Standard retail policy.",example:"A: Ich m\u00f6chte einen Umtausch machen.\nB: Haben Sie den Kassenbon?\nA: Ja, hier.\nB: Kein Problem. Was m\u00f6chten Sie umtauschen?",exampleSrc:"A: I would like to make an exchange.\nB: Do you have the receipt?\nA: Yes, here.\nB: No problem. What would you like to exchange?",funFact:"'Umtausch nur mit Kassenbon' (exchange only with receipt) is the standard policy in German retail. No receipt, no exchange, no exceptions."},
{type:"teach",trg:"die Vorfahrt",src:"the right of way",pos:"noun",gender:"f",note:"Vor (before) + Fahrt (driving). The yellow diamond sign means you have it.",example:"A: Wer hat hier Vorfahrt?\nB: Das Schild sagt: Vorfahrt beachten!\nA: Also muss ich warten?\nB: Ja, der andere Fahrer hat Vorfahrt.",exampleSrc:"A: Who has right of way here?\nB: The sign says: Yield!\nA: So I have to wait?\nB: Yes, the other driver has right of way.",funFact:"'Vorfahrt beachten!' (Yield!) is one of the most important road signs. The yellow diamond sign means you have Vorfahrt. Critical for driving in Germany."},
{type:"teach",trg:"der Halt",src:"the stop",pos:"noun",gender:"m",note:"From 'halten' (to stop/hold). On buses and trains: 'N\u00e4chster Halt...'",example:"A: N\u00e4chster Halt: Jungfernstieg.\nB: Das ist unsere Station!\nA: Schnell, wir m\u00fcssen aussteigen.\nB: Ich komme!",exampleSrc:"A: Next stop: Jungfernstieg.\nB: That is our station!\nA: Quick, we have to get off.\nB: I am coming!",funFact:"'N\u00e4chster Halt' (next stop) is the phrase you hear most on German public transport. Also: 'Halt! Stehenbleiben!' in action movies."},
{type:"teach",trg:"der Stau",src:"the traffic jam",pos:"noun",gender:"m",note:"Germany's Autobahn: famous for no speed limit AND epic traffic jams.",example:"A: Es gibt einen langen Stau auf der A7.\nB: Wie lange m\u00fcssen wir warten?\nA: Vielleicht eine Stunde.\nB: Dann nehmen wir die Umleitung.",exampleSrc:"A: There is a long traffic jam on the A7.\nB: How long do we have to wait?\nA: Maybe an hour.\nB: Then let us take the detour.",funFact:"'Im Stau stehen' (to be stuck in a traffic jam) is a German national experience. The ADAC (German automobile club) reports Stau updates constantly, especially on holiday weekends."},
{type:"teach",trg:"die Tankstelle",src:"the gas station",pos:"noun",gender:"f",note:"Tank + Stelle (place). Also convenience stores. Open late.",example:"A: Wir m\u00fcssen tanken.\nB: Wo ist die n\u00e4chste Tankstelle?\nA: In zwei Kilometern.\nB: Gut, wir haben noch genug Benzin.",exampleSrc:"A: We need to refuel.\nB: Where is the nearest gas station?\nA: In two kilometers.\nB: Good, we still have enough gasoline.",funFact:"German Tankstellen are also convenience stores. After 8 PM, they are often the only shops open. 'Tanken' = to refuel. 'Volltanken' = fill it up."},
{type:"teach",trg:"die Panne",src:"the breakdown",pos:"noun",gender:"f",note:"Also used metaphorically: 'Das war eine Panne' = That was a blunder.",example:"A: Wir haben eine Panne!\nB: Was ist passiert?\nA: Der Reifen ist platt.\nB: Rufen Sie den ADAC an!",exampleSrc:"A: We have a breakdown!\nB: What happened?\nA: The tire is flat.\nB: Call the ADAC!",funFact:"'Eine Panne haben' works for both car breakdowns and embarrassing blunders. From French 'panne.' The ADAC is Germany's roadside assistance, like AAA."},
{type:"teach",trg:"das Tempo",src:"the speed / pace",pos:"noun",gender:"n",note:"From Italian 'tempo.' 'Tempo 30' means a 30 km/h zone.",example:"A: Hier ist Tempo 30.\nB: Warum so langsam?\nA: Das ist ein Wohngebiet.\nB: Ach so, wegen der Kinder.",exampleSrc:"A: This is a 30 km/h zone.\nB: Why so slow?\nA: This is a residential area.\nB: I see, because of the children.",funFact:"'Tempo' is also a famous German tissue brand. 'Tempo' is to tissues what Kleenex is in the US. Asking for a 'Tempo' in Germany means asking for a tissue."},
{type:"teach",trg:"der Salon",src:"the salon",pos:"noun",gender:"m",note:"From French 'salon.' 'Friseursalon' = hair salon.",example:"A: Wo ist der Friseursalon?\nB: In der n\u00e4chsten Stra\u00dfe.\nA: Brauche ich einen Termin?\nB: Nein, einfach hingehen.",exampleSrc:"A: Where is the hair salon?\nB: In the next street.\nA: Do I need an appointment?\nB: No, just go there.",funFact:"The word retained its French pronunciation in German. 'Friseursalon' (hair salon), 'Kosmetiksalon' (beauty salon), 'Nagelsalon' (nail salon). All from French."},
{type:"teach",trg:"eilen",src:"to hurry",pos:"verb",gender:null,note:"'Eilt!' on documents means 'Urgent!' Related to English 'zeal.'",example:"A: Wir m\u00fcssen eilen!\nB: Warum?\nA: Das Meeting beginnt in f\u00fcnf Minuten.\nB: Dann los!",exampleSrc:"A: We have to hurry!\nB: Why?\nA: The meeting starts in five minutes.\nB: Then let's go!",funFact:"'Es eilt' (it is urgent) appears on official documents. Related to English 'zeal' via Proto-Germanic. 'Eilzustellung' = express delivery."},
{type:"teach",trg:"stoppen",src:"to stop",pos:"verb",gender:null,note:"From English 'stop.' Regular verb. Also used in sports timing.",example:"A: Stoppen Sie das Auto!\nB: Warum? Was ist passiert?\nA: Eine rote Ampel!\nB: Oh, danke! Ich habe sie nicht gesehen.",exampleSrc:"A: Stop the car!\nB: Why? What happened?\nA: A red light!\nA: Oh, thanks! I did not see it.",funFact:"'Die Zeit stoppen' means to time something with a stopwatch. 'Stopp!' as an interjection means 'Hold on!' or 'Wait!'"},
{type:"tip",title:"N-Deklination: the special masculine nouns",text:"Some masculine nouns add -(e)n in EVERY case except nominative. These are N-Deklination nouns.\n\nCommon N-Deklination nouns:\nder Herr, der Kollege, der Junge, der Kunde, der Name, der Student, der Patient, der Nachbar\n\nNominativ: der Herr / der Kollege\nAkkusativ: den Herrn / den Kollegen\nDativ: dem Herrn / dem Kollegen\nGenitiv: des Herrn / des Kollegen\n\nHow to spot them:\n- Masculine nouns ending in -e (Kollege, Junge, Kunde)\n- Endings: -ent (Student, Patient), -ant (Praktikant), -ist (Tourist)\n- The word Herr\n\nFrom the story: 'dem Herrn Kollegen' uses BOTH N-Deklination nouns in dative!",deepDive:{title:"Why N-Deklination exists",text:"N-Deklination is a remnant of Old German weak noun declension. These nouns were originally 'weak' masculine nouns that took -n in all oblique cases. Over centuries, most nouns lost this pattern, but about 200 common ones kept it.\n\nThe key rule: if you are not sure whether a masculine noun is N-Deklination, check if it ends in -e. Most masculine nouns ending in -e (der Junge, der Kollege, der Kunde, der Nachbar) are N-Deklination."}},
{type:"verb_table",title:"N-Deklination: der Kollege",groups:[{label:"Singular",rows:[{pronoun:"Nominativ",form:"der Kollege",src:"the colleague (subject)"},{pronoun:"Akkusativ",form:"den Kollegen",src:"the colleague (direct object)"},{pronoun:"Dativ",form:"dem Kollegen",src:"to the colleague"},{pronoun:"Genitiv",form:"des Kollegen",src:"of the colleague"}]},{label:"Vergleich: der Herr",rows:[{pronoun:"Nominativ",form:"der Herr",src:"the gentleman"},{pronoun:"Akkusativ",form:"den Herrn",src:"the gentleman (direct object)"},{pronoun:"Dativ",form:"dem Herrn",src:"to the gentleman"},{pronoun:"Genitiv",form:"des Herrn",src:"of the gentleman"}]}],note:"N-Deklination nouns add -(e)n in every case except nominative. Herr adds just -n, Kollege adds -n."},
{type:"mc",q:"'Die Lage DES Hafens.' Why is it 'des Hafens'?",opts:["Hafen is masculine. Genitive masculine: des + -(e)s","Hafen is neuter. Genitive: des","Hafen is in dative","Des is always used before H"],ans:"Hafen is masculine. Genitive masculine: des + -(e)s",hint:"Masculine and neuter genitive both use 'des' and add -(e)s to the noun."},
{type:"mc",q:"'Die Geschwindigkeit DER F\u00e4hre.' Which case is 'der'?",opts:["Nominative masculine: the ferry","Dative feminine: to the ferry","Accusative: the ferry","Genitive feminine: of the ferry"],ans:"Genitive feminine: of the ferry",hint:"F\u00e4hre is feminine. In genitive, die becomes der."},
{type:"fb",s:"Ich stelle Ihnen den {1} vor.",a:["Kollegen"],opts:["Kollegen","Kollege","Kolleges","Kolleg"],hint:"Kollege is an N-Deklination noun. In accusative, it adds -n.",sSrc:"I am introducing the colleague to you."},
{type:"mc",q:"'Der Name DES ... .' How does 'Herr' look in genitive?",opts:["des Herres","des Herren","des Herrs","des Herrn"],ans:"des Herrn",hint:"Herr is N-Deklination. It adds -n in every case except nominative."},
{type:"drag_fill",s:"Der Titel {1} {2} ist sehr lang.",blanks:{"1":"des","2":"Kollegen"},pool:["des","der","dem","Kollegen","Kollege","Kolleges"],hint:"Kollege is masculine AND N-Deklination. Genitive masculine article + N-Dekl ending.",sSrc:"The colleague's title is very long."},
{type:"match",pairs:[{trg:"des Mannes",src:"of the man"},{trg:"der Frau",src:"of the woman"},{trg:"des Kindes",src:"of the child"},{trg:"der Kinder",src:"of the children"},{trg:"des Kollegen",src:"of the colleague"}]},
{type:"mc",q:"Auf der Autobahn gibt es einen langen ...",opts:["Umtausch","Stau","Salon","Halt"],ans:"Stau",hint:"What forms when too many cars are on the road at once?"}
]},

// ─── Lesson 5: "Hamburger K\u00fcche" ─────────────────────────────────────
{id:"deu_r15l5",title:"Hamburger K\u00fcche",icon:"\uD83C\uDF5C",xp:15,board:true,steps:[
{type:"intro",title:"Hamburger K\u00fcche",desc:"Master food and restaurant vocabulary. Practice genitive case in real contexts. Discover regional food differences across Germany.",goals:["Learn 20 food and restaurant vocabulary words","Practice genitive case in food contexts","Discover regional food differences","Order food in a German restaurant"]},
{type:"teach",trg:"die Speise",src:"the dish / food",pos:"noun",gender:"f",note:"Formal and slightly old-fashioned. 'Speisekarte' = menu card.",example:"A: Welche Speisen empfehlen Sie?\nB: Die Fischspeisen sind ausgezeichnet.\nA: Haben Sie auch vegetarische Speisen?\nB: Ja, auf Seite zwei der Speisekarte.",exampleSrc:"A: Which dishes do you recommend?\nB: The fish dishes are excellent.\nA: Do you also have vegetarian dishes?\nB: Yes, on page two of the menu.",funFact:"'Speisekarte' (menu card), 'Speisesaal' (dining hall), 'Speisewagen' (dining car). The word Speise appears everywhere in formal dining contexts."},
{type:"teach",trg:"der Speisewagen",src:"the dining car",pos:"noun",gender:"m",note:"Speise + Wagen (wagon/car). Hot coffee and Currywurst at 250 km/h.",example:"A: Gibt es einen Speisewagen im Zug?\nB: Ja, in Wagen 7.\nA: Kann man dort fr\u00fchst\u00fccken?\nB: Ja, Kaffee und Br\u00f6tchen.",exampleSrc:"A: Is there a dining car on the train?\nB: Yes, in car 7.\nA: Can you have breakfast there?\nB: Yes, coffee and rolls.",funFact:"ICE trains have a 'Bordrestaurant' (on-board restaurant), but older trains called it Speisewagen. Hot coffee at 250 km/h is one of Germany's small luxuries."},
{type:"teach",trg:"die Vorspeise",src:"the appetizer / starter",pos:"noun",gender:"f",note:"Vor (before) + Speise (dish). The dish before the main dish.",example:"A: M\u00f6chten Sie eine Vorspeise?\nB: Ja, die Suppe bitte.\nA: Gute Wahl. Und als Hauptgericht?\nB: Den Braten.",exampleSrc:"A: Would you like an appetizer?\nB: Yes, the soup please.\nA: Good choice. And for the main course?\nB: The roast.",funFact:"German restaurant menus list in order: Vorspeise (starter), Hauptgericht (main course), Nachspeise (dessert). The Vor/Nach pattern makes it logical."},
{type:"teach",trg:"die Nachspeise",src:"the dessert",pos:"noun",gender:"f",note:"Nach (after) + Speise (dish). The after-dish.",example:"A: Was haben Sie als Nachspeise?\nB: Rote Gr\u00fctze mit Sahne.\nA: Was ist Rote Gr\u00fctze?\nB: Ein norddeutsches Dessert mit roten Fr\u00fcchten.",exampleSrc:"A: What do you have for dessert?\nB: Rote Gr\u00fctze with cream.\nA: What is Rote Gr\u00fctze?\nB: A northern German dessert with red berries.",funFact:"German compound logic: before = Vor-, after = Nach-. Vorspeise/Nachspeise, Vorname/Nachname, Vormittag/Nachmittag. Crystal clear pattern."},
{type:"teach",trg:"das Dessert",src:"the dessert (French loan)",pos:"noun",gender:"n",note:"From French 'desservir' (to clear the table). More cosmopolitan than Nachspeise.",example:"A: Zum Dessert nehme ich das Eis.\nB: Schokolade oder Vanille?\nA: Schokolade, bitte.\nB: Ausgezeichnete Wahl!",exampleSrc:"A: For dessert I will have the ice cream.\nB: Chocolate or vanilla?\nA: Chocolate, please.\nB: Excellent choice!",funFact:"On upscale Hamburg menus, you see 'Dessert.' In a traditional Kneipe, it is 'Nachspeise.' The word choice signals the restaurant's formality level."},
{type:"teach",trg:"das Men\u00fc",src:"the set meal",pos:"noun",gender:"n",note:"In German, Men\u00fc means a SET MEAL, NOT the card listing dishes. The card is 'Speisekarte.'",example:"A: Wir nehmen das Men\u00fc.\nB: Das Tagesmen\u00fc mit drei G\u00e4ngen?\nA: Ja, Vorspeise, Hauptgericht und Nachspeise.\nB: Perfekt. Kommt sofort.",exampleSrc:"A: We will take the set meal.\nB: The daily menu with three courses?\nA: Yes, appetizer, main course and dessert.\nB: Perfect. Coming right up.",funFact:"Das Men\u00fc means a set meal (starter + main + dessert), NOT the card listing dishes. The card is 'Speisekarte.' This false friend catches many English speakers."},
{type:"teach",trg:"der Braten",src:"the roast",pos:"noun",gender:"m",note:"Every region has its signature Braten: Schweinebraten, Sauerbraten.",example:"A: Ich nehme den Braten.\nB: Schweinebraten oder Rinderbraten?\nA: Schweinebraten, bitte.\nB: Mit Kn\u00f6deln und Kraut?",exampleSrc:"A: I will have the roast.\nB: Pork roast or beef roast?\nA: Pork roast, please.\nB: With dumplings and cabbage?",funFact:"'Schweinebraten' (pork roast) is Bavaria's national dish. 'Sauerbraten' (marinated pot roast) comes from the Rhineland. Every region has its signature Braten."},
{type:"teach",trg:"das Hackfleisch",src:"the ground meat",pos:"noun",gender:"n",note:"Hack (chopped) + Fleisch (meat). In northern Germany also called 'Mett.'",example:"A: Ich brauche 500 Gramm Hackfleisch.\nB: Vom Rind oder gemischt?\nA: Gemischt, bitte.\nB: Machen Sie Frikadellen?",exampleSrc:"A: I need 500 grams of ground meat.\nB: Beef or mixed?\nA: Mixed, please.\nB: Are you making meatballs?",funFact:"In northern Germany (Hamburg!), raw ground pork on bread is called 'Mettbr\u00f6tchen.' In Austria, ground meat is called 'Faschiertes.' Same product, different countries."},
{type:"teach",trg:"das H\u00fchnchen",src:"the chicken",pos:"noun",gender:"n",note:"Diminutive of 'Huhn.' The -chen suffix makes it neuter AND small/cute.",example:"A: Ein halbes H\u00fchnchen, bitte.\nB: Mit Pommes?\nA: Ja, und Salat dazu.\nB: Kommt sofort!",exampleSrc:"A: Half a chicken, please.\nB: With fries?\nA: Yes, and salad on the side.\nB: Coming right up!",funFact:"The -chen suffix always makes nouns neuter: das M\u00e4dchen (the girl), das H\u00fchnchen (the chicken), das Br\u00f6tchen (the bread roll). Every German supermarket rotisserie has Brath\u00e4hnchen."},
{type:"teach",trg:"das Gew\u00fcrz",src:"the spice",pos:"noun",gender:"n",note:"From 'W\u00fcrze' (seasoning). Plural: Gew\u00fcrze.",example:"A: Welche Gew\u00fcrze m\u00f6gen Sie?\nB: Pfeffer und Paprika.\nA: Hamburg war eine Gew\u00fcrzhandelsstadt.\nB: Stimmt, wegen des Hafens.",exampleSrc:"A: Which spices do you like?\nB: Pepper and paprika.\nA: Hamburg was a spice trading city.\nB: True, because of the harbor.",funFact:"Hamburg's Speicherstadt (warehouse district) stored spices from around the world for centuries. The Gew\u00fcrzmuseum (spice museum) is still there today."},
{type:"teach",trg:"der Essig",src:"the vinegar",pos:"noun",gender:"m",note:"From Latin 'acetum.' Germans love Essig on salad.",example:"A: Essig und \u00d6l f\u00fcr den Salat?\nB: Ja, bitte. Mehr Essig als \u00d6l.\nA: Sie m\u00f6gen es sauer?\nB: Ja, sehr!",exampleSrc:"A: Vinegar and oil for the salad?\nB: Yes, please. More vinegar than oil.\nA: You like it sour?\nB: Yes, very!",funFact:"'Essig und \u00d6l' (vinegar and oil) is the standard German salad dressing. Also: 'Es ist Essig!' (slang: It is over/ruined!). A versatile word."},
{type:"teach",trg:"der Honig",src:"the honey",pos:"noun",gender:"m",note:"From Proto-Germanic '*hunagaz.' Related to English 'honey.'",example:"A: M\u00f6chten Sie Honig aufs Brot?\nB: Ja, gern! Ist das lokaler Honig?\nA: Ja, vom Imker nebenan.\nB: Lecker!",exampleSrc:"A: Would you like honey on your bread?\nB: Yes, gladly! Is that local honey?\nA: Yes, from the beekeeper next door.\nB: Delicious!",funFact:"German breakfast often includes Honig on bread. 'Honigkuchen' (honey cake) is a Christmas specialty. Germany is Europe's largest honey consumer."},
{type:"teach",trg:"die So\u00dfe",src:"the sauce",pos:"noun",gender:"f",note:"From French 'sauce.' Written with \u00df in German (no c).",example:"A: Die So\u00dfe ist ausgezeichnet!\nB: Danke! Das ist unsere Hausspezialit\u00e4t.\nA: Was ist drin?\nB: Das ist ein Geheimnis!",exampleSrc:"A: The sauce is excellent!\nB: Thanks! That is our house specialty.\nA: What is in it?\nB: That is a secret!",funFact:"'Bratenso\u00dfe' (gravy) is essential with every Braten. Hamburg's fish restaurants are famous for their Dillso\u00dfe (dill sauce). The word comes from French."},
{type:"teach",trg:"die Karotte",src:"the carrot",pos:"noun",gender:"f",note:"From French 'carotte.' In northern Germany: 'M\u00f6hre.'",example:"A: Karotten oder M\u00f6hren?\nB: Das ist das Gleiche!\nA: Warum zwei W\u00f6rter?\nB: Regional: Karotte im S\u00fcden, M\u00f6hre im Norden.",exampleSrc:"A: Karotten or M\u00f6hren?\nB: That is the same thing!\nA: Why two words?\nB: Regional: Karotte in the south, M\u00f6hre in the north.",funFact:"Three words for one vegetable: Karotte (south), M\u00f6hre (north/Hamburg), gelbe R\u00fcbe (some regions). Germany's regional vocabulary in a nutshell."},
{type:"teach",trg:"die Limonade",src:"the lemonade / soft drink",pos:"noun",gender:"f",note:"Short: Limo. In Germany, 'Limo' means ANY sweet carbonated drink.",example:"A: Eine Limo, bitte!\nB: Welche? Zitrone oder Orange?\nA: Zitrone.\nB: Kommt sofort.",exampleSrc:"A: A soft drink, please!\nB: Which one? Lemon or orange?\nA: Lemon.\nB: Coming right up.",funFact:"In Germany, 'Limo' means ANY sweet carbonated drink, not just lemon-flavored. Ordering 'eine Limo' at any Kneipe gets you a fizzy soft drink."},
{type:"teach",trg:"der Imbiss",src:"the snack bar / quick bite",pos:"noun",gender:"m",note:"Germany's fast food institution. Currywurst, D\u00f6ner, Fischbr\u00f6tchen.",example:"A: Ich habe Hunger. Gibt es hier einen Imbiss?\nB: Ja, an der Ecke.\nA: Was haben die?\nB: Fischbr\u00f6tchen! Typisch Hamburg.",exampleSrc:"A: I am hungry. Is there a snack bar here?\nB: Yes, on the corner.\nA: What do they have?\nB: Fish sandwiches! Typical Hamburg.",funFact:"The Imbiss is Germany's fast food institution. Every corner has one. In Austria, a quick snack is called 'Jause.' In Hamburg, the star Imbiss food is the Fischbr\u00f6tchen."},
{type:"teach",trg:"die Kneipe",src:"the pub / bar",pos:"noun",gender:"f",note:"Informal, cozy, beer-focused. Hamburg's St. Pauli has legendary ones.",example:"A: Gehen wir in eine Kneipe?\nB: Ja, ich kenne eine gute in St. Pauli.\nA: Was trinken wir?\nB: Ein Astra, das Hamburger Bier!",exampleSrc:"A: Shall we go to a pub?\nB: Yes, I know a good one in St. Pauli.\nA: What do we drink?\nB: An Astra, the Hamburg beer!",funFact:"Hamburg's St. Pauli district has legendary Kneipen. 'Kneipe' suggests informal, cozy, beer-focused. Fancier places are called 'Bar' or 'Lounge.'"},
{type:"teach",trg:"lecker",src:"delicious / yummy",pos:"adj",gender:null,note:"The highest food compliment in casual German. From 'lecken' (to lick).",example:"A: Wie schmeckt der Fisch?\nB: Sehr lecker!\nA: Und die So\u00dfe?\nB: Auch lecker! Alles ist lecker hier.",exampleSrc:"A: How does the fish taste?\nB: Very delicious!\nA: And the sauce?\nB: Also delicious! Everything is delicious here.",funFact:"'Das ist lecker!' is the universal German food compliment. Something so good you want to lick the plate. From 'lecken' (to lick)."},
{type:"teach",trg:"salzig",src:"salty",pos:"adj",gender:null,note:"From 'Salz' (salt). The -ig suffix turns nouns into adjectives.",example:"A: Die Suppe ist zu salzig.\nB: Wirklich? Ich finde sie gut.\nA: Hamburg und Salz geh\u00f6ren zusammen.\nB: Stimmt, wegen des Meeres!",exampleSrc:"A: The soup is too salty.\nB: Really? I think it is good.\nA: Hamburg and salt go together.\nB: True, because of the sea!",funFact:"Hamburg's proximity to the sea means salty air and salty food. The -ig suffix turns nouns into adjectives: Salz/salzig, Hunger/hungrig, Durst/durstig."},
{type:"teach",trg:"mild",src:"mild",pos:"adj",gender:null,note:"Same as English. One of the easiest German adjectives for English speakers.",example:"A: Der K\u00e4se ist mild.\nB: Haben Sie auch w\u00fcrzigen K\u00e4se?\nA: Ja, den Tilsiter.\nB: Den nehme ich!",exampleSrc:"A: The cheese is mild.\nB: Do you also have sharp cheese?\nA: Yes, the Tilsiter.\nB: I will take that!",funFact:"'Milder K\u00e4se' (mild cheese), 'mildes Wetter' (mild weather), 'milde Strafe' (lenient punishment). One of the easiest German words for English speakers."},
{type:"mc",q:"'Der Geschmack DES Bratens ist ausgezeichnet.' What case is 'des Bratens'?",opts:["Dative: to the roast","Accusative: the roast","Nominative: the roast","Genitive: of the roast"],ans:"Genitive: of the roast",hint:"Des + noun + -s signals genitive masculine. The taste OF something."},
{type:"fb",s:"Die So\u00dfe {1} Vorspeise war lecker.",a:["der"],opts:["der","die","des","dem"],hint:"Vorspeise is feminine. Genitive feminine changes die to what?",sSrc:"The sauce of the appetizer was delicious."},
{type:"mc",q:"In Hamburg, Karotten are also called ...",opts:["Gew\u00fcrze","Kartoffeln","M\u00f6hren","R\u00fcben"],ans:"M\u00f6hren",hint:"Northern German dialect word for carrots, mentioned in the teach card."},
{type:"drag_fill",s:"W\u00e4hrend {1} {2} bestellen wir die Nachspeise.",blanks:{"1":"des","2":"Essens"},pool:["des","der","dem","Essens","Essen","Esse"],hint:"W\u00e4hrend takes genitive. Essen is neuter: des + -(e)ns.",sSrc:"During the meal we order the dessert."},
{type:"match",pairs:[{trg:"Vorspeise",src:"appetizer"},{trg:"Nachspeise",src:"dessert"},{trg:"Braten",src:"roast"},{trg:"Hackfleisch",src:"ground meat"},{trg:"Gew\u00fcrz",src:"spice"}]}
]},

// ─── Lesson 6: "Elbphilharmonie" ─────────────────────────────────────
{id:"deu_r15l6",title:"Elbphilharmonie",icon:"\uD83C\uDFB6",xp:15,board:true,steps:[
{type:"intro",title:"Elbphilharmonie",desc:"Experience Hamburg's most stunning building. Master genitive prepositions: w\u00e4hrend, wegen, trotz, statt, innerhalb. Practice genitive case in flowing German sentences.",goals:["Learn genitive prepositions","Practice genitive in natural contexts","Master building and hospitality vocabulary","Experience the Elbphilharmonie through story"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-ham-elbphilharmonie",trg:"Die Elbphilharmonie bei blauer Stunde. Verumius steht auf der Plaza und schaut auf das Glas, das die letzten Strahlen des Tageslichts f\u00e4ngt.",src:"The Elbphilharmonie at blue hour. Verumius stands on the plaza and looks at the glass catching the last rays of daylight."},
{type:"story",speaker:"narrator",mood:"contemplative",art:"de-ham-elbphilharmonie",trg:"Trotz des Regens war der Tag ein Erfolg. W\u00e4hrend des Meetings hat er professionelles Deutsch gesprochen. Wegen der Reise f\u00fchlt er sich st\u00e4rker.",src:"Despite the rain, the day was a success. During the meeting he spoke professional German. Because of the trip he feels stronger."},
{type:"story",speaker:"verumius",mood:"thinking",art:"de-ham-elbphilharmonie",trg:"Innerhalb eines Tages habe ich so viel erlebt. Statt der Angst f\u00fchle ich jetzt Stolz.",src:"Within one day I have experienced so much. Instead of fear I now feel pride."},
{type:"teach",trg:"die Bar",src:"the bar",pos:"noun",gender:"f",note:"From English/French 'bar.' Rooftop bars with harbor views are popular in Hamburg.",example:"A: Gehen wir an die Bar?\nB: Ja, die Bar auf dem Dach!\nA: Man sieht den ganzen Hafen.\nB: Bei Nacht ist es besonders sch\u00f6n.",exampleSrc:"A: Shall we go to the bar?\nB: Yes, the rooftop bar!\nA: You can see the whole harbor.\nB: At night it is especially beautiful.",funFact:"Hamburg's HafenCity has rooftop bars with harbor views. 'An der Bar sitzen' (to sit at the bar) is a common evening activity."},
{type:"teach",trg:"das Buffet",src:"the buffet",pos:"noun",gender:"n",note:"From French 'buffet.' 'Fr\u00fchst\u00fccksbuffet' = breakfast buffet.",example:"A: Das Fr\u00fchst\u00fccksbuffet ist toll!\nB: Ja, Br\u00f6tchen, K\u00e4se, Wurst, M\u00fcsli.\nA: Und Eier!\nB: Typisch deutsches Fr\u00fchst\u00fcck.",exampleSrc:"A: The breakfast buffet is great!\nB: Yes, rolls, cheese, cold cuts, muesli.\nA: And eggs!\nB: Typical German breakfast.",funFact:"German hotels are famous for their elaborate breakfast buffets. Also spelled 'B\u00fcfett' in older German. Both spellings are correct."},
{type:"teach",trg:"die Marmelade",src:"the jam",pos:"noun",gender:"f",note:"EU regulation: only citrus jam can be 'Marmelade.' Everything else is 'Konfit\u00fcre.'",example:"A: M\u00f6chten Sie Marmelade?\nB: Ja, Erdbeermarmelade, bitte.\nA: Technisch ist das Konfit\u00fcre.\nB: Egal, schmeckt gut!",exampleSrc:"A: Would you like jam?\nB: Yes, strawberry jam, please.\nA: Technically that is Konfit\u00fcre.\nB: Does not matter, tastes good!",funFact:"EU regulation says only citrus preserves can be called 'Marmelade.' Everything else is technically 'Konfit\u00fcre.' But every German still says Marmelade. In Switzerland, 'Konfit\u00fcre' is the standard word."},
{type:"teach",trg:"die Margarine",src:"the margarine",pos:"noun",gender:"f",note:"From French. Pronounced 'mar-ga-REE-ne' with stress on the third syllable.",example:"A: Butter oder Margarine?\nB: Margarine, bitte.\nA: Gesund!\nB: Naja, Geschmackssache.",exampleSrc:"A: Butter or margarine?\nB: Margarine, please.\nA: Healthy!\nB: Well, matter of taste.",funFact:"Invented as a cheap butter substitute. Pronounced 'mar-ga-REE-ne' in German, with stress on the third syllable. A breakfast-table staple alongside Butter."},
{type:"teach",trg:"die Wolle",src:"the wool",pos:"noun",gender:"f",note:"Same root as English 'wool.' Essential in Hamburg's maritime climate.",example:"A: Diese Jacke ist aus Wolle.\nB: Gut f\u00fcr Hamburg!\nA: Ja, wegen der K\u00e4lte.\nB: Wolle h\u00e4lt warm und trocken.",exampleSrc:"A: This jacket is made of wool.\nB: Good for Hamburg!\nA: Yes, because of the cold.\nB: Wool keeps you warm and dry.",funFact:"Hamburg's maritime climate means warm Wolle clothing is essential. 'Merinowolle' (merino wool) is a favorite. 'In Wolle gepackt' means bundled up."},
{type:"teach",trg:"das Leder",src:"the leather",pos:"noun",gender:"n",note:"Related to English 'leather.' Lederhosen are Bavarian, not Hamburg.",example:"A: Eine Lederjacke f\u00fcr Hamburg?\nB: Nicht ideal bei Regen.\nA: Stimmt. Lieber eine Regenjacke.\nB: Hamburg ist keine Lederhosen-Stadt!",exampleSrc:"A: A leather jacket for Hamburg?\nB: Not ideal in rain.\nA: True. Better a rain jacket.\nB: Hamburg is not a Lederhosen city!",funFact:"Lederhosen (leather pants) are Bavarian tradition, not Hamburg. Hamburg prefers practical rain jackets. 'Echtes Leder' (genuine leather) is a quality marker."},
{type:"teach",trg:"der Katalog",src:"the catalog",pos:"noun",gender:"m",note:"From Greek 'katalogos' (list). Once the backbone of German mail-order shopping.",example:"A: Haben Sie einen Katalog?\nB: Nein, heute ist alles online.\nA: Fr\u00fcher gab es dicke Kataloge.\nB: Ja, der Otto-Katalog war legend\u00e4r.",exampleSrc:"A: Do you have a catalog?\nB: No, today everything is online.\nA: In the past there were thick catalogs.\nB: Yes, the Otto catalog was legendary.",funFact:"The Otto catalog was once Germany's shopping bible. Hamburg-based Otto is still one of the world's largest online retailers. The physical Katalog era ended around 2010."},
{type:"teach",trg:"die H\u00fctte",src:"the hut / cabin",pos:"noun",gender:"f",note:"Related to English 'hut.' 'Bergh\u00fctte' = mountain cabin, 'Skih\u00fctte' = ski lodge.",example:"A: In den Alpen gibt es viele H\u00fctten.\nB: Kann man dort \u00fcbernachten?\nA: Ja, und essen! H\u00fcttenk\u00e4se kommt auch daher.\nB: Wirklich? Interessant!",exampleSrc:"A: In the Alps there are many cabins.\nB: Can you stay overnight?\nA: Yes, and eat! Cottage cheese also comes from there.\nB: Really? Interesting!",funFact:"In the Alps, H\u00fctten offer food and shelter to hikers. You can sleep in a Bergh\u00fctte after a long hike. 'H\u00fcttenk\u00e4se' (cottage cheese) literally means cabin cheese."},
{type:"teach",trg:"die Burg",src:"the castle / fortress",pos:"noun",gender:"f",note:"Hamburg = Ham (meadow/bend) + Burg (fortress). Germany has over 25,000.",example:"A: Wissen Sie, woher 'Hamburg' kommt?\nB: Ham + Burg. Eine Burg an der Alster!\nA: Genau! Die Hammaburg.\nB: Die gibt es leider nicht mehr.",exampleSrc:"A: Do you know where 'Hamburg' comes from?\nB: Ham + Burg. A fortress on the Alster!\nA: Exactly! The Hammaburg.\nB: Unfortunately it no longer exists.",funFact:"'Hamburg' literally contains this word: Ham (meadow/bend) + Burg (fortress). Germany has over 25,000 Burgen and Schl\u00f6sser. Many are now hotels and museums."},
{type:"teach",trg:"das Hallenbad",src:"the indoor pool",pos:"noun",gender:"n",note:"Halle (hall) + Bad (bath/pool). Almost every German town has one.",example:"A: Gibt es hier ein Hallenbad?\nB: Ja, das st\u00e4dtische Hallenbad.\nA: Kann man Bahnen schwimmen?\nB: Ja, 50-Meter-Becken!",exampleSrc:"A: Is there an indoor pool here?\nB: Yes, the municipal indoor pool.\nA: Can you swim laps?\nB: Yes, 50-meter pool!",funFact:"Germans love swimming. Almost every town has a Hallenbad (indoor pool) and a Freibad (outdoor pool for summer). Swimming lessons for children are nearly universal."},
{type:"teach",trg:"das Gasthaus",src:"the inn / guesthouse",pos:"noun",gender:"n",note:"Gast (guest) + Haus (house). Traditional German dining: hearty food, local beer.",example:"A: Essen wir im Gasthaus?\nB: Ja, dort gibt es Hausmannskost.\nA: Was ist das?\nB: Traditionelles, deftiges Essen.",exampleSrc:"A: Shall we eat at the inn?\nB: Yes, they have home cooking there.\nA: What is that?\nB: Traditional, hearty food.",funFact:"A Gasthaus is more rustic than a Restaurant: hearty food, local beer, wooden furniture. Many German villages have a Gasthaus as their social center."},
{type:"teach",trg:"die Gastst\u00e4tte",src:"the restaurant / eatery",pos:"noun",gender:"f",note:"Gast + St\u00e4tte (place). The official legal term for food-serving establishments.",example:"A: Ist das ein Restaurant oder eine Gastst\u00e4tte?\nB: Offiziell ist alles eine Gastst\u00e4tte.\nA: Auch McDonald's?\nB: Ja, gesetzlich gesehen schon!",exampleSrc:"A: Is that a restaurant or a Gastst\u00e4tte?\nB: Officially everything is a Gastst\u00e4tte.\nA: Even McDonald's?\nB: Yes, legally speaking!",funFact:"On tax forms and business licenses, every restaurant is officially a 'Gastst\u00e4tte.' The word is bureaucratic German at its finest."},
{type:"teach",trg:"das Kaffeehaus",src:"the coffee house",pos:"noun",gender:"n",note:"Kaffee + Haus. Vienna made the Kaffeehaus world-famous.",example:"A: Gehen wir ins Kaffeehaus?\nB: Hamburg hat tolle Kaffeeh\u00e4user.\nA: Hamburg und Kaffee?\nB: Ja! Deutschlands erstes Kaffeehaus war hier, 1677.",exampleSrc:"A: Shall we go to the coffee house?\nB: Hamburg has great coffee houses.\nA: Hamburg and coffee?\nB: Yes! Germany's first coffee house was here, 1677.",funFact:"Vienna made the Kaffeehaus world-famous, but Hamburg claims Germany's first one (1677). Coffee culture runs deep in the north. Hamburg is still the center of Germany's coffee trade."},
{type:"teach",trg:"die W\u00e4rme",src:"the warmth",pos:"noun",gender:"f",note:"From 'warm.' The -e suffix turns adjectives into abstract nouns (always feminine).",example:"A: Die W\u00e4rme des Kaffeehauses ist angenehm.\nB: Ja, draussen ist es kalt.\nA: Die W\u00e4rme tut gut.\nB: Noch einen Kaffee?",exampleSrc:"A: The warmth of the coffee house is pleasant.\nB: Yes, outside it is cold.\nA: The warmth feels good.\nB: Another coffee?",funFact:"The -e suffix turns adjectives into feminine abstract nouns: warm/W\u00e4rme, kalt/K\u00e4lte, n\u00e4he/N\u00e4he, gr\u00f6\u00dfe/Gr\u00f6\u00dfe. Always feminine. Very productive pattern."},
{type:"teach",trg:"die K\u00e4lte",src:"the cold / coldness",pos:"noun",gender:"f",note:"From 'kalt.' Same pattern as W\u00e4rme. Hamburg's maritime cold is wet and windy.",example:"A: Die K\u00e4lte ist heute schlimm.\nB: Trotz der K\u00e4lte gehen wir raus?\nA: Ja! Die Elbphilharmonie wartet.\nB: Gut, aber mit Wolle!",exampleSrc:"A: The cold is terrible today.\nB: Despite the cold we go outside?\nA: Yes! The Elbphilharmonie awaits.\nB: Okay, but with wool!",funFact:"'Trotz der K\u00e4lte' (despite the cold) uses genitive after 'trotz.' Hamburg's maritime K\u00e4lte is wet and windy, different from Bavaria's dry mountain cold."},
{type:"teach",trg:"flach",src:"flat",pos:"adj",gender:null,note:"Northern Germany is flach. The opposite of the Alps in the south.",example:"A: Hamburg ist sehr flach.\nB: Ja, keine Berge hier.\nA: Ganz anders als S\u00fcddeutschland.\nB: Daf\u00fcr haben wir das Meer!",exampleSrc:"A: Hamburg is very flat.\nB: Yes, no mountains here.\nA: Completely different from southern Germany.\nB: But we have the sea!",funFact:"'Flachland' (flatland) describes all of northern Germany. The highest point in Hamburg is just 116 meters. Related to English 'flat' via Proto-Germanic."},
{type:"teach",trg:"glatt",src:"smooth / slippery",pos:"adj",gender:null,note:"'Vorsicht, glatte Stra\u00dfe!' = Caution, slippery road! In winter: 'Glatteis.'",example:"A: Vorsicht, die Stra\u00dfe ist glatt!\nB: Wegen des Regens?\nA: Ja, bei Regen wird alles glatt.\nB: Ich fahre langsam.",exampleSrc:"A: Caution, the road is slippery!\nB: Because of the rain?\nA: Yes, in rain everything gets slippery.\nB: I am driving slowly.",funFact:"In winter, 'Glatteis' (black ice) is a serious hazard on German roads. 'Glatteiswarnung' (black ice warning) is a common weather report term."},
{type:"teach",trg:"abbiegen",src:"to turn (while driving/walking)",pos:"verb",gender:null,note:"Ab (off/away) + biegen (to bend). Separable prefix verb.",example:"A: Biegen Sie rechts ab.\nB: Bei der n\u00e4chsten Kreuzung?\nA: Ja, dann sehen Sie das Geb\u00e4ude.\nB: Danke!",exampleSrc:"A: Turn right.\nB: At the next intersection?\nA: Yes, then you will see the building.\nB: Thanks!",funFact:"Separable: 'Biegen Sie rechts ab' = Turn right. In a subordinate clause, it merges: '...wo ich abbiegen muss.' Essential for giving and following directions."},
{type:"teach",trg:"bremsen",src:"to brake",pos:"verb",gender:null,note:"From 'Bremse' (brake). 'Pl\u00f6tzlich bremsen' = to brake suddenly.",example:"A: Bremsen Sie!\nB: Was ist los?\nA: Ein Fu\u00dfg\u00e4nger auf der Fahrbahn!\nB: Gut gesehen! Danke.",exampleSrc:"A: Brake!\nB: What is wrong?\nA: A pedestrian on the road!\nB: Good eyes! Thanks.",funFact:"'Die Bremsen sind gut' (the brakes are good) is an important phrase for car inspections. 'Bremse' also means 'horsefly,' a completely different meaning with the same spelling."},
{type:"teach",trg:"während",src:"during, while",pos:"conj",gender:null,note:"As preposition: während + Genitiv (during).\nAs conjunction: während + verb-final clause (while).",example:"A: Was hast du während des Meetings gemacht?\nB: Ich habe Notizen gemacht.\nA: Während ich schrieb, hat er gesprochen.\nB: Teamarbeit!",exampleSrc:"A: What did you do during the meeting?\nB: I took notes.\nA: While I was writing, he spoke.\nB: Teamwork!",funFact:"Während does double duty: as a preposition with genitive (während des Essens) and as a conjunction meaning while (während ich schlief). Both are essential for B1."},
{type:"teach",trg:"statt",src:"instead of",pos:"prep",gender:null,note:"Short form of anstatt. Takes Genitiv.\nStatt des Autos = instead of the car.",example:"A: Statt des Taxis nehmen wir die U-Bahn.\nB: Gute Idee, das spart Geld.\nA: Statt Kaffee trinke ich Tee.\nB: Auch gesünder!",exampleSrc:"A: Instead of the taxi we take the subway.\nB: Good idea, that saves money.\nA: Instead of coffee I drink tea.\nB: Also healthier!",funFact:"Statt is the short form of anstatt. Both are correct. As a preposition it takes genitive. As part of statt...zu it creates infinitive clauses meaning instead of doing."},
{type:"teach",trg:"sich befinden",src:"to be located, to be situated",pos:"verb",gender:null,note:"Reflexive. Formal alternative to sein for location.\nDas Hotel befindet sich am Hafen.",example:"A: Wo befindet sich die Elbphilharmonie?\nB: Sie befindet sich in der HafenCity.\nA: Und der Hauptbahnhof?\nB: Er befindet sich im Zentrum.",exampleSrc:"A: Where is the Elbphilharmonie located?\nB: It is located in the HafenCity.\nA: And the main train station?\nB: It is located in the center.",funFact:"More formal than sein for describing locations. Das Museum befindet sich in der Altstadt sounds more official. Essential for giving directions and reading maps."},
{type:"tip",title:"Genitive prepositions: w\u00e4hrend, wegen, trotz, statt, innerhalb",text:"These five prepositions ALWAYS take genitive. They elevate your German from everyday to professional.\n\nw\u00e4hrend = during: W\u00e4hrend des Meetings (during the meeting)\nwegen = because of: Wegen des Regens (because of the rain)\ntrotz = despite: Trotz der K\u00e4lte (despite the cold)\nstatt/anstatt = instead of: Statt des Taxis (instead of the taxi)\ninnerhalb = within: Innerhalb eines Tages (within one day)\n\nPattern: preposition + genitive article + noun\nMasc/Neut: des + -(e)s\nFem/Pl: der + no change to noun\n\nIn casual speech, Germans sometimes use dative after wegen/trotz ('wegen dem Regen'), but written and professional German demands genitive.",deepDive:{title:"More genitive prepositions",text:"Beyond the big five, there are more genitive prepositions:\n\naußerhalb = outside of: Au\u00dferhalb der Stadt (outside the city)\noberhalb = above: Oberhalb des Hafens (above the harbor)\nunterhalb = below: Unterhalb der Br\u00fccke (below the bridge)\naufgrund = on the basis of: Aufgrund des Wetters (due to the weather)\nanhand = by means of: Anhand der Daten (based on the data)\n\nThe big five (w\u00e4hrend, wegen, trotz, statt, innerhalb) are the most common and the ones tested on exams."}},
{type:"mc",q:"'Trotz DES Regens war der Tag gut.' Why 'des Regens'?",opts:["trotz takes dative; Regen is neuter","des is always used with weather","trotz takes genitive; Regen is masculine","trotz takes accusative"],ans:"trotz takes genitive; Regen is masculine",hint:"Trotz is a genitive preposition. Masculine genitive: des + noun + -s."},
{type:"fb",s:"W\u00e4hrend {1} Meetings sprach Verumius Deutsch.",a:["des"],opts:["des","dem","der","das"],hint:"W\u00e4hrend takes genitive. Meeting is neuter. Neuter genitive article?",sSrc:"During the meeting Verumius spoke German."},
{type:"mc",q:"Verumius nahm die U-Bahn ___ des Taxis.",opts:["statt","trotz","innerhalb","w\u00e4hrend"],ans:"statt",hint:"He chose the subway INSTEAD OF the taxi. Which preposition means 'instead of'?"},
{type:"drag_fill",s:"{1} {2} Tages hat Verumius viel erlebt.",blanks:{"1":"Innerhalb","2":"eines"},pool:["Innerhalb","W\u00e4hrend","eines","des","einem","ein"],hint:"Within ONE day. Genitive preposition + indefinite genitive article for masculine/neuter.",sSrc:"Within one day Verumius experienced a lot."},
{type:"match",pairs:[{trg:"w\u00e4hrend",src:"during"},{trg:"wegen",src:"because of"},{trg:"trotz",src:"despite"},{trg:"statt",src:"instead of"},{trg:"innerhalb",src:"within"}]}
]},

// ─── Lesson 7: "Alles \u00fcber Hamburg" ──────────────────────────────────
{id:"deu_r15l7",title:"Alles \u00fcber Hamburg",icon:"\uD83C\uDFC6",xp:15,board:true,steps:[
{type:"intro",title:"Alles \u00fcber Hamburg",desc:"Test everything from Unit 15. Prove you can use genitive case, N-Deklination, and genitive prepositions. Show mastery of travel, food, and urban vocabulary.",goals:["Test genitive case mastery","Test N-Deklination mastery","Test genitive prepositions","Assess all unit vocabulary"]},
{type:"teach",trg:"das Benzin",src:"the gasoline / petrol",pos:"noun",gender:"n",note:"From the chemical compound 'benzene.' 'Bleifrei' = unleaded.",example:"A: Wir brauchen Benzin.\nB: Ist die Tankstelle weit?\nA: Nein, nur zwei Kilometer.\nB: Super oder Diesel?",exampleSrc:"A: We need gasoline.\nB: Is the gas station far?\nA: No, only two kilometers.\nB: Premium or diesel?",funFact:"Named after the chemical compound benzene, which was named after a tree resin. 'Super' and 'Diesel' are the common pump labels at German Tankstellen."},
{type:"teach",trg:"die Bremse",src:"the brake",pos:"noun",gender:"f",note:"Also means 'horsefly.' Completely different meaning, same spelling.",example:"A: Die Bremse funktioniert nicht!\nB: Das ist gef\u00e4hrlich!\nA: Wir m\u00fcssen zur Werkstatt.\nB: Sofort!",exampleSrc:"A: The brake does not work!\nB: That is dangerous!\nA: We need to go to the workshop.\nB: Immediately!",funFact:"'Handbremse' = handbrake, 'Bremse ziehen' = pull the brake. The word also means 'horsefly,' a completely unrelated meaning with the same spelling."},
{type:"teach",trg:"das Boot",src:"the boat",pos:"noun",gender:"n",note:"Same root as English 'boat.' The famous submarine film 'Das Boot' (1981).",example:"A: Fahren wir mit dem Boot?\nB: Ja, ein Ruderboot auf der Alster!\nA: Kann man die Alster mit dem Boot erkunden?\nB: Ja, das ist sehr beliebt in Hamburg.",exampleSrc:"A: Shall we go by boat?\nB: Yes, a rowboat on the Alster!\nA: Can you explore the Alster by boat?\nB: Yes, that is very popular in Hamburg.",funFact:"The famous submarine film 'Das Boot' (1981) made this word internationally known. In Hamburg, 'Boot' usually means the small boats on the Alster lake."},
{type:"teach",trg:"der Gehsteig",src:"the sidewalk",pos:"noun",gender:"m",note:"Geh (walk) + Steig (path). Austrian/southern German. North: 'B\u00fcrgersteig.'",example:"A: Bleiben Sie auf dem Gehsteig!\nB: In Hamburg sagt man B\u00fcrgersteig.\nA: Und in der Schweiz?\nB: Trottoir!",exampleSrc:"A: Stay on the sidewalk!\nB: In Hamburg they say B\u00fcrgersteig.\nA: And in Switzerland?\nB: Trottoir!",funFact:"Gehsteig (Austria/south), B\u00fcrgersteig (north), Trottoir (Switzerland). Three words for the same strip of pavement. A perfect example of regional vocabulary."},
{type:"teach",trg:"das Verkehrszeichen",src:"the traffic sign",pos:"noun",gender:"n",note:"Verkehr (traffic) + Zeichen (sign). Germany has over 1,000 different ones.",example:"A: Was bedeutet dieses Verkehrszeichen?\nB: Vorfahrt beachten.\nA: Deutschland hat so viele Verkehrszeichen!\nB: \u00dcber 1.000 verschiedene!",exampleSrc:"A: What does this traffic sign mean?\nB: Yield.\nA: Germany has so many traffic signs!\nB: Over 1,000 different ones!",funFact:"Germany has over 1,000 different Verkehrszeichen. There is even a Verkehrszeichenkatalog (traffic sign catalog). For the driving test, you need to know the most important 200."},
{type:"teach",trg:"die Landung",src:"the landing",pos:"noun",gender:"f",note:"From 'landen' (to land). The -ung suffix (always feminine) turns verbs into nouns.",example:"A: Die Landung war sanft.\nB: Gott sei Dank!\nA: Hamburg-Fuhlsb\u00fcttel ist ein kleiner Flughafen.\nB: Aber modern.",exampleSrc:"A: The landing was smooth.\nB: Thank God!\nA: Hamburg-Fuhlsb\u00fcttel is a small airport.\nB: But modern.",funFact:"'Notlandung' = emergency landing, 'Mondlandung' = moon landing. The -ung suffix turns verbs into feminine nouns: landen/Landung, landen/Landung. Reliable pattern."},
{type:"teach",trg:"das Fundb\u00fcro",src:"the lost and found office",pos:"noun",gender:"n",note:"Fund (find) + B\u00fcro (office). Every German city has one.",example:"A: Ich habe meinen Regenschirm verloren!\nB: Gehen Sie zum Fundb\u00fcro.\nA: Wo ist das?\nB: Im Hauptbahnhof.",exampleSrc:"A: I lost my umbrella!\nB: Go to the lost and found.\nA: Where is it?\nB: In the main station.",funFact:"Every German city has a Fundb\u00fcro. Left your umbrella on the train? Check the Fundb\u00fcro at the Hauptbahnhof. Germans are surprisingly good at turning in found items."},
{type:"teach",trg:"die Semmel",src:"the bread roll",pos:"noun",gender:"f",note:"In Bavaria and Austria: Semmel. In northern Germany: Br\u00f6tchen.",example:"A: Zwei Semmeln, bitte.\nB: In Hamburg sagen wir Br\u00f6tchen!\nA: Und in Berlin?\nB: Schrippe! Ein Br\u00f6tchen, drei Namen.",exampleSrc:"A: Two bread rolls, please.\nB: In Hamburg we say Br\u00f6tchen!\nA: And in Berlin?\nB: Schrippe! One roll, three names.",funFact:"One bread roll, many names: Br\u00f6tchen (north), Semmel (Bavaria/Austria), Schrippe (Berlin), Weck (southwest), Weggli (Switzerland). Germany's greatest linguistic debate."},
{type:"teach",trg:"der Kn\u00f6del",src:"the dumpling",pos:"noun",gender:"m",note:"Bavarian and Austrian classic. Not common in Hamburg.",example:"A: Was sind Kn\u00f6del?\nB: Kugeln aus Kartoffel- oder Brotteig.\nA: Gibt es die in Hamburg?\nB: Selten. Kn\u00f6del sind eher s\u00fcddeutsch.",exampleSrc:"A: What are dumplings?\nB: Balls made of potato or bread dough.\nA: Are there any in Hamburg?\nB: Rarely. Dumplings are more southern German.",funFact:"'Kartoffelkn\u00f6del' (potato dumpling) and 'Semmelkn\u00f6del' (bread dumpling) are Bavarian/Austrian classics. In Hamburg, you are more likely to find Fischbr\u00f6tchen."},
{type:"teach",trg:"die Sahne",src:"the cream",pos:"noun",gender:"f",note:"Northern German word. Austrian: 'Obers.' Swiss: 'Rahm.'",example:"A: Mit Sahne?\nB: Ja, bitte!\nA: In \u00d6sterreich hei\u00dft das Obers.\nB: Und in der Schweiz: Rahm.",exampleSrc:"A: With cream?\nB: Yes, please!\nA: In Austria that is called Obers.\nB: And in Switzerland: Rahm.",funFact:"Sahne (Germany/north), Obers (\u00d6sterreich/Austria), Rahm (Schweiz/Switzerland). Same product, three countries, three words."},
{type:"teach",trg:"die Schlagsahne",src:"the whipped cream",pos:"noun",gender:"f",note:"Schlag (whip/hit) + Sahne (cream). Standard German term.",example:"A: Kuchen mit Schlagsahne, bitte!\nB: Gern! Viel oder wenig?\nA: Viel!\nB: Ein wahrer Genie\u00dfer!",exampleSrc:"A: Cake with whipped cream, please!\nB: Gladly! A lot or a little?\nA: A lot!\nB: A true connoisseur!",funFact:"On every German cafe menu next to cake: 'mit Schlagsahne.' In Austria: 'Schlagobers.' In Switzerland: 'Schlagrahm.' One product, three words."},
{type:"teach",trg:"das M\u00fcsli",src:"the muesli",pos:"noun",gender:"n",note:"From Swiss German 'Mus' (puree). Now a German breakfast staple.",example:"A: Was fr\u00fchst\u00fccken Sie?\nB: M\u00fcsli mit Joghurt.\nA: Selbst gemacht?\nB: Nein, aus dem Supermarkt.",exampleSrc:"A: What do you have for breakfast?\nB: Muesli with yogurt.\nA: Homemade?\nB: No, from the supermarket.",funFact:"Originally 'Bircherm\u00fcsli,' invented by Swiss doctor Maximilian Bircher-Brenner around 1900. Now a German breakfast staple. Swiss spelling: M\u00fcesli."},
{type:"teach",trg:"anschnallen",src:"to buckle up",pos:"verb",gender:null,note:"An (on) + schnallen (to buckle). Separable: 'Schnall dich an!'",example:"A: Bitte anschnallen!\nB: Nat\u00fcrlich.\nA: Auf der Autobahn ist es Pflicht.\nB: In Deutschland nimmt man das ernst.",exampleSrc:"A: Please buckle up!\nB: Of course.\nA: On the Autobahn it is mandatory.\nB: In Germany they take that seriously.",funFact:"'Bitte anschnallen!' is the phrase on every flight and Autobahn sign. Germans take seatbelts seriously. Fines for not wearing one: 30 euros."},
{type:"teach",trg:"hupen",src:"to honk",pos:"verb",gender:null,note:"'Hupen verboten!' = Honking forbidden! Common sign near hospitals.",example:"A: Warum hupen Sie?\nB: Der Radfahrer hat mich nicht gesehen!\nA: Hupen Sie nicht so laut.\nB: Entschuldigung.",exampleSrc:"A: Why are you honking?\nB: The cyclist did not see me!\nA: Do not honk so loudly.\nB: Sorry.",funFact:"Germans consider unnecessary Hupen extremely rude. 'Hupen verboten!' signs are common near hospitals. Road rage by horn is frowned upon."},
{type:"teach",trg:"landen",src:"to land",pos:"verb",gender:null,note:"Regular verb. From 'Land.' Also figurative: 'Wo bist du gelandet?'",example:"A: Das Flugzeug landet in Hamburg.\nB: Wann genau?\nA: In zehn Minuten.\nB: Perfekt, wir sind p\u00fcnktlich.",exampleSrc:"A: The airplane is landing in Hamburg.\nB: When exactly?\nA: In ten minutes.\nB: Perfect, we are on time.",funFact:"Also used figuratively: 'Wo bist du gelandet?' = Where did you end up? Uses 'sein' in perfect tense: 'Das Flugzeug ist gelandet.'"},
{type:"teach",trg:"losfahren",src:"to depart / set off",pos:"verb",gender:null,note:"Los (off/away) + fahren (to drive). Separable. 'Los!' = Go!",example:"A: Wann fahren wir los?\nB: Um acht Uhr.\nA: Fr\u00fch!\nB: Ja, die Strecke ist lang.",exampleSrc:"A: When do we set off?\nB: At eight o'clock.\nA: Early!\nB: Yes, the route is long.",funFact:"'Los!' alone means 'Go!' Germans shout it at sports events. Separable: 'Wir fahren um 8 Uhr los.' Very common in everyday speech."},
{type:"teach",trg:"stehenbleiben",src:"to stop / stand still",pos:"verb",gender:null,note:"Stehen (to stand) + bleiben (to stay). Separable: 'Bleib stehen!'",example:"A: Bitte stehenbleiben!\nB: Warum?\nA: Das Foto ist noch nicht fertig.\nB: Oh, Entschuldigung. Ich bleibe stehen.",exampleSrc:"A: Please stand still!\nB: Why?\nA: The photo is not done yet.\nB: Oh, sorry. I will stand still.",funFact:"'Bleib stehen!' is one of the most common commands. Also used by police: 'Stehenbleiben!' Used in everyday life when someone is about to walk into danger."},
{type:"teach",trg:"tanken",src:"to refuel",pos:"verb",gender:null,note:"From 'Tank.' 'Volltanken' = to fill up completely.",example:"A: Wir m\u00fcssen tanken.\nB: Die n\u00e4chste Tankstelle ist in f\u00fcnf Kilometern.\nA: Reicht das Benzin?\nB: Gerade so.",exampleSrc:"A: We need to refuel.\nB: The next gas station is in five kilometers.\nA: Is the gasoline enough?\nB: Just barely.",funFact:"'Volltanken' = fill it up. Also slang: 'Energie tanken' = to recharge your energy. 'Sonne tanken' = to soak up the sun. Versatile verb."},
{type:"teach",trg:"\u00fcberfahren",src:"to run over",pos:"verb",gender:null,note:"Inseparable prefix. 'Eine rote Ampel \u00fcberfahren' = to run a red light.",example:"A: Er hat die rote Ampel \u00fcberfahren!\nB: Das ist sehr gef\u00e4hrlich.\nA: Und verboten!\nB: Ja, hohe Strafe.",exampleSrc:"A: He ran the red light!\nB: That is very dangerous.\nA: And forbidden!\nB: Yes, heavy fine.",funFact:"Inseparable prefix: 'Er hat die Ampel \u00fcberfahren' (no ge-). 'Eine rote Ampel \u00fcberfahren' = to run a red light. Serious offense with heavy fines."},
{type:"teach",trg:"\u00fcberholen",src:"to overtake / pass",pos:"verb",gender:null,note:"Inseparable prefix. 'Rechts \u00fcberholen ist verboten' on the Autobahn.",example:"A: Darf ich hier \u00fcberholen?\nB: Nein, \u00dcberholverbot!\nA: Und auf der Autobahn?\nB: Nur links \u00fcberholen!",exampleSrc:"A: May I overtake here?\nB: No, no-passing zone!\nA: And on the Autobahn?\nB: Only overtake on the left!",funFact:"'Rechts \u00fcberholen ist verboten' (passing on the right is forbidden) is a cardinal rule of the Autobahn. Violators face heavy fines."},
{type:"mc",q:"'Die Atmosph\u00e4re DES Hafens ist besonders.' Which case?",opts:["Accusative masculine","Genitive masculine","Nominative neuter","Dative masculine"],ans:"Genitive masculine",hint:"Des + noun ending in -s: the classic signal for this case and gender combination."},
{type:"mc",q:"'Wegen DER K\u00e4lte blieb Verumius im Kaffeehaus.' Why 'der'?",opts:["Der is nominative masculine here","Wegen takes dative; K\u00e4lte is feminine","Wegen takes genitive; K\u00e4lte is feminine","K\u00e4lte is always 'der'"],ans:"Wegen takes genitive; K\u00e4lte is feminine",hint:"Wegen demands genitive. Feminine genitive: die becomes der."},
{type:"fb",s:"Der Titel des {1} war 'Professor Doktor.'",a:["Herrn"],opts:["Herrn","Herr","Herrs","Herren"],hint:"Herr is N-Deklination. In genitive, it adds -n after 'des.'",sSrc:"The gentleman's title was 'Professor Doktor.'"},
{type:"mc",q:"'___ des schlechten Wetters ging Verumius zur Elbphilharmonie.'",opts:["W\u00e4hrend","Wegen","Trotz","Statt"],ans:"Trotz",hint:"He went DESPITE the bad weather. Which preposition means 'despite'?"},
{type:"drag_fill",s:"{1} {2} Reise lernte Verumius viel \u00fcber Hamburg.",blanks:{"1":"W\u00e4hrend","2":"der"},pool:["W\u00e4hrend","Trotz","der","des","dem","die"],hint:"During THE trip. Reise is feminine. Genitive feminine article?",sSrc:"During the trip Verumius learned a lot about Hamburg."},
{type:"fb",s:"Die Rundfahrt durch den Hafen {1} Stadt war wunderbar.",a:["der"],opts:["der","die","des","dem"],hint:"Stadt is feminine. Genitive feminine: die becomes what?",sSrc:"The tour through the city's harbor was wonderful."},
{type:"match",pairs:[{trg:"W\u00e4hrend des Fluges",src:"During the flight"},{trg:"Wegen des Nebels",src:"Because of the fog"},{trg:"Trotz der K\u00e4lte",src:"Despite the cold"},{trg:"Statt des Zuges",src:"Instead of the train"},{trg:"Innerhalb der Stadt",src:"Within the city"}]},
{type:"mc",q:"Verumius muss tanken. Where does he go?",opts:["Zum Hallenbad","Zum Fundb\u00fcro","Zur Gastst\u00e4tte","Zur Tankstelle"],ans:"Zur Tankstelle",hint:"Tanken means to refuel. Where do you get fuel?"},
{type:"drag_fill",s:"{1} des Meetings stellte man Verumius dem {2} vor.",blanks:{"1":"W\u00e4hrend","2":"Kollegen"},pool:["W\u00e4hrend","Trotz","Kollegen","Kollege","Kolleg","Herrn"],hint:"DURING the meeting, someone was introduced to the colleague. Dative N-Dekl: dem Kollegen.",sSrc:"During the meeting Verumius was introduced to the colleague."}
]},

// ─── Lesson 8: "Zur\u00fcck nach Berlin" ──────────────────────────────────
{id:"deu_r15l8",title:"Zur\u00fcck nach Berlin",icon:"\uD83C\uDF03",xp:15,board:true,steps:[
{type:"intro",title:"Zur\u00fcck nach Berlin",desc:"Reflect on the Hamburg trip. Learn direction and movement vocabulary. Discover Germany's regional vocabulary differences. Master the unit's grammar in a final cultural context.",goals:["Learn direction and movement vocabulary","Discover regional vocabulary differences","Practice all unit grammar in cultural context","Reflect on the Hamburg experience"]},
{type:"story",speaker:"narrator",mood:"peaceful",art:"de-ham-ice-night",trg:"Der ICE f\u00e4hrt durch die Nacht. Drau\u00dfen: dunkle Felder, ferne Dorflichter. Verumius schreibt in sein Notizbuch.",src:"The ICE travels through the night. Outside: dark fields, distant village lights. Verumius writes in his notebook."},
{type:"story",speaker:"verumius",mood:"reflective",art:"de-ham-ice-night",trg:"Trotz des Regens, trotz der Nervosit\u00e4t war es ein guter Tag. Der Name des Professors war schwer zu merken, aber sein L\u00e4cheln war echt.",src:"Despite the rain, despite the nervousness, it was a good day. The professor's name was hard to remember, but his smile was genuine."},
{type:"story",speaker:"narrator",mood:"warm",art:"de-ber-hauptbahnhof-night",trg:"Berlin Hauptbahnhof. Auf dem Bahnsteig: ein bekanntes Gesicht. Lukas mit einem Paket unter dem Arm.",src:"Berlin Central Station. On the platform: a familiar face. Lukas with a package under his arm."},
{type:"story",speaker:"lukas",mood:"friendly",art:"de-ber-hauptbahnhof-night",trg:"Hey! Wie war Hamburg?",src:"Hey! How was Hamburg?"},
{type:"story",speaker:"verumius",mood:"amused",art:"de-ber-hauptbahnhof-night",trg:"Regnerisch.",src:"Rainy."},
{type:"story",speaker:"lukas",mood:"laughing",art:"de-ber-hauptbahnhof-night",trg:"Hamburg halt. Komm, wir nehmen die S-Bahn zusammen.",src:"Hamburg, of course. Come on, let's take the S-Bahn together."},
{type:"teach",trg:"pauschal",src:"flat-rate / all-inclusive",pos:"adj",gender:null,note:"'Pauschalreise' = package tour. From French 'forfait.'",example:"A: Ist das ein Pauschalangebot?\nB: Ja, Hotel, Fl\u00fcge und Essen inklusive.\nA: Was kostet die Pauschalreise?\nB: 899 Euro pro Person.",exampleSrc:"A: Is that an all-inclusive offer?\nB: Yes, hotel, flights and food included.\nA: What does the package tour cost?\nB: 899 euros per person.",funFact:"'Pauschalreise' (package tour) is very popular in Germany. Germans are among the world's most enthusiastic tourists. 'Pauschal bezahlen' = to pay a flat rate."},
{type:"teach",trg:"vorder",src:"front / forward",pos:"adj",gender:null,note:"'Der vordere Teil des Zuges' = the front part of the train.",example:"A: Sitzen wir im vorderen Teil?\nB: Ja, Wagen 1.\nA: Das ist besser bei kurzen Halten.\nB: Stimmt, n\u00e4her am Ausgang.",exampleSrc:"A: Are we sitting in the front section?\nB: Yes, car 1.\nA: That is better for short stops.\nB: True, closer to the exit.",funFact:"Comparative of 'vorn' (in front). 'Vorderseite' = front side, 'Vordert\u00fcr' = front door, 'Vorderrad' = front wheel. Very productive compound element."},
{type:"teach",trg:"abw\u00e4rts",src:"downward",pos:"adv",gender:null,note:"Ab (away/down) + -w\u00e4rts (toward). Also figurative: 'Es geht abw\u00e4rts.'",example:"A: Es geht abw\u00e4rts.\nB: Wirklich? Bergab?\nA: Nein, ich meine die Wirtschaft.\nB: Ach so, leider.",exampleSrc:"A: Things are going downhill.\nB: Really? Downhill?\nA: No, I mean the economy.\nB: I see, unfortunately.",funFact:"The -w\u00e4rts suffix indicates direction: abw\u00e4rts (downward), aufw\u00e4rts (upward), r\u00fcckw\u00e4rts (backward), vorw\u00e4rts (forward). A useful pattern."},
{type:"teach",trg:"aufw\u00e4rts",src:"upward",pos:"adv",gender:null,note:"Auf (up) + -w\u00e4rts. Opposite of abw\u00e4rts.",example:"A: Die Karriere geht aufw\u00e4rts!\nB: Gut gemacht!\nA: Danke. Wegen der Hamburg-Reise.\nB: Siehst du, es hat sich gelohnt.",exampleSrc:"A: The career is going up!\nB: Well done!\nA: Thanks. Because of the Hamburg trip.\nB: See, it was worth it.",funFact:"'Es geht aufw\u00e4rts!' (Things are looking up!) is an optimistic expression. Opposite of 'Es geht abw\u00e4rts.' The -w\u00e4rts direction pattern is productive."},
{type:"teach",trg:"au\u00dfen",src:"outside",pos:"adv",gender:null,note:"Opposite of 'innen' (inside). 'Au\u00dfenseiter' = outsider.",example:"A: Von au\u00dfen sieht das Geb\u00e4ude klein aus.\nB: Aber innen ist es riesig!\nA: Au\u00dfen alt, innen modern.\nB: Typisch Hamburg.",exampleSrc:"A: From the outside the building looks small.\nB: But inside it is enormous!\nA: Old outside, modern inside.\nB: Typical Hamburg.",funFact:"Hamburg's Au\u00dfenalster (Outer Alster lake) is a famous landmark. 'Au\u00dfenseiter' (outsider) literally means 'outside-sitter.' Opposite: 'innen' (inside)."},
{type:"teach",trg:"quer",src:"across / diagonally",pos:"adv",gender:null,note:"'Quer durch die Stadt' = across the city. Related to English 'queer.'",example:"A: Wir fahren quer durch Hamburg.\nB: Von Altona bis Wandsbek?\nA: Ja, quer durch die ganze Stadt.\nB: Das dauert eine Stunde.",exampleSrc:"A: We are going across Hamburg.\nB: From Altona to Wandsbek?\nA: Yes, across the entire city.\nB: That takes an hour.",funFact:"'Querstra\u00dfe' = cross street. 'Quereinstieg' = lateral entry. Related to English 'queer' (originally meaning 'oblique/odd')."},
{type:"teach",trg:"rauf",src:"up (colloquial)",pos:"adv",gender:null,note:"Short for 'herauf.' Colloquial. The prefix rauf- attaches to verbs.",example:"A: Komm rauf!\nB: Ich komme! Welches Stockwerk?\nA: Drittes.\nB: Gibt es keinen Aufzug?",exampleSrc:"A: Come up!\nB: I am coming! Which floor?\nA: Third.\nB: Is there no elevator?",funFact:"Short for 'herauf' (up here). Informal register. 'Raufgehen' = go up, 'raufklettern' = climb up. The colloquial prefix rauf- is very common in spoken German."},
{type:"teach",trg:"r\u00fcckw\u00e4rts",src:"backward",pos:"adv",gender:null,note:"R\u00fcck (back) + -w\u00e4rts. 'R\u00fcckw\u00e4rts einparken' = reverse parking.",example:"A: K\u00f6nnen Sie r\u00fcckw\u00e4rts einparken?\nB: Nat\u00fcrlich! Das ist Pflicht bei der Fahrpr\u00fcfung.\nA: In meinem Land auch.\nB: R\u00fcckw\u00e4rts ist r\u00fcckw\u00e4rts, \u00fcberall gleich!",exampleSrc:"A: Can you reverse park?\nB: Of course! That is mandatory in the driving test.\nA: In my country too.\nB: Backward is backward, the same everywhere!",funFact:"Germans must master r\u00fcckw\u00e4rts einparken for the driving test. 'R\u00fcckw\u00e4rtsgang' = reverse gear. The -w\u00e4rts suffix indicates direction."},
{type:"teach",trg:"voraus",src:"ahead / in advance",pos:"adv",gender:null,note:"'Im Voraus' = in advance. 'Geradeaus' = straight ahead.",example:"A: Bitte im Voraus bezahlen.\nB: Okay, wie viel?\nA: 25 Euro.\nB: Hier, bitte.",exampleSrc:"A: Please pay in advance.\nB: Okay, how much?\nA: 25 euros.\nB: Here you are.",funFact:"'Im Voraus' (in advance) and 'voraus' (ahead) are essential words. 'Voraussetzung' (prerequisite) and 'voraussichtlich' (presumably) build on the same root."},
{type:"teach",trg:"entlang",src:"along",pos:"prep",gender:null,note:"After noun + accusative, or before noun + dative/genitive.",example:"A: Gehen Sie die Stra\u00dfe entlang.\nB: Wie weit?\nA: Bis zum Hafen.\nB: Am Ufer entlang?",exampleSrc:"A: Walk along the street.\nB: How far?\nA: To the harbor.\nB: Along the shore?",funFact:"Unusual grammar: 'die Stra\u00dfe entlang' (after noun, accusative) or 'entlang der Stra\u00dfe' (before noun, genitive). Both are correct."},
{type:"teach",trg:"entfernen",src:"to remove / to be distant",pos:"verb",gender:null,note:"Ent- (away) + fernen (from fern = far). Inseparable.",example:"A: Bitte entfernen Sie den Gegenstand.\nB: Welchen Gegenstand?\nA: Den Koffer dort.\nB: Oh, das ist meiner! Entschuldigung.",exampleSrc:"A: Please remove the object.\nB: Which object?\nA: The suitcase there.\nB: Oh, that is mine! Sorry.",funFact:"Also used as adjective: 'weit entfernt' (far away), 'drei Kilometer entfernt' (three kilometers away). Inseparable prefix ent- means 'away from.'"},
{type:"teach",trg:"flie\u00dfen",src:"to flow",pos:"verb",gender:null,note:"Irregular: flie\u00dft, floss, ist geflossen. Related to English 'flow.'",example:"A: Die Elbe flie\u00dft durch Hamburg.\nB: Wohin flie\u00dft sie?\nA: In die Nordsee.\nB: Der Fluss ist riesig hier.",exampleSrc:"A: The Elbe flows through Hamburg.\nB: Where does it flow?\nA: Into the North Sea.\nB: The river is enormous here.",funFact:"Hamburg exists because the Elbe flie\u00dft to the North Sea. Irregular conjugation: flie\u00dft, floss, ist geflossen. Related to English 'flow' and 'flood.'"},
{type:"teach",trg:"parkieren",src:"to park (Swiss)",pos:"verb",gender:null,note:"Swiss German for 'parken.' The -ieren ending follows French/Latin loan patterns.",example:"A: Wo kann man hier parkieren?\nB: In der Schweiz sagt man parkieren.\nA: Und in Deutschland?\nB: Parken! Ohne -ieren.",exampleSrc:"A: Where can you park here?\nB: In Switzerland they say parkieren.\nA: And in Germany?\nB: Parken! Without -ieren.",funFact:"In Germany and Austria: 'parken.' In Switzerland: 'parkieren.' The -ieren ending follows the French/Latin loan pattern common in Swiss German."},
{type:"teach",trg:"\u00fcberqueren",src:"to cross",pos:"verb",gender:null,note:"\u00dcber (over) + queren (to cross). Inseparable. More formal than 'gehen \u00fcber.'",example:"A: Bitte \u00fcberqueren Sie die Stra\u00dfe am Zebrastreifen.\nB: Nat\u00fcrlich!\nA: In Deutschland wartet man bei Rot.\nB: Ja, das habe ich gelernt!",exampleSrc:"A: Please cross the street at the crosswalk.\nB: Of course!\nA: In Germany you wait at red.\nB: Yes, I learned that!",funFact:"Inseparable: 'Er \u00fcberquert die Stra\u00dfe.' More formal than '\u00fcber die Stra\u00dfe gehen.' Past participle: '\u00fcberquert' (no ge-)."},
{type:"teach",trg:"umdrehen",src:"to turn around",pos:"verb",gender:null,note:"Um (around) + drehen (to turn). Separable. Also reflexive: 'sich umdrehen.'",example:"A: Dreh dich um!\nB: Warum?\nA: Sieh mal, der Sonnenuntergang!\nB: Oh, wundersch\u00f6n!",exampleSrc:"A: Turn around!\nB: Why?\nA: Look, the sunset!\nB: Oh, beautiful!",funFact:"Separable: 'Dreh dich um!' (Turn around!). Reflexive: 'sich umdrehen.' Verumius dreht sich um und sieht Lukas auf dem Bahnsteig."},
{type:"teach",trg:"umtauschen",src:"to exchange (goods/money)",pos:"verb",gender:null,note:"Um (exchange) + tauschen (to swap). Separable.",example:"A: Kann ich das umtauschen?\nB: Nur mit Kassenbon.\nA: Hier ist er.\nB: Gut. Was m\u00f6chten Sie stattdessen?",exampleSrc:"A: Can I exchange this?\nB: Only with the receipt.\nA: Here it is.\nB: Good. What would you like instead?",funFact:"'Euro in Dollar umtauschen' = to exchange euros for dollars. 'Umtausch nur innerhalb von 14 Tagen' = exchange only within 14 days. Standard German retail policy."},
{type:"teach",trg:"das Zeug",src:"the stuff / things",pos:"noun",gender:"n",note:"Very versatile. 'Zeug' appears in many compounds: Fahrzeug, Werkzeug, Spielzeug.",example:"A: Was ist das f\u00fcr ein Zeug?\nB: Mein Reisezeug.\nA: Du hast viel Zeug dabei!\nB: Ja, ich packe immer zu viel ein.",exampleSrc:"A: What kind of stuff is that?\nB: My travel stuff.\nA: You have a lot of stuff with you!\nB: Yes, I always pack too much.",funFact:"'Zeug' is one of German's most productive compound elements: Fahrzeug (vehicle), Flugzeug (airplane), Werkzeug (tool), Spielzeug (toy), Feuerzeug (lighter). Literally 'stuff for X.'"},
{type:"tip",title:"Germany, Austria, Switzerland: one language, many words",text:"German is spoken in Germany (D), Austria (A), and Switzerland (CH). But each country has its own vocabulary, sometimes for everyday items.\n\nCream: Sahne (D) / Rahm (CH) / Obers (A)\nWhipped cream: Schlagsahne (D) / Schlagrahm (CH) / Schlagobers (A)\nCarrot: Karotte (D-south) / M\u00f6hre (D-north) / R\u00fcbe (D-regional)\nBread roll: Br\u00f6tchen (D-north) / Semmel (D-south, A) / Weggli (CH)\nJam: Marmelade (D, A) / Konfit\u00fcre (CH, formal D)\nSidewalk: B\u00fcrgersteig (D-north) / Gehsteig (D-south, A) / Trottoir (CH)\nBicycle: Fahrrad (D, A) / Velo (CH)\nParking: parken (D, A) / parkieren (CH)\n\nHamburg's 'Moin!' vs Berlin's 'Hallo' vs Bavaria's 'Gr\u00fc\u00df Gott' vs Switzerland's 'Gr\u00fcezi' shows that even greetings split by region.",deepDive:{title:"Why so many variants?",text:"Germany was not unified until 1871. Before that, it was hundreds of independent states, each developing its own dialect and vocabulary. Austria and Switzerland went their own way even earlier.\n\nSwiss German (Schweizerdeutsch) is so different from Standard German that Germans often cannot understand it. Austrian German (Osterreichisches Deutsch) is closer but has many unique words, especially for food.\n\nThe Goethe B1 exam accepts all standard variants. 'Semmel' is as correct as 'Br\u00f6tchen.' Understanding regional variants is part of B1 competence."}},
{type:"teach",trg:"der Rahm",src:"cream (Swiss German)",pos:"noun",gender:"m",note:"Standard in Switzerland. 'Rahmk\u00e4se' = cream cheese in Swiss German.",example:"A: In der Schweiz sagt man Rahm.\nB: Statt Sahne?\nA: Genau. Rahm, nicht Sahne.\nB: Interessant! Gleiches Produkt.",exampleSrc:"A: In Switzerland they say Rahm.\nB: Instead of Sahne?\nA: Exactly. Rahm, not Sahne.\nB: Interesting! Same product.",funFact:"Standard in Switzerland. 'Rahmk\u00e4se' = cream cheese in Swiss German. In Germany: Sahne. Same product, different countries."},
{type:"teach",trg:"der Schlagrahm",src:"whipped cream (Swiss)",pos:"noun",gender:"m",note:"Schlag + Rahm. On Swiss cafe menus where Germans see Schlagsahne.",example:"A: Einen Kaffee mit Schlagrahm, bitte.\nB: Sie sind aus der Schweiz?\nA: Ja! In Z\u00fcrich sagen wir Schlagrahm.\nB: Hier hei\u00dft das Schlagsahne.",exampleSrc:"A: A coffee with whipped cream, please.\nB: You are from Switzerland?\nA: Yes! In Z\u00fcrich we say Schlagrahm.\nB: Here it is called Schlagsahne.",funFact:"On a Swiss cafe menu where a German menu says Schlagsahne, you find Schlagrahm. Same product, different tradition."},
{type:"teach",trg:"die M\u00f6hre",src:"carrot (northern German)",pos:"noun",gender:"f",note:"In Hamburg, you hear M\u00f6hre. In Munich: Karotte.",example:"A: M\u00f6hren oder Karotten?\nB: In Hamburg: M\u00f6hren!\nA: Schmecken sie anders?\nB: Nein, nur der Name ist anders.",exampleSrc:"A: M\u00f6hren or Karotten?\nB: In Hamburg: M\u00f6hren!\nA: Do they taste different?\nB: No, only the name is different.",funFact:"Verumius learned Karotte first, now hears M\u00f6hre in Hamburg. In some regions: 'Gelbe R\u00fcbe.' Three words for one vegetable."},
{type:"teach",trg:"die Konfit\u00fcre",src:"jam/preserve (Swiss/formal)",pos:"noun",gender:"f",note:"EU regulation says non-citrus jam must be called Konfit\u00fcre. Swiss standard.",example:"A: Das ist Konfit\u00fcre, nicht Marmelade.\nB: Was ist der Unterschied?\nA: Technisch nur Zitrus = Marmelade.\nB: Das wusste ich nicht!",exampleSrc:"A: That is Konfit\u00fcre, not Marmelade.\nB: What is the difference?\nA: Technically only citrus = Marmelade.\nB: I did not know that!",funFact:"EU regulation says only citrus preserves can be 'Marmelade.' Everything else is technically 'Konfit\u00fcre.' The Swiss just followed the rule from the start."},
{type:"teach",trg:"das Schlagobers",src:"whipped cream (Austrian)",pos:"noun",gender:"n",note:"Schlag + Obers (cream, Austrian). In a Viennese Kaffeehaus: essential.",example:"A: Einen Melange mit Schlagobers, bitte!\nB: Das klingt wienerisch!\nA: Ja, in Wien sagt man Schlagobers.\nB: Und in Berlin: Schlagsahne.",exampleSrc:"A: A Melange with whipped cream, please!\nB: That sounds Viennese!\nA: Yes, in Vienna they say Schlagobers.\nB: And in Berlin: Schlagsahne.",funFact:"In a Viennese Kaffeehaus: 'Einen Melange mit Schlagobers, bitte!' In Berlin, that same order is 'Milchkaffee mit Schlagsahne.' Language geography in action."},
{type:"mc",q:"W\u00e4hrend ___ langen Reise schlief Verumius sofort ein.",opts:["der","die","des","dem"],ans:"der",hint:"W\u00e4hrend takes genitive. Reise is feminine. What does 'die' become in genitive?"},
{type:"fb",s:"Verumius traf den {1} am Bahnsteig.",a:["Kollegen"],opts:["Kollegen","Kollege","Kolleges","Kolleg"],hint:"Kollege is N-Deklination. What ending does it take in accusative?",sSrc:"Verumius met the colleague on the platform."},
{type:"mc",q:"In a Swiss cafe, how would you order whipped cream?",opts:["Schlagsahne","Schlagrahm","Schlagobers","Sahne"],ans:"Schlagrahm",hint:"Switzerland uses Rahm for cream. Whipped = Schlag + Rahm."},
{type:"drag_fill",s:"{1} {2} Aufenthalts in Hamburg besuchte Verumius die Elbphilharmonie.",blanks:{"1":"W\u00e4hrend","2":"des"},pool:["W\u00e4hrend","Trotz","des","der","dem","eines"],hint:"DURING the stay. Aufenthalt is masculine. Genitive masculine: des.",sSrc:"During the stay in Hamburg Verumius visited the Elbphilharmonie."},
{type:"match",pairs:[{trg:"Sahne (D)",src:"cream"},{trg:"Rahm (CH)",src:"cream"},{trg:"Semmel (A/South)",src:"bread roll"},{trg:"M\u00f6hre (North)",src:"carrot"},{trg:"Trottoir (CH)",src:"sidewalk"}]}
]}

]},

{n:16,lang:"de",srcLang:"en",track:"v2",title:"Der Streit",sub:"Neighbor conflict, Ruhezeit, indirect questions, nachdem + Plusquamperfekt",icon:"\uD83D\uDCDD",level:"B1.2",color:"#7B5EE8",lessons:[

// ============================================================
// Lesson 1: "Das Bohrloch" (The Drill Hole) — Story intro
// 20 new words, 24 steps
// ============================================================
{id:"deu_r16l1",title:"Das Bohrloch",icon:"\uD83D\uDD29",xp:15,board:true,steps:[
{type:"intro",title:"Das Bohrloch",desc:"Sunday evening, 20:05. Verumius has a drill and a shelf. What could go wrong? A lot, if you do not know the Ruhezeit (quiet hours).",goals:["Learn vocabulary for arguments, conflicts, and emotions","Discover the German Ruhezeit and Hausordnung","Experience Verumius's first neighbor dispute"]},
{type:"story",speaker:"narrator",mood:"scene-setting",art:"de-ber-apartment-drill",trg:"Sonntagabend, 20:05 Uhr. Verumius hat eine Bohrmaschine in der Hand und ein Regal an der Wand. Alles ist ruhig. Fast.",src:"Sunday evening, 8:05 PM. Verumius has a drill in his hand and a shelf on the wall. Everything is quiet. Almost."},
{type:"teach",trg:"der Streit",src:"the argument, the dispute",pos:"noun",gender:"m",note:"Covers everything from a small quarrel to a legal dispute.\nEinen Streit haben = to have an argument.",example:"A: Hattest du einen Streit mit dem Nachbarn?\nB: Ja, er war sehr laut.\nA: Was war das Problem?\nB: Ich habe am Sonntag gebohrt.",exampleSrc:"A: Did you have an argument with the neighbor?\nB: Yes, he was very loud.\nA: What was the problem?\nB: I drilled on Sunday.",funFact:"From Old High German 'strit' (battle). The word covers everything from a lovers' quarrel to a legal dispute. 'Einen Streit haben' is heard in every German apartment building."},
{type:"teach",trg:"der \u00c4rger",src:"the annoyance, the trouble",pos:"noun",gender:"m",note:"Related to 'arg' (bad). Trouble, annoyance, anger in one word.\n\u00c4rger machen = to cause trouble.",example:"A: Was ist los? Du siehst gestresst aus.\nB: Ich habe \u00c4rger mit dem Nachbarn.\nA: Schon wieder?\nB: Ja, wegen der Ruhezeit.",exampleSrc:"A: What's wrong? You look stressed.\nB: I have trouble with the neighbor.\nA: Again?\nB: Yes, because of the quiet hours.",funFact:"Related to 'arg' (bad/severe). Der \u00c4rger is trouble, annoyance, and anger rolled into one. The Umlaut dots make it hiss like frustration itself."},
{type:"teach",trg:"der Konflikt",src:"the conflict",pos:"noun",gender:"m",note:"Borrowed from Latin 'conflictus' (a striking together).\nA Streit can be small; a Konflikt is structural.",example:"A: Gibt es einen Konflikt im Haus?\nB: Ja, zwischen dem zweiten und dritten Stock.\nA: Was f\u00fcr ein Konflikt?\nB: L\u00e4rm am Wochenende.",exampleSrc:"A: Is there a conflict in the building?\nB: Yes, between the second and third floor.\nA: What kind of conflict?\nB: Noise on the weekend.",funFact:"Borrowed from Latin 'conflictus' (a striking together). Germans use it for serious disputes. A Streit can be small; a Konflikt is structural. Office politics, international relations, neighbor wars."},
{type:"teach",trg:"die Laune",src:"the mood",pos:"noun",gender:"f",note:"Gute Laune = good mood. Schlechte Laune = bad mood.\nLaunisch = moody.",example:"A: Wie ist deine Laune heute?\nB: Schlechte Laune. Der Nachbar hat geklopft.\nA: Das verdirbt die Laune.\nB: Ja, total.",exampleSrc:"A: How is your mood today?\nB: Bad mood. The neighbor knocked.\nA: That ruins the mood.\nB: Yes, totally.",funFact:"From Latin 'luna' (moon). The idea that moods change like moon phases. 'Launisch' means moody. Germans track moods like weather forecasts."},
{type:"teach",trg:"die Stimmung",src:"the atmosphere, the mood",pos:"noun",gender:"f",note:"From 'Stimme' (voice). The mood a group or room creates.\nDie Stimmung ist gut = the vibe is right.",example:"A: Wie war die Stimmung auf der Party?\nB: Am Anfang gut, dann gab es Streit.\nA: Oh nein. Wor\u00fcber?\nB: \u00dcber die Musik. Zu laut.",exampleSrc:"A: How was the atmosphere at the party?\nB: Good at first, then there was an argument.\nA: Oh no. About what?\nB: About the music. Too loud.",funFact:"From 'Stimme' (voice). The mood that a group or room creates together. Concert reviews always discuss Stimmung. A word that captures the collective emotional temperature."},
{type:"teach",trg:"der Nerv",src:"the nerve",pos:"noun",gender:"m",note:"Plural: Nerven. Du gehst mir auf die Nerven = You are getting on my nerves.",example:"A: Der L\u00e4rm geht mir auf die Nerven!\nB: Welcher L\u00e4rm?\nA: Die Bohrmaschine von oben!\nB: Das ist Verumius. Er bohrt seit einer Stunde.",exampleSrc:"A: The noise is getting on my nerves!\nB: What noise?\nA: The drill from upstairs!\nB: That's Verumius. He's been drilling for an hour.",funFact:"'Du gehst mir auf die Nerven' is THE German complaint phrase. Borrowed from Latin 'nervus.' Every neighbor dispute involves Nerven. Plural always: you never lose just one nerve."},
{type:"teach",trg:"die Sorge",src:"the worry, the concern",pos:"noun",gender:"f",note:"Keine Sorge! = No worries! Sich Sorgen machen = to worry.\nFeminine, like most abstract nouns ending in -e.",example:"A: Ich mache mir Sorgen wegen des Streits.\nB: Keine Sorge, das wird schon.\nA: Meinst du?\nB: Ja, sprich einfach mit dem Nachbarn.",exampleSrc:"A: I'm worried about the argument.\nB: No worries, it will be fine.\nA: You think so?\nB: Yes, just talk to the neighbor.",funFact:"'Keine Sorge!' (No worries!) is comforting. 'Sich Sorgen machen' uses the reflexive. Die Sorge is feminine, like most abstract nouns ending in -e."},
{type:"teach",trg:"der Vorwurf",src:"the accusation, the reproach",pos:"noun",gender:"m",note:"Vor (before) + Wurf (throw). You throw something in front of someone.\nJemandem Vorw\u00fcrfe machen = to accuse someone.",example:"A: Der Nachbar macht mir Vorw\u00fcrfe.\nB: Warum?\nA: Weil ich zu laut war.\nB: Hat er recht?",exampleSrc:"A: The neighbor is making accusations.\nB: Why?\nA: Because I was too loud.\nB: Is he right?",funFact:"Vor (before) + Wurf (throw). You throw something in front of someone. 'Jemandem Vorw\u00fcrfe machen' is the classic weapon in any German Streit."},
{type:"teach",trg:"die Vorschrift",src:"the regulation, the rule",pos:"noun",gender:"f",note:"Vor (before) + Schrift (writing). Something written beforehand.\nDie Hausordnung is a book of Vorschriften.",example:"A: Kennst du die Vorschriften im Haus?\nB: Nein, welche Vorschriften?\nA: Die Ruhezeit! Kein L\u00e4rm nach 20 Uhr.\nB: Das wusste ich nicht!",exampleSrc:"A: Do you know the regulations in the building?\nB: No, what regulations?\nA: The quiet hours! No noise after 8 PM.\nB: I didn't know that!",funFact:"Vor (before) + Schrift (writing). Something written down beforehand. Germans are famous for Vorschriften. The Hausordnung (house rules) is a book of Vorschriften."},
{type:"teach",trg:"das Verbot",src:"the prohibition, the ban",pos:"noun",gender:"n",note:"From 'verbieten' (to forbid). A Verbot is absolute.\nRauchverbot = smoking ban. Parkverbot = no parking.",example:"A: Gibt es ein Verbot f\u00fcr L\u00e4rm?\nB: Ja, w\u00e4hrend der Ruhezeit.\nA: Was passiert, wenn man das Verbot ignoriert?\nB: Man bekommt eine Warnung oder Strafe.",exampleSrc:"A: Is there a ban on noise?\nB: Yes, during the quiet hours.\nA: What happens if you ignore the ban?\nB: You get a warning or a fine.",funFact:"From 'verbieten' (to forbid). A Verbot is absolute: no exceptions. 'Rauchverbot' (smoking ban), 'Parkverbot' (no parking). German compounds with Verbot are everywhere."},
{type:"teach",trg:"die Strafe",src:"the punishment, the penalty",pos:"noun",gender:"f",note:"Zur Strafe = as punishment. Geldstrafe = fine.\nHaftstrafe = prison sentence.",example:"A: Gibt es eine Strafe f\u00fcr L\u00e4rm am Sonntag?\nB: Theoretisch ja, eine Geldstrafe.\nA: Wie viel?\nB: Bis zu f\u00fcnfhundert Euro.",exampleSrc:"A: Is there a penalty for noise on Sunday?\nB: Theoretically yes, a fine.\nA: How much?\nB: Up to five hundred euros.",funFact:"Geldstrafe = fine. Haftstrafe = prison sentence. The Ruhezeit violation Verumius just committed? In theory, a Strafe-worthy offense. In practice, usually just an angry note."},
{type:"teach",trg:"w\u00fctend",src:"furious, angry",pos:"adj",gender:null,note:"From 'Wut' (rage). Stronger than \u00e4rgerlich.\nW\u00fctend werden = to become furious.",example:"A: Der Nachbar ist w\u00fctend.\nB: Warum?\nA: Wegen der Bohrmaschine.\nB: Kann ich verstehen. Es ist Sonntagabend.",exampleSrc:"A: The neighbor is furious.\nB: Why?\nA: Because of the drill.\nB: I can understand. It's Sunday evening.",funFact:"From 'Wut' (rage). Stronger than \u00e4rgerlich. 'W\u00fctend werden' means to become furious. The neighbor above is probably w\u00fctend right now."},
{type:"teach",trg:"\u00e4rgerlich",src:"annoying, irritating",pos:"adj",gender:null,note:"From \u00c4rger. Can describe the annoyed person OR the annoying thing.\nDas ist \u00e4rgerlich = That is annoying.",example:"A: Das ist wirklich \u00e4rgerlich.\nB: Was ist \u00e4rgerlich?\nA: Die Situation mit dem Nachbarn.\nB: Ja, aber du bist auch \u00e4rgerlich f\u00fcr ihn.",exampleSrc:"A: That is really annoying.\nB: What is annoying?\nA: The situation with the neighbor.\nB: Yes, but you are also annoying to him.",funFact:"Can describe the person who is annoyed OR the thing that causes annoyance. 'Das ist \u00e4rgerlich' (That is annoying). Dual meaning, context decides."},
{type:"teach",trg:"ernst",src:"serious",pos:"adj",gender:null,note:"Im Ernst? = Seriously? Also a common first name.\nDie Lage ist ernst = The situation is serious.",example:"A: Ist die Situation ernst?\nB: Ja, der Nachbar will die Polizei rufen.\nA: Im Ernst?\nB: Ja, im Ernst.",exampleSrc:"A: Is the situation serious?\nB: Yes, the neighbor wants to call the police.\nA: Seriously?\nB: Yes, seriously.",funFact:"'Im Ernst?' (Seriously?) is everyday speech. Also a common first name (Ernst). 'Die Lage ist ernst' is how German news anchors begin bad news."},
{type:"teach",trg:"still",src:"quiet, silent",pos:"adj",gender:null,note:"Sei still! = Be quiet! Stilles Wasser = non-carbonated water.\nStille Nacht = Silent Night (the Christmas carol).",example:"A: Sei still! Der Nachbar schl\u00e4ft.\nB: Aber es ist erst acht Uhr!\nA: Ruhezeit. Alles muss still sein.\nB: In Deutschland ist sonntags alles still.",exampleSrc:"A: Be quiet! The neighbor is sleeping.\nB: But it's only eight o'clock!\nA: Quiet hours. Everything must be silent.\nB: In Germany everything is quiet on Sundays.",funFact:"'Sei still!' (Be quiet!) is what every German child hears. Also: 'Stille Nacht' (Silent Night), the Christmas carol written in Austria. Still water = Stilles Wasser (non-carbonated)."},
{type:"teach",trg:"schreien",src:"to scream, to shout",pos:"verb",gender:null,note:"Irregular: schrie, geschrien. Same root as English 'shriek'.\nSchrei nicht so! = Don't shout like that!",example:"A: Der Nachbar schreit!\nB: Warum schreit er?\nA: Er hat 'Ruhezeit!' geschrien.\nB: Er hat recht, auch wenn er schreit.",exampleSrc:"A: The neighbor is screaming!\nB: Why is he screaming?\nA: He screamed 'Quiet hours!'\nB: He's right, even if he's screaming.",funFact:"Irregular: schrie, geschrien. From the same root as English 'shriek.' 'Schrei nicht so!' is neighbor-dispute standard vocabulary."},
{type:"teach",trg:"schweigen",src:"to be silent, to stay quiet",pos:"verb",gender:null,note:"Irregular: schwieg, geschwiegen. The opposite of schreien.\nSchweigen ist Gold = Silence is golden.",example:"A: Was hat der Nachbar gesagt?\nB: Nichts. Er schweigt seit gestern.\nA: Er schweigt? Kein Wort?\nB: Kein Wort. Nur Schweigen.",exampleSrc:"A: What did the neighbor say?\nB: Nothing. He has been silent since yesterday.\nA: He's silent? Not a word?\nB: Not a word. Just silence.",funFact:"Irregular: schwieg, geschwiegen. The opposite of schreien. 'Schweigen ist Gold' (Silence is golden). A verb that means NOT making sound. Very German."},
{type:"teach",trg:"klagen",src:"to complain, to sue",pos:"verb",gender:null,note:"Same word for both meanings.\n\u00dcber etwas klagen = to complain about.\nGegen jemanden klagen = to sue someone.",example:"A: Der Nachbar klagt \u00fcber den L\u00e4rm.\nB: Klagt er nur, oder klagt er vor Gericht?\nA: Erstmal klagt er nur.\nB: Hoffentlich bleibt es dabei.",exampleSrc:"A: The neighbor is complaining about the noise.\nB: Is he just complaining, or is he suing?\nA: Just complaining for now.\nB: Hopefully it stays that way.",funFact:"Same word for both complaining and suing. In Germany, complaining and suing share linguistic DNA. The preposition decides: '\u00fcber' for complaining, 'gegen' for suing."},
{type:"teach",trg:"streiken",src:"to go on strike",pos:"verb",gender:null,note:"From English 'strike.' Borrowed during the Industrial Revolution.\nDeutsche Bahn strikes are legendary.",example:"A: Die M\u00fcllabfuhr streikt.\nB: Seit wann streiken sie?\nA: Seit drei Tagen.\nB: Kein Wunder, dass es hier stinkt.",exampleSrc:"A: The garbage collectors are on strike.\nB: Since when have they been striking?\nA: For three days.\nB: No wonder it stinks here.",funFact:"From English 'strike.' Germans borrowed it during the Industrial Revolution. Deutsche Bahn strikes are legendary. 'Die Nachbarn streiken' could mean they are on a noise protest."},
{type:"teach",trg:"blo\u00df",src:"just, merely, only",pos:"adv",gender:null,note:"As a Modalpartikel, adds desperation or emphasis.\nWas soll ich blo\u00df tun? = What on earth should I do?",example:"A: Was soll ich blo\u00df tun?\nB: Dich entschuldigen.\nA: Blo\u00df das?\nB: Ja, blo\u00df das. Ein einfaches 'Entschuldigung' reicht.",exampleSrc:"A: What on earth should I do?\nB: Apologize.\nA: Just that?\nB: Yes, just that. A simple 'sorry' is enough.",funFact:"As a Modalpartikel, it adds desperation or emphasis. 'Was soll ich blo\u00df tun?' expresses helplessness. Verumius is thinking this right now."},
{type:"story",speaker:"narrator",mood:"tense",art:"de-ber-apartment-door",trg:"Nachdem Verumius die Bohrmaschine abgestellt hatte, klopfte es an der T\u00fcr.",src:"After Verumius had turned off the drill, there was a knock at the door."},
{type:"mc",q:"Der Nachbar von Verumius ist w\u00fctend wegen des L\u00e4rms. Welches Wort beschreibt jemanden, der vor Wut kocht?",opts:["still","w\u00fctend","ernst","blo\u00df"],ans:"w\u00fctend",hint:"Dieses Wort kommt von 'Wut' und bedeutet voller Rage."}
]},

// ============================================================
// Lesson 2: "Die Hausordnung" (The House Rules) — Vocab teach
// 20 new words, 24 steps
// ============================================================
{id:"deu_r16l2",title:"Die Hausordnung",icon:"\uD83D\uDCCB",xp:15,board:true,steps:[
{type:"intro",title:"Die Hausordnung",desc:"Every German apartment building has a Hausordnung (house rules). Today you learn the language of blame, criticism, and compromise.",goals:["Learn vocabulary for arguments, complaints, and conflict resolution","Master words for blame, criticism, and compromise","Understand how Germans express disagreements"]},
{type:"teach",trg:"die Schuld",src:"the guilt, the fault, the debt",pos:"noun",gender:"f",note:"Three meanings in one word. Wer hat Schuld? = Whose fault?\nEntschuldigung literally means 'un-guilting.'",example:"A: Wer hat Schuld an dem Streit?\nB: Beide Seiten haben Schuld.\nA: Verumius hat die Ruhezeit verletzt.\nB: Aber der Nachbar hat geschrien.",exampleSrc:"A: Who is at fault for the argument?\nB: Both sides are at fault.\nA: Verumius violated the quiet hours.\nB: But the neighbor screamed.",funFact:"Three meanings in one word: guilt, fault, debt. 'Schulden' (debts) is the plural. 'Entschuldigung' literally means 'un-guilting.' You already know that word from Unit 1."},
{type:"teach",trg:"schuldig",src:"guilty",pos:"adj",gender:null,note:"Er ist schuldig = He is guilty. Used in courtrooms and arguments.\nThe opposite: unschuldig = innocent.",example:"A: Ist er schuldig?\nB: Der Richter sagt: schuldig.\nA: Und der Nachbar?\nB: Auch nicht ganz unschuldig.",exampleSrc:"A: Is he guilty?\nB: The judge says: guilty.\nA: And the neighbor?\nB: Also not entirely innocent.",funFact:"The -ig ending turns the noun Schuld into an adjective. Used in courtrooms and arguments. The opposite: unschuldig (innocent)."},
{type:"teach",trg:"schuld",src:"at fault (predicative only)",pos:"adj",gender:null,note:"Er ist schuld = He is to blame. Only with 'sein.'\nNo endings, no declension. A stripped-down blame word.",example:"A: Wer ist schuld?\nB: Verumius ist schuld.\nA: Nur er?\nB: Na ja, beide sind ein bisschen schuld.",exampleSrc:"A: Who is to blame?\nB: Verumius is to blame.\nA: Only him?\nB: Well, both are a little to blame.",funFact:"Unlike 'schuldig,' this form is only used with 'sein.' No endings, no declension. A stripped-down blame word for everyday finger-pointing."},
{type:"teach",trg:"die Kritik",src:"the criticism",pos:"noun",gender:"f",note:"From Greek 'kritike' (the art of judging).\nKritik \u00fcben = to exercise criticism (formal phrase).",example:"A: Die Kritik des Nachbarn war hart.\nB: Aber konstruktive Kritik?\nA: Nein, nur Beschwerden.\nB: Das ist keine Kritik, das ist Meckern.",exampleSrc:"A: The neighbor's criticism was harsh.\nB: But constructive criticism?\nA: No, just complaints.\nB: That's not criticism, that's grumbling.",funFact:"From Greek 'kritike' (the art of judging). Germans value 'konstruktive Kritik' (constructive criticism) in the workplace. Destructive criticism is just Meckern (grumbling)."},
{type:"teach",trg:"der Respekt",src:"the respect",pos:"noun",gender:"m",note:"Same in English, French, and many other languages.\nRespekt haben vor = to have respect for.",example:"A: Man muss Respekt vor den Nachbarn haben.\nB: Respekt bedeutet: leise sein nach acht.\nA: Stimmt. Respekt ist keine Einbahnstra\u00dfe.\nB: Respekt!",exampleSrc:"A: You must have respect for the neighbors.\nB: Respect means: be quiet after eight.\nA: True. Respect is not a one-way street.\nB: Respect!",funFact:"Same word in English, French, and a dozen other languages. 'Respekt!' on its own is slang for 'impressive!' Used seriously and casually."},
{type:"teach",trg:"die Geduld",src:"the patience",pos:"noun",gender:"f",note:"From 'dulden' (to endure). Geduld ist eine Tugend = Patience is a virtue.\nThe opposite: Ungeduld = impatience.",example:"A: Ich brauche Geduld mit meinem Nachbarn.\nB: Geduld ist eine Tugend.\nA: Wie lange muss ich noch Geduld haben?\nB: Bis er dir verzeiht.",exampleSrc:"A: I need patience with my neighbor.\nB: Patience is a virtue.\nA: How long do I still need to be patient?\nB: Until he forgives you.",funFact:"From 'dulden' (to endure). German bureaucracy requires enormous Geduld. The opposite is Ungeduld. 'Geduld ist eine Tugend' mirrors 'patience is a virtue.'"},
{type:"teach",trg:"der Kompromiss",src:"the compromise",pos:"noun",gender:"m",note:"From Latin 'compromissum.' In apartment disputes, the Kompromiss is king.\nEinen Kompromiss finden = to find a compromise.",example:"A: Wir m\u00fcssen einen Kompromiss finden.\nB: Welchen Kompromiss?\nA: Du bohrst nicht am Sonntag, ich beschwere mich nicht mehr.\nB: Das klingt nach einem fairen Kompromiss.",exampleSrc:"A: We need to find a compromise.\nB: What compromise?\nA: You don't drill on Sunday, I stop complaining.\nB: That sounds like a fair compromise.",funFact:"From Latin 'compromissum.' In German apartment disputes, the Kompromiss is king. 'Einen Kompromiss finden' resolves most Streit situations."},
{type:"teach",trg:"das Verst\u00e4ndnis",src:"the understanding, the comprehension",pos:"noun",gender:"n",note:"From 'verstehen' (to understand). The -nis ending creates neuter abstract nouns.\nIch habe Verst\u00e4ndnis daf\u00fcr = I understand/sympathize.",example:"A: Ich habe Verst\u00e4ndnis f\u00fcr den Nachbarn.\nB: Wirklich?\nA: Ja, er braucht seine Ruhe.\nB: Dann zeig ihm dein Verst\u00e4ndnis.",exampleSrc:"A: I have understanding for the neighbor.\nB: Really?\nA: Yes, he needs his peace.\nB: Then show him your understanding.",funFact:"The -nis ending creates neuter abstract nouns: Ergebnis, Erlebnis, Verst\u00e4ndnis. From 'verstehen' (to understand). A word for empathy with a grammatical pattern."},
{type:"teach",trg:"die Stimme",src:"the voice, the vote",pos:"noun",gender:"f",note:"Also means 'vote' (die Stimme abgeben = to cast a vote).\nFrom 'stimmen' (to be correct / to tune).",example:"A: Ich h\u00f6re eine laute Stimme.\nB: Das ist der Nachbar. Er hat eine starke Stimme.\nA: Er erhebt seine Stimme.\nB: Ja, und seine Stimme klingt w\u00fctend.",exampleSrc:"A: I hear a loud voice.\nB: That's the neighbor. He has a strong voice.\nA: He is raising his voice.\nB: Yes, and his voice sounds angry.",funFact:"Also means 'vote' (die Stimme abgeben = to cast a vote). From 'stimmen' (to be correct/to tune). Your voice, your vote, your tuning fork. All one word."},
{type:"teach",trg:"der Gedanke",src:"the thought",pos:"noun",gender:"m",note:"From 'denken' (to think). Weak masculine noun (N-Deklination):\nden Gedanken, dem Gedanken.",example:"A: Was ist dein erster Gedanke?\nB: Mein erster Gedanke: Entschuldigung.\nA: Ein guter Gedanke.\nB: Ja, jetzt muss ich diesen Gedanken umsetzen.",exampleSrc:"A: What is your first thought?\nB: My first thought: apology.\nA: A good thought.\nB: Yes, now I need to act on this thought.",funFact:"From 'denken' (to think). Weak masculine noun: der Gedanke, den Gedanken, dem Gedanken. One of those N-Deklination words."},
{type:"teach",trg:"kritisieren",src:"to criticize",pos:"verb",gender:null,note:"From Kritik. The -ieren ending marks verbs borrowed from French/Latin.\nAlways regular, always stressed on -ier-.",example:"A: Der Nachbar kritisiert mich st\u00e4ndig.\nB: Was genau kritisiert er?\nA: Alles. Den L\u00e4rm, die Musik, sogar meinen M\u00fcll.\nB: Manche Leute kritisieren einfach gern.",exampleSrc:"A: The neighbor criticizes me constantly.\nB: What exactly does he criticize?\nA: Everything. The noise, the music, even my trash.\nB: Some people just like to criticize.",funFact:"The -ieren ending marks verbs borrowed from French or Latin. Always regular, always stressed on the -ier-. 'Alles kritisieren' is a German stereotype."},
{type:"teach",trg:"beleidigen",src:"to insult, to offend",pos:"verb",gender:null,note:"Beleidigung (insult) is a crime in German law (Section 185 StGB).\nYou can be fined for insulting someone.",example:"A: Hat der Nachbar dich beleidigt?\nB: Ja, er hat mich beleidigt.\nA: Was hat er gesagt?\nB: Er hat mich einen 'r\u00fccksichtslosen Bohrer' genannt.",exampleSrc:"A: Did the neighbor insult you?\nB: Yes, he insulted me.\nA: What did he say?\nB: He called me a 'inconsiderate driller.'",funFact:"'Beleidigung' (insult) is actually a crime in German law (Section 185 StGB). You can be fined for insulting someone. The German legal system takes words seriously."},
{type:"teach",trg:"unterbrechen",src:"to interrupt",pos:"verb",gender:null,note:"Unter (under) + brechen (break). You break into someone's speech.\nInseparable prefix: Er unterbricht mich st\u00e4ndig.",example:"A: Lass mich ausreden! Du unterbrichst mich!\nB: Entschuldigung, ich unterbreche dich nicht mehr.\nA: Danke. Also, ich wollte sagen...\nB: Ja? Was?",exampleSrc:"A: Let me finish! You're interrupting me!\nB: Sorry, I won't interrupt you anymore.\nA: Thanks. So, I wanted to say...\nB: Yes? What?",funFact:"Unter (under) + brechen (break). You break into someone's speech from below. Inseparable prefix: 'Er unterbricht mich st\u00e4ndig.' A polite-sounding word for rude behavior."},
{type:"teach",trg:"widersprechen",src:"to contradict",pos:"verb",gender:null,note:"Wider (against) + sprechen (speak). To speak against.\nInseparable. Takes dative: Ich widerspreche dir.",example:"A: Ich widerspreche dir.\nB: Warum widersprichst du mir?\nA: Weil du nicht recht hast.\nB: Jeder hat das Recht zu widersprechen.",exampleSrc:"A: I contradict you.\nB: Why are you contradicting me?\nA: Because you are not right.\nB: Everyone has the right to contradict.",funFact:"Wider (against) + sprechen (speak). To speak against. Takes dative. A polite argument verb. 'Ich muss Ihnen widersprechen' is formal disagreement."},
{type:"teach",trg:"verlangen",src:"to demand, to require",pos:"verb",gender:null,note:"Stronger than 'bitten' (to ask).\nDas ist zu viel verlangt = That is asking too much.",example:"A: Der Nachbar verlangt eine Entschuldigung.\nB: Er verlangt das?\nA: Ja, er verlangt sogar eine schriftliche.\nB: Das ist zu viel verlangt!",exampleSrc:"A: The neighbor demands an apology.\nB: He demands that?\nA: Yes, he even demands a written one.\nB: That is asking too much!",funFact:"Stronger than 'bitten' (to ask). When your neighbor verlangt something, the Streit is escalating. 'Das ist zu viel verlangt' is a useful pushback phrase."},
{type:"teach",trg:"behaupten",src:"to claim, to assert",pos:"verb",gender:null,note:"From 'Haupt' (head). To hold your head up, maintain a position.\nEr behauptet, dass... = He claims that...",example:"A: Der Nachbar behauptet, dass ich jeden Tag bohre.\nB: Stimmt das?\nA: Nein! Ich behaupte das Gegenteil.\nB: Wer behauptet was, ist die Frage.",exampleSrc:"A: The neighbor claims that I drill every day.\nB: Is that true?\nA: No! I claim the opposite.\nB: Who claims what is the question.",funFact:"From 'Haupt' (head). To hold your head up, to maintain a position. Essential for indirect speech and reported claims. 'Er behauptet, dass...' is how arguments escalate."},
{type:"teach",trg:"frech",src:"cheeky, rude",pos:"adj",gender:null,note:"Sei nicht so frech! = Don't be so rude!\nOriginally meant 'brave/bold' in Old High German.",example:"A: Der Nachbar war ziemlich frech.\nB: Was hat er gesagt?\nA: 'Gehen Sie zur\u00fcck in Ihr Land!'\nB: Das ist nicht frech, das ist beleidigend.",exampleSrc:"A: The neighbor was quite rude.\nB: What did he say?\nA: 'Go back to your country!'\nB: That's not rude, that's offensive.",funFact:"Originally meant 'brave/bold' in Old High German. The meaning shifted from courage to impudence over centuries. 'Sei nicht so frech!' is every German parent's battle cry."},
{type:"teach",trg:"peinlich",src:"embarrassing",pos:"adj",gender:null,note:"From 'Pein' (pain/torment). Something peinlich causes social pain.\nDas ist mir peinlich = That embarrasses me.",example:"A: Die Situation war sehr peinlich.\nB: Was war peinlich?\nA: Alle Nachbarn haben den Streit geh\u00f6rt.\nB: Das ist wirklich peinlich.",exampleSrc:"A: The situation was very embarrassing.\nB: What was embarrassing?\nA: All the neighbors heard the argument.\nB: That is really embarrassing.",funFact:"From 'Pein' (pain/torment). Something peinlich causes social pain. 'Das ist mir peinlich.' Drilling on a Sunday? Peinlich."},
{type:"teach",trg:"merkw\u00fcrdig",src:"strange, odd",pos:"adj",gender:null,note:"Literally 'worthy of noticing' (merken + w\u00fcrdig).\nOriginally positive: remarkable. Now mostly means weird.",example:"A: Das ist merkw\u00fcrdig.\nB: Was ist merkw\u00fcrdig?\nA: Der Nachbar hat pl\u00f6tzlich aufgeh\u00f6rt zu klopfen.\nB: Vielleicht ist er eingeschlafen.",exampleSrc:"A: That is strange.\nB: What is strange?\nA: The neighbor suddenly stopped knocking.\nB: Maybe he fell asleep.",funFact:"Literally 'worthy of noticing' (merken + w\u00fcrdig). Originally positive: remarkable. Now mostly means weird. The shift from 'noteworthy' to 'odd' happened over centuries."},
{type:"teach",trg:"seltsam",src:"strange, peculiar",pos:"adj",gender:null,note:"From 'selten' (rarely). Something that happens seldom is seltsam.\nSlightly softer than merkw\u00fcrdig.",example:"A: Ein seltsamer Nachbar.\nB: Warum seltsam?\nA: Er schreibt Zettel statt zu reden.\nB: Das ist nicht seltsam, das ist deutsch.",exampleSrc:"A: A peculiar neighbor.\nB: Why peculiar?\nA: He writes notes instead of talking.\nB: That's not peculiar, that's German.",funFact:"From 'selten' (rarely). Something that happens seldom is seltsam. Slightly softer than merkw\u00fcrdig. 'Ein seltsamer Nachbar' is the polite way to say 'a weird neighbor.'"},
{type:"mc",q:"Der Nachbar sagt, es ist Verumius' Fehler. Welcher Satz passt?",opts:["Er hat Respekt.","Er ist schuld.","Er ist still.","Er hat Geduld."],ans:"Er ist schuld.",hint:"Die pr\u00e4dikative Form, die 'an etwas die Schuld tragen' bedeutet, benutzt 'sein.'"},
{type:"fb",s:"Der Nachbar {1}, dass Verumius zu laut war.",a:["behauptet"],opts:["behauptet","kritisiert","beleidigt","unterbricht"],hint:"Welches Verb bedeutet, etwas zu behaupten oder eine Aussage zu machen?",sSrc:"The neighbor claims that Verumius was too loud."},
{type:"match",pairs:[{trg:"Kritik",src:"criticism"},{trg:"Kompromiss",src:"compromise"},{trg:"Vorwurf",src:"accusation"},{trg:"Geduld",src:"patience"},{trg:"Schuld",src:"guilt/fault"},{trg:"Verst\u00e4ndnis",src:"understanding"}]}
]},

// ============================================================
// Lesson 3: "Die Zettel an der Wand" (The Notes on the Wall)
// Story dev + grammar intro — nachdem + Plusquamperfekt (#20)
// 20 new words, 24 steps
// ============================================================
{id:"deu_r16l3",title:"Die Zettel an der Wand",icon:"\uD83D\uDCCC",xp:15,board:true,steps:[
{type:"intro",title:"Die Zettel an der Wand",desc:"The next morning, three new notes hang in the stairwell. The conflict escalates on paper. Time to learn mediation vocabulary and master 'nachdem + Plusquamperfekt.'",goals:["Learn vocabulary for mediation and conflict resolution","Master 'nachdem + Plusquamperfekt' for time sequences","Read the note war in the stairwell"]},
{type:"story",speaker:"narrator",mood:"humorous",art:"de-ber-stairwell-notes",trg:"Nachdem Verumius den ersten Zettel gelesen hatte, fand er am n\u00e4chsten Morgen drei neue Zettel an der Wand.",src:"After Verumius had read the first note, he found three new notes on the wall the next morning."},
{type:"teach",trg:"das Geheimnis",src:"the secret",pos:"noun",gender:"n",note:"From 'geheim' (secret). The -nis ending creates neuter nouns.\nEin offenes Geheimnis = an open secret.",example:"A: Das Treppenhaus hat ein Geheimnis.\nB: Was f\u00fcr ein Geheimnis?\nA: Jeder wei\u00df, wer die Zettel schreibt.\nB: Das ist ein offenes Geheimnis.",exampleSrc:"A: The stairwell has a secret.\nB: What kind of secret?\nA: Everyone knows who writes the notes.\nB: That's an open secret.",funFact:"From 'geheim' (secret). The -nis ending creates neuter nouns. 'Ein offenes Geheimnis' is one everyone knows but nobody says aloud."},
{type:"teach",trg:"das Gewissen",src:"the conscience",pos:"noun",gender:"n",note:"From 'wissen' (to know). Your Gewissen is what you know inside.\nEin schlechtes Gewissen haben = to have a guilty conscience.",example:"A: Hast du ein schlechtes Gewissen?\nB: Ja, mein Gewissen plagt mich.\nA: Dann entschuldige dich.\nB: Mein Gewissen sagt das Gleiche.",exampleSrc:"A: Do you have a guilty conscience?\nB: Yes, my conscience is plaguing me.\nA: Then apologize.\nB: My conscience says the same thing.",funFact:"From 'wissen' (to know). Your Gewissen is what you know inside. 'Ein gutes Gewissen ist ein sanftes Ruhekissen' (A good conscience is a soft pillow)."},
{type:"teach",trg:"die Herausforderung",src:"the challenge",pos:"noun",gender:"f",note:"Heraus (out) + Forderung (demand). 16 letters.\nA demand that pulls you out of comfort.",example:"A: Das Zusammenleben ist eine Herausforderung.\nB: Ja, eine gro\u00dfe Herausforderung.\nA: Aber jede Herausforderung macht st\u00e4rker.\nB: Philosophisch. Aber wahr.",exampleSrc:"A: Living together is a challenge.\nB: Yes, a big challenge.\nA: But every challenge makes you stronger.\nB: Philosophical. But true.",funFact:"Heraus (out) + Forderung (demand). A demand that pulls you out of comfort. 16 letters. Living in Germany as a foreigner is eine gro\u00dfe Herausforderung."},
{type:"teach",trg:"die Kraft",src:"the strength, the power, the force",pos:"noun",gender:"f",note:"Mit voller Kraft = with full force.\nKraftwerk = power plant (and the famous electronic band).",example:"A: Ich brauche Kraft f\u00fcr dieses Gespr\u00e4ch.\nB: Du hast die Kraft.\nA: Woher nimmst du die Kraft?\nB: Aus dem Kaffee. Immer aus dem Kaffee.",exampleSrc:"A: I need strength for this conversation.\nB: You have the strength.\nA: Where do you get the strength from?\nB: From the coffee. Always from the coffee.",funFact:"'Mit voller Kraft' (with full force). Also in compound: 'Kraftwerk' (power plant, and the famous electronic band). Die Kraft is feminine, like most abstract -ft nouns."},
{type:"teach",trg:"der Mut",src:"the courage",pos:"noun",gender:"m",note:"Mut machen = to encourage. Mutig = courageous.\nVerumius braucht Mut, um an die T\u00fcr zu klopfen.",example:"A: Hast du den Mut, zum Nachbarn zu gehen?\nB: Ich brauche noch etwas Mut.\nA: Mut ist, wenn man Angst hat und es trotzdem tut.\nB: Okay. Ich gehe.",exampleSrc:"A: Do you have the courage to go to the neighbor?\nB: I need a bit more courage.\nA: Courage is when you're scared and do it anyway.\nB: Okay. I'll go.",funFact:"'Mut machen' (to encourage). 'Mutig' (courageous). Verumius needs Mut to knock on the neighbor's door and apologize."},
{type:"teach",trg:"das Herz",src:"the heart",pos:"noun",gender:"n",note:"Same root as English 'heart,' Latin 'cor,' Greek 'kardia.'\nVon Herzen = from the heart. Herzlich = heartfelt.",example:"A: Sprich von Herzen.\nB: Mein Herz sagt: Entschuldigung.\nA: Dann sag es mit Herz.\nB: Okay. Von ganzem Herzen: Es tut mir leid.",exampleSrc:"A: Speak from the heart.\nB: My heart says: sorry.\nA: Then say it with heart.\nB: Okay. With all my heart: I'm sorry.",funFact:"Same root as English 'heart,' Latin 'cor,' Greek 'kardia.' 'Von Herzen' (from the heart). 'Herzlich' (heartfelt) you already know from Unit 1."},
{type:"teach",trg:"das Gef\u00fchl",src:"the feeling, the emotion",pos:"noun",gender:"n",note:"From 'f\u00fchlen' (to feel). Plural: Gef\u00fchle.\nThe Ge- prefix + -l ending creates neuter collective nouns.",example:"A: Was ist dein Gef\u00fchl bei der Sache?\nB: Mein Gef\u00fchl sagt: entschuldigen.\nA: Vertrau deinem Gef\u00fchl.\nB: Meine Gef\u00fchle sind gemischt.",exampleSrc:"A: What is your feeling about the matter?\nB: My feeling says: apologize.\nA: Trust your feeling.\nB: My feelings are mixed.",funFact:"From 'f\u00fchlen' (to feel). The Ge- prefix + -l ending creates neuter collective nouns. 'Ein gutes Gef\u00fchl haben' means to have a good feeling about something."},
{type:"teach",trg:"beruhigen",src:"to calm (someone) down",pos:"verb",gender:null,note:"Be- + ruhig (quiet) + -en. Reflexive: sich beruhigen.\nThe be- prefix makes it transitive: you calm SOMEONE.",example:"A: Beruhige dich!\nB: Ich kann mich nicht beruhigen.\nA: Trink einen Tee. Das beruhigt.\nB: Okay, ich versuche mich zu beruhigen.",exampleSrc:"A: Calm down!\nB: I can't calm down.\nA: Drink a tea. That calms.\nB: Okay, I'll try to calm down.",funFact:"Be- + ruhig (quiet) + -en. 'Beruhige dich!' (Calm down!). The be- prefix makes it transitive: you calm SOMEONE. Reflexive: 'sich beruhigen.'"},
{type:"teach",trg:"entspannen",src:"to relax",pos:"verb",gender:null,note:"Ent- (un-) + spannen (to tense). To un-tense.\nEntspann dich! = Relax! Entspannung = relaxation.",example:"A: Du musst dich entspannen.\nB: Wie soll ich mich entspannen?\nA: Yoga? Meditation?\nB: Ich entspanne mich mit einer Bohrmaschine. Oh, warte...",exampleSrc:"A: You need to relax.\nB: How should I relax?\nA: Yoga? Meditation?\nB: I relax with a drill. Oh, wait...",funFact:"Ent- (un-) + spannen (to tense). To un-tense. 'Entspann dich!' (Relax!). 'Entspannung' (relaxation) is a German wellness keyword."},
{type:"teach",trg:"einigen",src:"to agree, to unite",pos:"verb",gender:null,note:"Sich einigen = to reach agreement. From 'ein' (one).\nWir haben uns geeinigt = We reached an agreement.",example:"A: K\u00f6nnen wir uns einigen?\nB: Ich hoffe, wir einigen uns.\nA: Wor\u00fcber sollen wir uns einigen?\nB: \u00dcber die Ruhezeiten.",exampleSrc:"A: Can we reach an agreement?\nB: I hope we agree.\nA: What should we agree on?\nB: On the quiet hours.",funFact:"From 'ein' (one). To become one mind. 'Wir haben uns geeinigt' (We reached an agreement). Essential conflict resolution verb."},
{type:"teach",trg:"entgegenkommen",src:"to meet halfway, to accommodate",pos:"verb",gender:null,note:"Entgegen (toward) + kommen (come). Separable.\nEr kommt mir entgegen = He meets me halfway.",example:"A: Der Nachbar kommt mir entgegen.\nB: Wirklich? Wie kommt er dir entgegen?\nA: Er erlaubt Bohren bis 19 Uhr.\nB: Das ist nett. Komm ihm auch entgegen.",exampleSrc:"A: The neighbor is meeting me halfway.\nB: Really? How is he meeting you halfway?\nA: He allows drilling until 7 PM.\nB: That's nice. Meet him halfway too.",funFact:"Entgegen (toward) + kommen (come). Separable: 'Er kommt mir entgegen.' Literally: someone comes toward you. Figuratively: compromise."},
{type:"teach",trg:"\u00fcberzeugen",src:"to convince",pos:"verb",gender:null,note:"\u00dcber (over) + zeugen (to witness/testify). Inseparable.\nIch bin \u00fcberzeugt = I am convinced.",example:"A: Kannst du den Nachbarn \u00fcberzeugen?\nB: Ich versuche ihn zu \u00fcberzeugen.\nA: Bist du \u00fcberzeugt, dass es klappt?\nB: Ich bin nicht \u00fcberzeugt, aber ich versuche es.",exampleSrc:"A: Can you convince the neighbor?\nB: I'll try to convince him.\nA: Are you convinced it will work?\nB: I'm not convinced, but I'll try.",funFact:"\u00dcber (over) + zeugen (to witness/testify). To bring someone over to your testimony. 'Ich bin \u00fcberzeugt' (I am convinced). Inseparable prefix."},
{type:"teach",trg:"\u00fcberreden",src:"to persuade, to talk into",pos:"verb",gender:null,note:"\u00dcber + reden (talk). Slightly manipulative vs \u00fcberzeugen.\nEr hat mich \u00fcberredet = He talked me into it.",example:"A: Hildi hat mich \u00fcberredet.\nB: Wozu hat sie dich \u00fcberredet?\nA: Zum Nachbarn zu gehen und mich zu entschuldigen.\nB: \u00dcberredet oder \u00fcberzeugt?",exampleSrc:"A: Hildi talked me into it.\nB: Into what did she talk you?\nA: Going to the neighbor and apologizing.\nB: Talked into or convinced?",funFact:"\u00dcber + reden (talk). To talk someone over. Slightly manipulative compared to \u00fcberzeugen. '\u00dcberreden' uses emotion; '\u00fcberzeugen' uses logic."},
{type:"teach",trg:"loben",src:"to praise",pos:"verb",gender:null,note:"Lob = praise (noun). Nicht geschimpft ist genug gelobt.\nGermans praise sparingly; when they loben, they mean it.",example:"A: Hildi lobt Verumius.\nB: Wof\u00fcr lobt sie ihn?\nA: F\u00fcr seinen Mut.\nB: Ein Lob von Hildi ist viel wert.",exampleSrc:"A: Hildi praises Verumius.\nB: What does she praise him for?\nA: For his courage.\nB: A compliment from Hildi is worth a lot.",funFact:"'Nicht geschimpft ist genug gelobt' (Not scolded is enough praised) is a Swabian saying. Germans praise sparingly; when they loben, they mean it."},
{type:"teach",trg:"reichen",src:"to suffice, to hand/pass",pos:"verb",gender:null,note:"Two meanings: 'Das reicht!' (That is enough!) and\n'Kannst du mir das Salz reichen?' (Can you pass me the salt?).",example:"A: Reicht eine Entschuldigung?\nB: Ich glaube, das reicht.\nA: Kannst du mir den Zettel reichen?\nB: Hier, bitte. Reicht dir ein Zettel?",exampleSrc:"A: Is an apology enough?\nB: I think that's enough.\nA: Can you pass me the note?\nB: Here you go. Is one note enough?",funFact:"Two everyday uses in one verb: 'Das reicht!' (That is enough!) and 'Kannst du mir das Salz reichen?' (Can you pass me the salt?). Context is everything."},
{type:"teach",trg:"ehrlich",src:"honest",pos:"adj",gender:null,note:"From 'Ehre' (honor). Ehrlich gesagt... = Honestly speaking...\nEhrlich w\u00e4hrt am l\u00e4ngsten = Honesty lasts longest.",example:"A: Sei ehrlich. War es laut?\nB: Ehrlich gesagt, ja.\nA: Danke f\u00fcr die ehrliche Antwort.\nB: Ehrlich w\u00e4hrt am l\u00e4ngsten.",exampleSrc:"A: Be honest. Was it loud?\nB: Honestly speaking, yes.\nA: Thanks for the honest answer.\nB: Honesty lasts longest.",funFact:"From 'Ehre' (honor). 'Ehrlich gesagt...' begins many German confessions. 'Ehrlich w\u00e4hrt am l\u00e4ngsten' is the German version of 'honesty is the best policy.'"},
{type:"teach",trg:"fair",src:"fair",pos:"adj",gender:null,note:"Borrowed from English. Pronounced 'fehr' in German.\nAdopted because 'gerecht' felt too formal.",example:"A: Das war nicht fair!\nB: Was war nicht fair?\nA: Der Zettel an der Wand. Er nennt meinen Namen.\nB: Stimmt, das ist nicht fair.",exampleSrc:"A: That was not fair!\nB: What was not fair?\nA: The note on the wall. It names my name.\nB: True, that is not fair.",funFact:"Borrowed from English. Pronounced 'fehr' in German. Used constantly in arguments. Germans adopted this word because 'gerecht' felt too formal for everyday disputes."},
{type:"teach",trg:"tolerant",src:"tolerant",pos:"adj",gender:null,note:"Same spelling as English, from Latin 'tolerare' (to endure).\nBerlin prides itself on being tolerant.",example:"A: Man muss tolerant sein.\nB: Ich bin tolerant, aber nicht bei L\u00e4rm.\nA: Toleranz hat Grenzen?\nB: Jede Toleranz hat Grenzen. Besonders sonntags.",exampleSrc:"A: You have to be tolerant.\nB: I'm tolerant, but not with noise.\nA: Tolerance has limits?\nB: Every tolerance has limits. Especially on Sundays.",funFact:"Same spelling as English, from Latin 'tolerare' (to endure). Berlin prides itself on being tolerant. The apartment building is testing that claim."},
{type:"teach",trg:"treu",src:"loyal, faithful",pos:"adj",gender:null,note:"Treu wie Gold = faithful as gold. Same root as English 'true.'\nA treu friend, a treu dog, a treu neighbor.",example:"A: Ein treuer Nachbar beschwert sich nicht sofort.\nB: Bist du ein treuer Nachbar?\nA: Ich versuche treu zu sein.\nB: Dann sei treu und entschuldige dich.",exampleSrc:"A: A loyal neighbor doesn't complain immediately.\nB: Are you a loyal neighbor?\nA: I try to be loyal.\nB: Then be loyal and apologize.",funFact:"Same root as English 'true.' 'Treu wie Gold' (faithful as gold). A treu friend, a treu dog, a treu neighbor who does not drill on Sundays."},
{type:"teach",trg:"dankbar",src:"grateful",pos:"adj",gender:null,note:"Dank (thanks) + -bar (able). Ich bin dankbar = I am grateful.\nThe -bar suffix works like English '-able.'",example:"A: Ich bin dankbar f\u00fcr Hildis Hilfe.\nB: Wof\u00fcr genau bist du dankbar?\nA: Dass sie zwischen uns vermittelt.\nB: Ja, wir sollten alle dankbar sein.",exampleSrc:"A: I'm grateful for Hildi's help.\nB: What exactly are you grateful for?\nA: That she's mediating between us.\nB: Yes, we should all be grateful.",funFact:"Dank (thanks) + -bar (able). The -bar suffix works like English '-able': dankbar, machbar (doable), essbar (edible)."},
{type:"tip",title:"nachdem + Plusquamperfekt: Ordering Past Events",text:"'nachdem' = 'after.' The nachdem clause uses the Plusquamperfekt (hatte/war + Partizip II) because the event happened FIRST.\n\nThe main clause uses Perfekt or Präteritum.\n\nExample:\nNachdem er den Zettel gelesen hatte, ging er zum Nachbarn.\n(After he had read the note, he went to the neighbor.)\n\nThe verb goes to the END in the nachdem clause.\n\nEarlier (Plusquamperfekt) -> later (Präteritum/Perfekt).",deepDive:{title:"Plusquamperfekt: The Past Before the Past",text:"The Plusquamperfekt shows what happened BEFORE another event in the past.\n\nFormation: hatte/war + Partizip II\n\nWith haben: Ich hatte gelesen (I had read)\nWith sein: Er war gegangen (He had gone)\n\nNote: The same verbs that use 'sein' in Perfekt also use 'war' in Plusquamperfekt:\ngehen: war gegangen\nkommen: war gekommen\nfahren: war gefahren"}},
{type:"fb",s:"Nachdem Verumius die Bohrmaschine abgestellt {1}, klopfte es an der T\u00fcr.",a:["hatte"],opts:["hatte","hat","war","ist"],hint:"Die nachdem-Klausel braucht Plusquamperfekt. Welches Hilfsverb passt zu 'abgestellt'?",sSrc:"After Verumius had turned off the drill, there was a knock at the door."}
]},

// ============================================================
// Lesson 4: "Indirekte Fragen" (Indirect Questions) — Grammar
// 20 new words, 24 steps
// ============================================================
{id:"deu_r16l4",title:"Indirekte Fragen",icon:"\u2753",xp:15,board:true,steps:[
{type:"intro",title:"Indirekte Fragen",desc:"Direct questions are direct. Indirect questions are polite. Learn how to ask elegantly in German without seeming rude.",goals:["Master indirect questions with W-words and 'ob'","Learn vocabulary for relationships and emotions","Combine time sequences with indirect speech"]},
{type:"teach",trg:"die Diskussion",src:"the discussion",pos:"noun",gender:"f",note:"From Latin 'discussio' (examination). More structured than a Streit.\nEine Diskussion f\u00fchren = to lead a discussion.",example:"A: Wir brauchen eine sachliche Diskussion.\nB: Keine Diskussion ohne Respekt.\nA: Die Diskussion \u00fcber L\u00e4rm muss sein.\nB: Einverstanden. Beginnen wir die Diskussion.",exampleSrc:"A: We need an objective discussion.\nB: No discussion without respect.\nA: The discussion about noise must happen.\nB: Agreed. Let's begin the discussion.",funFact:"From Latin 'discussio' (examination). More structured than a Streit. Germans value 'sachliche Diskussion' (objective discussion). Subjective = Streit. Objective = Diskussion."},
{type:"teach",trg:"die Beziehung",src:"the relationship",pos:"noun",gender:"f",note:"From 'beziehen' (to relate to). Covers romantic, professional, international.\nIn einer Beziehung sein = to be in a relationship.",example:"A: Wie ist deine Beziehung zum Nachbarn?\nB: Kompliziert. Die Beziehung ist angespannt.\nA: Eine gute Beziehung braucht Arbeit.\nB: Wie bei jeder Beziehung.",exampleSrc:"A: How is your relationship with the neighbor?\nB: Complicated. The relationship is tense.\nA: A good relationship takes work.\nB: Like every relationship.",funFact:"From 'beziehen' (to relate to). Covers romantic, professional, and international relationships. 'In einer Beziehung sein' is the Facebook status in German."},
{type:"teach",trg:"die Freundschaft",src:"the friendship",pos:"noun",gender:"f",note:"Freund + -schaft (collective suffix, like English '-ship').\nGermans distinguish sharply between Freunde and Bekannte.",example:"A: Kann aus Nachbarschaft Freundschaft werden?\nB: Manchmal. Echte Freundschaft braucht Zeit.\nA: Freundschaft beginnt mit Respekt.\nB: Und Marmelade.",exampleSrc:"A: Can neighborhood turn into friendship?\nB: Sometimes. Real friendship takes time.\nA: Friendship begins with respect.\nB: And jam.",funFact:"Freund (friend) + -schaft (collective suffix, like English '-ship'). Germans distinguish sharply between Freunde (friends) and Bekannte (acquaintances). Freundschaft is earned, not given."},
{type:"teach",trg:"die Ehe",src:"the marriage",pos:"noun",gender:"f",note:"One of the shortest German nouns. From Old High German 'ewa' (law).\nDie Ehe schlie\u00dfen = to enter marriage.",example:"A: Eine Ehe ist wie eine Nachbarschaft.\nB: Wie meinst du das?\nA: Man muss Kompromisse finden.\nB: In der Ehe und im Treppenhaus.",exampleSrc:"A: A marriage is like a neighborhood.\nB: What do you mean?\nA: You have to find compromises.\nB: In marriage and in the stairwell.",funFact:"One of the shortest German nouns. From Old High German 'ewa' (law/eternity). 'Ehe' also means 'before' as a conjunction. Marriage and 'before' share a word. Coincidence? Debatable."},
{type:"teach",trg:"das Ehepaar",src:"the married couple",pos:"noun",gender:"n",note:"Ehe + Paar (pair). The compound tells you everything:\na pair bonded by Ehe.",example:"A: Das Ehepaar von nebenan ist nett.\nB: Welches Ehepaar?\nA: Herr und Frau M\u00fcller.\nB: Ach, das Ehepaar mit dem Hund.",exampleSrc:"A: The married couple next door is nice.\nB: Which married couple?\nA: Mr. and Mrs. M\u00fcller.\nB: Oh, the married couple with the dog.",funFact:"Ehe + Paar (pair). The compound tells you everything: a pair bonded by Ehe. The neighbor and his wife are ein Ehepaar."},
{type:"teach",trg:"die Scheidung",src:"the divorce",pos:"noun",gender:"f",note:"From 'scheiden' (to separate). Die Scheidung einreichen = to file for divorce.\nGermany has a mandatory one-year separation period.",example:"A: Die Scheidung war schwer.\nB: Ja, eine Scheidung ist nie leicht.\nA: Aber nach der Scheidung ging es besser.\nB: Manchmal ist eine Scheidung der richtige Weg.",exampleSrc:"A: The divorce was hard.\nB: Yes, a divorce is never easy.\nA: But after the divorce things got better.\nB: Sometimes a divorce is the right path.",funFact:"From 'scheiden' (to separate). Germany has a mandatory one-year separation period (Trennungsjahr) before divorce. No shortcuts."},
{type:"teach",trg:"die Trennung",src:"the separation",pos:"noun",gender:"f",note:"From 'trennen' (to separate). Broader than Scheidung: any split.\nDie Trennung von Kirche und Staat = separation of church and state.",example:"A: Die Trennung vom Nachbarn w\u00e4re sch\u00f6n.\nB: Du kannst dich nicht von deinem Nachbarn trennen.\nA: Doch, ich ziehe um.\nB: Das ist eine radikale Trennung.",exampleSrc:"A: A separation from the neighbor would be nice.\nB: You can't separate from your neighbor.\nA: Yes I can, I'll move.\nB: That's a radical separation.",funFact:"From 'trennen' (to separate). Broader than Scheidung: any split. 'Mulltrennung' (waste separation) uses the same word. Domestic and romantic contexts, same verb."},
{type:"teach",trg:"der Schreck",src:"the fright, the shock",pos:"noun",gender:"m",note:"Einen Schreck bekommen = to get a fright.\nShort, sharp, immediate. The moment of shock.",example:"A: Ich habe einen Schreck bekommen!\nB: Warum? Was war der Schreck?\nA: Der Nachbar stand pl\u00f6tzlich vor der T\u00fcr.\nB: Das war ein gro\u00dfer Schreck.",exampleSrc:"A: I got a fright!\nB: Why? What was the shock?\nA: The neighbor was suddenly at the door.\nB: That was a big fright.",funFact:"'Einen Schreck bekommen' (to get a fright). Short, sharp, immediate. Der Schreck is the moment of shock. Related to 'erschrecken.'"},
{type:"teach",trg:"der Schrecken",src:"the horror, the terror",pos:"noun",gender:"m",note:"Longer and deeper than Schreck. Der Schrecken des Krieges = the horror of war.\nZu meinem Schrecken... = To my horror...",example:"A: Der Schrecken des Zettelkriegs.\nB: Schrecken? Das ist kein Krieg!\nA: F\u00fcr Verumius ist es ein Schrecken.\nB: Zu meinem Schrecken hast du recht.",exampleSrc:"A: The horror of the note war.\nB: Horror? This is no war!\nA: For Verumius it is a horror.\nB: To my horror, you're right.",funFact:"Longer and deeper than Schreck. 'Der Schrecken des Krieges' (the horror of war). Can also mean fright: 'Zu meinem Schrecken...' (To my horror...)."},
{type:"teach",trg:"die Entt\u00e4uschung",src:"the disappointment",pos:"noun",gender:"f",note:"Ent- (un-) + T\u00e4uschung (deception). To be un-deceived.\nGerman frames disappointment as losing a false belief.",example:"A: Was f\u00fcr eine Entt\u00e4uschung!\nB: Ja, die Entt\u00e4uschung ist gro\u00df.\nA: Ich bin entt\u00e4uscht vom Nachbarn.\nB: Jede Entt\u00e4uschung lehrt etwas.",exampleSrc:"A: What a disappointment!\nB: Yes, the disappointment is great.\nA: I'm disappointed in the neighbor.\nB: Every disappointment teaches something.",funFact:"Ent- (un-) + T\u00e4uschung (deception). To be un-deceived, to have illusions removed. German frames disappointment as losing a false belief. Philosophical."},
{type:"teach",trg:"leiden",src:"to suffer",pos:"verb",gender:null,note:"Irregular: litt, gelitten. Ich kann ihn nicht leiden = I can't stand him.\nAlso: Leid tun = to be sorry (Es tut mir leid).",example:"A: Ich leide unter dem L\u00e4rm.\nB: Ich kann den L\u00e4rm auch nicht leiden.\nA: Wir leiden beide.\nB: Ja, das ganze Haus leidet.",exampleSrc:"A: I'm suffering from the noise.\nB: I can't stand the noise either.\nA: We're both suffering.\nB: Yes, the whole building is suffering.",funFact:"Irregular: litt, gelitten. 'Ich kann ihn nicht leiden' (I cannot stand him) is the common idiom. Also: 'Leid tun' (to be sorry). 'Es tut mir leid.'"},
{type:"teach",trg:"entt\u00e4uschen",src:"to disappoint",pos:"verb",gender:null,note:"From Entt\u00e4uschung. Inseparable prefix: ent- stays attached.\nDu entt\u00e4uschst mich = You disappoint me.",example:"A: Du entt\u00e4uschst mich.\nB: Es tut mir leid, dich zu entt\u00e4uschen.\nA: Entt\u00e4usch mich nicht noch einmal.\nB: Ich werde dich nicht entt\u00e4uschen.",exampleSrc:"A: You disappoint me.\nB: I'm sorry to disappoint you.\nA: Don't disappoint me again.\nB: I won't disappoint you.",funFact:"Inseparable prefix: ent- stays attached. Regular conjugation despite the irregular-looking stem. 'Du entt\u00e4uschst mich' is a heavy accusation in any language."},
{type:"teach",trg:"erschrecken",src:"to frighten / to be frightened",pos:"verb",gender:null,note:"Two verbs in one! Transitive (frighten): regular.\nIntransitive (be frightened): irregular (erschrak, erschrocken).",example:"A: Erschreck mich nicht!\nB: Entschuldigung, ich wollte dich nicht erschrecken.\nA: Ich bin erschrocken.\nB: Ich erschrecke mich auch leicht.",exampleSrc:"A: Don't scare me!\nB: Sorry, I didn't mean to scare you.\nA: I was frightened.\nB: I also get scared easily.",funFact:"Two verbs in one. Transitive (frighten someone): regular. Intransitive (be frightened): irregular (erschrak, erschrocken). One of German's sneakiest verbs."},
{type:"teach",trg:"trennen",src:"to separate",pos:"verb",gender:null,note:"Sich trennen = to break up. Regular verb.\nM\u00fclltrennung = waste separation. Same verb, different contexts.",example:"A: Sollen wir uns trennen?\nB: Du meinst die Diskussion trennen?\nA: Ja, Thema L\u00e4rm und Thema Respekt trennen.\nB: Gute Idee. Eins nach dem anderen.",exampleSrc:"A: Should we separate?\nB: You mean separate the discussion?\nA: Yes, separate the topic of noise and the topic of respect.\nB: Good idea. One at a time.",funFact:"'Sich trennen' (to break up). Regular verb. 'M\u00fclltrennung' (waste separation) was in U8. Same verb, domestic and romantic contexts."},
{type:"teach",trg:"scheiden",src:"to divorce, to separate (formally)",pos:"verb",gender:null,note:"Irregular: schied, geschieden. Sich scheiden lassen = to get divorced.\nThe 'lassen' construction adds formality.",example:"A: Sie wollen sich scheiden lassen.\nB: Warum lassen sie sich scheiden?\nA: Zu viel Streit.\nB: Nicht jeder Streit endet in Scheidung.",exampleSrc:"A: They want to get divorced.\nB: Why are they getting divorced?\nA: Too much arguing.\nB: Not every argument ends in divorce.",funFact:"Irregular: schied, geschieden. 'Sich scheiden lassen' (to get divorced). The 'lassen' construction adds formality. Legal and permanent."},
{type:"teach",trg:"f\u00fcrchten",src:"to fear",pos:"verb",gender:null,note:"Sich f\u00fcrchten vor = to be afraid of. From 'Furcht' (fear).\nFurchtbar = terrible (literally 'fear-able').",example:"A: Verumius f\u00fcrchtet den n\u00e4chsten Zettel.\nB: Er f\u00fcrchtet sich vor dem Nachbarn?\nA: Nein, er f\u00fcrchtet sich vor weiteren Beschwerden.\nB: Furcht ist normal nach einem Streit.",exampleSrc:"A: Verumius fears the next note.\nB: He's afraid of the neighbor?\nA: No, he's afraid of more complaints.\nB: Fear is normal after an argument.",funFact:"'Sich f\u00fcrchten vor' (to be afraid of). From 'Furcht' (fear). 'Furchtbar' (terrible, literally 'fear-able'). Verumius f\u00fcrchtet sich vor dem n\u00e4chsten Zettel."},
{type:"teach",trg:"hassen",src:"to hate",pos:"verb",gender:null,note:"Strong word. Regular conjugation. Same root as English 'hate.'\n'Hass' (hatred) is a legal concept in Hassrede (hate speech).",example:"A: Ich hasse L\u00e4rm.\nB: Alle hassen L\u00e4rm.\nA: Aber ich hasse auch Zettel.\nB: Du hasst Zettel mehr als L\u00e4rm?",exampleSrc:"A: I hate noise.\nB: Everyone hates noise.\nA: But I also hate notes.\nB: You hate notes more than noise?",funFact:"Strong word. Same root as English 'hate.' Germans use it seriously. 'Hass' (hatred) is also a legal concept in Hassrede (hate speech)."},
{type:"teach",trg:"langweilen",src:"to bore",pos:"verb",gender:null,note:"Sich langweilen = to be bored. From 'Langeweile' (boredom).\nReflexive for being bored, transitive for boring others.",example:"A: Langweilt dich der Streit?\nB: Nein, er langweilt mich nicht.\nA: Mich langweilt er schon.\nB: Dann lass uns den Streit beenden.",exampleSrc:"A: Does the argument bore you?\nB: No, it doesn't bore me.\nA: It bores me already.\nB: Then let's end the argument.",funFact:"'Sich langweilen' (to be bored). From 'Langeweile' (boredom, literally 'long-while'). Reflexive for being bored, transitive for boring others."},
{type:"teach",trg:"verzeihen",src:"to forgive",pos:"verb",gender:null,note:"Irregular: verzieh, verziehen. Verzeihung! = Forgiveness! (I'm sorry).\nMore formal than 'Entschuldigung.'",example:"A: K\u00f6nnen Sie mir verzeihen?\nB: Ich verzeihe Ihnen.\nA: Wirklich? Sie verzeihen mir?\nB: Ja, Verzeihung geh\u00f6rt zum Leben.",exampleSrc:"A: Can you forgive me?\nB: I forgive you.\nA: Really? You forgive me?\nB: Yes, forgiveness is part of life.",funFact:"Irregular: verzieh, verziehen. 'Verzeihung!' is a formal apology, more polished than 'Entschuldigung.' The peace-offering verb."},
{type:"teach",trg:"verzichten",src:"to give up, to do without",pos:"verb",gender:null,note:"Auf etwas verzichten = to forgo something.\nIch verzichte auf mein Recht = I waive my right.",example:"A: Ich verzichte auf das Bohren am Sonntag.\nB: Du verzichtest darauf? Wirklich?\nA: Ja, ich verzichte gern darauf.\nB: Darauf zu verzichten ist ein guter Anfang.",exampleSrc:"A: I'm giving up drilling on Sundays.\nB: You're giving that up? Really?\nA: Yes, I'm happy to give it up.\nB: Giving that up is a good start.",funFact:"'Auf etwas verzichten' (to forgo something). Takes auf + accusative. A conscious decision to let go. 'Ich verzichte auf mein Recht' (I waive my right)."},
{type:"tip",title:"Indirekte Fragen: h\u00f6fliches Deutsch",text:"Direkt: 'Wo ist das B\u00fcro?' (Where is the office?)\nIndirekt: 'K\u00f6nnen Sie mir sagen, wo das B\u00fcro ist?'\n\nDas Verb wandert ans ENDE nach dem W-Wort.\n\nF\u00fcr Ja/Nein-Fragen benutze 'ob':\n'Wissen Sie, ob er zu Hause ist?' (Do you know whether he is home?)\n\nH\u00f6fliche Einleitungen:\n- K\u00f6nnen/K\u00f6nnten Sie mir sagen, ...?\n- Ich m\u00f6chte wissen, ...\n- Wissen Sie, ...?\n- D\u00fcrfte ich fragen, ...?",deepDive:{title:"Verb-Endstellung in Nebens\u00e4tzen",text:"In jedem Nebensatz steht das konjugierte Verb am Ende:\n\n- dass er kommt (that he comes)\n- weil sie krank ist (because she is sick)\n- ob er zu Hause ist (whether he is home)\n- wo das B\u00fcro ist (where the office is)\n\nIndirekte Fragen sind Nebens\u00e4tze. Darum gilt die gleiche Regel: Verb ans Ende.\n\nDirekt: Wo ist er? -> Indirekt: ..., wo er ist.\nDirekt: Kommt er? -> Indirekt: ..., ob er kommt."}},
{type:"mc",q:"Welcher Satz fragt korrekt 'K\u00f6nnen Sie mir sagen, wo das B\u00fcro ist?'?",opts:["K\u00f6nnen Sie mir sagen, wo ist das B\u00fcro?","Sagen Sie mir, wo ist das B\u00fcro?","K\u00f6nnen Sie mir sagen, wo das B\u00fcro ist?","Wo das B\u00fcro ist, k\u00f6nnen Sie mir sagen?"],ans:"K\u00f6nnen Sie mir sagen, wo das B\u00fcro ist?",hint:"In indirekten Fragen geht das Verb ans Ende der Klausel."},
{type:"drag_fill",s:"Nachdem er den Brief gelesen {1}, wollte er wissen, {2} der Nachbar wirklich w\u00fctend {3}.",blanks:{"1":"hatte","2":"ob","3":"war"},pool:["hatte","ob","war","hat","dass","ist"],hint:"Eine nachdem + Plusquamperfekt-Klausel, gefolgt von einer indirekten Ja/Nein-Frage mit ob + Verb am Ende.",sSrc:"After he had read the letter, he wanted to know whether the neighbor was really angry."}
]},

// ============================================================
// Lesson 5: "Hildi greift ein" (Hildi Intervenes) — Vocab + review
// 20 new words, 24 steps
// ============================================================
{id:"deu_r16l5",title:"Hildi greift ein",icon:"\u2696\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Hildi greift ein",desc:"Hildi turns her living room into a courtroom. Tea, Hausordnung, and reading glasses. The mediation begins.",goals:["Learn vocabulary for law and justice","Practice nachdem and indirect questions in context","Witness Hildi mediating better than any lawyer"]},
{type:"story",speaker:"hildi",mood:"authoritative",art:"de-ber-hildi-mediation",trg:"Nachdem ich die Hausordnung gelesen hatte, wusste ich sofort, wer Recht hat.",src:"After I had read the house rules, I knew immediately who is right."},
{type:"teach",trg:"der Polizist",src:"the policeman",pos:"noun",gender:"m",note:"From 'Polizei' (police). Weak masculine noun (N-Deklination):\nden Polizisten, dem Polizisten.",example:"A: Sollen wir einen Polizisten rufen?\nB: Nein, wir brauchen keinen Polizisten.\nA: Der Polizist w\u00fcrde den Streit beenden.\nB: Hildi beendet den Streit schneller.",exampleSrc:"A: Should we call a policeman?\nB: No, we don't need a policeman.\nA: The policeman would end the argument.\nB: Hildi ends the argument faster.",funFact:"From 'Polizei' (police). Weak masculine noun (N-Deklination): den Polizisten, dem Polizisten. 'Die Polizei rufen' (to call the police)."},
{type:"teach",trg:"die Polizistin",src:"the policewoman",pos:"noun",gender:"f",note:"Polizist + -in. About 30% of German police officers are women.\nThe feminine -in suffix you know from Unit 1.",example:"A: Die Polizistin war sehr nett.\nB: Welche Polizistin?\nA: Die Polizistin, die letzte Woche hier war.\nB: Ach, wegen des L\u00e4rms?",exampleSrc:"A: The policewoman was very nice.\nB: Which policewoman?\nA: The policewoman who was here last week.\nB: Oh, because of the noise?",funFact:"Polizist + -in. The feminine -in suffix is always added for female professionals. About 30% of German police officers are women, and rising."},
{type:"teach",trg:"der Richter",src:"the judge",pos:"noun",gender:"m",note:"From 'richten' (to direct/judge). Vor dem Richter stehen = to stand before the judge.\nGerman judges do not use gavels.",example:"A: Hildi ist wie ein Richter.\nB: Sie ist kein Richter, sie ist Nachbarin.\nA: Aber sie urteilt wie ein Richter.\nB: Ein Richter mit Lesebrille und Tee.",exampleSrc:"A: Hildi is like a judge.\nB: She's no judge, she's a neighbor.\nA: But she judges like a judge.\nB: A judge with reading glasses and tea.",funFact:"From 'richten' (to direct/judge). German judges do not use gavels. They simply say 'Im Namen des Volkes' (In the name of the people)."},
{type:"teach",trg:"die Richterin",src:"the female judge",pos:"noun",gender:"f",note:"Richter + -in. Germany's highest court has had several Richterinnen.\nThe -in suffix is always added for female professionals.",example:"A: Die Richterin hat das Urteil gesprochen.\nB: Was hat die Richterin gesagt?\nA: Die Richterin sagt: beide haben Recht.\nB: Eine weise Richterin.",exampleSrc:"A: The judge delivered the verdict.\nB: What did the judge say?\nA: The judge says: both are right.\nB: A wise judge.",funFact:"Richter + -in. Germany's highest court (Bundesverfassungsgericht) has had several Richterinnen. The -in suffix is always added for female professionals."},
{type:"teach",trg:"der Anwalt",src:"the lawyer",pos:"noun",gender:"m",note:"From Old High German 'anawalt' (representative).\nEinen Anwalt nehmen = to get a lawyer.",example:"A: Brauchst du einen Anwalt?\nB: Einen Anwalt? Wegen eines Streits?\nA: Man wei\u00df nie.\nB: Hildi ist billiger als jeder Anwalt.",exampleSrc:"A: Do you need a lawyer?\nB: A lawyer? Because of an argument?\nA: You never know.\nB: Hildi is cheaper than any lawyer.",funFact:"From Old High German 'anawalt' (representative). Germans have Rechtsschutzversicherung (legal insurance) because they sue so often. Well, so goes the stereotype."},
{type:"teach",trg:"die Anw\u00e4ltin",src:"the female lawyer",pos:"noun",gender:"f",note:"Anwalt + -in. Note: no Umlaut change.\nSome words Umlaut when adding -in, this one does not.",example:"A: Meine Anw\u00e4ltin sagt, ich habe Recht.\nB: Du hast eine Anw\u00e4ltin?\nA: Nein, Hildi spielt die Anw\u00e4ltin.\nB: Die beste Anw\u00e4ltin im Haus.",exampleSrc:"A: My lawyer says I'm right.\nB: You have a lawyer?\nA: No, Hildi is playing the lawyer.\nB: The best lawyer in the building.",funFact:"Anwalt + -in. Note: some words Umlaut when adding -in (Arzt/\u00c4rztin), others do not (Anwalt/Anw\u00e4ltin). This one does not."},
{type:"teach",trg:"der Strafzettel",src:"the ticket, the fine",pos:"noun",gender:"m",note:"Strafe + Zettel (note/ticket). A punishment-note.\nEinen Strafzettel bekommen = to get a ticket.",example:"A: Verumius hat einen Strafzettel bekommen.\nB: Wof\u00fcr?\nA: Falschparken.\nB: Erst L\u00e4rm, dann Falschparken. Was kommt als N\u00e4chstes?",exampleSrc:"A: Verumius got a ticket.\nB: For what?\nA: Illegal parking.\nB: First noise, then illegal parking. What's next?",funFact:"Strafe + Zettel (note/ticket). A punishment-note. Parking tickets, noise violation notices. 'Einen Strafzettel bekommen' is a rite of passage in Germany."},
{type:"teach",trg:"die Kriminalpolizei",src:"the criminal investigation department",pos:"noun",gender:"f",note:"Kriminal + Polizei. Abbreviated: die Kripo.\nEvery German crime TV show features the Kripo.",example:"A: Brauchen wir die Kriminalpolizei?\nB: Die Kripo? Wegen eines Bohrlochs?\nA: Nein, nat\u00fcrlich nicht.\nB: Gut. Die Kriminalpolizei hat Besseres zu tun.",exampleSrc:"A: Do we need the criminal police?\nB: The Kripo? Because of a drill hole?\nA: No, of course not.\nB: Good. The criminal police have better things to do.",funFact:"Abbreviated: die Kripo. Handles serious crimes. Every German crime TV show (Tatort, anyone?) features the Kripo."},
{type:"teach",trg:"der Prozess",src:"the trial, the process",pos:"noun",gender:"m",note:"From Latin 'processus.' Einen Prozess f\u00fchren = to conduct a trial.\nAlso means process in general.",example:"A: Es wird keinen Prozess geben.\nB: Ein Prozess wegen L\u00e4rm?\nA: Nein, der Prozess der Vers\u00f6hnung.\nB: Der wichtigste Prozess.",exampleSrc:"A: There won't be a trial.\nB: A trial because of noise?\nA: No, the process of reconciliation.\nB: The most important process.",funFact:"From Latin 'processus.' 'Einen Prozess f\u00fchren' (to conduct a trial). Also means process in general. Legal and general, one word."},
{type:"teach",trg:"das Urteil",src:"the verdict, the judgment",pos:"noun",gender:"n",note:"Ur- (original/primal) + Teil (part). The original division.\nEin Urteil f\u00e4llen = to pass judgment.",example:"A: Hildis Urteil war klar.\nB: Was war ihr Urteil?\nA: Beide Seiten m\u00fcssen sich entschuldigen.\nB: Ein faires Urteil.",exampleSrc:"A: Hildi's verdict was clear.\nB: What was her verdict?\nA: Both sides must apologize.\nB: A fair verdict.",funFact:"Ur- (original/primal) + Teil (part). The original division: guilty or not guilty. 'Ein Urteil f\u00e4llen' (to pass judgment). Also: opinion. 'Sich ein Urteil bilden.'"},
{type:"teach",trg:"das Risiko",src:"the risk",pos:"noun",gender:"n",note:"From Italian 'risico.' Plural: Risiken.\nEin Risiko eingehen = to take a risk.",example:"A: Es war ein Risiko, am Sonntag zu bohren.\nB: Ja, ein gro\u00dfes Risiko.\nA: Das Risiko hat sich nicht gelohnt.\nB: N\u00e4chstes Mal: kein Risiko.",exampleSrc:"A: It was a risk to drill on Sunday.\nB: Yes, a big risk.\nA: The risk didn't pay off.\nB: Next time: no risk.",funFact:"From Italian 'risico.' Plural: Risiken (not Risikos). 'Ein Risiko eingehen' (to take a risk). Drilling on Sunday was definitely ein Risiko."},
{type:"teach",trg:"der Verdacht",src:"the suspicion",pos:"noun",gender:"m",note:"From 'verd\u00e4chtig' (suspicious). Unter Verdacht stehen = to be under suspicion.\nVerdacht sch\u00f6pfen = to grow suspicious.",example:"A: Der Nachbar hat einen Verdacht.\nB: Welchen Verdacht?\nA: Dass Verumius auch unter der Woche bohrt.\nB: Das ist ein falscher Verdacht!",exampleSrc:"A: The neighbor has a suspicion.\nB: What suspicion?\nA: That Verumius also drills during the week.\nB: That's a false suspicion!",funFact:"'Unter Verdacht stehen' (to be under suspicion). 'Verdacht sch\u00f6pfen' (to grow suspicious, literally to scoop suspicion). Used in crime shows constantly."},
{type:"teach",trg:"verd\u00e4chtig",src:"suspicious",pos:"adj",gender:null,note:"From Verdacht. Das ist verd\u00e4chtig = That is suspicious.\nSich verd\u00e4chtig machen = to make oneself look suspicious.",example:"A: Das ist verd\u00e4chtig.\nB: Was ist verd\u00e4chtig?\nA: Dass der Nachbar pl\u00f6tzlich freundlich ist.\nB: Freundlichkeit ist nicht verd\u00e4chtig!",exampleSrc:"A: That is suspicious.\nB: What is suspicious?\nA: That the neighbor is suddenly friendly.\nB: Friendliness is not suspicious!",funFact:"From Verdacht. 'Das ist verd\u00e4chtig' (That is suspicious). 'Sich verd\u00e4chtig machen' (to make oneself look suspicious). Crime show vocabulary, now in your apartment."},
{type:"teach",trg:"strafbar",src:"punishable",pos:"adj",gender:null,note:"Strafe + -bar. Strafbare Handlung = punishable act.\nDrilling during Ruhezeit is technically strafbar.",example:"A: Ist L\u00e4rm w\u00e4hrend der Ruhezeit strafbar?\nB: Theoretisch ja, das ist strafbar.\nA: Wie strafbar?\nB: Geldbu\u00dfe bis f\u00fcnfhundert Euro.",exampleSrc:"A: Is noise during quiet hours punishable?\nB: Theoretically yes, that is punishable.\nA: How punishable?\nB: Fine up to five hundred euros.",funFact:"Strafe + -bar. Drilling during Ruhezeit is technically strafbar in some municipalities. Usually just gets you a stern note."},
{type:"teach",trg:"gerecht",src:"just, fair",pos:"adj",gender:null,note:"From 'Recht' (right/law). Gerechtigkeit = justice.\nFormal version of 'fair.'",example:"A: Hildis Urteil war gerecht.\nB: War es wirklich gerecht?\nA: Ja, beide Seiten waren zufrieden.\nB: Dann war es gerecht.",exampleSrc:"A: Hildi's verdict was just.\nB: Was it really fair?\nA: Yes, both sides were satisfied.\nB: Then it was fair.",funFact:"From 'Recht' (right/law). 'Gerechtigkeit' (justice). Hildi wants a gerechtes Urteil. 'Gerecht und fair' uses both the German and the borrowed English word."},
{type:"teach",trg:"unentschieden",src:"undecided, tied",pos:"adj",gender:null,note:"Un- + entschieden (decided). Das Spiel endete unentschieden.\nIn the neighbor dispute: both sides have valid points.",example:"A: Wer hat gewonnen?\nB: Unentschieden.\nA: In einem Streit gibt es kein Unentschieden.\nB: Bei Hildi schon. Beide haben Recht.",exampleSrc:"A: Who won?\nB: A draw.\nA: In an argument there's no draw.\nB: With Hildi there is. Both are right.",funFact:"Un- + entschieden (decided). 'Das Spiel endete unentschieden' (The match ended in a draw). In the neighbor dispute: both sides have valid points. Unentschieden."},
{type:"teach",trg:"gespannt",src:"excited, eager, tense",pos:"adj",gender:null,note:"From 'spannen' (to tense). Ich bin gespannt! = I'm curious/excited!\nLike a rubber band pulled tight with anticipation.",example:"A: Ich bin gespannt auf das Ergebnis.\nB: Wir sind alle gespannt.\nA: Gespannt wie ein Flitzebogen.\nB: Die Stimmung ist gespannt.",exampleSrc:"A: I'm eager about the result.\nB: We're all eager.\nA: Tense as a bowstring.\nB: The atmosphere is tense.",funFact:"From 'spannen' (to tense). Like a rubber band pulled tight with anticipation. 'Gespannt warten' (to wait eagerly). Both positive (excited) and negative (tense) meaning."},
{type:"teach",trg:"\u00e4ngstlich",src:"anxious, fearful",pos:"adj",gender:null,note:"From 'Angst' (fear/anxiety). \u00c4ngstlich sein = to be fearful.\nThe English word 'angst' was borrowed from German.",example:"A: Verumius ist \u00e4ngstlich.\nB: Warum \u00e4ngstlich?\nA: Er f\u00fcrchtet die Reaktion des Nachbarn.\nB: Sei nicht so \u00e4ngstlich. Hildi ist dabei.",exampleSrc:"A: Verumius is anxious.\nB: Why anxious?\nA: He fears the neighbor's reaction.\nB: Don't be so anxious. Hildi is there.",funFact:"From 'Angst' (fear/anxiety). The English word 'angst' was borrowed directly from German. You already know a world-famous German word."},
{type:"teach",trg:"einsam",src:"lonely",pos:"adj",gender:null,note:"From 'ein' (one) + -sam (tendency suffix). One-tending.\nSich einsam f\u00fchlen = to feel lonely.",example:"A: Der Nachbar f\u00fchlt sich vielleicht einsam.\nB: Einsam? Er hat doch seine Frau.\nA: Einsam trotzdem. Einsam kann man auch zu zweit sein.\nB: Tiefe Worte f\u00fcr einen Zettelkrieg.",exampleSrc:"A: The neighbor maybe feels lonely.\nB: Lonely? He has his wife.\nA: Lonely anyway. You can be lonely even as a pair.\nB: Deep words for a note war.",funFact:"From 'ein' (one) + -sam (tendency suffix). One-tending. Someone who tends toward being alone. The neighbor might be einsam, hence the complaints."},
{type:"teach",trg:"stolz",src:"proud",pos:"adj",gender:null,note:"Stolz auf etwas sein = to be proud of something.\nTakes auf + accusative.",example:"A: Hildi ist stolz auf ihre Mediation.\nB: Sie kann stolz sein.\nA: Ich bin stolz auf dich, Hildi.\nB: Danke. Ich bin stolz auf euch alle.",exampleSrc:"A: Hildi is proud of her mediation.\nB: She can be proud.\nA: I'm proud of you, Hildi.\nB: Thanks. I'm proud of all of you.",funFact:"'Stolz auf etwas sein' (to be proud of something). Takes auf + accusative. 'Ich bin stolz auf dich' (I am proud of you). A word Hildi uses after successful mediation."},
{type:"teach",trg:"mutig",src:"courageous, brave",pos:"adj",gender:null,note:"From 'Mut' (courage). Mutig sein = to be brave.\nThe -ig ending turns nouns into adjectives: Mut -> mutig.",example:"A: Das war mutig von dir.\nB: Mutig? Ich hatte Angst.\nA: Trotzdem mutig. Mut ist Handeln trotz Angst.\nB: Dann war ich sehr mutig.",exampleSrc:"A: That was brave of you.\nB: Brave? I was scared.\nA: Brave anyway. Courage is acting despite fear.\nB: Then I was very brave.",funFact:"From 'Mut' (courage). The -ig ending turns nouns into adjectives: Mut -> mutig, Schuld -> schuldig, Hunger -> hungrig. A productive pattern."},
{type:"teach",trg:"k\u00e4mpfen",src:"to fight, to struggle",pos:"verb",gender:null,note:"From 'Kampf' (fight/battle). F\u00fcr etwas k\u00e4mpfen = to fight for something.\nRelated to English 'camp' (military).",example:"A: Er k\u00e4mpft f\u00fcr seine Ruhe.\nB: Und Verumius k\u00e4mpft f\u00fcr sein Regal.\nA: Beide k\u00e4mpfen f\u00fcr das Richtige.\nB: Wenn alle k\u00e4mpfen, braucht man Hildi.",exampleSrc:"A: He fights for his peace.\nB: And Verumius fights for his shelf.\nA: Both fight for the right thing.\nB: When everyone fights, you need Hildi.",funFact:"From 'Kampf' (fight/battle). 'F\u00fcr etwas k\u00e4mpfen' (to fight for something). Related to Latin 'campus' (field, as in battlefield)."},
{type:"teach",trg:"schlie\u00dflich",src:"finally, after all",pos:"adv",gender:null,note:"From 'schlie\u00dfen' (to close). The closing word of an argument.\nSchlie\u00dflich hat er Recht = After all, he is right.",example:"A: Schlie\u00dflich hat Hildi recht.\nB: Ja, schlie\u00dflich kennt sie die Regeln.\nA: Schlie\u00dflich wohnt sie hier am l\u00e4ngsten.\nB: Schlie\u00dflich sind wir alle Nachbarn.",exampleSrc:"A: After all, Hildi is right.\nB: Yes, after all, she knows the rules.\nA: After all, she's lived here the longest.\nB: After all, we're all neighbors.",funFact:"From 'schlie\u00dfen' (to close). The closing word of an argument. 'Schlie\u00dflich' signals the final point. Used constantly in everyday reasoning."},
{type:"mc",q:"Hildi fragt: 'Wissen Sie, ob das wirklich _____ ist?'",opts:["gespannt","dankbar","einsam","strafbar"],ans:"strafbar",hint:"Hildi pr\u00fcft den rechtlichen Status. Welches Wort beschreibt eine Handlung, die bestraft werden kann?"},
{type:"fb",s:"Nachdem Hildi das Urteil gesprochen {1}, waren beide Nachbarn zufrieden.",a:["hatte"],opts:["hatte","hat","ist","war"],hint:"Nachdem braucht Plusquamperfekt: Hilfsverb + Partizip II. Das Hilfsverb f\u00fcr 'sprechen' ist 'haben.'",sSrc:"After Hildi had spoken the verdict, both neighbors were satisfied."},
{type:"mc",q:"Verumius m\u00f6chte wissen, ob der Nachbar ihm verzeihen kann. Welche indirekte Frage ist korrekt?",opts:["Er fragt, ob der Nachbar ihm verzeihen k\u00f6nnen.","Er fragt, ob kann der Nachbar ihm verzeihen.","Er fragt, der Nachbar ob ihm verzeihen kann.","Er fragt, ob der Nachbar ihm verzeihen kann."],ans:"Er fragt, ob der Nachbar ihm verzeihen kann.",hint:"Nach 'ob' steht das konjugierte Verb am Ende des Nebensatzes."},
{type:"match",pairs:[{trg:"Polizist",src:"policeman"},{trg:"Richterin",src:"female judge"},{trg:"Anwalt",src:"lawyer"},{trg:"Urteil",src:"verdict"},{trg:"Risiko",src:"risk"},{trg:"Prozess",src:"trial"}]}
]},

// ============================================================
// Lesson 6: "Heinrichs Weisheit" (Heinrich's Wisdom) — Story climax
// 20 new words, 24 steps
// ============================================================
{id:"deu_r16l6",title:"Heinrichs Weisheit",icon:"\uD83D\uDCDE",xp:15,board:true,steps:[
{type:"intro",title:"Heinrichs Weisheit",desc:"Hildi calls Heinrich. He yells through the phone. But his wisdom is worth gold. Learn trust, betrayal, and ver- prefix verbs.",goals:["Learn vocabulary for trust and betrayal","Hear Heinrich's phone wisdom","Combine nachdem + indirect questions in one sentence"]},
{type:"story",speaker:"hildi",mood:"warm",art:"de-ber-hildi-kitchen-phone",trg:"Warte, ich rufe Heinrich an. Er wei\u00df immer, was man in solchen Situationen tun soll.",src:"Wait, I'll call Heinrich. He always knows what to do in situations like these."},
{type:"teach",trg:"das Vertrauen",src:"the trust",pos:"noun",gender:"n",note:"From 'trauen' (to trust/dare). Vertrauen ist gut, Kontrolle ist besser.\nAttributed to Lenin, but Germans live by it.",example:"A: Vertrauen ist die Basis jeder Beziehung.\nB: Auch einer Nachbarschaft?\nA: Besonders einer Nachbarschaft.\nB: Vertrauen braucht Zeit.",exampleSrc:"A: Trust is the basis of every relationship.\nB: Even a neighborhood?\nA: Especially a neighborhood.\nB: Trust takes time.",funFact:"'Vertrauen ist gut, Kontrolle ist besser' (Trust is good, control is better). Attributed to Lenin, but Germans live by it. Also the unofficial motto of the Hausordnung."},
{type:"teach",trg:"die Verzeihung",src:"the forgiveness, the pardon",pos:"noun",gender:"f",note:"The noun from 'verzeihen.' Verzeihung! = formal apology.\nMore polished than 'Entschuldigung.'",example:"A: Verzeihung!\nB: Wof\u00fcr bitten Sie um Verzeihung?\nA: F\u00fcr den L\u00e4rm am Sonntag.\nB: Verzeihung angenommen.",exampleSrc:"A: Pardon!\nB: What are you asking forgiveness for?\nA: For the noise on Sunday.\nB: Forgiveness accepted.",funFact:"More polished than 'Entschuldigung.' Used when bumping into someone at the opera, not at the supermarket. 'Verzeihung!' is a formal apology in one word."},
{type:"teach",trg:"die Wunde",src:"the wound",pos:"noun",gender:"f",note:"Both physical and emotional. Alte Wunden aufrei\u00dfen = to reopen old wounds.\nThe neighbor dispute has left Wunden.",example:"A: Der Streit hat Wunden hinterlassen.\nB: Welche Wunden?\nA: Emotionale Wunden.\nB: Zeit heilt alle Wunden.",exampleSrc:"A: The argument has left wounds.\nB: What wounds?\nA: Emotional wounds.\nB: Time heals all wounds.",funFact:"Both physical and emotional. 'Alte Wunden aufrei\u00dfen' (to reopen old wounds). 'Zeit heilt alle Wunden' (Time heals all wounds). The same proverb in both languages."},
{type:"teach",trg:"die Tr\u00e4ne",src:"the tear (teardrop)",pos:"noun",gender:"f",note:"Usually plural: Tr\u00e4nen. Tr\u00e4nen in den Augen = tears in the eyes.\nKrokodilstr\u00e4nen = crocodile tears.",example:"A: Tr\u00e4nen sind keine Schw\u00e4che.\nB: Hatte der Nachbar Tr\u00e4nen?\nA: Fast. Tr\u00e4nen lagen in der Luft.\nB: Tr\u00e4nen wegen eines Bohrlochs?",exampleSrc:"A: Tears are not weakness.\nB: Did the neighbor have tears?\nA: Almost. Tears were in the air.\nB: Tears because of a drill hole?",funFact:"Usually plural: Tr\u00e4nen. 'Krokodilstr\u00e4nen' (crocodile tears) exists in German too. Same metaphor, same skepticism."},
{type:"teach",trg:"das Ungl\u00fcck",src:"the misfortune, the accident",pos:"noun",gender:"n",note:"Un- + Gl\u00fcck (luck/happiness). Ein Ungl\u00fcck kommt selten allein.\nThe opposite of everything good.",example:"A: Ein Ungl\u00fcck kommt selten allein.\nB: Was f\u00fcr ein Ungl\u00fcck?\nA: Erst der Streit, dann das Kl\u00e4ren.\nB: Das ist kein Ungl\u00fcck, das ist das Leben.",exampleSrc:"A: Misfortune rarely comes alone.\nB: What misfortune?\nA: First the argument, then the making up.\nB: That's not misfortune, that's life.",funFact:"Un- + Gl\u00fcck (luck/happiness). 'Ein Ungl\u00fcck kommt selten allein' (Misfortune rarely comes alone). Das Ungl\u00fcck. The opposite of everything good."},
{type:"teach",trg:"der Schade",src:"the pity, the shame",pos:"noun",gender:"m",note:"Das ist schade = That is a pity. Also an exclamation: Schade!\nOne of the most useful expressions of mild disappointment.",example:"A: Schade, dass es so gekommen ist.\nB: Ja, wirklich schade.\nA: Es ist ein Schade f\u00fcr alle.\nB: Aber kein bleibender Schade.",exampleSrc:"A: What a pity it came to this.\nB: Yes, really a pity.\nA: It's a shame for everyone.\nB: But no lasting damage.",funFact:"'Das ist schade' (That is a pity). Also an exclamation: 'Schade!' Used constantly in daily conversation. One of the most useful expressions of mild disappointment."},
{type:"teach",trg:"der Schaden",src:"the damage",pos:"noun",gender:"m",note:"Different from Schade (pity). Einen Schaden verursachen = to cause damage.\n'Schadenfreude' is Germany's most famous export word.",example:"A: Gibt es einen Schaden?\nB: Nur ein kleines Loch in der Wand.\nA: Der Schaden ist gering.\nB: Gering, aber der Nachbar sieht das anders.",exampleSrc:"A: Is there any damage?\nB: Just a small hole in the wall.\nA: The damage is minor.\nB: Minor, but the neighbor sees it differently.",funFact:"Different from Schade (pity). 'Schadenfreude' (joy at others' misfortune) is Germany's most famous export word. 'Einen Schaden verursachen' = to cause damage."},
{type:"teach",trg:"der Verlust",src:"the loss",pos:"noun",gender:"m",note:"From 'verlieren' (to lose). Einen Verlust erleiden = to suffer a loss.\nFinancial, personal, game loss. Der Verlust covers them all.",example:"A: Der Verlust von Vertrauen ist das Schlimmste.\nB: Ja, ein gro\u00dfer Verlust.\nA: Aber Vertrauen kann man wieder aufbauen.\nB: Nach jedem Verlust kommt ein Neuanfang.",exampleSrc:"A: The loss of trust is the worst.\nB: Yes, a great loss.\nA: But trust can be rebuilt.\nB: After every loss comes a new beginning.",funFact:"From 'verlieren' (to lose). 'Einen Verlust erleiden' (to suffer a loss). Financial loss, personal loss, game loss. Der Verlust covers them all."},
{type:"teach",trg:"vertrauen",src:"to trust",pos:"verb",gender:null,note:"Jemandem vertrauen = to trust someone. Takes dative.\nIch vertraue dir = I trust you.",example:"A: Kannst du mir vertrauen?\nB: Ich vertraue dir.\nA: Wirklich? Du vertraust mir?\nB: Ja, ich vertraue dir. Aber bohre nicht mehr am Sonntag.",exampleSrc:"A: Can you trust me?\nB: I trust you.\nA: Really? You trust me?\nB: Yes, I trust you. But don't drill on Sunday anymore.",funFact:"'Jemandem vertrauen' (to trust someone). Takes dative. 'Ich vertraue dir' (I trust you). The verb version of Vertrauen. Essential for any relationship."},
{type:"teach",trg:"versprechen",src:"to promise",pos:"verb",gender:null,note:"Irregular: versprach, versprochen. Ich verspreche dir = I promise you.\nAlso: sich versprechen = to misspeak.",example:"A: Ich verspreche, nicht mehr am Sonntag zu bohren.\nB: Versprichst du das?\nA: Ich verspreche es.\nB: Ein Versprechen ist ein Versprechen.",exampleSrc:"A: I promise not to drill on Sunday anymore.\nB: Do you promise that?\nA: I promise.\nB: A promise is a promise.",funFact:"Irregular: versprach, versprochen. Also: 'sich versprechen' (to misspeak). Promise and mistake share a verb. Choose your prefix carefully."},
{type:"teach",trg:"verraten",src:"to betray, to reveal",pos:"verb",gender:null,note:"Irregular: verriet, verraten. Ein Geheimnis verraten = to reveal a secret.\nJemanden verraten = to betray someone.",example:"A: Verrate mir, was Heinrich gesagt hat.\nB: Er hat ein Geheimnis verraten.\nA: Was hat er verraten?\nB: Dass Nachbarn wie Brot sind.",exampleSrc:"A: Tell me what Heinrich said.\nB: He revealed a secret.\nA: What did he reveal?\nB: That neighbors are like bread.",funFact:"Irregular: verriet, verraten. One verb for secrets shared and trust broken. 'Ein Geheimnis verraten' and 'Jemanden verraten' use the same word."},
{type:"teach",trg:"verhalten",src:"to behave",pos:"verb",gender:null,note:"Sich verhalten = to behave/conduct oneself.\nIrregular: verhielt, verhalten.",example:"A: Wie soll ich mich verhalten?\nB: Verhalte dich ruhig und h\u00f6flich.\nA: Ich habe mich schlecht verhalten.\nB: Dann \u00e4ndere dein Verhalten.",exampleSrc:"A: How should I behave?\nB: Behave calmly and politely.\nA: I behaved badly.\nB: Then change your behavior.",funFact:"'Sich verhalten' (to behave/conduct oneself). Irregular: verhielt, verhalten. 'Wie soll ich mich verhalten?' (How should I behave?). The reflexive is essential."},
{type:"teach",trg:"verhindern",src:"to prevent",pos:"verb",gender:null,note:"Einen Streit verhindern = to prevent an argument.\nDas konnte ich nicht verhindern = I couldn't prevent that.",example:"A: Kann man Streit verhindern?\nB: Man kann versuchen, Streit zu verhindern.\nA: Wie verhindern wir den n\u00e4chsten Streit?\nB: Nicht am Sonntag bohren.",exampleSrc:"A: Can you prevent arguments?\nB: You can try to prevent arguments.\nA: How do we prevent the next argument?\nB: Don't drill on Sunday.",funFact:"Inseparable ver-. 'Das konnte ich nicht verhindern' (I could not prevent that). A key mediation word. Prevention is better than Streit."},
{type:"teach",trg:"verlassen",src:"to leave, to abandon / to rely on",pos:"verb",gender:null,note:"Irregular: verlie\u00df, verlassen. Die Wohnung verlassen = to leave.\nSich auf jemanden verlassen = to rely on someone.",example:"A: Er hat das Zimmer verlassen.\nB: Kann man sich auf ihn verlassen?\nA: Ja, verlass dich auf Heinrich.\nB: Er hat uns noch nie verlassen.",exampleSrc:"A: He left the room.\nB: Can you rely on him?\nA: Yes, rely on Heinrich.\nB: He has never abandoned us.",funFact:"Irregular: verlie\u00df, verlassen. Two meanings: 'Die Wohnung verlassen' (to leave the apartment) and 'Sich auf jemanden verlassen' (to rely on someone). Leaving and relying: one verb."},
{type:"teach",trg:"verlaufen",src:"to get lost, to go (of events)",pos:"verb",gender:null,note:"Sich verlaufen = to lose one's way.\nWie ist das Gespr\u00e4ch verlaufen? = How did the conversation go?",example:"A: Wie ist die Mediation verlaufen?\nB: Sie ist gut verlaufen.\nA: Ich habe mich fast verlaufen auf dem Weg zu Hildi.\nB: Verlaufen? Sie wohnt nebenan!",exampleSrc:"A: How did the mediation go?\nB: It went well.\nA: I almost got lost on the way to Hildi.\nB: Got lost? She lives next door!",funFact:"'Sich verlaufen' (to lose one's way). 'Wie ist das Gespr\u00e4ch verlaufen?' (How did the conversation go?). Irregular like 'laufen.' Two very different uses."},
{type:"teach",trg:"vers\u00e4umen",src:"to miss, to neglect",pos:"verb",gender:null,note:"Eine Chance vers\u00e4umen = to miss an opportunity.\nMore formal than 'verpassen.'",example:"A: Vers\u00e4ume nicht, dich zu entschuldigen.\nB: Ich werde es nicht vers\u00e4umen.\nA: Wenn du es vers\u00e4umst, wird es schlimmer.\nB: Keine Sorge, ich vers\u00e4ume es nicht.",exampleSrc:"A: Don't neglect to apologize.\nB: I won't neglect it.\nA: If you neglect it, it will get worse.\nB: Don't worry, I won't neglect it.",funFact:"More formal than 'verpassen.' 'Vers\u00e4ume nicht, dich zu entschuldigen' (Do not neglect to apologize). A verb for missed opportunities and unfulfilled duties."},
{type:"teach",trg:"weigern",src:"to refuse",pos:"verb",gender:null,note:"Sich weigern = to refuse. Always reflexive.\nEr weigert sich, die T\u00fcr zu \u00f6ffnen.",example:"A: Der Nachbar weigert sich zu reden.\nB: Er weigert sich?\nA: Ja, er weigert sich strikt.\nB: Dann muss Hildi ihn \u00fcberzeugen.",exampleSrc:"A: The neighbor refuses to talk.\nB: He refuses?\nA: Yes, he strictly refuses.\nB: Then Hildi has to convince him.",funFact:"'Sich weigern' (to refuse). Always reflexive. 'Er weigert sich, die T\u00fcr zu \u00f6ffnen' (He refuses to open the door). The stubborn neighbor verb."},
{type:"teach",trg:"zwingen",src:"to force",pos:"verb",gender:null,note:"Irregular: zwang, gezwungen. Strong word, strong verb.\nNiemand kann dich zwingen = Nobody can force you.",example:"A: Man kann niemanden zum Frieden zwingen.\nB: Stimmt, Frieden kann man nicht erzwingen.\nA: Heinrich hat uns nicht gezwungen.\nB: Nein, er hat uns \u00fcberzeugt.",exampleSrc:"A: You can't force anyone into peace.\nB: True, peace can't be forced.\nA: Heinrich didn't force us.\nB: No, he convinced us.",funFact:"Irregular: zwang, gezwungen. 'Niemand kann dich zwingen' (Nobody can force you). 'Gezwungen' also means 'forced/stiff' as an adjective."},
{type:"teach",trg:"ernsthaft",src:"seriously, earnest",pos:"adj",gender:null,note:"Ernst + -haft (having the quality of). Ernsthaft? = Seriously?\nStronger than 'ernst.'",example:"A: Ernsthaft?\nB: Ja, ernsthaft.\nA: Das ist eine ernsthafte Angelegenheit.\nB: Aber keine hoffnungslose.",exampleSrc:"A: Seriously?\nB: Yes, seriously.\nA: This is a serious matter.\nB: But not a hopeless one.",funFact:"Ernst + -haft (having the quality of). 'Ernsthaft?' (Seriously?). Stronger than 'ernst.' 'Eine ernsthafte Diskussion' (a serious discussion). The adjective for real, non-trivial matters."},
{type:"teach",trg:"heimlich",src:"secretly",pos:"adj",gender:null,note:"From 'Heim' (home). Originally: homely, private. Now: secret, covert.\n'Das Unheimliche' (the uncanny) is Freud's famous term.",example:"A: Verumius hat heimlich Marmelade gekocht.\nB: Warum heimlich?\nA: Es soll eine \u00dcberraschung sein.\nB: Heimlich ist manchmal die beste Strategie.",exampleSrc:"A: Verumius secretly made jam.\nB: Why secretly?\nA: It's supposed to be a surprise.\nB: Secretly is sometimes the best strategy.",funFact:"From 'Heim' (home). Originally: homely, private. Now: secret, covert. 'Das Unheimliche' (the uncanny) is Freud's famous term. Home became secret became creepy."},
{type:"teach",trg:"hinterher",src:"afterwards, behind",pos:"adv",gender:null,note:"Hinter (behind) + her (toward here). After the fact.\nHinterher ist man immer kl\u00fcger = Hindsight is 20/20.",example:"A: Hinterher ist man immer kl\u00fcger.\nB: Ja, hinterher wei\u00df man alles besser.\nA: Hinterher h\u00e4tte ich nicht gebohrt.\nB: Hinterher sagen alle das.",exampleSrc:"A: In hindsight you're always smarter.\nB: Yes, afterwards you know everything better.\nA: In hindsight I wouldn't have drilled.\nB: Everyone says that afterwards.",funFact:"Hinter (behind) + her (toward here). 'Hinterher ist man immer kl\u00fcger' (Hindsight is 20/20) is a German proverb. Literally: afterwards one is always smarter."},
{type:"teach",trg:"eben",src:"just, exactly, precisely",pos:"adv",gender:null,note:"Versatile Modalpartikel. Das ist eben so = That's just how it is.\nAlso means 'flat/level' as an adjective.",example:"A: Das ist eben Deutschland.\nB: Was meinst du mit 'eben'?\nA: Eben: so ist es halt.\nB: Regeln sind eben Regeln.",exampleSrc:"A: That's just Germany.\nB: What do you mean by 'just'?\nA: Just: that's how it is.\nB: Rules are just rules.",funFact:"One of the most versatile Modalpartikeln. 'Das ist eben so' (That's just how it is). Expresses resigned acceptance. Also 'eben' = 'flat/level' and 'just now' (Ich war eben dort)."},
{type:"teach",trg:"stinken",src:"to stink",pos:"verb",gender:null,note:"Irregular: stank, gestunken. Same root as English 'stink.'\nDas stinkt mir = That annoys me (colloquial).",example:"A: Der M\u00fcll stinkt.\nB: Ja, er stinkt seit drei Tagen.\nA: Und die Situation stinkt auch.\nB: Alles stinkt. Wir brauchen frische Luft.",exampleSrc:"A: The trash stinks.\nB: Yes, it has been stinking for three days.\nA: And the situation stinks too.\nB: Everything stinks. We need fresh air.",funFact:"Irregular: stank, gestunken. Same root as English 'stink.' 'Das stinkt mir' (That annoys me) uses the verb figuratively. Both literal and emotional stench."},
{type:"story",speaker:"heinrich",mood:"warm-and-loud",art:"de-ber-phone-heinrich",trg:"Nachbarn sind wie Brot. Man braucht sie jeden Tag!",src:"Neighbors are like bread. You need them every day!"},
{type:"mc",q:"Nachdem Heinrich angerufen hatte, wollte Verumius wissen, ob er dem Nachbarn _____ konnte.",opts:["vertrauen","zwingen","weigern","verraten"],ans:"vertrauen",hint:"Welches Verb bedeutet 'jemandem glauben und sich auf ihn verlassen'? Es nimmt den Dativ."}
]},

// ============================================================
// Lesson 7: "Alles auf den Tisch" (Everything on the Table) — Quiz
// 18 new words, 22 steps (assessment-heavy)
// ============================================================
{id:"deu_r16l7",title:"Alles auf den Tisch",icon:"\uD83D\uDCDA",xp:15,board:true,steps:[
{type:"intro",title:"Alles auf den Tisch",desc:"Zeit f\u00fcr die Pr\u00fcfung. Kannst du Ereignisse mit 'nachdem' ordnen und h\u00f6fliche indirekte Fragen stellen? Beweise es. Lerne dabei Krimivokabular.",goals:["Teste alle Grammatik und Vokabeln aus Unit 16","Beweise, dass du nachdem und indirekte Fragen beherrschst","Lerne Krimivokabular f\u00fcr den Kontext"]},
{type:"teach",trg:"der Dieb",src:"the thief",pos:"noun",gender:"m",note:"Same root as English 'thief' (Proto-Germanic). Plural: Diebe.\nHaltet den Dieb! = Stop the thief!",example:"A: Ein Dieb war im Haus!\nB: Ein Dieb? Was hat er gestohlen?\nA: Nichts. Er hat nur die Zettel gelesen.\nB: Ein Dieb, der Zettel liest?",exampleSrc:"A: A thief was in the building!\nB: A thief? What did he steal?\nA: Nothing. He only read the notes.\nB: A thief who reads notes?",funFact:"Same root as English 'thief' (Proto-Germanic *theubaz). Der Dieb, plural: Diebe. 'Haltet den Dieb!' is from fairy tales and crime reports alike."},
{type:"teach",trg:"der Einbrecher",src:"the burglar",pos:"noun",gender:"m",note:"Ein (in) + brechen (break) + -er (person). Someone who breaks in.\nDer Einbrecher kam durch das Fenster.",example:"A: War es ein Einbrecher?\nB: Nein, kein Einbrecher. Nur der Nachbar.\nA: Der Nachbar als Einbrecher?\nB: Er hat die T\u00fcr verwechselt.",exampleSrc:"A: Was it a burglar?\nB: No, no burglar. Just the neighbor.\nA: The neighbor as a burglar?\nB: He confused the door.",funFact:"Ein (in) + brechen (break) + -er (person). Someone who breaks in. 'Der Einbrecher kam durch das Fenster' is how crime reports begin."},
{type:"teach",trg:"die Einbrecherin",src:"the female burglar",pos:"noun",gender:"f",note:"Einbrecher + -in. Die Einbrecherin.\nCrime is equal-opportunity in German grammar.",example:"A: Die Einbrecherin wurde gefasst.\nB: Eine Einbrecherin?\nA: Ja, die Einbrecherin war sehr geschickt.\nB: Geschickt, aber nicht geschickt genug.",exampleSrc:"A: The female burglar was caught.\nB: A female burglar?\nA: Yes, the burglar was very skilled.\nB: Skilled, but not skilled enough.",funFact:"Einbrecher + -in. German always offers the feminine form. Crime is an equal-opportunity employer in grammar."},
{type:"teach",trg:"der Einbruch",src:"the burglary, the break-in",pos:"noun",gender:"m",note:"The noun from 'einbrechen.' Also: Einbruch der Dunkelheit = nightfall.\nTwo meanings: crime and twilight.",example:"A: Nach dem Einbruch war alles anders.\nB: Welcher Einbruch?\nA: Der Einbruch in die Nachbarwohnung.\nB: Bei Einbruch der Dunkelheit kam die Polizei.",exampleSrc:"A: After the break-in everything was different.\nB: What break-in?\nA: The break-in at the neighboring apartment.\nB: At nightfall the police came.",funFact:"The noun from 'einbrechen.' 'Einbruch der Dunkelheit' means nightfall (literally: the breaking-in of darkness). Two meanings: crime and twilight."},
{type:"teach",trg:"das Gef\u00e4ngnis",src:"the prison",pos:"noun",gender:"n",note:"From 'fangen' (to catch). Ge- + fang + -nis.\nThe -nis ending creates neuter nouns: Gef\u00e4ngnis, Ergebnis, Geheimnis.",example:"A: Im Gef\u00e4ngnis? Wegen L\u00e4rm?\nB: Niemand kommt ins Gef\u00e4ngnis wegen L\u00e4rm.\nA: Gut. Kein Gef\u00e4ngnis.\nB: Nur Marmelade.",exampleSrc:"A: In prison? Because of noise?\nB: Nobody goes to prison for noise.\nA: Good. No prison.\nB: Just jam.",funFact:"From 'fangen' (to catch). A place of catching. The -nis ending creates neuter nouns: Gef\u00e4ngnis, Ergebnis, Geheimnis."},
{type:"teach",trg:"der T\u00e4ter",src:"the perpetrator",pos:"noun",gender:"m",note:"From 'Tat' (deed/act). The one who does the deed.\nGender-neutral alternative: T\u00e4terperson.",example:"A: Wer ist der T\u00e4ter?\nB: Verumius ist der T\u00e4ter.\nA: Der T\u00e4ter des Bohrlochs!\nB: Ein gef\u00e4hrlicher T\u00e4ter mit Bohrmaschine.",exampleSrc:"A: Who is the perpetrator?\nB: Verumius is the perpetrator.\nA: The perpetrator of the drill hole!\nB: A dangerous perpetrator with a drill.",funFact:"From 'Tat' (deed/act). The one who does the deed. Legal and journalistic German. 'Der T\u00e4ter floh' (The perpetrator fled)."},
{type:"teach",trg:"die T\u00e4terin",src:"the female perpetrator",pos:"noun",gender:"f",note:"T\u00e4ter + -in with Umlaut: T\u00e4terin.\nGerman legal language always specifies.",example:"A: Die T\u00e4terin ist bekannt.\nB: Eine T\u00e4terin?\nA: Ja, in diesem Fall war die T\u00e4terin eine Frau.\nB: Die T\u00e4terin wurde identifiziert.",exampleSrc:"A: The perpetrator is known.\nB: A female perpetrator?\nA: Yes, in this case the perpetrator was a woman.\nB: The perpetrator was identified.",funFact:"T\u00e4ter + -in. Note the \u00e4 stays the same: T\u00e4terin. German legal language always specifies."},
{type:"teach",trg:"die Tat",src:"the deed, the act, the crime",pos:"noun",gender:"f",note:"Auf frischer Tat ertappt = caught in the act.\nIn der Tat = indeed (literally: in the deed).",example:"A: Was war die Tat?\nB: Bohren am Sonntag. Das ist die Tat.\nA: In der Tat eine schlimme Tat.\nB: Er wurde auf frischer Tat ertappt.",exampleSrc:"A: What was the deed?\nB: Drilling on Sunday. That's the deed.\nA: Indeed a terrible deed.\nB: He was caught in the act.",funFact:"'Auf frischer Tat ertappt' (caught in the act). 'In der Tat' (indeed). Small word, enormous range. From crime to emphasis."},
{type:"teach",trg:"der Verbrecher",src:"the criminal",pos:"noun",gender:"m",note:"From 'verbrechen' (to commit a crime). Ver- + brechen (break).\nStronger than Dieb: any serious criminal.",example:"A: Verumius ist kein Verbrecher.\nB: Nein, ein Verbrecher bohrt nachts.\nA: Verumius bohrt nur am Sonntagabend.\nB: Kein Verbrecher, aber kein guter Nachbar.",exampleSrc:"A: Verumius is no criminal.\nB: No, a criminal drills at night.\nA: Verumius only drills on Sunday evening.\nB: No criminal, but not a good neighbor.",funFact:"From 'verbrechen' (to commit a crime). Ver- + brechen (break). Someone who breaks the law. Stronger than Dieb: any serious criminal."},
{type:"teach",trg:"die Verbrecherin",src:"the female criminal",pos:"noun",gender:"f",note:"Verbrecher + -in. Die Verbrecherin.\nThe pattern: masculine + -in = feminine role.",example:"A: Die Verbrecherin wurde gefasst.\nB: Welche Verbrecherin?\nA: Die vom Einbruch gestern.\nB: Gut, dass die Verbrecherin gefasst wurde.",exampleSrc:"A: The criminal was caught.\nB: Which criminal?\nA: The one from yesterday's burglary.\nB: Good that the criminal was caught.",funFact:"Verbrecher + -in. The pattern is always the same: masculine + -in = feminine profession or role."},
{type:"teach",trg:"der Verlierer",src:"the loser",pos:"noun",gender:"m",note:"From 'verlieren' (to lose). Ein guter Verlierer sein = to be a good loser.\nIn the neighbor dispute, nobody wants to be the Verlierer.",example:"A: Wer ist der Verlierer?\nB: Niemand. Es gibt keinen Verlierer.\nA: Dann sind wir beide Gewinner?\nB: Genau. Kein Verlierer, zwei Gewinner.",exampleSrc:"A: Who is the loser?\nB: Nobody. There is no loser.\nA: Then we're both winners?\nB: Exactly. No loser, two winners.",funFact:"From 'verlieren' (to lose). 'Ein guter Verlierer sein' (to be a good loser). In the neighbor dispute, nobody wants to be the Verlierer."},
{type:"teach",trg:"festnehmen",src:"to arrest",pos:"verb",gender:null,note:"Fest (firm) + nehmen (take). Separable: Die Polizei nimmt ihn fest.\nMore official than 'verhaften.'",example:"A: Die Polizei hat den Dieb festgenommen.\nB: Wann haben sie ihn festgenommen?\nA: Gestern Nacht.\nB: Gut, dass sie ihn festgenommen haben.",exampleSrc:"A: The police arrested the thief.\nB: When did they arrest him?\nA: Last night.\nB: Good that they arrested him.",funFact:"Fest (firm) + nehmen (take). Separable: 'Die Polizei nimmt ihn fest.' To take someone firmly. More official than 'verhaften.'"},
{type:"teach",trg:"verhaften",src:"to arrest",pos:"verb",gender:null,note:"From 'Haft' (custody). Inseparable ver-.\nEr wurde verhaftet = He was arrested.",example:"A: Der Einbrecher wurde verhaftet.\nB: Warum wurde er verhaftet?\nA: Wegen Einbruchs.\nB: Verhaftet und verurteilt?",exampleSrc:"A: The burglar was arrested.\nB: Why was he arrested?\nA: For burglary.\nB: Arrested and convicted?",funFact:"From 'Haft' (custody). Inseparable ver-. 'Er wurde verhaftet' (He was arrested). Used interchangeably with festnehmen in daily speech."},
{type:"teach",trg:"verurteilen",src:"to convict, to sentence",pos:"verb",gender:null,note:"From 'Urteil' (verdict). Zu drei Jahren verurteilt = sentenced to three years.\nThe legal climax of any Prozess.",example:"A: Der Richter hat ihn verurteilt.\nB: Wozu wurde er verurteilt?\nA: Zu einer Geldstrafe.\nB: Verurteilt wegen L\u00e4rm? Unglaublich.",exampleSrc:"A: The judge convicted him.\nB: What was he sentenced to?\nA: A fine.\nB: Convicted for noise? Unbelievable.",funFact:"From 'Urteil' (verdict). 'Zu drei Jahren verurteilt' (sentenced to three years). The legal climax of any Prozess."},
{type:"teach",trg:"fangen",src:"to catch",pos:"verb",gender:null,note:"Irregular: fing, gefangen. 'Fang!' = Catch!\nChildren play 'Fangen' (tag). 'Anfangen' = to begin.",example:"A: Fang den Dieb!\nB: Ich kann ihn nicht fangen.\nA: Die Polizei hat ihn gefangen.\nB: Gefangen ist gefangen.",exampleSrc:"A: Catch the thief!\nB: I can't catch him.\nA: The police caught him.\nB: Caught is caught.",funFact:"Irregular: fing, gefangen. Children play 'Fangen' (tag). 'Anfangen' (to begin, literally: to catch on). The caught one is 'gefangen.'"},
{type:"teach",trg:"stehlen",src:"to steal",pos:"verb",gender:null,note:"Irregular: stahl, gestohlen. Same root as English 'steal.'\nJemandem die Show stehlen = to steal someone's show.",example:"A: Der Dieb hat nichts gestohlen.\nB: Was? Er hat nichts gestohlen?\nA: Nein. Er hat nur die Marmelade probiert.\nB: Marmelade stehlen z\u00e4hlt auch!",exampleSrc:"A: The thief didn't steal anything.\nB: What? He didn't steal anything?\nA: No. He only tried the jam.\nB: Stealing jam counts too!",funFact:"Irregular: stahl, gestohlen. Same root as English 'steal.' 'Jemandem die Show stehlen' works in German too."},
{type:"teach",trg:"schie\u00dfen",src:"to shoot",pos:"verb",gender:null,note:"Irregular: schoss, geschossen. Ein Tor schie\u00dfen = to score a goal.\nUsed in football, crime, and photography.",example:"A: Er hat ein Tor geschossen!\nB: Im Fu\u00dfball? Oder mit der Kamera?\nA: Ein Foto geschossen. Vom Zettel.\nB: Man schie\u00dft Tore und Fotos. Interessant.",exampleSrc:"A: He scored a goal!\nB: In football? Or with a camera?\nA: Shot a photo. Of the note.\nB: You shoot goals and photos. Interesting.",funFact:"Irregular: schoss, geschossen. 'Ein Tor schie\u00dfen' (to score a goal). Used in football, crime, and photography ('ein Foto schie\u00dfen')."},
{type:"teach",trg:"greifen",src:"to grab, to grasp",pos:"verb",gender:null,note:"Irregular: griff, gegriffen. Nach etwas greifen = to reach for something.\nBegreifen = to comprehend (to grasp mentally).",example:"A: Greif dir die Marmelade.\nB: Ich greife nach dem Glas.\nA: Er hat nach der T\u00fcrklinke gegriffen.\nB: Greifen, nicht rei\u00dfen!",exampleSrc:"A: Grab the jam.\nB: I'm reaching for the jar.\nA: He reached for the door handle.\nB: Grab, don't pull!",funFact:"Irregular: griff, gegriffen. 'Begreifen' (to comprehend) = to grasp mentally. 'Zugreifen' = to help oneself (at a buffet). One root, many meanings."},
{type:"teach",trg:"einbrechen",src:"to break in, to burglarize",pos:"verb",gender:null,note:"Separable: Er bricht ein. Irregular: brach ein, eingebrochen.\nAlso: Einbruch der Dunkelheit = nightfall.",example:"A: Jemand ist eingebrochen!\nB: Wo ist er eingebrochen?\nA: In die Wohnung nebenan.\nB: Er ist durch das Fenster eingebrochen.",exampleSrc:"A: Someone broke in!\nB: Where did they break in?\nA: Into the apartment next door.\nB: They broke in through the window.",funFact:"Separable: 'Er bricht ein.' Irregular: brach ein, eingebrochen. Also used metaphorically: 'Das Eis bricht ein' (the ice breaks). From ein (in) + brechen (break)."},
{type:"teach",trg:"der Streik",src:"the strike (labor)",pos:"noun",gender:"m",note:"From English 'strike.' Borrowed during the Industrial Revolution.\nIn den Streik treten = to go on strike.",example:"A: Die M\u00fcllabfuhr ist im Streik.\nB: Seit wann dauert der Streik?\nA: Seit einer Woche.\nB: Ein Streik bedeutet volle M\u00fclltonnen.",exampleSrc:"A: The garbage collectors are on strike.\nB: How long has the strike lasted?\nA: For a week.\nB: A strike means full trash cans.",funFact:"From English 'strike.' The noun form of 'streiken.' Deutsche Bahn strikes are so legendary they have their own memes. 'Generalstreik' (general strike) shaped German labor history."},
{type:"teach",trg:"unterlassen",src:"to refrain from, to cease",pos:"verb",gender:null,note:"Unter + lassen (let). Inseparable. Unterlassen Sie das! = Stop doing that!\nLegal tone: 'Unterlassungserkl\u00e4rung' = cease-and-desist.",example:"A: Unterlassen Sie das Bohren am Sonntag!\nB: Ich werde es unterlassen.\nA: Sie m\u00fcssen es unterlassen.\nB: Versprochen. Ich unterlasse es.",exampleSrc:"A: Cease the drilling on Sunday!\nB: I will refrain from it.\nA: You must refrain from it.\nB: Promised. I'll cease.",funFact:"Unter + lassen (let). Inseparable. 'Unterlassen Sie das!' is formal for 'Stop doing that!' 'Unterlassungserkl\u00e4rung' (cease-and-desist letter) is the legal nuclear option in neighbor disputes."},
{type:"teach",trg:"sch\u00fctteln",src:"to shake",pos:"verb",gender:null,note:"Den Kopf sch\u00fctteln = to shake one's head (means 'no' in Germany).\nH\u00e4nde sch\u00fctteln = to shake hands.",example:"A: Er sch\u00fcttelt den Kopf.\nB: Warum sch\u00fcttelt er den Kopf?\nA: Er sch\u00fcttelt den Kopf \u00fcber den L\u00e4rm.\nB: Dann sch\u00fctteln wir ihm die Hand und entschuldigen uns.",exampleSrc:"A: He shakes his head.\nB: Why is he shaking his head?\nA: He's shaking his head about the noise.\nB: Then let's shake his hand and apologize.",funFact:"'Den Kopf sch\u00fctteln' (to shake one's head) means 'no' in Germany. 'H\u00e4nde sch\u00fctteln' (to shake hands) is the classic German greeting. One verb, two social rituals."},
{type:"mc",q:"Nachdem der Dieb das Fenster ge\u00f6ffnet _____, stieg er in die Wohnung.",opts:["ist","hatte","hat","war"],ans:"hatte",hint:"Nachdem-Klausel = Plusquamperfekt. Welches Hilfsverb passt zu 'ge\u00f6ffnet'?"},
{type:"fb",s:"K\u00f6nnen Sie mir sagen, {1} der T\u00e4ter geflohen ist?",a:["wohin"],opts:["wohin","ob","dass","woher"],hint:"Die Frage zielt auf eine Richtung: in welche Richtung ist der T\u00e4ter geflohen?",sSrc:"Can you tell me where the perpetrator fled to?"},
{type:"mc",q:"Welcher Satz ist grammatisch korrekt?",opts:["Nachdem er verhaftet worden war, der Richter fragte, ob er schuldig sei.","Nachdem er verhaftet worden war, fragte der Richter, ob er schuldig sei.","Nachdem er verhaftet worden war, fragte der Richter, ob er schuldig ist?","Nach er verhaftet worden war, der Richter fragte ob er schuldig war."],ans:"Nachdem er verhaftet worden war, fragte der Richter, ob er schuldig sei.",hint:"nachdem + Plusquamperfekt im Nebensatz, dann Hauptsatz Verb an zweiter Stelle, dann ob + Verb am Ende."},
{type:"match",pairs:[{trg:"Dieb",src:"thief"},{trg:"Einbruch",src:"burglary"},{trg:"Gef\u00e4ngnis",src:"prison"},{trg:"Urteil",src:"verdict"},{trg:"T\u00e4ter",src:"perpetrator"},{trg:"Verlierer",src:"loser"}]},
{type:"drag_fill",s:"Nachdem die Polizei den T\u00e4ter {1} hatte, wollte der Richter wissen, {2} er die Tat {3} hatte.",blanks:{"1":"festgenommen","2":"ob","3":"geplant"},pool:["festgenommen","ob","geplant","verhaftet","dass","gemacht"],hint:"Nachdem die Polizei den T\u00e4ter festgenommen hatte, wollte der Richter wissen, ob er die Tat geplant hatte.",sSrc:"After the police had arrested the perpetrator, the judge wanted to know whether he had planned the deed."}
]},

// ============================================================
// Lesson 8: "Marmelade und Frieden" (Jam and Peace) — Resolution
// 20 new words + 5 affixes in tip, 24 steps
// ============================================================
{id:"deu_r16l8",title:"Marmelade und Frieden",icon:"\uD83C\uDF53",xp:15,board:true,steps:[
{type:"intro",title:"Marmelade und Frieden",desc:"Verumius places a jar of jam in front of the door. The neighbor responds with pickles. This is how you solve conflicts in German: with preserving jars.",goals:["Learn the final conflict vocabulary","Experience the German art of the peace offering","Reflect on Ruhezeit, Hausordnung, and neighbor culture"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-ber-stairwell-jam",trg:"Nachdem Verumius lange nachgedacht hatte, stellte er ein Glas Marmelade vor die T\u00fcr des Nachbarn.",src:"After Verumius had thought for a long time, he placed a jar of jam at the neighbor's door."},
{type:"teach",trg:"der Gegner",src:"the opponent",pos:"noun",gender:"m",note:"From 'gegen' (against). Sports opponent, debate adversary, or neighbor.\nEin fairer Gegner = a fair opponent.",example:"A: Der Nachbar war mein Gegner.\nB: Und jetzt?\nA: Jetzt ist er kein Gegner mehr.\nB: Von Gegner zu Nachbar. Ein guter Weg.",exampleSrc:"A: The neighbor was my opponent.\nB: And now?\nA: Now he's no longer an opponent.\nB: From opponent to neighbor. A good path.",funFact:"From 'gegen' (against). Can be a sports opponent, a debate adversary, or a neighbor in a Streit. 'Ein fairer Gegner' is what Hildi made both sides become."},
{type:"teach",trg:"die Langeweile",src:"the boredom",pos:"noun",gender:"f",note:"Lange (long) + Weile (while). A long while.\nMir ist langweilig = I am bored. Aus Langeweile = out of boredom.",example:"A: Aus Langeweile hat er Zettel geschrieben.\nB: Langeweile f\u00fchrt zu Zettelkrieg?\nA: Langeweile f\u00fchrt zu vielen Dingen.\nB: Dann braucht der Nachbar ein Hobby.",exampleSrc:"A: He wrote notes out of boredom.\nB: Boredom leads to note wars?\nA: Boredom leads to many things.\nB: Then the neighbor needs a hobby.",funFact:"Lange (long) + Weile (while). A long while. The compound tells the whole story: time stretching painfully. 'Mir ist langweilig' is how every German child announces boredom."},
{type:"teach",trg:"betrunken",src:"drunk",pos:"adj",gender:null,note:"Past participle of 'trinken' used as adjective.\nBetrunken Auto fahren = to drive drunk. Illegal everywhere.",example:"A: War der Nachbar betrunken?\nB: Nein, er war n\u00fcchtern. Und trotzdem w\u00fctend.\nA: N\u00fcchtern und w\u00fctend ist schlimmer als betrunken.\nB: Da hast du recht.",exampleSrc:"A: Was the neighbor drunk?\nB: No, he was sober. And still angry.\nA: Sober and angry is worse than drunk.\nB: You're right about that.",funFact:"Past participle of 'trinken' used as adjective. 'Betrunken Auto fahren' is illegal everywhere. The participle-as-adjective pattern is very productive in German."},
{type:"teach",trg:"geschieden",src:"divorced",pos:"adj",gender:null,note:"Past participle of 'scheiden.' Familienstand: geschieden.\nA legal status turned adjective.",example:"A: Ist der Nachbar geschieden?\nB: Nein, er ist verheiratet.\nA: Vielleicht bald geschieden, wenn er so weiter macht.\nB: Geschieden wegen L\u00e4rmstreit?",exampleSrc:"A: Is the neighbor divorced?\nB: No, he's married.\nA: Maybe divorced soon, if he keeps this up.\nB: Divorced because of a noise dispute?",funFact:"Past participle of 'scheiden.' On German forms, Familienstand: geschieden. A legal status turned adjective."},
{type:"teach",trg:"getrennt",src:"separated",pos:"adj",gender:null,note:"Past participle of 'trennen.' Sie leben getrennt = They live separately.\nGetrennt zahlen = to pay separately (at restaurants).",example:"A: Die zwei Nachbarn leben getrennt durch eine Wand.\nB: Getrennt, aber verbunden.\nA: Getrennt zahlen?\nB: Nein, die Marmelade ist gratis.",exampleSrc:"A: The two neighbors live separated by a wall.\nB: Separated, but connected.\nA: Pay separately?\nB: No, the jam is free.",funFact:"Past participle of 'trennen.' 'Getrennt zahlen' (to pay separately) at restaurants is very German. Every group dinner ends with this phrase."},
{type:"teach",trg:"geheim",src:"secret",pos:"adj",gender:null,note:"From 'Heim' (home). What stays at home, stays private.\nGeheimdienst = secret service. Geheimnis = secret (noun).",example:"A: Die Marmelade ist ein geheimes Rezept.\nB: Geheim? Von wem?\nA: Von Verumius. Es ist geheim.\nB: Ein geheimes Friedensangebot.",exampleSrc:"A: The jam is a secret recipe.\nB: Secret? From whom?\nA: From Verumius. It's secret.\nB: A secret peace offering.",funFact:"From 'Heim' (home). Originally: homely, private. Now: secret. 'Geheimdienst' (secret service). 'Geheimnis' (secret, the noun) you already know."},
{type:"teach",trg:"schlank",src:"slim",pos:"adj",gender:null,note:"Positive connotation, unlike 'd\u00fcnn' (thin) which can sound clinical.\nSchlank bleiben = to stay slim.",example:"A: Die Chance auf Frieden ist schlank.\nB: Schlank, aber nicht null.\nA: Wie Verumius nach drei Wochen nur Marmelade.\nB: Schlank und voller Hoffnung.",exampleSrc:"A: The chance for peace is slim.\nB: Slim, but not zero.\nA: Like Verumius after three weeks of only jam.\nB: Slim and full of hope.",funFact:"Positive connotation, unlike 'd\u00fcnn' (thin). 'Schlank bleiben' (to stay slim) is a fitness goal. Used literally and metaphorically."},
{type:"teach",trg:"schmal",src:"narrow",pos:"adj",gender:null,note:"Ein schmaler Weg = a narrow path. Different from 'eng' (tight).\nSchmal = visually narrow. Eng = physically tight.",example:"A: Der Flur ist sehr schmal.\nB: Zu schmal f\u00fcr zwei Marmeladengl\u00e4ser?\nA: Nein, f\u00fcr ein Glas reicht der schmale Flur.\nB: Ein schmaler Weg zum Frieden.",exampleSrc:"A: The hallway is very narrow.\nB: Too narrow for two jam jars?\nA: No, the narrow hallway fits one jar.\nB: A narrow path to peace.",funFact:"Different from 'eng' (tight). Schmal = visually narrow. Eng = physically tight. 'Schmale Schultern' (narrow shoulders). A word about appearance, not squeeze."},
{type:"teach",trg:"schief",src:"crooked, askew",pos:"adj",gender:null,note:"Das Bild h\u00e4ngt schief = The picture hangs crooked.\nSchiefgehen = to go wrong. 'Es wird schon schiefgehen!' = ironic.",example:"A: Das Regal h\u00e4ngt schief.\nB: Nat\u00fcrlich h\u00e4ngt es schief. Das war ja das Problem.\nA: Schief, aber es h\u00e4lt.\nB: Schief und schief gelaufen.",exampleSrc:"A: The shelf hangs crooked.\nB: Of course it hangs crooked. That was the problem.\nA: Crooked, but it holds.\nB: Crooked and gone wrong.",funFact:"'Schiefgehen' (to go wrong). 'Es wird schon schiefgehen!' is ironic encouragement: 'It will go wrong!' meaning 'What could go wrong?' Verumius's shelf was definitely schief."},
{type:"teach",trg:"stumm",src:"mute, silent",pos:"adj",gender:null,note:"Stronger than 'still.' A stumm person cannot or will not speak.\nStummfilm = silent film.",example:"A: Der Nachbar war drei Tage stumm.\nB: Stumm? Kein Wort?\nA: Kein einziges Wort. Stumm wie ein Fisch.\nB: Dann kam die Marmelade.",exampleSrc:"A: The neighbor was silent for three days.\nB: Silent? Not a word?\nA: Not a single word. Mute as a fish.\nB: Then came the jam.",funFact:"Stronger than 'still.' A stumm person cannot or will not speak. 'Stummfilm' (silent film). The neighbor was stumm for three days after the drill incident."},
{type:"teach",trg:"selten",src:"rarely, rare",pos:"adj",gender:null,note:"Selten so gelacht = Rarely laughed so much.\nEin seltenes Buch = a rare book. 'Seltsam' comes from selten.",example:"A: Solche Nachbarn sind selten.\nB: Ja, gute Nachbarn sind selten.\nA: Selten, aber wertvoll.\nB: Wie seltene B\u00fccher.",exampleSrc:"A: Such neighbors are rare.\nB: Yes, good neighbors are rare.\nA: Rare, but valuable.\nB: Like rare books.",funFact:"'Selten so gelacht' (Rarely laughed so much). As adjective: 'ein seltenes Buch' (a rare book). 'Seltsam' (strange), which you know, comes from selten."},
{type:"teach",trg:"unglaublich",src:"unbelievable, incredibly",pos:"adj",gender:null,note:"Un- + glaub (believe) + -lich. An intensifier in casual speech.\nDas ist unglaublich = That is unbelievable.",example:"A: Die Marmelade ist unglaublich gut.\nB: Unglaublich? Wirklich?\nA: Ja, unglaublich lecker.\nB: Unglaublich, dass Marmelade Frieden bringt.",exampleSrc:"A: The jam is unbelievably good.\nB: Unbelievable? Really?\nA: Yes, incredibly delicious.\nB: Unbelievable that jam brings peace.",funFact:"Un- + glaub (believe) + -lich. An intensifier in casual speech. 'Das ist unglaublich' expresses shock, admiration, or disbelief. Triple use, one word."},
{type:"teach",trg:"unheimlich",src:"uncanny, incredibly",pos:"adj",gender:null,note:"Un- + heimlich (homely). What is not homely is creepy.\nIn casual German: 'unheimlich gut' = incredibly good.",example:"A: Die Stille war unheimlich.\nB: Unheimlich still?\nA: Ja, unheimlich still. Drei Tage.\nB: Unheimlich, aber dann kam die Marmelade.",exampleSrc:"A: The silence was uncanny.\nB: Uncannily quiet?\nA: Yes, uncannily quiet. Three days.\nB: Uncanny, but then came the jam.",funFact:"Un- + heimlich (homely). Freud wrote about 'das Unheimliche.' In casual German: 'unheimlich gut' (incredibly good). Same word: creepy AND intensifier."},
{type:"teach",trg:"verliebt",src:"in love",pos:"adj",gender:null,note:"Past participle of 'sich verlieben' (to fall in love).\nVerliebt sein = to be in love. Frisch verliebt = freshly in love.",example:"A: Verumius ist verliebt.\nB: In wen?\nA: In die Marmelade.\nB: Verliebt in Marmelade? Das ist sehr deutsch.",exampleSrc:"A: Verumius is in love.\nB: With whom?\nA: With the jam.\nB: In love with jam? That's very German.",funFact:"Past participle of 'sich verlieben.' 'Verliebt sein' (to be in love). After the jam peace offering, Verumius and the neighbor are not verliebt, but perhaps they are friends."},
{type:"teach",trg:"vergeblich",src:"in vain, futile",pos:"adj",gender:null,note:"Vergeblich warten = to wait in vain.\nFrom 'vergeben' (to forgive, to give away). Something given with no return.",example:"A: War die M\u00fche vergeblich?\nB: Nein, nicht vergeblich. Die Marmelade hat geholfen.\nA: Also nicht vergeblich!\nB: Nichts ist vergeblich, wenn Marmelade im Spiel ist.",exampleSrc:"A: Was the effort in vain?\nB: No, not in vain. The jam helped.\nA: So not in vain!\nB: Nothing is in vain when jam is involved.",funFact:"'Vergeblich warten' (to wait in vain). From 'vergeben' (to forgive, to give away). Something given away with no return. 'Alle M\u00fche war vergeblich' (All effort was in vain)."},
{type:"teach",trg:"bei\u00dfen",src:"to bite",pos:"verb",gender:null,note:"Irregular: biss, gebissen. Der Hund bei\u00dft = The dog bites.\nIn den sauren Apfel bei\u00dfen = to bite the bullet.",example:"A: Bei\u00df in die Marmelade.\nB: Man bei\u00dft nicht in Marmelade!\nA: In den sauren Apfel bei\u00dfen?\nB: Lieber in s\u00fc\u00dfe Marmelade.",exampleSrc:"A: Bite into the jam.\nB: You don't bite into jam!\nA: Bite the bullet?\nB: Rather into sweet jam.",funFact:"Irregular: biss, gebissen. 'In den sauren Apfel bei\u00dfen' (to bite the sour apple = to bite the bullet). Same idiom, different fruit."},
{type:"teach",trg:"beschr\u00e4nken",src:"to limit, to restrict",pos:"verb",gender:null,note:"Sich beschr\u00e4nken auf = to limit oneself to.\nBeschr\u00e4nkt can mean 'limited' or 'narrow-minded.'",example:"A: Beschr\u00e4nke das Bohren auf Werktage.\nB: Ich beschr\u00e4nke mich.\nA: Beschr\u00e4nke dich auf die erlaubten Zeiten.\nB: Versprochen. Ich beschr\u00e4nke mich.",exampleSrc:"A: Limit the drilling to weekdays.\nB: I'll limit myself.\nA: Limit yourself to the allowed times.\nB: Promised. I'll limit myself.",funFact:"'Sich beschr\u00e4nken auf' (to limit oneself to). 'Beschr\u00e4nkt' can mean 'limited' or 'narrow-minded.' 'Bahnubergang beschr\u00e4nkt' (railroad crossing with barrier)."},
{type:"teach",trg:"entlassen",src:"to release, to dismiss, to fire",pos:"verb",gender:null,note:"Ent- + lassen (let). Aus dem Krankenhaus entlassen = discharged.\nEntlassen werden = to be fired. Context decides.",example:"A: Der Streit ist entlassen.\nB: Man entl\u00e4sst keinen Streit!\nA: Dann ist der Streit beendet.\nB: Besser. Entlassen klingt wie gek\u00fcndigt.",exampleSrc:"A: The argument is dismissed.\nB: You don't dismiss an argument!\nA: Then the argument is over.\nB: Better. Dismissed sounds like fired.",funFact:"Ent- + lassen (let). 'Aus dem Krankenhaus entlassen' (discharged from hospital). 'Entlassen werden' (to be fired). Context determines whether it is freedom or unemployment."},
{type:"teach",trg:"bestrafen",src:"to punish",pos:"verb",gender:null,note:"Be- + Strafe + -en. The be- prefix makes Strafe transitive.\nDie Hausordnung exists to bestrafen violators. In theory.",example:"A: Muss man Verumius bestrafen?\nB: Nein, er hat sich selbst bestraft.\nA: Wie hat er sich bestraft?\nB: Mit drei Tagen Schweigen vom Nachbarn.",exampleSrc:"A: Must Verumius be punished?\nB: No, he punished himself.\nA: How did he punish himself?\nB: With three days of silence from the neighbor.",funFact:"Be- + Strafe + -en. The be- prefix makes Strafe into a transitive verb. The Hausordnung exists to bestrafen violators. In theory."},
{type:"teach",trg:"betr\u00fcgen",src:"to cheat, to deceive",pos:"verb",gender:null,note:"Irregular: betrog, betrogen. Jemanden betr\u00fcgen = to cheat someone.\nBetrug = fraud (noun). A heavy word.",example:"A: Hat der Nachbar mich betrogen?\nB: Nein, er hat dich nicht betrogen.\nA: Er hat behauptet, ich bohre jeden Tag!\nB: Das ist keine Betrug, das ist \u00dcbertreibung.",exampleSrc:"A: Did the neighbor deceive me?\nB: No, he didn't deceive you.\nA: He claimed I drill every day!\nB: That's not fraud, that's exaggeration.",funFact:"Irregular: betrog, betrogen. In relationships and in business, a heavy word. 'Betrug' (fraud) is the noun. Trust broken, promises violated."},
{type:"teach",trg:"auseinander",src:"apart, asunder",pos:"adv",gender:null,note:"Aus (out) + einander (each other). Literally: out from each other.\nAuseinandergehen = to part ways. Auseinandersetzen = to discuss.",example:"A: Die Nachbarn gingen auseinander.\nB: Auseinander? Nach dem Streit?\nA: Ja, aber dann kamen sie wieder zusammen.\nB: Erst auseinander, dann zusammen. So ist das Leben.",exampleSrc:"A: The neighbors parted ways.\nB: Apart? After the argument?\nA: Yes, but then they came back together.\nB: First apart, then together. That's life.",funFact:"Aus (out) + einander (each other). 'Sich auseinandersetzen mit' (to grapple with/discuss) is essential academic German. Literally: to sit apart from each other and think."},
{type:"teach",trg:"heim",src:"home, homeward",pos:"adv",gender:null,note:"Short for 'nach Hause.' Heimgehen = to go home.\nDas Heim = the home (noun). Heimat = homeland.",example:"A: Gehen wir heim.\nB: Ja, es ist sp\u00e4t. Heim mit uns.\nA: Heim ist, wo die Marmelade steht.\nB: Und die Bohrmaschine.",exampleSrc:"A: Let's go home.\nB: Yes, it's late. Home with us.\nA: Home is where the jam stands.\nB: And the drill.",funFact:"Short for 'nach Hause.' 'Heimgehen' (to go home), 'Heimweh' (homesickness), 'Heimat' (homeland). 'Heim' is one of the most emotionally loaded words in German."},
{type:"tip",title:"F\u00fcnf Affixe, die alles ver\u00e4ndern",text:"F\u00fcnf Vorsilben und Zusammensetzungen, die deinen Wortschatz multiplizieren:\n\n1. miss- (falsch): Missverst\u00e4ndnis = misunderstanding, Misstrauen = mistrust\n2. schwieger- (angeheiratet): Schwiegermutter = mother-in-law, Schwiegervater = father-in-law\n3. un- (nicht): unglaublich = unbelievable, unheimlich = uncanny\n4. vorbei- (vorbei): vorbeigehen = to walk past, vorbeikommen = to come by\n5. weg- (weg): weggehen = to go away, wegnehmen = to take away\n\nJedes Wort, das du kennst, kann mit diesen Affixen modifiziert werden.",deepDive:{title:"Trennbare vs. untrennbare Pr\u00e4fixe",text:"Trennbare Pr\u00e4fixe (betont, trennen sich ab):\nvorbei-: Er geht vorbei. / Er ist vorbeigegangen.\nweg-: Sie geht weg. / Sie ist weggegangen.\n\nUntrennbare Pr\u00e4fixe (unbetont, bleiben dran):\nmiss-: Er missversteht mich. / Er hat mich missverstanden.\n\nZusammensetzungsformen:\nschwieger-: immer zusammen, nie getrennt.\nun-: immer zusammen bei Adjektiven und Nomen."}},
{type:"story",speaker:"narrator",mood:"resolution",art:"de-ber-stairwell-pickles",trg:"Am n\u00e4chsten Morgen fand Verumius ein Glas Gurken vor seiner T\u00fcr. Auf dem Zettel stand: 'Von Ihrem Nachbarn. Frieden?'",src:"The next morning Verumius found a jar of pickles at his door. The note read: 'From your neighbor. Peace?'"},
{type:"mc",q:"Nachdem Verumius lange nachgedacht hatte, stellte er ein Glas Marmelade vor die T\u00fcr. Was bedeutet 'nachdem' hier?",opts:["Gleichzeitigkeit: nachdenken und handeln zur gleichen Zeit","Kontrast: obwohl er nachgedacht hat","Bedingung: nur wenn er nachgedacht hat","Zeitliche Reihenfolge: zuerst nachdenken, dann handeln"],ans:"Zeitliche Reihenfolge: zuerst nachdenken, dann handeln",hint:"'nachdem' ordnet Ereignisse: das fr\u00fchere Ereignis (Plusquamperfekt) passiert VOR dem sp\u00e4teren."},
{type:"fb",s:"K\u00f6nnten Sie mir sagen, {1} der Nachbar die Gurken gebracht hat?",a:["wann"],opts:["wann","ob","dass","weil"],hint:"Die Frage fragt nach dem Zeitpunkt der Lieferung. Welches W-Wort passt?",sSrc:"Could you tell me when the neighbor brought the pickles?"},
{type:"drag_fill",s:"Nachdem er die Marmelade {1} hatte, wollte der Nachbar wissen, {2} Verumius wirklich so nett {3}.",blanks:{"1":"probiert","2":"ob","3":"war"},pool:["probiert","ob","war","gegessen","dass","ist"],hint:"Nachdem er die Marmelade probiert hatte, wollte er wissen, ob Verumius wirklich so nett war.",sSrc:"After he had tasted the jam, the neighbor wanted to know whether Verumius was really that nice."},
{type:"match",pairs:[{trg:"Gegner",src:"opponent"},{trg:"Langeweile",src:"boredom"},{trg:"stumm",src:"mute/silent"},{trg:"unglaublich",src:"unbelievable"},{trg:"bei\u00dfen",src:"to bite"},{trg:"bestrafen",src:"to punish"}]}
]}

]},

{n:17,lang:"de",srcLang:"en",track:"v2",title:"Karneval im Rheinland",sub:"Cologne carnival, infinitive clauses, costumes, Rosenmontagszug",icon:"\uD83C\uDFAD",level:"B1.2",color:"#7B5EE8",lessons:[

// ─── Lesson 1: Kölle Alaaf! ───────────────────────────────────
{id:"deu_r17l1",title:"K\u00f6lle Alaaf!",icon:"\uD83C\uDF89",xp:15,board:true,steps:[
{type:"intro",title:"K\u00f6lle Alaaf!",desc:"Verumius steps off the ICE in Cologne. The cathedral towers over the chaos. Everyone is in costume. Confetti on the ground. Music everywhere. Welcome to Karneval.",goals:["Learn key Karneval vocabulary","Experience Germany's wildest tradition through Verumius's eyes","Discover why Cologne goes crazy during Karneval"]},
{type:"story",speaker:"narrator",mood:"excited",art:"koeln-hbf-karneval",trg:"K\u00f6ln Hauptbahnhof in der Karnevalswoche. Die gotischen T\u00fcrme des Doms verdunkeln den Himmel. Drinnen herrscht das reine Chaos. Jeder Mensch tr\u00e4gt ein Kost\u00fcm. Konfetti bedeckt den Boden. Musik dröhnt aus Lautsprechern. Verumius steigt aus dem ICE und tritt in eine Wand aus Farbe und Lärm.",src:"Cologne main station during carnival week. The Gothic spires of the Dom darken the sky. Inside: pure chaos. Every person wears a costume. Confetti covers the floor. Music thumps from speakers. Verumius steps off the ICE and into a wall of color and noise."},
{type:"story",speaker:"verumius",mood:"shocked",trg:"Das ist... Deutschland? Das gleiche Land mit den Formularen und der P\u00fcnktlichkeit?",src:"This is... Germany? The same country with the forms and the punctuality?"},
{type:"story",speaker:"mia",mood:"excited",trg:"Willkommen beim Karneval, Verumius! Hier gelten andere Regeln. K\u00f6lle Alaaf!",src:"Welcome to Carnival, Verumius! Different rules apply here. Kölle Alaaf!"},
{type:"teach",trg:"der Karneval",src:"the carnival",pos:"noun",gender:"m",note:"Masculine noun. The wild celebration before Lent.\nIn the Rhineland, Karneval season starts on 11.11. at 11:11.",example:"A: Wann beginnt der Karneval?\nB: Offiziell am 11. November um 11:11 Uhr.\nA: Und wann ist der H\u00f6hepunkt?\nB: Am Rosenmontag, im Februar oder M\u00e4rz.",exampleSrc:"A: When does carnival begin?\nB: Officially on November 11th at 11:11.\nA: And when is the highlight?\nB: On Rose Monday, in February or March.",funFact:"From Latin 'carne vale' (farewell to meat). The number 11 is the 'fool's number' because it stands one above the holy 10. Over 1.5 million people flood Cologne's streets on Rosenmontag."},
{type:"teach",trg:"das Kost\u00fcm",src:"the costume",pos:"noun",gender:"n",note:"Neuter noun. During Karneval, wearing a Kost\u00fcm is not optional.\nNot dressing up marks you as an outsider.",example:"A: Was f\u00fcr ein Kost\u00fcm tr\u00e4gst du?\nB: Ich bin eine Biene! Und du?\nA: Ich bin ein r\u00f6mischer Senator.\nB: Das passt perfekt zu dir!",exampleSrc:"A: What kind of costume are you wearing?\nB: I'm a bee! And you?\nA: I'm a Roman senator.\nB: That suits you perfectly!",funFact:"From French 'costume.' Up to 1.5 million costumed people flood Cologne's streets on Rosenmontag. Not dressing up marks you as an outsider instantly."},
{type:"teach",trg:"die Tradition",src:"the tradition",pos:"noun",gender:"f",note:"Feminine noun. Same as English, from Latin 'traditio' (handing down).\nRhineland Karneval traditions date back over 600 years.",example:"A: Ist Karneval eine alte Tradition?\nB: Ja, \u00fcber 600 Jahre alt im Rheinland.\nA: Jede Stadt hat eigene Traditionen?\nB: Genau. K\u00f6ln ruft 'Alaaf!', D\u00fcsseldorf ruft 'Helau!'",exampleSrc:"A: Is carnival an old tradition?\nB: Yes, over 600 years old in the Rhineland.\nA: Every city has its own traditions?\nB: Exactly. Cologne shouts 'Alaaf!', Düsseldorf shouts 'Helau!'",funFact:"Every city has its own greeting: 'Alaaf!' in Cologne, 'Helau!' in D\u00fcsseldorf. Using the wrong one in the wrong city is a social crime."},
{type:"teach",trg:"die Freude",src:"the joy",pos:"noun",gender:"f",note:"Feminine noun. From Old High German 'frewida.'\n'Freude sch\u00f6ner G\u00f6tterfunken' is the European anthem.",example:"A: Sp\u00fcrst du die Freude in der Luft?\nB: Ja! Alle Menschen lachen und tanzen.\nA: Das ist die Freude des Karnevals.\nB: So etwas habe ich noch nie erlebt.",exampleSrc:"A: Do you feel the joy in the air?\nB: Yes! Everyone is laughing and dancing.\nA: That is the joy of carnival.\nB: I've never experienced anything like this.",funFact:"Beethoven set Schiller's 'Ode an die Freude' to music. It became the European anthem. Joy is literally Europe's official emotion."},
{type:"teach",trg:"der Humor",src:"the humor",pos:"noun",gender:"m",note:"Masculine noun. Same in English and German, from Latin.\nGerman humor exists, despite the stereotype.",example:"A: Haben Deutsche wirklich keinen Humor?\nB: Quatsch! Karneval beweist das Gegenteil.\nA: Die politische Satire ist wirklich gut.\nB: Ja, deutscher Humor ist clever und mutig.",exampleSrc:"A: Do Germans really have no humor?\nB: Nonsense! Carnival proves the opposite.\nA: The political satire is really good.\nB: Yes, German humor is clever and bold.",funFact:"Karneval proves German humor exists. Political satire on parade floats is biting, clever, and fearless. Carnival comedians are celebrities."},
{type:"teach",trg:"der Hut",src:"the hat",pos:"noun",gender:"m",note:"Masculine noun. Same root as English 'hood.'\n'Hut ab!' (Hat off!) means 'Respect!'",example:"A: Sch\u00f6ner Hut! Woher hast du den?\nB: Selbst gemacht! Mit Federn und Glitzer.\nA: Hut ab! Der ist wirklich kreativ.\nB: Danke! Drei Abende Arbeit.",exampleSrc:"A: Nice hat! Where did you get it?\nB: Handmade! With feathers and glitter.\nA: Respect! It's really creative.\nB: Thanks! Three evenings of work.",funFact:"'Hut ab!' (Hat off!) means 'Respect!' Karneval hats range from tiny pointed Narrenkappen to enormous feathered creations."},
{type:"teach",trg:"der Schmuck",src:"the jewelry, the decoration",pos:"noun",gender:"m",note:"Masculine noun. From 'schm\u00fccken' (to decorate).\nEnglish borrowed 'schmuck' as an insult from Yiddish, but in German it means something beautiful.",example:"A: Du tr\u00e4gst so viel Schmuck heute!\nB: Beim Karneval gilt: je mehr, desto besser.\nA: Die Ketten und Ohrringe sind toll.\nB: Alles nur Modeschmuck, aber es gl\u00e4nzt!",exampleSrc:"A: You're wearing so much jewelry today!\nB: At carnival the rule is: the more, the better.\nA: The necklaces and earrings are great.\nB: All just costume jewelry, but it sparkles!",funFact:"In German, Schmuck means something beautiful. English borrowed 'schmuck' as an insult from Yiddish, a completely different meaning. During Karneval, the more Schmuck the better."},
{type:"teach",trg:"fr\u00f6hlich",src:"happy, cheerful",pos:"adj",gender:null,note:"From 'froh' (glad) + '-lich.' Describes bubbly, outward happiness.\nThe Rhineland is stereotyped as Germany's fr\u00f6hlich region.",example:"A: Warum sind alle so fr\u00f6hlich?\nB: Das ist der Geist des Karnevals!\nA: Sogar die Polizisten lachen.\nB: Fr\u00f6hliche Menschen \u00fcberall!",exampleSrc:"A: Why is everyone so cheerful?\nB: That's the spirit of carnival!\nA: Even the police officers are laughing.\nB: Happy people everywhere!",funFact:"'Fr\u00f6hliche Weihnachten!' means Merry Christmas. The Rhineland is stereotyped as Germany's most fr\u00f6hlich region."},
{type:"teach",trg:"verr\u00fcckt",src:"crazy",pos:"adj",gender:null,note:"Literally 'moved/shifted' (ver- + r\u00fccken).\nSomething shifted out of its normal place.",example:"A: Das ist ja verr\u00fcckt hier!\nB: Ja, Karneval ist offiziell verr\u00fcckt.\nA: Ein Mann im Bananenkost\u00fcm tanzt auf dem Tisch.\nB: Ganz normal beim Karneval!",exampleSrc:"A: This is crazy here!\nB: Yes, carnival is officially crazy.\nA: A man in a banana costume is dancing on the table.\nB: Totally normal at carnival!",funFact:"Literally means 'shifted out of place.' 'Das ist verr\u00fcckt!' is the German 'That's crazy!' Karneval is officially sanctioned verr\u00fcckt."},
{type:"teach",trg:"wundersch\u00f6n",src:"wonderfully beautiful",pos:"adj",gender:null,note:"Wunder (wonder) + sch\u00f6n (beautiful). A superlative that stacks wonder on top of beauty.\nStronger than just 'sch\u00f6n.'",example:"A: Schau mal die Kost\u00fcme!\nB: Wundersch\u00f6n! Besonders die Kleider.\nA: Die Farben sind unglaublich.\nB: K\u00f6ln ist heute wundersch\u00f6n.",exampleSrc:"A: Look at the costumes!\nB: Wonderfully beautiful! Especially the dresses.\nA: The colors are incredible.\nB: Cologne is wonderfully beautiful today.",funFact:"Germans use wundersch\u00f6n for landscapes, moments, and people they genuinely admire. It stacks wonder on top of beauty."},
{type:"teach",trg:"begeistert",src:"enthusiastic, thrilled",pos:"adj",gender:null,note:"From 'Geist' (spirit). Be-geist-ert = 'filled with spirit.'\nWhen you are begeistert, a spirit has entered you.",example:"A: Wie findest du den Karneval?\nB: Ich bin total begeistert!\nA: Das freut mich. Du strahlst richtig.\nB: So viel Energie und Freude!",exampleSrc:"A: How do you find the carnival?\nB: I'm totally thrilled!\nA: I'm glad. You're really glowing.\nB: So much energy and joy!",funFact:"From 'Geist' (spirit). When you are begeistert, a spirit has literally entered you. The perfect word for carnival energy."},
{type:"teach",trg:"riesig",src:"huge, enormous",pos:"adj",gender:null,note:"From 'Riese' (giant). Literally 'giant-like.'\nCologne's parade stretches over 7 kilometers.",example:"A: Die Wagen sind riesig!\nB: Manche sind \u00fcber zehn Meter hoch.\nA: Und die Menschenmenge ist auch riesig.\nB: \u00dcber eine Million Menschen!",exampleSrc:"A: The floats are enormous!\nB: Some are over ten meters tall.\nA: And the crowd is also huge.\nB: Over one million people!",funFact:"From 'Riese' (giant). Carnival floats are riesig. Cologne's parade stretches over 7 kilometers. Everything at Karneval is riesig."},
{type:"teach",trg:"kreativ",src:"creative",pos:"adj",gender:null,note:"From Latin 'creare.' Same in many languages.\nKarneval costumes reward kreative Ideen.",example:"A: Dein Kost\u00fcm ist sehr kreativ!\nB: Danke, ich habe es selbst gemacht.\nA: Aus was ist das?\nB: Aus Pappe, Farbe und Fantasie!",exampleSrc:"A: Your costume is very creative!\nB: Thanks, I made it myself.\nA: What is it made of?\nB: Cardboard, paint, and imagination!",funFact:"The best Karneval costumes are handmade, political, or absurdly original. A bed frame as a costume? Kreativ."},
{type:"teach",trg:"gr\u00fc\u00dfen",src:"to greet",pos:"verb",gender:null,note:"From 'Gru\u00df' (greeting). During Karneval, strangers gr\u00fc\u00dfen each other.\n'Alaaf!' and 'Helau!' replace 'Hallo.'",example:"A: Gr\u00fc\u00df dich! K\u00f6lle Alaaf!\nB: Alaaf! Sch\u00f6nes Kost\u00fcm!\nA: Danke! Beim Karneval gr\u00fc\u00dft man jeden.\nB: Das ist so anders als im Alltag.",exampleSrc:"A: Greetings! K\u00f6lle Alaaf!\nB: Alaaf! Nice costume!\nA: Thanks! At carnival you greet everyone.\nB: That's so different from everyday life.",funFact:"Greeting strangers in normal German life would be unusual. At Karneval it is mandatory. 'Alaaf!' and 'Helau!' replace 'Hallo.'"},
{type:"teach",trg:"schauen",src:"to look, to watch",pos:"verb",gender:null,note:"Southern German and Austrian for 'gucken.'\n'Schau mal!' (Look!) is what Mia says every five seconds.",example:"A: Schau mal, der Wagen!\nB: Wow, der ist riesig!\nA: Schau dir die Details an!\nB: Unglaublich. Ich kann nicht aufh\u00f6ren zu schauen.",exampleSrc:"A: Look, the float!\nB: Wow, it's enormous!\nA: Look at the details!\nB: Unbelievable. I can't stop looking.",funFact:"Standard German, slightly more literary than gucken. 'Schau mal!' (Look!) is the southern version of 'Guck mal!'"},
{type:"teach",trg:"gucken",src:"to look, to peek",pos:"verb",gender:null,note:"Northern German and colloquial.\n'Guck mal!' = 'Look!' Same meaning as schauen but more casual.",example:"A: Guck mal, ein Pirat!\nB: Und da, eine Prinzessin!\nA: Man kann \u00fcberall hingucken.\nB: Jede Richtung ist Karneval.",exampleSrc:"A: Look, a pirate!\nB: And there, a princess!\nA: You can look everywhere.\nB: Every direction is carnival.",funFact:"Northern German and colloquial. Perfect pair with schauen: there is a LOT to guck at during Karneval."},
{type:"teach",trg:"winken",src:"to wave",pos:"verb",gender:null,note:"People wave at parade floats to get candy thrown to them.\n'Winke winke!' is baby talk for waving goodbye.",example:"A: Wink mal! Dann werfen sie Bonbons!\nB: So? (winkt enthusiastisch)\nA: Ja! Lauter! Kamelle!\nB: Es funktioniert! Ich habe Schokolade gefangen!",exampleSrc:"A: Wave! Then they'll throw candy!\nB: Like this? (waves enthusiastically)\nA: Yes! Louder! Kamelle!\nB: It works! I caught chocolate!",funFact:"At the Rosenmontagszug, enthusiastic winken equals more candy. 'Winke winke!' is baby talk for waving goodbye."},
{type:"teach",trg:"diesmal",src:"this time",pos:"adv",gender:null,note:"Dies (this) + mal (time/instance).\n'Diesmal ist alles anders' (This time everything is different).",example:"A: Warst du schon mal in K\u00f6ln?\nB: Ja, aber diesmal ist es anders.\nA: Warum?\nB: Diesmal bin ich beim Karneval!",exampleSrc:"A: Have you been to Cologne before?\nB: Yes, but this time it's different.\nA: Why?\nB: This time I'm at Carnival!",funFact:"Verumius has seen formal Germany, bureaucratic Germany, quiet Germany. Diesmal: wild Germany."},
{type:"mc",q:"Verumius sieht Menschen in bunten Kleidern. Was tragen sie?",opts:["H\u00fcte","Schmuck","Formulare","Kost\u00fcme"],ans:"Kost\u00fcme",hint:"The special clothing people wear to transform into someone else during carnival."},
{type:"mc",q:"Mia ruft: 'K\u00f6lle Alaaf!' Was bedeutet das?",opts:["Eine Bitte um Ruhe","Eine Beleidigung","Ein k\u00f6lnischer Karnevalsgru\u00df","Ein Abschied"],ans:"Ein k\u00f6lnischer Karnevalsgru\u00df",hint:"The traditional shout of celebration specific to Cologne's carnival."},
{type:"fb",s:"Die Parade ist {1}. Sie ist \u00fcber sieben Kilometer lang!",a:["riesig"],opts:["riesig","fr\u00f6hlich","kreativ","verr\u00fcckt"],hint:"A word meaning enormous, derived from the German word for giant.",sSrc:"The parade is enormous. It is over seven kilometers long!"}
]},

// ─── Lesson 2: Masken und Melodien ────────────────────────────
{id:"deu_r17l2",title:"Masken und Melodien",icon:"\uD83C\uDFB6",xp:15,board:true,steps:[
{type:"intro",title:"Masken und Melodien",desc:"Music, stages, performances. Karneval is not just costumes but also entertainment. Learn words for music, performance, and showbusiness.",goals:["Learn words for stage, music, and entertainment","Understand the -er/-erin pattern for profession names","Describe Karneval shows and street performers"]},
{type:"teach",trg:"die B\u00fchne",src:"the stage",pos:"noun",gender:"f",note:"Feminine noun. From Middle High German 'b\u00fchne' (raised platform).\nEvery Karneval has a B\u00fchne f\u00fcr die 'Sitzung' (formal comedy session).",example:"A: Wann ist der Auftritt auf der B\u00fchne?\nB: In zehn Minuten. Die Band macht sich bereit.\nA: Ich sehe die B\u00fchne von hier.\nB: Lass uns n\u00e4her gehen!",exampleSrc:"A: When is the performance on stage?\nB: In ten minutes. The band is getting ready.\nA: I can see the stage from here.\nB: Let's go closer!",funFact:"Every Karneval celebration has a B\u00fchne for the 'Sitzung' (formal comedy session). These are not amateur nights. Rhineland B\u00fchnenkultur is professional entertainment."},
{type:"teach",trg:"der Tanz",src:"the dance",pos:"noun",gender:"m",note:"Masculine noun. From Old French 'danse.'\nCarnival dances include the Funkenmariechen (female solo dancer).",example:"A: Magst du den Tanz?\nB: Ja, die T\u00e4nzerin ist fantastisch!\nA: Der Tanz ist eine Tradition.\nB: So elegant und gleichzeitig lustig.",exampleSrc:"A: Do you like the dance?\nB: Yes, the dancer is fantastic!\nA: The dance is a tradition.\nB: So elegant and funny at the same time.",funFact:"Carnival dances include the Funkenmariechen, a female solo dancer in military costume. Some Tanz traditions go back centuries."},
{type:"teach",trg:"der S\u00e4nger",src:"the singer (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'singen' + '-er' (agent suffix).\nCarnival S\u00e4nger perform songs that become annual hits.",example:"A: Wer ist der S\u00e4nger auf der B\u00fchne?\nB: Das ist ein ber\u00fchmter Karnevalss\u00e4nger.\nA: Er singt wahnsinnig gut!\nB: Seine Lieder kennt jeder in K\u00f6ln.",exampleSrc:"A: Who is the singer on stage?\nB: That's a famous carnival singer.\nA: He sings insanely well!\nB: Everyone in Cologne knows his songs.",funFact:"Carnival S\u00e4nger perform original songs that become annual hits. The best ones are remembered for decades across the Rhineland."},
{type:"teach",trg:"die S\u00e4ngerin",src:"the singer (female)",pos:"noun",gender:"f",note:"Feminine noun. S\u00e4nger + '-in.'\nThe -er/-erin pattern works for all agent nouns.",example:"A: Die S\u00e4ngerin hat eine tolle Stimme.\nB: Ja, sie ist die beste im ganzen Rheinland.\nA: Kennst du ihre Lieder?\nB: Nat\u00fcrlich! Alle singen mit.",exampleSrc:"A: The singer has a great voice.\nB: Yes, she's the best in the whole Rhineland.\nA: Do you know her songs?\nB: Of course! Everyone sings along.",funFact:"The -er/-erin pattern works for all agent nouns. You already know Lehrer/Lehrerin, Spieler/Spielerin. Same system every time."},
{type:"teach",trg:"der Musiker",src:"the musician (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'Musik' + '-er.'\nCarnival bands play brass-heavy music that gets entire streets moving.",example:"A: Der Musiker spielt Trompete.\nB: Und der andere spielt Trommel.\nA: Die Musik ist so mitrei\u00dfend!\nB: Karnevalsmusiker sind echte Profis.",exampleSrc:"A: The musician plays trumpet.\nB: And the other one plays drums.\nA: The music is so captivating!\nB: Carnival musicians are real professionals.",funFact:"Carnival bands (Kapellen) play brass-heavy music that gets entire streets moving. Being a Karnevalsmusiker is a respected tradition."},
{type:"teach",trg:"die Musikerin",src:"the musician (female)",pos:"noun",gender:"f",note:"Feminine noun. Musiker + '-in.'\nThe pattern is reliable: Musiker/Musikerin, K\u00fcnstler/K\u00fcnstlerin.",example:"A: Die Musikerin spielt Fl\u00f6te.\nB: Sie ist wirklich talentiert.\nA: Seit wann spielt sie?\nB: Seit sie ein Kind war.",exampleSrc:"A: The musician plays flute.\nB: She is really talented.\nA: How long has she been playing?\nB: Since she was a child.",funFact:"The -ler/-lerin pattern: Musiker/Musikerin, K\u00fcnstler/K\u00fcnstlerin, Sportler/Sportlerin. German builds profession pairs reliably."},
{type:"teach",trg:"die Oper",src:"the opera",pos:"noun",gender:"f",note:"Feminine noun. From Italian 'opera' (work).\nCologne has the Oper K\u00f6ln, one of Germany's largest opera houses.",example:"A: Warst du schon mal in der Oper?\nB: Ja, einmal in der Oper K\u00f6ln.\nA: W\u00e4hrend des Karnevals?\nB: Ja! Sogar die Oper macht beim Karneval mit.",exampleSrc:"A: Have you ever been to the opera?\nB: Yes, once at the Cologne Opera.\nA: During carnival?\nB: Yes! Even the opera joins in during carnival.",funFact:"Cologne has the Oper K\u00f6ln, one of Germany's largest opera houses. During Karneval season, even the opera gets into the spirit."},
{type:"teach",trg:"das Orchester",src:"the orchestra",pos:"noun",gender:"n",note:"Neuter noun. From Greek 'orchestra' (dancing place).\nKarneval uses everything from full Orchester to tiny street bands.",example:"A: H\u00f6rst du das Orchester?\nB: Ja, sie spielen Karnevalsmusik!\nA: Ein ganzes Orchester auf der Stra\u00dfe!\nB: Das gibt es nur beim Karneval.",exampleSrc:"A: Do you hear the orchestra?\nB: Yes, they're playing carnival music!\nA: A whole orchestra on the street!\nB: That only happens at carnival.",funFact:"From Greek 'orchestra' (dancing place). Karneval uses everything from full Orchester to tiny street bands."},
{type:"teach",trg:"die Fl\u00f6te",src:"the flute",pos:"noun",gender:"f",note:"Feminine noun. From Old French 'flaute.'\n'Blockfl\u00f6te' (recorder) is the instrument every German child learns first.",example:"A: Was ist das f\u00fcr ein Instrument?\nB: Das ist eine Fl\u00f6te.\nA: Der Klang ist so sch\u00f6n.\nB: Fl\u00f6ten geh\u00f6ren zu jedem Karnevalszug.",exampleSrc:"A: What kind of instrument is that?\nB: That's a flute.\nA: The sound is so beautiful.\nB: Flutes belong to every carnival parade.",funFact:"In carnival parades, you hear Fl\u00f6ten alongside drums and brass. 'Blockfl\u00f6te' (recorder) is the instrument every German child learns first."},
{type:"teach",trg:"das Publikum",src:"the audience",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'publicum' (the public).\nAt Karneval, the line between Publikum and performers blurs.",example:"A: Das Publikum ist begeistert!\nB: Alle klatschen und singen mit.\nA: Wo h\u00f6rt das Publikum auf und wo fangen die K\u00fcnstler an?\nB: Beim Karneval gibt es keinen Unterschied.",exampleSrc:"A: The audience is thrilled!\nB: Everyone is clapping and singing along.\nA: Where does the audience end and the artists begin?\nB: At carnival there's no difference.",funFact:"At Karneval, the line between Publikum and performers blurs completely. Everyone sings along, everyone dances, everyone is part of the show."},
{type:"teach",trg:"der Auftritt",src:"the performance, the appearance",pos:"noun",gender:"m",note:"Masculine noun. Auf (on/up) + Tritt (step).\nLiterally 'stepping onto' the stage.",example:"A: Der Auftritt war fantastisch!\nB: Ja, die Band hat alles gegeben.\nA: Wann ist der n\u00e4chste Auftritt?\nB: In einer Stunde auf der gro\u00dfen B\u00fchne.",exampleSrc:"A: The performance was fantastic!\nB: Yes, the band gave it their all.\nA: When is the next performance?\nB: In one hour on the main stage.",funFact:"Literally 'stepping up onto' the stage. An appearance, a performance. Whether on stage or entering a room, it is always an Auftritt."},
{type:"teach",trg:"der Saal",src:"the hall, the ballroom",pos:"noun",gender:"m",note:"Masculine noun. From Old High German 'sal.'\nPlural: S\u00e4le. One of the few German words with this unusual plural.",example:"A: Der Saal ist voll!\nB: \u00dcber tausend Menschen in einem Saal.\nA: Die Stimmung ist unglaublich.\nB: Karnevalss\u00e4le sind immer ausverkauft.",exampleSrc:"A: The hall is full!\nB: Over a thousand people in one hall.\nA: The atmosphere is incredible.\nB: Carnival halls are always sold out.",funFact:"Karneval 'Sitzungen' happen in large S\u00e4le (plural). The biggest hold thousands of costumed revelers. Saal is one of the few German words with the plural S\u00e4le."},
{type:"teach",trg:"musikalisch",src:"musical",pos:"adj",gender:null,note:"From Musik + '-alisch.'\n'Sie ist sehr musikalisch' (She is very musical).",example:"A: Bist du musikalisch?\nB: Ein bisschen. Ich spiele Gitarre.\nA: Das Rheinland ist sehr musikalisch.\nB: Hier singt man \u00fcberall, sogar in der Kneipe.",exampleSrc:"A: Are you musical?\nB: A little. I play guitar.\nA: The Rhineland is very musical.\nB: Here people sing everywhere, even in the pub.",funFact:"The Rhineland is Germany's most musikalisch region. People sing at pubs, parades, and train stations during Karneval."},
{type:"teach",trg:"popul\u00e4r",src:"popular",pos:"adj",gender:null,note:"From Latin 'popularis.' Same as English.\nStress falls on the last syllable: po-pu-L\u00c4R.",example:"A: Dieses Lied ist sehr popul\u00e4r.\nB: Ja, jeder kennt es!\nA: Wie hei\u00dft es?\nB: 'Viva Colonia.' Der popul\u00e4rste Karnevalsschlager.",exampleSrc:"A: This song is very popular.\nB: Yes, everyone knows it!\nA: What's it called?\nB: 'Viva Colonia.' The most popular carnival hit.",funFact:"'Viva Colonia' is one of the most popul\u00e4r Karnevalslieder ever. Karneval songs become national hits that people sing for decades."},
{type:"teach",trg:"traditionell",src:"traditional",pos:"adj",gender:null,note:"Tradition + '-ell.' Karneval is both traditionell and modern.\nOld Sitzung format coexists with techno floats.",example:"A: Ist das ein traditionelles Lied?\nB: Ja, schon \u00fcber hundert Jahre alt.\nA: Aber die Band spielt es modern.\nB: Traditionell und modern, das passt zusammen.",exampleSrc:"A: Is that a traditional song?\nB: Yes, over a hundred years old.\nA: But the band plays it in a modern way.\nB: Traditional and modern, that fits together.",funFact:"Karneval is both traditionell and modern. The old Sitzung format coexists with techno floats and hip-hop acts."},
{type:"teach",trg:"elegant",src:"elegant",pos:"adj",gender:null,note:"Same as English, from French.\nSome carnival events demand elegante Kost\u00fcme.",example:"A: Dein Kost\u00fcm ist sehr elegant.\nB: Danke! Es ist ein Prinzessinnenkleid.\nA: Elegant und trotzdem Karneval.\nB: Man kann beides sein!",exampleSrc:"A: Your costume is very elegant.\nB: Thanks! It's a princess dress.\nA: Elegant and still carnival.\nB: You can be both!",funFact:"Some carnival events demand elegante costumes. The Prinzenpaar (carnival prince and princess) wear regal outfits. Elegant is the opposite of the street chaos."},
{type:"teach",trg:"schick",src:"stylish, chic",pos:"adj",gender:null,note:"Borrowed from French 'chic.'\n'Das Kost\u00fcm ist sehr schick!' Implies taste and effort.",example:"A: Du siehst schick aus!\nB: Findest du? Nur ein einfaches Kost\u00fcm.\nA: Aber sehr schick gemacht.\nB: Danke, das ist nett von dir.",exampleSrc:"A: You look stylish!\nB: You think? Just a simple costume.\nA: But very stylishly done.\nB: Thanks, that's nice of you.",funFact:"Borrowed from French 'chic.' A schick costume gets compliments. A verr\u00fcckt costume gets laughs. Both are welcome at Karneval."},
{type:"teach",trg:"am\u00fcsieren",src:"to amuse, to have fun",pos:"verb",gender:null,note:"From French 'amuser.' Reflexive: sich am\u00fcsieren.\n'Wir haben uns k\u00f6stlich am\u00fcsiert' (We had a wonderful time).",example:"A: Am\u00fcsierst du dich?\nB: Ja, ich am\u00fcsiere mich k\u00f6stlich!\nA: Das freut mich.\nB: Karneval ist zum Am\u00fcsieren gemacht.",exampleSrc:"A: Are you having fun?\nB: Yes, I'm having a wonderful time!\nA: I'm glad.\nB: Carnival is made for having fun.",funFact:"The core purpose of Karneval: sich am\u00fcsieren. 'Wir haben uns k\u00f6stlich am\u00fcsiert' is one of the most satisfying German sentences."},
{type:"teach",trg:"l\u00e4cheln",src:"to smile",pos:"verb",gender:null,note:"The diminutive form of 'lachen' (to laugh).\nThe '-eln' ending makes it softer: a gentle smile, not a full laugh.",example:"A: Warum l\u00e4chelst du?\nB: Weil alles so sch\u00f6n ist.\nA: Du l\u00e4chelst seit einer Stunde.\nB: Karneval macht das mit mir.",exampleSrc:"A: Why are you smiling?\nB: Because everything is so beautiful.\nA: You've been smiling for an hour.\nB: Carnival does that to me.",funFact:"The diminutive form of 'lachen' (to laugh). The '-eln' ending softens it: not a full laugh, but a gentle smile. 'Sie l\u00e4chelt' is one of the most beautiful German sentences."},
{type:"teach",trg:"klingen",src:"to sound",pos:"verb",gender:null,note:"Irregular: klingt, klang, geklungen.\nRelated to English 'cling' and 'clang.'",example:"A: Die Musik klingt fantastisch!\nB: Ja, das Orchester klingt wunderbar.\nA: Alles klingt nach Karneval.\nB: Musik, Lachen, Gl\u00e4ser, Konfetti.",exampleSrc:"A: The music sounds fantastic!\nB: Yes, the orchestra sounds wonderful.\nA: Everything sounds like carnival.\nB: Music, laughter, glasses, confetti.",funFact:"Irregular: klingt, klang, geklungen. Related to English 'cling' and 'clang.' At Karneval, everything klingt: music, laughter, glasses."},
{type:"mc",q:"Die Band betritt die B\u00fchne. Was bedeutet 'Auftritt'?",opts:["ein Orchester","eine Melodie","ein Auftritt auf der B\u00fchne","ein Tanz"],ans:"ein Auftritt auf der B\u00fchne",hint:"Literally stepping up onto something, like a stage. An appearance or performance."},
{type:"mc",q:"Wenn ein m\u00e4nnlicher Musiker 'der Musiker' ist, was ist eine weibliche Musikerin?",opts:["der Musikerin","die Musikerin","das Musikerin","die Musiker"],ans:"die Musikerin",hint:"The universal feminine suffix in German adds -in and changes the article to die."},
{type:"fb",s:"Die Musik {1} fantastisch!",a:["klingt"],opts:["klingt","klingen","schaut","l\u00e4chelt"],hint:"Which verb describes how music reaches your ears?",sSrc:"The music sounds fantastic!"},
{type:"match",pairs:[{trg:"B\u00fchne",src:"stage"},{trg:"Publikum",src:"audience"},{trg:"Auftritt",src:"performance"},{trg:"Saal",src:"hall"}]},
{type:"mc",q:"Mia sagt: 'Ich habe mich am\u00fcsiert.' Was bedeutet das?",opts:["Ich habe gesungen","Ich hatte Spa\u00df","Ich war ver\u00e4rgert","Ich habe getanzt"],ans:"Ich hatte Spa\u00df",hint:"Sich am\u00fcsieren is the reflexive verb for entertaining yourself, having a good time."}
]},

// ─── Lesson 3: Jeder ist du ──────────────────────────────────
{id:"deu_r17l3",title:"Jeder ist du",icon:"\uD83E\uDD1D",xp:15,board:true,steps:[
{type:"intro",title:"Jeder ist du",desc:"During Karneval the rules are suspended. Strangers say 'du.' People dress up to be someone else. Learn costume and character vocabulary and the um...zu construction.",goals:["Learn vocabulary for costumes and characters","Understand the um...zu construction (purpose)","Discover why Karneval suspends Germany's formality"]},
{type:"story",speaker:"narrator",mood:"warm",art:"koeln-altstadt-kneipe",trg:"K\u00f6lner Altstadt. Eine enge Gasse mit mittelalterlichen H\u00e4usern, geschm\u00fcckt mit Luftschlangen und Konfetti. Verumius und Mia sitzen an einem Kneipentisch. Ein Mann im Piratenkost\u00fcm hebt sein Glas: 'Alaaf!' Ein Fremder. Und er hat 'du' benutzt.",src:"Cologne Old Town. A narrow alley of medieval buildings draped in streamers and confetti. Verumius and Mia sit at a pub table. A man in a pirate costume raises his glass: 'Alaaf!' A stranger. And he used 'du.'"},
{type:"story",speaker:"verumius",mood:"amazed",trg:"Hat der Pirat gerade 'du' zu mir gesagt? Ein Fremder?",src:"Did the pirate just say 'du' to me? A stranger?"},
{type:"story",speaker:"mia",mood:"explaining",trg:"Beim Karneval sind alle du. Die Regeln sind aufgehoben. Man verkleidet sich, um eine andere Person zu sein. Ohne sich zu verkleiden, kann man Karneval nicht richtig erleben.",src:"At carnival everyone is 'du.' The rules are suspended. You dress up in order to be a different person. Without dressing up, you can't properly experience carnival."},
{type:"story",speaker:"verumius",mood:"happy",trg:"Also bin ich nicht Verumius der Ausl\u00e4nder. Ich bin... ein r\u00f6mischer Senator?",src:"So I'm not Verumius the foreigner. I'm... a Roman senator?"},
{type:"story",speaker:"mia",mood:"laughing",trg:"Genau! Statt Formulare auszuf\u00fcllen, feierst du. Das ist der Punkt.",src:"Exactly! Instead of filling out forms, you celebrate. That's the point."},
{type:"teach",trg:"der Held",src:"the hero",pos:"noun",gender:"m",note:"Masculine noun. From Old High German 'helid' (warrior).\nCarnival is full of Helden: superheroes, knights, fairy tale princes.",example:"A: Als wer bist du verkleidet?\nB: Als Superheld!\nA: Jeder will ein Held sein.\nB: Beim Karneval kann jeder ein Held sein.",exampleSrc:"A: Who are you dressed up as?\nB: As a superhero!\nA: Everyone wants to be a hero.\nB: At carnival everyone can be a hero.",funFact:"From Old High German 'helid' (warrior). Related to English 'hold' in its original sense of bravery. The costume makes the Held."},
{type:"teach",trg:"die Heldin",src:"the hero (female)",pos:"noun",gender:"f",note:"Feminine noun. Held + '-in.'\nWonder Woman, Pippi Langstrumpf, Cleopatra: popular carnival Heldinnen.",example:"A: Tolles Kost\u00fcm! Wer bist du?\nB: Ich bin eine Heldin aus einem M\u00e4rchen.\nA: Welche Heldin?\nB: Rosenrot! Aus 'Schneewittchen und Rosenrot.'",exampleSrc:"A: Great costume! Who are you?\nB: I'm a heroine from a fairy tale.\nA: Which heroine?\nB: Rose Red! From 'Snow White and Rose Red.'",funFact:"The -in pattern even works on ancient words like Held. Wonder Woman, Cleopatra, and Pippi Langstrumpf are all popular carnival Heldinnen."},
{type:"teach",trg:"der K\u00fcnstler",src:"the artist (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'Kunst' (art) + '-ler.'\nProfessional K\u00fcnstler design the massive parade floats.",example:"A: Wer hat diesen Wagen gebaut?\nB: Ein Team von K\u00fcnstlern.\nA: Das ist echte Kunst!\nB: Die K\u00fcnstler arbeiten monatelang daran.",exampleSrc:"A: Who built this float?\nB: A team of artists.\nA: That's real art!\nB: The artists work on it for months.",funFact:"Carnival is art. Professional K\u00fcnstler design the massive parade floats months in advance. Some floats are genuine political masterpieces."},
{type:"teach",trg:"die K\u00fcnstlerin",src:"the artist (female)",pos:"noun",gender:"f",note:"Feminine noun. K\u00fcnstler + '-in.'\nThe -ler/-lerin pattern: Sportler/Sportlerin, K\u00fcnstler/K\u00fcnstlerin.",example:"A: Die K\u00fcnstlerin hat die Masken gemalt.\nB: Sie ist unglaublich talentiert.\nA: Jede Maske ist ein Kunstwerk.\nB: Die K\u00fcnstlerin hat drei Wochen daf\u00fcr gebraucht.",exampleSrc:"A: The artist painted the masks.\nB: She is incredibly talented.\nA: Every mask is a work of art.\nB: The artist needed three weeks for them.",funFact:"The -ler/-lerin pattern: K\u00fcnstler/K\u00fcnstlerin, Sportler/Sportlerin. German builds profession pairs as reliably as compound nouns."},
{type:"teach",trg:"die Rolle",src:"the role",pos:"noun",gender:"f",note:"Feminine noun. From French 'role' (originally a scroll with an actor's lines).\n'Welche Rolle spielst du?' is the standard Karneval question.",example:"A: Welche Rolle spielst du heute?\nB: Ich bin ein r\u00f6mischer Senator.\nA: Die Rolle passt zu dir!\nB: Beim Karneval spielt jeder eine Rolle.",exampleSrc:"A: What role are you playing today?\nB: I'm a Roman senator.\nA: The role suits you!\nB: At carnival everyone plays a role.",funFact:"At Karneval, your costume IS your Rolle. 'Welche Rolle spielst du?' is the standard question at every carnival party."},
{type:"teach",trg:"die Figur",src:"the character, the figure",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'figura.'\n'Eine interessante Figur' means a character in a story OR an interesting person.",example:"A: Welche Figur bist du?\nB: Eine Figur aus einem Comic.\nA: Ich erkenne die Figur nicht.\nB: Das ist auch egal. Hauptsache bunt!",exampleSrc:"A: Which character are you?\nB: A character from a comic.\nA: I don't recognize the character.\nB: That doesn't matter. Main thing is colorful!",funFact:"At Karneval, everyone becomes a Figur. 'Eine interessante Figur' can mean a fictional character OR a fascinating real person."},
{type:"teach",trg:"die Szene",src:"the scene",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'skene' (tent, stage backdrop).\nDie Karnevalsszene = the entire carnival subculture.",example:"A: Das ist eine tolle Szene!\nB: Ja, die Altstadt ist eine einzige gro\u00dfe Szene.\nA: Wie im Theater.\nB: Genau, und jeder spielt mit.",exampleSrc:"A: What a great scene!\nB: Yes, the Old Town is one big scene.\nA: Like in a theater.\nB: Exactly, and everyone plays along.",funFact:"Also means a social milieu. 'Die Karnevalsszene' is the entire carnival subculture: the societies, the traditions, the insiders."},
{type:"teach",trg:"die Puppe",src:"the doll, the puppet",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'pupa.'\nCarnival floats often feature giant Puppen of politicians.",example:"A: Schau, diese riesige Puppe auf dem Wagen!\nB: Das ist ein Politiker!\nA: Als Puppe auf einem Karnevalswagen?\nB: Ja, das ist politische Satire.",exampleSrc:"A: Look at that giant puppet on the float!\nB: That's a politician!\nA: As a puppet on a carnival float?\nB: Yes, that's political satire.",funFact:"Carnival floats often feature giant Puppen of politicians and celebrities. Being turned into a Karnevalspuppe means you are famous enough to mock."},
{type:"teach",trg:"das M\u00e4rchen",src:"the fairy tale",pos:"noun",gender:"n",note:"Neuter noun because of the -chen ending.\nFrom 'M\u00e4r' (tale) + '-chen' (diminutive).",example:"A: Als wer bist du verkleidet?\nB: Als Prinz aus einem M\u00e4rchen!\nA: Welches M\u00e4rchen?\nB: Dornr\u00f6schen. Aber ich bin der Prinz.",exampleSrc:"A: Who are you dressed up as?\nB: A prince from a fairy tale!\nA: Which fairy tale?\nB: Sleeping Beauty. But I'm the prince.",funFact:"Grimm's M\u00e4rchen (Cinderella, Snow White, Hansel and Gretel) are Germany's biggest cultural export after cars and beer. The -chen ending always makes nouns neuter."},
{type:"teach",trg:"die Fantasie",src:"the imagination, the fantasy",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'phantasia.'\nGerman spells it with F, not Ph.",example:"A: Das Kost\u00fcm ist pure Fantasie!\nB: Danke! Fantasie ist alles beim Karneval.\nA: Ohne Fantasie kein Kost\u00fcm.\nB: Genau. Fantasie ist das Wichtigste.",exampleSrc:"A: The costume is pure imagination!\nB: Thanks! Imagination is everything at carnival.\nA: Without imagination, no costume.\nB: Exactly. Imagination is the most important thing.",funFact:"German spells it Fantasie with F, not Ph. Karneval is where German Fantasie breaks free from German Ordnung (order)."},
{type:"teach",trg:"locker",src:"relaxed, casual",pos:"adj",gender:null,note:"'Locker bleiben!' (Stay relaxed!)\nThe Rhineland attitude is locker, warm and informal.",example:"A: Die Stimmung hier ist so locker.\nB: Ja, das Rheinland ist locker.\nA: Anders als in Berlin.\nB: Berlin ist cool, das Rheinland ist warm.",exampleSrc:"A: The atmosphere here is so relaxed.\nB: Yes, the Rhineland is relaxed.\nA: Different from Berlin.\nB: Berlin is cool, the Rhineland is warm.",funFact:"The Rhineland attitude is locker. Berlin is cool. Both are informal, but locker is warm where Berlin coolness is reserved."},
{type:"teach",trg:"prima",src:"great, excellent",pos:"adj",gender:null,note:"From Latin 'prima' (first/best). Colloquial and positive.\n'Prima!' on its own means 'Great!'",example:"A: Wie findest du den Karneval?\nB: Prima! Einfach prima!\nA: Ich bin froh, dass es dir gef\u00e4llt.\nB: Gef\u00e4llt? Ich bin begeistert!",exampleSrc:"A: How do you like the carnival?\nB: Great! Simply great!\nA: I'm glad you like it.\nB: Like it? I'm thrilled!",funFact:"From Latin 'prima' (first/best). No declension, no complications. One of the easiest German adjectives to use."},
{type:"teach",trg:"klasse",src:"great, awesome",pos:"adj",gender:null,note:"Used as an indeclinable adjective.\n'Das Kost\u00fcm ist klasse!' Very colloquial.",example:"A: Das Kost\u00fcm ist klasse!\nB: Findest du? Nur zusammengeklebt.\nA: Gerade deshalb ist es klasse.\nB: Kreativit\u00e4t schl\u00e4gt Geld.",exampleSrc:"A: The costume is awesome!\nB: You think? Just glued together.\nA: That's exactly why it's awesome.\nB: Creativity beats money.",funFact:"From 'Klasse' (class) used informally. Like English 'classy' shortened to express pure quality. Indeclinable, no endings needed."},
{type:"teach",trg:"h\u00fcbsch",src:"pretty, attractive",pos:"adj",gender:null,note:"From Middle High German 'h\u00fcbesch' (courtly).\nGentler than 'sch\u00f6n,' implies charm rather than grandeur.",example:"A: Das ist ein h\u00fcbsches Kost\u00fcm!\nB: Danke! Nicht sch\u00f6n, aber h\u00fcbsch.\nA: Was ist der Unterschied?\nB: H\u00fcbsch ist charmant, sch\u00f6n ist gro\u00df.",exampleSrc:"A: That's a pretty costume!\nB: Thanks! Not beautiful, but pretty.\nA: What's the difference?\nB: Pretty is charming, beautiful is grand.",funFact:"From Middle High German 'h\u00fcbesch' (courtly). H\u00fcbsch implies charm rather than grandeur. Gentler and more personal than 'sch\u00f6n.'"},
{type:"teach",trg:"intensiv",src:"intensive, intense",pos:"adj",gender:null,note:"Same as English, from Latin 'intensivus.'\nStress on the last syllable: in-ten-SIV.",example:"A: Das war ein intensiver Tag!\nB: Ja, alle Sinne auf einmal.\nA: Die Farben, der L\u00e4rm, die Emotionen.\nB: Karneval ist ein intensives Erlebnis.",exampleSrc:"A: That was an intense day!\nB: Yes, all senses at once.\nA: The colors, the noise, the emotions.\nB: Carnival is an intense experience.",funFact:"Karneval is intensiv: the colors, the noise, the emotions. 'Ein intensives Erlebnis' (an intense experience)."},
{type:"teach",trg:"umarmen",src:"to hug",pos:"verb",gender:null,note:"Um- (around) + Arme (arms). Literally 'to put arms around.'\nDuring Karneval, strangers umarmen each other.",example:"A: Der Fremde hat mich umarmt!\nB: Das ist normal beim Karneval.\nA: In Berlin w\u00fcrde niemand das tun.\nB: Beim Karneval umarmt man alle.",exampleSrc:"A: The stranger hugged me!\nB: That's normal at carnival.\nA: In Berlin nobody would do that.\nB: At carnival you hug everyone.",funFact:"During Karneval, strangers umarmen each other freely. Try it on a normal Tuesday in Germany and watch the horror."},
{type:"teach",trg:"schminken",src:"to apply makeup, to paint (face)",pos:"verb",gender:null,note:"Reflexive: sich schminken (to put makeup on yourself).\nAt Karneval, schminken is an art form.",example:"A: Hast du dich geschminkt?\nB: Ja, ich bin eine Katze!\nA: Die Schminke sieht toll aus.\nB: Danke, ich habe eine Stunde gebraucht.",exampleSrc:"A: Did you do your face paint?\nB: Yes, I'm a cat!\nA: The makeup looks great.\nB: Thanks, it took me an hour.",funFact:"At Karneval, schminken is an art form. Entire faces become cats, clowns, or abstract art. Even grown men schminken themselves without embarrassment."},
{type:"teach",trg:"dekorieren",src:"to decorate",pos:"verb",gender:null,note:"From French 'd\u00e9corer.' Streets and pubs are dekoriert for weeks.\nThe decoration budget in Cologne runs into millions.",example:"A: Wer hat die Stra\u00dfe dekoriert?\nB: Die Anwohner! Jedes Haus ist geschm\u00fcckt.\nA: Wochenlang dekorieren sie alles.\nB: Karneval ist Gemeinschaftsarbeit.",exampleSrc:"A: Who decorated the street?\nB: The residents! Every house is decorated.\nA: They decorate everything for weeks.\nB: Carnival is a community effort.",funFact:"Streets, buildings, and pubs are dekoriert for weeks before Karneval. The decoration budget in Cologne alone runs into millions of euros."},
{type:"teach",trg:"k\u00fcssen",src:"to kiss",pos:"verb",gender:null,note:"A 'B\u00fctzchen' (little kiss on the cheek) between strangers is acceptable at Karneval.\nOn any other day it would be completely inappropriate.",example:"A: Hat sie mich gerade gek\u00fcsst?\nB: Ja, das war ein B\u00fctzchen. Normal beim Karneval.\nA: Einfach so? Einen Fremden?\nB: Willkommen im Rheinland!",exampleSrc:"A: Did she just kiss me?\nB: Yes, that was a B\u00fctzchen. Normal at carnival.\nA: Just like that? A stranger?\nB: Welcome to the Rhineland!",funFact:"The 'B\u00fctzchen' (Rhineland dialect for a little kiss on the cheek) between strangers is acceptable during Karneval. On any other day it would be assault."},
{type:"teach",trg:"der Kuss",src:"the kiss",pos:"noun",gender:"m",note:"Masculine noun. Plural: K\u00fcsse (with Umlaut).\nThe 'B\u00fctzchen' is the gentlest carnival tradition.",example:"A: Was ist ein B\u00fctzchen?\nB: Ein kleiner Kuss auf die Wange.\nA: Im Rheinland ist das normal?\nB: Nur beim Karneval. Sonst nicht.",exampleSrc:"A: What is a B\u00fctzchen?\nB: A little kiss on the cheek.\nA: In the Rhineland that's normal?\nB: Only at carnival. Otherwise not.",funFact:"The noun from k\u00fcssen. Plural: K\u00fcsse (with Umlaut). The B\u00fctzchen (Rhineland dialect for Kuss) is the gentlest carnival tradition."},
{type:"teach",trg:"um",src:"in order to (with zu + infinitive)",pos:"part",gender:null,note:"As particle in um...zu constructions: expresses purpose.\n'Ich lerne, um Deutsch zu sprechen.'",example:"A: Warum lernst du Deutsch?\nB: Um in Deutschland zu arbeiten.\nA: Und warum fährst du nach Köln?\nB: Um Karneval zu feiern!",exampleSrc:"A: Why are you learning German?\nB: In order to work in Germany.\nA: And why are you going to Cologne?\nB: In order to celebrate carnival!",funFact:"Um has many faces: as a preposition it means around (um die Ecke). In um...zu constructions it means in order to. Combined with zu + infinitive, it creates German purpose clauses."},
{type:"tip",title:"um...zu: Expressing Purpose",text:"When you want to say WHY someone does something, use um...zu + infinitive.\n\nStructure: main clause, um + ... + zu + infinitive.\n\n'Man verkleidet sich, um eine andere Person zu sein.'\n(One dresses up in order to be a different person.)\n\n'Wir fahren nach Köln, um Karneval zu feiern.'\n(We travel to Cologne in order to celebrate carnival.)\n\nImportant rule: The subject in both parts must be the same.\n'Ich lerne, um Deutsch zu sprechen.' (I learn in order to speak German.)\nThink of 'um' as 'in order' and 'zu' as 'to.'",deepDive:{title:"um...zu with Separable Verbs",text:"With separable verbs, 'zu' goes between prefix and verb:\n\nanziehen: um anzuziehen (in order to put on)\naussehen: um auszusehen (in order to look)\nmitmachen: um mitzumachen (in order to join in)\n\n'Er verkleidet sich, um gut auszusehen.'\n(He dresses up in order to look good.)\n\nThe 'zu' slides into the middle of the verb."}},
{type:"mc",q:"Mia sagt: 'Man verkleidet sich, um eine andere Person zu sein.' Was bedeutet 'um...zu sein'?",opts:["statt ... zu sein (instead of being)","weil ... sein (because of being)","ohne ... zu sein (without being)","um ... zu sein (in order to be)"],ans:"um ... zu sein (in order to be)",hint:"The um...zu construction expresses purpose: doing X in order to achieve Y."},
{type:"fb",s:"Wir fahren nach K\u00f6ln, {1} Karneval zu feiern.",a:["um"],opts:["um","ohne","statt","damit"],hint:"Which word introduces a purpose clause meaning 'in order to'?",sSrc:"We travel to Cologne in order to celebrate carnival."},
{type:"mc",q:"Verumius tr\u00e4gt eine Toga. Welche Rolle spielt er?",opts:["Einen Piraten","Eine M\u00e4rchenfigur","Einen Helden","Einen r\u00f6mischen Senator"],ans:"Einen r\u00f6mischen Senator",hint:"Think about what Verumius actually IS. His costume is biographical."}
]},

// ─── Lesson 4: Warum? Wozu? Stattdessen! ─────────────────────
{id:"deu_r17l4",title:"Warum? Wozu? Stattdessen!",icon:"\uD83D\uDCA1",xp:15,board:true,steps:[
{type:"intro",title:"Warum? Wozu? Stattdessen!",desc:"Vier Konstruktionen mit Infinitivs\u00e4tzen: um...zu, ohne...zu, (an)statt...zu und damit. Lerne, wann du welche brauchst, und \u00fcbe sie mit Sport- und Karnevalsvokabeln.",goals:["Beherrsche alle vier Infinitivklausel-Konstruktionen","Verstehe den Unterschied zwischen um...zu und damit","Lerne Sport- und Spielvokabeln"]},
{type:"teach",trg:"der Spieler",src:"the player (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'spielen' (to play) + '-er.'\n'Spieler' without context usually means football player.",example:"A: Der Spieler hat ein Tor geschossen!\nB: Welcher Spieler?\nA: Die Nummer 9. Ein toller Spieler.\nB: Fu\u00dfballspieler sind in Deutschland Helden.",exampleSrc:"A: The player scored a goal!\nB: Which player?\nA: Number 9. A great player.\nB: Football players are heroes in Germany.",funFact:"Whether football, cards, or carnival games, a Spieler is anyone who plays. 'Spieler' without context usually means football player in Germany."},
{type:"teach",trg:"die Spielerin",src:"the player (female)",pos:"noun",gender:"f",note:"Feminine noun. Spieler + '-in.'\nThe German women's football team has won two World Cups.",example:"A: Die Spielerin ist sehr schnell.\nB: Ja, sie ist die beste Spielerin im Team.\nA: Seit wann spielt sie?\nB: Seit sie f\u00fcnf Jahre alt war.",exampleSrc:"A: The player is very fast.\nB: Yes, she's the best player on the team.\nA: How long has she been playing?\nB: Since she was five years old.",funFact:"The German women's national football team has won two World Cups. Spielerinnen are national heroes."},
{type:"teach",trg:"der Sportler",src:"the athlete (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'Sport' + '-ler.'\nGermany has won over 1,800 Olympic medals.",example:"A: Er ist ein guter Sportler.\nB: Ja, er l\u00e4uft jeden Tag zehn Kilometer.\nA: Ein echter Sportler.\nB: Sport ist sein Leben.",exampleSrc:"A: He's a good athlete.\nB: Yes, he runs ten kilometers every day.\nA: A true athlete.\nB: Sports is his life.",funFact:"Germany has won over 1,800 Olympic medals. Sportler are respected in every German community."},
{type:"teach",trg:"die Sportlerin",src:"the athlete (female)",pos:"noun",gender:"f",note:"Feminine noun. Sportler + '-in.'\nThe -ler/-lerin pattern is reliable as clockwork.",example:"A: Sie ist eine ber\u00fchmte Sportlerin.\nB: In welcher Sportart?\nA: Leichtathletik. Sie l\u00e4uft die 100 Meter.\nB: Eine fantastische Sportlerin!",exampleSrc:"A: She is a famous athlete.\nB: In which sport?\nA: Track and field. She runs the 100 meters.\nB: A fantastic athlete!",funFact:"The -ler/-lerin pattern works like clockwork. Sportler/Sportlerin, K\u00fcnstler/K\u00fcnstlerin. You can predict every profession pair."},
{type:"teach",trg:"die Sportart",src:"the type of sport",pos:"noun",gender:"f",note:"Feminine noun. Sport + Art (type/kind).\n'Welche Sportart machst du?'",example:"A: Welche Sportart magst du?\nB: Fu\u00dfball ist meine liebste Sportart.\nA: In Deutschland die popul\u00e4rste Sportart?\nB: Ja, Fu\u00dfball ist Nummer eins.",exampleSrc:"A: Which sport do you like?\nB: Football is my favorite sport.\nA: The most popular sport in Germany?\nB: Yes, football is number one.",funFact:"Sport + Art (type/kind). The compound is transparent: Art tells you it is a category. 'Welche Sportart machst du?' is the standard question."},
{type:"teach",trg:"der Trainer",src:"the coach (male)",pos:"noun",gender:"m",note:"Masculine noun. From English 'trainer.'\nIn Germany, Trainer means coach, not shoes. Pronounced 'TRAY-ner.'",example:"A: Wer ist der Trainer?\nB: Der Mann mit dem Trainingsanzug.\nA: Er sieht streng aus.\nB: Gute Trainer sind immer ein bisschen streng.",exampleSrc:"A: Who is the coach?\nB: The man in the tracksuit.\nA: He looks strict.\nB: Good coaches are always a bit strict.",funFact:"In Germany, Trainer usually means coach, not shoes. A Fu\u00dfballtrainer coaches the team. Pronounced 'TRAY-ner,' not like English."},
{type:"teach",trg:"die Trainerin",src:"the coach (female)",pos:"noun",gender:"f",note:"Feminine noun. Trainer + '-in.'\nMore and more women coach professional teams in Germany.",example:"A: Die Trainerin ist sehr gut.\nB: Ja, unter ihrer Leitung gewinnt das Team.\nA: Seit wann ist sie Trainerin?\nB: Seit f\u00fcnf Jahren. Vorher war sie Spielerin.",exampleSrc:"A: The coach is very good.\nB: Yes, under her leadership the team wins.\nA: How long has she been a coach?\nB: For five years. Before that she was a player.",funFact:"More and more women coach professional teams in Germany. The language, as always, had the word ready."},
{type:"teach",trg:"der Spielplatz",src:"the playground",pos:"noun",gender:"m",note:"Masculine noun. Spiel (play) + Platz (place).\nGerman playgrounds are more adventurous than American ones.",example:"A: Gibt es hier einen Spielplatz?\nB: Ja, gleich um die Ecke.\nA: Der Spielplatz sieht toll aus!\nB: Deutsche Spielpl\u00e4tze sind abenteuerlich.",exampleSrc:"A: Is there a playground here?\nB: Yes, just around the corner.\nA: The playground looks great!\nB: German playgrounds are adventurous.",funFact:"German playgrounds are famous for being more adventurous: higher climbing structures, fewer safety nets. Germans believe children learn by taking risks."},
{type:"teach",trg:"das Spielzeug",src:"the toy, the toys",pos:"noun",gender:"n",note:"Neuter noun. Spiel (play) + Zeug (stuff/thing).\nSame pattern as Flugzeug (airplane), Werkzeug (tool).",example:"A: Was f\u00fcr Spielzeug haben deutsche Kinder?\nB: Lego, Playmobil, Holzspielzeug.\nA: Playmobil ist deutsch?\nB: Ja! Aus F\u00fcrth in Bayern.",exampleSrc:"A: What kind of toys do German children have?\nB: Lego, Playmobil, wooden toys.\nA: Playmobil is German?\nB: Yes! From F\u00fcrth in Bavaria.",funFact:"Same pattern as Flugzeug (flight-thing = airplane), Werkzeug (work-thing = tool). German loves describing things by function + Zeug."},
{type:"teach",trg:"das Stadion",src:"the stadium",pos:"noun",gender:"n",note:"Neuter noun. From Greek 'stadion.'\nGerman Stadien (plural) are some of the best-attended in the world.",example:"A: Das Stadion ist riesig!\nB: \u00dcber 80.000 Pl\u00e4tze.\nA: Deutsche Stadien sind immer voll.\nB: Fu\u00dfball ist hier Religion.",exampleSrc:"A: The stadium is enormous!\nB: Over 80,000 seats.\nA: German stadiums are always full.\nB: Football is religion here.",funFact:"Germany hosted the 2006 World Cup. German Stadien (plural) are some of the best-attended in the world."},
{type:"teach",trg:"das Golf",src:"golf (the sport)",pos:"noun",gender:"n",note:"Neuter noun for the sport. Der Golf is the Volkswagen car.\nSame spelling, different gender, completely different meaning.",example:"A: Spielst du Golf?\nB: Ja, aber nicht so oft.\nA: Golf oder Volkswagen Golf?\nB: Den Sport! Den VW Golf fahre ich auch.",exampleSrc:"A: Do you play golf?\nB: Yes, but not so often.\nA: Golf or Volkswagen Golf?\nB: The sport! I also drive the VW Golf.",funFact:"Das Golf is the sport. Der Golf is the Volkswagen car. Same spelling, different gender, completely different meaning."},
{type:"teach",trg:"der Ski",src:"the ski",pos:"noun",gender:"m",note:"Masculine noun. From Norwegian 'ski.'\nPronounced 'shee' in German. 'Ski fahren' = to ski.",example:"A: F\u00e4hrst du Ski?\nB: Ja, jeden Winter in den Alpen.\nA: Ski fahren ist toll!\nB: Die besten Pisten sind in \u00d6sterreich.",exampleSrc:"A: Do you ski?\nB: Yes, every winter in the Alps.\nA: Skiing is great!\nB: The best slopes are in Austria.",funFact:"Pronounced 'shee' in German, from Norwegian. The Alps make Germany, Austria, and Switzerland a Ski paradise. 'Ski fahren' uses 'fahren' (to drive/travel)."},
{type:"teach",trg:"die Gymnastik",src:"gymnastics",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'gymnastike.'\nFriedrich Ludwig Jahn invented the parallel bars, rings, and horse.",example:"A: Machst du Gymnastik?\nB: Ja, jeden Morgen.\nA: Gymnastik h\u00e4lt fit.\nB: Die Deutschen lieben Turnvereine.",exampleSrc:"A: Do you do gymnastics?\nB: Yes, every morning.\nA: Gymnastics keeps you fit.\nB: Germans love gymnastics clubs.",funFact:"Friedrich Ludwig Jahn, the 'father of gymnastics,' was German. He invented the parallel bars, rings, and horse. Turnvereine exist in every German town."},
{type:"teach",trg:"der Start",src:"the start",pos:"noun",gender:"m",note:"Masculine noun. Same as English.\n'Am Start' (at the start). Used for races, competitions, beginnings.",example:"A: Bist du bereit f\u00fcr den Start?\nB: Ja, ich stehe am Start.\nA: Auf die Pl\u00e4tze, fertig, los!\nB: Der Start war perfekt!",exampleSrc:"A: Are you ready for the start?\nB: Yes, I'm at the start.\nA: On your marks, get set, go!\nB: The start was perfect!",funFact:"Same as English. 'Startschuss' (starting shot) signals the beginning. Borrowed into German and used for races, competitions, and beginnings."},
{type:"teach",trg:"der Rekord",src:"the record (competitive)",pos:"noun",gender:"m",note:"Masculine noun. From English 'record.'\nNote: Rekord only means a competitive record, NOT a music record.",example:"A: Das ist ein neuer Rekord!\nB: Wirklich? Wie schnell?\nA: Unter zehn Sekunden!\nB: Einen Rekord zu brechen ist ein tolles Gef\u00fchl.",exampleSrc:"A: That's a new record!\nB: Really? How fast?\nA: Under ten seconds!\nB: Breaking a record is a great feeling.",funFact:"From English 'record.' Rekord only means a competitive record, NOT a music record (that is 'Platte' or 'Schallplatte')."},
{type:"teach",trg:"der Sieg",src:"the victory",pos:"noun",gender:"m",note:"Masculine noun. From Old High German 'sigu.'\n'Siegfried' (victory-peace) is one of Germany's most famous names.",example:"A: Was f\u00fcr ein Sieg!\nB: Ja, das Team hat gewonnen!\nA: Ein verdienter Sieg.\nB: Die Freude \u00fcber den Sieg ist riesig.",exampleSrc:"A: What a victory!\nB: Yes, the team won!\nA: A well-deserved victory.\nB: The joy about the victory is enormous.",funFact:"'Siegfried' (victory-peace) is one of Germany's most famous names. The Siegess\u00e4ule (Victory Column) stands in the heart of Berlin."},
{type:"teach",trg:"der Sieger",src:"the winner, the victor",pos:"noun",gender:"m",note:"Masculine noun. Sieg + '-er.'\n'Und der Sieger ist...' (And the winner is...).",example:"A: Und der Sieger ist...\nB: Wer? Wer hat gewonnen?\nA: Das Team in Rot!\nB: Ein verdienter Sieger!",exampleSrc:"A: And the winner is...\nB: Who? Who won?\nA: The team in red!\nB: A deserved winner!",funFact:"'Und der Sieger ist...' (And the winner is...). Every Karneval float competition has a Sieger. Every competition needs one."},
{type:"teach",trg:"die Siegerin",src:"the winner (female)",pos:"noun",gender:"f",note:"Feminine noun. Sieger + '-in.'\nBy now you can predict every profession pair in German.",example:"A: Die Siegerin bekommt den Pokal.\nB: Sie hat es verdient!\nA: Die beste Sportlerin des Turniers.\nB: Eine w\u00fcrdige Siegerin.",exampleSrc:"A: The winner receives the trophy.\nB: She deserved it!\nA: The best athlete of the tournament.\nB: A worthy winner.",funFact:"By now you can predict every profession pair in German. Sieger/Siegerin follows the same pattern as all the others."},
{type:"teach",trg:"siegen",src:"to win, to be victorious",pos:"verb",gender:null,note:"Regular verb. From Sieg.\n'Wer siegt, feiert' (Whoever wins, celebrates).",example:"A: Wer wird siegen?\nB: Ich hoffe, unsere Mannschaft.\nA: Siegen ist nicht alles.\nB: Aber es hilft!",exampleSrc:"A: Who will win?\nB: I hope our team.\nA: Winning isn't everything.\nB: But it helps!",funFact:"Related to 'besiegen' (to defeat) with the be- prefix adding a direct object. 'Wer siegt, feiert.'"},
{type:"teach",trg:"starten",src:"to start, to launch",pos:"verb",gender:null,note:"Regular verb. From English 'start.'\nSame word, same meaning, fully adopted into German grammar.",example:"A: Wann startet das Rennen?\nB: In f\u00fcnf Minuten.\nA: Alle Sportler starten gleichzeitig.\nB: M\u00f6ge der Beste siegen!",exampleSrc:"A: When does the race start?\nB: In five minutes.\nA: All athletes start at the same time.\nB: May the best one win!",funFact:"Same word, same meaning, fully adopted into German grammar. 'Das Rennen startet um 10 Uhr.'"},
{type:"tip",title:"Vier Infinitivkonstruktionen",text:"1. um...zu = in order to (Zweck, gleiches Subjekt):\n'Ich trainiere, um zu siegen.' (I train in order to win.)\n\n2. ohne...zu = without doing (gleiches Subjekt):\n'Er feiert, ohne m\u00fcde zu werden.' (He celebrates without getting tired.)\n\n3. (an)statt...zu = instead of doing (gleiches Subjekt):\n'Statt zu arbeiten, feiert sie Karneval.' (Instead of working, she celebrates carnival.)\n\n4. damit = so that (VERSCHIEDENE Subjekte):\n'Ich winke, damit die Leute Bonbons werfen.' (I wave so that the people throw candy.)\n\nWichtige Regel: Wenn beide Teile das gleiche Subjekt haben, benutze um...zu. Wenn die Subjekte verschieden sind, MUSS damit + konjugiertes Verb stehen.",deepDive:{title:"Wortstellung in Infinitivs\u00e4tzen",text:"In allen Infinitivs\u00e4tzen steht zu + Infinitiv am Ende:\n\num ... zu feiern\nohne ... zu warten\nstatt ... zu arbeiten\n\nBei trennbaren Verben rutscht zu in die Mitte:\num anzufangen (not: um zu anfangen)\nohne aufzuh\u00f6ren (not: ohne zu aufh\u00f6ren)\nstatt mitzumachen (not: statt zu mitmachen)\n\nDamit-S\u00e4tze haben ein konjugiertes Verb am ENDE:\nIch singe, damit alle mitsingen.\n(Verb 'mitsingen' ist konjugiert: 'mitsingen')"}},
{type:"verb_table",title:"Infinitivklauseln im Vergleich",note:"Same subject = um/ohne/statt + zu + Infinitiv. Different subjects = damit + conjugated verb.",groups:[{label:"Gleiches Subjekt (Infinitivsatz)",rows:[{pronoun:"um...zu",form:"Ich lerne, um Deutsch zu sprechen.",src:"I learn in order to speak German."},{pronoun:"ohne...zu",form:"Er tanzt, ohne m\u00fcde zu werden.",src:"He dances without getting tired."},{pronoun:"(an)statt...zu",form:"Statt zu lernen, feiert sie.",src:"Instead of studying, she celebrates."}]},{label:"Verschiedene Subjekte (damit-Satz)",rows:[{pronoun:"damit",form:"Ich winke, damit du mich siehst.",src:"I wave so that you see me."}]}]},
{type:"tip",title:"Verbs with zu + Infinitive",text:"Some verbs only need zu + infinitive (without um/ohne/statt):\n\nversuchen zu: Ich versuche, Deutsch zu sprechen.\nanfangen zu: Er fängt an, Deutsch zu lernen.\naufhören zu: Sie hört auf zu rauchen.\nvergessen zu: Ich habe vergessen, dich anzurufen.\nbeginnen zu: Es beginnt zu regnen.\nplanen zu: Wir planen, nach Köln zu fahren.\nhoffen zu: Ich hoffe, dich bald zu sehen.\n\nPattern: conjugated verb + (comma) + zu + infinitive.\n\nSpecial: brauchen nur/nicht zu (replaces müssen in negations):\n'Du brauchst nicht zu kommen.' = 'Du musst nicht kommen.'",deepDive:{title:"Separable and Inseparable Verbs with zu",text:"Separable verbs: zu goes BETWEEN prefix and verb.\naufstehen: aufzustehen (not: zu aufstehen)\neinkaufen: einzukaufen\nmitmachen: mitzumachen\nkennenlernen: kennenzulernen\nfernsehen: fernzusehen\n\nInseparable verbs: zu goes BEFORE the whole verb.\nverstehen: zu verstehen\nbesuchen: zu besuchen\nentdecken: zu entdecken\n\nSeparable prefixes: auf, an, ein, mit, aus, ab, zu, vor\nInseparable prefixes: be-, ge-, er-, ver-, zer-, ent-, emp-, miss-"}},
{type:"mc",q:"Ich kaufe Bonbons, ___ die Kinder sich freuen.",opts:["um...zu","ohne...zu","statt...zu","damit"],ans:"damit",hint:"The subject changes: I buy, the CHILDREN are happy. Different subjects need damit."},
{type:"mc",q:"'Er feiert die ganze Nacht, ohne m\u00fcde zu werden.' Was bedeutet 'ohne...zu'?",opts:["without doing","instead of","in order to","so that"],ans:"without doing",hint:"Ohne means without. The ...zu adds an infinitive action that does NOT happen."},
{type:"fb",s:"Mia tanzt, {1} aufzuh\u00f6ren.",a:["ohne"],opts:["ohne","um","statt","damit"],hint:"Mia dances and does NOT stop. Which word means 'without'?",sSrc:"Mia dances without stopping."},
{type:"mc",q:"'Statt zu arbeiten, gehen wir zum Karneval.' Was machen wir?",opts:["Wir arbeiten beim Karneval","Wir gehen zum Karneval statt zu arbeiten","Wir gehen ohne zu arbeiten","Wir arbeiten und gehen dann zum Karneval"],ans:"Wir gehen zum Karneval statt zu arbeiten",hint:"Statt introduces an alternative: what you do INSTEAD of the other thing."},
{type:"fb",s:"Verumius zieht eine Toga an, {1} ein Senator zu sein.",a:["um"],opts:["um","ohne","statt","damit"],hint:"He puts on the toga for a PURPOSE: to be a senator.",sSrc:"Verumius puts on a toga in order to be a senator."},
{type:"drag_fill",s:"{1} nur zuzuschauen, tanzt Verumius mit, {2} Spa\u00df zu haben.",blanks:{"1":"Statt","2":"um"},pool:["Statt","um","ohne","damit","weil"],hint:"First: he does not just watch (alternative). Second: the purpose is to have fun.",sSrc:"Instead of just watching, Verumius dances along in order to have fun."},
{type:"mc",q:"'Ich singe, ___ alle mitmachen.' Welches Wort fehlt?",opts:["ohne","damit","statt","um"],ans:"damit",hint:"I sing, but the subject of mitmachen is 'alle' (everyone else). Different subjects need damit."}
]},

// ─── Lesson 5: Kneipentour durch die Altstadt ─────────────────
{id:"deu_r17l5",title:"Kneipentour durch die Altstadt",icon:"\uD83C\uDF7A",xp:15,board:true,steps:[
{type:"intro",title:"Kneipentour durch die Altstadt",desc:"Mia leads Verumius through the Cologne old town. Every pub has a different program. Learn media and entertainment vocabulary and practice all four infinitive constructions.",goals:["Learn words for media, journalism, and entertainment","Practice all four infinitive constructions in conversation","Experience the Cologne pub tour with Mia"]},
{type:"story",speaker:"narrator",mood:"warm",art:"koeln-altstadt-nacht",trg:"Die Altstadt gl\u00fcht. Jede Kneipe ist voll. Musik quillt durch offene T\u00fcren. Kostumierte Menschen flie\u00dfen zwischen den Kneipen wie ein Strom aus Farbe. Mia f\u00fchrt Verumius durch die Menge mit der Sicherheit von jemandem, der das schon hundert Mal gemacht hat.",src:"The Old Town glows. Every pub is full. Music spills through open doors. Costumed people flow between pubs like a river of color. Mia leads Verumius through the crowd with the confidence of someone who has done this a hundred times."},
{type:"story",speaker:"mia",mood:"informative",trg:"Jede Kneipe hat ein anderes Programm. Man geht von Kneipe zu Kneipe, um alles mitzuerleben. Das nennt man eine Kneipentour.",src:"Every pub has a different program. You go from pub to pub in order to experience everything. That's called a Kneipentour."},
{type:"story",speaker:"verumius",mood:"curious",trg:"Und die Leute tragen Kost\u00fcme, um andere Menschen zu treffen? Ohne sich zu kennen?",src:"And people wear costumes in order to meet other people? Without knowing each other?"},
{type:"story",speaker:"mia",mood:"explaining",trg:"Genau. Statt sich vorzustellen, sagt man einfach 'Alaaf!' und tanzt zusammen. Damit jeder Spa\u00df hat.",src:"Exactly. Instead of introducing yourself, you just say 'Alaaf!' and dance together. So that everyone has fun."},
{type:"teach",trg:"die Runde",src:"the round",pos:"noun",gender:"f",note:"Feminine noun. From 'rund' (round).\n'Eine Runde ausgeben' means to buy a round of drinks.",example:"A: Ich gebe eine Runde aus!\nB: F\u00fcr alle? Das ist gro\u00dfz\u00fcgig!\nA: Beim Karneval gibt man gerne Runden aus.\nB: Prost! K\u00f6lle Alaaf!",exampleSrc:"A: I'm buying a round!\nB: For everyone? That's generous!\nA: At carnival people gladly buy rounds.\nB: Cheers! K\u00f6lle Alaaf!",funFact:"'Eine Runde ausgeben' means to buy a round of drinks. At Karneval, rounds flow freely. A Runde through the Altstadt means visiting a circle of pubs."},
{type:"teach",trg:"die Unterhaltung",src:"the entertainment, the conversation",pos:"noun",gender:"f",note:"Feminine noun. Unter- (under/between) + Haltung (holding).\nCovers both entertainment and conversation. Context decides.",example:"A: Die Unterhaltung heute Abend war toll.\nB: Meinst du die Musik oder das Gespr\u00e4ch?\nA: Beides! Die ganze Unterhaltung.\nB: Karneval ist die beste Unterhaltung.",exampleSrc:"A: The entertainment tonight was great.\nB: Do you mean the music or the conversation?\nA: Both! The whole entertainment.\nB: Carnival is the best entertainment.",funFact:"Literally 'holding between' people. Covers both entertainment and conversation. Context decides which meaning applies."},
{type:"teach",trg:"das Vergn\u00fcgen",src:"the pleasure, the fun",pos:"noun",gender:"n",note:"Neuter noun. 'Es war mir ein Vergn\u00fcgen' (It was a pleasure).\n'Vergn\u00fcgungspark' = amusement park.",example:"A: Es war mir ein Vergn\u00fcgen!\nB: Mir auch! Was f\u00fcr ein Abend.\nA: Karneval ist ein reines Vergn\u00fcgen.\nB: Vergn\u00fcgen pur!",exampleSrc:"A: It was a pleasure!\nB: For me too! What an evening.\nA: Carnival is pure pleasure.\nB: Pure fun!",funFact:"'Es war mir ein Vergn\u00fcgen' (It was a pleasure). 'Vergn\u00fcgungspark' (amusement park) comes from the same root."},
{type:"teach",trg:"die Neuigkeit",src:"the news, the novelty",pos:"noun",gender:"f",note:"Feminine noun. Neu (new) + '-igkeit' (noun suffix).\nAlways feminine because of the -keit/-igkeit ending.",example:"A: Hast du Neuigkeiten?\nB: Ja! Morgen ist der Rosenmontagszug!\nA: Das ist keine Neuigkeit, das wissen alle!\nB: Aber es f\u00fchlt sich jedes Mal neu an.",exampleSrc:"A: Do you have any news?\nB: Yes! Tomorrow is the Rose Monday parade!\nA: That's not news, everyone knows that!\nB: But it feels new every time.",funFact:"'Hast du Neuigkeiten?' (Do you have news?). Always feminine because of the -keit/-igkeit ending. Always."},
{type:"teach",trg:"die Diskothek",src:"the disco, the nightclub",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'diskos' + 'theke.'\nUsually shortened to 'Disko.'",example:"A: Gehen wir in die Diskothek?\nB: Klar! Welche Disko ist gut?\nA: Die mit der Karnevalsparty.\nB: In der Karnevalswoche hat jede Disko eine Party.",exampleSrc:"A: Shall we go to the disco?\nB: Sure! Which disco is good?\nA: The one with the carnival party.\nB: During carnival week every disco has a party.",funFact:"Usually shortened to 'Disko.' During Karneval, every Disko runs themed carnival parties. The word sounds retro, but the parties are modern."},
{type:"teach",trg:"die Galerie",src:"the gallery",pos:"noun",gender:"f",note:"Feminine noun. From Italian 'galleria.'\nCologne has over 30 Galerien in the city center.",example:"A: Gibt es hier eine Galerie?\nB: Ja, sogar die Galerien machen beim Karneval mit.\nA: Kunst und Karneval passen zusammen?\nB: In K\u00f6ln passt alles zusammen.",exampleSrc:"A: Is there a gallery here?\nB: Yes, even the galleries participate in carnival.\nA: Art and carnival go together?\nB: In Cologne everything goes together.",funFact:"Even art galleries participate in Karneval with themed exhibitions. Cologne has over 30 Galerien in the city center alone."},
{type:"teach",trg:"die Serie",src:"the series (TV)",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'series.'\nNetflix Germany produces Serien like 'Dark' and 'Babylon Berlin.'",example:"A: Schaust du eine gute Serie?\nB: Ja, eine deutsche Serie auf Netflix.\nA: Welche?\nB: 'Dark.' Die ist wahnsinnig gut.",exampleSrc:"A: Are you watching a good series?\nB: Yes, a German series on Netflix.\nA: Which one?\nB: 'Dark.' It's insanely good.",funFact:"Netflix Germany produces German-language Serien like 'Dark' and 'Babylon Berlin.' Germans binge-watch Serien just like everyone else."},
{type:"teach",trg:"die Reportage",src:"the report, the feature story",pos:"noun",gender:"f",note:"Feminine noun. From French 'reportage.'\nGerman TV sends Reportage teams to cover Karneval every year.",example:"A: Hast du die Reportage \u00fcber Karneval gesehen?\nB: Ja, im Fernsehen. Sehr gut gemacht.\nA: Die Reportage hat alles gezeigt.\nB: Von den Kost\u00fcmen bis zum Rosenmontagszug.",exampleSrc:"A: Did you see the report about carnival?\nB: Yes, on TV. Very well done.\nA: The report showed everything.\nB: From the costumes to the Rose Monday parade.",funFact:"German TV sends Reportage teams to cover Karneval every year. It is prime-time content across the country."},
{type:"teach",trg:"der Reporter",src:"the reporter (male)",pos:"noun",gender:"m",note:"Masculine noun. Same as English.\nDuring Karneval, Reporter interview costumed people in the crowd.",example:"A: Schau, ein Reporter!\nB: Er interviewt die Leute in Kost\u00fcmen.\nA: Reporter m\u00fcssen beim Karneval Bonbons ausweichen.\nB: Ein gef\u00e4hrlicher Job!",exampleSrc:"A: Look, a reporter!\nB: He's interviewing people in costumes.\nA: Reporters have to dodge candy at carnival.\nB: A dangerous job!",funFact:"During Karneval, Reporter stand in the crowd interviewing costumed people. The best interviews become viral clips. Reporter must dodge flying candy."},
{type:"teach",trg:"die Reporterin",src:"the reporter (female)",pos:"noun",gender:"f",note:"Feminine noun. Reporter + '-in.'\nThe pattern never fails.",example:"A: Die Reporterin ist live vor Ort.\nB: Sie berichtet direkt vom Rosenmontagszug.\nA: Ein toller Job!\nB: Reporterin beim Karneval, Traumberuf!",exampleSrc:"A: The reporter is live on the scene.\nB: She's reporting directly from the Rose Monday parade.\nA: A great job!\nB: Being a reporter at carnival, dream job!",funFact:"The -er/-erin pattern never fails. At this point you could build feminine forms in your sleep."},
{type:"teach",trg:"der Journalist",src:"the journalist (male)",pos:"noun",gender:"m",note:"Masculine noun. From French 'journaliste.'\nA broader term than Reporter.",example:"A: Bist du Journalist?\nB: Ja, ich schreibe f\u00fcr eine Zeitung.\nA: \u00dcber den Karneval?\nB: Ja, Karneval ist immer eine gute Geschichte.",exampleSrc:"A: Are you a journalist?\nB: Yes, I write for a newspaper.\nA: About the carnival?\nB: Yes, carnival is always a good story.",funFact:"A broader term than Reporter. Journalisten write, broadcast, and analyze. Karneval political satire gives Journalisten plenty of material."},
{type:"teach",trg:"die Journalistin",src:"the journalist (female)",pos:"noun",gender:"f",note:"Feminine noun. Journalist + '-in.'\nGermany has more women in journalism than most European countries.",example:"A: Die Journalistin schreibt einen Artikel.\nB: \u00dcber die Karnevalstradition.\nA: Sie kennt sich sehr gut aus.\nB: Eine erfahrene Journalistin.",exampleSrc:"A: The journalist is writing an article.\nB: About the carnival tradition.\nA: She knows a lot about it.\nB: An experienced journalist.",funFact:"Germany has more women in journalism than most European countries. The language keeps up with -in."},
{type:"teach",trg:"der Fotograf",src:"the photographer (male)",pos:"noun",gender:"m",note:"Masculine noun. From Greek 'photos' (light) + 'graphein' (to write).\nLiterally 'light writer.'",example:"A: Der Fotograf macht Bilder vom Umzug.\nB: Karneval ist ein Traum f\u00fcr Fotografen.\nA: Farbe, Bewegung, Emotion.\nB: Jedes Foto erz\u00e4hlt eine Geschichte.",exampleSrc:"A: The photographer takes pictures of the parade.\nB: Carnival is a dream for photographers.\nA: Color, movement, emotion.\nB: Every photo tells a story.",funFact:"From Greek: 'light writer.' Karneval is a Fotograf's dream: color, movement, emotion, chaos. Every shot tells a story."},
{type:"teach",trg:"die Fotografie",src:"the photography, the photograph",pos:"noun",gender:"f",note:"Feminine noun. The -ie ending is always feminine.\nCovers both the art and the individual image.",example:"A: Die Fotografie ist wundersch\u00f6n!\nB: Danke! Fotografie ist meine Leidenschaft.\nA: Machst du beruflich Fotografie?\nB: Ja, besonders bei Events wie Karneval.",exampleSrc:"A: The photograph is beautiful!\nB: Thanks! Photography is my passion.\nA: Do you do photography professionally?\nB: Yes, especially at events like carnival.",funFact:"The -ie ending is always feminine. Fotografie as an art form was partly developed with German optics that made modern photography possible."},
{type:"teach",trg:"original",src:"original",pos:"adj",gender:null,note:"Same as English. 'Ein originales Kost\u00fcm' (an original costume).\nThe most admired Karneval costumes are original and handmade.",example:"A: Ist das Kost\u00fcm original?\nB: Ja, komplett selbst gemacht!\nA: Originale Kost\u00fcme sind die besten.\nB: Gekauft ist okay, aber original ist besser.",exampleSrc:"A: Is the costume original?\nB: Yes, completely self-made!\nA: Original costumes are the best.\nB: Store-bought is okay, but original is better.",funFact:"The most admired Karneval costumes are original: handmade, unique, creative. Store-bought is acceptable but not celebrated."},
{type:"teach",trg:"realistisch",src:"realistic",pos:"adj",gender:null,note:"From 'real' + '-istisch.'\nSome Karneval costumes are museum-quality realistic.",example:"A: Das Kost\u00fcm ist unglaublich realistisch!\nB: Man k\u00f6nnte denken, er ist wirklich ein Ritter.\nA: Manche Kost\u00fcme sind Kunstwerke.\nB: Realistisch und trotzdem lustig.",exampleSrc:"A: The costume is incredibly realistic!\nB: You'd think he's really a knight.\nA: Some costumes are works of art.\nB: Realistic and still funny.",funFact:"Some Karneval costumes are museum-quality. Others are intentionally unrealistisch. Both approaches work."},
{type:"teach",trg:"interkulturell",src:"intercultural",pos:"adj",gender:null,note:"Inter- (between) + kulturell (cultural).\nKarneval in Cologne is interkulturell: many influences blend.",example:"A: Karneval in K\u00f6ln ist sehr interkulturell.\nB: Ja, Menschen aus aller Welt feiern zusammen.\nA: T\u00fcrkische, italienische, japanische Einfl\u00fcsse.\nB: Das macht den K\u00f6lner Karneval besonders.",exampleSrc:"A: Carnival in Cologne is very intercultural.\nB: Yes, people from all over the world celebrate together.\nA: Turkish, Italian, Japanese influences.\nB: That's what makes Cologne carnival special.",funFact:"Karneval in Cologne blends Turkish, Italian, Japanese, and Brazilian influences with Rhineland traditions. Truly interkulturell."},
{type:"teach",trg:"auftreten",src:"to appear, to perform",pos:"verb",gender:null,note:"Separable verb. Auf (on) + treten (to step).\n'Die Band tritt heute auf' (The band performs today).",example:"A: Wann tritt die Band auf?\nB: In einer Stunde.\nA: Sie treten auf der gro\u00dfen B\u00fchne auf.\nB: Ich freue mich auf den Auftritt!",exampleSrc:"A: When does the band perform?\nB: In one hour.\nA: They're performing on the main stage.\nB: I'm looking forward to the performance!",funFact:"At Karneval, everyone tritt auf, whether on stage or in the street. The separable prefix auf- means 'up/onto.'"},
{type:"teach",trg:"begegnen",src:"to encounter, to meet (by chance)",pos:"verb",gender:null,note:"Uses sein as auxiliary, not haben.\nBegegnen implies chance, not planning.",example:"A: Ich bin ihr zuf\u00e4llig begegnet.\nB: Beim Karneval begegnet man vielen Menschen.\nA: Jede Begegnung ist eine \u00dcberraschung.\nB: Das macht den Karneval so besonders.",exampleSrc:"A: I ran into her by chance.\nB: At carnival you encounter many people.\nA: Every encounter is a surprise.\nB: That's what makes carnival so special.",funFact:"Uses sein as auxiliary: 'Ich bin ihr begegnet.' Begegnen implies chance, not planning. Karneval is full of zuf\u00e4llige Begegnungen."},
{type:"teach",trg:"sorgen",src:"to take care of, to ensure",pos:"verb",gender:null,note:"'F\u00fcr Stimmung sorgen' (to ensure a good atmosphere).\n'Sich Sorgen machen' = to worry. Different meanings.",example:"A: Wer sorgt f\u00fcr die Musik?\nB: Die Band sorgt f\u00fcr Stimmung.\nA: Mach dir keine Sorgen!\nB: Beim Karneval sorgt man nur f\u00fcr Spa\u00df.",exampleSrc:"A: Who takes care of the music?\nB: The band ensures a good atmosphere.\nA: Don't worry!\nB: At carnival you only take care of fun.",funFact:"'F\u00fcr Stimmung sorgen' = to ensure a good atmosphere. 'Sich Sorgen machen' = to worry. With and without 'sich,' completely different meanings."},
{type:"mc",q:"Mia geht zur Kneipentour, ___ alle Bands zu sehen, ___ eine einzige zu verpassen.",opts:["um / ohne","ohne / um","damit / statt","statt / damit"],ans:"um / ohne",hint:"First: purpose (in order to see). Second: without missing. Same subject (Mia) both times."},
{type:"fb",s:"Man kann Karneval nicht erleben, {1} mitzumachen.",a:["ohne"],opts:["ohne","um","statt","damit"],hint:"You cannot experience carnival WITHOUT participating.",sSrc:"You cannot experience carnival without participating."},
{type:"drag_fill",s:"Verumius tanzt, {1} ein guter T\u00e4nzer zu sein, {2} Spa\u00df zu haben.",blanks:{"1":"ohne","2":"um"},pool:["ohne","um","statt","damit","weil"],hint:"First: he is not a good dancer (without being). Second: the purpose is fun.",sSrc:"Verumius dances without being a good dancer, in order to have fun."},
{type:"mc",q:"'Mia erkl\u00e4rt die Traditionen, damit Verumius alles versteht.' Warum damit und nicht um...zu?",opts:["Die Subjekte sind verschieden: Mia erkl\u00e4rt, Verumius versteht","Es gibt keinen Unterschied","Es klingt formeller","Damit ist immer besser"],ans:"Die Subjekte sind verschieden: Mia erkl\u00e4rt, Verumius versteht",hint:"Two different people doing two different things. That requires damit."},
{type:"mc",q:"Ein Fotograf macht Bilder. Eine Reporterin schreibt Artikel. Was haben beide gemeinsam?",opts:["Beide singen","Beide tanzen","Beide arbeiten im Journalismus","Beide tragen Kost\u00fcme"],ans:"Beide arbeiten im Journalismus",hint:"Both professions involve documenting and sharing events with the public."}
]},

// ─── Lesson 6: Rosenmontagszug! ──────────────────────────────
{id:"deu_r17l6",title:"Rosenmontagszug!",icon:"\uD83C\uDF8A",xp:15,board:true,steps:[
{type:"intro",title:"Rosenmontagszug!",desc:"Der H\u00f6hepunkt des Karnevals. Sieben Kilometer organisierter Wahnsinn. Riesige Wagen, fliegende Bonbons, \u00fcber eine Million Menschen. Verumius erlebt den gr\u00f6\u00dften Stra\u00dfenumzug Deutschlands.",goals:["Erlebe den Rosenmontagszug durch Verumius' Augen","Lerne Vokabeln f\u00fcr Zuschauer, Talente und extreme Emotionen","Meistere alle vier Infinitivkonstruktionen in Quiz-Kontexten"]},
{type:"story",speaker:"narrator",mood:"ecstatic",art:"koeln-rosenmontagszug",trg:"Der Rosenmontagszug. Sieben Kilometer organisierter Wahnsinn. Wagen so gro\u00df wie H\u00e4user gleiten die Stra\u00dfe entlang. Politische Satire ragt \u00fcber die Menge. Bonbons regnen vom Himmel. Verumius steht mit offenem Mund da, als ein Wagen in Form einer riesigen Brezel vorbeif\u00e4hrt.",src:"The Rose Monday parade. Seven kilometers of organized madness. Floats the size of buildings glide down the street. Political satire towers above the crowd. Candy rains from the sky. Verumius stands open-mouthed as a float shaped like a giant pretzel passes by."},
{type:"story",speaker:"verumius",mood:"excited",trg:"KAMELLE! KAMELLE!",src:"KAMELLE! KAMELLE! (The magic word to get candy thrown from the floats.)"},
{type:"story",speaker:"mia",mood:"singing",trg:"K\u00f6lle Alaaf! K\u00f6lle Alaaf!",src:"K\u00f6lle Alaaf! K\u00f6lle Alaaf! (Arms linked with strangers, swaying, singing.)"},
{type:"story",speaker:"narrator",mood:"warm",trg:"Ein Fremder im B\u00e4renkost\u00fcm umarmt Verumius. Verumius umarmt zur\u00fcck, ohne nachzudenken. Vor zwei Monaten hatte er Angst, beim B\u00fcrgeramt Deutsch zu sprechen. Jetzt f\u00e4ngt er Bonbons und umarmt B\u00e4ren.",src:"A stranger in a bear costume hugs Verumius. Verumius hugs back without thinking. Two months ago he was terrified of speaking German at the citizens' office. Now he catches candy and hugs bears."},
{type:"teach",trg:"der Zuschauer",src:"the spectator (male)",pos:"noun",gender:"m",note:"Masculine noun. Zu (to/at) + schauen (to watch) + '-er.'\nOver one million Zuschauer line the parade route.",example:"A: Wie viele Zuschauer sind hier?\nB: \u00dcber eine Million!\nA: Die Zuschauer stehen seit Stunden.\nB: F\u00fcr den Rosenmontagszug wartet man gerne.",exampleSrc:"A: How many spectators are here?\nB: Over one million!\nA: The spectators have been standing for hours.\nB: For the Rose Monday parade you gladly wait.",funFact:"Zu + schauen + -er: someone who watches (schaut zu). Over one million Zuschauer line the Rosenmontagszug route."},
{type:"teach",trg:"die Zuschauerin",src:"the spectator (female)",pos:"noun",gender:"f",note:"Feminine noun. Zuschauer + '-in.'\nThe -er/-erin pattern is now automatic for you.",example:"A: Die Zuschauerin neben mir ist begeistert.\nB: Alle Zuschauerinnen und Zuschauer feiern.\nA: Egal ob Mann oder Frau.\nB: Karneval macht alle gleich.",exampleSrc:"A: The spectator next to me is thrilled.\nB: All spectators are celebrating.\nA: Whether man or woman.\nB: Carnival makes everyone equal.",funFact:"The -er/-erin pattern is now automatic. You are building a profession vocabulary factory."},
{type:"teach",trg:"der Schauspieler",src:"the actor (male)",pos:"noun",gender:"m",note:"Masculine noun. Schau (show) + Spiel (play) + '-er.'\nLiterally 'show-player.'",example:"A: Ist er ein Schauspieler?\nB: Nein, er ist nur gut verkleidet!\nA: Er spielt seine Rolle perfekt.\nB: Beim Karneval ist jeder ein Schauspieler.",exampleSrc:"A: Is he an actor?\nB: No, he's just well disguised!\nA: He plays his role perfectly.\nB: At carnival everyone is an actor.",funFact:"Literally 'show-player.' German compound logic: someone who plays (spielt) in a show (Schau)."},
{type:"teach",trg:"die Schauspielerin",src:"the actor (female)",pos:"noun",gender:"f",note:"Feminine noun. Schauspieler + '-in.'\nAt Karneval, everyone is a Schauspielerin for a day.",example:"A: Die Schauspielerin tr\u00e4gt ein tolles Kost\u00fcm.\nB: Ist sie wirklich Schauspielerin?\nA: Ja, sie spielt im K\u00f6lner Theater.\nB: Kein Wunder, dass sie so gut ist!",exampleSrc:"A: The actress is wearing a great costume.\nB: Is she really an actress?\nA: Yes, she acts at the Cologne theater.\nB: No wonder she's so good!",funFact:"At Karneval, everyone is a Schauspielerin for a day. The costume is the role."},
{type:"teach",trg:"der Zuh\u00f6rer",src:"the listener (male)",pos:"noun",gender:"m",note:"Masculine noun. Zu (to) + h\u00f6ren (to hear/listen) + '-er.'\nSomeone who actively listens (h\u00f6rt zu).",example:"A: Die Zuh\u00f6rer singen alle mit!\nB: Bei Karnevalsmusik kann niemand still sein.\nA: Aus Zuh\u00f6rern werden S\u00e4nger.\nB: Das ist der Geist des Karnevals.",exampleSrc:"A: The listeners are all singing along!\nB: With carnival music nobody can stay quiet.\nA: Listeners become singers.\nB: That's the spirit of carnival.",funFact:"Radio has Zuh\u00f6rer, lectures have Zuh\u00f6rer, Karneval songs have Zuh\u00f6rer who become Mits\u00e4nger (people who sing along)."},
{type:"teach",trg:"die Zuh\u00f6rerin",src:"the listener (female)",pos:"noun",gender:"f",note:"Feminine noun. Zuh\u00f6rer + '-in.'\nThe zu- prefix means 'toward.' Zuh\u00f6rer listens toward something.",example:"A: Die Zuh\u00f6rerin klatscht begeistert.\nB: Sie kennt jedes Lied.\nA: Eine echte Karnevalsfan.\nB: Zuh\u00f6rerin und Mits\u00e4ngerin!",exampleSrc:"A: The listener claps enthusiastically.\nB: She knows every song.\nA: A true carnival fan.\nB: Listener and sing-along participant!",funFact:"German distinguishes what English does not: Zuh\u00f6rer listens actively (zu means toward), H\u00f6rer may hear more passively."},
{type:"teach",trg:"der H\u00f6rer",src:"the listener, the receiver",pos:"noun",gender:"m",note:"Masculine noun. H\u00f6ren (to hear) + '-er.'\nAlso means 'telephone receiver.'",example:"A: Wie viele H\u00f6rer hat der Radiosender?\nB: \u00dcber eine Million.\nA: H\u00f6rer und Zuschauer, das ist ein Unterschied.\nB: H\u00f6rer h\u00f6ren, Zuschauer schauen.",exampleSrc:"A: How many listeners does the radio station have?\nB: Over one million.\nA: Listeners and spectators, that's a difference.\nB: Listeners hear, spectators watch.",funFact:"Also means 'telephone receiver' (the part you hold to your ear). Broader than Zuh\u00f6rer (active listener)."},
{type:"teach",trg:"die H\u00f6rerin",src:"the listener (female)",pos:"noun",gender:"f",note:"Feminine noun. H\u00f6rer + '-in.'\nThe difference: H\u00f6rer hears passively, Zuh\u00f6rer listens actively.",example:"A: Die H\u00f6rerin ruft beim Radiosender an.\nB: Was m\u00f6chte sie?\nA: Ein Karnevalslied w\u00fcnschen.\nB: Radio und Karneval geh\u00f6ren zusammen.",exampleSrc:"A: The listener calls the radio station.\nB: What does she want?\nA: To request a carnival song.\nB: Radio and carnival belong together.",funFact:"H\u00f6rer may hear passively, Zuh\u00f6rer listens actively. German distinguishes what English often does not."},
{type:"teach",trg:"das Tor",src:"the gate, the goal",pos:"noun",gender:"n",note:"Neuter noun. 'Ein Tor schie\u00dfen' (to score a goal) in football.\nAlso 'gateway': das Brandenburger Tor.",example:"A: Tor! Ein Tor!\nB: Wer hat das Tor geschossen?\nA: Die Nummer 10!\nB: Was f\u00fcr ein fantastisches Tor!",exampleSrc:"A: Goal! A goal!\nB: Who scored the goal?\nA: Number 10!\nB: What a fantastic goal!",funFact:"'Ein Tor schie\u00dfen' = to score a goal. Also 'gateway': das Brandenburger Tor. During Karneval parades, city gates are symbolically opened."},
{type:"teach",trg:"das Talent",src:"the talent",pos:"noun",gender:"n",note:"Neuter noun. From Greek 'talanton.' Same word in English.\nKarneval discovers Talente: comedy, music, costume design.",example:"A: Sie hat ein echtes Talent!\nB: F\u00fcr was?\nA: F\u00fcr Kost\u00fcmdesign.\nB: Talent kommt beim Karneval zur Geltung.",exampleSrc:"A: She has a real talent!\nB: For what?\nA: For costume design.\nB: Talent shines at carnival.",funFact:"Karneval discovers Talente in comedy, music, and costume design. The B\u00fchne is open to everyone with Talent."},
{type:"teach",trg:"der Typ",src:"the type, the guy",pos:"noun",gender:"m",note:"Masculine noun. From Greek 'typos.'\nColloquially: 'der Typ' means 'that guy.'",example:"A: Wer ist der Typ da dr\u00fcben?\nB: Keine Ahnung, aber sein Kost\u00fcm ist klasse.\nA: Ein lustiger Typ.\nB: Beim Karneval trifft man alle Typen.",exampleSrc:"A: Who is that guy over there?\nB: No idea, but his costume is awesome.\nA: A funny guy.\nB: At carnival you meet all types.",funFact:"In colloquial German, 'der Typ' means 'that guy.' 'Er ist ein lustiger Typ' (He is a funny guy). Also means 'type' formally."},
{type:"teach",trg:"das Ballett",src:"the ballet",pos:"noun",gender:"n",note:"Neuter noun. From Italian 'balletto' (little dance).\nThe Funkenmariechen performs moves from Ballett and military drill.",example:"A: Ist das Ballett?\nB: So \u00e4hnlich. Das ist eine Funkenmariechen.\nA: Eine Mischung aus Ballett und Milit\u00e4rtanz?\nB: Genau. Eine Jahrhunderte alte Tradition.",exampleSrc:"A: Is that ballet?\nB: Sort of. That's a Funkenmariechen.\nA: A mix of ballet and military dance?\nB: Exactly. A centuries-old tradition.",funFact:"The Funkenmariechen (carnival solo dancer) performs moves from Ballett and military drill. Cologne's dance tradition is centuries old."},
{type:"teach",trg:"wahnsinnig",src:"insane, incredibly",pos:"adj",gender:null,note:"Wahn (delusion) + Sinn (sense). Literally 'delusional-minded.'\nUsed as intensifier: 'wahnsinnig gut' (insanely good).",example:"A: Die Parade ist wahnsinnig laut!\nB: Wahnsinnig bunt, wahnsinnig lustig.\nA: Wahnsinnig viele Menschen.\nB: Einfach wahnsinnig!",exampleSrc:"A: The parade is insanely loud!\nB: Insanely colorful, insanely funny.\nA: An insane number of people.\nB: Simply insane!",funFact:"Wahn (delusion) + Sinn (sense). Used as an intensifier: 'wahnsinnig gut' (insanely good), 'wahnsinnig laut' (insanely loud). The Rosenmontagszug is wahnsinnig everything."},
{type:"teach",trg:"allerbest",src:"the very best of all",pos:"adj",gender:null,note:"Aller- (of all) + best (best). A double superlative.\n'Das allerbeste Kost\u00fcm!' Reserved for when 'best' is not enough.",example:"A: Das war der allerbeste Tag!\nB: Findest du? Besser als Berlin?\nA: Berlin ist toll, aber heute war allerbest.\nB: Karneval macht alles allerbest.",exampleSrc:"A: That was the very best day!\nB: You think? Better than Berlin?\nA: Berlin is great, but today was the very best.\nB: Carnival makes everything the very best.",funFact:"Aller- cranks any superlative to maximum. 'Das allerbeste Kost\u00fcm!' Reserved for when 'best' is simply not enough."},
{type:"teach",trg:"allersch\u00f6nst",src:"the most beautiful of all",pos:"adj",gender:null,note:"Aller- + sch\u00f6nst. Same amplifier.\n'Der allersch\u00f6nste Tag' (The most beautiful day of all).",example:"A: Das ist der allersch\u00f6nste Wagen!\nB: Ja, die Farben sind unglaublich.\nA: Der allersch\u00f6nste Moment.\nB: Karneval liefert allersch\u00f6nste Erinnerungen.",exampleSrc:"A: That is the most beautiful float of all!\nB: Yes, the colors are incredible.\nA: The most beautiful moment of all.\nB: Carnival delivers the most beautiful memories.",funFact:"Same aller- amplifier. 'Der allersch\u00f6nste Tag.' Verumius might use this about Rosenmontag."},
{type:"teach",trg:"springen",src:"to jump",pos:"verb",gender:null,note:"Irregular: sprang, gesprungen. Same root as English 'spring.'\nChildren springen to catch candy from the air.",example:"A: Die Kinder springen nach den Bonbons!\nB: Alle springen und lachen.\nA: Ich springe auch!\nB: Spring h\u00f6her, dann f\u00e4ngst du mehr!",exampleSrc:"A: The children jump for the candy!\nB: Everyone jumps and laughs.\nA: I'm jumping too!\nB: Jump higher, then you'll catch more!",funFact:"Irregular: sprang, gesprungen. Same root as English 'spring.' At the parade, children springen to catch candy from the air."},
{type:"teach",trg:"rennen",src:"to run (fast)",pos:"verb",gender:null,note:"Irregular: rannte, gerannt. More urgent than 'laufen.'\n'Renn nicht!' (Don't run!).",example:"A: Die Kinder rennen den Bonbons hinterher!\nB: Renn nicht so schnell!\nA: Aber die Schokolade!\nB: Erwachsene rennen auch, wenn niemand hinschaut.",exampleSrc:"A: The children run after the candy!\nB: Don't run so fast!\nA: But the chocolate!\nB: Adults run too, when nobody's watching.",funFact:"More urgent than 'laufen.' Children rennen after candy at the parade. Adults pretend not to, then rennen when nobody watches."},
{type:"teach",trg:"klettern",src:"to climb",pos:"verb",gender:null,note:"Regular verb. 'Auf einen Baum klettern' (to climb a tree).\nAlso a popular sport: Kletterhalle (climbing gym).",example:"A: Die Kinder klettern auf die Absperrung!\nB: Um besser zu sehen.\nA: Vorsicht beim Klettern!\nB: Kinder klettern \u00fcberall.",exampleSrc:"A: The children climb on the barrier!\nB: In order to see better.\nA: Be careful climbing!\nB: Children climb everywhere.",funFact:"During Karneval, children klettern on barriers to get a better view. Klettern is also a popular sport: Kletterhalle (climbing gym)."},
{type:"teach",trg:"treiben",src:"to drive, to push, to do (sport)",pos:"verb",gender:null,note:"Irregular: trieb, getrieben. 'Sport treiben' (to do sports).\n'Was treibst du?' colloquially means 'What are you up to?'",example:"A: Was treibst du beim Karneval?\nB: Ich treibe mich durch die Altstadt!\nA: Sport treiben oder Spa\u00df treiben?\nB: Beim Karneval? Nur Spa\u00df!",exampleSrc:"A: What are you up to at carnival?\nB: I'm roaming through the Old Town!\nA: Doing sports or having fun?\nB: At carnival? Just fun!",funFact:"'Sport treiben' = to do sports. 'Was treibst du?' colloquially means 'What are you up to?' At Karneval, die Menge treibt durch die Stra\u00dfen."},
{type:"teach",trg:"treten",src:"to step, to kick",pos:"verb",gender:null,note:"Irregular: trat, getreten. Many separable compounds:\neintreten = enter, auftreten = perform, austreten = exit.",example:"A: Treten Sie bitte ein!\nB: Danke! Wo ist die B\u00fchne?\nA: Geradeaus. Die Band tritt gleich auf.\nB: Toll, wir sind rechtzeitig!",exampleSrc:"A: Please step in!\nB: Thanks! Where is the stage?\nA: Straight ahead. The band performs shortly.\nB: Great, we're on time!",funFact:"One root verb, many separable prefixes: eintreten (enter), auftreten (perform), austreten (exit). You already know auftreten from Lesson 5."},
{type:"mc",q:"Verumius rennt durch die Menge, um Bonbons zu fangen, ohne hinzufallen. Welche Konstruktionen?",opts:["um...zu und damit","ohne...zu und statt...zu","um...zu und ohne...zu","damit und statt...zu"],ans:"um...zu und ohne...zu",hint:"Purpose (in order to catch) and absence (without falling). Both have the same subject."},
{type:"fb",s:"Statt zu Hause zu bleiben, feiern wir den ganzen Tag. '{1}...zu' bedeutet 'instead of.'",a:["Statt"],opts:["Statt","Ohne","Um","Damit"],hint:"The construction that introduces what you do NOT do, replaced by the other action.",sSrc:"Instead of staying at home, we celebrate all day. 'Statt...zu' means 'instead of.'"},
{type:"mc",q:"\u00dcber eine Million Menschen stehen am Stra\u00dfenrand und schauen zu. Sie sind...",opts:["Schauspieler","Sportler","Zuschauer","Reporter"],ans:"Zuschauer",hint:"People who watch (schauen zu) an event are called this."},
{type:"drag_fill",s:"Mia singt laut, {1} alle mitsingen, {2} ihre Stimme zu verlieren.",blanks:{"1":"damit","2":"ohne"},pool:["damit","ohne","um","statt","weil"],hint:"First: different subjects (Mia sings, everyone else joins). Second: she does it without losing her voice.",sSrc:"Mia sings loudly so that everyone sings along, without losing her voice."},
{type:"mc",q:"Verumius sagt: 'Das war der allerbeste Tag!' Was bedeutet 'allerbest'?",opts:["ziemlich gut","der allerbeste von allen","der schlimmste","der normalste"],ans:"der allerbeste von allen",hint:"Aller- is a double superlative prefix that amplifies 'best' even further."}
]},

// ─── Lesson 7: Kamelle und Konfetti ──────────────────────────
{id:"deu_r17l7",title:"Kamelle und Konfetti",icon:"\uD83C\uDF6C",xp:15,board:true,steps:[
{type:"intro",title:"Kamelle und Konfetti",desc:"Zeig, was du kannst. Alle vier Infinitivkonstruktionen im Test. Literatur- und Medienvokabeln. Keine Trainingsrollen mehr.",goals:["Beweise Beherrschung aller vier Infinitivkonstruktionen","Lerne W\u00f6rter f\u00fcr Literatur, Medien und Kultur","Bestehe die schwerste \u00dcbungsrunde des Karnevals"]},
{type:"teach",trg:"der Maler",src:"the painter (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'malen' (to paint) + '-er.'\nCovers both house painters and artists.",example:"A: Wer hat dieses Bild gemalt?\nB: Ein ber\u00fchmter Maler aus K\u00f6ln.\nA: Der Maler hat Talent.\nB: Maler und K\u00fcnstler, das ist oft dasselbe.",exampleSrc:"A: Who painted this picture?\nB: A famous painter from Cologne.\nA: The painter has talent.\nB: Painter and artist, that's often the same thing.",funFact:"Germany's most famous Maler: Albrecht D\u00fcrer, Caspar David Friedrich, Gerhard Richter. The word covers both house painters and Picassos."},
{type:"teach",trg:"die Malerin",src:"the painter (female)",pos:"noun",gender:"f",note:"Feminine noun. Maler + '-in.'\nK\u00e4the Kollwitz and Paula Modersohn-Becker are among Germany's greatest.",example:"A: Die Malerin stellt im Museum aus.\nB: Ihre Bilder sind wundersch\u00f6n.\nA: Eine talentierte Malerin.\nB: Ihre Werke h\u00e4ngen in Museen weltweit.",exampleSrc:"A: The painter exhibits in the museum.\nB: Her paintings are beautiful.\nA: A talented painter.\nB: Her works hang in museums worldwide.",funFact:"K\u00e4the Kollwitz and Paula Modersohn-Becker are among Germany's greatest Malerinnen. Their work hangs in museums worldwide."},
{type:"teach",trg:"der Schriftsteller",src:"the writer, the author (male)",pos:"noun",gender:"m",note:"Masculine noun. Schrift (writing) + stellen (to place) + '-er.'\nMore literary than 'Autor.'",example:"A: Wer ist dein Lieblingsschriftsteller?\nB: Thomas Mann. Ein gro\u00dfer Schriftsteller.\nA: Schriftsteller oder Autor?\nB: Schriftsteller klingt literarischer.",exampleSrc:"A: Who is your favorite writer?\nB: Thomas Mann. A great writer.\nA: Writer or author?\nB: Schriftsteller sounds more literary.",funFact:"Someone who 'places writing.' More literary than Autor. Goethe, Kafka, and Thomas Mann are Germany's iconic Schriftsteller."},
{type:"teach",trg:"die Schriftstellerin",src:"the writer, the author (female)",pos:"noun",gender:"f",note:"Feminine noun. Schriftsteller + '-in.'\nHerta M\u00fcller won the Nobel Prize in Literature.",example:"A: Die Schriftstellerin hat den Nobelpreis gewonnen.\nB: Wirklich? F\u00fcr welches Buch?\nA: F\u00fcr ihr Gesamtwerk.\nB: Eine gro\u00dfartige Schriftstellerin.",exampleSrc:"A: The writer won the Nobel Prize.\nB: Really? For which book?\nA: For her complete body of work.\nB: A magnificent writer.",funFact:"Herta M\u00fcller won the Nobel Prize. Christa Wolf defined East German literature. The -in makes any profession feminine."},
{type:"teach",trg:"der Autor",src:"the author (male)",pos:"noun",gender:"m",note:"Masculine noun. From Latin 'auctor.'\nBroader than Schriftsteller: books, articles, screenplays.",example:"A: Wer ist der Autor dieses Buches?\nB: Ein junger Autor aus Berlin.\nA: Jeder, der schreibt, ist ein Autor.\nB: Aber nicht jeder Autor ist ein Schriftsteller.",exampleSrc:"A: Who is the author of this book?\nB: A young author from Berlin.\nA: Everyone who writes is an author.\nB: But not every author is a Schriftsteller.",funFact:"Broader than Schriftsteller: an Autor writes books, articles, screenplays, blogs. Everyone who writes is an Autor. Not everyone is a Schriftsteller."},
{type:"teach",trg:"die Autorin",src:"the author (female)",pos:"noun",gender:"f",note:"Feminine noun. Autor + '-in.'\nGermany's book market is the third largest in the world.",example:"A: Die Autorin stellt ihr neues Buch vor.\nB: Worüber schreibt sie?\nA: \u00dcber Karneval im Rheinland.\nB: Das wird bestimmt ein Bestseller!",exampleSrc:"A: The author presents her new book.\nB: What does she write about?\nA: About carnival in the Rhineland.\nB: That will surely be a bestseller!",funFact:"Germany's book market is the third largest in the world after the US and China. Autorinnen are well represented on bestseller lists."},
{type:"teach",trg:"der Roman",src:"the novel",pos:"noun",gender:"m",note:"Masculine noun. From French 'roman.'\nNot the nationality (that is 'R\u00f6mer').",example:"A: Liest du gerade einen Roman?\nB: Ja, einen deutschen Roman.\nA: Welchen?\nB: 'Die Blechtrommel' von G\u00fcnter Grass.",exampleSrc:"A: Are you reading a novel right now?\nB: Yes, a German novel.\nA: Which one?\nB: 'The Tin Drum' by G\u00fcnter Grass.",funFact:"Not the nationality (that would be 'R\u00f6mer'). The Bildungsroman (coming-of-age novel) is a German invention that influenced world literature."},
{type:"teach",trg:"das Gedicht",src:"the poem",pos:"noun",gender:"n",note:"Neuter noun because of the Ge- prefix. From 'dichten' (to compose).\nGoethe's Gedichte are memorized in every German school.",example:"A: Kennst du ein deutsches Gedicht?\nB: Ja! 'Der Erlk\u00f6nig' von Goethe.\nA: Beim Karneval gibt es auch Gedichte.\nB: Ja, humorvolle Reime bei den Sitzungen.",exampleSrc:"A: Do you know a German poem?\nB: Yes! 'The Erlking' by Goethe.\nA: At carnival there are poems too.\nB: Yes, humorous rhymes at the sessions.",funFact:"Neuter because of the Ge- prefix. Karneval has its own Gedicht tradition: humorous rhymes recited at Sitzungen."},
{type:"teach",trg:"die Erz\u00e4hlung",src:"the narrative, the short story",pos:"noun",gender:"f",note:"Feminine noun. From 'erz\u00e4hlen' (to tell/narrate).\nThe -ung suffix always makes feminine nouns.",example:"A: Ist das eine Erz\u00e4hlung oder ein Roman?\nB: Eine Erz\u00e4hlung. Zu kurz f\u00fcr einen Roman.\nA: Wor\u00fcber handelt die Erz\u00e4hlung?\nB: \u00dcber einen Fremden beim K\u00f6lner Karneval.",exampleSrc:"A: Is that a narrative or a novel?\nB: A narrative. Too short for a novel.\nA: What is the narrative about?\nB: About a stranger at Cologne carnival.",funFact:"The -ung suffix always makes feminine nouns. Kafka's 'Die Verwandlung' (The Metamorphosis) is Germany's most famous Erz\u00e4hlung."},
{type:"teach",trg:"die Literatur",src:"the literature",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'literatura.'\nGermany has produced 14 Nobel Prize winners in Literatur.",example:"A: Magst du deutsche Literatur?\nB: Ja, besonders die Klassiker.\nA: Literatur ist Kultur.\nB: Und Kultur ist beim Karneval \u00fcberall.",exampleSrc:"A: Do you like German literature?\nB: Yes, especially the classics.\nA: Literature is culture.\nB: And culture is everywhere at carnival.",funFact:"Germany has produced 14 Nobel Prize winners in Literatur. The Frankfurt Book Fair is the world's largest."},
{type:"teach",trg:"die Schrift",src:"the script, the writing, the typeface",pos:"noun",gender:"f",note:"Feminine noun. From 'schreiben' (to write).\nGutenberg's Druckerpresse made Schrift available to everyone.",example:"A: Was f\u00fcr eine Schrift ist das?\nB: Eine alte deutsche Schrift. Fraktur.\nA: Schwer zu lesen!\nB: Fr\u00fcher war das die normale Schrift.",exampleSrc:"A: What kind of script is that?\nB: An old German script. Fraktur.\nA: Hard to read!\nB: In the past that was the normal script.",funFact:"Gutenberg's printing press made Schrift available to everyone. The Lutheran Bible standardized German Schrift across dialects."},
{type:"teach",trg:"der Verlag",src:"the publishing house",pos:"noun",gender:"m",note:"Masculine noun. From 'verlegen' (to publish).\nGermany has over 2,000 Verlage.",example:"A: Welcher Verlag hat das Buch herausgegeben?\nB: Ein kleiner K\u00f6lner Verlag.\nA: Deutschland hat viele Verlage.\nB: \u00dcber 2.000! Lesen ist hier wichtig.",exampleSrc:"A: Which publisher released the book?\nB: A small Cologne publisher.\nA: Germany has many publishers.\nB: Over 2,000! Reading is important here.",funFact:"Germany has over 2,000 Verlage. The biggest: Bertelsmann, Springer, Suhrkamp. 'Im Verlag erscheinen' means 'to be published by.'"},
{type:"teach",trg:"das Medium",src:"the medium",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'medium.' Plural: Medien.\n'Die Medien berichten \u00fcber Karneval.'",example:"A: Welches Medium nutzt du am meisten?\nB: Die Medien berichten \u00fcber Karneval.\nA: Fernsehen, Radio, Zeitung?\nB: Und Social Media! Alle Medien.",exampleSrc:"A: Which medium do you use the most?\nB: The media report on carnival.\nA: TV, radio, newspaper?\nB: And social media! All media.",funFact:"Plural: Medien. In German, Medien nearly always means news media. 'Die Medien berichten \u00fcber Karneval.'"},
{type:"teach",trg:"die Garantie",src:"the guarantee, the warranty",pos:"noun",gender:"f",note:"Feminine noun. From French 'garantie.'\n'Keine Garantie!' (No guarantee!).",example:"A: Gibt es eine Garantie f\u00fcr gutes Wetter?\nB: Keine Garantie! Aber Karneval feiert man bei jedem Wetter.\nA: Garantiert Spa\u00df?\nB: Das ist die einzige Garantie beim Karneval.",exampleSrc:"A: Is there a guarantee for good weather?\nB: No guarantee! But carnival is celebrated in any weather.\nA: Guaranteed fun?\nB: That's the only guarantee at carnival.",funFact:"At Karneval, es ist die Garantie f\u00fcr eine gute Zeit. In stores, Garantie means warranty. Same word, different context."},
{type:"teach",trg:"garantieren",src:"to guarantee",pos:"verb",gender:null,note:"From Garantie. Regular -ieren verb.\nAll -ieren verbs form past participle without ge-: garantiert.",example:"A: Kannst du mir Spa\u00df garantieren?\nB: Beim Karneval garantiert!\nA: Das hast du garantiert?\nB: Ich garantiere es. Hundert Prozent.",exampleSrc:"A: Can you guarantee me fun?\nB: At carnival, guaranteed!\nA: You guaranteed that?\nB: I guarantee it. One hundred percent.",funFact:"All -ieren verbs are regular and form their past participle without ge-: garantiert, not gegarantiert. A reliable pattern."},
{type:"teach",trg:"auff\u00fchren",src:"to perform, to stage",pos:"verb",gender:null,note:"Separable verb. Auf (up) + f\u00fchren (to lead).\nAlso 'sich auff\u00fchren' = to behave (usually badly).",example:"A: Welches St\u00fcck f\u00fchren sie auf?\nB: Eine Karnevalskomödie.\nA: Sie f\u00fchren es heute Abend auf.\nB: Und morgen f\u00fchren sie sich danach auf!",exampleSrc:"A: Which piece are they performing?\nB: A carnival comedy.\nA: They're staging it tonight.\nB: And tomorrow they'll behave badly afterward!",funFact:"'Ein St\u00fcck auff\u00fchren' = to perform a play. Also 'sich auff\u00fchren' = to behave (usually badly). 'F\u00fchr dich nicht so auf!' (Don't make a scene!)"},
{type:"teach",trg:"auffallen",src:"to stand out, to be noticeable",pos:"verb",gender:null,note:"Separable verb. Auf (up) + fallen (to fall).\n'Das f\u00e4llt auf!' (That stands out!).",example:"A: Dein Kost\u00fcm f\u00e4llt auf!\nB: Danke! Beim Karneval will man auffallen.\nA: Im Alltag f\u00e4llt man nicht gern auf.\nB: Aber heute: je mehr, desto besser!",exampleSrc:"A: Your costume stands out!\nB: Thanks! At carnival you want to stand out.\nA: In everyday life people don't like to stand out.\nB: But today: the more, the better!",funFact:"At Karneval, aufzufallen is the goal. In normal German life, it is often avoided. A complete cultural reversal."},
{type:"teach",trg:"verwenden",src:"to use, to employ",pos:"verb",gender:null,note:"Ver- + wenden (to turn). More formal than 'benutzen.'\nUsed for materials, methods, and resources.",example:"A: Welche Farben verwendest du?\nB: Rot, Gelb und Gr\u00fcn.\nA: Und welches Material?\nB: Ich verwende Pappe und Stoff.",exampleSrc:"A: Which colors do you use?\nB: Red, yellow, and green.\nA: And which material?\nB: I use cardboard and fabric.",funFact:"More formal than 'benutzen.' Used for materials, methods, and resources. 'Welche Farben verwendest du?'"},
{type:"teach",trg:"wetten",src:"to bet",pos:"verb",gender:null,note:"'Wetten, dass...?' (Wanna bet that...?).\nAlso Germany's biggest TV show for decades.",example:"A: Wetten, dass Verumius Spa\u00df hat?\nB: Darauf wette ich!\nA: Ich wette, er kommt n\u00e4chstes Jahr wieder.\nB: Darauf w\u00fcrde ich auch wetten.",exampleSrc:"A: Wanna bet that Verumius is having fun?\nB: I'd bet on that!\nA: I bet he'll come back next year.\nB: I'd bet on that too.",funFact:"'Wetten, dass...?' was also Germany's biggest TV show for decades. 'Ich wette, Verumius hat Spa\u00df.'"},
{type:"teach",trg:"irren",src:"to err, to be wrong",pos:"verb",gender:null,note:"'Sich irren' = to be mistaken.\n'Irren ist menschlich' (To err is human).",example:"A: Du irrst dich! Das ist kein Pirat.\nB: Oh, ich habe mich geirrt?\nA: Ja, das ist ein Wikinger!\nB: Irren ist menschlich.",exampleSrc:"A: You're wrong! That's not a pirate.\nB: Oh, I was mistaken?\nA: Yes, that's a Viking!\nB: To err is human.",funFact:"'Irren ist menschlich' (To err is human). 'Wer dachte, Deutsche haben keinen Humor, hat sich geirrt.'"},
{type:"mc",q:"Wir fahren nach K\u00f6ln, ___ den Rosenmontagszug zu sehen.",opts:["ohne","damit","statt","um"],ans:"um",hint:"We travel with a PURPOSE: to see the parade. Same subject, purpose clause."},
{type:"mc",q:"Die Kinder fangen Bonbons, ___ hinzufallen.",opts:["damit","statt","ohne","um"],ans:"ohne",hint:"The children catch candy and do NOT fall. The word for 'without.'"},
{type:"fb",s:"Der S\u00e4nger singt laut, {1} das Publikum ihn h\u00f6rt.",a:["damit"],opts:["damit","um","ohne","statt"],hint:"The singer sings (subject 1) so that the audience (subject 2) hears. Different subjects.",sSrc:"The singer sings loudly so that the audience hears him."},
{type:"mc",q:"'Statt den Roman zu lesen, schaut er die Serie.' Was macht er?",opts:["Er liest den Roman ohne zu schauen","Er schaut die Serie statt den Roman zu lesen","Er schaut, um zu lesen","Er liest den Roman und schaut die Serie"],ans:"Er schaut die Serie statt den Roman zu lesen",hint:"Statt introduces what was replaced by the actual action."},
{type:"drag_fill",s:"{1} nur zuzuh\u00f6ren, singt Verumius mit, {2} den Text zu kennen, {3} alle lachen.",blanks:{"1":"Statt","2":"ohne","3":"damit"},pool:["Statt","ohne","damit","um","weil","obwohl"],hint:"Instead of just listening, without knowing the lyrics, so that everyone laughs. Three constructions.",sSrc:"Instead of just listening, Verumius sings along without knowing the lyrics, so that everyone laughs."},
{type:"match",pairs:[{trg:"um...zu",src:"in order to"},{trg:"ohne...zu",src:"without doing"},{trg:"(an)statt...zu",src:"instead of doing"},{trg:"damit",src:"so that (different subject)"}]},
{type:"mc",q:"Ein Autor schreibt Romane. Ein Schriftsteller ist...",opts:["ein Sportler","auch ein Autor","ein Musiker","ein Maler"],ans:"auch ein Autor",hint:"Schriftsteller is the more literary term, but both write. One contains the other."},
{type:"fb",s:"Der Maler malt, {1} ber\u00fchmt zu werden.",a:["um"],opts:["um","ohne","statt","damit"],hint:"The purpose of painting: becoming famous. Same subject, purpose clause.",sSrc:"The painter paints in order to become famous."},
{type:"mc",q:"'Mia erkl\u00e4rt die Tradition, damit Verumius sie versteht, ohne gelangweilt zu klingen.' Wie viele Infinitivkonstruktionen hat dieser Satz?",opts:["Eins: ohne...zu","Drei: damit, ohne und um","Eins: damit","Zwei: damit und ohne...zu"],ans:"Zwei: damit und ohne...zu",hint:"Find the two clause connectors: one for purpose (different subjects) and one for 'without doing.'"}
]},

// ─── Lesson 8: Konfetti im Haar ──────────────────────────────
{id:"deu_r17l8",title:"Konfetti im Haar",icon:"\u2728",xp:15,board:true,steps:[
{type:"intro",title:"Konfetti im Haar",desc:"ICE zur\u00fcck nach Berlin. Konfetti im Haar, zerknitterte Toga, schr\u00e4ge Bienenf\u00fchler. Verumius reflektiert \u00fcber den verr\u00fccktesten Tag seines Lebens. Lerne regionale Karnevalsnamen und bestehe den Abschlusstest.",goals:["Schlie\u00dfe das Karnevalserlebnis ab","Lerne regionale Karnevalsvokabeln und kulturelle Kontraste","Bestehe den Abschlusstest \u00fcber alle vier Infinitivkonstruktionen"]},
{type:"story",speaker:"narrator",mood:"quiet",art:"ice-konfetti-sunset",trg:"ICE nach Berlin. Der Wahnsinn ist vorbei. Konfetti klebt noch in Verumius' Haaren. Seine r\u00f6mische Senatortoga ist zerknittert. Mia schl\u00e4ft auf der anderen Seite des Ganges, die Bienenf\u00fchler schief. Durch das Fenster verblasst das Rheinland in der D\u00e4mmerung.",src:"ICE to Berlin. The madness is over. Confetti still clings to Verumius's hair. His Roman senator toga is wrinkled. Mia sleeps across the aisle, bee antennae crooked. Through the window, the Rhineland fades into twilight."},
{type:"story",speaker:"verumius",mood:"reflective",trg:"Ich bin nach K\u00f6ln gefahren, um Karneval zu erleben. Ich bin zur\u00fccckgekommen mit Konfetti im Haar und einem L\u00e4cheln im Gesicht.",src:"I went to Cologne to experience carnival. I came back with confetti in my hair and a smile on my face."},
{type:"story",speaker:"narrator",mood:"warm",trg:"Er entfernt das Konfetti nicht. Noch nicht. Es ist der Beweis, dass es passiert ist. Dass Deutschland, das Land der Formulare und P\u00fcnktlichkeit, auch das in sich hat. Diese wilde, warme, verr\u00fcckte Freude.",src:"He doesn't remove the confetti. Not yet. It is proof that it happened. That Germany, the land of forms and punctuality, has this in it too. This wild, warm, crazy joy."},
{type:"teach",trg:"der Fasching",src:"carnival (Bavarian/Austrian term)",pos:"noun",gender:"m",note:"Masculine noun. Southern German and Austrian word for carnival.\nFrom 'Fastenschank' (last drink before fasting).",example:"A: In M\u00fcnchen sagt man 'Fasching.'\nB: Und in K\u00f6ln 'Karneval.'\nA: Fasching, Karneval, Fasnacht.\nB: Drei Namen, eine Party!",exampleSrc:"A: In Munich they say 'Fasching.'\nB: And in Cologne 'Karneval.'\nA: Fasching, Karneval, Fasnacht.\nB: Three names, one party!",funFact:"In Munich they say Fasching, in Cologne Karneval, in Basel Fasnacht. Same party, three names. From 'Fastenschank' (last drink before fasting)."},
{type:"teach",trg:"die Fasnacht",src:"carnival (Swiss/Southwestern term)",pos:"noun",gender:"f",note:"Feminine noun. Swiss and Southwestern German.\nFrom 'Fasten' (fasting) + 'Nacht' (night).",example:"A: Basel feiert Fasnacht.\nB: Die Basler Fasnacht beginnt um vier Uhr morgens!\nA: Um vier? Das ist verr\u00fcckt.\nB: Jede Region hat ihre eigene Art.",exampleSrc:"A: Basel celebrates Fasnacht.\nB: Basel's Fasnacht starts at four in the morning!\nA: At four? That's crazy.\nB: Every region has its own way.",funFact:"Basel's Fasnacht starts at 4 AM in darkness. Each region owns its version. Fasten (fasting) + Nacht (night): the night before fasting begins."},
{type:"teach",trg:"der Friseur",src:"the hairdresser (male)",pos:"noun",gender:"m",note:"Masculine noun. From French 'friseur.'\nAfter Karneval, Friseure have their busiest week.",example:"A: Ich muss zum Friseur nach dem Karneval.\nB: Warum?\nA: Gl\u00fcckshaarspray und Konfetti.\nB: Nach dem Karneval ist immer Hochsaison beim Friseur.",exampleSrc:"A: I need to go to the hairdresser after carnival.\nB: Why?\nA: Glitter hairspray and confetti.\nB: After carnival is always peak season at the hairdresser.",funFact:"After Karneval, Friseure have their busiest week: washing out hair dye, glitter, and face paint. Germany has over 80,000 Friseur salons."},
{type:"teach",trg:"die Frisur",src:"the hairstyle",pos:"noun",gender:"f",note:"Feminine noun. From French 'frisure.'\n'Sch\u00f6ne Frisur!' is a genuine compliment.",example:"A: Sch\u00f6ne Frisur! Ist das f\u00fcr den Karneval?\nB: Ja, eine Karnevalsfrisur mit Gl\u00fccksstr\u00e4hnen.\nA: Kreative Frisuren geh\u00f6ren zum Karneval.\nB: Nach dem Fest brauche ich eine neue Frisur.",exampleSrc:"A: Nice hairstyle! Is that for carnival?\nB: Yes, a carnival hairstyle with glitter streaks.\nA: Creative hairstyles are part of carnival.\nB: After the party I'll need a new hairstyle.",funFact:"Karneval Frisuren range from elaborate wigs to spray-painted mohawks. 'Sch\u00f6ne Frisur!' is a genuine compliment in German."},
{type:"teach",trg:"der Coiffeur",src:"the hairdresser (Swiss German)",pos:"noun",gender:"m",note:"Masculine noun. Swiss German for Friseur.\nDirectly from French.",example:"A: In der Schweiz sagt man 'Coiffeur.'\nB: Und in Deutschland 'Friseur.'\nA: Beide aus dem Franz\u00f6sischen.\nB: Die Schweiz liebt franz\u00f6sische W\u00f6rter.",exampleSrc:"A: In Switzerland they say 'Coiffeur.'\nB: And in Germany 'Friseur.'\nA: Both from French.\nB: Switzerland loves French words.",funFact:"In Switzerland, you go to the Coiffeur, not the Friseur. Same job, French word, Swiss identity."},
{type:"teach",trg:"die Coiffeuse",src:"the hairdresser (female, Swiss)",pos:"noun",gender:"f",note:"Feminine noun. French feminine form.\nOne of few profession pairs using a French feminine instead of -in.",example:"A: Die Coiffeuse schneidet mir die Haare.\nB: Nicht 'Friseurin'?\nA: In der Schweiz: Coiffeuse.\nB: Jedes Land hat seine eigenen W\u00f6rter.",exampleSrc:"A: The hairdresser cuts my hair.\nB: Not 'Friseurin'?\nA: In Switzerland: Coiffeuse.\nB: Every country has its own words.",funFact:"One of the few profession pairs that uses a French feminine form instead of the German -in suffix. Swiss German identity in one word."},
{type:"teach",trg:"der Bart",src:"the beard",pos:"noun",gender:"m",note:"Masculine noun. Same root as English 'beard.'\n'Sich einen Bart wachsen lassen' = to grow a beard.",example:"A: Ist das ein echter Bart?\nB: Nein, ein Karnevalsbart!\nA: Falsche B\u00e4rte sind das beliebteste Accessoire.\nB: Nach den H\u00fcten.",exampleSrc:"A: Is that a real beard?\nB: No, a carnival beard!\nA: Fake beards are the most popular accessory.\nB: After hats.",funFact:"Fake B\u00e4rte (beards) are the most popular Karneval accessory after hats. 'Sich einen Bart wachsen lassen' = to grow a beard."},
{type:"teach",trg:"die Socke",src:"the sock",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'soccus' (light shoe).\n'Von den Socken sein' = to be blown away.",example:"A: Bunte Socken zum Kost\u00fcm?\nB: Nat\u00fcrlich! Alles muss bunt sein.\nA: Ich bin von den Socken!\nB: Das hei\u00dft, du bist \u00fcberrascht.",exampleSrc:"A: Colorful socks with the costume?\nB: Of course! Everything has to be colorful.\nA: I'm knocked off my socks!\nB: That means you're surprised.",funFact:"'Von den Socken sein' means to be blown away, literally 'knocked off your socks.' Karneval will leave you von den Socken."},
{type:"teach",trg:"der Strumpf",src:"the stocking",pos:"noun",gender:"m",note:"Masculine noun. Strumpfhosen (tights) are part of many Karneval costumes.\n'Pippi Langstrumpf' is named after her long stockings.",example:"A: Wer ist Pippi Langstrumpf?\nB: Ein schwedisches M\u00e4dchen mit langen Str\u00fcmpfen.\nA: Langstrumpf bedeutet 'long stocking'?\nB: Genau! Das st\u00e4rkste M\u00e4dchen der Welt.",exampleSrc:"A: Who is Pippi Longstocking?\nB: A Swedish girl with long stockings.\nA: Langstrumpf means 'long stocking'?\nB: Exactly! The strongest girl in the world.",funFact:"'Pippi Langstrumpf' (Pippi Longstocking) is named after her long stockings. Germans love this character. Strumpfhosen are part of many costumes."},
{type:"teach",trg:"der K\u00f6nig",src:"the king",pos:"noun",gender:"m",note:"Masculine noun. From Old High German 'kuning.'\n'Der Kunde ist K\u00f6nig' (The customer is king).",example:"A: Wer ist der K\u00f6nig des Karnevals?\nB: Es gibt einen Prinzen, keinen K\u00f6nig.\nA: Warum keinen K\u00f6nig?\nB: Karneval parodiert die Macht. Prinz reicht.",exampleSrc:"A: Who is the king of carnival?\nB: There's a prince, not a king.\nA: Why no king?\nB: Carnival parodies power. A prince is enough.",funFact:"Carnival has a Prinz (prince), not a K\u00f6nig. K\u00f6nig appears everywhere in German culture: 'Der Kunde ist K\u00f6nig' (The customer is king)."},
{type:"teach",trg:"f\u00e4rbig",src:"colored, colorful",pos:"adj",gender:null,note:"From 'Farbe' (color) + '-ig.' Variant of 'farbig.'\nMore southern German. Both forms are correct.",example:"A: Die Stra\u00dfen sind so f\u00e4rbig!\nB: Man sagt auch 'farbig.'\nA: Beides ist richtig?\nB: Ja, Deutsch hat oft zwei Formen.",exampleSrc:"A: The streets are so colorful!\nB: You can also say 'farbig.'\nA: Both are correct?\nB: Yes, German often has two forms.",funFact:"F\u00e4rbig is more southern, farbig more northern. Both mean 'colorful.' Having two forms for the same word is typically German."},
{type:"teach",trg:"farbig",src:"colored, colorful",pos:"adj",gender:null,note:"From 'Farbe' + '-ig.' Variant of 'f\u00e4rbig.'\nMore northern German. Both are correct.",example:"A: Karneval ist das farbigste Fest.\nB: So viele Farben auf einmal.\nA: Farbig und laut und verr\u00fcckt.\nB: Genau so soll es sein.",exampleSrc:"A: Carnival is the most colorful festival.\nB: So many colors at once.\nA: Colorful and loud and crazy.\nB: That's exactly how it should be.",funFact:"The difference is regional: f\u00e4rbig is more southern, farbig more northern. Both mean 'colorful.' Karneval is the most farbig event in Germany."},
{type:"teach",trg:"stilistisch",src:"stylistic",pos:"adj",gender:null,note:"From 'Stil' (style) + '-istisch.'\nUsed for art, writing, and fashion criticism.",example:"A: Das Kost\u00fcm ist stilistisch perfekt.\nB: Jedes Detail stimmt.\nA: Stilistisch durchdacht.\nB: Kunst am K\u00f6rper.",exampleSrc:"A: The costume is stylistically perfect.\nB: Every detail is right.\nA: Stylistically thought through.\nB: Art on the body.",funFact:"Used for art, writing, and fashion criticism. The best Karneval costumes are stilistisch durchdacht (stylistically thought through)."},
{type:"teach",trg:"k\u00fcrzlich",src:"recently",pos:"adv",gender:null,note:"From 'kurz' (short) + '-lich.'\nSomething that happened a short time ago.",example:"A: K\u00fcrzlich war ich in K\u00f6ln.\nB: Beim Karneval?\nA: Ja, k\u00fcrzlich erst. Letzte Woche.\nB: Und? Wie war es?",exampleSrc:"A: Recently I was in Cologne.\nB: At carnival?\nA: Yes, just recently. Last week.\nB: And? How was it?",funFact:"From 'kurz' (short) + '-lich.' Something that happened a short time ago. An adverb of recent time."},
{type:"teach",trg:"doppelt",src:"double",pos:"adj",gender:null,note:"From 'doppel-.' 'Doppelt gemoppelt' = redundant.\nSome people wear doppelte Kost\u00fcme: two characters in one.",example:"A: Doppelt so viel Konfetti wie letztes Jahr!\nB: Doppelt so laut, doppelt so bunt.\nA: Alles war doppelt so gut.\nB: Doppelt gemoppelt? Nein, doppelt genie\u00dfen!",exampleSrc:"A: Double the confetti compared to last year!\nB: Twice as loud, twice as colorful.\nA: Everything was twice as good.\nB: Redundant? No, double the enjoyment!",funFact:"'Doppelt gemoppelt' (doubly done, redundant) is a fun German saying. Some people wear doppelte costumes: two characters in one outfit."},
{type:"teach",trg:"neulich",src:"recently, the other day",pos:"adv",gender:null,note:"From 'neu' (new) + '-lich.' Similar to k\u00fcrzlich but more conversational.\nWarm, storytelling register.",example:"A: Neulich habe ich Mia getroffen.\nB: Ach ja? Wo denn?\nA: Beim Karneval in K\u00f6ln.\nB: Neulich war ich auch dort!",exampleSrc:"A: The other day I met Mia.\nB: Really? Where?\nA: At carnival in Cologne.\nB: The other day I was there too!",funFact:"Similar to k\u00fcrzlich but more conversational and warm. 'Neulich habe ich Mia getroffen' has a storytelling quality."},
{type:"teach",trg:"irgendwann",src:"someday, at some point",pos:"adv",gender:null,note:"Irgend- (some-) + wann (when).\nIrgend- makes question words indefinite: irgendwo, irgendwer.",example:"A: Kommst du irgendwann wieder nach K\u00f6ln?\nB: Irgendwann bestimmt!\nA: Vielleicht n\u00e4chstes Jahr?\nB: Irgendwann, versprochen.",exampleSrc:"A: Will you come back to Cologne someday?\nB: Someday for sure!\nA: Maybe next year?\nB: Someday, I promise.",funFact:"Irgend- is a prefix that makes question words indefinite: irgendwann (sometime), irgendwo (somewhere), irgendwer (someone)."},
{type:"teach",trg:"sowieso",src:"anyway, regardless",pos:"part",gender:null,note:"A very common filler in spoken German.\nThree syllables: so-wie-so. Shrugs off objections.",example:"A: Sollen wir ein Taxi nehmen?\nB: Das wollte ich sowieso vorschlagen.\nA: Ich bin sowieso m\u00fcde.\nB: Nach dem Karneval ist man sowieso m\u00fcde.",exampleSrc:"A: Should we take a taxi?\nB: I was going to suggest that anyway.\nA: I'm tired anyway.\nB: After carnival you're tired anyway.",funFact:"A very common filler in spoken German. Three syllables: so-wie-so. Shrugs off objections elegantly."},
{type:"teach",trg:"rasieren",src:"to shave",pos:"verb",gender:null,note:"'Sich rasieren' (to shave oneself). From French 'raser.'\nAfter Karneval, men discover glitter under fake beards.",example:"A: Ich muss mich rasieren.\nB: Den Karnevalsbart abrasieren?\nA: Ja, und darunter ist Glitzer.\nB: Glitzer geht nie ganz weg.",exampleSrc:"A: I need to shave.\nB: Shave off the carnival beard?\nA: Yes, and underneath there's glitter.\nB: Glitter never fully goes away.",funFact:"After Karneval, many men rasieren off their fake beards and discover glitter underneath that lasts for weeks."},
{type:"teach",trg:"vergn\u00fcgen",src:"to enjoy, to amuse (reflexive)",pos:"verb",gender:null,note:"'Sich vergn\u00fcgen' (to enjoy oneself). The verb form of Vergn\u00fcgen.\nPast participle 'vergn\u00fcgt' doubles as an adjective.",example:"A: Habt ihr euch vergn\u00fcgt?\nB: Ja, wir haben uns k\u00f6stlich vergn\u00fcgt!\nA: Man kann sich immer vergn\u00fcgen.\nB: Beim Karneval besonders.",exampleSrc:"A: Did you enjoy yourselves?\nB: Yes, we had a wonderful time!\nA: You can always enjoy yourself.\nB: At carnival especially.",funFact:"Reflexive: 'sich vergn\u00fcgen.' The past participle 'vergn\u00fcgt' doubles as an adjective meaning cheerful or amused."},
{type:"teach",trg:"faulenzen",src:"to laze around",pos:"verb",gender:null,note:"From 'faul' (lazy) + '-enzen.'\nA guilt-free verb. Everyone deserves to faulenzen sometimes.",example:"A: Was machst du morgen?\nB: Faulenzen. Den ganzen Tag.\nA: Nach dem Karneval verdient man das.\nB: Faulenzen ist die beste Medizin.",exampleSrc:"A: What are you doing tomorrow?\nB: Lazing around. All day.\nA: After carnival you deserve that.\nB: Lazing around is the best medicine.",funFact:"From 'faul' (lazy) + '-enzen.' A guilt-free verb. 'Nach dem Karneval faulenze ich den ganzen Tag.'"},
{type:"teach",trg:"tauchen",src:"to dive",pos:"verb",gender:null,note:"'Ins Wasser tauchen' (to dive into water).\n'Auftauchen' = to surface/appear.",example:"A: Beim Karneval taucht man in die Menge ein.\nB: Und nach dem Karneval taucht man wieder auf.\nA: Eintauchen und auftauchen.\nB: Wie ein Taucher im Meer der Freude.",exampleSrc:"A: At carnival you dive into the crowd.\nB: And after carnival you surface again.\nA: Diving in and surfacing.\nB: Like a diver in a sea of joy.",funFact:"Also 'auftauchen' (to surface/appear). At Karneval, man taucht ein in die Menge (one dives into the crowd). Both literal and figurative."},
{type:"teach",trg:"zelten",src:"to camp",pos:"verb",gender:null,note:"From 'Zelt' (tent). Regular verb.\nDie-hard fans zelten overnight along the parade route.",example:"A: Manche Leute zelten am Stra\u00dfenrand.\nB: \u00dcber Nacht? F\u00fcr den besten Platz?\nA: Ja! Zelten f\u00fcr den Rosenmontagszug.\nB: Das ist wahrer Karnevalsgeist.",exampleSrc:"A: Some people camp on the roadside.\nB: Overnight? For the best spot?\nA: Yes! Camping for the Rose Monday parade.\nB: That's true carnival spirit.",funFact:"Some die-hard carnival fans zelten along the parade route overnight to get the best spots for the Rosenmontagszug."},
{type:"teach",trg:"zuschauen",src:"to watch",pos:"verb",gender:null,note:"Separable verb. Zu (at) + schauen (to look).\nSynonym of zugucken. 'Ich schaue gerne zu.'",example:"A: Ich schaue gerne zu.\nB: Beim Karneval kann man nicht nur zuschauen.\nA: Man muss mitmachen?\nB: Genau! Zuschauen reicht nicht.",exampleSrc:"A: I like to watch.\nB: At carnival you can't just watch.\nA: You have to join in?\nB: Exactly! Watching isn't enough.",funFact:"Synonym of zugucken. Separable: 'Ich schaue gerne zu.' The zu- prefix means 'at/toward.'"},
{type:"teach",trg:"vergn\u00fcgt",src:"amused, cheerful",pos:"adj",gender:null,note:"Past participle of vergn\u00fcgen used as adjective.\n'Sie sieht vergn\u00fcgt aus' (She looks cheerful).",example:"A: Du siehst vergn\u00fcgt aus.\nB: Bin ich auch! Karneval war toll.\nA: Verumius f\u00fchlt sich vergn\u00fcgt.\nB: Vergn\u00fcgt und m\u00fcde. Die beste Kombination.",exampleSrc:"A: You look cheerful.\nB: I am! Carnival was great.\nA: Verumius feels amused.\nB: Cheerful and tired. The best combination.",funFact:"Past participle of vergn\u00fcgen used as adjective. Vergn\u00fcgt is how Verumius feels: amused, cheerful, deeply satisfied."},
{type:"teach",trg:"aller-",src:"(prefix) of all, the very (superlative amplifier)",pos:"part",gender:null,note:"Prefix that amplifies superlatives to maximum.\naller- + best = allerbest (the very best of all).",example:"A: Das war der allerbeste Tag!\nB: Und das allersch\u00f6nste Erlebnis.\nA: Aller- macht alles noch intensiver.\nB: Das allerwichtigste Wort beim Karneval: Alaaf!",exampleSrc:"A: That was the very best day!\nB: And the most beautiful experience of all.\nA: Aller- makes everything even more intense.\nB: The most important word at carnival: Alaaf!",funFact:"Aller- cranks any superlative to maximum: allerbest, allersch\u00f6nst, allerwichtigst. You can attach it to any superlative in German."},
{type:"teach",trg:"doppel-",src:"(prefix) double",pos:"part",gender:null,note:"Prefix meaning 'double.' Builds compounds freely.\ndoppel- + Punkt = Doppelpunkt (colon).",example:"A: Ein Doppelzimmer, bitte.\nB: Doppel- bedeutet immer 'zwei.'\nA: Doppelt gemoppelt!\nB: Das hei\u00dft: unn\u00f6tig wiederholt.",exampleSrc:"A: A double room, please.\nB: Doppel- always means 'two.'\nA: Doubly done!\nB: That means: unnecessarily repeated.",funFact:"Builds compounds freely: Doppelzimmer (double room), Doppelpunkt (colon), Doppelg\u00e4nger (a word English borrowed directly from German)."},
{type:"teach",trg:"wieder-",src:"(prefix) again, re-",pos:"part",gender:null,note:"Prefix meaning 'again.' Separable in most verbs.\nwiedersehen = to see again, wiederholen = to repeat.",example:"A: Wir sehen uns wieder!\nB: Wiedersehen beim n\u00e4chsten Karneval?\nA: Auf Wiedersehen!\nB: Bis wir uns wiedersehen!",exampleSrc:"A: We'll see each other again!\nB: See you again at the next carnival?\nA: Goodbye! (lit: until seeing again)\nB: Until we see each other again!",funFact:"'Auf Wiedersehen' (goodbye) literally means 'until seeing again.' Wieder- as a prefix adds 'again' to any verb: wiederkommen, wiederfinden, wiederholen."},
{type:"teach",trg:"zusammen-",src:"(prefix) together",pos:"part",gender:null,note:"Prefix meaning 'together.' Very productive in German.\nzusammenarbeiten = to work together, zusammenleben = to live together.",example:"A: Zusammen feiern ist sch\u00f6ner.\nB: Zusammen singen, zusammen tanzen.\nA: Zusammen ist alles besser.\nB: Das ist die Botschaft des Karnevals.",exampleSrc:"A: Celebrating together is nicer.\nB: Singing together, dancing together.\nA: Together everything is better.\nB: That's the message of carnival.",funFact:"Very productive: zusammenarbeiten (work together), zusammenleben (live together), zusammenhalten (hold together). Karneval is all about zusammen."},
{type:"tip",title:"Drei Karnevale, ein Land",text:"Karneval (Rheinland: K\u00f6ln, D\u00fcsseldorf, Mainz)\nFasching (Bayern, \u00d6sterreich)\nFasnacht (Schweiz, S\u00fcdwestdeutschland)\n\nGleiche Feier, verschiedene Namen, verschiedene Traditionen.\nK\u00f6lns Karneval ist der gr\u00f6\u00dfte: \u00fcber 1 Million Menschen am Rosenmontag.\nBasels Fasnacht beginnt um 4 Uhr morgens in der Dunkelheit.\nM\u00fcnchens Fasching ist familienfreundlich.\nDas Rheinland hat das organisierte Karnevalschaos erfunden.\nJede Region besteht darauf, dass ihre Version die beste ist.",deepDive:{title:"Karnevalsgesellschaften",text:"Karneval ist nicht spontan. Hinter der Chaos stecken 'Karnevalsgesellschaften' (carnival societies): Vereine, die das ganze Jahr Karneval planen.\n\nSie organisieren:\n- Sitzungen (formale Showabende)\n- Den Rosenmontagszug\n- Prinzenpaar-Wahlen\n- Karnevalslieder\n\nDie \u00e4ltesten Gesellschaften sind \u00fcber 200 Jahre alt. Mitglied zu werden ist eine Ehre. Die Hierarchie ist streng, aber der Spa\u00df ist es wert."}},
{type:"mc",q:"In M\u00fcnchen sagt man nicht 'Karneval.' Wie hei\u00dft es dort?",opts:["Helau","Fasnacht","Fasching","Alaaf"],ans:"Fasching",hint:"The Bavarian and Austrian word for the same celebration."},
{type:"fb",s:"Verumius f\u00e4hrt nach K\u00f6ln, {1} Karneval zu feiern.",a:["um"],opts:["um","ohne","statt","damit"],hint:"Purpose: the reason for traveling. Same subject.",sSrc:"Verumius goes to Cologne in order to celebrate carnival."},
{type:"mc",q:"'Verumius feiert die ganze Nacht, ohne m\u00fcde zu werden.' Was bedeutet das?",opts:["Er feiert die ganze Nacht, ohne m\u00fcde zu werden","Er feiert, statt zu schlafen","Er feiert, damit andere m\u00fcde werden","Er feiert, weil er m\u00fcde ist"],ans:"Er feiert die ganze Nacht, ohne m\u00fcde zu werden",hint:"Ohne means without. The action (getting tired) does NOT happen."},
{type:"mc",q:"'Mia singt laut, damit Verumius den Text lernt.' Warum damit und nicht um...zu?",opts:["Verschiedene Subjekte: Mia singt, Verumius lernt","Es gibt keinen Unterschied","Um...zu ist nur f\u00fcr Sport","Damit klingt formeller"],ans:"Verschiedene Subjekte: Mia singt, Verumius lernt",hint:"Two different people doing two different things. That requires damit."},
{type:"drag_fill",s:"Verumius reist nach K\u00f6ln, {1} Karneval zu erleben, {2} die Regeln zu kennen, und Mia erkl\u00e4rt alles, {3} er sich nicht irrt.",blanks:{"1":"um","2":"ohne","3":"damit"},pool:["um","ohne","damit","statt","weil","obwohl"],hint:"Purpose (in order to), absence (without knowing), different subject (so that he doesn't make mistakes).",sSrc:"Verumius travels to Cologne in order to experience carnival, without knowing the rules, and Mia explains everything so that he doesn't make mistakes."},
{type:"match",pairs:[{trg:"Vergn\u00fcgen",src:"pleasure"},{trg:"Unterhaltung",src:"entertainment"},{trg:"Neuigkeit",src:"news"},{trg:"Tradition",src:"tradition"}]},
{type:"mc",q:"Statt den ganzen Tag zu faulenzen, geht Mia zum Karneval. Was macht Mia?",opts:["Sie faulenzt beim Karneval","Sie geht zum Karneval statt zu faulenzen","Sie faulenzt statt zum Karneval zu gehen","Sie geht, weil sie faul ist"],ans:"Sie geht zum Karneval statt zu faulenzen",hint:"Statt introduces what is NOT done. The main clause says what IS done."}
]}

]},

{n:18,lang:"de",srcLang:"en",track:"v2",title:"Im Biergarten",sub:"Beer garden, Spargelzeit, als vs wenn, fixed prepositions, da-/wo- compounds",icon:"\uD83C\uDF7A",level:"B1.2",color:"#7B5EE8",lessons:[

// ─── Lesson 1: Unter den Kastanien ───────────────────────────────────
{id:"deu_r18l1",title:"Unter den Kastanien",icon:"\uD83C\uDF33",xp:15,board:true,steps:[
{type:"intro",title:"Unter den Kastanien",desc:"A Berlin Biergarten in late June. Golden light through chestnut leaves. Fairy lights, grilled sausages, clinking beer steins. Time to learn how Germans socialize outdoors.",goals:["Learn 18 restaurant and socializing words","Meet the full cast for a summer evening together","Express hunger, thirst, and satisfaction"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-ber-biergarten-entrance",trg:"Ein Berliner Biergarten im sp\u00e4ten Juni. Goldenes Licht f\u00e4llt durch die Bl\u00e4tter der Kastanienb\u00e4ume. Lichterketten leuchten schon. Lange Holzb\u00e4nke, der Geruch von gegrillten W\u00fcrstchen, das Klirren von Bierkr\u00fcgen. Hildi sitzt an einem reservierten Tisch, die Arme verschr\u00e4nkt, und beobachtet den Eingang.",src:"A Berlin beer garden in late June. Golden light falls through the chestnut tree leaves. Fairy lights are already glowing. Long wooden benches, the smell of grilled sausages, the clink of beer steins. Hildi sits at a reserved table, arms folded, watching the entrance."},
{type:"story",speaker:"hildi",mood:"pleased",art:"de-ber-biergarten-table",trg:"Hier! Ich habe den besten Tisch reserviert. Unter den alten Kastanien. Als ich jung war, gab es hier nur drei Bierg\u00e4rten in ganz Berlin.",src:"Here! I reserved the best table. Under the old chestnut trees. When I was young, there were only three beer gardens in all of Berlin."},
{type:"story",speaker:"verumius",mood:"happy",trg:"Es ist wundersch\u00f6n hier. So gem\u00fctlich. Ich freue mich auf den Abend.",src:"It is beautiful here. So cozy. I am looking forward to the evening."},
{type:"story",speaker:"mia",mood:"energetic",trg:"Entschuldigung, ich komme direkt vom Lauftreff. Ich bin so durstig! Und hungrig. Beides.",src:"Sorry, I am coming straight from the running group. I am so thirsty! And hungry. Both."},
{type:"story",speaker:"narrator",mood:"curious",trg:"Lukas kommt als Letzter. Er tr\u00e4gt etwas Ungew\u00f6hnliches auf dem R\u00fccken: einen Gitarrenkoffer. Niemand sagt etwas, aber Mia hebt eine Augenbraue.",src:"Lukas arrives last. He is carrying something unusual on his back: a guitar case. Nobody says anything, but Mia raises an eyebrow."},
{type:"teach",trg:"die Terrasse",src:"the terrace, the patio",pos:"noun",gender:"f",note:"An outdoor dining area. Bierg\u00e4rten have their own tradition, but both mean eating outside.",example:"A: Sollen wir drinnen oder auf der Terrasse sitzen?\nB: Auf der Terrasse! Das Wetter ist perfekt.\nA: Gut, ich sehe noch einen freien Tisch.\nB: Schnell, bevor ihn jemand nimmt!",exampleSrc:"A: Should we sit inside or on the terrace?\nB: On the terrace! The weather is perfect.\nA: Good, I see a free table.\nB: Quick, before someone takes it!",funFact:"From French 'terrasse.' Germans flock outdoors the moment the sun appears. Bierg\u00e4rten technically have their own traditions separate from a Terrasse, but both mean eating outside."},
{type:"teach",trg:"der Treffpunkt",src:"the meeting point",pos:"noun",gender:"m",note:"'Treff' (meeting) + 'Punkt' (point). Every friend group has one.",example:"A: Wo ist unser Treffpunkt heute?\nB: Im Biergarten, unter den Kastanien.\nA: Gut, ich bin in zehn Minuten da.\nB: Hildi wartet schon!",exampleSrc:"A: Where is our meeting point today?\nB: In the beer garden, under the chestnut trees.\nA: Good, I will be there in ten minutes.\nB: Hildi is already waiting!",funFact:"'Treff' (meeting) + 'Punkt' (point). Every German friend group has their Treffpunkt. The Biergarten in summer is the ultimate one."},
{type:"teach",trg:"der Wirt",src:"the innkeeper, the landlord",pos:"noun",gender:"m",note:"From Old High German 'wirt' (host). Runs the whole Biergarten operation.",example:"A: Wer ist der Wirt hier?\nB: Der Mann mit der Sch\u00fcrze da dr\u00fcben.\nA: Er sieht freundlich aus.\nB: Ja, er kennt alle Stammg\u00e4ste beim Namen.",exampleSrc:"A: Who is the innkeeper here?\nB: The man with the apron over there.\nA: He looks friendly.\nB: Yes, he knows all the regulars by name.",funFact:"The pub landlord. From Old High German 'wirt' (host). A Biergartenwirt runs the whole operation. Related to English 'worth' through the idea of hospitality."},
{type:"teach",trg:"die Wirtin",src:"the innkeeper (female)",pos:"noun",gender:"f",note:"The -in suffix marks feminine. Many famous Berlin Wirtinnen have run legendary beer gardens.",example:"A: Die Wirtin hat uns begr\u00fc\u00dft.\nB: Ja, sie ist hier seit zwanzig Jahren.\nA: Sie kennt wirklich jeden.\nB: Das macht einen guten Biergarten aus.",exampleSrc:"A: The innkeeper greeted us.\nB: Yes, she has been here for twenty years.\nA: She really knows everyone.\nB: That is what makes a good beer garden.",funFact:"Female innkeeper. The -in suffix. Many famous Berlin Wirtinnen have run legendary beer gardens for decades. 'Die Wirtin' is also the title of a famous German folk song."},
{type:"teach",trg:"der Kellner",src:"the waiter",pos:"noun",gender:"m",note:"From 'Keller' (cellar). Originally the person who brought drinks up from the cellar.",example:"A: Wo ist unser Kellner?\nB: Ich glaube, er bedient den Tisch da dr\u00fcben.\nA: Wir warten schon zehn Minuten.\nB: Im Biergarten muss man geduldig sein.",exampleSrc:"A: Where is our waiter?\nB: I think he is serving the table over there.\nA: We have been waiting ten minutes.\nB: In a beer garden you have to be patient.",funFact:"From 'Keller' (cellar). A waiter was originally the person who brought drinks up from the cellar. In Bavaria, you might hear 'Bedienung!' (Service!) instead of calling the Kellner."},
{type:"teach",trg:"die Kellnerin",src:"the waitress",pos:"noun",gender:"f",note:"Female server. In a traditional Biergarten, she carries multiple one-liter beer steins at once.",example:"A: Die Kellnerin ist unglaublich schnell.\nB: Siehst du, wie viele Bierkr\u00fcge sie tr\u00e4gt?\nA: Vier auf einmal!\nB: Das ist noch gar nichts f\u00fcr einen Biergarten.",exampleSrc:"A: The waitress is incredibly fast.\nB: Do you see how many beer steins she is carrying?\nA: Four at once!\nB: That is nothing for a beer garden.",funFact:"Female server. In a traditional Biergarten, the Kellnerin carries multiple one-liter beer steins at once. The record is 29 steins carried at once by a Bavarian Kellnerin."},
{type:"teach",trg:"der Ober",src:"the waiter (formal)",pos:"noun",gender:"m",note:"Short for 'Oberkellner' (head waiter). An older, more formal word.",example:"A: Herr Ober, die Speisekarte bitte!\nB: Sofort, mein Herr.\nA: Und bringen Sie bitte auch Wasser.\nB: Nat\u00fcrlich, stilles oder mit Kohlens\u00e4ure?",exampleSrc:"A: Waiter, the menu please!\nB: Right away, sir.\nA: And please bring water too.\nB: Of course, still or sparkling?",funFact:"Short for 'Oberkellner' (head waiter). An older, more formal word. 'Herr Ober!' is how you call a waiter in a traditional Austrian or South German restaurant."},
{type:"teach",trg:"das Trinkgeld",src:"the tip",pos:"noun",gender:"n",note:"'Trink' (drink) + 'Geld' (money). In Germany, tipping is 5-10%.",example:"A: Wie viel Trinkgeld gibt man in Deutschland?\nB: Normalerweise f\u00fcnf bis zehn Prozent.\nA: Das ist weniger als in Amerika.\nB: Ja, aber Kellner verdienen hier mehr Grundgehalt.",exampleSrc:"A: How much tip do you give in Germany?\nB: Usually five to ten percent.\nA: That is less than in America.\nB: Yes, but waiters earn more base salary here.",funFact:"'Trink' (drink) + 'Geld' (money). Tip money was originally money so the server could buy themselves a drink. In Germany, tipping is 5-10%, not the 15-20% common in the US."},
{type:"teach",trg:"der Grill",src:"the grill, the barbecue",pos:"noun",gender:"m",note:"Same word as English. Germans grill obsessively in summer.",example:"A: Riechst du den Grill?\nB: Ja, Bratwurst und Steaks!\nA: Ich will auch etwas vom Grill.\nB: Dann gehen wir zur Grillstation.",exampleSrc:"A: Do you smell the grill?\nB: Yes, bratwurst and steaks!\nA: I want something from the grill too.\nB: Then let us go to the grill station.",funFact:"Same word as English. Germans grill obsessively in summer. 'Grillen' (to barbecue) is practically a national sport. A Biergarten often has a Grillstation with Bratwurst and Steaks."},
{type:"teach",trg:"die Scheibe",src:"the slice, the disk, the pane",pos:"noun",gender:"f",note:"Anything flat and round or flat and thin. 'Eine Scheibe Brot' = a slice of bread.",example:"A: M\u00f6chtest du eine Scheibe Brot?\nB: Ja, bitte, mit Butter.\nA: Und eine Scheibe K\u00e4se dazu?\nB: Perfekt, danke!",exampleSrc:"A: Would you like a slice of bread?\nB: Yes, please, with butter.\nA: And a slice of cheese with it?\nB: Perfect, thanks!",funFact:"A slice, disk, or pane. 'Eine Scheibe Brot' (a slice of bread). Also 'Windschutzscheibe' (windshield). The word covers anything flat and round or flat and thin."},
{type:"teach",trg:"die Mahlzeit",src:"the meal, the mealtime",pos:"noun",gender:"f",note:"'Mahl' (meal) + 'Zeit' (time). Also a noon greeting among coworkers.",example:"A: Mahlzeit!\nB: Mahlzeit! Gehst du auch in die Kantine?\nA: Ja, ich brauche eine warme Mahlzeit.\nB: Ich auch. Heute gibt es Schnitzel.",exampleSrc:"A: Bon appetit! (noon greeting)\nB: Bon appetit! Are you going to the cafeteria too?\nA: Yes, I need a warm meal.\nB: Me too. Today they have schnitzel.",funFact:"'Mahl' (meal) + 'Zeit' (time). Also a greeting: saying 'Mahlzeit!' around noon is how German coworkers greet each other at lunch. It is simultaneously a word and a social ritual."},
{type:"teach",trg:"gem\u00fctlich",src:"cozy, comfortable, convivial",pos:"adj",gender:null,note:"Possibly the most untranslatable German word. No single English word captures it.",example:"A: Der Biergarten ist wirklich gem\u00fctlich.\nB: Ja, die Lichterketten machen alles so sch\u00f6n.\nA: Und die alten Kastanienb\u00e4ume.\nB: Das ist typisch deutsch: Gem\u00fctlichkeit im Freien.",exampleSrc:"A: The beer garden is really cozy.\nB: Yes, the fairy lights make everything so pretty.\nA: And the old chestnut trees.\nB: That is typically German: coziness outdoors.",funFact:"Possibly the most untranslatable German word. Cozy, comfortable, convivial, warm, relaxed. A Biergarten under chestnut trees on a summer evening is the definition of gem\u00fctlich. No single English word captures it."},
{type:"teach",trg:"durstig",src:"thirsty",pos:"adj",gender:null,note:"From 'Durst' (thirst). The -ig suffix turns nouns into adjectives.",example:"A: Bist du durstig?\nB: Ja, sehr! Ich brauche ein gro\u00dfes Bier.\nA: Oder ein Wasser?\nB: Erst das Bier, dann das Wasser.",exampleSrc:"A: Are you thirsty?\nB: Yes, very! I need a big beer.\nA: Or a water?\nB: First the beer, then the water.",funFact:"From 'Durst' (thirst). 'Ich bin durstig' is survival vocabulary in any Biergarten. The -ig suffix turns nouns into adjectives: Durst becomes durstig, Hunger becomes hungrig."},
{type:"teach",trg:"hungrig",src:"hungry",pos:"adj",gender:null,note:"From 'Hunger.' Same pattern as durstig. Cognate with English 'hungry.'",example:"A: Ich bin so hungrig!\nB: Wollen wir etwas bestellen?\nA: Ja, sofort. Eine Bratwurst vom Grill.\nB: Und Kartoffelsalat dazu.",exampleSrc:"A: I am so hungry!\nB: Shall we order something?\nA: Yes, right away. A bratwurst from the grill.\nB: And potato salad with it.",funFact:"From 'Hunger.' Same pattern as durstig. 'Bist du hungrig?' is the question that starts every Biergarten evening. Cognate with English 'hungry.'"},
{type:"teach",trg:"satt",src:"full, satisfied (after eating)",pos:"adj",gender:null,note:"'Ich bin satt' = I have had enough. The opposite of hungrig.",example:"A: M\u00f6chtest du noch etwas?\nB: Nein danke, ich bin satt.\nA: Wirklich? Es gibt noch Kuchen.\nB: Na gut, ein kleines St\u00fcck vielleicht.",exampleSrc:"A: Would you like more?\nB: No thanks, I am full.\nA: Really? There is still cake.\nB: Well, a small piece maybe.",funFact:"Full, satisfied (after eating). 'Ich bin satt' means you have had enough. Germans say 'satt' not 'voll' for food fullness. 'Voll' means drunk."},
{type:"teach",trg:"genie\u00dfen",src:"to enjoy, to savor",pos:"verb",gender:null,note:"Irregular strong verb (genoss, genossen). 'Genie\u00dfe den Abend!'",example:"A: Genie\u00dft du den Abend?\nB: Ja, sehr! Das Essen ist toll.\nA: Und die Musik erst!\nB: Ich genie\u00dfe jeden Moment.",exampleSrc:"A: Are you enjoying the evening?\nB: Yes, very much! The food is great.\nA: And the music!\nB: I am savoring every moment.",funFact:"To enjoy, to savor. An irregular strong verb (genoss, genossen). From the same root as 'Genuss' (pleasure/enjoyment). A word for conscious, deliberate enjoyment."},
{type:"teach",trg:"spazieren gehen",src:"to go for a walk",pos:"verb",gender:null,note:"A separable verb phrase. 'Wir gehen spazieren.' From Italian 'spaziare.'",example:"A: Wollen wir nach dem Essen spazieren gehen?\nB: Gute Idee! Durch den Park.\nA: Der Abend ist so sch\u00f6n.\nB: Ja, ein Spaziergang nach dem Essen ist gesund.",exampleSrc:"A: Shall we go for a walk after dinner?\nB: Good idea! Through the park.\nA: The evening is so beautiful.\nB: Yes, a walk after dinner is healthy.",funFact:"A separable verb phrase. From Italian 'spaziare' (to take space). The German evening walk (Spaziergang) is a cultural institution."},
{type:"teach",trg:"prost",src:"cheers",pos:"intj",gender:null,note:"From Latin 'prosit' (may it be beneficial). You MUST make eye contact when clinking glasses.",example:"A: Prost!\nB: Prost! Auf einen sch\u00f6nen Abend!\nA: Vergiss nicht: Augenkontakt!\nB: Stimmt, sonst gibt es sieben Jahre Pech.",exampleSrc:"A: Cheers!\nB: Cheers! To a lovely evening!\nA: Do not forget: eye contact!\nB: True, otherwise seven years of bad luck.",funFact:"From Latin 'prosit' (may it be beneficial). The universal German toast. You MUST make eye contact when clinking glasses. Not doing so supposedly brings seven years of bad luck."},
{type:"mc",q:"Mia kommt vom Lauftreff und sagt, sie ist sehr ___. Welches Wort beschreibt ihren Zustand?",opts:["satt","gem\u00fctlich","hungrig","durstig"],ans:"durstig",hint:"She wants something to drink first. This word comes from Durst."},
{type:"mc",q:"Was bedeutet 'Mahlzeit!', wenn ein Kollege es um die Mittagszeit sagt?",opts:["Es bedeutet Tsch\u00fcss","Es ist eine Entschuldigung","Es bedeutet Danke","Es ist ein Mittagsgru\u00df"],ans:"Es ist ein Mittagsgru\u00df",hint:"Mahl means meal, Zeit means time. Think about what happens at noon in German offices."},
{type:"fb",s:"Lukas, m\u00f6chtest du etwas trinken? -- Ja, ich bin sehr {1}!",a:["durstig"],opts:["durstig","hungrig","satt","gem\u00fctlich"],hint:"Lukas wants something to drink. Which adjective describes being thirsty?",sSrc:"Lukas, would you like something to drink? -- Yes, I am very thirsty!"}
]},

// ─── Lesson 2: Brotzeit und Bratwurst ────────────────────────────────
{id:"deu_r18l2",title:"Brotzeit und Bratwurst",icon:"\uD83C\uDF54",xp:15,board:true,steps:[
{type:"intro",title:"Brotzeit und Bratwurst",desc:"Time to fill the table. Learn kitchen equipment, ingredients, and food states. From Pfanne to Pflaume, from raw to cooked.",goals:["Name kitchen equipment and cooking vessels","Describe ingredients and their properties","Distinguish between raw and cooked food states"]},
{type:"teach",trg:"die Pfanne",src:"the pan, the skillet",pos:"noun",gender:"f",note:"From Latin 'patina.' 'Bratpfanne' (frying pan) is where Bratwurst gets its sizzle.",example:"A: Wo ist die Pfanne?\nB: Im Schrank, neben dem Herd.\nA: Ich brauche die gro\u00dfe Bratpfanne.\nB: Die mit dem schwarzen Griff?",exampleSrc:"A: Where is the pan?\nB: In the cabinet, next to the stove.\nA: I need the big frying pan.\nB: The one with the black handle?",funFact:"From Latin 'patina.' 'Bratpfanne' (frying pan) is where Bratwurst gets its sizzle. 'Etwas auf die Pfanne hauen' (to slap something on the pan) is slang for doing something boldly."},
{type:"teach",trg:"die Kanne",src:"the jug, the pot, the pitcher",pos:"noun",gender:"f",note:"'Kaffeekanne' (coffee pot), 'Teekanne' (teapot), 'Gie\u00dfkanne' (watering can).",example:"A: Soll ich eine Kanne Kaffee machen?\nB: Ja, bitte! Eine gro\u00dfe Kanne.\nA: Mit Milch?\nB: Nein, schwarz.",exampleSrc:"A: Shall I make a pot of coffee?\nB: Yes, please! A big pot.\nA: With milk?\nB: No, black.",funFact:"A jug, pot, or pitcher. 'Kaffeekanne' (coffee pot), 'Teekanne' (teapot), 'Gie\u00dfkanne' (watering can). The -kanne compounds cover every kind of pouring vessel."},
{type:"teach",trg:"die Sch\u00fcssel",src:"the bowl",pos:"noun",gender:"f",note:"From 'sch\u00fctten' (to pour). Not to be confused with 'Schl\u00fcssel' (key).",example:"A: Gib mir bitte die gro\u00dfe Sch\u00fcssel.\nB: F\u00fcr den Kartoffelsalat?\nA: Ja, wir brauchen viel Platz.\nB: Hier, die reicht bestimmt.",exampleSrc:"A: Please hand me the big bowl.\nB: For the potato salad?\nA: Yes, we need a lot of space.\nB: Here, this one should be enough.",funFact:"From 'sch\u00fctten' (to pour). A Sch\u00fcssel holds salads, soups, or Kartoffelsalat at the Biergarten. Not to be confused with 'Schl\u00fcssel' (key). One letter difference, completely different objects."},
{type:"teach",trg:"die Dose",src:"the can, the tin",pos:"noun",gender:"f",note:"'Konservendose' (canned food). 'Dosenbier' (canned beer) is the budget option.",example:"A: Hast du eine Dose Tomaten?\nB: Ja, im Regal oben.\nA: Und Dosenbier?\nB: Im K\u00fchlschrank, ganz unten.",exampleSrc:"A: Do you have a can of tomatoes?\nB: Yes, on the top shelf.\nA: And canned beer?\nB: In the fridge, right at the bottom.",funFact:"A can or tin. 'Konservendose' (canned food). In many German regions, Dose also means a small container or box. 'Dosenbier' (canned beer) is the budget option at any German park gathering."},
{type:"teach",trg:"die T\u00fcte",src:"the bag (paper or plastic)",pos:"noun",gender:"f",note:"'Eine T\u00fcte Chips' (a bag of chips). In southern Germany: 'Sackerl' or 'Sack.'",example:"A: Brauchen Sie eine T\u00fcte?\nB: Nein danke, ich habe meinen Beutel.\nA: In Berlin sagt man T\u00fcte, in M\u00fcnchen Sackerl.\nB: Und in der Schweiz?",exampleSrc:"A: Do you need a bag?\nB: No thanks, I have my own bag.\nA: In Berlin they say T\u00fcte, in Munich Sackerl.\nB: And in Switzerland?",funFact:"A bag (paper or plastic). In northern Germany, T\u00fcte is universal. In southern Germany and Austria, they say 'Sackerl' or 'Sack.' Regional vocabulary at its finest."},
{type:"teach",trg:"die Zutat",src:"the ingredient",pos:"noun",gender:"f",note:"'Zu' (to/added) + 'Tat' (deed). Something 'added to the deed' of cooking.",example:"A: Welche Zutaten brauchen wir?\nB: Mehl, Eier und Zucker.\nA: Haben wir alles?\nB: Wir brauchen noch Butter.",exampleSrc:"A: Which ingredients do we need?\nB: Flour, eggs, and sugar.\nA: Do we have everything?\nB: We still need butter.",funFact:"'Zu' (to/added) + 'Tat' (deed/action). An ingredient, literally something 'added to the deed' of cooking. 'Zutaten' (plural) is what every recipe lists first."},
{type:"teach",trg:"die Zwiebel",src:"the onion",pos:"noun",gender:"f",note:"From Latin 'cepulla' (small onion). In nearly every German dish.",example:"A: Kannst du die Zwiebeln schneiden?\nB: Ja, aber ich weine immer dabei.\nA: Versuch es mit einer Taucherbrille.\nB: Das ist nicht dein Ernst!",exampleSrc:"A: Can you cut the onions?\nB: Yes, but I always cry doing it.\nA: Try wearing swimming goggles.\nB: You are not serious!",funFact:"From Latin 'cepulla' (small onion). The Zwiebel is in nearly every German dish. 'Zwiebelkuchen' (onion tart) paired with Federwei\u00dfer (young wine) is an autumn tradition."},
{type:"teach",trg:"der Pfeffer",src:"the pepper",pos:"noun",gender:"m",note:"From Latin 'piper,' which came from Sanskrit. Same root as English 'pepper.'",example:"A: Kannst du mir den Pfeffer geben?\nB: Hier, bitte. Schwarzer oder wei\u00dfer?\nA: Schwarzer Pfeffer, frisch gemahlen.\nB: Das macht alles besser.",exampleSrc:"A: Can you pass me the pepper?\nB: Here you go. Black or white?\nA: Black pepper, freshly ground.\nB: That makes everything better.",funFact:"From Latin 'piper,' which came from Sanskrit. 'Geh dahin, wo der Pfeffer w\u00e4chst!' (Go where the pepper grows!) means 'Get lost!' because pepper came from far away."},
{type:"teach",trg:"das Mehl",src:"the flour",pos:"noun",gender:"n",note:"From Old High German 'melo' (ground grain). Related to English 'meal' and 'mill.'",example:"A: Wie viel Mehl brauchen wir?\nB: Zweihundert Gramm Mehl Typ 405.\nA: Was bedeutet 405?\nB: Das ist besonders feines Mehl zum Backen.",exampleSrc:"A: How much flour do we need?\nB: Two hundred grams of Type 405 flour.\nA: What does 405 mean?\nB: That is especially fine flour for baking.",funFact:"From Old High German 'melo' (ground grain). Related to English 'meal' (ground grain) and 'mill.' German baking depends on precise Mehl types: Type 405 (fine), 550, 1050 (coarse)."},
{type:"teach",trg:"das Fett",src:"the fat, the grease",pos:"noun",gender:"n",note:"Same root as English 'fat.' 'Fettarm' (low-fat), 'fettfrei' (fat-free).",example:"A: Gib etwas Fett in die Pfanne.\nB: Butter oder \u00d6l?\nA: \u00d6l ist ges\u00fcnder.\nB: Aber Butter schmeckt besser!",exampleSrc:"A: Put some fat in the pan.\nB: Butter or oil?\nA: Oil is healthier.\nB: But butter tastes better!",funFact:"Same root as English 'fat.' 'Ins Fettn\u00e4pfchen treten' (to step in the fat pot) means to make a social blunder."},
{type:"teach",trg:"der Pilz",src:"the mushroom",pos:"noun",gender:"m",note:"From Latin 'pileus' (cap). Germans forage for Pilze in forests every autumn.",example:"A: Ich habe frische Pilze vom Markt.\nB: Steinpilze oder Champignons?\nA: Steinpilze! Zum Braten.\nB: Perfekt, mit Butter und Knoblauch.",exampleSrc:"A: I have fresh mushrooms from the market.\nB: Porcini or champignons?\nA: Porcini! For frying.\nB: Perfect, with butter and garlic.",funFact:"From Latin 'pileus' (cap). Germans forage for Pilze in forests every autumn. 'Pilzsammeln' (mushroom picking) is a beloved tradition but dangerous without expertise."},
{type:"teach",trg:"die Pflaume",src:"the plum",pos:"noun",gender:"f",note:"From Latin 'prunum.' 'Pflaumenkuchen' (plum cake) is a classic late-summer dessert.",example:"A: Die Pflaumen sind reif!\nB: Perfekt f\u00fcr Pflaumenkuchen.\nA: Hast du das Rezept von deiner Oma?\nB: Ja, mit Zimt und Streuseln.",exampleSrc:"A: The plums are ripe!\nB: Perfect for plum cake.\nA: Do you have your grandma's recipe?\nB: Yes, with cinnamon and crumble.",funFact:"From Latin 'prunum' via Germanic transformation. 'Pflaumenkuchen' (plum cake) is a classic late-summer dessert. In slang, 'Du Pflaume!' means 'You dolt!' but gently."},
{type:"teach",trg:"die Aprikose",src:"the apricot",pos:"noun",gender:"f",note:"From Arabic 'al-barquq' through Latin. In Austria: 'Marille.'",example:"A: Magst du Aprikosen?\nB: Ja, sehr! Besonders als Marmelade.\nA: In \u00d6sterreich sagt man Marille.\nB: Gleiche Frucht, anderes Wort.",exampleSrc:"A: Do you like apricots?\nB: Yes, very much! Especially as jam.\nA: In Austria they say Marille.\nB: Same fruit, different word.",funFact:"From Arabic 'al-barquq' through Latin. In Austria, they say 'Marille' instead of Aprikose. Same fruit, different word depending on which side of the border you stand."},
{type:"teach",trg:"die Frucht",src:"the fruit",pos:"noun",gender:"f",note:"From Latin 'fructus.' The formal word. Casual German uses 'Obst' for fresh fruit.",example:"A: Diese Frucht kenne ich nicht.\nB: Das ist eine Kaki. Probier mal!\nA: Mmm, s\u00fc\u00df und weich.\nB: Fr\u00fcchtetee damit schmeckt auch gut.",exampleSrc:"A: I do not know this fruit.\nB: That is a persimmon. Try it!\nA: Mmm, sweet and soft.\nB: Fruit tea with it also tastes good.",funFact:"From Latin 'fructus.' 'Fr\u00fcchtetee' (fruit tea) is what Germans drink when they do not want caffeine. Die Frucht is the formal word. Casual German uses 'Obst' for fresh fruit."},
{type:"teach",trg:"das Geb\u00e4ck",src:"the pastries, the baked goods",pos:"noun",gender:"n",note:"From 'backen' (to bake). The Ge- prefix makes it collective: all baked goods.",example:"A: Das Geb\u00e4ck hier ist fantastisch.\nB: Ja, alles frisch vom B\u00e4cker.\nA: Ich nehme ein Croissant und ein Br\u00f6tchen.\nB: Gute Wahl!",exampleSrc:"A: The pastries here are fantastic.\nB: Yes, everything fresh from the baker.\nA: I will take a croissant and a bread roll.\nB: Good choice!",funFact:"From 'backen' (to bake). The Ge- prefix makes it collective: all baked goods together. Cookies, pastries, bread rolls. Das Geb\u00e4ck is neuter, like most Ge- collective nouns."},
{type:"teach",trg:"drin",src:"in it, inside (colloquial)",pos:"adv",gender:null,note:"Colloquial contraction of 'darin' (in it/there).\nVery common in spoken German.",example:"A: Was ist da drin?\nB: Kartoffelsalat und Würstchen.\nA: Ist Senf auch drin?\nB: Klar, ohne Senf geht es nicht!",exampleSrc:"A: What is in there?\nB: Potato salad and sausages.\nA: Is mustard in it too?\nB: Of course, it does not work without mustard!",funFact:"Drin is the casual version of darin, just as drauf is casual for darauf and drüber for darüber. In everyday speech, Germans almost always use the short forms."},
{type:"teach",trg:"das Picknick",src:"the picnic",pos:"noun",gender:"n",note:"Borrowed from French 'pique-nique.' The Biergarten is a permanent communal Picknick.",example:"A: Wollen wir ein Picknick im Park machen?\nB: Gute Idee! Ich bringe den Salat.\nA: Und ich bringe Brot und K\u00e4se.\nB: Perfekt, um drei Uhr am See?",exampleSrc:"A: Shall we have a picnic in the park?\nB: Good idea! I will bring the salad.\nA: And I will bring bread and cheese.\nB: Perfect, at three o'clock by the lake?",funFact:"Borrowed from French 'pique-nique.' Germans love a Picknick in the park: blanket, bread, cheese, wine. The Biergarten is essentially a permanent communal Picknick."},
{type:"teach",trg:"roh",src:"raw, uncooked",pos:"adj",gender:null,note:"'Rohes Fleisch' (raw meat), 'Rohkost' (raw vegetables/health food). Related to English 'raw.'",example:"A: Ist das Fleisch noch roh?\nB: Ja, es muss noch zehn Minuten auf den Grill.\nA: Rohes Fleisch ist gef\u00e4hrlich.\nB: Nicht in Deutschland: Mett ist roh und beliebt!",exampleSrc:"A: Is the meat still raw?\nB: Yes, it needs ten more minutes on the grill.\nA: Raw meat is dangerous.\nB: Not in Germany: Mett is raw and popular!",funFact:"'Rohes Fleisch' (raw meat), 'Rohkost' (raw vegetables/health food). Related to English 'raw' through Proto-Germanic. Germans eat some things raw that surprise foreigners: 'Mett' (raw minced pork) is a real thing."},
{type:"teach",trg:"gar",src:"cooked, done",pos:"adj",gender:null,note:"'Das Fleisch ist gar' (The meat is done). Also an adverb: 'gar nicht' (not at all).",example:"A: Ist die Bratwurst schon gar?\nB: Noch nicht, noch zwei Minuten.\nA: Ich mag sie gar nicht roh.\nB: Keine Sorge, sie wird perfekt!",exampleSrc:"A: Is the bratwurst done yet?\nB: Not yet, two more minutes.\nA: I do not like it raw at all.\nB: Do not worry, it will be perfect!",funFact:"Cooked, done (as an adjective). 'Das Fleisch ist gar' (The meat is done). Also an adverb meaning 'at all' or 'even': 'gar nicht' (not at all). Two completely different meanings in one word."},
{type:"mc",q:"Du musst Zwiebeln braten. Welches K\u00fcchenger\u00e4t brauchst du?",opts:["Dose","Kanne","Pfanne","Sch\u00fcssel"],ans:"Pfanne",hint:"This item comes from Latin 'patina' and is used for frying on the stove."},
{type:"fb",s:"F\u00fcr den Kuchen brauchen wir {1}, Eier und Zucker.",a:["Mehl"],opts:["Mehl","Fett","Pfeffer","Pilz"],hint:"The white powder that forms the base of all baking.",sSrc:"For the cake we need flour, eggs, and sugar."},
{type:"match",pairs:[{trg:"roh",src:"raw/uncooked"},{trg:"gar",src:"cooked/done"},{trg:"Zutat",src:"ingredient"},{trg:"Frucht",src:"fruit"}]},
{type:"teach",trg:"die Marille",src:"the apricot (Austrian)",pos:"noun",gender:"f",note:"Austrian word for Aprikose. From Italian amarella.\nMarillenknödel = apricot dumplings, an Austrian classic.",example:"A: Was ist eine Marille?\nB: Das ist die österreichische Aprikose.\nA: Und Marillenknödel?\nB: Ein süßer Knödel mit einer Marille drin!",exampleSrc:"A: What is a Marille?\nB: That is the Austrian apricot.\nA: And Marillenknödel?\nB: A sweet dumpling with an apricot inside!",funFact:"Marille comes from Italian amarella (little bitter one). Marillenknödel are one of Austria's most beloved desserts. The Wachau region is famous for its Marillen orchards."},
{type:"mc",q:"In \u00d6sterreich hei\u00dft 'Aprikose' anders. Wie sagt man dort?",opts:["Frucht","Pflaume","Zwiebel","Marille"],ans:"Marille",hint:"This is the Austrian word for the same fruit. It comes from Italian 'amarella.'"},
{type:"fb",s:"Zum Fr\u00fchst\u00fcck esse ich gerne frisches {1} vom B\u00e4cker.",a:["Geb\u00e4ck"],opts:["Geb\u00e4ck","Picknick","Mehl","Fett"],hint:"The collective noun for all baked goods, with the Ge- prefix.",sSrc:"For breakfast I like to eat fresh pastries from the baker."}
]},

// ─── Lesson 3: Die Spargel-Panik ────────────────────────────────────
{id:"deu_r18l3",title:"Die Spargel-Panik",icon:"\uD83E\uDD66",xp:15,board:true,steps:[
{type:"intro",title:"Die Spargel-Panik",desc:"Heinrich calls in a panic: Spargelzeit ends June 24! Learn the difference between 'als' and 'wenn,' plus food shopping and nutrition vocabulary.",goals:["Understand the German obsession with Spargelzeit","Learn als (one-time past) vs wenn (repeated/conditional)","Pick up food shopping and nutrition vocabulary"]},
{type:"story",speaker:"narrator",mood:"amused",art:"de-ber-biergarten-table",trg:"Hildis Handy summt. Sie stellt es auf Lautsprecher. Heinrichs Stimme f\u00fcllt den ganzen Tisch. Er klingt aufgeregt.",src:"Hildi's phone buzzes. She puts it on speaker. Heinrich's voice fills the whole table. He sounds agitated."},
{type:"story",speaker:"heinrich",mood:"urgent",trg:"Es ist der zwanzigste Juni! Spargelzeit endet am vierundzwanzigsten! Habt ihr schon Spargel bestellt? Ich bestehe darauf!",src:"It is the twentieth of June! Asparagus season ends on the twenty-fourth! Have you ordered asparagus yet? I insist!"},
{type:"story",speaker:"verumius",mood:"confused",trg:"Warum ist Spargel so dringend? Es ist doch nur Gem\u00fcse...",src:"Why is asparagus so urgent? It is just a vegetable..."},
{type:"story",speaker:"hildi",mood:"explaining",trg:"Als ich ein Kind war, haben wir jedes Jahr auf den ersten Spargel gewartet. Wenn die Saison endet, gibt es keinen mehr. Bis n\u00e4chstes Jahr.",src:"When I was a child, we waited every year for the first asparagus. When the season ends, there is no more. Until next year."},
{type:"story",speaker:"lukas",mood:"laughing",trg:"Heinrich hat recht. Wenn man den letzten Spargel verpasst, ist das eine nationale Trag\u00f6die.",src:"Heinrich is right. If you miss the last asparagus, that is a national tragedy."},
{type:"teach",trg:"die Saison",src:"the season (food/sports)",pos:"noun",gender:"f",note:"From French 'saison.' Spargelzeit is Germany's most famous food Saison.",example:"A: Wann ist Erdbeer-Saison?\nB: Von Mai bis Juli.\nA: Und Spargel-Saison?\nB: Mitte April bis zum vierundzwanzigsten Juni.",exampleSrc:"A: When is strawberry season?\nB: From May to July.\nA: And asparagus season?\nB: Mid-April to the twenty-fourth of June.",funFact:"From French 'saison.' Spargelzeit is Germany's most famous food Saison: mid-April to June 24. Germans eat 1.7 kg of Spargel per person per year."},
{type:"teach",trg:"die Ernte",src:"the harvest",pos:"noun",gender:"f",note:"From 'ernten' (to harvest). 'Erntezeit' (harvest time) is peak season for farmers.",example:"A: Die Ernte war dieses Jahr gut.\nB: Ja, der Sommer war perfekt.\nA: Besonders die Spargelernte.\nB: Die beste seit Jahren!",exampleSrc:"A: The harvest was good this year.\nB: Yes, the summer was perfect.\nA: Especially the asparagus harvest.\nB: The best in years!",funFact:"Harvest. From 'ernten' (to harvest). 'Erntezeit' (harvest time) is when German farmers are busiest. The word carries weight in a country where seasonal eating is still important."},
{type:"teach",trg:"die Quittung",src:"the receipt",pos:"noun",gender:"f",note:"From Latin 'quietare' (to settle). Germans keep Quittungen for everything.",example:"A: Kann ich die Quittung haben?\nB: Nat\u00fcrlich, hier bitte.\nA: Ich brauche sie f\u00fcr die Steuererkl\u00e4rung.\nB: Typisch deutsch!",exampleSrc:"A: Can I have the receipt?\nB: Of course, here you go.\nA: I need it for the tax return.\nB: Typically German!",funFact:"From Latin 'quietare' (to settle). 'Kann ich die Quittung haben?' is essential shopping vocabulary. Germans keep Quittungen for everything, especially for tax returns."},
{type:"teach",trg:"der Rabatt",src:"the discount",pos:"noun",gender:"m",note:"From Italian 'rabatto.' A discount or reduction.",example:"A: Gibt es einen Rabatt auf den Spargel?\nB: Ja, zehn Prozent, weil die Saison fast vorbei ist.\nA: Dann nehme ich zwei Kilo!\nB: Kluge Entscheidung.",exampleSrc:"A: Is there a discount on the asparagus?\nB: Yes, ten percent, because the season is almost over.\nA: Then I will take two kilos!\nB: Smart decision.",funFact:"From Italian 'rabatto' (discount). 'Sonderangebot' (special offer) and 'Rabatt' are the words that make German shoppers happy."},
{type:"teach",trg:"das Sonderangebot",src:"the special offer",pos:"noun",gender:"n",note:"'Sonder' (special) + 'Angebot' (offer). Neuter because Angebot is neuter.",example:"A: Schau mal, Spargel im Sonderangebot!\nB: Nur drei Euro das Kilo!\nA: Heinrich w\u00e4re begeistert.\nB: Ruf ihn an!",exampleSrc:"A: Look, asparagus on special offer!\nB: Only three euros per kilo!\nA: Heinrich would be thrilled.\nB: Call him!",funFact:"'Sonder' (special) + 'Angebot' (offer). German supermarkets advertise Sonderangebote in weekly flyers. Das Sonderangebot is neuter because Angebot is neuter. Compound gender rule."},
{type:"teach",trg:"die Schlange",src:"the snake, the queue",pos:"noun",gender:"f",note:"'Schlange stehen' (to stand in line) makes the queue a snake.",example:"A: Oh nein, die Schlange ist so lang!\nB: Ja, alle wollen den letzten Spargel.\nA: Wir m\u00fcssen Schlange stehen.\nB: Das geh\u00f6rt zum deutschen Alltag.",exampleSrc:"A: Oh no, the queue is so long!\nB: Yes, everyone wants the last asparagus.\nA: We have to stand in line.\nB: That is part of German daily life.",funFact:"A snake AND a queue. 'Schlange stehen' (to stand in line) makes the queue a snake. Germans queue precisely but not always patiently."},
{type:"teach",trg:"der Backofen",src:"the oven",pos:"noun",gender:"m",note:"'Back' (bake) + 'Ofen' (oven). Every German kitchen has one.",example:"A: Heize den Backofen auf 180 Grad vor.\nB: Ober- und Unterhitze?\nA: Ja, f\u00fcr den Spargelauflauf.\nB: In zwanzig Minuten ist er hei\u00df.",exampleSrc:"A: Preheat the oven to 180 degrees.\nB: Top and bottom heat?\nA: Yes, for the asparagus casserole.\nB: It will be hot in twenty minutes.",funFact:"'Back' (bake) + 'Ofen' (oven). 'Den Backofen auf 180 Grad vorheizen' (Preheat the oven to 180 degrees) begins every German recipe. Celsius, naturally."},
{type:"teach",trg:"das Nahrungsmittel",src:"the foodstuff",pos:"noun",gender:"n",note:"'Nahrung' (nourishment) + 'Mittel' (means). The formal, official word for food.",example:"A: Nahrungsmittel m\u00fcssen korrekt beschriftet sein.\nB: Das steht im Gesetz.\nA: Jede Zutat muss auf der Verpackung stehen.\nB: Deutschland nimmt das ernst.",exampleSrc:"A: Foodstuffs must be labeled correctly.\nB: That is the law.\nA: Every ingredient must be on the packaging.\nB: Germany takes that seriously.",funFact:"'Nahrung' (nourishment) + 'Mittel' (means/agent). The formal, official word for food. You see it on packaging and in regulations. More technical than 'Essen' (food/eating)."},
{type:"teach",trg:"die Ern\u00e4hrung",src:"the nutrition, the diet",pos:"noun",gender:"f",note:"From 'ern\u00e4hren' (to nourish). Covers your entire relationship with food.",example:"A: Achtest du auf deine Ern\u00e4hrung?\nB: Ja, ich esse viel Obst und Gem\u00fcse.\nA: Gesunde Ern\u00e4hrung ist wichtig.\nB: Besonders im Sommer mit frischem Spargel!",exampleSrc:"A: Do you watch your diet?\nB: Yes, I eat lots of fruit and vegetables.\nA: Healthy nutrition is important.\nB: Especially in summer with fresh asparagus!",funFact:"From 'ern\u00e4hren' (to nourish). 'Gesunde Ern\u00e4hrung' (healthy nutrition) is a topic Germans take seriously. Die Ern\u00e4hrung covers your entire relationship with food."},
{type:"teach",trg:"die Di\u00e4t",src:"the diet",pos:"noun",gender:"f",note:"From Greek 'diaita' (way of life). Can also mean a special medical diet.",example:"A: Machst du eine Di\u00e4t?\nB: Nein, ich esse einfach weniger Zucker.\nA: Das ist auch eine Art Di\u00e4t.\nB: Stimmt, aber es f\u00fchlt sich nicht so an.",exampleSrc:"A: Are you on a diet?\nB: No, I just eat less sugar.\nA: That is also a kind of diet.\nB: True, but it does not feel like it.",funFact:"From Greek 'diaita' (way of life). In German, Di\u00e4t can also mean a special medical diet, not just weight loss. Politicians' salaries are also called 'Di\u00e4ten.'"},
{type:"teach",trg:"das Vitamin",src:"the vitamin",pos:"noun",gender:"n",note:"Coined in 1912 from Latin 'vita' (life) + 'amine.' 'Vitamin C' is pronounced 'Vitamin Tsay.'",example:"A: Spargel hat viele Vitamine.\nB: Besonders Vitamin C und K.\nA: Deshalb ist er so gesund.\nB: Und lecker!",exampleSrc:"A: Asparagus has many vitamins.\nB: Especially vitamin C and K.\nA: That is why it is so healthy.\nB: And delicious!",funFact:"Coined in 1912 from Latin 'vita' (life) + 'amine.' Germans are vitamin-conscious. 'Vitamin C' is pronounced 'Vitamin Tsay.' The health-food market in Germany is enormous."},
{type:"teach",trg:"reif",src:"ripe, mature",pos:"adj",gender:null,note:"'Der Apfel ist reif.' Also figurative: 'reif f\u00fcr etwas sein' (to be ready for something).",example:"A: Sind die Erdbeeren schon reif?\nB: Ja, sie sind perfekt rot.\nA: Dann pfl\u00fccken wir sie heute.\nB: Die reifen sind die s\u00fc\u00dfesten.",exampleSrc:"A: Are the strawberries ripe yet?\nB: Yes, they are perfectly red.\nA: Then we will pick them today.\nB: The ripe ones are the sweetest.",funFact:"Ripe, mature. Also used figuratively: 'reif f\u00fcr etwas sein' (to be ready for something). 'Ich bin reif f\u00fcr den Urlaub' (I am ready for vacation)."},
{type:"teach",trg:"haltbar",src:"durable, having a shelf life",pos:"adj",gender:null,note:"'Halt' (hold) + '-bar' (able). 'Mindestens haltbar bis...' (Best before...).",example:"A: Wie lange ist die Milch haltbar?\nB: Bis n\u00e4chsten Mittwoch.\nA: Und die Konserven?\nB: Die sind Jahre haltbar.",exampleSrc:"A: How long does the milk keep?\nB: Until next Wednesday.\nA: And the canned goods?\nB: They keep for years.",funFact:"'Halt' (hold) + '-bar' (able). 'Mindestens haltbar bis...' (Best before...) appears on every German food package. The -bar suffix works like English '-able.'"},
{type:"teach",trg:"vegetarisch",src:"vegetarian",pos:"adj",gender:null,note:"From Latin 'vegetare' (to enliven). Germany has high rates of vegetarianism.",example:"A: Gibt es etwas Vegetarisches?\nB: Ja, Kartoffelsalat und Spargelsuppe.\nA: Perfekt, ich esse kein Fleisch.\nB: In Berlin ist das ganz normal.",exampleSrc:"A: Is there anything vegetarian?\nB: Yes, potato salad and asparagus soup.\nA: Perfect, I do not eat meat.\nB: In Berlin that is completely normal.",funFact:"From Latin 'vegetare' (to enliven). Germany has one of the highest rates of vegetarianism in Europe. Berlin alone has over 60 fully vegetarian restaurants."},
{type:"teach",trg:"zubereiten",src:"to prepare (food)",pos:"verb",gender:null,note:"'Zu' (to) + 'bereiten' (to prepare). More specific than 'vorbereiten.' Separable.",example:"A: Wie bereitet man Spargel zu?\nB: Sch\u00e4len, kochen, mit Butter servieren.\nA: Wie lange kocht er?\nB: Zehn bis f\u00fcnfzehn Minuten.",exampleSrc:"A: How do you prepare asparagus?\nB: Peel, boil, serve with butter.\nA: How long does it cook?\nB: Ten to fifteen minutes.",funFact:"'Zu' (to) + 'bereiten' (to prepare). More specific than 'vorbereiten' (general preparation). Separable: 'Ich bereite das Essen zu.'"},
{type:"teach",trg:"mischen",src:"to mix",pos:"verb",gender:null,note:"Regular verb. 'Einen Salat mischen' (to toss a salad). Related to English 'mix.'",example:"A: Kannst du den Salat mischen?\nB: Klar, mit welchem Dressing?\nA: Essig und \u00d6l.\nB: Ich mische alles zusammen.",exampleSrc:"A: Can you toss the salad?\nB: Sure, with which dressing?\nA: Vinegar and oil.\nB: I will mix everything together.",funFact:"To mix. Regular verb. 'Einen Salat mischen' (to toss a salad), 'Karten mischen' (to shuffle cards). Related to English 'mix' through Latin 'miscere.'"},
{type:"teach",trg:"sp\u00fclen",src:"to rinse, to wash (dishes)",pos:"verb",gender:null,note:"'Geschirr sp\u00fclen' (to wash dishes). Also 'die Toilette sp\u00fclen' (to flush).",example:"A: Wer sp\u00fclt heute das Geschirr?\nB: Du! Ich habe gestern gesp\u00fclt.\nA: Wir brauchen eine Sp\u00fclmaschine.\nB: Stimmt, Handsp\u00fclen dauert ewig.",exampleSrc:"A: Who washes the dishes today?\nB: You! I washed them yesterday.\nA: We need a dishwasher.\nB: True, hand-washing takes forever.",funFact:"To rinse or wash (dishes). 'Geschirr sp\u00fclen' (to wash dishes). Also 'die Toilette sp\u00fclen' (to flush the toilet). The Sp\u00fclmaschine is the dishwasher."},
{type:"tip",title:"als vs wenn: Zwei W\u00f6rter f\u00fcr 'when'",text:"German has two words where English has one.\n\nALS = one specific moment in the past.\n'Als ich ein Kind war...' (When I was a child...)\n'Als Heinrich anrief...' (When Heinrich called...)\n\nWENN = every time, repeatedly, or hypothetically.\n'Wenn ich Spargel esse...' (When/whenever I eat asparagus...)\n'Wenn die Saison endet...' (When the season ends...)\n\nMemory trick:\nALS = ONCE in the past.\nWENN = WHENEVER or IF.\n\nHildi says 'Als ich ein Kind war' (one specific past). Lukas says 'Wenn man den letzten Spargel verpasst' (every year, repeated).",deepDive:"The distinction is strict in German. You cannot use 'wenn' for a single past event, and you cannot use 'als' for repeated or present events. In reported speech or written German, the rule holds firm. Some learners think 'als' means 'as' and 'wenn' means 'when/if,' but the real key is: was it a one-time past event (als) or is it repeated/habitual/conditional (wenn)?"},
{type:"verb_table",title:"als vs wenn (when)",note:"Als = one specific past event. Wenn = repeated, habitual, or hypothetical.",groups:[{label:"als (einmalig in der Vergangenheit)",rows:[{pronoun:"Als ich ankam,",form:"war alles bereit.",src:"When I arrived, everything was ready."},{pronoun:"Als wir Kinder waren,",form:"spielten wir im Garten.",src:"When we were children, we played in the garden."},{pronoun:"Als Heinrich anrief,",form:"sa\u00dfen wir im Biergarten.",src:"When Heinrich called, we were sitting in the beer garden."}]},{label:"wenn (wiederholt / hypothetisch)",rows:[{pronoun:"Wenn ich Hunger habe,",form:"esse ich Brot.",src:"When(ever) I am hungry, I eat bread."},{pronoun:"Wenn die Saison endet,",form:"gibt es keinen Spargel.",src:"When the season ends, there is no asparagus."},{pronoun:"Wenn ich k\u00f6nnte,",form:"w\u00fcrde ich jeden Tag grillen.",src:"If I could, I would grill every day."}]}]},
{type:"mc",q:"Erg\u00e4nze: '_____ ich gestern im Biergarten war, habe ich Spargel bestellt.'",opts:["Ob","Wenn","Als","Weil"],ans:"Als",hint:"Yesterday is a single, specific moment in the past. Which word means 'when' for one-time events?"},
{type:"fb",s:"{1} die Spargelzeit endet, sind die Deutschen immer traurig.",a:["Wenn"],opts:["Wenn","Als","Ob","Weil"],hint:"The asparagus season ends EVERY year. This is a repeated event.",sSrc:"When the asparagus season ends, Germans are always sad."}
]},

// ─── Lesson 4: Worauf freust du dich? ───────────────────────────────
{id:"deu_r18l4",title:"Worauf freust du dich?",icon:"\uD83D\uDCA1",xp:15,board:true,steps:[
{type:"intro",title:"Worauf freust du dich?",desc:"Some German verbs always come with a specific preposition. Learn the combos, then replace them with clever da- and wo- compounds.",goals:["Master verbs with fixed prepositions (sich freuen auf/\u00fcber, warten auf, denken an)","Learn da-compounds (darauf, dar\u00fcber) to replace prepositional phrases","Form questions with wo-compounds (worauf, wor\u00fcber)"]},
{type:"teach",trg:"der Konsum",src:"the consumption",pos:"noun",gender:"m",note:"From Latin 'consumere.' Covers everything from food to media consumption.",example:"A: Der Konsum von Spargel steigt jedes Jahr.\nB: Die Deutschen lieben Spargel.\nA: Der Konsum von Bio-Produkten w\u00e4chst auch.\nB: Ja, immer mehr Leute kaufen bio.",exampleSrc:"A: The consumption of asparagus increases every year.\nB: Germans love asparagus.\nA: The consumption of organic products is also growing.\nB: Yes, more and more people buy organic.",funFact:"From Latin 'consumere.' 'Konsumgesellschaft' (consumer society) is a word Germans use critically. Der Konsum is masculine."},
{type:"teach",trg:"die Fl\u00fcssigkeit",src:"the liquid, the fluid",pos:"noun",gender:"f",note:"'Fl\u00fcssig' (liquid) + '-keit' (noun suffix). The -keit suffix always creates feminine nouns.",example:"A: Trinkst du genug Fl\u00fcssigkeit?\nB: Ich versuche es. Zwei Liter am Tag.\nA: Bei der Hitze brauchst du mehr.\nB: Stimmt, ich hole mir noch Wasser.",exampleSrc:"A: Do you drink enough fluids?\nB: I try. Two liters a day.\nA: In this heat you need more.\nB: True, I will get more water.",funFact:"'Fl\u00fcssig' (liquid) + '-keit' (noun suffix). 'Viel Fl\u00fcssigkeit trinken' (drink plenty of fluids) is standard German health advice. The -keit suffix always creates feminine nouns."},
{type:"teach",trg:"der Alkohol",src:"the alcohol",pos:"noun",gender:"m",note:"From Arabic 'al-kuhl' (the kohl/essence). Germany has relaxed alcohol laws.",example:"A: Trinkst du Alkohol?\nB: Manchmal. Ein Bier im Biergarten.\nA: In Deutschland darf man ab sechzehn Bier trinken.\nB: Ja, aber Schnaps erst ab achtzehn.",exampleSrc:"A: Do you drink alcohol?\nB: Sometimes. A beer in the beer garden.\nA: In Germany you can drink beer from age sixteen.\nB: Yes, but spirits only from eighteen.",funFact:"From Arabic 'al-kuhl' (the kohl/essence). Germany has some of the most relaxed alcohol laws in Europe. Beer from age 16, spirits from 18."},
{type:"teach",trg:"der Kakao",src:"the cocoa, the hot chocolate",pos:"noun",gender:"m",note:"From Nahuatl 'cacahuatl' via Spanish. 'Jemanden durch den Kakao ziehen' = to make fun of someone.",example:"A: M\u00f6chtest du Kakao oder Kaffee?\nB: Kakao, bitte. Mit Sahne.\nA: Du trinkst immer Kakao!\nB: Ja, das ist mein Lieblingsgetr\u00e4nk.",exampleSrc:"A: Would you like cocoa or coffee?\nB: Cocoa, please. With cream.\nA: You always drink cocoa!\nB: Yes, that is my favorite drink.",funFact:"From Nahuatl 'cacahuatl' via Spanish. 'Jemanden durch den Kakao ziehen' (to pull someone through the cocoa) means to make fun of someone."},
{type:"teach",trg:"die Serviceangestellte",src:"the service employee (female)",pos:"noun",gender:"f",note:"'Service' + 'Angestellte' (employee). Gender-neutral alternative to Kellner/Kellnerin.",example:"A: Entschuldigung, k\u00f6nnen Sie uns helfen?\nB: Nat\u00fcrlich! Ich bin Ihre Serviceangestellte heute Abend.\nA: Wir h\u00e4tten gerne die Karte.\nB: Sofort!",exampleSrc:"A: Excuse me, can you help us?\nB: Of course! I am your service attendant this evening.\nA: We would like the menu.\nB: Right away!",funFact:"'Service' + 'Angestellte' (employee). The gender-neutral alternative to Kellner/Kellnerin. Modern German hospitality vocabulary."},
{type:"teach",trg:"die Vermietung",src:"the rental, the letting",pos:"noun",gender:"f",note:"From 'vermieten' (to rent out). Feminine because of -ung.",example:"A: Die Vermietung von Ferienwohnungen boomt.\nB: Besonders in Berlin.\nA: Siehst du das Schild? 'Vermietung ab Juni.'\nB: Vielleicht f\u00fcr den Sommer.",exampleSrc:"A: The rental of vacation apartments is booming.\nB: Especially in Berlin.\nA: Do you see the sign? 'Rental from June.'\nB: Maybe for the summer.",funFact:"From 'vermieten' (to rent out). 'Zimmervermietung' (room rental). Die Vermietung is feminine because of -ung. You see it on signs everywhere."},
{type:"teach",trg:"die Vermittlung",src:"the mediation, the placement",pos:"noun",gender:"f",note:"From 'vermitteln' (to mediate/arrange). The -ung ending makes it feminine.",example:"A: Die Vermittlung hat mir eine Wohnung gefunden.\nB: Wie schnell?\nA: In nur zwei Wochen.\nB: Das ist in Berlin ein Wunder!",exampleSrc:"A: The agency found me an apartment.\nB: How quickly?\nA: In just two weeks.\nB: That is a miracle in Berlin!",funFact:"From 'vermitteln' (to mediate/arrange). 'Arbeitsvermittlung' (job placement), 'Zimmervermittlung' (accommodation service). The -ung ending makes it feminine."},
{type:"teach",trg:"die Er\u00f6ffnung",src:"the opening, the inauguration",pos:"noun",gender:"f",note:"From 'er\u00f6ffnen' (to open formally). A formal event with speeches and ribbon-cutting.",example:"A: Kommst du zur Er\u00f6ffnung des neuen Biergartens?\nB: Ja, nat\u00fcrlich! Wann ist es?\nA: N\u00e4chsten Samstag um zw\u00f6lf.\nB: Ich bin dabei!",exampleSrc:"A: Are you coming to the opening of the new beer garden?\nB: Yes, of course! When is it?\nA: Next Saturday at noon.\nB: I will be there!",funFact:"From 'er\u00f6ffnen' (to open formally). 'Die Er\u00f6ffnung des Biergartens' (the opening of the beer garden). Grand openings in Germany involve speeches and ribbon-cutting."},
{type:"teach",trg:"bio",src:"organic",pos:"adj",gender:null,note:"Short for 'biologisch.' 'Bio-Bratwurst,' 'Bio-Bier.' Germany is Europe's largest organic market.",example:"A: Ist die Bratwurst bio?\nB: Ja, vom Bio-Bauernhof.\nA: Dann nehme ich zwei.\nB: Bio ist teurer, aber es lohnt sich.",exampleSrc:"A: Is the bratwurst organic?\nB: Yes, from an organic farm.\nA: Then I will take two.\nB: Organic is more expensive, but it is worth it.",funFact:"Short for 'biologisch.' Germany is the largest organic food market in Europe. The 'Bio' label is legally protected and strictly regulated."},
{type:"teach",trg:"biologisch",src:"biological, organic",pos:"adj",gender:null,note:"From Greek 'bios' (life) + 'logos' (study). In food context it means organic.",example:"A: Ist das biologisch angebaut?\nB: Ja, ohne Pestizide.\nA: Biologische Landwirtschaft ist wichtig.\nB: F\u00fcr die Umwelt und f\u00fcr uns.",exampleSrc:"A: Is that organically grown?\nB: Yes, without pesticides.\nA: Organic farming is important.\nB: For the environment and for us.",funFact:"From Greek 'bios' (life) + 'logos' (study). 'Biologische Landwirtschaft' (organic farming). Longer form of 'bio,' used in formal or written contexts."},
{type:"teach",trg:"mager",src:"lean, thin, low-fat",pos:"adj",gender:null,note:"'Magermilch' (skim milk), 'mageres Fleisch' (lean meat).",example:"A: Hast du Magermilch?\nB: Nein, nur Vollmilch.\nA: Ich achte auf meine Ern\u00e4hrung.\nB: Dann kaufe ich n\u00e4chstes Mal Magermilch.",exampleSrc:"A: Do you have skim milk?\nB: No, only whole milk.\nA: I watch my diet.\nB: Then I will buy skim milk next time.",funFact:"Lean, thin, low-fat. 'Magermilch' (skim milk), 'mageres Fleisch' (lean meat). Not a compliment when applied to food portions."},
{type:"teach",trg:"spitz",src:"sharp, pointed",pos:"adj",gender:null,note:"'Ein spitzer Stift' (a sharp pencil). Also 'spitze!' as slang for 'great!'",example:"A: Vorsicht, das Messer ist spitz!\nB: Danke, ich passe auf.\nA: Und wie war das Essen?\nB: Spitze!",exampleSrc:"A: Careful, the knife is sharp!\nB: Thanks, I will be careful.\nA: And how was the food?\nB: Great!",funFact:"Sharp, pointed. 'Ein spitzer Stift' (a sharp pencil). Also 'spitze!' as slang for 'great!' Related to English 'spit' (the pointed landform)."},
{type:"teach",trg:"er\u00f6ffnen",src:"to open (formally), to inaugurate",pos:"verb",gender:null,note:"'Er-' (to begin/achieve) + '\u00f6ffnen' (to open). More formal than simply '\u00f6ffnen.'",example:"A: Wann er\u00f6ffnet der neue Biergarten?\nB: N\u00e4chste Woche.\nA: Wer er\u00f6ffnet ihn offiziell?\nB: Der B\u00fcrgermeister!",exampleSrc:"A: When does the new beer garden open?\nB: Next week.\nA: Who officially opens it?\nB: The mayor!",funFact:"'Er-' (to begin/achieve) + '\u00f6ffnen' (to open). You 'er\u00f6ffnen' a business, a meeting, or a Biergarten season. More formal than simply '\u00f6ffnen' (to open a door)."},
{type:"teach",trg:"konsumieren",src:"to consume",pos:"verb",gender:null,note:"From Latin 'consumere.' More formal than 'essen' or 'trinken.'",example:"A: Deutsche konsumieren viel Bier.\nB: Aber weniger als fr\u00fcher.\nA: Der Konsum sinkt seit Jahren.\nB: Daf\u00fcr steigt der Weinkonsum.",exampleSrc:"A: Germans consume a lot of beer.\nB: But less than before.\nA: Consumption has been dropping for years.\nB: But wine consumption is increasing.",funFact:"From Latin 'consumere.' More formal than 'essen' or 'trinken.' 'Alkohol konsumieren' sounds more official. Used in health contexts and regulations."},
{type:"teach",trg:"l\u00f6sen",src:"to solve, to dissolve, to buy (a ticket)",pos:"verb",gender:null,note:"Three meanings in one verb. 'Ein Problem l\u00f6sen,' 'eine Fahrkarte l\u00f6sen.'",example:"A: Ich muss noch eine Fahrkarte l\u00f6sen.\nB: Am Automaten oder online?\nA: Online ist einfacher.\nB: Problem gel\u00f6st!",exampleSrc:"A: I still need to buy a ticket.\nB: At the machine or online?\nA: Online is easier.\nB: Problem solved!",funFact:"To solve, to dissolve, to buy (a ticket). 'Ein Problem l\u00f6sen,' 'Salz l\u00f6st sich in Wasser,' 'eine Fahrkarte l\u00f6sen.' Three meanings, one verb."},
{type:"teach",trg:"heben",src:"to lift, to raise",pos:"verb",gender:null,note:"Strong verb: heben, hob, gehoben. 'Ein Glas heben' (to raise a glass). Related to English 'heave.'",example:"A: Heben wir die Gl\u00e4ser!\nB: Prost! Auf den Sommer!\nA: Dieses Bierglas ist schwer.\nB: Ein Liter! Das ist Training.",exampleSrc:"A: Let us raise our glasses!\nB: Cheers! To summer!\nA: This beer glass is heavy.\nB: One liter! That is exercise.",funFact:"Strong verb: heben, hob, gehoben. 'Ein Glas heben' (to raise a glass) is what you do at 'Prost!' Related to English 'heave.'"},
{type:"tip",title:"Verben mit festen Pr\u00e4positionen",text:"Some German verbs always pair with a specific preposition. The preposition changes the meaning.\n\nsich freuen AUF = look forward to (future)\nsich freuen \u00dcBER = be happy about (present/past)\nwarten AUF = wait for\ndenken AN = think of\nbestehen AUF = insist on\nsich interessieren F\u00dcR = be interested in\n\nYou cannot swap the prepositions. Each combo is one fixed unit. Memorize them as pairs.\n\nExample from the story:\nHeinrich besteht AUF Spargel. (Heinrich insists ON asparagus.)\nVerumius freut sich AUF den Abend. (Verumius looks forward TO the evening.)",deepDive:"The case after the preposition matters too. 'Auf' with fixed-preposition verbs usually takes accusative: 'Ich warte auf DEN Kellner.' 'An' takes accusative with 'denken': 'Ich denke an DEN Abend.' These differ from the spatial use of the same prepositions, where the two-way prepositions take dative for location and accusative for direction."},
{type:"verb_table",title:"Verben mit festen Pr\u00e4positionen",note:"Each verb-preposition pair is a fixed unit. The preposition determines the case.",groups:[{label:"auf (Akkusativ)",rows:[{pronoun:"sich freuen auf",form:"Ich freue mich auf den Sommer.",src:"I look forward to summer."},{pronoun:"warten auf",form:"Wir warten auf den Kellner.",src:"We wait for the waiter."},{pronoun:"bestehen auf",form:"Heinrich besteht auf Spargel.",src:"Heinrich insists on asparagus."}]},{label:"\u00fcber (Akkusativ)",rows:[{pronoun:"sich freuen \u00fcber",form:"Sie freut sich \u00fcber das Geschenk.",src:"She is happy about the gift."},{pronoun:"sprechen \u00fcber",form:"Wir sprechen \u00fcber das Essen.",src:"We talk about the food."}]},{label:"an (Akkusativ)",rows:[{pronoun:"denken an",form:"Ich denke an den Abend.",src:"I think of the evening."},{pronoun:"sich erinnern an",form:"Er erinnert sich an den Biergarten.",src:"He remembers the beer garden."}]},{label:"f\u00fcr (Akkusativ)",rows:[{pronoun:"sich interessieren f\u00fcr",form:"Sie interessiert sich f\u00fcr Bio-Essen.",src:"She is interested in organic food."}]}]},
{type:"tip",title:"da- und wo-Komposita",text:"When you want to say 'about it' or 'for it,' German uses DA + preposition:\ndarauf (on it), dar\u00fcber (about it), daran (of it), daf\u00fcr (for it).\n\nFor questions, use WO + preposition:\nworauf (on what), wor\u00fcber (about what), woran (of what), wof\u00fcr (for what).\n\nIf the preposition starts with a vowel, add an -r-:\nda + auf = darauf\nwo + auf = worauf\nda + \u00fcber = dar\u00fcber\n\nExample:\n'Worauf wartest du?' -- 'Darauf, dass der Kellner kommt.'\n(What are you waiting for? -- For the waiter to come.)",deepDive:"Da-compounds replace prepositional phrases that refer to things (not people). For people, use the preposition plus a pronoun: 'Ich denke an ihn' (I think of him), NOT 'Ich denke daran' when referring to a person. Wo-compounds work the same way: 'An wen denkst du?' (Who are you thinking of?) for people, 'Woran denkst du?' (What are you thinking of?) for things."},
{type:"mc",q:"Verumius _____ sich _____ den Spargel. (freut sich auf etwas)",opts:["freut...\u00fcber","freut...auf","wartet...auf","denkt...an"],ans:"freut...auf",hint:"Looking forward to something in the FUTURE uses 'sich freuen' plus the preposition for future anticipation."},
{type:"mc",q:"Heinrich besteht auf Spargel. Er besteht _____ .",opts:["dar\u00fcber","darauf","daf\u00fcr","daran"],ans:"darauf",hint:"The verb is 'bestehen AUF.' Replace 'auf Spargel' with da + auf."},
{type:"fb",s:"{1} freust du dich? -- Auf den Sommer!",a:["Worauf"],opts:["Worauf","Wor\u00fcber","Woran","Wof\u00fcr"],hint:"The answer uses 'auf.' The question word combines 'wo' with 'auf.'",sSrc:"What are you looking forward to? -- To summer!"},
{type:"mc",q:"'_____ ich das erste Mal Spargel a\u00df, war ich \u00fcberrascht.' Welches Wort passt?",opts:["Weil","Als","Damit","Wenn"],ans:"Als",hint:"The FIRST time is a single, one-time past event. Which word is for that?"},
{type:"drag_fill",s:"Mia {1} sich {2} Bio-Essen. Sie denkt oft {3}.",blanks:{"1":"interessiert","2":"f\u00fcr","3":"daran"},pool:["interessiert","f\u00fcr","daran","freut","auf","darauf"],hint:"First: the verb for being interested plus its fixed preposition. Second: 'denken an' replaced with a da-compound.",sSrc:"Mia is interested in organic food. She often thinks about it."},
{type:"match",pairs:[{trg:"darauf",src:"on it / for it"},{trg:"dar\u00fcber",src:"about it"},{trg:"daran",src:"of it / to it"},{trg:"daf\u00fcr",src:"for it (purpose)"}]}
]},

// ─── Lesson 5: Lukas spielt ─────────────────────────────────────────
{id:"deu_r18l5",title:"Lukas spielt",icon:"\uD83C\uDFB8",xp:15,board:true,steps:[
{type:"intro",title:"Lukas spielt",desc:"The golden hour fades to blue. Fairy lights glow. Lukas picks up his guitar. His band broke up last month. Tonight, he plays alone.",goals:["Practice als vs wenn in emotional contexts","Use verbs with fixed prepositions to describe feelings","Learn nature and agriculture vocabulary"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-ber-biergarten-dusk",trg:"Die goldene Stunde geht in Blau \u00fcber. Lichterketten erwachen in den Kastanien\u00e4sten. Lukas steht auf der kleinen erh\u00f6hten Fl\u00e4che, Gitarre in der Hand. Niemand hat ihn gebeten zu spielen. Er hat einfach angefangen.",src:"The golden hour fades to blue. Fairy lights come alive in the chestnut branches. Lukas stands on the small raised area, guitar in hand. No one asked him to play. He just started."},
{type:"story",speaker:"mia",mood:"quiet",trg:"Sie beugt sich zu Verumius: 'Seine Band hat sich letzten Monat getrennt. Er spricht nicht dar\u00fcber. Aber er denkt st\u00e4ndig daran.'",src:"She leans toward Verumius: 'His band broke up last month. He does not talk about it. But he thinks about it constantly.'"},
{type:"story",speaker:"narrator",mood:"emotional",art:"de-ber-biergarten-guitar",trg:"Lukas spielt. Augen geschlossen. Die Musik ist sch\u00f6n und traurig. Ein Lied \u00fcber Sommerabende, die nicht ewig dauern. Hildi stellt ihren Bierkrug ab. Sogar sie ist still.",src:"Lukas plays. Eyes closed. The music is beautiful and sad. A song about summer evenings that will not last. Hildi puts down her beer stein. Even she is quiet."},
{type:"story",speaker:"verumius",mood:"thinking",trg:"Als ich ihn zum ersten Mal traf, war er immer lustig. Jetzt verstehe ich: Wenn er Musik macht, zeigt er, was er wirklich f\u00fchlt.",src:"When I first met him, he was always funny. Now I understand: when he makes music, he shows what he really feels."},
{type:"teach",trg:"die Wiese",src:"the meadow",pos:"noun",gender:"f",note:"'Liegewiese' (sunbathing lawn) is where Germans spread blankets in parks.",example:"A: Lass uns auf die Wiese setzen.\nB: Ja, das Gras ist weich.\nA: Die Wiese ist voller Blumen.\nB: Ein perfekter Sommerabend.",exampleSrc:"A: Let us sit on the meadow.\nB: Yes, the grass is soft.\nA: The meadow is full of flowers.\nB: A perfect summer evening.",funFact:"A meadow. 'Liegewiese' (sunbathing lawn) is where Germans spread their blankets in parks. 'Auf der gr\u00fcnen Wiese' is also business jargon for building from scratch."},
{type:"teach",trg:"das Gras",src:"the grass",pos:"noun",gender:"n",note:"Same word and same root as English. 'Das Gras wachsen h\u00f6ren' = to be overly perceptive.",example:"A: Das Gras im Park ist so gr\u00fcn.\nB: Ja, es hat viel geregnet.\nA: Perfekt zum Picknicken.\nB: Aber nicht zu nass?",exampleSrc:"A: The grass in the park is so green.\nB: Yes, it rained a lot.\nA: Perfect for a picnic.\nB: But not too wet?",funFact:"Same word and same root as English. 'Das Gras wachsen h\u00f6ren' (to hear the grass grow) means to be overly sensitive or perceptive."},
{type:"teach",trg:"das Feld",src:"the field",pos:"noun",gender:"n",note:"Cognate with English 'field.' Germany's agricultural Felder feed much of Europe.",example:"A: Schau dir die Felder an!\nB: Getreide, so weit man sehen kann.\nA: Die Ernte wird gut dieses Jahr.\nB: Ja, der Regen war perfekt.",exampleSrc:"A: Look at the fields!\nB: Grain, as far as you can see.\nA: The harvest will be good this year.\nB: Yes, the rain was perfect.",funFact:"Cognate with English 'field.' 'Feldforschung' (field research), 'Spielfeld' (playing field). Germany's agricultural Felder feed much of Europe."},
{type:"teach",trg:"das Tuch",src:"the cloth, the scarf",pos:"noun",gender:"n",note:"'Halstuch' (neck scarf), 'Handtuch' (towel), 'Tischtuch' (tablecloth).",example:"A: Hast du ein Tuch dabei?\nB: Ja, mein Halstuch. Warum?\nA: Es wird k\u00fchler am Abend.\nB: Stimmt, nimm es.",exampleSrc:"A: Do you have a scarf with you?\nB: Yes, my neck scarf. Why?\nA: It is getting cooler in the evening.\nB: True, take it.",funFact:"A cloth or scarf. German compounds with Tuch name every type of fabric you drape: 'Halstuch' (neck scarf), 'Handtuch' (hand-cloth = towel), 'Tischtuch' (tablecloth)."},
{type:"teach",trg:"der Sack",src:"the sack, the bag",pos:"noun",gender:"m",note:"Same word as English. In Austria: 'Sackerl' replaces 'T\u00fcte' for a small bag.",example:"A: Bring bitte einen Sack Kartoffeln mit.\nB: Vom Markt oder vom Supermarkt?\nA: Vom Markt, die sind frischer.\nB: Gut, ich nehme einen gro\u00dfen Sack.",exampleSrc:"A: Please bring a sack of potatoes.\nB: From the market or the supermarket?\nA: From the market, they are fresher.\nB: Good, I will take a big sack.",funFact:"Same word as English. In Austria and southern Germany, 'Sackerl' replaces 'T\u00fcte' for a small bag. 'Die Katze aus dem Sack lassen' (let the cat out of the bag) works in German too."},
{type:"teach",trg:"die B\u00fcchse",src:"the can, the tin, the box",pos:"noun",gender:"f",note:"'Konservenb\u00fcchse' (tin can). In some regions, B\u00fcchse and Dose are interchangeable.",example:"A: \u00d6ffne mal die B\u00fcchse mit den Bohnen.\nB: Wo ist der Dosenöffner?\nA: In der Schublade.\nB: Gefunden!",exampleSrc:"A: Open the can of beans.\nB: Where is the can opener?\nA: In the drawer.\nB: Found it!",funFact:"A can, tin, or box. 'Konservenb\u00fcchse' (tin can). In some regions, B\u00fcchse and Dose are interchangeable. Also historically a rifle or musket, from the cylindrical shape."},
{type:"teach",trg:"der Klo\u00df",src:"the dumpling",pos:"noun",gender:"m",note:"Plural: Kl\u00f6\u00dfe. In southern Germany: Kn\u00f6del. Classic side dish.",example:"A: Magst du Kl\u00f6\u00dfe?\nB: Ja! Kartoffelkl\u00f6\u00dfe sind mein Lieblingsbeilage.\nA: In Bayern sagt man Kn\u00f6del.\nB: Gleich lecker, egal wie man es nennt.",exampleSrc:"A: Do you like dumplings?\nB: Yes! Potato dumplings are my favorite side.\nA: In Bavaria they say Kn\u00f6del.\nB: Equally delicious, no matter what you call them.",funFact:"A dumpling. Plural: Kl\u00f6\u00dfe. In southern Germany: Kn\u00f6del. 'Einen Klo\u00df im Hals haben' (to have a dumpling in your throat) means to be choked up with emotion."},
{type:"teach",trg:"der Koch",src:"the cook, the chef",pos:"noun",gender:"m",note:"From Latin 'coquus.' 'Viele K\u00f6che verderben den Brei' (Too many cooks spoil the porridge).",example:"A: Der Koch hier ist fantastisch.\nB: Ja, alles schmeckt perfekt.\nA: Er kocht seit zwanzig Jahren.\nB: Erfahrung macht den Koch.",exampleSrc:"A: The chef here is fantastic.\nB: Yes, everything tastes perfect.\nA: He has been cooking for twenty years.\nB: Experience makes the chef.",funFact:"From Latin 'coquus.' 'Viele K\u00f6che verderben den Brei' (Too many cooks spoil the porridge). Same proverb, same meaning, same ancient wisdom."},
{type:"teach",trg:"die K\u00f6chin",src:"the cook, the chef (female)",pos:"noun",gender:"f",note:"Koch + -in. More women lead professional kitchens in Germany now.",example:"A: Die K\u00f6chin hat ein neues Rezept.\nB: Was gibt es heute?\nA: Spargelsuppe mit Br\u00f6tchen.\nB: Klingt wunderbar!",exampleSrc:"A: The chef has a new recipe.\nB: What is there today?\nA: Asparagus soup with bread rolls.\nB: Sounds wonderful!",funFact:"Female cook. Koch + -in. More and more women lead professional kitchens in Germany, though the industry still has a long way to go."},
{type:"teach",trg:"die Landwirtschaft",src:"the agriculture",pos:"noun",gender:"f",note:"'Land' (country/land) + 'Wirtschaft' (economy). Feminine because of -schaft.",example:"A: Die Landwirtschaft in Brandenburg ist wichtig.\nB: Ja, viele Bauernhöfe dort.\nA: Spargel kommt oft aus Brandenburg.\nB: Das beste Spargelgebiet Deutschlands!",exampleSrc:"A: Agriculture in Brandenburg is important.\nB: Yes, many farms there.\nA: Asparagus often comes from Brandenburg.\nB: The best asparagus region in Germany!",funFact:"'Land' (country/land) + 'Wirtschaft' (economy/management). Germany's agricultural sector feeds 80 million people efficiently."},
{type:"teach",trg:"aufwachen",src:"to wake up",pos:"verb",gender:null,note:"'Auf' (up) + 'wachen' (to be awake). Separable: 'Ich wache um sechs auf.'",example:"A: Wann bist du aufgewacht?\nB: Um sechs Uhr. Die V\u00f6gel haben mich geweckt.\nA: Im Sommer wache ich auch fr\u00fch auf.\nB: Das Licht kommt so fr\u00fch!",exampleSrc:"A: When did you wake up?\nB: At six o'clock. The birds woke me.\nA: In summer I also wake up early.\nB: The light comes so early!",funFact:"'Auf' (up) + 'wachen' (to be awake). Not to be confused with 'aufwecken' (to wake someone else up). Aufwachen is what you do. Aufwecken is what your alarm does to you."},
{type:"teach",trg:"bl\u00fchen",src:"to bloom, to blossom",pos:"verb",gender:null,note:"From the same root as 'Blume' (flower) and 'Bl\u00fcte' (blossom).",example:"A: Die Rosen bl\u00fchen wundersch\u00f6n.\nB: Ja, der Garten sieht toll aus.\nA: Im Fr\u00fchling bl\u00fcht alles.\nB: Meine Lieblingszeit!",exampleSrc:"A: The roses are blooming beautifully.\nB: Yes, the garden looks great.\nA: In spring everything blooms.\nB: My favorite time!",funFact:"To bloom, to blossom. Also figurative: 'Das Gesch\u00e4ft bl\u00fcht' (Business is blooming). From the same root as 'Blume' (flower) and 'Bl\u00fcte' (blossom)."},
{type:"teach",trg:"n\u00e4hern",src:"to approach, to come closer",pos:"verb",gender:null,note:"Often reflexive: 'sich n\u00e4hern.' From 'nah' (near).",example:"A: Wir n\u00e4hern uns dem Biergarten.\nB: Ich rieche schon die Bratwurst!\nA: Noch f\u00fcnf Minuten.\nB: Ich kann es kaum erwarten.",exampleSrc:"A: We are approaching the beer garden.\nB: I can already smell the bratwurst!\nA: Five more minutes.\nB: I can hardly wait.",funFact:"To approach, to come closer. Often reflexive: 'sich n\u00e4hern.' 'Wir n\u00e4hern uns dem Ziel' (We are approaching the goal). From 'nah' (near)."},
{type:"teach",trg:"pflanzen",src:"to plant",pos:"verb",gender:null,note:"From Latin 'planta.' 'Einen Baum pflanzen.' Also a noun: die Pflanze (the plant).",example:"A: Hast du die Tomaten gepflanzt?\nB: Ja, gestern Nachmittag.\nA: Wann k\u00f6nnen wir ernten?\nB: In ungef\u00e4hr zwei Monaten.",exampleSrc:"A: Did you plant the tomatoes?\nB: Yes, yesterday afternoon.\nA: When can we harvest?\nB: In about two months.",funFact:"From Latin 'planta.' Germans take gardening seriously: Kleing\u00e4rten (allotment gardens) are a national institution."},
{type:"teach",trg:"wachsen",src:"to grow",pos:"verb",gender:null,note:"Strong verb: wachsen, wuchs, gewachsen. Not to be confused with 'wachsen' (to wax).",example:"A: Der Spargel w\u00e4chst unter der Erde.\nB: Deshalb ist er wei\u00df?\nA: Genau! Ohne Licht bleibt er wei\u00df.\nB: Faszinierend!",exampleSrc:"A: Asparagus grows under the ground.\nB: That is why it is white?\nA: Exactly! Without light it stays white.\nB: Fascinating!",funFact:"Strong verb: wachsen, wuchs, gewachsen. 'Kinder wachsen schnell.' Not to be confused with 'wachsen' (to wax), which is a different verb with different origins."},
{type:"teach",trg:"gie\u00dfen",src:"to pour, to water (plants)",pos:"verb",gender:null,note:"Strong verb: goss, gegossen. 'Blumen gie\u00dfen,' 'Es gie\u00dft' (It is pouring rain).",example:"A: Kannst du die Blumen gie\u00dfen?\nB: Klar, die sehen trocken aus.\nA: Jeden Abend gie\u00dfen im Sommer.\nB: Sonst gehen sie ein.",exampleSrc:"A: Can you water the flowers?\nB: Sure, they look dry.\nA: Water them every evening in summer.\nB: Otherwise they will die.",funFact:"To pour or to water (plants). 'Blumen gie\u00dfen' (to water flowers). Strong verb: goss, gegossen. 'Es gie\u00dft' means 'It is pouring rain.'"},
{type:"mc",q:"Lukas sagt: '_____ ich das letzte Konzert mit meiner Band spielte, wusste ich nicht, dass es das letzte war.'",opts:["Wenn","Obwohl","Weil","Als"],ans:"Als",hint:"The last concert was a single, specific moment in the past."},
{type:"fb",s:"Mia sagt: Lukas spricht nicht {1} seine Band.",a:["\u00fcber"],opts:["\u00fcber","auf","an","f\u00fcr"],hint:"The verb 'sprechen' pairs with which preposition to mean 'talk about'?",sSrc:"Mia says: Lukas does not talk about his band."},
{type:"mc",q:"Lukas denkt oft an seine Band. Er denkt oft _____ .",opts:["daf\u00fcr","daran","darauf","dar\u00fcber"],ans:"daran",hint:"'Denken AN' requires da + an. What is da + an?"},
{type:"drag_fill",s:"{1} Lukas seine Band hatte, spielten sie jeden Freitag. {2} er jetzt allein spielt, klingt es anders.",blanks:{"1":"Als","2":"Wenn"},pool:["Als","Wenn","Weil","Dass","Ob"],hint:"First blank: having the band was a specific period in the past. Second blank: playing alone is a repeated present situation.",sSrc:"When Lukas had his band, they played every Friday. When he plays alone now, it sounds different."},
{type:"mc",q:"Wie fragt man 'Woran denkt Lukas?' auf Englisch?",opts:["What is Lukas interested in?","What is Lukas waiting for?","What is Lukas thinking about?","What is Lukas happy about?"],ans:"What is Lukas thinking about?",hint:"The verb is 'denken AN.' The wo-compound combines wo + an."},
{type:"fb",s:"Die Blumen auf der {1} bl\u00fchen im Sommer.",a:["Wiese"],opts:["Wiese","Feld","Gras","Landwirtschaft"],hint:"The word for a meadow where flowers and grass grow.",sSrc:"The flowers on the meadow bloom in summer."}
]},

// ─── Lesson 6: Dialekt auf dem Teller ───────────────────────────────
{id:"deu_r18l6",title:"Dialekt auf dem Teller",icon:"\uD83C\uDDE6\uD83C\uDDF9",xp:15,board:true,steps:[
{type:"intro",title:"Dialekt auf dem Teller",desc:"German is not one language but many regional flavors. Learn farming vocabulary, then discover what Austrians and Swiss call their food.",goals:["Learn words for farming, residents, and pets","Discover Austrian and Swiss German food vocabulary","Understand regional identity through food words"]},
{type:"teach",trg:"der Bauer",src:"the farmer",pos:"noun",gender:"m",note:"From Old High German 'giburo' (neighbor). Also the pawn in chess.",example:"A: Der Bauer verkauft frischen Spargel.\nB: Direkt vom Feld!\nA: Bauernm\u00e4rkte sind in Berlin beliebt.\nB: Jeden Samstag am Maybachufer.",exampleSrc:"A: The farmer sells fresh asparagus.\nB: Straight from the field!\nA: Farmers' markets are popular in Berlin.\nB: Every Saturday at Maybachufer.",funFact:"From Old High German 'giburo' (neighbor, fellow dweller). Also the pawn in chess. 'Bauernregel' (farmer's rule) = weather proverbs based on centuries of agricultural observation."},
{type:"teach",trg:"der Bauernhof",src:"the farm",pos:"noun",gender:"m",note:"'Bauer' + 'Hof' (yard/farm). Masculine because Hof is masculine.",example:"A: Warst du schon mal auf einem Bauernhof?\nB: Ja, als Kind. Wir haben Urlaub dort gemacht.\nA: Urlaub auf dem Bauernhof ist toll f\u00fcr Kinder.\nB: Und f\u00fcr Erwachsene!",exampleSrc:"A: Have you ever been to a farm?\nB: Yes, as a child. We vacationed there.\nA: Farm vacations are great for children.\nB: And for adults!",funFact:"'Bauer' + 'Hof' (yard/farm). 'Urlaub auf dem Bauernhof' (vacation on a farm) is a popular German family holiday."},
{type:"teach",trg:"der Bewohner",src:"the resident, the inhabitant",pos:"noun",gender:"m",note:"From 'bewohnen' (to inhabit). The Be- prefix + wohnen = who lives somewhere.",example:"A: Wie viele Bewohner hat das Haus?\nB: Zw\u00f6lf Parteien.\nA: Kennen sich alle?\nB: Die meisten, ja. Wir grillen zusammen.",exampleSrc:"A: How many residents does the building have?\nB: Twelve parties.\nA: Does everyone know each other?\nB: Most of them, yes. We barbecue together.",funFact:"From 'bewohnen' (to inhabit). 'Die Bewohner des Hauses' (the residents of the building). The Be- prefix + wohnen makes it about who lives somewhere."},
{type:"teach",trg:"die Bewohnerin",src:"the resident (female)",pos:"noun",gender:"f",note:"Bewohner + -in. On official forms: 'Bewohner/Bewohnerin.'",example:"A: Sind Sie Bewohnerin dieses Hauses?\nB: Ja, seit f\u00fcnf Jahren.\nA: Dann kennen Sie sicher Frau Schmidt.\nB: Nat\u00fcrlich, sie wohnt \u00fcber mir.",exampleSrc:"A: Are you a resident of this building?\nB: Yes, for five years.\nA: Then you surely know Mrs. Schmidt.\nB: Of course, she lives above me.",funFact:"Female resident. On official forms: 'Bewohner/Bewohnerin' or the modern 'Bewohnende' (gender-neutral)."},
{type:"teach",trg:"der Mieter",src:"the tenant",pos:"noun",gender:"m",note:"From 'mieten' (to rent). Over 50% of Germans rent rather than own.",example:"A: Der Mieter im dritten Stock zieht aus.\nB: Schade, er war nett.\nA: Wer wird der neue Mieter?\nB: Keine Ahnung, aber die Nachfrage ist gro\u00df.",exampleSrc:"A: The tenant on the third floor is moving out.\nB: Too bad, he was nice.\nA: Who will be the new tenant?\nB: No idea, but demand is high.",funFact:"From 'mieten' (to rent). Germany is a nation of renters: over 50% of Germans rent rather than own their home. Der Mieter has strong legal protections."},
{type:"teach",trg:"die Mieterin",src:"the tenant (female)",pos:"noun",gender:"f",note:"Mieter + -in. German rental law is among the most tenant-friendly in the world.",example:"A: Die Mieterin hat sich beschwert.\nB: Wor\u00fcber?\nA: \u00dcber den L\u00e4rm vom Biergarten.\nB: Verst\u00e4ndlich, aber es ist Sommer!",exampleSrc:"A: The tenant complained.\nB: About what?\nA: About the noise from the beer garden.\nB: Understandable, but it is summer!",funFact:"Female tenant. German rental law (Mietrecht) is among the most tenant-friendly in the world. Evictions are difficult. Rent caps exist."},
{type:"teach",trg:"das Haustier",src:"the pet",pos:"noun",gender:"n",note:"'Haus' (house) + 'Tier' (animal). Neuter because Tier is neuter.",example:"A: Hast du ein Haustier?\nB: Ja, eine Katze.\nA: Haustiere d\u00fcrfen in Bierg\u00e4rten meistens mit.\nB: Meine Katze bleibt lieber zu Hause.",exampleSrc:"A: Do you have a pet?\nB: Yes, a cat.\nA: Pets are usually allowed in beer gardens.\nB: My cat prefers to stay home.",funFact:"'Haus' (house) + 'Tier' (animal). Germans love their Haustiere: 34 million pets, more than in most European countries. Dogs can ride public transit."},
{type:"teach",trg:"die Marille",src:"the apricot (Austrian)",pos:"noun",gender:"f",note:"Austrian for 'Aprikose.' From Italian 'amarella' (little bitter one).",example:"A: In Wien sagt man Marille.\nB: Und in Berlin Aprikose.\nA: Marillenknödel sind österreichisch.\nB: Und unglaublich lecker!",exampleSrc:"A: In Vienna they say Marille.\nB: And in Berlin Aprikose.\nA: Apricot dumplings are Austrian.\nB: And incredibly delicious!",funFact:"Austrian for 'Aprikose' (apricot). From Italian 'amarella' (little bitter one). 'Marillenknödel' (apricot dumplings) are Austria's most famous dessert."},
{type:"teach",trg:"der Paradeiser",src:"the tomato (Austrian)",pos:"noun",gender:"m",note:"Austrian for 'Tomate.' From 'Paradiesapfel' (paradise apple).",example:"A: Gib mir bitte einen Paradeiser.\nB: Du meinst eine Tomate?\nA: In \u00d6sterreich sagen wir Paradeiser.\nB: Paradiesapfel, wie poetisch!",exampleSrc:"A: Please pass me a Paradeiser.\nB: You mean a tomato?\nA: In Austria we say Paradeiser.\nB: Paradise apple, how poetic!",funFact:"Austrian for 'Tomate.' From Italian 'pomodoro' (golden apple) via 'Paradiesapfel' (paradise apple). Austrians still call the tomato a 'paradise fruit.'"},
{type:"teach",trg:"der Erdapfel",src:"the potato (Austrian/Swiss)",pos:"noun",gender:"m",note:"'Erd' (earth) + 'Apfel' (apple). French says the same: 'pomme de terre.'",example:"A: Erdapfelsalat zum Schnitzel?\nB: Unbedingt! In \u00d6sterreich geh\u00f6rt das zusammen.\nA: Kartoffelsalat in Deutschland.\nB: Erdapfelsalat in Wien. Gleiches Gericht.",exampleSrc:"A: Potato salad with the schnitzel?\nB: Absolutely! In Austria they belong together.\nA: Kartoffelsalat in Germany.\nB: Erdapfelsalat in Vienna. Same dish.",funFact:"Austrian/Swiss for 'Kartoffel' (potato). 'Erd' (earth) + 'Apfel' (apple). An earth apple. French says the same: 'pomme de terre.' Three names for one vegetable."},
{type:"teach",trg:"das Henderl",src:"the chicken (Austrian)",pos:"noun",gender:"n",note:"Austrian diminutive. The -erl suffix is the Austrian form of -chen.",example:"A: Ein halbes Henderl, bitte!\nB: Mit Kartoffelsalat?\nA: Nat\u00fcrlich!\nB: Kommt sofort.",exampleSrc:"A: Half a chicken, please!\nB: With potato salad?\nA: Of course!\nB: Coming right up.",funFact:"Austrian dialect for a small chicken. The -erl suffix is the Austrian diminutive (like -chen in standard German). 'Ein halbes Henderl' is a classic Austrian Gasthaus order."},
{type:"teach",trg:"das Hendl",src:"the chicken (Bavarian)",pos:"noun",gender:"n",note:"Bavarian dialect. Even shorter than Henderl. Neuter because of the diminutive.",example:"A: Auf dem Oktoberfest gibt es Hendl.\nB: Hendl mit Kartoffelsalat!\nA: Das klassische Oktoberfest-Essen.\nB: Dazu eine Ma\u00df Bier.",exampleSrc:"A: At Oktoberfest there is chicken.\nB: Chicken with potato salad!\nA: The classic Oktoberfest meal.\nB: With a liter of beer.",funFact:"Bavarian dialect for chicken. Even shorter than Henderl. 'Hendl mit Kartoffelsalat' is the quintessential Oktoberfest meal."},
{type:"teach",trg:"das Obers",src:"the cream (Austrian)",pos:"noun",gender:"n",note:"Austrian for 'Sahne.' From 'das Obere' (the top part) because cream rises to the top.",example:"A: Kaffee mit Obers, bitte.\nB: In Deutschland sagt man Sahne.\nA: Aber Obers klingt sch\u00f6ner.\nB: Finde ich auch!",exampleSrc:"A: Coffee with cream, please.\nB: In Germany they say Sahne.\nA: But Obers sounds nicer.\nB: I think so too!",funFact:"Austrian for 'Sahne' (cream). From 'das Obere' (the top part) because cream rises to the top of milk. 'Kaffee mit Obers' is how you order coffee with cream in Vienna."},
{type:"teach",trg:"der Schwammerl",src:"the mushroom (Bavarian/Austrian)",pos:"noun",gender:"m",note:"The -erl diminutive. 'Schwammerlsuppe' (mushroom soup) is Bavarian comfort food.",example:"A: Gehen wir Schwammerl suchen!\nB: Im Wald? Ist das nicht gef\u00e4hrlich?\nA: Nicht, wenn man sich auskennt.\nB: Schwammerlsuppe w\u00e4re toll.",exampleSrc:"A: Let us go mushroom hunting!\nB: In the forest? Is that not dangerous?\nA: Not if you know what you are doing.\nB: Mushroom soup would be great.",funFact:"Bavarian/Austrian for 'Pilz' (mushroom). 'Schwammerlsuppe' (mushroom soup) is comfort food in Bavaria and Austria. Standard German 'Pilz' sounds clinical by comparison."},
{type:"teach",trg:"der Fleischhauer",src:"the butcher (Austrian)",pos:"noun",gender:"m",note:"'Fleisch' (meat) + 'Hauer' (one who chops). The word paints a picture.",example:"A: Wo ist der n\u00e4chste Fleischhauer?\nB: In \u00d6sterreich sagt man Fleischhauer.\nA: In Deutschland Metzger oder Fleischer.\nB: Drei W\u00f6rter, ein Beruf.",exampleSrc:"A: Where is the nearest butcher?\nB: In Austria they say Fleischhauer.\nA: In Germany Metzger or Fleischer.\nB: Three words, one trade.",funFact:"Austrian for 'Metzger' (butcher). 'Fleisch' (meat) + 'Hauer' (one who chops). Standard German has Metzger (south) and Fleischer (north). Three words, one trade."},
{type:"teach",trg:"das Backrohr",src:"the oven (Austrian)",pos:"noun",gender:"n",note:"'Back' (bake) + 'Rohr' (pipe/tube). The oven as a baking tube.",example:"A: Schieb den Kuchen ins Backrohr!\nB: Auf welcher Temperatur?\nA: 180 Grad, wie immer.\nB: In Deutschland sagt man Backofen.",exampleSrc:"A: Put the cake in the oven!\nB: At what temperature?\nA: 180 degrees, as always.\nB: In Germany they say Backofen.",funFact:"Austrian for 'Backofen' (oven). 'Back' (bake) + 'Rohr' (pipe/tube). The oven as a baking tube. Same appliance, Austrian name."},
{type:"teach",trg:"das Br\u00f6tli",src:"the bread roll (Swiss)",pos:"noun",gender:"n",note:"Swiss diminutive. The -li suffix is the Swiss form of -chen.",example:"A: Ein Br\u00f6tli mit Butter, bitte.\nB: In Z\u00fcrich sagt man Br\u00f6tli.\nA: In Berlin Br\u00f6tchen, in M\u00fcnchen Semmel.\nB: Jede Region hat ihr eigenes Wort!",exampleSrc:"A: A bread roll with butter, please.\nB: In Zurich they say Br\u00f6tli.\nA: In Berlin Br\u00f6tchen, in Munich Semmel.\nB: Every region has its own word!",funFact:"Swiss German for 'Br\u00f6tchen' (bread roll). The -li suffix is the Swiss diminutive. Every German-speaking country has its own word for a bread roll."},
{type:"teach",trg:"die Glace",src:"the ice cream (Swiss)",pos:"noun",gender:"f",note:"Swiss German for 'Eis.' From French 'glace' (ice). Shows French influence.",example:"A: M\u00f6chtest du eine Kugel Glace?\nB: In der Schweiz sagt man so.\nA: Eine Kugel Glace in Bern, eine Kugel Eis in Berlin.\nB: Hauptsache, es schmeckt!",exampleSrc:"A: Would you like a scoop of ice cream?\nB: In Switzerland they say it that way.\nA: A scoop of Glace in Bern, a scoop of Eis in Berlin.\nB: The main thing is it tastes good!",funFact:"Swiss German for 'Eis' (ice cream). From French 'glace' (ice). Switzerland's French influence shows in its food vocabulary."},
{type:"tip",title:"Drei L\u00e4nder, drei K\u00fcchen",text:"German is spoken in Germany, Austria, and Switzerland (plus Liechtenstein, Luxembourg, and parts of Belgium and Italy). Each country has unique food vocabulary.\n\nStandard German is understood everywhere, but regional terms carry identity:\n\nTomate (DE) = Paradeiser (AT)\nKartoffel (DE) = Erdapfel (AT/CH)\nSahne (DE) = Obers (AT)\nBr\u00f6tchen (DE) = Semmel (BY/AT) = Br\u00f6tli (CH)\nEis (DE) = Glace (CH)\nPilz (DE) = Schwammerl (BY/AT)\n\nThe Biergarten is Bavarian. The Beisl is Austrian. The Beiz is Swiss. Same concept: a place to eat, drink, and belong.",deepDive:"Knowing regional variants shows respect and cultural awareness. Austrian German (Österreichisches Deutsch) and Swiss Standard German (Schweizer Hochdeutsch) are officially recognized standard varieties, not dialects. They have their own dictionaries and official vocabulary lists."},
{type:"mc",q:"In \u00d6sterreich hei\u00dft 'Sahne' (cream) wie?",opts:["Br\u00f6tli","Obers","Glace","Paradeiser"],ans:"Obers",hint:"This word comes from 'das Obere' because cream rises to the top of the milk."},
{type:"fb",s:"In Wien bestellt man 'Kaffee mit {1}' statt 'Kaffee mit Sahne.'",a:["Obers"],opts:["Obers","Glace","Marille","Erdapfel"],hint:"The Austrian word for cream, from 'the top part' of milk.",sSrc:"In Vienna you order 'coffee with Obers' instead of 'coffee with Sahne.'"},
{type:"match",pairs:[{trg:"Marille",src:"Aprikose"},{trg:"Paradeiser",src:"Tomate"},{trg:"Erdapfel",src:"Kartoffel"},{trg:"Schwammerl",src:"Pilz"}]},
{type:"mc",q:"'Die Bewohner warten _____ den Fr\u00fchling.' Welche Pr\u00e4position erg\u00e4nzt 'warten'?",opts:["f\u00fcr","\u00fcber","an","auf"],ans:"auf",hint:"Warten always pairs with this preposition. You wait ON something."},
{type:"mc",q:"'_____ ich in Wien war, habe ich zum ersten Mal Marillenkn\u00f6del probiert.'",opts:["Wenn","Damit","Als","Weil"],ans:"Als",hint:"Being in Vienna was a specific trip in the past. One time."}
]},

// ─── Lesson 7: Prost und Wiederholung ───────────────────────────────
{id:"deu_r18l7",title:"Prost und Wiederholung",icon:"\uD83C\uDF7B",xp:15,board:true,steps:[
{type:"intro",title:"Prost und Wiederholung",desc:"Time to prove your skills. Review all Unit 18 grammar, vocabulary, and cultural knowledge in a comprehensive assessment.",goals:["Test als vs wenn in varied contexts","Prove mastery of verbs with fixed prepositions","Use da-/wo- compounds fluently"]},
{type:"teach",trg:"der Abt",src:"the abbot",pos:"noun",gender:"m",note:"From Latin 'abbas.' Many German breweries were founded by monks.",example:"A: Der Abt leitete das Kloster.\nB: Und die Brauerei!\nA: Klosterbier hat eine lange Tradition.\nB: Manche Kl\u00f6ster brauen noch heute.",exampleSrc:"A: The abbot led the monastery.\nB: And the brewery!\nA: Monastery beer has a long tradition.\nB: Some monasteries still brew today.",funFact:"From Latin 'abbas.' Many German breweries were founded by monks, and the Abt supervised beer production. 'Klosterbier' (monastery beer) has a centuries-old tradition."},
{type:"teach",trg:"der Abwart",src:"the caretaker (Swiss)",pos:"noun",gender:"m",note:"Swiss German for 'Hausmeister.' 'Ab' (away) + 'Wart' (one who watches).",example:"A: Der Abwart k\u00fcmmert sich um das Geb\u00e4ude.\nB: In Deutschland sagt man Hausmeister.\nA: In der Schweiz ist es der Abwart.\nB: Wieder ein regionales Wort!",exampleSrc:"A: The caretaker takes care of the building.\nB: In Germany they say Hausmeister.\nA: In Switzerland it is the Abwart.\nB: Another regional word!",funFact:"Swiss German for 'Hausmeister' (caretaker/janitor). 'Ab' (away) + 'Wart' (one who watches). The person who watches over a building."},
{type:"teach",trg:"die Abwartin",src:"the caretaker (female, Swiss)",pos:"noun",gender:"f",note:"Abwart + -in. Swiss German follows the same -in pattern for feminine forms.",example:"A: Die Abwartin hat den Flur geputzt.\nB: Sie macht das jeden Morgen.\nA: In der Schweiz sagt man Abwartin.\nB: Und in Deutschland Hausmeisterin.",exampleSrc:"A: The caretaker cleaned the hallway.\nB: She does that every morning.\nA: In Switzerland they say Abwartin.\nB: And in Germany Hausmeisterin.",funFact:"Female caretaker. Swiss German follows the same -in pattern for feminine forms as standard German."},
{type:"teach",trg:"der Bub",src:"the boy (Bavarian/Austrian/Swiss)",pos:"noun",gender:"m",note:"Southern German for 'Junge.' Used across all southern German-speaking regions.",example:"A: Der Bub spielt im Garten.\nB: In Bayern sagt man Bub.\nA: In Norddeutschland sagt man Junge.\nB: Nord-S\u00fcd-Unterschied, wie immer.",exampleSrc:"A: The boy is playing in the garden.\nB: In Bavaria they say Bub.\nA: In northern Germany they say Junge.\nB: North-south difference, as always.",funFact:"Bavarian/Austrian/Swiss for 'Junge' (boy). 'Ein lieber Bub.' In northern Germany, nobody says Bub. Another north-south divide."},
{type:"teach",trg:"der Feber",src:"February (Austrian)",pos:"noun",gender:"m",note:"Austrian for 'Februar.' Shortened, localized. Instantly marks someone as Austrian.",example:"A: Im Feber ist es kalt in Wien.\nB: Feber? Du meinst Februar?\nA: In \u00d6sterreich sagen wir Feber.\nB: Wieder was gelernt!",exampleSrc:"A: In Feber it is cold in Vienna.\nB: Feber? You mean February?\nA: In Austria we say Feber.\nB: Learned something new!",funFact:"Austrian for 'Februar.' One of those calendar words that instantly tells you someone is Austrian."},
{type:"teach",trg:"das Poulet",src:"the chicken (Swiss)",pos:"noun",gender:"n",note:"From French 'poulet.' Switzerland's French influence again.",example:"A: Poulet mit Pommes, bitte.\nB: In Z\u00fcrich sagt man Poulet.\nA: In Berlin H\u00e4hnchen, in M\u00fcnchen Hendl.\nB: Drei L\u00e4nder, drei H\u00fchner!",exampleSrc:"A: Chicken with fries, please.\nB: In Zurich they say Poulet.\nA: In Berlin H\u00e4hnchen, in Munich Hendl.\nB: Three countries, three chickens!",funFact:"Swiss German for 'H\u00e4hnchen' (chicken). From French 'poulet.' 'Poulet mit Pommes' in Zurich = 'H\u00e4hnchen mit Pommes' in Berlin = 'Hendl mit Pommes' in Munich."},
{type:"teach",trg:"ein paar",src:"a few, some",pos:"pron",gender:null,note:"Written lowercase. 'Ein Paar' (capitalized) = a pair/couple. Case matters!",example:"A: Ich brauche ein paar Minuten.\nB: Kein Problem, nimm dir Zeit.\nA: Ein paar Freunde kommen sp\u00e4ter.\nB: Je mehr, desto besser!",exampleSrc:"A: I need a few minutes.\nB: No problem, take your time.\nA: A few friends are coming later.\nB: The more, the merrier!",funFact:"Written lowercase (unlike 'ein Paar' = a pair/couple). 'Ein paar Freunde' = a few friends. 'Ein Paar Schuhe' = a pair of shoes. The capital P changes the meaning entirely."},
{type:"teach",trg:"halt",src:"just, simply (particle)",pos:"part",gender:null,note:"'Das ist halt so.' Extremely common in spoken German, especially southern.",example:"A: Warum regnet es so viel?\nB: Das ist halt Sommer in Berlin.\nA: Ich wollte im Biergarten sitzen.\nB: Dann musst du halt warten.",exampleSrc:"A: Why does it rain so much?\nB: That is just how summer is in Berlin.\nA: I wanted to sit in the beer garden.\nB: Then you just have to wait.",funFact:"A particle meaning 'just, simply.' 'Das ist halt so' (That is just how it is). Extremely common in spoken German, especially southern. Signals acceptance or resignation."},
{type:"teach",trg:"extra",src:"extra, on purpose, especially",pos:"adv",gender:null,note:"Same as English. Also means 'on purpose': 'Das hast du extra gemacht!'",example:"A: Ich habe extra f\u00fcr dich Spargel gekauft.\nB: Wie nett von dir!\nA: Der letzte der Saison.\nB: Extra f\u00fcr mich? Danke!",exampleSrc:"A: I bought asparagus especially for you.\nB: How nice of you!\nA: The last of the season.\nB: Especially for me? Thanks!",funFact:"Same as English 'extra.' Also means 'on purpose': 'Das hast du extra gemacht!' (You did that on purpose!)."},
{type:"teach",trg:"gratis",src:"free (of charge)",pos:"adv",gender:null,note:"From Latin 'gratis.' Also 'kostenlos' or 'umsonst.'",example:"A: Ist der Eintritt gratis?\nB: Ja, der Biergarten ist frei zug\u00e4nglich.\nA: Und das Wasser?\nB: Auch gratis, zum Bier dazu.",exampleSrc:"A: Is admission free?\nB: Yes, the beer garden is freely accessible.\nA: And the water?\nB: Also free, with the beer.",funFact:"From Latin 'gratis' (for free). 'Der Eintritt ist gratis.' Germans also say 'kostenlos' (costless) or 'umsonst' (for nothing)."},
{type:"teach",trg:"jedes Mal",src:"every time",pos:"adv",gender:null,note:"'Jedes' (every) + 'Mal' (time). Perfect with 'wenn' for repeated actions.",example:"A: Jedes Mal, wenn ich hier bin, bestelle ich Spargel.\nB: Du bist wie Heinrich!\nA: Jedes Mal schmeckt es anders.\nB: Das macht es spannend.",exampleSrc:"A: Every time I am here, I order asparagus.\nB: You are like Heinrich!\nA: Every time it tastes different.\nB: That makes it exciting.",funFact:"'Jedes' (every) + 'Mal' (time/instance). 'Jedes Mal, wenn ich im Biergarten bin, bestelle ich Spargel.' Perfect with 'wenn' for repeated actions."},
{type:"teach",trg:"nebenbei",src:"on the side, incidentally, by the way",pos:"adv",gender:null,note:"'Neben' (beside) + 'bei' (by). A useful conversational filler.",example:"A: Nebenbei bemerkt, der Spargel war fantastisch.\nB: Finde ich auch!\nA: Und nebenbei: Lukas hat toll gespielt.\nB: Ja, wirklich beeindruckend.",exampleSrc:"A: By the way, the asparagus was fantastic.\nB: I think so too!\nA: And incidentally: Lukas played great.\nB: Yes, really impressive.",funFact:"'Neben' (beside) + 'bei' (by). 'Nebenbei bemerkt...' (By the way...). Also 'nebenbei arbeiten' (to work on the side). A useful conversational filler."},
{type:"teach",trg:"au",src:"ouch, ow",pos:"intj",gender:null,note:"An exclamation of pain or surprise. Short for 'Aua!' Also a place name element.",example:"A: Au! Das war hei\u00df!\nB: Vorsicht mit dem Grill!\nA: Au, mein Finger!\nB: Zeig mal, ist es schlimm?",exampleSrc:"A: Ouch! That was hot!\nB: Careful with the grill!\nA: Ow, my finger!\nB: Let me see, is it bad?",funFact:"An exclamation of pain or surprise. 'Au! Das war hei\u00df!' Short for 'Aua!' Also a place name element: 'Au' means a water meadow."},
{type:"teach",trg:"der Blitz",src:"the lightning, the flash",pos:"noun",gender:"m",note:"Also 'Blitzkrieg' (lightning war), 'Blitzeis' (flash ice). Fast and sudden.",example:"A: Hast du den Blitz gesehen?\nB: Ja! Und dann der Donner!\nA: Ein Gewitter im Biergarten.\nB: Schnell, unter das Dach!",exampleSrc:"A: Did you see the lightning?\nB: Yes! And then the thunder!\nA: A thunderstorm in the beer garden.\nB: Quick, under the roof!",funFact:"Same word as English 'blitz.' 'Blitzschnell' (lightning fast), 'Blitzeis' (flash ice on roads). Also the camera flash. Germans say 'Blitz' when a summer storm interrupts a Biergarten evening."},
{type:"mc",q:"'Jedes Mal, _____ wir im Biergarten sind, bestellt Hildi Spargel.' Welches Wort passt?",opts:["obwohl","als","wenn","weil"],ans:"wenn",hint:"'Jedes Mal' signals repetition. Which 'when' word is for repeated events?"},
{type:"mc",q:"Heinrich _____ auf frischem Spargel. (besteht auf)",opts:["besteht","denkt","freut sich","wartet"],ans:"besteht",hint:"Which verb means 'to insist' and pairs with 'auf'?"},
{type:"fb",s:"Mia interessiert sich f\u00fcr Bio-Essen. Sie interessiert sich {1}.",a:["daf\u00fcr"],opts:["daf\u00fcr","darauf","dar\u00fcber","daran"],hint:"The verb is 'sich interessieren F\u00dcR.' Replace 'f\u00fcr Bio-Essen' with da + f\u00fcr.",sSrc:"Mia is interested in organic food. She is interested in it."},
{type:"mc",q:"Du willst fragen 'Wor\u00fcber freust du dich?' Was bedeutet das auf Englisch?",opts:["What are you waiting for?","What are you happy about?","What are you thinking of?","What are you interested in?"],ans:"What are you happy about?",hint:"Being happy ABOUT something uses 'sich freuen \u00dcBER.' The wo-compound is wo + \u00fcber."},
{type:"drag_fill",s:"{1} ich zum ersten Mal Spargel a\u00df, freute ich mich {2}. Jetzt freue ich mich {3} Mal {4}.",blanks:{"1":"Als","2":"dar\u00fcber","3":"jedes","4":"darauf"},pool:["Als","Wenn","dar\u00fcber","darauf","daran","jedes","jede","daf\u00fcr"],hint:"First: one-time past event. Second: happy ABOUT it (past, da + \u00fcber). Third + fourth: every time, looking forward to it (future, da + auf).",sSrc:"When I ate asparagus for the first time, I was happy about it. Now I look forward to it every time."},
{type:"mc",q:"'Poulet' ist das Schweizer Wort f\u00fcr...",opts:["Schweinefleisch (pork)","Rindfleisch (beef)","Lamm (lamb)","H\u00e4hnchen (chicken)"],ans:"H\u00e4hnchen (chicken)",hint:"This word comes from French and refers to poultry."},
{type:"fb",s:"Der Eintritt zum Biergarten ist {1}. Man muss nichts bezahlen.",a:["gratis"],opts:["gratis","extra","halt","nebenbei"],hint:"A word from Latin meaning 'for free.'",sSrc:"Admission to the beer garden is free. You do not have to pay anything."},
{type:"match",pairs:[{trg:"Als ich ankam",src:"When I arrived (one time)"},{trg:"Wenn ich esse",src:"When(ever) I eat"},{trg:"sich freuen auf",src:"to look forward to"},{trg:"Worauf wartest du?",src:"What are you waiting for?"}]},
{type:"mc",q:"'_____ wartet Verumius?' -- 'Auf den Kellner. Er wartet _____.'",opts:["Woran...daran","Wof\u00fcr...daf\u00fcr","Wor\u00fcber...dar\u00fcber","Worauf...darauf"],ans:"Worauf...darauf",hint:"'Warten AUF' is the fixed combo. Question = wo + auf. Answer = da + auf."},
{type:"drag_fill",s:"{1} wir im Biergarten sa\u00dfen, rief Heinrich an. Er bestand {2}, dass wir Spargel bestellen.",blanks:{"1":"Als","2":"darauf"},pool:["Als","Wenn","darauf","dar\u00fcber","daran","Weil"],hint:"Sitting in the beer garden was a specific moment. Heinrich insisted ON it: bestehen auf = darauf.",sSrc:"When we were sitting in the beer garden, Heinrich called. He insisted that we order asparagus."}
]},

// ─── Lesson 8: Der Nachhauseweg ─────────────────────────────────────
{id:"deu_r18l8",title:"Der Nachhauseweg",icon:"\uD83C\uDF19",xp:15,board:true,steps:[
{type:"intro",title:"Der Nachhauseweg",desc:"Berlin summer night. The group walks home together, splitting off one by one. Final vocabulary, final grammar assessment, and a moment of belonging.",goals:["Learn remaining vocabulary for food, farming, and daily life","Master all three grammar constructs in combination","Reflect on friendship and belonging"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-ber-summer-night-street",trg:"Berliner Sommernacht. Die Gruppe str\u00f6mt aus dem Biergarten. Stra\u00dfenlaternen leuchten durch Lindenb\u00e4ume. Die Luft ist warm. Mia schaut auf ihr Handy, ob die letzte U-Bahn noch f\u00e4hrt.",src:"Berlin summer night. The group spills out of the beer garden. Streetlights glow through linden trees. The air is warm. Mia checks her phone for the last U-Bahn."},
{type:"story",speaker:"mia",mood:"happy",trg:"Das war ein sch\u00f6ner Abend. Wir sollten das \u00f6fter machen. Jedes Mal, wenn wir uns treffen, f\u00fchlt es sich wie Zuhause an.",src:"That was a lovely evening. We should do this more often. Every time we meet, it feels like home."},
{type:"story",speaker:"hildi",mood:"soft",trg:"Als mein Mann noch lebte, gingen wir jeden Sommer in den Biergarten. Ich hatte mich so darauf gefreut, heute wieder dort zu sein.",src:"When my husband was still alive, we went to the beer garden every summer. I had looked forward to being there again today."},
{type:"story",speaker:"lukas",mood:"quiet",trg:"Danke f\u00fcr heute. Ich habe lange nicht gespielt. Ich freue mich dar\u00fcber, dass ihr zugeh\u00f6rt habt.",src:"Thanks for today. I have not played in a long time. I am happy that you listened."},
{type:"story",speaker:"verumius",mood:"belonging",art:"de-ber-building-entrance-night",trg:"Verumius geht die letzten Meter allein. Der Hauseingang ist vor ihm. Hildis Licht brennt schon oben. Er denkt: 'Als ich nach Berlin kam, kannte ich niemanden. Jetzt wartet jemand auf mich.'",src:"Verumius walks the last meters alone. The building entrance is ahead. Hildi's light is already on upstairs. He thinks: 'When I came to Berlin, I knew no one. Now someone is waiting for me.'"},
{type:"teach",trg:"der Metzger",src:"the butcher",pos:"noun",gender:"m",note:"Standard southern German. Northern: 'Fleischer.' Austrian: 'Fleischhauer.' Three words, one trade.",example:"A: Ich gehe zum Metzger.\nB: Bring bitte Bratwurst mit!\nA: Vom Metzger oder vom Supermarkt?\nB: Vom Metzger, die schmeckt besser.",exampleSrc:"A: I am going to the butcher.\nB: Please bring bratwurst!\nA: From the butcher or the supermarket?\nB: From the butcher, it tastes better.",funFact:"Standard southern German. Northern Germans say 'Fleischer,' Austrians say 'Fleischhauer.' From Latin 'macellarius' (slaughterer). Every region defends its word."},
{type:"teach",trg:"ern\u00e4hren",src:"to nourish, to feed",pos:"verb",gender:null,note:"Reflexive: 'sich ern\u00e4hren' (to eat, to sustain oneself). From 'Nahrung.'",example:"A: Wie ern\u00e4hrst du dich?\nB: Ich ern\u00e4hre mich meistens vegetarisch.\nA: Das ist gesund.\nB: Und gut f\u00fcr die Umwelt.",exampleSrc:"A: How do you eat?\nB: I eat mostly vegetarian.\nA: That is healthy.\nB: And good for the environment.",funFact:"Reflexive: 'sich ern\u00e4hren' (to eat, to sustain oneself). 'Sich gesund ern\u00e4hren' (to eat healthily). The er- prefix makes it about achieving nourishment."},
{type:"teach",trg:"fressen",src:"to eat (for animals)",pos:"verb",gender:null,note:"Using 'fressen' for a person is rude. Humans 'essen,' animals 'fressen.'",example:"A: Die Katze frisst ihr Futter.\nB: Sie frisst immer so schnell.\nA: Sag nie 'fressen' \u00fcber einen Menschen!\nB: Warum nicht?\nA: Das ist sehr unhöflich.",exampleSrc:"A: The cat eats its food.\nB: She always eats so fast.\nA: Never say 'fressen' about a person!\nB: Why not?\nA: That is very rude.",funFact:"To eat (for animals). 'Der Hund frisst.' Using 'fressen' for a person is rude: 'Er frisst wie ein Schwein' (He eats like a pig). The distinction matters."},
{type:"teach",trg:"f\u00fcttern",src:"to feed (an animal or baby)",pos:"verb",gender:null,note:"From 'Futter' (animal food/feed). 'Die Enten f\u00fcttern' (to feed the ducks).",example:"A: D\u00fcrfen wir die Enten f\u00fcttern?\nB: Ja, aber nur mit Haferflocken.\nA: Kein Brot?\nB: Nein, Brot ist schlecht f\u00fcr Enten.",exampleSrc:"A: Can we feed the ducks?\nB: Yes, but only with oat flakes.\nA: No bread?\nB: No, bread is bad for ducks.",funFact:"From 'Futter' (animal food/feed). Also slang: 'Ich muss meinen Computer f\u00fcttern' (I need to feed data into my computer)."},
{type:"teach",trg:"grillieren",src:"to barbecue (Swiss)",pos:"verb",gender:null,note:"Swiss German for 'grillen.' The -ieren suffix shows French influence.",example:"A: Wollen wir am Wochenende grillieren?\nB: In der Schweiz sagt man grillieren.\nA: In Deutschland grillen.\nB: Gleicher Rauch, anderes Verb!",exampleSrc:"A: Shall we barbecue this weekend?\nB: In Switzerland they say grillieren.\nA: In Germany grillen.\nB: Same smoke, different verb!",funFact:"Swiss German for 'grillen.' The -ieren suffix shows French influence. In Switzerland: 'Wir grillieren am See.' In Germany: 'Wir grillen im Park.'"},
{type:"teach",trg:"n\u00e4hen",src:"to sew",pos:"verb",gender:null,note:"From Old High German 'najen.' Related to English 'needle.'",example:"A: Kannst du n\u00e4hen?\nB: Ja, ich n\u00e4he meine Kn\u00f6pfe selbst an.\nA: Ich brauche eine N\u00e4hmaschine.\nB: F\u00fcr gro\u00dfe Projekte lohnt sich das.",exampleSrc:"A: Can you sew?\nB: Yes, I sew my own buttons on.\nA: I need a sewing machine.\nB: For big projects it is worth it.",funFact:"To sew. From Old High German 'najen.' Related to English 'needle' through the same root. 'Mit hei\u00dfer Nadel gen\u00e4ht' (sewn with a hot needle) means done hastily."},
{type:"teach",trg:"n\u00fctzen",src:"to be useful, to use",pos:"verb",gender:null,note:"Southern/Austrian variant of 'nutzen.' Both are correct.",example:"A: Das n\u00fctzt nichts.\nB: Doch, es n\u00fctzt mehr als du denkst.\nA: In \u00d6sterreich sagt man n\u00fctzen.\nB: In Deutschland auch nutzen.",exampleSrc:"A: That is no use.\nB: Yes it is, it helps more than you think.\nA: In Austria they say n\u00fctzen.\nB: In Germany also nutzen.",funFact:"Southern German and Austrian variant of 'nutzen.' Both are correct. The \u00fc vs u distinction is regional, not grammatical."},
{type:"teach",trg:"nutzen",src:"to use, to make use of",pos:"verb",gender:null,note:"Standard German variant. 'Die Gelegenheit nutzen' (to seize the opportunity).",example:"A: Nutze die Gelegenheit!\nB: Welche Gelegenheit?\nA: Der letzte Spargel der Saison!\nB: Du hast recht, ich nutze sie.",exampleSrc:"A: Seize the opportunity!\nB: Which opportunity?\nA: The last asparagus of the season!\nB: You are right, I will seize it.",funFact:"'Die Gelegenheit nutzen' (to seize the opportunity). 'Nutzen' as a noun (der Nutzen) means benefit. Verb and noun share the same form."},
{type:"teach",trg:"runterwerfen",src:"to throw down",pos:"verb",gender:null,note:"'Runter' (down) + 'werfen' (to throw). Separable. Colloquial contraction of 'herunterwerfen.'",example:"A: Wirf das nicht runter!\nB: Entschuldigung, es ist mir aus der Hand gerutscht.\nA: Der Bierkrug ist fast runtergefallen.\nB: Zum Gl\u00fcck nicht!",exampleSrc:"A: Do not throw that down!\nB: Sorry, it slipped out of my hand.\nA: The beer stein almost fell down.\nB: Luckily not!",funFact:"'Runter' (down) + 'werfen' (to throw). Separable. Colloquial contraction of 'herunterwerfen.' Spoken German loves shortening."},
{type:"teach",trg:"verpflegen",src:"to cater, to provide food and care",pos:"verb",gender:null,note:"From 'Pflege' (care) + ver- prefix. 'Die G\u00e4ste verpflegen.'",example:"A: Wer verpflegt die G\u00e4ste heute?\nB: Der Koch und seine K\u00f6chin.\nA: Die Verpflegung war ausgezeichnet.\nB: Ja, alles frisch und lecker.",exampleSrc:"A: Who caters for the guests today?\nB: The chef and his cook.\nA: The catering was excellent.\nB: Yes, everything fresh and delicious.",funFact:"From 'Pflege' (care) + ver- prefix. 'Verpflegung' (catering/provisions) appears on conference schedules. The word covers providing complete food and care."},
{type:"teach",trg:"bio-",src:"organic, biological (prefix)",pos:"noun",gender:null,note:"Prefix meaning organic. 'Bio-Markt,' 'Bio-Bauer,' 'Bio-Milch.' Legally protected in the EU.",example:"A: Kaufst du im Bio-Markt ein?\nB: Ja, meistens Bio-Gem\u00fcse.\nA: Bio-Produkte sind teurer.\nB: Aber die Qualit\u00e4t lohnt sich.",exampleSrc:"A: Do you shop at the organic market?\nB: Yes, mostly organic vegetables.\nA: Organic products are more expensive.\nB: But the quality is worth it.",funFact:"Prefix meaning organic or biological. In German, bio- attaches to almost any food noun. The prefix alone on a label means certified organic under EU regulation."},
{type:"teach",trg:"einzel-",src:"single, individual (prefix)",pos:"noun",gender:null,note:"'Einzelzimmer' (single room), 'Einzelkind' (only child), 'Einzelhandel' (retail).",example:"A: Ich brauche ein Einzelzimmer.\nB: F\u00fcr wie viele N\u00e4chte?\nA: Drei. Und bitte kein Einzelkind-Zuschlag.\nB: Kein Problem!",exampleSrc:"A: I need a single room.\nB: For how many nights?\nA: Three. And please no single supplement.\nB: No problem!",funFact:"Prefix meaning single or individual. 'Einzelzimmer' (single room), 'Einzelkind' (only child), 'Einzelhandel' (retail). One of German's most productive compound prefixes."},
{type:"mc",q:"'_____ Verumius nach Berlin kam, kannte er niemanden.' Welches Wort?",opts:["Wenn","Weil","Als","Obwohl"],ans:"Als",hint:"Arriving in Berlin was a single event in the past."},
{type:"mc",q:"Lukas freut sich dar\u00fcber, dass seine Freunde zugeh\u00f6rt haben. Was ersetzt 'dar\u00fcber'?",opts:["f\u00fcr + die Tatsache, dass sie zugeh\u00f6rt haben","\u00fcber + die Tatsache, dass sie zugeh\u00f6rt haben","auf + die Tatsache, dass sie zugeh\u00f6rt haben","an + die Tatsache, dass sie zugeh\u00f6rt haben"],ans:"\u00fcber + die Tatsache, dass sie zugeh\u00f6rt haben",hint:"Being happy ABOUT something uses 'sich freuen \u00dcBER.' Da + \u00fcber = dar\u00fcber."},
{type:"fb",s:"{1} besteht Heinrich? -- Darauf, dass wir Spargel bestellen.",a:["Worauf"],opts:["Worauf","Wor\u00fcber","Woran","Wof\u00fcr"],hint:"Bestehen AUF. The question form uses wo + auf.",sSrc:"What does Heinrich insist on? -- That we order asparagus."},
{type:"drag_fill",s:"{1} wir im Biergarten waren, freute sich Hildi {2}. Sie hatte sich lange {3} gefreut.",blanks:{"1":"Als","2":"dar\u00fcber","3":"darauf"},pool:["Als","Wenn","dar\u00fcber","darauf","daran","daf\u00fcr"],hint:"First: specific past evening (als). Second: happy ABOUT the evening (da + \u00fcber). Third: had looked FORWARD to it (da + auf).",sSrc:"When we were in the beer garden, Hildi was happy about it. She had looked forward to it for a long time."},
{type:"mc",q:"Welches Wort bedeutet 'sich ern\u00e4hren' oder 'essen' im gesundheitsbewussten Sinne?",opts:["fressen","verpflegen","sich ern\u00e4hren","f\u00fcttern"],ans:"sich ern\u00e4hren",hint:"This reflexive verb is about sustained, healthy eating. Not for animals."},
{type:"match",pairs:[{trg:"als",src:"when (one-time past)"},{trg:"wenn",src:"when(ever) / if"},{trg:"darauf",src:"on it (da + auf)"},{trg:"Worauf?",src:"On what? (wo + auf)"}]},
{type:"mc",q:"Hildi sagt: 'Jedes Mal, _____ die Spargelzeit beginnt, denke ich _____ meine Kindheit.'",opts:["als...\u00fcber","wenn...auf","als...an","wenn...an"],ans:"wenn...an",hint:"Every year = repeated (wenn). Thinking OF something = denken AN."},
{type:"drag_fill",s:"Verumius wartet {1} den Fr\u00fchling. Er freut sich {2}.",blanks:{"1":"auf","2":"darauf"},pool:["auf","darauf","\u00fcber","dar\u00fcber","an","daran"],hint:"Warten AUF. Then replace 'auf den Fr\u00fchling' with the da-compound.",sSrc:"Verumius waits for spring. He looks forward to it."}
]}

]},

{n:19,lang:"de",srcLang:"en",track:"v2",title:"Ausländerbehörde",sub:"Immigration office, passive with modals, advanced subordination, residence permit",icon:"\uD83D\uDCCB",level:"B1.2",color:"#7B5EE8",lessons:[

// ===== LESSON 1: "Wartenummer B089" (Queue Number B089) =====
// Story intro + vocabulary. 16 new words. 22 steps.
{id:"deu_r19l1",title:"Wartenummer B089",icon:"\uD83C\uDFE2",xp:15,board:true,steps:[
{type:"intro",title:"Wartenummer B089",desc:"Verumius sitzt in der Ausländerbehörde. Wartenummer B089. Das Display zeigt A247. Sein Ordner ist perfekt organisiert. Hildi hat geholfen.",goals:["Lerne wichtige Wörter rund um Behörden und Anträge","Verstehe, wie ein deutsches Amt funktioniert","Begleite Verumius im Wartezimmer der Ausländerbehörde"]},

{type:"story",speaker:"narrator",mood:"tense",art:"de-auslaenderbehoerde-waiting",trg:"Verumius sitzt in der Ausländerbehörde. Wartenummer B089. Das digitale Display zeigt A247. Sein Ordner liegt auf den Knien, perfekt organisiert. Hildi hat alles sortiert. Geburtsurkunde, Meldebescheinigung, Arbeitsvertrag, Krankenversicherung, Passfotos. Neonlicht summt über den Reihen aus Plastikstühlen. Ein Drucker rattert irgendwo im Hintergrund.",src:"Verumius sits in the immigration office. Queue number B089. The digital display shows A247. His folder lies on his lap, perfectly organized. Hildi sorted everything. Birth certificate, registration confirmation, employment contract, health insurance, passport photos. Fluorescent light hums above the rows of plastic chairs. A printer rattles somewhere in the background."},

{type:"teach",trg:"die Behörde",src:"the government authority",pos:"noun",gender:"f",note:"From 'beherrschen' (to govern). Any official authority.\nAusländerbehörde = foreigners' authority.",example:"A: Welche Behörde ist für Visa zuständig?\nB: Die Ausländerbehörde.\nA: Und wo finde ich die?\nB: Am Friedrichring 12, dritter Stock.",exampleSrc:"A: Which authority handles visas?\nB: The immigration office.\nA: And where can I find it?\nB: At Friedrichring 12, third floor.",funFact:"Germans have a Behörde for everything. The word comes from 'beherrschen' (to govern). There are over 14,000 different Behörden in Germany, from the Finanzamt to the Jugendamt."},

{type:"teach",trg:"das Amt",src:"the office, the bureau",pos:"noun",gender:"n",note:"From Gothic 'andbahti' (service). Plural: Ämter.\nBürgeramt, Finanzamt, Standesamt.",example:"A: Ich muss zum Amt gehen.\nB: Zu welchem Amt?\nA: Zum Bürgeramt, für die Anmeldung.\nB: Hast du einen Termin?",exampleSrc:"A: I have to go to the office.\nB: Which office?\nA: The citizens' office, for registration.\nB: Do you have an appointment?",funFact:"The word Amt comes from Gothic 'andbahti' (service). An Amt is an office or bureau. Bürgeramt, Finanzamt, Standesamt. German bureaucracy runs on Ämter. Das Amt is neuter, like most institutions."},

{type:"teach",trg:"das Dokument",src:"the document",pos:"noun",gender:"n",note:"From Latin 'documentum' (lesson/proof). Plural: Dokumente.\nNearly identical in English.",example:"A: Haben Sie alle Dokumente dabei?\nB: Ja, hier ist mein Ordner.\nA: Sehr gut. Ich prüfe alles der Reihe nach.\nB: Bitte, nehmen Sie sich Zeit.",exampleSrc:"A: Do you have all documents with you?\nB: Yes, here is my folder.\nA: Very good. I'll check everything in order.\nB: Please, take your time.",funFact:"In Germany, you need Dokumente for everything: renting an apartment, opening a bank account, starting a job, even getting a library card. The phrase 'Bringen Sie alle Dokumente mit' is survival German."},

{type:"teach",trg:"der Antrag",src:"the application, the formal request",pos:"noun",gender:"m",note:"An- (toward) + tragen (to carry). Literally 'to carry toward.'\n'Einen Antrag stellen' = to file an application.",example:"A: Ich möchte einen Antrag stellen.\nB: Welchen Antrag?\nA: Einen Antrag auf Aufenthaltstitel.\nB: Füllen Sie bitte dieses Formular aus.",exampleSrc:"A: I would like to file an application.\nB: Which application?\nA: An application for a residence permit.\nB: Please fill out this form.",funFact:"'Einen Antrag stellen' (to file an application) is survival vocabulary in Germany. The verb is stellen, not machen. Every official process begins with an Antrag."},

{type:"teach",trg:"das Visum",src:"the visa",pos:"noun",gender:"n",note:"From Latin 'visum' (something seen/approved). Plural: Visa.\nDer Aufenthaltstitel replaces it long-term.",example:"A: Wie lange ist Ihr Visum gültig?\nB: Noch drei Monate.\nA: Dann müssen Sie rechtzeitig verlängern.\nB: Ja, deshalb bin ich heute hier.",exampleSrc:"A: How long is your visa valid?\nB: Three more months.\nA: Then you must renew in time.\nB: Yes, that's why I'm here today.",funFact:"Every non-EU resident in Germany needs a Visum. The Aufenthaltstitel (residence permit) replaces it long-term. Das Visum, plural: Visa. The word comes from Latin 'visum' (something officially seen and approved)."},

{type:"teach",trg:"der Aufenthalt",src:"the stay, the residence",pos:"noun",gender:"m",note:"Auf- (up/upon) + enthalten (to hold). A stay or residence.\nAufenthaltserlaubnis = residence permit.",example:"A: Wie lange dauert Ihr Aufenthalt in Deutschland?\nB: Ich lebe seit einem Jahr hier.\nA: Und Sie möchten den Aufenthalt verlängern?\nB: Ja, unbefristet, wenn möglich.",exampleSrc:"A: How long is your stay in Germany?\nB: I've lived here for a year.\nA: And you want to extend the stay?\nB: Yes, indefinitely, if possible.",funFact:"Aufenthaltserlaubnis, Aufenthaltstitel, Aufenthaltsgenehmigung. German compound words build meaning layer by layer. Aufenthalt (stay) is the root of an entire family of immigration terms."},

{type:"teach",trg:"die Unterlage",src:"the document, the paperwork",pos:"noun",gender:"f",note:"Unter (under) + Lage (position). Usually plural: Unterlagen.\n'Haben Sie alle Unterlagen?' is the classic question.",example:"A: Haben Sie alle Unterlagen?\nB: Ja, alles ist in diesem Ordner.\nA: Geburtsurkunde, Meldebescheinigung?\nB: Alles dabei, in der richtigen Reihenfolge.",exampleSrc:"A: Do you have all the paperwork?\nB: Yes, everything is in this folder.\nA: Birth certificate, registration confirmation?\nB: Everything's here, in the right order.",funFact:"Die Unterlagen (plural) means 'documents/paperwork.' Every Behörde asks: 'Haben Sie alle Unterlagen?' The word literally means 'things lying underneath,' supporting your case."},

{type:"teach",trg:"die Frist",src:"the deadline",pos:"noun",gender:"f",note:"From Old High German 'frist' (time period).\n'Die Frist läuft ab' = the deadline expires.",example:"A: Wann ist die Frist für den Antrag?\nB: Am 15. März.\nA: Dann habe ich noch zwei Wochen.\nB: Reichen Sie alles rechtzeitig ein.",exampleSrc:"A: When is the deadline for the application?\nB: March 15th.\nA: Then I have two more weeks.\nB: Submit everything on time.",funFact:"Missing a Frist in German bureaucracy has real consequences. Always ask: 'Wann ist die Frist?' The word comes from Old High German 'frist' (time period). Once the Frist expires, your case may be closed."},

{type:"teach",trg:"nötig",src:"necessary, needed",pos:"adj",gender:null,note:"From 'Not' (need/necessity). Stronger than 'brauchen.'\n'Es ist nötig, alle Dokumente mitzubringen.'",example:"A: Ist ein Passfoto nötig?\nB: Ja, zwei Passfotos sind nötig.\nA: Biometrisch?\nB: Ja, das ist Vorschrift.",exampleSrc:"A: Is a passport photo necessary?\nB: Yes, two passport photos are necessary.\nA: Biometric?\nB: Yes, that is required.",funFact:"Nötig implies urgency or obligation, stronger than 'brauchen' (to need). 'Es ist nötig, alle Dokumente mitzubringen.' The root is 'Not' (need/necessity), the same root as English 'need.'"},

{type:"teach",trg:"rechtzeitig",src:"on time, punctual",pos:"adj",gender:null,note:"Recht (right) + zeitig (timely). Arriving rechtzeitig at\nthe Behörde means arriving early.",example:"A: Sind Sie rechtzeitig gekommen?\nB: Ja, ich bin eine halbe Stunde früher da.\nA: Sehr gut. Pünktlichkeit ist wichtig.\nB: Das habe ich in Deutschland gelernt.",exampleSrc:"A: Did you come on time?\nB: Yes, I'm half an hour early.\nA: Very good. Punctuality is important.\nB: I learned that in Germany.",funFact:"Germans value Pünktlichkeit (punctuality). Arriving rechtzeitig at the Behörde means arriving early. Late? Your appointment may be gone. The word combines 'recht' (right) and 'zeitig' (timely)."},

{type:"teach",trg:"zunächst",src:"first of all, initially",pos:"adv",gender:null,note:"Zu (to) + nächst (nearest). A formal connector.\n'Zunächst müssen Sie das Formular ausfüllen.'",example:"A: Was muss ich zuerst machen?\nB: Zunächst füllen Sie das Formular aus.\nA: Und dann?\nB: Danach gehen Sie zum Schalter drei.",exampleSrc:"A: What do I have to do first?\nB: First of all, fill out the form.\nA: And then?\nB: After that, go to counter three.",funFact:"Zunächst is a formal word for 'first of all.' You hear it constantly in official instructions. 'Zunächst müssen Sie das Formular ausfüllen, danach die Gebühr bezahlen.'"},

{type:"teach",trg:"vorläufig",src:"provisional, temporary",pos:"adj",gender:null,note:"Vor (before) + läufig (running). Not yet final.\nA vorläufige Genehmigung = temporary approval.",example:"A: Ist der Aufenthaltstitel schon endgültig?\nB: Nein, zunächst ist er vorläufig.\nA: Wie lange gilt die vorläufige Genehmigung?\nB: Sechs Monate. Dann kommt die endgültige.",exampleSrc:"A: Is the residence permit already final?\nB: No, initially it is provisional.\nA: How long is the temporary approval valid?\nB: Six months. Then comes the final one.",funFact:"Many German permits start vorläufig before becoming endgültig (final). A vorläufige Genehmigung is a temporary approval. The word literally means 'pre-running,' something that comes before the real thing."},

{type:"teach",trg:"sicher",src:"safe, certain, sure",pos:"adj",gender:null,note:"From Latin 'securus' (without care). Two meanings:\n'Ich bin sicher' = I am sure. 'Das ist sicher' = safe/certain.",example:"A: Sind Sie sicher, dass alle Dokumente dabei sind?\nB: Ja, ganz sicher. Ich habe alles dreimal geprüft.\nA: Gut. Dann kann es losgehen.\nB: Ich bin sicher, dass alles in Ordnung ist.",exampleSrc:"A: Are you sure all documents are here?\nB: Yes, completely sure. I checked everything three times.\nA: Good. Then we can get started.\nB: I'm sure everything is in order.",funFact:"Sicher means both 'safe' and 'certain.' Context determines which. 'Ich bin sicher' = I am sure. 'Das ist sicher' = That is safe/certain. The word comes from Latin 'securus' (without care)."},

{type:"teach",trg:"danach",src:"after that, afterwards",pos:"adv",gender:null,note:"Da (there) + nach (after). A pronominal adverb.\n'Zunächst das Formular, danach die Gebühr bezahlen.'",example:"A: Zunächst den Antrag ausfüllen.\nB: Und danach?\nA: Danach bringen Sie alles zum Schalter.\nB: Verstanden. Erst das Formular, danach der Schalter.",exampleSrc:"A: First fill out the application.\nB: And after that?\nA: After that, bring everything to the counter.\nB: Understood. First the form, then the counter.",funFact:"Germans love sequencing with zunächst...danach...schließlich. Danach is a pronominal adverb (da + nach). It means 'after that' and is essential for following multi-step bureaucratic instructions."},

{type:"teach",trg:"die Bestätigung",src:"the confirmation",pos:"noun",gender:"f",note:"From 'bestätigen' (to confirm). Paper proof of anything.\n'Können Sie mir eine Bestätigung geben?'",example:"A: Kann ich eine Bestätigung bekommen?\nB: Ja, ich drucke Ihnen eine Bestätigung aus.\nA: Danke, die brauche ich für meinen Arbeitgeber.\nB: Bitte, hier ist Ihre Bestätigung.",exampleSrc:"A: Can I get a confirmation?\nB: Yes, I'll print out a confirmation for you.\nA: Thanks, I need it for my employer.\nB: Here you go, here is your confirmation.",funFact:"Every official action in Germany produces a Bestätigung. Paper proof is king. 'Können Sie mir eine Bestätigung geben?' is a phrase you will use again and again."},

{type:"teach",trg:"die Meldung",src:"the registration, the report",pos:"noun",gender:"f",note:"From 'melden' (to report/register). Die Anmeldung is\nthe residential registration every resident needs.",example:"A: Haben Sie Ihre Meldung schon gemacht?\nB: Ja, die Anmeldung habe ich letzte Woche erledigt.\nA: Gut, die Meldebescheinigung brauchen wir hier.\nB: Hier ist sie.",exampleSrc:"A: Have you done your registration yet?\nB: Yes, I completed the registration last week.\nA: Good, we need the registration certificate here.\nB: Here it is.",funFact:"The Anmeldung (residential registration) is the first Meldung every resident needs. No Meldung = no bank account, no insurance, no phone contract. The word comes from 'melden' (to report)."},

{type:"story",speaker:"narrator",mood:"reflective",art:"de-auslaenderbehoerde-waiting",trg:"Verumius prüft seinen Ordner noch einmal. Geburtsurkunde, Meldebescheinigung, Arbeitsvertrag, Krankenversicherung, Passfotos. Alles ist da. Hildis Checklisten-System funktioniert. Er atmet tief durch. B089. Es kann nicht mehr lange dauern.",src:"Verumius checks his folder one more time. Birth certificate, registration confirmation, employment contract, health insurance, passport photos. Everything is there. Hildi's checklist system works. He takes a deep breath. B089. It can't be much longer now."},

{type:"mc",q:"Verumius hat eine Wartenummer. Wo ist er?",opts:["Im Krankenhaus","In der Schule","In der Behörde","Im Restaurant"],ans:"In der Behörde",hint:"A place where you take a number and wait for government services."},

{type:"fb",s:"Verumius muss {1} alle Unterlagen sammeln.",a:["zunächst"],opts:["zunächst","danach","trotzdem","während"],hint:"Which word means 'first of all' when listing steps?",sSrc:"Verumius must first of all collect all the documents."},

{type:"mc",q:"Verumius hat eine vorläufige Genehmigung. Was bedeutet das?",opts:["Die Genehmigung ist abgelaufen.","Die Genehmigung ist temporär.","Die Genehmigung ist falsch.","Die Genehmigung ist endgültig."],ans:"Die Genehmigung ist temporär.",hint:"Vorläufig means something is not yet permanent."}
]},

// ===== LESSON 2: "Amtsdeutsch" (Official German) =====
// Vocab teach (bureaucracy + legal + family). 18 new words. 24 steps.
{id:"deu_r19l2",title:"Amtsdeutsch",icon:"\uD83D\uDCDC",xp:15,board:true,steps:[
{type:"intro",title:"Amtsdeutsch",desc:"Die Sprache der deutschen Verwaltung: lang, genau und voller Fachbegriffe. Gesetze, Gebühren, Pflichten. Willkommen in der Welt des Amtsdeutsch.",goals:["Lerne bürokratisches Vokabular für Amt und Recht","Verstehe Fachbegriffe der Verwaltung","Meistere Wörter für Staatsbürgerschaft und Pflichten"]},

{type:"teach",trg:"die Gebühr",src:"the fee",pos:"noun",gender:"f",note:"From 'gebühren' (to be due). A government fee.\nDie Bearbeitungsgebühr = processing fee.",example:"A: Wie hoch ist die Gebühr für den Antrag?\nB: Die Gebühr beträgt 100 Euro.\nA: Kann ich mit Karte bezahlen?\nB: Nein, nur Überweisung oder Bargeld.",exampleSrc:"A: How much is the fee for the application?\nB: The fee is 100 euros.\nA: Can I pay by card?\nB: No, only bank transfer or cash.",funFact:"Die Bearbeitungsgebühr (processing fee) is attached to every Antrag. Germany never does paperwork for free. The word comes from 'gebühren' (to be due)."},

{type:"teach",trg:"die Urkunde",src:"the certificate",pos:"noun",gender:"f",note:"From Old High German 'urchundi' (testimony). Original only.\nGeburtsurkunde, Heiratsurkunde.",example:"A: Ich brauche eine beglaubigte Urkunde.\nB: Welche Urkunde genau?\nA: Die Geburtsurkunde.\nB: Bringen Sie bitte das Original mit.",exampleSrc:"A: I need a certified certificate.\nB: Which certificate exactly?\nA: The birth certificate.\nB: Please bring the original.",funFact:"Geburtsurkunde (birth certificate), Heiratsurkunde (marriage certificate). The word comes from Old High German 'urchundi' (testimony). Original documents only. Copies will not do."},

{type:"teach",trg:"das Gesetz",src:"the law",pos:"noun",gender:"n",note:"From 'setzen' (to set/place). Something 'set' in place.\n'Gesetz ist Gesetz' is a very German phrase.",example:"A: Was sagt das Gesetz dazu?\nB: Das Gesetz ist hier eindeutig.\nA: Gibt es Ausnahmen?\nB: Nein, Gesetz ist Gesetz.",exampleSrc:"A: What does the law say about that?\nB: The law is clear here.\nA: Are there exceptions?\nB: No, the law is the law.",funFact:"Das Grundgesetz is the German constitution. The word Gesetz comes from 'setzen' (to set in place). 'Gesetz ist Gesetz' (the law is the law) is a very German expression."},

{type:"teach",trg:"das Recht",src:"the right, the law",pos:"noun",gender:"n",note:"Same root as English 'right.' Both a right and the legal system.\n'Sie haben das Recht auf...' = you are entitled to...",example:"A: Habe ich das Recht auf einen Aufenthaltstitel?\nB: Ja, wenn alle Voraussetzungen erfüllt sind.\nA: Welche Rechte habe ich als Einwohner?\nB: Viele. Informieren Sie sich beim Amt.",exampleSrc:"A: Do I have the right to a residence permit?\nB: Yes, if all requirements are met.\nA: What rights do I have as a resident?\nB: Many. Inform yourself at the office.",funFact:"'Recht' means both a right (das Recht auf...) and the legal system (das Recht). 'Sie haben das Recht auf einen Aufenthaltstitel' means you are legally entitled to one."},

{type:"teach",trg:"die Pflicht",src:"the duty, the obligation",pos:"noun",gender:"f",note:"From Old High German 'pflihti' (care/duty).\nSchulpflicht, Versicherungspflicht. Germany runs on Pflichten.",example:"A: Was sind meine Pflichten als Einwohner?\nB: Sie müssen sich anmelden und Steuern zahlen.\nA: Gibt es noch andere Pflichten?\nB: Ja, die Versicherungspflicht zum Beispiel.",exampleSrc:"A: What are my duties as a resident?\nB: You must register and pay taxes.\nA: Are there other duties?\nB: Yes, mandatory insurance for example.",funFact:"Die Schulpflicht (compulsory education), die Versicherungspflicht (mandatory insurance). Germany runs on Pflichten. The word comes from Old High German 'pflihti' (care/duty)."},

{type:"teach",trg:"die Herkunft",src:"the origin",pos:"noun",gender:"f",note:"Her- (from) + Kunft (coming). Where you come from.\nHerkunftsland = country of origin.",example:"A: Woher kommen Sie? Was ist Ihre Herkunft?\nB: Ich komme aus Griechenland.\nA: Und wie lange sind Sie schon in Deutschland?\nB: Seit zwei Jahren.",exampleSrc:"A: Where do you come from? What is your origin?\nB: I come from Greece.\nA: And how long have you been in Germany?\nB: For two years.",funFact:"The Behörde always asks about Herkunft. Herkunftsland = country of origin. Not the same as Heimat (which is emotional). Herkunft is factual, about geography and nationality."},

{type:"teach",trg:"die Integration",src:"the integration",pos:"noun",gender:"f",note:"Latin 'integratio' (renewal). The process of becoming\npart of society. Integrationskurse are mandatory for many.",example:"A: Haben Sie einen Integrationskurs besucht?\nB: Ja, 600 Stunden Deutsch und 100 Stunden Politik.\nA: Sehr gut. Das ist wichtig für die Integration.\nB: Es war anstrengend, aber hilfreich.",exampleSrc:"A: Have you attended an integration course?\nB: Yes, 600 hours of German and 100 hours of civics.\nA: Very good. That is important for integration.\nB: It was exhausting, but helpful.",funFact:"Germany has Integrationskurse (integration courses): 600 hours of German + 100 hours of civics. Mandatory for many immigrants. The concept of Integration is central to German immigration policy."},

{type:"teach",trg:"die Migration",src:"the migration",pos:"noun",gender:"f",note:"Latin 'migratio' (moving). Population movement as a concept.\nEinwanderung = immigration, Auswanderung = emigration.",example:"A: Migration ist ein globales Thema.\nB: Ja, Millionen Menschen migrieren jedes Jahr.\nA: Deutschland hat eine lange Migrationsgeschichte.\nB: Seit den 1960er-Jahren, mit den Gastarbeitern.",exampleSrc:"A: Migration is a global topic.\nB: Yes, millions of people migrate every year.\nA: Germany has a long history of migration.\nB: Since the 1960s, with the guest workers.",funFact:"Immigration (Einwanderung) and emigration (Auswanderung) are both types of Migration. Germany's Migrationsgeschichte goes back to the 1960s Gastarbeiter (guest workers) program."},

{type:"teach",trg:"der Migrant",src:"the migrant (male)",pos:"noun",gender:"m",note:"A person who migrates. Die Migrantin = female form.\nPlural 'Migranten' covers everyone.",example:"A: Wie viele Migranten leben in Berlin?\nB: Über eine Million Menschen haben Migrationshintergrund.\nA: Das ist fast ein Drittel der Bevölkerung.\nB: Berlin ist eine sehr diverse Stadt.",exampleSrc:"A: How many migrants live in Berlin?\nB: Over a million people have a migration background.\nA: That's almost a third of the population.\nB: Berlin is a very diverse city.",funFact:"German always has masculine and feminine forms: der Migrant, die Migrantin. The plural 'Migranten' covers everyone. Gender-specific titles are standard in official German."},

{type:"teach",trg:"die Verwaltung",src:"the administration",pos:"noun",gender:"f",note:"From 'verwalten' (to administer). Die Stadtverwaltung =\ncity administration. Verwaltungsakt = administrative act.",example:"A: Die Verwaltung hat meinen Antrag bearbeitet.\nB: Wie lange hat das gedauert?\nA: Sechs Wochen.\nB: Das ist für die deutsche Verwaltung ganz normal.",exampleSrc:"A: The administration processed my application.\nB: How long did that take?\nA: Six weeks.\nB: That's quite normal for the German administration.",funFact:"Germany's Verwaltung is legendarily thorough. Every process has a Verwaltungsakt (administrative act). Die Stadtverwaltung = city administration. The word comes from 'verwalten' (to administer)."},

{type:"teach",trg:"der Wohnort",src:"the place of residence",pos:"noun",gender:"m",note:"Wohn- (dwelling) + Ort (place). On every form.\nDifferent from Wohnsitz (official registered address).",example:"A: Was ist Ihr Wohnort?\nB: Berlin, Kreuzberg.\nA: Ist das auch Ihr offizieller Wohnsitz?\nB: Ja, ich bin dort angemeldet.",exampleSrc:"A: What is your place of residence?\nB: Berlin, Kreuzberg.\nA: Is that also your official registered address?\nB: Yes, I'm registered there.",funFact:"You can have a Wohnort without a Wohnsitz if you haven't registered yet. Wohnort = where you live. Wohnsitz = where you are officially registered. Both appear on every German form."},

{type:"teach",trg:"der Wohnsitz",src:"the official registered address",pos:"noun",gender:"m",note:"Wohn- (dwelling) + Sitz (seat). Your officially registered address.\nThe Anmeldung establishes your Wohnsitz.",example:"A: Haben Sie einen Wohnsitz in Deutschland?\nB: Ja, seit der Anmeldung letzte Woche.\nA: Gut. Ohne Wohnsitz geht hier nichts.\nB: Das habe ich schnell gelernt.",exampleSrc:"A: Do you have a registered address in Germany?\nB: Yes, since the registration last week.\nA: Good. Nothing works here without a registered address.\nB: I learned that quickly.",funFact:"Without a Wohnsitz, you legally do not live anywhere in Germany. No Wohnsitz means no bank account, no insurance, no phone contract. The Anmeldung (registration) establishes your Wohnsitz."},

{type:"teach",trg:"die Daten",src:"the data, personal details",pos:"noun",gender:"pl",note:"Latin 'data' (things given). Always plural in German.\nPersönliche Daten = personal data. Datenschutz = data protection.",example:"A: Bitte geben Sie Ihre persönlichen Daten an.\nB: Name, Geburtsdatum und Adresse?\nA: Ja, und Ihre Telefonnummer.\nB: Hier, alles ist ausgefüllt.",exampleSrc:"A: Please provide your personal data.\nB: Name, date of birth, and address?\nA: Yes, and your phone number.\nB: Here, everything is filled in.",funFact:"Daten is always plural in German. Persönliche Daten = personal data. Data protection (Datenschutz) is a near-sacred concept in Germany. The word comes from Latin 'data' (things given)."},

{type:"teach",trg:"rechtlich",src:"legal, juridical",pos:"adj",gender:null,note:"Recht + -lich. 'Rechtlich gesehen...' = legally speaking.\nDifferent from 'recht' (right) and 'rechts' (to the right).",example:"A: Ist das rechtlich erlaubt?\nB: Rechtlich gesehen, ja.\nA: Gibt es rechtliche Probleme?\nB: Nein, alles ist rechtlich in Ordnung.",exampleSrc:"A: Is that legally permitted?\nB: Legally speaking, yes.\nA: Are there legal problems?\nB: No, everything is legally in order.",funFact:"'Rechtlich gesehen...' (legally speaking...) is how officials introduce legal requirements. Different from 'recht' (right/correct) and 'rechts' (to the right). Three forms, three meanings."},

{type:"teach",trg:"endgültig",src:"final, definitive",pos:"adj",gender:null,note:"End- (final) + gültig (valid). Cannot be appealed normally.\nThe opposite of vorläufig.",example:"A: Ist die Entscheidung endgültig?\nB: Ja, der Bescheid ist endgültig.\nA: Kann ich noch Widerspruch einlegen?\nB: Nur innerhalb von vier Wochen.",exampleSrc:"A: Is the decision final?\nB: Yes, the ruling is final.\nA: Can I still file an objection?\nB: Only within four weeks.",funFact:"An endgültiger Bescheid (final decision) cannot be appealed through normal channels. The opposite of vorläufig. The word you want to hear at the Behörde."},

{type:"teach",trg:"verantwortlich",src:"responsible",pos:"adj",gender:null,note:"Ver- + Antwort (answer) + -lich. Literally 'answerable.'\n'Wer ist dafür verantwortlich?'",example:"A: Wer ist für diesen Fall verantwortlich?\nB: Frau Müller ist dafür verantwortlich.\nA: Kann ich mit ihr sprechen?\nB: Sie ist gerade in einer Besprechung.",exampleSrc:"A: Who is responsible for this case?\nB: Ms. Müller is responsible for it.\nA: Can I speak with her?\nB: She is currently in a meeting.",funFact:"The Behörde always wants to know who is verantwortlich. The word literally means 'answerable' (ver- + Antwort + -lich). 'Wer ist dafür verantwortlich?' is a key bureaucratic question."},

{type:"teach",trg:"zuständig",src:"responsible, in charge (jurisdictionally)",pos:"adj",gender:null,note:"Zu- + Stand + -ig. Competent for a specific matter.\n'Diese Behörde ist für Visa zuständig.'",example:"A: Sind Sie für Aufenthaltstitel zuständig?\nB: Nein, dafür ist Schalter drei zuständig.\nA: Und wer ist hier zuständig?\nB: Ich bin für Anmeldungen zuständig.",exampleSrc:"A: Are you in charge of residence permits?\nB: No, counter three is in charge of that.\nA: And who is in charge here?\nB: I'm in charge of registrations.",funFact:"Each office is zuständig for specific matters. Wrong Behörde? They send you to the zuständige one. 'Diese Behörde ist für Visa zuständig.' Zuständig means jurisdictionally responsible, not personally responsible."},

{type:"tip",title:"Amtsdeutsch: Die Sprache der Verwaltung",text:"German official language uses:\n\n1. Long compound nouns: Aufenthaltsgenehmigung, Bearbeitungsgebühr\n2. Passive constructions: 'wird bearbeitet' (is being processed)\n3. Formal vocabulary: erhalten instead of bekommen\n\nKey pattern: nouns are built from smaller parts.\nAufenthalts-genehmigungs-antrag = residence-permit-application.\nRead right to left for meaning: it is an Antrag (application)\nfor a Genehmigung (approval) of an Aufenthalt (stay).",deepDive:"Amtsdeutsch sounds different from everyday German because it evolved from legal Latin traditions. The long compound nouns are actually more precise than using multiple words. Each compound has exactly one meaning, leaving no room for ambiguity. This precision is intentional: in law, every word matters."},

{type:"mc",q:"Welches Wort bedeutet 'deadline'?",opts:["Frist","Gebühr","Recht","Pflicht"],ans:"Frist",hint:"This word refers to a time limit for submitting something."},

{type:"mc",q:"Was ist ein Wohnsitz?",opts:["Ein bequemer Stuhl","Die offizielle Meldeadresse","Der Arbeitsplatz","Das Heimatland"],ans:"Die offizielle Meldeadresse",hint:"Wohn- relates to living, Sitz relates to an official seat or registration."},

{type:"fb",s:"Die Ausländerbehörde ist für Visa {1}.",a:["zuständig"],opts:["zuständig","verantwortlich","endgültig","rechtlich"],hint:"Which adjective describes jurisdictional responsibility of an office?",sSrc:"The immigration office is in charge of visas."},

{type:"match",pairs:[{trg:"Gebühr",src:"fee"},{trg:"Urkunde",src:"certificate"},{trg:"Gesetz",src:"law"},{trg:"Pflicht",src:"duty"},{trg:"Verwaltung",src:"administration"}]},

{type:"mc",q:"Verumius braucht eine Geburtsurkunde. Was ist das?",opts:["Ein Formular für die Schule","Ein Foto für den Pass","Ein offizielles Dokument über die Geburt","Eine Bestätigung der Adresse"],ans:"Ein offizielles Dokument über die Geburt",hint:"Geburt means birth. Urkunde means certificate."}
]},

// ===== LESSON 3: "Das muss gemacht werden" (That Must Be Done) =====
// Grammar: Passive with modals (#9). 14 new words. 22 steps.
{id:"deu_r19l3",title:"Das muss gemacht werden",icon:"\u2699\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Das muss gemacht werden",desc:"Passiv mit Modalverben: Was muss getan werden? Was kann beantragt werden? Was darf nicht vergessen werden? Die Sprache der Behörde, Schritt für Schritt.",goals:["Lerne Passiv mit Modalverben: muss/kann/soll/darf + Partizip II + werden","Drücke Pflichten, Erlaubnisse und Verbote aus","Verwende bürokratisches Deutsch mit Sicherheit"]},

{type:"teach",trg:"beantragen",src:"to apply for (officially)",pos:"verb",gender:null,note:"Be- + Antrag + -en. To apply for something at an office.\n'Einen Aufenthaltstitel beantragen.'",example:"A: Was möchten Sie beantragen?\nB: Ich möchte einen Aufenthaltstitel beantragen.\nA: Haben Sie alle Unterlagen?\nB: Ja, alles ist vollständig.",exampleSrc:"A: What would you like to apply for?\nB: I would like to apply for a residence permit.\nA: Do you have all the documents?\nB: Yes, everything is complete.",funFact:"The be- prefix makes it transitive: you beantragen something directly. 'Einen Aufenthaltstitel beantragen' is what Verumius is doing right now. Without be-, Antrag is just the noun."},

{type:"teach",trg:"genehmigen",src:"to approve, to grant permission",pos:"verb",gender:null,note:"From 'genehm' (agreeable). To approve officially.\n'Der Antrag wurde genehmigt.' = the golden words.",example:"A: Wurde mein Antrag genehmigt?\nB: Ja, Ihr Antrag wurde genehmigt.\nA: Wirklich? Das ist eine gute Nachricht!\nB: Herzlichen Glückwunsch.",exampleSrc:"A: Was my application approved?\nB: Yes, your application was approved.\nA: Really? That's great news!\nB: Congratulations.",funFact:"'Der Antrag wurde genehmigt' is the sentence every applicant wants to hear. Die Genehmigung = the approval. The word comes from 'genehm' (agreeable)."},

{type:"teach",trg:"ausstellen",src:"to issue (a document)",pos:"verb",gender:null,note:"Aus- (out) + stellen (to place). To issue officially.\n'Einen Pass ausstellen' = to issue a passport.",example:"A: Wo wird der Aufenthaltstitel ausgestellt?\nB: Am Schalter fünf.\nA: Wie lange dauert das Ausstellen?\nB: Etwa 20 Minuten.",exampleSrc:"A: Where is the residence permit issued?\nB: At counter five.\nA: How long does the issuing take?\nB: About 20 minutes.",funFact:"The Behörde stellt Dokumente aus. Without ausstellen, no official paper exists. Separable verb: 'Sie stellt den Pass aus.' In passive: 'Der Pass wird ausgestellt.'"},

{type:"teach",trg:"verlängern",src:"to extend, to renew",pos:"verb",gender:null,note:"Ver- + länger (longer) + -n. To make something last longer.\n'Das Visum verlängern' = to extend the visa.",example:"A: Ich muss mein Visum verlängern.\nB: Wann läuft es ab?\nA: In drei Wochen.\nB: Dann stellen Sie schnell einen Antrag.",exampleSrc:"A: I need to extend my visa.\nB: When does it expire?\nA: In three weeks.\nB: Then file an application quickly.",funFact:"Every permit has an expiry date. Verlängern before the Frist. Always. The word literally means 'to make longer' (ver- + länger)."},

{type:"teach",trg:"anerkennen",src:"to officially recognize",pos:"verb",gender:null,note:"An- (at) + erkennen (to recognize). To recognize officially.\n'Einen Abschluss anerkennen' = to recognize a degree.",example:"A: Wird mein Diplom in Deutschland anerkannt?\nB: Das hängt vom Fach ab.\nA: Ich habe Informatik studiert.\nB: Informatik wird meistens anerkannt.",exampleSrc:"A: Is my diploma recognized in Germany?\nB: That depends on the subject.\nA: I studied computer science.\nB: Computer science is usually recognized.",funFact:"Foreign qualifications must be anerkannt (recognized) in Germany before they count. The process is called Anerkennung. Without it, your degree is just a piece of paper."},

{type:"teach",trg:"erhalten",src:"to receive (formal)",pos:"verb",gender:null,note:"Er- + halten (to hold). Formal register for 'to receive.'\n'Sie erhalten den Bescheid per Post.'",example:"A: Wann erhalte ich den Bescheid?\nB: Sie erhalten ihn innerhalb von sechs Wochen.\nA: Per Post oder per E-Mail?\nB: Per Post, als Einschreiben.",exampleSrc:"A: When will I receive the decision?\nB: You will receive it within six weeks.\nA: By mail or by email?\nB: By mail, as registered post.",funFact:"In official German, erhalten replaces bekommen (to get). Same meaning, higher register. 'Sie erhalten den Bescheid per Post.' You see erhalten on every official letter."},

{type:"teach",trg:"enthalten",src:"to contain",pos:"verb",gender:null,note:"Ent- + halten (to hold). What is inside something.\nNot to be confused with erhalten (receive).",example:"A: Was enthält der Antrag?\nB: Er enthält alle persönlichen Daten.\nA: Ist die Geburtsurkunde enthalten?\nB: Ja, alle Unterlagen sind enthalten.",exampleSrc:"A: What does the application contain?\nB: It contains all personal data.\nA: Is the birth certificate included?\nB: Yes, all documents are included.",funFact:"Enthalten = what is inside. Erhalten = what you get. Same root (halten = to hold), different prefixes, very different meanings. A common source of confusion for learners."},

{type:"teach",trg:"verpflichten",src:"to obligate",pos:"verb",gender:null,note:"Ver- + Pflicht + -en. When the Behörde says verpflichtet,\nit is not a suggestion. It is the law.",example:"A: Sind wir verpflichtet, einen Integrationskurs zu machen?\nB: Ja, Sie sind gesetzlich dazu verpflichtet.\nA: Was passiert, wenn ich nicht teilnehme?\nB: Es gibt Konsequenzen für Ihren Aufenthalt.",exampleSrc:"A: Are we obligated to take an integration course?\nB: Yes, you are legally obligated to do so.\nA: What happens if I don't attend?\nB: There are consequences for your residence status.",funFact:"When the Behörde says verpflichtet, it is not a suggestion. It is the law. The word combines ver- (intensifier) + Pflicht (duty) + -en (verb ending)."},

{type:"teach",trg:"fällig",src:"due, payable",pos:"adj",gender:null,note:"From 'fallen' (to fall due). The deadline has arrived.\n'Die Gebühr ist sofort fällig.'",example:"A: Wann ist die Gebühr fällig?\nB: Die Gebühr ist sofort fällig.\nA: Kann ich auch nächste Woche bezahlen?\nB: Nein, sofort fällig bedeutet sofort.",exampleSrc:"A: When is the fee due?\nB: The fee is due immediately.\nA: Can I also pay next week?\nB: No, due immediately means immediately.",funFact:"When something is fällig, the deadline has arrived. No more waiting. 'Die Gebühr ist sofort fällig.' The word comes from 'fallen' (to fall due)."},

{type:"teach",trg:"zusätzlich",src:"additional",pos:"adj",gender:null,note:"Zu- (to) + Satz (set) + -lich. The word you do not want\nto hear at the Behörde: it means more paperwork.",example:"A: Brauchen Sie zusätzliche Dokumente?\nB: Ja, wir brauchen zusätzlich eine Meldebescheinigung.\nA: Die habe ich nicht dabei.\nB: Dann müssen Sie noch einmal kommen.",exampleSrc:"A: Do you need additional documents?\nB: Yes, we additionally need a registration certificate.\nA: I don't have that with me.\nB: Then you'll have to come again.",funFact:"The word you do not want to hear at the Behörde. 'Zusätzliche Dokumente sind erforderlich' means more paperwork, more time, more waiting."},

{type:"teach",trg:"untersagt",src:"forbidden, prohibited",pos:"adj",gender:null,note:"Unter- + sagen (to say). Stronger than 'verboten.'\nUsed in official documents and formal contexts.",example:"A: Darf ich hier ohne Genehmigung arbeiten?\nB: Nein, das ist streng untersagt.\nA: Was passiert, wenn jemand trotzdem arbeitet?\nB: Es gibt hohe Strafen.",exampleSrc:"A: Am I allowed to work here without a permit?\nB: No, that is strictly prohibited.\nA: What happens if someone works anyway?\nB: There are heavy penalties.",funFact:"Stronger than 'verboten.' 'Das Arbeiten ist ohne Genehmigung untersagt.' Official German prefers untersagt in formal documents. Unter- + sagen literally means 'to say against.'"},

{type:"teach",trg:"voraussichtlich",src:"presumably, expected",pos:"adj",gender:null,note:"Voraus (ahead) + sichtlich (visibly). Bureaucratic hedging.\n'Voraussichtlich sechs Wochen.' No guarantees.",example:"A: Wie lange dauert die Bearbeitung?\nB: Voraussichtlich sechs Wochen.\nA: Kann es auch schneller gehen?\nB: Voraussichtlich nicht, aber manchmal passiert es.",exampleSrc:"A: How long does processing take?\nB: Presumably six weeks.\nA: Could it be faster?\nB: Presumably not, but sometimes it happens.",funFact:"Bureaucratic hedging: they expect it, but no guarantees. 'Die Bearbeitung dauert voraussichtlich sechs Wochen.' Voraus (ahead) + sichtlich (visibly) = 'as far as can be seen ahead.'"},

{type:"teach",trg:"inklusive",src:"including (casual)",pos:"prep",gender:null,note:"From Latin. Casual form of 'including.'\nEinschließlich is the formal German equivalent.",example:"A: Was kostet der Antrag?\nB: 100 Euro, inklusive Bearbeitungsgebühr.\nA: Sind die Passfotos inklusive?\nB: Nein, die müssen Sie selbst mitbringen.",exampleSrc:"A: How much does the application cost?\nB: 100 euros, including processing fee.\nA: Are passport photos included?\nB: No, you have to bring those yourself.",funFact:"Both inklusive and einschließlich mean 'including.' Inklusive is from Latin (casual). Einschließlich is the German compound (formal). Same meaning, different register."},

{type:"teach",trg:"einschließlich",src:"including (formal)",pos:"prep",gender:null,note:"Ein- + schließlich. Formal German for 'including.'\n'Einschließlich aller Unterlagen.'",example:"A: Welche Kosten fallen an?\nB: 150 Euro, einschließlich aller Gebühren.\nA: Gibt es versteckte Kosten?\nB: Nein, alles ist einschließlich.",exampleSrc:"A: What costs are there?\nB: 150 euros, including all fees.\nA: Are there hidden costs?\nB: No, everything is included.",funFact:"Einschließlich is the formal German compound for 'including.' You see it on every official document. 'Einschließlich aller Unterlagen' = including all paperwork."},

{type:"tip",title:"Passiv mit Modalverben: Wer macht was?",text:"You already know passive (wird + Partizip II). Now add a modal verb.\n\nStructure: Modal (position 2) + Partizip II + werden (end).\n\n'Das Formular muss ausgefüllt werden.'\n(The form must be filled out.)\n\nAll modals work:\nmuss (must), kann (can), soll (should), darf (may), will (wants to).\n\nThe modal takes V2 position. Werden goes to the end.\nThe Partizip II sits right before werden.",deepDive:"In a Nebensatz (subordinate clause), the modal goes to the very end, after werden:\n\n'Ich weiß, dass das Formular ausgefüllt werden muss.'\n\nThe order is: Partizip II + werden + modal.\nThis triple verb cluster at the end is typical of German subordinate clauses and sounds complex, but the pattern is always the same."},

{type:"verb_table",title:"Passiv mit Modalverben",groups:[{label:"Beispiele mit verschiedenen Modalverben",rows:[{pronoun:"müssen",form:"Das Formular muss ausgefüllt werden.",src:"The form must be filled out."},{pronoun:"können",form:"Der Antrag kann online gestellt werden.",src:"The application can be filed online."},{pronoun:"sollen",form:"Die Gebühr soll überwiesen werden.",src:"The fee should be transferred."},{pronoun:"dürfen",form:"Das Dokument darf nicht kopiert werden.",src:"The document may not be copied."},{pronoun:"wollen",form:"Der Termin will verschoben werden.",src:"The appointment is to be rescheduled."}]}],note:"Modal in V2 position. Partizip II before werden at the end. Always."},

{type:"mc",q:"Das Visum _____ verlängert werden.",opts:["hat","wird","muss","ist"],ans:"muss",hint:"Which modal verb expresses obligation? The structure is modal + PP + werden."},

{type:"mc",q:"Welcher Satz hat die richtige Wortstellung?",opts:["Der Antrag gestellt werden kann online.","Kann der Antrag gestellt online werden.","Der Antrag kann online gestellt werden.","Der Antrag online gestellt werden kann."],ans:"Der Antrag kann online gestellt werden.",hint:"Modal in V2, Partizip II before werden at the end."},

{type:"fb",s:"Der Pass {1} am Schalter abgeholt werden.",a:["kann"],opts:["kann","muss","wird","hat"],hint:"Which modal expresses ability or permission?",sSrc:"The passport can be picked up at the counter."},

{type:"mc",q:"Wie sagt man 'Working without a permit is not allowed' im Passiv?",opts:["Arbeiten ist ohne Genehmigung nicht.","Ohne Genehmigung darf nicht gearbeitet werden.","Ohne Genehmigung wird nicht gearbeitet.","Ohne Genehmigung muss nicht gearbeitet werden."],ans:"Ohne Genehmigung darf nicht gearbeitet werden.",hint:"Dürfen + nicht = prohibition. Passive structure: darf nicht + PP + werden."},

{type:"drag_fill",s:"Die Unterlagen {1} rechtzeitig {2} {3}.",blanks:{"1":"müssen","2":"eingereicht","3":"werden"},pool:["müssen","eingereicht","werden","muss","einreichen","wird"],hint:"Plural subject = müssen. Then Partizip II, then werden at the very end.",sSrc:"The documents must be submitted on time."},

{type:"mc",q:"Verumius fragt: 'Kann der Antrag auch online gestellt werden?' Was will er wissen?",opts:["Wann die Frist abläuft","Wie viel der Antrag kostet","Ob er den Antrag digital einreichen kann","Ob der Antrag genehmigt wurde"],ans:"Ob er den Antrag digital einreichen kann",hint:"Kann...gestellt werden asks about possibility. Online = digitally."}
]},

// ===== LESSON 4: "Bevor die Frist abläuft" (Before the Deadline Expires) =====
// Grammar: Subordinating conjunctions expanded (#18). 16 new words. 24 steps.
{id:"deu_r19l4",title:"Bevor die Frist abläuft",icon:"\u23F0",xp:15,board:true,steps:[
{type:"intro",title:"Bevor die Frist abläuft",desc:"Acht neue Konjunktionen. Zeit, Zweck, Bedingung, Einräumung. Komplexe Sätze für offizielle Situationen. Das Verb geht ans Ende.",goals:["Lerne 8 neue Nebensatzkonjunktionen","Drücke Zeit, Zweck, Bedingung und Einräumung aus","Baue komplexe deutsche Sätze für offizielle Kontexte"]},

{type:"teach",trg:"obwohl",src:"although",pos:"conj",gender:null,note:"Ob (whether) + wohl (well). Introduces a concession.\nVerb goes to the END of the obwohl-clause.",example:"A: Obwohl er nervös war, hatte er alle Dokumente.\nB: Das ist beeindruckend.\nA: Obwohl die Frist kurz war, hat er alles geschafft.\nB: Gute Vorbereitung ist alles.",exampleSrc:"A: Although he was nervous, he had all documents.\nB: That's impressive.\nA: Although the deadline was short, he managed everything.\nB: Good preparation is everything.",funFact:"Obwohl always sends the verb to the end of its clause. 'Obwohl er nervös war, hatte er alle Dokumente.' It introduces a concession: something is true despite another fact."},

{type:"teach",trg:"trotzdem",src:"nevertheless, despite that",pos:"adv",gender:null,note:"Trotz (despite) + dem (that). NOT a conjunction but an adverb.\nTrotzdem takes V2 position in its clause.",example:"A: Er war nervös.\nB: Trotzdem hatte er alle Dokumente.\nA: Die Frist war kurz.\nB: Trotzdem hat er alles geschafft.",exampleSrc:"A: He was nervous.\nB: Nevertheless, he had all documents.\nA: The deadline was short.\nB: Nevertheless, he managed everything.",funFact:"Trotzdem is NOT a conjunction but an adverb. 'Er war nervös. Trotzdem hatte er alle Dokumente.' Trotzdem takes V2 position in its clause. Compare: obwohl = verb-final, trotzdem = verb-second."},

{type:"teach",trg:"bevor",src:"before",pos:"conj",gender:null,note:"Be- + vor (before). The bevor-clause describes what\nhas NOT happened yet. Verb-final.",example:"A: Bevor die Frist abläuft, muss alles eingereicht sein.\nB: Wann läuft die Frist ab?\nA: Am Freitag.\nB: Dann haben wir noch drei Tage.",exampleSrc:"A: Before the deadline expires, everything must be submitted.\nB: When does the deadline expire?\nA: On Friday.\nB: Then we still have three days.",funFact:"The bevor-clause describes what has NOT happened yet. 'Bevor die Frist abläuft, müssen alle Dokumente eingereicht werden.' Verb goes to the end of the bevor-clause."},

{type:"teach",trg:"seitdem",src:"since (a point in time)",pos:"conj",gender:null,note:"Seit (since) + dem (that). Marks the starting point\nof an ongoing situation. Verb-final.",example:"A: Seitdem ich in Berlin wohne, lerne ich Deutsch.\nB: Und wie lange wohnst du schon hier?\nA: Seitdem ich den Job bekommen habe.\nB: Das sind schon fast zwei Jahre.",exampleSrc:"A: Since I've been living in Berlin, I've been learning German.\nB: And how long have you been living here?\nA: Since I got the job.\nB: That's almost two years already.",funFact:"Seitdem marks the starting point of an ongoing situation. 'Seitdem ich in Berlin wohne, lerne ich Deutsch.' The conjunction version always takes verb-final word order."},

{type:"teach",trg:"bis",src:"until",pos:"conj",gender:null,note:"Old High German 'biz.' Marks the endpoint. Short, powerful.\n'Warten Sie, bis Ihre Nummer aufgerufen wird.'",example:"A: Warten Sie bitte, bis Ihre Nummer aufgerufen wird.\nB: Wie lange dauert das noch?\nA: Bis Nummer B089 dran ist, vielleicht eine Stunde.\nB: Ich warte, bis es so weit ist.",exampleSrc:"A: Please wait until your number is called.\nB: How much longer will that take?\nA: Until number B089 comes up, maybe an hour.\nB: I'll wait until it's time.",funFact:"'Bis' is short and powerful: 'Warten Sie, bis Ihre Nummer aufgerufen wird.' It marks the endpoint. Used constantly in bureaucratic instructions."},

{type:"teach",trg:"damit",src:"so that, in order that",pos:"conj",gender:null,note:"Da- (there) + mit (with). Different subjects allowed.\nVerb-final. 'Damit der Antrag bearbeitet werden kann.'",example:"A: Bringen Sie alle Unterlagen mit.\nB: Warum?\nA: Damit der Antrag bearbeitet werden kann.\nB: Verstanden. Ich bringe alles mit.",exampleSrc:"A: Bring all documents with you.\nB: Why?\nA: So that the application can be processed.\nB: Understood. I'll bring everything.",funFact:"Damit expresses purpose: 'so that.' Different subjects are allowed (unlike um...zu). 'Bringen Sie alle Unterlagen mit, damit der Antrag bearbeitet werden kann.'"},

{type:"teach",trg:"falls",src:"in case, if (uncertain)",pos:"conj",gender:null,note:"From 'Fall' (case). More uncertain than 'wenn.'\nFalls = it might happen. Wenn = it probably will.",example:"A: Falls Sie Fragen haben, rufen Sie uns an.\nB: Was passiert, falls ich die Frist verpasse?\nA: Falls das passiert, müssen Sie einen neuen Antrag stellen.\nB: Dann passe ich auf die Frist auf.",exampleSrc:"A: In case you have questions, call us.\nB: What happens if I miss the deadline?\nA: If that happens, you must file a new application.\nB: Then I'll watch the deadline.",funFact:"Falls is more uncertain than 'wenn.' Falls = it might happen. Wenn = it probably will. Formal German prefers falls for conditions that may or may not occur."},

{type:"teach",trg:"während",src:"while, during",pos:"conj",gender:null,note:"From 'währen' (to last). Temporal overlap.\nAlso a preposition with genitive: während des Gesprächs.",example:"A: Während der Beamte die Dokumente prüft, wartet Verumius.\nB: Ist das normal?\nA: Ja, während der Prüfung muss man warten.\nB: Während ich warte, lese ich ein Buch.",exampleSrc:"A: While the officer checks the documents, Verumius waits.\nB: Is that normal?\nA: Yes, during the check you have to wait.\nB: While I wait, I read a book.",funFact:"Während is both a conjunction (while) and a preposition with genitive (during). As a conjunction: 'Während der Beamte prüft, wartet Verumius.' As a preposition: 'während des Gesprächs.'"},

{type:"teach",trg:"abhängen",src:"to depend on",pos:"verb",gender:null,note:"Ab- (from) + hängen (to hang). Always with 'von.'\n'Es hängt davon ab, ob...' = it depends on whether...",example:"A: Wird mein Antrag genehmigt?\nB: Das hängt von den Unterlagen ab.\nA: Wovon hängt es noch ab?\nB: Es hängt auch von der Bearbeitungszeit ab.",exampleSrc:"A: Will my application be approved?\nB: That depends on the documents.\nA: What else does it depend on?\nB: It also depends on the processing time.",funFact:"Always used with 'von': von etwas abhängen. 'Es hängt davon ab, ob alle Unterlagen vollständig sind.' The outcome is 'hanging from' a condition."},

{type:"teach",trg:"abstimmen",src:"to coordinate, to align",pos:"verb",gender:null,note:"Ab- (off) + stimmen (to be correct/to vote). In bureaucracy:\nalign, coordinate. Also: to vote (in politics).",example:"A: Sind die Unterlagen aufeinander abgestimmt?\nB: Ja, alles passt zusammen.\nA: Gut, das ist wichtig.\nB: Wir haben alles sorgfältig abgestimmt.",exampleSrc:"A: Are the documents coordinated with each other?\nB: Yes, everything fits together.\nA: Good, that is important.\nB: We coordinated everything carefully.",funFact:"In bureaucracy, everything must be abgestimmt (aligned, coordinated). 'Die Unterlagen müssen aufeinander abgestimmt sein.' The word also means 'to vote' in political contexts."},

{type:"teach",trg:"umgehen",src:"to handle, to deal with",pos:"verb",gender:null,note:"Um- (around) + gehen (to go). Separable: UMgehen = handle.\nInseparable: umGEHen = circumvent.",example:"A: Wie geht man mit der Verwaltung um?\nB: Geduldig und gut vorbereitet.\nA: Und wenn es Probleme gibt?\nB: Ruhig bleiben und höflich nachfragen.",exampleSrc:"A: How do you deal with the administration?\nB: Patiently and well prepared.\nA: And if there are problems?\nB: Stay calm and ask politely.",funFact:"Two meanings depending on stress. 'UMgehen' (separable) = to handle/deal with. 'umGEHen' (inseparable) = to circumvent. 'Wie geht man mit der Verwaltung um?' = How do you deal with the administration?"},

{type:"teach",trg:"sichern",src:"to secure, to safeguard",pos:"verb",gender:null,note:"From 'sicher' (safe/certain). To secure, protect, back up.\n'Sichern Sie Ihre Daten' = protect your data.",example:"A: Haben Sie Kopien Ihrer Unterlagen?\nB: Ja, ich habe alles gesichert.\nA: Gut. Man sollte immer Kopien sichern.\nB: Das hat mir Hildi beigebracht.",exampleSrc:"A: Do you have copies of your documents?\nB: Yes, I've secured everything.\nA: Good. One should always secure copies.\nB: Hildi taught me that.",funFact:"In bureaucratic context: make copies, store safely, have backups. 'Sichern Sie Ihre Daten.' Related to Sicherheit (security). Always have backup copies of every official document."},

{type:"teach",trg:"der Zugang",src:"the access",pos:"noun",gender:"m",note:"Zu- (to) + Gang (way/passage). Access to something.\n'Zugang zum Arbeitsmarkt' = access to the job market.",example:"A: Habe ich Zugang zum Arbeitsmarkt?\nB: Ja, mit dem Aufenthaltstitel haben Sie vollen Zugang.\nA: Und ohne?\nB: Ohne Aufenthaltstitel ist der Zugang eingeschränkt.",exampleSrc:"A: Do I have access to the job market?\nB: Yes, with the residence permit you have full access.\nA: And without?\nB: Without a residence permit, access is restricted.",funFact:"The Aufenthaltstitel determines your Zugang to many things in Germany: work, education, social services. Zu- (to) + Gang (way/passage) = the way to something."},

{type:"teach",trg:"die Rufnummer",src:"the phone number (formal)",pos:"noun",gender:"f",note:"Ruf (call) + Nummer (number). More formal than Telefonnummer.\nAlways appears on official forms.",example:"A: Wie ist Ihre Rufnummer?\nB: 030-5551234.\nA: Und Ihre Mobilnummer?\nB: 0170-9876543.",exampleSrc:"A: What is your phone number?\nB: 030-5551234.\nA: And your mobile number?\nB: 0170-9876543.",funFact:"More formal than Telefonnummer. On official forms, you always see Rufnummer. Die Rufnummer is feminine because Nummer is feminine."},

{type:"teach",trg:"der Zivilstand",src:"the marital status",pos:"noun",gender:"m",note:"Zivil (civil) + Stand (status). Germany uses Familienstand\nmore often. Ledig, verheiratet, geschieden, verwitwet.",example:"A: Was ist Ihr Zivilstand?\nB: Ledig.\nA: Und Ihre Staatsangehörigkeit?\nB: Griechisch.",exampleSrc:"A: What is your marital status?\nB: Single.\nA: And your nationality?\nB: Greek.",funFact:"Swiss/Austrian term; Germany uses Familienstand more often. Both appear on forms. Options: ledig (single), verheiratet (married), geschieden (divorced), verwitwet (widowed)."},

{type:"teach",trg:"das Original",src:"the original (document)",pos:"noun",gender:"n",note:"From Latin 'originalis.' The original, not a copy.\n'Bringen Sie bitte das Original mit.'",example:"A: Ist das eine Kopie oder das Original?\nB: Das ist das Original.\nA: Gut, wir brauchen immer das Original.\nB: Kopien werden nicht akzeptiert?",exampleSrc:"A: Is that a copy or the original?\nB: That is the original.\nA: Good, we always need the original.\nB: Copies are not accepted?",funFact:"German offices almost always require Originale. Copies are only accepted exceptionally. 'Bringen Sie bitte das Original mit' is something you hear at every Behörde."},

{type:"tip",title:"Nebensatzkonjunktionen: Verb ans Ende",text:"All subordinating conjunctions push the conjugated verb to the END of their clause.\n\nObwohl er nervös WAR.\nBevor die Frist ABLÄUFT.\nWährend der Beamte die Dokumente PRÜFT.\n\nThe main clause keeps normal V2 order.\nWhen the subordinate clause comes first, the main clause verb comes immediately after the comma:\n'Bevor die Frist abläuft, MUSS man den Antrag einreichen.'",deepDive:"Trotzdem is NOT a subordinating conjunction. It is an adverb and keeps V2 word order: 'Trotzdem HAT er alle Dokumente.'\n\nCompare:\n'Obwohl er nervös war, hatte er alle Dokumente.'\nvs.\n'Er war nervös. Trotzdem hatte er alle Dokumente.'\n\nSame meaning, different structure. Obwohl = verb-final clause. Trotzdem = verb-second in a new sentence."},

{type:"mc",q:"Obwohl er alle Dokumente _____, war er nervös.",opts:["hatte","er hatte","hat","hatte er"],ans:"hatte",hint:"After obwohl, the verb goes to the END. Subject + object + verb."},

{type:"mc",q:"_____ Sie Fragen haben, können Sie uns anrufen.",opts:["Seitdem","Bis","Trotzdem","Falls"],ans:"Falls",hint:"This conjunction means 'in case' or 'if (uncertain)'. It introduces a possibility."},

{type:"fb",s:"{1} ich in Deutschland lebe, brauche ich einen Aufenthaltstitel.",a:["Seitdem"],opts:["Seitdem","Bevor","Bis","Falls"],hint:"Which conjunction marks the starting point of an ongoing situation?",sSrc:"Since I've been living in Germany, I need a residence permit."},

{type:"mc",q:"Welches Satzpaar hat die gleiche Bedeutung?",opts:["Obwohl er müde war, ging er zur Behörde. / Er war müde. Trotzdem ging er zur Behörde.","Obwohl er müde war, ging er zur Behörde. / Er war müde, trotzdem er ging zur Behörde.","Obwohl er müde war, ging er zur Behörde. / Trotzdem er müde war, ging er zur Behörde.","Obwohl er müde war, ging er zur Behörde. / Er ging trotzdem müde zur Behörde."],ans:"Obwohl er müde war, ging er zur Behörde. / Er war müde. Trotzdem ging er zur Behörde.",hint:"Obwohl is a conjunction (verb-final). Trotzdem is an adverb (V2 in a new sentence)."},

{type:"drag_fill",s:"{1} die Frist {2}, muss der Antrag eingereicht werden.",blanks:{"1":"Bevor","2":"abläuft"},pool:["Bevor","abläuft","Bis","ablauft","Nachdem","abgelaufen"],hint:"Which conjunction means 'before'? The verb goes to the end of the subordinate clause.",sSrc:"Before the deadline expires, the application must be submitted."},

{type:"mc",q:"Verumius bringt alle Unterlagen mit, _____ der Antrag bearbeitet werden kann.",opts:["obwohl","falls","bis","damit"],ans:"damit",hint:"Which conjunction expresses purpose: 'so that' something can happen?"}
]},

// ===== LESSON 5: "Die Dokumentenprüfung" (The Document Check) =====
// Story development + combo practice. 15 new words. 22 steps.
{id:"deu_r19l5",title:"Die Dokumentenprüfung",icon:"\uD83D\uDD0D",xp:15,board:true,steps:[
{type:"intro",title:"Die Dokumentenprüfung",desc:"Die Beamtin prüft jedes Dokument. Verumius wartet. Passiv mit Modalverben und Nebensätze in der Praxis. Bürokratie live.",goals:["Übe Passiv mit Modalverben im Behörden-Dialog","Kombiniere Konjunktionen mit komplexer Grammatik","Überstehe eine Dokumentenprüfung bei der Behörde"]},

{type:"story",speaker:"beamtin",mood:"neutral",art:"de-auslaenderbehoerde-interview",trg:"Guten Tag. Nehmen Sie bitte Platz. Ich muss zunächst alle Unterlagen prüfen, bevor wir den Antrag bearbeiten können.",src:"Good day. Please take a seat. I must first check all documents before we can process the application."},

{type:"story",speaker:"verumius",mood:"nervous",art:"de-auslaenderbehoerde-interview",trg:"Guten Tag. Hier sind alle Dokumente, einschließlich der Geburtsurkunde und der Meldebescheinigung.",src:"Good day. Here are all documents, including the birth certificate and the registration confirmation."},

{type:"teach",trg:"die Beamtin",src:"the civil servant (female)",pos:"noun",gender:"f",note:"Feminine form of Beamter. Civil servants in Germany\nhave lifelong job security and their own pension system.",example:"A: Die Beamtin prüft Ihre Unterlagen.\nB: Wie lange dauert das?\nA: Die Beamtin arbeitet gründlich, das dauert etwas.\nB: Ich warte geduldig.",exampleSrc:"A: The civil servant is checking your documents.\nB: How long will that take?\nA: The civil servant works thoroughly, it takes a while.\nB: I'll wait patiently.",funFact:"In Germany, Beamte have special status: job security for life, their own pension system, no right to strike. The person behind the desk at the Behörde is almost always a Beamter or Beamtin."},

{type:"teach",trg:"das Asyl",src:"the asylum",pos:"noun",gender:"n",note:"From Greek 'asylon' (sanctuary). Political asylum.\nGuaranteed in Germany's Grundgesetz, Article 16a.",example:"A: Was bedeutet Asyl?\nB: Asyl ist Schutz für politisch Verfolgte.\nA: Ist das Recht auf Asyl im Grundgesetz?\nB: Ja, in Artikel 16a.",exampleSrc:"A: What does asylum mean?\nB: Asylum is protection for politically persecuted people.\nA: Is the right to asylum in the constitution?\nB: Yes, in Article 16a.",funFact:"Das Asylrecht (right to asylum) is guaranteed in Germany's Grundgesetz, Article 16a. The word comes from Greek 'asylon' (sanctuary). A foundational principle of German democracy."},

{type:"teach",trg:"die Geburt",src:"the birth",pos:"noun",gender:"f",note:"From 'gebären' (to give birth). Root of many compounds:\nGeburtsurkunde, Geburtsort, Geburtsdatum.",example:"A: Was ist Ihr Geburtsdatum?\nB: Der 15. Mai 1990.\nA: Und Ihr Geburtsort?\nB: Athen, Griechenland.",exampleSrc:"A: What is your date of birth?\nB: May 15, 1990.\nA: And your place of birth?\nB: Athens, Greece.",funFact:"One root word, many compounds: die Geburtsurkunde (birth certificate), der Geburtsort (birthplace), das Geburtsdatum (date of birth). German builds precise meaning by combining words."},

{type:"teach",trg:"die Schwangerschaft",src:"the pregnancy",pos:"noun",gender:"f",note:"Schwanger (pregnant) + -schaft (state of).\nTriggers special protections: Mutterschutz, Kündigungsschutz.",example:"A: Gibt es besondere Regelungen bei Schwangerschaft?\nB: Ja, Schwangerschaft bedeutet besonderen Schutz.\nA: Mutterschutz und Kündigungsschutz?\nB: Genau, beides ist gesetzlich garantiert.",exampleSrc:"A: Are there special regulations for pregnancy?\nB: Yes, pregnancy means special protection.\nA: Maternity protection and termination protection?\nB: Exactly, both are guaranteed by law.",funFact:"In Germany, Schwangerschaft triggers special protections: Mutterschutz (maternity protection), Kündigungsschutz (termination protection). The Behörde tracks this information."},

{type:"teach",trg:"der Einwohner",src:"the resident, the inhabitant (male)",pos:"noun",gender:"m",note:"Ein- (in) + Wohner (dweller). Die Einwohnerin = female.\nDifferent from Bürger (citizen): Einwohner includes everyone.",example:"A: Wie viele Einwohner hat Berlin?\nB: Etwa 3,7 Millionen Einwohner.\nA: Bin ich jetzt auch ein Einwohner?\nB: Ja, mit der Anmeldung sind Sie offiziell Einwohner.",exampleSrc:"A: How many inhabitants does Berlin have?\nB: About 3.7 million inhabitants.\nA: Am I also a resident now?\nB: Yes, with the registration you are officially a resident.",funFact:"Different from Bürger (citizen): Einwohner includes everyone who lives there, regardless of citizenship. Das Einwohnermeldeamt is where you register."},

{type:"teach",trg:"das Lager",src:"the camp, the warehouse",pos:"noun",gender:"n",note:"From 'lagern' (to store/camp). In immigration context:\nErstaufnahmelager = initial reception camp.",example:"A: Was ist ein Erstaufnahmelager?\nB: Ein Lager für neue Asylbewerber.\nA: Wie lange bleibt man dort?\nB: Bis ein Platz in einer Wohnung frei wird.",exampleSrc:"A: What is an initial reception camp?\nB: A camp for new asylum seekers.\nA: How long does one stay there?\nB: Until a place in an apartment becomes available.",funFact:"Historically loaded word in German. In immigration context: Erstaufnahmelager (initial reception camp). Modern usage is primarily logistical. The word simply means a place where things or people are stored/housed."},

{type:"teach",trg:"das Konsulat",src:"the consulate",pos:"noun",gender:"n",note:"Handles visas and documents for citizens abroad.\nEvery large city has consulates of many countries.",example:"A: Brauche ich eine Bescheinigung vom Konsulat?\nB: Ja, das Konsulat Ihres Heimatlandes muss das ausstellen.\nA: Wo ist das griechische Konsulat?\nB: In der Wittenbergplatz-Straße.",exampleSrc:"A: Do I need a certificate from the consulate?\nB: Yes, the consulate of your home country must issue that.\nA: Where is the Greek consulate?\nB: On Wittenbergplatz Street.",funFact:"Das Konsulat handles visas and documents for citizens abroad. Die Botschaft (embassy) handles diplomatic relations. Every country has a Botschaft in Berlin. Botschaft also means 'message' in everyday German."},

{type:"teach",trg:"die Botschaft",src:"the embassy, the message",pos:"noun",gender:"f",note:"Two meanings: embassy (diplomatic) and message (everyday).\n'Die griechische Botschaft in Berlin.'",example:"A: Ich muss zur Botschaft.\nB: Zur griechischen Botschaft?\nA: Ja, für ein Dokument.\nB: Die Botschaft ist in Charlottenburg.",exampleSrc:"A: I need to go to the embassy.\nB: To the Greek embassy?\nA: Yes, for a document.\nB: The embassy is in Charlottenburg.",funFact:"Botschaft means both 'embassy' and 'message.' 'Die Botschaft des Botschafters' could mean 'the message of the ambassador' or 'the embassy of the ambassador.' Context makes it clear."},

{type:"teach",trg:"ausschließen",src:"to exclude, to rule out",pos:"verb",gender:null,note:"Aus- (out) + schließen (to close). To close out, exclude.\n'Das kann nicht ausgeschlossen werden.'",example:"A: Kann ein Fehler ausgeschlossen werden?\nB: Nein, Fehler können nie ganz ausgeschlossen werden.\nA: Was machen wir, falls ein Fehler auftaucht?\nB: Dann korrigieren wir ihn sofort.",exampleSrc:"A: Can an error be ruled out?\nB: No, errors can never be completely ruled out.\nA: What do we do if an error comes up?\nB: Then we correct it immediately.",funFact:"In legal German: possibilities are ausgeschlossen (ruled out) or not. 'Das kann nicht ausgeschlossen werden' is a careful bureaucratic way of saying 'it's possible.'"},

{type:"teach",trg:"empfangen",src:"to receive (formal)",pos:"verb",gender:null,note:"Emp- + fangen (to catch). Higher register than bekommen\nor erhalten. Used in official correspondence.",example:"A: Haben Sie den Bescheid empfangen?\nB: Ja, ich habe ihn gestern empfangen.\nA: Gut, dann können wir weitermachen.\nB: Ich habe auch die Bestätigung empfangen.",exampleSrc:"A: Have you received the decision?\nB: Yes, I received it yesterday.\nA: Good, then we can proceed.\nB: I also received the confirmation.",funFact:"Higher register than bekommen or erhalten. 'Den Bescheid empfangen.' Used in official correspondence. The word literally means 'to catch toward' (emp- + fangen)."},

{type:"teach",trg:"integrieren",src:"to integrate",pos:"verb",gender:null,note:"From Latin 'integrare' (to make whole).\n'Sich in die Gesellschaft integrieren.'",example:"A: Haben Sie sich gut integriert?\nB: Ja, ich habe Deutsch gelernt und arbeite hier.\nA: Das ist vorbildlich.\nB: Es war nicht immer einfach, aber es hat sich gelohnt.",exampleSrc:"A: Have you integrated well?\nB: Yes, I learned German and work here.\nA: That is exemplary.\nB: It wasn't always easy, but it was worth it.",funFact:"Germany expects active integration: language courses, civic knowledge, cultural participation. 'Sich in die Gesellschaft integrieren' is the official phrase."},

{type:"teach",trg:"illegal",src:"illegal",pos:"adj",gender:null,note:"Same in English. Il- (not) + legal. 'Illegaler Aufenthalt.'\nThe term 'irregulärer Aufenthalt' is increasingly preferred.",example:"A: Ist es illegal, ohne Visum zu arbeiten?\nB: Ja, das ist illegal.\nA: Was passiert dann?\nB: Es gibt hohe Strafen und Konsequenzen für den Aufenthalt.",exampleSrc:"A: Is it illegal to work without a visa?\nB: Yes, that is illegal.\nA: What happens then?\nB: There are heavy penalties and consequences for the residence status.",funFact:"'Illegaler Aufenthalt' = illegal stay. In German legal language, the term 'irregulärer Aufenthalt' is increasingly preferred. Both are used in official contexts."},

{type:"teach",trg:"recht",src:"right, correct (adjective)",pos:"adj",gender:null,note:"As adjective: right, correct. 'Das ist recht.'\nDifferent from 'Recht' (noun) and 'rechts' (to the right).",example:"A: Ist das so recht?\nB: Ja, das ist genau recht.\nA: Haben Sie recht verstanden?\nB: Ich glaube, ich habe alles recht gemacht.",exampleSrc:"A: Is that correct like this?\nB: Yes, that is exactly right.\nA: Did you understand correctly?\nB: I believe I did everything correctly.",funFact:"Three forms, three meanings: 'recht' (adjective: correct), 'Recht' (noun: law/right), 'rechts' (adverb: to the right). Context determines which meaning applies."},

{type:"teach",trg:"zugänglich",src:"accessible",pos:"adj",gender:null,note:"Zu- (to) + Gang (way) + -lich. Available, accessible.\n'Die Informationen sind öffentlich zugänglich.'",example:"A: Sind die Formulare online zugänglich?\nB: Ja, alle Formulare sind online zugänglich.\nA: Gut, dann kann ich mich vorbereiten.\nB: Die Website der Behörde ist sehr zugänglich.",exampleSrc:"A: Are the forms accessible online?\nB: Yes, all forms are accessible online.\nA: Good, then I can prepare.\nB: The authority's website is very accessible.",funFact:"Related to Zugang (access). In bureaucracy: services should be zugänglich for everyone. 'Die Informationen sind öffentlich zugänglich' = the information is publicly accessible."},

{type:"story",speaker:"beamtin",mood:"neutral",art:"de-auslaenderbehoerde-interview",trg:"Die Geburtsurkunde muss beglaubigt werden. Haben Sie das Original mitgebracht, oder nur eine Kopie? Wir hatten doch abgemacht, dass alle Originale dabei sein müssen.",src:"The birth certificate must be certified. Did you bring the original, or only a copy? We had agreed that all originals must be included."},

{type:"mc",q:"Die Beamtin sagt: 'Die Geburtsurkunde muss beglaubigt werden.' Was bedeutet das?",opts:["Das Dokument braucht eine offizielle Bestätigung.","Das Dokument wird nicht akzeptiert.","Das Dokument muss neu geschrieben werden.","Das Dokument ist falsch."],ans:"Das Dokument braucht eine offizielle Bestätigung.",hint:"Beglaubigt means certified/authenticated. Muss...werden means it must be done."},

{type:"fb",s:"Der Antrag kann erst bearbeitet werden, {1} alle Unterlagen vollständig sind.",a:[{type:"teach",trg:"nachdem",src:"after (conjunction)",pos:"conj",gender:null,note:"Temporal conjunction. The nachdem-clause uses Perfekt,\nthe main clause uses Präteritum or Präsens.",example:"A: Nachdem ich den Antrag abgegeben habe, warte ich.\nB: Wie lange dauert es?\nA: Nachdem alle Unterlagen geprüft sind, kommt die Antwort.\nB: Das kann Wochen dauern.",exampleSrc:"A: After I submitted the application, I wait.\nB: How long does it take?\nA: After all documents are checked, the answer comes.\nB: That can take weeks.",funFact:"Nachdem forces a time-sequence shift: the nachdem-clause is one tense further back than the main clause. Perfekt in nachdem, Präsens in main. Plusquamperfekt in nachdem, Präteritum in main."},
"nachdem"],opts:["nachdem","trotzdem","obwohl","falls"],hint:"Which conjunction means 'after'? The application can only be processed after everything is complete.",sSrc:"The application can only be processed after all documents are complete."},

{type:"mc",q:"Welcher Satz kombiniert falls mit Passiv + Modalverb richtig?",opts:["Falls ein Dokument fehlt, muss es werden nachgereicht.","Falls ein Dokument fehlt, es muss nachgereicht werden.","Ein Dokument fehlt, falls muss es nachgereicht werden.","Falls ein Dokument fehlt, muss es nachgereicht werden."],ans:"Falls ein Dokument fehlt, muss es nachgereicht werden.",hint:"Falls-clause: verb-final. Main clause after comma: V2 (muss), then PP + werden at end."},

{type:"drag_fill",s:"Die Beamtin sagt, {1} der Antrag erst genehmigt werden {2}, {3} alle Gebühren bezahlt sind.",blanks:{"1":"dass","2":"kann","3":"nachdem"},pool:["dass","kann","nachdem","weil","muss","bevor"],hint:"Dass introduces what the officer says. The modal goes to the end of the dass-clause. Nachdem introduces the time condition.",sSrc:"The officer says that the application can only be approved after all fees are paid."},

{type:"mc",q:"Verumius fragt: 'Kann der Aufenthaltstitel auch vorläufig ausgestellt werden, falls die Beglaubigung noch fehlt?' Was will er?",opts:["Eine temporäre Lösung, während ein Dokument noch fehlt","Einen endgültigen Aufenthaltstitel","Einen neuen Termin","Die Absage seines Antrags"],ans:"Eine temporäre Lösung, während ein Dokument noch fehlt",hint:"Vorläufig means temporary. Falls means in case. He wants a provisional solution."}
]},

// ===== LESSON 6: "Bankdeutsch und Briefpost" (Banking German and Postal Mail) =====
// Vocab teach (banking + mail + family). 18 new words. 24 steps.
{id:"deu_r19l6",title:"Bankdeutsch und Briefpost",icon:"\uD83C\uDFE6",xp:15,board:true,steps:[
{type:"intro",title:"Bankdeutsch und Briefpost",desc:"Money and mail: two pillars of German daily life. Cash, bank transfers, mailboxes, and registered letters. Plus: family words for official forms.",goals:["Learn banking and postal vocabulary","Describe family relationships","Master compound nouns for financial and postal services"]},

{type:"teach",trg:"das Bargeld",src:"the cash",pos:"noun",gender:"n",note:"Bar (cash/bare) + Geld (money). Cash money.\nGermany is one of the most cash-loving countries in Europe.",example:"A: Kann ich mit Karte bezahlen?\nB: Nein, wir nehmen nur Bargeld.\nA: Wo ist der nächste Geldautomat?\nB: Gleich um die Ecke.",exampleSrc:"A: Can I pay by card?\nB: No, we only accept cash.\nA: Where is the nearest ATM?\nB: Right around the corner.",funFact:"Germany is one of the most cash-loving countries in Europe. Many shops still do not accept cards. 'Bargeld abheben' = to withdraw cash. The word combines 'bar' (cash) + 'Geld' (money)."},

{type:"teach",trg:"das Girokonto",src:"the checking account",pos:"noun",gender:"n",note:"Giro (from Italian 'giro,' circulation) + Konto (account).\nEvery resident needs one. No Girokonto = no rent, no salary.",example:"A: Haben Sie ein Girokonto in Deutschland?\nB: Ja, bei der Sparkasse.\nA: Gut, ohne Girokonto geht nichts.\nB: Das habe ich schnell gelernt.",exampleSrc:"A: Do you have a checking account in Germany?\nB: Yes, at the savings bank.\nA: Good, nothing works without a checking account.\nB: I learned that quickly.",funFact:"Every resident needs a Girokonto. Without it: no rent payment, no salary, no insurance. The Anmeldung enables the Girokonto. The word comes from Italian 'giro' (circulation)."},

{type:"teach",trg:"die Überweisung",src:"the bank transfer",pos:"noun",gender:"f",note:"Über (over) + Weisung (direction). Germans pay rent, bills,\nand each other by Überweisung. IBAN is essential.",example:"A: Wie bezahle ich die Miete?\nB: Per Überweisung.\nA: Brauche ich dafür die IBAN?\nB: Ja, die IBAN des Vermieters.",exampleSrc:"A: How do I pay the rent?\nB: By bank transfer.\nA: Do I need the IBAN for that?\nB: Yes, the landlord's IBAN.",funFact:"Germans pay rent, bills, and each other by Überweisung. 'Können Sie mir die IBAN für die Überweisung geben?' is everyday banking German."},

{type:"teach",trg:"die Einzahlung",src:"the deposit",pos:"noun",gender:"f",note:"Ein- (in) + Zahlung (payment). A deposit into an account.\nOpposite: Auszahlung (withdrawal). Ein = in, Aus = out.",example:"A: Ich möchte eine Einzahlung machen.\nB: Wie viel möchten Sie einzahlen?\nA: 500 Euro.\nB: In bar oder per Überweisung?",exampleSrc:"A: I would like to make a deposit.\nB: How much would you like to deposit?\nA: 500 euros.\nB: In cash or by transfer?",funFact:"The opposite of Einzahlung is Auszahlung (withdrawal). Ein = in, Aus = out. Simple German logic for banking transactions."},
{type:"teach",trg:"abmachen",src:"to arrange, to agree on",pos:"verb",gender:null,note:"Separable: ab + machen. 'Wir haben einen Termin abgemacht.'\nAlso: etwas abmachen = to take something off.",example:"A: Wir hatten doch abgemacht, dass alle Originale dabei sein müssen.\nB: Tut mir leid, ich habe es vergessen.\nA: Bitte machen Sie einen neuen Termin ab.\nB: Ja, ich rufe morgen an.",exampleSrc:"A: We had agreed that all originals must be included.\nB: I am sorry, I forgot.\nA: Please arrange a new appointment.\nB: Yes, I will call tomorrow.",funFact:"Abmachen has two meanings: to agree/arrange (einen Termin abmachen) and to remove (ein Etikett abmachen). Context makes the meaning clear. Abgemacht! means Deal! or Agreed!"},
{type:"teach",trg:"der Beleg",src:"the receipt, the proof",pos:"noun",gender:"m",note:"From belegen (to prove/document).\nKassenbeleg = receipt. Beleg vorlegen = to present proof.",example:"A: Haben Sie den Beleg?\nB: Ja, hier ist der Kassenbeleg.\nA: Bitte heben Sie alle Belege auf.\nB: Für die Steuererklärung?",exampleSrc:"A: Do you have the receipt?\nB: Yes, here is the receipt.\nA: Please keep all receipts.\nB: For the tax return?",funFact:"Germans keep Belege for everything. Kassenbeleg (cash register receipt), Überweisungsbeleg (transfer receipt). Ohne Beleg kein Beweis (without receipt, no proof) is a German tax motto."},
{type:"teach",trg:"die EC-Karte",src:"the debit card",pos:"noun",gender:"f",note:"EC = Electronic Cash. The standard German debit card.\nNow officially called girocard, but everyone says EC-Karte.",example:"A: Kann ich mit EC-Karte bezahlen?\nB: Ja, ab fünf Euro.\nA: Wo ist meine EC-Karte?\nB: Vielleicht im Geldbeutel?",exampleSrc:"A: Can I pay with a debit card?\nB: Yes, from five euros.\nA: Where is my debit card?\nB: Maybe in the wallet?",funFact:"The EC-Karte was renamed girocard in 2007, but nobody uses the new name. Kreditkarte (credit card) is less common in Germany. Cash and EC-Karte dominate daily payments."},
{type:"teach",trg:"einzahlen",src:"to deposit (money)",pos:"verb",gender:null,note:"Separable: ein + zahlen. Opposite: abheben (to withdraw).\nGeld einzahlen = to deposit money.",example:"A: Ich möchte 200 Euro einzahlen.\nB: In bar oder per Überweisung?\nA: In bar, bitte.\nB: Bitte legen Sie das Geld in den Automaten.",exampleSrc:"A: I would like to deposit 200 euros.\nB: In cash or by transfer?\nA: In cash, please.\nB: Please put the money in the machine.",funFact:"Ein (in) + zahlen (to pay). Money goes IN. The opposite is abheben (to lift off/withdraw). Simple German logic: ein = in, ab = off/away."},

{type:"teach",trg:"der Betrag",src:"the amount (of money)",pos:"noun",gender:"m",note:"From 'betragen' (to amount to). 'Der Betrag beträgt 35 Euro.'\nYes, Betrag and betragen look almost the same.",example:"A: Welchen Betrag möchten Sie überweisen?\nB: Den Betrag von 100 Euro.\nA: Der Betrag wurde überwiesen.\nB: Danke, ich sehe die Bestätigung.",exampleSrc:"A: What amount would you like to transfer?\nB: The amount of 100 euros.\nA: The amount has been transferred.\nB: Thanks, I can see the confirmation.",funFact:"'Der Betrag beträgt 35 Euro.' Yes, Betrag (noun: amount) and betragen (verb: to amount to) look almost the same. The noun is the amount, the verb means 'to amount to.'"},

{type:"teach",trg:"der Zins",src:"the interest (financial)",pos:"noun",gender:"m",note:"From Latin 'census' (tax). Die Zinsen (plural) = interest rates.\n'Wie hoch sind die Zinsen?'",example:"A: Wie hoch sind die Zinsen auf dem Girokonto?\nB: Die Zinsen sind momentan sehr niedrig.\nA: Fast null Prozent?\nB: Ja, die Zinsen waren jahrelang negativ.",exampleSrc:"A: How high are the interest rates on the checking account?\nB: The interest rates are currently very low.\nA: Almost zero percent?\nB: Yes, interest rates were negative for years.",funFact:"Germany had negative Zinsen for years. The concept is central to Girokonto discussions. Die Zinsen (plural) = interest rates. The word comes from Latin 'census' (tax)."},

{type:"teach",trg:"der Geldautomat",src:"the ATM",pos:"noun",gender:"m",note:"Geld (money) + Automat (machine). ATM.\nAustria says Bankomat, Switzerland says Bancomat.",example:"A: Wo ist der nächste Geldautomat?\nB: Gegenüber, bei der Sparkasse.\nA: Kann ich dort auch Geld einzahlen?\nB: Ja, an diesem Geldautomaten geht beides.",exampleSrc:"A: Where is the nearest ATM?\nB: Across the street, at the savings bank.\nA: Can I also deposit money there?\nB: Yes, this ATM handles both.",funFact:"Austria says Bankomat, Switzerland says Bancomat, Germany says Geldautomat. Three countries, three words, one machine. The gender comes from 'der Automat.'"},

{type:"teach",trg:"die Bankleitzahl",src:"the bank routing number",pos:"noun",gender:"f",note:"Bank + Leit- (routing) + Zahl (number). Being replaced by IBAN.\nOlder forms still ask for it.",example:"A: Was ist Ihre Bankleitzahl?\nB: 10050000. Aber heute benutzt man die IBAN.\nA: Stimmt, die IBAN ist international.\nB: Die Bankleitzahl ist nur noch für alte Formulare.",exampleSrc:"A: What is your bank routing number?\nB: 10050000. But today we use the IBAN.\nA: True, the IBAN is international.\nB: The routing number is only for old forms.",funFact:"Being replaced by IBAN in Europe, but older forms still ask for it. The gender comes from the last element: die Zahl. This is the rule for all German compound nouns."},

{type:"teach",trg:"der Briefkasten",src:"the mailbox",pos:"noun",gender:"m",note:"Brief (letter) + Kasten (box). Yellow in Germany (Deutsche Post).\nLeerungszeiten (collection times) posted on front.",example:"A: Wo ist der nächste Briefkasten?\nB: Am Ende der Straße, der gelbe Kasten.\nA: Wann wird er geleert?\nB: Jeden Tag um 17 Uhr.",exampleSrc:"A: Where is the nearest mailbox?\nB: At the end of the street, the yellow box.\nA: When is it emptied?\nB: Every day at 5 PM.",funFact:"Yellow in Germany (Deutsche Post). Every German neighborhood has one. Leerungszeiten (collection times) are posted on the front. Brief (letter) + Kasten (box) = mailbox."},

{type:"teach",trg:"der Briefumschlag",src:"the envelope",pos:"noun",gender:"m",note:"Brief (letter) + Umschlag (envelope, literally 'turn-around').\nGerman has precise postal vocabulary.",example:"A: Haben Sie einen Briefumschlag?\nB: Ja, hier. Welche Größe brauchen Sie?\nA: Einen großen Briefumschlag für die Unterlagen.\nB: A4? Hier, bitte.",exampleSrc:"A: Do you have an envelope?\nB: Yes, here. What size do you need?\nA: A large envelope for the documents.\nB: A4? Here you go.",funFact:"'Umschlag' literally means 'turn-around,' because you fold paper around the letter. German has some of the most precise postal vocabulary of any language."},

{type:"teach",trg:"der Briefträger",src:"the mail carrier (male)",pos:"noun",gender:"m",note:"Brief (letter) + Träger (carrier). Die Briefträgerin = female.\nGerman mail delivery is remarkably punctual.",example:"A: Wann kommt der Briefträger?\nB: Jeden Tag gegen zehn Uhr.\nA: Auch am Samstag?\nB: Ja, aber nicht am Sonntag.",exampleSrc:"A: When does the mail carrier come?\nB: Every day around ten o'clock.\nA: Also on Saturday?\nB: Yes, but not on Sunday.",funFact:"In Germany, mail delivery is remarkably punctual. You can almost set your clock by the Briefträger. Der Briefträger, die Briefträgerin. Brief (letter) + Träger (carrier)."},

{type:"teach",trg:"das Einschreiben",src:"the registered mail",pos:"noun",gender:"n",note:"Ein- (in) + schreiben (to write). Registered mail with proof.\n'Per Einschreiben schicken' for important documents.",example:"A: Wie soll ich den Antrag schicken?\nB: Per Einschreiben.\nA: Warum per Einschreiben?\nB: Weil Sie dann einen Beweis haben, dass es angekommen ist.",exampleSrc:"A: How should I send the application?\nB: By registered mail.\nA: Why by registered mail?\nB: Because then you have proof that it arrived.",funFact:"For anything important (Kündigung, Antrag, Beschwerde), Germans use Einschreiben. Proof of delivery. 'Per Einschreiben schicken' is the safest way to send official documents."},

{type:"teach",trg:"der Cousin",src:"the cousin (male)",pos:"noun",gender:"m",note:"From French. Pronounced koo-ZAN. Die Cousine = female.\nGerman borrowed these because Vetter/Base became outdated.",example:"A: Hast du Verwandte in Deutschland?\nB: Ja, mein Cousin lebt in München.\nA: Und deine Cousine?\nB: Sie lebt in Hamburg.",exampleSrc:"A: Do you have relatives in Germany?\nB: Yes, my cousin lives in Munich.\nA: And your female cousin?\nB: She lives in Hamburg.",funFact:"Pronounced the French way in German: koo-ZAN (Cousin), koo-ZEE-neh (Cousine). German borrowed these because the old Germanic words (Vetter/Base) became outdated."},

{type:"teach",trg:"der Neffe",src:"the nephew",pos:"noun",gender:"m",note:"From Latin 'nepos' (grandson, then nephew). Your sibling's son.\nSame root as English 'nephew' and 'nepotism.'",example:"A: Wer ist der Junge?\nB: Das ist mein Neffe, der Sohn meiner Schwester.\nA: Und das Mädchen?\nB: Das ist meine Nichte.",exampleSrc:"A: Who is the boy?\nB: That's my nephew, my sister's son.\nA: And the girl?\nB: That's my niece.",funFact:"Same root as English 'nephew' and the word 'nepotism' (favoring your nephews). From Latin 'nepos' (grandson, then nephew)."},

{type:"teach",trg:"die Nichte",src:"the niece",pos:"noun",gender:"f",note:"Your sibling's daughter. Die Nichte.\nNot related to 'nicht' (not), despite the similar spelling.",example:"A: Ist das deine Nichte?\nB: Ja, die Tochter meines Bruders.\nA: Sie sieht dir ähnlich.\nB: Das sagen alle.",exampleSrc:"A: Is that your niece?\nB: Yes, my brother's daughter.\nA: She looks like you.\nB: Everyone says that.",funFact:"Not related to 'nicht' (not), despite the similar appearance. Die Nichte is your sibling's daughter. The word has its own Latin etymology."},

{type:"teach",trg:"der Onkel",src:"the uncle",pos:"noun",gender:"m",note:"From French 'oncle,' from Latin 'avunculus.'\nAlso used affectionately: 'Onkel' + first name for close friends.",example:"A: Mein Onkel kommt zu Besuch.\nB: Aus Deutschland?\nA: Nein, aus Griechenland.\nB: Schön, dass er dich besucht.",exampleSrc:"A: My uncle is coming to visit.\nB: From Germany?\nA: No, from Greece.\nB: Nice that he's visiting you.",funFact:"Every German child calls friendly adult men 'Onkel' even if they are not related. 'Onkel' + first name = affectionate address. From French 'oncle,' from Latin 'avunculus.'"},

{type:"tip",title:"Zusammengesetzte Nomen im Bankwesen",text:"German builds banking vocabulary by combining words:\n\nGeld + Automat = Geldautomat\nBank + Leit + Zahl = Bankleitzahl\nÜber + Weisung = Überweisung\n\nThe gender always comes from the LAST element:\nDer Automat, so der Geldautomat.\nDie Zahl, so die Bankleitzahl.\nDie Weisung, so die Überweisung.\n\nMaster this rule and you can decode any compound noun.\n\nBonus: der Beleg (receipt). After every Einzahlung or Überweisung,\nyou get a Beleg as proof. Der Beleg ist Ihre Bestätigung.",deepDive:"This rule is universal in German. No exceptions. Die Tasche is feminine, so die Brieftasche is also feminine. Der Kasten is masculine, so der Briefkasten is also masculine. Das Konto is neuter, so das Girokonto is also neuter. The last word always determines the gender."},

{type:"mc",q:"Verumius möchte Geld abheben. Wo geht er hin?",opts:["Zur Überweisung","Zum Geldautomaten","Zum Briefkasten","Zur Einzahlung"],ans:"Zum Geldautomaten",hint:"Abheben means to withdraw. Which machine gives you Bargeld?"},

{type:"mc",q:"Verumius schickt einen wichtigen Antrag. Wie sollte er ihn schicken?",opts:["Per Briefkasten","Per Einschreiben","Per Überweisung","Per Geldautomat"],ans:"Per Einschreiben",hint:"Important documents need proof of delivery. Which postal service provides that?"},

{type:"fb",s:"Der Sohn meiner Schwester ist mein {1}.",a:["Neffe"],opts:["Neffe","Onkel","Cousin","Enkel"],hint:"Your sister's son. Which word means nephew?",sSrc:"My sister's son is my nephew."},

{type:"match",pairs:[{trg:"Girokonto",src:"checking account"},{trg:"Überweisung",src:"bank transfer"},{trg:"Bargeld",src:"cash"},{trg:"Einzahlung",src:"deposit"},{trg:"Geldautomat",src:"ATM"}]},

{type:"drag_fill",s:"Die Überweisung {1} innerhalb von drei Tagen {2} {3}.",blanks:{"1":"muss","2":"ausgeführt","3":"werden"},pool:["muss","ausgeführt","werden","kann","ausführen","wird"],hint:"Obligation: muss. Passive: Partizip II + werden. The transfer must be executed.",sSrc:"The transfer must be executed within three days."}
]},

// ===== LESSON 7: "Alles auf dem Prüfstand" (Everything Under Review) =====
// Comprehensive quiz. 10 new words. 22 steps.
{id:"deu_r19l7",title:"Alles auf dem Prüfstand",icon:"\u2705",xp:15,board:true,steps:[
{type:"intro",title:"Alles auf dem Prüfstand",desc:"Alles aus Unit 19 auf dem Prüfstand. Passiv mit Modalverben, Konjunktionen, Bürokratie, Bankwesen, Familie. Zeig, was du kannst.",goals:["Teste Passiv mit Modalverben und Konjunktionen","Beweise dein Behörden- und Bankvokabular","Kombiniere mehrere Grammatikstrukturen in komplexen Sätzen"]},

{type:"teach",trg:"der Enkel",src:"the grandson, the grandchild",pos:"noun",gender:"m",note:"From Old High German 'eninchili' (little grandfather).\nDie Enkelin = granddaughter. Originally 'little ancestor.'",example:"A: Haben Sie Enkel?\nB: Ja, zwei Enkel und eine Enkelin.\nA: Wie alt sind sie?\nB: Der Enkel ist fünf, die Enkelin ist drei.",exampleSrc:"A: Do you have grandchildren?\nB: Yes, two grandsons and one granddaughter.\nA: How old are they?\nB: The grandson is five, the granddaughter is three.",funFact:"The word originally meant 'little ancestor' because grandchildren resemble grandparents. Der Enkel (grandson), die Enkelin (granddaughter). From Old High German 'eninchili.'"},

{type:"teach",trg:"die Angehörige",src:"the relative, the family member",pos:"noun",gender:"f",note:"An- (to) + gehören (to belong) + -ige. Family member.\n'Nächste Angehörige' = next of kin on official forms.",example:"A: Wer sind Ihre nächsten Angehörigen?\nB: Meine Schwester und mein Onkel.\nA: Name und Rufnummer bitte.\nB: Maria, 0170-1234567.",exampleSrc:"A: Who are your next of kin?\nB: My sister and my uncle.\nA: Name and phone number please.\nB: Maria, 0170-1234567.",funFact:"'Nächste Angehörige' = next of kin. On official forms, this field asks who should be contacted in emergencies. The word means 'those who belong to you.'"},

{type:"teach",trg:"verwandt",src:"related (by family)",pos:"adj",gender:null,note:"'Wir sind verwandt' = We are related.\nDie Verwandtschaft = the relatives (collectively).",example:"A: Sind Sie mit Herrn Müller verwandt?\nB: Ja, er ist mein Onkel.\nA: Haben Sie noch mehr Verwandte in Berlin?\nB: Ja, die ganze Verwandtschaft lebt hier.",exampleSrc:"A: Are you related to Mr. Müller?\nB: Yes, he is my uncle.\nA: Do you have more relatives in Berlin?\nB: Yes, the whole family lives here.",funFact:"Germans take Verwandtschaft seriously at holidays. Die Verwandtschaft = the relatives (collectively). 'Wir sind verwandt' = we are related."},

{type:"teach",trg:"spätestens",src:"at the latest",pos:"adv",gender:null,note:"Superlative of 'spät' (late) + -ens. Absolute deadline.\n'Spätestens am Freitag' = by Friday at the latest.",example:"A: Wann muss der Antrag eingereicht sein?\nB: Spätestens am 15. März.\nA: Und wenn ich zu spät bin?\nB: Dann wird der Antrag nicht mehr bearbeitet.",exampleSrc:"A: When must the application be submitted?\nB: By March 15th at the latest.\nA: And if I'm too late?\nB: Then the application will no longer be processed.",funFact:"The word bureaucrats use to set absolute deadlines. No flexibility after spätestens. 'Spätestens am Freitag' means there is absolutely no extension beyond Friday."},

{type:"teach",trg:"ausschließlich",src:"exclusively",pos:"adv",gender:null,note:"Aus- + schließlich (finally). Only this, nothing else.\n'Ausschließlich mit Termin' = by appointment only.",example:"A: Kann ich ohne Termin kommen?\nB: Nein, ausschließlich mit Termin.\nA: Und online?\nB: Der Service ist ausschließlich persönlich.",exampleSrc:"A: Can I come without an appointment?\nB: No, by appointment only.\nA: And online?\nB: The service is exclusively in person.",funFact:"The Behörde loves this word. It means 'only this, nothing else.' 'Ausschließlich mit Termin' = by appointment only. No exceptions."},

{type:"teach",trg:"statt",src:"instead of",pos:"prep",gender:null,note:"Short for 'anstatt.' Preposition with genitive.\n'Statt einer Kopie brauchen wir das Original.'",example:"A: Kann ich eine Kopie bringen?\nB: Nein, statt einer Kopie brauchen wir das Original.\nA: Statt einer Überweisung kann ich bar bezahlen?\nB: Ja, das geht auch.",exampleSrc:"A: Can I bring a copy?\nB: No, instead of a copy we need the original.\nA: Instead of a transfer, can I pay cash?\nB: Yes, that works too.",funFact:"Short for 'anstatt' (instead of). Takes genitive. 'Statt einer Kopie brauchen wir das Original.' Also used in 'statt...zu' (instead of doing)."},

{type:"teach",trg:"trotz",src:"despite",pos:"prep",gender:null,note:"Preposition with genitive. 'Trotz aller Schwierigkeiten.'\nRelated to trotzdem (adverb: nevertheless).",example:"A: Trotz aller Schwierigkeiten hat er den Antrag eingereicht.\nB: Das war mutig.\nA: Trotz der langen Wartezeit blieb er geduldig.\nB: Beeindruckend.",exampleSrc:"A: Despite all difficulties, he submitted the application.\nB: That was brave.\nA: Despite the long wait, he remained patient.\nB: Impressive.",funFact:"Closely related to trotzdem (nevertheless). Trotz = preposition with genitive, trotzdem = adverb. 'Trotz aller Schwierigkeiten' = despite all difficulties."},

{type:"teach",trg:"dahin",src:"there, to that place",pos:"adv",gender:null,note:"Da- (there) + hin (toward). Direction away from the speaker.\nContrast: daher = from there (toward speaker).",example:"A: Wie komme ich zur Ausländerbehörde?\nB: Fahren Sie mit der U-Bahn. Linie 6 fährt dahin.\nA: Wie lange brauche ich dahin?\nB: Etwa 20 Minuten.",exampleSrc:"A: How do I get to the immigration office?\nB: Take the subway. Line 6 goes there.\nA: How long does it take to get there?\nB: About 20 minutes.",funFact:"Hin and her define direction in German. Dahin = there (away from speaker). Daher = from there (toward speaker). 'Wie komme ich dahin?' = How do I get there?"},

{type:"teach",trg:"die Tante",src:"the aunt",pos:"noun",gender:"f",note:"From French 'tante.' Your parent's sister.\n'Tante-Emma-Laden' = a small corner shop.",example:"A: Meine Tante kommt morgen zu Besuch.\nB: Aus welcher Stadt?\nA: Aus Düsseldorf.\nB: Schön, dann habt ihr Familienbesuch.",exampleSrc:"A: My aunt is coming to visit tomorrow.\nB: From which city?\nA: From Düsseldorf.\nB: Nice, then you'll have family visiting.",funFact:"'Tante-Emma-Laden' is a German expression for a small corner shop (Aunt Emma's shop). Die Tante is the counterpart to der Onkel. Also used affectionately for older family friends."},

{type:"teach",trg:"die Enkelin",src:"the granddaughter",pos:"noun",gender:"f",note:"Enkel + -in. The feminine form of Enkel.\nPlural: die Enkelinnen.",example:"A: Ist das Ihre Enkelin?\nB: Ja, sie heißt Lena.\nA: Wie alt ist Ihre Enkelin?\nB: Drei Jahre alt.",exampleSrc:"A: Is that your granddaughter?\nB: Yes, her name is Lena.\nA: How old is your granddaughter?\nB: Three years old.",funFact:"The feminine form of Enkel. Der Enkel (grandson/grandchild), die Enkelin (granddaughter). Plural: die Enkelinnen. German always provides gendered forms for family members."},

{type:"mc",q:"Der Aufenthaltstitel _____ beantragt werden.",opts:["ist","wird","muss","hat"],ans:"muss",hint:"Which modal expresses obligation? Structure: modal + PP + werden."},

{type:"mc",q:"Ohne Visum _____ in Deutschland nicht gearbeitet _____.",opts:["muss...werden","soll...haben","kann...sein","darf...werden"],ans:"darf...werden",hint:"Prohibition = darf nicht. Passive = PP + werden."},

{type:"fb",s:"{1} er alle Dokumente hatte, war er trotzdem nervös.",a:["Obwohl"],opts:["Obwohl","Trotzdem","Bevor","Weil"],hint:"Which conjunction means 'although'? It requires verb-final order.",sSrc:"Although he had all documents, he was still nervous."},

{type:"mc",q:"Verumius wartet, _____ seine Nummer aufgerufen wird.",opts:["seitdem","bis","damit","falls"],ans:"bis",hint:"He waits until a specific event happens. Which conjunction means 'until'?"},

{type:"fb",s:"Der Antrag kann erst genehmigt werden, {1} alle Gebühren bezahlt sind.",a:["nachdem"],opts:["nachdem","obwohl","falls","bevor"],hint:"The approval happens AFTER the fees are paid. Which conjunction marks time sequence?",sSrc:"The application can only be approved after all fees are paid."},

{type:"mc",q:"Welcher Satz kombiniert Bedingung mit Passiv + Modalverb richtig?",opts:["Falls die Frist abläuft, muss der Antrag neu gestellt werden.","Falls die Frist abläuft, der Antrag muss neu gestellt werden.","Falls die Frist abläuft, den Antrag muss neu gestellt werden.","Die Frist abläuft falls, muss der Antrag neu gestellt werden."],ans:"Falls die Frist abläuft, muss der Antrag neu gestellt werden.",hint:"Falls-clause: verb-final. Main clause: V2 (muss), then PP + werden at end."},

{type:"match",pairs:[{trg:"obwohl",src:"although"},{trg:"bevor",src:"before"},{trg:"seitdem",src:"since (time)"},{trg:"damit",src:"so that"},{trg:"falls",src:"in case"}]},

{type:"drag_fill",s:"{1} Verumius den Antrag eingereicht hat, {2} der Bescheid innerhalb von sechs Wochen {3} {4}.",blanks:{"1":"Nachdem","2":"muss","3":"ausgestellt","4":"werden"},pool:["Nachdem","muss","ausgestellt","werden","Bevor","kann","ausstellen","wird"],hint:"After he submitted the application, the decision must be issued. Nachdem + Perfekt, then muss + PP + werden.",sSrc:"After Verumius submitted the application, the decision must be issued within six weeks."},

{type:"mc",q:"Was ist der Unterschied zwischen Wohnort und Wohnsitz?",opts:["Kein Unterschied","Wohnort ist formeller","Wohnsitz bedeutet Arbeitsplatz","Wohnsitz ist die offizielle Meldeadresse"],ans:"Wohnsitz ist die offizielle Meldeadresse",hint:"Sitz implies official registration. Ort is more general."},

{type:"fb",s:"Die Tochter meines Bruders ist meine {1}.",a:["Nichte"],opts:["Nichte","Cousine","Enkelin","Tante"],hint:"Your brother's daughter. The female form of Neffe.",sSrc:"My brother's daughter is my niece."},

{type:"mc",q:"Die Überweisung muss bis Freitag ausgeführt werden. Was bedeutet das?",opts:["Der Bankauftrag hat eine Frist bis Freitag.","Die Bank ist am Freitag geschlossen.","Die Zinsen werden am Freitag berechnet.","Man braucht Bargeld am Freitag."],ans:"Der Bankauftrag hat eine Frist bis Freitag.",hint:"Muss...werden = obligation. Bis Freitag = deadline."},

{type:"drag_fill",s:"{1} die Beamtin alle Unterlagen geprüft hat, {2} der Aufenthaltstitel {3} {4}, {5} alle Gebühren bezahlt sind.",blanks:{"1":"Nachdem","2":"kann","3":"ausgestellt","4":"werden","5":"falls"},pool:["Nachdem","kann","ausgestellt","werden","falls","Bevor","muss","ausstellen","wird","obwohl"],hint:"After the officer checked everything, the permit can be issued, if all fees are paid. Time + possibility + condition.",sSrc:"After the officer checked all documents, the residence permit can be issued, if all fees are paid."}
]},

// ===== LESSON 8: "Ich habe es geschafft!" (I Made It!) =====
// Story resolution + cultural deep dive. 13 new words. 22 steps.
{id:"deu_r19l8",title:"Ich habe es geschafft!",icon:"\uD83C\uDF89",xp:15,board:true,steps:[
{type:"intro",title:"Ich habe es geschafft!",desc:"Der Stempel fällt. WUMM. Genehmigt. Verumius ruft KD an. Der Gruppenchat explodiert. Offizieller Einwohner von Deutschland.",goals:["Feiere Verumius' Aufenthaltstitel","Lerne Vokabular für Handel und Alltag","Reflektiere den bürokratischen Weg und die deutsche Verwaltungskultur"]},

{type:"story",speaker:"narrator",mood:"triumphant",art:"de-auslaenderbehoerde-stamp",trg:"Die Beamtin greift zum Stempel. WUMM. Genehmigt. Verumius' Gesicht verwandelt sich. Er steht auf, bedankt sich dreimal und geht in den Flur. Das Handy ist schon in der Hand.",src:"The officer reaches for the stamp. THUNK. Approved. Verumius's face transforms. He stands up, thanks her three times, and walks into the hallway. The phone is already in his hand."},

{type:"story",speaker:"verumius",mood:"excited",art:"de-auslaenderbehoerde-hallway",trg:"Herr Hoffmann, ich habe es geschafft! Der Aufenthaltstitel wurde genehmigt!",src:"Mr. Hoffmann, I made it! The residence permit was approved!"},

{type:"story",speaker:"kd",mood:"deadpan",art:"de-auslaenderbehoerde-hallway",trg:"Natürlich. Sie hatten ja alle Unterlagen. War doch klar.",src:"Of course. You had all the documents. That was obvious."},

{type:"teach",trg:"der Käufer",src:"the buyer (male)",pos:"noun",gender:"m",note:"From 'kaufen' (to buy). Die Käuferin = female buyer.\nIn contracts: Käufer (buyer) vs. Verkäufer (seller).",example:"A: Wer ist der Käufer?\nB: Herr Schmidt ist der Käufer.\nA: Und die Käuferin?\nB: Frau Weber kauft das zweite Auto.",exampleSrc:"A: Who is the buyer?\nB: Mr. Schmidt is the buyer.\nA: And the female buyer?\nB: Mrs. Weber is buying the second car.",funFact:"In legal contracts, the Käufer is the buyer, the Verkäufer is the seller. Every Kaufvertrag (sales contract) names both. The word comes from 'kaufen' (to buy)."},

{type:"teach",trg:"die Verkäuferin",src:"the sales clerk (female)",pos:"noun",gender:"f",note:"Ver- + Käuferin. Female sales clerk. Der Verkäufer = male.\nCommon job title on signs: 'Verkäuferin gesucht.'",example:"A: Entschuldigung, können Sie mir helfen?\nB: Ja, ich bin die Verkäuferin. Was suchen Sie?\nA: Einen neuen Ordner für meine Dokumente.\nB: Die Ordner finden Sie in Gang drei.",exampleSrc:"A: Excuse me, can you help me?\nB: Yes, I'm the sales clerk. What are you looking for?\nA: A new folder for my documents.\nB: You'll find the folders in aisle three.",funFact:"In German, you still commonly see gendered job titles on signs: 'Verkäuferin gesucht' (female sales clerk wanted). The masculine form is Verkäufer."},

{type:"teach",trg:"die Betriebsrätin",src:"the works council member (female)",pos:"noun",gender:"f",note:"Betrieb (company) + Rat (council) + -in. Employee representative\nwith real legal power. Codetermination = Mitbestimmung.",example:"A: Wer ist die Betriebsrätin?\nB: Frau Schneider vertritt die Mitarbeiter.\nA: Was macht die Betriebsrätin genau?\nB: Sie verhandelt Arbeitsbedingungen mit der Geschäftsleitung.",exampleSrc:"A: Who is the works council member?\nB: Ms. Schneider represents the employees.\nA: What exactly does the works council member do?\nB: She negotiates working conditions with management.",funFact:"Der Betriebsrat is a uniquely German institution: employee representatives with real legal power. Codetermination (Mitbestimmung) is fundamental to German labor law."},

{type:"teach",trg:"die Chipkarte",src:"the chip card",pos:"noun",gender:"f",note:"Chip + Karte. A card with an electronic chip.\nDie EC-Karte is the German debit card (officially 'girocard').",example:"A: Haben Sie Ihre Chipkarte dabei?\nB: Ja, hier ist meine EC-Karte.\nA: Die EC-Karte ist auch eine Chipkarte.\nB: Stimmt, mit dem goldenen Chip.",exampleSrc:"A: Do you have your chip card with you?\nB: Yes, here is my debit card.\nA: The debit card is also a chip card.\nB: Right, with the golden chip.",funFact:"Die EC-Karte (Electronic Cash card) is the German debit card. Germans use 'EC-Karte' even though the official name changed to 'girocard' in 2007. Old habits die hard."},

{type:"teach",trg:"der Bancomat",src:"the ATM (Swiss German)",pos:"noun",gender:"m",note:"Swiss German for ATM. From Italian 'banco' (bank) +\n'automatico.' Die Bancomatkarte = Swiss debit card.",example:"A: Wo ist der nächste Bancomat?\nB: In der Schweiz sagt man Bancomat.\nA: Und in Deutschland?\nB: Da sagt man Geldautomat.",exampleSrc:"A: Where is the nearest ATM?\nB: In Switzerland they say Bancomat.\nA: And in Germany?\nB: There they say Geldautomat.",funFact:"Switzerland has its own banking vocabulary. Same machine, different name. Bancomat (Swiss) vs. Bankomat (Austrian) vs. Geldautomat (German)."},

{type:"teach",trg:"der Bankomat",src:"the ATM (Austrian German)",pos:"noun",gender:"m",note:"Austrian German for ATM. Die Bankomatkarte = Austrian\ndebit card. Three countries, three words, one machine.",example:"A: Ich suche einen Bankomaten.\nB: In Österreich sagt man Bankomat.\nA: Und die Karte heißt Bankomatkarte?\nB: Ja, genau.",exampleSrc:"A: I'm looking for an ATM.\nB: In Austria they say Bankomat.\nA: And the card is called Bankomatkarte?\nB: Yes, exactly.",funFact:"Austria says Bankomat, Switzerland says Bancomat, Germany says Geldautomat. Three countries, three words. Austrian German is its own world with many unique terms."},

{type:"teach",trg:"die Brieftasche",src:"the wallet",pos:"noun",gender:"f",note:"Brief (letter) + Tasche (bag). Originally for carrying letters.\nDas Portemonnaie (from French) is the elegant alternative.",example:"A: Wo ist meine Brieftasche?\nB: Auf dem Tisch, neben den Schlüsseln.\nA: Danke, ich brauche mein Portemonnaie für die Gebühr.\nB: Brieftasche und Portemonnaie sind dasselbe.",exampleSrc:"A: Where is my wallet?\nB: On the table, next to the keys.\nA: Thanks, I need my wallet for the fee.\nB: Brieftasche and Portemonnaie are the same thing.",funFact:"Brief (letter) + Tasche (bag) = wallet (originally for carrying letters/documents). Das Portemonnaie is from French 'porte-monnaie' (money carrier). Both mean wallet. Brieftasche is more German, Portemonnaie more elegant."},

{type:"teach",trg:"der Zuschlag",src:"the surcharge, the supplement",pos:"noun",gender:"m",note:"Zu- (to) + Schlag (strike/hit). Extra charge on top of base price.\nICE-Zuschlag, Nachtzuschlag.",example:"A: Gibt es einen Zuschlag für den ICE?\nB: Ja, der ICE-Zuschlag beträgt 13 Euro.\nA: Und für die erste Klasse?\nB: Da kommt noch ein Zuschlag dazu.",exampleSrc:"A: Is there a surcharge for the ICE?\nB: Yes, the ICE surcharge is 13 euros.\nA: And for first class?\nB: There's an additional surcharge for that.",funFact:"ICE-Zuschlag (high-speed train surcharge). Nachtzuschlag (night surcharge). Germany loves adding Zuschläge to base prices. Zu- (to) + Schlag (strike/hit)."},

{type:"story",speaker:"narrator",mood:"warm",art:"de-apartment-celebration",trg:"Verumius' Handy explodiert. Lukas schickt Party-Emojis. Mia schreibt: 'Herzlichen Glückwunsch!' Hildi (die texten gelernt hat): 'Gute Nachricht.' Heinrich (über Hildis Handy): 'Endlich!'",src:"Verumius's phone explodes. Lukas sends party emojis. Mia writes: 'Congratulations!' Hildi (who learned to text): 'Good news.' Heinrich (via Hildi's phone): 'Finally!'"},

{type:"story",speaker:"verumius",mood:"reflective",art:"de-apartment-celebration",trg:"Verumius sitzt auf der Couch. Der Aufenthaltstitel liegt auf dem Couchtisch. Seitdem er in Deutschland angekommen ist, musste so viel erledigt werden. Anmeldung, Girokonto, Versicherung, Sprachkurs, Arbeitsvertrag, Behördengänge. Aber jetzt: offizieller Einwohner. Endlich ein Zuhause. Alles ist drin.",src:"Verumius sits on the couch. The residence permit lies on the coffee table. Since he arrived in Germany, so much had to be done. Registration, checking account, insurance, language course, employment contract, trips to government offices. But now: official resident. Finally a home. Everything is included."},

{type:"tip",title:"Deutsche Bürokratie: Warum sie so funktioniert",text:"Germany's administrative system dates back to Prussian efficiency reforms in the 1700s.\n\nThe principle: if something is documented, it exists. If it is not documented, it does not.\n\nThis explains the obsession with Urkunden, Bescheinigungen, and Originale.\n\nThe Ausländerbehörde is not trying to be difficult. It follows a system designed for maximum legal certainty.\n\nEvery stamp, every Frist, every Bestätigung serves a purpose: protecting both the state and the individual.\n\n'Ordnung muss sein' (there must be order) captures the philosophy.",deepDive:"The German word 'Beamtenstaat' (civil servant state) describes a country where bureaucracy is a profession, not just a job. Beamte study for years, pass state exams, and receive lifelong employment. This creates consistency but also rigidity. The system prioritizes fairness through uniformity: everyone follows the same rules, fills out the same forms, waits the same amount of time."},

{type:"mc",q:"Nachdem alle Unterlagen geprüft worden waren, _____ der Aufenthaltstitel ausgestellt _____.",opts:["konnte...werden","sollte...sind","musste...sein","wurde...haben"],ans:"konnte...werden",hint:"After checking, the permit could be issued. Passive + modal: konnte + PP + werden."},

{type:"mc",q:"Verumius feiert, _____ er wochenlang auf den Termin gewartet hat.",opts:["obwohl","damit","nachdem","bevor"],ans:"nachdem",hint:"He celebrates after waiting. Which conjunction marks completed prior action?"},

{type:"fb",s:"In Deutschland muss jeder Einwohner einen {1} haben.",a:["Wohnsitz"],opts:["Wohnsitz","Arbeitsplatz","Aufenthaltstitel","Pass"],hint:"The official registered address that everyone needs. The Anmeldung establishes this.",sSrc:"In Germany, every resident must have a registered address."},

{type:"mc",q:"In Österreich sagt man 'Bankomat.' In der Schweiz sagt man...?",opts:["Geldautomat","Bancomat","EC-Karte","Chipkarte"],ans:"Bancomat",hint:"Swiss German uses an Italian-influenced word. It sounds like the Austrian version but with a 'c' instead of 'k.'"},

{type:"match",pairs:[{trg:"Behörde",src:"government authority"},{trg:"Aufenthalt",src:"residence/stay"},{trg:"Gebühr",src:"fee"},{trg:"Überweisung",src:"bank transfer"},{trg:"Einschreiben",src:"registered mail"}]},

{type:"drag_fill",s:"{1} Verumius alle Dokumente eingereicht hatte, {2} der Aufenthaltstitel genehmigt {3}, {4} er alle Gebühren bezahlt hatte.",blanks:{"1":"Nachdem","2":"konnte","3":"werden","4":"nachdem"},pool:["Nachdem","konnte","werden","nachdem","Bevor","wurde","wird","obwohl"],hint:"After submitting, the permit could be approved, after he had paid. Nachdem + konnte...werden.",sSrc:"After Verumius had submitted all documents, the residence permit could be approved, after he had paid all fees."},

{type:"mc",q:"Was musste Verumius alles machen, bevor der Aufenthaltstitel genehmigt werden konnte?",opts:["Nichts, der Aufenthaltstitel wird automatisch ausgestellt","Alle Unterlagen sammeln, Gebühren bezahlen und rechtzeitig den Antrag stellen","Nur das Visum verlängern","Nur die Gebühr bezahlen"],ans:"Alle Unterlagen sammeln, Gebühren bezahlen und rechtzeitig den Antrag stellen",hint:"The full process requires multiple steps. Which answer covers everything?"}
]}

]},

{n:20,lang:"de",srcLang:"en",track:"v2",title:"Die Versicherung",sub:"Health insurance maze, compound nouns, relative clauses with prepositions, adverbial conjunctions",icon:"🏥",level:"B1.2",color:"#7B5EE8",lessons:[

// ═══════════════════════════════════════════════════════════════
// Lesson 1: "Der Papierstapel" — Story intro (18 words, 24 steps)
// Scene 1: Kitchen table of despair
// ═══════════════════════════════════════════════════════════════
{id:"deu_r20l1",title:"Der Papierstapel",icon:"📄",xp:15,board:true,steps:[
{type:"intro",title:"Der Papierstapel",desc:"Verumius sitzt an seinem K\u00fcchentisch. Vor ihm liegen zwanzig Briefe von der Krankenkasse. Er versteht kein Wort.",goals:["Lerne Vokabeln rund um Gesundheit und Versicherung","Erlebe Verumius im Kampf mit deutscher B\u00fcrokratie","Verstehe, warum Krankenversicherung in Deutschland wichtig ist"]},
{type:"story",speaker:"narrator",mood:"comedy",art:"de-ber-kitchen-papers",trg:"Verumius sitzt an seinem K\u00fcchentisch. Vor ihm liegen zwanzig Briefe, f\u00fcnf Brosch\u00fcren und drei Formulare. Alle kommen von der Krankenkasse. Er versteht kein Wort.",src:"Verumius sits at his kitchen table. In front of him lie twenty letters, five brochures, and three forms. They all come from the health insurance company. He does not understand a single word."},
{type:"teach",trg:"die Versicherung",src:"the insurance",pos:"noun",gender:"f",note:"From versichern (to insure/assure).\nVer- + sicher (safe) + -ung = making safe.",example:"A: Hast du eine Krankenversicherung?\nB: Ja, ich bin bei der TK versichert.\nA: Ist das eine gute Versicherung?\nB: Ja, die Leistungen sind sehr gut.",exampleSrc:"A: Do you have health insurance?\nB: Yes, I am insured with TK.\nA: Is that a good insurance?\nB: Yes, the benefits are very good.",funFact:"Germans are famously over-insured: liability, legal protection, glass breakage, even dog insurance exists. The word itself means 'making something safe.'"},
{type:"teach",trg:"der Krankenwagen",src:"the ambulance",pos:"noun",gender:"m",note:"Krank (sick) + Wagen (vehicle).\nLiterally: the sick-car. Call 112 in emergencies.",example:"A: Ruft den Krankenwagen!\nB: Was ist passiert?\nA: Der Mann ist gest\u00fcrzt.\nB: Ich rufe sofort die 112 an.",exampleSrc:"A: Call the ambulance!\nB: What happened?\nA: The man fell down.\nB: I will call 112 right away.",funFact:"Unlike the US, the Krankenwagen ride is covered by your Versicherung. In emergencies, call 112. This number works across all of Europe."},
{type:"teach",trg:"die Kosten",src:"the costs, the expenses",pos:"noun",gender:"pl",note:"Always plural in this meaning.\n'Die Kosten steigen' is Germany's favorite headline.",example:"A: Wie hoch sind die Kosten?\nB: Die Kosten betragen 200 Euro pro Monat.\nA: Das ist teuer!\nB: Ja, aber die Versicherung deckt viel ab.",exampleSrc:"A: How high are the costs?\nB: The costs amount to 200 euros per month.\nA: That is expensive!\nB: Yes, but the insurance covers a lot.",funFact:"From Latin 'constare' (to stand firm at a price). No singular form when it means expenses. 'Die Kosten steigen' (costs are rising) appears in German news almost daily."},
{type:"teach",trg:"der Patient",src:"the patient (male)",pos:"noun",gender:"m",note:"Weak masculine noun (N-Deklination).\nDen Patienten, dem Patienten in all other cases.",example:"A: Der Patient wartet seit einer Stunde.\nB: Welcher Patient?\nA: Der Patient mit den Kopfschmerzen.\nB: Ah, ich rufe ihn gleich auf.",exampleSrc:"A: The patient has been waiting for an hour.\nB: Which patient?\nA: The patient with the headache.\nB: Ah, I will call him in shortly.",funFact:"From Latin 'patiens' (suffering/enduring). The patient literally endures. Same root as 'patience.' A weak masculine noun: der Patient but den/dem Patienten."},
{type:"teach",trg:"die Patientin",src:"the patient (female)",pos:"noun",gender:"f",note:"Feminine form of Patient.\nThe -in suffix creates feminine person nouns.",example:"A: Wie geht es der Patientin?\nB: Die Patientin f\u00fchlt sich besser.\nA: Kann sie morgen nach Hause?\nB: Ja, wenn die Untersuchung gut ausf\u00e4llt.",exampleSrc:"A: How is the patient doing?\nB: The patient is feeling better.\nA: Can she go home tomorrow?\nB: Yes, if the examination goes well.",funFact:"The -in suffix creates feminine versions of person nouns. Der Patient becomes die Patientin. German insists on gendered forms for people, though modern usage is evolving."},
{type:"teach",trg:"die Untersuchung",src:"the examination, the checkup",pos:"noun",gender:"f",note:"Unter (under) + such (seek) + -ung.\nMedical exam, investigation, or scientific study.",example:"A: Wann ist Ihre n\u00e4chste Untersuchung?\nB: N\u00e4chste Woche beim Hausarzt.\nA: Ist es eine Routineuntersuchung?\nB: Ja, ich gehe einmal im Jahr.",exampleSrc:"A: When is your next checkup?\nB: Next week at the family doctor.\nA: Is it a routine checkup?\nB: Yes, I go once a year.",funFact:"One word covers medical checkups, police investigations, and scientific studies. 'Zur Untersuchung gehen' means going for a medical exam. A seeking-under."},
{type:"teach",trg:"die Therapie",src:"the therapy",pos:"noun",gender:"f",note:"From Greek 'therapeia' (healing).\nAll covered by Krankenkasse if prescribed by a doctor.",example:"A: Brauche ich eine Therapie?\nB: Ja, ich empfehle Physiotherapie.\nA: Wie oft pro Woche?\nB: Zweimal. Die Krankenkasse zahlt.",exampleSrc:"A: Do I need therapy?\nB: Yes, I recommend physiotherapy.\nA: How often per week?\nB: Twice. The health insurance pays.",funFact:"Germans love therapy: Physiotherapie, Psychotherapie, Ergotherapie. All covered by the Krankenkasse if your doctor prescribes them. The German system is thorough."},
{type:"teach",trg:"die Operation",src:"the operation, the surgery",pos:"noun",gender:"f",note:"From Latin. Abbreviated as 'OP' in hospitals.\nOP-Saal = operating room.",example:"A: War die Operation erfolgreich?\nB: Ja, alles ist gut gelaufen.\nA: Wie lange dauert die Erholung?\nB: Etwa zwei Wochen, sagt der Arzt.",exampleSrc:"A: Was the operation successful?\nB: Yes, everything went well.\nA: How long does the recovery take?\nB: About two weeks, says the doctor.",funFact:"Same word, borrowed from Latin. Abbreviated as 'OP' in German hospitals. 'Operiert werden' (to be operated on) uses passive voice. The OP-Saal (operating room) is where it happens."},
{type:"teach",trg:"die Klinik",src:"the clinic, the hospital",pos:"noun",gender:"f",note:"From Greek 'kline' (bed).\nLarger than a Praxis, smaller than a Universit\u00e4tsklinikum.",example:"A: In welcher Klinik waren Sie?\nB: In der Charit\u00e9. Die ist sehr bekannt.\nA: Waren die \u00c4rzte gut?\nB: Ausgezeichnet. Ich kann die Klinik empfehlen.",exampleSrc:"A: Which clinic were you at?\nB: At the Charit\u00e9. It is very well known.\nA: Were the doctors good?\nB: Excellent. I can recommend the clinic.",funFact:"A Klinik is a hospital or specialized medical center. Larger than a Praxis (doctor's office), smaller than a Universit\u00e4tsklinikum. Germans distinguish these carefully."},
{type:"teach",trg:"die Medizin",src:"the medicine, the field of medicine",pos:"noun",gender:"f",note:"Both the substance and the academic field.\n'Medizin studieren' AND 'Medizin nehmen.'",example:"A: Studierst du Medizin?\nB: Nein, ich nehme nur Medizin gegen Husten.\nA: Ach so! Das sind zwei verschiedene Bedeutungen.\nB: Genau. Kontext ist alles.",exampleSrc:"A: Do you study medicine?\nB: No, I only take medicine for a cough.\nA: Oh! Those are two different meanings.\nB: Exactly. Context is everything.",funFact:"One word, two meanings. 'Medizin studieren' (to study medicine) and 'Medizin nehmen' (to take medicine). From Latin 'medicina.' Context decides."},
{type:"teach",trg:"die Erk\u00e4ltung",src:"the cold (illness)",pos:"noun",gender:"f",note:"From 'kalt' (cold). Literally: a colding.\nThe most common reason Germans visit the Arzt.",example:"A: Ich habe eine schlimme Erk\u00e4ltung.\nB: Seit wann?\nA: Seit drei Tagen. Husten und Schnupfen.\nB: Bleib im Bett und trink viel Tee.",exampleSrc:"A: I have a bad cold.\nB: Since when?\nA: For three days. Cough and runny nose.\nB: Stay in bed and drink lots of tea.",funFact:"Germans believe cold weather causes colds. 'Sich erk\u00e4lten' (to catch a cold). This is the most common reason Germans visit the Arzt."},
{type:"teach",trg:"die Verletzung",src:"the injury",pos:"noun",gender:"f",note:"From verletzen (to injure).\nVer- + letzen (to damage). 'Schwere Verletzung' = serious injury.",example:"A: Was f\u00fcr eine Verletzung haben Sie?\nB: Ich habe eine Verletzung am Knie.\nA: Wie ist das passiert?\nB: Ich bin beim Joggen gest\u00fcrzt.",exampleSrc:"A: What kind of injury do you have?\nB: I have a knee injury.\nA: How did that happen?\nB: I fell while jogging.",funFact:"The Unfallversicherung (accident insurance) covers Verletzungen at work. From 'verletzen' (to injure): ver- intensifies, letzen means to damage."},
{type:"teach",trg:"der Notfall",src:"the emergency",pos:"noun",gender:"m",note:"Not (need/emergency) + Fall (case).\n'Im Notfall' = in an emergency. Leads to Notaufnahme, Notruf.",example:"A: Ist das ein Notfall?\nB: Ja, rufen Sie sofort die 112 an!\nA: Was soll ich sagen?\nB: Sagen Sie, wo Sie sind und was passiert ist.",exampleSrc:"A: Is this an emergency?\nB: Yes, call 112 immediately!\nA: What should I say?\nB: Say where you are and what happened.",funFact:"The most important compound for survival in Germany. One tiny word 'Not' spawns Notfall, Notaufnahme, Notarzt, Notruf, Notausgang. Learn Not, unlock five words."},
{type:"teach",trg:"die Notaufnahme",src:"the emergency room",pos:"noun",gender:"f",note:"Not (emergency) + Aufnahme (intake/admission).\nOpen 24/7. Bring your Versichertenkarte.",example:"A: Wo ist die Notaufnahme?\nB: Im Erdgeschoss, links um die Ecke.\nA: Muss ich lange warten?\nB: Das h\u00e4ngt davon ab, wie voll es ist.",exampleSrc:"A: Where is the emergency room?\nB: On the ground floor, left around the corner.\nA: Do I have to wait long?\nB: That depends on how busy it is.",funFact:"The emergency room. Where you go when it is a Notfall. Open 24/7. Bring your Versichertenkarte. Without it, you still get treated but the paperwork gets complicated."},
{type:"teach",trg:"der Notruf",src:"the emergency call",pos:"noun",gender:"m",note:"Not (emergency) + Ruf (call).\n112 in all of Europe, free from any phone.",example:"A: Kennst du den Notruf?\nB: Ja, 112 f\u00fcr Krankenwagen und Feuerwehr.\nA: Und die Polizei?\nB: Die Polizei hat die 110.",exampleSrc:"A: Do you know the emergency number?\nB: Yes, 112 for ambulance and fire department.\nA: And the police?\nB: The police have 110.",funFact:"112 works in all of Europe. Free from any phone, even without a SIM card. 'Den Notruf w\u00e4hlen' (to dial the emergency number). The most important number to memorize in Germany."},
{type:"teach",trg:"versichern",src:"to insure, to assure",pos:"verb",gender:null,note:"Ver- + sicher (safe/sure).\nReflexive for insurance, transitive for assurance.",example:"A: Bist du krankenversichert?\nB: Ja, ich habe mich bei der TK versichert.\nA: Ich versichere dir, das ist eine gute Wahl.\nB: Danke f\u00fcr den Tipp!",exampleSrc:"A: Do you have health insurance?\nB: Yes, I insured myself with TK.\nA: I assure you, that is a good choice.\nB: Thanks for the tip!",funFact:"'Sich versichern' (to get insured). 'Ich versichere Ihnen...' (I assure you...). Reflexive for insurance, transitive for assurance. One verb, two very different uses."},
{type:"teach",trg:"behandeln",src:"to treat (medically), to handle",pos:"verb",gender:null,note:"Be- + handeln (to act). To act upon something.\n'Der Arzt behandelt den Patienten.'",example:"A: Wer hat Sie behandelt?\nB: Doktor M\u00fcller hat mich behandelt.\nA: Wie war die Behandlung?\nB: Sehr professionell. Ich bin zufrieden.",exampleSrc:"A: Who treated you?\nB: Doctor M\u00fcller treated me.\nA: How was the treatment?\nB: Very professional. I am satisfied.",funFact:"To act upon something with your hands. 'Der Arzt behandelt den Patienten' (The doctor treats the patient). Also used for topics: 'Das Buch behandelt die Geschichte.' Handle and treat in one verb."},
{type:"teach",trg:"finanziell",src:"financial",pos:"adj",gender:null,note:"From French 'financiel.'\nThe -iell ending marks French-origin adjectives.",example:"A: Hast du finanzielle Probleme?\nB: Nein, aber die Versicherung ist teuer.\nA: Finanzielle Planung ist wichtig.\nB: Da hast du recht.",exampleSrc:"A: Do you have financial problems?\nB: No, but the insurance is expensive.\nA: Financial planning is important.\nB: You are right about that.",funFact:"The -iell ending marks French-origin adjectives in German. 'Finanzielle Probleme' (financial problems) is why Verumius stares at his Krankenkasse letters with despair."},
{type:"story",speaker:"narrator",mood:"comedic-despair",art:"de-ber-kitchen-papers",trg:"Die Briefe, \u00fcber die Verumius sich beschwert, sind alle auf Beamtendeutsch geschrieben. Das ist die Sprache, in der Formulare leben und Hoffnung stirbt.",src:"The letters Verumius complains about are all written in bureaucratic German. That is the language in which forms live and hope dies."},
{type:"mc",q:"Verumius hat eine schlimme Erk\u00e4ltung. Welches deutsche Wort beschreibt das?",opts:["Verletzung","Erk\u00e4ltung","Therapie","Operation"],ans:"Erk\u00e4ltung",hint:"This word comes from 'kalt' (cold) and describes a common illness."},
{type:"fb",s:"Im {1} ruft man die Nummer 112 an.",a:["Notfall"],opts:["Notfall","Notruf","Klinik","Kosten"],hint:"Which compound word means an emergency case?",sSrc:"In an emergency, you call the number 112."},
{type:"match",pairs:[{trg:"Versicherung",src:"insurance"},{trg:"Untersuchung",src:"examination"},{trg:"Notaufnahme",src:"emergency room"},{trg:"Krankenwagen",src:"ambulance"}]}
]},

// ═══════════════════════════════════════════════════════════════
// Lesson 2: "K\u00f6rpervokabular" — Vocab teach (20 words, 24 steps)
// Pure vocabulary: body parts, symptoms, sensations
// ═══════════════════════════════════════════════════════════════
{id:"deu_r20l2",title:"K\u00f6rpervokabular",icon:"🦴",xp:15,board:true,steps:[
{type:"intro",title:"K\u00f6rpervokabular",desc:"K\u00f6rperteile, Symptome und k\u00f6rperliche Empfindungen. Alles, was du brauchst, um dem Arzt deine Probleme zu erkl\u00e4ren.",goals:["Lerne K\u00f6rperteile auf Deutsch","Meistere W\u00f6rter f\u00fcr Symptome und Empfindungen","Beschreibe Gesundheitsprobleme auf Deutsch"]},
{type:"teach",trg:"die Brust",src:"the chest, the breast",pos:"noun",gender:"f",note:"From Proto-Germanic *brustiz.\n'Brustschmerzen' = chest pains. Tell the Notarzt this one.",example:"A: Wo haben Sie Schmerzen?\nB: In der Brust. Es tut beim Atmen weh.\nA: Seit wann?\nB: Seit heute Morgen.",exampleSrc:"A: Where do you have pain?\nB: In the chest. It hurts when breathing.\nA: Since when?\nB: Since this morning.",funFact:"Cognate with English 'breast.' 'Brustschmerzen' (chest pains) is what you tell the Notarzt. Die Brust covers the entire chest area in medical German."},
{type:"teach",trg:"die Schulter",src:"the shoulder",pos:"noun",gender:"f",note:"Cognate with English 'shoulder.'\n'Die kalte Schulter zeigen' = to give the cold shoulder.",example:"A: Meine Schulter tut weh.\nB: Die linke oder die rechte?\nA: Die rechte Schulter.\nB: Bewegen Sie den Arm mal nach oben.",exampleSrc:"A: My shoulder hurts.\nB: The left or the right one?\nA: The right shoulder.\nB: Move your arm upward.",funFact:"'Die kalte Schulter zeigen' (to give the cold shoulder) exists in German too. Same idiom, same body part, same meaning across both languages."},
{type:"teach",trg:"das Knie",src:"the knee",pos:"noun",gender:"n",note:"Neuter. Pronounced with a spoken K.\nUnlike English, the K is NOT silent in German.",example:"A: Tut das Knie noch weh?\nB: Ja, besonders beim Treppensteigen.\nA: Legen Sie K\u00fchlpacks auf das Knie.\nB: Wie oft am Tag?",exampleSrc:"A: Does the knee still hurt?\nB: Yes, especially when climbing stairs.\nA: Put ice packs on the knee.\nB: How often per day?",funFact:"Pronounced 'k-nee' with a spoken K, unlike English where the K is silent. From Proto-Germanic *knewa-. Same root, different pronunciation fate."},
{type:"teach",trg:"der Finger",src:"the finger",pos:"noun",gender:"m",note:"Identical spelling to English.\nFrom Proto-Germanic *fingraz.",example:"A: Was ist mit deinem Finger passiert?\nB: Ich habe ihn in der T\u00fcr eingeklemmt.\nA: Ist er gebrochen?\nB: Nein, nur gequetscht.",exampleSrc:"A: What happened to your finger?\nB: I caught it in the door.\nA: Is it broken?\nB: No, just bruised.",funFact:"Identical in spelling, nearly identical in pronunciation. 'Keinen Finger r\u00fchren' (to not lift a finger) works in both languages too."},
{type:"teach",trg:"der Muskel",src:"the muscle",pos:"noun",gender:"m",note:"From Latin 'musculus' (little mouse).\nFlexing a muscle looks like a mouse under the skin.",example:"A: Mir tut jeder Muskel weh.\nB: Warst du im Fitnessstudio?\nA: Ja, ich habe zu viel trainiert.\nB: Muskelkater! Das geht in zwei Tagen weg.",exampleSrc:"A: Every muscle hurts.\nB: Were you at the gym?\nA: Yes, I trained too much.\nB: Muscle soreness! That goes away in two days.",funFact:"From Latin 'musculus' (little mouse). Flexing a muscle looks like a mouse running under the skin. Germans kept the Latin word, English shortened it."},
{type:"teach",trg:"der Knochen",src:"the bone",pos:"noun",gender:"m",note:"'Knochenbruch' = bone fracture.\n'Bis auf die Knochen' = to the bone (thoroughly).",example:"A: Ist der Knochen gebrochen?\nB: Nein, nur ein Riss.\nA: Wie lange dauert die Heilung?\nB: Etwa sechs Wochen f\u00fcr den Knochen.",exampleSrc:"A: Is the bone broken?\nB: No, just a crack.\nA: How long does healing take?\nB: About six weeks for the bone.",funFact:"'Knochenbruch' (bone fracture) is a compound you can now decode: Knochen + Bruch (break). 'Bis auf die Knochen' (to the bone) means thoroughly."},
{type:"teach",trg:"die Nase",src:"the nose",pos:"noun",gender:"f",note:"Cognate with English 'nose.'\n'Die Nase voll haben' = to be fed up.",example:"A: Meine Nase l\u00e4uft die ganze Zeit.\nB: Hast du Schnupfen?\nA: Ja, seit gestern. Und ich kann nichts riechen.\nB: Nimm Nasentropfen.",exampleSrc:"A: My nose is running all the time.\nB: Do you have a cold?\nA: Yes, since yesterday. And I cannot smell anything.\nB: Take nose drops.",funFact:"'Die Nase voll haben' (to have a full nose) means to be fed up. Also: 'Schnupfen' is a stuffy nose. Germans have a word for every nasal condition."},
{type:"teach",trg:"die Lippe",src:"the lip",pos:"noun",gender:"f",note:"Cognate with English 'lip.'\n'Lippenbekenntnis' = lip service (false promise).",example:"A: Meine Lippen sind total trocken.\nB: Hier, nimm diesen Lippenbalsam.\nA: Danke! Trockene Lippen im Winter sind nervig.\nB: Ja, besonders bei K\u00e4lte.",exampleSrc:"A: My lips are totally dry.\nB: Here, take this lip balm.\nA: Thanks! Dry lips in winter are annoying.\nB: Yes, especially in the cold.",funFact:"'Lippenbekenntnis' (lip confession) means lip service. Germans say it when someone promises something but does not mean it. The lips move but the heart stays still."},
{type:"teach",trg:"die Haut",src:"the skin",pos:"noun",gender:"f",note:"Cognate with English 'hide' (animal skin).\n'Hautarzt' = dermatologist.",example:"A: Meine Haut ist ganz rot.\nB: Haben Sie eine Allergie?\nA: Vielleicht. Es juckt auch.\nB: Gehen Sie zum Hautarzt.",exampleSrc:"A: My skin is completely red.\nB: Do you have an allergy?\nA: Maybe. It also itches.\nB: Go to the dermatologist.",funFact:"Cognate with English 'hide' (animal skin). 'Aus der Haut fahren' (to drive out of one's skin) means to lose one's temper. 'Hautarzt' = dermatologist."},
{type:"teach",trg:"der Atem",src:"the breath",pos:"noun",gender:"m",note:"'Atem holen' = to catch one's breath.\n'Atemlos' = breathless.",example:"A: Mir fehlt der Atem.\nB: Setzen Sie sich hin und atmen Sie tief.\nA: Ich bekomme kaum Atem.\nB: Wir rufen einen Arzt.",exampleSrc:"A: I cannot catch my breath.\nB: Sit down and breathe deeply.\nA: I can barely get air.\nB: We will call a doctor.",funFact:"Sanskrit 'atman' (breath/soul) is a distant cousin. Your breath, your spirit, your life force. All one ancient root. 'Atemlos' (breathless) works literally and figuratively."},
{type:"teach",trg:"atmen",src:"to breathe",pos:"verb",gender:null,note:"From Atem. Regular verb.\n'Tief atmen' = to breathe deeply.",example:"A: Atmen Sie tief ein.\nB: So?\nA: Ja, und jetzt langsam ausatmen.\nB: Okay. Einatmen, ausatmen.",exampleSrc:"A: Breathe in deeply.\nB: Like this?\nA: Yes, and now breathe out slowly.\nB: Okay. Breathe in, breathe out.",funFact:"The doctor says 'Atmen Sie tief ein' (Breathe in deeply) during every Untersuchung. Einatmen (breathe in), ausatmen (breathe out). German splits breathing into directions."},
{type:"teach",trg:"bluten",src:"to bleed",pos:"verb",gender:null,note:"From 'Blut' (blood). Regular verb.\nCognate with English 'bleed/blood.'",example:"A: Die Wunde blutet stark!\nB: Dr\u00fccken Sie ein Tuch darauf.\nA: Wie lange soll ich dr\u00fccken?\nB: Bis es aufh\u00f6rt zu bluten.",exampleSrc:"A: The wound is bleeding heavily!\nB: Press a cloth onto it.\nA: How long should I press?\nB: Until it stops bleeding.",funFact:"Cognate with English 'bleed/blood.' 'Mein Herz blutet' (My heart bleeds) for emotional pain works in German too."},
{type:"teach",trg:"brechen",src:"to break",pos:"verb",gender:null,note:"Irregular: bricht, brach, gebrochen.\nAlso: 'erbrechen' = to vomit (to break out).",example:"A: Ich glaube, ich habe mir den Arm gebrochen.\nB: K\u00f6nnen Sie den Arm bewegen?\nA: Nein, es tut furchtbar weh.\nB: Wir m\u00fcssen r\u00f6ntgen.",exampleSrc:"A: I think I broke my arm.\nB: Can you move the arm?\nA: No, it hurts terribly.\nB: We need to take an X-ray.",funFact:"Cognate with English 'break.' 'Sich den Arm brechen' (to break one's arm). Also: 'erbrechen' = to vomit (to break out). A versatile verb."},
{type:"teach",trg:"messen",src:"to measure",pos:"verb",gender:null,note:"Irregular: misst, ma\u00df, gemessen.\n'Fieber messen' = to take a temperature.",example:"A: Wir m\u00fcssen Ihren Blutdruck messen.\nB: Ist der zu hoch?\nA: Mal sehen. Bitte den Arm ausstrecken.\nB: So? Wie hoch ist er?",exampleSrc:"A: We need to measure your blood pressure.\nB: Is it too high?\nA: Let's see. Please extend your arm.\nB: Like this? How high is it?",funFact:"'Fieber messen' (to take a temperature). 'Blutdruck messen' (to measure blood pressure). From the same root as English 'measure' via Latin."},
{type:"teach",trg:"sp\u00fcren",src:"to feel, to sense",pos:"verb",gender:null,note:"Physical sensation, not emotional.\nDifferent from 'f\u00fchlen' (emotional feeling).",example:"A: Sp\u00fcren Sie den Schmerz hier?\nB: Ja, ich sp\u00fcre einen stechenden Schmerz.\nA: Und hier?\nB: Nein, da sp\u00fcre ich nichts.",exampleSrc:"A: Do you feel the pain here?\nB: Yes, I feel a stabbing pain.\nA: And here?\nB: No, I do not feel anything there.",funFact:"Different from 'f\u00fchlen' (emotional feeling). Sp\u00fcren is physical sensation. The Spur (trace/track) is related: what you can physically detect."},
{type:"teach",trg:"schwitzen",src:"to sweat",pos:"verb",gender:null,note:"Regular verb. From 'Schwei\u00df' (sweat).\n'Ins Schwitzen kommen' = to start sweating.",example:"A: Warum schwitzen Sie so?\nB: Ich habe Fieber und schwitze die ganze Nacht.\nA: Trinken Sie viel Wasser.\nB: Ja, das mache ich.",exampleSrc:"A: Why are you sweating so much?\nB: I have a fever and sweat all night.\nA: Drink lots of water.\nB: Yes, I am doing that.",funFact:"Germans love their saunas, where schwitzen is the whole point. 'Ins Schwitzen kommen' (to start sweating) also means getting nervous about something."},
{type:"teach",trg:"frieren",src:"to freeze, to be cold",pos:"verb",gender:null,note:"Irregular: fror, gefroren.\n'Mich friert' or 'Ich friere' both mean 'I am cold.'",example:"A: Frierst du?\nB: Ja, mir ist eiskalt.\nA: Hier, nimm meine Jacke.\nB: Danke! Ich friere seit einer Stunde.",exampleSrc:"A: Are you cold?\nB: Yes, I am freezing.\nA: Here, take my jacket.\nB: Thanks! I have been freezing for an hour.",funFact:"Cognate with English 'freeze.' The impersonal 'Mich friert' is older and more formal. 'Ich friere' is the everyday version. Both are correct."},
{type:"teach",trg:"ersch\u00f6pft",src:"exhausted",pos:"adj",gender:null,note:"From 'ersch\u00f6pfen' (to exhaust).\nStronger than 'm\u00fcde' (tired). Drained out.",example:"A: Du siehst ersch\u00f6pft aus.\nB: Ich bin total ersch\u00f6pft. Die ganze Woche war stressig.\nA: Du solltest dich ausruhen.\nB: Ja, ich lege mich gleich hin.",exampleSrc:"A: You look exhausted.\nB: I am totally exhausted. The whole week was stressful.\nA: You should rest.\nB: Yes, I will lie down right away.",funFact:"Literally 'drained out' (the Sch\u00f6pf- root relates to scooping/drawing water). Stronger than 'm\u00fcde' (tired). When m\u00fcde is not enough, you are ersch\u00f6pft."},
{type:"teach",trg:"blass",src:"pale",pos:"adj",gender:null,note:"'Blass werden' = to turn pale.\n'Blass vor Neid' = pale with envy.",example:"A: Du bist ganz blass. Geht es dir gut?\nB: Ich f\u00fchle mich nicht so gut.\nA: Setz dich hin. Du siehst wirklich blass aus.\nB: Ja, mir ist auch schwindelig.",exampleSrc:"A: You are very pale. Are you alright?\nB: I do not feel so well.\nA: Sit down. You really look pale.\nB: Yes, I also feel dizzy.",funFact:"Cognate with English 'blaze' through a surprising twist: original meaning was 'shining/white.' The paleness of bright light became the paleness of illness."},
{type:"teach",trg:"k\u00f6rperlich",src:"physical, bodily",pos:"adj",gender:null,note:"From 'K\u00f6rper' (body) + -lich.\n'K\u00f6rperliche Arbeit' = physical labor.",example:"A: Machen Sie k\u00f6rperliche Arbeit?\nB: Ja, ich arbeite auf einer Baustelle.\nA: Haben Sie k\u00f6rperliche Beschwerden?\nB: Ja, R\u00fcckenschmerzen und M\u00fcdigkeit.",exampleSrc:"A: Do you do physical work?\nB: Yes, I work at a construction site.\nA: Do you have physical complaints?\nB: Yes, back pain and fatigue.",funFact:"The -lich ending turns nouns into adjectives. 'K\u00f6rperlich und geistig' (physically and mentally) is a common pair in German medical contexts."},
{type:"mc",q:"Der Arzt bittet dich, den Arm zu heben. Aber zuerst: Wie hei\u00dft das Gelenk zwischen Ober- und Unterschenkel?",opts:["Schulter","Finger","Knie","Brust"],ans:"Knie",hint:"This joint bends when you sit. In German, the K is pronounced."},
{type:"fb",s:"Der Patient ist sehr {1}. Er hat kein Blut mehr im Gesicht.",a:["blass"],opts:["blass","ersch\u00f6pft","k\u00f6rperlich","finanziell"],hint:"Which adjective describes someone who has lost color in their face?",sSrc:"The patient is very pale. He has no more blood in his face."},
{type:"match",pairs:[{trg:"atmen",src:"to breathe"},{trg:"bluten",src:"to bleed"},{trg:"frieren",src:"to freeze"},{trg:"schwitzen",src:"to sweat"}]}
]},

// ═══════════════════════════════════════════════════════════════
// Lesson 3: "KD im Caf\u00e9" — Story dev + grammar (18 words, 22 steps)
// Scene 2: KD off-duty at cafe, relative clauses + prepositions
// ═══════════════════════════════════════════════════════════════
{id:"deu_r20l3",title:"KD im Caf\u00e9",icon:"☕",xp:15,board:true,steps:[
{type:"intro",title:"KD im Caf\u00e9",desc:"KD sitzt in Jeans und Pullover im Caf\u00e9. Er liest die Versicherungsbriefe wie Kinderb\u00fccher. Heute lernst du Finanz- und Zahlungsvokabeln.",goals:["Lerne Finanz- und Zahlungsvokabeln","Verstehe Relativs\u00e4tze mit Pr\u00e4positionen","Erlebe KD als Mensch, nicht nur als Beamter"]},
{type:"story",speaker:"KD",mood:"warm",art:"de-ber-cafe-kd",trg:"Also, zeig mal her. Die Briefe, \u00fcber die du dich beschwerst, sind eigentlich ganz einfach. Das ist nur Beamtendeutsch.",src:"Alright, let me see. The letters you are complaining about are actually quite simple. That is just bureaucratic German."},
{type:"teach",trg:"die Versichertenkarte",src:"the health insurance card",pos:"noun",gender:"f",note:"Versicherte (insured person) + Karte (card).\nBring it to every doctor visit.",example:"A: Haben Sie Ihre Versichertenkarte dabei?\nB: Ja, hier bitte.\nA: Danke. Bitte im Wartezimmer Platz nehmen.\nB: Wie lange muss ich warten?",exampleSrc:"A: Do you have your insurance card with you?\nB: Yes, here you go.\nA: Thank you. Please take a seat in the waiting room.\nB: How long do I have to wait?",funFact:"Your health insurance card. Without it, you pay upfront. The electronic Gesundheitskarte replaced the old paper version in 2015. Always carry it."},
{type:"teach",trg:"die Zahlung",src:"the payment",pos:"noun",gender:"f",note:"From 'zahlen' (to pay) + -ung.\n'Monatliche Zahlung' = monthly payment.",example:"A: Die Zahlung ist f\u00e4llig.\nB: Wann muss ich bezahlen?\nA: Bis zum 15. des Monats.\nB: Kann ich per \u00dcberweisung zahlen?",exampleSrc:"A: The payment is due.\nB: When do I have to pay?\nA: By the 15th of the month.\nB: Can I pay by bank transfer?",funFact:"'Zahlungserinnerung' (payment reminder) is the polite version of a Mahnung. The -ung suffix creates the noun from the verb. Standard German word-building."},
{type:"teach",trg:"die Mahnung",src:"the payment reminder, the warning",pos:"noun",gender:"f",note:"From 'mahnen' (to warn/remind).\nThree levels: polite, firm, legal action.",example:"A: Ich habe eine Mahnung bekommen!\nB: Die erste oder die zweite?\nA: Die zweite.\nB: Dann musst du schnell bezahlen.",exampleSrc:"A: I received a payment reminder!\nB: The first or the second one?\nA: The second one.\nB: Then you need to pay quickly.",funFact:"The first Mahnung is polite. The second is firm. The third threatens legal action. Germans take Mahnungen extremely seriously. Do not ignore them."},
{type:"teach",trg:"die Ausgabe",src:"the expenditure, the expense",pos:"noun",gender:"f",note:"Aus (out) + Gabe (giving). Money going out.\nOpposite of Einnahme (income).",example:"A: Wie hoch sind deine monatlichen Ausgaben?\nB: Etwa 1500 Euro.\nA: Das sind hohe Ausgaben.\nB: Ja, die Miete allein kostet 800 Euro.",exampleSrc:"A: How high are your monthly expenses?\nB: About 1500 euros.\nA: Those are high expenses.\nB: Yes, the rent alone costs 800 euros.",funFact:"Money going out. The opposite of Einnahme (income). Also means 'edition' (Ausgabe eines Buchs). Context decides whether it is money or books."},
{type:"teach",trg:"die Erh\u00f6hung",src:"the increase, the raise",pos:"noun",gender:"f",note:"From 'erh\u00f6hen' (to increase/raise).\nCompound with everything: Beitrags-, Miet-, Lohnerh\u00f6hung.",example:"A: Es gibt eine Beitragserh\u00f6hung.\nB: Schon wieder? Um wie viel?\nA: Um 0,5 Prozent.\nB: Das ist doch eine kleine Erh\u00f6hung.",exampleSrc:"A: There is a premium increase.\nB: Again? By how much?\nA: By 0.5 percent.\nB: That is just a small increase.",funFact:"Germans compound Erh\u00f6hung with everything that costs money. Beitragserh\u00f6hung (premium increase), Mieterh\u00f6hung (rent increase), Lohnerh\u00f6hung (pay raise). The word that never stops compounding."},
{type:"teach",trg:"die Summe",src:"the sum, the total",pos:"noun",gender:"f",note:"From Latin 'summa.' International, mathematical.\n'In Summe' = in total.",example:"A: Wie hoch ist die Summe?\nB: Die Summe betr\u00e4gt 3.500 Euro.\nA: Das ist eine hohe Summe.\nB: Ja, aber sie beinhaltet alles.",exampleSrc:"A: How high is the total?\nB: The total amounts to 3,500 euros.\nA: That is a large sum.\nB: Yes, but it includes everything.",funFact:"From Latin 'summa.' Simple, international, mathematical. Even the Romans did their Summen. 'In Summe' (in total) works in business and everyday speech."},
{type:"teach",trg:"die Steuer",src:"the tax",pos:"noun",gender:"f",note:"'Einkommensteuer' = income tax.\n'Mehrwertsteuer' = VAT. Germany's tax system is famously complex.",example:"A: Wie viel Steuer zahlst du?\nB: Viel zu viel! Fast 40 Prozent.\nA: Die Steuer in Deutschland ist hoch.\nB: Ja, aber daf\u00fcr funktioniert das System.",exampleSrc:"A: How much tax do you pay?\nB: Way too much! Almost 40 percent.\nA: The tax in Germany is high.\nB: Yes, but the system works because of it.",funFact:"From Old High German 'stiura' (support/contribution). 'Steuererkl\u00e4rung' (tax return) is an annual ritual. Germany's tax system is famously complex."},
{type:"teach",trg:"der Lohn",src:"the wage, the salary",pos:"noun",gender:"m",note:"'Mindestlohn' = minimum wage.\nDifferent from 'Gehalt' (monthly salary, white-collar).",example:"A: Wie hoch ist der Mindestlohn?\nB: 12,41 Euro pro Stunde.\nA: Reicht der Lohn zum Leben?\nB: In Berlin ist es knapp.",exampleSrc:"A: How high is the minimum wage?\nB: 12.41 euros per hour.\nA: Is the wage enough to live on?\nB: In Berlin it is tight.",funFact:"Different from 'Gehalt' (monthly salary for white-collar workers). Lohn is traditionally for hourly/manual work. The distinction is fading in modern German."},
{type:"teach",trg:"berechnen",src:"to calculate, to charge",pos:"verb",gender:null,note:"Be- + rechnen (to calculate).\nCalculation and billing in one verb.",example:"A: K\u00f6nnen Sie die Kosten berechnen?\nB: Ja, ich berechne alles f\u00fcr Sie.\nA: Was berechnen Sie f\u00fcr die Untersuchung?\nB: Das berechnen wir \u00fcber die Krankenkasse.",exampleSrc:"A: Can you calculate the costs?\nB: Yes, I will calculate everything for you.\nA: What do you charge for the examination?\nB: We charge that through the health insurance.",funFact:"'Die Kosten berechnen' (to calculate the costs). Also: 'Dem Kunden etwas berechnen' (to charge the customer for something). Calculation and billing in one verb."},
{type:"teach",trg:"finanzieren",src:"to finance",pos:"verb",gender:null,note:"From French 'financer.' The -ieren ending = borrowed verb.\nRegular, predictable, international.",example:"A: Wie finanzierst du dein Studium?\nB: Meine Eltern finanzieren es teilweise.\nA: Und den Rest?\nB: Den finanziere ich mit einem Nebenjob.",exampleSrc:"A: How do you finance your studies?\nB: My parents finance it partly.\nA: And the rest?\nB: I finance that with a part-time job.",funFact:"The -ieren ending marks it as a borrowed verb. Regular, predictable, international. 'Wie finanzierst du das?' (How do you finance that?) is a common German question."},
{type:"teach",trg:"die Einnahme",src:"the income, the revenue",pos:"noun",gender:"f",note:"Ein (in) + Nahme (taking). Money coming in.\nAlso: 'Einnahme von Medizin' = taking medicine.",example:"A: Wie sind Ihre monatlichen Einnahmen?\nB: Meine Einnahmen betragen 2.500 Euro netto.\nA: Und die Ausgaben?\nB: Etwa 1.800 Euro.",exampleSrc:"A: What is your monthly income?\nB: My income is 2,500 euros net.\nA: And the expenses?\nB: About 1,800 euros.",funFact:"The opposite of Ausgabe. Money coming in, medicine going in. 'Einnahme von Medizin' = taking medicine. Same word for money and medicine intake."},
{type:"teach",trg:"der Einkauf",src:"the purchase, the shopping",pos:"noun",gender:"m",note:"Ein (in) + Kauf (purchase).\n'Eink\u00e4ufe machen' = to do shopping.",example:"A: Ich muss noch Eink\u00e4ufe machen.\nB: Was brauchst du?\nA: Nur den t\u00e4glichen Einkauf. Brot, Milch, Gem\u00fcse.\nB: Soll ich mitkommen?",exampleSrc:"A: I still need to do shopping.\nB: What do you need?\nA: Just the daily shopping. Bread, milk, vegetables.\nB: Should I come along?",funFact:"The Einkaufswagen (shopping cart) is where German compounds shine. Ein (in) + Kauf (purchase) + Wagen (cart). Three words, one object."},
{type:"teach",trg:"der Kauf",src:"the purchase",pos:"noun",gender:"m",note:"From 'kaufen' (to buy).\n'Kaufvertrag' = purchase contract. Short, sharp, commercial.",example:"A: War das ein guter Kauf?\nB: Ja, ein sehr guter Kauf.\nA: Wie viel hast du bezahlt?\nB: Nur 50 Euro. Ein echtes Schn\u00e4ppchen.",exampleSrc:"A: Was that a good purchase?\nB: Yes, a very good purchase.\nA: How much did you pay?\nB: Only 50 euros. A real bargain.",funFact:"Short, sharp, commercial. 'Ein guter Kauf' (a good buy). 'Kaufvertrag' (purchase contract). Every transaction is a Kauf."},
{type:"teach",trg:"der Gewinn",src:"the profit, the winnings",pos:"noun",gender:"m",note:"From 'gewinnen' (to win).\n'Gewinn machen' = to make a profit.",example:"A: Hat die Firma Gewinn gemacht?\nB: Ja, der Gewinn war h\u00f6her als letztes Jahr.\nA: Wie hoch war der Gewinn?\nB: Fast eine Million Euro.",exampleSrc:"A: Did the company make a profit?\nB: Yes, the profit was higher than last year.\nA: How high was the profit?\nB: Almost one million euros.",funFact:"The Ge- prefix plus -nn creates the noun from the verb. 'Lottogewinn' (lottery winnings). Standard German word-formation pattern."},
{type:"teach",trg:"niedrig",src:"low",pos:"adj",gender:null,note:"From 'nieder' (down).\n'Niedrig' for measurable things, 'tief' for depth and emotion.",example:"A: Die Kosten sind relativ niedrig.\nB: Wirklich? Wie niedrig?\nA: Nur 150 Euro pro Monat.\nB: Das ist tats\u00e4chlich niedrig.",exampleSrc:"A: The costs are relatively low.\nB: Really? How low?\nA: Only 150 euros per month.\nB: That is indeed low.",funFact:"'Niedrig' for measurable things (costs, blood pressure, temperature), 'tief' for depth and emotion. From 'nieder' (down). Two words for 'low' with different domains."},
{type:"teach",trg:"gering",src:"small, slight, minor",pos:"adj",gender:null,note:"More formal than 'niedrig.'\n'Nicht im Geringsten' = not in the slightest.",example:"A: Sind die Risiken gering?\nB: Ja, nur ein geringes Risiko.\nA: Dann mache ich es.\nB: Die Kosten sind auch gering.",exampleSrc:"A: Are the risks minor?\nB: Yes, only a minor risk.\nA: Then I will do it.\nB: The costs are also minor.",funFact:"More formal than 'niedrig.' Used for quantities and importance, not physical size. 'Nicht im Geringsten' (not in the slightest) is a useful intensifier."},
{type:"teach",trg:"knapp",src:"tight, scarce, barely",pos:"adj",gender:null,note:"'Knapp bei Kasse' = tight on money.\n'Knapp gewonnen' = barely won.",example:"A: Hast du genug Geld?\nB: Es ist knapp. Sehr knapp.\nA: Reicht es f\u00fcr die Versicherung?\nB: Gerade so. Knapp, aber es reicht.",exampleSrc:"A: Do you have enough money?\nB: It is tight. Very tight.\nA: Is it enough for the insurance?\nB: Just barely. Tight, but it is enough.",funFact:"A word that squeezes everything: time, money, space. If it is knapp, there is almost not enough. 'Knapp bei Kasse' (tight on money) is the student's motto."},
{type:"tip",title:"Relativs\u00e4tze mit Pr\u00e4positionen",text:"In German, prepositions stay with the relative pronoun. In English, you might say 'the letter I am complaining ABOUT.' In German, the preposition comes FIRST:\n\nDer Brief, \u00dcBER DEN ich mich beschwere.\n\nFormula: Noun, + PREPOSITION + RELATIVE PRONOUN + ... verb at end.\n\nThe relative pronoun matches:\n- Gender from the noun it refers to\n- Case from the preposition\n\nExamples:\n- Die Karte, MIT DER du zum Arzt gehst (mit + dative, die = feminine)\n- Der Brief, \u00dcBER DEN du dich beschwerst (\u00fcber + accusative, der = masculine)\n- Das Formular, AUF DAS ich warte (auf + accusative, das = neuter)",deepDive:{title:"How to build relative clauses with prepositions",text:"Step 1: Identify the preposition the verb needs (sich beschweren \u00dcBER, warten AUF, sich entscheiden F\u00dcR).\n\nStep 2: Determine the case the preposition requires (accusative or dative).\n\nStep 3: Match the relative pronoun to the gender of the noun AND the case from the preposition.\n\nDer Brief (\u00fcber + acc, masculine) = \u00fcber den\nDie Karte (mit + dat, feminine) = mit der\nDas Formular (auf + acc, neuter) = auf das\n\nThe verb always goes to the end of the relative clause."}},
{type:"mc",q:"KD sagt: 'Die Versicherung, bei der du versichert bist, ist gut.' Was bedeutet 'bei der'?",opts:["the doctor","the hospital","the insurance company","the card"],ans:"the insurance company",hint:"The relative pronoun 'der' is feminine dative, matching 'die Versicherung.'"},
{type:"fb",s:"Die monatliche {1} f\u00fcr die Versicherung betr\u00e4gt 200 Euro.",a:["Zahlung"],opts:["Zahlung","Mahnung","Ausgabe","Erh\u00f6hung"],hint:"Which noun specifically means a regular payment?",sSrc:"The monthly payment for the insurance amounts to 200 euros."}
]},

// ═══════════════════════════════════════════════════════════════
// Lesson 4: "Die Grammatik der B\u00fcrokratie" — Grammar (18 words, 24 steps)
// Grammar: #11 Relative clauses + prepositions, #33 Adverbial conjunctions
// ═══════════════════════════════════════════════════════════════
{id:"deu_r20l4",title:"Die Grammatik der B\u00fcrokratie",icon:"📐",xp:15,board:true,steps:[
{type:"intro",title:"Die Grammatik der B\u00fcrokratie",desc:"Zwei wichtige Grammatikstrukturen: Relativs\u00e4tze mit Pr\u00e4positionen und Adverbialkonjunktionen. Medizinvokabeln verbinden beides.",goals:["Meistere Relativs\u00e4tze mit Pr\u00e4positionen","Lerne Adverbialkonjunktionen: deshalb, trotzdem, deswegen, also, sonst","Verbinde Medizinvokabeln mit Grammatikstrukturen"]},
{type:"teach",trg:"das Pflaster",src:"the bandage, the plaster",pos:"noun",gender:"n",note:"From Latin 'emplastrum.'\nAlso means 'pavement' (Kopfsteinpflaster = cobblestone).",example:"A: Hast du ein Pflaster?\nB: Ja, hier. Gro\u00df oder klein?\nA: Ein gro\u00dfes Pflaster bitte.\nB: Hier, kleb es auf die Wunde.",exampleSrc:"A: Do you have a bandage?\nB: Yes, here. Large or small?\nA: A large bandage please.\nB: Here, stick it on the wound.",funFact:"From Latin 'emplastrum.' Also means 'pavement' (Kopfsteinpflaster = cobblestone). Two very different surfaces that share a word."},
{type:"teach",trg:"die Salbe",src:"the ointment, the salve",pos:"noun",gender:"f",note:"Cognate with English 'salve.'\nFrom Latin 'salvare' (to save/heal).",example:"A: Diese Salbe hilft gegen Schmerzen.\nB: Wie oft soll ich die Salbe auftragen?\nA: Zweimal am Tag.\nB: Morgens und abends?",exampleSrc:"A: This ointment helps against pain.\nB: How often should I apply the ointment?\nA: Twice a day.\nB: Morning and evening?",funFact:"Cognate with English 'salve.' From Latin 'salvare' (to save/heal). One of the oldest medicine words in Germanic languages. Apply to Haut for relief."},
{type:"teach",trg:"die Pille",src:"the pill",pos:"noun",gender:"f",note:"From Latin 'pilula' (little ball).\n'Die Pille' alone usually means the contraceptive pill.",example:"A: Nehmen Sie diese Pillen dreimal t\u00e4glich.\nB: Vor oder nach dem Essen?\nA: Nach dem Essen. Mit Wasser.\nB: Wie lange soll ich sie nehmen?",exampleSrc:"A: Take these pills three times daily.\nB: Before or after eating?\nA: After eating. With water.\nB: How long should I take them?",funFact:"'Die Pille' by itself usually means the contraceptive pill. For other pills: 'Tablette' or 'Pille gegen Kopfschmerzen.' Context-dependent social meaning."},
{type:"teach",trg:"die Spritze",src:"the injection, the syringe",pos:"noun",gender:"f",note:"From 'spritzen' (to spray/squirt).\n'Spritzenphobie' is a real diagnosis.",example:"A: Ich brauche eine Spritze gegen die Schmerzen.\nB: Haben Sie Angst vor Spritzen?\nA: Ein bisschen.\nB: Keine Sorge, es dauert nur eine Sekunde.",exampleSrc:"A: I need an injection for the pain.\nB: Are you afraid of injections?\nA: A little.\nB: Don't worry, it only takes a second.",funFact:"Germans fear the Spritze more than most medical procedures. 'Spritzenphobie' is a real diagnosis. From 'spritzen' (to spray/squirt)."},
{type:"teach",trg:"der Tropfen",src:"the drop",pos:"noun",gender:"m",note:"'Augentropfen' = eye drops, 'Nasentropfen' = nose drops.\nAlso the verb 'tropfen' (to drip).",example:"A: Nehmen Sie diese Tropfen dreimal am Tag.\nB: Wie viele Tropfen?\nA: Zehn Tropfen in ein Glas Wasser.\nB: Vor oder nach dem Essen?",exampleSrc:"A: Take these drops three times a day.\nB: How many drops?\nA: Ten drops in a glass of water.\nB: Before or after eating?",funFact:"'Ein Tropfen auf den hei\u00dfen Stein' (a drop on a hot stone) means a futile effort. The drop evaporates before it can help. A beautifully pessimistic idiom."},
{type:"teach",trg:"das Schmerzmittel",src:"the painkiller",pos:"noun",gender:"n",note:"Schmerz (pain) + Mittel (means/remedy).\nTransparent compound: pain-means.",example:"A: Haben Sie ein Schmerzmittel?\nB: Ja, Ibuprofen oder Paracetamol?\nA: Was empfehlen Sie?\nB: Bei Kopfschmerzen: Ibuprofen.",exampleSrc:"A: Do you have a painkiller?\nB: Yes, ibuprofen or paracetamol?\nA: What do you recommend?\nB: For headaches: ibuprofen.",funFact:"German compounds are transparent: pain-means. You always know what you are swallowing. 'Schmerzmittel einnehmen' (to take painkillers)."},
{type:"teach",trg:"der Schnupfen",src:"the cold, the runny nose",pos:"noun",gender:"m",note:"From 'schnupfen' (to sniff).\nLess formal than Erk\u00e4ltung. Focuses on the nose.",example:"A: Hast du Schnupfen?\nB: Ja, meine Nase l\u00e4uft den ganzen Tag.\nA: Hier, nimm ein Taschentuch.\nB: Danke. Dieser Schnupfen geht nicht weg.",exampleSrc:"A: Do you have a cold?\nB: Yes, my nose is running all day.\nA: Here, take a tissue.\nB: Thanks. This cold won't go away.",funFact:"Schnupfen focuses on the nose; Erk\u00e4ltung is the whole-body cold. From 'schnupfen' (to sniff). Less formal, more specific."},
{type:"teach",trg:"der Husten",src:"the cough",pos:"noun",gender:"m",note:"Also the verb 'husten' (to cough).\n'Hustensirup' = cough syrup. Onomatopoeia.",example:"A: Wie lange haben Sie schon Husten?\nB: Seit einer Woche.\nA: Trockener Husten oder mit Schleim?\nB: Trockener Husten, besonders nachts.",exampleSrc:"A: How long have you had a cough?\nB: For a week.\nA: Dry cough or with mucus?\nB: Dry cough, especially at night.",funFact:"Onomatopoeia: the word sounds like a cough. Same root as English 'cough' before English changed its spelling. 'Hustensirup' (cough syrup) is a pharmacy staple."},
{type:"teach",trg:"die Infektion",src:"the infection",pos:"noun",gender:"f",note:"From Latin 'infectio.'\nThe -tion ending is always feminine, always stressed on the last syllable.",example:"A: Es ist eine bakterielle Infektion.\nB: Brauche ich Antibiotika?\nA: Ja, ich verschreibe Ihnen welche.\nB: Wie lange dauert die Infektion?",exampleSrc:"A: It is a bacterial infection.\nB: Do I need antibiotics?\nA: Yes, I will prescribe some.\nB: How long does the infection last?",funFact:"Identical in most European languages. The -tion ending is always feminine in German, always stressed on the last syllable. A reliable pattern."},
{type:"teach",trg:"das Virus",src:"the virus",pos:"noun",gender:"n",note:"From Latin 'virus' (poison).\nNeuter (das Virus), though some say 'der Virus.'",example:"A: Ist es ein Virus oder eine Infektion?\nB: Ein Virus. Antibiotika helfen nicht.\nA: Was soll ich tun?\nB: Ruhe, Fl\u00fcssigkeit und abwarten.",exampleSrc:"A: Is it a virus or an infection?\nB: A virus. Antibiotics won't help.\nA: What should I do?\nB: Rest, fluids, and wait it out.",funFact:"Neuter in German (das Virus), though some Germans say 'der Virus.' The Duden accepts both. Scientists insist on 'das.' A rare grammar debate in medicine."},
{type:"teach",trg:"verschreiben",src:"to prescribe",pos:"verb",gender:null,note:"Ver- + schreiben (to write). The doctor writes for you.\n'Sich verschreiben' = to make a writing mistake.",example:"A: Der Arzt hat mir Tropfen verschrieben.\nB: Gegen was?\nA: Gegen die Infektion.\nB: Gut, nimm sie regelm\u00e4\u00dfig ein.",exampleSrc:"A: The doctor prescribed me drops.\nB: For what?\nA: For the infection.\nB: Good, take them regularly.",funFact:"The doctor writes something for you. 'Sich verschreiben' means to make a writing mistake. The ver- prefix changes everything. One letter, two very different meanings."},
{type:"teach",trg:"einnehmen",src:"to take (medicine), to collect (money)",pos:"verb",gender:null,note:"Ein + nehmen. Separable prefix.\n'Nehmen Sie die Tabletten zweimal t\u00e4glich ein.'",example:"A: Wie soll ich die Medizin einnehmen?\nB: Zweimal t\u00e4glich, morgens und abends.\nA: Vor oder nach dem Essen?\nB: Nach dem Essen einnehmen.",exampleSrc:"A: How should I take the medicine?\nB: Twice daily, morning and evening.\nA: Before or after eating?\nB: Take it after eating.",funFact:"Separable: 'Nehmen Sie die Tabletten zweimal t\u00e4glich ein.' Also: 'Einnahmen' (revenue). Medicine intake and money intake share a verb."},
{type:"teach",trg:"operieren",src:"to operate (surgery)",pos:"verb",gender:null,note:"From Latin 'operari.' Regular: -ieren ending.\n'Am Knie operiert' = operated on the knee.",example:"A: Wir m\u00fcssen operieren.\nB: Ist die Operation gef\u00e4hrlich?\nA: Nein, ein Routineeingriff.\nB: Wann wird operiert?",exampleSrc:"A: We need to operate.\nB: Is the operation dangerous?\nA: No, a routine procedure.\nB: When will you operate?",funFact:"The -ieren ending makes it regular and predictable. 'Operiert werden' (to be operated on). A serious verb for a serious procedure."},
{type:"teach",trg:"die \u00c4rztin",src:"the doctor (female)",pos:"noun",gender:"f",note:"Feminine of Arzt. The -in suffix is standard.\nModern: '\u00c4rzt*in' for inclusive forms.",example:"A: Die \u00c4rztin kommt gleich.\nB: Welche \u00c4rztin?\nA: Frau Dr. Weber. Sie ist sehr gut.\nB: Gut, ich warte.",exampleSrc:"A: The doctor will be right with you.\nB: Which doctor?\nA: Dr. Weber. She is very good.\nB: Good, I will wait.",funFact:"The feminine of Arzt. In modern German, many institutions use '\u00c4rzt*in' to be inclusive. The -in suffix is the standard feminine marker for person nouns."},
{type:"teach",trg:"die Doktorin",src:"the doctor (female, title)",pos:"noun",gender:"f",note:"Feminine of Doktor.\n'Frau Doktor' is more common than 'Frau Doktorin.'",example:"A: Guten Tag, Frau Doktorin.\nB: Guten Tag. Was kann ich f\u00fcr Sie tun?\nA: Ich habe Bauchschmerzen.\nB: Seit wann?",exampleSrc:"A: Good day, Doctor.\nB: Good day. What can I do for you?\nA: I have a stomachache.\nB: Since when?",funFact:"'Frau Doktorin M\u00fcller' is extremely formal. Most people simply say 'Frau Doktor.' The -in is grammatically correct but socially optional with titles."},
{type:"teach",trg:"die Schwierigkeit",src:"the difficulty",pos:"noun",gender:"f",note:"From 'schwierig' (difficult) + -keit.\nAbstract noun from adjective.",example:"A: Haben Sie Schwierigkeiten mit dem Formular?\nB: Ja, ich verstehe Punkt 5 nicht.\nA: Das ist eine bekannte Schwierigkeit.\nB: Kann mir jemand helfen?",exampleSrc:"A: Do you have difficulties with the form?\nB: Yes, I do not understand point 5.\nA: That is a known difficulty.\nB: Can someone help me?",funFact:"The -keit suffix turns adjectives into abstract nouns. 'Finanzielle Schwierigkeiten' (financial difficulties). The insurance letters are full of Schwierigkeiten."},
{type:"teach",trg:"maximal",src:"maximum, at most",pos:"adj",gender:null,note:"From Latin 'maximus.'\n'Maximal zwei Tabletten pro Tag.'",example:"A: Wie viele Tabletten darf ich nehmen?\nB: Maximal drei pro Tag.\nA: Und wenn die Schmerzen schlimmer werden?\nB: Dann kommen Sie zur\u00fcck.",exampleSrc:"A: How many tablets am I allowed to take?\nB: Maximum three per day.\nA: And if the pain gets worse?\nB: Then come back.",funFact:"In insurance: 'maximale Erstattung' (maximum reimbursement). International, transparent, precise. From Latin 'maximus.'"},
{type:"teach",trg:"minimal",src:"minimal, at least",pos:"adj",gender:null,note:"The opposite of maximal.\n'Minimaler Aufwand, maximaler Effekt.'",example:"A: Wie gro\u00df ist das Risiko?\nB: Minimal. Wirklich sehr gering.\nA: Gibt es minimale Nebenwirkungen?\nB: Ja, nur minimale.",exampleSrc:"A: How big is the risk?\nB: Minimal. Really very low.\nA: Are there minimal side effects?\nB: Yes, only minimal.",funFact:"'Minimaler Aufwand, maximaler Effekt' (minimal effort, maximum effect). Insurance companies love this phrase. For them, not for you."},
{type:"teach",trg:"deswegen",src:"therefore, for that reason",pos:"adv",gender:null,note:"Des (of that) + wegen (because of). Synonym of deshalb.\nMain clause connector: verb in second position after it.",example:"A: Verumius war krank. Deswegen ging er zum Arzt.\nB: Hat der Arzt etwas verschrieben?\nA: Ja, deswegen geht es ihm besser.\nB: Gut, deswegen kann er morgen wiederkommen.",exampleSrc:"A: Verumius was sick. Therefore he went to the doctor.\nB: Did the doctor prescribe something?\nA: Yes, therefore he feels better.\nB: Good, therefore he can come back tomorrow.",funFact:"Deswegen, deshalb, daher, darum all mean therefore. Germans use them interchangeably. Deswegen literally breaks down to des (of that) + wegen (because of): because of that."},
{type:"tip",title:"Adverbialkonjunktionen: deshalb, trotzdem, deswegen, also, sonst",text:"These words connect two main clauses and show cause, contrast, or consequence. The verb comes IMMEDIATELY after them (V2 position).\n\nStructure: Main clause. Adverbial conjunction + VERB + subject + rest.\n\n- deshalb (therefore): Er ist krank. Deshalb geht er zum Arzt.\n- trotzdem (nevertheless): Es regnet. Trotzdem geht sie joggen.\n- deswegen (that is why): Die Kosten steigen. Deswegen zahlen wir mehr.\n- also (so/therefore): Du bist versichert. Also musst du dir keine Sorgen machen.\n- sonst (otherwise): Nimm die Medizin. Sonst wird es schlimmer.\n\nCompare with weil (subordinating): Er geht zum Arzt, weil er krank ist. (verb at END)\nVs. deshalb (adverbial): Er ist krank. Deshalb GEHT er zum Arzt. (verb after deshalb)",deepDive:{title:"Adverbial vs. subordinating conjunctions",text:"Subordinating conjunctions (weil, dass, obwohl, damit, falls) push the verb to the END of the clause:\nEr geht zum Arzt, weil er krank IST.\n\nAdverbial conjunctions (deshalb, trotzdem, deswegen, also, sonst) keep the verb in SECOND position:\nEr ist krank. Deshalb GEHT er zum Arzt.\n\nThe key difference: subordinating conjunctions create Nebens\u00e4tze (subordinate clauses). Adverbial conjunctions connect two Haupts\u00e4tze (main clauses). The word order tells you which type you are dealing with."}},
{type:"tip",title:"deshalb vs. trotzdem: Logikrichtung",text:"Beide bewirken Inversion (Verb in Position 2), aber entgegengesetzte Logik:\n\ndeshalb = erwartetes Ergebnis (Konsequenz):\nEs regnet. Deshalb bleibe ich zu Hause. (logisch)\n\ntrotzdem = unerwartetes Ergebnis (Überraschung):\nEs regnet. Trotzdem gehe ich raus. (unerwartet)\n\ndeshalb = 'deswegen' / trotzdem = 'trotz dessen'",deepDive:{title:"dennoch vs. trotzdem",text:"trotzdem = Alltagssprache\ndennoch = formelle Schriftsprache, Essays, Nachrichten\n\n'Der Markt fiel. Dennoch blieben die Anleger ruhig.'\n\nIm Gespräch: trotzdem.\nIm Aufsatz: dennoch."}},
{type:"tip",title:"obwohl vs. trotzdem: Grammar Difference",text:"obwohl = subordinating conjunction, verb goes to the END:\nObwohl es regnet, gehe ich raus.\n[Subclause: verb LAST] [Main clause: V2]\n\ntrotzdem = adverb, verb stays in position 2:\nEs regnet. Trotzdem gehe ich raus.\n[Main clause 1] [Main clause 2]\n\nSame meaning. Completely different grammar.\nTest: Can you start a new sentence with it? trotzdem YES, obwohl NO.",deepDive:{title:"Sentence Structure Comparison",text:"With obwohl (one complex sentence):\nObwohl es kalt ist, gehe ich schwimmen.\n[Subclause: verb at end] [Main clause: V2]\n\nWith trotzdem (two main clauses):\nEs ist kalt. Trotzdem gehe ich schwimmen.\n[Main clause 1] [Main clause 2: V2 after trotzdem]\n\nPractice converting:\nobwohl sentence to trotzdem sentence and vice versa."}},
{type:"tip",title:"Formality Scale: Adding Information",text:"From casual to formal:\n\nauch = also (simplest form)\naußerdem = moreover (everyday, versatile)\nzudem = furthermore (slightly formal)\ndarüber hinaus = beyond that (essays only)\n\nAll add new information. außerdem is the safe default.",deepDive:{title:"Word Order with außerdem",text:"Position 1 (with inversion):\nAußerdem spricht sie Französisch.\n\nMiddle of sentence (without inversion):\nSie spricht außerdem Französisch.\n\nBoth correct. Position 1 emphasizes the addition."}},
{type:"tip",title:"Paarkonjunktionen: sowohl...als auch / weder...noch",text:"sowohl A als auch B = both A and B:\nSie ist sowohl intelligent als auch fleißig.\n\nweder A noch B = neither A nor B:\nEr trinkt weder Kaffee noch Tee.\n\nWICHTIG: weder...noch ist bereits negativ.\nNie zusätzlich nicht oder kein verwenden:\nEr trinkt weder Kaffee noch Tee. (richtig)\nEr trinkt nicht weder Kaffee noch Tee. (falsch)",deepDive:{title:"weder...noch mit ganzen Sätzen",text:"Mit ganzen Sätzen: weder löst Inversion in beiden Teilen aus:\nWeder hat er Zeit, noch hat er Lust.\n(Neither does he have time, nor does he feel like it.)\n\nDas Verb kommt in BEIDEN Teilen direkt nach weder/noch."}},
{type:"mc",q:"Welcher Satz hat die richtige Wortstellung?",opts:["Deshalb er geht zum Arzt.","Deshalb er zum Arzt geht.","Deshalb zum Arzt er geht.","Deshalb geht er zum Arzt."],ans:"Deshalb geht er zum Arzt.",hint:"After an adverbial conjunction, the verb comes immediately next."},
{type:"fb",s:"Die \u00c4rztin, bei {1} ich war, hat mir Tropfen verschrieben.",a:["der"],opts:["der","die","dem","den"],hint:"Bei takes dative. \u00c4rztin is feminine. What is the feminine dative relative pronoun?",sSrc:"The doctor I was at prescribed me drops."},
{type:"mc",q:"Es regnet stark. _____ bleibe ich zu Hause. Welches Wort bedeutet 'therefore'?",opts:["Trotzdem","Deshalb","Sonst","Also"],ans:"Deshalb",hint:"Which conjunction shows a direct cause-effect relationship?"},
{type:"drag_fill",s:"Die Klinik, in {1} ich war, war sehr gut. {2} empfehle ich sie.",blanks:{"1":"der","2":"Deshalb"},pool:["der","die","dem","Deshalb","Trotzdem","Sonst"],hint:"First blank: in + dative, feminine Klinik. Second blank: a consequence conjunction.",sSrc:"The clinic I was at was very good. Therefore I recommend it."}
]},

// ═══════════════════════════════════════════════════════════════
// Lesson 5: "Apotheke und Pflege" — Vocab + review (20 words, 24 steps)
// Pharmacy and caregiving vocabulary
// ═══════════════════════════════════════════════════════════════
{id:"deu_r20l5",title:"Apotheke und Pflege",icon:"💊",xp:15,board:true,steps:[
{type:"intro",title:"Apotheke und Pflege",desc:"Drugstore, pharmacy, and care. Learn how to take care of sick people while practicing relative clauses and adverbial conjunctions.",goals:["Learn pharmacy and care vocabulary","Master care terminology","Practice relative clauses and adverbial conjunctions with new vocabulary"]},
{type:"teach",trg:"die Drogerie",src:"the drugstore (toiletries shop)",pos:"noun",gender:"f",note:"NOT a drugstore in the American sense.\ndm, Rossmann, M\u00fcller: toiletries, cosmetics, household. No medicine.",example:"A: Wo kaufst du Shampoo?\nB: In der Drogerie. Bei dm oder Rossmann.\nA: Nicht in der Apotheke?\nB: Nein, die Drogerie ist f\u00fcr K\u00f6rperpflege.",exampleSrc:"A: Where do you buy shampoo?\nB: At the drugstore. At dm or Rossmann.\nA: Not at the pharmacy?\nB: No, the drugstore is for personal care.",funFact:"A famous false friend. A Drogerie sells toiletries, cosmetics, and household products. No prescription drugs. For medicine, you need the Apotheke."},
{type:"teach",trg:"die Zahncreme",src:"the toothpaste",pos:"noun",gender:"f",note:"Zahn (tooth) + Creme (cream).\nAlso called 'Zahnpasta.' Both are correct.",example:"A: Welche Zahncreme benutzt du?\nB: Eine mit Fluorid.\nA: Wo kaufst du sie?\nB: In der Drogerie. Die ist dort g\u00fcnstiger.",exampleSrc:"A: Which toothpaste do you use?\nB: One with fluoride.\nA: Where do you buy it?\nB: At the drugstore. It is cheaper there.",funFact:"Germans use both Zahncreme and Zahnpasta interchangeably. Regional preference: north tends toward Zahnpasta, south toward Zahncreme."},
{type:"teach",trg:"die Zahnpasta",src:"the toothpaste",pos:"noun",gender:"f",note:"Zahn (tooth) + Pasta (paste). From Italian.\nSynonym for Zahncreme.",example:"A: Hast du noch Zahnpasta?\nB: Nein, die ist leer.\nA: Ich kaufe neue Zahnpasta.\nB: Nimm die mit Kr\u00e4utern.",exampleSrc:"A: Do you still have toothpaste?\nB: No, it is empty.\nA: I will buy new toothpaste.\nB: Get the one with herbs.",funFact:"From Italian 'pasta' (paste). The other word for toothpaste. Both Zahncreme and Zahnpasta are correct. Regional and personal preference decides."},
{type:"teach",trg:"die Zahnb\u00fcrste",src:"the toothbrush",pos:"noun",gender:"f",note:"Zahn (tooth) + B\u00fcrste (brush).\nCompound noun: you already know both halves.",example:"A: Ich brauche eine neue Zahnb\u00fcrste.\nB: Eine elektrische oder eine normale?\nA: Eine elektrische Zahnb\u00fcrste.\nB: Die kosten ab 30 Euro.",exampleSrc:"A: I need a new toothbrush.\nB: An electric one or a normal one?\nA: An electric toothbrush.\nB: Those cost from 30 euros.",funFact:"Compound noun: you already know both halves. This is how German vocabulary grows exponentially. Know the parts, know the whole."},
{type:"teach",trg:"die B\u00fcrste",src:"the brush",pos:"noun",gender:"f",note:"Not just for teeth: Haarb\u00fcrste, Schuhb\u00fcrste, Nagelb\u00fcrste.\nA bristle tool for cleaning anything.",example:"A: Wo ist meine B\u00fcrste?\nB: Welche B\u00fcrste? Die Haarb\u00fcrste?\nA: Ja, die Haarb\u00fcrste.\nB: Im Badezimmer, neben dem Spiegel.",exampleSrc:"A: Where is my brush?\nB: Which brush? The hairbrush?\nA: Yes, the hairbrush.\nB: In the bathroom, next to the mirror.",funFact:"Haarb\u00fcrste (hairbrush), Schuhb\u00fcrste (shoe brush), Nagelb\u00fcrste (nail brush). A bristle tool for cleaning anything. From Middle High German 'burste.'"},
{type:"teach",trg:"das Taschentuch",src:"the tissue, the handkerchief",pos:"noun",gender:"n",note:"Tasche (pocket) + Tuch (cloth).\nTempo is the generic German word for tissue.",example:"A: Hast du ein Taschentuch?\nB: Ja, hier. Hast du Schnupfen?\nA: Ja, seit gestern.\nB: Gute Besserung!",exampleSrc:"A: Do you have a tissue?\nB: Yes, here. Do you have a cold?\nA: Yes, since yesterday.\nB: Get well soon!",funFact:"Tempo is the generic German word for tissue (brand name, like Kleenex in English). 'Hast du ein Taschentuch?' is what you ask when someone has Schnupfen."},
{type:"teach",trg:"der Pfleger",src:"the caregiver, the nurse (male)",pos:"noun",gender:"m",note:"From 'pflegen' (to care for) + -er.\n'Altenpfleger' = elderly care worker.",example:"A: Der Pfleger kommt um acht Uhr.\nB: Ist er nett?\nA: Ja, ein sehr guter Pfleger.\nB: Gut, Oma braucht gute Pflege.",exampleSrc:"A: The caregiver comes at eight o'clock.\nB: Is he nice?\nA: Yes, a very good caregiver.\nB: Good, grandma needs good care.",funFact:"An increasingly important profession in aging Germany. The country has a chronic shortage of Pfleger. 'Altenpfleger' (elderly care worker) is one of the most needed jobs."},
{type:"teach",trg:"die Pflegerin",src:"the caregiver, the nurse (female)",pos:"noun",gender:"f",note:"Pfleger + -in. Standard feminine suffix.\nThe majority of Pflege workers are female.",example:"A: Die Pflegerin ist sehr erfahren.\nB: Wie lange arbeitet sie schon?\nA: Seit zehn Jahren als Pflegerin.\nB: Das merkt man.",exampleSrc:"A: The caregiver is very experienced.\nB: How long has she been working?\nA: For ten years as a caregiver.\nB: You can tell.",funFact:"The majority of Pflege workers in Germany are female. The profession is chronically understaffed. Same pattern: male -er, female -erin."},
{type:"teach",trg:"der Krankenpfleger",src:"the male nurse",pos:"noun",gender:"m",note:"Kranke (sick person) + Pfleger (carer).\nModern: 'Pflegefachkraft' for all genders.",example:"A: Mein Bruder ist Krankenpfleger.\nB: In welcher Klinik arbeitet er?\nA: In der Charit\u00e9.\nB: Das ist ein sehr guter Beruf.",exampleSrc:"A: My brother is a nurse.\nB: At which clinic does he work?\nA: At the Charit\u00e9.\nB: That is a very good profession.",funFact:"Modern German is moving toward 'Pflegefachkraft' for all genders. But 'Krankenpfleger' is still widely understood and used."},
{type:"teach",trg:"die Krankenschwester",src:"the nurse (female)",pos:"noun",gender:"f",note:"Kranke (sick) + Schwester (sister).\nHistorically, nuns cared for the sick. The name stuck.",example:"A: Die Krankenschwester misst meinen Blutdruck.\nB: Ist er zu hoch?\nA: Nein, sagt die Krankenschwester.\nB: Gut, dann ist alles in Ordnung.",exampleSrc:"A: The nurse is measuring my blood pressure.\nB: Is it too high?\nA: No, says the nurse.\nB: Good, then everything is fine.",funFact:"Historically, nuns (Schwestern) cared for the sick. The name stuck. Being phased out officially in favor of 'Pflegefachfrau,' but still widely used."},
{type:"teach",trg:"der Betreuer",src:"the supervisor, the caretaker",pos:"noun",gender:"m",note:"From 'betreuen' (to look after).\nBroader than Pfleger: children, patients, elderly.",example:"A: Wer ist der Betreuer der Gruppe?\nB: Herr Schmidt. Er betreut zehn Patienten.\nA: Ist er gut?\nB: Ja, ein sehr f\u00fcrsorglicher Betreuer.",exampleSrc:"A: Who is the supervisor of the group?\nB: Mr. Schmidt. He looks after ten patients.\nA: Is he good?\nB: Yes, a very caring supervisor.",funFact:"Broader than Pfleger: a Betreuer can supervise children, patients, or elderly. 'Kinderbetreuer' (childcare worker). The person responsible for your wellbeing."},
{type:"teach",trg:"die Betreuerin",src:"the female supervisor, the female caretaker",pos:"noun",gender:"f",note:"Betreuer + -in.\n'Die Betreuerin k\u00fcmmert sich um die Senioren.'",example:"A: Die Betreuerin kommt heute Nachmittag.\nB: Gut, Opa freut sich immer.\nA: Ja, die Betreuerin ist sehr nett.\nB: Er vertraut ihr.",exampleSrc:"A: The caretaker comes this afternoon.\nB: Good, grandpa always looks forward to it.\nA: Yes, the caretaker is very nice.\nB: He trusts her.",funFact:"Same pattern: male -er, female -erin. Betreuer/Betreuerin, Pfleger/Pflegerin. German is consistent with its gendered suffixes."},
{type:"teach",trg:"die Betreuung",src:"the care, the supervision",pos:"noun",gender:"f",note:"From 'betreuen' + -ung. Abstract noun.\n'Kinderbetreuung' = childcare.",example:"A: Die Betreuung im Altenheim ist sehr gut.\nB: Wie viele Stunden am Tag?\nA: 24 Stunden Betreuung.\nB: Das ist beruhigend.",exampleSrc:"A: The care at the nursing home is very good.\nB: How many hours per day?\nA: 24-hour care.\nB: That is reassuring.",funFact:"'Kinderbetreuung' (childcare), 'Seniorenbetreuung' (elderly care). The -ung suffix creates the concept from the verb. German's favorite noun-maker."},
{type:"teach",trg:"pflegen",src:"to care for, to maintain",pos:"verb",gender:null,note:"'Einen Kranken pflegen' = to care for a sick person.\nAlso: 'Kontakte pflegen' = to maintain contacts.",example:"A: Wer pflegt deine Mutter?\nB: Ein Pfleger kommt jeden Tag.\nA: Pflegt er sie gut?\nB: Ja, er pflegt sie mit viel Geduld.",exampleSrc:"A: Who cares for your mother?\nB: A caregiver comes every day.\nA: Does he care for her well?\nB: Yes, he cares for her with great patience.",funFact:"Care in every sense. 'Einen Kranken pflegen' (to care for a sick person). 'Kontakte pflegen' (to maintain contacts). 'Den Garten pflegen' (to tend the garden)."},
{type:"teach",trg:"betreuen",src:"to look after, to supervise",pos:"verb",gender:null,note:"Inseparable prefix be-.\nBroader than pflegen. 'Kinder betreuen' = to look after children.",example:"A: Wer betreut die Kinder?\nB: Eine Betreuerin betreut sie.\nA: Wie viele Kinder betreut sie?\nB: Zehn Kinder pro Gruppe.",exampleSrc:"A: Who looks after the children?\nB: A caretaker looks after them.\nA: How many children does she look after?\nB: Ten children per group.",funFact:"Be- + treuen (loyalty-related root). To be loyal to someone by watching over them. Inseparable prefix. Broader than pflegen."},
{type:"teach",trg:"erleichtern",src:"to ease, to relieve",pos:"verb",gender:null,note:"Er- + leicht (light/easy) + -ern. To make lighter.\n'Erleichtert sein' = to be relieved.",example:"A: Diese Medizin erleichtert den Schmerz.\nB: Wirklich? Wie schnell?\nA: Nach etwa 30 Minuten.\nB: Gut, ich bin erleichtert.",exampleSrc:"A: This medicine eases the pain.\nB: Really? How fast?\nA: After about 30 minutes.\nB: Good, I am relieved.",funFact:"A beautiful compound verb. Er- + leicht (light/easy) + -ern. To make lighter. Recovery is literally making the burden lighter."},
{type:"teach",trg:"verbinden",src:"to bandage, to connect",pos:"verb",gender:null,note:"Ver- + binden (to bind).\n'Eine Wunde verbinden' = to bandage a wound.",example:"A: Ich muss die Wunde verbinden.\nB: Haben Sie einen Verband?\nA: Ja, ich verbinde das sofort.\nB: Danke, das tut schon besser.",exampleSrc:"A: I need to bandage the wound.\nB: Do you have a bandage?\nA: Yes, I will bandage it right away.\nB: Thanks, that feels better already.",funFact:"The bandage binds; the phone line connects. Same verb. 'Eine Wunde verbinden' (to bandage a wound). 'Verbunden sein' (to be connected)."},
{type:"teach",trg:"ersetzen",src:"to replace",pos:"verb",gender:null,note:"Er- + setzen (to set/place).\nTo set something new in the place of the old.",example:"A: Wir m\u00fcssen das Pflaster ersetzen.\nB: Wie oft?\nA: Jeden Tag ersetzen.\nB: Und dann heilt die Wunde schneller?",exampleSrc:"A: We need to replace the bandage.\nB: How often?\nA: Replace it every day.\nB: And then the wound heals faster?",funFact:"'Nichts kann Gesundheit ersetzen' (Nothing can replace health). To set something new in the place of the old. The verb that built the Ersatz noun."},
{type:"teach",trg:"der Ersatz",src:"the replacement, the substitute",pos:"noun",gender:"m",note:"From ersetzen. 'Ersatzteil' = spare part.\nEntered English during the World Wars.",example:"A: Haben Sie einen Ersatz f\u00fcr dieses Medikament?\nB: Ja, es gibt einen g\u00fcnstigen Ersatz.\nA: Wirkt der Ersatz genauso gut?\nB: Ja, gleicher Wirkstoff.",exampleSrc:"A: Do you have a substitute for this medicine?\nB: Yes, there is a cheaper substitute.\nA: Does the substitute work just as well?\nB: Yes, same active ingredient.",funFact:"During both World Wars, 'Ersatz' entered English as a word meaning cheap substitute. Germans use it neutrally. 'Ersatzteil' (spare part). 'Kaffee-Ersatz' (coffee substitute)."},
{type:"teach",trg:"die Besserung",src:"the improvement, the recovery",pos:"noun",gender:"f",note:"From 'besser' (better) + -ung.\n'Gute Besserung!' = Get well soon!",example:"A: Gute Besserung!\nB: Danke! Ich hoffe auf schnelle Besserung.\nA: Ruh dich gut aus.\nB: Mache ich. Danke f\u00fcr die Genesungsw\u00fcnsche.",exampleSrc:"A: Get well soon!\nB: Thanks! I hope for a quick recovery.\nA: Rest well.\nB: I will. Thanks for the well wishes.",funFact:"'Gute Besserung!' is THE thing Germans say when someone is sick. The most important two-word phrase in German healthcare culture. Say it often."},
{type:"mc",q:"Du brauchst Shampoo und Zahnpasta. Wohin gehst du?",opts:["Apotheke","Klinik","Drogerie","Notaufnahme"],ans:"Drogerie",hint:"This store sells toiletries and cosmetics, not prescription medicine."},
{type:"fb",s:"Die Pflegerin arbeitet hart. {1} ist sie oft ersch\u00f6pft.",a:["Deshalb"],opts:["Deshalb","Trotzdem","Weil","Dass"],hint:"Which word means 'therefore' and is followed by verb-second word order?",sSrc:"The nurse works hard. Therefore she is often exhausted."},
{type:"drag_fill",s:"Die Salbe, {1} der Arzt mir verschrieben hat, hilft nicht. {2} brauche ich ein anderes Schmerzmittel.",blanks:{"1":"die","2":"Deswegen"},pool:["die","der","das","Deswegen","Trotzdem","Weil"],hint:"First blank: accusative relative pronoun for feminine Salbe. Second blank: consequence conjunction + verb-second.",sSrc:"The ointment the doctor prescribed me does not help. That is why I need a different painkiller."}
]},

// ═══════════════════════════════════════════════════════════════
// Lesson 6: "TK oder AOK?" — Story climax (18 words, 22 steps)
// Scene 3: The decision
// ═══════════════════════════════════════════════════════════════
{id:"deu_r20l6",title:"TK oder AOK?",icon:"📋",xp:15,board:true,steps:[
{type:"intro",title:"TK oder AOK?",desc:"Verumius trifft seine Entscheidung. Zwei Brosch\u00fcren, ein Stift, ein Moment. Lerne Renten- und Sozialsystemvokabeln.",goals:["Lerne Renten- und Sozialsystemvokabeln","Erlebe Verumius bei seiner ersten erwachsenen Entscheidung auf Deutsch","Kombiniere Relativs\u00e4tze mit Adverbialkonjunktionen"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-ber-kitchen-clean",trg:"Der K\u00fcchentisch ist aufger\u00e4umt. Zwanzig Briefe sind jetzt zwei Brosch\u00fcren. Verumius h\u00e4lt einen Stift in der Hand. Die Versicherung, f\u00fcr die er sich entscheidet, wird ihn die n\u00e4chsten Jahre begleiten.",src:"The kitchen table is tidy. Twenty letters are now two brochures. Verumius holds a pen in his hand. The insurance he chooses will accompany him for the next years."},
{type:"teach",trg:"die Rente",src:"the pension, the retirement",pos:"noun",gender:"f",note:"'In Rente gehen' = to retire. From Latin 'renta.'\nRentenversicherung (pension insurance) is mandatory.",example:"A: Wann gehst du in Rente?\nB: Mit 67. Noch 30 Jahre.\nA: Bekommst du eine gute Rente?\nB: Ich hoffe es. Ich zahle jeden Monat ein.",exampleSrc:"A: When will you retire?\nB: At 67. Another 30 years.\nA: Will you get a good pension?\nB: I hope so. I pay in every month.",funFact:"The German Rentensystem is pay-as-you-go: today's workers fund today's retirees. 'Rentenversicherung' (pension insurance) is mandatory for all employees."},
{type:"teach",trg:"die Pension",src:"the pension (civil servants), the guesthouse",pos:"noun",gender:"f",note:"Two meanings: retirement pay for Beamte, or a small hotel.\nContext is essential.",example:"A: Mein Vater bekommt eine Pension.\nB: Ist er Beamter?\nA: Ja, er war 40 Jahre Lehrer.\nB: Dann ist die Pension sicher gut.",exampleSrc:"A: My father gets a pension.\nB: Is he a civil servant?\nA: Yes, he was a teacher for 40 years.\nB: Then the pension is surely good.",funFact:"Two meanings. For civil servants: retirement pay (Beamtenpension). For travelers: a small guesthouse. 'In Pension gehen' (to retire, for Beamte). Context is essential."},
{type:"teach",trg:"der Senior",src:"the senior, the elderly person",pos:"noun",gender:"m",note:"From Latin 'senior' (older).\n'Seniorenrabatt' = senior discount.",example:"A: Gibt es einen Seniorenrabatt?\nB: Ja, f\u00fcr Senioren ab 65 Jahren.\nA: Wie viel Prozent?\nB: 20 Prozent auf alle Eintrittskarten.",exampleSrc:"A: Is there a senior discount?\nB: Yes, for seniors from 65 years.\nA: How many percent?\nB: 20 percent on all tickets.",funFact:"'Seniorenrabatt' (senior discount), 'Seniorenticket' (reduced fare). Respectful term for older adults. From Latin 'senior' (older)."},
{type:"teach",trg:"die Seniorin",src:"the senior (female)",pos:"noun",gender:"f",note:"Senior + -in. Standard feminine formation.\nGerman insists on gendered forms, even for international words.",example:"A: Die Seniorin joggt jeden Morgen.\nB: Wie alt ist sie?\nA: 78 Jahre alt.\nB: Beeindruckend! Eine sportliche Seniorin.",exampleSrc:"A: The senior woman jogs every morning.\nB: How old is she?\nA: 78 years old.\nB: Impressive! An athletic senior.",funFact:"German insists on gendered forms, even for international words. Senior becomes Seniorin. The -in suffix is universal for person nouns."},
{type:"teach",trg:"der Pensionist",src:"the pensioner, the retiree",pos:"noun",gender:"m",note:"Austrian German primarily.\nIn Germany, 'Rentner' is more common.",example:"A: Mein Nachbar ist Pensionist.\nB: Aus \u00d6sterreich?\nA: Ja, er ist aus Wien.\nB: Dort sagt man Pensionist statt Rentner.",exampleSrc:"A: My neighbor is a pensioner.\nB: From Austria?\nA: Yes, he is from Vienna.\nB: There they say Pensionist instead of Rentner.",funFact:"Austrian German primarily. In Germany, 'Rentner' is more common. Regional variation within German-speaking countries shows the language is not monolithic."},
{type:"teach",trg:"die Pensionistin",src:"the pensioner (female)",pos:"noun",gender:"f",note:"Austrian form. Pensionist + -in.\nStandard feminine formation.",example:"A: Die Pensionistin lebt in Salzburg.\nB: Bekommt sie eine gute Pension?\nA: Ja, sie war Lehrerin.\nB: Lehrerinnen bekommen gute Pensionen.",exampleSrc:"A: The pensioner lives in Salzburg.\nB: Does she get a good pension?\nA: Yes, she was a teacher.\nB: Teachers get good pensions.",funFact:"Austrian form. Four morphemes: Pension-ist-in. Standard feminine formation applied to a regional word."},
{type:"teach",trg:"das Altenheim",src:"the nursing home",pos:"noun",gender:"n",note:"Alten (old people) + Heim (home).\nGermany has over 15,000 Altenheime.",example:"A: Meine Oma wohnt im Altenheim.\nB: Gef\u00e4llt es ihr dort?\nA: Ja, das Altenheim ist sehr sch\u00f6n.\nB: Hat sie gute Betreuung?",exampleSrc:"A: My grandma lives in the nursing home.\nB: Does she like it there?\nA: Yes, the nursing home is very nice.\nB: Does she have good care?",funFact:"A place where Senioren receive Betreuung and Pflege. Germany has over 15,000 Altenheime. The aging population makes this an increasingly important topic."},
{type:"teach",trg:"das Altersheim",src:"the retirement home",pos:"noun",gender:"n",note:"Alter (age) + Heim (home). Synonym for Altenheim.\nRegional preference decides which one you hear.",example:"A: Gibt es ein Altersheim in der N\u00e4he?\nB: Ja, am Stadtrand.\nA: Ist das Altersheim gut?\nB: Ja, es hat einen guten Ruf.",exampleSrc:"A: Is there a retirement home nearby?\nB: Yes, on the outskirts.\nA: Is the retirement home good?\nB: Yes, it has a good reputation.",funFact:"'Altersheim' focuses on age; 'Altenheim' focuses on the people. Both mean the same thing. Regional preference decides which one you hear."},
{type:"teach",trg:"die Einrichtung",src:"the facility, the institution",pos:"noun",gender:"f",note:"Ein (in) + Richtung (direction) = arrangement.\nAlso means furniture ('die Einrichtung des Zimmers').",example:"A: Die Einrichtung ist modern.\nB: Welche Einrichtung meinst du?\nA: Die medizinische Einrichtung am Park.\nB: Ah ja, die ist erst letztes Jahr er\u00f6ffnet worden.",exampleSrc:"A: The facility is modern.\nB: Which facility do you mean?\nA: The medical facility by the park.\nB: Ah yes, that one only opened last year.",funFact:"To set things in the right direction. 'Eine medizinische Einrichtung' (a medical facility). Also: furniture ('die Einrichtung des Zimmers'). Direction and arrangement in one word."},
{type:"teach",trg:"pensionieren",src:"to pension off, to retire",pos:"verb",gender:null,note:"The -ieren ending makes it regular.\nPrimarily for Beamte. Workers: 'in Rente gehen.'",example:"A: Wann wird er pensioniert?\nB: N\u00e4chstes Jahr.\nA: Freut er sich?\nB: Ja, er wurde letzten Monat informiert.",exampleSrc:"A: When will he be retired?\nB: Next year.\nA: Is he looking forward to it?\nB: Yes, he was informed last month.",funFact:"Primarily for civil servants (Beamte). For normal workers: 'in Rente gehen.' Germany has two retirement systems: one for Beamte, one for everyone else."},
{type:"teach",trg:"die Not",src:"the need, the distress, the emergency",pos:"noun",gender:"f",note:"Root of Notfall, Notaufnahme, Notruf, Notausgang.\nOne tiny word spawns an entire emergency vocabulary.",example:"A: Er ist in gro\u00dfer Not.\nB: Was ist passiert?\nA: Er hat sein Geld verloren.\nB: Wir m\u00fcssen ihm helfen.",exampleSrc:"A: He is in great distress.\nB: What happened?\nA: He lost his money.\nB: We need to help him.",funFact:"Root of Notfall, Notaufnahme, Notruf, Notausgang. One tiny word spawns an entire emergency vocabulary. 'Not macht erfinderisch' (Necessity is the mother of invention)."},
{type:"teach",trg:"der Notausgang",src:"the emergency exit",pos:"noun",gender:"m",note:"Not (emergency) + Ausgang (exit).\nGreen signs, required by law in every public building.",example:"A: Wo ist der Notausgang?\nB: Dort hinten, neben der Treppe.\nA: Danke. Man sollte immer wissen, wo er ist.\nB: Genau, das ist Sicherheit.",exampleSrc:"A: Where is the emergency exit?\nB: Back there, next to the stairs.\nA: Thanks. You should always know where it is.\nB: Exactly, that is safety.",funFact:"Green signs with a running figure. Required by law in every public building. 'Wo ist der Notausgang?' is essential survival German."},
{type:"teach",trg:"das Opfer",src:"the victim, the sacrifice",pos:"noun",gender:"n",note:"From Latin 'offerre' (to offer).\nBoth meanings: the one harmed and the one given up.",example:"A: Wie viele Opfer gab es?\nB: Drei Verletzte, keine Toten.\nA: Das ist schrecklich.\nB: Ja, die Opfer werden im Krankenhaus behandelt.",exampleSrc:"A: How many victims were there?\nB: Three injured, no dead.\nA: That is terrible.\nB: Yes, the victims are being treated in the hospital.",funFact:"The word holds both meanings: the one harmed and the one given up. 'Unfallopfer' (accident victim). 'Ein Opfer bringen' (to make a sacrifice). Same word, dual fate."},
{type:"teach",trg:"der Tod",src:"death",pos:"noun",gender:"m",note:"Masculine despite being abstract.\nCognate with English 'death.' Often personified.",example:"A: Der Tod ist ein schwieriges Thema.\nB: Ja, aber ein wichtiges.\nA: In Deutschland spricht man offen dar\u00fcber.\nB: Das finde ich gut.",exampleSrc:"A: Death is a difficult topic.\nB: Yes, but an important one.\nA: In Germany, people talk about it openly.\nB: I think that is good.",funFact:"Often personified in German literature as 'der Sensenmann' (the grim reaper). Cognate with English 'death.' Masculine, despite being an abstract noun."},
{type:"teach",trg:"die Tote",src:"the dead person (female), the dead",pos:"noun",gender:"f",note:"Adjectival noun from 'tot' (dead).\nDer/die Tote changes with gender and case like an adjective.",example:"A: Die Polizei fand eine Tote.\nB: Wer war die Tote?\nA: Das wird noch ermittelt.\nB: Die Zahl der Toten steigt.",exampleSrc:"A: The police found a dead woman.\nB: Who was the dead woman?\nA: That is still being investigated.\nB: The number of dead is rising.",funFact:"Adjectival noun: der/die Tote changes with gender and case like an adjective. 'Die Zahl der Toten' (the number of dead). Grammatically, death is declined."},
{type:"teach",trg:"die Kranke",src:"the sick person (female)",pos:"noun",gender:"f",note:"Adjectival noun from 'krank.'\nDer Kranke (male), die Kranke (female).",example:"A: Die Kranke braucht Ruhe.\nB: Wie geht es der Kranken?\nA: Besser. Die Kranke erholt sich langsam.\nB: Das sind gute Nachrichten.",exampleSrc:"A: The sick woman needs rest.\nB: How is the sick woman doing?\nA: Better. The sick woman is recovering slowly.\nB: That is good news.",funFact:"Another adjective acting as a noun. Der Kranke (male), die Kranke (female). 'Die Kranken pflegen' (to care for the sick). Adjective becomes person."},
{type:"teach",trg:"t\u00f6dlich",src:"deadly, fatal",pos:"adj",gender:null,note:"From Tod + -lich.\n'T\u00f6dlich langweilig' = deadly boring (emphasis).",example:"A: Ist die Krankheit t\u00f6dlich?\nB: Nein, nicht mit der richtigen Behandlung.\nA: Gott sei Dank.\nB: Aber ohne Behandlung kann sie t\u00f6dlich sein.",exampleSrc:"A: Is the disease deadly?\nB: No, not with the right treatment.\nA: Thank God.\nB: But without treatment it can be deadly.",funFact:"Germans use t\u00f6dlich for emphasis, like English 'dead tired.' 'T\u00f6dlich langweilig' (deadly boring). From Tod + -lich. The adjective of death."},
{type:"teach",trg:"die Lieferung",src:"the delivery",pos:"noun",gender:"f",note:"From 'liefern' (to deliver) + -ung.\nIn insurance: what the Krankenkasse delivers (pays for).",example:"A: Wann kommt die Lieferung?\nB: Die Lieferung kommt morgen.\nA: Gut, ich warte auf die Medikamentenlieferung.\nB: Sie wird bis 12 Uhr geliefert.",exampleSrc:"A: When does the delivery come?\nB: The delivery comes tomorrow.\nA: Good, I am waiting for the medicine delivery.\nB: It will be delivered by 12 o'clock.",funFact:"In the insurance context: what the Krankenkasse delivers (pays for). 'Medikamentenlieferung' (medicine delivery). From 'liefern' (to deliver) + -ung."},
{type:"story",speaker:"narrator",mood:"triumphant",art:"de-ber-kitchen-clean",trg:"Verumius kreist 'TK' ein. Die Entscheidung, \u00fcber die er zwei Wochen nachgedacht hat, ist getroffen. Trotzdem f\u00fchlt er sich erleichtert. Also ist er jetzt ein richtiger Berliner.",src:"Verumius circles 'TK.' The decision he thought about for two weeks is made. Nevertheless, he feels relieved. So he is now a real Berliner."},
{type:"mc",q:"Die Versicherung, _____ ich mich entschieden habe, ist die TK. Was passt?",opts:["f\u00fcr der","f\u00fcr das","f\u00fcr den","f\u00fcr die"],ans:"f\u00fcr die",hint:"sich entscheiden f\u00fcr + accusative. Versicherung is feminine."}
]},

// ═══════════════════════════════════════════════════════════════
// Lesson 7: "Pr\u00fcfung: Gesundheit und System" — Comprehensive quiz (15 words, 22 steps)
// Assessment of both grammar constructs
// ═══════════════════════════════════════════════════════════════
{id:"deu_r20l7",title:"Pr\u00fcfung: Gesundheit und System",icon:"📝",xp:15,board:true,steps:[
{type:"intro",title:"Pr\u00fcfung: Gesundheit und System",desc:"Test your knowledge of health and insurance vocabulary. Show that you have mastered relative clauses and adverbial conjunctions.",goals:["Test health and insurance vocabulary","Prove mastery of relative clauses with prepositions","Show competence with adverbial conjunctions"]},
{type:"teach",trg:"der Raucher",src:"the smoker (male)",pos:"noun",gender:"m",note:"From 'rauchen' (to smoke) + -er.\n'Raucherbereich' = smoking area.",example:"A: Bist du Raucher?\nB: Nein, ich habe vor drei Jahren aufgeh\u00f6rt.\nA: Gut gemacht! Rauchen ist ungesund.\nB: Ja, ich f\u00fchle mich viel besser.",exampleSrc:"A: Are you a smoker?\nB: No, I quit three years ago.\nA: Well done! Smoking is unhealthy.\nB: Yes, I feel much better.",funFact:"Germany was one of the last EU countries to ban indoor smoking (2007). 'Raucher oder Nichtraucher?' was once asked on every train."},
{type:"teach",trg:"die Raucherin",src:"the smoker (female)",pos:"noun",gender:"f",note:"Raucher + -in. Standard feminine suffix.\nSame pattern as Pfleger/Pflegerin.",example:"A: Ist sie Raucherin?\nB: Ja, leider. Sie raucht seit 20 Jahren.\nA: Das ist schlecht f\u00fcr die Gesundheit.\nB: Ich wei\u00df, aber sie kann nicht aufh\u00f6ren.",exampleSrc:"A: Is she a smoker?\nB: Yes, unfortunately. She has been smoking for 20 years.\nA: That is bad for health.\nB: I know, but she cannot quit.",funFact:"Same pattern as Pfleger/Pflegerin, Betreuer/Betreuerin. German's consistent feminine suffix at work."},
{type:"teach",trg:"der Nichtraucher",src:"the non-smoker (male)",pos:"noun",gender:"m",note:"Nicht + Raucher. The Nicht- prefix negates.\n'Nichtraucherzone' = non-smoking zone.",example:"A: Ich bin Nichtraucher.\nB: Sehr gut. Seit immer?\nA: Ja, ich habe nie geraucht.\nB: Beneidenswert!",exampleSrc:"A: I am a non-smoker.\nB: Very good. Since always?\nA: Yes, I have never smoked.\nB: Enviable!",funFact:"The Nicht- prefix negates the person noun. 'Nichtraucher sein' (to be a non-smoker) is now the default in public spaces across Germany."},
{type:"teach",trg:"die Nichtraucherin",src:"the non-smoker (female)",pos:"noun",gender:"f",note:"Nichtraucher + -in.\nFour morphemes: Nicht-rauch-er-in.",example:"A: Sie ist \u00fcberzeugte Nichtraucherin.\nB: Gut f\u00fcr sie.\nA: Ja, sie hat nie angefangen.\nB: Das ist die beste Entscheidung.",exampleSrc:"A: She is a committed non-smoker.\nB: Good for her.\nA: Yes, she never started.\nB: That is the best decision.",funFact:"Four morphemes in one word: Nicht-rauch-er-in. German stacks prefixes and suffixes like building blocks. Know the parts, decode any word."},
{type:"teach",trg:"die Sucht",src:"the addiction",pos:"noun",gender:"f",note:"From 'suchen' (to seek). An endless seeking.\n'Drogensucht' = drug addiction.",example:"A: Sucht ist eine Krankheit.\nB: Ja, eine sehr ernste.\nA: Kann man Sucht heilen?\nB: Mit Therapie und Unterst\u00fctzung, ja.",exampleSrc:"A: Addiction is a disease.\nB: Yes, a very serious one.\nA: Can you cure addiction?\nB: With therapy and support, yes.",funFact:"From 'suchen' (to seek). An addiction is an endless seeking. 'Drogensucht' (drug addiction), 'Spielsucht' (gambling addiction), 'Internetsucht' (internet addiction). Whatever you cannot stop seeking."},
{type:"teach",trg:"das Suchtmittel",src:"the addictive substance",pos:"noun",gender:"n",note:"Sucht (addiction) + Mittel (substance/means).\nClinical, official, legal.",example:"A: Alkohol ist ein Suchtmittel.\nB: Ja, und Nikotin auch.\nA: Welche Suchtmittel sind legal?\nB: Alkohol, Nikotin und Koffein.",exampleSrc:"A: Alcohol is an addictive substance.\nB: Yes, and nicotine too.\nA: Which addictive substances are legal?\nB: Alcohol, nicotine, and caffeine.",funFact:"The compound is clinical, official, legal. Used in medical and legal contexts. 'Suchtmittelgesetz' (narcotics law). German compounds leave nothing ambiguous."},
{type:"teach",trg:"die Droge",src:"the drug",pos:"noun",gender:"f",note:"From Dutch 'droog' (dry). Originally dried herbs.\nThe Drogerie kept the old, innocent meaning.",example:"A: Drogen sind gef\u00e4hrlich.\nB: Ja, besonders harte Drogen.\nA: Gibt es Hilfe f\u00fcr Abh\u00e4ngige?\nB: Ja, es gibt Drogenberatungsstellen.",exampleSrc:"A: Drugs are dangerous.\nB: Yes, especially hard drugs.\nA: Is there help for addicts?\nB: Yes, there are drug counseling centers.",funFact:"From Dutch 'droog' (dry). Originally meant dried herbs and spices. The meaning shifted to illegal substances. The Drogerie kept the old, innocent meaning."},
{type:"teach",trg:"das Gift",src:"poison",pos:"noun",gender:"n",note:"The ultimate false friend.\nEnglish 'gift' = present. German 'Gift' = poison.",example:"A: Vorsicht, das ist Gift!\nB: Wirklich? Es sieht harmlos aus.\nA: Nein, das ist sehr giftiges Material.\nB: Danke f\u00fcr die Warnung!",exampleSrc:"A: Careful, that is poison!\nB: Really? It looks harmless.\nA: No, that is very poisonous material.\nB: Thanks for the warning!",funFact:"The ultimate false friend. English 'gift' = present. German 'Gift' = poison. Same root (something given), opposite outcomes. Do not confuse at the pharmacy."},
{type:"teach",trg:"s\u00fcchtig",src:"addicted",pos:"adj",gender:null,note:"From Sucht + -ig.\n'S\u00fcchtig machen' = to be addictive. Can be serious or playful.",example:"A: Bist du s\u00fcchtig nach Kaffee?\nB: Ja, total s\u00fcchtig! Drei Tassen am Tag.\nA: Das ist noch nicht schlimm.\nB: Aber ohne Kaffee bin ich nicht funktionsf\u00e4hig.",exampleSrc:"A: Are you addicted to coffee?\nB: Yes, totally addicted! Three cups a day.\nA: That is not so bad yet.\nB: But without coffee I cannot function.",funFact:"Can be serious or playful. 'S\u00fcchtig nach Schokolade' (addicted to chocolate) is lighthearted. 'Drogenabh\u00e4ngig' is the clinical term for serious addiction."},
{type:"teach",trg:"blind",src:"blind",pos:"adj",gender:null,note:"Same in English and German.\n'Blinder Passagier' = stowaway (blind passenger).",example:"A: Mein Opa ist fast blind.\nB: Braucht er Hilfe im Alltag?\nA: Ja, ein Betreuer kommt t\u00e4glich.\nB: Gut, dass er Unterst\u00fctzung hat.",exampleSrc:"A: My grandpa is almost blind.\nB: Does he need help in daily life?\nA: Yes, a caregiver comes daily.\nB: Good that he has support.",funFact:"From Proto-Germanic *blindaz. 'Blinder Passagier' (stowaway, literally 'blind passenger'). 'Blindenschrift' = Braille (blind-writing)."},
{type:"teach",trg:"taub",src:"deaf, numb",pos:"adj",gender:null,note:"Cognate with English 'deaf' through sound shifts.\nAlso means 'numb': 'Mein Finger ist taub.'",example:"A: Sie ist seit der Kindheit taub.\nB: Kann sie Geb\u00e4rdensprache?\nA: Ja, flie\u00dfend.\nB: Beeindruckend.",exampleSrc:"A: She has been deaf since childhood.\nB: Can she do sign language?\nA: Yes, fluently.\nB: Impressive.",funFact:"Also means 'numb.' 'Mein Finger ist taub' (My finger is numb). 'Geh\u00f6rlos' (hearing-less) is preferred in modern usage over 'taubstumm' (deaf-mute)."},
{type:"teach",trg:"link",src:"left (direction), sneaky",pos:"adj",gender:null,note:"'Die linke Hand' = the left hand.\nColloquially: 'ein linker Typ' = a shady character.",example:"A: Bist du Linksh\u00e4nder?\nB: Ja, ich schreibe mit der linken Hand.\nA: Interessant. Mein Bruder auch.\nB: Wir sind etwa zehn Prozent der Bev\u00f6lkerung.",exampleSrc:"A: Are you left-handed?\nB: Yes, I write with the left hand.\nA: Interesting. My brother too.\nB: We are about ten percent of the population.",funFact:"The association of left with dishonesty exists in many languages (Latin 'sinister'). Colloquially: 'ein linker Typ' (a shady character). An ancient bias preserved in language."},
{type:"teach",trg:"stechen",src:"to sting, to stab, to prick",pos:"verb",gender:null,note:"Irregular: sticht, stach, gestochen.\nRelated to English 'stick.'",example:"A: Au! Die Biene hat mich gestochen!\nB: Wo hat sie dich gestochen?\nA: Am Arm. Es brennt und sticht.\nB: Lass mich sehen. Bist du allergisch?",exampleSrc:"A: Ow! The bee stung me!\nB: Where did it sting you?\nA: On the arm. It burns and stings.\nB: Let me see. Are you allergic?",funFact:"'Die Biene sticht' (The bee stings). 'Es sticht in der Brust' (There is a stabbing pain in the chest). Related to English 'stick.' Irregular: sticht, stach, gestochen."},
{type:"teach",trg:"schieben",src:"to push, to shove",pos:"verb",gender:null,note:"Irregular: schob, geschoben.\n'Den Rollstuhl schieben' = to push the wheelchair.",example:"A: Kannst du den Rollstuhl schieben?\nB: Ja, kein Problem.\nA: Vorsichtig, die Rampe ist steil.\nB: Ich schiebe ganz langsam.",exampleSrc:"A: Can you push the wheelchair?\nB: Yes, no problem.\nA: Carefully, the ramp is steep.\nB: I will push very slowly.",funFact:"'Etwas auf die lange Bank schieben' (to put something on the long bench) = to procrastinate. Irregular: schob, geschoben. Pushing in every sense."},
{type:"teach",trg:"wiegen",src:"to weigh",pos:"verb",gender:null,note:"Irregular: wog, gewogen.\nAlso: 'das Baby wiegen' = to rock the baby.",example:"A: Wie viel wiegen Sie?\nB: Etwa 80 Kilo.\nA: Das ist ein normales Gewicht.\nB: Ja, ich achte auf meine Gesundheit.",exampleSrc:"A: How much do you weigh?\nB: About 80 kilos.\nA: That is a normal weight.\nB: Yes, I pay attention to my health.",funFact:"Two different verbs that merged into one form. 'Wie viel wiegen Sie?' (How much do you weigh?). 'Das Baby wiegen' (to rock the baby). Context decides."},
{type:"mc",q:"Du siehst ein Etikett mit 'Gift' auf einer Flasche in der Apotheke. Was bedeutet es?",opts:["Present","Poison","Medicine","Supplement"],ans:"Poison",hint:"This is the most famous German-English false friend. Not a present!"},
{type:"fb",s:"Die Apotheke, {1} der ich meine Medizin hole, ist in der N\u00e4he.",a:["bei"],opts:["bei","mit","f\u00fcr","\u00fcber"],hint:"Which preposition means 'at' or 'from' when collecting something from a place?",sSrc:"The pharmacy I get my medicine from is nearby."},
{type:"drag_fill",s:"Der Patient, {1} dem die \u00c4rztin die Spritze gegeben hat, hatte Angst. {2} war er danach erleichtert.",blanks:{"1":"dem","2":"Trotzdem"},pool:["dem","den","der","Trotzdem","Deshalb","Sonst"],hint:"First blank: dative masculine relative pronoun. Second blank: contrast conjunction (despite that).",sSrc:"The patient the doctor gave the injection to was afraid. Nevertheless, he was relieved afterwards."},
{type:"mc",q:"Du hast Fieber. _____ solltest du zum Arzt gehen. Welches Wort bedeutet 'that is why'?",opts:["Trotzdem","Sonst","Deswegen","Also"],ans:"Deswegen",hint:"This conjunction shows direct consequence, similar to 'deshalb.'"},
{type:"match",pairs:[{trg:"Sucht",src:"addiction"},{trg:"Gift",src:"poison"},{trg:"Droge",src:"drug"},{trg:"Pflaster",src:"bandage"}]},
{type:"fb",s:"Nimm deine Medizin. {1} wird es schlimmer.",a:["Sonst"],opts:["Sonst","Deshalb","Trotzdem","Also"],hint:"Which conjunction means 'otherwise' and warns of a negative consequence?",sSrc:"Take your medicine. Otherwise it will get worse."}
]},

// ═══════════════════════════════════════════════════════════════
// Lesson 8: "Hildis Servietten-Diagramm" — Resolution + culture (18 words, 23 steps)
// Scene 4: Hildi explains the system
// ═══════════════════════════════════════════════════════════════
{id:"deu_r20l8",title:"Hildis Servietten-Diagramm",icon:"📝",xp:15,board:true,steps:[
{type:"intro",title:"Hildis Servietten-Diagramm",desc:"Hildi zeichnet das deutsche Gesundheitssystem auf eine Serviette. Es ist \u00fcberraschend klar. Lerne die letzten Vokabeln und wiederhole alle Grammatik.",goals:["Lerne die letzten Einheitsvokabeln","Verstehe das deutsche Gesundheitssystem durch Hildis Erkl\u00e4rung","Wiederhole Relativs\u00e4tze und Adverbialkonjunktionen"]},
{type:"story",speaker:"hildi",mood:"teaching",art:"de-ber-hildi-kitchen",trg:"Also, pass auf. Die Krankenkasse, bei der du versichert bist, ist die TK. Deshalb bekommst du eine Versichertenkarte. Damit gehst du zum Arzt.",src:"Alright, pay attention. The health insurance fund you are insured with is TK. Therefore you get an insurance card. You take that to the doctor."},
{type:"teach",trg:"die M\u00fcnze",src:"the coin",pos:"noun",gender:"f",note:"From Latin 'moneta' (mint).\nRelated to English 'money' and 'mint.'",example:"A: Hast du eine M\u00fcnze f\u00fcr den Automaten?\nB: Ja, hier ist eine 1-Euro-M\u00fcnze.\nA: Danke! Der Automat nimmt nur M\u00fcnzen.\nB: Kein Schein? Nur M\u00fcnzen?",exampleSrc:"A: Do you have a coin for the machine?\nB: Yes, here is a 1-euro coin.\nA: Thanks! The machine only takes coins.\nB: No bills? Only coins?",funFact:"German parking meters still love M\u00fcnzen. The 1-Euro-M\u00fcnze has country-specific designs on the back. Each country's coin tells a different story."},
{type:"teach",trg:"abheben",src:"to withdraw (money), to lift off",pos:"verb",gender:null,note:"Separable: 'Geld abheben' = to withdraw money.\nAlso: 'Das Flugzeug hebt ab' = the plane lifts off.",example:"A: Ich muss Geld abheben.\nB: Wo ist der n\u00e4chste Geldautomat?\nA: Um die Ecke. Ich hebe schnell 100 Euro ab.\nB: Gut, ich warte hier.",exampleSrc:"A: I need to withdraw money.\nB: Where is the nearest ATM?\nA: Around the corner. I will quickly withdraw 100 euros.\nB: Good, I will wait here.",funFact:"Money leaves the account; the plane leaves the ground. Same verb. Separable: 'Ich hebe 100 Euro ab.' The ab- prefix means away/off."},
{type:"teach",trg:"abnehmen",src:"to lose weight, to decrease, to pick up (phone)",pos:"verb",gender:null,note:"Separable: ab- (off/down) + nehmen (to take).\nThree meanings, all about taking something away.",example:"A: Ich m\u00f6chte f\u00fcnf Kilo abnehmen.\nB: Dann musst du weniger essen.\nA: Oder mehr Sport machen.\nB: Am besten beides!",exampleSrc:"A: I would like to lose five kilos.\nB: Then you need to eat less.\nA: Or exercise more.\nB: Best to do both!",funFact:"Three meanings, all about taking something away. 'F\u00fcnf Kilo abnehmen' (to lose five kilos). 'Den H\u00f6rer abnehmen' (to pick up the receiver). 'Die Kosten nehmen ab' (Costs are decreasing)."},
{type:"teach",trg:"zunehmen",src:"to gain weight, to increase",pos:"verb",gender:null,note:"The opposite of abnehmen.\nZu- (to/toward) + nehmen = to take on more.",example:"A: Im Winter nehme ich immer zu.\nB: Wie viel?\nA: Etwa zwei Kilo.\nB: Das ist nicht viel. Im Fr\u00fchling nimmst du wieder ab.",exampleSrc:"A: In winter I always gain weight.\nB: How much?\nA: About two kilos.\nB: That is not much. In spring you will lose it again.",funFact:"What goes up (zunehmen) can come down (abnehmen). 'Die Kosten nehmen zu' (Costs are increasing). The opposite twins of German weight and finance talk."},
{type:"teach",trg:"sich erk\u00e4lten",src:"to catch a cold",pos:"verb",gender:null,note:"Reflexive. Er- + kalt = to become cold.\nPerfekt: 'Ich habe mich erk\u00e4ltet.'",example:"A: Ich habe mich erk\u00e4ltet.\nB: Schon wieder? Zieh dich w\u00e4rmer an.\nA: Ja, es war zu kalt drau\u00dfen.\nB: Trink Tee und ruh dich aus.",exampleSrc:"A: I caught a cold.\nB: Again? Dress more warmly.\nA: Yes, it was too cold outside.\nB: Drink tea and rest.",funFact:"The verb form of Erk\u00e4ltung. Reflexive: 'sich erk\u00e4lten.' The Perfekt uses haben because it is reflexive. 'Ich habe mich erk\u00e4ltet' (I caught a cold)."},
{type:"teach",trg:"sich erholen",src:"to recover, to recuperate",pos:"verb",gender:null,note:"Reflexive. Er- + holen (to fetch).\nYou fetch yourself back from illness.",example:"A: Hast du dich von der Grippe erholt?\nB: Ja, ich habe mich gut erholt.\nA: Wie lange hat die Erholung gedauert?\nB: Etwa eine Woche.",exampleSrc:"A: Have you recovered from the flu?\nB: Yes, I have recovered well.\nA: How long did the recovery take?\nB: About a week.",funFact:"Beautiful metaphor: recovery is self-retrieval. You fetch yourself back from illness. 'Sich von einer Operation erholen' (to recover from an operation)."},
{type:"teach",trg:"die Erholung",src:"the recovery, the recreation",pos:"noun",gender:"f",note:"From erholen + -ung.\n'Erholungsurlaub' = recovery vacation. Kur may be prescribed.",example:"A: Du brauchst Erholung.\nB: Ja, ich bin ersch\u00f6pft.\nA: Nimm dir ein paar Tage Erholung.\nB: Der Arzt hat mir eine Kur verschrieben.",exampleSrc:"A: You need rest.\nB: Yes, I am exhausted.\nA: Take a few days of rest.\nB: The doctor prescribed me a health retreat.",funFact:"In Germany, your doctor can prescribe a Kur (health retreat) for Erholung. The Krankenkasse may pay. Recovery is a medical right, not a luxury."},
{type:"teach",trg:"sch\u00e4tzen",src:"to estimate, to value, to appreciate",pos:"verb",gender:null,note:"Three meanings in one verb.\n'Gesch\u00e4tzt' = approximately.",example:"A: Ich sch\u00e4tze die Kosten auf 500 Euro.\nB: Das ist eine grobe Sch\u00e4tzung.\nA: Ja, aber ich sch\u00e4tze, es wird nicht mehr.\nB: Ich sch\u00e4tze deine Ehrlichkeit.",exampleSrc:"A: I estimate the costs at 500 euros.\nB: That is a rough estimate.\nA: Yes, but I estimate it will not be more.\nB: I appreciate your honesty.",funFact:"Three meanings in one verb. 'Die Kosten sch\u00e4tzen' (to estimate costs). 'Ich sch\u00e4tze deine Hilfe' (I appreciate your help). A word of judgment and gratitude."},
{type:"teach",trg:"verteilen",src:"to distribute",pos:"verb",gender:null,note:"Ver- + teilen (to share/divide). Inseparable.\n'Die Kosten werden verteilt.'",example:"A: Wer verteilt die Medikamente?\nB: Die Pflegerin verteilt sie.\nA: Wie werden die Kosten verteilt?\nB: Auf alle Versicherten gleichm\u00e4\u00dfig.",exampleSrc:"A: Who distributes the medicine?\nB: The caregiver distributes them.\nA: How are the costs distributed?\nB: Equally among all insured persons.",funFact:"The system distributes everything. 'Medikamente verteilen' (to distribute medicine). 'Die Kosten werden verteilt' (The costs are distributed). Inseparable prefix ver-."},
{type:"teach",trg:"behindern",src:"to hinder, to obstruct",pos:"verb",gender:null,note:"Be- + hindern (to prevent).\n'Menschen mit Behinderung' = people with disabilities.",example:"A: Der Unfall behindert den Verkehr.\nB: Wie lange noch?\nA: Etwa eine Stunde.\nB: Dann nehme ich einen anderen Weg.",exampleSrc:"A: The accident is obstructing traffic.\nB: For how much longer?\nA: About an hour.\nB: Then I will take another route.",funFact:"'Behindert' as an adjective means 'disabled.' 'Menschen mit Behinderung' (people with disabilities) is the preferred modern phrase."},
{type:"teach",trg:"st\u00fcrzen",src:"to fall, to crash",pos:"verb",gender:null,note:"'Er ist gest\u00fcrzt' = he fell.\nAlso: 'die Regierung st\u00fcrzen' = to topple the government.",example:"A: Was ist passiert?\nB: Er ist von der Leiter gest\u00fcrzt.\nA: Ist er verletzt?\nB: Ja, er hat sich den Arm gebrochen.",exampleSrc:"A: What happened?\nB: He fell from the ladder.\nA: Is he injured?\nB: Yes, he broke his arm.",funFact:"Falls in medicine, revolutions in politics. Same verb. 'Vom Fahrrad st\u00fcrzen' (to fall off the bicycle). 'Die Regierung st\u00fcrzen' (to topple the government)."},
{type:"teach",trg:"die Ordination",src:"the doctor's office (Austrian)",pos:"noun",gender:"f",note:"Austrian German. In Germany: 'Arztpraxis.'\nKnowing both words helps across German-speaking countries.",example:"A: Wo ist die Ordination?\nB: In Wien sagt man Ordination.\nA: In Deutschland sagt man Arztpraxis.\nB: Ja, gleiche Sache, anderes Wort.",exampleSrc:"A: Where is the doctor's office?\nB: In Vienna they say Ordination.\nA: In Germany they say Arztpraxis.\nB: Yes, same thing, different word.",funFact:"Austrian German. In Germany: 'Arztpraxis.' Regional vocabulary: knowing both words helps across German-speaking countries. Austria, Germany, and Switzerland all speak differently."},
{type:"teach",trg:"befreit",src:"exempt, freed",pos:"adj",gender:null,note:"From 'befreien' (to free).\n'Von der Zuzahlung befreit' = exempt from co-payment.",example:"A: Sind Sie von der Zuzahlung befreit?\nB: Ja, ich bin befreit.\nA: Dann m\u00fcssen Sie nichts extra zahlen.\nB: Gut, ich habe den Befreiungsausweis dabei.",exampleSrc:"A: Are you exempt from the co-payment?\nB: Yes, I am exempt.\nA: Then you do not have to pay anything extra.\nB: Good, I have the exemption card with me.",funFact:"In the insurance context: certain groups are befreit from paying extra. Low-income patients, children, and chronically ill people may be befreit von der Zuzahlung."},
{type:"teach",trg:"befriedigend",src:"satisfactory",pos:"adj",gender:null,note:"From 'befriedigen' (to satisfy).\nAlso a school grade: 3 = befriedigend.",example:"A: Wie war die Behandlung?\nB: Befriedigend. Nicht schlecht, nicht gro\u00dfartig.\nA: Also Note drei?\nB: Ja, genau. Befriedigend.",exampleSrc:"A: How was the treatment?\nB: Satisfactory. Not bad, not great.\nA: So grade three?\nB: Yes, exactly. Satisfactory.",funFact:"Also a school grade in Germany (3 = befriedigend). Not great, not terrible. The German grade of adequacy. 'Eine befriedigende L\u00f6sung' (a satisfactory solution)."},
{type:"teach",trg:"kr\u00e4ftig",src:"strong, powerful, hearty",pos:"adj",gender:null,note:"From 'Kraft' (strength/force).\n'Kr\u00e4ftig essen' = to eat heartily.",example:"A: Du siehst kr\u00e4ftig aus!\nB: Danke, ich trainiere viel.\nA: Und isst du kr\u00e4ftig?\nB: Ja, eine kr\u00e4ftige Suppe zum Mittag.",exampleSrc:"A: You look strong!\nB: Thanks, I train a lot.\nA: And do you eat heartily?\nB: Yes, a hearty soup for lunch.",funFact:"Conveys robust, physical strength. 'Eine kr\u00e4ftige Suppe' (a hearty soup). German comfort food is kr\u00e4ftig. From 'Kraft' (strength/force)."},
{type:"teach",trg:"parallel",src:"parallel",pos:"adj",gender:null,note:"Same in most European languages.\n'Die gesetzliche und private Versicherung laufen parallel.'",example:"A: Die beiden Systeme laufen parallel.\nB: Das gesetzliche und das private?\nA: Ja, parallel nebeneinander.\nB: Und welches ist besser?",exampleSrc:"A: The two systems run in parallel.\nB: The public and the private one?\nA: Yes, parallel to each other.\nB: And which one is better?",funFact:"In insurance: 'Die gesetzliche und private Versicherung laufen parallel' (public and private insurance run in parallel). Germany's dual healthcare system."},
{type:"teach",trg:"der Mangel",src:"the lack, the deficiency",pos:"noun",gender:"m",note:"'Fachkr\u00e4ftemangel' = shortage of skilled workers.\n'Mangelware' = scarce commodity.",example:"A: Es gibt einen Mangel an Pflegern.\nB: Ja, der Pflegermangel ist ein gro\u00dfes Problem.\nA: Was kann man dagegen tun?\nB: Bessere Bezahlung und mehr Ausbildungspl\u00e4tze.",exampleSrc:"A: There is a shortage of caregivers.\nB: Yes, the caregiver shortage is a big problem.\nA: What can be done about it?\nB: Better pay and more training positions.",funFact:"Germany's healthcare system suffers from Pflegermangel (caregiver shortage). 'Fachkr\u00e4ftemangel' (shortage of skilled workers) is a national concern across many sectors."},
{type:"teach",trg:"die Badewanne",src:"the bathtub",pos:"noun",gender:"f",note:"Bade (bathing) + Wanne (tub).\nHaving a Badewanne instead of just a Dusche is a luxury.",example:"A: Hat die Wohnung eine Badewanne?\nB: Ja, eine gro\u00dfe Badewanne.\nA: Toll! Ich liebe es, in der Badewanne zu liegen.\nB: Die Badewanne ist fast neu.",exampleSrc:"A: Does the apartment have a bathtub?\nB: Yes, a large bathtub.\nA: Great! I love lying in the bathtub.\nB: The bathtub is almost new.",funFact:"In German apartments, having a Badewanne instead of just a Dusche is a luxury. Insurance covers bath aids for elderly patients. Bathing is healthcare in Germany."},
{type:"story",speaker:"hildi",mood:"warm",art:"de-ber-hildi-kitchen",trg:"Verumius nickt langsam. Das System, in das er eingezahlt hat, sch\u00fctzt ihn jetzt. Trotzdem versteht er die Formulare immer noch nicht. Also zeichnet Hildi ein neues Diagramm.",src:"Verumius nods slowly. The system he has paid into now protects him. Nevertheless, he still does not understand the forms. So Hildi draws a new diagram."},
{type:"mc",q:"Hildi sagt: 'Die Krankenkasse, _____ du jeden Monat zahlst, hilft dir im Notfall.' Was passt?",opts:["an der","an die","an den","an dem"],ans:"an die",hint:"zahlen an + accusative. Krankenkasse is feminine. What is the feminine accusative?"},
{type:"drag_fill",s:"Das Altenheim, in {1} meine Oma wohnt, ist sehr gut. {2} besuche ich sie oft.",blanks:{"1":"dem","2":"Deshalb"},pool:["dem","der","das","Deshalb","Trotzdem","Sonst"],hint:"First blank: in + dative, neuter Altenheim. Second blank: consequence conjunction.",sSrc:"The nursing home my grandma lives in is very good. Therefore I visit her often."}
]}

]},

{n:21,lang:"de",srcLang:"en",track:"v2",title:"Ost und West",sub:"Leipzig, reunification, Nikolaikirche, adjective declension without articles, reciprocal verbs",icon:"\uD83C\uDFDB\uFE0F",level:"B1.2",color:"#7B5EE8",lessons:[

// Lesson 1: Leipzig Hauptbahnhof (Story intro, 22 steps, 16 new words)
{id:"deu_r21l1",title:"Leipzig Hauptbahnhof",icon:"\uD83D\uDE89",xp:15,board:true,steps:[
{type:"intro",title:"Leipzig Hauptbahnhof",desc:"Travel with Mia to Leipzig. Learn vocabulary for history, society, and change. Discover the story of German reunification.",goals:["Learn 16 key words about history and society","Join Mia in her hometown Leipzig","Discover the history of German reunification"]},
{type:"story",speaker:"narrator",mood:"excited",art:"de-lei-hbf",trg:"Der ICE h\u00e4lt in Leipzig. Mia steht schon an der T\u00fcr, bevor der Zug steht. Sie hat Verumius seit Wochen von ihrer Stadt erz\u00e4hlt. Jetzt ist er endlich hier.",src:"The ICE stops in Leipzig. Mia is already at the door before the train has stopped. She has been telling Verumius about her city for weeks. Now he is finally here."},
{type:"story",speaker:"mia",mood:"proud",art:"de-lei-hbf",trg:"Das ist Leipzig Hauptbahnhof! Einer der gr\u00f6\u00dften Bahnh\u00f6fe Europas. Frisch renoviert, mit Gesch\u00e4ften drin. Fr\u00fcher war das hier alles grau.",src:"This is Leipzig Central Station! One of the largest train stations in Europe. Freshly renovated, with shops inside. It all used to be grey here."},
{type:"teach",trg:"die Grenze",src:"the border, the boundary",pos:"noun",gender:"f",note:"From Old High German greniza, borrowed from Slavic.\nThe most famous German Grenze split the country from 1949 to 1989.",example:"A: Wo war fr\u00fcher die Grenze?\nB: Mitten durch Berlin. Mitten durch Deutschland.\nA: Kann man die Grenze noch sehen?\nB: An manchen Stellen ja. Es gibt Gedenkst\u00e4tten.",exampleSrc:"A: Where was the border before?\nB: Right through Berlin. Right through Germany.\nA: Can you still see the border?\nB: In some places yes. There are memorial sites.",funFact:"Grenzenlos (boundless) became a symbol of reunification. When the Grenze fell, people danced on the wall. The inner-German border was 1,393 km long with fences, mines, and watchtowers."},
{type:"teach",trg:"die Mauer",src:"the wall",pos:"noun",gender:"f",note:"From Latin murus. Die Berliner Mauer stood from 1961 to 1989.\nWhen Germans say die Mauer, everyone knows which wall.",example:"A: Hast du die Mauer gesehen?\nB: Nein, ich bin zu jung. Aber meine Oma erinnert sich.\nA: Wie war das, als die Mauer fiel?\nB: Sie sagt, sie hat geweint vor Freude.",exampleSrc:"A: Did you see the Wall?\nB: No, I am too young. But my grandma remembers.\nA: What was it like when the Wall fell?\nB: She says she cried with joy.",funFact:"Mauerfall (fall of the wall) needs no further explanation in German. The Berlin Wall fell on November 9, 1989. Pieces of the Wall are now sold as souvenirs worldwide."},
{type:"teach",trg:"die Freiheit",src:"freedom",pos:"noun",gender:"f",note:"Frei (free) + -heit (abstract suffix).\nThe word that echoed through Nikolaikirche in 1989.",example:"A: Was bedeutet Freiheit f\u00fcr dich?\nB: Sagen zu k\u00f6nnen, was ich denke.\nA: Und f\u00fcr die Menschen in der DDR?\nB: Reisen zu d\u00fcrfen. W\u00e4hlen zu d\u00fcrfen.",exampleSrc:"A: What does freedom mean to you?\nB: Being able to say what I think.\nA: And for the people in the GDR?\nB: Being allowed to travel. Being allowed to vote.",funFact:"Freiheit was the single most powerful word of the peaceful revolution. Leipzig calls itself Heldenstadt (hero city) because of it. 70,000 people marched for Freiheit with candles in October 1989."},
{type:"teach",trg:"die Gesellschaft",src:"society",pos:"noun",gender:"f",note:"From Geselle (companion) + -schaft.\nLiterally: companionship. Covers social structures and business.",example:"A: Was ist eine Gesellschaft?\nB: Alle Menschen, die zusammen leben.\nA: Und eine GmbH?\nB: Das ist eine Gesellschaft mit beschr\u00e4nkter Haftung. Ein Unternehmen.",exampleSrc:"A: What is a Gesellschaft?\nB: All people who live together.\nA: And a GmbH?\nB: That is a company with limited liability. A business.",funFact:"A GmbH (Gesellschaft mit beschr\u00e4nkter Haftung) is a company with limited liability. The word covers both grand social structures and small business partnerships. Over 500,000 GmbHs exist in Germany."},
{type:"teach",trg:"historisch",src:"historical",pos:"adj",gender:null,note:"From Greek historikos. Germans distinguish historisch\n(historically significant) from geschichtlich (relating to history as a discipline).",example:"A: Ist Leipzig eine historische Stadt?\nB: Ja, sehr. Hier hat Bach gearbeitet.\nA: Und die Nikolaikirche?\nB: Historisch! Dort begann die friedliche Revolution.",exampleSrc:"A: Is Leipzig a historic city?\nB: Yes, very. Bach worked here.\nA: And the Nikolaikirche?\nB: Historic! The peaceful revolution began there.",funFact:"Leipzig is historisch because history happened here: Bach composed, Goethe wrote Faust at Auerbachs Keller, and the 1989 peaceful revolution started at Nikolaikirche."},
{type:"teach",trg:"politisch",src:"political",pos:"adj",gender:null,note:"From Greek politikos (of citizens).\nPolitische Bildung (political education) is taught in every German school.",example:"A: Ist das eine politische Frage?\nB: Ja, es geht um die Wiedervereinigung.\nA: War Leipzig politisch wichtig?\nB: Sehr. Die Montagsdemonstrationen begannen hier.",exampleSrc:"A: Is that a political question?\nB: Yes, it is about reunification.\nA: Was Leipzig politically important?\nB: Very. The Monday demonstrations began here.",funFact:"Politisch korrekt entered German from English. Germans debate politics with passion. Politische Bildung (political education) is a mandatory school subject designed to prevent history from repeating."},
{type:"teach",trg:"national",src:"national",pos:"adj",gender:null,note:"German national identity is complicated. After 1945, national\nbecame a loaded word. It coexists carefully with European identity.",example:"A: Gibt es ein deutsches Nationalgef\u00fchl?\nB: Ja, aber es ist kompliziert nach der Geschichte.\nA: Wann zeigen Deutsche Nationalstolz?\nB: Meistens bei der Fu\u00dfball-WM. Da ist es okay.",exampleSrc:"A: Is there a German national feeling?\nB: Yes, but it is complicated after history.\nA: When do Germans show national pride?\nB: Mostly at the football World Cup. Then it is okay.",funFact:"Nationalmannschaft (national team) is one of the few safe contexts for national in German. After 1945, the word carried so much weight that Germans developed a careful, reflective relationship with national identity."},
{type:"teach",trg:"die Erinnerung",src:"the memory, the remembrance",pos:"noun",gender:"f",note:"Er- + inner (inner) + -ung. To bring something inward again.\nErinnerungskultur (remembrance culture) is a core German value.",example:"A: Hast du Erinnerungen an die DDR?\nB: Nein, ich bin zu jung. Aber meine Familie erinnert sich.\nA: Sind die Erinnerungen gut oder schlecht?\nB: Beides. Es war kompliziert.",exampleSrc:"A: Do you have memories of the GDR?\nB: No, I am too young. But my family remembers.\nA: Are the memories good or bad?\nB: Both. It was complicated.",funFact:"Erinnerungskultur (remembrance culture) defines how Germany confronts its past through memorials, museums, and education. Germany has over 1,200 Holocaust memorials. Remembering is not optional."},
{type:"teach",trg:"die Vergangenheit",src:"the past",pos:"noun",gender:"f",note:"From vergangen (gone by). Ver- + gangen (gone).\nThe past that has gone away.",example:"A: Die Vergangenheit ist wichtig.\nB: Ja, man muss aus ihr lernen.\nA: Sprechen Deutsche oft \u00fcber die Vergangenheit?\nB: Ja, besonders \u00fcber die Zeit nach 1945.",exampleSrc:"A: The past is important.\nB: Yes, one must learn from it.\nA: Do Germans often talk about the past?\nB: Yes, especially about the time after 1945.",funFact:"Vergangenheitsbew\u00e4ltigung (coming to terms with the past) is a famously long German word for a famously difficult process. It describes how a society processes and comes to terms with its own history."},
{type:"teach",trg:"die Entwicklung",src:"the development",pos:"noun",gender:"f",note:"From entwickeln (to develop). Ent- (out of) + wickeln (to wrap).\nLiterally: unwrapping. Development is an unwrapping of potential.",example:"A: Wie war die Entwicklung nach 1989?\nB: Schnell, aber nicht immer einfach.\nA: Was hat sich entwickelt?\nB: Die Wirtschaft, die Infrastruktur, die ganze Gesellschaft.",exampleSrc:"A: How was the development after 1989?\nB: Fast, but not always easy.\nA: What developed?\nB: The economy, the infrastructure, the whole society.",funFact:"Entwicklungsland (developing country) uses the same logic: a land that is unwrapping its potential. After reunification, East Germany went through the largest Entwicklung in European peacetime history."},
{type:"teach",trg:"entstehen",src:"to arise, to come into being",pos:"verb",gender:null,note:"Ent- (out of) + stehen (to stand). Something standing\nforth into existence. Perfekt: ist entstanden.",example:"A: Wann ist Leipzig entstanden?\nB: Im 12. Jahrhundert als Handelsstadt.\nA: Und die Universit\u00e4t?\nB: Die ist 1409 entstanden. Eine der \u00e4ltesten in Deutschland.",exampleSrc:"A: When did Leipzig come into being?\nB: In the 12th century as a trading city.\nA: And the university?\nB: It was founded in 1409. One of the oldest in Germany.",funFact:"Die Stadt ist im 12. Jahrhundert entstanden is how Germans describe a city's birth. Entstehen implies organic growth rather than deliberate founding. Cities entstehen. Companies werden gegr\u00fcndet (are founded)."},
{type:"teach",trg:"erleben",src:"to experience",pos:"verb",gender:null,note:"Er- (achieving prefix) + leben (to live). To truly live\nthrough something. Stronger than Erfahrung (experience gained over time).",example:"A: Was hast du in Leipzig erlebt?\nB: Ich habe die Nikolaikirche besucht. Das war sehr bewegend.\nA: M\u00f6chtest du mehr erleben?\nB: Ja! Mia will mir noch viel zeigen.",exampleSrc:"A: What did you experience in Leipzig?\nB: I visited the Nikolaikirche. That was very moving.\nA: Would you like to experience more?\nB: Yes! Mia wants to show me a lot more.",funFact:"Ein Erlebnis (an experience) is something you actively lived through. It is stronger than Erfahrung (experience gained gradually). Germans value Erlebnisse: the moments that stay with you forever."},
{type:"teach",trg:"erfahren",src:"to find out, to experience",pos:"verb",gender:null,note:"Er- + fahren (to drive/travel). Literally: to travel toward\nknowledge. Also an adjective: ein erfahrener Arzt (an experienced doctor).",example:"A: Hast du von der Geschichte der Nikolaikirche erfahren?\nB: Ja, Mia hat mir alles erz\u00e4hlt.\nA: Wie hast du davon erfahren?\nB: Sie hat es mir auf der Zugfahrt erz\u00e4hlt.",exampleSrc:"A: Did you find out about the history of the Nikolaikirche?\nB: Yes, Mia told me everything.\nA: How did you find out about it?\nB: She told me about it on the train ride.",funFact:"Erfahren works as both verb and adjective. As a verb: Ich habe erfahren, dass... (I found out that...). As an adjective: ein erfahrener Arzt (an experienced doctor). Travel (fahren) leads to knowledge."},
{type:"teach",trg:"\u00fcberhaupt",src:"at all, in general",pos:"adv",gender:null,note:"One of German's most versatile words. Adds emphasis,\ndoubt, or generalization depending on context.",example:"A: Verstehst du \u00fcberhaupt, was hier passiert ist?\nB: Nicht ganz. Erz\u00e4hl mir mehr.\nA: \u00dcberhaupt ist Leipzig eine besondere Stadt.\nB: Das merke ich. Sie hat so viel Geschichte.",exampleSrc:"A: Do you understand at all what happened here?\nB: Not entirely. Tell me more.\nA: In general, Leipzig is a special city.\nB: I can tell. It has so much history.",funFact:"Hast du \u00fcberhaupt verstanden? (Did you understand at all?) adds emphasis. \u00dcberhaupt nicht (not at all) is a strong negation. The word shifts meaning with context: emphasis, doubt, or generalization."},
{type:"teach",trg:"vor allem",src:"above all, especially",pos:"adv",gender:null,note:"Literally: before everything. A connector that signals\nwhat matters most in a statement.",example:"A: Was gef\u00e4llt dir an Leipzig?\nB: Vor allem die Geschichte. Und die Architektur.\nA: Und das Essen?\nB: Ja, auch. Aber vor allem die Atmosph\u00e4re.",exampleSrc:"A: What do you like about Leipzig?\nB: Above all the history. And the architecture.\nA: And the food?\nB: Yes, that too. But above all the atmosphere.",funFact:"Leipzig ist sch\u00f6n, aber vor allem ist es historisch. Vor allem marks what matters most. Germans use it to prioritize in conversation: the thing after vor allem is the real point."},
{type:"teach",trg:"urspr\u00fcnglich",src:"original(ly)",pos:"adj",gender:null,note:"From Ursprung (origin). Ur- (primal/original) + Sprung (leap).\nThe primal leap, the very beginning.",example:"A: Was war Leipzig urspr\u00fcnglich?\nB: Eine Handelsstadt. Seit dem Mittelalter.\nA: Und heute?\nB: Immer noch. Aber vor allem eine Kulturstadt.",exampleSrc:"A: What was Leipzig originally?\nB: A trading city. Since the Middle Ages.\nA: And today?\nB: Still. But above all a cultural city.",funFact:"Urspr\u00fcnglich wollte ich... (Originally I wanted to...) is how Germans preface changed plans. The Ur- prefix means primal or original. Urlaub (vacation) literally means primal-leave: the original permission to be away."},
{type:"mc",q:"Leipzig nennt sich Heldenstadt. Wof\u00fcr k\u00e4mpften die Menschen 1989?",opts:["Erinnerung","Freiheit","Gesellschaft","Grenze"],ans:"Freiheit",hint:"Dieses Wort bedeutet freedom, gebaut aus frei + -heit."},
{type:"fb",s:"Die Berliner {1} fiel am 9. November 1989.",a:["Mauer"],opts:["Mauer","Grenze","Freiheit","Gesellschaft"],hint:"Welches Wort bedeutet wall, die ber\u00fchmte in Berlin?",sSrc:"The Berlin Wall fell on November 9, 1989."},
{type:"match",pairs:[{trg:"Grenze",src:"border"},{trg:"Freiheit",src:"freedom"},{trg:"Erinnerung",src:"memory"},{trg:"Vergangenheit",src:"past"}]}
]},

// Lesson 2: Stimmen der Geschichte (Vocab teach, 24 steps, 18 new words)
{id:"deu_r21l2",title:"Stimmen der Geschichte",icon:"\uD83D\uDDE3\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Stimmen der Geschichte",desc:"Learn vocabulary for politics, civic life, and social structures. Build the words you need to discuss history and current events in German.",goals:["Learn 18 words about politics and society","Discuss civic participation in German","Understand news vocabulary"]},
{type:"teach",trg:"die Bev\u00f6lkerung",src:"the population",pos:"noun",gender:"f",note:"From Volk (people). Be- + v\u00f6lker + -ung.\nThe process of populating, and the population itself.",example:"A: Wie gro\u00df ist die Bev\u00f6lkerung Deutschlands?\nB: Etwa 84 Millionen.\nA: Und Leipzigs?\nB: Ungef\u00e4hr 600.000. Die Stadt w\u00e4chst.",exampleSrc:"A: How large is the population of Germany?\nB: About 84 million.\nA: And Leipzig's?\nB: About 600,000. The city is growing.",funFact:"Die Bev\u00f6lkerung Deutschlands is about 84 million. One word for both the people and the act of peopling a land. After reunification, the Bev\u00f6lkerung of the former East shrank as millions moved west."},
{type:"teach",trg:"der B\u00fcrger",src:"the citizen (male)",pos:"noun",gender:"m",note:"From Burg (castle/fortress). Originally the people who lived\ninside the castle walls. B\u00fcrgerrecht = civil right.",example:"A: Was ist ein B\u00fcrger?\nB: Jemand mit Rechten und Pflichten in einem Staat.\nA: Die B\u00fcrger Leipzigs waren mutig.\nB: Ja, sie haben 1989 f\u00fcr ihre Rechte gek\u00e4mpft.",exampleSrc:"A: What is a citizen?\nB: Someone with rights and duties in a state.\nA: The citizens of Leipzig were brave.\nB: Yes, they fought for their rights in 1989.",funFact:"B\u00fcrgermeister (mayor) literally means citizen-master. English burgess is a cousin. The 1989 Leipzig demonstrators chanted Wir sind das Volk! (We are the people!), claiming their rights as B\u00fcrger."},
{type:"teach",trg:"die B\u00fcrgerin",src:"the citizen (female)",pos:"noun",gender:"f",note:"The -in suffix marks the feminine form.\nB\u00fcrgerinnen und B\u00fcrger is the standard inclusive phrasing.",example:"A: Ist sie eine Leipziger B\u00fcrgerin?\nB: Ja, sie ist hier geboren und aufgewachsen.\nA: Was bedeutet ihr die Stadt?\nB: Alles. Sie ist eine stolze Leipzigerin.",exampleSrc:"A: Is she a Leipzig citizen?\nB: Yes, she was born and raised here.\nA: What does the city mean to her?\nB: Everything. She is a proud Leipzigerin.",funFact:"B\u00fcrgerinnen und B\u00fcrger is the standard inclusive phrasing in official German. The -in ending is mandatory in formal contexts for all professional and civic titles."},
{type:"teach",trg:"die Gewalt",src:"violence, power",pos:"noun",gender:"f",note:"From walten (to rule). One word, two meanings:\nGewalt anwenden = to use violence. Gewaltenteilung = separation of powers.",example:"A: Gab es Gewalt bei den Demonstrationen?\nB: Nein! Das ist das Besondere. Keine Gewalt.\nA: Wie ist das m\u00f6glich?\nB: Die Menschen hatten nur Kerzen. Keine Waffen.",exampleSrc:"A: Was there violence at the demonstrations?\nB: No! That is what makes it special. No violence.\nA: How is that possible?\nB: The people only had candles. No weapons.",funFact:"The Leipzig revolution was remarkable because it succeeded ohne Gewalt (without violence). Gewalt means both violence and power. Gewaltenteilung (separation of powers) is the foundation of the German constitution."},
{type:"teach",trg:"der Krieg",src:"the war",pos:"noun",gender:"m",note:"From Old High German chreg (stubbornness/effort).\nDer Kalte Krieg (the Cold War) divided Germany.",example:"A: Was war der Kalte Krieg?\nB: Ein Konflikt zwischen Ost und West. Ohne direkten Kampf.\nA: Wie lange dauerte er?\nB: Ungef\u00e4hr 45 Jahre. Von 1945 bis 1990.",exampleSrc:"A: What was the Cold War?\nB: A conflict between East and West. Without direct fighting.\nA: How long did it last?\nB: About 45 years. From 1945 to 1990.",funFact:"Nachkriegszeit (post-war period) shaped everything about modern Germany. A short, heavy word. Krieg carries the weight of two World Wars and the Cold War that divided Germany for 40 years."},
{type:"teach",trg:"der Friede",src:"peace",pos:"noun",gender:"m",note:"Also spelled Frieden (both forms are correct).\nFrom Proto-Germanic frithuz (protection).",example:"A: Was bedeutet Friede f\u00fcr Leipzig?\nB: Alles. Die Friedensgebete in der Nikolaikirche begannen alles.\nA: Friedensgebete?\nB: Ja, Gebete f\u00fcr den Frieden. Jeden Montag.",exampleSrc:"A: What does peace mean for Leipzig?\nB: Everything. The peace prayers at the Nikolaikirche started everything.\nA: Peace prayers?\nB: Yes, prayers for peace. Every Monday.",funFact:"Friedensgebet (peace prayer) was what started the 1989 movement at Nikolaikirche. Friedlich (peaceful) describes how Leipzig changed the world. Friede and Frieden are both correct forms."},
{type:"teach",trg:"der Kampf",src:"the fight, the struggle",pos:"noun",gender:"m",note:"From Latin campus (battlefield). Not always physical:\nKampf gegen den Klimawandel (fight against climate change).",example:"A: War es ein Kampf?\nB: Ja, ein Kampf um Freiheit. Aber ohne Gewalt.\nA: Wie k\u00e4mpft man ohne Gewalt?\nB: Mit Worten, mit Kerzen, mit Mut.",exampleSrc:"A: Was it a fight?\nB: Yes, a fight for freedom. But without violence.\nA: How do you fight without violence?\nB: With words, with candles, with courage.",funFact:"Kampf um Freiheit (fight for freedom) is one of the most emotionally charged phrases in German. The word serves both physical and abstract struggles. Leipzig's Kampf was won with candles, not weapons."},
{type:"teach",trg:"die Reform",src:"the reform",pos:"noun",gender:"f",note:"From Latin reformare (to reshape).\nReformen durchf\u00fchren = to carry out reforms.",example:"A: Was wollten die Menschen 1989?\nB: Reformen. Mehr Freiheit, freie Wahlen.\nA: Wollten sie die DDR abschaffen?\nB: Anfangs nicht. Zuerst wollten sie nur Reformen.",exampleSrc:"A: What did the people want in 1989?\nB: Reforms. More freedom, free elections.\nA: Did they want to abolish the GDR?\nB: Not at first. At first they only wanted reforms.",funFact:"The 1989 movement started as a call for Reform, not reunification. History took its own course. Reformen durchf\u00fchren (to carry out reforms) is what politicians promise and what the people of Leipzig demanded."},
{type:"teach",trg:"die Wahl",src:"the election, the choice",pos:"noun",gender:"f",note:"From w\u00e4hlen (to choose). Freie Wahlen was a key demand\nof the 1989 demonstrators.",example:"A: Was bedeutet Wahl?\nB: Eine Entscheidung. Oder eine politische Abstimmung.\nA: Die erste freie Wahl in der DDR?\nB: M\u00e4rz 1990. Ein historischer Moment.",exampleSrc:"A: What does Wahl mean?\nB: A decision. Or a political vote.\nA: The first free election in the GDR?\nB: March 1990. A historic moment.",funFact:"Freie Wahlen (free elections) was a key demand of the 1989 demonstrators. Die Qual der Wahl (the agony of choice) is a German rhyming idiom for having too many options. Voter turnout in Germany regularly exceeds 70%."},
{type:"teach",trg:"die Politik",src:"politics",pos:"noun",gender:"f",note:"From Greek politike (civic affairs). No plural form.\nIn die Politik gehen = to go into politics.",example:"A: Interessierst du dich f\u00fcr Politik?\nB: Ja, seit ich in Leipzig war. Die Geschichte ist faszinierend.\nA: Politik ist in Deutschland wichtig.\nB: Ja, die Wahlbeteiligung ist sehr hoch.",exampleSrc:"A: Are you interested in politics?\nB: Yes, since I was in Leipzig. The history is fascinating.\nA: Politics is important in Germany.\nB: Yes, voter turnout is very high.",funFact:"Germans take their Politik seriously: voter turnout regularly exceeds 70%. In die Politik gehen (to go into politics) is a respected choice. Political education is mandatory in German schools."},
{type:"teach",trg:"der Politiker",src:"the politician (male)",pos:"noun",gender:"m",note:"Politik + -er. Ein erfahrener Politiker uses adjective\ndeclension you will learn this unit.",example:"A: Wer war ein wichtiger Politiker der Wiedervereinigung?\nB: Helmut Kohl. Er war Bundeskanzler.\nA: Und aus Leipzig?\nB: Viele B\u00fcrgerrechtler wurden sp\u00e4ter Politiker.",exampleSrc:"A: Who was an important politician of reunification?\nB: Helmut Kohl. He was Federal Chancellor.\nA: And from Leipzig?\nB: Many civil rights activists later became politicians.",funFact:"German political titles are long: Bundestagsabgeordneter (member of the Bundestag) has 24 letters. Ein erfahrener Politiker uses the adjective declension pattern you will learn in this unit."},
{type:"teach",trg:"die Politikerin",src:"the politician (female)",pos:"noun",gender:"f",note:"The -in suffix is standard, not optional, in formal German\nfor all professional titles.",example:"A: Gibt es viele Politikerinnen in Deutschland?\nB: Ja, immer mehr. Deutschland hatte eine Kanzlerin.\nA: Wer war das?\nB: Angela Merkel. Sie regierte 16 Jahre.",exampleSrc:"A: Are there many female politicians in Germany?\nB: Yes, more and more. Germany had a female Chancellor.\nA: Who was that?\nB: Angela Merkel. She governed for 16 years.",funFact:"Germany has had a female Chancellor (Bundeskanzlerin) and numerous female ministers. The -in ending is standard, not optional, in formal German for all professional titles."},
{type:"teach",trg:"die Rede",src:"the speech",pos:"noun",gender:"f",note:"From reden (to speak/talk). Eine Rede halten = to give a speech.\nRedefreiheit = freedom of speech.",example:"A: Hat jemand eine Rede gehalten?\nB: Ja, der Pfarrer in der Nikolaikirche.\nA: Wor\u00fcber?\nB: \u00dcber Frieden und Gewaltlosigkeit.",exampleSrc:"A: Did someone give a speech?\nB: Yes, the pastor at the Nikolaikirche.\nA: About what?\nB: About peace and nonviolence.",funFact:"Wovon ist die Rede? (What are we talking about?) is everyday German. Redefreiheit (freedom of speech) was one of the rights the 1989 demonstrators fought for. A Rede is both a formal speech and any topic of conversation."},
{type:"teach",trg:"die \u00d6ffentlichkeit",src:"the public, publicity",pos:"noun",gender:"f",note:"From \u00f6ffentlich (public). Offen (open) + -lich + -keit.\nTriple suffix chain. The space where citizens and government meet.",example:"A: War die Revolution \u00f6ffentlich?\nB: Ja, sie fand in der \u00d6ffentlichkeit statt.\nA: Konnte jeder zusehen?\nB: Ja. Die ganze Welt hat zugesehen.",exampleSrc:"A: Was the revolution public?\nB: Yes, it took place in public.\nA: Could everyone watch?\nB: Yes. The whole world was watching.",funFact:"In der \u00d6ffentlichkeit (in public) is where citizens and government meet. Die \u00d6ffentlichkeit informieren (to inform the public) was impossible in the DDR. The 1989 revolution brought everything into the \u00d6ffentlichkeit."},
{type:"teach",trg:"\u00f6ffentlich",src:"public",pos:"adj",gender:null,note:"From offen (open). \u00d6ffentliche Verkehrsmittel = public transport.\n\u00d6ffentliche Meinung = public opinion.",example:"A: Ist das eine \u00f6ffentliche Veranstaltung?\nB: Ja, jeder kann kommen.\nA: Gibt es \u00f6ffentliche Verkehrsmittel?\nB: Ja, die Stra\u00dfenbahn f\u00e4hrt direkt dorthin.",exampleSrc:"A: Is that a public event?\nB: Yes, everyone can come.\nA: Is there public transport?\nB: Yes, the tram goes directly there.",funFact:"What is \u00f6ffentlich belongs to everyone. Contrast: privat (private). \u00d6ffentliche Verkehrsmittel (public transport) and \u00f6ffentliche Meinung (public opinion) are everyday German phrases."},
{type:"teach",trg:"sozial",src:"social",pos:"adj",gender:null,note:"From Latin socialis. Soziale Marktwirtschaft is Germany's\neconomic model: capitalism with a social safety net.",example:"A: Was bedeutet sozial?\nB: Es geht um das Zusammenleben der Menschen.\nA: Und soziale Marktwirtschaft?\nB: Freier Markt mit sozialem Schutz. Das deutsche Modell.",exampleSrc:"A: What does sozial mean?\nB: It is about how people live together.\nA: And social market economy?\nB: Free market with social protection. The German model.",funFact:"Soziale Marktwirtschaft (social market economy) is Germany's economic model: capitalism with a social safety net. Sozialwohnung (social housing) and Sozialhilfe (social welfare) are core institutions."},
{type:"teach",trg:"f\u00fchren",src:"to lead, to guide",pos:"verb",gender:null,note:"From Proto-Germanic forjan. F\u00fchrung = leadership/guided tour.\nEin Gespr\u00e4ch f\u00fchren = to lead a conversation.",example:"A: Wer hat die Friedensgebete gef\u00fchrt?\nB: Der Pfarrer der Nikolaikirche.\nA: Er hat die Menschen gef\u00fchrt?\nB: Ja, mit Worten. Nicht mit Gewalt.",exampleSrc:"A: Who led the peace prayers?\nB: The pastor of the Nikolaikirche.\nA: He led the people?\nB: Yes, with words. Not with violence.",funFact:"F\u00fchrung means both leadership and guided tour. Ein Gespr\u00e4ch f\u00fchren (to lead a conversation) and Krieg f\u00fchren (to wage war) use the same verb. The word serves both peaceful guidance and forceful direction."},
{type:"teach",trg:"dienen",src:"to serve",pos:"verb",gender:null,note:"From Proto-Germanic thewjan. Dem Frieden dienen = to serve peace.\nDer Dienst = service.",example:"A: Wem diente die Nikolaikirche?\nB: Dem Frieden. Sie war ein Ort des Gebets.\nA: Und heute?\nB: Sie dient der Erinnerung. Sie ist ein Denkmal des Friedens.",exampleSrc:"A: What did the Nikolaikirche serve?\nB: Peace. It was a place of prayer.\nA: And today?\nB: It serves remembrance. It is a monument of peace.",funFact:"Beamter im \u00f6ffentlichen Dienst (civil servant) is a formal title. In Leipzig, many felt they had served a system that did not serve them back. Dienen implies duty and dedication."},
{type:"story",speaker:"mia",mood:"reflective",art:"de-lei-walk",trg:"Meine Gro\u00dfeltern haben in der DDR gelebt. Sie haben einander nicht sofort vertraut. Das war normal. Man wusste nie, wer f\u00fcr die Stasi arbeitete.",src:"My grandparents lived in the GDR. They did not trust each other right away. That was normal. You never knew who worked for the Stasi."},
{type:"mc",q:"Die Demonstranten 1989 forderten freie Wahlen. Was bedeutet Wahl?",opts:["election","speech","violence","reform"],ans:"election",hint:"Dieses Wort kommt von w\u00e4hlen (to choose)."},
{type:"fb",s:"Die B\u00fcrger forderten {1} und Demokratie.",a:["Freiheit"],opts:["Freiheit","Gewalt","Krieg","Kampf"],hint:"Welches Wort bedeutet freedom, das Gegenteil von Unterdr\u00fcckung?",sSrc:"The citizens demanded freedom and democracy."},
{type:"mc",q:"\u00d6ffentlichkeit kommt von offen. Was bedeutet \u00f6ffentlich?",opts:["public","open","official","honest"],ans:"public",hint:"Was offen (open) ist, geh\u00f6rt allen, ist f\u00fcr alle sichtbar."},
{type:"match",pairs:[{trg:"Bev\u00f6lkerung",src:"population"},{trg:"Gewalt",src:"violence"},{trg:"Wahl",src:"election"},{trg:"Rede",src:"speech"}]}
]},

// Lesson 3: Altes Rathaus (Story dev + grammar, 24 steps, 16 new words)
{id:"deu_r21l3",title:"Altes Rathaus",icon:"\uD83C\uDFDB\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Altes Rathaus",desc:"Explore Leipzig's historic center with Mia. Learn adjective declension without articles (strong endings). Discuss monuments, influence, and cultural change.",goals:["Learn 16 words about monuments and cultural change","Master adjective declension without articles","Form opinions about history with einerseits/andererseits"]},
{type:"story",speaker:"mia",mood:"animated",art:"de-lei-markt",trg:"Das ist der Marktplatz. Und dort: das Alte Rathaus. Renaissance-Architektur aus dem 16. Jahrhundert. Goethe hat in Auerbachs Keller gesessen und Faust geschrieben. Echter historischer Boden!",src:"This is the market square. And there: the Old Town Hall. Renaissance architecture from the 16th century. Goethe sat in Auerbachs Keller and wrote Faust. Real historic ground!"},
{type:"teach",trg:"das Denkmal",src:"the monument, the memorial",pos:"noun",gender:"n",note:"Denk (think) + Mal (mark/time). A thinking-mark.\nDenkmalschutz (monument protection) is serious in Germany.",example:"A: Was ist dieses Denkmal?\nB: Ein Denkmal f\u00fcr die friedliche Revolution.\nA: Gibt es viele Denkm\u00e4ler in Leipzig?\nB: Ja, \u00fcberall. Leipzig vergisst nicht.",exampleSrc:"A: What is this monument?\nB: A monument to the peaceful revolution.\nA: Are there many monuments in Leipzig?\nB: Yes, everywhere. Leipzig does not forget.",funFact:"A Denkmal is a thinking-mark, a place that makes you think. Denkmalschutz (monument protection) is serious in Germany: you cannot even change the windows of a protected building without permission."},
{type:"teach",trg:"der Einfluss",src:"the influence",pos:"noun",gender:"m",note:"Ein (in) + Fluss (flow). Something flowing in.\nGro\u00dfen Einfluss haben = to have great influence.",example:"A: Hatte Leipzig Einfluss auf die Musik?\nB: Enormen Einfluss! Bach, Mendelssohn, Schumann.\nA: Und auf die Politik?\nB: Auch. Die Montagsdemonstrationen ver\u00e4nderten alles.",exampleSrc:"A: Did Leipzig have influence on music?\nB: Enormous influence! Bach, Mendelssohn, Schumann.\nA: And on politics?\nB: Also. The Monday demonstrations changed everything.",funFact:"Leipzig's influence on German music is enormous: Bach, Mendelssohn, and Schumann all worked here. The Gewandhaus Orchestra is one of the oldest in the world, founded in 1743."},
{type:"teach",trg:"der Fortschritt",src:"progress",pos:"noun",gender:"m",note:"Fort (forward) + Schritt (step). A forward step.\nFortschritte machen = to make progress.",example:"A: Gibt es Fortschritt in Ostdeutschland?\nB: Ja, aber langsam. Es braucht Zeit.\nA: Welchen Fortschritt?\nB: Wirtschaftlich, sozial, und in der Infrastruktur.",exampleSrc:"A: Is there progress in East Germany?\nB: Yes, but slowly. It takes time.\nA: What kind of progress?\nB: Economic, social, and in infrastructure.",funFact:"The word Fortschritt itself walks forward: Fort (forward) + Schritt (step). Technischer Fortschritt (technological progress) is a favorite German compound. After reunification, Fortschritt in the east was rapid but uneven."},
{type:"teach",trg:"die Generation",src:"the generation",pos:"noun",gender:"f",note:"From Latin generatio. Die n\u00e4chste Generation = the next generation.\nGermans speak of Kriegsgeneration and Nachkriegsgeneration.",example:"A: Versteht die junge Generation die DDR?\nB: Nicht direkt. Aber sie lernt davon.\nA: Und die \u00e4ltere Generation?\nB: Sie hat es erlebt. Sie erinnert sich.",exampleSrc:"A: Does the young generation understand the GDR?\nB: Not directly. But it learns from it.\nA: And the older generation?\nB: They experienced it. They remember.",funFact:"Germans speak of the Kriegsgeneration, Nachkriegsgeneration, and Wiedervereinigungsgeneration. Each carries different weight. The generation gap between Ost and West still shapes German society."},
{type:"teach",trg:"das Symbol",src:"the symbol",pos:"noun",gender:"n",note:"From Greek symbolon (sign/token).\nLeipzigs Nikolaikirche ist ein Symbol der friedlichen Revolution.",example:"A: Was ist ein Symbol der Einheit?\nB: Das Brandenburger Tor. Jeder kennt es.\nA: Und f\u00fcr Leipzig?\nB: Die Nikolaikirche. Ein Symbol des friedlichen Wandels.",exampleSrc:"A: What is a symbol of unity?\nB: The Brandenburg Gate. Everyone knows it.\nA: And for Leipzig?\nB: The Nikolaikirche. A symbol of peaceful change.",funFact:"Das Brandenburger Tor ist ein Symbol der Einheit (The Brandenburg Gate is a symbol of unity). Leipzig's Nikolaikirche is a Symbol of the peaceful revolution. Symbols carry deeper meaning than mere signs."},
{type:"teach",trg:"das Zeichen",src:"the sign, the mark",pos:"noun",gender:"n",note:"From zeichnen (to draw). Ein Zeichen setzen = to make a statement.\nMore concrete than Symbol. Traffic signs are Zeichen.",example:"A: Die Kerzen waren ein Zeichen.\nB: Ja, ein Zeichen f\u00fcr den Frieden.\nA: Was f\u00fcr ein Zeichen?\nB: Ein Zeichen, dass Gewalt nicht n\u00f6tig ist.",exampleSrc:"A: The candles were a sign.\nB: Yes, a sign for peace.\nA: What kind of sign?\nB: A sign that violence is not necessary.",funFact:"Ein Zeichen setzen (to set a sign, to make a statement) is what the people of Leipzig did. More concrete than Symbol: a Zeichen is something visible, a Symbol carries deeper meaning."},
{type:"teach",trg:"die Wirkung",src:"the effect, the impact",pos:"noun",gender:"f",note:"From wirken (to have an effect). Nebenwirkung = side effect.\nLangfristige Wirkung = long-term effect.",example:"A: Welche Wirkung hatten die Demonstrationen?\nB: Eine enorme Wirkung. Die Mauer fiel.\nA: Hat Leipzig heute noch diese Wirkung?\nB: Ja, als Erinnerung daran, was m\u00f6glich ist.",exampleSrc:"A: What effect did the demonstrations have?\nB: An enormous effect. The Wall fell.\nA: Does Leipzig still have this effect today?\nB: Yes, as a reminder of what is possible.",funFact:"Nebenwirkung (side effect) is what you read on medicine packages. Langfristige Wirkung (long-term effect) is how historians describe what happened in Leipzig. The Wirkung of the peaceful revolution is still felt today."},
{type:"teach",trg:"die Hoffnung",src:"hope",pos:"noun",gender:"f",note:"From hoffen (to hope). Die Hoffnung stirbt zuletzt = hope dies last.\nIn 1989, Hoffnung brought 70,000 people onto the streets.",example:"A: Hatten die Menschen Hoffnung?\nB: Ja, trotz allem. Sie hofften auf Ver\u00e4nderung.\nA: Und heute?\nB: Hoffnung ist immer noch da. Leipzigs Motto.",exampleSrc:"A: Did the people have hope?\nB: Yes, despite everything. They hoped for change.\nA: And today?\nB: Hope is still there. Leipzig's motto.",funFact:"Die Hoffnung stirbt zuletzt (hope dies last) is a German proverb. In 1989, Hoffnung was the fuel that brought 70,000 people onto Leipzig's streets with candles. Hope, not weapons, changed history."},
{type:"teach",trg:"kritisch",src:"critical",pos:"adj",gender:null,note:"From Greek kritikos (able to judge). Kritisch denken = to think critically.\nBeing kritisch means you think carefully, not negatively.",example:"A: Ist es wichtig, kritisch zu denken?\nB: Ja, besonders bei historischen Themen.\nA: Warum?\nB: Weil man verschiedene Perspektiven sehen muss.",exampleSrc:"A: Is it important to think critically?\nB: Yes, especially with historical topics.\nA: Why?\nB: Because you have to see different perspectives.",funFact:"Germans value kritisches Denken (critical thinking) in education. Being kritisch is not negative: it means you think carefully and question assumptions. Eine kritische Masse (a critical mass) uses the scientific meaning."},
{type:"teach",trg:"h\u00e4ufig",src:"frequent(ly)",pos:"adj",gender:null,note:"From Haufen (pile/heap). Something that piles up happens h\u00e4ufig.\nMore formal than oft (often) but means the same.",example:"A: Kommen h\u00e4ufig Touristen nach Leipzig?\nB: Ja, immer h\u00e4ufiger. Die Stadt wird beliebter.\nA: Was besuchen sie am h\u00e4ufigsten?\nB: Die Nikolaikirche und Auerbachs Keller.",exampleSrc:"A: Do tourists come to Leipzig frequently?\nB: Yes, more and more often. The city is becoming more popular.\nA: What do they visit most frequently?\nB: The Nikolaikirche and Auerbachs Keller.",funFact:"H\u00e4ufig gestellte Fragen (frequently asked questions, FAQ) uses this word. H\u00e4ufig comes from Haufen (pile/heap): something that piles up happens often."},
{type:"teach",trg:"st\u00e4ndig",src:"constant(ly)",pos:"adj",gender:null,note:"From Stand (standing/state). Something that keeps standing.\nOften used with mild complaint: Sie redet st\u00e4ndig.",example:"A: Ver\u00e4ndert sich Leipzig st\u00e4ndig?\nB: Ja, st\u00e4ndig. Die Stadt entwickelt sich weiter.\nA: Ist das gut?\nB: Meistens ja. Aber manche vermissen das Alte.",exampleSrc:"A: Is Leipzig constantly changing?\nB: Yes, constantly. The city continues to develop.\nA: Is that good?\nB: Mostly yes. But some miss the old ways.",funFact:"St\u00e4ndige Vertretung (permanent representation) is a diplomatic term. In everyday German, st\u00e4ndig often carries mild complaint: Sie redet st\u00e4ndig (She talks constantly). Implies something unending."},
{type:"teach",trg:"ewig",src:"eternal",pos:"adj",gender:null,note:"From Old High German ewig (age-long).\nEwig und drei Tage = forever and three days (German idiom).",example:"A: Dauert die Renovierung ewig?\nB: Fast! Seit drei Jahren wird gebaut.\nA: In Leipzig wird ewig gebaut?\nB: Nein, aber manchmal f\u00fchlt es sich so an.",exampleSrc:"A: Does the renovation take forever?\nB: Almost! They have been building for three years.\nA: Is Leipzig always under construction?\nB: No, but sometimes it feels that way.",funFact:"Ewig und drei Tage (forever and three days) is the German version of forever and a day. Das Ewige Licht (the eternal light) burns in every Catholic church. Ewig carries both sacred and everyday meanings."},
{type:"teach",trg:"ver\u00e4ndern",src:"to change, to alter",pos:"verb",gender:null,note:"Ver- + \u00e4ndern (to make different). Reflexive: sich ver\u00e4ndern.\nStronger than \u00e4ndern: implies transformation.",example:"A: Hat Leipzig sich ver\u00e4ndert?\nB: Total. Nach der Wende hat sich alles ver\u00e4ndert.\nA: Zum Guten?\nB: Meistens ja. Die Stadt ist lebendiger geworden.",exampleSrc:"A: Has Leipzig changed?\nB: Totally. After the Wende everything changed.\nA: For the better?\nB: Mostly yes. The city has become more vibrant.",funFact:"Die Welt ver\u00e4ndern (to change the world) is what the people of Leipzig did. Ver\u00e4ndern implies transformation, deeper than just \u00e4ndern. Sich ver\u00e4ndern (to change oneself) is reflexive: the change comes from within."},
{type:"teach",trg:"nachdenken",src:"to reflect, to think about",pos:"verb",gender:null,note:"Nach (after) + denken (to think). Thinking-after, pondering.\nSeparable: Ich denke dar\u00fcber nach. Requires \u00fcber + accusative.",example:"A: Denkst du \u00fcber die Geschichte nach?\nB: Ja, st\u00e4ndig. Leipzig macht nachdenklich.\nA: Wor\u00fcber denkst du nach?\nB: Dar\u00fcber, was Freiheit wirklich bedeutet.",exampleSrc:"A: Do you think about the history?\nB: Yes, constantly. Leipzig makes you thoughtful.\nA: What do you think about?\nB: About what freedom really means.",funFact:"Denk mal dar\u00fcber nach (Think about it) is an invitation to reflect. Nachdenken is separable: Ich denke dar\u00fcber nach. The nach- gives denken depth: not just thinking, but thinking-after."},
{type:"teach",trg:"wirken",src:"to have an effect, to seem",pos:"verb",gender:null,note:"Das wirkt komisch (That seems strange). Er wirkt m\u00fcde (He seems tired).\nBridges appearance and reality.",example:"A: Wie wirkt Leipzig auf dich?\nB: Beeindruckend. Die Stadt wirkt lebendig und historisch.\nA: Und die Nikolaikirche?\nB: Sie wirkt friedlich. Man sp\u00fcrt die Geschichte.",exampleSrc:"A: How does Leipzig seem to you?\nB: Impressive. The city seems vibrant and historic.\nA: And the Nikolaikirche?\nB: It seems peaceful. You feel the history.",funFact:"Wirken bridges appearance and reality: Das wirkt komisch (That seems strange) describes how something appears. An etwas wirken (to work on something) describes real action. One verb, two perspectives."},
{type:"teach",trg:"einerseits",src:"on one hand",pos:"adv",gender:null,note:"Einer (one) + seits (side). Always paired with andererseits.\nA connector for balanced arguments.",example:"A: Was denkst du \u00fcber die Wiedervereinigung?\nB: Einerseits war sie wunderbar. Freiheit f\u00fcr alle.\nA: Und andererseits?\nB: Andererseits war es schwer. Vieles musste sich \u00e4ndern.",exampleSrc:"A: What do you think about reunification?\nB: On one hand it was wonderful. Freedom for everyone.\nA: And on the other hand?\nB: On the other hand it was hard. A lot had to change.",funFact:"Einerseits ist Leipzig sch\u00f6n, andererseits hat es eine schwere Geschichte. This connector pair is essential for B1 argumentation: presenting balanced views on complex topics."},
{type:"tip",title:"Adjective Declension Without Articles: Strong Endings",text:"When no article stands before the adjective, the adjective takes over the article's job. It shows gender, number, and case.\n\nNominative:\n- masculine: guter Wein (like der)\n- feminine: kalte Milch (like die)\n- neuter: frisches Brot (like das)\n- plural: neue Ideen (like die)\n\nAccusative:\n- masculine: guten Wein (like den)\n- feminine: kalte Milch (like die)\n- neuter: frisches Brot (like das)\n- plural: neue Ideen (like die)\n\nDative:\n- masculine: gutem Wein (like dem)\n- feminine: kalter Milch (like der)\n- neuter: frischem Brot (like dem)\n- plural: neuen Ideen (like den)\n\nRemember: The adjective does the article's job.",deepDive:{title:"When Without Article?",text:"Adjectives without articles commonly appear with:\n\n1. Mass nouns: kaltes Wasser, frische Milch\n2. Abstract nouns: politische Freiheit, soziale Gerechtigkeit\n3. Plurals without articles: neue Ideen, alte Freunde\n4. After numbers: zwei gute Bücher\n5. In lists: mit großem Mut und starker Hoffnung\n\nThe endings match the endings of the definite article (der/die/das/den/dem)."}},
{type:"verb_table",title:"Starke Adjektivendungen (ohne Artikel)",groups:[{title:"Nominativ",rows:[{pronoun:"maskulin",form:"-er",src:"guter Wein"},{pronoun:"feminin",form:"-e",src:"kalte Milch"},{pronoun:"neutral",form:"-es",src:"frisches Brot"},{pronoun:"Plural",form:"-e",src:"neue Ideen"}]},{title:"Akkusativ",rows:[{pronoun:"maskulin",form:"-en",src:"guten Wein"},{pronoun:"feminin",form:"-e",src:"kalte Milch"},{pronoun:"neutral",form:"-es",src:"frisches Brot"},{pronoun:"Plural",form:"-e",src:"neue Ideen"}]},{title:"Dativ",rows:[{pronoun:"maskulin",form:"-em",src:"gutem Wein"},{pronoun:"feminin",form:"-er",src:"kalter Milch"},{pronoun:"neutral",form:"-em",src:"frischem Brot"},{pronoun:"Plural",form:"-en",src:"neuen Ideen"}]}],note:"The adjective takes the ending of the definite article. It does the article's job."},
{type:"mc",q:"Wie sagt man fresh bread auf Deutsch? (neutral, Nominativ, ohne Artikel)",opts:["frisches Brot","frischen Brot","frischem Brot","frischer Brot"],ans:"frisches Brot",hint:"Neutral Nominativ ohne Artikel braucht die Endung -es, wie das."},
{type:"fb",s:"Leipzig hat {1} Geschichte.",a:["lange"],opts:["lange","langer","langem","langen"],hint:"Geschichte ist feminin. Nominativ feminin ohne Artikel nimmt -e.",sSrc:"Leipzig has a long history."},
{type:"mc",q:"Mia trinkt _____ Kaffee. (maskulin, Akkusativ, ohne Artikel)",opts:["starke","starken","starkes","starker"],ans:"starken",hint:"Maskulin Akkusativ ohne Artikel nimmt -en, passend zu den."},
{type:"drag_fill",s:"Verumius trinkt {1} Tee und isst {2} Brot mit {3} Butter.",blanks:{"1":"hei\u00dfen","2":"frisches","3":"guter"},pool:["hei\u00dfen","frisches","guter","kalte","neuen","altem"],hint:"Tee ist maskulin Akkusativ (-en). Brot ist neutral Akkusativ (-es). Butter ist feminin Dativ (-er).",sSrc:"Verumius drinks hot tea and eats fresh bread with good butter."}
]},

// Lesson 4: Nikolaikirche (Grammar, 24 steps, 14 new words)
{id:"deu_r21l4",title:"Nikolaikirche",icon:"\u26ea",xp:15,board:true,steps:[
{type:"intro",title:"Nikolaikirche",desc:"Stand in the church where the peaceful revolution of 1989 began. Learn adjective declension in the genitive. Learn reciprocal verbs. Express emotional reactions to history.",goals:["Master adjective declension in the genitive (always -en)","Learn reciprocal verbs (sich, einander, miteinander)","Express emotional reactions to history"]},
{type:"story",speaker:"narrator",mood:"reverent",art:"de-lei-nikolai",trg:"Die Nikolaikirche ist still. Rosa-wei\u00dfe S\u00e4ulen steigen wie Palmen zur Decke. Hier begann alles. Hier beteten Menschen f\u00fcr Freiheit, w\u00e4hrend bewaffnete Polizisten drau\u00dfen warteten.",src:"The Nikolaikirche is quiet. Pink-white columns rise like palm trees to the ceiling. Everything began here. Here, people prayed for freedom while armed police waited outside."},
{type:"story",speaker:"mia",mood:"emotional",art:"de-lei-nikolai",trg:"Im Oktober 1989 kamen 70.000 Menschen hierher. Ohne Gewalt. Nur mit Kerzen. Die Polizei war da, aber niemand hat geschossen. Das war der Anfang des Endes.",src:"In October 1989, 70,000 people came here. Without violence. Only with candles. The police were there, but nobody fired. That was the beginning of the end."},
{type:"teach",trg:"die Versammlung",src:"the assembly, the gathering",pos:"noun",gender:"f",note:"Ver- + sammeln (to collect) + -ung. A coming-together.\nVersammlungsfreiheit = freedom of assembly.",example:"A: Waren die Montagsdemonstrationen Versammlungen?\nB: Ja, friedliche Versammlungen. Jeden Montag.\nA: War das erlaubt?\nB: Nein. Aber die Menschen kamen trotzdem.",exampleSrc:"A: Were the Monday demonstrations assemblies?\nB: Yes, peaceful assemblies. Every Monday.\nA: Was that allowed?\nB: No. But the people came anyway.",funFact:"Versammlungsfreiheit (freedom of assembly) is a constitutional right in Germany. The 1989 Montagsdemonstrationen were Versammlungen that changed history: illegal under DDR law, but unstoppable."},
{type:"teach",trg:"die Gemeinschaft",src:"the community",pos:"noun",gender:"f",note:"Gemein (common) + -schaft. What people share in common.\nWarmer than Gesellschaft: built on bonds, not structures.",example:"A: Was ist der Unterschied zwischen Gesellschaft und Gemeinschaft?\nB: Gesellschaft ist die Struktur. Gemeinschaft ist das Gef\u00fchl.\nA: Gab es Gemeinschaft in der DDR?\nB: Ja, trotz allem. Die Nachbarn halfen einander.",exampleSrc:"A: What is the difference between Gesellschaft and Gemeinschaft?\nB: Gesellschaft is the structure. Gemeinschaft is the feeling.\nA: Was there community in the GDR?\nB: Yes, despite everything. The neighbors helped each other.",funFact:"Europ\u00e4ische Gemeinschaft (European Community) was the predecessor of the EU. Gemeinschaft is warmer and more personal than Gesellschaft (society): built on bonds rather than structures."},
{type:"teach",trg:"die Jugend",src:"youth",pos:"noun",gender:"f",note:"No plural form. Die Jugend refers to young people collectively.\nJugendherberge (youth hostel) is a German invention.",example:"A: Was macht die Jugend in Leipzig?\nB: Viel Kultur. Musik, Kunst, Theater.\nA: Interessiert sich die Jugend f\u00fcr Geschichte?\nB: Ja, immer mehr. Die Schulen lehren es gut.",exampleSrc:"A: What does the youth in Leipzig do?\nB: A lot of culture. Music, art, theater.\nA: Is the youth interested in history?\nB: Yes, more and more. The schools teach it well.",funFact:"In meiner Jugend... (In my youth...) is how stories of the DDR often begin. Jugendherberge (youth hostel) is a German invention. Die Jugend has no plural: it is always collective."},
{type:"teach",trg:"der Zeuge",src:"the witness (male)",pos:"noun",gender:"m",note:"From zeugen (to testify). Weak noun: der Zeuge, den Zeugen.\nZeitzeuge = contemporary witness who lived through history.",example:"A: Gibt es noch Zeitzeugen von 1989?\nB: Ja, viele. Mias Gro\u00dfeltern zum Beispiel.\nA: Was erz\u00e4hlen die Zeitzeugen?\nB: Von Angst, Hoffnung und Ver\u00e4nderung.",exampleSrc:"A: Are there still contemporary witnesses of 1989?\nB: Yes, many. Mia's grandparents for example.\nA: What do the contemporary witnesses tell?\nB: About fear, hope, and change.",funFact:"Zeitzeuge (contemporary witness) is someone who lived through a historical period. Leipzig has many Zeitzeugen of 1989. Their stories carry the weight of lived experience. The weak noun declension (den Zeugen, dem Zeugen) is characteristic."},
{type:"teach",trg:"die Zeugin",src:"the witness (female)",pos:"noun",gender:"f",note:"The -in suffix marks the feminine form.\nAls Zeugin aussagen = to testify as a witness.",example:"A: Ist deine Oma eine Zeitzeugin?\nB: Ja, sie hat die Wende erlebt.\nA: Was erz\u00e4hlt sie?\nB: Dass sie nie geglaubt hat, dass die Mauer fallen w\u00fcrde.",exampleSrc:"A: Is your grandma a contemporary witness?\nB: Yes, she experienced the Wende.\nA: What does she tell?\nB: That she never believed the Wall would fall.",funFact:"Mia's grandparents are Zeitzeuginnen and Zeitzeugen of the DDR era. Their stories carry the weight of lived experience. In Germany, Zeitzeugen regularly visit schools to share their memories."},
{type:"teach",trg:"die Realit\u00e4t",src:"reality",pos:"noun",gender:"f",note:"From Latin realitas. Die Realit\u00e4t sieht anders aus = reality looks different.\nBorrowed word, paired with native Wirklichkeit.",example:"A: War die DDR eine gute Realit\u00e4t?\nB: F\u00fcr manche ja. F\u00fcr viele nein.\nA: Wie sah die Realit\u00e4t aus?\nB: Eingeschr\u00e4nkte Freiheit. \u00dcberwachung. Aber auch Gemeinschaft.",exampleSrc:"A: Was the GDR a good reality?\nB: For some yes. For many no.\nA: What did reality look like?\nB: Restricted freedom. Surveillance. But also community.",funFact:"Germans sometimes pair Realit\u00e4t with Wirklichkeit for emphasis: both mean reality, but Realit\u00e4t is borrowed from Latin, Wirklichkeit is native German. Die Realit\u00e4t sieht anders aus (Reality looks different) is everyday German."},
{type:"teach",trg:"die Wirklichkeit",src:"reality",pos:"noun",gender:"f",note:"From wirklich (real). Wirk- (effect/work) + -lich + -keit.\nWhat actually has effect, what truly works.",example:"A: Was ist der Unterschied zwischen Realit\u00e4t und Wirklichkeit?\nB: Fast keiner. Wirklichkeit klingt deutscher.\nA: In Wirklichkeit?\nB: In Wirklichkeit bedeuten sie das Gleiche.",exampleSrc:"A: What is the difference between Realit\u00e4t and Wirklichkeit?\nB: Almost none. Wirklichkeit sounds more German.\nA: In reality?\nB: In reality they mean the same thing.",funFact:"In Wirklichkeit (in reality) is how Germans reveal what is really going on beneath the surface. Wirklichkeit comes from wirken (to have an effect): reality is what actually has effect in the world."},
{type:"teach",trg:"gleichzeitig",src:"simultaneous(ly)",pos:"adj",gender:null,note:"Gleich (same) + Zeit (time) + -ig. At the same time.\nDescribes the feeling in Nikolaikirche perfectly.",example:"A: Wie f\u00fchlt es sich in der Nikolaikirche an?\nB: Gleichzeitig traurig und hoffnungsvoll.\nA: Wie ist das m\u00f6glich?\nB: Die Sch\u00f6nheit und die Geschichte koexistieren.",exampleSrc:"A: How does it feel in the Nikolaikirche?\nB: Simultaneously sad and hopeful.\nA: How is that possible?\nB: The beauty and the history coexist.",funFact:"Gleichzeitig traurig und hoffnungsvoll (simultaneously sad and hopeful) describes the feeling in Nikolaikirche perfectly. The beauty of the columns and the weight of what happened here coexist."},
{type:"teach",trg:"menschlich",src:"human, humane",pos:"adj",gender:null,note:"From Mensch (human being). Menschliche W\u00fcrde = human dignity.\nArticle 1 of the German constitution.",example:"A: Was ist menschliche W\u00fcrde?\nB: Das Recht, als Mensch respektiert zu werden.\nA: Steht das im Grundgesetz?\nB: Ja, Artikel 1. Die menschliche W\u00fcrde ist unantastbar.",exampleSrc:"A: What is human dignity?\nB: The right to be respected as a human being.\nA: Is that in the constitution?\nB: Yes, Article 1. Human dignity is inviolable.",funFact:"Menschliche W\u00fcrde (human dignity) is Article 1 of the German constitution. Menschlich means both human and humane. To be human is to be compassionate. This principle shaped post-war Germany."},
{type:"teach",trg:"v\u00f6llig",src:"completely",pos:"adj",gender:null,note:"From voll (full). Stronger than ganz (quite).\nV\u00f6llig unerwartet = completely unexpected.",example:"A: War der Mauerfall v\u00f6llig unerwartet?\nB: Ja, v\u00f6llig! Niemand hat damit gerechnet.\nA: Nicht einmal die Politiker?\nB: Nein, v\u00f6llig \u00fcberraschend f\u00fcr alle.",exampleSrc:"A: Was the fall of the Wall completely unexpected?\nB: Yes, completely! Nobody expected it.\nA: Not even the politicians?\nB: No, completely surprising for everyone.",funFact:"V\u00f6llig unerwartet (completely unexpected) describes what happened in November 1989. An intensifier stronger than ganz (quite). V\u00f6llig adds fullness to any adjective it precedes."},
{type:"teach",trg:"geschehen",src:"to happen, to occur",pos:"verb",gender:null,note:"Irregular: geschieht, geschah, ist geschehen. More formal than\npassieren. Geschichte (history) comes from the same root.",example:"A: Was ist in der Nikolaikirche geschehen?\nB: Hier begannen die Friedensgebete.\nA: Wann ist das geschehen?\nB: Ab 1982. Jeden Montag.",exampleSrc:"A: What happened in the Nikolaikirche?\nB: The peace prayers began here.\nA: When did that happen?\nB: From 1982 onward. Every Monday.",funFact:"Was ist geschehen? (What happened?) carries weight and formality. Geschichte (history) comes from the same root: history is what has happened. Geschehen is reserved for significant events."},
{type:"teach",trg:"entwickeln",src:"to develop",pos:"verb",gender:null,note:"Ent- (out of) + wickeln (to wrap). To unwrap.\nReflexive: sich entwickeln = to develop organically.",example:"A: Hat sich Leipzig nach der Wende entwickelt?\nB: Ja, enorm. Die Stadt hat sich komplett ver\u00e4ndert.\nA: Was hat sich entwickelt?\nB: Alles. Wirtschaft, Kultur, Infrastruktur.",exampleSrc:"A: Did Leipzig develop after the Wende?\nB: Yes, enormously. The city completely changed.\nA: What developed?\nB: Everything. Economy, culture, infrastructure.",funFact:"Sich entwickeln (to develop oneself) is reflexive for organic growth. Die Stadt hat sich schnell entwickelt (The city developed quickly). Transitive entwickeln is for deliberate creation: eine App entwickeln (to develop an app)."},
{type:"teach",trg:"\u00fcberlegen",src:"to consider, to think over",pos:"verb",gender:null,note:"\u00dcber (over) + legen (to lay). To lay thoughts over a matter.\nAlso an adjective: \u00fcberlegen = superior.",example:"A: \u00dcberlegst du noch?\nB: Ja, ich \u00fcberlege, was diese Kirche f\u00fcr mich bedeutet.\nA: Nimm dir Zeit.\nB: Die Geschichte hier ist so schwer. Ich muss nachdenken.",exampleSrc:"A: Are you still thinking it over?\nB: Yes, I am considering what this church means to me.\nA: Take your time.\nB: The history here is so heavy. I need to reflect.",funFact:"Ich \u00fcberlege mir das (I will think it over) is how Germans buy time for decisions. As an adjective, \u00fcberlegen means superior: same word, but stress changes meaning."},
{type:"teach",trg:"andererseits",src:"on the other hand",pos:"adv",gender:null,note:"Anderer (other) + seits (side). Partner of einerseits.\nEssential for B1 argumentation.",example:"A: Einerseits ist die Wiedervereinigung gut.\nB: Andererseits gibt es immer noch Unterschiede.\nA: Zwischen Ost und West?\nB: Ja. Wirtschaftlich und manchmal auch kulturell.",exampleSrc:"A: On one hand, reunification is good.\nB: On the other hand, there are still differences.\nA: Between East and West?\nB: Yes. Economically and sometimes culturally.",funFact:"Andererseits muss man die Geschichte verstehen (On the other hand, one must understand history). Essential for B1 argumentation. Always paired with einerseits to present balanced views."},
{type:"tip",title:"Adjective Declension in the Genitive: The Easiest Rule",text:"After every genitive article (des, der, des, der, eines, einer, eines), the adjective ALWAYS ends in -en. No exceptions.\n\nExamples:\n- des guten Mannes (masc)\n- der guten Frau (fem)\n- des guten Kindes (neut)\n- der guten Leute (plural)\n- eines guten Mannes\n- einer guten Frau\n- eines guten Kindes\n\nCommon contexts:\n- während des Kalten Krieges\n- trotz des schlechten Wetters\n- wegen des großen Erfolgs\n\nGenitive is the easiest case for adjective declension: always -en with an article.",deepDive:{title:"Genitive Prepositions",text:"These prepositions require the genitive:\n\nwährend = during: während des Krieges\ntrotz = despite: trotz des Regens\nwegen = because of: wegen des Wetters\naußerhalb = outside of: außerhalb der Stadt\ninnerhalb = inside of: innerhalb eines Jahres\nstatt/anstatt = instead of: statt des Buches\n\nIn colloquial speech, some Germans use dative after these prepositions, but in written German the genitive is correct."}},
{type:"tip",title:"Reciprocal Verbs: sich and einander",text:"When a plural subject does something TO EACH OTHER, German uses sich (ambiguous) or einander (unambiguous).\n\nSie kennen sich. = They know each other. OR They know themselves.\nSie kennen einander. = Unambiguous: each other.\n\nWith prepositions, einander becomes one word:\n- miteinander (with each other)\n- füreinander (for each other)\n- voneinander (from each other)\n- zueinander (to each other)\n\nComparison:\n- Sie waschen sich. = reflexive (themselves)\n- Sie helfen einander. = reciprocal (each other)",deepDive:{title:"Reciprocal Verbs in Practice",text:"Common reciprocal verbs:\n\nsich kennen / einander kennen = to know each other\nsich verstehen / einander verstehen = to understand each other\nsich vertrauen / einander vertrauen = to trust each other\nsich helfen / einander helfen = to help each other\nsich sehen / einander sehen = to see each other\n\nWith preposition + einander:\nSie sprechen miteinander. = They speak with each other.\nSie sorgen füreinander. = They care for each other.\nSie lernen voneinander. = They learn from each other.\n\nEinander is more formal and unambiguous than sich."}},
{type:"teach",trg:"der Dialekt",src:"the dialect",pos:"noun",gender:"m",note:"From Greek dialektos (manner of speaking).\nSächsisch is Leipzig's local dialect.",example:"A: Spricht man in Leipzig Dialekt?\nB: Ja, Sächsisch. Aber nicht alle.\nA: Ist der Dialekt schwer zu verstehen?\nB: Manchmal. Aber er ist auch charmant.",exampleSrc:"A: Do people speak dialect in Leipzig?\nB: Yes, Saxon. But not everyone.\nA: Is the dialect hard to understand?\nB: Sometimes. But it is also charming.",funFact:"Germany has dozens of distinct Dialekte. Sächsisch (Saxon) is Leipzig's dialect, often parodied but deeply loved by locals. Dialekt is identity: where you come from lives in how you speak."},
{type:"mc",q:"Erg\u00e4nze: w\u00e4hrend des _____ Krieges (during the Cold War)",opts:["Kalten","Kalter","Kaltem","Kaltes"],ans:"Kalten",hint:"Nach des im Genitiv enden Adjektive immer auf -en."},
{type:"fb",s:"Die Ost- und Westdeutschen verstanden {1} nicht sofort.",a:["einander"],opts:["einander","sich","zusammen","gegenseitig"],hint:"Welches Wort bedeutet explizit each other und entfernt Mehrdeutigkeit?",sSrc:"East and West Germans did not understand each other right away."},
{type:"mc",q:"Erg\u00e4nze: trotz der _____ Situation (despite the difficult situation)",opts:["schwieriger","schwierige","schwierigem","schwierigen"],ans:"schwierigen",hint:"Nach der im Genitiv feminin nimmt das Adjektiv immer -en."},
{type:"drag_fill",s:"W\u00e4hrend des {1} Krieges kannten Ost und West {2} kaum. Sie wussten wenig {3}.",blanks:{"1":"Kalten","2":"einander","3":"voneinander"},pool:["Kalten","einander","voneinander","Kalter","sich","miteinander"],hint:"Genitiv nach des = -en. Explizit each other = einander. About each other = voneinander.",sSrc:"During the Cold War, East and West barely knew each other. They knew little about each other."},
{type:"mc",q:"Mia erz\u00e4hlt von _____ Erinnerungen. (old memories, ohne Artikel, Dativ Plural)",opts:["altes Erinnerungen","alter Erinnerungen","alten Erinnerungen","alte Erinnerungen"],ans:"alten Erinnerungen",hint:"Dativ Plural ohne Artikel: das Adjektiv nimmt -en, passend zu den."}
]},

// Lesson 5: Hildis Fotoalbum (Vocab + review, 24 steps, 18 new words)
{id:"deu_r21l5",title:"Hildis Fotoalbum",icon:"\uD83D\uDCF7",xp:15,board:true,steps:[
{type:"intro",title:"Hildis Fotoalbum",desc:"Experience Hildi's most human moment. Learn vocabulary for childhood, homeland, and social structures. Practice all three grammar constructions with personal stories.",goals:["Learn 18 words about childhood and social structures","Experience Hildi's most vulnerable moment","Practice strong endings, genitive, and reciprocal verbs"]},
{type:"story",speaker:"narrator",mood:"intimate",art:"de-ber-stairwell",trg:"Es ist sp\u00e4t. Verumius kommt die Treppe hoch. Hildi sitzt auf der Bank im Treppenhaus, ein Fotoalbum auf dem Scho\u00df. Sie schaut nicht auf. Ihre Augen sind feucht.",src:"It is late. Verumius comes up the stairs. Hildi sits on the bench in the stairwell, a photo album on her lap. She does not look up. Her eyes are moist."},
{type:"story",speaker:"hildi",mood:"vulnerable",art:"de-ber-stairwell",trg:"Mein Mann und ich haben uns in Leipzig kennengelernt. Wir haben einander sofort vertraut. Das war selten in der DDR. Er hat immer gesagt: Eines Tages wird die Mauer fallen. Er hatte recht.",src:"My husband and I met in Leipzig. We trusted each other immediately. That was rare in the GDR. He always said: One day the wall will fall. He was right."},
{type:"teach",trg:"die Kindheit",src:"childhood",pos:"noun",gender:"f",note:"Kind (child) + -heit. The -heit suffix creates abstract nouns.\nMeine Kindheit in der DDR is how millions begin their stories.",example:"A: Wie war deine Kindheit?\nB: Einfach. Wir hatten nicht viel, aber wir waren gl\u00fccklich.\nA: Wo bist du aufgewachsen?\nB: In Leipzig. Eine sch\u00f6ne Kindheit, trotz allem.",exampleSrc:"A: How was your childhood?\nB: Simple. We did not have much, but we were happy.\nA: Where did you grow up?\nB: In Leipzig. A beautiful childhood, despite everything.",funFact:"Meine Kindheit in der DDR (my childhood in the GDR) is how millions of Germans begin their stories. The -heit suffix turns concrete words into abstract states: Kind becomes the state of being a child."},
{type:"teach",trg:"das Heimweh",src:"homesickness",pos:"noun",gender:"n",note:"Heim (home) + Weh (pain/ache). Home-ache.\nFernweh (distance-ache) is its opposite: longing to travel.",example:"A: Hast du Heimweh nach Leipzig?\nB: Manchmal. Besonders im Herbst.\nA: Was vermisst du?\nB: Den Dialekt. Das Essen. Die Menschen.",exampleSrc:"A: Do you have homesickness for Leipzig?\nB: Sometimes. Especially in autumn.\nA: What do you miss?\nB: The dialect. The food. The people.",funFact:"The German word is so precise it was borrowed into other languages. Fernweh (distance-ache) is its opposite: the longing to travel. Germans invented both words for both directions of longing."},
{type:"teach",trg:"das Heim",src:"the home",pos:"noun",gender:"n",note:"Warmer than Haus (house). Heimat (homeland) builds on this root.\nSich heimisch f\u00fchlen = to feel at home.",example:"A: Was ist ein Heim?\nB: Mehr als ein Haus. Ein Ort, wo man sich sicher f\u00fchlt.\nA: Ist Leipzig Mias Heim?\nB: Ja, immer. Auch wenn sie in Berlin lebt.",exampleSrc:"A: What is a Heim?\nB: More than a house. A place where you feel safe.\nA: Is Leipzig Mia's home?\nB: Yes, always. Even though she lives in Berlin.",funFact:"Altenheim (retirement home), Kinderheim (children's home), Tierheim (animal shelter): Heim is where you belong. Heimat (homeland) builds on this root. Heim is always warmer than Haus."},
{type:"teach",trg:"die Flucht",src:"the flight, the escape",pos:"noun",gender:"f",note:"From fliehen (to flee). Fluchtversuch from the DDR was a crime.\nOver 3.5 million fled East Germany before the Wall was built.",example:"A: Gab es viele Fluchtversuche?\nB: Ja, tausende. Viele waren gef\u00e4hrlich.\nA: Warum war die Flucht so schwer?\nB: Mauer, Stacheldraht, bewaffnete Grenzsoldaten.",exampleSrc:"A: Were there many escape attempts?\nB: Yes, thousands. Many were dangerous.\nA: Why was the escape so difficult?\nB: Wall, barbed wire, armed border soldiers.",funFact:"Fl\u00fcchtling (refugee) comes from Flucht. Over 3.5 million people fled East Germany before the Wall was built. After the Wall went up, Fluchtversuch (escape attempt) became a life-threatening crime."},
{type:"teach",trg:"das Erlebnis",src:"the experience (lived)",pos:"noun",gender:"n",note:"Er- + leben (to live) + -nis. Something you actively lived through.\nStronger than Erfahrung. The -nis ending is always neuter.",example:"A: Was war dein gr\u00f6\u00dftes Erlebnis in Leipzig?\nB: Die Nikolaikirche. Ein unvergessliches Erlebnis.\nA: Warum?\nB: Man sp\u00fcrt die Geschichte. Es ist \u00fcberw\u00e4ltigend.",exampleSrc:"A: What was your greatest experience in Leipzig?\nB: The Nikolaikirche. An unforgettable experience.\nA: Why?\nB: You feel the history. It is overwhelming.",funFact:"Ein unvergessliches Erlebnis (an unforgettable experience) is something you actively lived through. The -nis ending creates neuter nouns: das Erlebnis, das Ergebnis, das Geheimnis."},
{type:"teach",trg:"die Erziehung",src:"upbringing, education",pos:"noun",gender:"f",note:"From erziehen (to raise). Er- + ziehen (to pull). Pulling someone up.\nGute Erziehung (good upbringing) is highly valued.",example:"A: War die Erziehung in der DDR anders?\nB: Ja, sehr. Der Staat hatte viel Einfluss.\nA: Auf welche Weise?\nB: Die Kinder lernten, was der Staat wollte.",exampleSrc:"A: Was upbringing in the GDR different?\nB: Yes, very. The state had a lot of influence.\nA: In what way?\nB: The children learned what the state wanted.",funFact:"Erziehungsurlaub (parental leave) shows how seriously Germany takes Erziehung. Gute Erziehung (good upbringing) is a compliment. In the DDR, Erziehung was heavily state-controlled."},
{type:"teach",trg:"das Verh\u00e4ltnis",src:"the relationship, the ratio",pos:"noun",gender:"n",note:"Ver- + halten (to hold) + -nis. How things hold together.\nAlso means affair in romantic context.",example:"A: Wie ist das Verh\u00e4ltnis zwischen Ost und West heute?\nB: Besser als fr\u00fcher. Aber noch nicht perfekt.\nA: Was fehlt?\nB: Mehr Verst\u00e4ndnis f\u00fcreinander.",exampleSrc:"A: How is the relationship between East and West today?\nB: Better than before. But not yet perfect.\nA: What is missing?\nB: More understanding for each other.",funFact:"Das Verh\u00e4ltnis zwischen Ost und West (the relationship between East and West) is still a topic in Germany. Plural Verh\u00e4ltnisse means conditions/circumstances. One word, many layers."},
{type:"teach",trg:"das Verhalten",src:"behavior",pos:"noun",gender:"n",note:"Ver- + halten (to hold). How one holds oneself.\nAlso a verb: sich verhalten = to behave.",example:"A: Wie war das Verhalten der Polizei 1989?\nB: Am Anfang aggressiv. Dann zur\u00fcckhaltend.\nA: Warum?\nB: Sie sahen, dass die Menschen friedlich waren.",exampleSrc:"A: How was the behavior of the police in 1989?\nB: At first aggressive. Then restrained.\nA: Why?\nB: They saw that the people were peaceful.",funFact:"In the DDR, richtiges Verhalten (correct behavior) was state-defined. Auff\u00e4lliges Verhalten (conspicuous behavior) could lead to surveillance. Sich verhalten (to behave) is reflexive."},
{type:"teach",trg:"das Geschlecht",src:"gender, sex, lineage",pos:"noun",gender:"n",note:"From schlagen (to strike, originally: kind/type).\nAlso means generation/lineage: das Geschlecht der Habsburger.",example:"A: Was bedeutet Geschlecht?\nB: Mehrere Dinge: Geschlecht wie m\u00e4nnlich/weiblich.\nA: Und in der Grammatik?\nB: Auch! Maskulin, feminin, neutral: das grammatische Geschlecht.",exampleSrc:"A: What does Geschlecht mean?\nB: Several things: gender like male/female.\nA: And in grammar?\nB: Also! Masculine, feminine, neuter: the grammatical gender.",funFact:"Geschlechtergleichheit (gender equality) is a core value. Das Geschlecht der Habsburger (the House of Habsburg) uses the lineage meaning. Grammar uses it too: grammatisches Geschlecht = grammatical gender."},
{type:"teach",trg:"die Mehrheit",src:"the majority",pos:"noun",gender:"f",note:"Mehr (more) + -heit. The-more-ness.\nZweidrittelmehrheit = two-thirds majority for constitutional changes.",example:"A: Wollte die Mehrheit die Wiedervereinigung?\nB: Ja, die gro\u00dfe Mehrheit.\nA: Sofort?\nB: Im M\u00e4rz 1990, bei der ersten freien Wahl: ja.",exampleSrc:"A: Did the majority want reunification?\nB: Yes, the vast majority.\nA: Right away?\nB: In March 1990, at the first free election: yes.",funFact:"Die Mehrheit der Bev\u00f6lkerung (the majority of the population) voted for reunification. Zweidrittelmehrheit (two-thirds majority) is needed for constitutional changes. Opposite: Minderheit."},
{type:"teach",trg:"die Minderheit",src:"the minority",pos:"noun",gender:"f",note:"Minder (less) + -heit. The-less-ness.\nGermany recognizes four national minorities with constitutional protection.",example:"A: Gibt es Minderheiten in Deutschland?\nB: Ja, zum Beispiel D\u00e4nen, Friesen, Sorben und Sinti/Roma.\nA: Haben sie besondere Rechte?\nB: Ja, sie stehen unter besonderem Schutz.",exampleSrc:"A: Are there minorities in Germany?\nB: Yes, for example Danes, Frisians, Sorbs, and Sinti/Roma.\nA: Do they have special rights?\nB: Yes, they are under special protection.",funFact:"Germany recognizes four national minorities: Danes, Frisians, Sorbs, and Sinti/Roma. Each has constitutional protection. Ethnische Minderheiten (ethnic minorities) have specific rights in German law."},
{type:"teach",trg:"die Religion",src:"religion",pos:"noun",gender:"f",note:"From Latin religio. Germany has a unique system: Kirchensteuer\n(church tax) is automatically deducted from your salary.",example:"A: Spielt Religion in Deutschland eine Rolle?\nB: Weniger als fr\u00fcher. Aber die Kirchensteuer gibt es noch.\nA: Was ist Kirchensteuer?\nB: Eine Steuer, die automatisch abgezogen wird, wenn man einer Kirche angeh\u00f6rt.",exampleSrc:"A: Does religion play a role in Germany?\nB: Less than before. But the church tax still exists.\nA: What is church tax?\nB: A tax that is automatically deducted if you belong to a church.",funFact:"Germany's Kirchensteuer (church tax) is automatically deducted from your salary unless you formally leave your church. Religionsfreiheit (religious freedom) is constitutional. In East Germany under the DDR, religion was suppressed."},
{type:"teach",trg:"die Gewerkschaft",src:"the trade union",pos:"noun",gender:"f",note:"Ge- + Werk (work) + -schaft. A collective of workers.\nIG Metall is Germany's largest with 2+ million members.",example:"A: Was ist eine Gewerkschaft?\nB: Eine Organisation, die f\u00fcr Arbeiterrechte k\u00e4mpft.\nA: Sind Gewerkschaften in Deutschland stark?\nB: Ja, sehr. Sie verhandeln L\u00f6hne f\u00fcr ganze Branchen.",exampleSrc:"A: What is a trade union?\nB: An organization that fights for workers' rights.\nA: Are trade unions strong in Germany?\nB: Yes, very. They negotiate wages for entire industries.",funFact:"IG Metall is Germany's largest Gewerkschaft with over 2 million members. Unions are powerful in Germany: they negotiate industry-wide wages. In the DDR, unions existed but were controlled by the state."},
{type:"teach",trg:"gleichberechtigt",src:"equal (in rights)",pos:"adj",gender:null,note:"Gleich (equal) + berechtigt (entitled).\nArtikel 3: M\u00e4nner und Frauen sind gleichberechtigt.",example:"A: Sind M\u00e4nner und Frauen in Deutschland gleichberechtigt?\nB: Laut Grundgesetz ja. In der Praxis noch nicht ganz.\nA: Was fehlt?\nB: Gleiche Bezahlung. Gleiche Chancen in F\u00fchrungspositionen.",exampleSrc:"A: Are men and women equal in rights in Germany?\nB: According to the constitution yes. In practice not quite yet.\nA: What is missing?\nB: Equal pay. Equal opportunities in leadership positions.",funFact:"Article 3 of the German constitution: M\u00e4nner und Frauen sind gleichberechtigt (Men and women have equal rights). Four syllables, one fundamental principle. Reality still catches up to the law."},
{type:"teach",trg:"dauernd",src:"constant(ly), lasting",pos:"adj",gender:null,note:"From dauern (to last). More emotional than st\u00e4ndig:\nimplies slight annoyance or endlessness.",example:"A: Regnet es dauernd in Leipzig?\nB: Nicht dauernd. Aber h\u00e4ufig im Herbst.\nA: Das nervt.\nB: Ja, es regnet dauernd, wenn man keinen Schirm hat.",exampleSrc:"A: Does it rain constantly in Leipzig?\nB: Not constantly. But frequently in autumn.\nA: That is annoying.\nB: Yes, it rains constantly when you do not have an umbrella.",funFact:"Das dauert dauernd! (That always takes forever!) uses the word playfully. Dauernd is more emotional than st\u00e4ndig: it implies slight annoyance or a feeling of endlessness."},
{type:"teach",trg:"sogenannt",src:"so-called",pos:"adj",gender:null,note:"So (so) + genannt (called, from nennen). Can be neutral\nor skeptical. Sogenannte Experten implies doubt.",example:"A: Was war die sogenannte Wende?\nB: Die friedliche Revolution und Wiedervereinigung 1989/90.\nA: Warum sogenannt?\nB: Wende ist der informelle Name. Offiziell: Wiedervereinigung.",exampleSrc:"A: What was the so-called Wende?\nB: The peaceful revolution and reunification of 1989/90.\nA: Why so-called?\nB: Wende is the informal name. Officially: Wiedervereinigung.",funFact:"Die sogenannte friedliche Revolution (the so-called peaceful revolution) uses sogenannt neutrally as a naming device. But sogenannte Experten (so-called experts) implies they are not really experts. Context determines tone."},
{type:"teach",trg:"fliehen",src:"to flee",pos:"verb",gender:null,note:"Irregular: flieht, floh, ist geflohen.\nAus der DDR fliehen was life-threatening.",example:"A: Sind viele Menschen aus der DDR geflohen?\nB: Ja, Millionen, bevor die Mauer gebaut wurde.\nA: Und danach?\nB: Auch. Aber es war extrem gef\u00e4hrlich.",exampleSrc:"A: Did many people flee from the GDR?\nB: Yes, millions, before the Wall was built.\nA: And after that?\nB: Also. But it was extremely dangerous.",funFact:"Over 5,000 people successfully fled across the Berlin Wall. Fl\u00fcchtig (fleeting, fugitive) comes from this verb. Aus der DDR fliehen was one of the most dangerous decisions a person could make."},
{type:"teach",trg:"erziehen",src:"to raise, to educate",pos:"verb",gender:null,note:"Irregular: erzieht, erzog, hat erzogen. Er- + ziehen (to pull).\nGut erzogen (well-raised) is a compliment.",example:"A: Wer hat dich erzogen?\nB: Meine Gro\u00dfeltern. Meine Eltern haben viel gearbeitet.\nA: Wie haben sie dich erzogen?\nB: Streng, aber liebevoll. Gut erzogen, sagen die Nachbarn.",exampleSrc:"A: Who raised you?\nB: My grandparents. My parents worked a lot.\nA: How did they raise you?\nB: Strictly, but lovingly. Well-raised, say the neighbors.",funFact:"Kinder erziehen (to raise children) uses the same verb. Der Erzieher/die Erzieherin works in kindergartens. In the DDR, the state played a large role in Erziehung."},
{type:"mc",q:"Hildi sagt, sie und ihr Mann haben einander vertraut. Was bedeutet einander hier?",opts:["themselves","always","nobody","each other"],ans:"each other",hint:"Einander ist das explizit reziproke Wort, ohne Mehrdeutigkeit."},
{type:"fb",s:"W\u00e4hrend der {1} Jahre in der DDR erlebte Hildi viel.",a:["langen"],opts:["langen","lange","langer","langem"],hint:"Nach der im Genitiv Plural enden Adjektive auf -en. Immer.",sSrc:"During the long years in the GDR, Hildi experienced a lot."},
{type:"drag_fill",s:"Trotz {1} Angst halfen die Nachbarn {2}. Sie zeigten {3} Mut.",blanks:{"1":"gro\u00dfer","2":"einander","3":"echten"},pool:["gro\u00dfer","einander","echten","gro\u00dfe","sich","echter"],hint:"Trotz + Genitiv feminin ohne Artikel = -er. Sich gegenseitig helfen = einander. Echten: Akkusativ maskulin ohne Artikel = -en.",sSrc:"Despite great fear, the neighbors helped each other. They showed real courage."}
]},

// Lesson 6: Du kannst ruhig du sagen (Story climax, 24 steps, 16 new words)
{id:"deu_r21l6",title:"Du kannst ruhig du sagen",icon:"\uD83E\uDD1D",xp:15,board:true,steps:[
{type:"intro",title:"Du kannst ruhig du sagen",desc:"Experience the Sie-to-du switch as an emotional milestone. Learn vocabulary for institutions, discovery, and pressure. Practice all three grammar constructions in combination.",goals:["Experience the Sie-to-du switch as a sign of trust","Learn 16 new words about institutions and discovery","Combine all three grammar constructions"]},
{type:"story",speaker:"hildi",mood:"warm",art:"de-ber-stairwell",trg:"Verumius... wir kennen uns jetzt seit fast einem Jahr. Wir haben einander durch schwierige Zeiten geholfen. Du kannst ruhig du sagen.",src:"Verumius... we have known each other for almost a year now. We have helped each other through difficult times. You can go ahead and say du."},
{type:"story",speaker:"verumius",mood:"moved",art:"de-ber-stairwell",trg:"Das... das bedeutet mir sehr viel, Hildi. Danke. Ich meine... danke, dass du mir vertraust.",src:"That... that means a lot to me, Hildi. Thank you. I mean... thank you for trusting me."},
{type:"story",speaker:"narrator",mood:"warm",art:"de-lei-restaurant",trg:"Am n\u00e4chsten Tag fahren Mia und Verumius in ein Leipziger Restaurant. Mia bestellt auf S\u00e4chsisch. Der Kellner antwortet auf S\u00e4chsisch. Verumius versteht ungef\u00e4hr die H\u00e4lfte.",src:"The next day, Mia and Verumius go to a Leipzig restaurant. Mia orders in Saxon dialect. The waiter answers in Saxon dialect. Verumius understands about half."},
{type:"teach",trg:"der Standpunkt",src:"the point of view",pos:"noun",gender:"m",note:"Stand (standing) + Punkt (point). The point where you stand.\nMeinen Standpunkt vertreten = to represent my point of view.",example:"A: Was ist dein Standpunkt zur Wiedervereinigung?\nB: Einerseits war sie notwendig. Andererseits war sie schwer.\nA: Das ist ein differenzierter Standpunkt.\nB: Ja, einfache Antworten gibt es hier nicht.",exampleSrc:"A: What is your point of view on reunification?\nB: On one hand it was necessary. On the other hand it was hard.\nA: That is a nuanced point of view.\nB: Yes, there are no simple answers here.",funFact:"Your Standpunkt is the ground you stand on. More concrete than Meinung (opinion). Meinen Standpunkt vertreten (to represent my point of view) implies firmness and conviction."},
{type:"teach",trg:"die Einf\u00fchrung",src:"the introduction",pos:"noun",gender:"f",note:"Ein (in) + F\u00fchrung (leading). Leading into something.\nAlso: the introduction section of a book.",example:"A: Was war die Einf\u00fchrung der D-Mark im Osten?\nB: Ein wichtiger Schritt. Im Juli 1990.\nA: War das gut?\nB: Einerseits ja. Andererseits gingen viele Betriebe bankrott.",exampleSrc:"A: What was the introduction of the D-Mark in the East?\nB: An important step. In July 1990.\nA: Was that good?\nB: On one hand yes. On the other hand many businesses went bankrupt.",funFact:"Die Einf\u00fchrung des Euro (the introduction of the Euro) changed everyday life. The word works for introducing systems, currencies, or ideas. Einf\u00fchrungskurs (introductory course) uses the same root."},
{type:"teach",trg:"die Erfindung",src:"the invention",pos:"noun",gender:"f",note:"From erfinden (to invent). Er- + finden (to find).\nFinding something into existence.",example:"A: Was sind ber\u00fchmte deutsche Erfindungen?\nB: Der Buchdruck, das Aspirin, das MP3-Format.\nA: Das MP3-Format?\nB: Ja, vom Fraunhofer-Institut. Eine deutsche Erfindung.",exampleSrc:"A: What are famous German inventions?\nB: The printing press, aspirin, the MP3 format.\nA: The MP3 format?\nB: Yes, from the Fraunhofer Institute. A German invention.",funFact:"Deutsche Erfindungen include the printing press (Gutenberg), aspirin (Bayer), and the MP3 format (Fraunhofer). Er- + finden: to find something into existence. Every invention is a finding."},
{type:"teach",trg:"die T\u00e4tigkeit",src:"activity, occupation",pos:"noun",gender:"f",note:"From t\u00e4tig (active). Berufliche T\u00e4tigkeit = professional activity.\nMore formal than Arbeit (work).",example:"A: Was ist deine T\u00e4tigkeit?\nB: Ich arbeite als Sozialarbeiter.\nA: Ist das eine ehrenamtliche T\u00e4tigkeit?\nB: Nein, das ist mein Beruf. Ehrenamtlich arbeite ich im Tierheim.",exampleSrc:"A: What is your occupation?\nB: I work as a social worker.\nA: Is that a voluntary activity?\nB: No, that is my profession. I volunteer at the animal shelter.",funFact:"Berufliche T\u00e4tigkeit (professional activity) is what official forms ask for. Ehrenamtliche T\u00e4tigkeit (volunteer work) is highly valued in Germany. Over 30 million Germans volunteer regularly."},
{type:"teach",trg:"die Vertretung",src:"representation, substitute",pos:"noun",gender:"f",note:"From vertreten (to represent). Die Vertretung der B\u00fcrger\nis what parliament does.",example:"A: Wer ist die Vertretung des Chefs?\nB: Heute bin ich die Vertretung.\nA: Und im Parlament?\nB: Das Parlament ist die Vertretung des Volkes.",exampleSrc:"A: Who is the substitute for the boss?\nB: Today I am the substitute.\nA: And in parliament?\nB: Parliament is the representation of the people.",funFact:"Die Vertretung der B\u00fcrger (representation of citizens) is what parliament does. Also: Ich bin die Vertretung (I am the substitute) when someone is absent from work. One word, two contexts."},
{type:"teach",trg:"der Vertreter",src:"the representative (male)",pos:"noun",gender:"m",note:"From vertreten. Handelsvertreter = sales representative.\nVolksvertreter = people's representative (politician).",example:"A: Wer vertritt die B\u00fcrger?\nB: Die Abgeordneten. Sie sind Vertreter des Volkes.\nA: Und in der DDR?\nB: Da gab es auch Volksvertreter. Aber ohne freie Wahlen.",exampleSrc:"A: Who represents the citizens?\nB: The delegates. They are representatives of the people.\nA: And in the GDR?\nB: There were also people's representatives. But without free elections.",funFact:"In the DDR, Volksvertreter (people's representatives) was an ironic term since the people could not choose them. Today, Vertreter implies genuine representation."},
{type:"teach",trg:"die Vertreterin",src:"the representative (female)",pos:"noun",gender:"f",note:"The -in suffix marks the feminine form.\nUsed in all formal contexts.",example:"A: Wer ist die Vertreterin der Gewerkschaft?\nB: Frau M\u00fcller. Sie verhandelt f\u00fcr die Arbeiter.\nA: Ist sie eine gute Vertreterin?\nB: Ja, sie k\u00e4mpft f\u00fcr faire L\u00f6hne.",exampleSrc:"A: Who is the union representative?\nB: Mrs. M\u00fcller. She negotiates for the workers.\nA: Is she a good representative?\nB: Yes, she fights for fair wages.",funFact:"Modern German increasingly uses both forms in official documents: Vertreterinnen und Vertreter. Die Vertreterin der Gewerkschaft (the union representative) negotiates for workers' rights."},
{type:"teach",trg:"der Druck",src:"pressure, print",pos:"noun",gender:"m",note:"Two meanings, one word. Unter Druck stehen = to be under pressure.\nDruckerei = printing house. Gutenberg: der Buchdruck.",example:"A: Standen die Menschen in der DDR unter Druck?\nB: Ja, enormem Druck. Politisch und pers\u00f6nlich.\nA: Und was bedeutet Druck noch?\nB: Drucken! Gutenberg hat den Buchdruck erfunden.",exampleSrc:"A: Were the people in the GDR under pressure?\nB: Yes, enormous pressure. Politically and personally.\nA: And what else does Druck mean?\nB: Printing! Gutenberg invented book printing.",funFact:"Unter Druck stehen (to be under pressure) and Buchdruck (book printing) use the same word. Gutenberg's invention was der Buchdruck. Context separates the meanings clearly."},
{type:"teach",trg:"das Gold",src:"gold",pos:"noun",gender:"n",note:"Same word in English and German. Neuter, like most metals.\nMorgenstund hat Gold im Mund = the early bird catches the worm.",example:"A: Ist Leipzig die goldene Stadt?\nB: Nein, aber es gibt goldene Momente hier.\nA: Wie welche?\nB: Sonnenuntergang am Marktplatz. Pure goldene Stunde.",exampleSrc:"A: Is Leipzig the golden city?\nB: No, but there are golden moments here.\nA: Like what?\nB: Sunset at the market square. Pure golden hour.",funFact:"Goldene Zeiten (golden times) is an idiom. Morgenstund hat Gold im Mund (the morning hour has gold in its mouth) means the early bird catches the worm. Most metals are neuter in German: das Gold, das Silber."},
{type:"teach",trg:"der Gott",src:"God",pos:"noun",gender:"m",note:"From Proto-Germanic guthon. Gott sei Dank = Thank God.\nGenitive: Gottes. Gottesdienst = church service.",example:"A: Sagen Deutsche Gott sei Dank?\nB: Ja, auch Leute, die nicht religi\u00f6s sind.\nA: Was bedeutet Gottesdienst?\nB: Kirchendienst. W\u00f6rtlich: Gottes Dienst.",exampleSrc:"A: Do Germans say Thank God?\nB: Yes, even people who are not religious.\nA: What does Gottesdienst mean?\nB: Church service. Literally: God's service.",funFact:"Gott sei Dank (Thank God) is everyday German, even for atheists. Um Gottes willen! (For God's sake!) expresses shock. Gottesdienst (church service) literally means God's service. The genitive form Gottes appears in many compounds."},
{type:"teach",trg:"das Kreuz",src:"the cross",pos:"noun",gender:"n",note:"From Latin crux. Das Rote Kreuz = the Red Cross.\nKreuzung = intersection/crossroads.",example:"A: Was bedeutet das Kreuz in der Nikolaikirche?\nB: Es ist ein christliches Symbol. Und ein Symbol des Friedens.\nA: Und Kreuzung?\nB: Eine Stra\u00dfenkreuzung. Wo Wege sich kreuzen.",exampleSrc:"A: What does the cross in the Nikolaikirche mean?\nB: It is a Christian symbol. And a symbol of peace.\nA: And Kreuzung?\nB: A road intersection. Where paths cross.",funFact:"In Bavaria, a cross hangs in every classroom and courtroom. In the rest of Germany, this is controversial. Kreuzfahrt (cruise) literally means cross-journey, from the Crusades. Das Rote Kreuz (Red Cross) is recognized worldwide."},
{type:"teach",trg:"die Uniform",src:"the uniform",pos:"noun",gender:"f",note:"Same word in both languages. Represents both the clothing\nand the conformity it represents.",example:"A: Trugen die Soldaten an der Mauer Uniformen?\nB: Ja, immer. Die Uniform zeigte die Macht des Staates.\nA: Und die Demonstranten?\nB: Keine Uniformen. Nur Kerzen und Mut.",exampleSrc:"A: Did the soldiers at the Wall wear uniforms?\nB: Yes, always. The uniform showed the power of the state.\nA: And the demonstrators?\nB: No uniforms. Only candles and courage.",funFact:"The DDR used Uniformen to show state power. The 1989 protesters faced people in Uniform and stayed peaceful. The contrast between uniformed soldiers and candle-carrying citizens defines that night."},
{type:"teach",trg:"\u00fcbrigens",src:"by the way",pos:"adv",gender:null,note:"From \u00fcbrig (remaining/left over). What remains to be said.\nA casual conversation pivot.",example:"A: \u00dcbrigens, wei\u00dft du was?\nB: Was denn?\nA: Hildi hat mir das Du angeboten!\nB: Wirklich? Das ist ein gro\u00dfer Schritt!",exampleSrc:"A: By the way, you know what?\nB: What?\nA: Hildi offered me the Du!\nB: Really? That is a big step!",funFact:"\u00dcbrigens is beloved by Germans who change topics mid-sentence. It serves as a casual conversation pivot: whatever was \u00fcbrig (left over, remaining) to be said. Essential for natural German conversation."},
{type:"teach",trg:"vorhin",src:"a little while ago, earlier",pos:"adv",gender:null,note:"More specific than fr\u00fcher (earlier in general).\nRefers to something in the recent past, usually the same day.",example:"A: Was hast du vorhin gesagt?\nB: Dass Leipzig eine besondere Stadt ist.\nA: Vorhin im Restaurant?\nB: Ja, als wir das Leipziger Allerlei gegessen haben.",exampleSrc:"A: What did you say earlier?\nB: That Leipzig is a special city.\nA: Earlier in the restaurant?\nB: Yes, when we were eating the Leipziger Allerlei.",funFact:"Vorhin refers to something in the recent past, usually the same day. Was hast du vorhin gemeint? (What did you mean earlier?) is everyday German. More specific than fr\u00fcher (earlier in general)."},
{type:"teach",trg:"beeinflussen",src:"to influence",pos:"verb",gender:null,note:"Be- + Einfluss (influence) + -en. To apply influence.\nInseparable: always beeinflussen, never einfluss-be.",example:"A: Hat Leipzig die deutsche Geschichte beeinflusst?\nB: Enorm. Die friedliche Revolution hat alles ver\u00e4ndert.\nA: Und heute?\nB: Leipzig beeinflusst die Kultur. Musik, Kunst, Startups.",exampleSrc:"A: Did Leipzig influence German history?\nB: Enormously. The peaceful revolution changed everything.\nA: And today?\nB: Leipzig influences culture. Music, art, startups.",funFact:"Die Medien beeinflussen die \u00f6ffentliche Meinung (The media influence public opinion). Inseparable: always beeinflussen, never broken apart. Every influence is a flowing-in of ideas."},
{type:"teach",trg:"entdecken",src:"to discover",pos:"verb",gender:null,note:"Ent- (removing) + decken (to cover). To uncover.\nEvery discovery is an uncovering.",example:"A: Was hast du in Leipzig entdeckt?\nB: Viel! Die Geschichte, die Kultur, das Essen.\nA: Was war die beste Entdeckung?\nB: Auerbachs Keller. Dort hat Goethe geschrieben!",exampleSrc:"A: What did you discover in Leipzig?\nB: A lot! The history, the culture, the food.\nA: What was the best discovery?\nB: Auerbachs Keller. Goethe wrote there!",funFact:"Ent- + decken (to cover): to uncover. Amerika entdecken (to discover America) and Ich habe ein tolles Restaurant entdeckt (I discovered a great restaurant) use the same logic. Every discovery is an uncovering of something hidden."},
{type:"mc",q:"W\u00e4hrend des _____ Krieges verstanden Ost und West einander kaum. Welches Wort passt?",opts:["Kalter","Kalten","Kalte","Kaltem"],ans:"Kalten",hint:"Nach des (Genitiv) enden Adjektive immer auf -en."},
{type:"fb",s:"Leipzig hat {1} Architektur aus verschiedenen Jahrhunderten.",a:["historische"],opts:["historische","historisch","historischer","historischem"],hint:"Architektur ist feminin Akkusativ. Ohne Artikel nimmt das Adjektiv die starke Endung -e.",sSrc:"Leipzig has historic architecture from different centuries."},
{type:"drag_fill",s:"W\u00e4hrend {1} Zeiten half die Gemeinschaft {2}. Die B\u00fcrger zeigten {3} Mut.",blanks:{"1":"schwieriger","2":"einander","3":"gro\u00dfen"},pool:["schwieriger","einander","gro\u00dfen","schwierigen","sich","gro\u00dfer"],hint:"W\u00e4hrend + Genitiv Plural ohne Artikel = -er. Sich gegenseitig helfen = einander. Akkusativ maskulin ohne Artikel = -en.",sSrc:"During difficult times the community helped each other. The citizens showed great courage."},
{type:"mc",q:"Wenn Hildi sagt Du kannst ruhig du sagen, was passiert?",opts:["Sie bittet ihn zu gehen","Sie bietet die informelle Anrede als Zeichen des Vertrauens an","Sie korrigiert seine Grammatik","Sie bringt ihm ein neues Wort bei"],ans:"Sie bietet die informelle Anrede als Zeichen des Vertrauens an",hint:"Der Wechsel von Sie zu du ist ein Meilenstein in deutschen Beziehungen."}
]},

// Lesson 7: Zeitzeugen (Comprehensive quiz, 22 steps, 10 new words)
{id:"deu_r21l7",title:"Zeitzeugen",icon:"\uD83D\uDCDA",xp:15,board:true,steps:[
{type:"intro",title:"Zeitzeugen",desc:"Master all three grammar constructions through intensive practice. Combine adjective declension, genitive forms, and reciprocal verbs in real contexts.",goals:["Master all three grammar constructions","Combine two or more constructions per exercise","Show what you have learned about Leipzig and German history"]},
{type:"teach",trg:"die Zeichnung",src:"the drawing",pos:"noun",gender:"f",note:"From zeichnen (to draw). Zeichen (sign) + -ung.\nTechnische Zeichnung = technical drawing.",example:"A: Was ist das f\u00fcr eine Zeichnung?\nB: Eine Zeichnung der Nikolaikirche. Aus dem 19. Jahrhundert.\nA: Wer hat sie gemacht?\nB: Ein unbekannter K\u00fcnstler.",exampleSrc:"A: What kind of drawing is that?\nB: A drawing of the Nikolaikirche. From the 19th century.\nA: Who made it?\nB: An unknown artist.",funFact:"The -ung suffix turns verbs into nouns describing the result: zeichnen becomes Zeichnung. Technische Zeichnung (technical drawing) and Bauzeichnung (architectural drawing) are professional terms."},
{type:"teach",trg:"der Nachwuchs",src:"offspring, young talent",pos:"noun",gender:"m",note:"Nach (after) + Wuchs (growth). What grows after you.\nAlso a gentle way to ask about children.",example:"A: Hat Leipzig guten Nachwuchs in der Musik?\nB: Ja! Viele junge Musiker studieren hier.\nA: Und in der Politik?\nB: Auch. Der politische Nachwuchs ist aktiv.",exampleSrc:"A: Does Leipzig have good young talent in music?\nB: Yes! Many young musicians study here.\nA: And in politics?\nB: Also. The young political talent is active.",funFact:"Nachwuchsf\u00f6rderung (support for young talent) is important in German sports, arts, and industry. Nachwuchs literally means what grows after you: the next generation of talent."},
{type:"teach",trg:"der Sozialarbeiter",src:"the social worker (male)",pos:"noun",gender:"m",note:"Sozial + Arbeiter (worker). Sozialarbeit is a respected\nprofession in Germany.",example:"A: Was macht ein Sozialarbeiter?\nB: Er hilft Menschen in schwierigen Situationen.\nA: Zum Beispiel?\nB: Bei der Integration, bei Jugendproblemen, in Gemeinden.",exampleSrc:"A: What does a social worker do?\nB: He helps people in difficult situations.\nA: For example?\nB: With integration, with youth problems, in communities.",funFact:"Sozialarbeit (social work) is a respected profession in Germany. Many Sozialarbeiter help with integration, youth programs, and community building. The profession grew significantly after reunification."},
{type:"teach",trg:"die Sozialarbeiterin",src:"the social worker (female)",pos:"noun",gender:"f",note:"The -in suffix marks the feminine form.\nThe profession grew significantly after reunification.",example:"A: Arbeitest du als Sozialarbeiterin?\nB: Ja, in einem Jugendprojekt.\nA: Macht dir die Arbeit Spa\u00df?\nB: Ja, ich helfe jungen Menschen. Das ist erfu\u0308llend.",exampleSrc:"A: Do you work as a social worker?\nB: Yes, in a youth project.\nA: Do you enjoy the work?\nB: Yes, I help young people. That is fulfilling.",funFact:"In Germany, Sozialarbeiterinnen und Sozialarbeiter work in schools, hospitals, refugee centers, and community organizations. The profession is essential for social cohesion."},
{type:"teach",trg:"hierher",src:"here (to this place)",pos:"adv",gender:null,note:"Hier (here) + her (toward the speaker). Directional: motion toward here.\nKomm hierher! = Come here!",example:"A: Wie bist du hierher gekommen?\nB: Mit dem ICE. Von Berlin nach Leipzig.\nA: Komm hierher! Ich zeige dir etwas.\nB: Was denn?",exampleSrc:"A: How did you get here?\nB: By ICE. From Berlin to Leipzig.\nA: Come here! I will show you something.\nB: What?",funFact:"Hierher is directional: motion toward the speaker. Hier means at this place (no motion). Wie bist du hierher gekommen? (How did you get here?) implies the journey. Contrasts with dorthin (to there)."},
{type:"teach",trg:"stammen",src:"to come from, to originate",pos:"verb",gender:null,note:"Always about origins, never current residence.\nDas Wort stammt aus dem Lateinischen = The word comes from Latin.",example:"A: Woher stammst du?\nB: Ich stamme aus Leipzig. Aber ich lebe in Berlin.\nA: Und dieses Geb\u00e4ude?\nB: Es stammt aus dem 16. Jahrhundert.",exampleSrc:"A: Where do you come from originally?\nB: I come from Leipzig. But I live in Berlin.\nA: And this building?\nB: It dates from the 16th century.",funFact:"Ich stamme aus Leipzig (I come from Leipzig originally) is always about origins, never about current residence. Das Wort stammt aus dem Lateinischen (The word comes from Latin). Stamm means trunk, the root of a tree."},
{type:"teach",trg:"\u00fcbernehmen",src:"to take over, to adopt",pos:"verb",gender:null,note:"\u00dcber (over) + nehmen (to take). Inseparable in this meaning.\nVerantwortung \u00fcbernehmen = to take on responsibility.",example:"A: Wer hat nach der Wende Verantwortung \u00fcbernommen?\nB: Viele B\u00fcrgerrechtler.\nA: Haben sie politische \u00c4mter \u00fcbernommen?\nB: Ja, einige wurden Politiker.",exampleSrc:"A: Who took on responsibility after the Wende?\nB: Many civil rights activists.\nA: Did they take on political offices?\nB: Yes, some became politicians.",funFact:"Verantwortung \u00fcbernehmen (to take on responsibility) is a key phrase in German civic life. Die Firma wurde \u00fcbernommen (The company was taken over) uses the business meaning."},
{type:"teach",trg:"\u00fcberpr\u00fcfen",src:"to check, to verify",pos:"verb",gender:null,note:"\u00dcber (over) + pr\u00fcfen (to test). Testing thoroughly.\nMore thorough than pr\u00fcfen alone.",example:"A: Hast du die Fakten \u00fcberpr\u00fcft?\nB: Ja, alles stimmt.\nA: Gut. Man muss immer \u00fcberpr\u00fcfen.\nB: Besonders bei historischen Themen.",exampleSrc:"A: Have you verified the facts?\nB: Yes, everything is correct.\nA: Good. One must always verify.\nB: Especially with historical topics.",funFact:"Die Fakten \u00fcberpr\u00fcfen (to verify the facts) is essential in journalism and history. Inseparable: the \u00fcber- adds completeness and thoroughness to the basic pr\u00fcfen (to test)."},
{type:"teach",trg:"ver\u00f6ffentlichen",src:"to publish",pos:"verb",gender:null,note:"Ver- + \u00f6ffentlich (public) + -en. To make public.\nInseparable. Every publication is a making-public.",example:"A: Wurde die Geschichte von Leipzig ver\u00f6ffentlicht?\nB: Ja, in vielen B\u00fcchern und Dokumentationen.\nA: Wer hat dar\u00fcber ver\u00f6ffentlicht?\nB: Historiker, Zeitzeugen, Journalisten.",exampleSrc:"A: Was the story of Leipzig published?\nB: Yes, in many books and documentaries.\nA: Who published about it?\nB: Historians, contemporary witnesses, journalists.",funFact:"Ein Buch ver\u00f6ffentlichen (to publish a book) literally means to make a book public. Die Ergebnisse wurden ver\u00f6ffentlicht (The results were published). Inseparable and formal."},
{type:"teach",trg:"verschwinden",src:"to disappear",pos:"verb",gender:null,note:"Ver- + schwinden (to dwindle). Irregular: verschwindet, verschwand,\nist verschwunden. Spurlos verschwunden = vanished without a trace.",example:"A: Ist die Mauer komplett verschwunden?\nB: Fast. Nur kleine Teile stehen noch.\nA: Wohin ist sie verschwunden?\nB: Abgerissen. St\u00fccke als Souvenirs auf der ganzen Welt.",exampleSrc:"A: Has the Wall completely disappeared?\nB: Almost. Only small parts still stand.\nA: Where did it disappear to?\nB: Torn down. Pieces as souvenirs around the world.",funFact:"Spurlos verschwunden (vanished without a trace) was a feared phrase in the DDR. People sometimes verschwanden if they opposed the state. Today, die Mauer ist fast verschwunden (the Wall has almost disappeared) is a statement of progress."},
{type:"mc",q:"Trotz _____ Wetters tranken sie _____ Kaffee im Freien. (bad, hot)",opts:["schlechten / hei\u00dfen","schlechter / hei\u00dfen","schlechtem / hei\u00dfer","schlechtes / hei\u00dfe"],ans:"schlechten / hei\u00dfen",hint:"Trotz + Genitiv (mit Artikel) = -en. Hei\u00dfer Kaffee = maskulin Akkusativ ohne Artikel = -en."},
{type:"fb",s:"Die B\u00fcrger aus Ost und West mussten lernen, {1} zu vertrauen.",a:["einander"],opts:["einander","sich","ihnen","zusammen"],hint:"Explizit reziprok (each other) = einander, nicht sich.",sSrc:"The citizens from East and West had to learn to trust each other."},
{type:"mc",q:"_____ Fortschritt braucht Zeit. (Real progress, ohne Artikel)",opts:["Echtem Fortschritt","Echtes Fortschritt","Echter Fortschritt","Echte Fortschritt"],ans:"Echter Fortschritt",hint:"Fortschritt ist maskulin Nominativ. Ohne Artikel: starke Endung -er (wie der)."},
{type:"drag_fill",s:"W\u00e4hrend {1} Versammlungen zeigten die B\u00fcrger {2} gro\u00dfen Mut. Sie halfen {3} ohne {4} Angst.",blanks:{"1":"der","2":"einander","3":"einander","4":"gro\u00dfe"},pool:["der","einander","einander","gro\u00dfe","gro\u00dfer","sich"],hint:"W\u00e4hrend + Genitiv Plural mit Artikel = der. Gegenseitig = einander (zweimal). Ohne + Akkusativ feminin ohne Artikel = -e.",sSrc:"During the assemblies the citizens showed each other great courage. They helped each other without great fear."},
{type:"mc",q:"Die Rede eines _____ Politikers. Welche Form ist korrekt?",opts:["erfahrene","erfahrenem","erfahrener","erfahrenen"],ans:"erfahrenen",hint:"Nach eines (Genitiv) enden Adjektive IMMER auf -en."},
{type:"fb",s:"Sie sprachen mit {1} Stolz \u00fcber ihre Stadt.",a:["gro\u00dfem"],opts:["gro\u00dfem","gro\u00dfer","gro\u00dfen","gro\u00dfes"],hint:"Stolz ist maskulin. Dativ ohne Artikel nimmt -em (wie dem).",sSrc:"They spoke with great pride about their city."},
{type:"mc",q:"Die Nachbarn sorgten _____. (for each other)",opts:["f\u00fcreinander","miteinander","f\u00fcr einander","f\u00fcr sich"],ans:"f\u00fcreinander",hint:"F\u00fcr + einander mit Pr\u00e4position = ein Wort: f\u00fcreinander."},
{type:"teach",trg:"unterschiedlich",src:"different, varying",pos:"adj",gender:null,note:"Unter (between) + schiedlich (separated).\nSynonym: verschieden. Antonym: gleich.",example:"A: Die Erfahrungen in Ost und West sind unterschiedlich.\nB: Ja, die Generationen hatten unterschiedliche Leben.\nA: Aber sie lernen voneinander.\nB: Das ist wichtig.",exampleSrc:"A: The experiences in East and West are different.\nB: Yes, the generations had different lives.\nA: But they learn from each other.\nB: That is important.",funFact:"From unterscheiden (to distinguish). Things that can be told apart are unterschiedlich. Unterschiedliche Meinungen (different opinions) are valued in German Diskussionskultur."},
{type:"drag_fill",s:"Wegen {1} Vergangenheit verstehen Ost und West {2} manchmal nicht. Trotzdem arbeiten sie {3}.",blanks:{"1":"unterschiedlicher","2":"einander","3":"miteinander"},pool:["unterschiedlicher","einander","miteinander","unterschiedlichen","sich","f\u00fcreinander"],hint:"Wegen + Genitiv feminin ohne Artikel = -er. Nicht verstehen (each other) = einander. Zusammenarbeiten = miteinander.",sSrc:"Because of a different past, East and West sometimes do not understand each other. Nevertheless they work together."},
{type:"mc",q:"Welcher Satz verwendet Genitiv + Adjektiv ohne Artikel korrekt?",opts:["Trotz kaltem Wetters tranken sie hei\u00dfer Tee","Trotz kaltes Wetters tranken sie hei\u00dfe Tee","Trotz kalter Wetters tranken sie hei\u00dfes Tee","Trotz kalten Wetters tranken sie hei\u00dfen Tee"],ans:"Trotz kalten Wetters tranken sie hei\u00dfen Tee",hint:"Genitiv neutral ohne Artikel: kalten Wetters. Akkusativ maskulin ohne Artikel: hei\u00dfen Tee."},
{type:"fb",s:"Die Friedensgebete in der Nikolaikirche haben die {1} v\u00f6llig ver\u00e4ndert.",a:["Gesellschaft"],opts:["Gesellschaft","Gemeinschaft","Versammlung","Bev\u00f6lkerung"],hint:"Welches Wort bedeutet Gesellschaft als Gesamtstruktur, nicht nur lokale Gemeinschaft?",sSrc:"The peace prayers in the Nikolaikirche completely changed society."},
{type:"match",pairs:[{trg:"Flucht",src:"escape"},{trg:"Erfindung",src:"invention"},{trg:"Standpunkt",src:"point of view"},{trg:"Heimweh",src:"homesickness"},{trg:"Nachwuchs",src:"young talent"}]}
]},

// Lesson 8: Leipziger Allerlei (Resolution + culture, 22 steps, 14 new words)
{id:"deu_r21l8",title:"Leipziger Allerlei",icon:"\uD83C\uDF72",xp:15,board:true,steps:[
{type:"intro",title:"Leipziger Allerlei",desc:"Wrap up the Leipzig visit with culture and food. Learn the final vocabulary. Meet the Saxon dialect. Reflect on what Leipzig teaches about German identity.",goals:["Learn the final 14 vocabulary words of the unit","Discover Saxon dialect and regional culture","Reflect on Leipzig's significance for German identity"]},
{type:"story",speaker:"mia",mood:"playful",art:"de-lei-restaurant",trg:"Leipziger Allerlei! Das Traditionsgericht. Fr\u00fcher war es ein Gem\u00fcse-Eintopf f\u00fcr reiche Leute. Heute isst es jeder. \u00dcbrigens: Bestell nicht auf S\u00e4chsisch. Der Kellner lacht sonst.",src:"Leipziger Allerlei! The traditional dish. It used to be a vegetable stew for rich people. Today everyone eats it. By the way: do not order in Saxon. The waiter will laugh."},
{type:"story",speaker:"narrator",mood:"warm",art:"de-lei-restaurant",trg:"Mia spricht mit dem Kellner. Ihr S\u00e4chsisch kommt zur\u00fcck wie ein alter Freund. Verumius versteht: Leipzig ist nicht nur Geschichte. Es ist Mias Heimat, der Ort, von dem sie stammt. Und sie teilt ihn mit ihm.",src:"Mia talks to the waiter. Her Saxon comes back like an old friend. Verumius understands: Leipzig is not just history. It is Mia's home, the place she comes from. And she is sharing it with him."},
{type:"teach",trg:"die \u00c4nderung",src:"the change, the alteration",pos:"noun",gender:"f",note:"From \u00e4ndern (to change) + -ung. More concrete than Ver\u00e4nderung.\nAn \u00c4nderung is a specific adjustment, not a deep transformation.",example:"A: Gibt es \u00c4nderungen im Fahrplan?\nB: Ja, ab n\u00e4chster Woche.\nA: Was f\u00fcr \u00c4nderungen?\nB: Neue Abfahrtszeiten f\u00fcr den ICE nach Berlin.",exampleSrc:"A: Are there changes in the schedule?\nB: Yes, starting next week.\nA: What kind of changes?\nB: New departure times for the ICE to Berlin.",funFact:"\u00c4nderung der \u00d6ffnungszeiten (change of opening hours) is a common sign in German shops. More concrete than Ver\u00e4nderung (transformation). An \u00c4nderung is a specific, deliberate adjustment."},
{type:"teach",trg:"die Entwickelung",src:"the development (variant)",pos:"noun",gender:"f",note:"Older spelling variant of Entwicklung. Both forms are recognized.\nYou may encounter this in historical texts.",example:"A: Warum steht hier Entwickelung mit e?\nB: Das ist eine \u00e4ltere Schreibweise.\nA: Ist das falsch?\nB: Nein, nur altmodisch. Heute schreibt man Entwicklung.",exampleSrc:"A: Why does it say Entwickelung with an e here?\nB: That is an older spelling.\nA: Is that wrong?\nB: No, just old-fashioned. Today we write Entwicklung.",funFact:"Entwickelung is an older spelling variant of Entwicklung. The -e- in the middle reflects an earlier pronunciation pattern. You may encounter it in historical texts or older academic writing."},
{type:"teach",trg:"der Frieden",src:"peace",pos:"noun",gender:"m",note:"The more common variant of Friede. In Frieden leben = to live in peace.\nFriedensvertrag = peace treaty.",example:"A: Leben wir in Frieden?\nB: In Deutschland ja. Seit \u00fcber 80 Jahren.\nA: Ist Frieden selbstverst\u00e4ndlich?\nB: Nein. Leipzig zeigt, dass man daf\u00fcr k\u00e4mpfen muss.",exampleSrc:"A: Do we live in peace?\nB: In Germany yes. For over 80 years.\nA: Is peace taken for granted?\nB: No. Leipzig shows that you have to fight for it.",funFact:"Frieden is the more common variant of Friede. In Frieden leben (to live in peace) is what the 1989 demonstrators fought for. Friedensnobelpreis (Nobel Peace Prize) and Friedensvertrag (peace treaty) use this form."},
{type:"teach",trg:"der Kreis",src:"the circle, the district",pos:"noun",gender:"m",note:"Im Kreis stehen = to stand in a circle. Landkreis = rural district.\nFreundeskreis = circle of friends.",example:"A: Was ist ein Landkreis?\nB: Ein Verwaltungsbezirk. Eine Region.\nA: Und ein Freundeskreis?\nB: Die Gruppe von Freunden, die man hat.",exampleSrc:"A: What is a Landkreis?\nB: An administrative district. A region.\nA: And a Freundeskreis?\nB: The group of friends that you have.",funFact:"From Latin circus via Old High German. One shape, many meanings. Im Kreis stehen (to stand in a circle) is literal. Landkreis (rural district) is administrative. Freundeskreis (circle of friends) is social."},
{type:"teach",trg:"einf\u00fchren",src:"to introduce, to import",pos:"verb",gender:null,note:"Ein (in) + f\u00fchren (to lead). Leading something in. Separable.\nEr f\u00fchrt ein neues Gesetz ein.",example:"A: Wann wurde die D-Mark im Osten eingef\u00fchrt?\nB: Im Juli 1990.\nA: Und der Euro?\nB: 2002. Er wurde in ganz Europa eingef\u00fchrt.",exampleSrc:"A: When was the D-Mark introduced in the East?\nB: In July 1990.\nA: And the Euro?\nB: 2002. It was introduced across all of Europe.",funFact:"Ein neues System einf\u00fchren (to introduce a new system) and Waren einf\u00fchren (to import goods) use the same verb. Separable: Er f\u00fchrt ein neues Gesetz ein. The Einf\u00fchrung der D-Mark changed East German lives overnight."},
{type:"teach",trg:"gr\u00fcnden",src:"to found, to establish",pos:"verb",gender:null,note:"From Grund (ground/reason). To give something ground to stand on.\nEine Firma gr\u00fcnden = to found a company.",example:"A: Wann wurde die Universit\u00e4t Leipzig gegr\u00fcndet?\nB: 1409. Eine der \u00e4ltesten in Deutschland.\nA: Und das Gewandhaus-Orchester?\nB: 1743 gegr\u00fcndet. Eines der \u00e4ltesten der Welt.",exampleSrc:"A: When was the University of Leipzig founded?\nB: 1409. One of the oldest in Germany.\nA: And the Gewandhaus Orchestra?\nB: Founded in 1743. One of the oldest in the world.",funFact:"Leipzig's university was gegr\u00fcndet in 1409 and is one of the oldest in Germany. Eine Firma gr\u00fcnden (to found a company) uses the same verb. Die Gr\u00fcnder (the founders) are celebrated in German startup culture."},
{type:"teach",trg:"vertreten",src:"to represent",pos:"verb",gender:null,note:"Ver- + treten (to step). To step in for someone. Inseparable.\nIch vertrete die Meinung, dass... = I hold the view that...",example:"A: Wer vertritt die Interessen der B\u00fcrger?\nB: Die gew\u00e4hlten Abgeordneten.\nA: Vertrittst du einen Standpunkt?\nB: Ja: Leipzig verdient mehr Anerkennung.",exampleSrc:"A: Who represents the interests of the citizens?\nB: The elected delegates.\nA: Do you hold a point of view?\nB: Yes: Leipzig deserves more recognition.",funFact:"Die Interessen der B\u00fcrger vertreten (to represent citizens' interests) is the core function of parliament. Also: sich die Beine vertreten (to stretch one's legs) uses the same verb differently."},
{type:"teach",trg:"anderseits",src:"on the other hand (contracted)",pos:"adv",gender:null,note:"Contracted form of andererseits. More common in spoken German.\nBoth spellings are correct.",example:"A: Einerseits ist das Leipziger Allerlei traditionell.\nB: Anderseits hat sich das Rezept ver\u00e4ndert.\nA: Ist anderseits richtig?\nB: Ja, genauso wie andererseits.",exampleSrc:"A: On one hand the Leipziger Allerlei is traditional.\nB: On the other hand the recipe has changed.\nA: Is anderseits correct?\nB: Yes, just like andererseits.",funFact:"Anderseits is a contracted form of andererseits. More common in spoken German. Academic writing prefers andererseits. All three forms (andererseits, anderseits, andrerseits) are correct."},
{type:"teach",trg:"andrerseits",src:"on the other hand (contracted variant)",pos:"adv",gender:null,note:"Another contracted variant of andererseits. Regional preference.\nAll three forms are grammatically correct and interchangeable.",example:"A: Andrerseits muss man auch die andere Seite sehen.\nB: Stimmt. Es gibt immer zwei Seiten.\nA: Einerseits... andrerseits...\nB: Genau. So argumentiert man auf Deutsch.",exampleSrc:"A: On the other hand, one must also see the other side.\nB: True. There are always two sides.\nA: On one hand... on the other hand...\nB: Exactly. That is how you argue in German.",funFact:"Andrerseits is another contracted variant of andererseits. Regional preference determines which form people use. All three (andererseits, anderseits, andrerseits) are interchangeable."},
{type:"teach",trg:"hieher",src:"to here (regional/archaic)",pos:"adv",gender:null,note:"Regional/archaic variant of hierher. Common in Austrian German.\nRecognizing variants helps you understand real spoken German.",example:"A: Komm hieher! Schau dir das an!\nB: Ist hieher ein Dialektwort?\nA: Ja, die \u00f6sterreichische Variante von hierher.\nB: Ah, gut zu wissen!",exampleSrc:"A: Come here! Look at this!\nB: Is hieher a dialect word?\nA: Yes, the Austrian variant of hierher.\nB: Ah, good to know!",funFact:"Hieher is a regional variant of hierher, common in Austrian German and older texts. Komm hieher! = Komm hierher! Standard German uses hierher. Recognizing variants helps you understand real spoken German."},
{type:"teach",trg:"haupt-",src:"main, chief (prefix)",pos:"part",gender:null,note:"A prefix that makes any word more important.\nHauptstadt (capital), Hauptbahnhof (main station), Hauptsache (main thing).",example:"A: Was ist die Hauptstadt von Sachsen?\nB: Dresden. Aber Leipzig ist die gr\u00f6\u00dfere Stadt.\nA: Und die Hauptsache?\nB: Die Hauptsache ist, dass du Leipzig gesehen hast!",exampleSrc:"A: What is the capital of Saxony?\nB: Dresden. But Leipzig is the larger city.\nA: And the main thing?\nB: The main thing is that you have seen Leipzig!",funFact:"Haupt- appears in hundreds of compounds. Hauptstadt (capital city), Hauptbahnhof (main train station), Hauptsache (main thing). Leipzig Hauptbahnhof was the starting point of this unit."},
{type:"teach",trg:"unter-",src:"under, sub- (prefix)",pos:"part",gender:null,note:"A prefix meaning below, beneath, or subordinate.\nUnterschied (difference), Unterst\u00fctzung (support), Unterricht (instruction).",example:"A: Was bedeutet Unterschied?\nB: Differenz. Unter + Schied, von scheiden (trennen).\nA: Und Unterricht?\nB: Bildung, Lehre. Unter + richten (lenken).",exampleSrc:"A: What does Unterschied mean?\nB: Difference. Unter + Schied, from scheiden (to separate).\nA: And Unterricht?\nB: Education, teaching. Unter + richten (to direct).",funFact:"Unterschied (difference) literally means under-separation. Unterst\u00fctzung (support) means under-propping. Unterricht (instruction) means under-direction. Unter- is one of German's most productive prefixes."},
{type:"story",speaker:"mia",mood:"forward-looking",art:"de-lei-restaurant",trg:"N\u00e4chste Woche startet das Umweltprojekt im B\u00fcro. Du sollst auch mitmachen, Verumius. Einerseits ist es viel Arbeit. Andererseits k\u00f6nnen wir etwas ver\u00e4ndern.",src:"Next week the environmental project starts at the office. You should join in too, Verumius. On one hand it is a lot of work. On the other hand we can change something."},
{type:"mc",q:"Welche drei W\u00f6rter sind Varianten desselben Konzepts (on the other hand)?",opts:["\u00fcbrigens / andererseits / vorhin","einander / andererseits / \u00fcberhaupt","einerseits / anderseits / gleichzeitig","andererseits / anderseits / andrerseits"],ans:"andererseits / anderseits / andrerseits",hint:"Alle drei kommen von anderer Seite, nur mit verschiedenen Kontraktionen."},
{type:"fb",s:"Leipzig {1}bahnhof ist einer der gr\u00f6\u00dften Bahnh\u00f6fe Europas.",a:["Haupt"],opts:["Haupt","Unter","Vor","Nach"],hint:"Welches Pr\u00e4fix bedeutet main oder chief?",sSrc:"Leipzig main train station is one of the largest train stations in Europe."},
{type:"mc",q:"W\u00e4hrend der friedlichen Revolution k\u00e4mpften die B\u00fcrger f\u00fcr _____ Freiheit. (complete, ohne Artikel)",opts:["politische","politischen","politischer","politischem"],ans:"politische",hint:"Freiheit ist feminin Akkusativ. Ohne Artikel: starke Endung -e."},
{type:"drag_fill",s:"Die B\u00fcrger einer {1} Stadt halfen {2} im Kampf um Freiheit. Trotz {3} Drucks von der Regierung blieben sie friedlich.",blanks:{"1":"gro\u00dfen","2":"einander","3":"enormen"},pool:["gro\u00dfen","einander","enormen","gro\u00dfer","sich","enormer"],hint:"Nach einer (Genitiv feminin): -en. Sich gegenseitig helfen: einander. Trotz + Genitiv maskulin ohne Artikel = -en.",sSrc:"The citizens of a large city helped each other in the fight for freedom. Despite enormous pressure from the government they stayed peaceful."},
{type:"mc",q:"Was macht das Leipziger Allerlei kulturell bedeutend?",opts:["Es war einst ein Luxusgericht, das zum Alltagsessen wurde","Es wurde w\u00e4hrend der Revolution 1989 erfunden","Es wird nur auf S\u00e4chsisch serviert","Es ist eine Brotsorte aus Ostdeutschland"],ans:"Es war einst ein Luxusgericht, das zum Alltagsessen wurde",hint:"Mia erkl\u00e4rte, es war fr\u00fcher f\u00fcr reiche Leute, heute isst es jeder."},
{type:"teach",trg:"enorm",src:"enormous, tremendous",pos:"adj",gender:null,note:"From Latin enormis (out of the norm).\nEnormer Einfluss = enormous influence.",example:"A: Leipzig hatte einen enormen Einfluss auf die Musik.\nB: Ja, Bach, Mendelssohn, Schumann.\nA: Der Einfluss war enorm.\nB: Und auf die Politik auch.",exampleSrc:"A: Leipzig had an enormous influence on music.\nB: Yes, Bach, Mendelssohn, Schumann.\nA: The influence was enormous.\nB: And on politics too.",funFact:"From Latin enormis (out of the norm). Something enorm is literally beyond the normal scale. Germans use it frequently in both formal and informal contexts."},
{type:"match",pairs:[{trg:"\u00c4nderung",src:"change"},{trg:"Frieden",src:"peace"},{trg:"Kreis",src:"circle/district"},{trg:"gr\u00fcnden",src:"to found"},{trg:"einander",src:"each other"}]}
]}

]},

{n:22,lang:"de",srcLang:"en",track:"v2",title:"Umwelt und Alltag",sub:"Environment, sustainability, Partizip I+II as adjectives, lassen causative",icon:"\u267B\uFE0F",level:"B1.2",color:"#7B5EE8",lessons:[

// ============================================================
// Lesson 1: Nachhaltigkeit im Büro (Sustainability in the Office)
// Type: Story intro. 18 new words. 24 steps.
// Scene: Office conference room. Verumius presents in German.
// ============================================================
{id:"deu_r22l1",title:"Nachhaltigkeit im B\u00fcro",icon:"\u267B\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Nachhaltigkeit im B\u00fcro",desc:"Verumius steht vor seinen Kollegen und h\u00e4lt eine Pr\u00e4sentation. Auf Deutsch. Sein Thema: Nachhaltigkeit im B\u00fcro. Zeit, die wichtigsten Umweltw\u00f6rter zu lernen.",goals:["Lerne 18 zentrale W\u00f6rter rund um Umwelt und Klima","Begleite Verumius bei seiner ersten Pr\u00e4sentation auf Deutsch","Verstehe Trends und Statistiken zum Thema Nachhaltigkeit"]},
{type:"story",speaker:"narrator",mood:"proud",art:"de-office-presentation",trg:"Ein Jahr in Berlin. Verumius steht vor seinen Kollegen und h\u00e4lt eine Pr\u00e4sentation. Auf Deutsch. Mia sitzt in der zweiten Reihe und nickt ermutigend. Sein Thema: Nachhaltigkeit im B\u00fcro.",src:"One year in Berlin. Verumius stands before his colleagues and gives a presentation. In German. Mia sits in the second row, nodding encouragingly. His topic: sustainability in the office."},
{type:"teach",trg:"die Umwelt",src:"the environment",pos:"noun",gender:"f",note:"Um (around) + Welt (world). Everything that surrounds you.\nGermans rank environmental protection as a top political priority.",example:"A: Was ist dir wichtig?\nB: Die Umwelt ist mir sehr wichtig.\nA: Was tust du f\u00fcr die Umwelt?\nB: Ich trenne meinen M\u00fcll und spare Strom.",exampleSrc:"A: What is important to you?\nB: The environment is very important to me.\nA: What do you do for the environment?\nB: I separate my trash and save electricity.",funFact:"Um (around) + Welt (world). The world around you. Germans rank environmental protection as a top political priority. The Umwelt is not just nature. It is everything that surrounds you."},
{type:"teach",trg:"der Umweltschutz",src:"environmental protection",pos:"noun",gender:"m",note:"Umwelt + Schutz (protection). Germany pioneered the Green Party in 1980.\nEmbedded in Article 20a of the German constitution.",example:"A: Was bedeutet Umweltschutz f\u00fcr dich?\nB: Weniger Plastik, mehr Recycling.\nA: Ist Umweltschutz in Deutschland wichtig?\nB: Ja, es steht sogar im Grundgesetz.",exampleSrc:"A: What does environmental protection mean to you?\nB: Less plastic, more recycling.\nA: Is environmental protection important in Germany?\nB: Yes, it is even in the constitution.",funFact:"Umwelt + Schutz (protection). Germany pioneered the Green Party (Die Gr\u00fcnen) in 1980. Umweltschutz is embedded in Article 20a of the German constitution."},
{type:"teach",trg:"die Energie",src:"energy",pos:"noun",gender:"f",note:"From Greek 'energeia' (activity). The Energiewende aims to\nphase out nuclear and fossil fuels in Germany.",example:"A: Woher kommt unsere Energie?\nB: Immer mehr aus Wind und Sonne.\nA: Und der Rest?\nB: Noch aus Kohle und Gas, leider.",exampleSrc:"A: Where does our energy come from?\nB: More and more from wind and sun.\nA: And the rest?\nB: Still from coal and gas, unfortunately.",funFact:"From Greek 'energeia' (activity). 'Erneuerbare Energie' (renewable energy) is Germany's obsession. The Energiewende (energy transition) aims to phase out nuclear and fossil fuels."},
{type:"teach",trg:"das Klima",src:"the climate",pos:"noun",gender:"n",note:"From Greek 'klima' (inclination/region). Neuter.\n'Klimawandel' (climate change) dominates German news.",example:"A: Wie ist das Klima in Deutschland?\nB: Mild, aber es \u00e4ndert sich.\nA: Der Klimawandel?\nB: Ja, die Sommer werden hei\u00dfer.",exampleSrc:"A: What is the climate like in Germany?\nB: Mild, but it is changing.\nA: Climate change?\nB: Yes, the summers are getting hotter.",funFact:"From Greek 'klima' (inclination/region). 'Klimawandel' (climate change) and 'Klimaschutz' (climate protection) dominate German news. 'Klimaneutral' is the target."},
{type:"teach",trg:"der Strom",src:"electricity",pos:"noun",gender:"m",note:"Also means 'stream' or 'current.' From the flowing motion.\n'\u00d6kostrom' (green electricity) is a real product you can buy.",example:"A: Wie viel Strom verbrauchen wir?\nB: Zu viel. Wir m\u00fcssen sparen.\nA: Haben wir \u00d6kostrom?\nB: Ja, seit letztem Jahr.",exampleSrc:"A: How much electricity do we use?\nB: Too much. We need to save.\nA: Do we have green electricity?\nB: Yes, since last year.",funFact:"'Electricity' AND 'stream/current.' From the flowing motion of electric current. '\u00d6kostrom' (green electricity) is a real product you can buy. 'Der Strom flie\u00dft' works for rivers and wires."},
{type:"teach",trg:"die Luft",src:"the air",pos:"noun",gender:"f",note:"Cognate with English 'loft' (high air). 'Frische Luft' is\na German prescription for everything.",example:"A: Die Luft hier ist nicht gut.\nB: Ja, zu viele Autos.\nA: Geh an die frische Luft!\nB: Gute Idee. Ich gehe in den Park.",exampleSrc:"A: The air here is not good.\nB: Yes, too many cars.\nA: Get some fresh air!\nB: Good idea. I'll go to the park.",funFact:"Cognate with English 'loft' (high air). 'Frische Luft' (fresh air) is a German prescription for everything. Feeling tired? 'Geh an die frische Luft!' Air quality is a major environmental metric."},
{type:"teach",trg:"der Boden",src:"the ground, soil, floor",pos:"noun",gender:"m",note:"Triple meaning: 'fruchtbarer Boden' (fertile soil),\n'Erdboden' (ground), 'Fu\u00dfboden' (floor).",example:"A: Der Boden hier ist sehr fruchtbar.\nB: Ja, perfekt f\u00fcr Gem\u00fcse.\nA: Und der Fu\u00dfboden im B\u00fcro?\nB: Der muss auch sauber bleiben!",exampleSrc:"A: The soil here is very fertile.\nB: Yes, perfect for vegetables.\nA: And the floor in the office?\nB: That needs to stay clean too!",funFact:"Triple meaning. 'Fruchtbarer Boden' (fertile soil), 'Erdboden' (ground), 'Fu\u00dfboden' (floor). Related to English 'bottom.' The foundation of everything."},
{type:"teach",trg:"die Erde",src:"the earth, soil",pos:"noun",gender:"f",note:"Both the planet and the dirt. Cognate with English 'earth.'\n'Die Erde dreht sich' (the earth turns).",example:"A: Die Erde ist unser einziger Planet.\nB: Deshalb m\u00fcssen wir sie sch\u00fctzen.\nA: Was liegt in der Erde?\nB: Samen, Wurzeln und Mineralien.",exampleSrc:"A: The earth is our only planet.\nB: That's why we have to protect it.\nA: What is in the soil?\nB: Seeds, roots, and minerals.",funFact:"Both the planet and the dirt. Cognate with English 'earth.' 'Die Erde dreht sich' (the earth turns). 'In der Erde' (in the soil). Like English, one word for planet and ground."},
{type:"teach",trg:"die Temperatur",src:"the temperature",pos:"noun",gender:"f",note:"From Latin 'temperatura.' Germany uses Celsius.\n30+ degrees is a heatwave. Most homes have no AC.",example:"A: Wie ist die Temperatur heute?\nB: 35 Grad! Viel zu hei\u00df.\nA: Das ist extrem f\u00fcr Deutschland.\nB: Ja, fr\u00fcher war das selten.",exampleSrc:"A: What is the temperature today?\nB: 35 degrees! Way too hot.\nA: That is extreme for Germany.\nB: Yes, it used to be rare.",funFact:"From Latin 'temperatura.' Germany uses Celsius. 0 degrees is freezing, 20 is comfortable, 30+ is a heatwave. Germans panic at 35 degrees because most homes have no air conditioning."},
{type:"teach",trg:"die Hitze",src:"the heat",pos:"noun",gender:"f",note:"From 'hei\u00df' (hot). 'Hitzewelle' (heatwave).\nGermany's record: 42.6 degrees Celsius in 2019.",example:"A: Diese Hitze ist unertr\u00e4glich!\nB: Ja, 40 Grad im Schatten.\nA: Hast du eine Klimaanlage?\nB: Nein, die braucht man hier normalerweise nicht.",exampleSrc:"A: This heat is unbearable!\nB: Yes, 40 degrees in the shade.\nA: Do you have air conditioning?\nB: No, you normally don't need it here.",funFact:"From 'hei\u00df' (hot). 'Hitzewelle' (heatwave). Germany's record: 42.6 degrees Celsius in 2019. 'Vor Hitze umkommen' (to perish from heat) is how Germans describe summer."},
{type:"teach",trg:"die Kontrolle",src:"the control, check, inspection",pos:"noun",gender:"f",note:"From French 'contr\u00f4le.' 'Qualit\u00e4tskontrolle' (quality control),\n'Passkontrolle' (passport check).",example:"A: Wir brauchen mehr Kontrolle.\nB: \u00dcber den Energieverbrauch?\nA: Ja, und \u00fcber die Abgase.\nB: Kontrolle ist der erste Schritt.",exampleSrc:"A: We need more control.\nB: Over energy consumption?\nA: Yes, and over exhaust fumes.\nB: Control is the first step.",funFact:"From French 'contr\u00f4le.' 'Qualit\u00e4tskontrolle' (quality control), 'Passkontrolle' (passport check). Germans love Kontrolle in all forms. Ordnung muss sein."},
{type:"teach",trg:"das System",src:"the system",pos:"noun",gender:"n",note:"From Greek 'systema.' Neuter. 'Das Pfandsystem' is world-famous.\nGermany recycles 70%+ of packaging.",example:"A: Das Pfandsystem funktioniert gut.\nB: Ja, Deutschland recycelt fast alles.\nA: Brauchen wir ein besseres System?\nB: F\u00fcr Plastik ja, definitiv.",exampleSrc:"A: The deposit system works well.\nB: Yes, Germany recycles almost everything.\nA: Do we need a better system?\nB: For plastic, yes, definitely.",funFact:"From Greek 'systema.' 'Das Pfandsystem' (deposit system) is world-famous. Germany recycles 70%+ of packaging. The system works because it is a System."},
{type:"teach",trg:"die Statistik",src:"statistics",pos:"noun",gender:"f",note:"From Latin 'statisticum' (of the state). Originally meant state data.\n'Laut Statistik' (according to statistics).",example:"A: Laut Statistik steigt die Temperatur.\nB: Wie viel pro Jahr?\nA: Im Durchschnitt 0,3 Grad.\nB: Das klingt wenig, ist aber viel.",exampleSrc:"A: According to statistics, the temperature is rising.\nB: How much per year?\nA: On average 0.3 degrees.\nB: That sounds little, but it is a lot.",funFact:"From Latin 'statisticum' (of the state). Originally meant state data. 'Laut Statistik' (according to statistics) is how German presentations begin. Germans trust numbers."},
{type:"teach",trg:"der Durchschnitt",src:"the average",pos:"noun",gender:"m",note:"Durch (through) + Schnitt (cut). A cut through the middle.\n'Im Durchschnitt' (on average).",example:"A: Was ist der Durchschnitt?\nB: Im Durchschnitt 20 Grad.\nA: Und dieses Jahr?\nB: \u00dcber dem Durchschnitt, leider.",exampleSrc:"A: What is the average?\nB: On average 20 degrees.\nA: And this year?\nB: Above average, unfortunately.",funFact:"Durch (through) + Schnitt (cut). A cut through the middle. The average. 'Im Durchschnitt' (on average). Literally slicing through data to find the middle. German compound logic at its finest."},
{type:"teach",trg:"steigen",src:"to rise, to climb",pos:"verb",gender:null,note:"Irregular: stieg, gestiegen. 'Die Temperaturen steigen.'\n'Einsteigen' (to board), 'aussteigen' (to exit).",example:"A: Die Preise steigen wieder.\nB: Ja, und die Temperaturen auch.\nA: Steigt auch der Meeresspiegel?\nB: Leider ja, jedes Jahr.",exampleSrc:"A: The prices are rising again.\nB: Yes, and the temperatures too.\nA: Is the sea level also rising?\nB: Unfortunately yes, every year.",funFact:"Irregular: stieg, gestiegen. 'Die Temperaturen steigen' (temperatures are rising). 'Einsteigen' (to board), 'aussteigen' (to exit). A verb of upward motion in every context."},
{type:"teach",trg:"sinken",src:"to sink, to fall, to decrease",pos:"verb",gender:null,note:"Irregular: sank, gesunken. 'Die Kosten sinken.'\nCognate with English 'sink.' The opposite of steigen.",example:"A: Sinkt der Energieverbrauch?\nB: Ja, langsam.\nA: Und die Kosten?\nB: Die sinken leider nicht.",exampleSrc:"A: Is energy consumption decreasing?\nB: Yes, slowly.\nA: And the costs?\nB: Those are unfortunately not decreasing.",funFact:"Irregular: sank, gesunken. 'Die Kosten sinken' (costs are falling). Cognate with English 'sink.' The opposite of steigen. These two verbs describe every graph."},
{type:"teach",trg:"reduzieren",src:"to reduce",pos:"verb",gender:null,note:"From Latin 'reducere.' The -ieren ending marks a borrowed verb.\nRegular conjugation. International and professional.",example:"A: Wir m\u00fcssen den Stromverbrauch reduzieren.\nB: Um wie viel Prozent?\nA: Um mindestens 30 Prozent.\nB: Das ist viel, aber machbar.",exampleSrc:"A: We need to reduce electricity consumption.\nB: By how many percent?\nA: By at least 30 percent.\nB: That is a lot, but doable.",funFact:"From Latin 'reducere.' The -ieren ending marks a borrowed verb. 'Emissionen reduzieren' (to reduce emissions). Regular conjugation. International and professional."},
{type:"teach",trg:"extrem",src:"extreme, extremely",pos:"adj",gender:null,note:"From Latin 'extremus.' Functions as both adjective and\nintensifying adverb. 'Extrem wichtig' (extremely important).",example:"A: Das Wetter ist extrem hei\u00df.\nB: Ja, 42 Grad ist extrem.\nA: Ist das normal?\nB: Nein, das ist extrem ungew\u00f6hnlich.",exampleSrc:"A: The weather is extremely hot.\nB: Yes, 42 degrees is extreme.\nA: Is that normal?\nB: No, that is extremely unusual.",funFact:"From Latin 'extremus.' 'Extreme Hitze' (extreme heat), 'extrem wichtig' (extremely important). Functions as both adjective and intensifying adverb. Germans use it like English 'extremely.'"},
{type:"story",speaker:"verumius",mood:"nervous",art:"de-office-presentation",trg:"Die steigenden Temperaturen sind ein Problem f\u00fcr alle. Im Durchschnitt verbraucht unser B\u00fcro 30 Prozent mehr Strom als n\u00f6tig. Das k\u00f6nnen wir reduzieren.",src:"The rising temperatures are a problem for everyone. On average our office uses 30 percent more electricity than necessary. We can reduce that."},
{type:"mc",q:"Verumius spricht \u00fcber den Stromverbrauch im B\u00fcro. Welches Wort bedeutet 'electricity'?",opts:["Stern","Sturm","Strom","Stein"],ans:"Strom",hint:"Dieses Wort bedeutet auch 'stream' oder 'current.' Es flie\u00dft durch Kabel."},
{type:"fb",s:"Die Temperaturen {1} jedes Jahr.",a:["steigen"],opts:["steigen","sinken","reduzieren","kontrollieren"],hint:"Welches Verb bedeutet 'to rise'? Die Temperaturen gehen nach oben, nicht nach unten.",sSrc:"The temperatures rise every year."},
{type:"match",pairs:[{trg:"Umwelt",src:"environment"},{trg:"Klima",src:"climate"},{trg:"Energie",src:"energy"},{trg:"Durchschnitt",src:"average"}]}
]},

// ============================================================
// Lesson 2: Grün denken (Thinking Green)
// Type: Vocab teach. 20 new words. 24 steps.
// Pure vocabulary: waste, materials, trade, industry.
// ============================================================
{id:"deu_r22l2",title:"Gr\u00fcn denken",icon:"\ud83c\udf3f",xp:15,board:true,steps:[
{type:"intro",title:"Gr\u00fcn denken",desc:"M\u00fclltrennung, Recycling, Materialien und Handel. Heute baust du dein Umwelt-Vokabular aus.",goals:["Lerne W\u00f6rter f\u00fcr Abfall und Recycling","Verstehe Material- und Handelsvokabular","Baue dein Umwelt-Toolkit auf"]},
{type:"teach",trg:"der Abfall",src:"the waste, garbage",pos:"noun",gender:"m",note:"Ab (off/away) + Fall (fall). Something that falls away.\n'Abfall trennen' (to separate waste) is a German commandment.",example:"A: Wo kommt der Abfall hin?\nB: In die richtige Tonne, nat\u00fcrlich.\nA: Und wenn man den Abfall nicht trennt?\nB: Dann \u00e4rgern sich die Nachbarn.",exampleSrc:"A: Where does the garbage go?\nB: In the right bin, of course.\nA: And if you don't separate the waste?\nB: Then the neighbors get annoyed.",funFact:"Ab (off/away) + Fall (fall). Something that falls away, waste. 'Abfall trennen' (to separate waste) is a German commandment. Every German household sorts into at least four bins."},
{type:"teach",trg:"der Abfalleimer",src:"the trash can",pos:"noun",gender:"m",note:"Abfall + Eimer (bucket). Germans have color-coded bins:\nyellow for packaging, blue for paper, brown for organic.",example:"A: Wo ist der Abfalleimer?\nB: In der K\u00fcche, neben dem K\u00fchlschrank.\nA: Welcher Abfalleimer f\u00fcr Plastik?\nB: Der gelbe. Immer der gelbe.",exampleSrc:"A: Where is the trash can?\nB: In the kitchen, next to the fridge.\nA: Which trash can for plastic?\nB: The yellow one. Always the yellow one.",funFact:"Abfall + Eimer (bucket). Waste bucket. Germans have color-coded Abfalleimer: yellow for packaging, blue for paper, brown for organic. Putting wrong items in the wrong bin is a social crime."},
{type:"teach",trg:"die M\u00fcllabfuhr",src:"garbage collection",pos:"noun",gender:"f",note:"M\u00fcll (trash) + Abfuhr (removal). In Germany, you pay\nper kilogram of trash. Less waste means lower bills.",example:"A: Wann kommt die M\u00fcllabfuhr?\nB: Montags f\u00fcr Restm\u00fcll.\nA: Und f\u00fcr Papier?\nB: Jeden zweiten Mittwoch.",exampleSrc:"A: When does garbage collection come?\nB: Mondays for residual waste.\nA: And for paper?\nB: Every other Wednesday.",funFact:"M\u00fcll (trash) + Abfuhr (removal). 'Die M\u00fcllabfuhr kommt montags' (The garbage truck comes on Mondays). In Germany, you pay per kilogram of trash. Less waste means lower bills."},
{type:"teach",trg:"die M\u00fclltonne",src:"the wheelie bin",pos:"noun",gender:"f",note:"M\u00fcll + Tonne (barrel/bin). Every German address has\nM\u00fclltonnen in four colors. Wrong sorting is a social crime.",example:"A: Die M\u00fclltonne ist voll.\nB: Welche? Die gelbe oder die blaue?\nA: Die braune. Zu viel Bioabfall.\nB: Dann m\u00fcssen wir kompostieren.",exampleSrc:"A: The wheelie bin is full.\nB: Which one? The yellow or the blue one?\nA: The brown one. Too much organic waste.\nB: Then we need to compost.",funFact:"M\u00fcll + Tonne (barrel/bin). Every German address has M\u00fclltonnen in four colors. Putting the wrong item in the wrong Tonne is a social crime that neighbors will correct."},
{type:"teach",trg:"das Plastik",src:"plastic",pos:"noun",gender:"n",note:"From Greek 'plastikos' (moldable). Neuter.\nGermany banned single-use plastic bags in 2022.",example:"A: Ist das aus Plastik?\nB: Ja, leider. Zu viel Plastik.\nA: Gibt es eine Alternative?\nB: Ja, aus Glas oder Holz.",exampleSrc:"A: Is that made of plastic?\nB: Yes, unfortunately. Too much plastic.\nA: Is there an alternative?\nB: Yes, made of glass or wood.",funFact:"From Greek 'plastikos' (moldable). Germany banned single-use plastic bags in 2022. 'Plastikfrei' (plastic-free) is a lifestyle movement. The Pfand system tackles plastic bottles."},
{type:"teach",trg:"der Kunststoff",src:"plastic (formal), synthetic material",pos:"noun",gender:"m",note:"Kunst (art/artificial) + Stoff (material). The formal word\nfor plastic. Preferred in industry and science.",example:"A: Ist das Plastik oder Kunststoff?\nB: Das ist dasselbe. Kunststoff ist formeller.\nA: Was ist 'Kunststoffverpackung'?\nB: Verpackung aus Plastik. F\u00fcr die gelbe Tonne.",exampleSrc:"A: Is that Plastik or Kunststoff?\nB: That is the same thing. Kunststoff is more formal.\nA: What is 'Kunststoffverpackung'?\nB: Packaging made of plastic. For the yellow bin.",funFact:"Kunst (art/artificial) + Stoff (material). Literally 'artificial material.' The formal German word for plastic. 'Kunststoffverpackung' (plastic packaging). More technical than Plastik, preferred in industry."},
{type:"teach",trg:"das Holz",src:"wood",pos:"noun",gender:"n",note:"Cognate with English 'holt' (a small wood). 'Aus Holz' (made of wood).\nThe Black Forest is 60% of Baden-W\u00fcrttemberg's area.",example:"A: Woraus ist dieser Tisch?\nB: Aus Holz. Massives Eichenholz.\nA: Holz ist nachhaltig, oder?\nB: Ja, wenn es aus nachhaltiger Forstwirtschaft kommt.",exampleSrc:"A: What is this table made of?\nB: Wood. Solid oak wood.\nA: Wood is sustainable, right?\nB: Yes, if it comes from sustainable forestry.",funFact:"Cognate with English 'holt' (a small wood). 'Aus Holz' (made of wood). Germany's Black Forest (Schwarzwald) covers 60% of Baden-W\u00fcrttemberg. 'Holz hacken' (to chop wood) is a German weekend activity."},
{type:"teach",trg:"das Metall",src:"metal",pos:"noun",gender:"n",note:"From Greek 'metallon' (mine/quarry). Neuter.\nGermany recycles 93% of metal packaging.",example:"A: Ist das aus Metall?\nB: Ja, aus Aluminium.\nA: Kommt das in die gelbe Tonne?\nB: Ja, Metall geh\u00f6rt zum Verpackungsm\u00fcll.",exampleSrc:"A: Is that made of metal?\nB: Yes, aluminum.\nA: Does that go in the yellow bin?\nB: Yes, metal belongs with packaging waste.",funFact:"From Greek 'metallon' (mine/quarry). Neuter. 'Altmetall' (scrap metal). Germany recycles 93% of metal packaging. 'Schwermetall' means both heavy metal (chemistry) and heavy metal (music)."},
{type:"teach",trg:"das Material",src:"material",pos:"noun",gender:"n",note:"From Latin 'materialis.' Neuter. Plural: Materialien.\n'Baumaterial' (building material), 'Rohmaterial' (raw material).",example:"A: Welches Material ist das?\nB: Recyceltes Material.\nA: Aus welchem Material ist deine Tasche?\nB: Aus recyceltem Kunststoff.",exampleSrc:"A: What material is that?\nB: Recycled material.\nA: What material is your bag made of?\nB: From recycled synthetic material.",funFact:"From Latin 'materialis.' Neuter. 'Baumaterial' (building material), 'Rohmaterial' (raw material). International word, same in dozens of languages. Plural: Materialien."},
{type:"teach",trg:"der Stoff",src:"material, fabric, substance",pos:"noun",gender:"m",note:"Triple meaning: 'Rohstoff' (raw material), 'Baumwollstoff'\n(cotton fabric), 'Unterrichtsstoff' (lesson material).",example:"A: Was f\u00fcr ein Stoff ist das?\nB: Baumwolle. Ein nat\u00fcrlicher Stoff.\nA: Ist Plastik auch ein Stoff?\nB: Ja, ein k\u00fcnstlicher Stoff.",exampleSrc:"A: What kind of material is that?\nB: Cotton. A natural material.\nA: Is plastic also a material?\nB: Yes, an artificial material.",funFact:"Triple meaning. 'Rohstoff' (raw material), 'Werkstoff' (working material), 'Baumwollstoff' (cotton fabric). Also: 'Unterrichtsstoff' (lesson material). Anything that constitutes something."},
{type:"teach",trg:"die Ware",src:"goods, merchandise",pos:"noun",gender:"f",note:"'Waren' (goods, plural). 'Warenhaus' (department store).\nRelated to English 'ware' (as in hardware, silverware).",example:"A: Woher kommen diese Waren?\nB: Aus China. Die meisten Waren kommen von dort.\nA: Gibt es lokale Waren?\nB: Ja, im Bio-Markt.",exampleSrc:"A: Where do these goods come from?\nB: From China. Most goods come from there.\nA: Are there local goods?\nB: Yes, at the organic market.",funFact:"'Waren' (goods, plural). 'Hardware' and 'Software' were borrowed back from English. 'Warenhaus' (department store). Related to English 'ware' (as in hardware, silverware)."},
{type:"teach",trg:"der Handel",src:"trade, commerce",pos:"noun",gender:"m",note:"From 'handeln' (to trade/act). 'Einzelhandel' (retail),\n'Gro\u00dfhandel' (wholesale), 'Au\u00dfenhandel' (foreign trade).",example:"A: Der Handel mit China w\u00e4chst.\nB: Und der faire Handel?\nA: Der w\u00e4chst auch, aber langsamer.\nB: Handel ist wichtig f\u00fcr die Wirtschaft.",exampleSrc:"A: Trade with China is growing.\nB: And fair trade?\nA: That is growing too, but more slowly.\nB: Trade is important for the economy.",funFact:"From 'handeln' (to trade/act). 'Einzelhandel' (retail), 'Gro\u00dfhandel' (wholesale), 'Au\u00dfenhandel' (foreign trade). 'Fair Handel' (fair trade) is a growing movement."},
{type:"teach",trg:"der H\u00e4ndler",src:"dealer, trader",pos:"noun",gender:"m",note:"From Handel. 'Autoh\u00e4ndler' (car dealer),\n'Buchh\u00e4ndler' (bookseller). The -er suffix creates the agent.",example:"A: Kennst du einen guten H\u00e4ndler?\nB: Ja, den H\u00e4ndler auf dem Wochenmarkt.\nA: Was verkauft der H\u00e4ndler?\nB: Obst und Gem\u00fcse aus der Region.",exampleSrc:"A: Do you know a good trader?\nB: Yes, the trader at the weekly market.\nA: What does the trader sell?\nB: Fruit and vegetables from the region.",funFact:"From Handel. 'Autoh\u00e4ndler' (car dealer), 'Buchh\u00e4ndler' (bookseller). The -er suffix creates the person who does the action. A H\u00e4ndler handles Handel."},
{type:"teach",trg:"die H\u00e4ndlerin",src:"dealer, trader (female)",pos:"noun",gender:"f",note:"The feminine form. H\u00e4ndler + -in.\nGerman consistently creates feminine forms with -in.",example:"A: Die H\u00e4ndlerin auf dem Markt ist nett.\nB: Ja, sie verkauft Bio-Produkte.\nA: Ist die H\u00e4ndlerin jeden Tag da?\nB: Nur dienstags und samstags.",exampleSrc:"A: The female trader at the market is nice.\nB: Yes, she sells organic products.\nA: Is the trader there every day?\nB: Only on Tuesdays and Saturdays.",funFact:"The feminine form. H\u00e4ndler + -in. 'Die H\u00e4ndlerin auf dem Markt' (the female trader at the market). German consistently creates feminine forms with -in for person nouns."},
{type:"teach",trg:"der Export",src:"export",pos:"noun",gender:"m",note:"From Latin 'exportare' (to carry out). 'Made in Germany'\nis the world's most trusted export label.",example:"A: Was ist Deutschlands gr\u00f6\u00dfter Export?\nB: Autos, Maschinen und Chemie.\nA: Ist der Export wichtig?\nB: Ja, er treibt die Wirtschaft an.",exampleSrc:"A: What is Germany's biggest export?\nB: Cars, machines, and chemicals.\nA: Is export important?\nB: Yes, it drives the economy.",funFact:"From Latin 'exportare' (to carry out). 'Made in Germany' is the world's most trusted export label. Germany is the third-largest exporter globally. Cars, machines, chemicals."},
{type:"teach",trg:"der Import",src:"import",pos:"noun",gender:"m",note:"From Latin 'importare' (to carry in). The opposite of Export.\nGermany imports energy, raw materials, and coffee.",example:"A: Was importiert Deutschland?\nB: Viel Energie und Rohstoffe.\nA: Und Kaffee?\nB: Ja, Deutschland ist Europas gr\u00f6\u00dfter Kaffeetrinker.",exampleSrc:"A: What does Germany import?\nB: A lot of energy and raw materials.\nA: And coffee?\nB: Yes, Germany is Europe's biggest coffee consumer.",funFact:"From Latin 'importare' (to carry in). The opposite of Export. 'Importware' (imported goods). Germany imports energy, raw materials, and coffee. Germans are Europe's biggest coffee drinkers."},
{type:"teach",trg:"die Industrie",src:"industry",pos:"noun",gender:"f",note:"From Latin 'industria' (diligence). 'Schwerindustrie'\n(heavy industry). 'Industrie 4.0' is Germany's digital strategy.",example:"A: Die Industrie verbraucht viel Energie.\nB: Ja, besonders die Schwerindustrie.\nA: Gibt es gr\u00fcne Industrie?\nB: Ja, immer mehr Firmen werden nachhaltig.",exampleSrc:"A: Industry uses a lot of energy.\nB: Yes, especially heavy industry.\nA: Is there green industry?\nB: Yes, more and more companies are becoming sustainable.",funFact:"From Latin 'industria' (diligence). 'Schwerindustrie' (heavy industry). Germany's Ruhrgebiet was Europe's industrial heart. 'Industrie 4.0' is Germany's digital manufacturing strategy."},
{type:"teach",trg:"die Produktion",src:"production",pos:"noun",gender:"f",note:"From Latin 'productio.' The -tion ending is always feminine\nin German and always stressed on the last syllable.",example:"A: Die Produktion l\u00e4uft gut.\nB: Ja, aber sie verbraucht viel Strom.\nA: K\u00f6nnen wir die Produktion umstellen?\nB: Auf erneuerbare Energie, ja.",exampleSrc:"A: Production is going well.\nB: Yes, but it uses a lot of electricity.\nA: Can we switch the production?\nB: To renewable energy, yes.",funFact:"From Latin 'productio.' 'Massenproduktion' (mass production). 'Die Produktion einstellen' (to stop production). The -tion ending is always feminine in German and always stressed on the last syllable."},
{type:"teach",trg:"produzieren",src:"to produce",pos:"verb",gender:null,note:"The -ieren verb from Produktion. Regular conjugation.\n'In Deutschland produziert' (produced in Germany).",example:"A: Was produziert diese Fabrik?\nB: Solarpanels. Alles \u00f6kologisch.\nA: Produzieren sie auch f\u00fcr den Export?\nB: Ja, weltweit.",exampleSrc:"A: What does this factory produce?\nB: Solar panels. All ecological.\nA: Do they also produce for export?\nB: Yes, worldwide.",funFact:"The -ieren verb from Produktion. Regular conjugation. 'In Deutschland produziert' (produced in Germany). '\u00dcberproduzieren' (to overproduce). Reliable borrowed verb."},
{type:"teach",trg:"alternativ",src:"alternative",pos:"adj",gender:null,note:"From Latin 'alternare.' 'Alternative Energien' (alternative energies).\n'Die Alternative' (noun) means the alternative option.",example:"A: Gibt es alternative Energien?\nB: Ja, Wind und Sonne.\nA: Sind alternative Materialien teurer?\nB: Manchmal, aber sie sind besser f\u00fcr die Umwelt.",exampleSrc:"A: Are there alternative energies?\nB: Yes, wind and sun.\nA: Are alternative materials more expensive?\nB: Sometimes, but they are better for the environment.",funFact:"From Latin 'alternare.' 'Alternative Energien' (alternative energies), 'alternative Medizin' (alternative medicine). 'Die Alternative' (the noun) means the alternative option."},
{type:"teach",trg:"die Gelbe Tonne",src:"the yellow recycling bin",pos:"noun",gender:"f",note:"For packaging waste (Verpackung): plastic, aluminum, tetra paks.\nPart of Germany's Duales System (recycling system).",example:"A: Wohin kommt der Joghurtbecher?\nB: In die Gelbe Tonne.\nA: Und die Zeitung?\nB: In die Blaue Tonne. Papier ist blau.",exampleSrc:"A: Where does the yogurt cup go?\nB: In the yellow bin.\nA: And the newspaper?\nB: In the blue bin. Paper is blue.",funFact:"Germany's color-coded bin system: Gelbe Tonne (packaging), Blaue Tonne (paper), Braune Tonne (organic), Schwarze Tonne (residual waste). Getting it wrong can earn you a stern lecture from your neighbors."},
{type:"mc",q:"Dein deutscher Nachbar schimpft, weil du einen Joghurtbecher in die falsche Tonne geworfen hast. In welche Tonne geh\u00f6rt Verpackung?",opts:["Braune Tonne","Gelbe Tonne","Blaue Tonne","Schwarze Tonne"],ans:"Gelbe Tonne",hint:"Verpackung und Kunststoff kommen in die gelbe Tonne. Papier ist blau, Bio ist braun."},
{type:"fb",s:"Dieser Tisch ist aus {1} gemacht.",a:["Holz"],opts:["Holz","Metall","Luft","Handel"],hint:"Aus welchem Material besteht ein Tisch normalerweise? Denke an B\u00e4ume.",sSrc:"This table is made of wood."},
{type:"match",pairs:[{trg:"Handel",src:"trade"},{trg:"Export",src:"export"},{trg:"Industrie",src:"industry"},{trg:"Produktion",src:"production"}]}
]},

// ============================================================
// Lesson 3: Der Pfand-Meister (The Deposit Master)
// Type: Story dev + grammar intro. 18 new words. 24 steps.
// Scene: REWE Pfand machine callback to U4. Partizip I taught.
// ============================================================
{id:"deu_r22l3",title:"Der Pfand-Meister",icon:"\ud83c\udfaf",xp:15,board:true,steps:[
{type:"intro",title:"Der Pfand-Meister",desc:"Remember Unit 4? Verumius stood helplessly in front of the Pfandautomat. Today he is a pro. Along the way, learn an important grammar point: Partizip I as adjective.",goals:["Learn 18 words about danger, protection, and research","Understand Partizip I as adjective (die steigende Temperatur)","See how far Verumius has come since Unit 4"]},
{type:"story",speaker:"narrator",mood:"proud",art:"de-rewe-pfand",trg:"Erinnern Sie sich an Unit 4? Verumius stand ratlos vor dem Pfandautomaten. Heute schiebt er die Flaschen hinein wie ein Profi. Der lachende Verumius sammelt seinen Bon und geht zur Kasse.",src:"Remember Unit 4? Verumius stood helplessly in front of the deposit machine. Today he feeds the bottles in like a pro. The laughing Verumius collects his receipt and walks to the checkout."},
{type:"teach",trg:"das Abgas",src:"exhaust gas, emission",pos:"noun",gender:"n",note:"Ab (away) + Gas. The gas that goes away from the engine.\n'Abgasnormen' (emission standards) are strict in Germany.",example:"A: Die Abgase hier sind schrecklich.\nB: Ja, zu viele Autos.\nA: M\u00fcssen wir die Abgase reduzieren?\nB: Unbedingt. F\u00fcr bessere Luft.",exampleSrc:"A: The exhaust fumes here are terrible.\nB: Yes, too many cars.\nA: Do we have to reduce emissions?\nB: Absolutely. For better air.",funFact:"Ab (away) + Gas. Exhaust gas. 'Autoabgase' (car exhaust fumes). The word says what it is: gas that goes away from the engine. 'Abgasnormen' (emission standards) are strict in Germany."},
{type:"teach",trg:"die Gefahr",src:"danger",pos:"noun",gender:"f",note:"'In Gefahr' (in danger). 'Lebensgefahr' (mortal danger).\nFrom Old High German 'fara' (ambush).",example:"A: Ist das eine Gefahr f\u00fcr die Umwelt?\nB: Ja, eine gro\u00dfe Gefahr.\nA: Wie gro\u00df ist die Gefahr?\nB: Sehr gro\u00df. Wir m\u00fcssen handeln.",exampleSrc:"A: Is that a danger for the environment?\nB: Yes, a big danger.\nA: How big is the danger?\nB: Very big. We need to act.",funFact:"From Old High German 'fara' (ambush). 'In Gefahr' (in danger). 'Lebensgefahr' (mortal danger). 'Gef\u00e4hrlich' (dangerous). Danger originally meant an unexpected attack."},
{type:"teach",trg:"die Katastrophe",src:"catastrophe, disaster",pos:"noun",gender:"f",note:"From Greek 'katastrophe' (overturning). Germans say\n'Das ist eine Katastrophe!' for any major problem.",example:"A: Die \u00dcberschwemmung war eine Katastrophe.\nB: Ja, eine Naturkatastrophe.\nA: Gibt es mehr Katastrophen als fr\u00fcher?\nB: Ja, wegen des Klimawandels.",exampleSrc:"A: The flood was a catastrophe.\nB: Yes, a natural disaster.\nA: Are there more catastrophes than before?\nB: Yes, because of climate change.",funFact:"From Greek 'katastrophe' (overturning). 'Naturkatastrophe' (natural disaster), 'Umweltkatastrophe' (environmental disaster). Germans say 'Das ist eine Katastrophe!' for any major problem, from floods to late trains."},
{type:"teach",trg:"die Krise",src:"crisis",pos:"noun",gender:"f",note:"From Greek 'krisis' (decision/turning point). A Krise is\na turning point, not necessarily the end.",example:"A: Wir haben eine Klimakrise.\nB: Und eine Energiekrise.\nA: Jede Krise ist auch eine Chance.\nB: Stimmt. Wir m\u00fcssen uns \u00e4ndern.",exampleSrc:"A: We have a climate crisis.\nB: And an energy crisis.\nA: Every crisis is also an opportunity.\nB: True. We need to change.",funFact:"From Greek 'krisis' (decision/turning point). 'Klimakrise' (climate crisis), 'Wirtschaftskrise' (economic crisis). A Krise is a turning point, not necessarily the end. It demands a decision."},
{type:"teach",trg:"der Schutz",src:"protection",pos:"noun",gender:"m",note:"From 'sch\u00fctzen' (to protect). 'Umweltschutz,' 'Datenschutz,'\n'Mutterschutz.' Germans protect everything with a compound.",example:"A: Umweltschutz ist wichtig.\nB: Und Datenschutz auch.\nA: Was ist Mutterschutz?\nB: Schutz f\u00fcr schwangere Frauen bei der Arbeit.",exampleSrc:"A: Environmental protection is important.\nB: And data protection too.\nA: What is maternity protection?\nB: Protection for pregnant women at work.",funFact:"From 'sch\u00fctzen' (to protect). 'Umweltschutz' (environmental protection), 'Datenschutz' (data protection), 'Mutterschutz' (maternity protection). Germans protect everything with a compound."},
{type:"teach",trg:"die Sicherheit",src:"safety, security",pos:"noun",gender:"f",note:"From 'sicher' (safe/certain). The -heit suffix creates abstract nouns.\n'Verkehrssicherheit' (traffic safety).",example:"A: Die Sicherheit am Arbeitsplatz ist wichtig.\nB: Ja, Sicherheit geht vor.\nA: Was bedeutet Lebensmittelsicherheit?\nB: Dass unser Essen sicher ist.",exampleSrc:"A: Safety at the workplace is important.\nB: Yes, safety comes first.\nA: What does food safety mean?\nB: That our food is safe.",funFact:"From 'sicher' (safe/certain). 'Verkehrssicherheit' (traffic safety), 'Lebensmittelsicherheit' (food safety). The -heit suffix creates abstract nouns. Sicher + heit = the state of being safe."},
{type:"teach",trg:"die Forschung",src:"research",pos:"noun",gender:"f",note:"From 'forschen' (to research). Germany spends 3%+ of GDP\non Forschung. The Fraunhofer institutes are world-famous.",example:"A: Klimaforschung ist entscheidend.\nB: Ja, ohne Forschung keine L\u00f6sungen.\nA: Wer finanziert die Forschung?\nB: Meistens der Staat und die Industrie.",exampleSrc:"A: Climate research is crucial.\nB: Yes, without research no solutions.\nA: Who funds the research?\nB: Mostly the state and industry.",funFact:"From 'forschen' (to research). 'Klimaforschung' (climate research), 'Grundlagenforschung' (basic research). Germany spends 3%+ of GDP on Forschung. The Fraunhofer institutes are world-famous."},
{type:"teach",trg:"die Forderung",src:"demand, requirement",pos:"noun",gender:"f",note:"From 'fordern' (to demand). Not to be confused with 'f\u00f6rdern'\n(to promote/support). One Umlaut changes everything.",example:"A: Die Forderung nach Klimaschutz w\u00e4chst.\nB: Ja, die Leute fordern Ver\u00e4nderung.\nA: Was ist die wichtigste Forderung?\nB: Weniger Abgase bis 2030.",exampleSrc:"A: The demand for climate protection is growing.\nB: Yes, people are demanding change.\nA: What is the most important demand?\nB: Fewer emissions by 2030.",funFact:"From 'fordern' (to demand). Not to be confused with 'f\u00f6rdern' (to promote/support). One Umlaut changes demand into support. 'Die Forderung nach Klimaschutz' (the demand for climate protection)."},
{type:"teach",trg:"die Umfrage",src:"survey, poll",pos:"noun",gender:"f",note:"Um (around) + Frage (question). Asking around.\n'Laut einer Umfrage' (according to a survey).",example:"A: Laut einer Umfrage recyceln 90% der Deutschen.\nB: Das \u00fcberrascht mich nicht.\nA: Was sagt die Umfrage noch?\nB: Dass Klimaschutz Priorit\u00e4t Nummer eins ist.",exampleSrc:"A: According to a survey, 90% of Germans recycle.\nB: That doesn't surprise me.\nA: What else does the survey say?\nB: That climate protection is priority number one.",funFact:"Um (around) + Frage (question). Asking around. A survey or poll. 'Laut einer Umfrage' (according to a survey). Germans love Umfragen. Every news broadcast cites one."},
{type:"teach",trg:"sch\u00fctzen",src:"to protect",pos:"verb",gender:null,note:"'Die Umwelt sch\u00fctzen' (to protect the environment).\n'Sich sch\u00fctzen' (to protect oneself). Regular verb.",example:"A: Wie k\u00f6nnen wir die Umwelt sch\u00fctzen?\nB: Weniger Plastik benutzen.\nA: Und wie sch\u00fctzt du dich vor der Hitze?\nB: Ich bleibe im Schatten.",exampleSrc:"A: How can we protect the environment?\nB: Use less plastic.\nA: And how do you protect yourself from the heat?\nB: I stay in the shade.",funFact:"'Die Umwelt sch\u00fctzen' (to protect the environment). 'Sich sch\u00fctzen' (to protect oneself). Regular verb. The \u00fc-Umlaut gives it its distinctive German sound."},
{type:"teach",trg:"warnen",src:"to warn",pos:"verb",gender:null,note:"Cognate with English 'warn.' 'Vor Gefahr warnen'\n(to warn of danger). Regular verb.",example:"A: Ich warne dich vor der Hitze.\nB: Danke, ich nehme Wasser mit.\nA: Der Wetterdienst warnt vor Sturm.\nB: Dann bleibe ich lieber zu Hause.",exampleSrc:"A: I warn you about the heat.\nB: Thanks, I'll bring water.\nA: The weather service warns of a storm.\nB: Then I'd rather stay home.",funFact:"Cognate with English 'warn.' 'Vor Gefahr warnen' (to warn of danger). 'Unwetterwarnung' (severe weather warning). Regular verb. The Wetter-App sends Warnungen constantly."},
{type:"teach",trg:"fordern",src:"to demand",pos:"verb",gender:null,note:"No Umlaut. Different from 'f\u00f6rdern' (to support).\n'Wir fordern Klimaschutz' (We demand climate protection).",example:"A: Die Demonstranten fordern Klimaschutz.\nB: Was genau fordern sie?\nA: Weniger Abgase und mehr erneuerbare Energie.\nB: Das ist eine berechtigte Forderung.",exampleSrc:"A: The demonstrators demand climate protection.\nB: What exactly do they demand?\nA: Fewer emissions and more renewable energy.\nB: That is a legitimate demand.",funFact:"Different from 'f\u00f6rdern' (to support). No Umlaut here. 'Wir fordern Klimaschutz' (We demand climate protection). Regular verb. The missing dots change the meaning completely."},
{type:"teach",trg:"vermeiden",src:"to avoid",pos:"verb",gender:null,note:"Irregular: vermied, vermieden. 'Plastik vermeiden' (to avoid plastic).\nThe ver- prefix intensifies 'meiden' (to shun).",example:"A: Wie kann man Plastik vermeiden?\nB: Stoffbeutel benutzen.\nA: Kann man Abfall ganz vermeiden?\nB: Nicht ganz, aber stark reduzieren.",exampleSrc:"A: How can you avoid plastic?\nB: Use cloth bags.\nA: Can you completely avoid waste?\nB: Not entirely, but reduce it significantly.",funFact:"Irregular: vermied, vermieden. 'Plastik vermeiden' (to avoid plastic). 'Fehler vermeiden' (to avoid mistakes). The ver- prefix intensifies 'meiden' (to shun)."},
{type:"teach",trg:"verursachen",src:"to cause",pos:"verb",gender:null,note:"Ver- + Ursache (cause). 'Abgase verursachen Luftverschmutzung.'\nThe compound logic: to cause = to make into a cause.",example:"A: Was verursacht die Luftverschmutzung?\nB: Vor allem Abgase.\nA: Verursacht Plastik auch Probleme?\nB: Ja, besonders im Meer.",exampleSrc:"A: What causes the air pollution?\nB: Mainly exhaust fumes.\nA: Does plastic also cause problems?\nB: Yes, especially in the sea.",funFact:"Ver- + Ursache (cause). 'Abgase verursachen Luftverschmutzung' (Exhaust fumes cause air pollution). Regular verb. The compound logic: to cause = to make into a cause."},
{type:"teach",trg:"verschmutzen",src:"to pollute, to dirty",pos:"verb",gender:null,note:"Ver- + Schmutz (dirt). 'Die Luft verschmutzen' (to pollute the air).\nVer- often means 'to make into' something.",example:"A: Autos verschmutzen die Luft.\nB: Und Fabriken verschmutzen das Wasser.\nA: Wer verschmutzt am meisten?\nB: Die Industrie, laut Statistik.",exampleSrc:"A: Cars pollute the air.\nB: And factories pollute the water.\nA: Who pollutes the most?\nB: Industry, according to statistics.",funFact:"Ver- + Schmutz (dirt). 'Die Luft verschmutzen' (to pollute the air). 'Umweltverschmutzung' (environmental pollution). Ver- often means 'to make into' something."},
{type:"teach",trg:"giftig",src:"toxic, poisonous",pos:"adj",gender:null,note:"From 'Gift' (poison). False friend: English 'gift' = present.\nGerman 'Gift' = poison. Nobody's present.",example:"A: Ist das giftig?\nB: Ja, sehr giftig. Nicht anfassen!\nA: Giftiger Abfall ist gef\u00e4hrlich.\nB: Deshalb gibt es Sonderm\u00fcll.",exampleSrc:"A: Is that toxic?\nB: Yes, very toxic. Don't touch!\nA: Toxic waste is dangerous.\nB: That's why there is hazardous waste.",funFact:"From 'Gift' (poison). 'Giftige Chemikalien' (toxic chemicals). Fun false friend: English 'gift' = present. German 'Gift' = poison. 'Giftm\u00fcll' (toxic waste) is nobody's present."},
{type:"teach",trg:"\u00f6kologisch",src:"ecological",pos:"adj",gender:null,note:"From Greek 'oikos' (house) + 'logos' (study). Often shortened to\n'\u00f6ko-' as prefix: '\u00d6kostrom' (green electricity).",example:"A: Ist dieses Produkt \u00f6kologisch?\nB: Ja, zu 100 Prozent \u00f6kologisch.\nA: Was bedeutet '\u00f6kologisch' genau?\nB: Umweltfreundlich hergestellt.",exampleSrc:"A: Is this product ecological?\nB: Yes, 100 percent ecological.\nA: What does 'ecological' mean exactly?\nB: Produced in an environmentally friendly way.",funFact:"From Greek 'oikos' (house) + 'logos' (study). '\u00d6kologischer Landbau' (organic farming). Often shortened to '\u00f6ko-' as a prefix: '\u00d6kostrom' (green electricity)."},
{type:"teach",trg:"sparsam",src:"thrifty, economical",pos:"adj",gender:null,note:"From 'sparen' (to save). Germans consider Sparsamkeit\n(thriftiness) a virtue. Being sparsam is a compliment.",example:"A: Bist du sparsam mit Wasser?\nB: Ja, ich dusche nur f\u00fcnf Minuten.\nA: Das ist sehr sparsam.\nB: Sparsam sein ist gut f\u00fcr die Umwelt.",exampleSrc:"A: Are you economical with water?\nB: Yes, I only shower for five minutes.\nA: That is very economical.\nB: Being thrifty is good for the environment.",funFact:"From 'sparen' (to save). 'Sparsam mit Wasser umgehen' (to use water sparingly). Germans consider Sparsamkeit (thriftiness) a virtue. Being sparsam is a compliment."},
{type:"tip",title:"Partizip I as Adjective: The -end Form",text:"German can turn any verb into an adjective describing an ongoing action. Formation: infinitive + d.\n\nsteigen (to rise) becomes steigend (rising)\nlachen (to laugh) becomes lachend (laughing)\nwachsen (to grow) becomes wachsend (growing)\n\nThen it declines like a normal adjective:\n- der steigende Preis (the rising price)\n- die wachsende Gefahr (the growing danger)\n- ein sinkendes Schiff (a sinking ship)\n\nLike English: 'the laughing man' = 'der lachende Mann.' Same logic, same word order. Partizip I always describes an ongoing action.",deepDive:{title:"Partizip I: formation and usage",text:"The Partizip I is formed by adding -d to the infinitive. It always describes an ongoing action happening at the same time as the main verb.\n\nImportant: The Partizip I is used primarily as an adjective in German. Unlike English, you cannot use it to form progressive tenses ('I am running'). German says 'Ich laufe' (I run/am running).\n\nAs an adjective, it declines normally:\n- der lachende Mann (nominative masculine)\n- die lachenden M\u00e4nner (nominative plural)\n- mit steigendem Interesse (dative neuter)\n\nAs an adverb, it has no ending: 'Er ging lachend weg' (He left laughing)."}},
{type:"mc",q:"'Die steigenden Temperaturen sind gef\u00e4hrlich.' Was bedeutet 'steigenden' hier?",opts:["rising","fallen","average","extreme"],ans:"rising",hint:"Steigen bedeutet 'to rise.' Die Endung -d plus Adjektivendung beschreibt eine laufende Handlung."},
{type:"fb",s:"Die wachsende {1} durch Abgase ist ein ernstes Problem.",a:["Gefahr"],opts:["Gefahr","Sicherheit","Forschung","Umfrage"],hint:"Welches Substantiv bedeutet 'danger'? Etwas, das w\u00e4chst und bedroht.",sSrc:"The growing danger from exhaust fumes is a serious problem."},
{type:"mc",q:"Wie bildet man das Partizip I von 'schlafen' (to sleep)?",opts:["schlafend","schl\u00e4ft","schlafen","geschlafen"],ans:"schlafend",hint:"Nimm den Infinitiv und f\u00fcge -d hinzu. Die Bildung ist immer gleich."}
]},

// ============================================================
// Lesson 4: Grammatik der Natur (Grammar of Nature)
// Type: Grammar. 18 new words. 26 steps.
// Partizip II as adjective + lassen causative taught.
// ============================================================
{id:"deu_r22l4",title:"Grammatik der Natur",icon:"\ud83d\udcda",xp:15,board:true,steps:[
{type:"intro",title:"Grammatik der Natur",desc:"Heute lernst du zwei starke Grammatikwerkzeuge: Partizip II als Adjektiv (das recycelte Papier) und lassen als Kausalverb (Ich lasse mein Auto reparieren).",goals:["Verstehe Partizip II als Adjektiv (der gelesene Brief)","Lerne lassen in drei Bedeutungen: veranlassen, erlauben, lassen","Kombiniere alle drei neuen Grammatikkonstrukte"]},
{type:"teach",trg:"die Fabrik",src:"factory",pos:"noun",gender:"f",note:"From Latin 'fabrica' (workshop). Many old Fabriken are\nnow museums or cultural centers in the Ruhrgebiet.",example:"A: Was produziert diese Fabrik?\nB: Solarpanels.\nA: Ist die Fabrik umweltfreundlich?\nB: Ja, sie nutzt nur \u00d6kostrom.",exampleSrc:"A: What does this factory produce?\nB: Solar panels.\nA: Is the factory environmentally friendly?\nB: Yes, it uses only green electricity.",funFact:"From Latin 'fabrica' (workshop). 'Chemiefabrik' (chemical factory), 'Autofabrik' (car factory). The Ruhrgebiet had thousands. Many are now museums or cultural centers."},
{type:"teach",trg:"das Kraftwerk",src:"power plant",pos:"noun",gender:"n",note:"Kraft (power) + Werk (work/plant). Germany is shutting down\nnuclear Kraftwerke and building wind and solar ones.",example:"A: Was ist ein Kraftwerk?\nB: Eine Anlage, die Strom produziert.\nA: Kohlekraftwerk oder Windkraftwerk?\nB: Windkraftwerke sind besser f\u00fcr die Umwelt.",exampleSrc:"A: What is a power plant?\nB: A facility that produces electricity.\nA: Coal power plant or wind power plant?\nB: Wind power plants are better for the environment.",funFact:"Kraft (power) + Werk (work/plant). 'Atomkraftwerk' (nuclear power plant), 'Kohlekraftwerk' (coal power plant). Germany is shutting down nuclear ones."},
{type:"teach",trg:"die Anlage",src:"facility, plant, installation",pos:"noun",gender:"f",note:"From 'anlegen' (to lay out). 'Solaranlage' (solar installation),\n'Kl\u00e4ranlage' (water treatment plant). Context determines meaning.",example:"A: Was ist eine Solaranlage?\nB: Eine Anlage, die Sonnenlicht in Strom umwandelt.\nA: Hast du eine auf dem Dach?\nB: Ja, seit zwei Jahren.",exampleSrc:"A: What is a solar installation?\nB: A facility that converts sunlight into electricity.\nA: Do you have one on the roof?\nB: Yes, for two years.",funFact:"From 'anlegen' (to lay out). 'Solaranlage' (solar installation), 'Kl\u00e4ranlage' (water treatment plant), 'Geldanlage' (financial investment). Context determines which meaning."},
{type:"teach",trg:"die Werbung",src:"advertising",pos:"noun",gender:"f",note:"From 'werben' (to advertise/court). 'Keine Werbung!'\non German mailboxes means no junk mail.",example:"A: \u00dcberall Werbung!\nB: Ja, zu viel Werbung.\nA: Keine Werbung bitte.\nB: Schreib das auf deinen Briefkasten.",exampleSrc:"A: Advertising everywhere!\nB: Yes, too much advertising.\nA: No advertising please.\nB: Write that on your mailbox.",funFact:"From 'werben' (to advertise/court). 'Werbung machen' (to advertise). 'Keine Werbung!' on German mailboxes means no junk mail. Werbung is both the industry and the ads."},
{type:"teach",trg:"die Reklame",src:"advertising (informal/pejorative)",pos:"noun",gender:"f",note:"From French 'r\u00e9clame.' Slightly old-fashioned or pejorative.\nUsed for flashy or aggressive ads.",example:"A: Was ist der Unterschied zwischen Werbung und Reklame?\nB: Reklame klingt negativer.\nA: Wie 'billige Reklame'?\nB: Genau. Werbung ist neutraler.",exampleSrc:"A: What is the difference between Werbung and Reklame?\nB: Reklame sounds more negative.\nA: Like 'cheap advertising'?\nB: Exactly. Werbung is more neutral.",funFact:"From French 'r\u00e9clame.' Advertising, but slightly old-fashioned or pejorative. 'Reklame machen' sounds less professional than 'Werbung machen.' Used for flashy or aggressive ads."},
{type:"teach",trg:"die Marke",src:"brand, stamp",pos:"noun",gender:"f",note:"'Briefmarke' (postage stamp), 'Automarke' (car brand).\n'Deutsche Marken' are globally trusted.",example:"A: Welche Marke ist das?\nB: Eine deutsche Marke.\nA: Deutsche Marken sind beliebt.\nB: Ja, weltweit bekannt und vertraut.",exampleSrc:"A: What brand is that?\nB: A German brand.\nA: German brands are popular.\nB: Yes, known and trusted worldwide.",funFact:"'Briefmarke' (postage stamp), 'Automarke' (car brand). 'Deutsche Marken' are globally trusted. The word comes from 'markieren' (to mark). A brand marks its products."},
{type:"teach",trg:"das Modell",src:"model",pos:"noun",gender:"n",note:"From Italian 'modello.' Neuter. 'Gesch\u00e4ftsmodell' (business model),\n'Automodell' (car model).",example:"A: Welches Modell ist dein Auto?\nB: Ein Elektromodell.\nA: Dieses Modell ist gut f\u00fcr die Umwelt.\nB: Ja, null Abgase.",exampleSrc:"A: What model is your car?\nB: An electric model.\nA: This model is good for the environment.\nB: Yes, zero emissions.",funFact:"From Italian 'modello.' Neuter. 'Gesch\u00e4ftsmodell' (business model), 'Automodell' (car model). 'Ein Modell f\u00fcr Nachhaltigkeit' (a model for sustainability)."},
{type:"teach",trg:"der Faktor",src:"factor",pos:"noun",gender:"m",note:"From Latin 'factor' (maker). 'Ein wichtiger Faktor.'\nInternational word, same in most European languages.",example:"A: Was ist der wichtigste Faktor?\nB: Der Energieverbrauch.\nA: Gibt es andere Faktoren?\nB: Ja, Transport und Produktion.",exampleSrc:"A: What is the most important factor?\nB: Energy consumption.\nA: Are there other factors?\nB: Yes, transport and production.",funFact:"From Latin 'factor' (maker). 'Ein wichtiger Faktor' (an important factor). 'Risikofaktor' (risk factor). International word, same in most European languages."},
{type:"teach",trg:"die Stufe",src:"step, level, stage",pos:"noun",gender:"f",note:"'Vorstufe' (preliminary stage), 'Entwicklungsstufe'\n(development stage). Also literally a stair step.",example:"A: Auf welcher Stufe sind wir?\nB: Stufe zwei von f\u00fcnf.\nA: Vorsicht, Stufe!\nB: Danke, fast gestolpert.",exampleSrc:"A: What level are we at?\nB: Level two of five.\nA: Watch out, step!\nB: Thanks, almost tripped.",funFact:"'Vorstufe' (preliminary stage), 'Entwicklungsstufe' (development stage). Also literally a stair step. 'Vorsicht, Stufe!' (Watch out, step!) is on signs everywhere."},
{type:"teach",trg:"das Netz",src:"net, network",pos:"noun",gender:"n",note:"Cognate with English 'net.' 'Stromnetz' (power grid),\n'Ins Netz gehen' means to go online or to fall into a trap.",example:"A: Das Stromnetz ist \u00fcberlastet.\nB: Zu viele Klimaanlagen.\nA: Wir brauchen ein besseres Netz.\nB: Ja, f\u00fcr \u00d6kostrom.",exampleSrc:"A: The power grid is overloaded.\nB: Too many air conditioners.\nA: We need a better grid.\nB: Yes, for green electricity.",funFact:"Cognate with English 'net.' 'Internet' (internet), 'Stromnetz' (power grid). 'Ins Netz gehen' (to go into the net) means to go online. Also: to fall into a trap."},
{type:"teach",trg:"das Netzwerk",src:"network",pos:"noun",gender:"n",note:"Netz + Werk (work). 'Soziales Netzwerk' (social network).\nGermans turned 'Netzwerken' into a verb for professional networking.",example:"A: Hast du ein gutes Netzwerk?\nB: Ja, beruflich und privat.\nA: Netzwerken ist wichtig.\nB: Besonders in der Umweltbranche.",exampleSrc:"A: Do you have a good network?\nB: Yes, professionally and privately.\nA: Networking is important.\nB: Especially in the environmental sector.",funFact:"Netz + Werk (work). 'Soziales Netzwerk' (social network). 'Ein Netzwerk aufbauen' (to build a network). Professional networking is 'Netzwerken.' Germans turned it into a verb."},
{type:"teach",trg:"die Technik",src:"technology, technique",pos:"noun",gender:"f",note:"From Greek 'techne' (art/skill). Emphasizes practical application.\n'Informationstechnik' (IT).",example:"A: Welche Technik benutzt ihr?\nB: Moderne Solartechnik.\nA: Technik oder Technologie?\nB: Technik ist praktischer, Technologie theoretischer.",exampleSrc:"A: What technology do you use?\nB: Modern solar technology.\nA: Technik or Technologie?\nB: Technik is more practical, Technologie more theoretical.",funFact:"From Greek 'techne' (art/skill). 'Spitzentechnik' (cutting-edge technology). 'Informationstechnik' (IT). 'Technik' emphasizes practical application, 'Technologie' the science."},
{type:"teach",trg:"die Technologie",src:"technology (scientific)",pos:"noun",gender:"f",note:"Technik + -logie (study of). More academic than Technik.\nThe -ie ending is always stressed.",example:"A: Umwelttechnologie ist die Zukunft.\nB: Ja, Biotechnologie auch.\nA: Was ist der Unterschied zu Technik?\nB: Technologie ist wissenschaftlicher.",exampleSrc:"A: Environmental technology is the future.\nB: Yes, biotechnology too.\nA: What is the difference from Technik?\nB: Technologie is more scientific.",funFact:"Technik + -logie (study of). 'Umwelttechnologie' (environmental technology), 'Biotechnologie' (biotechnology). More academic and theoretical than Technik. The -ie ending is always stressed."},
{type:"teach",trg:"erh\u00f6hen",src:"to increase, to raise",pos:"verb",gender:null,note:"Er- + hoch (high). Transitive: someone raises something.\nCompare: steigen (intransitive, something rises on its own).",example:"A: Wir m\u00fcssen die Effizienz erh\u00f6hen.\nB: Und die Kosten nicht erh\u00f6hen?\nA: Genau. Effizienz erh\u00f6hen, Kosten senken.\nB: Das ist der Plan.",exampleSrc:"A: We need to increase efficiency.\nB: And not increase costs?\nA: Exactly. Increase efficiency, reduce costs.\nB: That's the plan.",funFact:"Er- + hoch (high). 'Die Temperatur erh\u00f6hen' (to increase the temperature). Transitive: someone raises something. Compare: steigen (intransitive, something rises on its own)."},
{type:"teach",trg:"f\u00f6rdern",src:"to promote, to support",pos:"verb",gender:null,note:"WITH Umlaut, unlike fordern (to demand). 'Erneuerbare Energien\nf\u00f6rdern.' 'F\u00f6rderung' (funding/support).",example:"A: Wir f\u00f6rdern erneuerbare Energien.\nB: Wie f\u00f6rdert ihr das?\nA: Mit Geld und mit Technik.\nB: Gute F\u00f6rderung macht den Unterschied.",exampleSrc:"A: We promote renewable energies.\nB: How do you promote that?\nA: With money and technology.\nB: Good support makes the difference.",funFact:"WITH Umlaut, unlike fordern (to demand). 'Erneuerbare Energien f\u00f6rdern' (to promote renewable energies). 'F\u00f6rderung' (funding/support). One dot changes demand to support."},
{type:"teach",trg:"protestieren",src:"to protest",pos:"verb",gender:null,note:"From Latin 'protestari.' Regular -ieren verb.\n'Fridays for Future' made Germany a global protest capital.",example:"A: Warum protestieren die Leute?\nB: Gegen den Klimawandel.\nA: Hilft protestieren?\nB: Es macht auf Probleme aufmerksam.",exampleSrc:"A: Why are the people protesting?\nB: Against climate change.\nA: Does protesting help?\nB: It draws attention to problems.",funFact:"From Latin 'protestari.' Regular -ieren verb. 'Gegen den Klimawandel protestieren' (to protest against climate change). 'Fridays for Future' started protests worldwide, including Germany."},
{type:"teach",trg:"statistisch",src:"statistical",pos:"adj",gender:null,note:"From Statistik. 'Statistisch gesehen' (statistically speaking).\nThe -isch ending creates adjectives from nouns.",example:"A: Statistisch gesehen steigt die Temperatur.\nB: Ist das statistisch signifikant?\nA: Ja, \u00fcber 50 Jahre gemessen.\nB: Dann ist es statistisch eindeutig.",exampleSrc:"A: Statistically speaking, the temperature is rising.\nB: Is that statistically significant?\nA: Yes, measured over 50 years.\nB: Then it is statistically clear.",funFact:"From Statistik. 'Statistisch gesehen' (statistically speaking). The -isch ending creates adjectives from nouns. 'Statistisch signifikant' (statistically significant)."},
{type:"teach",trg:"durchschnittlich",src:"average, on average",pos:"adj",gender:null,note:"From Durchschnitt. The -lich ending on compound nouns.\n'Durchschnittlich 20 Grad' (an average of 20 degrees).",example:"A: Wie hoch ist die durchschnittliche Temperatur?\nB: Durchschnittlich 10 Grad in Deutschland.\nA: Das ist durchschnittlich?\nB: Ja, aber es wird w\u00e4rmer.",exampleSrc:"A: What is the average temperature?\nB: On average 10 degrees in Germany.\nA: That is average?\nB: Yes, but it is getting warmer.",funFact:"From Durchschnitt. 'Durchschnittlich 20 Grad' (an average of 20 degrees). The -lich ending on compound nouns: Durchschnitt + lich = on average. Long but logical."},
{type:"tip",title:"Partizip II as Adjective: The Completed Action",text:"You know the Partizip II from the Perfekt: 'Ich habe das Buch gelesen.' Now as an adjective:\n\ngelesen (read) becomes: der gelesene Brief (the read letter)\nrecycelt (recycled) becomes: das recycelte Papier (the recycled paper)\nverschmutzt (polluted) becomes: die verschmutzte Luft (the polluted air)\n\nDeclension like any adjective. The key difference from Partizip I:\n- Partizip I (ongoing): der lesende Mann (the man who IS reading)\n- Partizip II (completed): der gelesene Brief (the letter that HAS BEEN read)\n\nLike English: 'the broken window,' 'the recycled paper.'",deepDive:{title:"Partizip II: regular and irregular forms",text:"Regular verbs form the Partizip II with ge- + stem + -t:\nmachen \u2192 gemacht, recyceln \u2192 recycelt\n\nIrregular verbs use ge- + stem change + -en:\nlesen \u2192 gelesen, brechen \u2192 gebrochen\n\nVerbs with inseparable prefixes (ver-, be-, er-, zer-) skip ge-:\nverschmutzen \u2192 verschmutzt, zerst\u00f6ren \u2192 zerst\u00f6rt\n\nVerbs ending in -ieren also skip ge-:\nrecyceln \u2192 recycelt, produzieren \u2192 produziert\n\nAs adjectives, all forms decline normally:\nder verschmutzte Fluss (nominative)\nden verschmutzten Fluss (accusative)\ndem verschmutzten Fluss (dative)"}},
{type:"tip",title:"Extended Participial Phrases",text:"German packs modifiers BEFORE the noun in a frame:\n\nArticle ... Participle + ending + NOUN\n\ndie [in Berlin lebende] Frau\ndas [von Goethe geschriebene] Buch\nder [seit Wochen geplante] Urlaub\n\nHow to read them: find the article, jump to the NOUN, read the middle.\nHow to build them: start with a relative clause, remove the relative pronoun, put the participle before the noun.",deepDive:{title:"Why German Does This",text:"English: 'The woman who lives in Berlin'\nFormal German: 'Die in Berlin lebende Frau'\n\nComplex information in a single noun phrase. Standard in academic writing.\nExtreme examples exist in legal texts.\nStart simple and build up.\n\nPractice converting:\n'Der Fluss, der verschmutzt ist' = 'Der verschmutzte Fluss'\n'Das Papier, das recycelt wurde' = 'Das recycelte Papier'\n'Die Frau, die in Berlin lebt' = 'Die in Berlin lebende Frau'"}},
{type:"tip",title:"State Passive: The Result Passive",text:"Formation: sein + Partizip II\nPresent: ist geöffnet (is open)\nPast: war geöffnet (was open)\n\nFocus: the STATE or RESULT, not the process.\n\nProcess passive (werden): Das Fenster wird geöffnet.\n(Someone is opening it right now.)\n\nState passive (sein): Das Fenster ist geöffnet.\n(It is in an open state.)",deepDive:{title:"State Passive in Daily Life",text:"Many state passive forms look like adjective + sein:\nDas Geschäft ist geschlossen.\nDer Kaffee ist gekocht.\nIst der Kaffee fertig?\n\nThe boundary between state passive and adjective is fluid in daily life.\nFor the exam: focus on the difference werden (process) vs. sein (state)."}},
{type:"tip",title:"bekommen-Passiv: Der Empfänger wird Subjekt",text:"Standardpassiv: Das Buch wird dem Kind geschenkt.\nbekommen-Passiv: Das Kind bekommt das Buch geschenkt.\n\nDer EMPFÄNGER wird zum Subjekt.\n\nSehr häufig in gesprochenem Deutsch.\nkriegen funktioniert identisch: Das Kind kriegt das Buch geschenkt.",deepDive:{title:"Wann bekommen-Passiv benutzen?",text:"Benutze es, wenn du den EMPFÄNGER betonen willst.\nNatürlich mit Verben des Gebens, Sendens, Erklärens.\n\nStandard: Mir wurde geholfen.\nbekommen: Ich bekam Hilfe.\n\nManche Grammatiker nennen es umgangssprachlich, aber es ist standard gesprochenes Deutsch."}},
{type:"tip",title:"sein + zu + Infinitiv and -bar Adjectives",text:"sein + zu + infinitive has TWO meanings depending on context:\n1. Possibility: Das ist zu schaffen. (can be done)\n2. Necessity: Die Regeln sind zu beachten. (must be followed)\n\n-bar = -able/-ible:\nmachbar (doable), lösbar (solvable), essbar (edible)\nun- negates: unlösbar, unvorstellbar, unessbar"},
{type:"verb_table",title:"Pr\u00e4sens: lassen (to let/have done/leave)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"lasse",src:"I let/have done"},{pronoun:"du",form:"l\u00e4sst",src:"you let/have done"},{pronoun:"er/sie/es",form:"l\u00e4sst",src:"he/she/it lets/has done"}]},{label:"Plural",rows:[{pronoun:"wir",form:"lassen",src:"we let/have done"},{pronoun:"ihr",form:"lasst",src:"you all let/have done"},{pronoun:"sie/Sie",form:"lassen",src:"they/you(formal) let/have done"}]}],note:"Irregular vowel change: a \u2192 \u00e4 in du/er/sie/es. Past: lie\u00df. Partizip II: gelassen (or lassen with another infinitive)."},
{type:"tip",title:"lassen: Three Verbs in One",text:"Lassen has three different meanings:\n\n1. TO HAVE DONE: etwas machen lassen\n'Ich lasse mein Auto reparieren.' (I have my car repaired.)\n'Sie lässt sich die Haare schneiden.' (She has her hair cut.)\n\n2. TO ALLOW: jemanden etwas tun lassen\n'Lass mich erklären!' (Let me explain!)\n'Er lässt sie gehen.' (He lets her go.)\n\n3. TO LEAVE/STOP: aufhören, zurücklassen\n'Lass das!' (Stop that!)\n'Ich lasse den Schirm hier.' (I leave the umbrella here.)\n\nPassive alternative: sich lassen = can be done\n'Das lässt sich machen.' (That can be done.)",deepDive:{title:"lassen in compound tenses",text:"In the Perfekt, lassen has two Partizip II forms:\n\n1. As a main verb: gelassen\n'Ich habe den Hund zu Hause gelassen.' (I left the dog at home.)\n\n2. With another infinitive: lassen (double infinitive)\n'Ich habe mein Auto reparieren lassen.' (I had my car repaired.)\n\nThe double infinitive construction (two infinitives at the end) is standard in German. It also applies to modal verbs in Perfekt:\n'Ich habe arbeiten m\u00fcssen.' (I had to work.)"}},
{type:"mc",q:"'Das recycelte Papier kommt in die blaue Tonne.' Was beschreibt 'recycelte'?",opts:["Papier, das sich selbst recycelt","Papier, das gerade recycelt wird","Papier, das recycelt werden soll","Papier, das bereits recycelt wurde"],ans:"Papier, das bereits recycelt wurde",hint:"Partizip II beschreibt eine abgeschlossene Handlung. Das Recycling ist schon passiert."},
{type:"fb",s:"Verumius {1} sein Fahrrad reparieren.",a:["l\u00e4sst"],opts:["l\u00e4sst","lassen","lasst","lass"],hint:"Dritte Person Singular von lassen. Er l\u00e4sst jemand anderen sein Fahrrad reparieren.",sSrc:"Verumius has his bike repaired."},
{type:"mc",q:"'Der lesende Mann' und 'der gelesene Brief.' Was ist der Unterschied?",opts:["Partizip I ist laufende Handlung, Partizip II ist abgeschlossene Handlung","Sie bedeuten dasselbe","Partizip I ist f\u00fcr Personen, Partizip II f\u00fcr Dinge","Partizip I ist Vergangenheit, Partizip II ist Gegenwart"],ans:"Partizip I ist laufende Handlung, Partizip II ist abgeschlossene Handlung",hint:"Der Mann liest gerade (laufend). Der Brief wurde gelesen (abgeschlossen)."},
{type:"drag_fill",s:"Mia {1} die {2} Dokumente kopieren.",blanks:{"1":"l\u00e4sst","2":"fehlenden"},pool:["l\u00e4sst","lasst","fehlenden","gefehlten","lassen"],hint:"Mia l\u00e4sst jemanden die fehlenden Dokumente kopieren. Kausatives lassen (3. Person) + Partizip I (laufendes Fehlen).",sSrc:"Mia has the missing documents copied."}
]},

// ============================================================
// Lesson 5: Bio oder Discounter? (Organic or Discount?)
// Type: Vocab + review. 20 new words. 24 steps.
// Scene: Split scene Bio-Markt vs Aldi/Lidl.
// ============================================================
{id:"deu_r22l5",title:"Bio oder Discounter?",icon:"\ud83d\uded2",xp:15,board:true,steps:[
{type:"intro",title:"Bio oder Discounter?",desc:"Bio market or Aldi? Mia loves organic, Lukas shops at the discounter. Verumius compares. Learn household vocabulary and practice all three grammar constructs.",goals:["Learn 20 new words about household and measurements","Compare ecological and budget shopping","Practice Partizip I, Partizip II, and lassen in new contexts"]},
{type:"story",speaker:"mia",mood:"passionate",art:"de-biomarkt",trg:"Schau dir das an! Dieses frisch gebackene Brot, die handgemachte Seife, der fair gehandelte Kaffee. Im Bio-Markt wei\u00dft du, woher alles kommt.",src:"Look at this! This freshly baked bread, the handmade soap, the fairly traded coffee. At the organic market you know where everything comes from."},
{type:"story",speaker:"lukas",mood:"practical",art:"de-discounter",trg:"Mia, ich lasse mich nicht von sch\u00f6ner Verpackung t\u00e4uschen. Ich kaufe meine Nudeln f\u00fcr 49 Cent und lasse den Rest auf dem Konto.",src:"Mia, I don't let myself be fooled by nice packaging. I buy my pasta for 49 cents and leave the rest in my account."},
{type:"teach",trg:"das Waschmittel",src:"detergent",pos:"noun",gender:"n",note:"Wasch (wash) + Mittel (means/agent). Germany has strict\nWaschmittel regulations. Phosphate bans started here in the 1980s.",example:"A: Welches Waschmittel benutzt du?\nB: \u00d6kologisches Waschmittel.\nA: Ist das besser f\u00fcr die Umwelt?\nB: Ja, weniger Chemie im Wasser.",exampleSrc:"A: Which detergent do you use?\nB: Ecological detergent.\nA: Is that better for the environment?\nB: Yes, fewer chemicals in the water.",funFact:"Wasch (wash) + Mittel (means/agent). Detergent. '\u00d6kologisches Waschmittel' (ecological detergent). Germany has strict Waschmittel regulations. Phosphate bans started here in the 1980s."},
{type:"teach",trg:"die Batterie",src:"battery",pos:"noun",gender:"f",note:"From French 'batterie.' Germany collects used Batterien\nin special green boxes at every supermarket.",example:"A: Die Batterie ist leer.\nB: Wirf sie in die Sammelbox.\nA: Wo ist die Sammelbox?\nB: Am Eingang vom Supermarkt.",exampleSrc:"A: The battery is empty.\nB: Throw it in the collection box.\nA: Where is the collection box?\nB: At the entrance of the supermarket.",funFact:"From French 'batterie.' 'Batterie einlegen' (to insert a battery). 'Aufladbare Batterie' (rechargeable battery). Germany collects used Batterien in special green boxes at every supermarket."},
{type:"teach",trg:"das Feuerzeug",src:"lighter",pos:"noun",gender:"n",note:"Feuer (fire) + Zeug (stuff/tool). Fire-tool.\n'Hast du ein Feuerzeug?' is a classic conversation starter.",example:"A: Hast du ein Feuerzeug?\nB: Ja, hier bitte.\nA: Wo kann ich ein Feuerzeug kaufen?\nB: An jeder Kasse.",exampleSrc:"A: Do you have a lighter?\nB: Yes, here you go.\nA: Where can I buy a lighter?\nB: At every checkout.",funFact:"Feuer (fire) + Zeug (stuff/tool). Fire-tool. A lighter. 'Hast du ein Feuerzeug?' is a classic conversation starter. Das Feuerzeug, neuter, like most -zeug compounds."},
{type:"teach",trg:"das Streichholz",src:"match",pos:"noun",gender:"n",note:"Streich (stroke) + Holz (wood). Strike-wood.\nMore poetic than Feuerzeug: a stick you stroke into flame.",example:"A: Hast du Streichh\u00f6lzer?\nB: Ja, in der Schublade.\nA: Streichh\u00f6lzer oder Feuerzeug?\nB: Streichh\u00f6lzer, die sind romantischer.",exampleSrc:"A: Do you have matches?\nB: Yes, in the drawer.\nA: Matches or lighter?\nB: Matches, they are more romantic.",funFact:"Streich (stroke) + Holz (wood). Strike-wood. A match. 'Streichh\u00f6lzer anz\u00fcnden' (to light matches). More poetic than Feuerzeug. The image: a stick of wood you stroke into flame."},
{type:"teach",trg:"die Zange",src:"pliers, tongs",pos:"noun",gender:"f",note:"'Bei\u00dfzange' (cutting pliers), 'Zuckerzange' (sugar tongs).\n'Jemanden in die Zange nehmen' means to put the squeeze on someone.",example:"A: Hast du eine Zange?\nB: Ja, im Werkzeugkasten.\nA: Ich brauche die Zange f\u00fcr das Rohr.\nB: Hier, nimm die gro\u00dfe.",exampleSrc:"A: Do you have pliers?\nB: Yes, in the toolbox.\nA: I need the pliers for the pipe.\nB: Here, take the big ones.",funFact:"'Bei\u00dfzange' (cutting pliers), 'Zuckerzange' (sugar tongs). 'Jemanden in die Zange nehmen' (to put the squeeze on someone). A gripping tool for work and idioms."},
{type:"teach",trg:"das Rohr",src:"pipe, tube",pos:"noun",gender:"n",note:"'Wasserrohr' (water pipe), 'Abflussrohr' (drain pipe).\nAlso means 'reed' (the plant). Plumbing runs on Rohre.",example:"A: Das Rohr ist kaputt.\nB: Welches Rohr?\nA: Das Wasserrohr in der K\u00fcche.\nB: Wir m\u00fcssen einen Klempner rufen.",exampleSrc:"A: The pipe is broken.\nB: Which pipe?\nA: The water pipe in the kitchen.\nB: We need to call a plumber.",funFact:"'Wasserrohr' (water pipe), 'Abflussrohr' (drain pipe). Also means 'reed' (the plant). 'Rohrleitung' (pipeline). 'Durch die Rohre' means through the pipes. Plumbing runs on Rohre."},
{type:"teach",trg:"der Sand",src:"sand",pos:"noun",gender:"m",note:"Same as English. 'Sandstrand' (sandy beach).\n'Den Kopf in den Sand stecken' means to bury one's head in the sand.",example:"A: Der Sand am Strand ist wei\u00df.\nB: Ja, wundersch\u00f6ner Sand.\nA: Steck nicht den Kopf in den Sand.\nB: Du hast recht. Ich muss handeln.",exampleSrc:"A: The sand at the beach is white.\nB: Yes, beautiful sand.\nA: Don't bury your head in the sand.\nB: You're right. I need to act.",funFact:"Same word as English. 'Sandstrand' (sandy beach), 'Sandkasten' (sandbox). 'Den Kopf in den Sand stecken' (to bury one's head in the sand) works identically in both languages."},
{type:"teach",trg:"der Stein",src:"stone",pos:"noun",gender:"m",note:"Cognate with English 'stone.' 'Edelstein' (gemstone).\n'Ein Stein vom Herzen' (relief, literally: a stone off the heart).",example:"A: Was ist das f\u00fcr ein Stein?\nB: Ein Edelstein. Sehr selten.\nA: Mir f\u00e4llt ein Stein vom Herzen.\nB: Gut, dass du erleichtert bist.",exampleSrc:"A: What kind of stone is that?\nB: A gemstone. Very rare.\nA: A weight off my shoulders. (lit: A stone off my heart.)\nB: Good that you are relieved.",funFact:"Cognate with English 'stone.' 'Ziegelstein' (brick), 'Edelstein' (gemstone). 'Ein Stein vom Herzen' (a stone off the heart) means relief."},
{type:"teach",trg:"das Grundst\u00fcck",src:"plot of land, property",pos:"noun",gender:"n",note:"Grund (ground) + St\u00fcck (piece). A piece of ground.\nEvery Grundst\u00fcck is in the Grundbuch (land registry).",example:"A: Wie gro\u00df ist das Grundst\u00fcck?\nB: 500 Quadratmeter.\nA: Ein Grundst\u00fcck in Berlin ist teuer.\nB: Sehr teuer. Besonders in Mitte.",exampleSrc:"A: How big is the plot of land?\nB: 500 square meters.\nA: A plot of land in Berlin is expensive.\nB: Very expensive. Especially in Mitte.",funFact:"Grund (ground) + St\u00fcck (piece). A piece of ground. Property/plot of land. 'Ein Grundst\u00fcck kaufen' (to buy a plot). German property law is thorough. Every Grundst\u00fcck is in the Grundbuch (land registry)."},
{type:"teach",trg:"der Rasen",src:"lawn",pos:"noun",gender:"m",note:"'Den Rasen m\u00e4hen' (to mow the lawn). 'Betreten des Rasens\nverboten' (Keep off the grass) is on signs in every German park.",example:"A: Der Rasen muss gem\u00e4ht werden.\nB: Nicht am Sonntag!\nA: Warum nicht?\nB: Rasen m\u00e4hen am Sonntag ist verboten.",exampleSrc:"A: The lawn needs to be mowed.\nB: Not on Sunday!\nA: Why not?\nB: Mowing the lawn on Sunday is forbidden.",funFact:"'Den Rasen m\u00e4hen' (to mow the lawn). 'Betreten des Rasens verboten' (Keep off the grass) is on signs in every German park. Germans take their Rasen seriously."},
{type:"teach",trg:"die Fl\u00e4che",src:"area, surface",pos:"noun",gender:"f",note:"From 'flach' (flat). 'Grundfl\u00e4che' (floor area),\n'Wasserfl\u00e4che' (water surface). Measured in Quadratmetern.",example:"A: Wie gro\u00df ist die Fl\u00e4che?\nB: 80 Quadratmeter.\nA: Die Fl\u00e4che Deutschlands?\nB: Etwa 357.000 Quadratkilometer.",exampleSrc:"A: How big is the area?\nB: 80 square meters.\nA: The area of Germany?\nB: About 357,000 square kilometers.",funFact:"From 'flach' (flat). 'Grundfl\u00e4che' (floor area), 'Wasserfl\u00e4che' (water surface). Measured in Quadratmetern. 'Die Fl\u00e4che Deutschlands' is about 357,000 square kilometers."},
{type:"teach",trg:"die H\u00e4lfte",src:"half",pos:"noun",gender:"f",note:"From 'halb' (half). 'Zur H\u00e4lfte' (halfway).\nEnglish 'half' and German 'H\u00e4lfte' share the same Proto-Germanic root.",example:"A: Die H\u00e4lfte ist schon fertig.\nB: Und die andere H\u00e4lfte?\nA: Morgen. Die H\u00e4lfte der Arbeit ist geschafft.\nB: Gut, weiter so.",exampleSrc:"A: Half is already done.\nB: And the other half?\nA: Tomorrow. Half the work is done.\nB: Good, keep going.",funFact:"From 'halb' (half). 'Die H\u00e4lfte der Bev\u00f6lkerung' (half the population). 'Zur H\u00e4lfte' (halfway). English 'half' and German 'H\u00e4lfte' share the same Proto-Germanic root."},
{type:"teach",trg:"die H\u00f6he",src:"height",pos:"noun",gender:"f",note:"From 'hoch' (high). 'Meeresh\u00f6he' (sea level). Also figuratively:\n'in voller H\u00f6he' (in full amount).",example:"A: In welcher H\u00f6he liegt Berlin?\nB: Etwa 34 Meter \u00fcber dem Meeresspiegel.\nA: Das ist nicht sehr hoch.\nB: Nein, Berlin ist ziemlich flach.",exampleSrc:"A: At what height is Berlin?\nB: About 34 meters above sea level.\nA: That is not very high.\nB: No, Berlin is quite flat.",funFact:"From 'hoch' (high). 'In der H\u00f6he' (at height). 'Meeresh\u00f6he' (sea level). Also figuratively: 'in voller H\u00f6he' (in full amount). The Umlaut \u00f6 comes from the adjective hoch."},
{type:"teach",trg:"die L\u00e4nge",src:"length",pos:"noun",gender:"f",note:"From 'lang' (long). 'In die L\u00e4nge ziehen' (to drag out).\nAdjective to abstract noun via Umlaut: lang becomes L\u00e4nge.",example:"A: Wie ist die L\u00e4nge des Flusses?\nB: 580 Kilometer.\nA: Zieh es nicht in die L\u00e4nge!\nB: Okay, ich fasse mich kurz.",exampleSrc:"A: What is the length of the river?\nB: 580 kilometers.\nA: Don't drag it out!\nB: Okay, I'll keep it short.",funFact:"From 'lang' (long). 'In die L\u00e4nge ziehen' (to drag out). 'Wellenl\u00e4nge' (wavelength). Adjective to abstract noun via Umlaut: lang becomes L\u00e4nge, just as hoch becomes H\u00f6he."},
{type:"teach",trg:"die Anzahl",src:"number (quantity)",pos:"noun",gender:"f",note:"An (at) + Zahl (number). More formal than 'Zahl' or 'Nummer.'\nUsed for countable quantities in statistics.",example:"A: Wie ist die Anzahl der Teilnehmer?\nB: 250.\nA: Die Anzahl steigt jedes Jahr.\nB: Ja, immer mehr Leute kommen.",exampleSrc:"A: What is the number of participants?\nB: 250.\nA: The number rises every year.\nB: Yes, more and more people come.",funFact:"An (at) + Zahl (number). 'Die Anzahl der Teilnehmer' (the number of participants). More formal than 'Zahl' or 'Nummer.' Used for countable quantities in statistics and reports."},
{type:"teach",trg:"der Rand",src:"edge, margin, rim",pos:"noun",gender:"m",note:"'Am Rand der Stadt' (on the edge of the city).\n'Au\u00dfer Rand und Band' (out of control).",example:"A: Am Rand der Stadt gibt es Natur.\nB: Ja, Felder und Wiesen.\nA: Er ist au\u00dfer Rand und Band.\nB: Total aufgeregt, ja.",exampleSrc:"A: On the edge of the city there is nature.\nB: Yes, fields and meadows.\nA: He is out of control.\nB: Totally excited, yes.",funFact:"'Am Rand der Stadt' (on the edge of the city). 'Brillenrand' (frame of glasses). 'Au\u00dfer Rand und Band' (out of control, literally out of edge and band)."},
{type:"teach",trg:"der Schatten",src:"shadow, shade",pos:"noun",gender:"m",note:"Cognate with English 'shadow.' 'Im Schatten sitzen'\n(to sit in the shade). '30 Grad im Schatten' means it is really hot.",example:"A: Lass uns im Schatten sitzen.\nB: Ja, bei 35 Grad braucht man Schatten.\nA: Die Schattenseite der Industrie.\nB: Verschmutzung und Abfall.",exampleSrc:"A: Let's sit in the shade.\nB: Yes, at 35 degrees you need shade.\nA: The downside of industry.\nB: Pollution and waste.",funFact:"Cognate with English 'shadow' (from 'shade'). 'Im Schatten sitzen' (to sit in the shade). 'Schattenseite' (downside, literally shadow side). '30 Grad im Schatten' means it is really hot."},
{type:"teach",trg:"verpacken",src:"to package",pos:"verb",gender:null,note:"Ver- + packen (to pack). 'Umweltfreundlich verpackt.'\n'Verpackungsm\u00fcll' is a major environmental topic.",example:"A: Wie ist das Produkt verpackt?\nB: In Plastik, leider.\nA: Kann man es anders verpacken?\nB: Ja, in Papier oder Karton.",exampleSrc:"A: How is the product packaged?\nB: In plastic, unfortunately.\nA: Can you package it differently?\nB: Yes, in paper or cardboard.",funFact:"Ver- + packen (to pack). 'Umweltfreundlich verpackt' (packaged in an eco-friendly way). 'Verpackungsm\u00fcll' (packaging waste) is a major environmental topic. Germany has strict Verpackungsverordnung."},
{type:"teach",trg:"verbrauchen",src:"to consume, to use up",pos:"verb",gender:null,note:"Ver- + brauchen (to need). 'Strom verbrauchen.' The ver-\nprefix means using something until it is gone.",example:"A: Wie viel Strom verbrauchen wir?\nB: Zu viel.\nA: Wir m\u00fcssen weniger verbrauchen.\nB: Ja, jeder Verbraucher muss sparen.",exampleSrc:"A: How much electricity do we use?\nB: Too much.\nA: We need to consume less.\nB: Yes, every consumer needs to save.",funFact:"Ver- + brauchen (to need). 'Strom verbrauchen' (to use electricity). 'Verbraucher' (consumer). The ver- prefix means using something until it is gone. Completely used up."},
{type:"teach",trg:"k\u00fcnstlich",src:"artificial",pos:"adj",gender:null,note:"From 'Kunst' (art/artifice). 'K\u00fcnstliches Licht' (artificial light).\n'K\u00fcnstliche Intelligenz' (artificial intelligence).",example:"A: Ist das k\u00fcnstlich oder nat\u00fcrlich?\nB: K\u00fcnstlich. Aus dem Labor.\nA: K\u00fcnstliche Intelligenz ist \u00fcberall.\nB: Ja, die Technologie w\u00e4chst schnell.",exampleSrc:"A: Is that artificial or natural?\nB: Artificial. From the lab.\nA: Artificial intelligence is everywhere.\nB: Yes, the technology is growing fast.",funFact:"From 'Kunst' (art/artifice). 'K\u00fcnstliches Licht' (artificial light). 'K\u00fcnstliche Intelligenz' (artificial intelligence). What Kunst creates is k\u00fcnstlich. Not natural, but made by human skill."},
{type:"mc",q:"Lukas sagt: 'Ich lasse mich nicht von sch\u00f6ner Verpackung t\u00e4uschen.' Was meint er?",opts:["Er l\u00e4sst sich Verpackung herstellen","Er l\u00e4sst sich nicht von h\u00fcbscher Verpackung hereinlegen","Er h\u00f6rt auf zu verpacken","Er l\u00e4sst die Verpackung im Laden"],ans:"Er l\u00e4sst sich nicht von h\u00fcbscher Verpackung hereinlegen",hint:"Sich lassen + Infinitiv = sich etwas antun lassen. T\u00e4uschen = hereinlegen."}
]},

// ============================================================
// Lesson 6: Ruhig du sagen (Go Ahead and Say du)
// Type: Story climax. 18 new words. 24 steps.
// Scene: VHS corridor du offer + park bench approval.
// ============================================================
{id:"deu_r22l6",title:"Ruhig du sagen",icon:"\ud83e\udd1d",xp:15,board:true,steps:[
{type:"intro",title:"Ruhig du sagen",desc:"A special moment: Yilmaz offers Verumius the Du. Along the way, learn weather and nature vocabulary and experience Mia's rare compliment.",goals:["Learn 18 words about weather and nature","Experience the Sie-to-du switch as a social milestone","Practice all three grammar constructs in dialogue"]},
{type:"story",speaker:"yilmaz",mood:"warm",art:"de-vhs-corridor",trg:"Verumius... wir kennen uns jetzt seit fast einem Jahr. Du kannst ruhig du sagen.",src:"Verumius... we have known each other for almost a year now. You can go ahead and say du."},
{type:"story",speaker:"verumius",mood:"surprised",art:"de-vhs-corridor",trg:"Das... das freut mich wirklich. Danke, Frau Yil... ich meine... danke, Elif.",src:"That... that really makes me happy. Thank you, Mrs. Yil... I mean... thank you, Elif."},
{type:"story",speaker:"narrator",mood:"warm",art:"de-vhs-corridor",trg:"Ein stiller Moment im leeren Flur. Kein gro\u00dfer Moment f\u00fcr die Welt, aber ein entscheidender Moment f\u00fcr Verumius. Die vertraute Stimme seiner Lehrerin hat jetzt einen anderen Klang.",src:"A quiet moment in the empty hallway. Not a big moment for the world, but a decisive moment for Verumius. The familiar voice of his teacher now has a different sound."},
{type:"teach",trg:"die Umgebung",src:"surroundings, area",pos:"noun",gender:"f",note:"Um (around) + Gebung (giving/area). 'Die nahe Umgebung'\n(the immediate surroundings). What is given around you.",example:"A: Wie ist die Umgebung hier?\nB: Sehr gr\u00fcn. Viel Natur.\nA: In der Umgebung von Berlin gibt es Seen.\nB: Ja, perfekt f\u00fcr den Sommer.",exampleSrc:"A: What are the surroundings like here?\nB: Very green. A lot of nature.\nA: In the Berlin area there are lakes.\nB: Yes, perfect for summer.",funFact:"Um (around) + Gebung (giving/area). Surroundings. 'Die nahe Umgebung' (the immediate surroundings). 'In der Umgebung von Berlin' (in the Berlin area). What is given around you."},
{type:"teach",trg:"der Wetterbericht",src:"weather report",pos:"noun",gender:"m",note:"Wetter (weather) + Bericht (report). Germans check the\nWetterbericht religiously. Rain is always possible.",example:"A: Was sagt der Wetterbericht?\nB: Morgen Regen.\nA: Schon wieder?\nB: Ja, der Wetterbericht sagt immer Regen.",exampleSrc:"A: What does the weather report say?\nB: Rain tomorrow.\nA: Again?\nB: Yes, the weather report always says rain.",funFact:"Wetter (weather) + Bericht (report). 'Den Wetterbericht lesen' (to read the weather report). Germans check the Wetterbericht religiously. Rain is always possible."},
{type:"teach",trg:"die Wettervorhersage",src:"weather forecast",pos:"noun",gender:"f",note:"Wetter + Vorhersage (forecast). Longer and more formal\nthan Wetterbericht. Used in official contexts.",example:"A: Laut Wettervorhersage wird es hei\u00df.\nB: Wie hei\u00df?\nA: 38 Grad.\nB: Die Wettervorhersage macht mir Angst.",exampleSrc:"A: According to the weather forecast, it will be hot.\nB: How hot?\nA: 38 degrees.\nB: The weather forecast scares me.",funFact:"Wetter + Vorhersage (forecast). 'Laut Wettervorhersage regnet es morgen' (According to the forecast, it rains tomorrow). Longer and more formal than Wetterbericht."},
{type:"teach",trg:"der Sturm",src:"storm",pos:"noun",gender:"m",note:"Cognate with English 'storm.' 'Sturmwarnung' (storm warning).\nGermany's worst storms come from the North Sea.",example:"A: Ein Sturm kommt!\nB: Wie stark?\nA: Sehr stark. Sturmwarnung.\nB: Dann bleiben wir zu Hause.",exampleSrc:"A: A storm is coming!\nB: How strong?\nA: Very strong. Storm warning.\nB: Then we stay home.",funFact:"Cognate with English 'storm.' 'Sturmwarnung' (storm warning). 'Im Sturm erobern' (to take by storm). Germany's worst storms come from the North Sea. Orkan = hurricane-force storm."},
{type:"teach",trg:"der Donner",src:"thunder",pos:"noun",gender:"m",note:"Related to the god Thor/Donar. 'Donnerstag' (Thursday) =\nThor's day. 'Donnerwetter!' is an exclamation of surprise.",example:"A: H\u00f6rst du den Donner?\nB: Ja, ein Gewitter kommt.\nA: Donner und Blitz!\nB: Donnerwetter, das war laut!",exampleSrc:"A: Do you hear the thunder?\nB: Yes, a thunderstorm is coming.\nA: Thunder and lightning!\nB: Wow, that was loud!",funFact:"Related to the god Thor/Donar. 'Donnerstag' (Thursday) = Thor's day. 'Donnerwetter!' is an exclamation of surprise (literally: thunder weather!). Both languages name Thursday after the thunder god."},
{type:"teach",trg:"der Alarm",src:"alarm, alert",pos:"noun",gender:"m",note:"From Italian 'all'arme' (to arms!). 'Feueralarm' (fire alarm),\n'Alarmstufe rot' (red alert). 'Alarm schlagen' (to sound the alarm).",example:"A: Alarm! Feueralarm!\nB: Schnell, raus aus dem Geb\u00e4ude.\nA: Ist das ein echter Alarm?\nB: Ja, die Feuerwehr kommt schon.",exampleSrc:"A: Alarm! Fire alarm!\nB: Quick, out of the building.\nA: Is that a real alarm?\nB: Yes, the fire department is already coming.",funFact:"From Italian 'all'arme' (to arms!). 'Feueralarm' (fire alarm), 'Alarmstufe rot' (red alert). 'Alarm schlagen' (to sound the alarm). International word with military origins."},
{type:"teach",trg:"die St\u00f6rung",src:"disruption, disturbance",pos:"noun",gender:"f",note:"From 'st\u00f6ren' (to disturb). Deutsche Bahn's favorite word:\n'Wegen einer St\u00f6rung...' (Due to a disruption...).",example:"A: Wegen einer St\u00f6rung f\u00e4hrt kein Zug.\nB: Schon wieder eine St\u00f6rung?\nA: Ja, eine technische St\u00f6rung.\nB: Das ist typisch f\u00fcr die Bahn.",exampleSrc:"A: Due to a disruption, no train is running.\nB: Another disruption?\nA: Yes, a technical disruption.\nB: That is typical for the railway.",funFact:"From 'st\u00f6ren' (to disturb). 'Betriebsst\u00f6rung' (service disruption). Deutsche Bahn's favorite word: 'Wegen einer St\u00f6rung...' (Due to a disruption...). Every train delay starts here."},
{type:"teach",trg:"die Unterst\u00fctzung",src:"support",pos:"noun",gender:"f",note:"Unter (under) + st\u00fctzen (to support). Support from below.\n'Um Unterst\u00fctzung bitten' (to ask for support).",example:"A: Brauchst du Unterst\u00fctzung?\nB: Ja, finanzielle Unterst\u00fctzung.\nA: Ich biete dir meine Unterst\u00fctzung an.\nB: Danke, das bedeutet mir viel.",exampleSrc:"A: Do you need support?\nB: Yes, financial support.\nA: I offer you my support.\nB: Thank you, that means a lot to me.",funFact:"Unter (under) + st\u00fctzen (to support). Support from below. 'Finanzielle Unterst\u00fctzung' (financial support). 'Um Unterst\u00fctzung bitten' (to ask for support). You hold something up from underneath."},
{type:"teach",trg:"der Tierpark",src:"zoo, animal park",pos:"noun",gender:"m",note:"Tier (animal) + Park. 'Der Berliner Tierpark' is the largest\nlandscape zoo in Europe. Emphasizes the park-like setting.",example:"A: Warst du schon im Tierpark?\nB: Ja, der Berliner Tierpark ist toll.\nA: Ist Tierpark dasselbe wie Zoo?\nB: \u00c4hnlich, aber der Tierpark ist mehr wie ein Park.",exampleSrc:"A: Have you been to the animal park?\nB: Yes, the Berlin Tierpark is great.\nA: Is Tierpark the same as Zoo?\nB: Similar, but the Tierpark is more like a park.",funFact:"Tier (animal) + Park. 'Der Berliner Tierpark' is the largest landscape zoo in Europe. Different from 'Zoo' (which is also used). Tierpark emphasizes the park-like setting."},
{type:"teach",trg:"besch\u00e4digen",src:"to damage",pos:"verb",gender:null,note:"Be- + Schaden (damage). 'Der Sturm hat das Dach besch\u00e4digt.'\nRegular verb. The be- prefix makes 'Schaden' transitive.",example:"A: Der Sturm hat das Dach besch\u00e4digt.\nB: Wie schlimm?\nA: Ziemlich besch\u00e4digt.\nB: Wir m\u00fcssen es reparieren lassen.",exampleSrc:"A: The storm damaged the roof.\nB: How bad?\nA: Quite damaged.\nB: We need to have it repaired.",funFact:"Be- + Schaden (damage). 'Der Sturm hat das Dach besch\u00e4digt' (The storm damaged the roof). Regular verb. The be- prefix makes 'Schaden' into a transitive verb."},
{type:"teach",trg:"brennen",src:"to burn",pos:"verb",gender:null,note:"Irregular: brannte, gebrannt. Cognate with English 'burn.'\n'Es brennt!' (It's burning!) is what you shout during a fire.",example:"A: Es brennt! Ruf die Feuerwehr!\nB: Wo brennt es?\nA: In der K\u00fcche. Das Essen brennt.\nB: Schnell, Wasser!",exampleSrc:"A: It's burning! Call the fire department!\nB: Where is it burning?\nA: In the kitchen. The food is burning.\nB: Quick, water!",funFact:"Irregular: brannte, gebrannt. Cognate with English 'burn.' 'Es brennt!' (It is burning!) is what you shout during a fire. 'Brennholz' (firewood). 'Brennnessel' (stinging nettle, the burning nettle)."},
{type:"teach",trg:"donnern",src:"to thunder",pos:"verb",gender:null,note:"From Donner. 'Es donnert' (it is thundering).\nAlso: 'gegen die T\u00fcr donnern' (to bang on the door).",example:"A: Es donnert seit einer Stunde.\nB: Ja, ein starkes Gewitter.\nA: Wer donnert da gegen die T\u00fcr?\nB: Der Nachbar. Er will rein.",exampleSrc:"A: It has been thundering for an hour.\nB: Yes, a strong thunderstorm.\nA: Who is banging on the door?\nB: The neighbor. He wants to come in.",funFact:"From Donner. 'Es donnert' (it is thundering). Also: 'gegen die T\u00fcr donnern' (to bang on the door). Regular despite its mythological origins. Thor would approve."},
{type:"teach",trg:"blitzen",src:"to flash (lightning)",pos:"verb",gender:null,note:"From 'Blitz' (lightning). 'Es blitzt' (there is lightning).\nSpeed cameras are called 'Blitzer' because they flash.",example:"A: Es blitzt!\nB: Und es donnert auch.\nA: Vorsicht, Blitzer!\nB: Zu sp\u00e4t. Geblitzt.",exampleSrc:"A: Lightning!\nB: And it is thundering too.\nA: Watch out, speed camera!\nB: Too late. Got flashed.",funFact:"From 'Blitz' (lightning). 'Es blitzt' (there is lightning). 'Blitzschnell' (lightning fast). Also: speed cameras are called 'Blitzer' because they flash when they catch you."},
{type:"teach",trg:"hageln",src:"to hail",pos:"verb",gender:null,note:"From 'Hagel' (hail). 'Es hagelt' (it is hailing).\n'Es hagelt Beschwerden' (complaints are hailing down).",example:"A: Es hagelt!\nB: Stell das Auto in die Garage.\nA: Hagel kann Autos zerst\u00f6ren.\nB: Ja, und auch Gew\u00e4chsh\u00e4user.",exampleSrc:"A: It is hailing!\nB: Put the car in the garage.\nA: Hail can destroy cars.\nB: Yes, and also greenhouses.",funFact:"From 'Hagel' (hail). 'Es hagelt' (it is hailing). Hail can destroy cars, crops, and greenhouse roofs. 'Es hagelt Beschwerden' (complaints are hailing down) is used figuratively."},
{type:"teach",trg:"trocknen",src:"to dry",pos:"verb",gender:null,note:"From 'trocken' (dry). 'W\u00e4sche trocknen' (to dry laundry).\nGermans often air-dry laundry rather than using a dryer.",example:"A: Die W\u00e4sche muss trocknen.\nB: Drau\u00dfen oder drinnen?\nA: Drau\u00dfen. Die Sonne trocknet schnell.\nB: Aber nur, wenn es nicht regnet.",exampleSrc:"A: The laundry needs to dry.\nB: Outside or inside?\nA: Outside. The sun dries quickly.\nB: But only if it doesn't rain.",funFact:"From 'trocken' (dry). 'W\u00e4sche trocknen' (to dry laundry). Germans often air-dry laundry rather than using a Trockner (dryer). Energy-saving and laundry-friendly."},
{type:"teach",trg:"retten",src:"to rescue, to save",pos:"verb",gender:null,note:"'Die Feuerwehr rettet Menschen.' 'Die Umwelt retten.'\n'Rettungswagen' (ambulance). A verb of heroic action.",example:"A: Die Feuerwehr rettet ein Kind.\nB: Helden!\nA: K\u00f6nnen wir die Umwelt noch retten?\nB: Ja, aber wir m\u00fcssen jetzt handeln.",exampleSrc:"A: The fire department is rescuing a child.\nB: Heroes!\nA: Can we still save the environment?\nB: Yes, but we need to act now.",funFact:"'Die Feuerwehr rettet Menschen' (The fire department rescues people). 'Die Umwelt retten' (to save the environment). 'Rettungswagen' (ambulance). A verb of heroic action."},
{type:"teach",trg:"steil",src:"steep",pos:"adj",gender:null,note:"'Ein steiler H\u00fcgel' (a steep hill). 'Steile Karriere'\n(meteoric career). 'Steile These' (bold claim).",example:"A: Der Weg ist sehr steil.\nB: Ja, ziemlich steil hier.\nA: Seine Karriere ist steil.\nB: Von null auf hundert.",exampleSrc:"A: The path is very steep.\nB: Yes, quite steep here.\nA: His career is steep.\nB: From zero to a hundred.",funFact:"'Ein steiler H\u00fcgel' (a steep hill). 'Steile Karriere' (meteoric career). 'Steile These' (bold claim). From physical incline to figurative extremes."},
{type:"teach",trg:"wild",src:"wild",pos:"adj",gender:null,note:"Same word, same meaning as English. 'Wilde Tiere' (wild animals).\nGermany has more wild boars than any European country.",example:"A: Gibt es wilde Tiere in Berlin?\nB: Ja, Wildschweine in den Vororten.\nA: Wild!\nB: Wirklich wild. Pass auf im Park.",exampleSrc:"A: Are there wild animals in Berlin?\nB: Yes, wild boars in the suburbs.\nA: Wild!\nB: Really wild. Be careful in the park.",funFact:"Same word, same meaning as English. 'Wilde Tiere' (wild animals), 'Wildnis' (wilderness). 'Wildschwein' (wild boar) roam Berlin's suburbs. Germany has more wild boars than any European country."},
{type:"story",speaker:"mia",mood:"warm",art:"de-park-bench",trg:"Du bist ein richtiger Berliner geworden. Du trennst deinen M\u00fcll, du l\u00e4sst dein Fahrrad reparieren statt ein neues zu kaufen, und du kennst jeden Pfandautomaten in Kreuzberg.",src:"You have become a real Berliner. You separate your trash, you have your bike repaired instead of buying a new one, and you know every deposit machine in Kreuzberg."},
{type:"mc",q:"Yilmaz sagt: 'Du kannst ruhig du sagen.' Welchen sozialen Meilenstein stellt das dar?",opts:["Sie bittet ihn, sie formell anzusprechen","Sie bittet ihn, leiser zu sprechen","Sie bietet informelle Anrede als Zeichen der N\u00e4he an","Sie korrigiert seine Grammatik"],ans:"Sie bietet informelle Anrede als Zeichen der N\u00e4he an",hint:"Der Wechsel von Sie zu du ist ein pers\u00f6nlicher Meilenstein in der deutschen Kultur."}
]},

// ============================================================
// Lesson 7: Umwelt-Quiz (Environment Quiz)
// Type: Comprehensive quiz. 14 new words. 22 steps.
// Assessment of all three grammar constructs.
// ============================================================
{id:"deu_r22l7",title:"Umwelt-Quiz",icon:"\ud83c\udfc6",xp:15,board:true,steps:[
{type:"intro",title:"Umwelt-Quiz",desc:"Test your environmental German. Prove you have mastered Partizip I and II as adjectives and can use lassen in all its meanings.",goals:["Test your environmental vocabulary","Prove mastery of Partizip I and II","Show you can use lassen in all its meanings"]},
{type:"teach",trg:"der Dreck",src:"dirt, filth",pos:"noun",gender:"m",note:"More colloquial than Schmutz. 'Im Dreck sitzen' (to be in trouble).\nNorthern German uses Dreck, southern prefers Schmutz.",example:"A: Hier ist \u00fcberall Dreck.\nB: Ja, wir m\u00fcssen sauber machen.\nA: Er sitzt im Dreck.\nB: Ja, gro\u00dfe Probleme.",exampleSrc:"A: There is dirt everywhere.\nB: Yes, we need to clean.\nA: He is in trouble. (lit: sitting in dirt)\nB: Yes, big problems.",funFact:"More colloquial than Schmutz. 'Im Dreck sitzen' (to be in trouble, literally: sitting in dirt). 'Dreckig' (dirty/filthy). Northern German uses Dreck, southern prefers Schmutz."},
{type:"teach",trg:"der Schmutz",src:"dirt, grime",pos:"noun",gender:"m",note:"More formal than Dreck. 'Schmutzig' (dirty).\n'Schmutzwasser' (dirty water).",example:"A: Der Schmutz muss weg.\nB: Ja, alles ist schmutzig.\nA: Schmutzwasser darf nicht in den Fluss.\nB: Deshalb gibt es Kl\u00e4ranlagen.",exampleSrc:"A: The dirt has to go.\nB: Yes, everything is dirty.\nA: Dirty water must not go into the river.\nB: That's why there are water treatment plants.",funFact:"More formal than Dreck. 'Schmutzig' (dirty). 'Schmutzwasser' (dirty water). The Sch- sound gives it a squelchy feel. German onomatopoeia at work."},
{type:"teach",trg:"der Staub",src:"dust",pos:"noun",gender:"m",note:"Cognate with English 'dust' (via different path).\n'Staubsauger' (vacuum cleaner, literally dust-sucker).",example:"A: \u00dcberall Staub!\nB: Wo ist der Staubsauger?\nA: Im Schrank. Staub wischen ist wichtig.\nB: Zu Staub werden wir alle.",exampleSrc:"A: Dust everywhere!\nB: Where is the vacuum cleaner?\nA: In the closet. Dusting is important.\nB: We all turn to dust eventually.",funFact:"Cognate with English 'dust' (via different path). 'Staubsauger' (vacuum cleaner, literally dust-sucker). 'Staub wischen' (to dust). 'Zu Staub werden' (to turn to dust)."},
{type:"teach",trg:"der H\u00fcgel",src:"hill",pos:"noun",gender:"m",note:"Diminutive feel from the -el ending. 'Ameisenh\u00fcgel' (anthill).\nGermany is full of H\u00fcgel in the Mittelgebirge region.",example:"A: Lass uns auf den H\u00fcgel steigen.\nB: Der H\u00fcgel ist ziemlich steil.\nA: Von oben sieht man die ganze Umgebung.\nB: Das lohnt sich.",exampleSrc:"A: Let's climb the hill.\nB: The hill is quite steep.\nA: From the top you can see the whole area.\nB: It's worth it.",funFact:"Diminutive feel from the -el ending, though not a true diminutive. 'Ameisenh\u00fcgel' (anthill). Germany's landscape is full of H\u00fcgel, especially in the Mittelgebirge region."},
{type:"teach",trg:"das Gebirge",src:"mountain range",pos:"noun",gender:"n",note:"Ge- + Berg (mountain) collective. 'Hochgebirge' (high mountains).\nThe Ge- prefix creates a collective: many mountains together.",example:"A: Die Alpen sind ein Hochgebirge.\nB: Ja, das h\u00f6chste Gebirge Europas.\nA: Und das Mittelgebirge?\nB: Niedriger, aber auch sch\u00f6n.",exampleSrc:"A: The Alps are a high mountain range.\nB: Yes, the highest mountain range in Europe.\nA: And the medium-height mountains?\nB: Lower, but also beautiful.",funFact:"Ge- + Berg (mountain) collective. Mountain range. 'Hochgebirge' (high mountains), 'Mittelgebirge' (medium-height mountains). The Ge- prefix creates a collective: many mountains together."},
{type:"teach",trg:"das Tal",src:"valley",pos:"noun",gender:"n",note:"Cognate with English 'dale.' 'Rheintal' (Rhine valley).\n'Bergauf, bergab, durch jedes Tal.'",example:"A: Das Tal ist wundersch\u00f6n.\nB: Ja, das Rheintal ist ber\u00fchmt.\nA: Durch jedes Tal flie\u00dft ein Fluss.\nB: Meistens, ja.",exampleSrc:"A: The valley is beautiful.\nB: Yes, the Rhine valley is famous.\nA: Through every valley flows a river.\nB: Mostly, yes.",funFact:"Cognate with English 'dale.' 'Rheintal' (Rhine valley), 'Moseltal' (Moselle valley). 'Bergauf, bergab, durch jedes Tal' (uphill, downhill, through every valley)."},
{type:"teach",trg:"der Mond",src:"moon",pos:"noun",gender:"m",note:"Cognate with English 'moon' and 'month' (Monat).\nSame root: time was measured by moons. 'Vollmond' (full moon).",example:"A: Schau, der Vollmond!\nB: Wundersch\u00f6n. Mondschein.\nA: Bei Vollmond schlafe ich schlecht.\nB: Ich auch. Komisch, oder?",exampleSrc:"A: Look, the full moon!\nB: Beautiful. Moonlight.\nA: I sleep badly during a full moon.\nB: Me too. Strange, right?",funFact:"Cognate with English 'moon' and 'month' (Monat). Same root: time was measured by moons. 'Vollmond' (full moon), 'Halbmond' (crescent/half moon). 'Mondschein' (moonshine/moonlight)."},
{type:"teach",trg:"der Stern",src:"star",pos:"noun",gender:"m",note:"Cognate with English 'star' (via Latin 'stella').\n'Sternschnuppe' (shooting star). Also a famous German news magazine.",example:"A: Schau dir die Sterne an!\nB: So viele Sterne heute.\nA: Hast du eine Sternschnuppe gesehen?\nB: Ja, w\u00fcnsch dir was!",exampleSrc:"A: Look at the stars!\nB: So many stars today.\nA: Did you see a shooting star?\nB: Yes, make a wish!",funFact:"Cognate with English 'star' (via Latin 'stella'). 'Sternschnuppe' (shooting star, literally star-snip). 'F\u00fcnf-Sterne-Hotel' (five-star hotel). Stern is also a famous German news magazine."},
{type:"teach",trg:"der L\u00e4rm",src:"noise",pos:"noun",gender:"m",note:"From French 'alarme.' 'L\u00e4rmschutz' (noise protection).\nGermans have strict Ruhezeiten (quiet hours).",example:"A: Der L\u00e4rm ist unertr\u00e4glich.\nB: Ja, zu viel L\u00e4rm.\nA: L\u00e4rm am Sonntag ist verboten.\nB: Ruhezeiten m\u00fcssen eingehalten werden.",exampleSrc:"A: The noise is unbearable.\nB: Yes, too much noise.\nA: Noise on Sunday is forbidden.\nB: Quiet hours must be observed.",funFact:"From French 'alarme.' 'L\u00e4rm machen' (to make noise). 'L\u00e4rmschutz' (noise protection). Germans have strict Ruhezeiten (quiet hours). Lawn mowing on Sunday? That is illegal L\u00e4rm."},
{type:"teach",trg:"das Gas",src:"gas",pos:"noun",gender:"n",note:"Coined by Dutch chemist Van Helmont in the 1600s from Greek 'chaos.'\n'Erdgas' (natural gas). 'Gas geben' (to step on the gas).",example:"A: Heizen wir mit Gas?\nB: Ja, Erdgas.\nA: Gas geben!\nB: Wir fahren schon schnell genug.",exampleSrc:"A: Do we heat with gas?\nB: Yes, natural gas.\nA: Step on it!\nB: We are already going fast enough.",funFact:"Coined by Dutch chemist Van Helmont in the 1600s from Greek 'chaos.' 'Erdgas' (natural gas), 'Abgas' (exhaust gas). 'Gas geben' (to step on the gas/accelerate). A Dutch-invented word used worldwide."},
{type:"teach",trg:"zerst\u00f6ren",src:"to destroy",pos:"verb",gender:null,note:"Zer- + st\u00f6ren (to disturb). The zer- prefix means apart/to pieces.\nStronger than besch\u00e4digen (to damage). Total destruction.",example:"A: Der Sturm hat alles zerst\u00f6rt.\nB: Komplett zerst\u00f6rt?\nA: Ja, das Haus ist zerst\u00f6rt.\nB: Das ist eine Katastrophe.",exampleSrc:"A: The storm destroyed everything.\nB: Completely destroyed?\nA: Yes, the house is destroyed.\nB: That is a catastrophe.",funFact:"Zer- + st\u00f6ren (to disturb). The zer- prefix means apart/to pieces. 'Die Umwelt zerst\u00f6ren' (to destroy the environment). Stronger than besch\u00e4digen (to damage). Total destruction."},
{type:"teach",trg:"weltenweit",src:"worldwide (literary)",pos:"adj",gender:null,note:"Welten (worlds) + weit (wide). A poetic variant of weltweit.\n'Weltenweite Probleme.' The extra -en- adds a literary tone.",example:"A: Das Problem ist weltenweit.\nB: Ja, nicht nur in Deutschland.\nA: Weltenweite Zusammenarbeit ist n\u00f6tig.\nB: Alle L\u00e4nder m\u00fcssen helfen.",exampleSrc:"A: The problem is worldwide.\nB: Yes, not only in Germany.\nA: Worldwide cooperation is needed.\nB: All countries must help.",funFact:"Welten (worlds) + weit (wide). A poetic variant of weltweit. Both are used. 'Weltenweite Probleme' (worldwide problems). The extra -en- adds a literary tone."},
{type:"teach",trg:"weltweit",src:"worldwide",pos:"adj",gender:null,note:"Welt + weit. The standard form. 'Weltweit bekannt'\n(known worldwide). More common than weltenweit.",example:"A: Dieses Problem ist weltweit.\nB: Ja, \u00fcberall auf der Welt.\nA: Weltweit einzigartig.\nB: Es gibt nichts Vergleichbares.",exampleSrc:"A: This problem is worldwide.\nB: Yes, everywhere in the world.\nA: Unique worldwide.\nB: There is nothing comparable.",funFact:"Welt + weit. The standard form. 'Weltweit bekannt' (known worldwide). More common than weltenweit in everyday use. 'Weltweit einzigartig' (unique worldwide)."},
{type:"teach",trg:"zentral",src:"central",pos:"adj",gender:null,note:"From Latin 'centralis.' 'Zentrale Lage' (central location).\n'Zentralheizung' (central heating).",example:"A: Die Lage ist sehr zentral.\nB: Ja, direkt in der Stadtmitte.\nA: Hast du Zentralheizung?\nB: Ja, in jedem Zimmer.",exampleSrc:"A: The location is very central.\nB: Yes, right in the city center.\nA: Do you have central heating?\nB: Yes, in every room.",funFact:"From Latin 'centralis.' 'Zentrale Lage' (central location). 'Zentralheizung' (central heating). Every German apartment listing mentions whether it has Zentralheizung."},
{type:"mc",q:"'Die steigenden Kosten und die wachsende Verschmutzung sind ein Problem.' Welche zwei Formen sind Partizip I?",opts:["steigenden und Verschmutzung","steigenden und wachsende","Kosten und Problem","wachsende und Problem"],ans:"steigenden und wachsende",hint:"Partizip I = Infinitiv + d + Adjektivendung. Suche nach dem -end-Muster."},
{type:"fb",s:"Die {1} Luft in der Stadt ist ein Gesundheitsrisiko.",a:["verschmutzte"],opts:["verschmutzte","verschmutzende","verschmutzen","Verschmutzung"],hint:"Die Luft IST verschmutzt worden. Partizip II als Adjektiv. Abgeschlossene Handlung.",sSrc:"The polluted air in the city is a health risk."},
{type:"mc",q:"Welcher Satz benutzt lassen als KAUSATIV (etwas machen lassen)?",opts:["Er l\u00e4sst den Hund im Auto","Lass das!","Ich lasse mein Fahrrad reparieren","Lass mich in Ruhe!"],ans:"Ich lasse mein Fahrrad reparieren",hint:"Kausativ bedeutet: jemand anderes f\u00fchrt die Handlung f\u00fcr dich aus. Wer repariert das Fahrrad?"},
{type:"drag_fill",s:"Der {1} Fluss und die {2} Fabrik sind ein Problem.",blanks:{"1":"verschmutzte","2":"brennende"},pool:["verschmutzte","brennende","verschmutzende","gebrannt","brennen"],hint:"Der Fluss wurde verschmutzt (abgeschlossen). Die Fabrik brennt gerade (laufend). Welches ist P1, welches P2?",sSrc:"The polluted river and the burning factory are a problem."},
{type:"mc",q:"Es donnert, es blitzt, und der Wind ist extrem stark. Welches Wort beschreibt dieses Wetter?",opts:["Sturm","Durchschnitt","Schatten","Umgebung"],ans:"Sturm",hint:"Donner, Blitz, extremer Wind. Das ist ein schweres Wetterereignis."},
{type:"fb",s:"Das Problem {1} sich l\u00f6sen.",a:["l\u00e4sst"],opts:["l\u00e4sst","lassen","lass","lasst"],hint:"Sich lassen + Infinitiv = kann gemacht werden. Dritte Person Singular.",sSrc:"The problem can be solved."},
{type:"match",pairs:[{trg:"der lachende Mann",src:"Partizip I (ongoing)"},{trg:"der gelesene Brief",src:"Partizip II (completed)"},{trg:"Ich lasse reparieren",src:"lassen causative"},{trg:"Das l\u00e4sst sich machen",src:"sich lassen passive"}]}
]},

// ============================================================
// Lesson 8: Ein richtiger Berliner (A Real Berliner)
// Type: Resolution + culture. 18 new words. 22 steps.
// Scene: Park bench reflection + cultural wrap-up.
// ============================================================
{id:"deu_r22l8",title:"Ein richtiger Berliner",icon:"\ud83c\udf33",xp:15,board:true,steps:[
{type:"intro",title:"Ein richtiger Berliner",desc:"Das letzte Kapitel dieser Einheit. Verumius blickt zur\u00fcck auf ein Jahr in Berlin. Lerne letzte Umwelt- und Notfallw\u00f6rter und bereite dich auf die n\u00e4chste Stufe vor.",goals:["Lerne 18 letzte W\u00f6rter zu Umwelt und Notfall","Reflektiere \u00fcber Verumius' Wachstum in Berlin","Bereite dich auf die B1-Pr\u00fcfungsreise vor"]},
{type:"teach",trg:"der Protest",src:"protest",pos:"noun",gender:"m",note:"From Latin 'protestari' (to declare publicly). 'Klimaprotest.'\n'Fridays for Future' made Berlin a global protest capital.",example:"A: Warst du beim Klimaprotest?\nB: Ja, tausende Leute waren da.\nA: Protest hilft!\nB: Ja, er macht auf Probleme aufmerksam.",exampleSrc:"A: Were you at the climate protest?\nB: Yes, thousands of people were there.\nA: Protesting helps!\nB: Yes, it draws attention to problems.",funFact:"From Latin 'protestari' (to declare publicly). 'Klimaprotest' (climate protest). 'Gegen etwas protestieren' (to protest against something). 'Fridays for Future' made Berlin a global protest capital."},
{type:"teach",trg:"die Alternative",src:"alternative",pos:"noun",gender:"f",note:"From Latin 'alternare.' 'Alternativlos' was Germany's\nun-word of the year 2010. Means there is no other option.",example:"A: Gibt es eine Alternative?\nB: Ja, erneuerbare Energie.\nA: Manche sagen, es gibt keine Alternative.\nB: 'Alternativlos' ist ein gef\u00e4hrliches Wort.",exampleSrc:"A: Is there an alternative?\nB: Yes, renewable energy.\nA: Some say there is no alternative.\nB: 'Without alternative' is a dangerous word.",funFact:"From Latin 'alternare.' 'Eine Alternative finden' (to find an alternative). 'Alternativlos' was Germany's un-word of the year 2010. It means there is no other option."},
{type:"teach",trg:"die Klimaanlage",src:"air conditioning",pos:"noun",gender:"f",note:"Klima + Anlage (system/facility). Rare in German homes.\nMost Germans say: open the window. Fresh air beats everything.",example:"A: Brauchen wir eine Klimaanlage?\nB: Nein, \u00f6ffne das Fenster.\nA: Bei 40 Grad?\nB: Okay, vielleicht doch eine Klimaanlage.",exampleSrc:"A: Do we need air conditioning?\nB: No, open the window.\nA: At 40 degrees?\nB: Okay, maybe air conditioning after all.",funFact:"Klima + Anlage (system/facility). Air conditioning. Rare in German homes. 'Brauchen wir eine Klimaanlage?' is the summer debate. Most Germans say no. Open the window."},
{type:"teach",trg:"der Hersteller",src:"manufacturer",pos:"noun",gender:"m",note:"Her (here/toward) + stellen (to place). The one who places\nsomething into existence. 'Vom Hersteller empfohlen.'",example:"A: Wer ist der Hersteller?\nB: Ein deutscher Hersteller.\nA: Vom Hersteller empfohlen?\nB: Ja, mit Garantie.",exampleSrc:"A: Who is the manufacturer?\nB: A German manufacturer.\nA: Recommended by the manufacturer?\nB: Yes, with warranty.",funFact:"Her (here/toward) + stellen (to place). Manufacturer. 'Automobilhersteller' (car manufacturer). 'Vom Hersteller empfohlen' (recommended by the manufacturer). The one who places something into existence."},
{type:"teach",trg:"die Feuerwehr",src:"fire department",pos:"noun",gender:"f",note:"Feuer (fire) + Wehr (defense). Fire defense. Call 112.\nGerman volunteer fire departments have 1 million members.",example:"A: Ruf die Feuerwehr! 112!\nB: Ich rufe sofort an.\nA: Die Feuerwehr kommt schnell.\nB: In f\u00fcnf Minuten sind sie da.",exampleSrc:"A: Call the fire department! 112!\nB: I'll call right away.\nA: The fire department comes quickly.\nB: In five minutes they are there.",funFact:"Feuer (fire) + Wehr (defense). Fire defense = fire department. 'Die Feuerwehr rufen' (to call the fire department). Call 112. German volunteer fire departments have 1 million members. Heroes in every village."},
{type:"teach",trg:"die Umweltverschmutzung",src:"environmental pollution",pos:"noun",gender:"f",note:"Umwelt + Verschmutzung (pollution). 22 letters.\nA compound noun that carries the weight of the problem.",example:"A: Umweltverschmutzung ist ein globales Problem.\nB: Ja, \u00fcberall auf der Welt.\nA: Wie k\u00f6nnen wir Umweltverschmutzung reduzieren?\nB: Weniger Abgase, weniger Plastik.",exampleSrc:"A: Environmental pollution is a global problem.\nB: Yes, everywhere in the world.\nA: How can we reduce environmental pollution?\nB: Fewer emissions, less plastic.",funFact:"Umwelt + Verschmutzung (pollution). Environmental pollution. 22 letters. A compound noun that carries the weight of the problem. 'Umweltverschmutzung reduzieren' (to reduce environmental pollution)."},
{type:"teach",trg:"der Z\u00fcnder",src:"igniter, detonator",pos:"noun",gender:"m",note:"From 'z\u00fcnden' (to ignite). 'Z\u00fcndstoff' (explosive material,\nalso figuratively: a hot topic). The dating app is named after this concept.",example:"A: Der Z\u00fcnder funktioniert nicht.\nB: Versuch es nochmal.\nA: Das Thema ist Z\u00fcndstoff.\nB: Ja, sehr kontrovers.",exampleSrc:"A: The igniter doesn't work.\nB: Try again.\nA: The topic is explosive material.\nB: Yes, very controversial.",funFact:"From 'z\u00fcnden' (to ignite). 'Z\u00fcndstoff' (explosive material, also figuratively: a hot topic). The dating app Tinder is named after this concept: something that ignites."},
{type:"teach",trg:"das Z\u00fcndholz",src:"match (for lighting)",pos:"noun",gender:"n",note:"Z\u00fcnd (ignite) + Holz (wood). Synonym of Streichholz.\nSouthern German prefers Z\u00fcndholz, northern prefers Streichholz.",example:"A: Hast du ein Z\u00fcndholz?\nB: Meinst du Streichholz?\nA: Ja, dasselbe. Regional verschieden.\nB: S\u00fcddeutsch sagt Z\u00fcndholz.",exampleSrc:"A: Do you have a match?\nB: You mean Streichholz?\nA: Yes, the same thing. Regional difference.\nB: Southern German says Z\u00fcndholz.",funFact:"Z\u00fcnd (ignite) + Holz (wood). A match. Synonym of Streichholz. Southern German prefers Z\u00fcndholz, northern prefers Streichholz. Same object, regional word choice."},
{type:"teach",trg:"die Form",src:"form, shape",pos:"noun",gender:"f",note:"From Latin 'forma.' 'In Form' (in shape/fit).\n'Die Form wahren' (to keep up appearances).",example:"A: In welcher Form ist das Grundst\u00fcck?\nB: Rechteckig.\nA: Bist du in Form?\nB: Ja, ich trainiere jeden Tag.",exampleSrc:"A: What shape is the plot of land?\nB: Rectangular.\nA: Are you in shape?\nB: Yes, I train every day.",funFact:"From Latin 'forma.' 'In Form' (in shape/fit), 'Formular' (form to fill out). 'Die Form wahren' (to keep up appearances). A word that spans fitness, bureaucracy, and etiquette."},
{type:"teach",trg:"unterst\u00fctzen",src:"to support",pos:"verb",gender:null,note:"Unter (under) + st\u00fctzen (to prop up). To support from below.\n'Die Regierung unterst\u00fctzt erneuerbare Energien.'",example:"A: Unterst\u00fctzt die Regierung Solarenergie?\nB: Ja, mit F\u00f6rderprogrammen.\nA: Wie kann ich die Umwelt unterst\u00fctzen?\nB: Weniger verbrauchen und mehr recyceln.",exampleSrc:"A: Does the government support solar energy?\nB: Yes, with funding programs.\nA: How can I support the environment?\nB: Consume less and recycle more.",funFact:"Unter (under) + st\u00fctzen (to prop up). To support from below. 'Erneuerbare Energien unterst\u00fctzen' (to support renewable energies). Regular verb. Related to Unterst\u00fctzung (support, the noun)."},
{type:"teach",trg:"entsorgen",src:"to dispose of",pos:"verb",gender:null,note:"Ent- (away from) + sorgen (to care). To dispose of.\nThe ent- prefix removes the care: you send it away.",example:"A: Wie entsorge ich Batterien?\nB: In die gr\u00fcne Sammelbox.\nA: Und Sonderm\u00fcll?\nB: Zum Wertstoffhof bringen.",exampleSrc:"A: How do I dispose of batteries?\nB: In the green collection box.\nA: And hazardous waste?\nB: Take it to the recycling center.",funFact:"Ent- (away from) + sorgen (to care). To dispose of. 'M\u00fcll entsorgen' (to dispose of trash). 'Sonderm\u00fcll entsorgen' (to dispose of hazardous waste). The ent- prefix removes the care: you send it away."},
{type:"teach",trg:"schaden",src:"to damage, to harm",pos:"verb",gender:null,note:"Takes dative. 'Der Umwelt schaden' (to harm the environment).\n'Rauchen schadet der Gesundheit.' Also a noun: der Schaden.",example:"A: Plastik schadet der Umwelt.\nB: Ja, besonders dem Meer.\nA: Rauchen schadet der Gesundheit.\nB: Das wei\u00df jeder.",exampleSrc:"A: Plastic harms the environment.\nB: Yes, especially the sea.\nA: Smoking damages health.\nB: Everyone knows that.",funFact:"'Der Umwelt schaden' (to harm the environment). Takes dative. 'Rauchen schadet der Gesundheit' (Smoking damages health). Also a noun: der Schaden (the damage)."},
{type:"teach",trg:"vergr\u00f6\u00dfern",src:"to enlarge, to increase",pos:"verb",gender:null,note:"Ver- + gro\u00df (big). 'Das Bild vergr\u00f6\u00dfern' (to enlarge the image).\nThe opposite: verkleinern (to make smaller).",example:"A: Kannst du das Bild vergr\u00f6\u00dfern?\nB: Ja, wie gro\u00df?\nA: Wir m\u00fcssen den Abstand vergr\u00f6\u00dfern.\nB: Okay, mehr Platz zwischen uns.",exampleSrc:"A: Can you enlarge the image?\nB: Yes, how big?\nA: We need to increase the distance.\nB: Okay, more space between us.",funFact:"Ver- + gro\u00df (big). 'Das Bild vergr\u00f6\u00dfern' (to enlarge the image). 'Den Abstand vergr\u00f6\u00dfern' (to increase the distance). The opposite: verkleinern (to make smaller)."},
{type:"teach",trg:"verbrennen",src:"to burn (up), to incinerate",pos:"verb",gender:null,note:"Ver- + brennen. Irregular: verbrannte, verbrannt.\nThe ver- prefix means to completion: burned up entirely.",example:"A: Darf man M\u00fcll verbrennen?\nB: Nur in speziellen Anlagen.\nA: Ich habe mich verbrannt!\nB: Kaltes Wasser, schnell!",exampleSrc:"A: Is it allowed to burn trash?\nB: Only in special facilities.\nA: I burned myself!\nB: Cold water, quick!",funFact:"Ver- + brennen. Irregular: verbrannte, verbrannt. 'M\u00fcll verbrennen' (to incinerate trash). 'Sich verbrennen' (to burn oneself). The ver- prefix means to completion: burned up entirely."},
{type:"teach",trg:"elektr-",src:"electr- (prefix for adjectives)",pos:"part",gender:null,note:"From Greek 'elektron' (amber). 'Elektrisch' (electric),\n'Elektronik' (electronics), 'Elektrizit\u00e4t' (electricity).",example:"A: Ist das elektrisch?\nB: Ja, rein elektrisch.\nA: Elektrische Ger\u00e4te verbrauchen Strom.\nB: Energieeffiziente Ger\u00e4te sparen Geld.",exampleSrc:"A: Is that electric?\nB: Yes, purely electric.\nA: Electrical devices use electricity.\nB: Energy-efficient devices save money.",funFact:"From Greek 'elektron' (amber). 'Elektrisch' (electric), 'Elektronik' (electronics), 'Elektrizit\u00e4t' (electricity). The elektr- base forms adjectives and abstract nouns about electricity."},
{type:"teach",trg:"elektro-",src:"electro- (prefix for compound nouns)",pos:"part",gender:null,note:"'Elektroauto' (electric car), 'Elektroherd' (electric stove).\nGermany's Elektromobilit\u00e4t push aims for 15 million e-cars by 2030.",example:"A: F\u00e4hrst du ein Elektroauto?\nB: Ja, seit einem Jahr.\nA: Und ein Elektroherd?\nB: Ja, Gas ist mir zu gef\u00e4hrlich.",exampleSrc:"A: Do you drive an electric car?\nB: Yes, for a year.\nA: And an electric stove?\nB: Yes, gas is too dangerous for me.",funFact:"'Elektroauto' (electric car), 'Elektroherd' (electric stove), 'Elektroger\u00e4t' (electrical device). Germany's Elektromobilit\u00e4t (e-mobility) push aims for 15 million e-cars by 2030."},
{type:"teach",trg:"\u00f6ko-",src:"eco- (prefix)",pos:"part",gender:null,note:"From Greek 'oikos' (house/household). '\u00d6kologie' (ecology),\n'\u00d6kostrom' (green electricity). '\u00d6ko' by itself is slang for environmentalist.",example:"A: Kaufst du \u00d6kostrom?\nB: Ja, und \u00d6ko-Lebensmittel.\nA: Bist du ein \u00d6ko?\nB: Ja, stolz darauf!",exampleSrc:"A: Do you buy green electricity?\nB: Yes, and organic food.\nA: Are you an eco-person?\nB: Yes, proud of it!",funFact:"From Greek 'oikos' (house/household). '\u00d6kologie' (ecology), '\u00d6kostrom' (green electricity), '\u00d6kosystem' (ecosystem). The prefix that turns everything green. '\u00d6ko' by itself is slang for an environmentalist."},
{type:"teach",trg:"\u00fcber-",src:"over-/above-/beyond- (prefix)",pos:"part",gender:null,note:"'\u00dcberdurchschnittlich' (above average), '\u00fcberall' (everywhere),\n'\u00fcbertreiben' (to exaggerate). The most productive German prefix.",example:"A: Das ist \u00fcberdurchschnittlich gut.\nB: Ja, weit \u00fcber dem Durchschnitt.\nA: \u00dcbertreib nicht!\nB: Ich \u00fcbertreibe nicht. Es ist \u00fcberall so.",exampleSrc:"A: That is above average.\nB: Yes, far above average.\nA: Don't exaggerate!\nB: I'm not exaggerating. It's like that everywhere.",funFact:"'\u00dcberdurchschnittlich' (above average), '\u00fcberall' (everywhere), '\u00fcbertreiben' (to exaggerate). The most productive German prefix. It intensifies everything it touches."},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-park-bench",trg:"Ein Jahr in Berlin. Der verlorene Tourist vom Flughafen ist jetzt ein Berliner, der seinen M\u00fcll trennt, sein Fahrrad reparieren l\u00e4sst und jeden Pfandautomaten in Kreuzberg kennt. Die n\u00e4chste Stufe wartet: die Pr\u00fcfung.",src:"One year in Berlin. The lost tourist from the airport is now a Berliner who separates his trash, has his bike repaired, and knows every deposit machine in Kreuzberg. The next level awaits: the exam."},
{type:"mc",q:"Umweltverschmutzung, Klimaanlage, Hersteller. Zu welchem Bereich geh\u00f6ren diese W\u00f6rter?",opts:["Essen und Kochen","Reise und Transport","Umwelt und Industrie","Gesundheit und Medizin"],ans:"Umwelt und Industrie",hint:"Alle drei W\u00f6rter beziehen sich auf Natur, Produktion oder Umweltauswirkungen."},
{type:"fb",s:"Der {1} Tourist vom Flughafen ist jetzt ein richtiger Berliner.",a:["verlorene"],opts:["verlorene","verloren","verlierender","Verlierer"],hint:"Der Tourist WAR verloren. Abgeschlossene Handlung als Adjektiv. Partizip II + Adjektivendung.",sSrc:"The lost tourist from the airport is now a real Berliner."},
{type:"mc",q:"Verumius l\u00e4sst sein Fahrrad reparieren. Wer macht die eigentliche Reparatur?",opts:["Mia","Ein Mechaniker oder Fahrradladen","Verumius selbst","Niemand"],ans:"Ein Mechaniker oder Fahrradladen",hint:"Kausatives lassen bedeutet: jemand anderes f\u00fchrt die Handlung aus. Verumius organisiert es."},
{type:"tip",title:"Deutsche Umweltkultur",text:"Deutschlands Umweltbewusstsein ist tief verwurzelt.\n\nPfand: Flaschenpfand. 25 Cent f\u00fcr Plastik, 8 Cent f\u00fcr Glas. R\u00fcckgabequote: 98%.\nM\u00fclltrennung: Mindestens vier Tonnen. Nachbarn korrigieren dich.\nEnergiewende: Der Umstieg auf erneuerbare Energie. Ziel: 80% bis 2030.\nBio: Bio-Produkte haben gro\u00dfe Marktanteile. Das Bio-Siegel ist vertrauensw\u00fcrdig.\n\nWenn Mia sagt 'Du bist ein richtiger Berliner geworden,' meint sie mehr als Geografie. M\u00fcll trennen, Energie sparen, Flaschen zur\u00fcckgeben: das sind Handlungen der Zugeh\u00f6rigkeit.",deepDive:{title:"Environmental identity in Germany",text:"Germany's relationship with nature has deep cultural roots. The Romantic movement (18th-19th century) celebrated forests and landscapes. The Wandervogel youth movement (1896) promoted hiking and outdoor life.\n\nToday, this manifests as:\n- The Green Party (Die Gr\u00fcnen): part of multiple federal governments\n- Pfandsystem: 98% bottle return rate\n- Energiewende: the most ambitious energy transition in the world\n- Organic food market: largest in Europe\n\nFor immigrants, adopting environmental habits becomes a marker of cultural integration. When Mia says Verumius is a 'richtiger Berliner,' his environmental behavior is the proof."}}
]}

]},

{n:23,lang:"de",srcLang:"en",track:"v2",title:"Die Prüfung",sub:"Goethe B1 exam, irreale Bedingungssätze, brauchen+zu, double infinitive",icon:"📝",level:"B1.2",color:"#7B5EE8",lessons:[

// =============================================
// Lesson 1: Lernmaschine (Learning Machine)
// Type: Story intro (cinematic). 18 new words. 24 steps.
// =============================================
{id:"deu_r23l1",title:"Lernmaschine",icon:"📚",xp:15,board:true,steps:[
{type:"intro",title:"Lernmaschine",desc:"Verumius hat sich in eine Lernmaschine verwandelt. Sein Apartment ist voller Karteikarten, Grammatiktabellen und leerer Kaffeetassen. Die Prüfung ist in drei Tagen.",goals:["Lerne Vokabeln rund um Lernen und Studieren","Erlebe Verumius in voller Prüfungsvorbereitung","Verstehe die Struktur der Goethe-B1-Prüfung"]},
{type:"story",speaker:"narrator",mood:"determined",art:"de-ber-study-bunker",trg:"Es ist fünf Uhr morgens. Verumius sitzt an seinem Schreibtisch. Überall liegen Karteikarten, Grammatiktabellen und leere Kaffeetassen. Die Prüfung ist in drei Tagen.",src:"It is five in the morning. Verumius sits at his desk. Everywhere lie flashcards, grammar charts, and empty coffee cups. The exam is in three days."},
{type:"teach",trg:"das Wissen",src:"knowledge",pos:"noun",gender:"n",note:"Neuter noun. The nominalized form of wissen (to know).\nWissen ist Macht = Knowledge is power.",example:"A: Wie bereitest du dich auf die Prüfung vor?\nB: Ich teste mein Wissen jeden Abend mit Karteikarten.\nA: Das ist eine gute Methode.\nB: Ja, mein Wissen wird jeden Tag besser.",exampleSrc:"A: How do you prepare for the exam?\nB: I test my knowledge every evening with flashcards.\nA: That is a good method.\nB: Yes, my knowledge gets better every day.",funFact:"Das Wissen is neuter, like most nominalized infinitives in German. The phrase 'Wissen ist Macht' (Knowledge is power) is attributed to Francis Bacon and beloved in German academic culture."},
{type:"teach",trg:"die Übung",src:"exercise, practice",pos:"noun",gender:"f",note:"Feminine noun. From üben (to practice).\nÜbung macht den Meister = Practice makes the master.",example:"A: Hast du die Übungen im Buch gemacht?\nB: Ja, alle Übungen auf Seite 42.\nA: Gut. Übung macht den Meister!\nB: Das sagt mein Kursleiter auch immer.",exampleSrc:"A: Did you do the exercises in the book?\nB: Yes, all exercises on page 42.\nA: Good. Practice makes the master!\nB: My course instructor always says that too.",funFact:"The German proverb 'Übung macht den Meister' (Practice makes the master) aims higher than the English 'Practice makes perfect.' Germans strive for mastery, not mere perfection."},
{type:"teach",trg:"die Wiederholung",src:"repetition, review",pos:"noun",gender:"f",note:"Feminine noun. Wieder (again) + holen (to fetch) + -ung.\nAlso means a TV rerun.",example:"A: Sollen wir die Grammatik noch einmal wiederholen?\nB: Ja, Wiederholung ist wichtig.\nA: Welches Kapitel zuerst?\nB: Kapitel fünf. Das war schwierig.",exampleSrc:"A: Should we review the grammar once more?\nB: Yes, repetition is important.\nA: Which chapter first?\nB: Chapter five. That was difficult.",funFact:"Literally 'fetching again.' Germans say 'Wiederholung ist die Mutter des Lernens' (Repetition is the mother of learning). The same proverb exists in Russian, showing a shared educational philosophy across cultures."},
{type:"teach",trg:"die Methode",src:"method",pos:"noun",gender:"f",note:"Feminine noun. From Greek methodos (pursuit of knowledge).\nEine gute Methode = a good method.",example:"A: Welche Methode benutzt du zum Lernen?\nB: Ich schreibe alles auf Karteikarten.\nA: Das ist eine bewährte Methode.\nB: Verumius hat jede Methode ausprobiert.",exampleSrc:"A: Which method do you use for studying?\nB: I write everything on flashcards.\nA: That is a proven method.\nB: Verumius has tried every method.",funFact:"From Greek 'methodos' (pursuit of knowledge). An international word found in dozens of languages. Verumius has tried every Methode: flashcards, apps, sticky notes on the mirror, and talking to himself on the U-Bahn."},
{type:"teach",trg:"die Regel",src:"rule",pos:"noun",gender:"f",note:"Feminine noun. From Latin regula.\nIn der Regel = as a rule, usually.",example:"A: Gibt es eine Regel für Adjektivendungen?\nB: Ja, aber die Regel hat viele Ausnahmen.\nA: In der Regel benutze ich einfach mein Gefühl.\nB: Das funktioniert auch!",exampleSrc:"A: Is there a rule for adjective endings?\nB: Yes, but the rule has many exceptions.\nA: As a rule, I just use my feeling.\nB: That works too!",funFact:"From Latin 'regula.' German grammar has many Regeln (rules) but also many Ausnahmen (exceptions). The phrase 'Die Ausnahme bestätigt die Regel' (The exception confirms the rule) is used constantly in German classrooms."},
{type:"teach",trg:"das Kapitel",src:"chapter",pos:"noun",gender:"n",note:"Neuter noun. From Latin capitulum (little head).\nEin neues Kapitel aufschlagen = to open a new chapter.",example:"A: Welches Kapitel liest du gerade?\nB: Kapitel zwölf. Das letzte Kapitel.\nA: Bald bist du fertig!\nB: Ja, ein neues Kapitel beginnt nach der Prüfung.",exampleSrc:"A: Which chapter are you reading now?\nB: Chapter twelve. The last chapter.\nA: Soon you will be finished!\nB: Yes, a new chapter begins after the exam.",funFact:"From Latin 'capitulum' (little head). 'Ein neues Kapitel aufschlagen' (to open a new chapter) works literally and metaphorically. Verumius is on the final Kapitel of his B1 textbook."},
{type:"teach",trg:"der Inhalt",src:"content, contents",pos:"noun",gender:"m",note:"Masculine noun. In (in) + Halt (hold).\nInhaltsverzeichnis = table of contents.",example:"A: Was ist der Inhalt dieser Lektion?\nB: Der Inhalt ist Konjunktiv II.\nA: Ist der Inhalt schwierig?\nB: Ja, aber das Inhaltsverzeichnis hilft beim Überblick.",exampleSrc:"A: What is the content of this lesson?\nB: The content is Konjunktiv II.\nA: Is the content difficult?\nB: Yes, but the table of contents helps with the overview.",funFact:"In (in) + Halt (hold). What a container holds. The -halt root appears everywhere in German: Gehalt (salary, what a position holds), Haushalt (household, house-hold), Aufenthalt (stay, a holding-up)."},
{type:"teach",trg:"die Bedeutung",src:"meaning, significance",pos:"noun",gender:"f",note:"Feminine noun. From bedeuten (to mean).\nVon großer Bedeutung = of great significance.",example:"A: Kennst du die Bedeutung von diesem Wort?\nB: Ja, die Bedeutung ist 'Prüfung.'\nA: Richtig! Die Prüfung ist von großer Bedeutung.\nB: Das stimmt. Sie ist sehr wichtig für mich.",exampleSrc:"A: Do you know the meaning of this word?\nB: Yes, the meaning is 'exam.'\nA: Correct! The exam is of great significance.\nB: That is true. It is very important for me.",funFact:"From 'bedeuten' (to mean). 'Von großer Bedeutung' (of great significance) is a key phrase in formal German. The Goethe exam tests whether you understand Bedeutungen in context, not just isolated definitions."},
{type:"teach",trg:"der Abschnitt",src:"section, paragraph",pos:"noun",gender:"m",note:"Masculine noun. Ab (off) + Schnitt (cut).\nA piece cut off from a whole.",example:"A: Lesen Sie den ersten Abschnitt.\nB: Wie lang ist der Abschnitt?\nA: Etwa zehn Zeilen.\nB: Gut, den Abschnitt habe ich verstanden.",exampleSrc:"A: Read the first section.\nB: How long is the section?\nA: About ten lines.\nB: Good, I understood the section.",funFact:"Ab (off) + Schnitt (cut). A piece cut off from a whole. The reading part of the Goethe exam divides texts into Abschnitte. Understanding each Abschnitt separately is a key reading strategy."},
{type:"teach",trg:"die Reihenfolge",src:"sequence, order",pos:"noun",gender:"f",note:"Feminine noun. Reihe (row) + Folge (succession).\nIn der richtigen Reihenfolge = in the correct order.",example:"A: In welcher Reihenfolge soll ich lernen?\nB: Zuerst Grammatik, dann Vokabeln.\nA: Die Reihenfolge ist also wichtig?\nB: Ja, die richtige Reihenfolge spart Zeit.",exampleSrc:"A: In what order should I study?\nB: First grammar, then vocabulary.\nA: So the order is important?\nB: Yes, the right sequence saves time.",funFact:"Reihe (row) + Folge (succession). The order in which things follow in a row. A word that is itself perfectly ordered: row-succession. Exam tasks often say 'Bringen Sie die Sätze in die richtige Reihenfolge.'"},
{type:"teach",trg:"der Zusammenhang",src:"context, connection",pos:"noun",gender:"m",note:"Masculine noun. Zusammen (together) + Hang (hanging).\nIm Zusammenhang mit = in connection with.",example:"A: Verstehst du das Wort im Zusammenhang?\nB: Ja, im Zusammenhang ist es klar.\nA: Gut, der Zusammenhang hilft immer.\nB: Wörter ohne Zusammenhang sind schwer zu merken.",exampleSrc:"A: Do you understand the word in context?\nB: Yes, in context it is clear.\nA: Good, context always helps.\nB: Words without context are hard to remember.",funFact:"Zusammen (together) + Hang (hanging). Things that hang together. The Goethe exam tests whether you understand words im Zusammenhang (in context), not in isolation. A deep principle of language learning."},
{type:"teach",trg:"konzentrieren",src:"to concentrate",pos:"verb",gender:null,note:"Reflexive: sich konzentrieren.\nIch kann mich nicht konzentrieren = I cannot concentrate.",example:"A: Kannst du dich hier konzentrieren?\nB: Nein, es ist zu laut. Ich kann mich nicht konzentrieren.\nA: Versuch es mit Musik.\nB: Gute Idee. Damit kann ich mich besser konzentrieren.",exampleSrc:"A: Can you concentrate here?\nB: No, it is too loud. I cannot concentrate.\nA: Try it with music.\nB: Good idea. With that I can concentrate better.",funFact:"From Latin 'concentrare' (to bring to a center). Reflexive in German: sich konzentrieren. 'Ich kann mich nicht konzentrieren' is what Verumius mutters at 5 AM after his fourth coffee."},
{type:"teach",trg:"verbessern",src:"to improve, to correct",pos:"verb",gender:null,note:"Ver- + besser (better). To make better.\nFehler verbessern = to correct mistakes.",example:"A: Wie kann ich mein Deutsch verbessern?\nB: Übe jeden Tag und verbessere deine Fehler.\nA: Kann ich mich wirklich verbessern?\nB: Ja, du hast dich schon viel verbessert!",exampleSrc:"A: How can I improve my German?\nB: Practice every day and correct your mistakes.\nA: Can I really improve?\nB: Yes, you have already improved a lot!",funFact:"Ver- + besser (better). To make something better. 'Fehler verbessern' (to correct mistakes) and 'sich verbessern' (to improve oneself). The whole point of exam preparation in a single word."},
{type:"teach",trg:"behalten",src:"to keep, to retain, to remember",pos:"verb",gender:null,note:"Be- + halten (to hold). Irregular: behält, behielt, behalten.\nVokabeln behalten = to retain vocabulary.",example:"A: Kannst du dir die neuen Wörter behalten?\nB: Manche kann ich gut behalten.\nA: Und die anderen?\nB: Die kann ich mir nicht behalten. Ich vergesse sie immer.",exampleSrc:"A: Can you remember the new words?\nB: Some I can remember well.\nA: And the others?\nB: I cannot remember those. I always forget them.",funFact:"Be- + halten (to hold). To hold something in your mind. 'Das kann ich mir nicht behalten' (I cannot remember that) is the lament of every language learner. The verb every student wishes worked better."},
{type:"teach",trg:"erkennen",src:"to recognize, to realize",pos:"verb",gender:null,note:"Er- + kennen (to know). Irregular: erkennt, erkannte, erkannt.\nDifferent from kennen (to be acquainted with).",example:"A: Erkennst du das Muster in der Grammatik?\nB: Ja, ich erkenne es jetzt!\nA: Gut. Wenn man das Muster erkennt, wird alles leichter.\nB: Stimmt, jetzt erkenne ich die Logik.",exampleSrc:"A: Do you recognize the pattern in the grammar?\nB: Yes, I recognize it now!\nA: Good. When you recognize the pattern, everything becomes easier.\nB: True, now I recognize the logic.",funFact:"Er- + kennen (to know). The flash of recognition. Different from 'kennen' (to be acquainted with). Erkennen is the moment you see and understand, the lightbulb moment every learner lives for."},
{type:"teach",trg:"regelmäßig",src:"regular, regularly",pos:"adj",gender:null,note:"Regel (rule) + mäßig (measured).\nRegelmäßig üben = to practice regularly.",example:"A: Wie oft übst du Deutsch?\nB: Ich übe regelmäßig, jeden Tag eine Stunde.\nA: Das ist gut. Regelmäßiges Üben ist wichtig.\nB: Ja, Verumius lernt seit Monaten regelmäßig.",exampleSrc:"A: How often do you practice German?\nB: I practice regularly, one hour every day.\nA: That is good. Regular practice is important.\nB: Yes, Verumius has been studying regularly for months.",funFact:"Regel (rule) + mäßig (measured). Following rules in a measured way. Germans value Regelmäßigkeit (regularity) as a cultural trait. Being regelmäßig at something is considered a virtue."},
{type:"teach",trg:"gründlich",src:"thorough, thoroughly",pos:"adj",gender:null,note:"From Grund (ground/reason). Getting to the bottom.\nGründlich lernen = to study thoroughly.",example:"A: Hast du das Kapitel gründlich gelesen?\nB: Ja, sehr gründlich. Jede Zeile.\nA: Gründliches Lernen zahlt sich aus.\nB: Das hoffe ich. Die Prüfung ist in drei Tagen.",exampleSrc:"A: Did you read the chapter thoroughly?\nB: Yes, very thoroughly. Every line.\nA: Thorough studying pays off.\nB: I hope so. The exam is in three days.",funFact:"From Grund (ground/reason). Getting to the bottom of things. Germans value Gründlichkeit (thoroughness) as a cultural trait. 'Gründlich' is high praise in a German workplace."},
{type:"teach",trg:"ziemlich",src:"quite, fairly",pos:"adj",gender:null,note:"From ziemen (to be proper). Softens statements.\nZiemlich gut = quite good. Ziemlich müde = fairly tired.",example:"A: Wie war die Übung?\nB: Ziemlich schwierig.\nA: Bist du müde?\nB: Ja, ziemlich müde. Aber ich mache weiter.",exampleSrc:"A: How was the exercise?\nB: Quite difficult.\nA: Are you tired?\nB: Yes, fairly tired. But I keep going.",funFact:"From 'ziemen' (to be proper/fitting). Originally meant 'fittingly,' now softens statements. The most diplomatic German intensifier. 'Ziemlich gut' lands exactly between 'gut' and 'sehr gut.'"},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-ber-study-dawn",trg:"Wenn Verumius mehr geschlafen hätte, wäre er jetzt weniger müde. Aber er braucht jede Minute. Die Prüfung wartet nicht.",src:"If Verumius had slept more, he would be less tired now. But he needs every minute. The exam does not wait."},
{type:"mc",q:"Verumius wiederholt seine Karteikarten jeden Abend. Welches Wort beschreibt diese regelmäßige Aktivität?",opts:["Zusammenhang","Wiederholung","Bedeutung","Abschnitt"],ans:"Wiederholung",hint:"Das Wort bedeutet, etwas noch einmal zu tun. Von wieder (again) und holen (to fetch)."},
{type:"fb",s:"Um Vokabeln zu {1}, muss man regelmäßig üben.",a:["behalten"],opts:["behalten","erkennen","konzentrieren","verbessern"],hint:"Which verb means to keep something in your memory?",sSrc:"To retain vocabulary, one must practice regularly."},
{type:"match",pairs:[{trg:"Methode",src:"method"},{trg:"Regel",src:"rule"},{trg:"Kapitel",src:"chapter"},{trg:"Reihenfolge",src:"sequence"}]}
]},

// =============================================
// Lesson 2: Werkzeuge des Lernens (Tools of Learning)
// Type: Vocab teach 1 (bubble). 20 new words. 24 steps.
// =============================================
{id:"deu_r23l2",title:"Werkzeuge des Lernens",icon:"📖",xp:15,board:true,steps:[
{type:"intro",title:"Werkzeuge des Lernens",desc:"Dictionaries, texts, graphics: the tools of a language learner. Learn vocabulary for books, texts, and reference works.",goals:["Learn vocabulary for books, texts, and reference works","Describe the structure of texts","Build your academic German toolkit"]},
{type:"teach",trg:"das Wörterbuch",src:"dictionary",pos:"noun",gender:"n",note:"Neuter noun. Wörter (words) + Buch (book).\nA book of words.",example:"A: Ich verstehe dieses Wort nicht.\nB: Schlag es im Wörterbuch nach.\nA: Welches Wörterbuch empfiehlst du?\nB: Den Duden. Das ist das beste deutsche Wörterbuch.",exampleSrc:"A: I do not understand this word.\nB: Look it up in the dictionary.\nA: Which dictionary do you recommend?\nB: The Duden. That is the best German dictionary.",funFact:"Wörter (words) + Buch (book). A book of words. The Duden is Germany's most famous Wörterbuch, first published in 1880. Verumius has worn his Deutsch-Englisch Wörterbuch thin."},
{type:"teach",trg:"das Lexikon",src:"encyclopedia, reference work",pos:"noun",gender:"n",note:"Neuter noun. From Greek lexikon (of words).\nBroader than a Wörterbuch: explains concepts.",example:"A: Was ist der Unterschied zwischen Wörterbuch und Lexikon?\nB: Ein Lexikon erklärt Konzepte, nicht nur Definitionen.\nA: Also wie eine Enzyklopädie?\nB: Genau. Das große Lexikon steht in jeder Bibliothek.",exampleSrc:"A: What is the difference between a dictionary and an encyclopedia?\nB: An encyclopedia explains concepts, not just definitions.\nA: So like an encyclopedia?\nB: Exactly. The large encyclopedia stands in every library.",funFact:"From Greek 'lexikon' (of words). Broader than a Wörterbuch: a Lexikon explains concepts, not just definitions. 'Das große Lexikon' has traditionally sat on every German bookshelf."},
{type:"teach",trg:"die Überschrift",src:"headline, title",pos:"noun",gender:"f",note:"Feminine noun. Über (over/above) + Schrift (writing).\nThe writing above: a headline.",example:"A: Lesen Sie zuerst die Überschrift.\nB: Die Überschrift sagt: 'Bildung in Deutschland.'\nA: Gut. Die Überschrift verrät oft das Thema.\nB: Das ist ein guter Prüfungstipp!",exampleSrc:"A: Read the headline first.\nB: The headline says: 'Education in Germany.'\nA: Good. The headline often reveals the topic.\nB: That is a good exam tip!",funFact:"Über (over/above) + Schrift (writing). The writing above a text. Exam tip: the Überschrift often reveals the topic before you read the text. Always read it first."},
{type:"teach",trg:"die Zeile",src:"line (of text)",pos:"noun",gender:"f",note:"Feminine noun. From Latin titulus via Old High German.\nZwischen den Zeilen lesen = to read between the lines.",example:"A: In welcher Zeile steht die Antwort?\nB: In Zeile sieben.\nA: Man muss zwischen den Zeilen lesen.\nB: Stimmt, nicht alles steht direkt in den Zeilen.",exampleSrc:"A: In which line is the answer?\nB: In line seven.\nA: One must read between the lines.\nB: True, not everything is directly in the lines.",funFact:"The Goethe exam often asks 'In welcher Zeile steht...?' (In which line does it say...?). 'Zwischen den Zeilen lesen' (to read between the lines) is a universal metaphor."},
{type:"teach",trg:"die Grafik",src:"graphic, chart",pos:"noun",gender:"f",note:"Feminine noun. From Greek graphike (the art of drawing).\nEine Grafik beschreiben = to describe a chart.",example:"A: Beschreiben Sie die Grafik.\nB: Die Grafik zeigt die Entwicklung seit 2020.\nA: Welche Informationen enthält die Grafik?\nB: Zahlen, Prozente und einen Trend.",exampleSrc:"A: Describe the chart.\nB: The chart shows the development since 2020.\nA: What information does the chart contain?\nB: Numbers, percentages, and a trend.",funFact:"From Greek 'graphike' (the art of drawing). 'Eine Grafik beschreiben' (to describe a chart) is a standard B1 writing task. Pie charts, bar graphs, line charts: all Grafiken."},
{type:"teach",trg:"die Abbildung",src:"illustration, figure",pos:"noun",gender:"f",note:"Feminine noun. Ab (from) + Bild (picture) + -ung.\nAbbreviated Abb. in textbooks.",example:"A: Siehe Abbildung drei auf Seite zehn.\nB: Die Abbildung zeigt eine Landkarte.\nA: Beschreiben Sie die Abbildung.\nB: Die Abbildung ist eine Karte von Deutschland.",exampleSrc:"A: See Figure three on page ten.\nB: The illustration shows a map.\nA: Describe the illustration.\nB: The illustration is a map of Germany.",funFact:"Ab (from) + Bild (picture) + -ung. A depiction or figure. Abbreviated 'Abb.' in textbooks. Every German academic paper is full of Abbildungen. 'Siehe Abb. 3' is the standard reference format."},
{type:"teach",trg:"die Darstellung",src:"representation, presentation",pos:"noun",gender:"f",note:"Feminine noun. Dar (forth) + stellen (to place) + -ung.\nBroader than Abbildung: visual, verbal, or mathematical.",example:"A: Die Darstellung der Daten ist sehr klar.\nB: Ja, die grafische Darstellung hilft.\nA: Können Sie eine andere Darstellung wählen?\nB: Natürlich. Tabelle oder Diagramm?",exampleSrc:"A: The representation of the data is very clear.\nB: Yes, the graphical representation helps.\nA: Can you choose a different representation?\nB: Of course. Table or diagram?",funFact:"Dar (there/forth) + stellen (to place) + -ung. A representation or presentation. Broader than Abbildung: can be visual, verbal, or mathematical. Academic German loves this word."},
{type:"teach",trg:"die Broschüre",src:"brochure, pamphlet",pos:"noun",gender:"f",note:"Feminine noun. From French brochure (stitched).\nInformationsbroschüre = information brochure.",example:"A: Haben Sie eine Broschüre über den Kurs?\nB: Ja, hier ist unsere Broschüre.\nA: Danke. Steht der Preis in der Broschüre?\nB: Ja, auf der letzten Seite.",exampleSrc:"A: Do you have a brochure about the course?\nB: Yes, here is our brochure.\nA: Thanks. Is the price in the brochure?\nB: Yes, on the last page.",funFact:"From French 'brochure' (stitched). Verumius has collected Broschüren from every language school in Berlin. The Goethe-Institut's Broschüre was the one that convinced him."},
{type:"teach",trg:"das Detail",src:"detail",pos:"noun",gender:"n",note:"Neuter noun. From French detail (a cutting).\nIm Detail = in detail. Auf Details achten = to pay attention to details.",example:"A: Achten Sie auf die Details im Text.\nB: Welches Detail ist wichtig?\nA: Jedes Detail kann in der Prüfung vorkommen.\nB: Gut, dann lese ich im Detail.",exampleSrc:"A: Pay attention to the details in the text.\nB: Which detail is important?\nA: Every detail can come up in the exam.\nB: Good, then I will read in detail.",funFact:"From French 'détail' (a cutting). 'Im Detail' (in detail). 'Auf Details achten' (to pay attention to details). The Goethe exam rewards those who read the Details carefully."},
{type:"teach",trg:"der Punkt",src:"point, period, dot",pos:"noun",gender:"m",note:"Masculine noun. From Latin punctum.\nAuf den Punkt kommen = to get to the point.",example:"A: Was ist der wichtigste Punkt?\nB: Der erste Punkt ist die Grammatik.\nA: Punkt für Punkt verstehe ich mehr.\nB: Gut, kommen wir zum nächsten Punkt.",exampleSrc:"A: What is the most important point?\nB: The first point is the grammar.\nA: Point by point, I understand more.\nB: Good, let us move to the next point.",funFact:"From Latin 'punctum.' Multi-purpose: a point in an argument, the period at the end of a sentence, and a dot. 'Auf den Punkt kommen' (to get to the point) is prized in German communication."},
{type:"teach",trg:"die Aussprache",src:"pronunciation",pos:"noun",gender:"f",note:"Feminine noun. Aus (out) + Sprache (speech).\nHow words come out of your mouth.",example:"A: Wie ist meine Aussprache?\nB: Deine Aussprache ist sehr gut.\nA: Die deutsche Aussprache ist schwierig.\nB: Übung hilft. Die Aussprache wird besser mit der Zeit.",exampleSrc:"A: How is my pronunciation?\nB: Your pronunciation is very good.\nA: German pronunciation is difficult.\nB: Practice helps. Pronunciation gets better with time.",funFact:"Aus (out) + Sprache (speech). How words come out of your mouth. The Sprechen section of the Goethe exam evaluates your Aussprache. Clear Aussprache is worth more points than complex vocabulary."},
{type:"teach",trg:"das Alphabet",src:"alphabet",pos:"noun",gender:"n",note:"Neuter noun. From Greek alpha + beta.\nThe German alphabet has 30 letters: 26 + ä, ö, ü, ß.",example:"A: Wie viele Buchstaben hat das deutsche Alphabet?\nB: Dreißig: sechsundzwanzig plus ä, ö, ü und ß.\nA: Das Alphabet ist fast wie das englische.\nB: Ja, aber die Aussprache ist anders!",exampleSrc:"A: How many letters does the German alphabet have?\nB: Thirty: twenty-six plus ä, ö, ü, and ß.\nA: The alphabet is almost like the English one.\nB: Yes, but the pronunciation is different!",funFact:"From Greek alpha + beta (first two letters). The German alphabet has 30 letters: 26 standard plus ä, ö, ü, and ß. The Eszett (ß) is unique to German."},
{type:"teach",trg:"der Ausdruck",src:"expression, printout",pos:"noun",gender:"m",note:"Masculine noun. Aus (out) + Druck (press).\nAlso means printout (pressed out of a printer).",example:"A: Was bedeutet dieser Ausdruck?\nB: Der Ausdruck bedeutet 'in Ordnung.'\nA: Idomatische Ausdrücke sind schwer.\nB: Ja, aber wichtig für die Prüfung.",exampleSrc:"A: What does this expression mean?\nB: The expression means 'in order.'\nA: Idiomatic expressions are hard.\nB: Yes, but important for the exam.",funFact:"Aus (out) + Druck (press). Expression. Also means 'printout' (something pressed out of a printer). Context decides which meaning. The Goethe exam loves testing idiomatic Ausdrücke."},
{type:"teach",trg:"die Beschreibung",src:"description",pos:"noun",gender:"f",note:"Feminine noun. From beschreiben (to describe).\nBildbeschreibung = picture description.",example:"A: Schreiben Sie eine Beschreibung der Grafik.\nB: Die Beschreibung soll kurz sein?\nA: Ja, eine kurze, klare Beschreibung.\nB: Gut, eine Beschreibung in fünf Sätzen.",exampleSrc:"A: Write a description of the chart.\nB: The description should be short?\nA: Yes, a short, clear description.\nB: Good, a description in five sentences.",funFact:"From 'beschreiben' (to describe). Be- + schreiben (to write). 'Bildbeschreibung' (picture description) is a classic exam task. Describe what you see, systematically, from general to specific."},
{type:"teach",trg:"die Erklärung",src:"explanation, declaration",pos:"noun",gender:"f",note:"Feminine noun. From erklären (to explain).\nAlso: declaration (Liebeserklärung = declaration of love).",example:"A: Können Sie mir eine Erklärung geben?\nB: Natürlich. Hier ist meine Erklärung.\nA: Die Erklärung ist sehr hilfreich.\nB: Gut, fragen Sie, wenn Sie eine weitere Erklärung brauchen.",exampleSrc:"A: Can you give me an explanation?\nB: Of course. Here is my explanation.\nA: The explanation is very helpful.\nB: Good, ask if you need another explanation.",funFact:"From 'erklären' (to explain). Also means 'declaration' (Liebeserklärung = declaration of love). Both meanings share the root idea: making something clear to someone."},
{type:"teach",trg:"die Einzelheit",src:"detail, particular",pos:"noun",gender:"f",note:"Feminine noun. Einzel (single) + -heit.\nAlle Einzelheiten = all the details. More formal than Detail.",example:"A: Erzählen Sie mir alle Einzelheiten.\nB: Die Einzelheiten stehen im Bericht.\nA: Jede Einzelheit ist wichtig.\nB: Gut, dann gehe ich auf jede Einzelheit ein.",exampleSrc:"A: Tell me all the details.\nB: The details are in the report.\nA: Every detail is important.\nB: Good, then I will address every detail.",funFact:"Einzel (single/individual) + -heit. A single detail, a particular. More formal than 'Detail.' Official documents and exam texts prefer Einzelheit. You will find both in the Goethe exam."},
{type:"teach",trg:"der Hinweis",src:"hint, note, reference",pos:"noun",gender:"m",note:"Masculine noun. Hin (toward) + Weis (pointing).\nWichtiger Hinweis = important notice.",example:"A: Lesen Sie den Hinweis auf Seite eins.\nB: Der Hinweis sagt: 'Sie haben 60 Minuten.'\nA: Danke für den Hinweis!\nB: Kein Problem. Achten Sie immer auf die Hinweise.",exampleSrc:"A: Read the note on page one.\nB: The note says: 'You have 60 minutes.'\nA: Thanks for the hint!\nB: No problem. Always pay attention to the notes.",funFact:"Hin (toward) + Weis (pointing). Something that points you in a direction. Exam papers always begin with Hinweise (instructions). 'Hinweis: Sie haben 60 Minuten Zeit.'"},
{type:"teach",trg:"aufschreiben",src:"to write down",pos:"verb",gender:null,note:"Separable: auf + schreiben. Ich schreibe es auf.\nSchreib das auf! = Write that down!",example:"A: Schreib dir die neuen Wörter auf!\nB: Ich schreibe alles auf.\nA: Hast du es aufgeschrieben?\nB: Ja, ich habe jedes Wort aufgeschrieben.",exampleSrc:"A: Write down the new words!\nB: I write everything down.\nA: Did you write it down?\nB: Yes, I wrote down every word.",funFact:"Auf (up/on) + schreiben (to write). Separable: 'Ich schreibe es auf.' Verumius has aufgeschrieben every new word for a year. His notebooks fill an entire shelf."},
{type:"teach",trg:"nachschlagen",src:"to look up (in a reference)",pos:"verb",gender:null,note:"Separable: nach + schlagen. Ich schlage es nach.\nEin Wort nachschlagen = to look up a word.",example:"A: Ich kenne dieses Wort nicht.\nB: Schlag es im Wörterbuch nach.\nA: Muss ich jedes Wort nachschlagen?\nB: Nein, nur die wichtigen. Den Rest errätst du aus dem Zusammenhang.",exampleSrc:"A: I do not know this word.\nB: Look it up in the dictionary.\nA: Do I have to look up every word?\nB: No, only the important ones. The rest you guess from context.",funFact:"Nach (after/to look up) + schlagen (to hit/strike). Originally meant to strike the pages of a book open. Now simply means to look something up. Separable: 'Ich schlage es nach.'"},
{type:"teach",trg:"markieren",src:"to mark, to highlight",pos:"verb",gender:null,note:"From French marquer. Regular verb.\nWichtige Stellen markieren = to highlight important passages.",example:"A: Markiere die wichtigen Wörter im Text.\nB: Soll ich alles markieren?\nA: Nein, nur die Schlüsselwörter.\nB: Gut, ich markiere nur die Schlüsselwörter.",exampleSrc:"A: Highlight the important words in the text.\nB: Should I highlight everything?\nA: No, only the key words.\nB: Good, I will only highlight the key words.",funFact:"From French 'marquer.' 'Wichtige Stellen markieren' (to highlight important passages). Verumius's textbook is more yellow from highlighting than white. A true B1 learner's book."},
{type:"mc",q:"Verumius braucht die Bedeutung eines unbekannten Wortes. Welches Werkzeug benutzt er?",opts:["Wörterbuch","Überschrift","Broschüre","Grafik"],ans:"Wörterbuch",hint:"Ein Buch der Wörter, in dem Bedeutungen und Übersetzungen stehen."},
{type:"fb",s:"Lesen Sie zuerst die {1}, bevor Sie den ganzen Text lesen.",a:["Überschrift"],opts:["Überschrift","Zeile","Einzelheit","Punkt"],hint:"Exam strategy: read the writing above the text first.",sSrc:"Read the headline first before you read the whole text."},
{type:"match",pairs:[{trg:"Hinweis",src:"hint/note"},{trg:"Ausdruck",src:"expression"},{trg:"Beschreibung",src:"description"},{trg:"Erklärung",src:"explanation"}]}
]},

// =============================================
// Lesson 3: Vor der Prüfung (Before the Exam)
// Type: Vocab teach 2 (bubble). 20 new words. 24 steps.
// =============================================
{id:"deu_r23l3",title:"Vor der Prüfung",icon:"🏫",xp:15,board:true,steps:[
{type:"intro",title:"Vor der Prüfung",desc:"Courses, exams, classroom roles: the vocabulary of education. Learn how to talk about school and university.",goals:["Learn vocabulary for education, courses, and academic life","Know the people in the classroom","Prepare for the Goethe exam format"]},
{type:"teach",trg:"das Institut",src:"institute",pos:"noun",gender:"n",note:"Neuter noun. From Latin institutum (establishment).\nGoethe-Institut: Germany's worldwide cultural institute.",example:"A: Wo machst du die Prüfung?\nB: Am Goethe-Institut in Berlin.\nA: Das Institut ist sehr bekannt.\nB: Ja, das Goethe-Institut gibt es in 98 Ländern.",exampleSrc:"A: Where are you taking the exam?\nB: At the Goethe-Institut in Berlin.\nA: The institute is very well known.\nB: Yes, the Goethe-Institut exists in 98 countries.",funFact:"From Latin 'institutum' (establishment). The Goethe-Institut is Germany's worldwide cultural institute, present in 98 countries. It promotes German language and cultural exchange. Where Verumius will sit his exam."},
{type:"teach",trg:"der Intensivkurs",src:"intensive course",pos:"noun",gender:"m",note:"Masculine noun. Intensiv + Kurs.\nTypically 20-25 hours per week.",example:"A: Hast du einen Intensivkurs gemacht?\nB: Ja, einen Deutsch-Intensivkurs im ersten Monat.\nA: Wie viele Stunden pro Woche?\nB: Zwanzig Stunden. Es war anstrengend, aber gut.",exampleSrc:"A: Did you take an intensive course?\nB: Yes, a German intensive course in the first month.\nA: How many hours per week?\nB: Twenty hours. It was exhausting, but good.",funFact:"Intensiv (intensive) + Kurs (course). Typically 20-25 hours per week. Verumius took one in his first month in Berlin. The fastest way to build a language foundation."},
{type:"teach",trg:"das Semester",src:"semester",pos:"noun",gender:"n",note:"Neuter noun. From Latin semestris (six-monthly).\nWintersemester (Oct-Mar), Sommersemester (Apr-Sep).",example:"A: In welchem Semester bist du?\nB: Im dritten Semester.\nA: Das Semester ist bald zu Ende.\nB: Ja, nur noch zwei Wochen bis zur Prüfung.",exampleSrc:"A: Which semester are you in?\nB: In the third semester.\nA: The semester is almost over.\nB: Yes, only two more weeks until the exam.",funFact:"From Latin 'semestris' (six-monthly). German universities run on Wintersemester (October-March) and Sommersemester (April-September). Borrowed into English for the same concept."},
{type:"teach",trg:"das Seminar",src:"seminar",pos:"noun",gender:"n",note:"Neuter noun. From Latin seminarium (seed bed).\nMore interactive than a Vorlesung (lecture).",example:"A: Warst du im Seminar?\nB: Ja, das Seminar war sehr interessant.\nA: Was habt ihr im Seminar besprochen?\nB: Wir haben im Seminar über Sprachpolitik diskutiert.",exampleSrc:"A: Were you at the seminar?\nB: Yes, the seminar was very interesting.\nA: What did you discuss in the seminar?\nB: We discussed language policy in the seminar.",funFact:"From Latin 'seminarium' (seed bed). A smaller, discussion-based class. More interactive than a Vorlesung (lecture). Ideas grow like seeds in a Seminar."},
{type:"teach",trg:"die Klassenarbeit",src:"class test, written test",pos:"noun",gender:"f",note:"Feminine noun. Klasse (class) + Arbeit (work).\nA written test in school.",example:"A: Morgen schreiben wir eine Klassenarbeit.\nB: In welchem Fach?\nA: In Deutsch. Die Klassenarbeit ist über Grammatik.\nB: Dann muss ich heute noch lernen.",exampleSrc:"A: Tomorrow we are writing a class test.\nB: In which subject?\nA: In German. The class test is about grammar.\nB: Then I have to study today.",funFact:"Klasse (class) + Arbeit (work). 'Morgen schreiben wir eine Klassenarbeit' makes every German student nervous. More formal than a Quiz, less than an Examen."},
{type:"teach",trg:"die Schularbeit",src:"homework, school test",pos:"noun",gender:"f",note:"Feminine noun. Schule (school) + Arbeit (work).\nMeaning varies by region: homework or formal test.",example:"A: Hast du deine Schularbeit gemacht?\nB: Ja, die Schularbeit ist fertig.\nA: Was für eine Schularbeit war das?\nB: Eine Mathematik-Schularbeit. Ziemlich schwierig.",exampleSrc:"A: Did you do your homework?\nB: Yes, the homework is done.\nA: What kind of homework was it?\nB: A mathematics assignment. Quite difficult.",funFact:"Schule (school) + Arbeit (work). In Austria, Schularbeit means a formal written exam. In Germany, it often means homework. Regional German at work: same word, different meanings."},
{type:"teach",trg:"die Nachhilfe",src:"tutoring",pos:"noun",gender:"f",note:"Feminine noun. Nach (after) + Hilfe (help). Extra help.\nNachhilfe geben = to give tutoring.",example:"A: Brauchst du Nachhilfe in Deutsch?\nB: Ja, ich nehme seit einem Monat Nachhilfe.\nA: Wer gibt dir Nachhilfe?\nB: Eine Studentin. Sie ist sehr geduldig.",exampleSrc:"A: Do you need tutoring in German?\nB: Yes, I have been taking tutoring for a month.\nA: Who gives you tutoring?\nB: A female student. She is very patient.",funFact:"Nach (after) + Hilfe (help). Extra tutoring after regular class. A massive industry in Germany: roughly one in four students receives Nachhilfe. It is considered normal, not shameful."},
{type:"teach",trg:"das Referat",src:"presentation, oral report",pos:"noun",gender:"n",note:"Neuter noun. From Latin referre (to report).\nEin Referat halten = to give a presentation.",example:"A: Wann hältst du dein Referat?\nB: Mein Referat ist nächste Woche.\nA: Worüber ist das Referat?\nB: Das Referat ist über das deutsche Bildungssystem.",exampleSrc:"A: When are you giving your presentation?\nB: My presentation is next week.\nA: What is the presentation about?\nB: The presentation is about the German education system.",funFact:"From Latin 'referre' (to report). Standard in German schools and universities. You research, write, and present. 'Ein Referat halten' (to give a presentation) is a skill every German student must master."},
{type:"teach",trg:"die Präsentation",src:"presentation",pos:"noun",gender:"f",note:"Feminine noun. From Latin praesentare.\nMore modern than Referat.",example:"A: Deine Präsentation war toll!\nB: Danke. Die Präsentation hat viel Arbeit gekostet.\nA: Wie lange hat die Präsentation gedauert?\nB: Etwa fünfzehn Minuten. Wie im Goethe-Sprechen.",exampleSrc:"A: Your presentation was great!\nB: Thanks. The presentation took a lot of work.\nA: How long did the presentation last?\nB: About fifteen minutes. Like in the Goethe speaking section.",funFact:"From Latin 'praesentare.' More modern than Referat. The Goethe B1 Sprechen section is essentially a mini-Präsentation: you present a topic to the group in a structured way."},
{type:"teach",trg:"die Studie",src:"study (scientific)",pos:"noun",gender:"f",note:"Feminine noun. From Latin studium.\nDifferent from Studium (university studies).",example:"A: Laut einer Studie lernen Kinder schneller.\nB: Was sagt die Studie genau?\nA: Die Studie zeigt, dass Kinder vor dem 7. Lebensjahr am schnellsten lernen.\nB: Interessant. Ich hätte als Kind anfangen sollen!",exampleSrc:"A: According to a study, children learn faster.\nB: What does the study say exactly?\nA: The study shows that children learn fastest before age 7.\nB: Interesting. I should have started as a child!",funFact:"From Latin 'studium.' Different from 'Studium' (university studies, what you DO). A Studie is a research project (what scientists DO). 'Laut einer Studie' (according to a study) is a phrase you hear daily in German news."},
{type:"teach",trg:"die Studierende",src:"student (gender-neutral)",pos:"noun",gender:"f",note:"Feminine/plural form. From studieren.\nThe modern gender-neutral form replacing Student/Studentin.",example:"A: Wie viele Studierende sind im Kurs?\nB: Etwa zwanzig Studierende.\nA: Sind alle Studierende aus Deutschland?\nB: Nein, die Studierende kommen aus aller Welt.",exampleSrc:"A: How many students are in the course?\nB: About twenty students.\nA: Are all students from Germany?\nB: No, the students come from all over the world.",funFact:"The gender-neutral modern form. From 'studieren.' Replacing 'Student/Studentin' in official German. Universities now write 'Liebe Studierende' (Dear students) to be inclusive."},
{type:"teach",trg:"die Teilnahme",src:"participation",pos:"noun",gender:"f",note:"Feminine noun. Teil (part) + Nahme (taking).\nTeilnahmebescheinigung = certificate of attendance.",example:"A: Ist die Teilnahme am Kurs Pflicht?\nB: Ja, die Teilnahme ist obligatorisch.\nA: Bekomme ich eine Teilnahmebescheinigung?\nB: Ja, nach dem Kurs gibt es eine Bescheinigung.",exampleSrc:"A: Is participation in the course mandatory?\nB: Yes, participation is obligatory.\nA: Do I get a certificate of attendance?\nB: Yes, after the course there is a certificate.",funFact:"Teil (part) + Nahme (taking). You need a Teilnahmebescheinigung (certificate of attendance) to register for the Goethe exam. Participation must be documented."},
{type:"teach",trg:"der Teilnehmer",src:"participant (male)",pos:"noun",gender:"m",note:"Masculine noun. Teil + nehmen + -er.\nOne who takes part.",example:"A: Wie viele Teilnehmer sind in der Prüfung?\nB: Etwa zwanzig Teilnehmer pro Sitzung.\nA: Kennen sich die Teilnehmer?\nB: Nein, die meisten Teilnehmer kennen sich nicht.",exampleSrc:"A: How many participants are in the exam?\nB: About twenty participants per session.\nA: Do the participants know each other?\nB: No, most participants do not know each other.",funFact:"Teil (part) + nehmen (to take) + -er (agent suffix). One who takes part. The Goethe exam room has about 20 Teilnehmer per session, each with their own story and reason for being there."},
{type:"teach",trg:"die Teilnehmerin",src:"participant (female)",pos:"noun",gender:"f",note:"Feminine noun. Teilnehmer + -in.\nModern alternative: Teilnehmende (gender-neutral).",example:"A: Die Teilnehmerin neben mir war sehr nett.\nB: Woher kam die Teilnehmerin?\nA: Aus der Türkei. Alle Teilnehmerinnen waren freundlich.\nB: Das ist schön. Prüfungsangst verbindet.",exampleSrc:"A: The participant next to me was very nice.\nB: Where was the participant from?\nA: From Turkey. All female participants were friendly.\nB: That is nice. Exam anxiety unites people.",funFact:"The feminine form. Modern German often uses 'Teilnehmende' as a gender-neutral alternative. Official Goethe-Institut documents use 'Teilnehmerinnen und Teilnehmer' for full inclusivity."},
{type:"teach",trg:"der Professor",src:"professor",pos:"noun",gender:"m",note:"Masculine noun. From Latin professor (public teacher).\nIn Germany, an earned title used on nameplates and business cards.",example:"A: Wer hat den Kurs unterrichtet?\nB: Professor Müller.\nA: Ist er ein guter Professor?\nB: Ja, der Professor erklärt alles sehr klar.",exampleSrc:"A: Who taught the course?\nB: Professor Müller.\nA: Is he a good professor?\nB: Yes, the professor explains everything very clearly.",funFact:"In Germany, Professor is an earned title, not just a job description. 'Herr Professor Müller' is the correct address. The title appears on business cards, nameplates, and even doorbells."},
{type:"teach",trg:"die Professorin",src:"professor (female)",pos:"noun",gender:"f",note:"Feminine noun. Professor + -in.\nOnly about 27% of German professors are women.",example:"A: Die Professorin hält heute die Vorlesung.\nB: Frau Professorin Schmidt ist sehr beliebt.\nA: Ja, die Professorin erklärt schwierige Themen einfach.\nB: Das ist eine wichtige Fähigkeit.",exampleSrc:"A: The professor is giving the lecture today.\nB: Professor Schmidt is very popular.\nA: Yes, the professor explains difficult topics simply.\nB: That is an important ability.",funFact:"The feminine form. Only about 27% of German professors are women (as of recent statistics). The gap is closing, but slowly. 'Frau Professorin Schmidt' is the correct formal address."},
{type:"teach",trg:"der Kursleiter",src:"course instructor (male)",pos:"noun",gender:"m",note:"Masculine noun. Kurs (course) + Leiter (leader).\nCourse instructor at a language school.",example:"A: Wer ist euer Kursleiter?\nB: Herr Becker ist unser Kursleiter.\nA: Ist der Kursleiter streng?\nB: Ja, aber fair. Ein guter Kursleiter.",exampleSrc:"A: Who is your course instructor?\nB: Mr. Becker is our course instructor.\nA: Is the course instructor strict?\nB: Yes, but fair. A good course instructor.",funFact:"Kurs (course) + Leiter (leader). The person who leads your language course. Verumius's Kursleiter at the Goethe-Institut is strict but fair, the kind who pushes students to their best."},
{type:"teach",trg:"die Kursleiterin",src:"course instructor (female)",pos:"noun",gender:"f",note:"Feminine noun. Kursleiter + -in.\nDie Kursleiterin gibt die Prüfungstermine bekannt.",example:"A: Die Kursleiterin hat die Termine bekanntgegeben.\nB: Wann ist der nächste Termin?\nA: Die Kursleiterin sagt: nächsten Freitag.\nB: Gut, dann muss ich bis Freitag fertig sein.",exampleSrc:"A: The course instructor announced the dates.\nB: When is the next date?\nA: The course instructor says: next Friday.\nB: Good, then I have to be finished by Friday.",funFact:"The feminine form. -in suffix, as always for feminine person nouns in German. 'Die Kursleiterin gibt die Prüfungstermine bekannt' (The course instructor announces the exam dates)."},
{type:"teach",trg:"unterrichten",src:"to teach, to instruct",pos:"verb",gender:null,note:"Unter (under/among) + richten (to direct).\nDeutsch unterrichten = to teach German.",example:"A: Wer unterrichtet den B1-Kurs?\nB: Frau Schmidt unterrichtet ihn.\nA: Sie unterrichtet sehr gut.\nB: Ja, sie unterrichtet seit zwanzig Jahren Deutsch.",exampleSrc:"A: Who teaches the B1 course?\nB: Mrs. Schmidt teaches it.\nA: She teaches very well.\nB: Yes, she has been teaching German for twenty years.",funFact:"Unter (under/among) + richten (to direct). To direct knowledge into someone. 'Unterricht' (instruction/class) is the noun form. Originally meant to direct something among people."},
{type:"teach",trg:"testen",src:"to test",pos:"verb",gender:null,note:"From English test, from Latin testum (clay pot for assaying).\nWissen testen = to test knowledge.",example:"A: Heute testen wir die Grammatik.\nB: Wie wird getestet?\nA: Mit einem kurzen Quiz.\nB: Gut, ich habe alles gelernt. Testen Sie mich!",exampleSrc:"A: Today we test the grammar.\nB: How will it be tested?\nA: With a short quiz.\nB: Good, I studied everything. Test me!",funFact:"From English 'test,' which came from Latin 'testum' (clay pot used for assaying metals). Full circle: Latin to English to German. Simple, regular, international."},
{type:"mc",q:"Verumius braucht zusätzliche Hilfe bei der Grammatik vor der Prüfung. Was sollte er suchen?",opts:["Referat","Nachhilfe","Studie","Semester"],ans:"Nachhilfe",hint:"Das Wort für zusätzliche Unterrichtsstunden. Nach (after) + Hilfe (help)."},
{type:"fb",s:"Am Goethe-{1} kann man die Sprachprüfung ablegen.",a:["Institut"],opts:["Institut","Seminar","Studio","Semester"],hint:"The worldwide German cultural organization where exams are held.",sSrc:"At the Goethe Institute you can take the language exam."},
{type:"match",pairs:[{trg:"Kursleiter",src:"course instructor"},{trg:"Teilnehmer",src:"participant"},{trg:"Professor",src:"professor"},{trg:"Studierende",src:"students"}]}
]},

// =============================================
// Lesson 4: Hypothesen und Wünsche (Hypotheses and Wishes)
// Type: Story dev + grammar (bubble). 18 new words. 24 steps.
// Grammar: TAUGHT: #6 Irreale Bedingungssätze, #29 brauchen + zu
// =============================================
{id:"deu_r23l4",title:"Hypothesen und Wünsche",icon:"💭",xp:15,board:true,steps:[
{type:"intro",title:"Hypothesen und Wünsche",desc:"Was wäre, wenn? Dr. Yilmaz erklärt die irrealen Bedingungssätze und brauchen + zu. Verumius lernt, hypothetisch zu denken.",goals:["Meistere irreale Bedingungssätze (Wenn ich...hätte, würde ich...)","Lerne brauchen + zu für Notwendigkeit","Diskutiere Prüfungsstrategien mit Dr. Yilmaz"]},
{type:"story",speaker:"yilmaz",mood:"calm-mentor",art:"de-ber-yilmaz-office",trg:"Wenn du mehr Zeit hättest, würdest du dich sicherer fühlen. Aber du brauchst dir keine Sorgen zu machen. Du bist gut vorbereitet.",src:"If you had more time, you would feel more confident. But you do not need to worry. You are well prepared."},
{type:"teach",trg:"die Ausnahme",src:"exception",pos:"noun",gender:"f",note:"Feminine noun. Aus (out) + Nahme (taking).\nDie Ausnahme bestätigt die Regel = The exception confirms the rule.",example:"A: Gibt es Ausnahmen bei dieser Regel?\nB: Ja, es gibt eine Ausnahme.\nA: Immer diese Ausnahmen!\nB: Die Ausnahme bestätigt die Regel.",exampleSrc:"A: Are there exceptions to this rule?\nB: Yes, there is one exception.\nA: Always these exceptions!\nB: The exception confirms the rule.",funFact:"Aus (out) + Nahme (taking). Something taken out of the rule. German grammar is famous for its many Ausnahmen (exceptions). The proverb 'Die Ausnahme bestätigt die Regel' is used constantly in language classes."},
{type:"teach",trg:"die Folge",src:"consequence, episode",pos:"noun",gender:"f",note:"Feminine noun. From folgen (to follow).\nAls Folge = as a consequence. Also: a TV episode.",example:"A: Was sind die Folgen, wenn ich nicht bestehe?\nB: Als Folge musst du die Prüfung wiederholen.\nA: Das ist keine schlimme Folge.\nB: Nein. Viele bestehen beim zweiten Versuch.",exampleSrc:"A: What are the consequences if I do not pass?\nB: As a consequence, you have to retake the exam.\nA: That is not a bad consequence.\nB: No. Many pass on the second try.",funFact:"From 'folgen' (to follow). What follows from something. Also: a TV episode (die nächste Folge). Consequence and sequel share the same root: what comes after."},
{type:"teach",trg:"der Gegensatz",src:"opposite, contrast",pos:"noun",gender:"m",note:"Masculine noun. Gegen (against) + Satz (sentence/setting).\nIm Gegensatz zu = in contrast to.",example:"A: Im Gegensatz zu gestern bin ich heute ruhig.\nB: Das ist ein großer Gegensatz!\nA: Ja, gestern war ich nervös, heute bin ich gelassen.\nB: Gegensätze können sich schnell ändern.",exampleSrc:"A: In contrast to yesterday, I am calm today.\nB: That is a big contrast!\nA: Yes, yesterday I was nervous, today I am relaxed.\nB: Contrasts can change quickly.",funFact:"Gegen (against) + Satz (sentence/setting). The opposite. 'Gegensätze ziehen sich an' (Opposites attract). A word that contains opposition in its very structure."},
{type:"teach",trg:"der Grund",src:"reason, ground",pos:"noun",gender:"m",note:"Masculine noun. Same word for physical ground and abstract reason.\nAus diesem Grund = for this reason.",example:"A: Aus welchem Grund lernst du Deutsch?\nB: Der Grund ist meine Arbeit.\nA: Das ist ein guter Grund.\nB: Im Grunde macht es mir auch Spaß.",exampleSrc:"A: For what reason are you learning German?\nB: The reason is my work.\nA: That is a good reason.\nB: Basically, I also enjoy it.",funFact:"Same word for physical ground and abstract reason. 'Im Grunde' (basically, literally: at the ground). 'Grundlos' (without reason). The foundation of arguments and the earth beneath your feet."},
{type:"teach",trg:"die Ursache",src:"cause",pos:"noun",gender:"f",note:"Feminine noun. Ur- (original/primal) + Sache (thing).\nDeeper than Grund: Ursache is the root cause.",example:"A: Was ist die Ursache des Problems?\nB: Die Ursache ist mangelnde Übung.\nA: Gibt es eine andere Ursache?\nB: Nein, die Ursache ist klar: zu wenig Praxis.",exampleSrc:"A: What is the cause of the problem?\nB: The cause is lack of practice.\nA: Is there another cause?\nB: No, the cause is clear: too little practice.",funFact:"Ur- (original/primal) + Sache (thing/matter). The original cause. Deeper than Grund: Ursache is the root cause, Grund is the stated reason. Forensic language: finding the Ursache means getting to the bottom."},
{type:"teach",trg:"die Begründung",src:"justification, reasoning",pos:"noun",gender:"f",note:"Feminine noun. From begründen (to give reasons).\nExam prompt: Begründen Sie Ihre Meinung.",example:"A: Schreiben Sie eine Begründung für Ihre Meinung.\nB: Meine Begründung ist: Sprachen öffnen Türen.\nA: Das ist eine gute Begründung.\nB: Danke. Eine klare Begründung ist wichtig in der Prüfung.",exampleSrc:"A: Write a justification for your opinion.\nB: My reasoning is: Languages open doors.\nA: That is a good justification.\nB: Thanks. A clear justification is important in the exam.",funFact:"From 'begründen' (to give reasons). 'Begründen Sie Ihre Meinung' (Justify your opinion) is one of the most common prompts in the Goethe B1 Schreiben section."},
{type:"teach",trg:"die Reaktion",src:"reaction",pos:"noun",gender:"f",note:"Feminine noun. From Latin reactio.\nMeine Reaktion = my reaction.",example:"A: Was war deine Reaktion auf die Nachricht?\nB: Meine erste Reaktion war Überraschung.\nA: Und dann?\nB: Dann Freude. Eine positive Reaktion!",exampleSrc:"A: What was your reaction to the news?\nB: My first reaction was surprise.\nA: And then?\nB: Then joy. A positive reaction!",funFact:"From Latin 'reactio.' International word. The Goethe exam's Sprechen section tests your Reaktion to discussion prompts. A quick, thoughtful Reaktion earns more points."},
{type:"teach",trg:"der Versuch",src:"attempt, experiment",pos:"noun",gender:"m",note:"Masculine noun. From versuchen (to try/attempt).\nBeim ersten Versuch = on the first try.",example:"A: Bestehst du beim ersten Versuch?\nB: Ich hoffe! Beim ersten Versuch wäre ideal.\nA: Und wenn nicht?\nB: Dann war es ein guter Versuch. Ich versuche es noch mal.",exampleSrc:"A: Will you pass on the first try?\nB: I hope! On the first try would be ideal.\nA: And if not?\nB: Then it was a good attempt. I will try again.",funFact:"From 'versuchen' (to try/attempt). An attempt or experiment. 'Versuch und Irrtum' (trial and error). Scientists use 'Versuch' where English says 'experiment.' Every exam is a Versuch."},
{type:"teach",trg:"der Vorteil",src:"advantage",pos:"noun",gender:"m",note:"Masculine noun. Vor (before/front) + Teil (part).\nThe part in front: the advantage.",example:"A: Was ist der Vorteil eines Intensivkurses?\nB: Der Vorteil ist, dass man schneller lernt.\nA: Gibt es auch Nachteile?\nB: Ja, aber die Vorteile überwiegen.",exampleSrc:"A: What is the advantage of an intensive course?\nB: The advantage is that you learn faster.\nA: Are there also disadvantages?\nB: Yes, but the advantages outweigh them.",funFact:"Vor (before/in front) + Teil (part). The part in front, the advantage. 'Vor- und Nachteile abwägen' (to weigh pros and cons) is one of the most common B1 writing tasks."},
{type:"teach",trg:"der Nachteil",src:"disadvantage",pos:"noun",gender:"m",note:"Masculine noun. Nach (after/behind) + Teil (part).\nThe part behind: the disadvantage.",example:"A: Was ist der Nachteil?\nB: Ein Nachteil ist der hohe Preis.\nA: Das stimmt. Das ist ein großer Nachteil.\nB: Vorteile und Nachteile muss man immer abwägen.",exampleSrc:"A: What is the disadvantage?\nB: A disadvantage is the high price.\nA: That is true. That is a big disadvantage.\nB: Advantages and disadvantages must always be weighed.",funFact:"Nach (after/behind) + Teil (part). The part behind, the disadvantage. 'Vorteile und Nachteile' (advantages and disadvantages) is one of the most common B1 writing and speaking tasks."},
{type:"teach",trg:"feststellen",src:"to establish, to notice",pos:"verb",gender:null,note:"Fest (firm) + stellen (to place). Separable.\nIch stelle fest, dass... = I notice/find that...",example:"A: Ich stelle fest, dass mein Deutsch besser wird.\nB: Das ist richtig. Ich stelle dasselbe fest.\nA: Woran stellst du das fest?\nB: An deiner Aussprache. Die hat sich verbessert.",exampleSrc:"A: I notice that my German is getting better.\nB: That is right. I notice the same thing.\nA: How do you notice that?\nB: By your pronunciation. It has improved.",funFact:"Fest (firm) + stellen (to place). To place something firmly into knowledge. 'Feststellung' (finding/observation). A word for when you notice something and it becomes a fact."},
{type:"teach",trg:"ergänzen",src:"to complete, to supplement",pos:"verb",gender:null,note:"From ganz (whole). To make whole again.\nExam instruction: Ergänzen Sie den Text.",example:"A: Ergänzen Sie den fehlenden Text.\nB: Ich ergänze den Satz: 'Er geht nach Hause.'\nA: Richtig! Sie haben den Satz korrekt ergänzt.\nB: Die Lücke zu ergänzen war einfach.",exampleSrc:"A: Complete the missing text.\nB: I complete the sentence: 'He goes home.'\nA: Correct! You completed the sentence correctly.\nB: Filling in the gap was easy.",funFact:"From 'ganz' (whole). To make whole again. 'Den Satz ergänzen' (to complete the sentence). Standard exam instruction: 'Ergänzen Sie den Text' (Complete the text). Making the incomplete whole."},
{type:"teach",trg:"folgen",src:"to follow",pos:"verb",gender:null,note:"Takes dative. Daraus folgt... = It follows that...\nKönnen Sie mir folgen? = Do you understand?",example:"A: Können Sie mir folgen?\nB: Ja, ich kann Ihnen folgen.\nA: Daraus folgt, dass wir weitermachen können.\nB: Einverstanden. Ich folge Ihrem Rat.",exampleSrc:"A: Can you follow me?\nB: Yes, I can follow you.\nA: It follows that we can continue.\nB: Agreed. I follow your advice.",funFact:"Takes dative. 'Daraus folgt...' (It follows that...). 'Können Sie mir folgen?' means both 'Can you follow me?' and 'Do you understand?' Context decides, as always in German."},
{type:"teach",trg:"gelten",src:"to be valid, to apply",pos:"verb",gender:null,note:"Irregular: gilt, galt, gegolten.\nDiese Regel gilt immer = This rule always applies.",example:"A: Gilt diese Regel auch für Nebensätze?\nB: Ja, die Regel gilt immer.\nA: Gilt sie auch für die Prüfung?\nB: Natürlich. Die Regeln gelten überall.",exampleSrc:"A: Does this rule also apply to subordinate clauses?\nB: Yes, the rule always applies.\nA: Does it also apply to the exam?\nB: Of course. The rules apply everywhere.",funFact:"Irregular: gilt, galt, gegolten. 'Diese Regel gilt immer' (This rule always applies). 'Als Experte gelten' (to be considered an expert). A word about what counts and what holds."},
{type:"teach",trg:"stimmen",src:"to be correct, to vote",pos:"verb",gender:null,note:"Das stimmt = That is correct. From Stimme (voice).\nAbstimmen = to vote.",example:"A: Stimmt es, dass die Prüfung vier Teile hat?\nB: Ja, das stimmt.\nA: Stimmt es auch, dass man 60% braucht?\nB: Das stimmt. Sechzig Prozent zum Bestehen.",exampleSrc:"A: Is it true that the exam has four parts?\nB: Yes, that is correct.\nA: Is it also true that you need 60%?\nB: That is correct. Sixty percent to pass.",funFact:"'Das stimmt' (That is correct) is one of the most useful B1 words. From 'Stimme' (voice). Your voice agrees: it is correct. Also the root of 'abstimmen' (to vote) and 'Stimmung' (mood)."},
{type:"teach",trg:"gelingen",src:"to succeed",pos:"verb",gender:null,note:"Impersonal: Es gelingt mir = I succeed.\nIrregular: gelang, gelungen. Takes dative.",example:"A: Ist es dir gelungen, alle Aufgaben zu lösen?\nB: Ja, es ist mir gelungen!\nA: Wenn es mir gelingt, die Prüfung zu bestehen...\nB: Es wird dir gelingen. Du bist bereit.",exampleSrc:"A: Did you succeed in solving all tasks?\nB: Yes, I succeeded!\nA: If I succeed in passing the exam...\nB: You will succeed. You are ready.",funFact:"Impersonal: 'Es gelingt mir' (I succeed, literally: it succeeds for me). Irregular: gelang, gelungen. Dative subject. A humble construction: success happens TO you, not because of you."},
{type:"teach",trg:"allgemein",src:"general, generally",pos:"adj",gender:null,note:"From alle (all) + gemein (common).\nIm Allgemeinen = in general.",example:"A: Im Allgemeinen ist die Prüfung fair.\nB: Allgemein gesagt, ja.\nA: Allgemeine Tipps sind immer hilfreich.\nB: Stimmt. Allgemeinbildung hilft auch.",exampleSrc:"A: In general, the exam is fair.\nB: Generally speaking, yes.\nA: General tips are always helpful.\nB: True. General knowledge also helps.",funFact:"From 'alle' (all) + 'gemein' (common). What is common to all. 'Im Allgemeinen' (in general). 'Allgemeinbildung' (general education) is valued in German culture as a mark of a well-rounded person."},
{type:"teach",trg:"kompliziert",src:"complicated",pos:"adj",gender:null,note:"From Latin complicare (to fold together).\nDie Grammatik ist kompliziert = The grammar is complicated.",example:"A: Ist die deutsche Grammatik kompliziert?\nB: Ja, ziemlich kompliziert.\nA: Was ist am kompliziertesten?\nB: Die Adjektivdeklination. Sehr kompliziert!",exampleSrc:"A: Is German grammar complicated?\nB: Yes, quite complicated.\nA: What is the most complicated?\nB: Adjective declension. Very complicated!",funFact:"From Latin 'complicare' (to fold together). Verumius's most-used adjective when talking about German grammar. But: 'Kompliziert ist nicht unmöglich' (Complicated is not impossible)."},
{type:"tip",title:"Unreal Conditionals: The German 'What If'",text:"Structure: Wenn + subject + Konjunktiv II (hätte/wäre/könnte...), subject + würde + infinitive.\n\nExample: 'Wenn ich mehr Zeit hätte, würde ich mehr lernen.'\n(If I had more time, I would study more.)\n\nThe wenn clause uses hätte/wäre. The main clause uses würde + infinitive.\n\nWithout wenn: verb jumps to position 1:\n'Hätte ich mehr Zeit, würde ich mehr lernen.'\n\nOnly for unreal/impossible conditions. For real conditions: normal wenn + present tense.",deepDive:{title:"Konjunktiv II: hätte vs. wäre vs. würde",text:"Hätte (from haben): Wenn ich mehr Geld hätte...\nWäre (from sein): Wenn ich reich wäre...\nKönnte (from können): Wenn ich fliegen könnte...\n\nMain clause always with würde + infinitive:\nWenn ich reich wäre, würde ich reisen.\n\nException: hätte/wäre/könnte can also appear in the main clause:\nWenn ich mehr Zeit hätte, wäre ich ruhiger.\n(würde + ruhiger + sein sounds clunky)"}},
{type:"tip",title:"brauchen + zu: Die höfliche Verneinung",text:"Struktur: brauchen + nicht/nur/kein + zu + Infinitiv.\n\n'Du brauchst nicht zu kommen.' (You do not need to come.)\n'Man braucht nur zu fragen.' (One only needs to ask.)\n\nNIE ohne nicht/nur/kein: 'Ich brauche zu lernen' ist FALSCH.\n\nUmgangssprache lässt oft 'zu' weg:\n'Du brauchst nicht kommen.'\n\nDie Goethe-Prüfung erwartet die vollständige Form mit 'zu.'",deepDive:{title:"brauchen als Modalverb-Ersatz",text:"brauchen + nicht + zu + Infinitiv ersetzt 'müssen + nicht':\n\nDu musst nicht kommen = Du brauchst nicht zu kommen.\nSie müssen nicht warten = Sie brauchen nicht zu warten.\n\nbrauchen + nur + zu + Infinitiv:\nDu musst nur fragen = Du brauchst nur zu fragen.\n\nWichtig: brauchen ist KEIN echtes Modalverb.\nEs braucht immer 'zu' vor dem Infinitiv."}},
{type:"tip",title:"Starke Konjunktiv-II-Formen",text:"Häufige starke Formen (bevorzugt gegenüber würde):\ngäbe, gäbe, käme, wüsste, fände, ließe, bräuchte\nhätte, wäre, könnte, müsste, dürfte, sollte\n\nBenutze würde + Infinitiv wenn:\n1. Die starke Form altmodisch klingt\n2. Konj. II = Präteritum (z.B. machte)\n3. Du dir unsicher bist",deepDive:{title:"Selten in der Sprache",text:"Selten im Gespräch (benutze stattdessen würde):\nhülfe (helfen), stürbe (sterben), würfe (werfen)\n\nHäufig im Alltag:\nhätte, wäre, könnte, müsste, wüsste, ginge, käme, fände, ließe, bräuchte"}},
{type:"tip",title:"Konjunktiv II Past: hätte/wäre + Partizip II",text:"Present irrealis (not real NOW):\nWenn ich Zeit hätte, würde ich kommen.\n\nPast irrealis (not real in the PAST):\nWenn ich Zeit gehabt hätte, wäre ich gekommen.\n\nPresent = simple Konjunktiv II forms.\nPast = hätte/wäre + Partizip II.",deepDive:{title:"Mixed Conditionals",text:"Past cause + present result:\nWenn ich damals studiert hätte (past), wäre ich jetzt Ärztin (present).\n\nThis is a mixed conditional: past irrealis in the wenn clause, present irrealis in the main clause."}},
{type:"tip",title:"hätte vs. wäre im Konjunktiv II Vergangenheit",text:"Benutze hätte + PP für die meisten Verben:\nhätte gemacht, hätte gesagt, hätte gewusst, hätte gekauft\n\nBenutze wäre + PP für:\nBewegungsverben: wäre gegangen, wäre gekommen, wäre gefahren\nZustandswechsel: wäre geworden, wäre eingeschlafen\nbleiben, sein, passieren, geschehen\n\nGleiche Regel wie Perfekt: ist gegangen = wäre gegangen.",deepDive:{title:"Wortstellung mit hätte/wäre + PP",text:"Hauptsatz:\nIch hätte das gemacht. (hätte = V2, PP am Ende)\n\nNebensatz:\n...wenn ich das gewusst hätte. (PP vor hätte am Ende)\n\nKomplexes Doppel-hätte-Muster:\nWenn ich das gewusst hätte, hätte ich es anders gemacht.\n\n1. Klausel: gewusst hätte (PP + Hilfsverb am Ende)\n2. Klausel: hätte ich es gemacht (V1 nach Wenn-Klausel, PP am Ende)"}},
{type:"tip",title:"Wunsch- und Bedauernsmuster",text:"Gegenwartswünsche:\nIch wünschte, ich hätte/wäre/könnte...\n\nVergangenes Bedauern:\nHätte ich doch nur + PP!\nWäre ich doch nur + PP!\nWenn ich doch nur + PP + hätte/wäre!\n\ndoch, nur, bloß verstärken die Emotion. Alle drei bedeuten dasselbe.",deepDive:{title:"Register-Unterschiede",text:"Ich wünschte = formell, ruhiger Wunsch\nHätte ich doch nur = emotionales Bedauern\nWenn ich doch nur = etwas sanfteres Bedauern\n\n'Hätte ich doch nur mehr gelernt!'\n'Wäre ich doch nur früher gekommen!'\n'Wenn ich das doch nur gewusst hätte!'"}},
{type:"tip",title:"als ob + Konjunktiv II",text:"Beide bedeuten 'als ob':\n\nals ob + ... + Verb am ENDE:\nEr tut, als ob er müde wäre.\n\nals + Verb SOFORT:\nEr tut, als wäre er müde.\n\nGleiche Bedeutung. als (ohne ob) ist eleganter.\nErfordert immer Konjunktiv II.",deepDive:{title:"Häufige Verben vor als ob",text:"tun als ob, aussehen als ob, klingen als ob,\nsich fühlen als ob, scheinen als ob, sich verhalten als ob\n\nAlle beschreiben ERSCHEINUNGEN, nicht Fakten.\n\n'Er tut, als wüsste er alles.'\n'Es sieht aus, als ob es regnen würde.'\n'Sie klingt, als wäre sie müde.'"}},
{type:"mc",q:"Welcher Satz drückt eine irreale Bedingung korrekt aus?",opts:["Wenn ich Zeit hätte, würde ich gelernt.","Wenn ich Zeit habe, lerne ich.","Wenn ich Zeit hätte, würde ich lernen.","Wenn ich Zeit hätte, lerne ich."],ans:"Wenn ich Zeit hätte, würde ich lernen.",hint:"Irreale Bedingung: wenn + Konjunktiv II, dann würde + Infinitiv (nicht Partizip)."},
{type:"fb",s:"Du brauchst dir keine Sorgen zu {1}.",a:["machen"],opts:["machen","haben","sein","gehen"],hint:"The infinitive that goes with Sorgen (worries). You make worries, not have them.",sSrc:"You do not need to worry."}
]},

// =============================================
// Lesson 5: Drei Konstruktionen (Three Constructions)
// Type: Grammar deep dive (bubble). 18 new words. 26 steps.
// Grammar: PRACTICED: #6, #29. TAUGHT: #32 Double infinitive.
// =============================================
{id:"deu_r23l5",title:"Drei Konstruktionen",icon:"🔧",xp:15,board:true,steps:[
{type:"intro",title:"Drei Konstruktionen",desc:"Drei Grammatikkonstruktionen, ein Ziel: Beherrschung. Irreale Bedingungssätze, brauchen + zu und der Doppelinfinitiv im Perfekt.",goals:["Meistere alle drei Grammatikkonstruktionen dieser Einheit","Übe irreale Bedingungssätze und brauchen + zu","Lerne den Doppelinfinitiv im Perfekt"]},
{type:"teach",trg:"die Kommunikation",src:"communication",pos:"noun",gender:"f",note:"Feminine noun. From Latin communicatio.\nMündliche Kommunikation = oral communication.",example:"A: Die Prüfung testet vier Bereiche der Kommunikation.\nB: Welche Bereiche?\nA: Lesen, Hören, Schreiben, Sprechen.\nB: Also alle Formen der Kommunikation.",exampleSrc:"A: The exam tests four areas of communication.\nB: Which areas?\nA: Reading, listening, writing, speaking.\nB: So all forms of communication.",funFact:"From Latin 'communicatio.' The Goethe exam has four sections testing four types of Kommunikation: Lesen, Hören, Schreiben, Sprechen. Complete communication competence."},
{type:"teach",trg:"die Recherche",src:"research (journalistic)",pos:"noun",gender:"f",note:"Feminine noun. From French recherche (search).\nMore journalistic than Studie (scientific).",example:"A: Hast du Recherche für dein Referat gemacht?\nB: Ja, eine gründliche Recherche im Internet.\nA: Internetrecherche ist schnell.\nB: Stimmt, aber man muss die Quellen prüfen.",exampleSrc:"A: Did you do research for your presentation?\nB: Yes, thorough research on the internet.\nA: Internet research is fast.\nB: True, but you have to check the sources.",funFact:"From French 'recherche' (search). More journalistic than Studie (scientific). 'Internetrecherche' (internet research). Verumius's exam prep involved extensive Recherche across multiple sources."},
{type:"teach",trg:"die Theorie",src:"theory",pos:"noun",gender:"f",note:"Feminine noun. From Greek theoria (contemplation).\nTheorie und Praxis = theory and practice.",example:"A: In der Theorie ist alles einfach.\nB: Stimmt. Theorie und Praxis sind verschieden.\nA: Die Theorie sagt, dass ich bestehe.\nB: Und in der Praxis? Auch!",exampleSrc:"A: In theory, everything is simple.\nB: True. Theory and practice are different.\nA: The theory says that I will pass.\nB: And in practice? Also!",funFact:"From Greek 'theoria' (contemplation). 'Theorie und Praxis' (theory and practice). The Goethe exam tests both: theoretisches Wissen (theoretical knowledge) and praktische Anwendung (practical application)."},
{type:"teach",trg:"das Forum",src:"forum",pos:"noun",gender:"n",note:"Neuter noun. From Latin forum (public square).\nPlural: Foren. Ein Online-Forum = an online forum.",example:"A: Hast du im Forum nachgefragt?\nB: Ja, das Online-Forum war sehr hilfreich.\nA: Was haben die Leute im Forum geschrieben?\nB: Viele Tipps zur Prüfungsvorbereitung.",exampleSrc:"A: Did you ask in the forum?\nB: Yes, the online forum was very helpful.\nA: What did the people in the forum write?\nB: Many tips for exam preparation.",funFact:"From Latin 'forum' (public square). Plural: Foren. The modern Forum is digital, but the function is the same: people discuss publicly. Exam preparation forums are popular in Germany."},
{type:"teach",trg:"der Dialog",src:"dialogue",pos:"noun",gender:"m",note:"Masculine noun. From Greek dialogos (conversation).\nEinen Dialog führen = to have a dialogue.",example:"A: Im Sprechen-Teil führen Sie einen Dialog.\nB: Mit wem führe ich den Dialog?\nA: Mit einem anderen Teilnehmer.\nB: Gut, einen Dialog führen kann ich.",exampleSrc:"A: In the speaking section, you have a dialogue.\nB: With whom do I have the dialogue?\nA: With another participant.\nB: Good, I can have a dialogue.",funFact:"From Greek 'dialogos' (conversation). The Goethe Sprechen section includes a Dialog with a partner. Two people, one topic, structured exchange. Practice with a partner helps."},
{type:"teach",trg:"die Intelligenz",src:"intelligence",pos:"noun",gender:"f",note:"Feminine noun. From Latin intelligentia.\nKünstliche Intelligenz = artificial intelligence.",example:"A: Sprachliche Intelligenz ist wichtig.\nB: Es gibt verschiedene Formen von Intelligenz.\nA: Emotionale Intelligenz hilft auch bei der Prüfung.\nB: Stimmt, Ruhe bewahren ist eine Form von Intelligenz.",exampleSrc:"A: Linguistic intelligence is important.\nB: There are different forms of intelligence.\nA: Emotional intelligence also helps in the exam.\nB: True, staying calm is a form of intelligence.",funFact:"From Latin 'intelligentia' (understanding). 'Künstliche Intelligenz' (artificial intelligence), 'Emotionale Intelligenz' (emotional intelligence). The Goethe exam measures sprachliche Intelligenz (linguistic intelligence)."},
{type:"teach",trg:"der Lerner",src:"learner (male)",pos:"noun",gender:"m",note:"Masculine noun. From lernen.\nDeutschlerner = German learner.",example:"A: Verumius ist ein motivierter Lerner.\nB: Wie lange ist er schon Deutschlerner?\nA: Seit einem Jahr. Ein fleißiger Lerner!\nB: Jeder gute Lerner war einmal Anfänger.",exampleSrc:"A: Verumius is a motivated learner.\nB: How long has he been a German learner?\nA: For one year. A diligent learner!\nB: Every good learner was once a beginner.",funFact:"From 'lernen.' Simple agent noun. More modern and neutral than 'Schüler' (student/pupil). What Verumius has been for one year. Every Lerner has a different story."},
{type:"teach",trg:"die Lernerin",src:"learner (female)",pos:"noun",gender:"f",note:"Feminine noun. Lerner + -in.\nGender-neutral alternative: Lernende.",example:"A: Die Lernerin aus Brasilien ist sehr gut.\nB: Ja, sie ist eine motivierte Lernerin.\nA: Jede Lernerin hat ihren eigenen Stil.\nB: Stimmt. Manche Lernerinnen lernen visuell.",exampleSrc:"A: The learner from Brazil is very good.\nB: Yes, she is a motivated learner.\nA: Every learner has her own style.\nB: True. Some learners learn visually.",funFact:"The feminine form. The Goethe-Institut increasingly prefers 'Lernende' (learning ones) as a gender-neutral alternative, but Lerner/Lernerin remains standard in everyday use."},
{type:"teach",trg:"der Leser",src:"reader (male)",pos:"noun",gender:"m",note:"Masculine noun. From lesen (to read).\nLiebe Leserinnen und Leser = Dear readers.",example:"A: Liebe Leserinnen und Leser...\nB: So beginnt jeder deutsche Zeitungsartikel.\nA: Der Leser muss den Text verstehen.\nB: Ein guter Leser liest zwischen den Zeilen.",exampleSrc:"A: Dear readers...\nB: That is how every German newspaper article begins.\nA: The reader must understand the text.\nB: A good reader reads between the lines.",funFact:"From 'lesen' (to read). 'Liebe Leserinnen und Leser' (Dear readers, fem. and masc.) opens every German newspaper column. The Lesen section tests whether you are a good Leser."},
{type:"teach",trg:"die Leserin",src:"reader (female)",pos:"noun",gender:"f",note:"Feminine noun. Leser + -in.\nDie aufmerksame Leserin = the attentive reader.",example:"A: Die Leserin hat den Fehler sofort bemerkt.\nB: Eine aufmerksame Leserin.\nA: In der Prüfung muss man eine gute Leserin sein.\nB: Stimmt, genaues Lesen ist der Schlüssel.",exampleSrc:"A: The reader noticed the mistake immediately.\nB: An attentive reader.\nA: In the exam, you have to be a good reader.\nB: True, careful reading is the key.",funFact:"The feminine form. 'Die aufmerksame Leserin' (the attentive reader). The Goethe exam's Lesen section does not care about your gender, only your Lesekompetenz (reading competence)."},
{type:"teach",trg:"analysieren",src:"to analyze",pos:"verb",gender:null,note:"From Greek analysis (dissolution).\nEinen Text analysieren = to analyze a text.",example:"A: Analysieren Sie den Text auf Seite fünf.\nB: Was genau soll ich analysieren?\nA: Die Hauptargumente und Beispiele.\nB: Gut, ich analysiere den Text Absatz für Absatz.",exampleSrc:"A: Analyze the text on page five.\nB: What exactly should I analyze?\nA: The main arguments and examples.\nB: Good, I will analyze the text paragraph by paragraph.",funFact:"From Greek 'analysis' (dissolution). 'Einen Text analysieren' (to analyze a text). The Schreiben section often asks you to analysieren a Grafik or Darstellung. Breaking something down to understand it."},
{type:"teach",trg:"darstellen",src:"to represent, to depict",pos:"verb",gender:null,note:"Separable: dar + stellen. Die Grafik stellt dar...\nAcademic German loves this verb.",example:"A: Was stellt die Grafik dar?\nB: Die Grafik stellt die Entwicklung dar.\nA: Können Sie das anders darstellen?\nB: Ja, ich stelle es als Tabelle dar.",exampleSrc:"A: What does the chart depict?\nB: The chart depicts the development.\nA: Can you represent that differently?\nB: Yes, I will present it as a table.",funFact:"Dar (there/forth) + stellen (to place). Separable. 'Die Grafik stellt die Entwicklung dar' (The chart depicts the development). A cornerstone of academic German."},
{type:"teach",trg:"unterscheiden",src:"to distinguish",pos:"verb",gender:null,note:"Unter (between) + scheiden (to separate).\nReflexive: sich unterscheiden = to differ.",example:"A: Können Sie die beiden Wörter unterscheiden?\nB: Ja, ich kann sie unterscheiden.\nA: Worin unterscheiden sie sich?\nB: Sie unterscheiden sich in der Bedeutung.",exampleSrc:"A: Can you distinguish the two words?\nB: Yes, I can distinguish them.\nA: How do they differ?\nB: They differ in meaning.",funFact:"Unter (under/between) + scheiden (to separate). To separate things in order to tell them apart. Reflexive: 'sich unterscheiden' (to differ). A key academic skill."},
{type:"teach",trg:"korrigieren",src:"to correct",pos:"verb",gender:null,note:"From Latin corrigere. Regular verb.\nSich selbst korrigieren = to correct oneself.",example:"A: Können Sie meinen Text korrigieren?\nB: Natürlich, ich korrigiere ihn gern.\nA: Wie viele Fehler haben Sie korrigiert?\nB: Nur drei. Sie haben sich selbst gut korrigiert.",exampleSrc:"A: Can you correct my text?\nB: Of course, I am happy to correct it.\nA: How many mistakes did you correct?\nB: Only three. You corrected yourself well.",funFact:"From Latin 'corrigere.' Self-correction (sich selbst korrigieren) is a sign of B1 fluency. The examiner notices when you catch and correct your own mistakes."},
{type:"teach",trg:"zusammenfassen",src:"to summarize",pos:"verb",gender:null,note:"Zusammen (together) + fassen (to grasp). Separable.\nZusammenfassung = summary. A core B1 writing skill.",example:"A: Fassen Sie den Text zusammen.\nB: Der Text handelt von Bildung in Deutschland.\nA: Gut zusammengefasst!\nB: Danke, zusammenfassen ist eine wichtige Fähigkeit.",exampleSrc:"A: Summarize the text.\nB: The text is about education in Germany.\nA: Well summarized!\nB: Thanks, summarizing is an important skill.",funFact:"Zusammen (together) + fassen (to grasp). To grasp things together into a whole. 'Zusammenfassung' (summary). One of the core B1 writing skills tested in the Goethe exam."},
{type:"teach",trg:"mündlich",src:"oral, verbal",pos:"adj",gender:null,note:"From Mund (mouth). Die mündliche Prüfung = the oral exam.\nMündlich und schriftlich = orally and in writing.",example:"A: Die Prüfung hat einen mündlichen Teil.\nB: Ja, der mündliche Teil dauert fünfzehn Minuten.\nA: Mündlich bin ich nervöser als schriftlich.\nB: Das ist normal. Mündliche Prüfungen sind stressiger.",exampleSrc:"A: The exam has an oral part.\nB: Yes, the oral part lasts fifteen minutes.\nA: Orally, I am more nervous than in writing.\nB: That is normal. Oral exams are more stressful.",funFact:"From 'Mund' (mouth). The Goethe B1 has both mündliche (oral) and schriftliche (written) sections. 'Mündlich und schriftlich' is a fixed pair in German education."},
{type:"teach",trg:"passiv",src:"passive",pos:"adj",gender:null,note:"From Latin passivus. Passiver Wortschatz = passive vocabulary.\nAlso a grammar term: Passiv = passive voice.",example:"A: Mein passiver Wortschatz ist größer als mein aktiver.\nB: Das ist normal. Passiv verstehen ist leichter.\nA: Wie mache ich passive Wörter aktiv?\nB: Durch Übung. Benutze sie in Sätzen!",exampleSrc:"A: My passive vocabulary is larger than my active one.\nB: That is normal. Passive understanding is easier.\nA: How do I make passive words active?\nB: Through practice. Use them in sentences!",funFact:"From Latin 'passivus.' 'Passiver Wortschatz' (passive vocabulary, words you understand but do not actively use). Verumius's passive German is probably already B2 level. The exam tests both active and passive knowledge."},
{type:"teach",trg:"theoretisch",src:"theoretical, theoretically",pos:"adj",gender:null,note:"Theorie + -isch. Theoretisch möglich = theoretically possible.",example:"A: Theoretisch kann ich die Prüfung bestehen.\nB: Nicht nur theoretisch! Praktisch auch.\nA: Theoretisch habe ich alles gelernt.\nB: Dann wirst du es auch praktisch schaffen.",exampleSrc:"A: Theoretically, I can pass the exam.\nB: Not only theoretically! Practically too.\nA: Theoretically, I have learned everything.\nB: Then you will manage it practically too.",funFact:"Theorie + -isch. 'Theoretisch möglich' (theoretically possible). 'Theoretisch könnte ich die Prüfung bestehen. Praktisch bin ich nervös.' The gap between theory and practice is universal."},
{type:"tip",title:"Doppelinfinitiv: Wenn Modalverben auf Perfekt treffen",text:"Im Perfekt benutzen Modalverben (können, müssen, wollen, dürfen, sollen, mögen) KEIN Partizip. Stattdessen: Doppelinfinitiv.\n\n'Er hat kommen können' (He was able to come).\nNICHT: 'Er hat kommen gekonnt.'\n\nDer Doppelinfinitiv steht immer am ENDE des Satzes.\n\nIn Nebensätzen springt das Hilfsverb (hat/ist) VOR den Doppelinfinitiv:\n'Ich weiß, dass er hat kommen können.'\nDas bricht die normale Nebensatz-Regel!",deepDive:{title:"Alle Modalverben im Doppelinfinitiv",text:"Er hat kommen können. (He was able to come.)\nSie hat es machen wollen. (She wanted to do it.)\nIch habe nicht gehen dürfen. (I was not allowed to go.)\nWir haben es sagen müssen. (We had to say it.)\nIhr habt nicht bleiben sollen. (You were not supposed to stay.)\n\nWichtig: Nur wenn ein abhängiger Infinitiv dabei ist!\nOhne Infinitiv: 'Er hat es gekonnt.' (Er hat es können ist falsch.)"}},
{type:"verb_table",title:"Doppelinfinitiv: können im Perfekt",note:"With a dependent infinitive, modals use double infinitive instead of past participle.",groups:[{label:"Standard-Perfekt (falsch bei Modalverben)",rows:[{pronoun:"er",form:"*hat gekonnt",src:"(incorrect with dependent infinitive)"}]},{label:"Doppelinfinitiv (korrekt)",rows:[{pronoun:"er",form:"hat kommen können",src:"he was able to come"},{pronoun:"sie",form:"hat es machen wollen",src:"she wanted to do it"},{pronoun:"ich",form:"habe nicht gehen dürfen",src:"I was not allowed to go"},{pronoun:"wir",form:"haben es sagen müssen",src:"we had to say it"}]}]},
{type:"mc",q:"Ergänzen Sie: 'Wenn ich Deutsch perfekt könnte, _____ ich in Deutschland arbeiten.'",opts:["habe","würde","werde","bin"],ans:"würde",hint:"Irreale Bedingung: Der Hauptsatz braucht würde + Infinitiv."},
{type:"mc",q:"Welcher Satz ist grammatisch korrekt?",opts:["Du brauchst nicht zu lernen.","Du brauchst nicht lernen zu.","Du brauchst zu lernen.","Du brauchst gelernt zu."],ans:"Du brauchst nicht zu lernen.",hint:"brauchen + zu funktioniert nur mit nicht, nur oder kein. Das zu steht vor dem Infinitiv."},
{type:"fb",s:"Er hat gestern nicht kommen {1}.",a:["können"],opts:["können","gekonnt","kann","konnte"],hint:"Modal + Perfekt = double infinitive. The modal stays in infinitive form.",sSrc:"He was not able to come yesterday."},
{type:"mc",q:"'Wenn er hätte kommen können, hätte er nicht zu Hause bleiben brauchen.' Was bedeutet dieser Satz?",opts:["He could come but he needed to stay home.","If he had been able to come, he would not have needed to stay home.","He had come and then stayed home.","If he comes, he will not stay home."],ans:"If he had been able to come, he would not have needed to stay home.",hint:"Zwei irreale Bedingungen kombiniert: hätte + kommen können (Doppelinfinitiv) und hätte + brauchen."},
{type:"drag_fill",s:"Wenn ich besser vorbereitet {1}, {2} ich die Prüfung leicht bestehen.",blanks:{"1":"wäre","2":"würde"},pool:["wäre","würde","bin","werde","hätte","könnte"],hint:"Irrealer Bedingungssatz. Die Wenn-Klausel braucht wäre, der Hauptsatz braucht würde.",sSrc:"If I were better prepared, I would easily pass the exam."}
]},

// =============================================
// Lesson 6: Wortschatz-Blitz (Vocabulary Lightning)
// Type: Vocab + practice (bubble). 20 new words. 26 steps.
// =============================================
{id:"deu_r23l6",title:"Wortschatz-Blitz",icon:"⚡",xp:15,board:true,steps:[
{type:"intro",title:"Wortschatz-Blitz",desc:"Zwanzig neue Wörter im Schnelldurchgang: akademische Aktivitäten, Karrieren und Werkzeuge des Wissens. Alle drei Grammatikkonstruktionen integriert.",goals:["Lerne Vokabeln für akademische Aktivitäten und Karrieren","Übe alle drei Grammatikkonstruktionen im Kontext","Baue Sprachflüssigkeit durch integrierte Übungen auf"]},
{type:"teach",trg:"die Aufnahme",src:"recording, admission, photograph",pos:"noun",gender:"f",note:"Feminine noun. Auf (up) + Nahme (taking).\nTonaufnahme = audio recording. Aufnahmeprüfung = entrance exam.",example:"A: Die Aufnahme ist von guter Qualität.\nB: Welche Aufnahme meinst du?\nA: Die Tonaufnahme für den Hören-Teil.\nB: Ah, stimmt. Die Aufnahme war klar.",exampleSrc:"A: The recording is of good quality.\nB: Which recording do you mean?\nA: The audio recording for the listening section.\nB: Ah, right. The recording was clear.",funFact:"Auf (up) + Nahme (taking). Taking up: recording, admission, or photograph. 'Tonaufnahme' (audio recording). 'Aufnahmeprüfung' (entrance exam). Context decides the meaning."},
{type:"teach",trg:"der Einfall",src:"idea, notion",pos:"noun",gender:"m",note:"Masculine noun. Ein (in) + Fall (fall).\nSomething that falls into your mind.",example:"A: Ich habe einen guten Einfall!\nB: Was für einen Einfall?\nA: Wir üben zusammen für die Prüfung.\nB: Das ist ein toller Einfall!",exampleSrc:"A: I have a good idea!\nB: What kind of idea?\nA: We practice together for the exam.\nB: That is a great idea!",funFact:"Ein (in) + Fall (fall). Something that falls into your mind: an idea. 'Mir fällt etwas ein' (Something occurs to me). Ideas arrive by falling, not by climbing. Inspiration drops in unexpectedly."},
{type:"teach",trg:"die Buchhandlung",src:"bookshop",pos:"noun",gender:"f",note:"Feminine noun. Buch (book) + Handlung (action/trade).\nGermany has more bookshops per capita than almost any other country.",example:"A: Gibt es eine Buchhandlung in der Nähe?\nB: Ja, die Buchhandlung am Marktplatz.\nA: Ich brauche ein neues Übungsbuch.\nB: In der Buchhandlung gibt es viele Lernmaterialien.",exampleSrc:"A: Is there a bookshop nearby?\nB: Yes, the bookshop at the market square.\nA: I need a new practice book.\nB: In the bookshop there are many learning materials.",funFact:"Buch (book) + Handlung (action/trade). Germany has more bookshops per capita than almost any other country. Books are price-fixed by law (Buchpreisbindung), protecting small shops from being undercut."},
{type:"teach",trg:"das Magazin",src:"magazine",pos:"noun",gender:"n",note:"Neuter noun. From Arabic makhazin (storehouses).\nNachrichtenmagazin = news magazine.",example:"A: Liest du gerne Magazin?\nB: Ja, ein deutsches Nachrichtenmagazin.\nA: Welches Magazin?\nB: Den Spiegel. Das bekannteste deutsche Magazin.",exampleSrc:"A: Do you like reading magazines?\nB: Yes, a German news magazine.\nA: Which magazine?\nB: Der Spiegel. The most famous German magazine.",funFact:"From Arabic 'makhazin' (storehouses). A magazine or warehouse. Der Spiegel is Germany's most famous Magazin, founded in 1947. Arabic to French to German: words travel far across cultures."},
{type:"teach",trg:"die Mensa",src:"cafeteria (university)",pos:"noun",gender:"f",note:"Feminine noun. From Latin mensa (table).\nIn der Mensa essen = to eat in the cafeteria.",example:"A: Wollen wir in der Mensa essen?\nB: Ja, die Mensa ist günstig.\nA: Was gibt es heute in der Mensa?\nB: Schnitzel mit Pommes. Für drei Euro fünfzig.",exampleSrc:"A: Do we want to eat in the cafeteria?\nB: Yes, the cafeteria is cheap.\nA: What is there today in the cafeteria?\nB: Schnitzel with fries. For three euros fifty.",funFact:"From Latin 'mensa' (table). The university cafeteria. German Mensen serve surprisingly decent food for 2-4 euros. Student life depends on the Mensa. The word reveals its Roman origin."},
{type:"teach",trg:"das Studio",src:"studio",pos:"noun",gender:"n",note:"Neuter noun. From Latin studium (study).\nTonstudio = recording studio. Fotostudio = photo studio.",example:"A: Wo wurde die Aufnahme gemacht?\nB: Im Studio des Goethe-Instituts.\nA: Ein professionelles Studio?\nB: Ja, mit guter Technik. Ein tolles Studio.",exampleSrc:"A: Where was the recording made?\nB: In the studio of the Goethe-Institut.\nA: A professional studio?\nB: Yes, with good technology. A great studio.",funFact:"From Latin 'studium' (study). A studio for art, music, or broadcasting. 'Tonstudio' (recording studio), 'Fotostudio' (photo studio). The space where creative work happens."},
{type:"teach",trg:"das Schreiben",src:"writing, letter (formal)",pos:"noun",gender:"n",note:"Neuter noun. The nominalized form of schreiben (to write).\nAlso: the Goethe exam's writing section.",example:"A: Das Schreiben ist der schwierigste Teil.\nB: Stimmt, das Schreiben braucht viel Übung.\nA: Haben Sie das offizielle Schreiben bekommen?\nB: Ja, das Schreiben vom Goethe-Institut ist angekommen.",exampleSrc:"A: The writing section is the hardest part.\nB: True, writing takes a lot of practice.\nA: Did you receive the official letter?\nB: Yes, the letter from the Goethe-Institut has arrived.",funFact:"The noun form of 'schreiben' (to write). Two meanings: a piece of formal writing (a letter) and the Goethe exam section. 'Das Schreiben' tests your written German at B1 level."},
{type:"teach",trg:"der Übersetzer",src:"translator (male)",pos:"noun",gender:"m",note:"Masculine noun. Über (across) + setzen (to set) + -er.\nOne who carries meaning across languages.",example:"A: Bist du Übersetzer?\nB: Nein, aber ich möchte Übersetzer werden.\nA: Ein guter Übersetzer braucht zwei Sprachen perfekt.\nB: Mindestens! Viele Übersetzer können drei oder vier.",exampleSrc:"A: Are you a translator?\nB: No, but I want to become a translator.\nA: A good translator needs two languages perfectly.\nB: At least! Many translators know three or four.",funFact:"Über (over/across) + setzen (to set) + -er. One who carries meaning across languages. Martin Luther was Germany's most famous Übersetzer: his Bible translation helped shape modern standard German."},
{type:"teach",trg:"die Übersetzerin",src:"translator (female)",pos:"noun",gender:"f",note:"Feminine noun. Übersetzer + -in.\nSimultanübersetzerin = simultaneous interpreter.",example:"A: Die Übersetzerin arbeitet bei der EU.\nB: Eine Simultanübersetzerin?\nA: Ja, die Übersetzerin übersetzt in Echtzeit.\nB: Das ist eine beeindruckende Fähigkeit.",exampleSrc:"A: The translator works at the EU.\nB: A simultaneous interpreter?\nA: Yes, the translator translates in real time.\nB: That is an impressive skill.",funFact:"The feminine form. Translation is one of the oldest professions in language: every culture needs Übersetzerinnen. The EU employs hundreds of them for its 24 official languages."},
{type:"teach",trg:"der Wissenschaftler",src:"scientist, scholar (male)",pos:"noun",gender:"m",note:"Masculine noun. Wissen (knowledge) + Schaft + -ler.\nA person who creates knowledge.",example:"A: Der Wissenschaftler hat eine neue Studie veröffentlicht.\nB: Worüber?\nA: Über Sprachlernen im Erwachsenenalter.\nB: Interessant. Wissenschaftler erforschen alles.",exampleSrc:"A: The scientist published a new study.\nB: About what?\nA: About language learning in adulthood.\nB: Interesting. Scientists research everything.",funFact:"Wissen (knowledge) + Schaft (creation/nature) + -ler (person). A scientist or scholar. The word contains Wissen: a Wissenschaftler creates knowledge. Germany has more Nobel Prize winners than any non-English-speaking country."},
{type:"teach",trg:"die Wissenschaftlerin",src:"scientist, scholar (female)",pos:"noun",gender:"f",note:"Feminine noun. Wissenschaftler + -in.\nForscherin und Wissenschaftlerin = researcher and scientist.",example:"A: Die Wissenschaftlerin hat den Preis gewonnen.\nB: Welchen Preis?\nA: Den Nobelpreis für Literatur.\nB: Eine beeindruckende Wissenschaftlerin!",exampleSrc:"A: The scientist won the prize.\nB: Which prize?\nA: The Nobel Prize for Literature.\nB: An impressive scientist!",funFact:"The feminine form. Germany has produced many notable Wissenschaftlerinnen across all fields. The number of female professors is growing, though still below parity."},
{type:"teach",trg:"aufgeben",src:"to give up, to assign",pos:"verb",gender:null,note:"Separable: auf + geben. Paradox: give up AND assign homework.\nIch gebe nicht auf! = I do not give up!",example:"A: Gibst du auf?\nB: Nein, ich gebe niemals auf!\nA: Gut. Der Lehrer gibt heute Hausaufgaben auf.\nB: Schon wieder? Ich gebe trotzdem nicht auf.",exampleSrc:"A: Are you giving up?\nB: No, I never give up!\nA: Good. The teacher is assigning homework today.\nB: Again? I still will not give up.",funFact:"Auf (up) + geben (to give). Paradox: means both 'to give up' AND 'to assign (homework).' 'Ich gebe nicht auf' (I do not give up). Context determines which meaning applies."},
{type:"teach",trg:"aufhalten",src:"to hold up, to delay, to stay",pos:"verb",gender:null,note:"Separable: auf + halten. Reflexive: sich aufhalten = to stay.\nIch will dich nicht aufhalten = I do not want to delay you.",example:"A: Wo hältst du dich gerade auf?\nB: Ich halte mich in der Bibliothek auf.\nA: Ich will dich nicht aufhalten.\nB: Kein Problem, ich halte mich hier noch eine Stunde auf.",exampleSrc:"A: Where are you staying right now?\nB: I am staying in the library.\nA: I do not want to hold you up.\nB: No problem, I am staying here for another hour.",funFact:"Auf (up) + halten (to hold). Reflexive: 'sich aufhalten' (to stay somewhere). Transitive: to delay someone. 'Ich will dich nicht aufhalten' (I do not want to hold you up). Location and delay in one verb."},
{type:"teach",trg:"ausreichen",src:"to be sufficient",pos:"verb",gender:null,note:"Separable: aus + reichen. Das reicht aus = That is sufficient.\nAusreichend (sufficient) is a barely-passing school grade.",example:"A: Reicht eine Stunde Übung aus?\nB: Nein, eine Stunde reicht nicht aus.\nA: Wie viel reicht aus?\nB: Mindestens zwei Stunden. Dann reicht es aus.",exampleSrc:"A: Is one hour of practice sufficient?\nB: No, one hour is not sufficient.\nA: How much is sufficient?\nB: At least two hours. Then it is sufficient.",funFact:"Aus (out) + reichen (to reach/suffice). 'Ausreichend' (sufficient) is a German school grade: barely passing, like a D. You want better than ausreichend on the Goethe exam."},
{type:"teach",trg:"bemerken",src:"to notice, to remark",pos:"verb",gender:null,note:"Be- + merken (to notice). Inseparable.\nIch habe bemerkt, dass... = I have noticed that...",example:"A: Hast du den Fehler bemerkt?\nB: Ja, ich habe ihn sofort bemerkt.\nA: Gut bemerkt!\nB: Danke, ich bemerke solche Dinge schnell.",exampleSrc:"A: Did you notice the mistake?\nB: Yes, I noticed it immediately.\nA: Well noticed!\nB: Thanks, I notice such things quickly.",funFact:"Be- + merken (to notice). The be- prefix makes it transitive: you notice something specific. 'Bemerkenswert' (remarkable). 'Ich habe bemerkt, dass...' (I have noticed that...) is a useful B1 construction."},
{type:"teach",trg:"beobachten",src:"to observe",pos:"verb",gender:null,note:"Be- + ob (over) + achten (to pay attention). Inseparable.\nDas Verhalten beobachten = to observe the behavior.",example:"A: Beobachten Sie die anderen Teilnehmer?\nB: Ja, ich beobachte, wie sie arbeiten.\nA: Was haben Sie beobachtet?\nB: Alle sind konzentriert. Ich beobachte viel Ehrgeiz.",exampleSrc:"A: Do you observe the other participants?\nB: Yes, I observe how they work.\nA: What have you observed?\nB: Everyone is concentrated. I observe a lot of ambition.",funFact:"Be- + ob (over) + achten (to pay attention). To observe. Scientific and everyday. 'Ich beobachte, dass...' (I observe that...). A word shared by scientists and curious people alike."},
{type:"teach",trg:"einfallen",src:"to occur to (someone)",pos:"verb",gender:null,note:"Separable: ein + fallen. Impersonal: Mir fällt ein...\nMir fällt nichts ein = Nothing comes to mind.",example:"A: Fällt dir ein guter Satz ein?\nB: Mir fällt gerade nichts ein.\nA: Denk nach. Es fällt dir bestimmt etwas ein.\nB: Ja! Mir ist ein Beispiel eingefallen!",exampleSrc:"A: Can you think of a good sentence?\nB: Nothing comes to mind right now.\nA: Think about it. Something will come to you.\nB: Yes! An example occurred to me!",funFact:"Ein (in) + fallen (to fall). Ideas fall into you. Impersonal: 'Mir fällt ein...' (It occurs to me...). 'Mir fällt nichts ein' (Nothing comes to mind). The noun is 'der Einfall' (the idea)."},
{type:"teach",trg:"eintreten",src:"to enter, to occur",pos:"verb",gender:null,note:"Separable: ein + treten. Bitte eintreten = Please come in.\nAlso: Der Fall ist eingetreten = The event has occurred.",example:"A: Bitte eintreten!\nB: Danke. Darf ich eintreten?\nA: Natürlich, treten Sie ein.\nB: Der erwartete Fall ist eingetreten: Prüfung morgen!",exampleSrc:"A: Please come in!\nB: Thank you. May I enter?\nA: Of course, come in.\nB: The expected event has occurred: exam tomorrow!",funFact:"Ein (in) + treten (to step). Literally: stepping into. 'Bitte eintreten' (Please come in). Also: 'Der Fall ist eingetreten' (The event has occurred). Stepping into a situation or a room."},
{type:"teach",trg:"präsentieren",src:"to present",pos:"verb",gender:null,note:"From Latin praesentare. Regular verb.\nDie Ergebnisse präsentieren = to present the results.",example:"A: Präsentieren Sie Ihr Thema der Gruppe.\nB: Ich präsentiere das Thema 'Bildung.'\nA: Gut präsentiert!\nB: Danke, ich habe lange geübt, um gut zu präsentieren.",exampleSrc:"A: Present your topic to the group.\nB: I am presenting the topic 'Education.'\nA: Well presented!\nB: Thanks, I practiced a long time to present well.",funFact:"From Latin 'praesentare.' The Goethe Sprechen section: you präsentieren a topic to the group. International verb, German pronunciation. Practice makes the Präsentation."},
{type:"teach",trg:"vorlesen",src:"to read aloud",pos:"verb",gender:null,note:"Separable: vor + lesen. Eine Geschichte vorlesen.\nVorlesung (lecture) comes from this verb.",example:"A: Können Sie den Text vorlesen?\nB: Ja, ich lese den ersten Absatz vor.\nA: Gut vorgelesen! Klare Aussprache.\nB: Danke, vorlesen hilft bei der Aussprache.",exampleSrc:"A: Can you read the text aloud?\nB: Yes, I will read the first paragraph aloud.\nA: Well read! Clear pronunciation.\nB: Thanks, reading aloud helps with pronunciation.",funFact:"Vor (in front of) + lesen (to read). 'Vorlesung' (lecture) comes from this: the professor reads aloud to students. A medieval origin with modern survival. Reading aloud is still the best pronunciation practice."},
{type:"mc",q:"'Wenn mir ein besseres Wort eingefallen wäre, hätte ich den Aufsatz besser schreiben können.' Welche Konstruktionen kombiniert dieser Satz?",opts:["Passiv + Nebensatz","Präsens + Futur","brauchen + zu + Perfekt","Irrealer Bedingungssatz + Doppelinfinitiv"],ans:"Irrealer Bedingungssatz + Doppelinfinitiv",hint:"Suchen Sie wenn + wäre (irreal) und hätte + Infinitiv + Infinitiv (Doppelinfinitiv)."},
{type:"fb",s:"Drei Stunden Übung pro Tag {1} nicht aus, um die Prüfung zu bestehen.",a:["reichen"],opts:["reichen","geben","fallen","halten"],hint:"Which verb means to be sufficient? The prefix aus- is already separated.",sSrc:"Three hours of practice per day are not sufficient to pass the exam."},
{type:"mc",q:"Welcher Satz ist korrekt?",opts:["Ihr braucht euch beeilen nicht zu.","Ihr braucht euch zu beeilen.","Ihr braucht nicht beeilt zu.","Ihr braucht euch nicht zu beeilen."],ans:"Ihr braucht euch nicht zu beeilen.",hint:"brauchen braucht nicht/nur/kein. Das zu steht direkt vor dem Infinitiv."},
{type:"match",pairs:[{trg:"vorlesen",src:"to read aloud"},{trg:"zusammenfassen",src:"to summarize"},{trg:"präsentieren",src:"to present"},{trg:"analysieren",src:"to analyze"}]},
{type:"drag_fill",s:"Sie hat das Buch nicht lesen {1}.",blanks:{"1":"können"},pool:["können","gekonnt","kann","konnte","lesen"],hint:"Modalverb im Perfekt: das Modalverb nimmt seine Infinitivform, kein Partizip.",sSrc:"She was not able to read the book."}
]},

// =============================================
// Lesson 7: Im Prüfungsraum (In the Exam Room)
// Type: Story climax + quiz (cinematic/bubble). 20 new words. 26 steps.
// =============================================
{id:"deu_r23l7",title:"Im Prüfungsraum",icon:"🕐",xp:15,board:true,steps:[
{type:"intro",title:"Im Prüfungsraum",desc:"Die Uhr tickt. Die Prüfungsbögen liegen umgedreht auf dem Tisch. Jetzt beginnt der Teil, für den Verumius monatelang gearbeitet hat.",goals:["Lerne deutsche Zeit- und Gradadverbien","Erlebe die Goethe-B1-Prüfung durch Verumius' Augen","Übe alle Grammatikkonstruktionen unter Prüfungsdruck"]},
{type:"story",speaker:"narrator",mood:"tense",art:"de-ber-goethe-exam",trg:"Verumius sitzt an seinem Platz. Das Herz klopft. Die Prüfungsbögen liegen umgedreht auf dem Tisch. Die Uhr tickt. Nun beginnt der Teil, für den er monatelang gearbeitet hat.",src:"Verumius sits at his desk. His heart pounds. The exam papers lie face down on the table. The clock ticks. Now begins the part he has worked toward for months."},
{type:"teach",trg:"allerdings",src:"however, admittedly",pos:"adv",gender:null,note:"Stronger than aber. Concedes a point.\nDie Prüfung ist fair, allerdings nicht einfach.",example:"A: Bist du vorbereitet?\nB: Ja, allerdings bin ich trotzdem nervös.\nA: Das ist normal, allerdings brauchst du dir keine Sorgen zu machen.\nB: Stimmt. Allerdings klopft mein Herz schnell.",exampleSrc:"A: Are you prepared?\nB: Yes, however I am still nervous.\nA: That is normal, although you do not need to worry.\nB: True. However, my heart is beating fast.",funFact:"Stronger than 'aber.' 'Die Prüfung ist fair, allerdings nicht einfach' (The exam is fair, however not easy). A connector that concedes a point while introducing a contrast. B1 writing gold."},
{type:"teach",trg:"bereits",src:"already (formal)",pos:"adv",gender:null,note:"More formal than schon.\nEr hat bereits drei Kapitel gelesen.",example:"A: Hast du bereits angefangen?\nB: Ja, ich habe bereits den ersten Teil gelesen.\nA: Du bist bereits weit gekommen.\nB: Stimmt, ich bin bereits bei Aufgabe fünf.",exampleSrc:"A: Have you already started?\nB: Yes, I have already read the first part.\nA: You have already come far.\nB: True, I am already at task five.",funFact:"More formal than 'schon.' Used in written German and formal speech. 'Bereits' signals that something happened sooner than expected. Exam register."},
{type:"teach",trg:"bisher",src:"so far, until now",pos:"adv",gender:null,note:"Bis (until) + her (to here).\nBisher hat alles geklappt = So far everything has worked out.",example:"A: Wie lief die Prüfung bisher?\nB: Bisher gut. Kein Problem bisher.\nA: Bisher hast du alles richtig.\nB: Hoffentlich bleibt es so. Bisher bin ich zufrieden.",exampleSrc:"A: How has the exam been going so far?\nB: So far good. No problems so far.\nA: So far you have everything correct.\nB: Hopefully it stays that way. So far I am satisfied.",funFact:"Bis (until) + her (to here). Limits the timeframe to the present moment. What has happened up to now, with no promise about what comes next."},
{type:"teach",trg:"inzwischen",src:"meanwhile, by now",pos:"adv",gender:null,note:"In + zwischen (between).\nInzwischen spricht er gut Deutsch = By now he speaks good German.",example:"A: Inzwischen ist eine Stunde vergangen.\nB: Schon? Inzwischen habe ich viel geschafft.\nA: Inzwischen bist du viel ruhiger.\nB: Stimmt, inzwischen fühle ich mich sicher.",exampleSrc:"A: Meanwhile, one hour has passed.\nB: Already? By now I have accomplished a lot.\nA: By now you are much calmer.\nB: True, by now I feel confident.",funFact:"In + zwischen (between). Marks a change over time. What has developed in the space between then and now. A year ago, Verumius struggled. Inzwischen spricht er gut Deutsch."},
{type:"teach",trg:"mittlerweile",src:"meanwhile, in the meantime",pos:"adv",gender:null,note:"Mittler (middle) + Weile (while).\nSynonym of inzwischen, slightly more literary.",example:"A: Mittlerweile versteht er fast alles.\nB: Ja, mittlerweile ist sein Deutsch sehr gut.\nA: Mittlerweile kann er sogar Witze verstehen.\nB: Das ist ein gutes Zeichen. Mittlerweile gehört er dazu.",exampleSrc:"A: By now he understands almost everything.\nB: Yes, by now his German is very good.\nA: By now he can even understand jokes.\nB: That is a good sign. By now he belongs.",funFact:"Mittler (middle) + Weile (while). Synonym of inzwischen, slightly more literary. Both mark the passage of time and the changes it brings."},
{type:"teach",trg:"kaum",src:"hardly, barely",pos:"adv",gender:null,note:"Er kann kaum glauben = He can hardly believe.\nAlso: kaum...da (no sooner...than).",example:"A: Er kann es kaum glauben.\nB: Kaum zu glauben, oder?\nA: Kaum hatte er angefangen, war er schon fertig.\nB: Er hat kaum Fehler gemacht.",exampleSrc:"A: He can hardly believe it.\nB: Hard to believe, right?\nA: No sooner had he started, he was already finished.\nB: He hardly made any mistakes.",funFact:"'Kaum' is powerful in storytelling: 'Kaum hatte er angefangen, da klingelte es' (No sooner had he started, the bell rang). Creates suspense and surprise in a single word."},
{type:"teach",trg:"nun",src:"now (formal/literary)",pos:"adv",gender:null,note:"More formal than jetzt. Nun geht es los = Now it begins.\nAlso a discourse marker: Nun, was meinen Sie?",example:"A: Nun beginnt die Prüfung.\nB: Ja, nun ist es so weit.\nA: Nun, wie fühlen Sie sich?\nB: Nun bin ich bereit. Nun geht es los!",exampleSrc:"A: Now the exam begins.\nB: Yes, now the time has come.\nA: Well, how do you feel?\nB: Now I am ready. Now it starts!",funFact:"More formal/literary than 'jetzt.' 'Nun geht es los' (Now it begins). Also a discourse marker: 'Nun, was meinen Sie?' (Well, what do you think?). Adds gravitas to any moment."},
{type:"teach",trg:"etwa",src:"approximately, perhaps",pos:"adv",gender:null,note:"Etwa 60 Minuten = approximately 60 minutes.\nRhetorical: Hast du etwa geschlafen? = Did you perhaps sleep?",example:"A: Wie lange dauert die Prüfung?\nB: Etwa vier Stunden insgesamt.\nA: Hast du etwa Angst?\nB: Nein! Na ja, etwa ein bisschen.",exampleSrc:"A: How long does the exam last?\nB: Approximately four hours in total.\nA: Are you perhaps afraid?\nB: No! Well, perhaps a little.",funFact:"Two meanings: approximation ('etwa 60 Minuten') and rhetorical surprise ('Hast du etwa geschlafen?' implies shock). The rhetorical etwa is a powerful B1 tool for expressing disbelief."},
{type:"teach",trg:"insgesamt",src:"in total, altogether",pos:"adv",gender:null,note:"Ins (into) + gesamt (entire).\nInsgesamt 210 Wörter = 210 words in total.",example:"A: Wie viele Aufgaben gibt es insgesamt?\nB: Insgesamt dreißig Aufgaben.\nA: Und wie viele Punkte insgesamt?\nB: Insgesamt hundert Punkte.",exampleSrc:"A: How many tasks are there in total?\nB: Thirty tasks in total.\nA: And how many points in total?\nB: One hundred points in total.",funFact:"Ins (into) + gesamt (entire). A word for summing up. 'Insgesamt war die Prüfung fair' (Overall, the exam was fair). Exam writing and formal German love this word."},
{type:"teach",trg:"höchstens",src:"at most",pos:"adv",gender:null,note:"Höchst (highest) + -ens (at). Sets the upper limit.\nHöchstens 20 Minuten = at most 20 minutes.",example:"A: Wie viele Fehler darf man machen?\nB: Höchstens zehn Fehler.\nA: Höchstens zwei Fehler im Sprechen-Teil.\nB: Das ist streng. Höchstens zwei!",exampleSrc:"A: How many mistakes can you make?\nB: At most ten mistakes.\nA: At most two mistakes in the speaking part.\nB: That is strict. At most two!",funFact:"Höchst (highest) + -ens (at). The ceiling. Sets the upper limit. 'Höchstens zwei Fehler' (at most two mistakes). The word that defines what is still acceptable."},
{type:"teach",trg:"beinah",src:"almost, nearly",pos:"adv",gender:null,note:"Bei (by/near) + nah (near).\nShortened form of beinahe. Spoken German prefers this.",example:"A: Ich hätte beinah den Wecker verschlafen!\nB: Beinah! Das wäre schlimm gewesen.\nA: Beinah hätte ich die Prüfung verpasst.\nB: Aber nur beinah. Du bist pünktlich.",exampleSrc:"A: I almost overslept the alarm!\nB: Almost! That would have been bad.\nA: I almost missed the exam.\nB: But only almost. You are on time.",funFact:"Bei (by/near) + nah (near). Shortened form of beinahe. Spoken German prefers the short form. The word for when disaster was close but did not quite arrive."},
{type:"teach",trg:"beinahe",src:"almost, nearly",pos:"adv",gender:null,note:"The full form of beinah.\nWritten German prefers this form. Same meaning.",example:"A: Er hätte beinahe alle Punkte bekommen.\nB: Beinahe perfekt!\nA: Beinahe hundert Prozent.\nB: Beinahe ist beeindruckend genug.",exampleSrc:"A: He almost got all the points.\nB: Almost perfect!\nA: Almost one hundred percent.\nB: Almost is impressive enough.",funFact:"The full form of beinah. Written German prefers the full form 'beinahe,' spoken German prefers the short form 'beinah.' Same meaning, different register. Context decides."},
{type:"teach",trg:"jemals",src:"ever",pos:"adv",gender:null,note:"Je (ever) + -mals (times).\nUsually in questions or superlatives.",example:"A: Hast du jemals eine Prüfung nicht bestanden?\nB: Nein, noch nie. Und du?\nA: Das ist die schwierigste Prüfung, die ich jemals geschrieben habe.\nB: Wenn du jemals Hilfe brauchst, frag mich.",exampleSrc:"A: Have you ever failed an exam?\nB: No, never. And you?\nA: This is the hardest exam I have ever written.\nB: If you ever need help, ask me.",funFact:"Je (ever) + -mals (times). Usually in questions or superlatives: 'Die schwierigste Prüfung, die ich jemals geschrieben habe' (The hardest exam I have ever written). The word for lifetime firsts."},
{type:"teach",trg:"jederzeit",src:"at any time, anytime",pos:"adv",gender:null,note:"Jeder (every) + Zeit (time).\nDu kannst jederzeit fragen = You can ask at any time.",example:"A: Kann ich jederzeit zur Prüfung kommen?\nB: Nein, nur zu den angemeldeten Terminen.\nA: Aber fragen kann ich jederzeit?\nB: Ja, jederzeit! Jederzeit gern.",exampleSrc:"A: Can I come to the exam at any time?\nB: No, only at registered dates.\nA: But I can ask at any time?\nB: Yes, anytime! Anytime with pleasure.",funFact:"Jeder (every) + Zeit (time). 'Jederzeit gern!' (Anytime, gladly!). A warm, open invitation word. It promises availability without conditions."},
{type:"teach",trg:"jeweils",src:"in each case, respectively",pos:"adv",gender:null,note:"Formal. Exam instructions use it.\nJeweils 20 Minuten pro Abschnitt.",example:"A: Markieren Sie jeweils die richtige Antwort.\nB: Jeweils eine Antwort pro Frage?\nA: Ja, jeweils nur eine.\nB: Verstanden. Jeweils eine Antwort.",exampleSrc:"A: Mark the correct answer in each case.\nB: One answer per question in each case?\nA: Yes, only one in each case.\nB: Understood. One answer each.",funFact:"Formal. Exam instructions love it: 'Markieren Sie jeweils die richtige Antwort' (Mark the correct answer in each case). A precision word for structured tasks."},
{type:"teach",trg:"nachher",src:"afterwards, later",pos:"adv",gender:null,note:"Nach (after) + her (to here). Casual.\nBis nachher! = See you later!",example:"A: Was machst du nachher?\nB: Nachher gehe ich feiern!\nA: Bis nachher!\nB: Ja, bis nachher! Erst die Prüfung, dann die Feier.",exampleSrc:"A: What are you doing afterwards?\nB: Afterwards I am going to celebrate!\nA: See you later!\nB: Yes, see you later! First the exam, then the party.",funFact:"Nach (after) + her (to here). Casual and warm. 'Bis nachher!' (See you later!). The promise of what comes after the exam. Verumius's motivation: nachher gibt es Kuchen."},
{type:"teach",trg:"längst",src:"long ago, long since",pos:"adv",gender:null,note:"Superlative of lang. Er hat längst alles gelernt.\nLängst vergessen = long forgotten.",example:"A: Hast du die Grammatik gelernt?\nB: Längst! Ich habe das längst verstanden.\nA: Gut, das solltest du längst können.\nB: Ja, das kann ich längst.",exampleSrc:"A: Did you learn the grammar?\nB: Long ago! I understood that long ago.\nA: Good, you should have been able to do that long ago.\nB: Yes, I have been able to do that for a long time.",funFact:"The superlative of 'lang.' 'Längst vergessen' (long forgotten). Emphasizes how far in the past something lies. Verumius hat längst alles gelernt, was er braucht."},
{type:"teach",trg:"mitten",src:"in the middle of",pos:"adv",gender:null,note:"Always followed by in + dative.\nMitten in der Prüfung = in the middle of the exam.",example:"A: Mitten in der Prüfung wurde es laut.\nB: Mitten in der Nacht hatte er noch gelernt.\nA: Mitten im Satz fiel ihm das Wort nicht ein.\nB: Das passiert jedem, mitten in der Aufregung.",exampleSrc:"A: In the middle of the exam, it became loud.\nB: In the middle of the night, he was still studying.\nA: In the middle of the sentence, the word did not come to him.\nB: That happens to everyone, in the middle of the excitement.",funFact:"Always followed by 'in' + dative. 'Mitten in der Nacht' (in the middle of the night). Places you right at the center of an event or moment. A powerful narrative word."},
{type:"teach",trg:"noch mal",src:"once more, again",pos:"adv",gender:null,note:"Noch (still) + mal (time). Written as two words.\nNoch mal lesen = to read once more.",example:"A: Sag das noch mal, bitte.\nB: Noch mal? Die Prüfung dauert vier Stunden.\nA: Lies den Text noch mal.\nB: Gut, ich lese ihn noch mal durch.",exampleSrc:"A: Say that once more, please.\nB: Once more? The exam lasts four hours.\nA: Read the text once more.\nB: Good, I will read through it once more.",funFact:"Noch (still) + mal (time). Written as two words. Informal. The exam gives you time to read noch mal. 'Sag das noch mal!' (Say that again!) is one of the most common German requests."},
{type:"teach",trg:"nochmals",src:"once again (formal)",pos:"adv",gender:null,note:"The formal version of noch mal. Written as one word.\nNochmals vielen Dank = Once again, many thanks.",example:"A: Nochmals vielen Dank für Ihre Hilfe.\nB: Gern geschehen. Nochmals viel Erfolg!\nA: Ich überprüfe nochmals meine Antworten.\nB: Gut, nochmals kontrollieren ist immer klug.",exampleSrc:"A: Once again, many thanks for your help.\nB: You are welcome. Once again, good luck!\nA: I will check my answers once again.\nB: Good, checking once again is always smart.",funFact:"The formal version of 'noch mal.' Written as one word. 'Nochmals vielen Dank' (Once again, many thanks). Exam and written register. Formality adds weight to the repetition."},
{type:"mc",q:"Verumius lernt seit einem Jahr Deutsch. Welcher Satz beschreibt seinen Fortschritt?",opts:["Höchstens spricht er gut Deutsch.","Mittlerweile spricht er gut Deutsch.","Längst spricht er schlecht Deutsch.","Nachher spricht er gut Deutsch."],ans:"Mittlerweile spricht er gut Deutsch.",hint:"Welches Wort bedeutet 'by now' und markiert Fortschritt über Zeit?"},
{type:"fb",s:"Die Prüfung dauert {1} vier Stunden.",a:["insgesamt"],opts:["insgesamt","höchstens","kaum","allerdings"],hint:"Which adverb means 'in total'?",sSrc:"The exam lasts four hours in total."},
{type:"mc",q:"'Wenn er nicht so gründlich gelernt hätte, würde er jetzt nervöser sein.' Was drückt dieser Satz aus?",opts:["Er ist zu nervös zum Lernen.","Er wird gründlich lernen und nervös werden.","Er hat nicht gelernt und ist nicht nervös.","Weil er gründlich gelernt hat, ist er weniger nervös."],ans:"Weil er gründlich gelernt hat, ist er weniger nervös.",hint:"Der irreale Bedingungssatz nennt eine irreale Bedingung: wenn er NICHT gelernt hätte. Die Realität ist das Gegenteil."},
{type:"drag_fill",s:"{1} hat Verumius {2} alles gelernt, was er braucht.",blanks:{"1":"Inzwischen","2":"längst"},pool:["Inzwischen","längst","kaum","nachher","bisher","allerdings"],hint:"By now + long ago: er hat längst alles gelernt, was er braucht.",sSrc:"By now, Verumius has long since learned everything he needs."}
]},

// =============================================
// Lesson 8: Die großen Wörter (The Big Words)
// Type: Heavy quiz + vocab (bubble). 20 new words. 26 steps.
// Conjunctions and connectors.
// =============================================
{id:"deu_r23l8",title:"Die großen Wörter",icon:"🔗",xp:15,board:true,steps:[
{type:"intro",title:"Die großen Wörter",desc:"Conjunctions and connectors: the building blocks of complex German sentences. Learn to link ideas logically and build elegant sentences for the writing section.",goals:["Master advanced conjunctions and connectors","Link ideas into complex, flowing German sentences","Prepare for the writing section of the Goethe exam"]},
{type:"tip",title:"einerseits...andererseits / zwar...aber",text:"einerseits...andererseits = on one hand...on the other hand\nKann in Position 1 (mit Inversion) oder Mitte stehen.\n\nzwar...aber = zwar (admittedly)...aber (but)\nzwar steht IMMER im Mittelfeld (nie Position 1):\nEr ist zwar nett, aber unzuverlässig.\n\nim Gegensatz zu = in contrast to (nimmt DATIV):\nim Gegensatz zu meinem Bruder\nim Gegensatz zur Situation (zu + der = zur)"},
{type:"tip",title:"Das Konzessionsmuster",text:"Unverzichtbar für B1-Aufsätze und Schreibaufgaben:\n\n1. Zugestehen: Zwar / Obwohl / Es stimmt, dass...\n2. Widerlegen: aber / trotzdem / dennoch / nichtsdestotrotz\n3. Schlussfolgerung: Daher / Folglich / Aus diesem Grund\n\nZeigt, dass du BEIDE Seiten sehen kannst.",deepDive:{title:"nichtsdestotrotz",text:"nichtsdestotrotz (nevertheless) = nichts + desto + trotz.\nGültig in formeller Schriftsprache. dennoch ist kürzer und ebenso formell.\n\nBeispiel:\n'Es stimmt, dass die Kosten hoch sind.\nNichtsdestotrotz überwiegen die Vorteile.\nDaher empfehle ich das Projekt.'"}},
{type:"teach",trg:"bevor",src:"before",pos:"conj",gender:null,note:"Nebensatz conjunction: verb goes to the end.\nDifferent from vor (preposition).",example:"A: Bevor du die Prüfung schreibst, atme tief ein.\nB: Das mache ich immer, bevor ich anfange.\nA: Bevor es losgeht, lies die Hinweise.\nB: Guter Tipp. Bevor ich starte, lese ich alles.",exampleSrc:"A: Before you write the exam, take a deep breath.\nB: I always do that before I start.\nA: Before it begins, read the instructions.\nB: Good tip. Before I start, I read everything.",funFact:"Be- + vor (before). Nebensatz conjunction: the verb goes to the end of the clause. Different from 'vor' (preposition). 'Bevor du gehst...' sends the verb to the end."},
{type:"teach",trg:"da",src:"since, because (formal)",pos:"conj",gender:null,note:"Synonym of weil but more formal. Da + Nebensatz.\nCan start a sentence. Also means 'there.'",example:"A: Da er gut vorbereitet ist, ist er ruhig.\nB: Da stimme ich zu.\nA: Da du hier bist, können wir anfangen.\nB: Gut, da alle da sind, geht es los.",exampleSrc:"A: Since he is well prepared, he is calm.\nB: I agree with that.\nA: Since you are here, we can start.\nB: Good, since everyone is here, let us begin.",funFact:"Synonym of 'weil' but more formal. 'Da' can start a sentence, 'weil' usually cannot in formal writing. Also means 'there.' A tiny word with two big jobs."},
{type:"teach",trg:"damit",src:"so that, in order that",pos:"conj",gender:null,note:"Nebensatz: verb at end. Allows different subjects.\nDifferent from um...zu (same subject only).",example:"A: Er übt, damit er die Prüfung besteht.\nB: Ich lerne Deutsch, damit mein Chef mich versteht.\nA: Sprich langsam, damit ich folgen kann.\nB: Gut, ich spreche langsam, damit du alles verstehst.",exampleSrc:"A: He practices so that he passes the exam.\nB: I learn German so that my boss understands me.\nA: Speak slowly so that I can follow.\nB: Good, I speak slowly so that you understand everything.",funFact:"Nebensatz conjunction. 'Damit' allows different subjects in each clause, unlike 'um...zu' which requires the same subject. A crucial distinction for B1 writing."},
{type:"teach",trg:"nachdem",src:"after",pos:"conj",gender:null,note:"Requires a tense shift: nachdem-clause uses a more past tense.\nNachdem er bestanden hat, feiert er.",example:"A: Nachdem er die Prüfung bestanden hat, feiert er.\nB: Nachdem wir gegessen haben, gehen wir spazieren.\nA: Was machst du, nachdem du fertig bist?\nB: Nachdem ich fertig bin, rufe ich meine Familie an.",exampleSrc:"A: After he has passed the exam, he celebrates.\nB: After we have eaten, we go for a walk.\nA: What do you do after you are finished?\nB: After I am finished, I call my family.",funFact:"Nach (after) + dem. Requires a tense shift: the nachdem-clause uses a 'more past' tense than the main clause. Perfekt in nachdem, Präsens in main clause. A unique German timing rule."},
{type:"teach",trg:"obwohl",src:"although",pos:"conj",gender:null,note:"Nebensatz conjunction. The concession word.\nObwohl er müde ist, lernt er weiter.",example:"A: Obwohl er müde ist, lernt er weiter.\nB: Obwohl die Prüfung schwer war, hat er bestanden.\nA: Obwohl es regnet, gehen wir raus.\nB: Obwohl ich nervös bin, fühle ich mich bereit.",exampleSrc:"A: Although he is tired, he keeps studying.\nB: Although the exam was hard, he passed.\nA: Although it is raining, we go out.\nB: Although I am nervous, I feel ready.",funFact:"Ob (whether) + wohl (well). The concession word. 'I know this is true, but still...' Nebensatz conjunction with verb at the end. A mainstay of sophisticated German writing."},
{type:"teach",trg:"falls",src:"in case, if",pos:"conj",gender:null,note:"More conditional than wenn (which also means when).\nFalls is purely hypothetical.",example:"A: Falls du Fragen hast, frag mich.\nB: Falls ich nicht bestehe, versuche ich es noch mal.\nA: Falls es regnet, bleiben wir drinnen.\nB: Gut, falls der Fall eintritt, sind wir vorbereitet.",exampleSrc:"A: In case you have questions, ask me.\nB: In case I do not pass, I will try again.\nA: In case it rains, we stay inside.\nB: Good, in case that happens, we are prepared.",funFact:"Fall (case) + -s. More conditional than 'wenn' (which also means 'when'). 'Falls' is purely hypothetical. It marks a possibility, not an expectation."},
{type:"teach",trg:"sobald",src:"as soon as",pos:"conj",gender:null,note:"So (so) + bald (soon). The trigger word.\nSobald die Prüfung beginnt, bin ich konzentriert.",example:"A: Sobald die Prüfung beginnt, bin ich konzentriert.\nB: Sobald ich das Ergebnis habe, rufe ich dich an.\nA: Sobald du fertig bist, gehen wir.\nB: Gut, sobald ich den letzten Satz schreibe.",exampleSrc:"A: As soon as the exam starts, I am focused.\nB: As soon as I have the result, I will call you.\nA: As soon as you are done, we go.\nB: Good, as soon as I write the last sentence.",funFact:"So (so) + bald (soon). The trigger word: the moment X happens, Y begins. 'Sobald die Prüfung beginnt, bin ich konzentriert.' Immediate cause and effect."},
{type:"teach",trg:"solange",src:"as long as",pos:"conj",gender:null,note:"So (so) + lange (long). Duration with a condition.\nSolange ich lebe, lerne ich.",example:"A: Solange ich lebe, lerne ich.\nB: Solange du übst, wirst du besser.\nA: Solange die Prüfung dauert, bin ich konzentriert.\nB: Solange es Kaffee gibt, schaffe ich alles.",exampleSrc:"A: As long as I live, I learn.\nB: As long as you practice, you will get better.\nA: As long as the exam lasts, I am focused.\nB: As long as there is coffee, I can do anything.",funFact:"So (so) + lange (long). Duration with a condition. Time-bound conditions. 'Solange du übst, wirst du besser' (As long as you practice, you will get better). The patience conjunction."},
{type:"teach",trg:"sodass",src:"so that (result)",pos:"conj",gender:null,note:"So + dass. Introduces a RESULT, not a purpose.\nCompare: damit (purpose) vs. sodass (result).",example:"A: Er hat gründlich gelernt, sodass er gut vorbereitet ist.\nB: Sie hat viel geübt, sodass sie sicher spricht.\nA: Der Text war klar, sodass ich alles verstanden habe.\nB: Gut, sodass du keine Probleme hattest.",exampleSrc:"A: He studied thoroughly, so that he is well prepared.\nB: She practiced a lot, so that she speaks confidently.\nA: The text was clear, so that I understood everything.\nB: Good, so that you had no problems.",funFact:"So + dass. Introduces a RESULT, not a purpose. Compare: damit (purpose, what you AIM for) vs. sodass (result, what HAPPENED). A subtle but important B1 distinction."},
{type:"teach",trg:"indem",src:"by (doing)",pos:"conj",gender:null,note:"In + dem. The method conjunction.\nMan lernt Sprachen, indem man sie spricht.",example:"A: Wie lernt man am besten?\nB: Indem man jeden Tag übt.\nA: Man verbessert sich, indem man Fehler macht.\nB: Richtig. Indem wir sprechen, lernen wir.",exampleSrc:"A: How does one learn best?\nB: By practicing every day.\nA: One improves by making mistakes.\nB: Right. By speaking, we learn.",funFact:"In + dem. The method conjunction. How you achieve something. 'Man lernt Sprachen, indem man sie spricht.' Unique to German; English uses 'by + gerund.' A word that shows the path."},
{type:"teach",trg:"ob",src:"whether",pos:"conj",gender:null,note:"Introduces indirect questions.\nIch frage mich, ob ich bestehe.",example:"A: Ich frage mich, ob ich bestehe.\nB: Ob er kommt oder nicht, ist egal.\nA: Weißt du, ob die Ergebnisse da sind?\nB: Nein, ob sie heute kommen, weiß ich nicht.",exampleSrc:"A: I wonder whether I will pass.\nB: Whether he comes or not does not matter.\nA: Do you know whether the results are there?\nB: No, whether they come today, I do not know.",funFact:"Introduces indirect questions. Short, common, essential. 'Ob er kommt oder nicht' (Whether he comes or not). Turns direct questions into embedded clauses."},
{type:"teach",trg:"entweder",src:"either",pos:"conj",gender:null,note:"Always paired with oder. The binary choice.\nEntweder du bestehst oder du versuchst es noch mal.",example:"A: Entweder du bestehst oder du versuchst es noch mal.\nB: Entweder heute oder nie!\nA: Entweder die Grammatik sitzt oder nicht.\nB: Bei mir sitzt sie. Entweder alles oder nichts!",exampleSrc:"A: Either you pass or you try again.\nB: Either today or never!\nA: Either the grammar is solid or not.\nB: Mine is solid. Either everything or nothing!",funFact:"Always paired with 'oder' (or). The binary choice structure. 'Entweder...oder' forces a decision between exactly two options. No middle ground."},
{type:"teach",trg:"weder",src:"neither",pos:"conj",gender:null,note:"Always paired with noch (nor). Negates both options.\nWeder müde noch nervös = Neither tired nor nervous.",example:"A: Er ist weder müde noch nervös.\nB: Weder kalt noch warm.\nA: Weder zu schwer noch zu leicht.\nB: Die perfekte Prüfung: weder zu lang noch zu kurz.",exampleSrc:"A: He is neither tired nor nervous.\nB: Neither cold nor warm.\nA: Neither too hard nor too easy.\nB: The perfect exam: neither too long nor too short.",funFact:"Always paired with 'noch' (nor). 'Weder...noch' negates both options. Double negation without being grammatically wrong. The opposite of 'sowohl...als auch.'"},
{type:"teach",trg:"sowohl",src:"both",pos:"conj",gender:null,note:"Always paired with als auch (as well as).\nSowohl mündlich als auch schriftlich.",example:"A: Die Prüfung testet sowohl Grammatik als auch Wortschatz.\nB: Sowohl mündlich als auch schriftlich.\nA: Sowohl leicht als auch schwierig.\nB: Sowohl stressig als auch aufregend!",exampleSrc:"A: The exam tests both grammar and vocabulary.\nB: Both orally and in writing.\nA: Both easy and difficult.\nB: Both stressful and exciting!",funFact:"Always paired with 'als auch' (as well as). 'Sowohl mündlich als auch schriftlich' (Both orally and in writing). Inclusive: not one or the other, but both. The B1 writing upgrade."},
{type:"teach",trg:"sondern",src:"but rather",pos:"conj",gender:null,note:"Stronger than aber. Only after a negation.\nNicht schwer, sondern anspruchsvoll.",example:"A: Die Prüfung ist nicht schwer, sondern fair.\nB: Nicht unmöglich, sondern machbar.\nA: Ich bin nicht nervös, sondern aufgeregt.\nB: Nicht Angst, sondern Respekt!",exampleSrc:"A: The exam is not hard, but rather fair.\nB: Not impossible, but rather doable.\nA: I am not nervous, but rather excited.\nB: Not fear, but rather respect!",funFact:"Stronger than 'aber.' Used ONLY after a negation. 'Nicht schwer, sondern anspruchsvoll' (Not hard, but rather demanding). Corrects a misconception. The 'actually' of German conjunctions."},
{type:"teach",trg:"trotzdem",src:"nevertheless",pos:"adv",gender:null,note:"Trotz (despite) + dem. Adverbial connector.\nMain clause word order after trotzdem.",example:"A: Die Prüfung ist schwer. Trotzdem gibt er nicht auf.\nB: Er ist müde. Trotzdem lernt er weiter.\nA: Es regnet. Trotzdem gehen wir.\nB: Ich bin nervös. Trotzdem bin ich bereit.",exampleSrc:"A: The exam is hard. Nevertheless he does not give up.\nB: He is tired. Nevertheless he keeps studying.\nA: It is raining. Nevertheless we go.\nB: I am nervous. Nevertheless I am ready.",funFact:"Trotz (despite) + dem. Adverbial connector with main clause word order (V2). Different from 'obwohl' (Nebensatz with verb-final). Same meaning, different structure. Knowing both is B1 mastery."},
{type:"teach",trg:"jedoch",src:"however (formal)",pos:"conj",gender:null,note:"More formal than aber.\nDie Aufgabe ist lang, jedoch machbar.",example:"A: Die Aufgabe ist lang, jedoch machbar.\nB: Die Prüfung ist anspruchsvoll, jedoch fair.\nA: Er ist jung, jedoch erfahren.\nB: Schwierig, jedoch nicht unmöglich.",exampleSrc:"A: The task is long, however doable.\nB: The exam is demanding, however fair.\nA: He is young, however experienced.\nB: Difficult, however not impossible.",funFact:"More formal than 'aber.' Written German and formal register. The Goethe Schreiben section rewards the use of 'jedoch' over 'aber.' Formality earns points."},
{type:"teach",trg:"nämlich",src:"namely, because (you see)",pos:"adv",gender:null,note:"Post-verbal position. Explains after the statement.\nEr ist müde, er hat nämlich nicht geschlafen.",example:"A: Er ist müde. Er hat nämlich nicht geschlafen.\nB: Ich bin nervös, ich schreibe nämlich eine Prüfung.\nA: Sie ist gut, sie hat nämlich viel geübt.\nB: Das erklärt alles. Er konnte nämlich nicht kommen.",exampleSrc:"A: He is tired. He has not slept, you see.\nB: I am nervous; I am writing an exam, you see.\nA: She is good; she has practiced a lot, you see.\nB: That explains everything. He was not able to come, you see.",funFact:"Post-verbal position. Explains the reason AFTER the statement. Unique German word order. 'Er ist müde, er hat nämlich nicht geschlafen' (He is tired; he has not slept, you see). Conversational explanation."},
{type:"teach",trg:"zwar",src:"indeed, admittedly",pos:"adv",gender:null,note:"Always paired with aber or jedoch.\nZwar ist die Prüfung schwer, aber machbar.",example:"A: Zwar ist die Prüfung schwer, aber machbar.\nB: Er ist zwar nervös, aber gut vorbereitet.\nA: Zwar habe ich Angst, jedoch bin ich bereit.\nB: Zwar lang, aber interessant!",exampleSrc:"A: Admittedly, the exam is hard, but doable.\nB: He is admittedly nervous, but well prepared.\nA: Admittedly I am afraid, however I am ready.\nB: Admittedly long, but interesting!",funFact:"Always paired with 'aber' or 'jedoch.' The concession before the counter-argument. 'Zwar...aber' is the signature structure of sophisticated B1 writing. Concede, then counter."},
{type:"teach",trg:"ebenfalls",src:"likewise, also (formal)",pos:"adv",gender:null,note:"Eben (even) + falls (case). More elegant than auch.\nIch wünsche Ihnen ebenfalls viel Erfolg.",example:"A: Ich wünsche Ihnen viel Erfolg.\nB: Danke, Ihnen ebenfalls!\nA: Mir hat die Prüfung gefallen. Ihnen ebenfalls?\nB: Ja, mir ebenfalls. Danke ebenfalls!",exampleSrc:"A: I wish you much success.\nB: Thank you, likewise!\nA: I enjoyed the exam. You too?\nB: Yes, me too. Thanks likewise!",funFact:"Eben (even) + falls (case). More elegant than 'auch.' 'Danke, ebenfalls!' (Thanks, likewise!) is a common polite response. Written register. Formality with warmth."},
{type:"mc",q:"Er lernt viel, _____ er die Prüfung besteht.",opts:["bevor","sodass","damit","obwohl"],ans:"damit",hint:"He studies so that he WILL pass. Which conjunction expresses purpose?"},
{type:"mc",q:"Die Prüfung ist nicht einfach, _____ anspruchsvoll.",opts:["sondern","jedoch","aber","trotzdem"],ans:"sondern",hint:"After a negation (nicht), which word means 'but rather'?"},
{type:"fb",s:"{1} die Prüfung beginnt, liest Verumius die Hinweise.",a:["Bevor"],opts:["Bevor","Nachdem","Sobald","Solange"],hint:"Which conjunction means 'before'?",sSrc:"Before the exam starts, Verumius reads the instructions."},
{type:"match",pairs:[{trg:"obwohl",src:"although"},{trg:"nachdem",src:"after"},{trg:"sobald",src:"as soon as"},{trg:"indem",src:"by (doing)"}]},
{type:"drag_fill",s:"{1} er gut vorbereitet ist, {2} er trotzdem nervös.",blanks:{"1":"Obwohl","2":"ist"},pool:["Obwohl","Weil","ist","hat","bleibt","Nachdem"],hint:"Although he is prepared, he IS still nervous. Obwohl = Nebensatz (verb at end), main clause = normal V2.",sSrc:"Although he is well prepared, he is still nervous."}
]},

// =============================================
// Lesson 9: BESTANDEN! (PASSED!)
// Type: Story resolution + quiz (cinematic/bubble). 20 new words. 26 steps.
// =============================================
{id:"deu_r23l9",title:"BESTANDEN!",icon:"🎉",xp:15,board:true,steps:[
{type:"intro",title:"BESTANDEN!",desc:"Das Ergebnis steht fest: BESTANDEN! Verumius hat die Goethe-B1-Prüfung bestanden. Zeit zu feiern, mit allen zusammen im Biergarten.",goals:["Lerne Adverbien der Begründung und des Grades","Erlebe den Moment der Prüfungsergebnisse","Feiere mit dem gesamten Cast im Biergarten"]},
{type:"story",speaker:"narrator",mood:"triumph",art:"de-ber-goethe-hallway",trg:"Verumius steht im Flur des Goethe-Instituts. Seine Augen suchen die Liste. Sein Finger gleitet über die Namen. Da: sein Name. Daneben ein einziges Wort: BESTANDEN. Er ballt die Faust.",src:"Verumius stands in the hallway of the Goethe-Institut. His eyes scan the list. His finger slides across the names. There: his name. Beside it, a single word: PASSED. He clenches his fist."},
{type:"teach",trg:"deswegen",src:"therefore, that is why",pos:"adv",gender:null,note:"Des (of that) + wegen (because of). Causal connector.\nMain clause word order after deswegen.",example:"A: Er hat viel gelernt, deswegen hat er bestanden.\nB: Deswegen bin ich hier: um zu feiern!\nA: Deswegen ist er so glücklich.\nB: Ja, deswegen strahlt er.",exampleSrc:"A: He studied a lot, that is why he passed.\nB: That is why I am here: to celebrate!\nA: That is why he is so happy.\nB: Yes, that is why he is beaming.",funFact:"Des (of that) + wegen (because of). Causal connector with V2 word order in the main clause. Stronger than 'deshalb' in some dialects. The word that connects cause and effect."},
{type:"teach",trg:"ebenso",src:"equally, just as",pos:"adv",gender:null,note:"Eben (even) + so (so). Formal comparison.\nEbenso wichtig wie = equally important as.",example:"A: Er ist ebenso stolz wie glücklich.\nB: Das Schreiben war ebenso schwer wie das Hören.\nA: Ebenso gut!\nB: Ja, alle Teile waren ebenso fair.",exampleSrc:"A: He is equally proud as he is happy.\nB: The writing was equally hard as the listening.\nA: Equally good!\nB: Yes, all parts were equally fair.",funFact:"Eben (even/just) + so (so). Formal register. 'Ebenso wichtig wie Grammatik ist Vokabelarbeit' (Equally important as grammar is vocabulary work). Comparison without the full 'genauso...wie' structure."},
{type:"teach",trg:"genauso",src:"just as, exactly as",pos:"adv",gender:null,note:"Genau (exact) + so (so). Less formal than ebenso.\nGenauso gut = just as good.",example:"A: Er ist genauso nervös wie beim ersten Mal.\nB: Und genauso gut vorbereitet.\nA: Genauso aufgeregt wie am ersten Tag.\nB: Genauso stolz wie seine Freunde.",exampleSrc:"A: He is just as nervous as the first time.\nB: And just as well prepared.\nA: Just as excited as on the first day.\nB: Just as proud as his friends.",funFact:"Genau (exact) + so (so). Less formal than ebenso. 'Genauso gut' (just as good). Precise comparison in everyday speech."},
{type:"teach",trg:"weshalb",src:"for which reason, why (formal)",pos:"adv",gender:null,note:"More formal than warum.\nWeshalb hast du so viel gelernt?",example:"A: Weshalb hast du so viel gelernt?\nB: Weshalb? Weil ich bestehen wollte!\nA: Weshalb bist du nach Deutschland gekommen?\nB: Weshalb? Das ist eine lange Geschichte.",exampleSrc:"A: Why did you study so much?\nB: Why? Because I wanted to pass!\nA: Why did you come to Germany?\nB: Why? That is a long story.",funFact:"More formal than 'warum.' Three words for 'why': wieso (casual), warum (neutral), weshalb (formal). Knowing all three shows B1 register awareness."},
{type:"teach",trg:"wieso",src:"why, how come",pos:"adv",gender:null,note:"From wie so (how so). More casual than warum.\nWieso nicht? = Why not?",example:"A: Wieso bist du so glücklich?\nB: Wieso? Weil ich bestanden habe!\nA: Wieso nicht feiern?\nB: Genau! Wieso nicht sofort feiern?",exampleSrc:"A: How come you are so happy?\nB: How come? Because I passed!\nA: Why not celebrate?\nB: Exactly! Why not celebrate right away?",funFact:"From 'wie so' (how so). The most casual of the three 'why' words. 'Wieso nicht?' (Why not?) is conversational and light. Verumius uses it when he is in a good mood."},
{type:"teach",trg:"daher",src:"therefore, from there",pos:"adv",gender:null,note:"Da (there) + her (from here). Direction and causality.\nDaher kommt sein Erfolg = That is where his success comes from.",example:"A: Er hat hart gearbeitet, daher sein Erfolg.\nB: Daher kennt er so viele Wörter.\nA: Daher ist er so selbstbewusst.\nB: Daher die Feier heute Abend!",exampleSrc:"A: He worked hard, hence his success.\nB: That is why he knows so many words.\nA: That is why he is so confident.\nB: Hence the celebration this evening!",funFact:"Da (there) + her (from here). Direction and causality in one word. 'Daher kommt sein Erfolg' (That is where his success comes from). Also: 'Daher hat er bestanden' (Therefore he passed)."},
{type:"teach",trg:"seitdem",src:"since then",pos:"adv",gender:null,note:"Seit (since) + dem (that). Conjunction or adverb.\nSeitdem er in Deutschland ist, lernt er Deutsch.",example:"A: Seitdem er in Deutschland ist, lernt er Deutsch.\nB: Seitdem hat sich viel verändert.\nA: Seitdem er angefangen hat, hat er nie aufgehört.\nB: Seitdem er hier ist, fühlt er sich zu Hause.",exampleSrc:"A: Since he has been in Germany, he has been learning German.\nB: Since then, a lot has changed.\nA: Since he started, he has never stopped.\nB: Since he has been here, he feels at home.",funFact:"Seit (since) + dem (that). Can be conjunction or adverb. Marks the starting point of a change. 'Seitdem er in Deutschland ist' (Since he has been in Germany). Time flows forward from seitdem."},
{type:"teach",trg:"teilweise",src:"partially, partly",pos:"adv",gender:null,note:"Teil (part) + -weise (way/manner).\nTeilweise richtig = partially correct.",example:"A: Die Antwort ist teilweise richtig.\nB: Nur teilweise? Was fehlt?\nA: Teilweise hast du recht, teilweise nicht.\nB: Also teilweise bestanden?",exampleSrc:"A: The answer is partially correct.\nB: Only partially? What is missing?\nA: You are partly right, partly not.\nB: So partially passed?",funFact:"Teil (part) + -weise (way/manner). Not all, not none: somewhere in between. 'Teilweise bewölkt' (partly cloudy). A word for nuance and degrees."},
{type:"teach",trg:"eher",src:"rather, sooner",pos:"adv",gender:null,note:"Comparative of eh (anyway).\nEher schwierig als einfach = Rather difficult than easy.",example:"A: War die Prüfung eher leicht oder eher schwer?\nB: Eher schwer, aber machbar.\nA: Je eher, desto besser.\nB: Stimmt, eher anfangen ist immer klug.",exampleSrc:"A: Was the exam rather easy or rather hard?\nB: Rather hard, but doable.\nA: The sooner, the better.\nB: True, starting sooner is always smart.",funFact:"Comparative of 'eh' (anyway). 'Eher schwierig als einfach' (Rather difficult than easy). 'Je eher, desto besser' (The sooner, the better). Subtle preference and gentle comparison."},
{type:"teach",trg:"eventuell",src:"possibly, perhaps",pos:"adv",gender:null,note:"FALSE FRIEND: does NOT mean 'eventually.'\nEventuell = possibly. Eventually = schließlich.",example:"A: Kommst du eventuell zur Feier?\nB: Eventuell, ich bin noch nicht sicher.\nA: Eventuell kommen noch mehr Leute.\nB: Eventuell regnet es, aber wir feiern trotzdem!",exampleSrc:"A: Are you possibly coming to the party?\nB: Possibly, I am not sure yet.\nA: Possibly more people will come.\nB: Possibly it will rain, but we celebrate anyway!",funFact:"FALSE FRIEND: does NOT mean 'eventually' (that is 'schließlich'). 'Eventuell' means 'possibly.' One of the most dangerous false friends between English and German. Many learners fall into this trap."},
{type:"teach",trg:"offenbar",src:"apparently, evidently",pos:"adv",gender:null,note:"Offen (open) + -bar (able to be). Open to being seen.\nSuggests evidence without certainty.",example:"A: Offenbar hat er bestanden.\nB: Ja, offenbar war er gut vorbereitet.\nA: Offenbar hat sich die Arbeit gelohnt.\nB: Offenbar stimmt es: Übung macht den Meister.",exampleSrc:"A: Apparently he passed.\nB: Yes, apparently he was well prepared.\nA: Apparently the work paid off.\nB: Apparently it is true: practice makes the master.",funFact:"Offen (open) + -bar (able to be). Open to being seen: apparent. Suggests evidence without absolute certainty. 'Offenbar' is the word for what seems clear but is not yet confirmed."},
{type:"teach",trg:"vermutlich",src:"presumably, probably",pos:"adv",gender:null,note:"From vermuten (to presume).\nStronger than vielleicht, weaker than sicher.",example:"A: Er hat vermutlich bestanden.\nB: Vermutlich ist er schon auf dem Weg.\nA: Vermutlich feiern sie im Biergarten.\nB: Vermutlich ja. Wo sonst?",exampleSrc:"A: He has presumably passed.\nB: Presumably he is already on the way.\nA: Presumably they are celebrating in the Biergarten.\nB: Presumably yes. Where else?",funFact:"From 'vermuten' (to presume). Educated guess. Stronger than 'vielleicht' (maybe), weaker than 'sicher' (certain). The word for when you are fairly sure but hedging."},
{type:"teach",trg:"ungefähr",src:"approximately",pos:"adv",gender:null,note:"Un- (not) + Gefahr (danger). Originally: without danger.\nMeaning shifted to rough/approximate.",example:"A: Wie lange hat die Prüfung gedauert?\nB: Ungefähr vier Stunden.\nA: Ungefähr wie viele Teilnehmer?\nB: Ungefähr zwanzig.",exampleSrc:"A: How long did the exam last?\nB: Approximately four hours.\nA: Approximately how many participants?\nB: Approximately twenty.",funFact:"Un- (not) + Gefahr (danger). Originally 'without danger/harmless,' shifted to 'rough/approximate.' The meaning journey from safety to estimation is uniquely German."},
{type:"teach",trg:"unterschiedlich",src:"different, varying",pos:"adj",gender:null,note:"From unterscheiden (to distinguish).\nUnterschiedliche Meinungen = differing opinions.",example:"A: Die Ergebnisse sind unterschiedlich.\nB: Ja, sehr unterschiedlich. Manche haben bestanden, manche nicht.\nA: Die Meinungen sind unterschiedlich.\nB: Stimmt, jeder hat unterschiedliche Erfahrungen.",exampleSrc:"A: The results are different.\nB: Yes, very different. Some passed, some did not.\nA: The opinions are different.\nB: True, everyone has different experiences.",funFact:"From 'unterscheiden' (to distinguish). 'Unterschiedliche Meinungen' (differing opinions). Academic vocabulary for describing variation and diversity."},
{type:"teach",trg:"interessant",src:"interesting",pos:"adj",gender:null,note:"From French interessant.\nInteressanterweise = interestingly.",example:"A: Die Prüfung war wirklich interessant.\nB: Interessant? Ich fand sie stressig!\nA: Interessanterweise war der Hören-Teil am leichtesten.\nB: Das ist interessant. Für mich war es das Lesen.",exampleSrc:"A: The exam was really interesting.\nB: Interesting? I found it stressful!\nA: Interestingly, the listening part was the easiest.\nB: That is interesting. For me, it was the reading.",funFact:"From French 'interessant.' Every German teacher's favorite compliment and filler word: 'Interessant!' It can mean genuine curiosity or polite deflection, depending on tone."},
{type:"teach",trg:"interessiert",src:"interested",pos:"adj",gender:null,note:"Past participle as adjective. Interessiert an + dative.\nInteressiert = the person. Interessant = the thing.",example:"A: Bist du an Deutschland interessiert?\nB: Ja, ich bin sehr interessiert an der Kultur.\nA: Woran bist du besonders interessiert?\nB: Ich bin an Sprachen interessiert.",exampleSrc:"A: Are you interested in Germany?\nB: Yes, I am very interested in the culture.\nA: What are you particularly interested in?\nB: I am interested in languages.",funFact:"Past participle used as adjective. 'Interessiert an' + dative. Common confusion: 'interessiert' describes the person who feels interest, 'interessant' describes the thing that generates interest."},
{type:"teach",trg:"neugierig",src:"curious",pos:"adj",gender:null,note:"Neu (new) + gierig (greedy). Greedy for the new.\nNeugierig auf + accusative.",example:"A: Bist du neugierig auf die Ergebnisse?\nB: Sehr neugierig! Ich kann es kaum erwarten.\nA: Neugierig sein ist gut fürs Lernen.\nB: Stimmt, neugierige Lerner sind die besten.",exampleSrc:"A: Are you curious about the results?\nB: Very curious! I can hardly wait.\nA: Being curious is good for learning.\nB: True, curious learners are the best.",funFact:"Neu (new) + gierig (greedy). Greedy for the new. The German word for curiosity reveals its nature: hunger for novelty. 'Neugierig auf die Ergebnisse' (Curious about the results)."},
{type:"teach",trg:"begrenzt",src:"limited",pos:"adj",gender:null,note:"From begrenzen (to limit). Be- + Grenze (border).\nBegrenzte Zeit = limited time.",example:"A: Die Zeit ist begrenzt.\nB: Ja, nur noch fünf Minuten. Sehr begrenzt.\nA: Mein Wortschatz ist noch begrenzt.\nB: Aber weniger begrenzt als vor einem Jahr!",exampleSrc:"A: The time is limited.\nB: Yes, only five more minutes. Very limited.\nA: My vocabulary is still limited.\nB: But less limited than a year ago!",funFact:"From 'begrenzen' (to limit). Be- + Grenze (border). 'Begrenzte Zeit' (limited time). Past participle as adjective. What has borders is begrenzt. What lies beyond the border is unlimited."},
{type:"teach",trg:"sichtbar",src:"visible",pos:"adj",gender:null,note:"Sicht (sight) + -bar (able to be).\nSichtbare Fortschritte = visible progress.",example:"A: Dein Fortschritt ist sichtbar!\nB: Wirklich? Der Fortschritt ist sichtbar?\nA: Ja, sehr sichtbar. Vor einem Jahr konntest du kaum sprechen.\nB: Danke! Sichtbare Ergebnisse motivieren.",exampleSrc:"A: Your progress is visible!\nB: Really? The progress is visible?\nA: Yes, very visible. A year ago you could barely speak.\nB: Thanks! Visible results motivate.",funFact:"Sicht (sight) + -bar (able to be). Able to be seen. 'Sichtbare Fortschritte' (visible progress). When your growth becomes sichtbar, even others can see it."},
{type:"story",speaker:"heinrich",mood:"warm-wise",art:"de-ber-biergarten-celebration",trg:"Heinrich kommt spät mit einem Laib Sauerteigbrot, in Stoff gewickelt. Er klopft Verumius auf die Schulter: 'Prüfungen kommen und gehen. Aber Brot bleibt.' Alle lachen.",src:"Heinrich arrives late with a loaf of sourdough bread wrapped in cloth. He claps Verumius on the shoulder: 'Exams come and go. But bread stays.' Everyone laughs."},
{type:"story",speaker:"heinrich",mood:"reflective",art:"de-ber-biergarten-celebration",trg:"Heinrich erzählt, wie er vor sechzig Jahren seine eigene Meisterprüfung nicht bestanden hat. 'Beim zweiten Mal war das Brot besser.' Verumius lächelt.",src:"Heinrich tells how he failed his own master baker's exam sixty years ago. 'The second time, the bread was better.' Verumius smiles."},
{type:"mc",q:"Verumius hat monatelang gelernt. _____ hat er die Prüfung bestanden.",opts:["Deswegen","Bevor","Trotzdem","Obwohl"],ans:"Deswegen",hint:"Monatelanges Lernen hat zum Ergebnis geführt. Welcher Konnektor zeigt Kausalität?"},
{type:"fb",s:"{1} kommt Lukas zur Feier. Er ist sich noch nicht sicher.",a:["Eventuell"],opts:["Eventuell","Schließlich","Seitdem","Offenbar"],hint:"Which word means 'possibly,' NOT 'eventually'?",sSrc:"Possibly Lukas will come to the party. He is not sure yet."},
{type:"mc",q:"'Wenn Verumius nicht nach Deutschland gekommen wäre, hätte er diese Freunde nie kennengelernt.' Dieser Satz drückt aus...",opts:["Bedauern über die Reise nach Deutschland.","Eine Vorhersage über die Zukunft.","Einen Plan, Deutschland zu verlassen.","Dankbarkeit für eine Entscheidung, die auch anders hätte ausgehen können."],ans:"Dankbarkeit für eine Entscheidung, die auch anders hätte ausgehen können.",hint:"Die irreale Vergangenheitsbedingung (nicht gekommen wäre) zeigt den nicht eingeschlagenen Weg. Die Realität ist das Gegenteil."},
{type:"drag_fill",s:"Verumius ist {1} stolz {2} glücklich.",blanks:{"1":"sowohl","2":"als auch"},pool:["sowohl","als auch","weder","noch","entweder","oder"],hint:"He is BOTH proud AND happy. Which two-part conjunction means both...and?",sSrc:"Verumius is both proud and happy."}
]},

// =============================================
// Lesson 10: Bildung und Kultur (Education and Culture)
// Type: Culture + final quiz (bubble). 36 new words. 28 steps.
// =============================================
{id:"deu_r23l10",title:"Bildung und Kultur",icon:"🎓",xp:15,board:true,steps:[
{type:"intro",title:"Bildung und Kultur",desc:"Demonstrativpronomen, Indefinitpronomen und die letzten akademischen Vokabeln. Ein kultureller Einblick in die Goethe-B1-Prüfung und eine umfassende Abschlussprüfung.",goals:["Lerne Demonstrativpronomen und verbleibendes akademisches Vokabular","Erforsche die deutsche Bildungskultur","Beweise Beherrschung aller Grammatik von Einheit 23"]},
{type:"teach",trg:"dasselbe",src:"the same (neuter)",pos:"pron",gender:"n",note:"Das (the, neuter) + selbe (same). The identical thing.\nDifferent from das Gleiche (the same kind).",example:"A: Ist das dasselbe Buch?\nB: Ja, das ist dasselbe Buch wie gestern.\nA: Dasselbe nochmal, bitte.\nB: Wir meinen dasselbe.",exampleSrc:"A: Is that the same book?\nB: Yes, that is the same book as yesterday.\nA: The same again, please.\nB: We mean the same thing.",funFact:"Das + selbe. 'Dasselbe' means the identical object. 'Das Gleiche' means the same TYPE but a different object. Germans debate this distinction passionately. Order 'das Gleiche' in a cafe, not 'dasselbe,' unless you want their cup."},
{type:"teach",trg:"derselbe",src:"the same (masculine)",pos:"pron",gender:"m",note:"Der (the, masc.) + selbe (same). The article declines.\nDerselbe Mann = the same man.",example:"A: Ist das derselbe Lehrer?\nB: Ja, derselbe wie letztes Semester.\nA: Am selben Tag?\nB: Ja, immer derselbe Tag, dieselbe Zeit.",exampleSrc:"A: Is that the same teacher?\nB: Yes, the same as last semester.\nA: On the same day?\nB: Yes, always the same day, the same time.",funFact:"The article part (der/die/das) declines through cases, but 'selbe' stays. 'Am selben Tag' (on the same day), dative form. A hybrid word that follows two declension patterns at once."},
{type:"teach",trg:"dieselbe",src:"the same (feminine)",pos:"pron",gender:"f",note:"Die (the, fem.) + selbe (same).\nDieselbe Frage = the same question.",example:"A: Hast du dieselbe Prüfung geschrieben?\nB: Ja, dieselbe Prüfung wie du.\nA: Immer dieselbe Geschichte.\nB: Stimmt, immer dieselbe!",exampleSrc:"A: Did you take the same exam?\nB: Yes, the same exam as you.\nA: Always the same story.\nB: True, always the same!",funFact:"Three genders, three forms (derselbe, dieselbe, dasselbe), one meaning: identical. 'Immer dieselbe Geschichte' (Always the same story) is a common German expression of mild exasperation."},
{type:"teach",trg:"dies",src:"this (formal/written)",pos:"pron",gender:null,note:"Short form of dieses. Formal/written register.\nDies ist mein Ergebnis.",example:"A: Dies ist mein Ergebnis.\nB: Dies überrascht mich nicht.\nA: Dies war eine gute Prüfung.\nB: Ja, dies kann man so sagen.",exampleSrc:"A: This is my result.\nB: This does not surprise me.\nA: This was a good exam.\nB: Yes, one can say this.",funFact:"Short form of 'dieses.' Formal and written. Spoken German prefers 'das' or 'dieses.' Academic and exam register. 'Dies zeigt, dass...' (This shows that...) is standard in formal writing."},
{type:"teach",trg:"diese",src:"this, these (fem./plural)",pos:"pron",gender:null,note:"Feminine singular or plural demonstrative.\nDiese Prüfung. Diese Wörter.",example:"A: Diese Prüfung war fair.\nB: Ja, diese Prüfung war gut.\nA: Diese Wörter sind wichtig.\nB: Stimmt, diese muss man können.",exampleSrc:"A: This exam was fair.\nB: Yes, this exam was good.\nA: These words are important.\nB: True, you have to know these.",funFact:"The feminine singular and plural demonstrative. 'Diese Prüfung' (this exam). 'Diese Wörter' (these words). Declines through all four cases. A fundamental building block of German."},
{type:"teach",trg:"dieser",src:"this (masculine)",pos:"pron",gender:null,note:"Masculine demonstrative. Dieser Tag = this day.\nEben dieser Moment = this very moment.",example:"A: Dieser Tag ist besonders.\nB: Ja, dieser Moment ist unvergesslich.\nA: Eben dieser Moment: BESTANDEN!\nB: Dieser Tag bleibt für immer in Erinnerung.",exampleSrc:"A: This day is special.\nB: Yes, this moment is unforgettable.\nA: This very moment: PASSED!\nB: This day will remain in memory forever.",funFact:"Points to something specific. 'Eben dieser Moment' (this very moment). Emphatic when combined with 'eben.' 'Dieser' directs attention to exactly this one thing, no other."},
{type:"teach",trg:"dieses",src:"this (neuter)",pos:"pron",gender:null,note:"Neuter demonstrative. Dieses Buch = this book.\nOften shortened to dies in spoken German.",example:"A: Dieses Mal hat er bestanden.\nB: Ja, dieses Mal!\nA: Dieses Buch hat ihm geholfen.\nB: Dieses und viel Übung.",exampleSrc:"A: This time he passed.\nB: Yes, this time!\nA: This book helped him.\nB: This one and lots of practice.",funFact:"The neuter demonstrative. 'Dieses Mal' (this time). In spoken German, often shortened to 'dies Buch' or even colloquially 'dis.' The full form is always correct."},
{type:"teach",trg:"irgendein",src:"some, any",pos:"pron",gender:null,note:"Irgend- (some/any) + ein. Indefinite.\nIrgendein Fehler = some mistake or other.",example:"A: Gibt es irgendein Problem?\nB: Nein, kein Problem. Irgendeine Frage?\nA: Ja, irgendeine Frage habe ich noch.\nB: Frag irgendwann, ich helfe gern.",exampleSrc:"A: Is there any problem?\nB: No, no problem. Any question?\nA: Yes, I still have some question.\nB: Ask sometime, I am happy to help.",funFact:"Irgend- is the vagueness prefix. It makes everything indefinite: irgendwann (sometime), irgendwo (somewhere), irgendwie (somehow). Irgendein makes 'ein' vague and unspecific."},
{type:"teach",trg:"mehrere",src:"several",pos:"pron",gender:null,note:"From mehr (more). Always plural.\nMehrere Versuche = several attempts.",example:"A: Er hat mehrere Prüfungen bestanden.\nB: Mehrere? Wie viele?\nA: Mehrere hundert Teilnehmer waren dabei.\nB: Und mehrere haben bestanden!",exampleSrc:"A: He passed several exams.\nB: Several? How many?\nA: Several hundred participants were there.\nB: And several passed!",funFact:"From 'mehr' (more). Always plural. More than two, fewer than many. 'Mehrere Versuche' (several attempts). The number is vague but greater than just a few."},
{type:"teach",trg:"sämtlich",src:"all, entire",pos:"pron",gender:null,note:"Stronger than alle. Written register.\nSämtliche Aufgaben = all tasks (emphatic).",example:"A: Sämtliche Teilnehmer haben bestanden!\nB: Sämtliche? Alle?\nA: Ja, sämtliche. Jeder einzelne.\nB: Das ist beeindruckend. Sämtliche!",exampleSrc:"A: Every single participant passed!\nB: Every single one? All?\nA: Yes, every single one.\nB: That is impressive. Every single one!",funFact:"Stronger and more emphatic than 'alle.' 'Sämtliche Teilnehmer haben bestanden' (Every single participant passed). Written register. When 'alle' is not emphatic enough, use 'sämtlich.'"},
{type:"teach",trg:"selb",src:"same (root form)",pos:"pron",gender:null,note:"The root of derselbe/dieselbe/dasselbe.\nZur selben Zeit = at the same time.",example:"A: Zur selben Zeit am selben Ort.\nB: Am selben Tag wie letztes Jahr.\nA: Im selben Raum.\nB: Ja, alles wie beim letzten Mal. Am selben Platz.",exampleSrc:"A: At the same time in the same place.\nB: On the same day as last year.\nA: In the same room.\nB: Yes, everything like last time. In the same seat.",funFact:"The root of derselbe/dieselbe/dasselbe. Only appears combined with articles. The bare form 'selb' is archaic in modern German. 'Zur selben Zeit' (at the same time) uses it in a fixed phrase."},
{type:"teach",trg:"selber",src:"oneself (colloquial)",pos:"pron",gender:null,note:"Informal version of selbst.\nIch habe es selber gemacht = I did it myself.",example:"A: Hast du das selber geschafft?\nB: Ja, ich habe alles selber gelernt.\nA: Selber kochen, selber lernen.\nB: Selber machen ist der beste Lehrer.",exampleSrc:"A: Did you manage that yourself?\nB: Yes, I learned everything myself.\nA: Cook yourself, learn yourself.\nB: Doing it yourself is the best teacher.",funFact:"Informal version of 'selbst.' Northern German prefers 'selber,' southern German prefers 'selbst.' Both are correct. 'Selber machen' (to do it yourself) is a German cultural value."},
{type:"teach",trg:"solch",src:"such",pos:"pron",gender:null,note:"Flexible word order: solch ein or ein solcher.\nMore formal than so ein.",example:"A: Solch ein Erfolg!\nB: Ein solcher Tag kommt nicht oft.\nA: Solch eine Leistung verdient Respekt.\nB: Ja, solch ein Ergebnis ist selten.",exampleSrc:"A: Such a success!\nB: Such a day does not come often.\nA: Such an achievement deserves respect.\nB: Yes, such a result is rare.",funFact:"Flexible word order: 'solch ein' or 'ein solcher.' Same meaning as 'so ein' but more formal. The written register's way of saying 'such a...'"},
{type:"teach",trg:"so viel",src:"so much",pos:"pron",gender:null,note:"Written as two words. So viel wie möglich = as much as possible.\nAlso conjunction: Soviel ich weiß (one word).",example:"A: Er hat so viel gelernt!\nB: So viel wie möglich.\nA: Soviel ich weiß, hat er bestanden.\nB: So viel Arbeit hat sich gelohnt.",exampleSrc:"A: He learned so much!\nB: As much as possible.\nA: As far as I know, he passed.\nB: So much work has paid off.",funFact:"Written as two words as a quantity phrase. As a conjunction ('as far as'), written as one word: 'Soviel ich weiß' (As far as I know). The spelling changes with the function."},
{type:"teach",trg:"desto",src:"the (more)...the",pos:"conj",gender:null,note:"Always paired with je. The German comparative correlation.\nJe mehr man übt, desto besser wird man.",example:"A: Je mehr man übt, desto besser wird man.\nB: Je früher, desto besser.\nA: Je schwieriger die Prüfung, desto stolzer das Ergebnis.\nB: Stimmt, je mehr Arbeit, desto größer die Freude.",exampleSrc:"A: The more one practices, the better one becomes.\nB: The earlier, the better.\nA: The harder the exam, the prouder the result.\nB: True, the more work, the greater the joy.",funFact:"Always paired with 'je.' The German comparative correlation structure. 'Je mehr...desto besser' (The more...the better). Unique and essential for B1+ German."},
{type:"teach",trg:"gleichfalls",src:"likewise",pos:"adv",gender:null,note:"Gleich (same) + Falls (case). The mirror response.\nDanke, gleichfalls! = Thanks, likewise!",example:"A: Viel Erfolg bei der nächsten Prüfung!\nB: Danke, gleichfalls!\nA: Schönen Tag noch!\nB: Gleichfalls! Danke!",exampleSrc:"A: Good luck with the next exam!\nB: Thanks, likewise!\nA: Have a nice day!\nB: Likewise! Thanks!",funFact:"Gleich (same) + Falls (case). The mirror response. 'Schönen Tag!' - 'Gleichfalls!' Polite and automatic. One of the most useful single-word responses in German."},
{type:"teach",trg:"je",src:"ever, each, the (in comparisons)",pos:"conj",gender:null,note:"Tiny word, huge range. Je nachdem = depending on.\nJe länger, desto besser.",example:"A: Je nachdem, wie du dich fühlst.\nB: Je zwei Personen pro Gruppe.\nA: Je länger ich lerne, desto sicherer fühle ich mich.\nB: Je nachdem, was die Prüfung verlangt.",exampleSrc:"A: Depending on how you feel.\nB: Two persons each per group.\nA: The longer I study, the more confident I feel.\nB: Depending on what the exam requires.",funFact:"Tiny word, huge range. 'Je nachdem' (depending on). 'Je zwei Personen' (two persons each). In comparisons: 'Je länger, desto besser' (the longer, the better). Three functions, two letters."},
{type:"teach",trg:"umso",src:"all the more",pos:"conj",gender:null,note:"Synonym of desto. Je mehr, umso besser.\nUmso besser! = All the better!",example:"A: Er hat bestanden! Umso besser!\nB: Je schwieriger die Prüfung, umso stolzer.\nA: Umso schöner, dass alle gekommen sind.\nB: Umso besser, dass wir zusammen feiern!",exampleSrc:"A: He passed! All the better!\nB: The harder the exam, the prouder.\nA: All the nicer that everyone came.\nB: All the better that we celebrate together!",funFact:"Synonym of 'desto.' Interchangeable in je...desto/umso structures. 'Umso besser!' (All the better!) as a standalone exclamation is more common than 'desto besser.'"},
{type:"tip",title:"Die Goethe-B1-Prüfung: Was sie beweist",text:"Das Goethe-Zertifikat B1 hat vier Teile:\n\n1. Lesen: 65 Minuten, Textverständnis\n2. Hören: 40 Minuten, Hörverstehen\n3. Schreiben: 60 Minuten, schriftlicher Ausdruck\n4. Sprechen: 15 Minuten mit Partner\n\nZum Bestehen braucht man 60% insgesamt.\n\nB1 beweist: Sie können die Hauptpunkte klarer Standardsprache verstehen, die meisten Reisesituationen bewältigen, einfache zusammenhängende Texte schreiben und Erfahrungen, Meinungen und Pläne beschreiben.\n\nDas Zertifikat wird für den deutschen Einbürgerungsantrag akzeptiert und von vielen Arbeitgebern verlangt. Verumius' BESTANDEN bedeutet: Er hat all das bewiesen.",deepDive:{title:"B1 im europäischen Kontext",text:"B1 ist die dritte von sechs CEFR-Stufen (A1-C2). Es wird auch 'Schwelle' (Threshold) genannt: die Schwelle zur selbstständigen Sprachverwendung.\n\nNach B1 können Sie:\n- Reisen ohne Sprachprobleme\n- Über vertraute Themen diskutieren\n- Einfache Briefe und Berichte schreiben\n- Filme und Serien mit Untertiteln verstehen\n\nVerumius hat die Schwelle überschritten. B2 wartet."}},
{type:"teach",trg:"regeln",src:"to regulate, to settle",pos:"verb",gender:null,note:"From Regel (rule). Das Problem regeln = to settle the problem.\nGeregelt = regulated, taken care of.",example:"A: Hast du alles geregelt?\nB: Ja, ich habe alles geregelt.\nA: Gut, dann ist das Problem geregelt.\nB: Alles geregelt. Wir können feiern.",exampleSrc:"A: Have you settled everything?\nB: Yes, I have settled everything.\nA: Good, then the problem is settled.\nB: Everything settled. We can celebrate.",funFact:"From Regel (rule). 'Das ist geregelt' (That is taken care of). From rule to resolution in one verb. A very German approach: if there is a Regel, things are geregelt."},
{type:"teach",trg:"fassen",src:"to grasp, to compose",pos:"verb",gender:null,note:"Zusammenfassen = to summarize. Sich fassen = to compose oneself.\nEinen Entschluss fassen = to make a decision.",example:"A: Ich kann es kaum fassen!\nB: Fass dich! Du hast bestanden!\nA: Ich muss mich fassen. Es ist einfach toll.\nB: Einen Entschluss fassen: wir feiern!",exampleSrc:"A: I can hardly believe it!\nB: Compose yourself! You passed!\nA: I have to compose myself. It is simply great.\nB: Make a decision: we celebrate!",funFact:"To grasp physically and mentally. 'Zusammenfassen' (to summarize), 'sich fassen' (to compose oneself), 'einen Entschluss fassen' (to make a decision). One verb, many grasps."},
{type:"teach",trg:"mitteilen",src:"to communicate, to inform",pos:"verb",gender:null,note:"Separable: mit + teilen. Formal communication.\nIch teile Ihnen mit, dass... = I inform you that...",example:"A: Ich teile Ihnen mit, dass Sie bestanden haben.\nB: Danke für die Mitteilung!\nA: Darf ich meiner Familie mitteilen, dass ich bestanden habe?\nB: Natürlich! Teilen Sie allen die gute Nachricht mit!",exampleSrc:"A: I inform you that you have passed.\nB: Thank you for the notification!\nA: May I tell my family that I passed?\nB: Of course! Share the good news with everyone!",funFact:"Mit (with) + teilen (to share). To share information formally. 'Mitteilung' (notification). The formal way to deliver news. 'Ich teile Ihnen mit, dass...' is how official results are communicated."},
{type:"teach",trg:"ausrichten",src:"to pass on (a message), to organize",pos:"verb",gender:null,note:"Separable: aus + richten. Kann ich etwas ausrichten?\nAlso: ein Fest ausrichten = to organize a celebration.",example:"A: Kann ich etwas ausrichten?\nB: Ja, richten Sie ihm aus, dass er bestanden hat!\nA: Wer richtet die Feier aus?\nB: Hildi richtet sie aus. Sie hat den Kuchen gebacken.",exampleSrc:"A: Can I pass on a message?\nB: Yes, tell him that he passed!\nA: Who is organizing the celebration?\nB: Hildi is organizing it. She baked the cake.",funFact:"Aus (out) + richten (to direct). Two meanings: to pass on a message and to organize an event. 'Kann ich etwas ausrichten?' (Can I take a message?) is standard phone German."},
{type:"teach",trg:"hinweisen",src:"to point out, to indicate",pos:"verb",gender:null,note:"Separable: hin + weisen. Auf etwas hinweisen.\nIch möchte darauf hinweisen, dass...",example:"A: Ich möchte auf einen Fehler hinweisen.\nB: Worauf weisen Sie hin?\nA: Ich weise darauf hin, dass die Zeit begrenzt ist.\nB: Danke für den Hinweis!",exampleSrc:"A: I would like to point out a mistake.\nB: What are you pointing out?\nA: I point out that the time is limited.\nB: Thanks for the hint!",funFact:"Hin (toward) + weisen (to point/show). To direct attention toward something. 'Ich möchte darauf hinweisen, dass...' (I would like to point out that...) is formal and precise. The verb behind 'der Hinweis.'"},
{type:"teach",trg:"ereignen",src:"to occur, to happen",pos:"verb",gender:null,note:"Reflexive: sich ereignen. Formal alternative to passieren.\nWas hat sich ereignet? = What happened?",example:"A: Was hat sich ereignet?\nB: Verumius hat die Prüfung bestanden!\nA: Das ist ein wichtiges Ereignis!\nB: Ja, so etwas ereignet sich nicht jeden Tag.",exampleSrc:"A: What happened?\nB: Verumius passed the exam!\nA: That is an important event!\nB: Yes, something like that does not happen every day.",funFact:"Reflexive: sich ereignen. More formal than 'passieren.' 'Ereignis' (event) is the noun. 'Was hat sich ereignet?' (What happened?) sounds more serious and weighty than 'Was ist passiert?'"},
{type:"teach",trg:"genügen",src:"to suffice, to be enough",pos:"verb",gender:null,note:"More formal than reichen or ausreichen.\nDas genügt = That is enough. Takes dative.",example:"A: Genügt das?\nB: Ja, das genügt vollkommen.\nA: Sechzig Prozent genügen zum Bestehen.\nB: Mir genügt mehr als sechzig. Ich will achtzig!",exampleSrc:"A: Is that enough?\nB: Yes, that is completely sufficient.\nA: Sixty percent is sufficient to pass.\nB: Just sufficient is not enough for me. I want eighty!",funFact:"More formal than 'reichen' or 'ausreichen.' 'Das genügt' (That is enough). Takes dative. A word of measured satisfaction. 'Es genügt mir' (It suffices for me)."},
{type:"teach",trg:"die Biologie",src:"biology",pos:"noun",gender:"f",note:"Feminine noun. From Greek bios (life) + logos (study).\nBiologie studieren = to study biology.",example:"A: Hast du Biologie in der Schule gelernt?\nB: Ja, Biologie war mein Lieblingsfach.\nA: Biologie und Chemie gehören zusammen.\nB: Stimmt, in der Biologie braucht man auch Chemie.",exampleSrc:"A: Did you learn biology in school?\nB: Yes, biology was my favorite subject.\nA: Biology and chemistry belong together.\nB: True, in biology you also need chemistry.",funFact:"From Greek 'bios' (life) + 'logos' (study). The study of life. International word. An academic subject that appears in Goethe exam reading texts about education and science."},
{type:"teach",trg:"mittler",src:"middle, medium",pos:"adj",gender:null,note:"Comparative-looking but a base form.\nMittlere Reife = secondary school certificate.",example:"A: Er hat die mittlere Reife.\nB: Die mittlere Reife ist ein wichtiger Abschluss.\nA: Mittlere Schwierigkeit.\nB: Nicht zu leicht, nicht zu schwer. Genau mittler.",exampleSrc:"A: He has the secondary school certificate.\nB: The secondary school certificate is an important qualification.\nA: Medium difficulty.\nB: Not too easy, not too hard. Exactly medium.",funFact:"Looks like a comparative but is a base form. 'Mittlere Reife' (secondary school certificate) is one of the most important educational terms in Germany. It opens doors to apprenticeships and further education."},
{type:"teach",trg:"öfter",src:"more often",pos:"adv",gender:null,note:"Comparative of oft (often). Öfter üben = to practice more often.\nImmer öfter = more and more often.",example:"A: Du solltest öfter üben.\nB: Ja, öfter wäre besser.\nA: Er kommt jetzt öfter zu Besuch.\nB: Immer öfter. Das freut mich.",exampleSrc:"A: You should practice more often.\nB: Yes, more often would be better.\nA: He comes to visit more often now.\nB: More and more often. That makes me happy.",funFact:"Comparative of 'oft' (often). 'Immer öfter' (more and more often) shows increasing frequency. Verumius's friends visit immer öfter since he started speaking German fluently."},
{type:"teach",trg:"relativ",src:"relatively",pos:"adj",gender:null,note:"From Latin relativus. International word.\nRelativ einfach = relatively easy.",example:"A: Die Prüfung war relativ fair.\nB: Relativ? Oder wirklich fair?\nA: Na ja, relativ gesehen schon.\nB: Relativ gut abgeschnitten, insgesamt.",exampleSrc:"A: The exam was relatively fair.\nB: Relatively? Or really fair?\nA: Well, relatively speaking, yes.\nB: Relatively well done, overall.",funFact:"From Latin 'relativus.' International word used identically in many languages. 'Relativ einfach' (relatively easy). A word that hedges and softens any statement."},
{type:"teach",trg:"folgend",src:"following",pos:"adj",gender:null,note:"Present participle of folgen (to follow).\nDie folgenden Punkte = the following points.",example:"A: Beachten Sie die folgenden Hinweise.\nB: Die folgenden Aufgaben sind schwieriger.\nA: Im Folgenden erkläre ich die Ergebnisse.\nB: Folgende Regeln gelten für die Prüfung.",exampleSrc:"A: Please note the following instructions.\nB: The following tasks are more difficult.\nA: In the following, I will explain the results.\nB: The following rules apply to the exam.",funFact:"Present participle of 'folgen' (to follow). 'Im Folgenden' (in the following) and 'folgende Punkte' (following points) are standard in formal German writing and exam instructions."},
{type:"teach",trg:"speziell",src:"special, specific",pos:"adj",gender:null,note:"From Latin specialis. Speziell für dich = specially for you.\nSpezial- as prefix: Spezialgebiet = specialty.",example:"A: Gibt es spezielle Tipps für die Prüfung?\nB: Ja, speziell für den Hören-Teil.\nA: Das ist ein spezielles Thema.\nB: Speziell dieses Thema ist wichtig.",exampleSrc:"A: Are there special tips for the exam?\nB: Yes, specially for the listening part.\nA: That is a special topic.\nB: This topic in particular is important.",funFact:"From Latin 'specialis.' 'Spezial-' as a prefix creates compounds: Spezialgebiet (specialty), Spezialeffekte (special effects). Both the adjective and the prefix form are common in German."},
{type:"teach",trg:"unterstreichen",src:"to underline, to emphasize",pos:"verb",gender:null,note:"Separable: unter + streichen. Inseparable for emphasis.\nWichtige Stellen unterstreichen = to underline important passages.",example:"A: Unterstreichen Sie die wichtigen Wörter.\nB: Soll ich alles unterstreichen?\nA: Nein, nur die Schlüsselwörter unterstreichen.\nB: Gut, ich unterstreiche nur das Wichtigste.",exampleSrc:"A: Underline the important words.\nB: Should I underline everything?\nA: No, only underline the key words.\nB: Good, I will only underline the most important things.",funFact:"Unter (under) + streichen (to strike/draw). Literally: to draw a line under. Also used figuratively: 'Ich möchte unterstreichen, dass...' (I would like to emphasize that...). Physical marking and rhetorical emphasis in one verb."},
{type:"mc",q:"'Verumius hat letztes Jahr dieselbe Prüfung versucht und nicht bestanden. Dieses Mal hat er bestanden.' Was spezifizieren dieselbe und dieses?",opts:["Jede Prüfung und jedes Mal.","Die gleiche Art und das letzte Mal.","Eine andere Prüfung und eine unbekannte Zeit.","Die identische Prüfung und dieses bestimmte Mal."],ans:"Die identische Prüfung und dieses bestimmte Mal.",hint:"Dieselbe = identisch (nicht nur ähnlich). Dieses = dieses bestimmte."},
{type:"fb",s:"{1} mehr man übt, desto besser wird man.",a:["Je"],opts:["Je","Wenn","Weil","Da"],hint:"The word that starts the German 'the more...the more' structure.",sSrc:"The more one practices, the better one becomes."},
{type:"mc",q:"'Wenn er hätte mehr üben können, hätte er nicht so nervös zu sein brauchen.' Dieser Satz kombiniert...",opts:["Perfekt + Präsens + Futur","Nebensatz + Hauptsatz + Infinitivsatz","Passiv + Konjunktiv I + Imperativ","Irrealer Bedingungssatz + Doppelinfinitiv + brauchen + zu"],ans:"Irrealer Bedingungssatz + Doppelinfinitiv + brauchen + zu",hint:"Alle drei Grammatikkonstruktionen in einem Satz. Wenn + hätte...können (Doppelinfinitiv im Irrealis), hätte + brauchen (brauchen + zu im Konjunktiv II)."},
{type:"match",pairs:[{trg:"dasselbe",src:"the same (neuter)"},{trg:"mehrere",src:"several"},{trg:"gleichfalls",src:"likewise"},{trg:"sämtlich",src:"all/entire"}]}
]}

]},

{n:24,lang:"de",srcLang:"en",track:"v2",title:"Einjährig",sub:"One year in Germany, Plusquamperfekt, Futur I, the decision to stay",icon:"🎉",level:"B1.2",color:"#7B5EE8",lessons:[

// ==================== LESSON 1: Ein Jahr ====================
{id:"deu_r24l1",title:"Ein Jahr",icon:"📅",xp:15,board:true,steps:[
{type:"intro",title:"Ein Jahr",desc:"Genau ein Jahr in Deutschland. Verumius steht am Fenster und blickt auf den Fernsehturm. Er erinnert sich an alles. Heute lernst du Wörter für Erfahrungen, Gewohnheiten und Wahrheit.",goals:["Lerne 16 neue Wörter rund um Erfahrungen und Alltag","Höre zum ersten Mal das Plusquamperfekt in der Erzählung","Begleite Verumius bei seiner Erinnerung an ein Jahr Berlin"]},
{type:"story",speaker:"narrator",mood:"warm-reflective",art:"berlin_apartment_morning_fernsehturm",trg:"Genau ein Jahr. Verumius steht am Fenster, Kaffee in der Hand, und schaut auf den Fernsehturm. Vor einem Jahr hatte er diesen Turm zum ersten Mal gesehen und nichts verstanden. Jetzt ist er Teil seiner Gewohnheit. Die Sonne geht auf. Berlin wacht auf. Und Verumius wacht mit.",src:"Exactly one year. Verumius stands at the window, coffee in hand, and looks at the Fernsehturm. A year ago he had seen this tower for the first time and understood nothing. Now it is part of his routine. The sun rises. Berlin wakes up. And Verumius wakes with it."},
{type:"teach",trg:"das Abenteuer",src:"the adventure",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Abenteuer.\n'Ein Abenteuer erleben' (to experience an adventure).",example:"A: Wie war dein Jahr in Berlin?\nB: Es war ein echtes Abenteuer!\nA: Würdest du es wieder machen?\nB: Sofort. Jedes Abenteuer hat sich gelohnt.",exampleSrc:"A: How was your year in Berlin?\nB: It was a real adventure!\nA: Would you do it again?\nB: Immediately. Every adventure was worth it.",funFact:"From Old French 'aventure' (what comes to you). The same root gives English 'adventure.' German kept the French pronunciation for centuries before spelling it phonetically. Das Abenteuer is neuter."},
{type:"teach",trg:"der Alltag",src:"the everyday life",pos:"noun",gender:"m",note:"Masculine noun. All (every) + Tag (day).\n'Im Alltag' (in daily life).",example:"A: Vermisst du den Alltag in deiner Heimat?\nB: Manchmal. Aber mein Alltag hier ist auch schön.\nA: Was machst du im Alltag?\nB: Ich arbeite, lerne Deutsch und trinke viel Kaffee.",exampleSrc:"A: Do you miss everyday life in your home country?\nB: Sometimes. But my everyday life here is also nice.\nA: What do you do in daily life?\nB: I work, learn German, and drink a lot of coffee.",funFact:"When the extraordinary becomes Alltag, you have truly arrived. Germans often say 'der ganz normale Alltag' (the perfectly normal everyday life). Verumius's German Alltag now includes Brezeln and Fahrpläne."},
{type:"teach",trg:"der Beginn",src:"the beginning",pos:"noun",gender:"m",note:"Masculine noun. From 'beginnen' (to begin).\n'Am Beginn' or 'zu Beginn' (at the beginning).",example:"A: Erinnerst du dich an den Beginn?\nB: Ja, zu Beginn war alles so fremd.\nA: Und jetzt?\nB: Jetzt ist es mein Zuhause.",exampleSrc:"A: Do you remember the beginning?\nB: Yes, at the beginning everything was so foreign.\nA: And now?\nB: Now it is my home.",funFact:"The noun strips the verb 'beginnen' down to its essence: the moment something starts. 'Von Beginn an' (from the very start). Related to English 'begin' through Germanic roots."},
{type:"teach",trg:"die Eile",src:"the hurry, the haste",pos:"noun",gender:"f",note:"Feminine noun. 'In Eile sein' (to be in a hurry).\n'Eile mit Weile' (more haste, less speed).",example:"A: Warum bist du so in Eile?\nB: Ich muss noch einkaufen!\nA: Du hast doch Zeit. Keine Eile.\nB: Stimmt. Eile mit Weile.",exampleSrc:"A: Why are you in such a hurry?\nB: I still have to go shopping!\nA: You have time. No hurry.\nB: True. More haste, less speed.",funFact:"'Eile mit Weile' (hurry with patience) is a beloved German proverb meaning 'more haste, less speed.' Verumius has learned that Berlin does not reward Eile. The city moves at its own pace."},
{type:"teach",trg:"das Ereignis",src:"the event, the occurrence",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Ereignisse.\nFrom 'sich ereignen' (to occur).",example:"A: Was war das wichtigste Ereignis in deinem Jahr?\nB: Der Tag, als ich Freunde gefunden habe.\nA: Das ist ein schönes Ereignis.\nB: Ja, es hat mein Leben verändert.",exampleSrc:"A: What was the most important event of your year?\nB: The day I found friends.\nA: That is a beautiful event.\nB: Yes, it changed my life.",funFact:"Stronger than 'Veranstaltung' (an organized event). An Ereignis happens to you. 'Ein wichtiges Ereignis' (an important event). It implies significance and often surprise."},
{type:"teach",trg:"die Gewohnheit",src:"the habit",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Gewohnheiten.\n'Aus Gewohnheit' (out of habit).",example:"A: Hast du neue Gewohnheiten in Berlin?\nB: Ja, ich trinke jeden Morgen Kaffee am Fenster.\nA: Das ist eine schöne Gewohnheit.\nB: Die Macht der Gewohnheit!",exampleSrc:"A: Do you have new habits in Berlin?\nB: Yes, I drink coffee at the window every morning.\nA: That is a nice habit.\nB: The force of habit!",funFact:"From 'gewohnt' (accustomed). 'Die Macht der Gewohnheit' (the force of habit) is a common phrase. Germans call humans 'Gewohnheitstiere' (creatures of habit). The compound is pure German wordcraft."},
{type:"teach",trg:"die Rückkehr",src:"the return",pos:"noun",gender:"f",note:"Feminine noun. Rück (back) + Kehr (turn).\n'Die Rückkehr nach Hause' (the return home).",example:"A: Denkst du an eine Rückkehr?\nB: In mein altes Land? Manchmal.\nA: Aber?\nB: Aber mein Zuhause ist jetzt hier.",exampleSrc:"A: Do you think about a return?\nB: To my old country? Sometimes.\nA: But?\nB: But my home is here now.",funFact:"Rück (back) + Kehr (turn). But what if home is no longer where you came from? That is the question Verumius faces today. 'Rückkehr' implies going back to something familiar, but Verumius has changed."},
{type:"teach",trg:"der Sinn",src:"the sense, the meaning, the purpose",pos:"noun",gender:"m",note:"Masculine noun. 'Das macht Sinn' (that makes sense).\nAlso: the five Sinne (senses).",example:"A: Hat das Jahr einen Sinn gehabt?\nB: Ja, einen großen Sinn.\nA: Welchen?\nB: Ich habe gelernt, wer ich bin.",exampleSrc:"A: Did the year have a purpose?\nB: Yes, a great purpose.\nA: Which one?\nB: I learned who I am.",funFact:"A tiny word carrying enormous philosophical weight. 'Sinnvoll' (meaningful), 'sinnlos' (pointless). 'Der Sinn des Lebens' (the meaning of life). Germans philosophize about Sinn the way English speakers philosophize about 'purpose.'"},
{type:"teach",trg:"die Tatsache",src:"the fact",pos:"noun",gender:"f",note:"Feminine noun. Tat (deed) + Sache (thing).\n'Die Tatsache, dass...' (the fact that...).",example:"A: Die Tatsache, dass du noch hier bist, sagt viel.\nB: Ja, ich bin geblieben.\nA: Das ist eine wichtige Tatsache.\nB: Die wichtigste Tatsache meines Jahres.",exampleSrc:"A: The fact that you are still here says a lot.\nB: Yes, I stayed.\nA: That is an important fact.\nB: The most important fact of my year.",funFact:"Tat (deed/fact) + Sache (thing). German facts are solid: they are deed-things, proven by what happened. Built from actions and evidence. 'Tatsächlich' (actually/indeed) is the adverb form."},
{type:"teach",trg:"die Wahrheit",src:"the truth",pos:"noun",gender:"f",note:"Feminine noun. From 'wahr' (true).\n'Die Wahrheit sagen' (to tell the truth).",example:"A: Was ist die Wahrheit über Berlin?\nB: Die Wahrheit? Berlin ist laut und schön zugleich.\nA: Das stimmt. Und du?\nB: In Wahrheit liebe ich es hier.",exampleSrc:"A: What is the truth about Berlin?\nB: The truth? Berlin is loud and beautiful at the same time.\nA: That is true. And you?\nB: In truth, I love it here.",funFact:"The -heit suffix turns adjectives into abstract nouns. Wahr becomes Wahrheit. True becomes truth. 'In Wahrheit' (in truth/actually). The same pattern: krank to Krankheit, frei to Freiheit."},
{type:"teach",trg:"der Zeitpunkt",src:"the point in time, the moment",pos:"noun",gender:"m",note:"Masculine noun. Zeit (time) + Punkt (point).\n'Der richtige Zeitpunkt' (the right moment).",example:"A: Wann ist der richtige Zeitpunkt für eine Entscheidung?\nB: Vielleicht jetzt. Vielleicht heute.\nA: Du hast recht. Der Zeitpunkt ist gekommen.\nB: Ja, genau dieser Zeitpunkt.",exampleSrc:"A: When is the right moment for a decision?\nB: Maybe now. Maybe today.\nA: You are right. The moment has come.\nB: Yes, exactly this moment.",funFact:"Germans are precise about time. Not just the hour, but the Zeitpunkt. 'Zu diesem Zeitpunkt' (at this point in time). It is more exact than 'Moment' or 'Augenblick,' focusing on the precise when."},
{type:"teach",trg:"der Zustand",src:"the condition, the state",pos:"noun",gender:"m",note:"Masculine noun. Zu (to) + Stand (standing).\n'In gutem Zustand' (in good condition).",example:"A: In welchem Zustand ist dein Deutsch?\nB: In viel besserem Zustand als vor einem Jahr!\nA: Das glaube ich. Du sprichst wirklich gut.\nB: Danke, der Zustand verbessert sich jeden Tag.",exampleSrc:"A: What condition is your German in?\nB: In much better condition than a year ago!\nA: I believe it. You speak really well.\nB: Thanks, the condition improves every day.",funFact:"How things stand right now. 'Der Zustand der Wohnung' (the condition of the apartment). Also used for emotional states: 'in einem guten Zustand sein' (to be in a good state). A snapshot of the present."},
{type:"teach",trg:"verbringen",src:"to spend (time)",pos:"verb",gender:null,note:"Irregular verb: verbrachte, verbracht.\nVer- intensifies 'bringen' (to bring).\n'Zeit verbringen' (to spend time).",example:"A: Wo hast du das letzte Jahr verbracht?\nB: In Berlin. Ein ganzes Jahr.\nA: Und? Hat es sich gelohnt?\nB: Jede Minute, die ich hier verbracht habe.",exampleSrc:"A: Where did you spend the last year?\nB: In Berlin. A whole year.\nA: And? Was it worth it?\nB: Every minute I spent here.",funFact:"You 'bring' time into an activity. Irregular: verbrachte, verbracht. Only used for time, never for money (that is 'ausgeben'). 'Ich habe ein Jahr in Berlin verbracht' is Perfekt."},
{type:"teach",trg:"vermissen",src:"to miss (someone/something)",pos:"verb",gender:null,note:"Regular verb. 'Ich vermisse dich' (I miss you).\nDifferent from 'verpassen' (to miss a bus).",example:"A: Vermisst du deine Heimat?\nB: Ja, ich vermisse meine Familie.\nA: Das ist normal. Und sonst?\nB: Ich vermisse das Essen. Aber nicht den Winter.",exampleSrc:"A: Do you miss your home country?\nB: Yes, I miss my family.\nA: That is normal. And otherwise?\nB: I miss the food. But not the winter.",funFact:"Vermissen is emotional absence. Verpassen is practical failure. 'Ich vermisse dich' (I miss you) vs. 'Ich habe den Bus verpasst' (I missed the bus). Two kinds of missing, two different verbs."},
{type:"teach",trg:"gewöhnen",src:"to get used to",pos:"verb",gender:null,note:"Regular, reflexive: 'sich an etwas gewöhnen.'\n'Ich habe mich daran gewöhnt' (I got used to it).",example:"A: Hast du dich an Berlin gewöhnt?\nB: Ja, ich habe mich an alles gewöhnt.\nA: Auch an das Wetter?\nB: An das Wetter gewöhnt man sich nie ganz!",exampleSrc:"A: Have you gotten used to Berlin?\nB: Yes, I have gotten used to everything.\nA: Even the weather?\nB: You never fully get used to the weather!",funFact:"The root of Gewohnheit. Reflexive with 'sich an etwas.' 'Ich habe mich daran gewöhnt' (I have gotten used to it). Verumius has sich an Berlin gewöhnt, including the Bureaucracy."},
{type:"teach",trg:"alltäglich",src:"everyday, ordinary",pos:"adj",gender:null,note:"Adjective. Alltag + -lich.\n'Alltägliche Dinge' (everyday things).",example:"A: Ist dein Leben in Berlin jetzt alltäglich?\nB: Ja, vieles ist alltäglich geworden.\nA: Klingt das langweilig?\nB: Nein! Alltäglich heißt: ich gehöre hierher.",exampleSrc:"A: Is your life in Berlin everyday now?\nB: Yes, many things have become everyday.\nA: Does that sound boring?\nB: No! Everyday means: I belong here.",funFact:"What was once extraordinary has become alltäglich. That is the meaning of calling a foreign city home. The -lich suffix transforms the noun Alltag into an adjective describing the quality of everdayness."},
{type:"story",speaker:"narrator",mood:"contemplative",art:"berlin_apartment_photos_phone",trg:"Er hatte so viel gelernt. Nicht nur die Sprache, sondern auch die Gewohnheiten, die Regeln, die kleinen Wahrheiten des Alltags. Es war ein Abenteuer gewesen, und die Tatsache, dass er geblieben war, überraschte ihn selbst.",src:"He had learned so much. Not just the language, but also the habits, the rules, the small truths of daily life. It had been an adventure, and the fact that he had stayed surprised even himself."},
{type:"tip",title:"Plusquamperfekt: ein erster Blick",text:"Du hast gerade 'hatte gelernt' und 'war gewesen' in der Geschichte gehört. Das ist das Plusquamperfekt (past perfect). Es beschreibt etwas, das VOR einem anderen vergangenen Ereignis passiert ist.\n\nFormel: hatte/war (Präteritum) + Partizip II (am Ende).\n\nEr hatte die Stadt gesehen. (He had seen the city.)\nSie war schon gegangen. (She had already gone.)\n\nWir üben diese Grammatik in Lektion 3 und 4.",deepDive:{title:"Warum Plusquamperfekt?",text:"Das Plusquamperfekt schafft zeitliche Tiefe in Erzählungen. Wenn du sagst 'Er hatte Deutsch gelernt, bevor er nach Berlin kam,' zeigst du zwei vergangene Zeitpunkte: das Lernen (weiter zurück) und das Kommen (näher an der Gegenwart). In Zeitungen, Romanen und beim Geschichtenerzählen ist diese Unterscheidung wichtig."}},
{type:"mc",q:"Verumius denkt an sein Jahr in Berlin. Was bedeutet 'Alltag'?",opts:["Das Abenteuer","Der Beginn","Die Gewohnheit","Das tägliche Leben"],ans:"Das tägliche Leben",hint:"Dieses zusammengesetzte Nomen verbindet 'all' (jeder) mit 'Tag' (day)."},
{type:"fb",s:"Verumius hat sich an das Leben in Berlin {1}.",a:["gewöhnt"],opts:["gewöhnt","vermisst","verbracht","begonnen"],hint:"Welches Verb bedeutet, sich an etwas anzupassen? Es ist reflexiv mit 'sich.'",sSrc:"Verumius has gotten used to life in Berlin."},
{type:"mc",q:"Der Erzähler sagt: 'Verumius hatte so viel gelernt.' Wann fand dieses Lernen statt?",opts:["Genau jetzt am Fenster","Erst gestern","In der Zukunft","Vor dem Moment, der in der Geschichte beschrieben wird"],ans:"Vor dem Moment, der in der Geschichte beschrieben wird",hint:"Das Plusquamperfekt beschreibt Ereignisse, die vor einem anderen vergangenen Ereignis stattfanden."},
{type:"match",pairs:[{trg:"Abenteuer",src:"adventure"},{trg:"Gewohnheit",src:"habit"},{trg:"Wahrheit",src:"truth"},{trg:"Zeitpunkt",src:"point in time"},{trg:"vermissen",src:"to miss"},{trg:"verbringen",src:"to spend (time)"}]}
]},

// ==================== LESSON 2: Rückblick ====================
{id:"deu_r24l2",title:"Rückblick",icon:"🔍",xp:15,board:true,steps:[
{type:"intro",title:"Rückblick",desc:"A look back at important decisions and coincidences. Learn words for decisions, chances, and doubts. Build the emotional vocabulary Verumius needs for his anniversary.",goals:["Learn 18 new words for decisions, chances, and doubts","Express decisions and surprises","Evaluate the significance of experiences"]},
{type:"teach",trg:"die Entscheidung",src:"the decision",pos:"noun",gender:"f",note:"Feminine noun. From 'entscheiden' (to decide).\n'Eine Entscheidung treffen' (to make a decision).",example:"A: War es eine schwere Entscheidung?\nB: Ja, die Entscheidung nach Berlin zu kommen war nicht leicht.\nA: Und jetzt? Bereust du es?\nB: Nein. Es war die beste Entscheidung meines Lebens.",exampleSrc:"A: Was it a difficult decision?\nB: Yes, the decision to come to Berlin was not easy.\nA: And now? Do you regret it?\nB: No. It was the best decision of my life.",funFact:"Ent- (un-/dis-) + scheiden (to separate). A decision separates one path from another. 'Eine Entscheidung treffen' (to make/meet a decision). The most important Entscheidung: nach Deutschland zu kommen."},
{type:"teach",trg:"die Chance",src:"the chance, the opportunity",pos:"noun",gender:"f",note:"Feminine noun. From French 'chance.'\nPronounced 'SHON-seh' with soft 'sh' sound.",example:"A: Berlin war eine große Chance für mich.\nB: Und du hast sie genutzt!\nA: Ja. Man muss seine Chancen nutzen.\nB: Sonst kommen sie nicht wieder.",exampleSrc:"A: Berlin was a big chance for me.\nB: And you took it!\nA: Yes. You have to seize your chances.\nB: Otherwise they do not come back.",funFact:"From French 'chance.' Pronounced with a soft 'sh' sound in German, not a hard 'ch.' 'Eine Chance nutzen' (to seize a chance). 'Zweite Chance' (second chance). Germans use the French pronunciation: 'SHON-seh.'"},
{type:"teach",trg:"die Gelegenheit",src:"the opportunity",pos:"noun",gender:"f",note:"Feminine noun. From 'gelegen' (convenient).\n'Bei Gelegenheit' (when the opportunity arises).",example:"A: Hattest du die Gelegenheit, viel zu reisen?\nB: Ja, bei jeder Gelegenheit.\nA: Was war die beste Gelegenheit?\nB: Die Gelegenheit, Hamburg zu besuchen.",exampleSrc:"A: Did you have the opportunity to travel a lot?\nB: Yes, at every opportunity.\nA: What was the best opportunity?\nB: The opportunity to visit Hamburg.",funFact:"More deliberate than Chance. A Gelegenheit is there if you look for it. 'Die Gelegenheit beim Schopf packen' (to seize the opportunity by its forelock). From 'gelegen' (convenient/situated)."},
{type:"teach",trg:"die Möglichkeit",src:"the possibility",pos:"noun",gender:"f",note:"Feminine noun. From 'möglich' (possible).\n'Es gibt viele Möglichkeiten' (there are many possibilities).",example:"A: Welche Möglichkeiten hast du jetzt?\nB: Viele! Ich kann bleiben oder weiterreisen.\nA: Was ist die beste Möglichkeit?\nB: Bleiben. Das ist die einzige Möglichkeit für mich.",exampleSrc:"A: What possibilities do you have now?\nB: Many! I can stay or travel on.\nA: What is the best possibility?\nB: Staying. That is the only possibility for me.",funFact:"The -keit suffix from -lich adjectives. Möglich becomes Möglichkeit. Possible becomes possibility. Same pattern as 'freundlich' to 'Freundlichkeit,' 'pünktlich' to 'Pünktlichkeit.'"},
{type:"teach",trg:"die Überraschung",src:"the surprise",pos:"noun",gender:"f",note:"Feminine noun. From 'überraschen' (to surprise).\nÜber (over) + raschen (to rush).",example:"A: Das Fest war eine Überraschung!\nB: Wirklich? Du hast nichts gewusst?\nA: Nein, eine totale Überraschung.\nB: Schön! Die besten Dinge sind Überraschungen.",exampleSrc:"A: The party was a surprise!\nB: Really? You did not know anything?\nA: No, a total surprise.\nB: Nice! The best things are surprises.",funFact:"Something that rushes over you unexpectedly. 'Eine Überraschungsparty' (a surprise party). 'Überraschungsei' (surprise egg, the famous Kinder toy). Verumius is planning one, in reverse: the surprise is for him."},
{type:"teach",trg:"die Überzeugung",src:"the conviction, the belief",pos:"noun",gender:"f",note:"Feminine noun. From 'überzeugen' (to convince).\n'Aus Überzeugung' (out of conviction).",example:"A: Warum bleibst du in Berlin?\nB: Aus Überzeugung. Ich glaube an diese Stadt.\nA: Das ist eine starke Überzeugung.\nB: Ja, ich bin überzeugt, dass es richtig ist.",exampleSrc:"A: Why are you staying in Berlin?\nB: Out of conviction. I believe in this city.\nA: That is a strong conviction.\nB: Yes, I am convinced that it is right.",funFact:"Stronger than Meinung (opinion). An Überzeugung is something you would defend. From 'überzeugen' (to convince). 'Überzeugungskraft' (persuasive power). When you hold an Überzeugung, it holds you too."},
{type:"teach",trg:"der Zweifel",src:"the doubt",pos:"noun",gender:"m",note:"Masculine noun. From 'zwei' (two).\n'Ohne Zweifel' (without doubt).",example:"A: Hattest du jemals Zweifel?\nB: Ja, am Beginn hatte ich viele Zweifel.\nA: Und jetzt?\nB: Keine Zweifel mehr. Ich bin sicher.",exampleSrc:"A: Did you ever have doubts?\nB: Yes, at the beginning I had many doubts.\nA: And now?\nB: No more doubts. I am sure.",funFact:"From 'zwei' (two). Doubt literally means 'being in two minds.' Same etymology as English 'doubt' (from Latin 'dubitare,' also from 'duo'/two). 'Im Zweifel' (when in doubt). Beautiful shared roots."},
{type:"teach",trg:"der Zufall",src:"the coincidence",pos:"noun",gender:"m",note:"Masculine noun. Zu (to) + Fall (fall/case).\n'Durch Zufall' (by coincidence).",example:"A: Wie hast du deine Wohnung gefunden?\nB: Durch Zufall! Ein Freund kannte jemanden.\nA: Was für ein glücklicher Zufall!\nB: Es war kein Zufall. Es war Schicksal.",exampleSrc:"A: How did you find your apartment?\nB: By coincidence! A friend knew someone.\nA: What a lucky coincidence!\nB: It was not a coincidence. It was fate.",funFact:"Something that falls to you by chance. 'Es war kein Zufall' (it was no coincidence). Was it Zufall that Verumius met Yilmaz on the wrong train? Sometimes what looks like Zufall is actually Schicksal."},
{type:"teach",trg:"der Wert",src:"the value, the worth",pos:"noun",gender:"m",note:"Masculine noun. 'Es ist viel wert' (it is worth a lot).\n'Wertvoll' (valuable), 'wertlos' (worthless).",example:"A: Was hat das größten Wert für dich?\nB: Die Freundschaften. Die haben den größten Wert.\nA: Nicht die Sprache?\nB: Die Sprache hat auch großen Wert. Aber Menschen sind wichtiger.",exampleSrc:"A: What has the greatest value for you?\nB: The friendships. Those have the greatest value.\nA: Not the language?\nB: The language also has great value. But people are more important.",funFact:"Same root as English 'worth.' 'Wert legen auf' (to place value on). The Wert of a year in Berlin: not measurable in money. Adjective 'wert' and noun 'der Wert' are related but used differently."},
{type:"teach",trg:"das Wunder",src:"the wonder, the miracle",pos:"noun",gender:"n",note:"Neuter noun. 'Kein Wunder' (no wonder).\nCognate with English 'wonder.'",example:"A: Ist es nicht ein Wunder, wie viel du gelernt hast?\nB: Ja, manchmal fühlt es sich wie ein Wunder an.\nA: Kein Wunder, du hast hart gearbeitet.\nB: Stimmt. Aber ein bisschen Wunder war auch dabei.",exampleSrc:"A: Is it not a wonder how much you have learned?\nB: Yes, sometimes it feels like a miracle.\nA: No wonder, you worked hard.\nB: True. But a bit of miracle was also involved.",funFact:"Cognate with English 'wonder.' 'Kein Wunder' (no wonder). 'Es grenzt an ein Wunder' (it borders on a miracle). 'Wunderkind' (wonder child) entered English directly from German."},
{type:"teach",trg:"der Schritt",src:"the step",pos:"noun",gender:"m",note:"Masculine noun. From 'schreiten' (to stride).\n'Schritt für Schritt' (step by step).",example:"A: Was war der wichtigste Schritt?\nB: Der erste Schritt: nach Berlin zu kommen.\nA: Und dann?\nB: Dann kam alles Schritt für Schritt.",exampleSrc:"A: What was the most important step?\nB: The first step: to come to Berlin.\nA: And then?\nB: Then everything came step by step.",funFact:"Verumius's first Schritt in Germany was at BER airport. Now he has made thousands. 'Schritt für Schritt' (step by step) is one of the most motivational German phrases. Every long journey is a series of Schritte."},
{type:"teach",trg:"der Fall",src:"the case, the fall",pos:"noun",gender:"m",note:"Masculine noun. 'Auf jeden Fall' (in any case).\n'Auf keinen Fall' (in no case/no way).",example:"A: Willst du auf jeden Fall in Berlin bleiben?\nB: Auf jeden Fall!\nA: Auf keinen Fall zurückgehen?\nB: Auf keinen Fall. Mein Leben ist hier.",exampleSrc:"A: Do you definitely want to stay in Berlin?\nB: Definitely!\nA: No way going back?\nB: No way. My life is here.",funFact:"'Auf jeden Fall' (in any case) and 'auf keinen Fall' (in no case/no way) are among the most useful German phrases. Grammar cases (Nominativ, Akkusativ, Dativ, Genitiv) are also called Fälle."},
{type:"teach",trg:"beschließen",src:"to decide, to resolve",pos:"verb",gender:null,note:"Irregular verb: beschloss, beschlossen.\nStronger than 'entscheiden.' A Beschluss is final.",example:"A: Hast du schon beschlossen, was du machen willst?\nB: Ja, ich habe beschlossen zu bleiben.\nA: Das ist eine gute Nachricht!\nB: Ja, der Beschluss steht fest.",exampleSrc:"A: Have you already decided what you want to do?\nB: Yes, I have decided to stay.\nA: That is good news!\nB: Yes, the decision is firm.",funFact:"Be- + schließen (to close). To close the matter. Stronger than entscheiden. A Beschluss is final. 'Ich habe beschlossen zu bleiben' (I have resolved to stay). Once you beschließen, the door is closed on alternatives."},
{type:"teach",trg:"entscheiden",src:"to decide",pos:"verb",gender:null,note:"Irregular: entschied, entschieden. Reflexive: 'sich entscheiden.'\n'Ich kann mich nicht entscheiden' (I cannot decide).",example:"A: Hast du dich schon entschieden?\nB: Ja, ich habe mich entschieden.\nA: Wofür?\nB: Für Berlin. Für immer.",exampleSrc:"A: Have you decided yet?\nB: Yes, I have decided.\nA: In favor of what?\nB: For Berlin. Forever.",funFact:"Ent- + scheiden (to separate). To separate the options. 'Sich entscheiden für' (to decide in favor of). 'Sich entscheiden gegen' (to decide against). Verumius hat sich für Berlin entschieden."},
{type:"teach",trg:"realisieren",src:"to realize, to implement",pos:"verb",gender:null,note:"Regular -ieren verb. Two meanings:\n1. 'Ich habe realisiert, dass...' (I realized that...)\n2. 'Einen Plan realisieren' (to implement a plan).",example:"A: Wann hast du realisiert, dass Berlin dein Zuhause ist?\nB: Irgendwann im Herbst. Plötzlich habe ich es realisiert.\nA: Was genau?\nB: Dass ich nicht mehr weg will.",exampleSrc:"A: When did you realize that Berlin is your home?\nB: Sometime in autumn. Suddenly I realized it.\nA: What exactly?\nB: That I no longer want to leave.",funFact:"The -ieren ending marks it as borrowed from French. Regular verb. Two meanings: mental realization and practical implementation. 'Einen Traum realisieren' (to make a dream come true)."},
{type:"teach",trg:"wundern",src:"to wonder, to be surprised",pos:"verb",gender:null,note:"Regular verb. Reflexive: 'sich wundern' (to be surprised).\n'Es wundert mich' (it surprises me).",example:"A: Es wundert mich, dass KD zur Feier kommt.\nB: Mich wundert das auch!\nA: Er hat sich wirklich verändert.\nB: Da wundert man sich manchmal.",exampleSrc:"A: It surprises me that KD is coming to the celebration.\nB: That surprises me too!\nA: He has really changed.\nB: Sometimes you are surprised.",funFact:"From Wunder (wonder/miracle). 'Das wundert mich nicht' (that does not surprise me). 'Sich wundern über' (to be surprised about). When something approaches the miraculous, you wundern sich."},
{type:"teach",trg:"ähnlich",src:"similar",pos:"adj",gender:null,note:"Adjective. 'Ähnlich wie...' (similar to...).\n'Sie sehen sich ähnlich' (they look similar).",example:"A: Ist Berlin ähnlich wie deine Heimatstadt?\nB: Nein, überhaupt nicht ähnlich.\nA: Was ist anders?\nB: Alles! Aber ähnlich lebendig.",exampleSrc:"A: Is Berlin similar to your hometown?\nB: No, not at all similar.\nA: What is different?\nB: Everything! But similarly lively.",funFact:"From Old High German 'ana-lih' (having the same appearance). The Umlaut ä makes it unmistakably German. 'Ähnlichkeit' (similarity). Things can be ähnlich without being gleich (identical)."},
{type:"teach",trg:"tatsächlich",src:"actually, indeed",pos:"adj",gender:null,note:"Adjective/adverb. From Tatsache (fact) + -lich.\n'Tatsächlich?' (Really?).",example:"A: Hast du tatsächlich ein ganzes Jahr durchgehalten?\nB: Tatsächlich, ja!\nA: Das hätte ich nicht gedacht.\nB: Ich tatsächlich auch nicht.",exampleSrc:"A: Did you actually hold out a whole year?\nB: Actually, yes!\nA: I would not have thought that.\nB: Actually, neither would I.",funFact:"Germans use this to express genuine surprise: 'Er ist tatsächlich geblieben?' (He actually stayed?). From Tatsache (fact) + -lich. Factual, real, indeed. A word that grounds surprise in reality."},
{type:"mc",q:"Verumius muss zwischen Bleiben und Gehen wählen. Welche zwei Wörter bedeuten beide 'to decide'?",opts:["vermissen und verbringen","ähnlich und tatsächlich","entscheiden und beschließen","wundern und realisieren"],ans:"entscheiden und beschließen",hint:"Beide Verben handeln davon, Optionen zu trennen oder eine Sache abzuschließen."},
{type:"fb",s:"Er hatte keine {1} mehr. Berlin war sein Zuhause.",a:["Zweifel"],opts:["Zweifel","Chance","Wunder","Schritt"],hint:"Welches Nomen bedeutet 'doubt'? Seine Wurzel ist die Zahl zwei.",sSrc:"He had no more doubts. Berlin was his home."},
{type:"match",pairs:[{trg:"Entscheidung",src:"decision"},{trg:"Möglichkeit",src:"possibility"},{trg:"Überraschung",src:"surprise"},{trg:"Zufall",src:"coincidence"},{trg:"beschließen",src:"to resolve"},{trg:"realisieren",src:"to realize"}]}
]},

// ==================== LESSON 3: Bevor Berlin ====================
{id:"deu_r24l3",title:"Bevor Berlin",icon:"📸",xp:15,board:true,steps:[
{type:"intro",title:"Bevor Berlin",desc:"Verumius schaut alte Fotos auf seinem Handy an. Jede Erinnerung ist ein Plusquamperfekt-Satz. Lerne, wie man beschreibt, was passiert war, bevor etwas anderes geschah.",goals:["Meistere das Plusquamperfekt (hatte/war + Partizip II)","Lerne 15 neue Wörter für Dauer, Vergleich und Bewertung","Erzähle Reihenfolgen vergangener Ereignisse"]},
{type:"story",speaker:"narrator",mood:"nostalgic",art:"berlin_apartment_photos_scrolling",trg:"Verumius scrollt durch alte Fotos. Vor einem Jahr hatte er noch kein Wort Deutsch gesprochen. Er hatte niemanden in Berlin gekannt. Und er hatte nicht gewusst, dass diese Stadt sein Leben verändern würde.",src:"Verumius scrolls through old photos. A year ago he had not spoken a single word of German. He had known nobody in Berlin. And he had not known that this city would change his life."},
{type:"teach",trg:"die Dauer",src:"the duration",pos:"noun",gender:"f",note:"Feminine noun. From 'dauern' (to last).\n'Auf Dauer' (in the long run).",example:"A: Wie lange war die Dauer deines Aufenthalts?\nB: Ein Jahr. Aber auf Dauer will ich bleiben.\nA: Also für immer?\nB: Vielleicht. Die Dauer ist noch offen.",exampleSrc:"A: How long was the duration of your stay?\nB: One year. But in the long run I want to stay.\nA: So forever?\nB: Maybe. The duration is still open.",funFact:"'Auf Dauer' (in the long run). 'Die Dauer des Aufenthalts' (the duration of the stay). How long something lasts. Verumius's stay has no set Dauer anymore. It is open-ended."},
{type:"teach",trg:"die Fortsetzung",src:"the continuation",pos:"noun",gender:"f",note:"Feminine noun. From 'fortsetzen' (to continue).\n'Fortsetzung folgt' (to be continued).",example:"A: Ist das das Ende deiner Geschichte?\nB: Nein! Fortsetzung folgt.\nA: Ich bin gespannt auf die Fortsetzung.\nB: Ich auch. Das Beste kommt noch.",exampleSrc:"A: Is this the end of your story?\nB: No! To be continued.\nA: I am excited about the continuation.\nB: Me too. The best is yet to come.",funFact:"Fort (onward) + setzen (to set). Every unit of this course has been a Fortsetzung of Verumius's story. 'Fortsetzung folgt' appears at the end of TV episodes, books, and movies. The story goes on."},
{type:"teach",trg:"das Mal",src:"the time (instance)",pos:"noun",gender:"n",note:"Neuter noun. 'Das erste Mal' (the first time).\n'Jedes Mal' (every time). Different from 'Zeit' (duration).",example:"A: Erinnerst du dich an das erste Mal in der Apotheke?\nB: Ja, jedes Mal war ich nervös.\nA: Und jetzt?\nB: Jetzt kaufe ich Medizin wie ein Profi. Jedes Mal.",exampleSrc:"A: Do you remember the first time at the pharmacy?\nB: Yes, every time I was nervous.\nA: And now?\nB: Now I buy medicine like a pro. Every time.",funFact:"'Zum ersten Mal' (for the first time). 'Zum letzten Mal' (for the last time). Mal counts occurrences. Zeit measures duration. 'Dieses Mal' (this time). 'Manchmal' (sometimes) literally means 'some times.'"},
{type:"teach",trg:"der Vergleich",src:"the comparison",pos:"noun",gender:"m",note:"Masculine noun. From 'vergleichen' (to compare).\n'Im Vergleich zu' (in comparison with).",example:"A: Wie war das erste Mal im Vergleich zu jetzt?\nB: Kein Vergleich! Am Beginn war alles so schwer.\nA: Und im Vergleich zu deiner Heimat?\nB: Berlin ist anders. Ein Vergleich ist schwierig.",exampleSrc:"A: How was the first time compared to now?\nB: No comparison! At the beginning everything was so hard.\nA: And compared to your home country?\nB: Berlin is different. A comparison is difficult.",funFact:"'Ein Vergleich hinkt' (a comparison limps = is flawed). 'Im Vergleich zu' (compared to). Comparing his first day to today: kein Vergleich. The verb 'vergleichen' is irregular: verglich, verglichen."},
{type:"teach",trg:"die Art",src:"the type, the kind, the manner",pos:"noun",gender:"f",note:"Feminine noun. 'Auf diese Art' (in this way).\n'Eine Art von...' (a kind of...). Also means species.",example:"A: Auf welche Art hat sich dein Leben verändert?\nB: Auf jede Art! Sprache, Freunde, Gewohnheiten.\nA: Das ist eine besondere Art zu leben.\nB: Ja, auf seine Art ist Berlin perfekt.",exampleSrc:"A: In what way has your life changed?\nB: In every way! Language, friends, habits.\nA: That is a special way to live.\nB: Yes, in its own way Berlin is perfect.",funFact:"A small word for a big concept. 'Auf seine Art' (in his own way). Also means 'species' in biology. 'Artenvielfalt' (biodiversity). From Latin 'ars' (skill/art), but the German meaning shifted to 'type/manner.'"},
{type:"teach",trg:"hinterlassen",src:"to leave behind",pos:"verb",gender:null,note:"Irregular: hinterließ, hinterlassen.\nHinter (behind) + lassen (to leave).\n'Spuren hinterlassen' (to leave traces).",example:"A: Was hat Berlin bei dir hinterlassen?\nB: Schöne Erinnerungen. Und ein paar Narben.\nA: Jede Erfahrung hinterlässt Spuren.\nB: Ja, und diese Spuren machen mich stärker.",exampleSrc:"A: What has Berlin left behind in you?\nB: Beautiful memories. And a few scars.\nA: Every experience leaves traces.\nB: Yes, and these traces make me stronger.",funFact:"'Spuren hinterlassen' (to leave traces). 'Eine Nachricht hinterlassen' (to leave a message). Irregular: hinterließ, hinterlassen. Not separable despite having 'hinter.' Every experience hinterlässt its mark."},
{type:"teach",trg:"lohnen",src:"to be worthwhile",pos:"verb",gender:null,note:"Regular verb. Reflexive: 'Es lohnt sich' (it is worth it).\nFrom 'Lohn' (reward).",example:"A: Hat sich das Jahr gelohnt?\nB: Ja, es hat sich absolut gelohnt.\nA: Würdest du es anderen empfehlen?\nB: Auf jeden Fall. Es lohnt sich immer.",exampleSrc:"A: Was the year worth it?\nB: Yes, it was absolutely worth it.\nA: Would you recommend it to others?\nB: Definitely. It is always worthwhile.",funFact:"When effort leads to reward. 'Der Lohn' (the wage/reward) is the root. 'Es hat sich gelohnt' (it was worth it). Reflexive construction: the 'sich' makes it about the thing being worthwhile, not about you rewarding yourself."},
{type:"teach",trg:"erfüllen",src:"to fulfill",pos:"verb",gender:null,note:"Regular verb. Er- (completion) + füllen (to fill).\n'Einen Traum erfüllen' (to fulfill a dream).",example:"A: Hat Berlin deine Erwartungen erfüllt?\nB: Ja und nein. Manche Träume hat es erfüllt.\nA: Welche?\nB: Den Traum, eine neue Sprache wirklich zu lernen.",exampleSrc:"A: Did Berlin fulfill your expectations?\nB: Yes and no. Some dreams it fulfilled.\nA: Which ones?\nB: The dream of really learning a new language.",funFact:"Er- (completion) + füllen (to fill). To fill completely. 'Sich erfüllen' (to come true). When something fills you up entirely. A Wunsch (wish) can sich erfüllen. A Versprechen (promise) must erfüllt werden."},
{type:"teach",trg:"vorkommen",src:"to occur, to seem",pos:"verb",gender:null,note:"Separable verb. Vor (before) + kommen (to come).\n'Das kommt mir bekannt vor' (that seems familiar).",example:"A: Kommt dir das nicht bekannt vor?\nB: Doch! Das kommt mir sehr bekannt vor.\nA: Das kommt öfter vor als du denkst.\nB: Es kam mir vor, als ob ich schon immer hier war.",exampleSrc:"A: Does that not seem familiar to you?\nB: Yes! That seems very familiar to me.\nA: That occurs more often than you think.\nB: It seemed to me as if I had always been here.",funFact:"Two meanings: 'Das kommt vor' (that happens/occurs) and 'Es kam ihm vor, als ob...' (It seemed to him as if...). Separable. 'Das kommt mir spanisch vor' (that seems fishy to me, literally: that seems Spanish to me)."},
{type:"teach",trg:"einzig",src:"only, sole",pos:"adj",gender:null,note:"Adjective. From 'ein' (one).\n'Der einzige Grund' (the only reason).",example:"A: War Berlin die einzige Möglichkeit?\nB: Nein, aber die einzige, die sich richtig anfühlte.\nA: Das ist der einzige Grund, der zählt.\nB: Genau. Der einzige, der wirklich zählt.",exampleSrc:"A: Was Berlin the only option?\nB: No, but the only one that felt right.\nA: That is the only reason that counts.\nB: Exactly. The only one that really counts.",funFact:"From 'ein' (one). The ultimate one. 'Einzigartig' (unique, literally one-of-a-kind). 'Kein Einziger' (not a single one). 'Das Einzige, was zählt' (the only thing that counts)."},
{type:"teach",trg:"besonder",src:"special, particular",pos:"adj",gender:null,note:"Adjective. 'Etwas Besonderes' (something special).\n'Besonders' (especially).",example:"A: Gibt es etwas Besonderes an diesem Tag?\nB: Ja, heute ist ein besonderer Tag.\nA: Was macht ihn so besonder?\nB: Genau ein Jahr Berlin. Das ist etwas ganz Besonderes.",exampleSrc:"A: Is there something special about this day?\nB: Yes, today is a special day.\nA: What makes it so special?\nB: Exactly one year of Berlin. That is something very special.",funFact:"'Im Besonderen' (in particular). 'Etwas Besonderes' uses the neuter nominalized form. No direct English cognate, but the concept is universal. Today is a besonderer Tag for Verumius."},
{type:"teach",trg:"gesamt",src:"entire, total",pos:"adj",gender:null,note:"Adjective. 'Die gesamte Stadt' (the entire city).\nStronger than 'ganz' (whole).",example:"A: Die gesamte Reise war unglaublich.\nB: Ja, das gesamte Jahr war ein Abenteuer.\nA: Insgesamt bist du zufrieden?\nB: Insgesamt absolut zufrieden.",exampleSrc:"A: The entire journey was incredible.\nB: Yes, the entire year was an adventure.\nA: Altogether you are satisfied?\nB: Altogether absolutely satisfied.",funFact:"Stronger than 'ganz' (whole). Gesamt means every single part included. 'Insgesamt' (altogether). 'Gesamtkosten' (total costs). 'Die gesamte Bevölkerung' (the entire population). Nothing left out."},
{type:"teach",trg:"gewöhnlich",src:"usually, ordinary",pos:"adj",gender:null,note:"Adjective/adverb. From Gewohnheit.\n'Gewöhnlich stehe ich um sieben auf' (I usually get up at seven).",example:"A: Was machst du gewöhnlich am Morgen?\nB: Gewöhnlich trinke ich Kaffee am Fenster.\nA: Ist das nicht gewöhnlich?\nB: Doch. Aber heute ist nichts gewöhnlich.",exampleSrc:"A: What do you usually do in the morning?\nB: Usually I drink coffee at the window.\nA: Isn't that ordinary?\nB: Yes. But today nothing is ordinary.",funFact:"Two meanings: 'usually' (adverb) and 'ordinary' (adjective). 'Etwas ganz Gewöhnliches' (something quite ordinary). But today is anything but gewöhnlich for Verumius. From the same root as Gewohnheit (habit)."},
{type:"teach",trg:"positiv",src:"positive",pos:"adj",gender:null,note:"International word. 'Positiv denken' (to think positively).\n'Ein positives Ergebnis' (a positive result).",example:"A: Wie siehst du dein Jahr? Positiv oder negativ?\nB: Sehr positiv!\nA: Was war am positivsten?\nB: Die Menschen. Die Erfahrungen. Alles positiv.",exampleSrc:"A: How do you see your year? Positive or negative?\nB: Very positive!\nA: What was the most positive?\nB: The people. The experiences. All positive.",funFact:"International vocabulary, German pronunciation. Verumius's attitude toward Berlin: positiv. Used in medicine too: 'Der Test ist positiv' (the test is positive). Same word, same meaning, worldwide."},
{type:"teach",trg:"negativ",src:"negative",pos:"adj",gender:null,note:"International word. 'Negativ bewerten' (to evaluate negatively).\n'Negative Erfahrungen' (negative experiences).",example:"A: Gab es auch negative Erfahrungen?\nB: Natürlich. Nicht alles war positiv.\nA: Zum Beispiel?\nB: Die Bürokratie. Aber selbst das war nicht nur negativ.",exampleSrc:"A: Were there also negative experiences?\nB: Of course. Not everything was positive.\nA: For example?\nB: The bureaucracy. But even that was not only negative.",funFact:"The counterpart to positiv. 'Negative Erfahrungen' (negative experiences). In medicine: 'Der Test ist negativ' (the test is negative, meaning clear/no disease). Context matters: negative can be good news at the doctor."},
{type:"tip",title:"Plusquamperfekt: Die Vergangenheit vor der Vergangenheit",text:"Das Plusquamperfekt beschreibt ein Ereignis, das VOR einem anderen vergangenen Ereignis passiert ist. Denke daran als 'die tiefere Vergangenheit.'\n\nMit hatte (die meisten Verben):\nEr hatte Deutsch gelernt. (He had learned German.)\nSie hatte das Buch gelesen. (She had read the book.)\n\nMit war (Bewegung/Zustandsänderung, wie beim Perfekt):\nEr war nach Berlin geflogen. (He had flown to Berlin.)\nSie war eingeschlafen. (She had fallen asleep.)\n\nVergleich:\nPerfekt: Er hat Deutsch gelernt. (He learned German.)\nPlusquamperfekt: Er hatte Deutsch gelernt. (He had learned German.)\n\nSignalwörter: bevor (before), nachdem (after), als (when), schon (already).",deepDive:{title:"Hatte oder war? Die gleiche Regel wie beim Perfekt",text:"Die Regel ist identisch zum Perfekt:\n\nhaben/hatte: die meisten Verben\nIch hatte gegessen. Ich hatte gelesen. Ich hatte gearbeitet.\n\nsein/war: Bewegungsverben und Zustandsänderungen\nIch war gegangen. Ich war geflogen. Ich war eingeschlafen.\n\nAuch: sein/war selbst: Ich war gewesen.\n\nDer Unterschied: Perfekt benutzt 'habe/bin', Plusquamperfekt benutzt 'hatte/war'. Die Partizip-II-Form bleibt gleich."}},
{type:"mc",q:"Wie sagt man 'She had already left' auf Deutsch?",opts:["Sie hat schon gegangen","Sie hatte schon gegangen","Sie ist schon gegangen","Sie war schon gegangen"],ans:"Sie war schon gegangen",hint:"'Gehen' benutzt im Perfekt 'sein.' Im Plusquamperfekt wird 'sein' zu 'war.'"},
{type:"fb",s:"Bevor er nach Berlin kam, {1} er kein Deutsch gesprochen.",a:["hatte"],opts:["hatte","hat","war","ist"],hint:"'Sprechen' benutzt 'haben.' Die Plusquamperfekt-Form von 'haben' ist...",sSrc:"Before he came to Berlin, he had not spoken German."},
{type:"mc",q:"Welcher Satz beschreibt etwas, das VOR Verumius' Ankunft in Berlin passierte?",opts:["Er hatte noch nie Currywurst gegessen","Er hat gestern Currywurst gegessen","Er isst gerade Currywurst","Er wird Currywurst essen"],ans:"Er hatte noch nie Currywurst gegessen",hint:"Das Plusquamperfekt zeigt die tiefere Vergangenheit, vor einem anderen vergangenen Ereignis."},
{type:"drag_fill",s:"Nachdem er das Formular {1} {2}, ging er zum Amt.",blanks:{"1":"ausgefüllt","2":"hatte"},pool:["ausgefüllt","hatte","hat","war","ausfüllen"],hint:"Im Nebensatz steht das Hilfsverb ganz am Ende. Partizip II kommt direkt davor.",sSrc:"After he had filled out the form, he went to the office."}
]},

// ==================== LESSON 4: Zukunftsmusik ====================
{id:"deu_r24l4",title:"Zukunftsmusik",icon:"🔮",xp:15,board:true,steps:[
{type:"intro",title:"Zukunftsmusik",desc:"What comes after one year? Verumius plans the future. Learn Futur I (werden + infinitive) and solidify the Plusquamperfekt. Distinguish between the past before the past and the future.",goals:["Master Futur I (werden + infinitive)","Solidify the Plusquamperfekt","Learn 14 new words for future and decisions"]},
{type:"teach",trg:"die Zukunft",src:"the future",pos:"noun",gender:"f",note:"Feminine noun. Zu (to) + Kunft (coming).\n'In Zukunft' (in the future).",example:"A: Was bringt die Zukunft?\nB: Ich weiß es nicht. Aber ich bin bereit.\nA: Die Zukunft liegt vor dir.\nB: Ja, und ich freue mich darauf.",exampleSrc:"A: What does the future bring?\nB: I do not know. But I am ready.\nA: The future lies before you.\nB: Yes, and I am looking forward to it.",funFact:"Zu (to) + Kunft (coming). What is coming toward you. 'Zukunftsmusik' (literally future-music) means pipe dreams or castles in the air. But Verumius's Zukunft in Berlin is very real."},
{type:"teach",trg:"die Planung",src:"the planning",pos:"noun",gender:"f",note:"Feminine noun. From 'planen' (to plan).\n'Die Planung steht' (the plan is set).",example:"A: Wie ist deine Planung für das nächste Jahr?\nB: Die Planung ist noch nicht fertig.\nA: Brauchst du Hilfe bei der Planung?\nB: Nein, danke. Meine Planung steht fast.",exampleSrc:"A: What is your planning for next year?\nB: The planning is not finished yet.\nA: Do you need help with the planning?\nB: No, thanks. My planning is almost set.",funFact:"Germans love a good Planung. Spontaneity makes them nervous. The -ung suffix creates the noun from 'planen.' 'Stadtplanung' (city planning). 'Familienplanung' (family planning). Everything gets planned."},
{type:"teach",trg:"der Zweck",src:"the purpose",pos:"noun",gender:"m",note:"Masculine noun. 'Zu diesem Zweck' (for this purpose).\n'Zwecklos' (pointless).",example:"A: Was ist der Zweck deiner Feier?\nB: Der Zweck? Einfach feiern, dass ich noch hier bin.\nA: Das ist ein guter Zweck!\nB: Der beste Zweck, den es gibt.",exampleSrc:"A: What is the purpose of your celebration?\nB: The purpose? Simply celebrating that I am still here.\nA: That is a good purpose!\nB: The best purpose there is.",funFact:"From Middle High German 'zwec' (nail/target). The point you aim for. 'Der Zweck heiligt die Mittel' (the end justifies the means). 'Zwecklos' (pointless, literally purpose-less)."},
{type:"teach",trg:"fortsetzen",src:"to continue",pos:"verb",gender:null,note:"Separable verb: 'Er setzt seine Reise fort.'\nFort (onward) + setzen (to set).",example:"A: Wirst du dein Deutschlernen fortsetzen?\nB: Natürlich! Ich setze es jeden Tag fort.\nA: Das ist die richtige Einstellung.\nB: Ja, ich werde es fortsetzen bis zum Ende.",exampleSrc:"A: Will you continue your German learning?\nB: Of course! I continue it every day.\nA: That is the right attitude.\nB: Yes, I will continue it until the end.",funFact:"'Wird fortgesetzt' (to be continued). The Fortsetzung of the Abenteuer. Separable: 'Er setzt seine Reise fort' (He continues his journey). In Perfekt: 'Er hat seine Reise fortgesetzt.'"},
{type:"teach",trg:"vorhaben",src:"to intend, to plan",pos:"verb",gender:null,note:"Separable verb: 'Was hast du vor?'\nVor (before) + haben (to have).",example:"A: Was hast du heute Abend vor?\nB: Ich habe vor, eine Feier zu machen.\nA: Was hast du genau vor?\nB: Lichterketten, Musik, Freunde. Alles.",exampleSrc:"A: What are your plans for this evening?\nB: I plan to have a celebration.\nA: What exactly do you have planned?\nB: Fairy lights, music, friends. Everything.",funFact:"Having something before you: a plan in mind. 'Was hast du heute vor?' (What are your plans today?) is one of the most common German questions. Separable. 'Ich habe vor zu bleiben' (I intend to stay)."},
{type:"teach",trg:"vorschlagen",src:"to suggest",pos:"verb",gender:null,note:"Separable, irregular: schlug vor, vorgeschlagen.\n'Ich schlage vor, dass...' (I suggest that...).",example:"A: Was schlägst du vor?\nB: Ich schlage vor, dass wir im Hinterhof feiern.\nA: Guter Vorschlag!\nB: Lukas hat es vorgeschlagen. Nicht ich.",exampleSrc:"A: What do you suggest?\nB: I suggest that we celebrate in the courtyard.\nA: Good suggestion!\nB: Lukas suggested it. Not me.",funFact:"Vor (before) + schlagen (to hit/strike). To strike forward with an idea. 'Der Vorschlag' (the suggestion). Irregular: schlug vor, vorgeschlagen. KD would never vorschlagen anything informal. Or so we thought."},
{type:"teach",trg:"entschließen",src:"to resolve, to decide firmly",pos:"verb",gender:null,note:"Irregular: entschloss, entschlossen. Reflexive.\n'Sich entschließen' (to make up one's mind). Stronger than entscheiden.",example:"A: Hast du dich entschlossen?\nB: Ja, ich habe mich entschlossen zu bleiben.\nA: Endgültig?\nB: Endgültig. Der Entschluss steht.",exampleSrc:"A: Have you made up your mind?\nB: Yes, I have resolved to stay.\nA: Permanently?\nB: Permanently. The resolution stands.",funFact:"Ent- + schließen (to close/lock). To unlock a decision. Stronger than entscheiden. A Beschluss is final, but an Entschluss is personal and resolute. 'Ich habe mich entschlossen' = the decision is locked."},
{type:"teach",trg:"zukünftig",src:"future (adjective)",pos:"adj",gender:null,note:"Adjective. From Zukunft + -ig.\n'Zukünftige Generationen' (future generations).",example:"A: Was sind deine zukünftigen Pläne?\nB: Mein zukünftiges Leben wird in Berlin sein.\nA: Klingt gut. Und zukünftige Reisen?\nB: Vielleicht München. Aber mein zukünftiges Zuhause ist hier.",exampleSrc:"A: What are your future plans?\nB: My future life will be in Berlin.\nA: Sounds good. And future travels?\nB: Maybe Munich. But my future home is here.",funFact:"The adjective form of what is coming. Zukunft + -ig = zukünftig. 'Zukünftige Generationen' (future generations). 'Mein zukünftiger Plan' (my future plan). A word that looks forward by nature."},
{type:"teach",trg:"weiter",src:"further, continued",pos:"adj",gender:null,note:"Adjective/adverb. 'Und so weiter' (and so on, abbreviated usw.).\n'Weitermachen' (to carry on).",example:"A: Wie geht es weiter?\nB: Ich mache weiter wie bisher.\nA: Und so weiter?\nB: Und so weiter. Schritt für Schritt.",exampleSrc:"A: What happens next?\nB: I carry on as before.\nA: And so on?\nB: And so on. Step by step.",funFact:"A word that always points forward. 'Weiterhin' (furthermore/still). 'Weitermachen' (to carry on). 'Wie geht es weiter?' (What happens next?). 'Und so weiter' (and so on) is abbreviated usw., appearing everywhere in German texts."},
{type:"teach",trg:"optimistisch",src:"optimistic",pos:"adj",gender:null,note:"From Latin 'optimus' (best). International word.\n'Ich bin optimistisch' (I am optimistic).",example:"A: Bist du optimistisch für die Zukunft?\nB: Sehr optimistisch!\nA: Warum so optimistisch?\nB: Weil ich weiß, dass ich es schaffen kann.",exampleSrc:"A: Are you optimistic about the future?\nB: Very optimistic!\nA: Why so optimistic?\nB: Because I know that I can do it.",funFact:"International word, German pronunciation with final '-isch.' Verumius war am Beginn nicht optimistisch. Jetzt schon. From Latin 'optimus' (best). The belief that the best outcome is possible."},
{type:"teach",trg:"vernünftig",src:"reasonable, sensible",pos:"adj",gender:null,note:"From 'Vernunft' (reason).\n'Eine vernünftige Entscheidung' (a sensible decision).",example:"A: War es vernünftig, nach Berlin zu kommen?\nB: Am Beginn war es nicht besonders vernünftig.\nA: Und jetzt?\nB: Jetzt war es die vernünftigste Entscheidung meines Lebens.",exampleSrc:"A: Was it reasonable to come to Berlin?\nB: At the beginning it was not particularly reasonable.\nA: And now?\nB: Now it was the most reasonable decision of my life.",funFact:"Germans value Vernunft (reason) highly. 'Sei vernünftig!' (Be reasonable!). It is the practical cousin of Weisheit (wisdom). A vernünftige Entscheidung is not exciting, but it is right."},
{type:"teach",trg:"sinnvoll",src:"meaningful, sensible",pos:"adj",gender:null,note:"Sinn (sense/meaning) + voll (full).\n'Eine sinnvolle Beschäftigung' (a meaningful activity).",example:"A: War das Jahr sinnvoll?\nB: Jeder Tag war sinnvoll.\nA: Was war am sinnvollsten?\nB: Das Deutschlernen. Es war die sinnvollste Investition.",exampleSrc:"A: Was the year meaningful?\nB: Every day was meaningful.\nA: What was the most meaningful?\nB: Learning German. It was the most meaningful investment.",funFact:"Full of meaning. The opposite of sinnlos. Sinn (sense/meaning) + voll (full). 'Eine sinnvolle Beschäftigung' (a meaningful activity). When something has Sinn, it is sinnvoll. When it lacks Sinn, it is sinnlos."},
{type:"teach",trg:"sinnlos",src:"pointless, meaningless",pos:"adj",gender:null,note:"Sinn + -los (without).\n'Es ist sinnlos zu warten' (It is pointless to wait).",example:"A: Manchmal dachte ich: das ist sinnlos.\nB: Was war sinnlos?\nA: Deutsch lernen, wenn niemand zuhört.\nB: Aber es war nicht sinnlos. Du hast es geschafft.",exampleSrc:"A: Sometimes I thought: this is pointless.\nB: What was pointless?\nA: Learning German when nobody is listening.\nB: But it was not pointless. You made it.",funFact:"Without purpose, without direction. The fear Verumius felt on day one. 'Sinnlose Gewalt' (senseless violence). But nothing in his year was truly sinnlos. Every struggle had its hidden Sinn."},
{type:"teach",trg:"wohl",src:"probably, well",pos:"adv",gender:null,note:"Adverb. Two meanings: probability and wellness.\n'Er wird wohl kommen' (He will probably come).\n'Sich wohl fühlen' (to feel well/comfortable).",example:"A: Er wird wohl heute Abend kommen.\nB: Wirklich? Fühlst du dich wohl damit?\nA: Ja, ich fühle mich sehr wohl.\nB: Na dann, er kommt wohl.",exampleSrc:"A: He will probably come tonight.\nB: Really? Do you feel comfortable with that?\nA: Yes, I feel very comfortable.\nB: Well then, he probably will come.",funFact:"Two meanings: wellness and probability. 'Wohl oder übel' (like it or not, literally well or ill). 'Wohlfühlen' (to feel comfortable) is a key German concept. The overlap shows that what feels right is probably right."},
{type:"tip",title:"Futur I: werden + Infinitiv",text:"Futur I drückt Zukunftspläne, Vorhersagen und Absichten aus.\n\nFormel: werden (konjugiert) + Infinitiv (am Ende)\n\nich werde bleiben\ndu wirst bleiben\ner/sie/es wird bleiben\nwir werden bleiben\nsie/Sie werden bleiben\n\nBeispiele:\nIch werde in Berlin bleiben. (I will stay in Berlin.)\nEr wird morgen kommen. (He will come tomorrow.)\nWir werden das schaffen. (We will manage that.)\n\nIm Nebensatz: ...dass ich in Berlin bleiben werde.\n\nHinweis: Im Alltag benutzt man oft Präsens + Zeitwort: 'Ich bleibe morgen.' Futur I betont die Absicht: 'Ich WERDE bleiben' = bewusste Entscheidung.",deepDive:{title:"Wann Futur I, wann Präsens für die Zukunft?",text:"Im Alltag benutzt Deutsch oft Präsens + Zeitangabe:\n'Ich fliege morgen nach Hamburg.' (I am flying to Hamburg tomorrow.)\n\nFutur I betont:\n1. Absicht: 'Ich werde bleiben.' (deliberate commitment)\n2. Vorhersage: 'Es wird regnen.' (prediction)\n3. Vermutung: 'Er wird wohl schlafen.' (He is probably sleeping.)\n\nVerumius sagt 'Ich werde bleiben' statt 'Ich bleibe', weil es eine bewusste, feierliche Entscheidung ist."}},
{type:"verb_table",title:"Futur I: bleiben (to stay)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"werde bleiben",src:"I will stay"},{pronoun:"du",form:"wirst bleiben",src:"you will stay"},{pronoun:"er/sie/es",form:"wird bleiben",src:"he/she/it will stay"}]},{label:"Plural",rows:[{pronoun:"wir",form:"werden bleiben",src:"we will stay"},{pronoun:"ihr",form:"werdet bleiben",src:"you (pl.) will stay"},{pronoun:"sie/Sie",form:"werden bleiben",src:"they/you (formal) will stay"}]}],note:"Werden ist unregelmäßig: ich werde, du wirst, er wird, wir werden, ihr werdet, sie werden. Im Nebensatz steht werden am Ende: '...dass ich bleiben werde.'"},
{type:"mc",q:"Wie sagt man 'We will continue' auf Deutsch?",opts:["Wir fortsetzen werden","Wir haben fortgesetzt","Wir werden fortsetzen","Wir werden fortgesetzt"],ans:"Wir werden fortsetzen",hint:"Futur I: konjugiertes werden + Infinitiv am Ende."},
{type:"fb",s:"Verumius {1} in Berlin bleiben.",a:["wird"],opts:["wird","werde","wirst","werden"],hint:"Verumius ist dritte Person Singular (er). Welche Form von werden passt?",sSrc:"Verumius will stay in Berlin."},
{type:"mc",q:"Welcher Satz schaut ZURÜCK in die Vergangenheit vor der Vergangenheit?",opts:["Er entscheidet gerade","Er hatte schon entschieden","Er hat entschieden","Er wird entscheiden"],ans:"Er hatte schon entschieden",hint:"Plusquamperfekt benutzt hatte/war + Partizip II für die tiefere Vergangenheit."},
{type:"drag_fill",s:"Ich {1} morgen einen Vorschlag {2}.",blanks:{"1":"werde","2":"machen"},pool:["werde","wirst","machen","gemacht","machte"],hint:"Futur I: konjugiertes werden + Infinitiv. Erste Person Singular.",sSrc:"I will make a suggestion tomorrow."},
{type:"mc",q:"Verumius hat sich an Berlin gewöhnt. _____ will er bleiben. Welche Konjunktion bedeutet 'therefore'?",opts:["Obwohl","Sonst","Trotzdem","Deshalb"],ans:"Deshalb",hint:"Diese Konjunktion drückt eine Ursache-Wirkungs-Beziehung aus. Sie ist KEINE unterordnende Konjunktion."},
{type:"fb",s:"Nachdem er ein Jahr in Berlin verbracht hatte, {1} er sich entschlossen zu bleiben.",a:["hatte"],opts:["hatte","hat","wird","war"],hint:"Plusquamperfekt von 'sich entschließen' (benutzt haben). Das Präteritum von haben ist...",sSrc:"After he had spent a year in Berlin, he had resolved to stay."},
{type:"mc",q:"Welcher Satz drückt ein stärkeres Engagement zum Bleiben aus?",opts:["Ich bleibe morgen","Ich werde bleiben","Ich bin geblieben","Ich blieb"],ans:"Ich werde bleiben",hint:"Futur I betont Absicht und bewusstes Engagement stärker als Präsens."}
]},

// ==================== LESSON 5: Vorbereitung ====================
{id:"deu_r24l5",title:"Vorbereitung",icon:"✨",xp:15,board:true,steps:[
{type:"intro",title:"Vorbereitung",desc:"Der Hinterhof wird vorbereitet. Lichterketten von Lukas, Hildi beaufsichtigt die Mülltonnenumsetzung. Lerne Feier- und Vorbereitungsvokabular und übe Futur I in Planungssätzen.",goals:["Lerne 18 neue Wörter für Feiern und Vorbereitung","Übe Futur I in Planungssätzen","Drücke Zustimmung und Akzeptanz aus"]},
{type:"story",speaker:"narrator",mood:"preparations",art:"berlin_courtyard_setup_fairylights",trg:"Der Hinterhof verwandelt sich. Verumius hängt Lichterketten auf, die er sich von Lukas geliehen hat. Hildi kommt mit Tee und inspiziert die Arbeit. 'Die Mülltonnen dürfen nicht einfach so verschoben werden,' sagt sie. 'Aber ich habe zugestimmt. Ausnahmsweise.'",src:"The courtyard transforms. Verumius hangs up fairy lights that he borrowed from Lukas. Hildi comes with tea and inspects the work. 'The recycling bins must not simply be moved,' she says. 'But I have agreed. Exceptionally.'"},
{type:"teach",trg:"die Gratulation",src:"the congratulations",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'gratulatio.'\n'Herzliche Gratulation' (warm congratulations).",example:"A: Herzliche Gratulation zum Jubiläum!\nB: Danke für die Gratulation!\nA: Ein Jahr Berlin verdient eine Gratulation.\nB: Und eine Feier. Definitiv eine Feier.",exampleSrc:"A: Warm congratulations on the anniversary!\nB: Thank you for the congratulations!\nA: One year of Berlin deserves congratulations.\nB: And a celebration. Definitely a celebration.",funFact:"'Herzlichen Glückwunsch' is more common for the moment of congratulating, but 'Gratulation' works too. From Latin 'gratulatio.' 'Zur Gratulation' (for congratulations). International root, German form."},
{type:"teach",trg:"die Leistung",src:"the achievement, the performance",pos:"noun",gender:"f",note:"Feminine noun. From 'leisten' (to achieve).\n'Eine tolle Leistung' (a great achievement).",example:"A: Ein Jahr Deutsch lernen ist eine tolle Leistung!\nB: Danke! Es war harte Arbeit.\nA: Leistung kommt von Leisten.\nB: Und Leisten kommt von: nicht aufgeben.",exampleSrc:"A: One year of learning German is a great achievement!\nB: Thanks! It was hard work.\nA: Achievement comes from achieving.\nB: And achieving comes from: not giving up.",funFact:"Germans respect Leistung deeply. 'Leistungsdruck' (performance pressure) is a common topic. 'Leistungsgesellschaft' (meritocracy, literally: achievement society). Verumius's year in German: eine echte Leistung."},
{type:"teach",trg:"das Souvenir",src:"the souvenir",pos:"noun",gender:"n",note:"Neuter noun. From French 'souvenir' (to remember).\nGermans use it exactly like English.",example:"A: Hast du Souvenirs aus deinem Jahr?\nB: Ja, aber die besten Souvenirs sind Erinnerungen.\nA: Und der Kaktus?\nB: Paragraph? Das ist kein Souvenir. Das ist Familie.",exampleSrc:"A: Do you have souvenirs from your year?\nB: Yes, but the best souvenirs are memories.\nA: And the cactus?\nB: Paragraph? That is not a souvenir. That is family.",funFact:"From French 'souvenir' (to remember). Das Souvenir is neuter. Every Reise deserves a Souvenir. But Verumius's best Souvenirs are not objects: they are memories and friendships."},
{type:"teach",trg:"die Verabredung",src:"the appointment, the date",pos:"noun",gender:"f",note:"Feminine noun. From 'verabreden' (to arrange).\nPersonal, not official (that is Termin).",example:"A: Hast du heute Abend eine Verabredung?\nB: Ja, eine Verabredung mit allen Freunden.\nA: Klingt nach einer schönen Verabredung.\nB: Die schönste Verabredung des Jahres.",exampleSrc:"A: Do you have a date tonight?\nB: Yes, a date with all friends.\nA: Sounds like a nice date.\nB: The nicest date of the year.",funFact:"Ver- + ab + reden (to talk). Different from Termin (official appointment). A Verabredung is personal. 'Ich habe eine Verabredung' can mean a meeting, a date, or any personal arrangement."},
{type:"teach",trg:"das Video",src:"the video",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'video' (I see).\nPronounced 'VEE-day-oh' in German.",example:"A: Lukas dreht ein Video von der Vorbereitung.\nB: Ein Video? Wofür?\nA: Für die Erinnerung. Ein Video vom Fest.\nB: Gute Idee! Videos sind die besten Souvenirs.",exampleSrc:"A: Lukas is shooting a video of the preparation.\nB: A video? What for?\nA: For the memory. A video of the celebration.\nB: Good idea! Videos are the best souvenirs.",funFact:"Pronounced 'VEE-day-oh' in German, not like English. From Latin 'video' (I see). 'Ein Video drehen' (to shoot a video). 'Videoanruf' (video call). Das Video is neuter."},
{type:"teach",trg:"die Wanderung",src:"the hike",pos:"noun",gender:"f",note:"Feminine noun. From 'wandern' (to hike).\n'Eine Wanderung machen' (to go on a hike).",example:"A: Erinnerst du dich an die Wanderung im Grunewald?\nB: Ja! Meine erste Wanderung in Deutschland.\nA: Das war eine schöne Wanderung.\nB: Die Wanderung hat mir gezeigt, wie grün Berlin ist.",exampleSrc:"A: Do you remember the hike in the Grunewald?\nB: Yes! My first hike in Germany.\nA: That was a beautiful hike.\nB: The hike showed me how green Berlin is.",funFact:"Germans walk. A lot. Wandertag (hiking day) is a school tradition. 'Wanderweg' (hiking trail), 'Wanderlust' (the desire to wander). English borrowed 'Wanderlust' directly from German."},
{type:"teach",trg:"die Übernachtung",src:"the overnight stay",pos:"noun",gender:"f",note:"Feminine noun. Über (over) + Nacht (night) + -ung.\n'Übernachtung mit Frühstück' (bed and breakfast).",example:"A: Wie viele Übernachtungen hattest du auf Reisen?\nB: Viele! Die Übernachtung in Hamburg war am besten.\nA: Was kostet eine Übernachtung dort?\nB: Etwa sechzig Euro pro Übernachtung.",exampleSrc:"A: How many overnight stays did you have on trips?\nB: Many! The overnight stay in Hamburg was the best.\nA: What does an overnight stay cost there?\nB: About sixty euros per overnight stay.",funFact:"The word literally means 'over-nighting.' German hotels count in Übernachtungen, not nights. 'Übernachtung mit Frühstück' (bed and breakfast, abbreviated ÜF). A very practical compound."},
{type:"teach",trg:"überraschen",src:"to surprise",pos:"verb",gender:null,note:"Regular verb. Not separable!\n'Ich bin überrascht' (I am surprised).",example:"A: Ich will meine Freunde überraschen.\nB: Wie willst du sie überraschen?\nA: Mit einer Feier im Hinterhof.\nB: Das wird sie bestimmt überraschen!",exampleSrc:"A: I want to surprise my friends.\nB: How do you want to surprise them?\nA: With a celebration in the courtyard.\nB: That will definitely surprise them!",funFact:"Über (over) + raschen (to rush). Something rushes over you unexpectedly. Not separable: 'ich überrasche,' NOT 'ich rasche über.' 'Lass dich überraschen' (let yourself be surprised)."},
{type:"teach",trg:"übertreiben",src:"to exaggerate",pos:"verb",gender:null,note:"Irregular: übertrieb, übertrieben. Not separable.\n'Übertreib nicht!' (Don't exaggerate!).",example:"A: Sind dreihundert Lichterketten zu viel?\nB: Ja, du übertreibst!\nA: Ich übertreibe nie. Na gut, vielleicht ein bisschen.\nB: Ein bisschen? Du übertreibst immer!",exampleSrc:"A: Are three hundred fairy lights too many?\nB: Yes, you are exaggerating!\nA: I never exaggerate. Well, maybe a little.\nB: A little? You always exaggerate!",funFact:"Über (over) + treiben (to drive). To drive something over the top. Irregular: übertrieb, übertrieben. Hildi denkt, Verumius übertreibt mit den Lichterketten. She might be right."},
{type:"teach",trg:"verabschieden",src:"to say goodbye",pos:"verb",gender:null,note:"Regular verb. Reflexive: 'sich verabschieden.'\nVer- + Abschied (farewell).",example:"A: Wann verabschieden sich die Gäste?\nB: Hoffentlich nicht zu früh!\nA: Ich will mich noch nicht verabschieden.\nB: Niemand will sich heute verabschieden.",exampleSrc:"A: When will the guests say goodbye?\nB: Hopefully not too early!\nA: I do not want to say goodbye yet.\nB: Nobody wants to say goodbye today.",funFact:"'Sich von jemandem verabschieden' (to say goodbye to someone). But tonight, nobody wants to sich verabschieden. The opposite of Abschied: a celebration of staying."},
{type:"teach",trg:"verstecken",src:"to hide",pos:"verb",gender:null,note:"Regular verb. Ver- + stecken (to put/stick).\n'Versteck dich!' (Hide yourself!).",example:"A: Wo hast du die Geschenke versteckt?\nB: Ich habe sie in der Küche versteckt.\nA: Gut versteckt?\nB: Sehr gut versteckt. Niemand hat sie gefunden.",exampleSrc:"A: Where did you hide the presents?\nB: I hid them in the kitchen.\nA: Well hidden?\nB: Very well hidden. Nobody found them.",funFact:"'Ostereier verstecken' (to hide Easter eggs) is a beloved German tradition. Verumius has Geschenke for his friends versteckt in the apartment. 'Versteckspiel' (hide and seek)."},
{type:"teach",trg:"aussuchen",src:"to pick out, to choose",pos:"verb",gender:null,note:"Separable verb: 'Such dir etwas aus!'\nAus (out) + suchen (to search).",example:"A: Hast du die Musik ausgesucht?\nB: Ja, ich habe Lukas' Lieblingslieder ausgesucht.\nA: Such dir auch etwas Ruhiges aus.\nB: Gute Idee. Ich suche noch etwas aus.",exampleSrc:"A: Did you pick out the music?\nB: Yes, I picked out Lukas's favorite songs.\nA: Pick out something quiet too.\nB: Good idea. I will pick out something else.",funFact:"To search something out of a group. Separable: 'Such dir etwas aus!' (Pick something out for yourself!). 'Ich habe mir die Lichterketten ausgesucht' (I picked out the fairy lights)."},
{type:"teach",trg:"zusagen",src:"to accept (an invitation), to appeal to",pos:"verb",gender:null,note:"Separable verb. Zu (to) + sagen (to say).\n'Alle haben zugesagt' (Everyone accepted).",example:"A: Haben alle zugesagt?\nB: Ja, alle haben zugesagt!\nA: Auch Yilmaz?\nB: Auch Yilmaz. Sie hat sofort zugesagt.",exampleSrc:"A: Has everyone accepted?\nB: Yes, everyone accepted!\nA: Even Yilmaz?\nB: Even Yilmaz. She accepted immediately.",funFact:"To say yes to something. 'Alle haben zugesagt' means everyone confirmed they would come. Also: 'Das sagt mir zu' (That appeals to me). Separable. Everyone has zugesagt for tonight."},
{type:"teach",trg:"zustimmen",src:"to agree",pos:"verb",gender:null,note:"Separable verb. Zu (to) + stimmen (to vote/be correct).\n'Ich stimme zu' (I agree).",example:"A: Stimmst du dem Plan zu?\nB: Ja, ich stimme voll zu.\nA: Hildi hat auch zugestimmt.\nB: Wenn Hildi zustimmt, ist alles gut.",exampleSrc:"A: Do you agree with the plan?\nB: Yes, I fully agree.\nA: Hildi also agreed.\nB: If Hildi agrees, everything is fine.",funFact:"To add your voice in favor. Separable: 'Ich stimme zu.' 'Zustimmung' (agreement/consent). Hildi hat der Verlegung der Mülltonnen zugestimmt. When Hildi agrees, you know it is serious."},
{type:"teach",trg:"gewohnt",src:"accustomed, used to",pos:"adj",gender:null,note:"From 'gewöhnen.' 'Ich bin es gewohnt' (I am used to it).\n'Wie gewohnt' (as usual). Different from 'gewöhnlich.'",example:"A: Bist du das deutsche Wetter gewohnt?\nB: Ja, ich bin es gewohnt.\nA: Wie gewohnt regnet es heute.\nB: Wie gewohnt. Aber ich bin es gewohnt.",exampleSrc:"A: Are you used to the German weather?\nB: Yes, I am used to it.\nA: As usual, it is raining today.\nB: As usual. But I am used to it.",funFact:"Different from 'gewöhnlich' (ordinary). Gewohnt is personal experience: 'Ich bin es gewohnt' (I am used to it). Gewöhnlich is general frequency: 'gewöhnlich regnet es' (it usually rains)."},
{type:"teach",trg:"üblich",src:"usual, customary",pos:"adj",gender:null,note:"From 'Übung' (practice). 'Wie üblich' (as usual).\n'Das ist hier üblich' (that is customary here).",example:"A: Ist es üblich, ein Jubiläum zu feiern?\nB: Ja, das ist hier üblich.\nA: Ist es auch üblich, alle einzuladen?\nB: Natürlich. Das ist ganz üblich.",exampleSrc:"A: Is it customary to celebrate an anniversary?\nB: Yes, that is customary here.\nA: Is it also customary to invite everyone?\nB: Of course. That is quite customary.",funFact:"What practice has established as normal. 'Üblicher Preis' (standard price). 'Wie üblich' (as usual). From 'Übung' (practice/exercise). What you practice becomes üblich. Custom comes from repetition."},
{type:"teach",trg:"selbstverständlich",src:"of course, self-evident",pos:"adj",gender:null,note:"Selbst (self) + verständlich (understandable).\n'Selbstverständlich!' (Of course!).",example:"A: Darf ich Hildi einladen?\nB: Selbstverständlich!\nA: Und KD?\nB: Das ist selbstverständlich auch in Ordnung.",exampleSrc:"A: May I invite Hildi?\nB: Of course!\nA: And KD?\nB: That is of course also fine.",funFact:"One of the longest everyday adjectives in German: 19 letters. Selbst (self) + verständlich (understandable). Self-evident. 'Das ist doch selbstverständlich' (That goes without saying). Germans love this word for things they consider obvious."},
{type:"teach",trg:"ungewöhnlich",src:"unusual",pos:"adj",gender:null,note:"Un- (not) + gewöhnlich (ordinary).\n'Ein ungewöhnlicher Tag' (an unusual day).",example:"A: Diese Feier ist ungewöhnlich.\nB: Warum ungewöhnlich?\nA: Weil KD kommt. Das ist ungewöhnlich.\nB: Stimmt. Aber heute ist ein ungewöhnlicher Tag.",exampleSrc:"A: This celebration is unusual.\nB: Why unusual?\nA: Because KD is coming. That is unusual.\nB: True. But today is an unusual day.",funFact:"Un- negates the adjective. Gewöhnlich (ordinary) becomes ungewöhnlich (unusual). 'Es ist ungewöhnlich warm' (It is unusually warm). Today is beautifully ungewöhnlich for Verumius."},
{type:"mc",q:"Alle Freunde von Verumius haben bestätigt, dass sie zur Feier kommen. Welches Verb bedeutet 'to accept an invitation'?",opts:["zustimmen","verabschieden","aussuchen","zusagen"],ans:"zusagen",hint:"Dieses trennbare Verb bedeutet wörtlich 'zu-sagen' und bezieht sich auf das Akzeptieren von Einladungen."},
{type:"fb",s:"Hildi hat dem Plan {1}. Die Mülltonnen dürfen umgestellt werden.",a:["zugestimmt"],opts:["zugestimmt","zugesagt","überrascht","übertrieben"],hint:"Welches Verb bedeutet, seine Zustimmung zu geben? Es bedeutet wörtlich 'seine Stimme hinzufügen.'",sSrc:"Hildi agreed to the plan. The recycling bins may be moved."},
{type:"drag_fill",s:"Verumius {1} alles {2}. Morgen {3} er seine Freunde einladen.",blanks:{"1":"hat","2":"vorbereitet","3":"wird"},pool:["hat","hatte","vorbereitet","wird","werde","vorbereiten"],hint:"Erster Teilsatz: Perfekt (hat + Partizip II). Zweiter Teilsatz: Futur I (wird + Infinitiv). Der Infinitiv steht schon im Satz.",sSrc:"Verumius has prepared everything. Tomorrow he will invite his friends."}
]},

// ==================== LESSON 6: Das Fest ====================
{id:"deu_r24l6",title:"Das Fest",icon:"🎶",xp:15,board:true,steps:[
{type:"intro",title:"Das Fest",desc:"Der Hinterhof leuchtet. Alle sind da: Hildi im guten Kleid, Lukas mit Gitarre, Mia mit Wein aus Leipzig, Yilmaz elegant wie immer. Und dann: KD kommt durch den Torbogen. Mit einem Kaktus.",goals:["Erlebe die Hoffeier mit allen Charakteren","Übe alle B1-Grammatik in natürlichem Dialog","Lerne Wörter für Ratschlag, Abschied und Widerstandsfähigkeit"]},
{type:"story",speaker:"narrator",mood:"warm-cinematic",art:"berlin_courtyard_fairylights_evening",trg:"Der Hinterhof leuchtet. Lichterketten hängen zwischen den Mauern. Hildi hat Tee gemacht, wie immer. Lukas stimmt seine Gitarre. Mia hat Wein aus Leipzig mitgebracht. Yilmaz lehnt an der Mauer und lächelt. Dann geht das Tor auf.",src:"The courtyard glows. Fairy lights hang between the walls. Hildi made tea, as always. Lukas tunes his guitar. Mia brought wine from Leipzig. Yilmaz leans against the wall and smiles. Then the gate opens."},
{type:"story",speaker:"KD",mood:"awkward-warm",art:"berlin_courtyard_kd_cactus",trg:"Ich habe gehört, dass es eine Feier gibt. Ich hatte nicht vorgehabt zu kommen, aber... hier. Für Paragraph.",src:"I heard there is a celebration. I had not intended to come, but... here. For Paragraph."},
{type:"teach",trg:"der Abschied",src:"the farewell",pos:"noun",gender:"m",note:"Masculine noun. From 'abscheiden' (to depart).\n'Abschied nehmen' (to say farewell).",example:"A: Ist das ein Abschied?\nB: Nein! Das ist das Gegenteil von Abschied.\nA: Kein Abschied also?\nB: Kein Abschied. Ein Anfang.",exampleSrc:"A: Is this a farewell?\nB: No! This is the opposite of farewell.\nA: No farewell then?\nB: No farewell. A beginning.",funFact:"From 'abscheiden' (to depart). 'Abschiedsparty' (farewell party). But this is not an Abschied. This is a celebration of staying. The opposite of goodbye. Sometimes the most powerful word is the one you do not need."},
{type:"teach",trg:"das Pech",src:"the bad luck",pos:"noun",gender:"n",note:"Neuter noun. Originally meant 'pitch/tar.'\n'Pech haben' (to have bad luck).",example:"A: Ich hatte Pech am Beginn. Alles ging schief.\nB: Aber jetzt hast du kein Pech mehr.\nA: Stimmt. Mein Pech hat sich in Glück verwandelt.\nB: Pech gehabt? Nein. Glück gehabt!",exampleSrc:"A: I had bad luck at the beginning. Everything went wrong.\nB: But now you have no more bad luck.\nA: True. My bad luck turned into good luck.\nB: Bad luck? No. Good luck!",funFact:"Originally meant 'pitch/tar' (sticky black substance). 'Pech haben' (to have bad luck). 'Pech gehabt!' (Tough luck!). The opposite of 'Glück.' KD sagt: sein Pech ist, dass er keine Feier verpassen kann."},
{type:"teach",trg:"der Rat",src:"the advice",pos:"noun",gender:"m",note:"Masculine noun. 'Einen Rat geben' (to give advice).\nAlso: 'Stadtrat' (city council).",example:"A: Hast du einen Rat für mich?\nB: Ja: Bleib, wo du glücklich bist.\nA: Das ist ein guter Rat.\nB: Guter Rat ist teuer, sagt man. Aber dieser ist umsonst.",exampleSrc:"A: Do you have advice for me?\nB: Yes: Stay where you are happy.\nA: That is good advice.\nB: Good advice is expensive, they say. But this one is free.",funFact:"The person who gives counsel AND the counsel itself. 'Guter Rat ist teuer' (good advice is expensive = hard to find). 'Stadtrat' (city council). 'Rathaus' (town hall, literally: advice house)."},
{type:"teach",trg:"der Ratschlag",src:"the piece of advice",pos:"noun",gender:"m",note:"Masculine noun. Rat + Schlag (strike/suggestion).\nMore concrete than 'Rat.'",example:"A: Yilmaz hat mir einen Ratschlag gegeben.\nB: Welchen Ratschlag?\nA: Sie sagte: 'Hör auf dein Herz.'\nB: Das ist der beste Ratschlag überhaupt.",exampleSrc:"A: Yilmaz gave me a piece of advice.\nB: Which piece of advice?\nA: She said: 'Listen to your heart.'\nB: That is the best piece of advice ever.",funFact:"Rat + Schlag (strike/suggestion). A piece of advice. More concrete than Rat. 'Ein guter Ratschlag' (a good piece of advice). Yilmaz hat immer einen Ratschlag für Verumius. Usually a good one."},
{type:"teach",trg:"die Zustimmung",src:"the agreement, the consent",pos:"noun",gender:"f",note:"Feminine noun. From 'zustimmen' (to agree).\n'Allgemeine Zustimmung' (general agreement).",example:"A: Wir feiern heute Abend!\nB: Hast du Hildis Zustimmung?\nA: Ja, sie hat ihre Zustimmung gegeben.\nB: Dann ist alles klar. Allgemeine Zustimmung!",exampleSrc:"A: We are celebrating tonight!\nB: Do you have Hildi's consent?\nA: Yes, she gave her consent.\nB: Then everything is clear. General agreement!",funFact:"From 'zustimmen' (to agree). 'Zustimmung finden' (to find approval). 'Allgemeine Zustimmung' (general agreement). The whole group nods: Zustimmung. When everyone stimmt zu, a decision has power."},
{type:"teach",trg:"leisten",src:"to achieve, to afford",pos:"verb",gender:null,note:"Regular verb. 'Sich etwas leisten können' (to be able to afford).\n'Einen Beitrag leisten' (to make a contribution).",example:"A: Was hast du in einem Jahr geleistet?\nB: Ich habe eine neue Sprache gelernt.\nA: Das ist eine große Leistung.\nB: Ja, und ich kann mir jetzt ein Leben hier leisten.",exampleSrc:"A: What did you achieve in one year?\nB: I learned a new language.\nA: That is a great achievement.\nB: Yes, and I can now afford a life here.",funFact:"Versatile: effort, money, and contribution. 'Gute Arbeit leisten' (to do good work). 'Sich etwas leisten können' (to be able to afford something). 'Einen Beitrag leisten' (to make a contribution). One verb, three domains."},
{type:"teach",trg:"zählen",src:"to count",pos:"verb",gender:null,note:"Regular verb. 'Das zählt' (that counts/matters).\n'Auf jemanden zählen' (to count on someone).",example:"A: Auf wen kannst du zählen?\nB: Auf meine Freunde. Auf jeden Einzelnen.\nA: Das ist es, was zählt.\nB: Ja, Freundschaft zählt mehr als alles andere.",exampleSrc:"A: Who can you count on?\nB: On my friends. On each and every one.\nA: That is what counts.\nB: Yes, friendship counts more than anything else.",funFact:"Cognate with English 'tell' (originally meant to count/list). 'Zählen bis zehn' (to count to ten). 'Das zählt' (that counts/matters). 'Auf jemanden zählen' (to count on someone). Diese Freunde: auf sie kann man zählen."},
{type:"teach",trg:"werfen",src:"to throw",pos:"verb",gender:null,note:"Irregular: wirft, warf, geworfen.\n'Einen Blick werfen' (to cast a glance).",example:"A: Lukas wirft Verumius eine Dose zu.\nB: Was ist darin?\nA: Ein Mixtape. Er hat es selbst gemacht.\nB: Er hat sein Herz in diese Musik geworfen.",exampleSrc:"A: Lukas throws Verumius a can.\nB: What is inside?\nA: A mixtape. He made it himself.\nB: He threw his heart into this music.",funFact:"Irregular: wirft, warf, geworfen. 'Einen Blick werfen' (to cast a glance). 'Einen Ball werfen' (to throw a ball). Lukas wirft Verumius eine Dose zu. Darin: ein Mixtape. A gesture worth more than words."},
{type:"teach",trg:"wenden",src:"to turn",pos:"verb",gender:null,note:"Mixed conjugation: wendete or wandte.\n'Sich an jemanden wenden' (to turn to someone for help).",example:"A: An wen hast du dich gewendet, wenn du Hilfe brauchtest?\nB: An meine Freunde. Ich habe mich immer an sie gewandt.\nA: Das zeigt Vertrauen.\nB: Ja, man muss sich an Menschen wenden können.",exampleSrc:"A: Who did you turn to when you needed help?\nB: To my friends. I always turned to them.\nA: That shows trust.\nB: Yes, you must be able to turn to people.",funFact:"'Sich an jemanden wenden' (to turn to someone for help). 'Bitte wenden' (please turn over, on forms). Mixed conjugation: wendete or wandte. 'Die Wendung' (the turn/twist). Every story needs a Wendung."},
{type:"teach",trg:"zugehen",src:"to approach, to go toward",pos:"verb",gender:null,note:"Separable verb. 'Er geht auf sie zu' (He walks toward her).\nAlso emotional: to make the first move.",example:"A: KD geht auf Verumius zu.\nB: Das ist ungewöhnlich. Er geht sonst nie auf Leute zu.\nA: Aber heute geht er auf alle zu.\nB: Es geht auf Mitternacht zu. Zeit für eine Rede.",exampleSrc:"A: KD walks toward Verumius.\nB: That is unusual. He never usually approaches people.\nA: But today he approaches everyone.\nB: It is approaching midnight. Time for a speech.",funFact:"Zu (to) + gehen (to go). 'Auf jemanden zugehen' is also emotional: to make the first move, to reach out. KD geht auf Verumius zu. A bureaucrat making the first social move. That is real growth."},
{type:"teach",trg:"zurechtkommen",src:"to manage, to cope",pos:"verb",gender:null,note:"Separable verb. 'Er kommt gut zurecht' (He manages well).\n'Ich komme damit zurecht' (I can cope with that).",example:"A: Kommst du in Berlin zurecht?\nB: Ja, ich komme sehr gut zurecht.\nA: Auch mit der Sprache?\nB: Auch damit. Ich komme mit allem zurecht.",exampleSrc:"A: Are you managing in Berlin?\nB: Yes, I am managing very well.\nA: Also with the language?\nB: Also with that. I am managing with everything.",funFact:"The quintessential B1 verb: managing life in a new language. Zurecht (into order) + kommen (to come). 'Er kommt gut zurecht' shows competence and resilience. The whole B1 journey in one verb."},
{type:"teach",trg:"entschlossen",src:"determined, resolute",pos:"adj",gender:null,note:"Past participle of 'entschließen,' used as adjective.\n'Er ist entschlossen' (He is determined).",example:"A: Bist du entschlossen zu bleiben?\nB: Ja, ich bin fest entschlossen.\nA: Deine Augen sagen: entschlossen.\nB: Absolut entschlossen. Keine Zweifel.",exampleSrc:"A: Are you determined to stay?\nB: Yes, I am firmly determined.\nA: Your eyes say: determined.\nB: Absolutely determined. No doubts.",funFact:"Past participle of entschließen, used as adjective. 'Eine entschlossene Haltung' (a resolute attitude). Verumius ist entschlossen: er bleibt. When a participle becomes an adjective, the action becomes a quality."},
{type:"teach",trg:"erwachsen",src:"grown-up, adult",pos:"adj",gender:null,note:"Past participle of 'erwachsen' (to grow up).\n'Erwachsene' (adults).",example:"A: Fühlst du dich erwachsen?\nB: Mehr als vor einem Jahr.\nA: Was bedeutet erwachsen für dich?\nB: Verantwortung übernehmen. In einer fremden Sprache.",exampleSrc:"A: Do you feel grown-up?\nB: More than a year ago.\nA: What does grown-up mean to you?\nB: Taking responsibility. In a foreign language.",funFact:"Past participle of 'erwachsen' (to grow up). 'Erwachsene' (adults). 'Erwachsenwerden' (growing up). This year has made Verumius erwachsen in a new language. Maturity comes through challenge."},
{type:"teach",trg:"verständlich",src:"understandable",pos:"adj",gender:null,note:"From 'verstehen' (to understand).\n'Das ist verständlich' (That is understandable).",example:"A: Dein Deutsch ist jetzt sehr verständlich.\nB: Wirklich? Ich kann mich verständlich machen?\nA: Absolut verständlich. Klar und deutlich.\nB: Das ist verständlich das schönste Kompliment.",exampleSrc:"A: Your German is now very understandable.\nB: Really? I can make myself understood?\nA: Absolutely understandable. Clear and distinct.\nB: That is understandably the nicest compliment.",funFact:"'Sich verständlich machen' (to make oneself understood). Verumius kann sich jetzt auf Deutsch verständlich machen. Ein Jahr hat gereicht. From verstehen (to understand) + -lich."},
{type:"teach",trg:"übrig",src:"remaining, left over",pos:"adj",gender:null,note:"'Es bleibt nichts übrig' (nothing remains).\n'Übrigens' (by the way) comes from this root.",example:"A: Was bleibt übrig nach einem Jahr?\nB: Viel. Erinnerungen, Freundschaften, Können.\nA: Und eine Frage bleibt übrig.\nB: Ja, eine einzige: bleiben oder gehen?",exampleSrc:"A: What remains after a year?\nB: A lot. Memories, friendships, skills.\nA: And one question remains.\nB: Yes, a single one: stay or go?",funFact:"'Übrigens' (by the way) comes from this root. 'Das Übrige' (the rest). After tonight, only one question is übrig: bleiben oder gehen? 'Im Übrigen' (moreover/incidentally)."},
{type:"teach",trg:"umgekehrt",src:"reversed, vice versa",pos:"adj",gender:null,note:"Um (around) + gekehrt (turned).\n'Und umgekehrt' (and vice versa).",example:"A: KD erwartet Formalität. Er bekommt Freundschaft.\nB: Genau umgekehrt!\nA: Und umgekehrt: Verumius erwartete Bürokratie.\nB: Und er bekam einen Freund. Genau umgekehrt.",exampleSrc:"A: KD expected formality. He gets friendship.\nB: Exactly the other way around!\nA: And vice versa: Verumius expected bureaucracy.\nB: And he got a friend. Exactly the other way around.",funFact:"'Es ist genau umgekehrt' (It is exactly the other way around). KD expected formality. Er bekam Freundschaft. Genau umgekehrt. Life has a way of turning expectations on their head."},
{type:"story",speaker:"Yilmaz",mood:"warm-proud",art:"berlin_courtyard_yilmaz_toast",trg:"Weißt du noch, als du mich auf dem Zug gefragt hattest, ob Berlin schwer ist? Ich hatte gelacht. Jetzt wirst du verstehen, warum.",src:"Do you remember when you had asked me on the train whether Berlin is hard? I had laughed. Now you will understand why."},
{type:"mc",q:"KD sagt: 'Ich hatte nicht vorgehabt zu kommen.' Welches Tempus ist das und was bedeutet es?",opts:["Präteritum: er hatte keine Pläne","Futur I: er wird nicht kommen wollen","Perfekt: er hat nicht vor gehabt zu kommen","Plusquamperfekt: er hatte nicht vor, zu kommen"],ans:"Plusquamperfekt: er hatte nicht vor, zu kommen",hint:"Hatte + Partizip II = Plusquamperfekt. Die Vergangenheit vor der Vergangenheit."},
{type:"fb",s:"Yilmaz sagt: 'Jetzt {1} du verstehen, warum.'",a:["wirst"],opts:["wirst","wurdest","hast","hattest"],hint:"Futur I: werden (konjugiert für du) + Infinitiv. Welche Form von werden passt zu du?",sSrc:"Yilmaz says: 'Now you will understand why.'"},
{type:"mc",q:"KD hat einen Kaktus mitgebracht 'für Paragraph.' Wer oder was ist Paragraph?",opts:["Ein juristisches Dokument","Der Hinterhof","KDs Haustier","Verumius' vorhandener Kaktus"],ans:"Verumius' vorhandener Kaktus",hint:"KD hat ein Geschwisterchen für etwas mitgebracht, das Verumius schon hat."},
{type:"match",pairs:[{trg:"Abschied",src:"farewell"},{trg:"Ratschlag",src:"piece of advice"},{trg:"zurechtkommen",src:"to manage/cope"},{trg:"entschlossen",src:"determined"},{trg:"zählen",src:"to count"},{trg:"übrig",src:"remaining"}]}
]},

// ==================== LESSON 7: Rückblick und Ausblick ====================
{id:"deu_r24l7",title:"Rückblick und Ausblick",icon:"📝",xp:15,board:true,steps:[
{type:"intro",title:"Rückblick und Ausblick",desc:"Test everything you have learned in B1. Plusquamperfekt, Futur I, Konjunktiv II, passive, relative clauses, subclause word order. Prove you are ready for B2.",goals:["Test all major B1 grammar constructions","Show you can mix tenses, moods, and structures","Prove your readiness for B2"]},
{type:"tip",title:"Tempusübersicht: Wann was benutzen",text:"Präsens: jetzt, allgemeine Wahrheiten, geplante Zukunft\nPerfekt: gesprochene Vergangenheit\nPräteritum: geschriebene/erzählende Vergangenheit\nPlusquamperfekt: vor der Vergangenheit (Nachdem er gegessen hatte, ging er)\nFutur I: Zukunftspläne\n\nPrüfung: Erzähltexte benutzen Präteritum. Mündliche Aufgaben benutzen Perfekt.",deepDive:{title:"Plusquamperfekt + nachdem/bevor",text:"Das Plusquamperfekt + nachdem/bevor-Muster wird häufig geprüft:\n'Nachdem ich die Prüfung bestanden hatte, feierte ich.'\nNebensatz = Plusquamperfekt, Hauptsatz = Präteritum.\n\nDieses Muster zeigt zeitliche Abfolge in der Vergangenheit.\nEs ist einer der häufigsten Testpunkte in Goethe B1."}},
{type:"tip",title:"Nomen-Verb-Verbindungen: Ein Vorgeschmack auf B2",text:"Feste Nomen-Verb-Verbindungen ersetzen einfache Verben:\n\nentscheiden = eine Entscheidung treffen\nbeeinflussen = Einfluss nehmen auf\nbeitragen = einen Beitrag leisten\n\nDiese Verbindungen werden in akademischem Schreiben, Geschäftssprache und Prüfungsaufsätzen erwartet.\n\nDu wirst sie in B2 vertiefen. Hier der erste Kontakt."},
{type:"teach",trg:"die Wandrung",src:"the walk, the journey (variant of Wanderung)",pos:"noun",gender:"f",note:"Feminine noun. Regional variant of 'Wanderung.'\n'Eine Wandrung durch Erinnerungen' (a walk through memories).",example:"A: Diese Lektion ist eine Wandrung durch B1.\nB: Eine Wandrung durch alles, was wir gelernt haben.\nA: Bist du bereit für die Wandrung?\nB: Bereit. Schritt für Schritt.",exampleSrc:"A: This lesson is a walk through B1.\nB: A walk through everything we have learned.\nA: Are you ready for the walk?\nB: Ready. Step by step.",funFact:"Variant spelling of Wanderung found in some regions. Both spellings appear on trail signs across Germany. 'Eine Wandrung durch die Erinnerungen' (a walk through memories). This lesson is your Wandrung through B1."},
{type:"teach",trg:"worüber",src:"about what",pos:"pron",gender:null,note:"Pronominal adverb. Wo + r + über.\n'Worüber sprichst du?' (What are you talking about?).",example:"A: Worüber denkst du nach?\nB: Worüber? Über das letzte Jahr.\nA: Worüber freust du dich am meisten?\nB: Worüber ich mich am meisten freue? Über alles.",exampleSrc:"A: What are you thinking about?\nB: About what? About the last year.\nA: What are you most happy about?\nB: What I am most happy about? About everything.",funFact:"Used when the object is a thing, not a person. For people: 'Über wen?' For things: 'Worüber?' Pronominal adverbs combine 'wo(r)' with a preposition. 'Darüber' is the answer form."},
{type:"teach",trg:"worum",src:"about what, for what",pos:"pron",gender:null,note:"Pronominal adverb. Wo + r + um.\n'Worum geht es?' (What is it about?).",example:"A: Worum geht es bei dieser Feier?\nB: Es geht darum, dass ich ein Jahr hier bin.\nA: Worum geht es wirklich?\nB: Darum, dass Berlin mein Zuhause ist.",exampleSrc:"A: What is this celebration about?\nB: It is about the fact that I have been here for a year.\nA: What is it really about?\nB: About the fact that Berlin is my home.",funFact:"The pair: worum for questions, darum for answers. 'Es geht darum, dass...' (It is about the fact that...). 'Worum geht es?' is one of the most useful German questions. It cuts to the core."},
{type:"teach",trg:"möglicherweise",src:"possibly",pos:"adv",gender:null,note:"Adverb of uncertainty. Möglich + -erweise.\nMore formal than 'vielleicht.'",example:"A: Wirst du für immer in Berlin bleiben?\nB: Möglicherweise. Wer weiß?\nA: Möglicherweise ist das die beste Entscheidung.\nB: Möglicherweise. Aber wahrscheinlich.",exampleSrc:"A: Will you stay in Berlin forever?\nB: Possibly. Who knows?\nA: Possibly that is the best decision.\nB: Possibly. But probably.",funFact:"The -erweise suffix creates manner adverbs from adjectives. Möglich (possible) + -erweise = möglicherweise (possibly). More formal than 'vielleicht.' Same pattern as 'normalerweise,' 'glücklicherweise.'"},
{type:"teach",trg:"möglichst",src:"as ... as possible",pos:"adv",gender:null,note:"From 'möglich.' Always paired with another word.\n'Möglichst schnell' (as quickly as possible).",example:"A: Ich will möglichst lange in Berlin bleiben.\nB: Möglichst für immer?\nA: Möglichst bald eine Entscheidung treffen.\nB: Mach es möglichst richtig.",exampleSrc:"A: I want to stay in Berlin as long as possible.\nB: As long as forever if possible?\nA: Make a decision as soon as possible.\nB: Do it as correctly as possible.",funFact:"Always paired with another adjective or adverb to create a superlative goal. 'Möglichst schnell' (as quickly as possible). 'Möglichst bald' (as soon as possible). A word that pushes toward the maximum."},
{type:"teach",trg:"nirgendwo",src:"nowhere",pos:"adv",gender:null,note:"Nirgend + wo. 'Nirgendwo sonst' (nowhere else).\nOpposite of 'irgendwo' (somewhere) and 'überall' (everywhere).",example:"A: Nirgendwo sonst fühle ich mich so zu Hause.\nB: Nirgendwo? Nicht einmal in deiner Heimat?\nA: Nirgendwo. Berlin ist einzigartig.\nB: Du hast nirgendwo anders so viel gelernt.",exampleSrc:"A: Nowhere else do I feel so at home.\nB: Nowhere? Not even in your home country?\nA: Nowhere. Berlin is unique.\nB: Nowhere else have you learned so much.",funFact:"Verumius felt nirgendwo zu Hause before he came to Berlin. Now he feels at home nirgendwo else. The opposite of 'irgendwo' (somewhere) and 'überall' (everywhere). Somewhere between those extremes lies home."},
{type:"teach",trg:"normalerweise",src:"normally, usually",pos:"adv",gender:null,note:"Normal + -erweise.\n'Normalerweise stehe ich früh auf' (I normally get up early).",example:"A: Was machst du normalerweise am Wochenende?\nB: Normalerweise gehe ich spazieren.\nA: Aber heute ist kein normaler Tag.\nB: Nein, normalerweise feiert man kein Jubiläum.",exampleSrc:"A: What do you normally do on the weekend?\nB: Normally I go for a walk.\nA: But today is not a normal day.\nB: No, you normally do not celebrate an anniversary.",funFact:"Same -erweise pattern as möglicherweise. German builds adverbs systematically from adjectives with this suffix. Normal + -erweise = normalerweise. Once you see the pattern, you can understand dozens of adverbs."},
{type:"teach",trg:"umsonst",src:"for free, in vain",pos:"adv",gender:null,note:"Two opposite-feeling meanings!\n1. 'Das war umsonst' (That was free).\n2. 'Das war alles umsonst' (That was all in vain).",example:"A: War das ganze Jahr umsonst?\nB: Umsonst? Auf keinen Fall!\nA: Die Erfahrung war nicht umsonst.\nB: Und das Fest heute ist auch fast umsonst. Kostet nichts!",exampleSrc:"A: Was the whole year in vain?\nB: In vain? No way!\nA: The experience was not in vain.\nB: And the celebration today is also almost free. Costs nothing!",funFact:"Two opposite-feeling meanings: 'for free' AND 'in vain.' Context decides. 'Umsonst und draußen' = free outdoor event. 'Das war alles umsonst' = pointless. One word, two worlds."},
{type:"teach",trg:"voneinander",src:"from each other",pos:"adv",gender:null,note:"Von (from) + einander (each other).\n'Voneinander lernen' (to learn from each other).",example:"A: Was habt ihr voneinander gelernt?\nB: Alles! Wir haben so viel voneinander gelernt.\nA: Und jetzt verabschiedet ihr euch voneinander?\nB: Nein. Wir bleiben. Alle.",exampleSrc:"A: What did you learn from each other?\nB: Everything! We learned so much from each other.\nA: And now you are saying goodbye to each other?\nB: No. We are staying. All of us.",funFact:"'Voneinander lernen' (to learn from each other). 'Sich voneinander verabschieden' (to say goodbye to each other). The friends tonight have voneinander gelernt. German builds reciprocal expressions with einander."},
{type:"teach",trg:"zumindest",src:"at least",pos:"adv",gender:null,note:"'Zumindest hat er es versucht' (At least he tried).\nStronger emphasis than 'wenigstens.'",example:"A: Hat sich alles gelohnt?\nB: Zumindest habe ich es versucht.\nA: Mehr als versucht! Du hast es geschafft.\nB: Zumindest das. Und zumindest bin ich nicht allein.",exampleSrc:"A: Was it all worth it?\nB: At least I tried.\nA: More than tried! You made it.\nB: At least that. And at least I am not alone.",funFact:"A word of consolation and minimum standards. Stronger emphasis than 'wenigstens.' 'Zumindest weiß ich jetzt Bescheid' (At least now I know). When you cannot say 'alles,' you can always say 'zumindest.'"},
{type:"mc",q:"Nachdem Verumius ein Jahr in Berlin verbracht hatte, _____ er sich entschlossen zu bleiben. Deshalb _____ er seinen Vermieter an.",opts:["hatte ... rief","hatte ... ruft","war ... rief","hat ... rief"],ans:"hatte ... rief",hint:"Erste Lücke: Plusquamperfekt (Hilfsverb im Präteritum + Partizip II). Zweite Lücke: Präteritum für die Haupterzählung nach 'deshalb.'"},
{type:"fb",s:"Verumius {1} seinen Freunden sagen, dass er bleiben wird.",a:["wird"],opts:["wird","hat","hatte","wäre"],hint:"Futur I: werden (konjugiert) + Infinitiv. Dritte Person Singular.",sSrc:"Verumius will tell his friends that he will stay."},
{type:"mc",q:"Wenn Verumius nicht nach Berlin gekommen wäre, _____ er seine Freunde nie kennengelernt.",opts:["wird","hat","hätte","hatte"],ans:"hätte",hint:"Konjunktiv II für irreale Bedingungen. Welche Form nimmt 'haben' im Konjunktiv II an?"},
{type:"drag_fill",s:"Obwohl er anfangs Probleme {1} {2}, {3} er jetzt gut zurecht.",blanks:{"1":"gehabt","2":"hatte","3":"kommt"},pool:["gehabt","hatte","hat","kommt","kam","haben"],hint:"Erster Teilsatz: Plusquamperfekt im Nebensatz (Partizip II + hatte am Ende). Zweiter Teilsatz: Präsens für den aktuellen Zustand.",sSrc:"Although he had had problems at the beginning, he now manages well."},
{type:"mc",q:"Welcher Satz steht im Passiv?",opts:["Die Lichterketten hängen im Hof","Verumius wird die Lichterketten aufhängen","Lukas hat die Lichterketten aufgehängt","Die Lichterketten wurden aufgehängt"],ans:"Die Lichterketten wurden aufgehängt",hint:"Passiv = werden/wurden + Partizip II. Das Subjekt empfängt die Handlung."},
{type:"fb",s:"Der Mann, {1} den Kaktus mitgebracht hat, heißt KD.",a:["der"],opts:["der","den","dem","die"],hint:"Das Relativpronomen ersetzt 'der Mann' (maskulin Nominativ) als Subjekt des Relativsatzes.",sSrc:"The man who brought the cactus is called KD."},
{type:"mc",q:"Verumius fragt sich, _____ er richtig entschieden hat.",opts:["wenn","weil","dass","ob"],ans:"ob",hint:"Für indirekte Ja/Nein-Fragen benutzt Deutsch 'ob' (whether)."},
{type:"drag_fill",s:"Er glaubt, dass er in Zukunft gut {1} {2}.",blanks:{"1":"zurechtkommen","2":"wird"},pool:["zurechtkommen","wird","werde","zurechtkommt","kommen"],hint:"Futur I im dass-Satz: Infinitiv + werden am Ende.",sSrc:"He believes that he will manage well in the future."},
{type:"mc",q:"Verumius hat viel gelernt. _____ fühlt er sich jetzt sicher. Welche Konjunktion passt?",opts:["Trotzdem","Deshalb","Sonst","Obwohl"],ans:"Deshalb",hint:"Der zweite Satz ist eine logische Konsequenz des ersten. Welche Konjunktion bedeutet 'therefore'?"},
{type:"fb",s:"Er hat beschlossen, in Berlin zu {1}.",a:["bleiben"],opts:["bleiben","geblieben","bleibt","blieb"],hint:"Nach 'zu' im Infinitivsatz steht das Verb im Infinitiv.",sSrc:"He has decided to stay in Berlin."},
{type:"match",pairs:[{trg:"hatte gesehen",src:"Plusquamperfekt"},{trg:"wird bleiben",src:"Futur I"},{trg:"wäre gekommen",src:"Konjunktiv II"},{trg:"wurde gebaut",src:"Passiv"}]}
]},

// ==================== LESSON 8: Ich werde bleiben ====================
{id:"deu_r24l8",title:"Ich werde bleiben",icon:"🏠",xp:15,board:true,steps:[
{type:"intro",title:"Ich werde bleiben",desc:"Die Gäste sind gegangen. Die Lichterketten leuchten noch. Verumius sitzt allein im Hof, umgeben von Geschenken: Hildis Teetasse, Lukas' Mixtape, Mias Wein, Yilmaz' Roman, KDs Kaktus. Es ist Zeit für eine Entscheidung.",goals:["Vervollständige den emotionalen Bogen","Meistere die letzten 16 Vokabeln","Höre Verumius' Entscheidung","Erhalte einen Ausblick auf B2"]},
{type:"story",speaker:"narrator",mood:"quiet-triumphant",art:"berlin_courtyard_night_gifts",trg:"Die Gäste sind gegangen. Die Lichterketten leuchten noch. Auf dem Tisch stehen die Geschenke: Hildis Teetasse, Lukas' Mixtape, Mias Wein, Yilmaz' Roman und KDs Kaktus. Der kleine Bruder von Paragraph. Verumius sitzt allein im Hof und lächelt.",src:"The guests have gone. The fairy lights still glow. On the table stand the gifts: Hildi's teacup, Lukas's mixtape, Mia's wine, Yilmaz's novel, and KD's cactus. Paragraph's little brother. Verumius sits alone in the courtyard and smiles."},
{type:"teach",trg:"der Augenblick",src:"the moment, the instant",pos:"noun",gender:"m",note:"Masculine noun. Auge (eye) + Blick (glance).\n'Einen Augenblick bitte' (one moment please).",example:"A: Dieser Augenblick ist perfekt.\nB: Genieß den Augenblick.\nA: Einen Augenblick bitte. Ich will mich erinnern.\nB: Manche Augenblicke vergisst man nie.",exampleSrc:"A: This moment is perfect.\nB: Enjoy the moment.\nA: One moment please. I want to remember.\nB: Some moments you never forget.",funFact:"Auge (eye) + Blick (glance). The time it takes for one glance. 'Im Augenblick' (at the moment). This Augenblick, in this courtyard, is the one Verumius will remember forever."},
{type:"teach",trg:"besetzen",src:"to occupy, to fill (a position)",pos:"verb",gender:null,note:"Regular verb. Be- + setzen (to set).\n'Der Platz ist besetzt' (the seat is taken).",example:"A: Ist dieser Platz besetzt?\nB: Ja, dieser Platz ist besetzt. Von mir.\nA: Du hast deinen Platz in Berlin besetzt.\nB: Und niemand kann ihn mir mehr nehmen.",exampleSrc:"A: Is this seat taken?\nB: Yes, this seat is taken. By me.\nA: You have claimed your place in Berlin.\nB: And nobody can take it from me anymore.",funFact:"'Der Platz ist besetzt' (the seat is taken). 'Eine Stelle besetzen' (to fill a position). Verumius hat seinen Platz in Berlin besetzt. Nobody else can sit there now. The seat is taken."},
{type:"teach",trg:"abschreiben",src:"to copy, to write off",pos:"verb",gender:null,note:"Separable verb. Ab (off) + schreiben (to write).\n'Schreib das nicht ab!' (Don't write that off!).",example:"A: Manche haben mich abgeschrieben.\nB: Abgeschrieben? Warum?\nA: Sie dachten, ich schaffe es nicht.\nB: Und jetzt? Sie haben sich geirrt. Nicht abschreiben!",exampleSrc:"A: Some people wrote me off.\nB: Wrote you off? Why?\nA: They thought I would not make it.\nB: And now? They were wrong. Do not write off!",funFact:"Two meanings: 'von jemandem abschreiben' (to copy from someone, like cheating) and 'jemanden abschreiben' (to write someone off). Separable. Verumius's old life: abgeschrieben. New chapter begins."},
{type:"teach",trg:"verwechseln",src:"to confuse, to mix up",pos:"verb",gender:null,note:"Regular verb. Ver- + wechseln (to change/exchange).\n'Verwechsle mich nicht mit...' (Don't confuse me with...).",example:"A: Verwechsle mich nicht mit einem Touristen!\nB: Du wirst nicht mehr mit einem Anfänger verwechselt.\nA: Das ist ein Kompliment.\nB: Ja, man verwechselt dich mit einem Berliner.",exampleSrc:"A: Don't confuse me with a tourist!\nB: You are no longer confused with a beginner.\nA: That is a compliment.\nB: Yes, they confuse you with a Berliner.",funFact:"Ver- + wechseln (to change/exchange). 'Verwechslungsgefahr' (risk of confusion). Verumius wird nicht mehr mit einem Anfänger verwechselt. From confused newcomer to resident: that is growth."},
{type:"teach",trg:"vermuten",src:"to suspect, to assume",pos:"verb",gender:null,note:"Regular verb. Ver- + Mut (originally: mind/thought).\n'Ich vermute, dass...' (I suspect that...).",example:"A: Ich vermute, dass du bleiben wirst.\nB: Richtig vermutet!\nA: Das habe ich schon lange vermutet.\nB: Vermutlich hattest du recht.",exampleSrc:"A: I suspect that you will stay.\nB: Correctly suspected!\nA: I have suspected that for a long time.\nB: Presumably you were right.",funFact:"'Vermutlich' (presumably) is the adverb. To form a thought about something uncertain. Ver- + Mut (courage, originally: mind/thought). 'Ich vermute, dass...' (I suspect that...). Regular verb."},
{type:"teach",trg:"zweifeln",src:"to doubt",pos:"verb",gender:null,note:"Regular verb. From 'Zweifel' (doubt).\n'An etwas zweifeln' (to doubt something).",example:"A: Hast du jemals gezweifelt?\nB: Ja, oft. Ich habe an mir gezweifelt.\nA: Und jetzt?\nB: Jetzt zweifle ich nicht mehr. Nicht an Berlin.",exampleSrc:"A: Did you ever doubt?\nB: Yes, often. I doubted myself.\nA: And now?\nB: Now I no longer doubt. Not about Berlin.",funFact:"From Zweifel (doubt). 'An etwas zweifeln' (to doubt something). 'Ich zweifle nicht daran' (I do not doubt it). Verumius hat aufgehört zu zweifeln. Berlin ist sein Zuhause. Doubt ended, certainty began."},
{type:"teach",trg:"wert",src:"worth (adjective)",pos:"adj",gender:null,note:"Adjective. 'Es ist es wert' (It is worth it).\nDifferent from 'der Wert' (noun).",example:"A: War dieses Jahr es wert?\nB: Jede Sekunde war es wert.\nA: Jede Sekunde?\nB: Ja. Auch die schwierigen. Auch die waren es wert.",exampleSrc:"A: Was this year worth it?\nB: Every second was worth it.\nA: Every second?\nB: Yes. Even the difficult ones. Even those were worth it.",funFact:"The adjective needs an object: etwas ist X wert. Different from der Wert (noun). 'Der Mühe wert' (worth the effort). War dieses Jahr es wert? Ja. Every single day."},
{type:"teach",trg:"wertlos",src:"worthless",pos:"adj",gender:null,note:"Wert + -los (without).\n'Wertloser Kram' (worthless junk).",example:"A: Manche Dinge aus dem ersten Monat sind wertlos.\nB: Wertlos? Nein! Nichts davon ist wertlos.\nA: Auch die Fehler?\nB: Vor allem die Fehler. Die sind am wenigsten wertlos.",exampleSrc:"A: Some things from the first month are worthless.\nB: Worthless? No! None of it is worthless.\nA: Even the mistakes?\nB: Especially the mistakes. Those are the least worthless.",funFact:"The -los suffix strips away value. But nothing from this year was truly wertlos. Every struggle had its Sinn. Wertlos is the shadow that makes wertvoll shine brighter."},
{type:"teach",trg:"wertvoll",src:"valuable",pos:"adj",gender:null,note:"Wert + voll (full). Full of worth.\n'Wertvolle Erinnerungen' (valuable memories).",example:"A: Was ist das Wertvollste aus diesem Jahr?\nB: Die Freundschaften. Die sind am wertvollsten.\nA: Wertvoller als die Sprache?\nB: Ja. Aber die Sprache hat sie mir gegeben.",exampleSrc:"A: What is the most valuable thing from this year?\nB: The friendships. Those are the most valuable.\nA: More valuable than the language?\nB: Yes. But the language gave them to me.",funFact:"Wertvoll and wertlos are perfect antonyms. The same root, opposite suffixes. Full of worth versus empty of it. 'Wertvolle Erinnerungen' (valuable memories). The suffix -voll always adds abundance."},
{type:"teach",trg:"zufällig",src:"by chance, coincidental",pos:"adj",gender:null,note:"From Zufall (coincidence).\n'Weißt du zufällig...?' (Do you happen to know...?).",example:"A: War es zufällig, dass du nach Berlin kamst?\nB: Ja, es war zufällig. Aber dass ich blieb, war kein Zufall.\nA: Weißt du zufällig, wann die nächste Feier ist?\nB: Nächstes Jahr. Vielleicht. Nicht zufällig.",exampleSrc:"A: Was it by chance that you came to Berlin?\nB: Yes, it was by chance. But that I stayed was no coincidence.\nA: Do you happen to know when the next celebration is?\nB: Next year. Maybe. Not by chance.",funFact:"Also used politely: 'Weißt du zufällig...?' (Do you happen to know...?). Meeting Yilmaz: zufällig. Bleiben: nicht zufällig. The difference between what happens to you and what you choose."},
{type:"teach",trg:"zuverlässig",src:"reliable",pos:"adj",gender:null,note:"Zu + verlässig (dependable).\n'Ein zuverlässiger Freund' (a reliable friend).",example:"A: Wer ist der zuverlässigste Mensch in deinem Leben?\nB: Alle meine Freunde sind zuverlässig.\nA: Auch KD?\nB: Überraschend zuverlässig. Auf seine Art.",exampleSrc:"A: Who is the most reliable person in your life?\nB: All my friends are reliable.\nA: Even KD?\nB: Surprisingly reliable. In his own way.",funFact:"'Zuverlässig wie eine Schweizer Uhr' (reliable as a Swiss watch). Hildi: zuverlässig. KD: überraschend zuverlässig. Reliability is one of the most valued traits in German culture."},
{type:"teach",trg:"los",src:"loose, off, going",pos:"adv",gender:null,note:"'Los!' (Go!/Let's go!). 'Was ist los?' (What's the matter?).\nAs prefix: losfahren, loslassen, loswerden.",example:"A: Es geht los! Das neue Kapitel fängt an.\nB: Los! Auf in die Zukunft!\nA: Was ist los? Du siehst aufgeregt aus.\nB: Nichts ist los. Alles ist gut. Es geht weiter.",exampleSrc:"A: It's starting! The new chapter begins.\nB: Let's go! On to the future!\nA: What's the matter? You look excited.\nB: Nothing is the matter. Everything is good. It goes on.",funFact:"'Los!' (Go!/Let's go!). 'Was ist los?' (What's the matter?). 'Es geht los' (It's starting). As a prefix: losfahren (to depart), loslassen (to let go), loswerden (to get rid of). The starting gun of German life."},
{type:"teach",trg:"durcheinander",src:"mixed up, confused",pos:"adv",gender:null,note:"Durch (through) + einander (each other).\nAlso a noun: 'ein Durcheinander' (a mess).",example:"A: Am Beginn war alles durcheinander.\nB: Ja, ein einziges Durcheinander.\nA: Und jetzt?\nB: Jetzt ist Ordnung. Kein Durcheinander mehr.",exampleSrc:"A: At the beginning everything was mixed up.\nB: Yes, one big mess.\nA: And now?\nB: Now there is order. No more chaos.",funFact:"Verumius's first months: ein einziges Durcheinander. Now: Ordnung. Also a noun: 'ein Durcheinander' (a mess/chaos). The word itself sounds chaotic: through-each-other. From chaos to clarity in one year."},
{type:"teach",trg:"äußerlich",src:"externally, outwardly",pos:"adj",gender:null,note:"From 'äußer' (outer/external).\nOpposite of 'innerlich' (inwardly).",example:"A: Hast du dich verändert?\nB: Äußerlich vielleicht nicht so viel.\nA: Und innerlich?\nB: Innerlich komplett. Nicht nur äußerlich.",exampleSrc:"A: Have you changed?\nB: Externally maybe not so much.\nA: And internally?\nB: Internally completely. Not just externally.",funFact:"The opposite of 'innerlich' (inwardly). 'Äußerliche Veränderungen' (external changes). Berlin has changed Verumius: nicht nur äußerlich, sondern auch innerlich. The visible and invisible transformation."},
{type:"teach",trg:"-weis / -weise",src:"suffix: in the manner of",pos:"part",gender:null,note:"Creates adverbs from adjectives.\nnormalerweise, möglicherweise, ausnahmsweise.\nOne of German's most productive suffixes.",example:"A: Normalerweise feiere ich nicht.\nB: Ausnahmsweise also?\nA: Ja, ausnahmsweise. Glücklicherweise sind alle da.\nB: Interessanterweise sogar KD.",exampleSrc:"A: I normally do not celebrate.\nB: Exceptionally then?\nA: Yes, exceptionally. Fortunately everyone is here.\nB: Interestingly even KD.",funFact:"One of German's most productive suffixes. Creates adverbs: 'normalerweise' (normally), 'möglicherweise' (possibly), 'ausnahmsweise' (exceptionally), 'glücklicherweise' (fortunately). Once you see -weise, you see it everywhere. It unlocks dozens of adverbs."},
{type:"story",speaker:"narrator",mood:"proud-quiet",art:"berlin_courtyard_night_reflection",trg:"Vor einem Jahr hatte er nichts verstanden. Jetzt versteht er fast alles. Nicht nur die Sprache, sondern auch die Stadt, die Menschen, die Regeln, die kleinen Wunder des Alltags. Er hatte gezweifelt, ob er es schaffen würde. Er hatte es geschafft.",src:"A year ago he had understood nothing. Now he understands almost everything. Not just the language, but also the city, the people, the rules, the small wonders of everyday life. He had doubted whether he would manage it. He managed it."},
{type:"story",speaker:"Verumius",mood:"resolute",art:"berlin_courtyard_night_decision",trg:"Ich bleibe. Ich werde bleiben. Und jetzt... wird es ernst.",src:"I am staying. I will stay. And now... it gets serious."},
{type:"tip",title:"Brücke zu B2: Was kommt als Nächstes",text:"Du hast B1 abgeschlossen! Du kannst jetzt:\n\nVergangene Ereignisse in mehreren Zeiten erzählen (Perfekt, Präteritum, Plusquamperfekt)\nÜber die Zukunft sprechen (Futur I)\nBedingungen und Wünsche ausdrücken (Konjunktiv II)\nKomplexe Sätze bauen (Nebensatz, Relativsätze, Infinitivsätze)\nPassiv verstehen und benutzen\n\nIn B2 erwartet dich:\nKonjunktiv I (indirekte Rede: 'Er sagte, er sei müde')\nErweiterte Adjektivkonstruktionen ('das in Berlin stattfindende Festival')\nGenitiv im täglichen Gebrauch\nAkademisches und professionelles Deutsch\nVerumius an der Universität\n\n'Ich werde bleiben. Und jetzt wird es ernst.'",deepDive:{title:"Der Weg von A1 bis hierher",text:"Denk an den Beginn: Verumius auf dem falschen Zug, kein Wort Deutsch. Jetzt: 3.298 Wörter, alle Grammatikkonstruktionen von A1 bis B1, und eine Entscheidung. Die Reise von 'Hallo' bis 'Ich werde bleiben' ist die Reise von Tourist zu Einwohner. B2 wird diese Reise vertiefen: von Einwohner zu Bürger, von Alltag zu Akademie, von Überleben zu Gedeihen."}},
{type:"mc",q:"Verumius sagt: 'Ich werde bleiben.' Warum benutzt er Futur I statt Präsens?",opts:["Weil es in der Vergangenheit geschah","Weil die Handlung gerade jetzt passiert","Um sein bewusstes Engagement zu betonen","Weil er unsicher ist"],ans:"Um sein bewusstes Engagement zu betonen",hint:"Futur I verleiht Absicht und bewusstes Engagement über einfaches Präsens hinaus. Das ist eine Erklärung."},
{type:"fb",s:"Er {1} gezweifelt, ob er es schaffen würde.",a:["hatte"],opts:["hatte","hat","war","ist"],hint:"Plusquamperfekt von zweifeln (benutzt haben). Was ist das Präteritum von haben?",sSrc:"He had doubted whether he would manage it."},
{type:"mc",q:"Was signalisiert 'Und jetzt wird es ernst' über die Geschichte?",opts:["B2 wird härtere Herausforderungen bringen","Verumius verlässt Berlin","Die Geschichte endet für immer","Die Grammatik wird einfacher"],ans:"B2 wird härtere Herausforderungen bringen",hint:"'Ernst' bedeutet serious. 'Es wird ernst' signalisiert, dass es jetzt richtig losgeht."},
{type:"match",pairs:[{trg:"wertvoll",src:"valuable"},{trg:"zuverlässig",src:"reliable"},{trg:"durcheinander",src:"mixed up"},{trg:"Augenblick",src:"moment"},{trg:"zweifeln",src:"to doubt"},{trg:"los",src:"off/going"}]}
]}

]}


];

export default GERMAN_V2_B1;
